INSERT INTO exercises (external_id, name, description, muscle_group, equipment, category, body_part, target, secondary_muscles, instructions_es, instructions_en, image_url, gif_url, media_id, attribution) VALUES
('0001', '3/4 sit-up', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Coloca las manos detrás de la cabeza con los codos apuntando hacia afuera. Activando el abdomen, levanta lentamente la parte superior del cuerpo del suelo, curvándote hacia adelante hasta que tu torso forme un áng', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"hip flexors","lower back"}', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Coloca las manos detrás de la cabeza con los codos apuntando hacia afuera. Activando el abdomen, levanta lentamente la parte superior del cuerpo del suelo, curvándote hacia adelante hasta que tu torso forme un ángulo de 45 grados. Haz una pausa por un momento en la parte superior, luego baja lentamente la parte superior del cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on your back with your knees bent and feet flat on the ground. Place your hands behind your head with your elbows pointing outwards. Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle. Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0001-2gPfomN.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0001-2gPfomN.gif', '2gPfomN', '© Gym visual — https://gymvisual.com/'),
('0002', '45° side bend', 'Ponte de pie con los pies separados a la altura de los hombros y los brazos extendidos hacia abajo a los lados. Manteniendo la espalda recta y el core activado, flexiona lentamente el torso hacia un lado, bajando la mano hacia la rodilla. Haz una pausa por un momento en la parte inferior, luego regr', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"obliques"}', 'Ponte de pie con los pies separados a la altura de los hombros y los brazos extendidos hacia abajo a los lados. Manteniendo la espalda recta y el core activado, flexiona lentamente el torso hacia un lado, bajando la mano hacia la rodilla. Haz una pausa por un momento en la parte inferior, luego regresa lentamente a la posición inicial. Repite del otro lado. Continúa alternando lados durante el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and your arms extended straight down by your sides. Keeping your back straight and your core engaged, slowly bend your torso to one side, lowering your hand towards your knee. Pause for a moment at the bottom, then slowly return to the starting position. Repeat on the other side. Continue alternating sides for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0002-Hy9D21L.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0002-Hy9D21L.gif', 'Hy9D21L', '© Gym visual — https://gymvisual.com/'),
('0003', 'air bike', 'Túmbate sobre tu espalda con las manos colocadas detrás de la cabeza. Levanta las piernas del suelo y flexiona las rodillas formando un ángulo de 90 grados. Lleva el codo derecho hacia la rodilla izquierda mientras simultáneamente estiras la pierna derecha. Regresa a la posición inicial y repite el ', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"hip flexors"}', 'Túmbate sobre tu espalda con las manos colocadas detrás de la cabeza. Levanta las piernas del suelo y flexiona las rodillas formando un ángulo de 90 grados. Lleva el codo derecho hacia la rodilla izquierda mientras simultáneamente estiras la pierna derecha. Regresa a la posición inicial y repite el movimiento del lado opuesto, llevando el codo izquierdo hacia la rodilla derecha mientras estiras la pierna izquierda. Continúa alternando lados con un movimiento de pedaleo durante el número de repeticiones deseado.', 'Lie flat on your back with your hands placed behind your head. Lift your legs off the ground and bend your knees at a 90-degree angle. Bring your right elbow towards your left knee while simultaneously straightening your right leg. Return to the starting position and repeat the movement on the opposite side, bringing your left elbow towards your right knee while straightening your left leg. Continue alternating sides in a pedaling motion for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0003-1ZFqTDN.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0003-1ZFqTDN.gif', '1ZFqTDN', '© Gym visual — https://gymvisual.com/'),
('1512', 'all fours squad stretch', 'Comienza apoyado sobre manos y rodillas, con las manos justo debajo de los hombros y las rodillas justo debajo de las caderas. Extiende una pierna hacia atrás, manteniendo la rodilla flexionada y el pie en flexión. Baja lentamente las caderas hacia el suelo, sintiendo un estiramiento en los cuádrice', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'quads', '{"hamstrings","glutes"}', 'Comienza apoyado sobre manos y rodillas, con las manos justo debajo de los hombros y las rodillas justo debajo de las caderas. Extiende una pierna hacia atrás, manteniendo la rodilla flexionada y el pie en flexión. Baja lentamente las caderas hacia el suelo, sintiendo un estiramiento en los cuádriceps. Mantén esta posición durante 20-30 segundos. Cambia de pierna y repite el estiramiento del otro lado.', 'Start on all fours with your hands directly under your shoulders and your knees directly under your hips. Extend one leg straight back, keeping your knee bent and your foot flexed. Slowly lower your hips towards the ground, feeling a stretch in your quads. Hold this position for 20-30 seconds. Switch legs and repeat the stretch on the other side.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1512-qBcKorM.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1512-qBcKorM.gif', 'qBcKorM', '© Gym visual — https://gymvisual.com/'),
('0006', 'alternate heel touchers', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Extiende los brazos hacia los lados, paralelos al suelo. Activando el abdomen, levanta los hombros del suelo y lleva la mano derecha hacia el talón derecho. Regresa a la posición inicial y repite del lado izquierd', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"obliques"}', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Extiende los brazos hacia los lados, paralelos al suelo. Activando el abdomen, levanta los hombros del suelo y lleva la mano derecha hacia el talón derecho. Regresa a la posición inicial y repite del lado izquierdo, llevando la mano izquierda hacia el talón izquierdo. Continúa alternando lados durante el número de repeticiones deseado.', 'Lie flat on your back with your knees bent and feet flat on the ground. Extend your arms straight out to the sides, parallel to the ground. Engaging your abs, lift your shoulders off the ground and reach your right hand towards your right heel. Return to the starting position and repeat on the left side, reaching your left hand towards your left heel. Continue alternating sides for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0006-qaZVsGk.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0006-qaZVsGk.gif', 'qaZVsGk', '© Gym visual — https://gymvisual.com/'),
('0007', 'alternate lateral pulldown', 'Siéntate en la máquina de cable con la espalda recta y los pies apoyados en el suelo. Agarra las agarraderas con un agarre prono, un poco más separadas que el ancho de los hombros. Inclínate ligeramente hacia atrás y lleva las agarraderas hacia el pecho, juntando los omóplatos. Haz una pausa por un ', 'back', 'cable', 'back', 'back', 'lats', '{"biceps","rhomboids"}', 'Siéntate en la máquina de cable con la espalda recta y los pies apoyados en el suelo. Agarra las agarraderas con un agarre prono, un poco más separadas que el ancho de los hombros. Inclínate ligeramente hacia atrás y lleva las agarraderas hacia el pecho, juntando los omóplatos. Haz una pausa por un momento en el punto máximo del movimiento, luego suelta lentamente las agarraderas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on the cable machine with your back straight and feet flat on the ground. Grasp the handles with an overhand grip, slightly wider than shoulder-width apart. Lean back slightly and pull the handles towards your chest, squeezing your shoulder blades together. Pause for a moment at the peak of the movement, then slowly release the handles back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0007-4IKbhHV.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0007-4IKbhHV.gif', '4IKbhHV', '© Gym visual — https://gymvisual.com/'),
('1368', 'ankle circles', 'Siéntate en el suelo con las piernas extendidas frente a ti. Levanta una pierna del suelo y rota el tobillo con un movimiento circular. Realiza el número de círculos deseado en una dirección, luego cambia a la dirección contraria. Repite con la otra pierna.', 'lower legs', 'body weight', 'lower legs', 'lower legs', 'calves', '{"ankle stabilizers"}', 'Siéntate en el suelo con las piernas extendidas frente a ti. Levanta una pierna del suelo y rota el tobillo con un movimiento circular. Realiza el número de círculos deseado en una dirección, luego cambia a la dirección contraria. Repite con la otra pierna.', 'Sit on the ground with your legs extended in front of you. Lift one leg off the ground and rotate your ankle in a circular motion. Perform the desired number of circles in one direction, then switch to the other direction. Repeat with the other leg.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1368-uL9CsKm.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1368-uL9CsKm.gif', 'uL9CsKm', '© Gym visual — https://gymvisual.com/'),
('3293', 'archer pull up', 'Comienza colgándote de una barra de dominadas con un agarre prono, un poco más separado que el ancho de los hombros. Activa el core y lleva los omóplatos hacia abajo y atrás. Mientras te elevas, flexiona un brazo y lleva el codo hacia el costado, manteniendo el otro brazo recto. Continúa subiendo ha', 'back', 'body weight', 'back', 'back', 'lats', '{"biceps","forearms"}', 'Comienza colgándote de una barra de dominadas con un agarre prono, un poco más separado que el ancho de los hombros. Activa el core y lleva los omóplatos hacia abajo y atrás. Mientras te elevas, flexiona un brazo y lleva el codo hacia el costado, manteniendo el otro brazo recto. Continúa subiendo hasta que la barbilla quede por encima de la barra y el brazo flexionado esté completamente doblado. Bájate de nuevo con control, estirando el brazo flexionado y repitiendo el movimiento del otro lado. Alterna los lados en cada repetición.', 'Start by hanging from a pull-up bar with an overhand grip, slightly wider than shoulder-width apart. Engage your core and pull your shoulder blades down and back. As you pull yourself up, bend one arm and bring your elbow towards your side, while keeping the other arm straight. Continue pulling until your chin is above the bar and your bent arm is fully flexed. Lower yourself back down with control, straightening the bent arm and repeating the movement on the other side. Alternate sides with each repetition.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3293-72BC5Za.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3293-72BC5Za.gif', '72BC5Za', '© Gym visual — https://gymvisual.com/'),
('3294', 'archer push up', 'Comienza en posición de flexión de brazos con las manos un poco más separadas que el ancho de los hombros. Extiende un brazo hacia el lado, paralelo al suelo. Baja el cuerpo flexionando los codos, manteniendo la espalda recta y el core activado. Empuja hacia arriba para volver a la posición inicial.', 'chest', 'body weight', 'chest', 'chest', 'pectorals', '{"triceps","shoulders","core"}', 'Comienza en posición de flexión de brazos con las manos un poco más separadas que el ancho de los hombros. Extiende un brazo hacia el lado, paralelo al suelo. Baja el cuerpo flexionando los codos, manteniendo la espalda recta y el core activado. Empuja hacia arriba para volver a la posición inicial. Repite del otro lado, extendiendo el brazo opuesto hacia el lado. Continúa alternando lados durante el número de repeticiones deseado.', 'Start in a push-up position with your hands slightly wider than shoulder-width apart. Extend one arm straight out to the side, parallel to the ground. Lower your body by bending your elbows, keeping your back straight and core engaged. Push back up to the starting position. Repeat on the other side, extending the opposite arm out to the side. Continue alternating sides for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3294-A9qxk2F.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3294-A9qxk2F.gif', 'A9qxk2F', '© Gym visual — https://gymvisual.com/'),
('2355', 'arm slingers hanging bent knee legs', 'Cuélgate de una barra de dominadas con los brazos completamente extendidos y las rodillas flexionadas formando un ángulo de 90 grados. Activa el core y levanta las rodillas hacia el pecho, acercándolas lo más posible a los codos. Baja lentamente las piernas de vuelta a la posición inicial. Repite el', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"shoulders","back"}', 'Cuélgate de una barra de dominadas con los brazos completamente extendidos y las rodillas flexionadas formando un ángulo de 90 grados. Activa el core y levanta las rodillas hacia el pecho, acercándolas lo más posible a los codos. Baja lentamente las piernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Hang from a pull-up bar with your arms fully extended and your knees bent at a 90-degree angle. Engage your core and lift your knees towards your chest, bringing them as close to your elbows as possible. Slowly lower your legs back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2355-uWpxD4v.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2355-uWpxD4v.gif', 'uWpxD4v', '© Gym visual — https://gymvisual.com/'),
('2333', 'arm slingers hanging straight legs', 'Cuélgate de una barra de dominadas con los brazos completamente extendidos y las piernas estiradas hacia abajo. Activa el core y levanta las piernas hacia adelante hasta que queden paralelas al suelo. Mantén un momento en la parte superior, luego baja lentamente las piernas de vuelta a la posición i', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"shoulders","back"}', 'Cuélgate de una barra de dominadas con los brazos completamente extendidos y las piernas estiradas hacia abajo. Activa el core y levanta las piernas hacia adelante hasta que queden paralelas al suelo. Mantén un momento en la parte superior, luego baja lentamente las piernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Hang from a pull-up bar with your arms fully extended and your legs straight down. Engage your core and lift your legs up in front of you until they are parallel to the ground. Hold for a moment at the top, then slowly lower your legs back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2333-PXTIwgu.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2333-PXTIwgu.gif', 'PXTIwgu', '© Gym visual — https://gymvisual.com/'),
('3214', 'arms apart circular toe touch (male)', 'Ponte de pie con los pies separados a la altura de los hombros y los brazos extendidos hacia los lados. Manteniendo las piernas rectas, flexiona el torso hacia adelante desde la cintura y lleva la mano derecha hacia los dedos de los pies. Mientras bajas, levanta simultáneamente la pierna izquierda r', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'glutes', '{"hamstrings","quadriceps","calves"}', 'Ponte de pie con los pies separados a la altura de los hombros y los brazos extendidos hacia los lados. Manteniendo las piernas rectas, flexiona el torso hacia adelante desde la cintura y lleva la mano derecha hacia los dedos de los pies. Mientras bajas, levanta simultáneamente la pierna izquierda recta detrás de ti, manteniendo el equilibrio. Regresa a la posición inicial y repite el movimiento llevando la mano izquierda hacia los dedos de los pies y levantando la pierna derecha detrás de ti. Continúa alternando lados durante el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and arms extended to the sides. Keeping your legs straight, bend forward at the waist and reach down towards your toes with your right hand. As you reach down, simultaneously lift your left leg straight up behind you, maintaining balance. Return to the starting position and repeat the movement with your left hand reaching towards your toes and your right leg lifting up behind you. Continue alternating sides for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3214-RtyAsy1.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3214-RtyAsy1.gif', 'RtyAsy1', '© Gym visual — https://gymvisual.com/'),
('3204', 'arms overhead full sit-up (male)', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Extiende los brazos por encima de la cabeza, manteniéndolos rectos. Activando el abdomen, levanta lentamente la parte superior del cuerpo del suelo, curvándote hacia adelante hasta que el torso quede erguido. Haz ', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"hip flexors","lower back"}', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Extiende los brazos por encima de la cabeza, manteniéndolos rectos. Activando el abdomen, levanta lentamente la parte superior del cuerpo del suelo, curvándote hacia adelante hasta que el torso quede erguido. Haz una pausa por un momento en la parte superior, luego baja lentamente la parte superior del cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on your back with your knees bent and feet flat on the ground. Extend your arms overhead, keeping them straight. Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is upright. Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3204-NAkmgdx.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3204-NAkmgdx.gif', 'NAkmgdx', '© Gym visual — https://gymvisual.com/'),
('0009', 'assisted chest dip (kneeling)', 'Ajusta la máquina a la altura deseada y asegura las rodillas sobre la almohadilla. Agarra las agarraderas con las palmas hacia abajo y los brazos completamente extendidos. Baja el cuerpo flexionando los codos hasta que los brazos queden paralelos al suelo. Haz una pausa por un momento, luego empuja ', 'chest', 'leverage machine', 'chest', 'chest', 'pectorals', '{"triceps","shoulders"}', 'Ajusta la máquina a la altura deseada y asegura las rodillas sobre la almohadilla. Agarra las agarraderas con las palmas hacia abajo y los brazos completamente extendidos. Baja el cuerpo flexionando los codos hasta que los brazos queden paralelos al suelo. Haz una pausa por un momento, luego empuja tu cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the machine to your desired height and secure your knees on the pad. Grasp the handles with your palms facing down and your arms fully extended. Lower your body by bending your elbows until your upper arms are parallel to the floor. Pause for a moment, then push yourself back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0009-PAgTVaK.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0009-PAgTVaK.gif', 'PAgTVaK', '© Gym visual — https://gymvisual.com/'),
('0011', 'assisted hanging knee raise', 'Cuélgate de una barra de dominadas con los brazos completamente extendidos y las palmas mirando hacia afuera. Activa el core y levanta las rodillas hacia el pecho, flexionando las caderas y las rodillas. Haz una pausa por un momento en la parte superior del movimiento, apretando el abdomen. Baja len', 'waist', 'assisted', 'waist', 'waist', 'abs', '{"hip flexors"}', 'Cuélgate de una barra de dominadas con los brazos completamente extendidos y las palmas mirando hacia afuera. Activa el core y levanta las rodillas hacia el pecho, flexionando las caderas y las rodillas. Haz una pausa por un momento en la parte superior del movimiento, apretando el abdomen. Baja lentamente las piernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Hang from a pull-up bar with your arms fully extended and your palms facing away from you. Engage your core muscles and lift your knees towards your chest, bending at the hips and knees. Pause for a moment at the top of the movement, squeezing your abs. Slowly lower your legs back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0011-03lzqwk.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0011-03lzqwk.gif', '03lzqwk', '© Gym visual — https://gymvisual.com/'),
('0010', 'assisted hanging knee raise with throw down', 'Cuélgate de una barra de dominadas con los brazos completamente extendidos y las palmas mirando hacia afuera. Activa el core y levanta las rodillas hacia el pecho, manteniendo las piernas juntas. Una vez que las rodillas estén a la altura del pecho, lanza las piernas explosivamente hacia el suelo, e', 'waist', 'assisted', 'waist', 'waist', 'abs', '{"hip flexors","lower back"}', 'Cuélgate de una barra de dominadas con los brazos completamente extendidos y las palmas mirando hacia afuera. Activa el core y levanta las rodillas hacia el pecho, manteniendo las piernas juntas. Una vez que las rodillas estén a la altura del pecho, lanza las piernas explosivamente hacia el suelo, extendiéndolas por completo. Deja que las piernas se balanceen de vuelta hacia arriba y repite el movimiento el número de repeticiones deseado.', 'Hang from a pull-up bar with your arms fully extended and your palms facing away from you. Engage your core and lift your knees towards your chest, keeping your legs together. Once your knees are at chest level, explosively throw your legs down towards the ground, extending them fully. Allow your legs to swing back up and repeat the movement for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0010-8K0w2yA.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0010-8K0w2yA.gif', '8K0w2yA', '© Gym visual — https://gymvisual.com/'),
('1708', 'assisted lying calves stretch', 'Túmbate sobre tu espalda con las piernas extendidas. Flexiona una rodilla y coloca el pie plano sobre el suelo. Con las manos o una toalla, jala suavemente los dedos del pie hacia tu cuerpo, sintiendo un estiramiento en la pantorrilla. Mantén el estiramiento durante 20-30 segundos. Suelta el estiram', 'lower legs', 'assisted', 'lower legs', 'lower legs', 'calves', '{"hamstrings"}', 'Túmbate sobre tu espalda con las piernas extendidas. Flexiona una rodilla y coloca el pie plano sobre el suelo. Con las manos o una toalla, jala suavemente los dedos del pie hacia tu cuerpo, sintiendo un estiramiento en la pantorrilla. Mantén el estiramiento durante 20-30 segundos. Suelta el estiramiento y repite con la otra pierna.', 'Lie on your back with your legs extended. Bend one knee and place your foot flat on the ground. Using your hands or a towel, gently pull your toes towards your body, feeling a stretch in your calf. Hold the stretch for 20-30 seconds. Release the stretch and repeat on the other leg.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1708-GxDwDX0.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1708-GxDwDX0.gif', 'GxDwDX0', '© Gym visual — https://gymvisual.com/'),
('1709', 'assisted lying glutes stretch', 'Túmbate sobre tu espalda con las piernas extendidas. Flexiona la rodilla derecha y coloca el tobillo derecho sobre el muslo izquierdo, justo encima de la rodilla. Agarra el muslo izquierdo con ambas manos y jálalo suavemente hacia el pecho. Mantén el estiramiento durante 20-30 segundos. Suelta y rep', 'upper legs', 'assisted', 'upper legs', 'upper legs', 'glutes', '{"hamstrings"}', 'Túmbate sobre tu espalda con las piernas extendidas. Flexiona la rodilla derecha y coloca el tobillo derecho sobre el muslo izquierdo, justo encima de la rodilla. Agarra el muslo izquierdo con ambas manos y jálalo suavemente hacia el pecho. Mantén el estiramiento durante 20-30 segundos. Suelta y repite del otro lado.', 'Lie on your back with your legs extended. Bend your right knee and place your right ankle on your left thigh, just above the knee. Grasp your left thigh with both hands and gently pull it towards your chest. Hold the stretch for 20-30 seconds. Release and repeat on the other side.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1709-yn0LjwL.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1709-yn0LjwL.gif', 'yn0LjwL', '© Gym visual — https://gymvisual.com/'),
('1710', 'assisted lying gluteus and piriformis stretch', 'Túmbate sobre tu espalda con las piernas extendidas. Flexiona la rodilla derecha y coloca el tobillo derecho sobre el muslo izquierdo, justo encima de la rodilla. Agarra el muslo izquierdo con ambas manos y jálalo suavemente hacia el pecho. Mantén el estiramiento durante 20-30 segundos. Suelta el es', 'upper legs', 'assisted', 'upper legs', 'upper legs', 'glutes', '{"hamstrings"}', 'Túmbate sobre tu espalda con las piernas extendidas. Flexiona la rodilla derecha y coloca el tobillo derecho sobre el muslo izquierdo, justo encima de la rodilla. Agarra el muslo izquierdo con ambas manos y jálalo suavemente hacia el pecho. Mantén el estiramiento durante 20-30 segundos. Suelta el estiramiento y repite del otro lado.', 'Lie on your back with your legs extended. Bend your right knee and place your right ankle on your left thigh, just above the knee. Grasp your left thigh with both hands and gently pull it towards your chest. Hold the stretch for 20-30 seconds. Release the stretch and repeat on the other side.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1710-RQNVT10.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1710-RQNVT10.gif', 'RQNVT10', '© Gym visual — https://gymvisual.com/'),
('0012', 'assisted lying leg raise with lateral throw down', 'Túmbate sobre tu espalda con las piernas extendidas y los brazos a los lados. Coloca las manos debajo de los glúteos como apoyo. Activa el abdomen y levanta las piernas del suelo, manteniéndolas rectas. Manteniendo las piernas juntas, bájalas hacia un lado hasta que queden a pocos centímetros del su', 'waist', 'assisted', 'waist', 'waist', 'abs', '{"hip flexors","obliques"}', 'Túmbate sobre tu espalda con las piernas extendidas y los brazos a los lados. Coloca las manos debajo de los glúteos como apoyo. Activa el abdomen y levanta las piernas del suelo, manteniéndolas rectas. Manteniendo las piernas juntas, bájalas hacia un lado hasta que queden a pocos centímetros del suelo. Haz una pausa por un momento, luego levanta las piernas de vuelta a la posición inicial. Repite el movimiento hacia el otro lado. Continúa alternando lados durante el número de repeticiones deseado.', 'Lie flat on your back with your legs extended and your arms by your sides. Place your hands under your glutes for support. Engage your abs and lift your legs off the ground, keeping them straight. While keeping your legs together, lower them to one side until they are a few inches above the ground. Pause for a moment, then lift your legs back to the starting position. Repeat the movement to the other side. Continue alternating sides for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0012-UGhRD1A.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0012-UGhRD1A.gif', 'UGhRD1A', '© Gym visual — https://gymvisual.com/'),
('0013', 'assisted lying leg raise with throw down', 'Túmbate sobre tu espalda con las piernas extendidas y los brazos a los lados. Coloca las manos debajo de los glúteos como apoyo. Activa el core y levanta las piernas del suelo, manteniéndolas rectas. Eleva las piernas hasta que queden perpendiculares al suelo. Baja las piernas de vuelta a la posició', 'waist', 'assisted', 'waist', 'waist', 'abs', '{"hip flexors","quadriceps"}', 'Túmbate sobre tu espalda con las piernas extendidas y los brazos a los lados. Coloca las manos debajo de los glúteos como apoyo. Activa el core y levanta las piernas del suelo, manteniéndolas rectas. Eleva las piernas hasta que queden perpendiculares al suelo. Baja las piernas de vuelta a la posición inicial. Simultáneamente, lanza las piernas hacia el suelo, manteniéndolas rectas. Eleva las piernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on your back with your legs extended and your arms by your sides. Place your hands under your glutes for support. Engage your core and lift your legs off the ground, keeping them straight. Raise your legs until they are perpendicular to the ground. Lower your legs back down to the starting position. Simultaneously, throw your legs down towards the ground, keeping them straight. Raise your legs back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0013-VX5YKR5.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0013-VX5YKR5.gif', 'VX5YKR5', '© Gym visual — https://gymvisual.com/'),
('0014', 'assisted motion russian twist', 'Siéntate en el suelo con las rodillas flexionadas y los pies apoyados en el suelo. Sostén el balón medicinal con ambas manos frente al pecho. Inclínate ligeramente hacia atrás, activando el abdomen y manteniendo la espalda recta. Gira lentamente el torso hacia la derecha, llevando el balón medicinal', 'waist', 'medicine ball', 'waist', 'waist', 'abs', '{"obliques","lower back"}', 'Siéntate en el suelo con las rodillas flexionadas y los pies apoyados en el suelo. Sostén el balón medicinal con ambas manos frente al pecho. Inclínate ligeramente hacia atrás, activando el abdomen y manteniendo la espalda recta. Gira lentamente el torso hacia la derecha, llevando el balón medicinal hacia el lado derecho del cuerpo. Haz una pausa por un momento, luego gira el torso hacia la izquierda, llevando el balón medicinal hacia el lado izquierdo del cuerpo. Continúa alternando lados durante el número de repeticiones deseado.', 'Sit on the ground with your knees bent and feet flat on the floor. Hold the medicine ball with both hands in front of your chest. Lean back slightly, engaging your abs and keeping your back straight. Slowly twist your torso to the right, bringing the medicine ball towards the right side of your body. Pause for a moment, then twist your torso to the left, bringing the medicine ball towards the left side of your body. Continue alternating sides for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0014-r7cT9YD.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0014-r7cT9YD.gif', 'r7cT9YD', '© Gym visual — https://gymvisual.com/'),
('0015', 'assisted parallel close grip pull-up', 'Ajusta la máquina al peso y la altura deseados. Coloca las manos en las barras paralelas con un agarre cerrado, con las palmas mirándose entre sí. Cuélgate de las barras con los brazos completamente extendidos y los pies sin tocar el suelo. Activa los músculos de la espalda y lleva el cuerpo hacia a', 'back', 'leverage machine', 'back', 'back', 'lats', '{"biceps","forearms"}', 'Ajusta la máquina al peso y la altura deseados. Coloca las manos en las barras paralelas con un agarre cerrado, con las palmas mirándose entre sí. Cuélgate de las barras con los brazos completamente extendidos y los pies sin tocar el suelo. Activa los músculos de la espalda y lleva el cuerpo hacia arriba hacia las barras, manteniendo los codos cerca del cuerpo. Continúa subiendo hasta que la barbilla quede por encima de las barras. Haz una pausa por un momento en la parte superior, luego baja lentamente el cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the machine to your desired weight and height. Place your hands on the parallel bars with a close grip, palms facing each other. Hang from the bars with your arms fully extended and your feet off the ground. Engage your back muscles and pull your body up towards the bars, keeping your elbows close to your body. Continue pulling until your chin is above the bars. Pause for a moment at the top, then slowly lower your body back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0015-vrhHa6D.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0015-vrhHa6D.gif', 'vrhHa6D', '© Gym visual — https://gymvisual.com/'),
('0016', 'assisted prone hamstring', 'Túmbate boca abajo sobre una esterilla o un banco con las piernas completamente extendidas. Pide a un compañero o usa una banda elástica para sujetar tus tobillos. Activa los isquiotibiales y levanta las piernas hacia los glúteos, manteniendo las rodillas rectas. Haz una pausa por un momento en la p', 'upper legs', 'assisted', 'upper legs', 'upper legs', 'hamstrings', '{"glutes","lower back"}', 'Túmbate boca abajo sobre una esterilla o un banco con las piernas completamente extendidas. Pide a un compañero o usa una banda elástica para sujetar tus tobillos. Activa los isquiotibiales y levanta las piernas hacia los glúteos, manteniendo las rodillas rectas. Haz una pausa por un momento en la parte superior, luego baja lentamente las piernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie face down on a mat or bench with your legs fully extended. Have a partner or use a resistance band to secure your ankles. Engage your hamstrings and lift your legs towards your glutes, keeping your knees straight. Pause for a moment at the top, then slowly lower your legs back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0016-VedGSby.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0016-VedGSby.gif', 'VedGSby', '© Gym visual — https://gymvisual.com/'),
('1713', 'assisted prone lying quads stretch', 'Túmbate boca abajo en el suelo con las piernas extendidas. Flexiona la rodilla izquierda y lleva la mano izquierda hacia atrás para agarrar el pie o el tobillo izquierdo. Jala suavemente el pie izquierdo hacia los glúteos, sintiendo un estiramiento en el cuádriceps izquierdo. Mantén el estiramiento ', 'upper legs', 'assisted', 'upper legs', 'upper legs', 'quads', '{"hamstrings","glutes"}', 'Túmbate boca abajo en el suelo con las piernas extendidas. Flexiona la rodilla izquierda y lleva la mano izquierda hacia atrás para agarrar el pie o el tobillo izquierdo. Jala suavemente el pie izquierdo hacia los glúteos, sintiendo un estiramiento en el cuádriceps izquierdo. Mantén el estiramiento durante 20-30 segundos, luego suelta. Repite con la pierna derecha.', 'Lie face down on the ground with your legs extended. Bend your left knee and reach back with your left hand to grab your left foot or ankle. Gently pull your left foot towards your glutes, feeling a stretch in your left quad. Hold the stretch for 20-30 seconds, then release. Repeat with your right leg.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1713-YUYAMEj.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1713-YUYAMEj.gif', 'YUYAMEj', '© Gym visual — https://gymvisual.com/'),
('1714', 'assisted prone rectus femoris stretch', 'Túmbate boca abajo en el suelo con las piernas rectas. Flexiona la rodilla derecha y lleva la mano derecha hacia atrás para agarrar el pie o el tobillo derecho. Jala suavemente el pie o el tobillo derecho hacia los glúteos, sintiendo un estiramiento en la parte frontal del muslo derecho. Mantén el e', 'waist', 'assisted', 'waist', 'waist', 'abs', '{"quadriceps"}', 'Túmbate boca abajo en el suelo con las piernas rectas. Flexiona la rodilla derecha y lleva la mano derecha hacia atrás para agarrar el pie o el tobillo derecho. Jala suavemente el pie o el tobillo derecho hacia los glúteos, sintiendo un estiramiento en la parte frontal del muslo derecho. Mantén el estiramiento durante 20-30 segundos. Suelta y repite del otro lado.', 'Lie face down on the ground with your legs straight. Bend your right knee and reach back with your right hand to grab your right foot or ankle. Gently pull your right foot or ankle towards your glutes, feeling a stretch in the front of your right thigh. Hold the stretch for 20-30 seconds. Release and repeat on the other side.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1714-2Ryn564.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1714-2Ryn564.gif', '2Ryn564', '© Gym visual — https://gymvisual.com/'),
('0017', 'assisted pull-up', 'Ajusta la máquina a los valores de peso y altura deseados. Agarra las agarraderas con un agarre prono, un poco más separadas que el ancho de los hombros. Cuélgate con los brazos completamente extendidos y los pies sin tocar el suelo. Activa los músculos de la espalda y lleva el cuerpo hacia arriba h', 'back', 'leverage machine', 'back', 'back', 'lats', '{"biceps","forearms"}', 'Ajusta la máquina a los valores de peso y altura deseados. Agarra las agarraderas con un agarre prono, un poco más separadas que el ancho de los hombros. Cuélgate con los brazos completamente extendidos y los pies sin tocar el suelo. Activa los músculos de la espalda y lleva el cuerpo hacia arriba hacia las agarraderas, manteniendo los codos cerca del cuerpo. Continúa subiendo hasta que la barbilla quede por encima de las agarraderas. Haz una pausa por un momento en la parte superior, luego baja lentamente el cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the machine to your desired weight and height settings. Grasp the handles with an overhand grip, slightly wider than shoulder-width apart. Hang with your arms fully extended and your feet off the ground. Engage your back muscles and pull your body up towards the handles, keeping your elbows close to your body. Continue pulling until your chin is above the handles. Pause for a moment at the top, then slowly lower your body back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0017-kiJ4Z2K.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0017-kiJ4Z2K.gif', 'kiJ4Z2K', '© Gym visual — https://gymvisual.com/'),
('1716', 'assisted seated pectoralis major stretch with stability ball', 'Siéntate sobre un balón de estabilidad con los pies apoyados en el suelo y la espalda recta. Sostén un balón de estabilidad con ambas manos y extiende los brazos rectos frente a ti. Baja lentamente el balón de estabilidad hacia el pecho, sintiendo un estiramiento en los pectorales. Mantén el estiram', 'chest', 'assisted', 'chest', 'chest', 'pectorals', '{"shoulders","triceps"}', 'Siéntate sobre un balón de estabilidad con los pies apoyados en el suelo y la espalda recta. Sostén un balón de estabilidad con ambas manos y extiende los brazos rectos frente a ti. Baja lentamente el balón de estabilidad hacia el pecho, sintiendo un estiramiento en los pectorales. Mantén el estiramiento durante unos segundos, luego regresa lentamente a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a stability ball with your feet flat on the ground and your back straight. Hold a stability ball with both hands and extend your arms straight out in front of you. Slowly lower the stability ball towards your chest, feeling a stretch in your pectoral muscles. Hold the stretch for a few seconds, then slowly return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1716-RoV1Rfa.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1716-RoV1Rfa.gif', 'RoV1Rfa', '© Gym visual — https://gymvisual.com/'),
('1712', 'assisted side lying adductor stretch', 'Túmbate de lado con las piernas rectas y apiladas una sobre la otra. Flexiona ligeramente la pierna de abajo para mayor estabilidad. Coloca el pie de arriba sobre una superficie estable, como un banco o un escalón. Manteniendo la pierna de arriba recta, bájala lentamente hacia el suelo, sintiendo un', 'upper legs', 'assisted', 'upper legs', 'upper legs', 'adductors', '{"hamstrings","glutes"}', 'Túmbate de lado con las piernas rectas y apiladas una sobre la otra. Flexiona ligeramente la pierna de abajo para mayor estabilidad. Coloca el pie de arriba sobre una superficie estable, como un banco o un escalón. Manteniendo la pierna de arriba recta, bájala lentamente hacia el suelo, sintiendo un estiramiento en la parte interna del muslo. Mantén el estiramiento durante 20-30 segundos. Regresa a la posición inicial y repite del otro lado.', 'Lie on your side with your legs straight and stacked on top of each other. Bend your bottom leg slightly for stability. Place your top foot on a stable surface, such as a bench or step. Keeping your top leg straight, slowly lower it towards the ground, feeling a stretch in your inner thigh. Hold the stretch for 20-30 seconds. Return to the starting position and repeat on the other side.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1712-hC6oYY5.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1712-hC6oYY5.gif', 'hC6oYY5', '© Gym visual — https://gymvisual.com/'),
('1758', 'assisted sit-up', 'Siéntate en el borde de un banco o pide a alguien que te sujete los pies. Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Coloca las manos detrás de la cabeza con los codos apuntando hacia afuera. Activando el abdomen, levanta lentamente la parte superior del c', 'waist', 'assisted', 'waist', 'waist', 'abs', '{"hip flexors"}', 'Siéntate en el borde de un banco o pide a alguien que te sujete los pies. Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Coloca las manos detrás de la cabeza con los codos apuntando hacia afuera. Activando el abdomen, levanta lentamente la parte superior del cuerpo del suelo, curvándote hacia adelante hasta que tu torso forme un ángulo de 45 grados. Haz una pausa por un momento en la parte superior, luego baja lentamente la parte superior del cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on the edge of a bench or have someone hold your feet down. Lie flat on your back with your knees bent and feet flat on the ground. Place your hands behind your head with your elbows pointing outwards. Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle. Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1758-aumB2IV.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1758-aumB2IV.gif', 'aumB2IV', '© Gym visual — https://gymvisual.com/'),
('1431', 'assisted standing chin-up', 'Ajusta la máquina al nivel de asistencia deseado. Sube a la plataforma para los pies y agarra las agarraderas con un agarre prono, un poco más separadas que el ancho de los hombros. Mantén el pecho arriba y los hombros atrás, activa el core y flexiona ligeramente las rodillas. Levanta el cuerpo flex', 'back', 'leverage machine', 'back', 'back', 'lats', '{"biceps","forearms"}', 'Ajusta la máquina al nivel de asistencia deseado. Sube a la plataforma para los pies y agarra las agarraderas con un agarre prono, un poco más separadas que el ancho de los hombros. Mantén el pecho arriba y los hombros atrás, activa el core y flexiona ligeramente las rodillas. Levanta el cuerpo flexionando los codos y llevándolos hacia abajo, en dirección a los costados. Continúa subiendo hasta que la barbilla quede por encima de la barra. Haz una pausa por un momento en la parte superior, luego baja lentamente el cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the machine to your desired assistance level. Stand on the foot platform and grip the handles with an overhand grip, slightly wider than shoulder-width apart. Keep your chest up and shoulders back, engage your core, and slightly bend your knees. Pull your body up by flexing your elbows and driving your elbows down towards your sides. Continue pulling until your chin is above the bar. Pause for a moment at the top, then slowly lower your body back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1431-7OeHptV.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1431-7OeHptV.gif', '7OeHptV', '© Gym visual — https://gymvisual.com/'),
('1432', 'assisted standing pull-up', 'Ajusta la máquina a los valores de peso y altura deseados. Ponte de pie frente a la máquina con los pies separados a la altura de los hombros. Agarra las agarraderas con un agarre prono, un poco más separadas que el ancho de los hombros. Activa los dorsales y los bíceps, y levántate hacia las agarra', 'back', 'leverage machine', 'back', 'back', 'lats', '{"biceps","forearms"}', 'Ajusta la máquina a los valores de peso y altura deseados. Ponte de pie frente a la máquina con los pies separados a la altura de los hombros. Agarra las agarraderas con un agarre prono, un poco más separadas que el ancho de los hombros. Activa los dorsales y los bíceps, y levántate hacia las agarraderas. Haz una pausa por un momento en la parte superior, apretando los músculos de la espalda. Bájate lentamente de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the machine to your desired weight and height settings. Stand facing the machine with your feet shoulder-width apart. Grasp the handles with an overhand grip, slightly wider than shoulder-width apart. Engage your lats and biceps, and pull yourself up towards the handles. Pause for a moment at the top, squeezing your back muscles. Slowly lower yourself back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1432-f4xtKBj.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1432-f4xtKBj.gif', 'f4xtKBj', '© Gym visual — https://gymvisual.com/'),
('0018', 'assisted standing triceps extension (with towel)', 'Ponte de pie con los pies separados a la altura de los hombros y sostén una toalla con ambas manos detrás de la cabeza. Mantén los codos cerca de las orejas y la parte superior de los brazos quieta. Extiende lentamente los antebrazos hacia arriba, apretando los tríceps en la parte superior. Haz una ', 'upper arms', 'assisted', 'upper arms', 'upper arms', 'triceps', '{"shoulders"}', 'Ponte de pie con los pies separados a la altura de los hombros y sostén una toalla con ambas manos detrás de la cabeza. Mantén los codos cerca de las orejas y la parte superior de los brazos quieta. Extiende lentamente los antebrazos hacia arriba, apretando los tríceps en la parte superior. Haz una pausa por un momento, luego baja lentamente la toalla de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and hold a towel with both hands behind your head. Keep your elbows close to your ears and your upper arms stationary. Slowly extend your forearms upward, squeezing your triceps at the top. Pause for a moment, then slowly lower the towel back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0018-7HcfMBP.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0018-7HcfMBP.gif', '7HcfMBP', '© Gym visual — https://gymvisual.com/'),
('0019', 'assisted triceps dip (kneeling)', 'Ajusta la máquina al peso y la altura deseados. Arrodíllate sobre la almohadilla frente a la máquina, con las manos sujetando las agarraderas. Baja el cuerpo flexionando los codos, manteniendo la espalda recta y cerca de la máquina. Haz una pausa por un momento en la parte inferior, luego empuja tu ', 'upper arms', 'leverage machine', 'upper arms', 'upper arms', 'triceps', '{"chest","shoulders"}', 'Ajusta la máquina al peso y la altura deseados. Arrodíllate sobre la almohadilla frente a la máquina, con las manos sujetando las agarraderas. Baja el cuerpo flexionando los codos, manteniendo la espalda recta y cerca de la máquina. Haz una pausa por un momento en la parte inferior, luego empuja tu cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the machine to your desired weight and height. Kneel down on the pad facing the machine, with your hands gripping the handles. Lower your body by bending your elbows, keeping your back straight and close to the machine. Pause for a moment at the bottom, then push yourself back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0019-J60bN17.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0019-J60bN17.gif', 'J60bN17', '© Gym visual — https://gymvisual.com/'),
('2364', 'assisted wide-grip chest dip (kneeling)', 'Ajusta la máquina a la altura deseada y asegura las rodillas sobre la almohadilla. Agarra las agarraderas con un agarre amplio y mantén los codos ligeramente flexionados. Baja el cuerpo flexionando los codos hasta que los brazos queden paralelos al suelo. Empuja tu cuerpo de vuelta a la posición ini', 'chest', 'leverage machine', 'chest', 'chest', 'pectorals', '{"triceps","shoulders"}', 'Ajusta la máquina a la altura deseada y asegura las rodillas sobre la almohadilla. Agarra las agarraderas con un agarre amplio y mantén los codos ligeramente flexionados. Baja el cuerpo flexionando los codos hasta que los brazos queden paralelos al suelo. Empuja tu cuerpo de vuelta a la posición inicial extendiendo los brazos. Repite el número de repeticiones deseado.', 'Adjust the machine to your desired height and secure your knees on the pad. Grasp the handles with a wide grip and keep your elbows slightly bent. Lower your body by bending your elbows until your upper arms are parallel to the floor. Push yourself back up to the starting position by extending your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2364-PnZJIrk.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2364-PnZJIrk.gif', 'PnZJIrk', '© Gym visual — https://gymvisual.com/'),
('3220', 'astride jumps (male)', 'Ponte de pie con los pies separados a la altura de los hombros. Flexiona las rodillas y baja el cuerpo hacia una posición de sentadilla. Salta explosivamente hacia arriba, extendiendo las piernas y los brazos. Mientras estás en el aire, separa las piernas y lleva los brazos hacia los lados. Aterriza', 'cardio', 'body weight', 'cardio', 'cardio', 'cardiovascular system', '{"quadriceps","hamstrings","calves"}', 'Ponte de pie con los pies separados a la altura de los hombros. Flexiona las rodillas y baja el cuerpo hacia una posición de sentadilla. Salta explosivamente hacia arriba, extendiendo las piernas y los brazos. Mientras estás en el aire, separa las piernas y lleva los brazos hacia los lados. Aterriza suavemente con los pies separados a la altura de los hombros, flexionando las rodillas para absorber el impacto. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart. Bend your knees and lower your body into a squat position. Jump explosively upwards, extending your legs and arms. While in the air, spread your legs apart and bring your arms out to the sides. Land softly with your feet shoulder-width apart, bending your knees to absorb the impact. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3220-f9lVSSI.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3220-f9lVSSI.gif', 'f9lVSSI', '© Gym visual — https://gymvisual.com/'),
('3672', 'back and forth step', 'Ponte de pie con los pies separados a la altura de los hombros. Da un paso adelante con el pie derecho, flexionando la rodilla y bajando el cuerpo hacia una posición de zancada. Empuja con el pie derecho y da un paso atrás para regresar a la posición inicial. Repite el movimiento con el pie izquierd', 'cardio', 'body weight', 'cardio', 'cardio', 'cardiovascular system', '{"quadriceps","hamstrings","glutes","calves"}', 'Ponte de pie con los pies separados a la altura de los hombros. Da un paso adelante con el pie derecho, flexionando la rodilla y bajando el cuerpo hacia una posición de zancada. Empuja con el pie derecho y da un paso atrás para regresar a la posición inicial. Repite el movimiento con el pie izquierdo, alternando las piernas en cada paso. Continúa dando pasos hacia adelante y hacia atrás, manteniendo un ritmo constante. Repite durante la duración o el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart. Step forward with your right foot, bending your knee and lowering your body into a lunge position. Push off with your right foot and step back to the starting position. Repeat the movement with your left foot, alternating legs with each step. Continue stepping back and forth, maintaining a steady pace. Repeat for the desired duration or number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3672-fNGumX0.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3672-fNGumX0.gif', 'fNGumX0', '© Gym visual — https://gymvisual.com/'),
('1314', 'back extension on exercise ball', 'Coloca el balón de estabilidad en el suelo y túmbate boca abajo sobre él, con las caderas apoyadas en el balón y los pies contra una pared u otra superficie estable. Coloca las manos detrás de la cabeza o cruzadas sobre el pecho. Activa el core y levanta lentamente la parte superior del cuerpo del b', 'back', 'stability ball', 'back', 'back', 'spine', '{"glutes","hamstrings"}', 'Coloca el balón de estabilidad en el suelo y túmbate boca abajo sobre él, con las caderas apoyadas en el balón y los pies contra una pared u otra superficie estable. Coloca las manos detrás de la cabeza o cruzadas sobre el pecho. Activa el core y levanta lentamente la parte superior del cuerpo del balón, extendiendo la espalda hasta que tu cuerpo forme una línea recta desde la cabeza hasta los talones. Haz una pausa por un momento en la parte superior, luego baja lentamente la parte superior del cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Place the stability ball on the ground and lie face down on top of it, with your hips resting on the ball and your feet against a wall or other stable surface. Position your hands behind your head or crossed over your chest. Engage your core and slowly lift your upper body off the ball, extending your back until your body forms a straight line from your head to your heels. Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1314-qLpO4vV.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1314-qLpO4vV.gif', 'qLpO4vV', '© Gym visual — https://gymvisual.com/'),
('3297', 'back lever', 'Comienza colgándote de una barra de dominadas con un agarre prono, con las manos un poco más separadas que el ancho de los hombros. Activa el core y lleva los omóplatos hacia abajo y atrás. Flexiona las rodillas y llévalas hacia el pecho. Levanta lentamente las piernas, manteniéndolas rectas, hasta ', 'back', 'body weight', 'back', 'back', 'upper back', '{"biceps","forearms","core"}', 'Comienza colgándote de una barra de dominadas con un agarre prono, con las manos un poco más separadas que el ancho de los hombros. Activa el core y lleva los omóplatos hacia abajo y atrás. Flexiona las rodillas y llévalas hacia el pecho. Levanta lentamente las piernas, manteniéndolas rectas, hasta que el cuerpo quede paralelo al suelo. Mantén esta posición durante unos segundos, luego baja lentamente las piernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Start by hanging from a pull-up bar with an overhand grip, hands slightly wider than shoulder-width apart. Engage your core and pull your shoulder blades down and back. Bend your knees and tuck them towards your chest. Slowly lift your legs up, keeping them straight, until your body is parallel to the ground. Hold this position for a few seconds, then slowly lower your legs back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3297-GaSzzuh.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3297-GaSzzuh.gif', 'GaSzzuh', '© Gym visual — https://gymvisual.com/'),
('1405', 'back pec stretch', 'Ponte de pie con la espalda recta y los pies separados a la altura de los hombros. Extiende los brazos rectos frente a ti, paralelos al suelo. Cruza los brazos frente al cuerpo, con el brazo derecho sobre el brazo izquierdo. Entrelaza los dedos y gira las palmas alejándolas del cuerpo. Levanta lenta', 'back', 'body weight', 'back', 'back', 'lats', '{"shoulders","chest"}', 'Ponte de pie con la espalda recta y los pies separados a la altura de los hombros. Extiende los brazos rectos frente a ti, paralelos al suelo. Cruza los brazos frente al cuerpo, con el brazo derecho sobre el brazo izquierdo. Entrelaza los dedos y gira las palmas alejándolas del cuerpo. Levanta lentamente los brazos hacia arriba y alejándolos del cuerpo, sintiendo un estiramiento en la espalda y el pecho. Mantén el estiramiento durante 15-30 segundos, luego suelta. Repite del lado opuesto.', 'Stand tall with your feet shoulder-width apart. Extend your arms straight out in front of you, parallel to the ground. Cross your arms in front of your body, with your right arm over your left arm. Interlock your fingers and rotate your palms away from your body. Slowly raise your arms up and away from your body, feeling a stretch in your back and chest. Hold the stretch for 15-30 seconds, then release. Repeat on the opposite side.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1405-chfnQnM.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1405-chfnQnM.gif', 'chfnQnM', '© Gym visual — https://gymvisual.com/'),
('1473', 'backward jump', 'Ponte de pie con los pies separados a la altura de los hombros. Flexiona ligeramente las rodillas y salta hacia atrás, impulsándote con ambos pies. Aterriza suavemente sobre la punta de los pies, flexionando las rodillas para absorber el impacto. Repite el número de repeticiones deseado.', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'quads', '{"hamstrings","glutes","calves"}', 'Ponte de pie con los pies separados a la altura de los hombros. Flexiona ligeramente las rodillas y salta hacia atrás, impulsándote con ambos pies. Aterriza suavemente sobre la punta de los pies, flexionando las rodillas para absorber el impacto. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart. Bend your knees slightly and jump backwards, pushing off with both feet. Land softly on the balls of your feet, bending your knees to absorb the impact. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1473-SaDOwk7.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1473-SaDOwk7.gif', 'SaDOwk7', '© Gym visual — https://gymvisual.com/'),
('0020', 'balance board', 'Coloca la tabla de equilibrio sobre una superficie plana. Sube a la tabla de equilibrio con un pie, asegurándote de que esté centrado. Desplaza lentamente tu peso hacia el pie que está sobre la tabla de equilibrio, manteniendo el core activado. Mantén el equilibrio y la estabilidad mientras sostiene', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'quads', '{"calves","hamstrings","glutes"}', 'Coloca la tabla de equilibrio sobre una superficie plana. Sube a la tabla de equilibrio con un pie, asegurándote de que esté centrado. Desplaza lentamente tu peso hacia el pie que está sobre la tabla de equilibrio, manteniendo el core activado. Mantén el equilibrio y la estabilidad mientras sostienes la posición durante el tiempo deseado. Repite el ejercicio con el otro pie.', 'Place the balance board on a flat surface. Step onto the balance board with one foot, ensuring it is centered. Slowly shift your weight onto the foot on the balance board, keeping your core engaged. Maintain your balance and stability as you hold the position for a desired amount of time. Repeat the exercise with the other foot.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0020-xAySMB0.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0020-xAySMB0.gif', 'xAySMB0', '© Gym visual — https://gymvisual.com/'),
('0968', 'band alternating biceps curl', 'Ponte de pie con los pies separados a la altura de los hombros y sostén la banda con un agarre supino, con las palmas hacia arriba. Mantén los codos cerca de los costados y flexiona lentamente un brazo hacia el hombro, apretando el bíceps en la parte superior. Baja el brazo de vuelta a la posición i', 'upper arms', 'band', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ponte de pie con los pies separados a la altura de los hombros y sostén la banda con un agarre supino, con las palmas hacia arriba. Mantén los codos cerca de los costados y flexiona lentamente un brazo hacia el hombro, apretando el bíceps en la parte superior. Baja el brazo de vuelta a la posición inicial y repite con el otro brazo. Continúa alternando los brazos durante el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and hold the band with an underhand grip, palms facing up. Keep your elbows close to your sides and slowly curl one arm up towards your shoulder, squeezing your biceps at the top. Lower the arm back down to the starting position and repeat with the other arm. Continue alternating arms for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0968-3omWx6P.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0968-3omWx6P.gif', '3omWx6P', '© Gym visual — https://gymvisual.com/'),
('0969', 'band alternating v-up', 'Túmbate sobre tu espalda con las piernas rectas y los brazos extendidos por encima de la cabeza, sosteniendo la banda. Activa el abdomen y levanta las piernas y la parte superior del cuerpo del suelo al mismo tiempo, llevando las manos hacia los dedos de los pies. Mientras bajas las piernas y la par', 'waist', 'band', 'waist', 'waist', 'abs', '{"hip flexors"}', 'Túmbate sobre tu espalda con las piernas rectas y los brazos extendidos por encima de la cabeza, sosteniendo la banda. Activa el abdomen y levanta las piernas y la parte superior del cuerpo del suelo al mismo tiempo, llevando las manos hacia los dedos de los pies. Mientras bajas las piernas y la parte superior del cuerpo de nuevo, cambia la posición de las piernas, cruzando una sobre la otra. Repite el movimiento, alternando la posición de las piernas en cada repetición. Continúa durante el número de repeticiones deseado.', 'Lie flat on your back with your legs straight and your arms extended overhead, holding the band. Engage your abs and lift your legs and upper body off the ground simultaneously, reaching your hands towards your toes. As you lower your legs and upper body back down, switch the position of your legs, crossing one over the other. Repeat the movement, alternating the position of your legs with each repetition. Continue for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0969-ztAa1RK.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0969-ztAa1RK.gif', 'ztAa1RK', '© Gym visual — https://gymvisual.com/'),
('0970', 'band assisted pull-up', 'Sujeta la banda a una barra de dominadas o a un punto de anclaje resistente. Pisa la banda y agarra la barra con las palmas mirando hacia afuera, con las manos un poco más separadas que el ancho de los hombros. Cuélgate con los brazos completamente extendidos, manteniendo el core activado y los homb', 'back', 'band', 'back', 'back', 'lats', '{"biceps","forearms"}', 'Sujeta la banda a una barra de dominadas o a un punto de anclaje resistente. Pisa la banda y agarra la barra con las palmas mirando hacia afuera, con las manos un poco más separadas que el ancho de los hombros. Cuélgate con los brazos completamente extendidos, manteniendo el core activado y los hombros abajo y atrás. Sube el cuerpo hacia la barra juntando los omóplatos y llevando los codos hacia abajo, en dirección a las caderas. Continúa subiendo hasta que la barbilla quede por encima de la barra, luego bájate lentamente de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Attach the band to a pull-up bar or sturdy anchor point. Step onto the band and grip the bar with your palms facing away from you, hands slightly wider than shoulder-width apart. Hang with your arms fully extended, keeping your core engaged and your shoulders down and back. Pull your body up towards the bar by squeezing your shoulder blades together and driving your elbows down towards your hips. Continue pulling until your chin is above the bar, then slowly lower yourself back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0970-r1XNRYB.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0970-r1XNRYB.gif', 'r1XNRYB', '© Gym visual — https://gymvisual.com/'),
('0971', 'band assisted wheel rollerout', 'Arrodíllate en el suelo y sostén las agarraderas de la banda con ambas manos, con las palmas hacia abajo. Coloca la banda en el suelo frente a ti y posiciona las manos separadas a la altura de los hombros. Activa el core y rueda lentamente la rueda hacia adelante, extendiendo el cuerpo lo más que pu', 'waist', 'band', 'waist', 'waist', 'abs', '{"lower back"}', 'Arrodíllate en el suelo y sostén las agarraderas de la banda con ambas manos, con las palmas hacia abajo. Coloca la banda en el suelo frente a ti y posiciona las manos separadas a la altura de los hombros. Activa el core y rueda lentamente la rueda hacia adelante, extendiendo el cuerpo lo más que puedas mientras mantienes el control. Haz una pausa por un momento en el punto más lejano, luego rueda lentamente la rueda de vuelta hacia las rodillas para regresar a la posición inicial. Repite el número de repeticiones deseado.', 'Kneel on the floor and hold the handles of the band with both hands, palms facing down. Place the band on the ground in front of you and position your hands shoulder-width apart. Engage your core and slowly roll the wheel forward, extending your body as far as you can while maintaining control. Pause for a moment at the furthest point, then slowly roll the wheel back towards your knees to return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0971-zhF9lW4.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0971-zhF9lW4.gif', 'zhF9lW4', '© Gym visual — https://gymvisual.com/'),
('1254', 'band bench press', 'Túmbate sobre un banco con los pies apoyados en el suelo y la espalda presionada contra el banco. Agarra las agarraderas de la banda con un agarre prono, un poco más separadas que el ancho de los hombros. Extiende los brazos por completo, empujando las bandas alejándolas del pecho. Baja lentamente l', 'chest', 'band', 'chest', 'chest', 'pectorals', '{"triceps","shoulders"}', 'Túmbate sobre un banco con los pies apoyados en el suelo y la espalda presionada contra el banco. Agarra las agarraderas de la banda con un agarre prono, un poco más separadas que el ancho de los hombros. Extiende los brazos por completo, empujando las bandas alejándolas del pecho. Baja lentamente las bandas de vuelta hacia el pecho, manteniendo los codos en un ángulo de 90 grados. Repite el número de repeticiones deseado.', 'Lie flat on a bench with your feet flat on the ground and your back pressed against the bench. Grasp the band handles with an overhand grip, slightly wider than shoulder-width apart. Extend your arms fully, pushing the bands away from your chest. Slowly lower the bands back down to your chest, keeping your elbows at a 90-degree angle. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1254-khlHMqs.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1254-khlHMqs.gif', 'khlHMqs', '© Gym visual — https://gymvisual.com/'),
('0980', 'band bent-over hip extension', 'Sujeta la banda a un punto de anclaje resistente a la altura del tobillo. Ponte de pie de espaldas al punto de anclaje con los pies separados a la altura de los hombros. Da un paso atrás para generar tensión en la banda, manteniendo las rodillas ligeramente flexionadas. Flexiona las caderas e inclín', 'upper legs', 'band', 'upper legs', 'upper legs', 'glutes', '{"hamstrings","lower back"}', 'Sujeta la banda a un punto de anclaje resistente a la altura del tobillo. Ponte de pie de espaldas al punto de anclaje con los pies separados a la altura de los hombros. Da un paso atrás para generar tensión en la banda, manteniendo las rodillas ligeramente flexionadas. Flexiona las caderas e inclínate hacia adelante, manteniendo la columna en posición neutral. Extiende la pierna derecha recta hacia atrás, apretando los glúteos en la parte superior. Baja la pierna derecha de vuelta y repite con la pierna izquierda. Continúa alternando las piernas durante el número de repeticiones deseado.', 'Attach the band to a sturdy anchor point at ankle height. Stand facing away from the anchor point with your feet shoulder-width apart. Step back to create tension in the band, keeping your knees slightly bent. Hinge at the hips and lean forward, maintaining a neutral spine. Extend your right leg straight back, squeezing your glutes at the top. Lower your right leg back down and repeat with the left leg. Continue alternating legs for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0980-wSScovH.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0980-wSScovH.gif', 'wSScovH', '© Gym visual — https://gymvisual.com/'),
('0972', 'band bicycle crunch', 'Túmbate sobre tu espalda con las manos detrás de la cabeza y las rodillas flexionadas. Levanta los pies del suelo y lleva la rodilla derecha hacia el pecho mientras simultáneamente giras el torso para llevar el codo izquierdo hacia la rodilla derecha. Estira la pierna derecha mientras llevas la rodi', 'waist', 'band', 'waist', 'waist', 'abs', '{"hip flexors","obliques"}', 'Túmbate sobre tu espalda con las manos detrás de la cabeza y las rodillas flexionadas. Levanta los pies del suelo y lleva la rodilla derecha hacia el pecho mientras simultáneamente giras el torso para llevar el codo izquierdo hacia la rodilla derecha. Estira la pierna derecha mientras llevas la rodilla izquierda hacia el pecho y giras el torso para llevar el codo derecho hacia la rodilla izquierda. Continúa alternando el movimiento de giro, como si estuvieras pedaleando una bicicleta, manteniendo el core activado durante todo el movimiento. Repite el número de repeticiones deseado.', 'Lie flat on your back with your hands behind your head and your knees bent. Lift your feet off the ground and bring your right knee towards your chest while simultaneously twisting your torso to bring your left elbow towards your right knee. Straighten your right leg while bringing your left knee towards your chest and twisting your torso to bring your right elbow towards your left knee. Continue alternating the twisting motion, as if you are pedaling a bicycle, while keeping your core engaged throughout the movement. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0972-tZkGYZ9.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0972-tZkGYZ9.gif', 'tZkGYZ9', '© Gym visual — https://gymvisual.com/'),
('0974', 'band close-grip pulldown', 'Sujeta la banda a un punto de anclaje alto, como una barra de dominadas o una viga resistente. Ponte de pie frente al punto de anclaje y agarra la banda con un agarre supino, con las manos separadas a la altura de los hombros. Da un paso atrás para generar tensión en la banda, manteniendo los pies s', 'back', 'band', 'back', 'back', 'lats', '{"biceps","forearms"}', 'Sujeta la banda a un punto de anclaje alto, como una barra de dominadas o una viga resistente. Ponte de pie frente al punto de anclaje y agarra la banda con un agarre supino, con las manos separadas a la altura de los hombros. Da un paso atrás para generar tensión en la banda, manteniendo los pies separados a la altura de las caderas. Activa el core y mantén la espalda recta mientras tiras de la banda hacia el pecho, juntando los omóplatos. Haz una pausa por un momento en la parte inferior del movimiento, luego suelta lentamente la banda de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Attach the band to a high anchor point, such as a pull-up bar or sturdy beam. Stand facing the anchor point and grab the band with an underhand grip, hands shoulder-width apart. Step back to create tension in the band, keeping your feet hip-width apart. Engage your core and keep your back straight as you pull the band down towards your chest, squeezing your shoulder blades together. Pause for a moment at the bottom of the movement, then slowly release the band back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0974-DptumMx.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0974-DptumMx.gif', 'DptumMx', '© Gym visual — https://gymvisual.com/'),
('0975', 'band close-grip push-up', 'Coloca una banda alrededor de la parte superior de los brazos, justo por encima de los codos. Adopta una posición de flexión de brazos con las manos justo debajo de los hombros y el cuerpo en línea recta desde la cabeza hasta los talones. Flexiona los codos y baja el pecho hacia el suelo, manteniend', 'upper arms', 'band', 'upper arms', 'upper arms', 'triceps', '{"chest","shoulders"}', 'Coloca una banda alrededor de la parte superior de los brazos, justo por encima de los codos. Adopta una posición de flexión de brazos con las manos justo debajo de los hombros y el cuerpo en línea recta desde la cabeza hasta los talones. Flexiona los codos y baja el pecho hacia el suelo, manteniendo los codos cerca de los costados. Empuja con las palmas para extender los brazos y regresar a la posición inicial. Repite el número de repeticiones deseado.', 'Place a band around your upper arms, just above the elbows. Assume a push-up position with your hands directly under your shoulders and your body in a straight line from head to heels. Bend your elbows and lower your chest towards the ground, keeping your elbows close to your sides. Push through your palms to extend your arms and return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0975-ufaxB52.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0975-ufaxB52.gif', 'ufaxB52', '© Gym visual — https://gymvisual.com/'),
('0976', 'band concentration curl', 'Siéntate en un banco o silla con las piernas separadas y los pies apoyados en el suelo. Sostén un extremo de la banda en la mano y pisa el otro extremo con el pie del mismo lado. Inclínate ligeramente hacia adelante y apoya el codo en la parte interna del muslo, justo encima de la rodilla. Con la pa', 'upper arms', 'band', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Siéntate en un banco o silla con las piernas separadas y los pies apoyados en el suelo. Sostén un extremo de la banda en la mano y pisa el otro extremo con el pie del mismo lado. Inclínate ligeramente hacia adelante y apoya el codo en la parte interna del muslo, justo encima de la rodilla. Con la palma hacia arriba, flexiona lentamente la mano hacia el hombro, manteniendo quieta la parte superior del brazo. Haz una pausa por un momento en la parte superior, luego baja lentamente la mano de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia de lado.', 'Sit on a bench or chair with your legs spread apart and your feet flat on the ground. Hold one end of the band in your hand and step on the other end with your foot on the same side. Lean forward slightly and rest your elbow on the inside of your thigh, just above the knee. With your palm facing up, slowly curl your hand towards your shoulder, keeping your upper arm stationary. Pause for a moment at the top, then slowly lower your hand back down to the starting position. Repeat for the desired number of repetitions, then switch sides.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0976-kmVVAfu.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0976-kmVVAfu.gif', 'kmVVAfu', '© Gym visual — https://gymvisual.com/'),
('3117', 'band fixed back close grip pulldown', 'Sujeta la banda a un punto fijo por encima de ti, como una barra de dominadas o una viga resistente. Siéntate en un banco o silla frente a la banda, con los pies apoyados en el suelo y las rodillas flexionadas. Agarra la banda con un agarre cerrado, con las palmas hacia ti. Mantén la espalda recta y', 'back', 'band', 'back', 'back', 'lats', '{"biceps","forearms"}', 'Sujeta la banda a un punto fijo por encima de ti, como una barra de dominadas o una viga resistente. Siéntate en un banco o silla frente a la banda, con los pies apoyados en el suelo y las rodillas flexionadas. Agarra la banda con un agarre cerrado, con las palmas hacia ti. Mantén la espalda recta y activa el core. Tira de la banda hacia el pecho, juntando los omóplatos. Haz una pausa por un momento en la parte inferior del movimiento, sintiendo la contracción en los dorsales. Suelta lentamente la banda de vuelta a la posición inicial, manteniendo el control durante todo el movimiento. Repite el número de repeticiones deseado.', 'Attach the band to a fixed point above you, such as a pull-up bar or sturdy beam. Sit down on a bench or chair facing the band, with your feet flat on the ground and your knees bent. Grasp the band with a close grip, palms facing towards you. Keep your back straight and engage your core. Pull the band down towards your chest, squeezing your shoulder blades together. Pause for a moment at the bottom of the movement, feeling the contraction in your lats. Slowly release the band back to the starting position, maintaining control throughout the movement. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3117-4LoWllp.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3117-4LoWllp.gif', '4LoWllp', '© Gym visual — https://gymvisual.com/'),
('3116', 'band fixed back underhand pulldown', 'Sujeta la banda a un punto de anclaje resistente por encima de tu cabeza. Ponte de pie frente al punto de anclaje con los pies separados a la altura de los hombros. Agarra la banda con un agarre supino, con las manos un poco más separadas que el ancho de los hombros. Da un paso atrás para generar te', 'back', 'band', 'back', 'back', 'lats', '{"biceps","rhomboids","rear deltoids"}', 'Sujeta la banda a un punto de anclaje resistente por encima de tu cabeza. Ponte de pie frente al punto de anclaje con los pies separados a la altura de los hombros. Agarra la banda con un agarre supino, con las manos un poco más separadas que el ancho de los hombros. Da un paso atrás para generar tensión en la banda, manteniendo los brazos completamente extendidos. Activa el core y junta los omóplatos. Tira de la banda hacia el pecho, guiando el movimiento con los codos. Haz una pausa por un momento en la parte inferior del movimiento, sintiendo la contracción en los dorsales. Suelta lentamente la tensión de la banda y regresa a la posición inicial. Repite el número de repeticiones deseado.', 'Attach the band to a sturdy anchor point above your head. Stand facing the anchor point with your feet shoulder-width apart. Grasp the band with an underhand grip, hands slightly wider than shoulder-width apart. Step back to create tension in the band, keeping your arms fully extended. Engage your core and squeeze your shoulder blades together. Pull the band down towards your chest, leading with your elbows. Pause for a moment at the bottom of the movement, feeling the contraction in your lats. Slowly release the tension in the band and return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3116-ZH68exZ.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3116-ZH68exZ.gif', 'ZH68exZ', '© Gym visual — https://gymvisual.com/'),
('0977', 'band front lateral raise', 'Ponte de pie con los pies separados a la altura de los hombros y sostén la banda frente a los muslos con las palmas hacia abajo. Mantén los brazos rectos y levanta la banda frente a ti hasta que los brazos queden paralelos al suelo. Haz una pausa por un momento en la parte superior, luego baja lenta', 'shoulders', 'band', 'shoulders', 'shoulders', 'delts', '{"traps","upper back"}', 'Ponte de pie con los pies separados a la altura de los hombros y sostén la banda frente a los muslos con las palmas hacia abajo. Mantén los brazos rectos y levanta la banda frente a ti hasta que los brazos queden paralelos al suelo. Haz una pausa por un momento en la parte superior, luego baja lentamente la banda de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and hold the band in front of your thighs with your palms facing down. Keep your arms straight and lift the band up in front of you until your arms are parallel to the ground. Pause for a moment at the top, then slowly lower the band back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0977-sTg7iys.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0977-sTg7iys.gif', 'sTg7iys', '© Gym visual — https://gymvisual.com/'),
('0978', 'band front raise', 'Ponte de pie con los pies separados a la altura de los hombros y sostén la banda frente a los muslos con las palmas hacia abajo. Mantén los brazos rectos y levántalos lentamente hacia adelante hasta que queden paralelos al suelo. Haz una pausa por un momento en la parte superior, luego baja lentamen', 'shoulders', 'band', 'shoulders', 'shoulders', 'delts', '{"triceps","upper back"}', 'Ponte de pie con los pies separados a la altura de los hombros y sostén la banda frente a los muslos con las palmas hacia abajo. Mantén los brazos rectos y levántalos lentamente hacia adelante hasta que queden paralelos al suelo. Haz una pausa por un momento en la parte superior, luego baja lentamente los brazos de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and hold the band in front of your thighs with your palms facing down. Keep your arms straight and slowly raise them forward until they are parallel to the ground. Pause for a moment at the top, then slowly lower your arms back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0978-TFA88iB.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0978-TFA88iB.gif', 'TFA88iB', '© Gym visual — https://gymvisual.com/'),
('1408', 'band hip lift', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Coloca una banda elástica justo por encima de las rodillas. Activa los glúteos y los músculos del core. Presiona los talones contra el suelo y levanta las caderas del suelo, apretando los glúteos en la parte super', 'upper legs', 'band', 'upper legs', 'upper legs', 'glutes', '{"hamstrings","quadriceps"}', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Coloca una banda elástica justo por encima de las rodillas. Activa los glúteos y los músculos del core. Presiona los talones contra el suelo y levanta las caderas del suelo, apretando los glúteos en la parte superior. Haz una pausa por un momento en la parte superior, luego baja lentamente las caderas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie on your back with your knees bent and feet flat on the ground. Place a resistance band just above your knees. Engage your glutes and core muscles. Press your heels into the ground and lift your hips off the floor, squeezing your glutes at the top. Pause for a moment at the top, then slowly lower your hips back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1408-E4R8Hz1.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1408-E4R8Hz1.gif', 'E4R8Hz1', '© Gym visual — https://gymvisual.com/'),
('0979', 'band horizontal pallof press', 'Sujeta la banda a un punto de anclaje resistente a la altura de la cintura. Ponte de pie perpendicular al punto de anclaje con los pies separados a la altura de los hombros. Agarra la agarradera de la banda con ambas manos y aléjate del punto de anclaje para generar tensión en la banda. Lleva las ma', 'waist', 'band', 'waist', 'waist', 'abs', '{"obliques","glutes"}', 'Sujeta la banda a un punto de anclaje resistente a la altura de la cintura. Ponte de pie perpendicular al punto de anclaje con los pies separados a la altura de los hombros. Agarra la agarradera de la banda con ambas manos y aléjate del punto de anclaje para generar tensión en la banda. Lleva las manos hacia el pecho, manteniendo los codos flexionados y cerca del cuerpo. Activa el core y mantén una postura estable. Extiende los brazos rectos frente a ti, empujando la banda alejándola del cuerpo. Mantén la posición extendida durante unos segundos, enfocándote en mantener la tensión en el core. Lleva lentamente las manos de vuelta al pecho, resistiendo el tirón de la banda. Repite el número de repeticiones deseado.', 'Attach the band to a sturdy anchor point at waist height. Stand perpendicular to the anchor point with your feet shoulder-width apart. Grasp the band handle with both hands and step away from the anchor point to create tension in the band. Bring your hands to your chest, keeping your elbows bent and close to your body. Engage your core and maintain a stable stance. Extend your arms straight out in front of you, pushing the band away from your body. Hold the extended position for a few seconds, focusing on maintaining tension in your core. Slowly bring your hands back to your chest, resisting the pull of the band. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0979-9pa4H5m.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0979-9pa4H5m.gif', '9pa4H5m', '© Gym visual — https://gymvisual.com/'),
('0981', 'band jack knife sit-up', 'Túmbate sobre tu espalda con las piernas rectas y los brazos extendidos por encima de la cabeza, sosteniendo la banda. Activa el abdomen y levanta las piernas y la parte superior del cuerpo simultáneamente, llevando las manos hacia los pies. Haz una pausa por un momento en la parte superior, luego b', 'waist', 'band', 'waist', 'waist', 'abs', '{"hip flexors"}', 'Túmbate sobre tu espalda con las piernas rectas y los brazos extendidos por encima de la cabeza, sosteniendo la banda. Activa el abdomen y levanta las piernas y la parte superior del cuerpo simultáneamente, llevando las manos hacia los pies. Haz una pausa por un momento en la parte superior, luego baja lentamente las piernas y la parte superior del cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on your back with your legs straight and your arms extended overhead, holding the band. Engage your abs and lift your legs and upper body simultaneously, bringing your hands towards your feet. Pause for a moment at the top, then slowly lower your legs and upper body back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0981-KCBKjma.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0981-KCBKjma.gif', 'KCBKjma', '© Gym visual — https://gymvisual.com/'),
('0983', 'band kneeling one arm pulldown', 'Sujeta la banda a un punto de anclaje resistente por encima de tu cabeza. Arrodíllate y sostén la banda con una mano, con la palma hacia abajo. Extiende el brazo por completo por encima de la cabeza, manteniendo el codo ligeramente flexionado. Activa los dorsales y tira de la banda hacia el costado,', 'back', 'band', 'back', 'back', 'lats', '{"biceps","rhomboids"}', 'Sujeta la banda a un punto de anclaje resistente por encima de tu cabeza. Arrodíllate y sostén la banda con una mano, con la palma hacia abajo. Extiende el brazo por completo por encima de la cabeza, manteniendo el codo ligeramente flexionado. Activa los dorsales y tira de la banda hacia el costado, llevando el codo hacia las costillas. Haz una pausa por un momento en la parte inferior, luego suelta lentamente la tensión y regresa a la posición inicial. Repite el número de repeticiones deseado, luego cambia de lado.', 'Attach the band to a sturdy anchor point above your head. Kneel down and hold the band with one hand, palm facing down. Extend your arm fully overhead, keeping your elbow slightly bent. Engage your lat muscles and pull the band down towards your side, bringing your elbow towards your ribcage. Pause for a moment at the bottom, then slowly release the tension and return to the starting position. Repeat for the desired number of repetitions, then switch sides.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0983-pmnrOp0.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0983-pmnrOp0.gif', 'pmnrOp0', '© Gym visual — https://gymvisual.com/'),
('0985', 'band kneeling twisting crunch', 'Sujeta la banda a un punto de anclaje resistente a la altura de la cintura. Arrodíllate de espaldas al punto de anclaje y sostén la banda con ambas manos, manteniendo los codos flexionados y cerca de los costados. Activa el abdomen y gira lentamente el torso hacia un lado, llevando las manos hacia l', 'waist', 'band', 'waist', 'waist', 'abs', '{"obliques"}', 'Sujeta la banda a un punto de anclaje resistente a la altura de la cintura. Arrodíllate de espaldas al punto de anclaje y sostén la banda con ambas manos, manteniendo los codos flexionados y cerca de los costados. Activa el abdomen y gira lentamente el torso hacia un lado, llevando las manos hacia la cadera opuesta. Haz una pausa por un momento, luego regresa lentamente a la posición inicial. Repite del otro lado. Continúa alternando lados durante el número de repeticiones deseado.', 'Attach the band to a sturdy anchor point at waist height. Kneel down facing away from the anchor point and hold the band with both hands, keeping your elbows bent and close to your sides. Engage your abs and slowly twist your torso to one side, bringing your hands towards your opposite hip. Pause for a moment, then slowly return to the starting position. Repeat on the other side. Continue alternating sides for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0985-225x2Vd.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0985-225x2Vd.gif', '225x2Vd', '© Gym visual — https://gymvisual.com/'),
('0984', 'band lying hip internal rotation', 'Túmbate sobre tu espalda con las piernas rectas y una banda elástica enrollada alrededor de los pies. Flexiona las rodillas y llévalas hacia el pecho, manteniendo los pies juntos. Rota lentamente las rodillas hacia afuera, separándolas entre sí, mientras mantienes los pies juntos. Haz una pausa por ', 'upper legs', 'band', 'upper legs', 'upper legs', 'glutes', '{"hamstrings","quadriceps"}', 'Túmbate sobre tu espalda con las piernas rectas y una banda elástica enrollada alrededor de los pies. Flexiona las rodillas y llévalas hacia el pecho, manteniendo los pies juntos. Rota lentamente las rodillas hacia afuera, separándolas entre sí, mientras mantienes los pies juntos. Haz una pausa por un momento al final de la rotación, luego regresa lentamente a la posición inicial. Repite el número de repeticiones deseado.', 'Lie on your back with your legs straight and a resistance band looped around your feet. Bend your knees and bring them towards your chest, keeping your feet together. Slowly rotate your knees outwards, away from each other, while keeping your feet together. Pause for a moment at the end of the rotation, then slowly return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0984-vIICElP.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0984-vIICElP.gif', 'vIICElP', '© Gym visual — https://gymvisual.com/'),
('1002', 'band lying straight leg raise', 'Túmbate sobre tu espalda con las piernas rectas y los pies juntos. Coloca la banda alrededor de los arcos de los pies y sostén los extremos de la banda con las manos. Activando el abdomen, levanta ambas piernas del suelo hasta que queden perpendiculares al suelo. Haz una pausa por un momento en la p', 'waist', 'band', 'waist', 'waist', 'abs', '{"hip flexors"}', 'Túmbate sobre tu espalda con las piernas rectas y los pies juntos. Coloca la banda alrededor de los arcos de los pies y sostén los extremos de la banda con las manos. Activando el abdomen, levanta ambas piernas del suelo hasta que queden perpendiculares al suelo. Haz una pausa por un momento en la parte superior, luego baja lentamente las piernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on your back with your legs straight and your feet together. Place the band around the arches of your feet and hold the ends of the band with your hands. Engaging your abs, lift both legs off the ground until they are perpendicular to the floor. Pause for a moment at the top, then slowly lower your legs back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1002-bbLR7fB.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1002-bbLR7fB.gif', 'bbLR7fB', '© Gym visual — https://gymvisual.com/'),
('0986', 'band one arm overhead biceps curl', 'Ponte de pie con los pies separados a la altura de los hombros y coloca un extremo de la banda bajo el pie. Sostén el otro extremo de la banda con el brazo completamente extendido por encima de la cabeza, con la palma hacia adelante. Manteniendo quieta la parte superior del brazo, flexiona el antebr', 'upper arms', 'band', 'upper arms', 'upper arms', 'biceps', '{"forearms","shoulders"}', 'Ponte de pie con los pies separados a la altura de los hombros y coloca un extremo de la banda bajo el pie. Sostén el otro extremo de la banda con el brazo completamente extendido por encima de la cabeza, con la palma hacia adelante. Manteniendo quieta la parte superior del brazo, flexiona el antebrazo hacia el hombro, apretando el bíceps. Haz una pausa por un momento en la parte superior, luego baja lentamente el antebrazo de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia de brazo.', 'Stand with your feet shoulder-width apart and place one end of the band under your foot. Hold the other end of the band with your arm fully extended overhead, palm facing forward. Keeping your upper arm stationary, curl your forearm towards your shoulder, squeezing your biceps. Pause for a moment at the top, then slowly lower your forearm back to the starting position. Repeat for the desired number of repetitions, then switch arms.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0986-UNAB8ak.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0986-UNAB8ak.gif', 'UNAB8ak', '© Gym visual — https://gymvisual.com/'),
('0987', 'band one arm single leg split squat', 'Ponte de pie con los pies separados a la altura de las caderas y coloca una banda elástica alrededor de los tobillos. Extiende una pierna hacia adelante y apoya la parte superior del pie sobre un banco o escalón detrás de ti. Sujétate de un apoyo con una mano para mantener el equilibrio. Flexiona la', 'upper legs', 'band', 'upper legs', 'upper legs', 'quads', '{"glutes","hamstrings"}', 'Ponte de pie con los pies separados a la altura de las caderas y coloca una banda elástica alrededor de los tobillos. Extiende una pierna hacia adelante y apoya la parte superior del pie sobre un banco o escalón detrás de ti. Sujétate de un apoyo con una mano para mantener el equilibrio. Flexiona la pierna de apoyo y baja el cuerpo hacia una posición de sentadilla, manteniendo la rodilla alineada con los dedos del pie. Empuja con el talón para regresar a la posición inicial. Repite el número de repeticiones deseado, luego cambia de pierna.', 'Stand with your feet hip-width apart and place a resistance band around your ankles. Extend one leg forward and rest the top of your foot on a bench or step behind you. Hold onto a support with one hand for balance. Bend your standing leg and lower your body down into a squat position, keeping your knee in line with your toes. Push through your heel to return to the starting position. Repeat for the desired number of repetitions, then switch legs.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0987-arsYEd3.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0987-arsYEd3.gif', 'arsYEd3', '© Gym visual — https://gymvisual.com/'),
('0988', 'band one arm standing low row', 'Sujeta la banda a un punto de anclaje estable a la altura de la cintura. Ponte de pie frente al punto de anclaje con los pies separados a la altura de los hombros. Sostén la banda con una mano, con la palma hacia adentro, y da un paso atrás para generar tensión en la banda. Flexiona ligeramente las ', 'back', 'band', 'back', 'back', 'upper back', '{"biceps","shoulders"}', 'Sujeta la banda a un punto de anclaje estable a la altura de la cintura. Ponte de pie frente al punto de anclaje con los pies separados a la altura de los hombros. Sostén la banda con una mano, con la palma hacia adentro, y da un paso atrás para generar tensión en la banda. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta. Tira de la banda hacia la cintura, juntando los omóplatos. Haz una pausa por un momento en la parte superior del movimiento, luego suelta lentamente la banda de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia de lado.', 'Attach the band to a stable anchor point at waist height. Stand facing the anchor point with your feet shoulder-width apart. Hold the band with one hand, palm facing inward, and step back to create tension in the band. Bend your knees slightly and hinge forward at the hips, keeping your back straight. Pull the band towards your waist, squeezing your shoulder blades together. Pause for a moment at the top of the movement, then slowly release the band back to the starting position. Repeat for the desired number of repetitions, then switch sides.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0988-km0sQC0.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0988-km0sQC0.gif', 'km0sQC0', '© Gym visual — https://gymvisual.com/'),
('0989', 'band one arm twisting chest press', 'Sujeta la banda a un punto de anclaje resistente a la altura del pecho. Ponte de pie con el costado hacia el punto de anclaje y agarra la banda con una mano. Aléjate del punto de anclaje para generar tensión en la banda. Coloca los pies separados a la altura de los hombros y flexiona ligeramente las', 'chest', 'band', 'chest', 'chest', 'pectorals', '{"shoulders","triceps"}', 'Sujeta la banda a un punto de anclaje resistente a la altura del pecho. Ponte de pie con el costado hacia el punto de anclaje y agarra la banda con una mano. Aléjate del punto de anclaje para generar tensión en la banda. Coloca los pies separados a la altura de los hombros y flexiona ligeramente las rodillas. Lleva la mano que sostiene la banda a través del cuerpo, hacia el hombro opuesto. Manteniendo la tensión en la banda, empuja la mano hacia adelante y alejándola del cuerpo, extendiendo el brazo. Regresa lentamente a la posición inicial y repite el número de repeticiones deseado. Cambia de lado y repite el ejercicio con la otra mano.', 'Attach the band to a sturdy anchor point at chest height. Stand with your side facing the anchor point and grab the band with one hand. Step away from the anchor point to create tension in the band. Position your feet shoulder-width apart and slightly bend your knees. Bring your hand holding the band across your body, towards the opposite shoulder. While maintaining tension in the band, push your hand forward and away from your body, extending your arm. Slowly return to the starting position and repeat for the desired number of repetitions. Switch sides and repeat the exercise with the other hand.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0989-c16nYGA.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0989-c16nYGA.gif', 'c16nYGA', '© Gym visual — https://gymvisual.com/'),
('0990', 'band one arm twisting seated row', 'Siéntate en un banco o silla con los pies apoyados en el suelo y la espalda recta. Sostén la banda con una mano y extiende el brazo completamente frente a ti. Manteniendo la espalda recta, tira de la banda hacia el cuerpo flexionando el codo y juntando los omóplatos. Al mismo tiempo, gira el torso h', 'back', 'band', 'back', 'back', 'upper back', '{"biceps","shoulders"}', 'Siéntate en un banco o silla con los pies apoyados en el suelo y la espalda recta. Sostén la banda con una mano y extiende el brazo completamente frente a ti. Manteniendo la espalda recta, tira de la banda hacia el cuerpo flexionando el codo y juntando los omóplatos. Al mismo tiempo, gira el torso hacia el lado del brazo que tira. Haz una pausa por un momento en la parte superior, luego suelta lentamente la tensión de la banda y regresa a la posición inicial. Repite el número de repeticiones deseado, luego cambia al otro brazo.', 'Sit on a bench or chair with your feet flat on the ground and your back straight. Hold the band with one hand and extend your arm fully in front of you. Keeping your back straight, pull the band towards your body by bending your elbow and squeezing your shoulder blades together. At the same time, twist your torso towards the side of the pulling arm. Pause for a moment at the top, then slowly release the tension in the band and return to the starting position. Repeat for the desired number of repetitions, then switch to the other arm.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0990-DKBwJrL.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0990-DKBwJrL.gif', 'DKBwJrL', '© Gym visual — https://gymvisual.com/'),
('0991', 'band pull through', 'Sujeta una banda elástica a un punto de anclaje resistente a nivel del suelo. Ponte de pie de espaldas al punto de anclaje con los pies separados a la altura de los hombros. Da un paso adelante para generar tensión en la banda, manteniendo las rodillas ligeramente flexionadas. Flexiona las caderas y', 'upper legs', 'band', 'upper legs', 'upper legs', 'glutes', '{"hamstrings","lower back"}', 'Sujeta una banda elástica a un punto de anclaje resistente a nivel del suelo. Ponte de pie de espaldas al punto de anclaje con los pies separados a la altura de los hombros. Da un paso adelante para generar tensión en la banda, manteniendo las rodillas ligeramente flexionadas. Flexiona las caderas y lleva los glúteos hacia atrás, manteniendo una ligera flexión en las rodillas. Baja el torso hasta que quede paralelo al suelo, sintiendo un estiramiento en los isquiotibiales. Empuja las caderas hacia adelante y aprieta los glúteos para regresar a la posición inicial. Repite el número de repeticiones deseado.', 'Attach a resistance band to a sturdy anchor point at ground level. Stand facing away from the anchor point with your feet shoulder-width apart. Step forward to create tension in the band, keeping your knees slightly bent. Hinge at the hips and push your glutes back, maintaining a slight bend in your knees. Lower your torso until it is parallel to the ground, feeling a stretch in your hamstrings. Drive your hips forward and squeeze your glutes to return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0991-VtTbiP3.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0991-VtTbiP3.gif', 'VtTbiP3', '© Gym visual — https://gymvisual.com/'),
('0992', 'band push sit-up', 'Sujeta la banda de forma segura a un punto de anclaje estable. Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Sostén la banda con ambas manos y extiende los brazos rectos hacia el techo. Activando el abdomen, levanta lentamente la parte superior del cuerpo del', 'waist', 'band', 'waist', 'waist', 'abs', '{"shoulders","chest"}', 'Sujeta la banda de forma segura a un punto de anclaje estable. Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Sostén la banda con ambas manos y extiende los brazos rectos hacia el techo. Activando el abdomen, levanta lentamente la parte superior del cuerpo del suelo, curvándote hacia adelante hasta que tu torso forme un ángulo de 45 grados. Haz una pausa por un momento en la parte superior, luego baja lentamente la parte superior del cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Attach the band securely to a stable anchor point. Lie flat on your back with your knees bent and feet flat on the ground. Hold the band with both hands and extend your arms straight up towards the ceiling. Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle. Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0992-zFzbBfL.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0992-zFzbBfL.gif', 'zFzbBfL', '© Gym visual — https://gymvisual.com/'),
('0993', 'band reverse fly', 'Sujeta la banda a un objeto fijo a la altura del pecho. Ponte de pie con los pies separados a la altura de los hombros y sostén la banda con ambas manos frente a ti. Mantén los brazos rectos y levántalos hacia los lados hasta que queden paralelos al suelo. Junta los omóplatos en la parte superior de', 'shoulders', 'band', 'shoulders', 'shoulders', 'delts', '{"upper back","trapezius"}', 'Sujeta la banda a un objeto fijo a la altura del pecho. Ponte de pie con los pies separados a la altura de los hombros y sostén la banda con ambas manos frente a ti. Mantén los brazos rectos y levántalos hacia los lados hasta que queden paralelos al suelo. Junta los omóplatos en la parte superior del movimiento. Baja lentamente los brazos de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Attach the band to a stationary object at chest height. Stand with your feet shoulder-width apart and hold the band with both hands in front of you. Keep your arms straight and lift them out to the sides until they are parallel to the ground. Squeeze your shoulder blades together at the top of the movement. Slowly lower your arms back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0993-sTfvVsG.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0993-sTfvVsG.gif', 'sTfvVsG', '© Gym visual — https://gymvisual.com/'),
('0994', 'band reverse wrist curl', 'Siéntate en un banco o silla con los pies apoyados en el suelo. Sostén la banda con un agarre prono, con las palmas hacia abajo, y envuélvela alrededor de los dedos. Apoya los antebrazos sobre los muslos, con las muñecas colgando del borde. Flexiona lentamente las muñecas hacia arriba, apretando los', 'lower arms', 'band', 'lower arms', 'lower arms', 'forearms', '{"forearms"}', 'Siéntate en un banco o silla con los pies apoyados en el suelo. Sostén la banda con un agarre prono, con las palmas hacia abajo, y envuélvela alrededor de los dedos. Apoya los antebrazos sobre los muslos, con las muñecas colgando del borde. Flexiona lentamente las muñecas hacia arriba, apretando los antebrazos. Haz una pausa por un momento en la parte superior, luego baja lentamente las muñecas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a bench or chair with your feet flat on the ground. Hold the band with an overhand grip, palms facing down, and wrap it around your fingers. Rest your forearms on your thighs, with your wrists hanging off the edge. Slowly curl your wrists upward, squeezing your forearms. Pause for a moment at the top, then slowly lower your wrists back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0994-Ezpnw9d.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0994-Ezpnw9d.gif', 'Ezpnw9d', '© Gym visual — https://gymvisual.com/'),
('0996', 'band seated hip internal rotation', 'Siéntate en una silla o banco con la espalda recta y los pies apoyados en el suelo. Coloca una banda elástica alrededor de los muslos, justo por encima de las rodillas. Mantén las rodillas flexionadas formando un ángulo de 90 grados y los pies separados a la altura de los hombros. Activa los glúteos', 'upper legs', 'band', 'upper legs', 'upper legs', 'glutes', '{"hamstrings","quadriceps"}', 'Siéntate en una silla o banco con la espalda recta y los pies apoyados en el suelo. Coloca una banda elástica alrededor de los muslos, justo por encima de las rodillas. Mantén las rodillas flexionadas formando un ángulo de 90 grados y los pies separados a la altura de los hombros. Activa los glúteos y rota lentamente las rodillas hacia afuera, empujando contra la resistencia de la banda. Haz una pausa por un momento al final del movimiento, luego regresa lentamente a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a chair or bench with your back straight and feet flat on the ground. Place a resistance band around your thighs, just above your knees. Keep your knees bent at a 90-degree angle and your feet shoulder-width apart. Engage your glutes and slowly rotate your knees outward, pushing against the resistance of the band. Pause for a moment at the end of the movement, then slowly return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0996-9gbyYKk.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0996-9gbyYKk.gif', '9gbyYKk', '© Gym visual — https://gymvisual.com/'),
('1011', 'band seated twist', 'Siéntate en el suelo con las piernas extendidas frente a ti y la espalda recta. Envuelve la banda alrededor de la cintura y sostén los extremos con ambas manos. Activa el abdomen y gira lentamente el torso hacia un lado, manteniendo la espalda recta y los pies en el suelo. Haz una pausa por un momen', 'waist', 'band', 'waist', 'waist', 'abs', '{"obliques"}', 'Siéntate en el suelo con las piernas extendidas frente a ti y la espalda recta. Envuelve la banda alrededor de la cintura y sostén los extremos con ambas manos. Activa el abdomen y gira lentamente el torso hacia un lado, manteniendo la espalda recta y los pies en el suelo. Haz una pausa por un momento al final de la rotación, luego regresa lentamente a la posición inicial. Repite el giro hacia el otro lado. Continúa alternando lados durante el número de repeticiones deseado.', 'Sit on the ground with your legs extended in front of you and your back straight. Wrap the band around your waist and hold the ends with both hands. Engage your abs and slowly twist your torso to one side, keeping your back straight and your feet on the ground. Pause for a moment at the end of the twist, then slowly return to the starting position. Repeat the twist to the other side. Continue alternating sides for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1011-S1JXDAG.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1011-S1JXDAG.gif', 'S1JXDAG', '© Gym visual — https://gymvisual.com/'),
('0997', 'band shoulder press', 'Ponte de pie con los pies separados a la altura de los hombros y coloca la banda bajo los pies. Sostén la banda con las palmas hacia adelante y eleva las manos a la altura de los hombros, con los codos flexionados. Empuja la banda por encima de la cabeza, extendiendo completamente los brazos. Haz un', 'shoulders', 'band', 'shoulders', 'shoulders', 'delts', '{"triceps","upper back"}', 'Ponte de pie con los pies separados a la altura de los hombros y coloca la banda bajo los pies. Sostén la banda con las palmas hacia adelante y eleva las manos a la altura de los hombros, con los codos flexionados. Empuja la banda por encima de la cabeza, extendiendo completamente los brazos. Haz una pausa por un momento en la parte superior, luego baja lentamente la banda de vuelta a la altura de los hombros. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and place the band under your feet. Hold the band with your palms facing forward and raise your hands to shoulder height, elbows bent. Press the band overhead, fully extending your arms. Pause for a moment at the top, then slowly lower the band back to shoulder height. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0997-peAeMR3.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0997-peAeMR3.gif', 'peAeMR3', '© Gym visual — https://gymvisual.com/'),
('1018', 'band shrug', 'Ponte de pie con los pies separados a la altura de los hombros y coloca la banda bajo los pies, sosteniendo los extremos con las manos. Mantén los brazos rectos y relajados, y deja que la banda cuelgue frente a los muslos. Activa los trapecios encogiendo los hombros hacia arriba, levantando la banda', 'back', 'band', 'back', 'back', 'traps', '{"shoulders"}', 'Ponte de pie con los pies separados a la altura de los hombros y coloca la banda bajo los pies, sosteniendo los extremos con las manos. Mantén los brazos rectos y relajados, y deja que la banda cuelgue frente a los muslos. Activa los trapecios encogiendo los hombros hacia arriba, levantando la banda lo más alto posible. Mantén la contracción por un momento, luego baja lentamente los hombros de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and place the band under your feet, holding the ends with your hands. Keep your arms straight and relaxed, and let the band hang in front of your thighs. Engage your traps by shrugging your shoulders upward, lifting the band as high as possible. Hold the contraction for a moment, then slowly lower your shoulders back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1018-trmte8s.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1018-trmte8s.gif', 'trmte8s', '© Gym visual — https://gymvisual.com/'),
('0998', 'band side triceps extension', 'Ponte de pie con los pies separados a la altura de los hombros y sostén la banda con ambas manos, con las palmas hacia abajo. Extiende los brazos hacia los lados, manteniéndolos paralelos al suelo. Flexiona lentamente los codos y lleva las manos hacia los hombros, manteniendo quieta la parte superio', 'upper arms', 'band', 'upper arms', 'upper arms', 'triceps', '{"shoulders"}', 'Ponte de pie con los pies separados a la altura de los hombros y sostén la banda con ambas manos, con las palmas hacia abajo. Extiende los brazos hacia los lados, manteniéndolos paralelos al suelo. Flexiona lentamente los codos y lleva las manos hacia los hombros, manteniendo quieta la parte superior de los brazos. Haz una pausa por un momento, luego extiende lentamente los brazos de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and hold the band with both hands, palms facing down. Extend your arms straight out to the sides, keeping them parallel to the ground. Slowly bend your elbows and bring your hands towards your shoulders, keeping your upper arms still. Pause for a moment, then slowly extend your arms back out to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0998-obe5LMq.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0998-obe5LMq.gif', 'obe5LMq', '© Gym visual — https://gymvisual.com/'),
('0999', 'band single leg calf raise', 'Ponte de pie con los pies separados a la altura de las caderas y coloca la banda alrededor de la base de los dedos del pie izquierdo. Sujétate de un objeto estable para mantener el equilibrio si es necesario. Levanta lentamente el talón izquierdo del suelo, llevando el peso del cuerpo hacia la punta', 'lower legs', 'band', 'lower legs', 'lower legs', 'calves', '{"ankles","feet"}', 'Ponte de pie con los pies separados a la altura de las caderas y coloca la banda alrededor de la base de los dedos del pie izquierdo. Sujétate de un objeto estable para mantener el equilibrio si es necesario. Levanta lentamente el talón izquierdo del suelo, llevando el peso del cuerpo hacia la punta del pie. Haz una pausa por un momento en la parte superior, luego baja lentamente el talón izquierdo de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia a la pierna derecha.', 'Stand with your feet hip-width apart and place the band around the ball of your left foot. Hold onto a stable object for balance if needed. Slowly raise your left heel off the ground, lifting your body weight onto the ball of your foot. Pause for a moment at the top, then slowly lower your left heel back down to the starting position. Repeat for the desired number of repetitions, then switch to the right leg.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0999-9JprnPh.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0999-9JprnPh.gif', '9JprnPh', '© Gym visual — https://gymvisual.com/'),
('1000', 'band single leg reverse calf raise', 'Ponte de pie con los pies separados a la altura de las caderas y coloca la banda alrededor de la base de los dedos del pie. Sujétate de un objeto estable para mantener el equilibrio. Levanta lentamente el talón del suelo, llevando el peso del cuerpo hacia la punta del pie. Haz una pausa por un momen', 'lower legs', 'band', 'lower legs', 'lower legs', 'calves', '{"hamstrings","glutes"}', 'Ponte de pie con los pies separados a la altura de las caderas y coloca la banda alrededor de la base de los dedos del pie. Sujétate de un objeto estable para mantener el equilibrio. Levanta lentamente el talón del suelo, llevando el peso del cuerpo hacia la punta del pie. Haz una pausa por un momento en la parte superior, luego baja lentamente el talón de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia a la otra pierna.', 'Stand with your feet hip-width apart and place the band around the ball of your foot. Hold onto a stable object for balance. Slowly raise your heel off the ground, lifting your body weight onto the ball of your foot. Pause for a moment at the top, then slowly lower your heel back down to the starting position. Repeat for the desired number of repetitions, then switch to the other leg.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1000-QsSQWbf.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1000-QsSQWbf.gif', 'QsSQWbf', '© Gym visual — https://gymvisual.com/'),
('1001', 'band single leg split squat', 'Ponte de pie con los pies separados a la altura de las caderas y coloca una banda elástica alrededor de los tobillos. Da un paso grande hacia adelante con el pie derecho y un paso más pequeño hacia atrás con el pie izquierdo. Flexiona las rodillas y baja el cuerpo hasta que el muslo derecho quede pa', 'upper legs', 'band', 'upper legs', 'upper legs', 'quads', '{"glutes","hamstrings"}', 'Ponte de pie con los pies separados a la altura de las caderas y coloca una banda elástica alrededor de los tobillos. Da un paso grande hacia adelante con el pie derecho y un paso más pequeño hacia atrás con el pie izquierdo. Flexiona las rodillas y baja el cuerpo hasta que el muslo derecho quede paralelo al suelo, manteniendo la rodilla izquierda ligeramente por encima del suelo. Empuja con el talón derecho para regresar a la posición inicial. Repite del otro lado.', 'Stand with your feet hip-width apart and place a resistance band around your ankles. Take a big step forward with your right foot and a smaller step back with your left foot. Bend your knees and lower your body until your right thigh is parallel to the ground, keeping your left knee slightly above the ground. Push through your right heel to return to the starting position. Repeat on the other side.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1001-y8bYM8w.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1001-y8bYM8w.gif', 'y8bYM8w', '© Gym visual — https://gymvisual.com/'),
('1004', 'band squat', 'Ponte de pie con los pies separados a la altura de los hombros, con la banda colocada justo por encima de las rodillas. Manteniendo el pecho arriba y el core activado, lleva las caderas hacia atrás y flexiona las rodillas para bajar a una posición de sentadilla. Asegúrate de que las rodillas se alin', 'upper legs', 'band', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves"}', 'Ponte de pie con los pies separados a la altura de los hombros, con la banda colocada justo por encima de las rodillas. Manteniendo el pecho arriba y el core activado, lleva las caderas hacia atrás y flexiona las rodillas para bajar a una posición de sentadilla. Asegúrate de que las rodillas se alineen con los dedos de los pies y de que el peso recaiga en los talones. Haz una pausa por un momento en la parte inferior, luego empuja con los talones para regresar a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, with the band placed just above your knees. Keeping your chest up and core engaged, push your hips back and bend your knees to lower into a squat position. Make sure your knees are tracking over your toes and your weight is in your heels. Pause for a moment at the bottom, then push through your heels to return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1004-TUZLh71.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1004-TUZLh71.gif', 'TUZLh71', '© Gym visual — https://gymvisual.com/'),
('1003', 'band squat row', 'Sujeta la banda a un punto de anclaje resistente a la altura de la cintura. Ponte de pie frente al punto de anclaje con los pies separados a la altura de los hombros. Sostén las agarraderas de la banda con las palmas mirándose entre sí y los brazos extendidos frente a ti. Flexiona las rodillas y baj', 'upper legs', 'band', 'upper legs', 'upper legs', 'glutes', '{"hamstrings","quadriceps","back"}', 'Sujeta la banda a un punto de anclaje resistente a la altura de la cintura. Ponte de pie frente al punto de anclaje con los pies separados a la altura de los hombros. Sostén las agarraderas de la banda con las palmas mirándose entre sí y los brazos extendidos frente a ti. Flexiona las rodillas y baja a una posición de sentadilla, manteniendo la espalda recta y el pecho elevado. Desde la posición de sentadilla, tira de las agarraderas de la banda hacia el cuerpo, juntando los omóplatos. Haz una pausa por un momento en la parte superior, luego suelta lentamente la tensión y regresa a la posición inicial. Repite el número de repeticiones deseado.', 'Attach the band to a sturdy anchor point at waist height. Stand facing the anchor point with your feet shoulder-width apart. Hold the band handles with your palms facing each other and your arms extended in front of you. Bend your knees and lower into a squat position, keeping your back straight and chest lifted. From the squat position, pull the band handles towards your body, squeezing your shoulder blades together. Pause for a moment at the top, then slowly release the tension and return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1003-w1NOByi.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1003-w1NOByi.gif', 'w1NOByi', '© Gym visual — https://gymvisual.com/'),
('1005', 'band standing crunch', 'Sujeta la banda a un punto de anclaje resistente a la altura de la cintura. Ponte de pie de espaldas al punto de anclaje con los pies separados a la altura de los hombros. Sostén la banda con ambas manos y llévala hacia el pecho, manteniendo los codos flexionados y cerca del cuerpo. Activa el abdome', 'waist', 'band', 'waist', 'waist', 'abs', '{"obliques"}', 'Sujeta la banda a un punto de anclaje resistente a la altura de la cintura. Ponte de pie de espaldas al punto de anclaje con los pies separados a la altura de los hombros. Sostén la banda con ambas manos y llévala hacia el pecho, manteniendo los codos flexionados y cerca del cuerpo. Activa el abdomen y flexiona lentamente el torso hacia adelante, llevando el pecho hacia las rodillas. Haz una pausa por un momento en la parte más alta del movimiento, luego regresa lentamente a la posición inicial. Repite el número de repeticiones deseado.', 'Attach the band to a sturdy anchor point at waist height. Stand facing away from the anchor point with your feet shoulder-width apart. Hold the band with both hands and bring it up to your chest, keeping your elbows bent and close to your body. Engage your abs and slowly crunch forward, bringing your chest towards your knees. Pause for a moment at the top of the crunch, then slowly return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1005-Kzg30R7.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1005-Kzg30R7.gif', 'Kzg30R7', '© Gym visual — https://gymvisual.com/'),
('1022', 'band standing rear delt row', 'Ponte de pie con los pies separados a la altura de los hombros y coloca la banda bajo los pies. Sostén las agarraderas de la banda con las palmas mirándose entre sí y los brazos extendidos frente a ti. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la esp', 'shoulders', 'band', 'shoulders', 'shoulders', 'delts', '{"trapezius","rhomboids","biceps"}', 'Ponte de pie con los pies separados a la altura de los hombros y coloca la banda bajo los pies. Sostén las agarraderas de la banda con las palmas mirándose entre sí y los brazos extendidos frente a ti. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta. Tira de la banda hacia el pecho, juntando los omóplatos. Haz una pausa por un momento en la parte superior, luego suelta lentamente la tensión y regresa a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and place the band under your feet. Hold the band handles with your palms facing each other and your arms extended in front of you. Bend your knees slightly and hinge forward at the hips, keeping your back straight. Pull the band towards your chest, squeezing your shoulder blades together. Pause for a moment at the top, then slowly release the tension and return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1022-tc5dYrf.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1022-tc5dYrf.gif', 'tc5dYrf', '© Gym visual — https://gymvisual.com/'),
('1007', 'band standing twisting crunch', 'Ponte de pie con los pies separados a la altura de los hombros y coloca la banda alrededor de la parte superior de la espalda, cruzándola frente al pecho. Sujeta los extremos de la banda con las manos, manteniendo los codos flexionados y cerca de los costados. Activa el abdomen y gira el torso hacia', 'waist', 'band', 'waist', 'waist', 'abs', '{"obliques"}', 'Ponte de pie con los pies separados a la altura de los hombros y coloca la banda alrededor de la parte superior de la espalda, cruzándola frente al pecho. Sujeta los extremos de la banda con las manos, manteniendo los codos flexionados y cerca de los costados. Activa el abdomen y gira el torso hacia un lado, llevando el codo hacia la rodilla opuesta. Haz una pausa breve y luego vuelve a la posición inicial. Repite del otro lado. Continúa alternando lados durante el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and place the band around your upper back, crossing it in front of your chest. Hold the ends of the band with your hands, keeping your elbows bent and close to your sides. Engage your abs and twist your torso to one side, bringing your elbow towards the opposite knee. Pause for a moment, then return to the starting position. Repeat on the other side. Continue alternating sides for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1007-euq4pwp.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1007-euq4pwp.gif', 'euq4pwp', '© Gym visual — https://gymvisual.com/'),
('1008', 'band step-up', 'Coloca una banda alrededor de los muslos, justo por encima de las rodillas. Ponte de pie frente a un escalón o plataforma con los pies separados a la altura de las caderas. Sube a la plataforma con el pie derecho, empujando con el talón. Extiende la pierna izquierda hacia atrás, manteniéndola recta.', 'upper legs', 'band', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves"}', 'Coloca una banda alrededor de los muslos, justo por encima de las rodillas. Ponte de pie frente a un escalón o plataforma con los pies separados a la altura de las caderas. Sube a la plataforma con el pie derecho, empujando con el talón. Extiende la pierna izquierda hacia atrás, manteniéndola recta. Baja el pie izquierdo de nuevo hasta el suelo. Repite subiendo a la plataforma con el pie izquierdo. Continúa alternando las piernas durante el número de repeticiones deseado.', 'Place a band around your thighs, just above your knees. Stand facing a step or platform with your feet hip-width apart. Step up onto the platform with your right foot, pushing through your heel. Extend your left leg behind you, keeping it straight. Lower your left foot back down to the ground. Repeat with your left foot stepping up onto the platform. Continue alternating legs for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1008-d5bTEPV.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1008-d5bTEPV.gif', 'd5bTEPV', '© Gym visual — https://gymvisual.com/'),
('1009', 'band stiff leg deadlift', 'Ponte de pie con los pies separados a la altura de los hombros y coloca la banda alrededor de los tobillos. Sujeta la banda con ambas manos frente a los muslos, con las palmas mirando hacia el cuerpo. Manteniendo la espalda recta y el core activado, flexiona las caderas y baja lentamente la parte su', 'upper legs', 'band', 'upper legs', 'upper legs', 'glutes', '{"hamstrings","lower back"}', 'Ponte de pie con los pies separados a la altura de los hombros y coloca la banda alrededor de los tobillos. Sujeta la banda con ambas manos frente a los muslos, con las palmas mirando hacia el cuerpo. Manteniendo la espalda recta y el core activado, flexiona las caderas y baja lentamente la parte superior del cuerpo hacia el suelo. Mientras bajas, empuja las caderas hacia atrás y deja que las rodillas se flexionen ligeramente. Baja la banda hacia el suelo, sintiendo un estiramiento en los isquiotibiales. Haz una pausa breve en la posición baja, luego activa los glúteos y los isquiotibiales para levantar la parte superior del cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and place the band around your ankles. Hold the band with both hands in front of your thighs, palms facing your body. Keeping your back straight and your core engaged, hinge at the hips and slowly lower your upper body towards the ground. As you lower, push your hips back and allow your knees to bend slightly. Lower the band towards the ground, feeling a stretch in your hamstrings. Pause for a moment at the bottom, then engage your glutes and hamstrings to lift your upper body back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1009-kuMiR2T.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1009-kuMiR2T.gif', 'kuMiR2T', '© Gym visual — https://gymvisual.com/'),
('1023', 'band straight back stiff leg deadlift', 'Ponte de pie con los pies separados a la altura de los hombros y coloca la banda alrededor de la parte superior de las piernas. Sujeta la banda con ambas manos frente a los muslos, con las palmas mirando hacia el cuerpo. Manteniendo la espalda recta y las rodillas ligeramente flexionadas, flexiona l', 'upper legs', 'band', 'upper legs', 'upper legs', 'glutes', '{"hamstrings","lower back"}', 'Ponte de pie con los pies separados a la altura de los hombros y coloca la banda alrededor de la parte superior de las piernas. Sujeta la banda con ambas manos frente a los muslos, con las palmas mirando hacia el cuerpo. Manteniendo la espalda recta y las rodillas ligeramente flexionadas, flexiona las caderas y baja la banda hacia el suelo. Siente el estiramiento en los isquiotibiales mientras bajas la banda. Activa los glúteos y los isquiotibiales para levantar el cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and place the band around your upper legs. Hold the band with both hands in front of your thighs, palms facing your body. Keeping your back straight and your knees slightly bent, hinge at the hips and lower the band towards the ground. Feel the stretch in your hamstrings as you lower the band. Engage your glutes and hamstrings to lift your body back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1023-lHeUULr.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1023-lHeUULr.gif', 'lHeUULr', '© Gym visual — https://gymvisual.com/'),
('1010', 'band straight leg deadlift', 'Ponte de pie con los pies separados a la altura de los hombros y coloca la banda alrededor de los pies. Sujeta la banda con ambas manos, con las palmas mirando hacia el cuerpo, y mantén los brazos rectos. Activa el core y mantén una ligera flexión en las rodillas. Inclínate lentamente hacia delante ', 'back', 'band', 'back', 'back', 'spine', '{"hamstrings","glutes"}', 'Ponte de pie con los pies separados a la altura de los hombros y coloca la banda alrededor de los pies. Sujeta la banda con ambas manos, con las palmas mirando hacia el cuerpo, y mantén los brazos rectos. Activa el core y mantén una ligera flexión en las rodillas. Inclínate lentamente hacia delante desde las caderas, manteniendo la espalda recta y el pecho elevado. Baja la banda hacia el suelo manteniendo las piernas rectas. Haz una pausa breve en la posición baja y luego contrae los glúteos y los isquiotibiales para volver a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and place the band around your feet. Hold the band with both hands, palms facing your body, and keep your arms straight. Engage your core and maintain a slight bend in your knees. Slowly hinge forward at your hips, keeping your back straight and chest lifted. Lower the band towards the ground while keeping your legs straight. Pause for a moment at the bottom, then squeeze your glutes and hamstrings to return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1010-KUaoUV8.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1010-KUaoUV8.gif', 'KUaoUV8', '© Gym visual — https://gymvisual.com/'),
('1012', 'band twisting overhead press', 'Ponte de pie con los pies separados a la altura de los hombros y coloca la banda bajo los pies. Sujeta las asas de la banda a la altura de los hombros con las palmas mirando hacia delante. Activa el core y empuja la banda por encima de la cabeza, extendiendo completamente los brazos. Mientras empuja', 'shoulders', 'band', 'shoulders', 'shoulders', 'delts', '{"triceps","upper back"}', 'Ponte de pie con los pies separados a la altura de los hombros y coloca la banda bajo los pies. Sujeta las asas de la banda a la altura de los hombros con las palmas mirando hacia delante. Activa el core y empuja la banda por encima de la cabeza, extendiendo completamente los brazos. Mientras empujas, gira el torso hacia un lado, manteniendo las caderas estables. Haz una pausa breve en la parte alta y luego vuelve a la posición inicial. Repite el empuje y el giro hacia el lado opuesto. Continúa alternando lados durante el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and place the band under your feet. Hold the band handles at shoulder height with your palms facing forward. Engage your core and press the band overhead, fully extending your arms. As you press, twist your torso to one side, keeping your hips stable. Pause for a moment at the top, then return to the starting position. Repeat the press and twist on the opposite side. Continue alternating sides for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1012-u4bAmKp.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1012-u4bAmKp.gif', 'u4bAmKp', '© Gym visual — https://gymvisual.com/'),
('1369', 'band two legs calf raise - (band under both legs) v. 2', 'Ponte de pie con los pies separados a la altura de los hombros y coloca una banda elástica bajo ambos pies. Sujeta los extremos de la banda con las manos para mantener el equilibrio. Levanta los talones del suelo lo más alto posible, usando las pantorrillas. Haz una pausa breve en la parte alta y lu', 'lower legs', 'band', 'lower legs', 'lower legs', 'calves', '{"ankles","feet"}', 'Ponte de pie con los pies separados a la altura de los hombros y coloca una banda elástica bajo ambos pies. Sujeta los extremos de la banda con las manos para mantener el equilibrio. Levanta los talones del suelo lo más alto posible, usando las pantorrillas. Haz una pausa breve en la parte alta y luego baja lentamente los talones de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and place a resistance band under both feet. Hold the ends of the band with your hands for stability. Raise your heels off the ground as high as possible, using your calves. Pause for a moment at the top, then slowly lower your heels back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1369-jl6uxZV.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1369-jl6uxZV.gif', 'jl6uxZV', '© Gym visual — https://gymvisual.com/'),
('1013', 'band underhand pulldown', 'Sujeta la banda a un punto de anclaje alto, como una barra de dominadas o una viga resistente. Ponte de pie frente al punto de anclaje con los pies separados a la altura de los hombros. Agarra la banda con un agarre supino, con las manos un poco más separadas que el ancho de los hombros. Extiende co', 'back', 'band', 'back', 'back', 'lats', '{"biceps","forearms"}', 'Sujeta la banda a un punto de anclaje alto, como una barra de dominadas o una viga resistente. Ponte de pie frente al punto de anclaje con los pies separados a la altura de los hombros. Agarra la banda con un agarre supino, con las manos un poco más separadas que el ancho de los hombros. Extiende completamente los brazos por encima de la cabeza, manteniendo los codos ligeramente flexionados. Activa los dorsales y tira de la banda hacia abajo en dirección al pecho, juntando los omóplatos. Haz una pausa breve en la parte baja del movimiento, luego libera lentamente la tensión y vuelve a la posición inicial. Repite el número de repeticiones deseado.', 'Attach the band to a high anchor point, such as a pull-up bar or sturdy beam. Stand facing the anchor point with your feet shoulder-width apart. Grasp the band with an underhand grip, hands slightly wider than shoulder-width apart. Extend your arms fully overhead, keeping your elbows slightly bent. Engage your lats and pull the band down towards your chest, squeezing your shoulder blades together. Pause for a moment at the bottom of the movement, then slowly release the tension and return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1013-k6tUeqS.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1013-k6tUeqS.gif', 'k6tUeqS', '© Gym visual — https://gymvisual.com/'),
('1014', 'band v-up', 'Túmbate sobre tu espalda con las piernas rectas y los brazos extendidos por encima de la cabeza, sosteniendo la banda. Activando el abdomen, levanta las piernas y la parte superior del cuerpo del suelo al mismo tiempo, llevando las manos hacia los dedos de los pies. Haz una pausa por un momento en l', 'waist', 'band', 'waist', 'waist', 'abs', '{"hip flexors"}', 'Túmbate sobre tu espalda con las piernas rectas y los brazos extendidos por encima de la cabeza, sosteniendo la banda. Activando el abdomen, levanta las piernas y la parte superior del cuerpo del suelo al mismo tiempo, llevando las manos hacia los dedos de los pies. Haz una pausa por un momento en la parte superior, luego baja lentamente las piernas y la parte superior del cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on your back with your legs straight and your arms extended overhead, holding the band. Engaging your abs, lift your legs and upper body off the ground simultaneously, reaching your hands towards your toes. Pause for a moment at the top, then slowly lower your legs and upper body back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1014-H6ETwO9.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1014-H6ETwO9.gif', 'H6ETwO9', '© Gym visual — https://gymvisual.com/'),
('1015', 'band vertical pallof press', 'Ponte de pie con los pies separados a la altura de los hombros y enrolla la banda alrededor de un objeto firme a la altura del pecho. Sujeta la banda con ambas manos y aléjate del punto de anclaje, creando tensión en la banda. Colócate perpendicular al punto de anclaje, con el costado mirando hacia ', 'waist', 'band', 'waist', 'waist', 'abs', '{"obliques","glutes"}', 'Ponte de pie con los pies separados a la altura de los hombros y enrolla la banda alrededor de un objeto firme a la altura del pecho. Sujeta la banda con ambas manos y aléjate del punto de anclaje, creando tensión en la banda. Colócate perpendicular al punto de anclaje, con el costado mirando hacia la banda. Extiende los brazos rectos hacia delante, manteniendo las manos a la altura del pecho. Activa el core y empuja la banda alejándola del pecho, extendiendo completamente los brazos. Mantén la posición durante unos segundos y luego lleva lentamente la banda de vuelta hacia el pecho. Repite el número de repeticiones deseado, luego cambia de lado.', 'Stand with your feet shoulder-width apart and wrap the band around a sturdy object at chest height. Hold the band with both hands and step away from the anchor point, creating tension in the band. Position yourself perpendicular to the anchor point, with your side facing the band. Extend your arms straight out in front of you, keeping your hands at chest height. Engage your core and press the band away from your chest, fully extending your arms. Hold the position for a few seconds, then slowly bring the band back towards your chest. Repeat for the desired number of repetitions, then switch sides.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1015-G7PXMlT.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1015-G7PXMlT.gif', 'G7PXMlT', '© Gym visual — https://gymvisual.com/'),
('1016', 'band wrist curl', 'Siéntate en un banco o silla con los pies apoyados en el suelo. Sujeta la banda con ambas manos, con las palmas hacia arriba, y apoya los antebrazos sobre los muslos. Flexiona lentamente las muñecas hacia arriba, apretando los antebrazos. Haz una pausa por un momento en la parte superior, luego baja', 'lower arms', 'band', 'lower arms', 'lower arms', 'forearms', '{"biceps","triceps"}', 'Siéntate en un banco o silla con los pies apoyados en el suelo. Sujeta la banda con ambas manos, con las palmas hacia arriba, y apoya los antebrazos sobre los muslos. Flexiona lentamente las muñecas hacia arriba, apretando los antebrazos. Haz una pausa por un momento en la parte superior, luego baja lentamente las muñecas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a bench or chair with your feet flat on the ground. Hold the band with both hands, palms facing up, and rest your forearms on your thighs. Slowly curl your wrists upward, squeezing your forearms. Pause for a moment at the top, then slowly lower your wrists back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1016-vUTfFHw.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1016-vUTfFHw.gif', 'vUTfFHw', '© Gym visual — https://gymvisual.com/'),
('1017', 'band y-raise', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta la banda frente a los muslos con las palmas mirando hacia adentro. Mantén los brazos rectos y levántalos hacia arriba y hacia los lados, formando una ''Y'' con el cuerpo. Junta los omóplatos en la parte superior del movimiento. Ba', 'shoulders', 'band', 'shoulders', 'shoulders', 'delts', '{"traps","rhomboids"}', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta la banda frente a los muslos con las palmas mirando hacia adentro. Mantén los brazos rectos y levántalos hacia arriba y hacia los lados, formando una ''Y'' con el cuerpo. Junta los omóplatos en la parte superior del movimiento. Baja lentamente los brazos de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and hold the band in front of your thighs with your palms facing inwards. Keep your arms straight and lift them up and out to the sides, forming a ''Y'' shape with your body. Squeeze your shoulder blades together at the top of the movement. Slowly lower your arms back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1017-aHDy5O5.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1017-aHDy5O5.gif', 'aHDy5O5', '© Gym visual — https://gymvisual.com/'),
('0023', 'barbell alternate biceps curl', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una barra en cada mano, con las palmas mirando hacia delante. Mantén los brazos superiores fijos y exhala mientras levantas el peso contrayendo los bíceps. Continúa levantando las barras hasta que los bíceps estén completamente ', 'upper arms', 'barbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una barra en cada mano, con las palmas mirando hacia delante. Mantén los brazos superiores fijos y exhala mientras levantas el peso contrayendo los bíceps. Continúa levantando las barras hasta que los bíceps estén completamente contraídos y las barras estén a la altura de los hombros. Mantén la posición contraída durante una breve pausa mientras aprietas los bíceps. Inhala mientras comienzas a bajar lentamente las barras de vuelta a la posición inicial. Repite el número de repeticiones deseado, alternando los brazos.', 'Stand up straight with your feet shoulder-width apart and hold a barbell in each hand, palms facing forward. Keep your upper arms stationary and exhale as you curl the weights while contracting your biceps. Continue to raise the barbells until your biceps are fully contracted and the barbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale as you slowly begin to lower the barbells back to the starting position. Repeat for the desired number of repetitions, alternating arms.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0023-Yza7XrQ.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0023-Yza7XrQ.gif', 'Yza7XrQ', '© Gym visual — https://gymvisual.com/'),
('0024', 'barbell bench front squat', 'Empieza de pie con los pies separados a la altura de los hombros y la barra apoyada en la parte superior del pecho, justo debajo de la clavícula. Sujeta la barra con un agarre pronado, manteniendo los codos elevados y los brazos superiores paralelos al suelo. Baja el cuerpo hacia una posición de sen', 'upper legs', 'barbell', 'upper legs', 'upper legs', 'quads', '{"hamstrings","glutes","calves"}', 'Empieza de pie con los pies separados a la altura de los hombros y la barra apoyada en la parte superior del pecho, justo debajo de la clavícula. Sujeta la barra con un agarre pronado, manteniendo los codos elevados y los brazos superiores paralelos al suelo. Baja el cuerpo hacia una posición de sentadilla flexionando las rodillas y las caderas, manteniendo la espalda recta y el pecho elevado. Haz una pausa breve en la parte baja de la sentadilla y luego empuja con los talones para volver a la posición inicial. Repite el número de repeticiones deseado.', 'Start by standing with your feet shoulder-width apart and the barbell resting on your upper chest, just below your collarbone. Hold the barbell with an overhand grip, keeping your elbows up and your upper arms parallel to the ground. Lower your body down into a squat position by bending at the knees and hips, keeping your back straight and your chest up. Pause for a moment at the bottom of the squat, then push through your heels to return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0024-Y7YcmIJ.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0024-Y7YcmIJ.gif', 'Y7YcmIJ', '© Gym visual — https://gymvisual.com/'),
('0025', 'barbell bench press', 'Túmbate sobre un banco con los pies apoyados en el suelo y la espalda presionada contra el banco. Agarra la barra con un agarre pronado un poco más ancho que la separación de los hombros. Levanta la barra del soporte y sostenla directamente sobre el pecho con los brazos completamente extendidos. Baj', 'chest', 'barbell', 'chest', 'chest', 'pectorals', '{"triceps","shoulders"}', 'Túmbate sobre un banco con los pies apoyados en el suelo y la espalda presionada contra el banco. Agarra la barra con un agarre pronado un poco más ancho que la separación de los hombros. Levanta la barra del soporte y sostenla directamente sobre el pecho con los brazos completamente extendidos. Baja la barra lentamente hacia el pecho, manteniendo los codos pegados al cuerpo. Haz una pausa breve cuando la barra toque el pecho. Empuja la barra de vuelta a la posición inicial extendiendo los brazos. Repite el número de repeticiones deseado.', 'Lie flat on a bench with your feet flat on the ground and your back pressed against the bench. Grasp the barbell with an overhand grip slightly wider than shoulder-width apart. Lift the barbell off the rack and hold it directly above your chest with your arms fully extended. Lower the barbell slowly towards your chest, keeping your elbows tucked in. Pause for a moment when the barbell touches your chest. Push the barbell back up to the starting position by extending your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0025-EIeI8Vf.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0025-EIeI8Vf.gif', 'EIeI8Vf', '© Gym visual — https://gymvisual.com/'),
('0026', 'barbell bench squat', 'Coloca una barra en un soporte de sentadillas a la altura del pecho. Ponte de pie de espaldas al soporte, con los pies separados a la altura de los hombros. Flexiona las rodillas y baja el cuerpo hacia una posición de sentadilla, manteniendo la espalda recta y el pecho elevado. Agarra la barra con u', 'upper legs', 'barbell', 'upper legs', 'upper legs', 'quads', '{"glutes","hamstrings","calves"}', 'Coloca una barra en un soporte de sentadillas a la altura del pecho. Ponte de pie de espaldas al soporte, con los pies separados a la altura de los hombros. Flexiona las rodillas y baja el cuerpo hacia una posición de sentadilla, manteniendo la espalda recta y el pecho elevado. Agarra la barra con un agarre pronado un poco más ancho que la separación de los hombros. Levanta la barra del soporte y retrocede un paso, asegurándote de que los pies sigan separados a la altura de los hombros. Baja el cuerpo hacia una sentadilla, manteniendo las rodillas alineadas con los dedos de los pies. Haz una pausa por un momento en la parte inferior, luego empuja con los talones para regresar a la posición inicial. Repite el número de repeticiones deseado.', 'Set up a barbell on a squat rack at chest height. Stand facing away from the rack, with your feet shoulder-width apart. Bend your knees and lower your body down into a squat position, keeping your back straight and chest up. Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart. Lift the barbell off the rack and step back, ensuring your feet are still shoulder-width apart. Lower your body down into a squat, keeping your knees in line with your toes. Pause for a moment at the bottom, then push through your heels to return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0026-W9pFVv1.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0026-W9pFVv1.gif', 'W9pFVv1', '© Gym visual — https://gymvisual.com/'),
('1316', 'barbell bent arm pullover', 'Túmbate boca arriba en un banco con la cabeza en un extremo y los pies en el suelo. Sujeta una barra con un agarre a la altura de los hombros y extiende los brazos rectos por encima del pecho. Baja la barra detrás de la cabeza manteniendo los brazos ligeramente flexionados. Haz una pausa breve y lue', 'back', 'barbell', 'back', 'back', 'lats', '{"triceps","chest"}', 'Túmbate boca arriba en un banco con la cabeza en un extremo y los pies en el suelo. Sujeta una barra con un agarre a la altura de los hombros y extiende los brazos rectos por encima del pecho. Baja la barra detrás de la cabeza manteniendo los brazos ligeramente flexionados. Haz una pausa breve y luego levanta la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on a bench with your head at one end and your feet on the floor. Hold a barbell with a shoulder-width grip and extend your arms straight above your chest. Lower the barbell behind your head while keeping your arms slightly bent. Pause for a moment, then raise the barbell back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1316-cA9FuWG.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1316-cA9FuWG.gif', 'cA9FuWG', '© Gym visual — https://gymvisual.com/'),
('0027', 'barbell bent over row', 'Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Inclínate hacia delante desde las caderas manteniendo la espalda recta y el pecho elevado. Agarra la barra con un agarre pronado, con las manos un poco más separadas que el ancho de los hombros. Ti', 'back', 'barbell', 'back', 'back', 'upper back', '{"biceps","forearms"}', 'Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Inclínate hacia delante desde las caderas manteniendo la espalda recta y el pecho elevado. Agarra la barra con un agarre pronado, con las manos un poco más separadas que el ancho de los hombros. Tira de la barra hacia la parte inferior del pecho retrayendo los omóplatos y contrayendo los músculos de la espalda. Haz una pausa breve en la parte alta y luego baja lentamente la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and knees slightly bent. Bend forward at the hips while keeping your back straight and chest up. Grasp the barbell with an overhand grip, hands slightly wider than shoulder-width apart. Pull the barbell towards your lower chest by retracting your shoulder blades and squeezing your back muscles. Pause for a moment at the top, then slowly lower the barbell back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0027-eZyBC3j.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0027-eZyBC3j.gif', 'eZyBC3j', '© Gym visual — https://gymvisual.com/'),
('2407', 'barbell biceps curl (with arm blaster)', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una barra con un agarre supino, con las palmas hacia arriba. Coloca los brazos superiores contra el soporte para brazos, manteniendo los codos cerca del torso. Manteniendo los brazos superiores fijos, exhala y levanta el peso mi', 'upper arms', 'barbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una barra con un agarre supino, con las palmas hacia arriba. Coloca los brazos superiores contra el soporte para brazos, manteniendo los codos cerca del torso. Manteniendo los brazos superiores fijos, exhala y levanta el peso mientras contraes los bíceps. Continúa levantando la barra hasta que los bíceps estén completamente contraídos y la barra esté a la altura de los hombros. Mantén la posición contraída durante una breve pausa mientras aprietas los bíceps. Inhala y comienza a bajar lentamente la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand up straight with your feet shoulder-width apart and hold a barbell with an underhand grip, palms facing up. Place your upper arms against the arm blaster, keeping your elbows close to your torso. Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Continue to raise the barbell until your biceps are fully contracted and the bar is at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly begin to lower the barbell back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2407-aee2Fcj.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2407-aee2Fcj.gif', 'aee2Fcj', '© Gym visual — https://gymvisual.com/'),
('0028', 'barbell clean and press', 'Ponte de pie con los pies separados a la altura de los hombros y la barra en el suelo frente a ti. Flexiona las rodillas y las caderas para bajar y agarrar la barra con un agarre pronado, con las manos un poco más separadas que el ancho de los hombros. Empuja con los talones y extiende las caderas y', 'upper legs', 'barbell', 'upper legs', 'upper legs', 'quads', '{"hamstrings","glutes","shoulders","triceps"}', 'Ponte de pie con los pies separados a la altura de los hombros y la barra en el suelo frente a ti. Flexiona las rodillas y las caderas para bajar y agarrar la barra con un agarre pronado, con las manos un poco más separadas que el ancho de los hombros. Empuja con los talones y extiende las caderas y las rodillas para levantar la barra del suelo, manteniéndola cerca del cuerpo. Cuando la barra llegue a los muslos, extiende las caderas de forma explosiva, encoge los hombros y tira de la barra hacia el pecho. Cuando la barra llegue a la altura del pecho, baja rápidamente debajo de ella y atrápala a la altura de los hombros, con los codos apuntando hacia delante y las palmas hacia arriba. Desde la posición de recepción, empuja la barra por encima de la cabeza extendiendo los brazos y llevando la barra recta hacia arriba. Baja la barra de vuelta a la posición inicial y repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and the barbell on the floor in front of you. Bend your knees and hinge at the hips to lower down and grip the barbell with an overhand grip, hands slightly wider than shoulder-width apart. Drive through your heels and extend your hips and knees to lift the barbell off the floor, keeping it close to your body. As the barbell reaches your thighs, explosively extend your hips, shrug your shoulders, and pull the barbell up towards your chest. As the barbell reaches chest height, quickly drop under it and catch it at shoulder level, with your elbows pointing forward and your palms facing up. From the catch position, press the barbell overhead by extending your arms and pushing the barbell straight up. Lower the barbell back down to the starting position and repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0028-SGY8Zui.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0028-SGY8Zui.gif', 'SGY8Zui', '© Gym visual — https://gymvisual.com/'),
('0029', 'barbell clean-grip front squat', 'Empieza de pie con los pies separados a la altura de los hombros y la barra apoyada en la parte superior del pecho, con los codos apuntando hacia delante. Baja el cuerpo flexionando las rodillas y empujando las caderas hacia atrás, como si te sentaras en una silla. Mantén el pecho elevado y la espal', 'upper legs', 'barbell', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves","core"}', 'Empieza de pie con los pies separados a la altura de los hombros y la barra apoyada en la parte superior del pecho, con los codos apuntando hacia delante. Baja el cuerpo flexionando las rodillas y empujando las caderas hacia atrás, como si te sentaras en una silla. Mantén el pecho elevado y la espalda recta mientras bajas, asegurándote de que las rodillas no sobrepasen los dedos de los pies. Continúa bajando hasta que los muslos queden paralelos al suelo, o tan abajo como puedas hacerlo cómodamente. Haz una pausa breve en la parte baja y luego empuja con los talones para volver a ponerte de pie, extendiendo las caderas y las rodillas. Repite el número de repeticiones deseado.', 'Start by standing with your feet shoulder-width apart and the barbell resting on your upper chest, with your elbows pointing forward. Lower your body by bending your knees and pushing your hips back, as if you are sitting back into a chair. Keep your chest up and your back straight as you lower down, making sure your knees do not go past your toes. Continue lowering until your thighs are parallel to the ground, or as low as you can comfortably go. Pause for a moment at the bottom, then push through your heels to stand back up, extending your hips and knees. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0029-qi996YS.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0029-qi996YS.gif', 'qi996YS', '© Gym visual — https://gymvisual.com/'),
('0030', 'barbell close-grip bench press', 'Túmbate sobre un banco con los pies apoyados en el suelo y la espalda presionada contra el banco. Agarra la barra con un agarre cerrado, un poco más estrecho que el ancho de los hombros. Saca la barra del soporte y bájala lentamente hacia el pecho, manteniendo los codos cerca del cuerpo. Haz una pau', 'upper arms', 'barbell', 'upper arms', 'upper arms', 'triceps', '{"chest","shoulders"}', 'Túmbate sobre un banco con los pies apoyados en el suelo y la espalda presionada contra el banco. Agarra la barra con un agarre cerrado, un poco más estrecho que el ancho de los hombros. Saca la barra del soporte y bájala lentamente hacia el pecho, manteniendo los codos cerca del cuerpo. Haz una pausa breve cuando la barra toque el pecho. Empuja la barra de vuelta a la posición inicial, extendiendo completamente los brazos. Repite el número de repeticiones deseado.', 'Lie flat on a bench with your feet flat on the ground and your back pressed against the bench. Grasp the barbell with a close grip, slightly narrower than shoulder-width apart. Unrack the barbell and lower it slowly towards your chest, keeping your elbows close to your body. Pause for a moment when the barbell touches your chest. Push the barbell back up to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0030-J6Dx1Mu.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0030-J6Dx1Mu.gif', 'J6Dx1Mu', '© Gym visual — https://gymvisual.com/'),
('0031', 'barbell curl', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una barra con un agarre supino, con las palmas mirando hacia delante. Mantén los codos cerca del torso y exhala mientras levantas el peso contrayendo los bíceps. Continúa levantando la barra hasta que los bíceps estén completame', 'upper arms', 'barbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una barra con un agarre supino, con las palmas mirando hacia delante. Mantén los codos cerca del torso y exhala mientras levantas el peso contrayendo los bíceps. Continúa levantando la barra hasta que los bíceps estén completamente contraídos y la barra esté a la altura de los hombros. Mantén la posición contraída durante una breve pausa mientras aprietas los bíceps. Inhala mientras comienzas a bajar lentamente la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand up straight with your feet shoulder-width apart and hold a barbell with an underhand grip, palms facing forward. Keep your elbows close to your torso and exhale as you curl the weights while contracting your biceps. Continue to raise the bar until your biceps are fully contracted and the bar is at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale as you slowly begin to lower the bar back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0031-25GPyDY.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0031-25GPyDY.gif', '25GPyDY', '© Gym visual — https://gymvisual.com/'),
('0032', 'barbell deadlift', 'Ponte de pie con los pies separados a la altura de los hombros y la barra en el suelo frente a ti. Flexiona las rodillas y las caderas para bajar el torso y agarra la barra con un agarre pronado, con las manos un poco más separadas que el ancho de los hombros. Mantén la espalda recta y el pecho elev', 'upper legs', 'barbell', 'upper legs', 'upper legs', 'glutes', '{"hamstrings","lower back"}', 'Ponte de pie con los pies separados a la altura de los hombros y la barra en el suelo frente a ti. Flexiona las rodillas y las caderas para bajar el torso y agarra la barra con un agarre pronado, con las manos un poco más separadas que el ancho de los hombros. Mantén la espalda recta y el pecho elevado mientras empujas con los talones para levantar la barra del suelo, extendiendo las caderas y las rodillas. Al ponerte de pie, aprieta los glúteos y mantén el core activado. Baja la barra de vuelta al suelo flexionando las caderas y las rodillas, manteniendo la espalda recta. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and the barbell on the ground in front of you. Bend your knees and hinge at the hips to lower your torso and grip the barbell with an overhand grip, hands slightly wider than shoulder-width apart. Keep your back straight and chest lifted as you drive through your heels to lift the barbell off the ground, extending your hips and knees. As you stand up straight, squeeze your glutes and keep your core engaged. Lower the barbell back down to the ground by bending at the hips and knees, keeping your back straight. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0032-ila4NZS.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0032-ila4NZS.gif', 'ila4NZS', '© Gym visual — https://gymvisual.com/'),
('0033', 'barbell decline bench press', 'Túmbate en un banco declinado con los pies sujetos y la cabeza más baja que las caderas. Agarra la barra con un agarre pronado un poco más ancho que la separación de los hombros. Saca la barra del soporte y bájala lentamente hacia el pecho, manteniendo los codos pegados al cuerpo. Haz una pausa brev', 'chest', 'barbell', 'chest', 'chest', 'pectorals', '{"triceps","shoulders"}', 'Túmbate en un banco declinado con los pies sujetos y la cabeza más baja que las caderas. Agarra la barra con un agarre pronado un poco más ancho que la separación de los hombros. Saca la barra del soporte y bájala lentamente hacia el pecho, manteniendo los codos pegados al cuerpo. Haz una pausa breve en la parte baja y luego empuja la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie on a decline bench with your feet secured and your head lower than your hips. Grasp the barbell with an overhand grip slightly wider than shoulder-width apart. Unrack the barbell and lower it slowly towards your chest, keeping your elbows tucked in. Pause for a moment at the bottom, then push the barbell back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0033-GrO65fd.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0033-GrO65fd.gif', 'GrO65fd', '© Gym visual — https://gymvisual.com/'),
('0034', 'barbell decline bent arm pullover', 'Túmbate en un banco declinado con la cabeza más baja que las caderas y los pies sujetos. Sujeta una barra con un agarre pronado (palmas mirando hacia afuera) y extiende los brazos rectos por encima del pecho. Baja la barra detrás de la cabeza de forma controlada, manteniendo los brazos ligeramente f', 'back', 'barbell', 'back', 'back', 'lats', '{"triceps","chest"}', 'Túmbate en un banco declinado con la cabeza más baja que las caderas y los pies sujetos. Sujeta una barra con un agarre pronado (palmas mirando hacia afuera) y extiende los brazos rectos por encima del pecho. Baja la barra detrás de la cabeza de forma controlada, manteniendo los brazos ligeramente flexionados. Haz una pausa breve y luego levanta la barra de vuelta a la posición inicial contrayendo los dorsales. Repite el número de repeticiones deseado.', 'Lie down on a decline bench with your head lower than your hips and your feet secured. Hold a barbell with a pronated grip (palms facing away from you) and extend your arms straight above your chest. Lower the barbell behind your head in a controlled manner, keeping your arms slightly bent. Pause for a moment, then raise the barbell back to the starting position by contracting your lats. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0034-hMEptv0.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0034-hMEptv0.gif', 'hMEptv0', '© Gym visual — https://gymvisual.com/'),
('0035', 'barbell decline close grip to skull press', 'Túmbate en un banco declinado con la cabeza más baja que los pies y sujeta una barra con un agarre cerrado. Baja la barra hacia la frente flexionando los codos, manteniendo los brazos superiores fijos. Haz una pausa breve y luego extiende los brazos para empujar la barra de vuelta a la posición inic', 'upper arms', 'barbell', 'upper arms', 'upper arms', 'triceps', '{"chest","shoulders"}', 'Túmbate en un banco declinado con la cabeza más baja que los pies y sujeta una barra con un agarre cerrado. Baja la barra hacia la frente flexionando los codos, manteniendo los brazos superiores fijos. Haz una pausa breve y luego extiende los brazos para empujar la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie on a decline bench with your head lower than your feet and hold a barbell with a close grip. Lower the barbell towards your forehead by bending your elbows, keeping your upper arms stationary. Pause for a moment, then extend your arms to press the barbell back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0035-LMGXZn8.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0035-LMGXZn8.gif', 'LMGXZn8', '© Gym visual — https://gymvisual.com/'),
('1255', 'barbell decline pullover', 'Túmbate en un banco declinado con la cabeza más baja que las caderas y los pies sujetos. Sujeta la barra con un agarre pronado (palmas mirando hacia afuera) y las manos un poco más separadas que el ancho de los hombros. Extiende los brazos por encima del pecho, manteniendo una ligera flexión en los ', 'chest', 'barbell', 'chest', 'chest', 'pectorals', '{"triceps","shoulders"}', 'Túmbate en un banco declinado con la cabeza más baja que las caderas y los pies sujetos. Sujeta la barra con un agarre pronado (palmas mirando hacia afuera) y las manos un poco más separadas que el ancho de los hombros. Extiende los brazos por encima del pecho, manteniendo una ligera flexión en los codos. Baja la barra describiendo un arco detrás de la cabeza, sintiendo un estiramiento en el pecho y los hombros. Haz una pausa breve y luego devuelve la barra a la posición inicial invirtiendo el movimiento. Repite el número de repeticiones deseado.', 'Lie down on a decline bench with your head lower than your hips and your feet secured. Hold the barbell with a pronated grip (palms facing away from you) and your hands slightly wider than shoulder-width apart. Extend your arms above your chest, keeping a slight bend in your elbows. Lower the barbell in an arc motion behind your head, feeling a stretch in your chest and shoulders. Pause for a moment, then return the barbell to the starting position by reversing the motion. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1255-9sgNE2O.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1255-9sgNE2O.gif', '9sgNE2O', '© Gym visual — https://gymvisual.com/'),
('0036', 'barbell decline wide-grip press', 'Túmbate en un banco declinado con los pies sujetos y la cabeza más baja que las caderas. Agarra la barra con un agarre amplio, un poco más ancho que la separación de los hombros. Baja la barra hacia el pecho, manteniendo los codos hacia los lados. Empuja la barra de vuelta a la posición inicial, ext', 'chest', 'barbell', 'chest', 'chest', 'pectorals', '{"triceps","shoulders"}', 'Túmbate en un banco declinado con los pies sujetos y la cabeza más baja que las caderas. Agarra la barra con un agarre amplio, un poco más ancho que la separación de los hombros. Baja la barra hacia el pecho, manteniendo los codos hacia los lados. Empuja la barra de vuelta a la posición inicial, extendiendo completamente los brazos. Repite el número de repeticiones deseado.', 'Lie on a decline bench with your feet secured and your head lower than your hips. Grasp the barbell with a wide grip, slightly wider than shoulder-width apart. Lower the barbell to your chest, keeping your elbows out to the sides. Push the barbell back up to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0036-hl8DUh8.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0036-hl8DUh8.gif', 'hl8DUh8', '© Gym visual — https://gymvisual.com/'),
('0037', 'barbell decline wide-grip pullover', 'Túmbate en un banco declinado con la cabeza más baja que las caderas y los pies sujetos. Sujeta una barra con un agarre amplio y extiende los brazos rectos por encima del pecho. Baja la barra detrás de la cabeza de forma controlada, manteniendo los brazos rectos. Haz una pausa breve y luego levanta ', 'back', 'barbell', 'back', 'back', 'lats', '{"triceps","chest"}', 'Túmbate en un banco declinado con la cabeza más baja que las caderas y los pies sujetos. Sujeta una barra con un agarre amplio y extiende los brazos rectos por encima del pecho. Baja la barra detrás de la cabeza de forma controlada, manteniendo los brazos rectos. Haz una pausa breve y luego levanta la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie on a decline bench with your head lower than your hips and your feet secured. Hold a barbell with a wide grip and extend your arms straight above your chest. Lower the barbell behind your head in a controlled manner, keeping your arms straight. Pause for a moment, then raise the barbell back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0037-Hj4FOCd.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0037-Hj4FOCd.gif', 'Hj4FOCd', '© Gym visual — https://gymvisual.com/'),
('0038', 'barbell drag curl', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una barra con un agarre supino, con las palmas hacia arriba. Deja que la barra cuelgue a la longitud del brazo frente a los muslos. Manteniendo los brazos superiores fijos, levanta la barra hacia el pecho contrayendo los bíceps.', 'upper arms', 'barbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una barra con un agarre supino, con las palmas hacia arriba. Deja que la barra cuelgue a la longitud del brazo frente a los muslos. Manteniendo los brazos superiores fijos, levanta la barra hacia el pecho contrayendo los bíceps. Haz una pausa breve en la parte alta y luego baja lentamente la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and hold a barbell with an underhand grip, palms facing up. Let the barbell hang at arm''s length in front of your thighs. Keeping your upper arms stationary, curl the barbell up towards your chest by contracting your biceps. Pause for a moment at the top, then slowly lower the barbell back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0038-IENzBdA.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0038-IENzBdA.gif', 'IENzBdA', '© Gym visual — https://gymvisual.com/'),
('1370', 'barbell floor calf raise', 'Coloca una barra en el suelo frente a ti. Ponte de pie con la parte delantera de los pies sobre el borde de la barra, dejando los talones colgando. Sujétate de un objeto estable para mantener el equilibrio si es necesario. Levanta los talones lo más alto posible, usando las pantorrillas para elevar ', 'lower legs', 'barbell', 'lower legs', 'lower legs', 'calves', '{"hamstrings"}', 'Coloca una barra en el suelo frente a ti. Ponte de pie con la parte delantera de los pies sobre el borde de la barra, dejando los talones colgando. Sujétate de un objeto estable para mantener el equilibrio si es necesario. Levanta los talones lo más alto posible, usando las pantorrillas para elevar el cuerpo. Haz una pausa breve en la parte alta y luego baja lentamente los talones de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Place a barbell on the floor in front of you. Stand with the balls of your feet on the edge of the barbell, with your heels hanging off. Hold onto a stable object for balance if needed. Raise your heels as high as possible, using your calves to lift your body. Pause for a moment at the top, then slowly lower your heels back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1370-2IHEa2T.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1370-2IHEa2T.gif', '2IHEa2T', '© Gym visual — https://gymvisual.com/'),
('0039', 'barbell front chest squat', 'Empieza de pie con los pies separados a la altura de los hombros, con los dedos de los pies ligeramente hacia afuera. Sujeta la barra frente al pecho con las manos separadas a la altura de los hombros, los codos apuntando hacia delante. Activa el core y mantén el pecho elevado mientras bajas el cuer', 'upper legs', 'barbell', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves","core"}', 'Empieza de pie con los pies separados a la altura de los hombros, con los dedos de los pies ligeramente hacia afuera. Sujeta la barra frente al pecho con las manos separadas a la altura de los hombros, los codos apuntando hacia delante. Activa el core y mantén el pecho elevado mientras bajas el cuerpo hacia una posición de sentadilla, empujando las caderas hacia atrás y flexionando las rodillas. Baja hasta que los muslos queden paralelos al suelo, o tan abajo como puedas hacerlo cómodamente. Haz una pausa por un momento en la parte inferior, luego empuja con los talones para regresar a la posición inicial. Repite el número de repeticiones deseado.', 'Start by standing with your feet shoulder-width apart, toes slightly turned out. Hold the barbell in front of your chest with your hands shoulder-width apart, elbows pointing forward. Engage your core and keep your chest up as you lower your body down into a squat position, pushing your hips back and bending your knees. Lower until your thighs are parallel to the ground, or as low as you can comfortably go. Pause for a moment at the bottom, then push through your heels to return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0039-IeTIEqg.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0039-IeTIEqg.gif', 'IeTIEqg', '© Gym visual — https://gymvisual.com/'),
('0041', 'barbell front raise', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una barra frente a los muslos con un agarre pronado. Mantén los brazos rectos y levanta la barra hacia delante y hacia arriba hasta que alcance la altura de los hombros. Haz una pausa breve en la parte alta y luego baja lentamen', 'shoulders', 'barbell', 'shoulders', 'shoulders', 'delts', '{"biceps","triceps"}', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una barra frente a los muslos con un agarre pronado. Mantén los brazos rectos y levanta la barra hacia delante y hacia arriba hasta que alcance la altura de los hombros. Haz una pausa breve en la parte alta y luego baja lentamente la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and hold a barbell in front of your thighs with an overhand grip. Keep your arms straight and lift the barbell forward and upward until it reaches shoulder level. Pause for a moment at the top, then slowly lower the barbell back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0041-b2Uoz54.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0041-b2Uoz54.gif', 'b2Uoz54', '© Gym visual — https://gymvisual.com/'),
('0040', 'barbell front raise and pullover', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una barra con un agarre pronado, con las palmas hacia abajo. Mantén los brazos rectos y levanta la barra frente a ti hasta que alcance la altura de los hombros. Haz una pausa breve en la parte alta y luego baja lentamente la bar', 'chest', 'barbell', 'chest', 'chest', 'pectorals', '{"deltoids","triceps"}', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una barra con un agarre pronado, con las palmas hacia abajo. Mantén los brazos rectos y levanta la barra frente a ti hasta que alcance la altura de los hombros. Haz una pausa breve en la parte alta y luego baja lentamente la barra de vuelta a la posición inicial. A continuación, baja la barra detrás de la cabeza, manteniendo los brazos rectos. Haz una pausa breve en la parte baja y luego levanta la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and hold a barbell with an overhand grip, palms facing down. Keep your arms straight and raise the barbell in front of you until it reaches shoulder height. Pause for a moment at the top, then slowly lower the barbell back down to the starting position. Next, lower the barbell behind your head, keeping your arms straight. Pause for a moment at the bottom, then raise the barbell back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0040-33AzZeV.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0040-33AzZeV.gif', '33AzZeV', '© Gym visual — https://gymvisual.com/'),
('0042', 'barbell front squat', 'Empieza de pie con los pies separados a la altura de los hombros, con los dedos de los pies ligeramente hacia afuera. Sujeta la barra frente a los hombros, apoyándola sobre la clavícula y los hombros. Activa el core y mantén el pecho elevado mientras bajas el cuerpo hacia una posición de sentadilla,', 'upper legs', 'barbell', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves","core"}', 'Empieza de pie con los pies separados a la altura de los hombros, con los dedos de los pies ligeramente hacia afuera. Sujeta la barra frente a los hombros, apoyándola sobre la clavícula y los hombros. Activa el core y mantén el pecho elevado mientras bajas el cuerpo hacia una posición de sentadilla, empujando las caderas hacia atrás y flexionando las rodillas. Baja hasta que los muslos queden paralelos al suelo, o tan abajo como puedas hacerlo cómodamente. Haz una pausa por un momento en la parte inferior, luego empuja con los talones para regresar a la posición inicial. Repite el número de repeticiones deseado.', 'Start by standing with your feet shoulder-width apart, toes slightly turned out. Hold the barbell in front of your shoulders, resting it on your collarbone and shoulders. Engage your core and keep your chest up as you lower your body down into a squat position, pushing your hips back and bending your knees. Lower until your thighs are parallel to the ground, or as low as you can comfortably go. Pause for a moment at the bottom, then push through your heels to return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0042-zG0zs85.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0042-zG0zs85.gif', 'zG0zs85', '© Gym visual — https://gymvisual.com/'),
('0043', 'barbell full squat', 'Ponte de pie con los pies separados a la altura de los hombros, con los dedos de los pies ligeramente hacia afuera. Sujeta la barra sobre la parte superior de la espalda, apoyándola en los trapecios o los deltoides posteriores. Activa el core y mantén el pecho elevado mientras comienzas a bajar el c', 'upper legs', 'barbell', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves","core"}', 'Ponte de pie con los pies separados a la altura de los hombros, con los dedos de los pies ligeramente hacia afuera. Sujeta la barra sobre la parte superior de la espalda, apoyándola en los trapecios o los deltoides posteriores. Activa el core y mantén el pecho elevado mientras comienzas a bajar el cuerpo. Flexiona las rodillas y las caderas, empujando las caderas hacia atrás y hacia abajo como si te sentaras en una silla. Baja hasta que los muslos queden paralelos al suelo o un poco por debajo. Mantén las rodillas alineadas con los dedos de los pies y el peso sobre los talones. Empuja con los talones para volver a ponerte de pie, extendiendo las caderas y las rodillas. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, toes slightly turned out. Hold the barbell across your upper back, resting it on your traps or rear delts. Engage your core and keep your chest up as you begin to lower your body down. Bend at the knees and hips, pushing your hips back and down as if sitting into a chair. Lower yourself until your thighs are parallel to the ground or slightly below. Keep your knees in line with your toes and your weight in your heels. Drive through your heels to stand back up, extending your hips and knees. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0043-qXTaZnJ.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0043-qXTaZnJ.gif', 'qXTaZnJ', '© Gym visual — https://gymvisual.com/'),
('1461', 'barbell full squat (back pov)', 'Ponte de pie con los pies separados a la altura de los hombros, con los dedos de los pies ligeramente hacia afuera. Sujeta la barra sobre la parte superior de la espalda, apoyándola en los trapecios o los deltoides posteriores. Activa el core y mantén el pecho elevado mientras comienzas a bajar el c', 'upper legs', 'barbell', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves","core"}', 'Ponte de pie con los pies separados a la altura de los hombros, con los dedos de los pies ligeramente hacia afuera. Sujeta la barra sobre la parte superior de la espalda, apoyándola en los trapecios o los deltoides posteriores. Activa el core y mantén el pecho elevado mientras comienzas a bajar el cuerpo. Flexiona las rodillas y las caderas, empujando las caderas hacia atrás y hacia abajo como si te sentaras en una silla. Baja el cuerpo hasta que los muslos queden paralelos al suelo o un poco por debajo. Mantén las rodillas alineadas con los dedos de los pies y el peso sobre los talones. Empuja con los talones para volver a ponerte de pie, extendiendo las caderas y las rodillas. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, toes slightly turned out. Hold the barbell across your upper back, resting it on your traps or rear delts. Engage your core and keep your chest up as you begin to lower your body down. Bend at the knees and hips, pushing your hips back and down as if sitting into a chair. Lower your body until your thighs are parallel to the ground or slightly below. Keep your knees in line with your toes and your weight in your heels. Drive through your heels to stand back up, extending your hips and knees. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1461-DhMl549.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1461-DhMl549.gif', 'DhMl549', '© Gym visual — https://gymvisual.com/'),
('1462', 'barbell full squat (side pov)', 'Ponte de pie con los pies separados a la altura de los hombros, con los dedos de los pies ligeramente hacia afuera. Sujeta la barra sobre la parte superior de la espalda, apoyándola en los trapecios o los deltoides posteriores. Activa el core y mantén el pecho elevado mientras comienzas a bajar el c', 'upper legs', 'barbell', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves","core"}', 'Ponte de pie con los pies separados a la altura de los hombros, con los dedos de los pies ligeramente hacia afuera. Sujeta la barra sobre la parte superior de la espalda, apoyándola en los trapecios o los deltoides posteriores. Activa el core y mantén el pecho elevado mientras comienzas a bajar el cuerpo. Flexiona las rodillas y las caderas, empujando las caderas hacia atrás y hacia abajo como si te sentaras en una silla. Baja el cuerpo hasta que los muslos queden paralelos al suelo o un poco por debajo. Mantén las rodillas alineadas con los dedos de los pies y el peso sobre los talones. Empuja con los talones para volver a ponerte de pie, extendiendo las caderas y las rodillas. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, toes slightly turned out. Hold the barbell across your upper back, resting it on your traps or rear delts. Engage your core and keep your chest up as you begin to lower your body down. Bend at the knees and hips, pushing your hips back and down as if sitting into a chair. Lower your body until your thighs are parallel to the ground or slightly below. Keep your knees in line with your toes and your weight in your heels. Drive through your heels to stand back up, extending your hips and knees. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1462-iYzB0Cz.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1462-iYzB0Cz.gif', 'iYzB0Cz', '© Gym visual — https://gymvisual.com/'),
('1545', 'barbell full zercher squat', 'Ponte de pie con los pies separados a la altura de los hombros y los dedos de los pies ligeramente hacia afuera. Sujeta la barra en el pliegue de los codos, agarrándola con las manos para mantener la estabilidad. Activa el core y mantén el pecho elevado mientras bajas las caderas hacia atrás y hacia', 'upper legs', 'barbell', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves","core"}', 'Ponte de pie con los pies separados a la altura de los hombros y los dedos de los pies ligeramente hacia afuera. Sujeta la barra en el pliegue de los codos, agarrándola con las manos para mantener la estabilidad. Activa el core y mantén el pecho elevado mientras bajas las caderas hacia atrás y hacia abajo en una posición de sentadilla. Mantén las rodillas alineadas con los dedos de los pies y el peso sobre los talones. Baja hasta que los muslos queden paralelos al suelo, o tan abajo como puedas hacerlo cómodamente. Empuja con los talones para volver a ponerte de pie, apretando los glúteos en la parte alta del movimiento. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and toes slightly turned out. Hold the barbell in the crooks of your elbows, with your hands gripping the barbell for stability. Engage your core and keep your chest lifted as you lower your hips back and down into a squat position. Keep your knees in line with your toes and your weight in your heels. Lower until your thighs are parallel to the ground, or as low as you can comfortably go. Drive through your heels to stand back up, squeezing your glutes at the top of the movement. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1545-vR1vold.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1545-vR1vold.gif', 'vR1vold', '© Gym visual — https://gymvisual.com/'),
('1409', 'barbell glute bridge', 'Empieza tumbado boca arriba en el suelo con las rodillas flexionadas y los pies planos sobre el suelo. Coloca una barra sobre las caderas, sujetándola con firmeza con ambas manos. Activa los glúteos y el core, luego levanta las caderas del suelo hasta que el cuerpo forme una línea recta desde las ro', 'upper legs', 'barbell', 'upper legs', 'upper legs', 'glutes', '{"hamstrings","lower back"}', 'Empieza tumbado boca arriba en el suelo con las rodillas flexionadas y los pies planos sobre el suelo. Coloca una barra sobre las caderas, sujetándola con firmeza con ambas manos. Activa los glúteos y el core, luego levanta las caderas del suelo hasta que el cuerpo forme una línea recta desde las rodillas hasta los hombros. Haz una pausa breve en la parte alta, apretando los glúteos. Baja lentamente las caderas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Start by lying flat on your back on the ground with your knees bent and feet flat on the floor. Place a barbell across your hips, holding it securely with both hands. Engage your glutes and core muscles, then lift your hips off the ground until your body forms a straight line from your knees to your shoulders. Pause for a moment at the top, squeezing your glutes. Slowly lower your hips back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1409-qKBpF7I.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1409-qKBpF7I.gif', 'qKBpF7I', '© Gym visual — https://gymvisual.com/'),
('3562', 'barbell glute bridge two legs on bench (male)', 'Empieza sentado en el borde de un banco con la parte superior de la espalda apoyada contra él y los pies planos sobre el suelo, separados a la altura de las caderas. Coloca una barra sobre las caderas, sujetándola con firmeza con ambas manos. Activa los glúteos y el core, luego empuja con los talone', 'upper legs', 'barbell', 'upper legs', 'upper legs', 'glutes', '{"hamstrings","core"}', 'Empieza sentado en el borde de un banco con la parte superior de la espalda apoyada contra él y los pies planos sobre el suelo, separados a la altura de las caderas. Coloca una barra sobre las caderas, sujetándola con firmeza con ambas manos. Activa los glúteos y el core, luego empuja con los talones para levantar las caderas del banco, creando una línea recta desde las rodillas hasta los hombros. Haz una pausa breve en la parte alta, apretando los glúteos. Baja lentamente las caderas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Start by sitting on the edge of a bench with your upper back resting against it and your feet flat on the ground, hip-width apart. Place a barbell across your hips, holding it securely with both hands. Engage your glutes and core muscles, then press through your heels to lift your hips off the bench, creating a straight line from your knees to your shoulders. Pause for a moment at the top, squeezing your glutes. Slowly lower your hips back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3562-qg2PGl6.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3562-qg2PGl6.gif', 'qg2PGl6', '© Gym visual — https://gymvisual.com/'),
('0044', 'barbell good morning', 'Empieza de pie con los pies separados a la altura de los hombros y la barra apoyada sobre la parte superior de la espalda. Manteniendo la espalda recta y el core activado, flexiona las caderas hacia delante, empujando los glúteos hacia atrás como si intentaras tocar la pared detrás de ti con ellos. ', 'upper legs', 'barbell', 'upper legs', 'upper legs', 'hamstrings', '{"lower back"}', 'Empieza de pie con los pies separados a la altura de los hombros y la barra apoyada sobre la parte superior de la espalda. Manteniendo la espalda recta y el core activado, flexiona las caderas hacia delante, empujando los glúteos hacia atrás como si intentaras tocar la pared detrás de ti con ellos. Baja el torso hasta que quede paralelo al suelo, sintiendo un estiramiento en los isquiotibiales. Haz una pausa breve y luego vuelve a la posición inicial apretando los glúteos y empujando las caderas hacia delante. Repite el número de repeticiones deseado.', 'Start by standing with your feet shoulder-width apart and the barbell resting on your upper back. Keeping your back straight and your core engaged, hinge forward at the hips, pushing your buttocks back as if you were trying to touch the wall behind you with your glutes. Lower your torso until it is parallel to the ground, feeling a stretch in your hamstrings. Pause for a moment, then return to the starting position by squeezing your glutes and pushing your hips forward. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0044-XlZ4lAC.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0044-XlZ4lAC.gif', 'XlZ4lAC', '© Gym visual — https://gymvisual.com/'),
('0045', 'barbell guillotine bench press', 'Túmbate sobre un banco con los pies apoyados en el suelo y la espalda presionada contra el banco. Agarra la barra con un agarre pronado un poco más ancho que la separación de los hombros. Baja la barra lentamente hacia el cuello, manteniendo los codos apuntando hacia afuera. Haz una pausa breve cuan', 'chest', 'barbell', 'chest', 'chest', 'pectorals', '{"shoulders","triceps"}', 'Túmbate sobre un banco con los pies apoyados en el suelo y la espalda presionada contra el banco. Agarra la barra con un agarre pronado un poco más ancho que la separación de los hombros. Baja la barra lentamente hacia el cuello, manteniendo los codos apuntando hacia afuera. Haz una pausa breve cuando la barra esté justo encima del cuello. Empuja la barra de vuelta a la posición inicial, extendiendo completamente los brazos. Repite el número de repeticiones deseado.', 'Lie flat on a bench with your feet flat on the ground and your back pressed against the bench. Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart. Lower the barbell slowly towards your neck, keeping your elbows pointed outwards. Pause for a moment when the barbell is just above your neck. Push the barbell back up to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0045-GXoaSgn.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0045-GXoaSgn.gif', 'GXoaSgn', '© Gym visual — https://gymvisual.com/'),
('0046', 'barbell hack squat', 'Empieza de pie con los pies separados a la altura de los hombros y los dedos de los pies ligeramente hacia afuera. Sujeta la barra detrás de las piernas, apoyándola en la parte superior de los muslos. Baja el cuerpo flexionando las rodillas y las caderas, manteniendo la espalda recta y el pecho elev', 'upper legs', 'barbell', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves"}', 'Empieza de pie con los pies separados a la altura de los hombros y los dedos de los pies ligeramente hacia afuera. Sujeta la barra detrás de las piernas, apoyándola en la parte superior de los muslos. Baja el cuerpo flexionando las rodillas y las caderas, manteniendo la espalda recta y el pecho elevado. Continúa bajando hasta que los muslos queden paralelos al suelo, o tan abajo como puedas hacerlo cómodamente. Haz una pausa breve y luego empuja con los talones para volver a la posición inicial. Repite el número de repeticiones deseado.', 'Start by standing with your feet shoulder-width apart and your toes slightly turned out. Hold the barbell behind your legs, resting it on your upper thighs. Lower your body by bending at the knees and hips, keeping your back straight and your chest up. Continue lowering until your thighs are parallel to the ground, or as low as you can comfortably go. Pause for a moment, then push through your heels to return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0046-5VCj6iH.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0046-5VCj6iH.gif', '5VCj6iH', '© Gym visual — https://gymvisual.com/'),
('1436', 'barbell high bar squat', 'Ponte de pie con los pies separados a la altura de los hombros, con los dedos de los pies ligeramente hacia afuera. Coloca la barra sobre la parte superior de la espalda, apoyándola en los trapecios. Activa el core y mantén el pecho elevado mientras comienzas a bajar en sentadilla, empujando las cad', 'upper legs', 'barbell', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves","core"}', 'Ponte de pie con los pies separados a la altura de los hombros, con los dedos de los pies ligeramente hacia afuera. Coloca la barra sobre la parte superior de la espalda, apoyándola en los trapecios. Activa el core y mantén el pecho elevado mientras comienzas a bajar en sentadilla, empujando las caderas hacia atrás y flexionando las rodillas. Baja hasta que los muslos queden paralelos al suelo, o tan abajo como puedas hacerlo cómodamente. Empuja con los talones para volver a ponerte de pie, extendiendo las caderas y las rodillas. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, toes slightly turned out. Place the barbell on your upper back, resting it on your traps. Engage your core and keep your chest up as you begin to squat down, pushing your hips back and bending your knees. Lower yourself until your thighs are parallel to the ground, or as low as you can comfortably go. Drive through your heels to stand back up, extending your hips and knees. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1436-Gnfo4FM.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1436-Gnfo4FM.gif', 'Gnfo4FM', '© Gym visual — https://gymvisual.com/'),
('0047', 'barbell incline bench press', 'Coloca un banco inclinado a un ángulo de 45 grados. Túmbate en el banco con los pies planos sobre el suelo. Agarra la barra con un agarre pronado un poco más ancho que la separación de los hombros. Saca la barra del soporte y bájala lentamente hacia el pecho, manteniendo los codos a un ángulo de 45 ', 'chest', 'barbell', 'chest', 'chest', 'pectorals', '{"shoulders","triceps"}', 'Coloca un banco inclinado a un ángulo de 45 grados. Túmbate en el banco con los pies planos sobre el suelo. Agarra la barra con un agarre pronado un poco más ancho que la separación de los hombros. Saca la barra del soporte y bájala lentamente hacia el pecho, manteniendo los codos a un ángulo de 45 grados. Haz una pausa breve en la parte baja y luego empuja la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Set up an incline bench at a 45-degree angle. Lie down on the bench with your feet flat on the ground. Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart. Unrack the barbell and lower it slowly towards your chest, keeping your elbows at a 45-degree angle. Pause for a moment at the bottom, then push the barbell back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0047-3TZduzM.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0047-3TZduzM.gif', '3TZduzM', '© Gym visual — https://gymvisual.com/'),
('1719', 'barbell incline close grip bench press', 'Coloca un banco inclinado a un ángulo de 45 grados. Túmbate en el banco con los pies planos sobre el suelo. Agarra la barra con un agarre cerrado, un poco más estrecho que el ancho de los hombros. Saca la barra del soporte y bájala lentamente hacia el pecho, manteniendo los codos cerca del cuerpo. H', 'upper arms', 'barbell', 'upper arms', 'upper arms', 'triceps', '{"chest","shoulders"}', 'Coloca un banco inclinado a un ángulo de 45 grados. Túmbate en el banco con los pies planos sobre el suelo. Agarra la barra con un agarre cerrado, un poco más estrecho que el ancho de los hombros. Saca la barra del soporte y bájala lentamente hacia el pecho, manteniendo los codos cerca del cuerpo. Haz una pausa breve cuando la barra toque el pecho. Empuja la barra de vuelta a la posición inicial, extendiendo completamente los brazos. Repite el número de repeticiones deseado.', 'Set up an incline bench at a 45-degree angle. Lie down on the bench with your feet flat on the ground. Grasp the barbell with a close grip, slightly narrower than shoulder-width apart. Unrack the barbell and lower it slowly towards your chest, keeping your elbows close to your body. Pause for a moment when the barbell touches your chest. Push the barbell back up to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1719-gx7s7uF.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1719-gx7s7uF.gif', 'gx7s7uF', '© Gym visual — https://gymvisual.com/'),
('0048', 'barbell incline reverse-grip press', 'Coloca un banco inclinado a un ángulo de 45 grados. Recuéstate en el banco y agarra la barra con un agarre invertido, con las manos un poco más separadas que el ancho de los hombros. Saca la barra del soporte y bájala hacia la parte superior del pecho, manteniendo los codos pegados al cuerpo. Haz un', 'upper arms', 'barbell', 'upper arms', 'upper arms', 'triceps', '{"chest","shoulders"}', 'Coloca un banco inclinado a un ángulo de 45 grados. Recuéstate en el banco y agarra la barra con un agarre invertido, con las manos un poco más separadas que el ancho de los hombros. Saca la barra del soporte y bájala hacia la parte superior del pecho, manteniendo los codos pegados al cuerpo. Haz una pausa breve en la parte baja y luego empuja la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Set up an incline bench at a 45-degree angle. Lie back on the bench and grasp the barbell with a reverse grip, hands slightly wider than shoulder-width apart. Unrack the barbell and lower it towards your upper chest, keeping your elbows tucked in. Pause for a moment at the bottom, then push the barbell back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0048-641mIfk.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0048-641mIfk.gif', '641mIfk', '© Gym visual — https://gymvisual.com/'),
('0049', 'barbell incline row', 'Coloca un banco inclinado a un ángulo de 45 grados. Túmbate boca abajo en el banco con el pecho apoyado en el respaldo y los pies planos sobre el suelo. Agarra la barra con un agarre pronado un poco más ancho que la separación de los hombros. Mantén la espalda recta y el core activado. Tira de la ba', 'back', 'barbell', 'back', 'back', 'upper back', '{"biceps","forearms"}', 'Coloca un banco inclinado a un ángulo de 45 grados. Túmbate boca abajo en el banco con el pecho apoyado en el respaldo y los pies planos sobre el suelo. Agarra la barra con un agarre pronado un poco más ancho que la separación de los hombros. Mantén la espalda recta y el core activado. Tira de la barra hacia el pecho, juntando los omóplatos. Haz una pausa breve en la parte alta y luego baja lentamente la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Set up an incline bench at a 45-degree angle. Lie face down on the bench with your chest against the pad and your feet flat on the ground. Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart. Keep your back straight and your core engaged. Pull the barbell towards your chest, squeezing your shoulder blades together. Pause for a moment at the top, then slowly lower the barbell back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0049-dmgMp3n.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0049-dmgMp3n.gif', 'dmgMp3n', '© Gym visual — https://gymvisual.com/'),
('0050', 'barbell incline shoulder raise', 'Coloca un banco inclinado a un ángulo de 45 grados. Siéntate en el banco con la espalda apoyada en el respaldo y los pies planos sobre el suelo. Sujeta una barra con un agarre pronado, un poco más ancho que la separación de los hombros. Levanta la barra hasta la altura de los hombros, manteniendo lo', 'chest', 'barbell', 'chest', 'chest', 'serratus anterior', '{"deltoids","trapezius"}', 'Coloca un banco inclinado a un ángulo de 45 grados. Siéntate en el banco con la espalda apoyada en el respaldo y los pies planos sobre el suelo. Sujeta una barra con un agarre pronado, un poco más ancho que la separación de los hombros. Levanta la barra hasta la altura de los hombros, manteniendo los codos ligeramente flexionados. Levanta lentamente la barra por encima de la cabeza, extendiendo completamente los brazos. Haz una pausa breve en la parte alta y luego baja lentamente la barra de vuelta a la altura de los hombros. Repite el número de repeticiones deseado.', 'Set up an incline bench at a 45-degree angle. Sit on the bench with your back against the pad and feet flat on the ground. Hold a barbell with an overhand grip, slightly wider than shoulder-width apart. Lift the barbell up to shoulder height, keeping your elbows slightly bent. Slowly raise the barbell overhead, extending your arms fully. Pause for a moment at the top, then slowly lower the barbell back to shoulder height. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0050-xi0yckC.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0050-xi0yckC.gif', 'xi0yckC', '© Gym visual — https://gymvisual.com/'),
('0051', 'barbell jefferson squat', 'Ponte de pie con los pies separados a la altura de los hombros y los dedos de los pies ligeramente hacia afuera. Sujeta la barra con un agarre pronado, apoyándola en la parte delantera del cuerpo, justo debajo de la cintura. Da un paso con el pie izquierdo hacia delante y el pie derecho hacia atrás,', 'upper legs', 'barbell', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves"}', 'Ponte de pie con los pies separados a la altura de los hombros y los dedos de los pies ligeramente hacia afuera. Sujeta la barra con un agarre pronado, apoyándola en la parte delantera del cuerpo, justo debajo de la cintura. Da un paso con el pie izquierdo hacia delante y el pie derecho hacia atrás, manteniendo los pies separados a la altura de los hombros. Flexiona las rodillas y baja el cuerpo hacia una posición de sentadilla, manteniendo la espalda recta y el pecho elevado. Empuja con los talones para volver a ponerte de pie en la posición inicial. Repite el movimiento, alternando el pie delantero y el trasero en cada repetición.', 'Stand with your feet shoulder-width apart and toes slightly turned out. Hold the barbell with an overhand grip, resting it on the front of your body, just below your waist. Step your left foot forward and your right foot back, keeping your feet shoulder-width apart. Bend your knees and lower your body down into a squat position, keeping your back straight and chest up. Push through your heels to stand back up to the starting position. Repeat the movement, alternating your forward and back foot with each repetition.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0051-pkSoCW9.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0051-pkSoCW9.gif', 'pkSoCW9', '© Gym visual — https://gymvisual.com/'),
('0052', 'barbell jm bench press', 'Túmbate sobre un banco con los pies apoyados en el suelo y la espalda presionada contra el banco. Agarra la barra con un agarre pronado un poco más ancho que la separación de los hombros. Baja la barra hacia el pecho, manteniendo los codos pegados cerca del cuerpo. Empuja la barra de vuelta a la pos', 'upper arms', 'barbell', 'upper arms', 'upper arms', 'triceps', '{"chest","shoulders"}', 'Túmbate sobre un banco con los pies apoyados en el suelo y la espalda presionada contra el banco. Agarra la barra con un agarre pronado un poco más ancho que la separación de los hombros. Baja la barra hacia el pecho, manteniendo los codos pegados cerca del cuerpo. Empuja la barra de vuelta a la posición inicial, extendiendo completamente los brazos. Repite el número de repeticiones deseado.', 'Lie flat on a bench with your feet flat on the ground and your back pressed against the bench. Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart. Lower the barbell to your chest, keeping your elbows tucked in close to your body. Push the barbell back up to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0052-ZsiqXYa.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0052-ZsiqXYa.gif', 'ZsiqXYa', '© Gym visual — https://gymvisual.com/'),
('0053', 'barbell jump squat', 'Empieza de pie con los pies separados a la altura de los hombros, sujetando una barra sobre la parte superior de la espalda. Baja el cuerpo hacia una posición de sentadilla flexionando las rodillas y empujando las caderas hacia atrás. Al llegar a la parte baja de la sentadilla, impúlsate hacia arrib', 'upper legs', 'barbell', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves"}', 'Empieza de pie con los pies separados a la altura de los hombros, sujetando una barra sobre la parte superior de la espalda. Baja el cuerpo hacia una posición de sentadilla flexionando las rodillas y empujando las caderas hacia atrás. Al llegar a la parte baja de la sentadilla, impúlsate hacia arriba saltando desde el suelo. Al saltar, extiende las caderas, las rodillas y los tobillos, empujando con la punta de los pies. Aterriza con suavidad de vuelta en la posición de sentadilla y repite el movimiento de inmediato el número de repeticiones deseado.', 'Start by standing with your feet shoulder-width apart, holding a barbell across your upper back. Lower your body into a squat position by bending your knees and pushing your hips back. Once you reach the bottom of the squat, explode upwards by jumping off the ground. As you jump, extend your hips, knees, and ankles, pushing through your toes. Land softly back into the squat position and immediately repeat the movement for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0053-1gFNTZV.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0053-1gFNTZV.gif', '1gFNTZV', '© Gym visual — https://gymvisual.com/'),
('1410', 'barbell lateral lunge', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una barra sobre la parte superior de la espalda. Da un paso grande hacia el lado con el pie derecho, manteniendo el pie izquierdo fijo en el suelo. Flexiona la rodilla derecha y baja el cuerpo hacia una posición de zancada, ma', 'upper legs', 'barbell', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves"}', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una barra sobre la parte superior de la espalda. Da un paso grande hacia el lado con el pie derecho, manteniendo el pie izquierdo fijo en el suelo. Flexiona la rodilla derecha y baja el cuerpo hacia una posición de zancada, manteniendo la pierna izquierda recta. Empuja con el pie derecho y vuelve a la posición inicial. Repite hacia el otro lado, dando el paso con el pie izquierdo.', 'Stand with your feet shoulder-width apart, holding a barbell across your upper back. Take a big step to the side with your right foot, keeping your left foot planted. Bend your right knee and lower your body down into a lunge position, keeping your left leg straight. Push off with your right foot and return to the starting position. Repeat on the other side, stepping with your left foot.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1410-py1HSzx.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1410-py1HSzx.gif', 'py1HSzx', '© Gym visual — https://gymvisual.com/'),
('1435', 'barbell low bar squat', 'Ponte de pie con los pies separados a la altura de los hombros y la barra apoyada sobre la parte superior de la espalda. Manteniendo el pecho elevado y el core activado, baja lentamente el cuerpo flexionando las rodillas y empujando las caderas hacia atrás. Continúa bajando hasta que los muslos qued', 'upper legs', 'barbell', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves"}', 'Ponte de pie con los pies separados a la altura de los hombros y la barra apoyada sobre la parte superior de la espalda. Manteniendo el pecho elevado y el core activado, baja lentamente el cuerpo flexionando las rodillas y empujando las caderas hacia atrás. Continúa bajando hasta que los muslos queden paralelos al suelo o un poco por debajo. Haz una pausa breve y luego empuja con los talones para volver a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and the barbell resting on your upper back. Keeping your chest up and core engaged, slowly lower your body by bending your knees and pushing your hips back. Continue lowering until your thighs are parallel to the ground or slightly below. Pause for a moment, then push through your heels to return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1435-bTpEUcm.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1435-bTpEUcm.gif', 'bTpEUcm', '© Gym visual — https://gymvisual.com/'),
('0054', 'barbell lunge', 'Empieza de pie con los pies separados a la altura de los hombros y una barra apoyada sobre la parte superior de la espalda. Da un paso hacia delante con el pie derecho, manteniendo el torso erguido. Baja el cuerpo flexionando la rodilla derecha hasta que el muslo quede paralelo al suelo. Empuja con ', 'upper legs', 'barbell', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves"}', 'Empieza de pie con los pies separados a la altura de los hombros y una barra apoyada sobre la parte superior de la espalda. Da un paso hacia delante con el pie derecho, manteniendo el torso erguido. Baja el cuerpo flexionando la rodilla derecha hasta que el muslo quede paralelo al suelo. Empuja con el talón derecho para regresar a la posición inicial. Repite con la pierna izquierda, alternando las piernas el número de repeticiones deseado.', 'Start by standing with your feet shoulder-width apart and a barbell resting on your upper back. Take a step forward with your right foot, keeping your torso upright. Lower your body by bending your right knee until your thigh is parallel to the ground. Push through your right heel to return to the starting position. Repeat with your left leg, alternating legs for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0054-t8iSghb.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0054-t8iSghb.gif', 't8iSghb', '© Gym visual — https://gymvisual.com/'),
('1720', 'barbell lying back of the head tricep extension', 'Túmbate boca arriba en un banco con los pies planos sobre el suelo y la cabeza en el extremo del banco. Sujeta una barra con un agarre pronado, manos separadas a la altura de los hombros, y extiende los brazos rectos por encima del pecho. Manteniendo los brazos superiores fijos, baja lentamente la b', 'upper arms', 'barbell', 'upper arms', 'upper arms', 'triceps', '{"shoulders"}', 'Túmbate boca arriba en un banco con los pies planos sobre el suelo y la cabeza en el extremo del banco. Sujeta una barra con un agarre pronado, manos separadas a la altura de los hombros, y extiende los brazos rectos por encima del pecho. Manteniendo los brazos superiores fijos, baja lentamente la barra detrás de la cabeza flexionando los codos. Haz una pausa breve y luego extiende los brazos de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on a bench with your feet flat on the ground and your head at the end of the bench. Hold a barbell with an overhand grip, hands shoulder-width apart, and extend your arms straight up over your chest. Keeping your upper arms stationary, slowly lower the barbell behind your head by bending your elbows. Pause for a moment, then extend your arms back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1720-yg8Totb.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1720-yg8Totb.gif', 'yg8Totb', '© Gym visual — https://gymvisual.com/'),
('0055', 'barbell lying close-grip press', 'Túmbate sobre un banco con los pies apoyados en el suelo y la espalda presionada contra el banco. Agarra la barra con un agarre cerrado, manos separadas a la altura de los hombros, con las palmas mirando hacia los pies. Levanta la barra del soporte y sostenla directamente sobre el pecho con los braz', 'upper arms', 'barbell', 'upper arms', 'upper arms', 'triceps', '{"chest","shoulders"}', 'Túmbate sobre un banco con los pies apoyados en el suelo y la espalda presionada contra el banco. Agarra la barra con un agarre cerrado, manos separadas a la altura de los hombros, con las palmas mirando hacia los pies. Levanta la barra del soporte y sostenla directamente sobre el pecho con los brazos completamente extendidos. Baja la barra lentamente hacia el pecho, manteniendo los codos cerca del cuerpo. Haz una pausa breve cuando la barra toque el pecho y luego empújala de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on a bench with your feet flat on the ground and your back pressed against the bench. Grasp the barbell with a close grip, hands shoulder-width apart, palms facing towards your feet. Lift the barbell off the rack and hold it directly above your chest with your arms fully extended. Slowly lower the barbell towards your chest, keeping your elbows close to your body. Pause for a moment when the barbell touches your chest, then push it back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0055-EcaV7aL.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0055-EcaV7aL.gif', 'EcaV7aL', '© Gym visual — https://gymvisual.com/'),
('0056', 'barbell lying close-grip triceps extension', 'Túmbate boca arriba en un banco con los pies planos sobre el suelo y la cabeza en el extremo del banco. Agarra la barra con un agarre cerrado, manos separadas a la altura de los hombros, con las palmas hacia arriba. Extiende completamente los brazos, levantando la barra por encima del pecho. Manteni', 'upper arms', 'barbell', 'upper arms', 'upper arms', 'triceps', '{"shoulders"}', 'Túmbate boca arriba en un banco con los pies planos sobre el suelo y la cabeza en el extremo del banco. Agarra la barra con un agarre cerrado, manos separadas a la altura de los hombros, con las palmas hacia arriba. Extiende completamente los brazos, levantando la barra por encima del pecho. Manteniendo los brazos superiores fijos, baja lentamente la barra hacia la frente flexionando los codos. Haz una pausa breve en la parte baja y luego extiende los brazos de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on a bench with your feet flat on the ground and your head at the end of the bench. Grasp the barbell with a close grip, hands shoulder-width apart, palms facing up. Extend your arms fully, lifting the barbell above your chest. Keeping your upper arms stationary, slowly lower the barbell towards your forehead by bending your elbows. Pause for a moment at the bottom, then extend your arms back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0056-HJ63mSO.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0056-HJ63mSO.gif', 'HJ63mSO', '© Gym visual — https://gymvisual.com/'),
('0057', 'barbell lying extension', 'Túmbate boca arriba en un banco con los pies planos sobre el suelo y la cabeza en el extremo del banco. Sujeta una barra con un agarre pronado, manos separadas a la altura de los hombros, y extiende los brazos rectos por encima del pecho. Manteniendo los brazos superiores fijos, baja lentamente la b', 'upper arms', 'barbell', 'upper arms', 'upper arms', 'triceps', '{"shoulders"}', 'Túmbate boca arriba en un banco con los pies planos sobre el suelo y la cabeza en el extremo del banco. Sujeta una barra con un agarre pronado, manos separadas a la altura de los hombros, y extiende los brazos rectos por encima del pecho. Manteniendo los brazos superiores fijos, baja lentamente la barra hacia la frente flexionando los codos. Haz una pausa breve y luego extiende los brazos de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on a bench with your feet flat on the ground and your head at the end of the bench. Hold the barbell with an overhand grip, hands shoulder-width apart, and extend your arms straight up over your chest. Keeping your upper arms stationary, slowly lower the barbell towards your forehead by bending your elbows. Pause for a moment, then extend your arms back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0057-EMpUwRI.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0057-EMpUwRI.gif', 'EMpUwRI', '© Gym visual — https://gymvisual.com/'),
('0058', 'barbell lying lifting (on hip)', 'Túmbate boca arriba en un banco con los pies planos sobre el suelo y las rodillas flexionadas. Sujeta la barra con un agarre pronado y colócala sobre las caderas. Activando los glúteos, levanta las caderas del banco hasta que el cuerpo forme una línea recta desde las rodillas hasta los hombros. Haz ', 'upper legs', 'barbell', 'upper legs', 'upper legs', 'glutes', '{"hamstrings","quadriceps"}', 'Túmbate boca arriba en un banco con los pies planos sobre el suelo y las rodillas flexionadas. Sujeta la barra con un agarre pronado y colócala sobre las caderas. Activando los glúteos, levanta las caderas del banco hasta que el cuerpo forme una línea recta desde las rodillas hasta los hombros. Haz una pausa por un momento en la parte superior, luego baja lentamente las caderas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on your back on a bench with your feet flat on the ground and your knees bent. Hold the barbell with an overhand grip and position it on your hips. Engaging your glutes, lift your hips off the bench until your body forms a straight line from your knees to your shoulders. Pause for a moment at the top, then slowly lower your hips back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0058-SNFfUff.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0058-SNFfUff.gif', 'SNFfUff', '© Gym visual — https://gymvisual.com/'),
('0059', 'barbell lying preacher curl', 'Siéntate en un banco predicador con el pecho apoyado en el respaldo y los brazos extendidos sobre el borde, sujetando una barra con un agarre supino. Manteniendo los brazos superiores fijos, exhala y levanta el peso mientras contraes los bíceps. Continúa levantando la barra hasta que los bíceps esté', 'upper arms', 'barbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Siéntate en un banco predicador con el pecho apoyado en el respaldo y los brazos extendidos sobre el borde, sujetando una barra con un agarre supino. Manteniendo los brazos superiores fijos, exhala y levanta el peso mientras contraes los bíceps. Continúa levantando la barra hasta que los bíceps estén completamente contraídos y la barra esté a la altura de los hombros. Mantén la posición contraída durante una breve pausa mientras aprietas los bíceps. Inhala y comienza a bajar lentamente la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a preacher bench with your chest against the pad and your arms extended over the edge, holding a barbell with an underhand grip. Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Continue to raise the bar until your biceps are fully contracted and the bar is at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly begin to lower the barbell back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0059-SYJ4Bkt.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0059-SYJ4Bkt.gif', 'SYJ4Bkt', '© Gym visual — https://gymvisual.com/'),
('0061', 'barbell lying triceps extension', 'Túmbate boca arriba en un banco con los pies planos sobre el suelo y la cabeza en el extremo del banco. Sujeta una barra con un agarre pronado, manos separadas a la altura de los hombros, y extiende los brazos rectos por encima del pecho. Manteniendo los brazos superiores fijos, baja lentamente la b', 'upper arms', 'barbell', 'upper arms', 'upper arms', 'triceps', '{"shoulders"}', 'Túmbate boca arriba en un banco con los pies planos sobre el suelo y la cabeza en el extremo del banco. Sujeta una barra con un agarre pronado, manos separadas a la altura de los hombros, y extiende los brazos rectos por encima del pecho. Manteniendo los brazos superiores fijos, baja lentamente la barra hacia la frente flexionando los codos. Haz una pausa breve en la parte baja y luego extiende los brazos de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on a bench with your feet flat on the ground and your head at the end of the bench. Hold the barbell with an overhand grip, hands shoulder-width apart, and extend your arms straight up over your chest. Keeping your upper arms stationary, slowly lower the barbell towards your forehead by bending your elbows. Pause for a moment at the bottom, then extend your arms back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0061-iZop9xO.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0061-iZop9xO.gif', 'iZop9xO', '© Gym visual — https://gymvisual.com/'),
('0060', 'barbell lying triceps extension skull crusher', 'Túmbate boca arriba en un banco con los pies planos sobre el suelo y la cabeza en el extremo del banco. Sujeta una barra con un agarre pronado, manos separadas a la altura de los hombros, y extiende los brazos rectos por encima del pecho. Manteniendo los brazos superiores fijos, baja lentamente la b', 'upper arms', 'barbell', 'upper arms', 'upper arms', 'triceps', '{"shoulders"}', 'Túmbate boca arriba en un banco con los pies planos sobre el suelo y la cabeza en el extremo del banco. Sujeta una barra con un agarre pronado, manos separadas a la altura de los hombros, y extiende los brazos rectos por encima del pecho. Manteniendo los brazos superiores fijos, baja lentamente la barra hacia la frente flexionando los codos. Haz una pausa breve cuando la barra esté justo encima de la frente y luego extiende los brazos de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on a bench with your feet flat on the ground and your head at the end of the bench. Hold the barbell with an overhand grip, hands shoulder-width apart, and extend your arms straight up over your chest. Keeping your upper arms stationary, slowly lower the barbell towards your forehead by bending your elbows. Pause for a moment when the barbell is just above your forehead, then extend your arms back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0060-h8LFzo9.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0060-h8LFzo9.gif', 'h8LFzo9', '© Gym visual — https://gymvisual.com/'),
('0063', 'barbell narrow stance squat', 'Ponte de pie con los pies separados a la altura de los hombros y los dedos de los pies ligeramente hacia afuera. Sujeta la barra sobre la parte superior de la espalda, apoyándola en los trapecios o los deltoides posteriores. Activa el core y mantén el pecho elevado mientras bajas lentamente el cuerp', 'upper legs', 'barbell', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves"}', 'Ponte de pie con los pies separados a la altura de los hombros y los dedos de los pies ligeramente hacia afuera. Sujeta la barra sobre la parte superior de la espalda, apoyándola en los trapecios o los deltoides posteriores. Activa el core y mantén el pecho elevado mientras bajas lentamente el cuerpo flexionando las rodillas y empujando las caderas hacia atrás. Continúa bajando hasta que los muslos queden paralelos al suelo o un poco por debajo. Haz una pausa breve y luego empuja con los talones para volver a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and toes pointing slightly outward. Hold the barbell across your upper back, resting it on your traps or rear delts. Engage your core and keep your chest up as you slowly lower your body by bending your knees and pushing your hips back. Continue lowering until your thighs are parallel to the ground or slightly below. Pause for a moment, then push through your heels to return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0063-elhhVgj.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0063-elhhVgj.gif', 'elhhVgj', '© Gym visual — https://gymvisual.com/'),
('0064', 'barbell one arm bent over row', 'Ponte de pie con los pies separados a la altura de los hombros, las rodillas ligeramente flexionadas, y sujeta una barra con una mano usando un agarre pronado. Inclínate hacia delante desde las caderas, manteniendo la espalda recta y la cabeza en posición neutral. Tira de la barra hacia el pecho, ma', 'back', 'barbell', 'back', 'back', 'upper back', '{"biceps","forearms"}', 'Ponte de pie con los pies separados a la altura de los hombros, las rodillas ligeramente flexionadas, y sujeta una barra con una mano usando un agarre pronado. Inclínate hacia delante desde las caderas, manteniendo la espalda recta y la cabeza en posición neutral. Tira de la barra hacia el pecho, manteniendo el codo cerca del cuerpo y juntando los omóplatos. Baja la barra de vuelta a la posición inicial de forma controlada. Repite el número de repeticiones deseado, luego cambia al otro brazo.', 'Stand with your feet shoulder-width apart, knees slightly bent, and hold a barbell with one hand using an overhand grip. Bend forward at the hips, keeping your back straight and your head in a neutral position. Pull the barbell up towards your chest, keeping your elbow close to your body and squeezing your shoulder blades together. Lower the barbell back down to the starting position in a controlled manner. Repeat for the desired number of repetitions, then switch to the other arm.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0064-Jsgsc27.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0064-Jsgsc27.gif', 'Jsgsc27', '© Gym visual — https://gymvisual.com/'),
('0065', 'barbell one arm floor press', 'Túmbate boca arriba en el suelo con las rodillas flexionadas y los pies planos sobre el suelo. Sujeta la barra con una mano, con la palma hacia arriba, y extiende el brazo recto por encima del pecho. Baja la barra lentamente hacia el pecho, manteniendo el codo cerca del cuerpo. Haz una pausa breve e', 'upper arms', 'barbell', 'upper arms', 'upper arms', 'triceps', '{"chest","shoulders"}', 'Túmbate boca arriba en el suelo con las rodillas flexionadas y los pies planos sobre el suelo. Sujeta la barra con una mano, con la palma hacia arriba, y extiende el brazo recto por encima del pecho. Baja la barra lentamente hacia el pecho, manteniendo el codo cerca del cuerpo. Haz una pausa breve en la parte baja y luego empuja la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia de brazo.', 'Lie flat on your back on the floor with your knees bent and feet flat on the ground. Hold the barbell with one hand, palm facing up, and extend your arm straight up over your chest. Slowly lower the barbell towards your chest, keeping your elbow close to your body. Pause for a moment at the bottom, then push the barbell back up to the starting position. Repeat for the desired number of repetitions, then switch arms.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0065-vtusOWT.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0065-vtusOWT.gif', 'vtusOWT', '© Gym visual — https://gymvisual.com/'),
('0066', 'barbell one arm side deadlift', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una barra en una mano con un agarre pronado. Mantén la espalda recta y el core activado. Flexiona las caderas y baja la barra hacia el exterior de la pierna, manteniendo el brazo recto y el pecho elevado. Baja la barra tanto c', 'upper legs', 'barbell', 'upper legs', 'upper legs', 'glutes', '{"hamstrings","quadriceps","lower back"}', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una barra en una mano con un agarre pronado. Mantén la espalda recta y el core activado. Flexiona las caderas y baja la barra hacia el exterior de la pierna, manteniendo el brazo recto y el pecho elevado. Baja la barra tanto como puedas manteniendo una buena forma. Haz una pausa por un momento, luego regresa lentamente a la posición inicial. Repite el número de repeticiones deseado, luego cambia de lado.', 'Stand with your feet shoulder-width apart, holding a barbell in one hand with an overhand grip. Keep your back straight and your core engaged. Bend at the hips and lower the barbell towards the outside of your leg, keeping your arm straight and your chest up. Lower the barbell as far as you can while maintaining good form. Pause for a moment, then slowly return to the starting position. Repeat for the desired number of repetitions, then switch sides.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0066-2DxtqHL.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0066-2DxtqHL.gif', '2DxtqHL', '© Gym visual — https://gymvisual.com/'),
('0067', 'barbell one arm snatch', 'Ponte de pie con los pies separados a la altura de los hombros, los dedos de los pies ligeramente hacia afuera. Sujeta la barra con un agarre pronado, manos un poco más separadas que el ancho de los hombros. Flexiona las rodillas y baja las caderas hacia una posición de sentadilla, manteniendo la es', 'shoulders', 'barbell', 'shoulders', 'shoulders', 'delts', '{"traps","forearms","core"}', 'Ponte de pie con los pies separados a la altura de los hombros, los dedos de los pies ligeramente hacia afuera. Sujeta la barra con un agarre pronado, manos un poco más separadas que el ancho de los hombros. Flexiona las rodillas y baja las caderas hacia una posición de sentadilla, manteniendo la espalda recta y el pecho elevado. Extiende las caderas, las rodillas y los tobillos de forma explosiva, impulsando la barra hacia arriba. Cuando la barra llegue a la altura del pecho, tira de ella hacia arriba con el brazo, manteniéndola cerca del cuerpo. Rota el codo por debajo de la barra y extiende el brazo completamente por encima de la cabeza, bloqueando el codo. Baja la barra de vuelta a la posición inicial de forma controlada. Repite el número de repeticiones deseado, luego cambia de brazo.', 'Stand with your feet shoulder-width apart, toes pointing slightly outwards. Hold the barbell with an overhand grip, hands slightly wider than shoulder-width apart. Bend your knees and lower your hips into a squat position, keeping your back straight and chest up. Explosively extend your hips, knees, and ankles, driving the barbell upwards. As the barbell reaches chest level, pull it upwards with your arm, keeping it close to your body. Rotate your elbow under the barbell and extend your arm fully overhead, locking out your elbow. Lower the barbell back down to the starting position in a controlled manner. Repeat for the desired number of repetitions, then switch arms.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0067-xHKN2s8.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0067-xHKN2s8.gif', 'xHKN2s8', '© Gym visual — https://gymvisual.com/'),
('0068', 'barbell one leg squat', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una barra sobre la parte superior de la espalda. Levanta un pie del suelo y extiéndelo hacia delante, manteniéndolo paralelo al suelo. Flexiona la pierna de apoyo y baja el cuerpo como si te sentaras en una silla, manteniendo el', 'upper legs', 'barbell', 'upper legs', 'upper legs', 'quads', '{"glutes","hamstrings","calves"}', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una barra sobre la parte superior de la espalda. Levanta un pie del suelo y extiéndelo hacia delante, manteniéndolo paralelo al suelo. Flexiona la pierna de apoyo y baja el cuerpo como si te sentaras en una silla, manteniendo el pecho elevado y la espalda recta. Baja hasta que el muslo quede paralelo al suelo, luego empuja con el talón para volver a la posición inicial. Repite el número de repeticiones deseado y luego cambia de pierna y repite.', 'Stand with your feet shoulder-width apart and hold a barbell across your upper back. Lift one foot off the ground and extend it forward, keeping it parallel to the ground. Bend your standing leg and lower your body down as if sitting back into a chair, keeping your chest up and your back straight. Lower yourself until your thigh is parallel to the ground, then push through your heel to return to the starting position. Repeat for the desired number of repetitions, then switch legs and repeat.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0068-uKyN64F.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0068-uKyN64F.gif', 'uKyN64F', '© Gym visual — https://gymvisual.com/'),
('0069', 'barbell overhead squat', 'Ponte de pie con los pies separados a la altura de los hombros y los dedos de los pies ligeramente hacia afuera. Sujeta la barra con un agarre amplio, colocándola por encima de la cabeza con los brazos completamente extendidos. Activa el core y baja el cuerpo hacia una posición de sentadilla, manten', 'upper legs', 'barbell', 'upper legs', 'upper legs', 'quads', '{"glutes","hamstrings","calves","core"}', 'Ponte de pie con los pies separados a la altura de los hombros y los dedos de los pies ligeramente hacia afuera. Sujeta la barra con un agarre amplio, colocándola por encima de la cabeza con los brazos completamente extendidos. Activa el core y baja el cuerpo hacia una posición de sentadilla, manteniendo el pecho elevado y las rodillas alineadas con los dedos de los pies. Haz una pausa por un momento en la parte inferior, luego empuja con los talones para regresar a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and toes slightly turned out. Hold the barbell with a wide grip, positioning it overhead with your arms fully extended. Engage your core and lower your body down into a squat position, keeping your chest up and knees tracking over your toes. Pause for a moment at the bottom, then push through your heels to return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0069-gfk9kD4.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0069-gfk9kD4.gif', 'gfk9kD4', '© Gym visual — https://gymvisual.com/'),
('1411', 'barbell palms down wrist curl over a bench', 'Siéntate en un banco con los pies planos sobre el suelo y los antebrazos apoyados sobre los muslos, con las palmas hacia abajo. Sujeta una barra con un agarre pronado, manos separadas a la altura de los hombros. Baja la barra hacia el suelo flexionando las muñecas, manteniendo los antebrazos fijos. ', 'lower arms', 'barbell', 'lower arms', 'lower arms', 'forearms', '{"biceps","brachialis"}', 'Siéntate en un banco con los pies planos sobre el suelo y los antebrazos apoyados sobre los muslos, con las palmas hacia abajo. Sujeta una barra con un agarre pronado, manos separadas a la altura de los hombros. Baja la barra hacia el suelo flexionando las muñecas, manteniendo los antebrazos fijos. Haz una pausa breve en la parte baja y luego levanta lentamente la barra extendiendo las muñecas. Repite el número de repeticiones deseado.', 'Sit on a bench with your feet flat on the ground and your forearms resting on your thighs, palms facing down. Hold a barbell with an overhand grip, hands shoulder-width apart. Lower the barbell towards the ground by flexing your wrists, keeping your forearms stationary. Pause for a moment at the bottom, then slowly raise the barbell back up by extending your wrists. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1411-yzYH9pI.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1411-yzYH9pI.gif', 'yzYH9pI', '© Gym visual — https://gymvisual.com/'),
('1412', 'barbell palms up wrist curl over a bench', 'Siéntate en un banco con los pies planos sobre el suelo y sujeta una barra con un agarre supino, con las palmas hacia arriba. Apoya los antebrazos sobre el banco, dejando que las muñecas cuelguen del borde. Manteniendo los antebrazos fijos, exhala y flexiona las muñecas hacia arriba tanto como sea p', 'lower arms', 'barbell', 'lower arms', 'lower arms', 'forearms', '{"biceps","shoulders"}', 'Siéntate en un banco con los pies planos sobre el suelo y sujeta una barra con un agarre supino, con las palmas hacia arriba. Apoya los antebrazos sobre el banco, dejando que las muñecas cuelguen del borde. Manteniendo los antebrazos fijos, exhala y flexiona las muñecas hacia arriba tanto como sea posible. Mantén la posición contraída durante una breve pausa, luego inhala y baja lentamente la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a bench with your feet flat on the ground and hold a barbell with an underhand grip, palms facing up. Rest your forearms on the bench, allowing your wrists to hang off the edge. Keeping your forearms stationary, exhale and curl your wrists upwards as far as possible. Hold the contracted position for a brief pause, then inhale and slowly lower the barbell back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1412-SJAA2IQ.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1412-SJAA2IQ.gif', 'SJAA2IQ', '© Gym visual — https://gymvisual.com/'),
('3017', 'barbell pendlay row', 'Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Inclínate hacia delante desde las caderas manteniendo la espalda recta y el pecho elevado. Agarra la barra con un agarre pronado un poco más ancho que la separación de los hombros. Tira de la barra', 'back', 'barbell', 'back', 'back', 'upper back', '{"biceps","forearms"}', 'Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Inclínate hacia delante desde las caderas manteniendo la espalda recta y el pecho elevado. Agarra la barra con un agarre pronado un poco más ancho que la separación de los hombros. Tira de la barra hacia la parte superior del abdomen, juntando los omóplatos. Baja la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and your knees slightly bent. Bend forward at the hips, keeping your back straight and your chest up. Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart. Pull the barbell towards your upper abdomen, squeezing your shoulder blades together. Lower the barbell back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3017-r0z6xzQ.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3017-r0z6xzQ.gif', 'r0z6xzQ', '© Gym visual — https://gymvisual.com/'),
('1751', 'barbell pin presses', 'Coloca una barra en un rack de potencia a la altura del pecho. Ponte de pie frente a la barra y colócate debajo de ella, con los pies separados a la altura de los hombros. Agarra la barra con un agarre pronado un poco más ancho que la separación de los hombros. Levanta la barra del soporte y sostenl', 'upper arms', 'barbell', 'upper arms', 'upper arms', 'triceps', '{"shoulders"}', 'Coloca una barra en un rack de potencia a la altura del pecho. Ponte de pie frente a la barra y colócate debajo de ella, con los pies separados a la altura de los hombros. Agarra la barra con un agarre pronado un poco más ancho que la separación de los hombros. Levanta la barra del soporte y sostenla directamente sobre el pecho con los brazos completamente extendidos. Baja la barra hacia el pecho, manteniendo los codos pegados cerca del cuerpo. Haz una pausa breve cuando la barra toque el pecho. Empuja la barra de vuelta a la posición inicial, extendiendo completamente los brazos. Repite el número de repeticiones deseado.', 'Set up a barbell on a power rack at chest height. Stand facing the barbell and position yourself underneath it, with your feet shoulder-width apart. Grip the barbell with an overhand grip, slightly wider than shoulder-width apart. Lift the barbell off the rack and hold it directly above your chest, with your arms fully extended. Lower the barbell down towards your chest, keeping your elbows tucked in close to your body. Pause for a moment when the barbell touches your chest. Push the barbell back up to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1751-bndCa3Q.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1751-bndCa3Q.gif', 'bndCa3Q', '© Gym visual — https://gymvisual.com/'),
('0070', 'barbell preacher curl', 'Siéntate en un banco predicador con los brazos superiores apoyados en el cojín y el pecho contra el soporte. Agarra la barra con un agarre supino, un poco más ancho que la separación de los hombros. Manteniendo los brazos superiores fijos, exhala y levanta la barra hacia los hombros. Haz una pausa b', 'upper arms', 'barbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Siéntate en un banco predicador con los brazos superiores apoyados en el cojín y el pecho contra el soporte. Agarra la barra con un agarre supino, un poco más ancho que la separación de los hombros. Manteniendo los brazos superiores fijos, exhala y levanta la barra hacia los hombros. Haz una pausa breve en la parte alta, apretando los bíceps. Inhala y baja lentamente la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a preacher bench with your upper arms resting on the pad and your chest against the support. Grasp the barbell with an underhand grip, slightly wider than shoulder-width apart. Keeping your upper arms stationary, exhale and curl the barbell up towards your shoulders. Pause for a moment at the top, squeezing your biceps. Inhale and slowly lower the barbell back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0070-qOgPVf6.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0070-qOgPVf6.gif', 'qOgPVf6', '© Gym visual — https://gymvisual.com/'),
('0071', 'barbell press sit-up', 'Túmbate boca arriba en una esterilla con las rodillas flexionadas y los pies planos sobre el suelo. Sujeta la barra con un agarre pronado, apoyándola sobre el pecho. Activando el abdomen, levanta lentamente la parte superior del cuerpo del suelo, curvándote hacia adelante hasta que tu torso forme un', 'waist', 'barbell', 'waist', 'waist', 'abs', '{"shoulders","chest"}', 'Túmbate boca arriba en una esterilla con las rodillas flexionadas y los pies planos sobre el suelo. Sujeta la barra con un agarre pronado, apoyándola sobre el pecho. Activando el abdomen, levanta lentamente la parte superior del cuerpo del suelo, curvándote hacia adelante hasta que tu torso forme un ángulo de 45 grados. Haz una pausa por un momento en la parte superior, luego baja lentamente la parte superior del cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on your back on a mat with your knees bent and feet flat on the ground. Hold the barbell with an overhand grip, resting it on your chest. Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle. Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0071-wnEscH8.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0071-wnEscH8.gif', 'wnEscH8', '© Gym visual — https://gymvisual.com/'),
('0072', 'barbell prone incline curl', 'Coloca un banco inclinado a un ángulo de 45 grados. Túmbate boca abajo en el banco con el pecho y el abdomen apoyados contra él. Sujeta una barra con un agarre supino, separado a la altura de los hombros. Extiende completamente los brazos, dejando que la barra cuelgue hacia el suelo. Manteniendo los', 'upper arms', 'barbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Coloca un banco inclinado a un ángulo de 45 grados. Túmbate boca abajo en el banco con el pecho y el abdomen apoyados contra él. Sujeta una barra con un agarre supino, separado a la altura de los hombros. Extiende completamente los brazos, dejando que la barra cuelgue hacia el suelo. Manteniendo los brazos superiores fijos, exhala y levanta el peso mientras contraes los bíceps. Continúa levantando la barra hasta que los bíceps estén completamente contraídos y la barra esté a la altura de los hombros. Mantén la posición contraída durante una breve pausa mientras aprietas los bíceps. Inhala y comienza a bajar lentamente la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Set up an incline bench at a 45-degree angle. Lie face down on the bench with your chest and stomach resting against it. Hold a barbell with an underhand grip, shoulder-width apart. Extend your arms fully, allowing the barbell to hang down towards the floor. Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Continue to raise the barbell until your biceps are fully contracted and the bar is at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly begin to lower the barbell back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0072-WLvTAv5.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0072-WLvTAv5.gif', 'WLvTAv5', '© Gym visual — https://gymvisual.com/'),
('0073', 'barbell pullover', 'Túmbate boca arriba en un banco con la cabeza en un extremo y los pies en el suelo. Sujeta una barra con un agarre a la altura de los hombros y extiende los brazos rectos por encima del pecho. Manteniendo los brazos rectos, baja la barra detrás de la cabeza de forma controlada hasta sentir un estira', 'back', 'barbell', 'back', 'back', 'lats', '{"chest","triceps"}', 'Túmbate boca arriba en un banco con la cabeza en un extremo y los pies en el suelo. Sujeta una barra con un agarre a la altura de los hombros y extiende los brazos rectos por encima del pecho. Manteniendo los brazos rectos, baja la barra detrás de la cabeza de forma controlada hasta sentir un estiramiento en los dorsales. Haz una pausa breve y luego levanta la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on a bench with your head at one end and your feet on the floor. Hold a barbell with a shoulder-width grip and extend your arms straight above your chest. Keeping your arms straight, lower the barbell behind your head in a controlled manner until you feel a stretch in your lats. Pause for a moment, then raise the barbell back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0073-i6LWjok.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0073-i6LWjok.gif', 'i6LWjok', '© Gym visual — https://gymvisual.com/'),
('0022', 'barbell pullover to press', 'Túmbate boca arriba en un banco con la cabeza en un extremo y los pies en el suelo. Sujeta una barra con un agarre pronado (palmas mirando hacia afuera) y extiende los brazos rectos por encima del pecho. Manteniendo los brazos rectos, baja la barra detrás de la cabeza con un movimiento en forma de a', 'back', 'barbell', 'back', 'back', 'lats', '{"triceps","chest","shoulders"}', 'Túmbate boca arriba en un banco con la cabeza en un extremo y los pies en el suelo. Sujeta una barra con un agarre pronado (palmas mirando hacia afuera) y extiende los brazos rectos por encima del pecho. Manteniendo los brazos rectos, baja la barra detrás de la cabeza con un movimiento en forma de arco hasta sentir un estiramiento en los dorsales. Haz una pausa breve, luego invierte el movimiento y empuja la barra de vuelta a la posición inicial por encima del pecho. Repite el número de repeticiones deseado.', 'Lie flat on a bench with your head at one end and your feet on the ground. Hold the barbell with a pronated grip (palms facing away from you) and extend your arms straight above your chest. Keeping your arms straight, lower the barbell behind your head in an arc-like motion until you feel a stretch in your lats. Pause for a moment, then reverse the motion and press the barbell back to the starting position above your chest. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0022-znLogoF.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0022-znLogoF.gif', 'znLogoF', '© Gym visual — https://gymvisual.com/'),
('0074', 'barbell rack pull', 'Coloca una barra en un soporte a la altura de la rodilla. Ponte de pie con los pies separados a la altura de los hombros, los dedos de los pies ligeramente hacia afuera. Flexiona las caderas y las rodillas para bajar y agarrar la barra con un agarre pronado, manos separadas a la altura de los hombro', 'upper legs', 'barbell', 'upper legs', 'upper legs', 'glutes', '{"hamstrings","lower back"}', 'Coloca una barra en un soporte a la altura de la rodilla. Ponte de pie con los pies separados a la altura de los hombros, los dedos de los pies ligeramente hacia afuera. Flexiona las caderas y las rodillas para bajar y agarrar la barra con un agarre pronado, manos separadas a la altura de los hombros. Activa el core y levanta la barra extendiendo las caderas y las rodillas, llevando los hombros hacia atrás y apretando los glúteos en la parte alta. Baja la barra de vuelta a la posición inicial flexionando las caderas y las rodillas. Repite el número de repeticiones deseado.', 'Set up a barbell on a rack at knee height. Stand with your feet shoulder-width apart, toes pointing slightly outwards. Bend at the hips and knees to lower yourself down and grip the barbell with an overhand grip, hands shoulder-width apart. Engage your core and lift the barbell by extending your hips and knees, pulling your shoulders back and squeezing your glutes at the top. Lower the barbell back down to the starting position by bending at the hips and knees. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0074-za9Ni4z.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0074-za9Ni4z.gif', 'za9Ni4z', '© Gym visual — https://gymvisual.com/'),
('0075', 'barbell rear delt raise', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una barra con un agarre pronado, con las palmas hacia abajo. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta. Levanta la barra hacia los lados, manteniendo los brazos ', 'shoulders', 'barbell', 'shoulders', 'shoulders', 'delts', '{"traps","rhomboids"}', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una barra con un agarre pronado, con las palmas hacia abajo. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta. Levanta la barra hacia los lados, manteniendo los brazos rectos, hasta que queden paralelos al suelo. Haz una pausa breve en la parte alta y luego baja lentamente la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and hold a barbell with an overhand grip, palms facing down. Bend your knees slightly and hinge forward at the hips, keeping your back straight. Raise the barbell out to the sides, keeping your arms straight, until they are parallel to the ground. Pause for a moment at the top, then slowly lower the barbell back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0075-Ln9iTbU.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0075-Ln9iTbU.gif', 'Ln9iTbU', '© Gym visual — https://gymvisual.com/'),
('0076', 'barbell rear delt row', 'Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Sujeta una barra con un agarre pronado, manos un poco más separadas que el ancho de los hombros. Inclínate hacia delante desde las caderas, manteniendo la espalda recta y el pecho elevado. Tira de ', 'shoulders', 'barbell', 'shoulders', 'shoulders', 'delts', '{"trapezius","rhomboids","biceps"}', 'Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Sujeta una barra con un agarre pronado, manos un poco más separadas que el ancho de los hombros. Inclínate hacia delante desde las caderas, manteniendo la espalda recta y el pecho elevado. Tira de la barra hacia el pecho, juntando los omóplatos. Haz una pausa breve en la parte alta y luego baja lentamente la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and knees slightly bent. Hold a barbell with an overhand grip, hands slightly wider than shoulder-width apart. Bend forward at the hips, keeping your back straight and chest up. Pull the barbell towards your chest, squeezing your shoulder blades together. Pause for a moment at the top, then slowly lower the barbell back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0076-S9zHIvU.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0076-S9zHIvU.gif', 'S9zHIvU', '© Gym visual — https://gymvisual.com/'),
('0078', 'barbell rear lunge', 'Empieza de pie con los pies separados a la altura de los hombros y una barra apoyada sobre la parte superior de la espalda. Da un paso hacia atrás con el pie derecho, apoyándote en la punta del pie. Flexiona ambas rodillas para bajar el cuerpo hasta que el muslo izquierdo quede paralelo al suelo. Em', 'upper legs', 'barbell', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves"}', 'Empieza de pie con los pies separados a la altura de los hombros y una barra apoyada sobre la parte superior de la espalda. Da un paso hacia atrás con el pie derecho, apoyándote en la punta del pie. Flexiona ambas rodillas para bajar el cuerpo hasta que el muslo izquierdo quede paralelo al suelo. Empuja con el talón izquierdo para volver a la posición inicial. Repite con la otra pierna.', 'Start by standing with your feet shoulder-width apart and a barbell resting on your upper back. Take a step backward with your right foot, landing on the ball of your foot. Bend both knees to lower your body until your left thigh is parallel to the ground. Push through your left heel to return to the starting position. Repeat with the other leg.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0078-VaP75jl.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0078-VaP75jl.gif', 'VaP75jl', '© Gym visual — https://gymvisual.com/'),
('0077', 'barbell rear lunge v. 2', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una barra sobre la parte superior de la espalda. Da un paso hacia atrás con el pie derecho, apoyándote en la punta del pie. Flexiona ambas rodillas para bajar el cuerpo hasta que el muslo izquierdo quede paralelo al suelo. Empuj', 'upper legs', 'barbell', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves"}', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una barra sobre la parte superior de la espalda. Da un paso hacia atrás con el pie derecho, apoyándote en la punta del pie. Flexiona ambas rodillas para bajar el cuerpo hasta que el muslo izquierdo quede paralelo al suelo. Empuja con el talón izquierdo para volver a la posición inicial. Repite con la otra pierna.', 'Stand with your feet shoulder-width apart and hold a barbell across your upper back. Take a step backward with your right foot, landing on the ball of your foot. Bend both knees to lower your body until your left thigh is parallel to the ground. Push through your left heel to return to the starting position. Repeat with the other leg.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0077-62Nw60O.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0077-62Nw60O.gif', '62Nw60O', '© Gym visual — https://gymvisual.com/'),
('0079', 'barbell revers wrist curl v. 2', 'Siéntate en un banco con los pies planos sobre el suelo y las rodillas flexionadas. Sujeta una barra con un agarre pronado, palmas hacia abajo, y las manos separadas a la altura de los hombros. Apoya los antebrazos sobre los muslos, dejando que las muñecas cuelguen del borde. Manteniendo los antebra', 'lower arms', 'barbell', 'lower arms', 'lower arms', 'forearms', '{"biceps","brachialis"}', 'Siéntate en un banco con los pies planos sobre el suelo y las rodillas flexionadas. Sujeta una barra con un agarre pronado, palmas hacia abajo, y las manos separadas a la altura de los hombros. Apoya los antebrazos sobre los muslos, dejando que las muñecas cuelguen del borde. Manteniendo los antebrazos fijos, exhala y flexiona las muñecas hacia arriba tanto como sea posible. Mantén la posición contraída durante una breve pausa, luego inhala y baja lentamente la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a bench with your feet flat on the ground and your knees bent. Hold a barbell with an overhand grip, palms facing down, and your hands shoulder-width apart. Rest your forearms on your thighs, allowing your wrists to hang off the edge. Keeping your forearms stationary, exhale and curl your wrists upward as far as possible. Hold the contracted position for a brief pause, then inhale and slowly lower the barbell back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0079-qDnGfDb.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0079-qDnGfDb.gif', 'qDnGfDb', '© Gym visual — https://gymvisual.com/'),
('2187', 'barbell reverse close-grip bench press', 'Túmbate sobre un banco con los pies apoyados en el suelo y la espalda presionada contra el banco. Agarra la barra con un agarre invertido, manos separadas a la altura de los hombros. Levanta la barra del soporte y sostenla directamente sobre el pecho con los brazos completamente extendidos. Baja la ', 'upper arms', 'barbell', 'upper arms', 'upper arms', 'triceps', '{"chest","shoulders"}', 'Túmbate sobre un banco con los pies apoyados en el suelo y la espalda presionada contra el banco. Agarra la barra con un agarre invertido, manos separadas a la altura de los hombros. Levanta la barra del soporte y sostenla directamente sobre el pecho con los brazos completamente extendidos. Baja la barra lentamente hacia el pecho, manteniendo los codos cerca del cuerpo. Haz una pausa breve cuando la barra esté justo encima del pecho. Empuja la barra de vuelta a la posición inicial, extendiendo completamente los brazos. Repite el número de repeticiones deseado.', 'Lie flat on a bench with your feet flat on the ground and your back pressed against the bench. Grasp the barbell with a reverse grip, hands shoulder-width apart. Lift the barbell off the rack and hold it directly above your chest with your arms fully extended. Slowly lower the barbell down towards your chest, keeping your elbows close to your body. Pause for a moment when the barbell is just above your chest. Push the barbell back up to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2187-YqJw82s.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2187-YqJw82s.gif', 'YqJw82s', '© Gym visual — https://gymvisual.com/'),
('0080', 'barbell reverse curl', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una barra con un agarre pronado, con las palmas hacia abajo. Mantén los brazos superiores fijos y exhala mientras levantas la barra hacia arriba, contrayendo los bíceps. Continúa levantando la barra hasta que los bíceps estén co', 'upper arms', 'barbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una barra con un agarre pronado, con las palmas hacia abajo. Mantén los brazos superiores fijos y exhala mientras levantas la barra hacia arriba, contrayendo los bíceps. Continúa levantando la barra hasta que los bíceps estén completamente contraídos y la barra esté a la altura de los hombros. Mantén la posición contraída durante una breve pausa mientras aprietas los bíceps. Inhala mientras bajas lentamente la barra de vuelta a la posición inicial, manteniendo los brazos superiores fijos. Repite el número de repeticiones deseado.', 'Stand up straight with your feet shoulder-width apart and hold a barbell with an overhand grip, palms facing down. Keep your upper arms stationary and exhale as you curl the barbell upward, contracting your biceps. Continue to raise the barbell until your biceps are fully contracted and the barbell is at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale as you slowly lower the barbell back to the starting position, keeping your upper arms stationary. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0080-xNrS20v.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0080-xNrS20v.gif', 'xNrS20v', '© Gym visual — https://gymvisual.com/'),
('0118', 'barbell reverse grip bent over row', 'Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Sujeta una barra con un agarre pronado, palmas hacia abajo, y las manos un poco más separadas que el ancho de los hombros. Inclínate hacia delante desde las caderas, manteniendo la espalda recta y ', 'back', 'barbell', 'back', 'back', 'upper back', '{"biceps","forearms"}', 'Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Sujeta una barra con un agarre pronado, palmas hacia abajo, y las manos un poco más separadas que el ancho de los hombros. Inclínate hacia delante desde las caderas, manteniendo la espalda recta y el pecho elevado, hasta que el torso quede casi paralelo al suelo. Tira de la barra hacia la parte inferior del pecho, juntando los omóplatos. Haz una pausa breve en la parte alta y luego baja lentamente la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and knees slightly bent. Hold a barbell with an overhand grip, palms facing down, and hands slightly wider than shoulder-width apart. Bend forward at the hips, keeping your back straight and chest up, until your torso is almost parallel to the floor. Pull the barbell towards your lower chest, squeezing your shoulder blades together. Pause for a moment at the top, then slowly lower the barbell back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0118-SzX3uzM.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0118-SzX3uzM.gif', 'SzX3uzM', '© Gym visual — https://gymvisual.com/'),
('1256', 'barbell reverse grip decline bench press', 'Túmbate en un banco declinado con los pies sujetos y la cabeza más baja que las caderas. Agarra la barra con un agarre invertido, un poco más ancho que la separación de los hombros. Saca la barra del soporte y bájala lentamente hacia el pecho, manteniendo los codos pegados al cuerpo. Haz una pausa b', 'chest', 'barbell', 'chest', 'chest', 'pectorals', '{"triceps","shoulders"}', 'Túmbate en un banco declinado con los pies sujetos y la cabeza más baja que las caderas. Agarra la barra con un agarre invertido, un poco más ancho que la separación de los hombros. Saca la barra del soporte y bájala lentamente hacia el pecho, manteniendo los codos pegados al cuerpo. Haz una pausa breve en la parte baja y luego empuja la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie on a decline bench with your feet secured and your head lower than your hips. Grasp the barbell with a reverse grip, slightly wider than shoulder-width apart. Unrack the barbell and lower it slowly towards your chest, keeping your elbows tucked in. Pause for a moment at the bottom, then push the barbell back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1256-DotAgEF.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1256-DotAgEF.gif', 'DotAgEF', '© Gym visual — https://gymvisual.com/'),
('1257', 'barbell reverse grip incline bench press', 'Coloca un banco inclinado a un ángulo de 45 grados. Túmbate en el banco con los pies planos sobre el suelo. Agarra la barra con un agarre invertido, manos un poco más separadas que el ancho de los hombros. Saca la barra del soporte y bájala lentamente hacia el pecho, manteniendo los codos pegados al', 'chest', 'barbell', 'chest', 'chest', 'pectorals', '{"triceps","shoulders"}', 'Coloca un banco inclinado a un ángulo de 45 grados. Túmbate en el banco con los pies planos sobre el suelo. Agarra la barra con un agarre invertido, manos un poco más separadas que el ancho de los hombros. Saca la barra del soporte y bájala lentamente hacia el pecho, manteniendo los codos pegados al cuerpo. Haz una pausa breve cuando la barra toque el pecho. Empuja la barra de vuelta a la posición inicial, extendiendo completamente los brazos. Repite el número de repeticiones deseado.', 'Set up an incline bench at a 45-degree angle. Lie down on the bench with your feet flat on the ground. Grasp the barbell with a reverse grip, hands slightly wider than shoulder-width apart. Unrack the barbell and lower it slowly towards your chest, keeping your elbows tucked in. Pause for a moment when the barbell touches your chest. Push the barbell back up to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1257-DU7I633.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1257-DU7I633.gif', 'DU7I633', '© Gym visual — https://gymvisual.com/'),
('1317', 'barbell reverse grip incline bench row', 'Coloca un banco inclinado a un ángulo de 45 grados. Siéntate en el banco frente al respaldo con el pecho apoyado contra él. Sujeta la barra con un agarre invertido (palmas hacia abajo) y las manos un poco más separadas que el ancho de los hombros. Mantén la espalda recta y el core activado. Tira de ', 'back', 'barbell', 'back', 'back', 'upper back', '{"biceps","forearms"}', 'Coloca un banco inclinado a un ángulo de 45 grados. Siéntate en el banco frente al respaldo con el pecho apoyado contra él. Sujeta la barra con un agarre invertido (palmas hacia abajo) y las manos un poco más separadas que el ancho de los hombros. Mantén la espalda recta y el core activado. Tira de la barra hacia la parte superior del abdomen, juntando los omóplatos. Haz una pausa breve en la parte alta del movimiento. Baja lentamente la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Set up an incline bench at a 45-degree angle. Sit on the bench facing the backrest with your chest against it. Grab the barbell with a reverse grip (palms facing down) and hands slightly wider than shoulder-width apart. Keep your back straight and core engaged. Pull the barbell towards your upper abdomen, squeezing your shoulder blades together. Pause for a moment at the top of the movement. Slowly lower the barbell back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1317-8d8qJQI.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1317-8d8qJQI.gif', '8d8qJQI', '© Gym visual — https://gymvisual.com/'),
('1721', 'barbell reverse grip skullcrusher', 'Túmbate boca arriba en un banco con los pies planos sobre el suelo y la cabeza en el extremo del banco. Sujeta la barra con un agarre invertido, palmas mirando hacia la cara, y las manos separadas a la altura de los hombros. Extiende los brazos rectos por encima del pecho, manteniendo los codos haci', 'upper arms', 'barbell', 'upper arms', 'upper arms', 'triceps', '{"forearms"}', 'Túmbate boca arriba en un banco con los pies planos sobre el suelo y la cabeza en el extremo del banco. Sujeta la barra con un agarre invertido, palmas mirando hacia la cara, y las manos separadas a la altura de los hombros. Extiende los brazos rectos por encima del pecho, manteniendo los codos hacia dentro y las muñecas rectas. Baja lentamente la barra hacia la frente flexionando los codos, manteniendo los brazos superiores fijos. Haz una pausa breve en la parte baja y luego extiende los brazos de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on a bench with your feet flat on the ground and your head at the end of the bench. Hold the barbell with a reverse grip, palms facing towards your face, and your hands shoulder-width apart. Extend your arms straight up over your chest, keeping your elbows in and your wrists straight. Slowly lower the barbell towards your forehead by bending your elbows, keeping your upper arms stationary. Pause for a moment at the bottom, then extend your arms back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1721-yRLPCLu.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1721-yRLPCLu.gif', 'yRLPCLu', '© Gym visual — https://gymvisual.com/'),
('0081', 'barbell reverse preacher curl', 'Siéntate en un banco predicador con el pecho apoyado en el cojín y los brazos extendidos rectos hacia abajo, sujetando una barra con un agarre pronado. Manteniendo los brazos superiores fijos, exhala y levanta la barra hacia arriba mientras contraes los bíceps. Continúa levantando la barra hasta que', 'upper arms', 'barbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Siéntate en un banco predicador con el pecho apoyado en el cojín y los brazos extendidos rectos hacia abajo, sujetando una barra con un agarre pronado. Manteniendo los brazos superiores fijos, exhala y levanta la barra hacia arriba mientras contraes los bíceps. Continúa levantando la barra hasta que los bíceps estén completamente contraídos y la barra esté a la altura de los hombros. Mantén la posición contraída durante una breve pausa mientras aprietas los bíceps. Inhala y baja lentamente la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a preacher bench with your chest against the pad and your arms extended straight down, holding a barbell with an overhand grip. Keeping your upper arms stationary, exhale and curl the barbell upward while contracting your biceps. Continue to raise the barbell until your biceps are fully contracted and the barbell is at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly lower the barbell back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0081-4LIG9xr.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0081-4LIG9xr.gif', '4LIG9xr', '© Gym visual — https://gymvisual.com/'),
('0082', 'barbell reverse wrist curl', 'Siéntate en un banco con los pies planos sobre el suelo y sujeta una barra con un agarre pronado, con las palmas hacia abajo. Apoya los antebrazos sobre los muslos, dejando que las muñecas cuelguen del borde. Flexiona lentamente las muñecas hacia arriba, llevando la barra hacia el cuerpo. Haz una pa', 'lower arms', 'barbell', 'lower arms', 'lower arms', 'forearms', '{"biceps","brachialis"}', 'Siéntate en un banco con los pies planos sobre el suelo y sujeta una barra con un agarre pronado, con las palmas hacia abajo. Apoya los antebrazos sobre los muslos, dejando que las muñecas cuelguen del borde. Flexiona lentamente las muñecas hacia arriba, llevando la barra hacia el cuerpo. Haz una pausa breve en la parte alta y luego baja lentamente la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a bench with your feet flat on the ground and hold a barbell with an overhand grip, palms facing down. Rest your forearms on your thighs, allowing your wrists to hang off the edge. Slowly curl your wrists upward, bringing the barbell towards your body. Pause for a moment at the top, then slowly lower the barbell back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0082-LsZkfU6.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0082-LsZkfU6.gif', 'LsZkfU6', '© Gym visual — https://gymvisual.com/'),
('0084', 'barbell rollerout', 'Ponte de rodillas en el suelo y sujeta una barra con ambas manos, separadas a la altura de los hombros. Haz rodar la barra hacia delante, extendiendo los brazos y manteniendo el core activado. Continúa rodando hacia delante hasta que el cuerpo esté completamente extendido y los brazos por encima de ', 'waist', 'barbell', 'waist', 'waist', 'abs', '{"lower back"}', 'Ponte de rodillas en el suelo y sujeta una barra con ambas manos, separadas a la altura de los hombros. Haz rodar la barra hacia delante, extendiendo los brazos y manteniendo el core activado. Continúa rodando hacia delante hasta que el cuerpo esté completamente extendido y los brazos por encima de la cabeza. Haz una pausa breve y luego haz rodar lentamente la barra de vuelta hacia las rodillas, manteniendo el control. Repite el número de repeticiones deseado.', 'Kneel on the floor and hold a barbell with both hands, shoulder-width apart. Roll the barbell forward, extending your arms and keeping your core engaged. Continue rolling forward until your body is fully extended and your arms are overhead. Pause for a moment, then slowly roll the barbell back towards your knees, maintaining control. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0084-7M66AVi.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0084-7M66AVi.gif', '7M66AVi', '© Gym visual — https://gymvisual.com/'),
('0083', 'barbell rollerout from bench', 'Empieza de rodillas en el suelo con una barra colocada sobre un banco frente a ti. Agarra la barra con un agarre pronado un poco más ancho que la separación de los hombros. Manteniendo el core activado y la espalda recta, haz rodar lentamente la barra hacia delante, extendiendo los brazos frente a t', 'waist', 'barbell', 'waist', 'waist', 'abs', '{"shoulders","triceps"}', 'Empieza de rodillas en el suelo con una barra colocada sobre un banco frente a ti. Agarra la barra con un agarre pronado un poco más ancho que la separación de los hombros. Manteniendo el core activado y la espalda recta, haz rodar lentamente la barra hacia delante, extendiendo los brazos frente a ti. Continúa haciendo rodar la barra hacia delante hasta que el cuerpo esté completamente extendido y los brazos por encima de la cabeza. Haz una pausa breve en la posición de extensión total, luego haz rodar lentamente la barra de vuelta hacia el cuerpo, volviendo a la posición inicial. Repite el número de repeticiones deseado.', 'Start by kneeling on the floor with a barbell placed on a bench in front of you. Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart. Keeping your core engaged and your back straight, slowly roll the barbell forward, extending your arms in front of you. Continue rolling the barbell forward until your body is fully extended and your arms are overhead. Pause for a moment at the fully extended position, then slowly roll the barbell back towards your body, returning to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0083-Gxg9lDc.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0083-Gxg9lDc.gif', 'Gxg9lDc', '© Gym visual — https://gymvisual.com/'),
('0085', 'barbell romanian deadlift', 'Ponte de pie con los pies separados a la altura de los hombros y los dedos de los pies apuntando hacia delante. Sujeta la barra con un agarre pronado, manos un poco más separadas que el ancho de los hombros. Flexiona las caderas, manteniendo la espalda recta y las rodillas ligeramente flexionadas. B', 'upper legs', 'barbell', 'upper legs', 'upper legs', 'glutes', '{"hamstrings","lower back"}', 'Ponte de pie con los pies separados a la altura de los hombros y los dedos de los pies apuntando hacia delante. Sujeta la barra con un agarre pronado, manos un poco más separadas que el ancho de los hombros. Flexiona las caderas, manteniendo la espalda recta y las rodillas ligeramente flexionadas. Baja la barra hacia el suelo, manteniéndola cerca del cuerpo. Siente el estiramiento en los isquiotibiales mientras bajas la barra. Cuando sientas el estiramiento en los isquiotibiales, empuja las caderas hacia delante y ponte de pie. Aprieta los glúteos en la parte alta del movimiento. Baja la barra de vuelta a la posición inicial y repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and your toes pointing forward. Hold the barbell with an overhand grip, hands slightly wider than shoulder-width apart. Bend at the hips, keeping your back straight and your knees slightly bent. Lower the barbell towards the ground, keeping it close to your body. Feel the stretch in your hamstrings as you lower the barbell. Once you feel a stretch in your hamstrings, push your hips forward and stand up straight. Squeeze your glutes at the top of the movement. Lower the barbell back down to the starting position and repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0085-wQ2c4XD.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0085-wQ2c4XD.gif', 'wQ2c4XD', '© Gym visual — https://gymvisual.com/'),
('0086', 'barbell seated behind head military press', 'Siéntate en un banco con la espalda recta y los pies planos sobre el suelo. Sujeta la barra con un agarre pronado, un poco más ancho que la separación de los hombros. Levanta la barra del soporte y bájala a la altura de los hombros, detrás de la cabeza. Empuja la barra hacia arriba hasta que los bra', 'shoulders', 'barbell', 'shoulders', 'shoulders', 'delts', '{"triceps","upper back"}', 'Siéntate en un banco con la espalda recta y los pies planos sobre el suelo. Sujeta la barra con un agarre pronado, un poco más ancho que la separación de los hombros. Levanta la barra del soporte y bájala a la altura de los hombros, detrás de la cabeza. Empuja la barra hacia arriba hasta que los brazos queden completamente extendidos. Baja la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a bench with your back straight and feet flat on the ground. Hold the barbell with an overhand grip, slightly wider than shoulder-width apart. Lift the barbell off the rack and bring it down to shoulder level, behind your head. Press the barbell upward until your arms are fully extended. Lower the barbell back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0086-ngPpyRS.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0086-ngPpyRS.gif', 'ngPpyRS', '© Gym visual — https://gymvisual.com/'),
('0087', 'barbell seated bradford rocky press', 'Siéntate en un banco con la espalda recta y los pies planos sobre el suelo. Sujeta la barra con un agarre pronado, un poco más ancho que la separación de los hombros. Levanta la barra hasta la altura de los hombros, manteniendo los codos ligeramente flexionados y apuntando hacia delante. Empuja la b', 'shoulders', 'barbell', 'shoulders', 'shoulders', 'delts', '{"triceps","upper back"}', 'Siéntate en un banco con la espalda recta y los pies planos sobre el suelo. Sujeta la barra con un agarre pronado, un poco más ancho que la separación de los hombros. Levanta la barra hasta la altura de los hombros, manteniendo los codos ligeramente flexionados y apuntando hacia delante. Empuja la barra por encima de la cabeza, extendiendo completamente los brazos. Baja la barra de vuelta a la altura de los hombros y repite el número de repeticiones deseado.', 'Sit on a bench with your back straight and feet flat on the ground. Hold the barbell with an overhand grip, slightly wider than shoulder-width apart. Lift the barbell to shoulder height, keeping your elbows slightly bent and pointing forward. Press the barbell overhead, fully extending your arms. Lower the barbell back to shoulder height and repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0087-0dCyly0.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0087-0dCyly0.gif', '0dCyly0', '© Gym visual — https://gymvisual.com/'),
('0088', 'barbell seated calf raise', 'Siéntate en un banco con los pies planos sobre el suelo y una barra apoyada sobre los muslos. Coloca la parte delantera de los pies sobre una plataforma elevada, como un bloque o un escalón. Coloca la barra sobre los muslos y sujétala con firmeza con las manos. Manteniendo la espalda recta y el core', 'lower legs', 'barbell', 'lower legs', 'lower legs', 'calves', '{"hamstrings","quadriceps"}', 'Siéntate en un banco con los pies planos sobre el suelo y una barra apoyada sobre los muslos. Coloca la parte delantera de los pies sobre una plataforma elevada, como un bloque o un escalón. Coloca la barra sobre los muslos y sujétala con firmeza con las manos. Manteniendo la espalda recta y el core activado, levanta los talones del suelo extendiendo los tobillos. Haz una pausa breve en la parte alta y luego baja lentamente los talones de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a bench with your feet flat on the floor and a barbell resting on your thighs. Place the balls of your feet on a raised platform, such as a block or step. Position the barbell across your thighs and hold it securely with your hands. Keeping your back straight and your core engaged, lift your heels off the ground by extending your ankles. Pause for a moment at the top, then slowly lower your heels back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0088-ktsFQAZ.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0088-ktsFQAZ.gif', 'ktsFQAZ', '© Gym visual — https://gymvisual.com/'),
('1371', 'barbell seated calf raise', 'Siéntate en un banco con los pies planos sobre el suelo y una barra apoyada sobre los muslos. Coloca la parte delantera de los pies sobre una plataforma elevada, como un bloque o un escalón. Baja los talones tanto como sea posible, sintiendo un estiramiento en las pantorrillas. Levanta los talones l', 'lower legs', 'barbell', 'lower legs', 'lower legs', 'calves', '{"hamstrings"}', 'Siéntate en un banco con los pies planos sobre el suelo y una barra apoyada sobre los muslos. Coloca la parte delantera de los pies sobre una plataforma elevada, como un bloque o un escalón. Baja los talones tanto como sea posible, sintiendo un estiramiento en las pantorrillas. Levanta los talones lo más alto posible, contrayendo las pantorrillas. Repite el número de repeticiones deseado.', 'Sit on a bench with your feet flat on the floor and a barbell resting on your thighs. Place the balls of your feet on a raised platform, such as a block or step. Lower your heels as far as possible, feeling a stretch in your calves. Raise your heels as high as possible, contracting your calves. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1371-ipvgBnC.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1371-ipvgBnC.gif', 'ipvgBnC', '© Gym visual — https://gymvisual.com/'),
('1718', 'barbell seated close grip behind neck triceps extension', 'Siéntate en un banco con la espalda recta y los pies planos sobre el suelo. Sujeta la barra con un agarre cerrado detrás del cuello, con las palmas mirando hacia delante. Mantén los codos cerca de la cabeza y baja lentamente la barra hacia la parte de atrás de la cabeza. Haz una pausa breve y luego ', 'upper arms', 'barbell', 'upper arms', 'upper arms', 'triceps', '{"shoulders"}', 'Siéntate en un banco con la espalda recta y los pies planos sobre el suelo. Sujeta la barra con un agarre cerrado detrás del cuello, con las palmas mirando hacia delante. Mantén los codos cerca de la cabeza y baja lentamente la barra hacia la parte de atrás de la cabeza. Haz una pausa breve y luego extiende los brazos de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a bench with your back straight and feet flat on the ground. Hold the barbell with a close grip behind your neck, palms facing forward. Keep your elbows close to your head and slowly lower the barbell towards the back of your head. Pause for a moment, then extend your arms back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1718-4CBIBOM.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1718-4CBIBOM.gif', '4CBIBOM', '© Gym visual — https://gymvisual.com/'),
('0089', 'barbell seated close-grip concentration curl', 'Siéntate en un banco con los pies planos sobre el suelo y sujeta una barra con un agarre supino, manos separadas a la altura de los hombros. Apoya los brazos superiores contra el interior de los muslos, justo por encima de las rodillas, y deja que la barra cuelgue frente a ti. Manteniendo los brazos', 'upper arms', 'barbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Siéntate en un banco con los pies planos sobre el suelo y sujeta una barra con un agarre supino, manos separadas a la altura de los hombros. Apoya los brazos superiores contra el interior de los muslos, justo por encima de las rodillas, y deja que la barra cuelgue frente a ti. Manteniendo los brazos superiores fijos, exhala y levanta la barra hacia los hombros, contrayendo los bíceps. Mantén la posición contraída durante una breve pausa, luego inhala y baja lentamente la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a bench with your feet flat on the floor and hold a barbell with an underhand grip, hands shoulder-width apart. Rest your upper arms against your inner thighs, just above your knees, and let the barbell hang down in front of you. Keeping your upper arms stationary, exhale and curl the barbell up towards your shoulders, contracting your biceps. Hold the contracted position for a brief pause, then inhale and slowly lower the barbell back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0089-1V1gj1u.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0089-1V1gj1u.gif', '1V1gj1u', '© Gym visual — https://gymvisual.com/'),
('0090', 'barbell seated good morning', 'Siéntate en un banco con los pies planos sobre el suelo y una barra apoyada sobre la parte superior de la espalda. Mantén la espalda recta y el pecho elevado. Inclínate lentamente hacia delante desde las caderas, bajando el torso hacia el suelo. Haz una pausa por un momento en la parte inferior, lue', 'upper legs', 'barbell', 'upper legs', 'upper legs', 'glutes', '{"hamstrings","lower back"}', 'Siéntate en un banco con los pies planos sobre el suelo y una barra apoyada sobre la parte superior de la espalda. Mantén la espalda recta y el pecho elevado. Inclínate lentamente hacia delante desde las caderas, bajando el torso hacia el suelo. Haz una pausa por un momento en la parte inferior, luego empuja con los talones para regresar a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a bench with your feet flat on the ground and a barbell resting on your upper back. Keep your back straight and your chest up. Slowly hinge forward at the hips, lowering your torso towards the ground. Pause for a moment at the bottom, then push through your heels to return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0090-d960PgE.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0090-d960PgE.gif', 'd960PgE', '© Gym visual — https://gymvisual.com/'),
('0091', 'barbell seated overhead press', 'Siéntate en un banco con la espalda recta y los pies planos sobre el suelo. Sujeta la barra con un agarre pronado, un poco más ancho que la separación de los hombros. Levanta la barra del soporte y llévala a la altura de los hombros, con los codos flexionados y las palmas hacia delante. Empuja la ba', 'shoulders', 'barbell', 'shoulders', 'shoulders', 'delts', '{"triceps","upper back"}', 'Siéntate en un banco con la espalda recta y los pies planos sobre el suelo. Sujeta la barra con un agarre pronado, un poco más ancho que la separación de los hombros. Levanta la barra del soporte y llévala a la altura de los hombros, con los codos flexionados y las palmas hacia delante. Empuja la barra por encima de la cabeza extendiendo completamente los brazos. Haz una pausa breve en la parte alta y luego baja lentamente la barra de vuelta a la altura de los hombros. Repite el número de repeticiones deseado.', 'Sit on a bench with your back straight and feet flat on the ground. Hold the barbell with an overhand grip, slightly wider than shoulder-width apart. Lift the barbell off the rack and bring it to shoulder level, with your elbows bent and palms facing forward. Press the barbell overhead by extending your arms fully. Pause for a moment at the top, then slowly lower the barbell back to shoulder level. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0091-kTbSH9h.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0091-kTbSH9h.gif', 'kTbSH9h', '© Gym visual — https://gymvisual.com/'),
('0092', 'barbell seated overhead triceps extension', 'Siéntate en un banco con la espalda recta y los pies planos sobre el suelo. Sujeta una barra con un agarre pronado, manos separadas a la altura de los hombros, y levántala por encima de la cabeza. Baja la barra detrás de la cabeza flexionando los codos, manteniendo los brazos superiores cerca de la ', 'upper arms', 'barbell', 'upper arms', 'upper arms', 'triceps', '{"shoulders"}', 'Siéntate en un banco con la espalda recta y los pies planos sobre el suelo. Sujeta una barra con un agarre pronado, manos separadas a la altura de los hombros, y levántala por encima de la cabeza. Baja la barra detrás de la cabeza flexionando los codos, manteniendo los brazos superiores cerca de la cabeza. Haz una pausa breve y luego extiende los brazos para levantar la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a bench with your back straight and feet flat on the ground. Hold a barbell with an overhand grip, hands shoulder-width apart, and raise it overhead. Lower the barbell behind your head by bending your elbows, keeping your upper arms close to your head. Pause for a moment, then extend your arms to raise the barbell back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0092-5uFK1xr.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0092-5uFK1xr.gif', '5uFK1xr', '© Gym visual — https://gymvisual.com/'),
('0094', 'barbell seated twist', 'Siéntate en un banco plano con los pies planos sobre el suelo y las rodillas flexionadas. Sujeta una barra con ambas manos frente al pecho, manteniendo los codos ligeramente flexionados. Activa el core y gira lentamente el torso hacia un lado, manteniendo la espalda recta. Haz una pausa breve al fin', 'waist', 'barbell', 'waist', 'waist', 'abs', '{"obliques","lower back"}', 'Siéntate en un banco plano con los pies planos sobre el suelo y las rodillas flexionadas. Sujeta una barra con ambas manos frente al pecho, manteniendo los codos ligeramente flexionados. Activa el core y gira lentamente el torso hacia un lado, manteniendo la espalda recta. Haz una pausa breve al final del giro y luego rota lentamente de vuelta a la posición inicial. Repite el giro hacia el otro lado. Continúa alternando lados durante el número de repeticiones deseado.', 'Sit on a flat bench with your feet flat on the ground and your knees bent. Hold a barbell with both hands in front of your chest, keeping your elbows slightly bent. Engage your core and slowly twist your torso to one side, keeping your back straight. Pause for a moment at the end of the twist, then slowly rotate back to the starting position. Repeat the twist to the other side. Continue alternating sides for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0094-dFSNDOA.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0094-dFSNDOA.gif', 'dFSNDOA', '© Gym visual — https://gymvisual.com/'),
('0095', 'barbell shrug', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una barra frente a ti con un agarre pronado. Mantén los brazos rectos y la espalda recta durante todo el ejercicio. Levanta los hombros hacia las orejas lo más alto posible, apretando los trapecios en la parte alta. Mantén la po', 'back', 'barbell', 'back', 'back', 'traps', '{"shoulders"}', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una barra frente a ti con un agarre pronado. Mantén los brazos rectos y la espalda recta durante todo el ejercicio. Levanta los hombros hacia las orejas lo más alto posible, apretando los trapecios en la parte alta. Mantén la posición por un momento y luego baja lentamente los hombros de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and hold a barbell in front of you with an overhand grip. Keep your arms straight and your back straight throughout the exercise. Lift your shoulders up towards your ears as high as possible, squeezing your traps at the top. Hold for a moment, then slowly lower your shoulders back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0095-dG7tG5y.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0095-dG7tG5y.gif', 'dG7tG5y', '© Gym visual — https://gymvisual.com/'),
('0096', 'barbell side bent v. 2', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una barra con ambas manos, con las palmas hacia abajo. Mantén la espalda recta y el core activado durante todo el ejercicio. Inclina lentamente el torso hacia el lado derecho, bajando la barra hacia tu rodilla derecha. Haz una p', 'waist', 'barbell', 'waist', 'waist', 'abs', '{"obliques","lower back"}', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una barra con ambas manos, con las palmas hacia abajo. Mantén la espalda recta y el core activado durante todo el ejercicio. Inclina lentamente el torso hacia el lado derecho, bajando la barra hacia tu rodilla derecha. Haz una pausa breve y luego vuelve a la posición inicial. Repite el movimiento hacia el lado izquierdo. Continúa alternando lados durante el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and hold a barbell with both hands, palms facing down. Keep your back straight and core engaged throughout the exercise. Slowly bend your torso to the right side, lowering the barbell towards your right knee. Pause for a moment, then return to the starting position. Repeat the movement on the left side. Continue alternating sides for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0096-i4JkUaL.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0096-i4JkUaL.gif', 'i4JkUaL', '© Gym visual — https://gymvisual.com/'),
('0098', 'barbell side split squat', 'Ponte de pie con los pies más separados que el ancho de los hombros, con las puntas de los pies ligeramente hacia afuera. Sujeta una barra sobre la parte superior de la espalda, apoyándola en los trapecios. Activa el core y mantén el pecho elevado mientras bajas el cuerpo hacia una posición de senta', 'upper legs', 'barbell', 'upper legs', 'upper legs', 'quads', '{"glutes","hamstrings","calves"}', 'Ponte de pie con los pies más separados que el ancho de los hombros, con las puntas de los pies ligeramente hacia afuera. Sujeta una barra sobre la parte superior de la espalda, apoyándola en los trapecios. Activa el core y mantén el pecho elevado mientras bajas el cuerpo hacia una posición de sentadilla, flexionando las rodillas y las caderas. Al bajar, empuja las rodillas hacia los lados y mantén el peso sobre los talones. Baja hasta que los muslos queden paralelos al suelo, luego empuja con los talones para volver a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet wider than shoulder-width apart, toes pointing slightly outward. Hold a barbell across your upper back, resting it on your traps. Engage your core and keep your chest up as you lower your body down into a squat position, bending at the knees and hips. As you lower, push your knees out to the sides and keep your weight on your heels. Lower until your thighs are parallel to the ground, then push through your heels to return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0098-W31mMjd.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0098-W31mMjd.gif', 'W31mMjd', '© Gym visual — https://gymvisual.com/'),
('0097', 'barbell side split squat v. 2', 'Ponte de pie con los pies más separados que el ancho de los hombros, con las puntas de los pies ligeramente hacia afuera. Sujeta una barra sobre la parte superior de la espalda, apoyándola en los hombros. Da un paso grande hacia el lado con el pie derecho, manteniendo el pie izquierdo fijo en el sue', 'upper legs', 'barbell', 'upper legs', 'upper legs', 'quads', '{"glutes","hamstrings","calves"}', 'Ponte de pie con los pies más separados que el ancho de los hombros, con las puntas de los pies ligeramente hacia afuera. Sujeta una barra sobre la parte superior de la espalda, apoyándola en los hombros. Da un paso grande hacia el lado con el pie derecho, manteniendo el pie izquierdo fijo en el suelo. Flexiona la rodilla derecha y baja el cuerpo hacia una posición de sentadilla, manteniendo el pecho elevado y la espalda recta. Empuja con el talón derecho para regresar a la posición inicial. Repite hacia el otro lado, dando el paso con el pie izquierdo. Continúa alternando lados durante el número de repeticiones deseado.', 'Stand with your feet wider than shoulder-width apart, toes pointing slightly outwards. Hold a barbell across your upper back, resting it on your shoulders. Take a big step to the side with your right foot, keeping your left foot planted. Bend your right knee and lower your body down into a squat position, keeping your chest up and your back straight. Push through your right heel to return to the starting position. Repeat on the other side, stepping out with your left foot. Continue alternating sides for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0097-HUEqZ1y.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0097-HUEqZ1y.gif', 'HUEqZ1y', '© Gym visual — https://gymvisual.com/'),
('1756', 'barbell single leg deadlift', 'Ponte de pie con los pies separados a la altura de las caderas, sujetando una barra frente a los muslos con agarre prono. Traslada el peso hacia el pie izquierdo y levanta el pie derecho ligeramente del suelo. Inclínate hacia adelante desde las caderas, manteniendo la espalda recta y la pierna derec', 'upper legs', 'barbell', 'upper legs', 'upper legs', 'glutes', '{"hamstrings","lower back"}', 'Ponte de pie con los pies separados a la altura de las caderas, sujetando una barra frente a los muslos con agarre prono. Traslada el peso hacia el pie izquierdo y levanta el pie derecho ligeramente del suelo. Inclínate hacia adelante desde las caderas, manteniendo la espalda recta y la pierna derecha extendida detrás de ti para el equilibrio. Baja la barra hacia el suelo, manteniéndola cerca del cuerpo y la pierna izquierda ligeramente flexionada. Haz una pausa breve en la posición más baja, luego activa los glúteos y los isquiotibiales para levantar el torso de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia de lado.', 'Stand with your feet hip-width apart, holding a barbell in front of your thighs with an overhand grip. Shift your weight onto your left foot and lift your right foot slightly off the ground. Hinge forward at the hips, keeping your back straight and your right leg extended behind you for balance. Lower the barbell towards the ground, keeping it close to your body and your left leg slightly bent. Pause for a moment at the bottom, then engage your glutes and hamstrings to lift your torso back up to the starting position. Repeat for the desired number of repetitions, then switch sides.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1756-gEyURal.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1756-gEyURal.gif', 'gEyURal', '© Gym visual — https://gymvisual.com/'),
('0099', 'barbell single leg split squat', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una barra sobre la parte superior de la espalda. Da un paso grande hacia adelante con una pierna, manteniendo el torso erguido. Baja el cuerpo flexionando la rodilla delantera y la cadera, mientras mantienes la pierna trasera ', 'upper legs', 'barbell', 'upper legs', 'upper legs', 'quads', '{"glutes","hamstrings","calves"}', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una barra sobre la parte superior de la espalda. Da un paso grande hacia adelante con una pierna, manteniendo el torso erguido. Baja el cuerpo flexionando la rodilla delantera y la cadera, mientras mantienes la pierna trasera recta. Continúa bajando hasta que el muslo delantero quede paralelo al suelo. Haz una pausa breve, luego empuja con el talón delantero para volver a la posición inicial. Repite el número de repeticiones deseado, luego cambia de pierna.', 'Stand with your feet shoulder-width apart, holding a barbell across your upper back. Take a large step forward with one leg, keeping your torso upright. Lower your body by bending your front knee and hip, while keeping your back leg straight. Continue lowering until your front thigh is parallel to the ground. Pause for a moment, then push through your front heel to return to the starting position. Repeat for the desired number of repetitions, then switch legs.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0099-gGNQmVt.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0099-gGNQmVt.gif', 'gGNQmVt', '© Gym visual — https://gymvisual.com/'),
('2799', 'barbell sitted alternate leg raise', 'Siéntate en un banco con la espalda recta y sujeta una barra sobre los muslos. Manteniendo las piernas rectas, levanta una pierna lo más alto posible mientras mantienes la otra pierna en el suelo. Baja la pierna elevada y repite con la otra pierna. Continúa alternando las piernas durante el número d', 'waist', 'barbell', 'waist', 'waist', 'abs', '{"hip flexors"}', 'Siéntate en un banco con la espalda recta y sujeta una barra sobre los muslos. Manteniendo las piernas rectas, levanta una pierna lo más alto posible mientras mantienes la otra pierna en el suelo. Baja la pierna elevada y repite con la otra pierna. Continúa alternando las piernas durante el número de repeticiones deseado.', 'Sit on a bench with your back straight and hold a barbell across your thighs. Keeping your legs straight, lift one leg up as high as possible while keeping the other leg on the ground. Lower the raised leg back down and repeat with the other leg. Continue alternating legs for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2799-G7xoEzr.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2799-G7xoEzr.gif', 'G7xoEzr', '© Gym visual — https://gymvisual.com/'),
('2800', 'barbell sitted alternate leg raise (female)', 'Siéntate en un banco con la espalda recta y sujeta una barra sobre los muslos. Coloca las manos a los lados del banco para apoyarte. Manteniendo las piernas rectas, levanta una pierna lo más alto posible manteniéndola paralela al suelo. Baja la pierna y repite con la otra pierna. Continúa alternando', 'waist', 'barbell', 'waist', 'waist', 'abs', '{"hip flexors","quadriceps"}', 'Siéntate en un banco con la espalda recta y sujeta una barra sobre los muslos. Coloca las manos a los lados del banco para apoyarte. Manteniendo las piernas rectas, levanta una pierna lo más alto posible manteniéndola paralela al suelo. Baja la pierna y repite con la otra pierna. Continúa alternando las piernas durante el número de repeticiones deseado.', 'Sit on a bench with your back straight and hold a barbell across your thighs. Place your hands on the sides of the bench for support. Keeping your legs straight, lift one leg up as high as possible while keeping it parallel to the ground. Lower the leg back down and repeat with the other leg. Continue alternating legs for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2800-BCs0G2F.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2800-BCs0G2F.gif', 'BCs0G2F', '© Gym visual — https://gymvisual.com/'),
('0100', 'barbell skier', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una barra frente a los muslos con un agarre pronado. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta y el pecho elevado. Levanta simultáneamente la barra hacia los hom', 'shoulders', 'barbell', 'shoulders', 'shoulders', 'delts', '{"triceps","core"}', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una barra frente a los muslos con un agarre pronado. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta y el pecho elevado. Levanta simultáneamente la barra hacia los hombros mientras saltas ligeramente del suelo. Al llegar a la parte más alta del movimiento, invierte rápidamente el movimiento y baja la barra de nuevo a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and hold a barbell in front of your thighs with an overhand grip. Bend your knees slightly and hinge forward at the hips, keeping your back straight and chest up. Simultaneously lift the barbell up towards your shoulders while jumping slightly off the ground. As you reach the top of the movement, quickly reverse the motion and lower the barbell back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0100-4Leypho.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0100-4Leypho.gif', '4Leypho', '© Gym visual — https://gymvisual.com/'),
('0101', 'barbell speed squat', 'Ponte de pie con los pies separados a la altura de los hombros, con los dedos de los pies ligeramente hacia afuera. Sujeta la barra sobre la parte superior de la espalda, apoyándola en los trapecios o los deltoides posteriores. Activa el core y mantén el pecho elevado mientras llevas las caderas hac', 'upper legs', 'barbell', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves"}', 'Ponte de pie con los pies separados a la altura de los hombros, con los dedos de los pies ligeramente hacia afuera. Sujeta la barra sobre la parte superior de la espalda, apoyándola en los trapecios o los deltoides posteriores. Activa el core y mantén el pecho elevado mientras llevas las caderas hacia atrás y hacia abajo, como si te sentaras en una silla. Baja hasta que los muslos queden paralelos al suelo, o tan abajo como puedas hacerlo cómodamente. Empuja con los talones para volver a ponerte de pie, contrayendo los glúteos en la parte más alta. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, toes slightly turned out. Hold the barbell across your upper back, resting it on your traps or rear delts. Engage your core and keep your chest up as you lower your hips back and down, as if sitting into a chair. Lower until your thighs are parallel to the ground, or as low as you can comfortably go. Drive through your heels to stand back up, squeezing your glutes at the top. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0101-euI1BwR.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0101-euI1BwR.gif', 'euI1BwR', '© Gym visual — https://gymvisual.com/'),
('2810', 'barbell split squat v. 2', 'Empieza de pie con los pies separados a la altura de los hombros, sujetando una barra sobre la parte superior de la espalda. Da un paso grande hacia adelante con el pie derecho, manteniendo el torso erguido. Baja el cuerpo flexionando las rodillas y las caderas hasta que el muslo derecho quede paral', 'upper legs', 'barbell', 'upper legs', 'upper legs', 'quads', '{"glutes","hamstrings","calves"}', 'Empieza de pie con los pies separados a la altura de los hombros, sujetando una barra sobre la parte superior de la espalda. Da un paso grande hacia adelante con el pie derecho, manteniendo el torso erguido. Baja el cuerpo flexionando las rodillas y las caderas hasta que el muslo derecho quede paralelo al suelo. Haz una pausa breve, luego empuja con el talón derecho para volver a la posición inicial. Repite con la pierna izquierda adelante el número de repeticiones deseado.', 'Start by standing with your feet shoulder-width apart, holding a barbell across your upper back. Take a large step forward with your right foot, keeping your torso upright. Lower your body by bending your knees and hips until your right thigh is parallel to the ground. Pause for a moment, then push through your right heel to return to the starting position. Repeat with your left leg forward for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2810-HBYyX94.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2810-HBYyX94.gif', 'HBYyX94', '© Gym visual — https://gymvisual.com/'),
('0102', 'barbell squat (on knees)', 'Comienza arrodillado en el suelo con las rodillas separadas a la altura de las caderas y las puntas de los pies apuntando hacia adelante. Coloca una barra sobre los hombros, sujetándola con agarre prono y las manos un poco más separadas que el ancho de los hombros. Activa el core y mantén el pecho e', 'upper legs', 'barbell', 'upper legs', 'upper legs', 'quads', '{"glutes","hamstrings","calves"}', 'Comienza arrodillado en el suelo con las rodillas separadas a la altura de las caderas y las puntas de los pies apuntando hacia adelante. Coloca una barra sobre los hombros, sujetándola con agarre prono y las manos un poco más separadas que el ancho de los hombros. Activa el core y mantén el pecho elevado mientras bajas lentamente el cuerpo flexionando las rodillas, manteniendo la espalda recta. Continúa bajando hasta que los muslos queden paralelos al suelo, o tan abajo como puedas hacerlo cómodamente. Haz una pausa por un momento en la parte inferior, luego empuja con los talones para regresar a la posición inicial. Repite el número de repeticiones deseado.', 'Start by kneeling on the ground with your knees hip-width apart and your toes pointing forward. Place a barbell across your shoulders, gripping it with an overhand grip and your hands slightly wider than shoulder-width apart. Engage your core and keep your chest lifted as you slowly lower your body down by bending your knees, keeping your back straight. Continue lowering until your thighs are parallel to the ground, or as low as you can comfortably go. Pause for a moment at the bottom, then push through your heels to return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0102-oR7O9LW.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0102-oR7O9LW.gif', 'oR7O9LW', '© Gym visual — https://gymvisual.com/'),
('2798', 'barbell squat jump step rear lunge', 'Empieza de pie con los pies separados a la altura de los hombros, sujetando una barra sobre la parte superior de la espalda. Baja el cuerpo hacia una posición de sentadilla flexionando las rodillas y empujando las caderas hacia atrás. Impúlsate explosivamente hacia arriba, saltando del suelo lo más ', 'upper legs', 'barbell', 'upper legs', 'upper legs', 'quads', '{"glutes","hamstrings","calves"}', 'Empieza de pie con los pies separados a la altura de los hombros, sujetando una barra sobre la parte superior de la espalda. Baja el cuerpo hacia una posición de sentadilla flexionando las rodillas y empujando las caderas hacia atrás. Impúlsate explosivamente hacia arriba, saltando del suelo lo más alto que puedas. Aterriza suavemente sobre los pies y de inmediato retrocede con una pierna hacia una zancada inversa. Baja el cuerpo hasta que el muslo delantero quede paralelo al suelo, manteniendo la espalda recta. Empuja con el talón delantero para volver a la posición inicial. Repite la secuencia de salto y zancada con la otra pierna. Continúa alternando las piernas durante el número de repeticiones deseado.', 'Start by standing with your feet shoulder-width apart, holding a barbell across your upper back. Lower your body into a squat position by bending your knees and pushing your hips back. Explode upwards, jumping off the ground as high as you can. Land softly on your feet and immediately step back with one leg into a reverse lunge. Lower your body down until your front thigh is parallel to the ground, keeping your back straight. Push through your front heel to return to the starting position. Repeat the jump and lunge sequence on the other leg. Continue alternating legs for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2798-RYcV1kH.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2798-RYcV1kH.gif', 'RYcV1kH', '© Gym visual — https://gymvisual.com/'),
('0103', 'barbell standing ab rollerout', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta la barra con ambas manos frente a los muslos. Activa el core y enrolla lentamente la barra hacia el suelo, manteniendo la espalda recta y los brazos extendidos. Continúa enrollando la barra hacia adelante hasta que el cuerpo est', 'waist', 'barbell', 'waist', 'waist', 'abs', '{"shoulders","lower back"}', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta la barra con ambas manos frente a los muslos. Activa el core y enrolla lentamente la barra hacia el suelo, manteniendo la espalda recta y los brazos extendidos. Continúa enrollando la barra hacia adelante hasta que el cuerpo esté completamente extendido y las manos queden justo sobre la cabeza. Haz una pausa breve, luego enrolla lentamente la barra de vuelta hacia los muslos, manteniendo el control y el core activado. Repite el número de repeticiones deseado.', 'Stand upright with your feet shoulder-width apart and hold the barbell with both hands in front of your thighs. Engage your core and slowly roll the barbell down towards the ground, keeping your back straight and your arms extended. Continue rolling the barbell forward until your body is fully extended and your hands are directly above your head. Pause for a moment, then slowly roll the barbell back towards your thighs, maintaining control and keeping your core engaged. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0103-xnInPfE.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0103-xnInPfE.gif', 'xnInPfE', '© Gym visual — https://gymvisual.com/'),
('0104', 'barbell standing back wrist curl', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una barra con agarre prono. Apoya la barra sobre el dorso de las manos con las palmas hacia abajo y los dedos apuntando hacia el cuerpo. Manteniendo los brazos superiores quietos, exhala y flexiona las muñecas hacia arriba lo má', 'lower arms', 'barbell', 'lower arms', 'lower arms', 'forearms', '{"biceps","shoulders"}', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una barra con agarre prono. Apoya la barra sobre el dorso de las manos con las palmas hacia abajo y los dedos apuntando hacia el cuerpo. Manteniendo los brazos superiores quietos, exhala y flexiona las muñecas hacia arriba lo más posible. Mantén la posición contraída durante una breve pausa, luego inhala y baja lentamente la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand up straight with your feet shoulder-width apart and hold a barbell with an overhand grip. Rest the barbell on the back of your hands with your palms facing down and your fingers pointing towards your body. Keeping your upper arms stationary, exhale and curl your wrists upwards as far as possible. Hold the contracted position for a brief pause, then inhale and slowly lower the barbell back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0104-2qTvJAZ.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0104-2qTvJAZ.gif', '2qTvJAZ', '© Gym visual — https://gymvisual.com/'),
('0105', 'barbell standing bradford press', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta la barra frente a los hombros con agarre prono. Empuja la barra por encima de la cabeza, extendiendo completamente los brazos. Baja la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'shoulders', 'barbell', 'shoulders', 'shoulders', 'delts', '{"triceps","upper back"}', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta la barra frente a los hombros con agarre prono. Empuja la barra por encima de la cabeza, extendiendo completamente los brazos. Baja la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and hold the barbell in front of your shoulders with an overhand grip. Press the barbell overhead, fully extending your arms. Lower the barbell back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0105-dCPESfR.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0105-dCPESfR.gif', 'dCPESfR', '© Gym visual — https://gymvisual.com/'),
('1372', 'barbell standing calf raise', 'Ponte de pie con los pies separados a la altura de los hombros y coloca una barra sobre la parte superior de la espalda. Levanta los talones del suelo lo más alto posible, apoyándote solo en las puntas de los pies. Haz una pausa breve en la parte alta y luego baja lentamente los talones de vuelta a ', 'lower legs', 'barbell', 'lower legs', 'lower legs', 'calves', '{"hamstrings","glutes"}', 'Ponte de pie con los pies separados a la altura de los hombros y coloca una barra sobre la parte superior de la espalda. Levanta los talones del suelo lo más alto posible, apoyándote solo en las puntas de los pies. Haz una pausa breve en la parte alta y luego baja lentamente los talones de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and place a barbell across your upper back. Raise your heels off the ground as high as possible, using only your toes. Pause for a moment at the top, then slowly lower your heels back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1372-8ozhUIZ.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1372-8ozhUIZ.gif', '8ozhUIZ', '© Gym visual — https://gymvisual.com/'),
('0106', 'barbell standing close grip curl', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una barra con agarre supino, manos juntas. Mantén los codos cerca del torso y los brazos superiores quietos durante todo el movimiento. Exhala al flexionar el peso contrayendo los bíceps. Continúa levantando la barra hasta que l', 'upper arms', 'barbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una barra con agarre supino, manos juntas. Mantén los codos cerca del torso y los brazos superiores quietos durante todo el movimiento. Exhala al flexionar el peso contrayendo los bíceps. Continúa levantando la barra hasta que los bíceps estén completamente contraídos y la barra esté a la altura de los hombros. Mantén la posición contraída durante una breve pausa mientras aprietas los bíceps. Inhala mientras comienzas a llevar lentamente la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand up straight with your feet shoulder-width apart and hold a barbell with an underhand grip, hands close together. Keep your elbows close to your torso and your upper arms stationary throughout the movement. Exhale as you curl the weights while contracting your biceps. Continue to raise the bar until your biceps are fully contracted and the bar is at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale as you slowly begin to bring the barbell back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0106-4dUn2iv.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0106-4dUn2iv.gif', '4dUn2iv', '© Gym visual — https://gymvisual.com/'),
('1456', 'barbell standing close grip military press', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta la barra con agarre prono, manos un poco más juntas que el ancho de los hombros. Levanta la barra hasta la altura de los hombros, manteniendo los codos cerca del cuerpo. Empuja la barra por encima de la cabeza, extendiendo compl', 'shoulders', 'barbell', 'shoulders', 'shoulders', 'delts', '{"triceps","upper back"}', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta la barra con agarre prono, manos un poco más juntas que el ancho de los hombros. Levanta la barra hasta la altura de los hombros, manteniendo los codos cerca del cuerpo. Empuja la barra por encima de la cabeza, extendiendo completamente los brazos. Baja la barra de nuevo a la altura de los hombros. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and hold the barbell with an overhand grip, hands slightly closer than shoulder-width apart. Lift the barbell to shoulder height, keeping your elbows close to your body. Press the barbell overhead, extending your arms fully. Lower the barbell back to shoulder height. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1456-wdRZISl.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1456-wdRZISl.gif', 'wdRZISl', '© Gym visual — https://gymvisual.com/'),
('2414', 'barbell standing concentration curl', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una barra con una mano, con la palma hacia arriba. Apoya la otra mano sobre el muslo para mayor estabilidad. Manteniendo el brazo superior quieto, exhala y flexiona el peso hacia el hombro. Haz una pausa breve en la parte alta, ', 'upper arms', 'barbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una barra con una mano, con la palma hacia arriba. Apoya la otra mano sobre el muslo para mayor estabilidad. Manteniendo el brazo superior quieto, exhala y flexiona el peso hacia el hombro. Haz una pausa breve en la parte alta, apretando los bíceps. Inhala y baja lentamente el peso de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia de brazo.', 'Stand with your feet shoulder-width apart and hold a barbell in one hand, palm facing up. Rest your opposite hand on your thigh for support. Keeping your upper arm stationary, exhale and curl the weight up towards your shoulder. Pause for a moment at the top, squeezing your biceps. Inhale and slowly lower the weight back down to the starting position. Repeat for the desired number of repetitions, then switch arms.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2414-vsMcDi9.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2414-vsMcDi9.gif', 'vsMcDi9', '© Gym visual — https://gymvisual.com/'),
('0107', 'barbell standing front raise over head', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una barra frente a los muslos con agarre prono. Mantén la espalda recta y activa el core. Levanta lentamente la barra frente a ti, manteniendo los brazos rectos y las palmas hacia abajo. Continúa levantando hasta que la barra ', 'shoulders', 'barbell', 'shoulders', 'shoulders', 'delts', '{"triceps","upper back"}', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una barra frente a los muslos con agarre prono. Mantén la espalda recta y activa el core. Levanta lentamente la barra frente a ti, manteniendo los brazos rectos y las palmas hacia abajo. Continúa levantando hasta que la barra quede ligeramente por encima del nivel de los hombros. Haz una pausa breve en la parte alta y luego baja lentamente la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, holding a barbell in front of your thighs with an overhand grip. Keep your back straight and engage your core. Slowly raise the barbell in front of you, keeping your arms straight and your palms facing down. Continue lifting until the barbell is slightly above shoulder level. Pause for a moment at the top, then slowly lower the barbell back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0107-S8mo30S.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0107-S8mo30S.gif', 'S8mo30S', '© Gym visual — https://gymvisual.com/'),
('0108', 'barbell standing leg calf raise', 'Ponte de pie con los pies separados a la altura de los hombros y coloca una barra sobre la parte superior de la espalda. Levanta los talones del suelo lo más alto posible, usando las pantorrillas. Haz una pausa breve en la parte alta y luego baja lentamente los talones de vuelta a la posición inicia', 'lower legs', 'barbell', 'lower legs', 'lower legs', 'calves', '{"hamstrings","glutes"}', 'Ponte de pie con los pies separados a la altura de los hombros y coloca una barra sobre la parte superior de la espalda. Levanta los talones del suelo lo más alto posible, usando las pantorrillas. Haz una pausa breve en la parte alta y luego baja lentamente los talones de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and place a barbell across your upper back. Raise your heels off the ground as high as possible, using your calves. Pause for a moment at the top, then slowly lower your heels back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0108-rGwhJ5o.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0108-rGwhJ5o.gif', 'rGwhJ5o', '© Gym visual — https://gymvisual.com/'),
('0109', 'barbell standing overhead triceps extension', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una barra con agarre prono. Levanta la barra por encima de la cabeza, extendiendo completamente los brazos. Manteniendo los brazos superiores cerca de la cabeza, baja lentamente la barra detrás de la cabeza flexionando los codos', 'upper arms', 'barbell', 'upper arms', 'upper arms', 'triceps', '{"shoulders"}', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una barra con agarre prono. Levanta la barra por encima de la cabeza, extendiendo completamente los brazos. Manteniendo los brazos superiores cerca de la cabeza, baja lentamente la barra detrás de la cabeza flexionando los codos. Haz una pausa breve, luego levanta la barra de vuelta a la posición inicial extendiendo los brazos. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and hold a barbell with an overhand grip. Raise the barbell overhead, fully extending your arms. Keeping your upper arms close to your head, slowly lower the barbell behind your head by bending your elbows. Pause for a moment, then raise the barbell back to the starting position by extending your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0109-dZl9Q27.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0109-dZl9Q27.gif', 'dZl9Q27', '© Gym visual — https://gymvisual.com/'),
('0110', 'barbell standing reverse grip curl', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una barra con un agarre supino, con las palmas hacia arriba. Mantén los codos cerca del torso y los brazos superiores quietos. Exhala y flexiona el peso contrayendo los bíceps, llevando la barra lo más cerca posible de los hombr', 'upper arms', 'barbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una barra con un agarre supino, con las palmas hacia arriba. Mantén los codos cerca del torso y los brazos superiores quietos. Exhala y flexiona el peso contrayendo los bíceps, llevando la barra lo más cerca posible de los hombros. Mantén la posición contraída durante una breve pausa mientras aprietas los bíceps. Inhala y baja lentamente la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand up straight with your feet shoulder-width apart and hold a barbell with an underhand grip, palms facing up. Keep your elbows close to your torso and your upper arms stationary. Exhale and curl the weights while contracting your biceps, bringing the barbell as close to your shoulders as possible. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly lower the barbell back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0110-LWuA3aZ.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0110-LWuA3aZ.gif', 'LWuA3aZ', '© Gym visual — https://gymvisual.com/'),
('0111', 'barbell standing rocking leg calf raise', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una barra sobre la parte superior de la espalda. Levanta los talones del suelo lo más alto posible, manteniendo el equilibrio sobre las puntas de los pies. Baja lentamente los talones de vuelta a la posición inicial. Repite el n', 'lower legs', 'barbell', 'lower legs', 'lower legs', 'calves', '{"hamstrings","quadriceps"}', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una barra sobre la parte superior de la espalda. Levanta los talones del suelo lo más alto posible, manteniendo el equilibrio sobre las puntas de los pies. Baja lentamente los talones de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and hold a barbell across your upper back. Raise your heels off the ground as high as possible, balancing on the balls of your feet. Slowly lower your heels back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0111-6HiHHe0.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0111-6HiHHe0.gif', '6HiHHe0', '© Gym visual — https://gymvisual.com/'),
('0112', 'barbell standing twist', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una barra frente al pecho con ambas manos, palmas hacia abajo. Activa el core y mantén la espalda recta durante todo el ejercicio. Gira lentamente el torso hacia la derecha, pivotando sobre los pies y las caderas, mientras manti', 'waist', 'barbell', 'waist', 'waist', 'abs', '{"obliques","lower back"}', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una barra frente al pecho con ambas manos, palmas hacia abajo. Activa el core y mantén la espalda recta durante todo el ejercicio. Gira lentamente el torso hacia la derecha, pivotando sobre los pies y las caderas, mientras mantienes estable la parte inferior del cuerpo. Haz una pausa por un momento al final de la rotación, luego regresa lentamente a la posición inicial. Repite el giro hacia el lado izquierdo. Continúa alternando los giros el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and hold a barbell in front of your chest with both hands, palms facing down. Engage your core and keep your back straight throughout the exercise. Slowly twist your torso to the right, pivoting on your feet and hips, while keeping your lower body stable. Pause for a moment at the end of the twist, then slowly return to the starting position. Repeat the twist to the left side. Continue alternating twists for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0112-yQe5HpE.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0112-yQe5HpE.gif', 'yQe5HpE', '© Gym visual — https://gymvisual.com/'),
('1629', 'barbell standing wide grip biceps curl', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una barra con agarre supino, manos más separadas que el ancho de los hombros. Mantén la espalda recta y los codos cerca del torso. Exhala y flexiona la barra hacia los hombros, manteniendo los brazos superiores quietos. Haz una ', 'upper arms', 'barbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una barra con agarre supino, manos más separadas que el ancho de los hombros. Mantén la espalda recta y los codos cerca del torso. Exhala y flexiona la barra hacia los hombros, manteniendo los brazos superiores quietos. Haz una pausa breve en la parte alta, apretando los bíceps. Inhala y baja lentamente la barra de vuelta a la posición inicial, extendiendo completamente los brazos. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and hold a barbell with an underhand grip, hands wider than shoulder-width apart. Keep your back straight and your elbows close to your torso. Exhale and curl the barbell up towards your shoulders, keeping your upper arms stationary. Pause for a moment at the top, squeezing your biceps. Inhale and slowly lower the barbell back to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1629-faHKVkK.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1629-faHKVkK.gif', 'faHKVkK', '© Gym visual — https://gymvisual.com/'),
('1457', 'barbell standing wide military press', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta la barra con agarre prono, un poco más separado que el ancho de los hombros. Levanta la barra hasta la altura de los hombros, manteniendo los codos ligeramente por delante de la barra. Empuja la barra por encima de la cabeza, ex', 'shoulders', 'barbell', 'shoulders', 'shoulders', 'delts', '{"triceps","upper back"}', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta la barra con agarre prono, un poco más separado que el ancho de los hombros. Levanta la barra hasta la altura de los hombros, manteniendo los codos ligeramente por delante de la barra. Empuja la barra por encima de la cabeza, extendiendo completamente los brazos. Baja la barra de vuelta a la altura de los hombros y repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and hold the barbell with an overhand grip, slightly wider than shoulder-width. Lift the barbell to shoulder height, keeping your elbows slightly in front of the bar. Press the barbell overhead, extending your arms fully. Lower the barbell back to shoulder height and repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1457-Kyd9Rz5.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1457-Kyd9Rz5.gif', 'Kyd9Rz5', '© Gym visual — https://gymvisual.com/'),
('0113', 'barbell standing wide-grip curl', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una barra con agarre prono, manos más separadas que el ancho de los hombros. Deja que la barra cuelgue a la longitud del brazo frente a los muslos, con las palmas mirando hacia afuera del cuerpo. Manteniendo los brazos superiore', 'upper arms', 'barbell', 'upper arms', 'upper arms', 'biceps', '{"forearms","shoulders"}', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una barra con agarre prono, manos más separadas que el ancho de los hombros. Deja que la barra cuelgue a la longitud del brazo frente a los muslos, con las palmas mirando hacia afuera del cuerpo. Manteniendo los brazos superiores quietos, exhala y flexiona la barra hacia arriba contrayendo los bíceps. Continúa levantando la barra hasta que los bíceps estén completamente contraídos y la barra esté a la altura de los hombros. Mantén la posición contraída durante una breve pausa mientras aprietas los bíceps. Inhala y comienza a bajar lentamente la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand up straight with your feet shoulder-width apart and hold a barbell with an overhand grip, hands wider than shoulder-width apart. Let the barbell hang at arm''s length in front of your thighs, with your palms facing away from your body. Keeping your upper arms stationary, exhale and curl the barbell upward by contracting your biceps. Continue to raise the barbell until your biceps are fully contracted and the barbell is at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly begin to lower the barbell back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0113-NdIb5Z1.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0113-NdIb5Z1.gif', 'NdIb5Z1', '© Gym visual — https://gymvisual.com/'),
('0114', 'barbell step-up', 'Ponte de pie frente a un banco o escalón con una barra apoyada en la parte superior de la espalda. Coloca un pie sobre el banco o escalón, asegurándote de que todo el pie esté en contacto con la superficie. Empuja con el talón y sube al banco o escalón, extendiendo completamente la cadera y la rodil', 'upper legs', 'barbell', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves"}', 'Ponte de pie frente a un banco o escalón con una barra apoyada en la parte superior de la espalda. Coloca un pie sobre el banco o escalón, asegurándote de que todo el pie esté en contacto con la superficie. Empuja con el talón y sube al banco o escalón, extendiendo completamente la cadera y la rodilla. Haz una pausa breve en la parte más alta, luego baja de vuelta a la posición inicial. Repite con la pierna contraria. Continúa alternando las piernas durante el número de repeticiones deseado.', 'Stand in front of a bench or step with a barbell resting on your upper back. Place one foot on the bench or step, ensuring your entire foot is in contact with the surface. Push through your heel and step up onto the bench or step, fully extending your hip and knee. Pause briefly at the top, then lower yourself back down to the starting position. Repeat with the opposite leg. Continue alternating legs for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0114-Kxquu2E.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0114-Kxquu2E.gif', 'Kxquu2E', '© Gym visual — https://gymvisual.com/'),
('0115', 'barbell stiff leg good morning', 'Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Sujeta la barra sobre la parte superior de la espalda, apoyándola en los trapecios. Manteniendo la espalda recta, inclínate hacia adelante desde las caderas, empujando los glúteos hacia atrás. Baja', 'upper legs', 'barbell', 'upper legs', 'upper legs', 'glutes', '{"hamstrings","lower back"}', 'Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Sujeta la barra sobre la parte superior de la espalda, apoyándola en los trapecios. Manteniendo la espalda recta, inclínate hacia adelante desde las caderas, empujando los glúteos hacia atrás. Baja el torso hasta que quede paralelo al suelo, sintiendo un estiramiento en los isquiotibiales. Activa los glúteos y los isquiotibiales para volver a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and your knees slightly bent. Hold the barbell across your upper back, resting it on your traps. Keeping your back straight, hinge forward at the hips, pushing your glutes back. Lower your torso until it is parallel to the ground, feeling a stretch in your hamstrings. Engage your glutes and hamstrings to return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0115-JrOHAZc.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0115-JrOHAZc.gif', 'JrOHAZc', '© Gym visual — https://gymvisual.com/'),
('0116', 'barbell straight leg deadlift', 'Ponte de pie con los pies separados a la altura de los hombros y los dedos de los pies apuntando hacia delante. Sujeta la barra con un agarre pronado, manos un poco más separadas que el ancho de los hombros. Flexiona las caderas y baja la barra hacia el suelo, manteniendo la espalda recta y las rodi', 'upper legs', 'barbell', 'upper legs', 'upper legs', 'hamstrings', '{"glutes","lower back"}', 'Ponte de pie con los pies separados a la altura de los hombros y los dedos de los pies apuntando hacia delante. Sujeta la barra con un agarre pronado, manos un poco más separadas que el ancho de los hombros. Flexiona las caderas y baja la barra hacia el suelo, manteniendo la espalda recta y las rodillas ligeramente flexionadas. Baja la barra hasta que sientas un estiramiento en los isquiotibiales. Activa los isquiotibiales y los glúteos para levantar la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and your toes pointing forward. Hold the barbell with an overhand grip, hands slightly wider than shoulder-width apart. Bend at your hips and lower the barbell towards the ground, keeping your back straight and your knees slightly bent. Lower the barbell until you feel a stretch in your hamstrings. Engage your hamstrings and glutes to lift the barbell back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0116-hrVQWvE.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0116-hrVQWvE.gif', 'hrVQWvE', '© Gym visual — https://gymvisual.com/'),
('0117', 'barbell sumo deadlift', 'Ponte de pie con los pies más separados que el ancho de los hombros, con las puntas de los pies hacia afuera. Coloca una barra en el suelo frente a ti, centrada entre los pies. Flexiona las rodillas y baja las caderas, manteniendo la espalda recta y el pecho elevado, para sujetar la barra con agarre', 'upper legs', 'barbell', 'upper legs', 'upper legs', 'glutes', '{"hamstrings","quadriceps","lower back"}', 'Ponte de pie con los pies más separados que el ancho de los hombros, con las puntas de los pies hacia afuera. Coloca una barra en el suelo frente a ti, centrada entre los pies. Flexiona las rodillas y baja las caderas, manteniendo la espalda recta y el pecho elevado, para sujetar la barra con agarre prono. Activa el core y empuja con los talones para levantar la barra del suelo, extendiendo las caderas y las rodillas simultáneamente. Al levantar, mantén el pecho elevado y la espalda recta, y empuja las caderas hacia adelante para activar completamente los glúteos. Haz una pausa breve en la parte más alta, luego baja lentamente la barra de vuelta a la posición inicial, manteniendo el control durante todo el movimiento. Repite el número de repeticiones deseado.', 'Stand with your feet wider than shoulder-width apart, toes pointing outwards. Place a barbell on the ground in front of you, centered between your feet. Bend your knees and lower your hips, keeping your back straight and chest up, to grip the barbell with an overhand grip. Engage your core and drive through your heels to lift the barbell off the ground, extending your hips and knees simultaneously. As you lift, keep your chest up and back straight, and push your hips forward to fully engage your glutes. Pause for a moment at the top, then slowly lower the barbell back down to the starting position, maintaining control throughout the movement. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0117-KgI0tqW.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0117-KgI0tqW.gif', 'KgI0tqW', '© Gym visual — https://gymvisual.com/'),
('3305', 'barbell thruster', 'Comienza de pie con los pies separados a la altura de los hombros, sujetando una barra a la altura de los hombros con agarre prono. Baja a una posición de sentadilla flexionando las rodillas y empujando las caderas hacia atrás. Al llegar a la parte más baja de la sentadilla, empuja explosivamente co', 'shoulders', 'barbell', 'shoulders', 'shoulders', 'delts', '{"quadriceps","glutes","hamstrings","core"}', 'Comienza de pie con los pies separados a la altura de los hombros, sujetando una barra a la altura de los hombros con agarre prono. Baja a una posición de sentadilla flexionando las rodillas y empujando las caderas hacia atrás. Al llegar a la parte más baja de la sentadilla, empuja explosivamente con los talones para ponerte de pie, presionando simultáneamente la barra por encima de la cabeza. Baja la barra de nuevo a la altura de los hombros mientras vuelves a bajar a la posición de sentadilla. Repite el número de repeticiones deseado.', 'Start by standing with your feet shoulder-width apart, holding a barbell at shoulder height with an overhand grip. Lower into a squat position by bending your knees and pushing your hips back. As you reach the bottom of the squat, explosively drive through your heels to stand up, simultaneously pressing the barbell overhead. Lower the barbell back to shoulder height as you lower back into the squat position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3305-f7Y9eDZ.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3305-f7Y9eDZ.gif', 'f7Y9eDZ', '© Gym visual — https://gymvisual.com/'),
('0120', 'barbell upright row', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una barra con agarre prono, manos un poco más separadas que el ancho de los hombros. Deja que la barra cuelgue frente a los muslos, con los brazos completamente extendidos. Manteniendo la espalda recta y el core activado, exhala', 'shoulders', 'barbell', 'shoulders', 'shoulders', 'delts', '{"traps","biceps"}', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una barra con agarre prono, manos un poco más separadas que el ancho de los hombros. Deja que la barra cuelgue frente a los muslos, con los brazos completamente extendidos. Manteniendo la espalda recta y el core activado, exhala y levanta la barra en línea recta hacia la barbilla, guiando el movimiento con los codos. Haz una pausa breve en la parte más alta, luego inhala y baja lentamente la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and hold a barbell with an overhand grip, hands slightly wider than shoulder-width apart. Let the barbell hang in front of your thighs, arms fully extended. Keeping your back straight and core engaged, exhale and lift the barbell straight up towards your chin, leading with your elbows. Pause for a moment at the top, then inhale and slowly lower the barbell back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0120-UDlhcO8.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0120-UDlhcO8.gif', 'UDlhcO8', '© Gym visual — https://gymvisual.com/'),
('0119', 'barbell upright row v. 2', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una barra con agarre prono, manos un poco más separadas que el ancho de los hombros. Deja que la barra cuelgue frente a los muslos, con los brazos completamente extendidos. Manteniendo la espalda recta, exhala y levanta la barra', 'shoulders', 'barbell', 'shoulders', 'shoulders', 'delts', '{"traps","biceps"}', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una barra con agarre prono, manos un poco más separadas que el ancho de los hombros. Deja que la barra cuelgue frente a los muslos, con los brazos completamente extendidos. Manteniendo la espalda recta, exhala y levanta la barra en línea recta hacia la barbilla, guiando el movimiento con los codos. Haz una pausa breve en la parte más alta, luego inhala y baja lentamente la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and hold a barbell with an overhand grip, hands slightly wider than shoulder-width apart. Let the barbell hang in front of your thighs, arms fully extended. Keeping your back straight, exhale and lift the barbell straight up towards your chin, leading with your elbows. Pause for a moment at the top, then inhale and slowly lower the barbell back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0119-83HoW9X.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0119-83HoW9X.gif', '83HoW9X', '© Gym visual — https://gymvisual.com/'),
('0121', 'barbell upright row v. 3', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una barra con agarre prono, manos un poco más separadas que el ancho de los hombros. Deja que la barra cuelgue frente a los muslos, con los brazos completamente extendidos. Manteniendo el core activado y la espalda recta, exhala', 'shoulders', 'barbell', 'shoulders', 'shoulders', 'delts', '{"traps","biceps"}', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una barra con agarre prono, manos un poco más separadas que el ancho de los hombros. Deja que la barra cuelgue frente a los muslos, con los brazos completamente extendidos. Manteniendo el core activado y la espalda recta, exhala mientras levantas la barra en línea recta hacia la barbilla, guiando el movimiento con los codos. Haz una pausa breve en la parte más alta, luego inhala mientras bajas lentamente la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and hold a barbell with an overhand grip, hands slightly wider than shoulder-width apart. Let the barbell hang in front of your thighs, arms fully extended. Keeping your core engaged and back straight, exhale as you lift the barbell straight up towards your chin, leading with your elbows. Pause for a moment at the top, then inhale as you slowly lower the barbell back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0121-fI18Rbc.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0121-fI18Rbc.gif', 'fI18Rbc', '© Gym visual — https://gymvisual.com/'),
('0122', 'barbell wide bench press', 'Túmbate sobre un banco con los pies apoyados en el suelo y la espalda presionada contra el banco. Agarra la barra con un agarre amplio, un poco más ancho que la separación de los hombros. Levanta la barra del soporte y sostenla directamente sobre el pecho con los brazos completamente extendidos. Baj', 'chest', 'barbell', 'chest', 'chest', 'pectorals', '{"shoulders","triceps"}', 'Túmbate sobre un banco con los pies apoyados en el suelo y la espalda presionada contra el banco. Agarra la barra con un agarre amplio, un poco más ancho que la separación de los hombros. Levanta la barra del soporte y sostenla directamente sobre el pecho con los brazos completamente extendidos. Baja la barra lentamente hacia el pecho, manteniendo los codos ligeramente abiertos hacia afuera. Haz una pausa breve cuando la barra toque el pecho y luego empújala de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on a bench with your feet flat on the ground and your back pressed against the bench. Grasp the barbell with a wide grip, slightly wider than shoulder-width apart. Lift the barbell off the rack and hold it directly above your chest with your arms fully extended. Lower the barbell slowly towards your chest, keeping your elbows slightly flared out. Pause for a moment when the barbell touches your chest, then push it back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0122-JsKq9so.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0122-JsKq9so.gif', 'JsKq9so', '© Gym visual — https://gymvisual.com/'),
('1258', 'barbell wide reverse grip bench press', 'Túmbate sobre un banco con los pies apoyados en el suelo y la espalda presionada contra el banco. Sujeta la barra con un agarre supino amplio, un poco más separado que el ancho de los hombros. Levanta la barra del soporte y sostenla directamente sobre el pecho con los brazos completamente extendidos', 'chest', 'barbell', 'chest', 'chest', 'pectorals', '{"triceps","shoulders"}', 'Túmbate sobre un banco con los pies apoyados en el suelo y la espalda presionada contra el banco. Sujeta la barra con un agarre supino amplio, un poco más separado que el ancho de los hombros. Levanta la barra del soporte y sostenla directamente sobre el pecho con los brazos completamente extendidos. Baja la barra lentamente hacia el pecho, manteniendo los codos pegados al cuerpo y las muñecas rectas. Haz una pausa breve cuando la barra toque el pecho y luego empújala de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on a bench with your feet flat on the ground and your back pressed against the bench. Grasp the barbell with a wide reverse grip, slightly wider than shoulder-width apart. Lift the barbell off the rack and hold it directly above your chest with your arms fully extended. Lower the barbell slowly towards your chest, keeping your elbows tucked in and your wrists straight. Pause for a moment when the barbell touches your chest, then push it back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1258-945zpRg.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1258-945zpRg.gif', '945zpRg', '© Gym visual — https://gymvisual.com/'),
('0124', 'barbell wide squat', 'Ponte de pie con los pies más separados que el ancho de los hombros, con las puntas de los pies ligeramente hacia afuera. Sujeta la barra sobre la parte superior de la espalda, apoyándola en los trapecios o los deltoides posteriores. Activa el core y mantén el pecho elevado mientras bajas el cuerpo ', 'upper legs', 'barbell', 'upper legs', 'upper legs', 'quads', '{"glutes","hamstrings","calves"}', 'Ponte de pie con los pies más separados que el ancho de los hombros, con las puntas de los pies ligeramente hacia afuera. Sujeta la barra sobre la parte superior de la espalda, apoyándola en los trapecios o los deltoides posteriores. Activa el core y mantén el pecho elevado mientras bajas el cuerpo hacia una sentadilla, empujando las caderas hacia atrás y flexionando las rodillas. Baja hasta que los muslos queden paralelos al suelo, o tan abajo como puedas hacerlo cómodamente. Haz una pausa por un momento en la parte inferior, luego empuja con los talones para regresar a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet wider than shoulder-width apart, toes pointing slightly outward. Hold the barbell across your upper back, resting it on your traps or rear delts. Engage your core and keep your chest up as you lower your body down into a squat, pushing your hips back and bending your knees. Lower until your thighs are parallel to the ground, or as low as you can comfortably go. Pause for a moment at the bottom, then push through your heels to return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0124-s7HX1BY.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0124-s7HX1BY.gif', 's7HX1BY', '© Gym visual — https://gymvisual.com/'),
('0123', 'barbell wide-grip upright row', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una barra con agarre prono, manos más separadas que el ancho de los hombros. Deja que la barra cuelgue frente a los muslos, con los brazos completamente extendidos. Manteniendo la espalda recta, exhala y levanta la barra en líne', 'shoulders', 'barbell', 'shoulders', 'shoulders', 'delts', '{"traps","biceps"}', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una barra con agarre prono, manos más separadas que el ancho de los hombros. Deja que la barra cuelgue frente a los muslos, con los brazos completamente extendidos. Manteniendo la espalda recta, exhala y levanta la barra en línea recta hacia la barbilla, guiando el movimiento con los codos. Haz una pausa breve en la parte más alta, luego inhala y baja lentamente la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and hold a barbell with an overhand grip, hands wider than shoulder-width apart. Let the barbell hang in front of your thighs, arms fully extended. Keeping your back straight, exhale and lift the barbell straight up towards your chin, leading with your elbows. Pause for a moment at the top, then inhale and slowly lower the barbell back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0123-RgJDRR1.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0123-RgJDRR1.gif', 'RgJDRR1', '© Gym visual — https://gymvisual.com/'),
('0126', 'barbell wrist curl', 'Siéntate en un banco con los pies planos en el suelo y los antebrazos apoyados sobre los muslos, sujetando una barra con agarre supino. Deja que la barra ruede hacia las puntas de los dedos, manteniendo las muñecas rectas. Enrolla lentamente la barra hacia los antebrazos flexionando las muñecas. Haz', 'lower arms', 'barbell', 'lower arms', 'lower arms', 'forearms', '{"biceps","brachialis"}', 'Siéntate en un banco con los pies planos en el suelo y los antebrazos apoyados sobre los muslos, sujetando una barra con agarre supino. Deja que la barra ruede hacia las puntas de los dedos, manteniendo las muñecas rectas. Enrolla lentamente la barra hacia los antebrazos flexionando las muñecas. Haz una pausa breve en la parte alta y luego baja lentamente la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a bench with your feet flat on the ground and your forearms resting on your thighs, holding a barbell with an underhand grip. Allow the barbell to roll down to your fingertips, keeping your wrists straight. Slowly curl the barbell up towards your forearms by flexing your wrists. Pause for a moment at the top, then slowly lower the barbell back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0126-82LxxkW.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0126-82LxxkW.gif', '82LxxkW', '© Gym visual — https://gymvisual.com/'),
('0125', 'barbell wrist curl v. 2', 'Siéntate en un banco con los pies planos sobre el suelo y las rodillas flexionadas. Sujeta una barra con agarre supino, palmas hacia arriba, y las manos separadas a la altura de los hombros. Apoya los antebrazos sobre los muslos, dejando que las muñecas cuelguen del borde. Flexiona lentamente las mu', 'lower arms', 'barbell', 'lower arms', 'lower arms', 'forearms', '{"biceps","brachialis"}', 'Siéntate en un banco con los pies planos sobre el suelo y las rodillas flexionadas. Sujeta una barra con agarre supino, palmas hacia arriba, y las manos separadas a la altura de los hombros. Apoya los antebrazos sobre los muslos, dejando que las muñecas cuelguen del borde. Flexiona lentamente las muñecas hacia arriba, llevando la barra hacia los antebrazos. Haz una pausa breve en la parte alta y luego baja lentamente la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a bench with your feet flat on the ground and your knees bent. Hold a barbell with an underhand grip, palms facing up, and your hands shoulder-width apart. Rest your forearms on your thighs, allowing your wrists to hang off the edge. Slowly curl your wrists upward, bringing the barbell towards your forearms. Pause for a moment at the top, then slowly lower the barbell back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0125-6kSxYnw.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0125-6kSxYnw.gif', '6kSxYnw', '© Gym visual — https://gymvisual.com/'),
('0127', 'barbell zercher squat', 'Ponte de pie con los pies separados a la altura de los hombros y los dedos de los pies ligeramente hacia afuera. Sujeta la barra en el pliegue de los codos, con las manos agarrando la barra para mayor estabilidad. Activa el core y mantén el pecho elevado mientras bajas las caderas hacia atrás y haci', 'upper legs', 'barbell', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves","core"}', 'Ponte de pie con los pies separados a la altura de los hombros y los dedos de los pies ligeramente hacia afuera. Sujeta la barra en el pliegue de los codos, con las manos agarrando la barra para mayor estabilidad. Activa el core y mantén el pecho elevado mientras bajas las caderas hacia atrás y hacia abajo en una posición de sentadilla. Mantén las rodillas alineadas con los dedos de los pies y el peso sobre los talones. Haz una pausa breve en la parte baja de la sentadilla y luego empuja con los talones para volver a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and toes slightly turned out. Hold the barbell in the crooks of your elbows, with your hands gripping the bar for stability. Engage your core and keep your chest lifted as you lower your hips back and down into a squat position. Keep your knees in line with your toes and your weight in your heels. Pause for a moment at the bottom of the squat, then push through your heels to return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0127-LSTChY9.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0127-LSTChY9.gif', 'LSTChY9', '© Gym visual — https://gymvisual.com/'),
('3212', 'basic toe touch (male)', 'Ponte de pie con los pies separados a la altura de los hombros y los brazos a los costados. Inclínate hacia adelante desde la cintura, manteniendo la espalda recta y las rodillas ligeramente flexionadas. Extiende las manos hacia las puntas de los pies, manteniendo las piernas lo más rectas posible. ', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'glutes', '{"hamstrings","calves"}', 'Ponte de pie con los pies separados a la altura de los hombros y los brazos a los costados. Inclínate hacia adelante desde la cintura, manteniendo la espalda recta y las rodillas ligeramente flexionadas. Extiende las manos hacia las puntas de los pies, manteniendo las piernas lo más rectas posible. Haz una pausa por un momento en la parte inferior, luego regresa lentamente a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and your arms by your sides. Bend forward at the waist, keeping your back straight and your knees slightly bent. Reach down towards your toes with your hands, keeping your legs as straight as possible. Pause for a moment at the bottom, then slowly return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3212-BbfB8Gb.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3212-BbfB8Gb.gif', 'BbfB8Gb', '© Gym visual — https://gymvisual.com/'),
('0128', 'battling ropes', 'Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Sujeta un extremo de la cuerda en cada mano, con las palmas mirándose entre sí. Levanta los brazos hasta la altura de los hombros, manteniendo los codos ligeramente flexionados. Comienza a hacer on', 'shoulders', 'rope', 'shoulders', 'shoulders', 'delts', '{"forearms","core"}', 'Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Sujeta un extremo de la cuerda en cada mano, con las palmas mirándose entre sí. Levanta los brazos hasta la altura de los hombros, manteniendo los codos ligeramente flexionados. Comienza a hacer ondas alternas con las cuerdas, levantando y bajando rápidamente cada brazo. Continúa durante el tiempo o el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and knees slightly bent. Hold one end of the rope in each hand, with your palms facing each other. Raise your arms to shoulder height, keeping your elbows slightly bent. Begin making alternating waves with the ropes by rapidly raising and lowering each arm. Continue for the desired duration or number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0128-RJa4tCo.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0128-RJa4tCo.gif', 'RJa4tCo', '© Gym visual — https://gymvisual.com/'),
('3360', 'bear crawl', 'Comienza apoyado sobre manos y rodillas, con las manos justo debajo de los hombros y las rodillas justo debajo de las caderas. Levanta las rodillas ligeramente del suelo, manteniendo la espalda plana y el core activado. Mueve la mano derecha y el pie izquierdo hacia adelante simultáneamente, seguido', 'cardio', 'body weight', 'cardio', 'cardio', 'cardiovascular system', '{"core","shoulders","triceps"}', 'Comienza apoyado sobre manos y rodillas, con las manos justo debajo de los hombros y las rodillas justo debajo de las caderas. Levanta las rodillas ligeramente del suelo, manteniendo la espalda plana y el core activado. Mueve la mano derecha y el pie izquierdo hacia adelante simultáneamente, seguido de la mano izquierda y el pie derecho. Continúa avanzando a gatas, alternando los movimientos de manos y pies. Mantén un ritmo constante y el core firme durante todo el ejercicio. Continúa durante la distancia o el tiempo deseado.', 'Start on all fours with your hands directly under your shoulders and your knees directly under your hips. Lift your knees slightly off the ground, keeping your back flat and your core engaged. Move your right hand and left foot forward simultaneously, followed by your left hand and right foot. Continue crawling forward, alternating your hand and foot movements. Maintain a steady pace and keep your core tight throughout the exercise. Continue for the desired distance or time.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3360-0Yz8WdV.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3360-0Yz8WdV.gif', '0Yz8WdV', '© Gym visual — https://gymvisual.com/'),
('1259', 'behind head chest stretch', 'Ponte de pie con la espalda recta y los pies separados a la altura de los hombros. Entrelaza los dedos detrás de la cabeza con los codos apuntando hacia afuera. Junta lentamente los omóplatos y empuja el pecho hacia adelante. Mantén el estiramiento durante 15-30 segundos. Suelta el estiramiento y re', 'chest', 'assisted', 'chest', 'chest', 'pectorals', '{"shoulders","triceps"}', 'Ponte de pie con la espalda recta y los pies separados a la altura de los hombros. Entrelaza los dedos detrás de la cabeza con los codos apuntando hacia afuera. Junta lentamente los omóplatos y empuja el pecho hacia adelante. Mantén el estiramiento durante 15-30 segundos. Suelta el estiramiento y repite cuantas veces lo desees.', 'Stand tall with your feet shoulder-width apart. Interlace your fingers behind your head with your elbows pointing outwards. Slowly squeeze your shoulder blades together and push your chest forward. Hold the stretch for 15-30 seconds. Release the stretch and repeat as desired.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1259-QoHIhPl.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1259-QoHIhPl.gif', 'QoHIhPl', '© Gym visual — https://gymvisual.com/'),
('0129', 'bench dip (knees bent)', 'Siéntate en el borde de un banco o silla con las manos sujetando el borde junto a las caderas. Desliza los glúteos fuera del banco y estira las piernas frente a ti, manteniendo los talones en el suelo. Flexiona los codos y baja el cuerpo hacia el suelo, manteniendo la espalda cerca del banco. Haz un', 'upper arms', 'body weight', 'upper arms', 'upper arms', 'triceps', '{"chest","shoulders"}', 'Siéntate en el borde de un banco o silla con las manos sujetando el borde junto a las caderas. Desliza los glúteos fuera del banco y estira las piernas frente a ti, manteniendo los talones en el suelo. Flexiona los codos y baja el cuerpo hacia el suelo, manteniendo la espalda cerca del banco. Haz una pausa por un momento en la parte inferior, luego empuja tu cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on the edge of a bench or chair with your hands gripping the edge next to your hips. Slide your butt off the bench and straighten your legs in front of you, keeping your heels on the ground. Bend your elbows and lower your body towards the ground, keeping your back close to the bench. Pause for a moment at the bottom, then push yourself back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0129-RrLske5.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0129-RrLske5.gif', 'RrLske5', '© Gym visual — https://gymvisual.com/'),
('1399', 'bench dip on floor', 'Siéntate en el borde de un banco o silla con las manos sujetando el borde, los dedos apuntando hacia adelante. Desliza los glúteos fuera del banco, sosteniendo tu peso con las manos. Baja el cuerpo flexionando los codos hasta que los brazos queden paralelos al suelo. Empújate de vuelta hacia arriba ', 'upper arms', 'body weight', 'upper arms', 'upper arms', 'triceps', '{"chest","shoulders"}', 'Siéntate en el borde de un banco o silla con las manos sujetando el borde, los dedos apuntando hacia adelante. Desliza los glúteos fuera del banco, sosteniendo tu peso con las manos. Baja el cuerpo flexionando los codos hasta que los brazos queden paralelos al suelo. Empújate de vuelta hacia arriba a la posición inicial extendiendo los brazos. Repite el número de repeticiones deseado.', 'Sit on the edge of a bench or chair with your hands gripping the edge, fingers pointing forward. Slide your butt off the bench, supporting your weight with your hands. Lower your body by bending your elbows until your upper arms are parallel to the floor. Push yourself back up to the starting position by straightening your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1399-9RT8oQW.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1399-9RT8oQW.gif', '9RT8oQW', '© Gym visual — https://gymvisual.com/'),
('0130', 'bench hip extension', 'Siéntate en un banco con la espalda contra el banco y los pies planos en el suelo. Coloca las manos sobre el banco para apoyarte. Activa los glúteos y los isquiotibiales, luego levanta las caderas del banco hasta que el cuerpo forme una línea recta desde las rodillas hasta los hombros. Haz una pausa', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'glutes', '{"hamstrings"}', 'Siéntate en un banco con la espalda contra el banco y los pies planos en el suelo. Coloca las manos sobre el banco para apoyarte. Activa los glúteos y los isquiotibiales, luego levanta las caderas del banco hasta que el cuerpo forme una línea recta desde las rodillas hasta los hombros. Haz una pausa por un momento en la parte superior, luego baja lentamente las caderas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a bench with your back against the bench and your feet flat on the ground. Place your hands on the bench for support. Engage your glutes and hamstrings, then lift your hips off the bench until your body forms a straight line from your knees to your shoulders. Pause for a moment at the top, then slowly lower your hips back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0130-u27Kcdz.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0130-u27Kcdz.gif', 'u27Kcdz', '© Gym visual — https://gymvisual.com/'),
('3019', 'bench pull-ups', 'Colócate debajo de una barra o una superficie horizontal resistente que esté a la altura del pecho. Sujeta la barra o la superficie con agarre prono, un poco más separado que el ancho de los hombros. Cuélgate con los brazos completamente extendidos y el cuerpo recto. Lleva el pecho hacia la barra o ', 'back', 'body weight', 'back', 'back', 'lats', '{"biceps","forearms"}', 'Colócate debajo de una barra o una superficie horizontal resistente que esté a la altura del pecho. Sujeta la barra o la superficie con agarre prono, un poco más separado que el ancho de los hombros. Cuélgate con los brazos completamente extendidos y el cuerpo recto. Lleva el pecho hacia la barra o la superficie juntando los omóplatos y flexionando los codos. Continúa tirando hasta que la barbilla quede por encima de la barra o la superficie. Baja de nuevo a la posición inicial con control. Repite el número de repeticiones deseado.', 'Position yourself under a bar or a sturdy horizontal surface that is at chest height. Grab the bar or surface with an overhand grip, slightly wider than shoulder-width apart. Hang with your arms fully extended and your body straight. Pull your chest towards the bar or surface by squeezing your shoulder blades together and bending your elbows. Continue pulling until your chin is above the bar or surface. Lower yourself back down to the starting position with control. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3019-mExgrF9.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3019-mExgrF9.gif', 'mExgrF9', '© Gym visual — https://gymvisual.com/'),
('3639', 'bent knee lying twist (male)', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Extiende los brazos hacia los lados, perpendiculares al cuerpo. Manteniendo las rodillas juntas, bájalas lentamente hacia un lado, intentando tocar el suelo con las rodillas. Haz una pausa breve, luego activa el c', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'glutes', '{"obliques","hip flexors"}', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Extiende los brazos hacia los lados, perpendiculares al cuerpo. Manteniendo las rodillas juntas, bájalas lentamente hacia un lado, intentando tocar el suelo con las rodillas. Haz una pausa breve, luego activa el core y levanta lentamente las rodillas de vuelta a la posición inicial. Repite el movimiento hacia el otro lado. Continúa alternando lados durante el número de repeticiones deseado.', 'Lie flat on your back with your knees bent and feet flat on the ground. Extend your arms out to the sides, perpendicular to your body. Keeping your knees together, slowly lower them to one side, aiming to touch the ground with your knees. Pause for a moment, then engage your core and slowly lift your knees back to the starting position. Repeat the movement to the other side. Continue alternating sides for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3639-6sYyrRX.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3639-6sYyrRX.gif', '6sYyrRX', '© Gym visual — https://gymvisual.com/'),
('1770', 'biceps leg concentration curl', 'Siéntate en un banco con las piernas separadas y los pies planos en el suelo. Sujeta una mancuerna con una mano y coloca el codo en la parte interna del muslo, justo por encima de la rodilla. Con la palma hacia arriba, flexiona la mancuerna hacia el hombro manteniendo el brazo superior quieto. Contr', 'upper arms', 'body weight', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Siéntate en un banco con las piernas separadas y los pies planos en el suelo. Sujeta una mancuerna con una mano y coloca el codo en la parte interna del muslo, justo por encima de la rodilla. Con la palma hacia arriba, flexiona la mancuerna hacia el hombro manteniendo el brazo superior quieto. Contrae el bíceps en la parte más alta del movimiento, luego baja lentamente la mancuerna de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia de brazo.', 'Sit on a bench with your legs spread apart and your feet flat on the ground. Hold a dumbbell in one hand and place your elbow on the inside of your thigh, just above the knee. With your palm facing up, curl the dumbbell towards your shoulder while keeping your upper arm stationary. Squeeze your biceps at the top of the movement, then slowly lower the dumbbell back to the starting position. Repeat for the desired number of repetitions, then switch arms.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1770-sJFIDIp.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1770-sJFIDIp.gif', 'sJFIDIp', '© Gym visual — https://gymvisual.com/'),
('0139', 'biceps narrow pull-ups', 'Cuélgate de una barra de dominadas con las palmas mirando hacia ti y las manos separadas a la altura de los hombros. Activa el core y tira de tu cuerpo hacia la barra, enfocándote en usar los bíceps para levantar el cuerpo. Haz una pausa breve en la parte más alta, luego baja lentamente de vuelta a ', 'upper arms', 'body weight', 'upper arms', 'upper arms', 'biceps', '{"forearms","shoulders"}', 'Cuélgate de una barra de dominadas con las palmas mirando hacia ti y las manos separadas a la altura de los hombros. Activa el core y tira de tu cuerpo hacia la barra, enfocándote en usar los bíceps para levantar el cuerpo. Haz una pausa breve en la parte más alta, luego baja lentamente de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Hang from a pull-up bar with your palms facing towards you and your hands shoulder-width apart. Engage your core and pull yourself up towards the bar, focusing on using your biceps to lift your body. Pause for a moment at the top, then slowly lower yourself back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0139-50BETrz.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0139-50BETrz.gif', '50BETrz', '© Gym visual — https://gymvisual.com/'),
('0140', 'biceps pull-up', 'Cuélgate de una barra de dominadas con las palmas mirando hacia afuera y las manos separadas a la altura de los hombros. Activa el core y tira de tu cuerpo hacia arriba flexionando los codos, llevando el pecho hacia la barra. Haz una pausa en la parte más alta del movimiento, luego baja lentamente d', 'upper arms', 'body weight', 'upper arms', 'upper arms', 'biceps', '{"forearms","shoulders"}', 'Cuélgate de una barra de dominadas con las palmas mirando hacia afuera y las manos separadas a la altura de los hombros. Activa el core y tira de tu cuerpo hacia arriba flexionando los codos, llevando el pecho hacia la barra. Haz una pausa en la parte más alta del movimiento, luego baja lentamente de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Hang from a pull-up bar with your palms facing away from you and your hands shoulder-width apart. Engage your core and pull yourself up by bending your elbows, bringing your chest towards the bar. Pause at the top of the movement, then slowly lower yourself back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0140-guT8YnS.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0140-guT8YnS.gif', 'guT8YnS', '© Gym visual — https://gymvisual.com/'),
('0137', 'body-up', 'Comienza colocando las manos sobre una superficie elevada, como un banco o unas barras paralelas, con las palmas hacia abajo y los dedos apuntando hacia adelante. Extiende las piernas frente a ti, manteniendo los talones en el suelo y el cuerpo recto. Baja el cuerpo flexionando los codos, manteniénd', 'upper arms', 'body weight', 'upper arms', 'upper arms', 'triceps', '{"chest","shoulders"}', 'Comienza colocando las manos sobre una superficie elevada, como un banco o unas barras paralelas, con las palmas hacia abajo y los dedos apuntando hacia adelante. Extiende las piernas frente a ti, manteniendo los talones en el suelo y el cuerpo recto. Baja el cuerpo flexionando los codos, manteniéndolos cerca del cuerpo, hasta que los brazos superiores queden paralelos al suelo. Haz una pausa breve, luego empuja con las palmas para extender los brazos y levantar el cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Start by placing your hands on a raised surface, such as a bench or parallel bars, with your palms facing down and fingers pointing forward. Extend your legs out in front of you, keeping your heels on the ground and your body straight. Lower your body by bending your elbows, keeping them close to your sides, until your upper arms are parallel to the ground. Pause for a moment, then push through your palms to straighten your arms and lift your body back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0137-U6G2gk9.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0137-U6G2gk9.gif', 'U6G2gk9', '© Gym visual — https://gymvisual.com/'),
('3543', 'bodyweight drop jump squat', 'Ponte de pie con los pies separados a la altura de los hombros. Baja el cuerpo hacia una posición de sentadilla flexionando las rodillas y empujando las caderas hacia atrás. Salta hacia arriba explosivamente, extendiendo las caderas, las rodillas y los tobillos. Mientras estás en el aire, junta rápi', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves"}', 'Ponte de pie con los pies separados a la altura de los hombros. Baja el cuerpo hacia una posición de sentadilla flexionando las rodillas y empujando las caderas hacia atrás. Salta hacia arriba explosivamente, extendiendo las caderas, las rodillas y los tobillos. Mientras estás en el aire, junta rápidamente los pies. Aterriza suavemente sobre las puntas de los pies y de inmediato vuelve a bajar a una posición de sentadilla. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart. Lower your body into a squat position by bending your knees and pushing your hips back. Jump up explosively, extending your hips, knees, and ankles. While in mid-air, quickly bring your feet together. Land softly on the balls of your feet and immediately drop back into a squat position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3543-wfotm7S.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3543-wfotm7S.gif', 'wfotm7S', '© Gym visual — https://gymvisual.com/'),
('3544', 'bodyweight incline side plank', 'Comienza tumbado de lado con las piernas extendidas y apiladas una sobre la otra. Coloca el antebrazo en el suelo justo debajo del hombro, con el codo flexionado en un ángulo de 90 grados. Activa el core y levanta las caderas del suelo, formando una línea recta desde la cabeza hasta los pies. Mantén', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"obliques","shoulders"}', 'Comienza tumbado de lado con las piernas extendidas y apiladas una sobre la otra. Coloca el antebrazo en el suelo justo debajo del hombro, con el codo flexionado en un ángulo de 90 grados. Activa el core y levanta las caderas del suelo, formando una línea recta desde la cabeza hasta los pies. Mantén esta posición durante el tiempo deseado. Baja las caderas de nuevo al suelo y repite hacia el otro lado.', 'Start by lying on your side with your legs extended and stacked on top of each other. Place your forearm on the ground directly below your shoulder, with your elbow bent at a 90-degree angle. Engage your core and lift your hips off the ground, creating a straight line from your head to your feet. Hold this position for the desired amount of time. Lower your hips back down to the ground and repeat on the other side.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3544-5VXmnV5.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3544-5VXmnV5.gif', '5VXmnV5', '© Gym visual — https://gymvisual.com/'),
('1771', 'bodyweight kneeling triceps extension', 'Ponte de rodillas en el suelo con las rodillas separadas a la altura de las caderas. Coloca las manos en el suelo frente a ti, separadas a la altura de los hombros, con los dedos apuntando hacia adelante. Extiende las piernas rectas detrás de ti, equilibrándote sobre las puntas de los pies y las man', 'upper arms', 'body weight', 'upper arms', 'upper arms', 'triceps', '{"shoulders","chest"}', 'Ponte de rodillas en el suelo con las rodillas separadas a la altura de las caderas. Coloca las manos en el suelo frente a ti, separadas a la altura de los hombros, con los dedos apuntando hacia adelante. Extiende las piernas rectas detrás de ti, equilibrándote sobre las puntas de los pies y las manos, formando una línea recta desde la cabeza hasta los talones. Flexiona los codos y baja la parte superior del cuerpo hacia el suelo, manteniendo los codos cerca del cuerpo. Haz una pausa breve en la posición más baja, luego empuja con las manos para extender los brazos y volver a la posición inicial. Repite el número de repeticiones deseado.', 'Kneel down on the ground with your knees hip-width apart. Place your hands on the ground in front of you, shoulder-width apart, fingers pointing forward. Extend your legs straight behind you, balancing on your toes and hands, forming a straight line from head to heels. Bend your elbows and lower your upper body towards the ground, keeping your elbows close to your sides. Pause for a moment at the bottom, then push through your hands to straighten your arms and return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1771-s0HKO2I.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1771-s0HKO2I.gif', 's0HKO2I', '© Gym visual — https://gymvisual.com/'),
('1769', 'bodyweight side lying biceps curl', 'Túmbate de lado con las piernas extendidas y la cabeza apoyada sobre el brazo. Mantén el brazo superior junto al cuerpo y flexiona el codo para llevar el antebrazo hacia el hombro. Haz una pausa por un momento en la parte superior, luego baja lentamente el antebrazo de vuelta a la posición inicial. ', 'upper arms', 'body weight', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Túmbate de lado con las piernas extendidas y la cabeza apoyada sobre el brazo. Mantén el brazo superior junto al cuerpo y flexiona el codo para llevar el antebrazo hacia el hombro. Haz una pausa por un momento en la parte superior, luego baja lentamente el antebrazo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie on your side with your legs extended and your head supported by your arm. Hold your upper arm against your side and bend your elbow to curl your forearm towards your shoulder. Pause for a moment at the top, then slowly lower your forearm back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1769-gscGLOU.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1769-gscGLOU.gif', 'gscGLOU', '© Gym visual — https://gymvisual.com/'),
('3168', 'bodyweight squatting row', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando un objeto resistente o un entrenador de suspensión con los brazos extendidos. Baja el cuerpo hacia una posición de sentadilla, manteniendo la espalda recta y las rodillas detrás de las puntas de los pies. Desde la posición de ', 'back', 'body weight', 'back', 'back', 'upper back', '{"biceps","shoulders"}', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando un objeto resistente o un entrenador de suspensión con los brazos extendidos. Baja el cuerpo hacia una posición de sentadilla, manteniendo la espalda recta y las rodillas detrás de las puntas de los pies. Desde la posición de sentadilla, tira del cuerpo hacia arriba en dirección al objeto o al entrenador de suspensión, juntando los omóplatos. Haz una pausa por un momento en la parte superior, luego baja lentamente el cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, holding onto a sturdy object or suspension trainer with your arms extended. Lower your body into a squat position, keeping your back straight and your knees behind your toes. From the squat position, pull your body up towards the object or suspension trainer, squeezing your shoulder blades together. Pause for a moment at the top, then slowly lower your body back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3168-3xK09Sk.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3168-3xK09Sk.gif', '3xK09Sk', '© Gym visual — https://gymvisual.com/'),
('3167', 'bodyweight squatting row (with towel)', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una toalla frente a ti con las palmas hacia abajo. Flexiona las rodillas y baja el cuerpo hacia una posición de sentadilla, manteniendo la espalda recta y el pecho elevado. Mientras bajas a la sentadilla, tira simultáneamente ', 'back', 'body weight', 'back', 'back', 'upper back', '{"biceps","shoulders"}', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una toalla frente a ti con las palmas hacia abajo. Flexiona las rodillas y baja el cuerpo hacia una posición de sentadilla, manteniendo la espalda recta y el pecho elevado. Mientras bajas a la sentadilla, tira simultáneamente de la toalla hacia el pecho, juntando los omóplatos. Haz una pausa breve en la parte más baja de la sentadilla, luego vuelve lentamente a la posición inicial mientras extiendes los brazos. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, holding a towel in front of you with your palms facing down. Bend your knees and lower your body into a squat position, keeping your back straight and your chest up. As you lower into the squat, simultaneously pull the towel towards your chest, squeezing your shoulder blades together. Pause for a moment at the bottom of the squat, then slowly return to the starting position while extending your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3167-BReCuOn.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3167-BReCuOn.gif', 'BReCuOn', '© Gym visual — https://gymvisual.com/'),
('1373', 'bodyweight standing calf raise', 'Ponte de pie con los pies separados a la altura de los hombros, con las puntas de los pies apuntando hacia adelante. Coloca las manos sobre una pared o superficie estable para mantener el equilibrio. Levanta lentamente los talones del suelo, llevando el peso del cuerpo hacia las puntas de los pies. ', 'lower legs', 'body weight', 'lower legs', 'lower legs', 'calves', '{"ankles","feet"}', 'Ponte de pie con los pies separados a la altura de los hombros, con las puntas de los pies apuntando hacia adelante. Coloca las manos sobre una pared o superficie estable para mantener el equilibrio. Levanta lentamente los talones del suelo, llevando el peso del cuerpo hacia las puntas de los pies. Haz una pausa breve en la parte alta y luego baja lentamente los talones de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, toes pointing forward. Place your hands on a wall or stable surface for balance. Slowly raise your heels off the ground, lifting your body weight onto the balls of your feet. Pause for a moment at the top, then slowly lower your heels back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1373-bJYHBIN.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1373-bJYHBIN.gif', 'bJYHBIN', '© Gym visual — https://gymvisual.com/'),
('3156', 'bodyweight standing close-grip one arm row', 'Ponte de pie con los pies separados a la altura de los hombros, las rodillas ligeramente flexionadas, y sujeta una mancuerna en una mano con agarre neutro. Inclínate hacia adelante desde las caderas, manteniendo la espalda recta y el core activado. Tira de la mancuerna hacia el pecho, manteniendo el', 'back', 'body weight', 'back', 'back', 'upper back', '{"biceps","forearms"}', 'Ponte de pie con los pies separados a la altura de los hombros, las rodillas ligeramente flexionadas, y sujeta una mancuerna en una mano con agarre neutro. Inclínate hacia adelante desde las caderas, manteniendo la espalda recta y el core activado. Tira de la mancuerna hacia el pecho, manteniendo el codo cerca del cuerpo y juntando los omóplatos. Haz una pausa breve en la parte más alta, luego baja lentamente la mancuerna de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia de lado.', 'Stand with your feet shoulder-width apart, knees slightly bent, and hold a dumbbell in one hand with a neutral grip. Bend forward at the hips, keeping your back straight and your core engaged. Pull the dumbbell up towards your chest, keeping your elbow close to your body and squeezing your shoulder blades together. Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position. Repeat for the desired number of repetitions, then switch sides.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3156-v2DfH14.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3156-v2DfH14.gif', 'v2DfH14', '© Gym visual — https://gymvisual.com/'),
('3158', 'bodyweight standing close-grip row', 'Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Inclínate hacia adelante desde la cintura, manteniendo la espalda recta y el core activado. Extiende los brazos rectos frente a ti, sujetando la barra o las agarraderas con un agarre cerrado. Tira ', 'back', 'body weight', 'back', 'back', 'upper back', '{"biceps","forearms"}', 'Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Inclínate hacia adelante desde la cintura, manteniendo la espalda recta y el core activado. Extiende los brazos rectos frente a ti, sujetando la barra o las agarraderas con un agarre cerrado. Tira de la barra o las agarraderas hacia el cuerpo, juntando los omóplatos. Haz una pausa breve en la parte más alta del movimiento, luego suelta lentamente y vuelve a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and knees slightly bent. Bend forward at the waist, keeping your back straight and your core engaged. Extend your arms straight in front of you, gripping the bar or handles with a close grip. Pull the bar or handles towards your body, squeezing your shoulder blades together. Pause for a moment at the top of the movement, then slowly release and return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3158-tig3PXb.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3158-tig3PXb.gif', 'tig3PXb', '© Gym visual — https://gymvisual.com/'),
('3162', 'bodyweight standing one arm row', 'Ponte de pie con los pies separados a la altura de los hombros, las rodillas ligeramente flexionadas, y sujeta una mancuerna con una mano. Inclínate hacia adelante desde las caderas, manteniendo la espalda recta y el core activado. Deja que la mancuerna cuelgue recta frente a ti, con el brazo comple', 'back', 'body weight', 'back', 'back', 'upper back', '{"biceps","forearms"}', 'Ponte de pie con los pies separados a la altura de los hombros, las rodillas ligeramente flexionadas, y sujeta una mancuerna con una mano. Inclínate hacia adelante desde las caderas, manteniendo la espalda recta y el core activado. Deja que la mancuerna cuelgue recta frente a ti, con el brazo completamente extendido. Tira de la mancuerna hacia el pecho, manteniendo el codo cerca del cuerpo. Junta los omóplatos en la parte superior del movimiento. Baja la mancuerna de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia de lado.', 'Stand with your feet shoulder-width apart, knees slightly bent, and hold a dumbbell in one hand. Bend forward at the hips, keeping your back straight and your core engaged. Let the dumbbell hang straight down in front of you, with your arm fully extended. Pull the dumbbell up towards your chest, keeping your elbow close to your body. Squeeze your shoulder blades together at the top of the movement. Lower the dumbbell back down to the starting position. Repeat for the desired number of repetitions, then switch sides.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3162-xbkPfaw.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3162-xbkPfaw.gif', 'xbkPfaw', '© Gym visual — https://gymvisual.com/'),
('3161', 'bodyweight standing one arm row (with towel)', 'Ponte de pie con los pies separados a la altura de los hombros, las rodillas ligeramente flexionadas, y sujeta una toalla con una mano. Inclínate hacia adelante desde las caderas, manteniendo la espalda recta y el core activado. Tira de la toalla hacia el pecho, juntando los omóplatos. Haz una pausa', 'back', 'body weight', 'back', 'back', 'upper back', '{"biceps","forearms"}', 'Ponte de pie con los pies separados a la altura de los hombros, las rodillas ligeramente flexionadas, y sujeta una toalla con una mano. Inclínate hacia adelante desde las caderas, manteniendo la espalda recta y el core activado. Tira de la toalla hacia el pecho, juntando los omóplatos. Haz una pausa breve en la parte más alta, luego baja lentamente la toalla de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia al otro brazo.', 'Stand with your feet shoulder-width apart, knees slightly bent, and hold a towel with one hand. Bend forward at the hips, keeping your back straight and your core engaged. Pull the towel towards your chest, squeezing your shoulder blades together. Pause for a moment at the top, then slowly lower the towel back to the starting position. Repeat for the desired number of repetitions, then switch to the other arm.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3161-O4oIqQD.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3161-O4oIqQD.gif', 'O4oIqQD', '© Gym visual — https://gymvisual.com/'),
('3166', 'bodyweight standing row', 'Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Sujeta una barra o las agarraderas con agarre prono, palmas hacia abajo. Mantén la espalda recta y el core activado. Tira de la barra o las agarraderas hacia el cuerpo, juntando los omóplatos. Haz ', 'back', 'body weight', 'back', 'back', 'upper back', '{"biceps","shoulders"}', 'Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Sujeta una barra o las agarraderas con agarre prono, palmas hacia abajo. Mantén la espalda recta y el core activado. Tira de la barra o las agarraderas hacia el cuerpo, juntando los omóplatos. Haz una pausa breve en la parte alta del movimiento. Suelta lentamente y extiende los brazos de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and knees slightly bent. Grasp a bar or handles with an overhand grip, palms facing down. Keep your back straight and core engaged. Pull the bar or handles towards your body, squeezing your shoulder blades together. Pause for a moment at the top of the movement. Slowly release and extend your arms back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3166-wd4ds3s.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3166-wd4ds3s.gif', 'wd4ds3s', '© Gym visual — https://gymvisual.com/'),
('3165', 'bodyweight standing row (with towel)', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una toalla frente a ti con ambas manos. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta. Tira de la toalla hacia el pecho, juntando los omóplatos. Haz una pausa por un', 'back', 'body weight', 'back', 'back', 'upper back', '{"biceps","shoulders"}', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una toalla frente a ti con ambas manos. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta. Tira de la toalla hacia el pecho, juntando los omóplatos. Haz una pausa por un momento en la parte superior, luego suelta lentamente la tensión y regresa a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and hold a towel in front of you with both hands. Bend your knees slightly and hinge forward at the hips, keeping your back straight. Pull the towel towards your chest, squeezing your shoulder blades together. Pause for a moment at the top, then slowly release the tension and return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3165-uTv34oq.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3165-uTv34oq.gif', 'uTv34oq', '© Gym visual — https://gymvisual.com/'),
('0138', 'bottoms-up', 'Túmbate sobre tu espalda con las piernas extendidas y los brazos a los lados. Flexiona las rodillas y llévalas hacia el pecho, manteniendo los pies fuera del suelo. Activando el abdomen, levanta las caderas del suelo, llevando las rodillas hacia la cabeza. Haz una pausa por un momento en la parte su', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"obliques","hip flexors"}', 'Túmbate sobre tu espalda con las piernas extendidas y los brazos a los lados. Flexiona las rodillas y llévalas hacia el pecho, manteniendo los pies fuera del suelo. Activando el abdomen, levanta las caderas del suelo, llevando las rodillas hacia la cabeza. Haz una pausa por un momento en la parte superior, luego baja lentamente las caderas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on your back with your legs extended and your arms by your sides. Bend your knees and bring them towards your chest, keeping your feet off the ground. Engaging your abs, lift your hips off the ground, bringing your knees towards your head. Pause for a moment at the top, then slowly lower your hips back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0138-CI6baTY.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0138-CI6baTY.gif', 'CI6baTY', '© Gym visual — https://gymvisual.com/'),
('1374', 'box jump down with one leg stabilization', 'Ponte de pie frente a una caja o plataforma con los pies separados a la altura de los hombros. Flexiona las rodillas y salta sobre la caja, aterrizando suavemente con un pie sobre la caja y el otro pie colgando del borde. Estabilízate sobre la caja con el pie que está sobre ella, mientras mantienes ', 'lower legs', 'body weight', 'lower legs', 'lower legs', 'calves', '{"quadriceps","hamstrings","glutes"}', 'Ponte de pie frente a una caja o plataforma con los pies separados a la altura de los hombros. Flexiona las rodillas y salta sobre la caja, aterrizando suavemente con un pie sobre la caja y el otro pie colgando del borde. Estabilízate sobre la caja con el pie que está sobre ella, mientras mantienes el otro pie fuera del suelo. Mantén esta posición durante unos segundos, activando los músculos de la pantorrilla para conservar el equilibrio. Baja lentamente con el pie que está sobre la caja, volviendo a la posición inicial. Repite el ejercicio con la otra pierna.', 'Stand in front of a box or platform with your feet shoulder-width apart. Bend your knees and jump onto the box, landing softly with one foot on the box and the other foot hanging off the edge. Stabilize yourself on the box with the foot that is on it, while keeping the other foot off the ground. Hold this position for a few seconds, engaging your calf muscles to maintain balance. Slowly step down with the foot that is on the box, returning to the starting position. Repeat the exercise with the other leg.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1374-iPm26QU.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1374-iPm26QU.gif', 'iPm26QU', '© Gym visual — https://gymvisual.com/'),
('2466', 'bridge - mountain climber (cross body)', 'Comienza en una posición de plancha alta con las manos justo debajo de los hombros y el cuerpo en línea recta. Activa el core y levanta el pie derecho del suelo, llevando la rodilla derecha hacia el codo izquierdo. Vuelve a colocar el pie derecho en la posición inicial y repite el movimiento llevand', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"glutes","quadriceps","hamstrings","shoulders","triceps"}', 'Comienza en una posición de plancha alta con las manos justo debajo de los hombros y el cuerpo en línea recta. Activa el core y levanta el pie derecho del suelo, llevando la rodilla derecha hacia el codo izquierdo. Vuelve a colocar el pie derecho en la posición inicial y repite el movimiento llevando el pie izquierdo hacia el codo derecho. Continúa alternando los lados, moviéndote a un ritmo controlado. Mantén las caderas niveladas y evita levantarlas demasiado alto o dejarlas caer demasiado bajo. Mantén un patrón de respiración constante durante todo el ejercicio. Repite el número de repeticiones deseado.', 'Start in a high plank position with your hands directly under your shoulders and your body in a straight line. Engage your core and lift your right foot off the ground, bringing your right knee towards your left elbow. Return your right foot to the starting position and repeat the movement with your left foot towards your right elbow. Continue alternating sides, moving at a controlled pace. Keep your hips level and avoid lifting your hips too high or sagging them too low. Maintain a steady breathing pattern throughout the exercise. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2466-9c6T1YX.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2466-9c6T1YX.gif', '9c6T1YX', '© Gym visual — https://gymvisual.com/'),
('1160', 'burpee', 'Comienza de pie con los pies separados a la altura de los hombros. Baja el cuerpo hacia una posición de sentadilla flexionando las rodillas y colocando las manos en el suelo frente a ti. Lleva los pies hacia atrás de una patada hasta una posición de flexión de brazos. Realiza una flexión de brazos, ', 'cardio', 'body weight', 'cardio', 'cardio', 'cardiovascular system', '{"quadriceps","hamstrings","calves","shoulders","chest"}', 'Comienza de pie con los pies separados a la altura de los hombros. Baja el cuerpo hacia una posición de sentadilla flexionando las rodillas y colocando las manos en el suelo frente a ti. Lleva los pies hacia atrás de una patada hasta una posición de flexión de brazos. Realiza una flexión de brazos, manteniendo el cuerpo en línea recta. Salta con los pies de vuelta a la posición de sentadilla. Salta hacia arriba explosivamente, llevando los brazos por encima de la cabeza. Aterriza suavemente y baja de inmediato a una posición de sentadilla para comenzar la siguiente repetición.', 'Start in a standing position with your feet shoulder-width apart. Lower your body into a squat position by bending your knees and placing your hands on the floor in front of you. Kick your feet back into a push-up position. Perform a push-up, keeping your body in a straight line. Jump your feet back into the squat position. Jump up explosively, reaching your arms overhead. Land softly and immediately lower back into a squat position to begin the next repetition.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1160-dK9394r.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1160-dK9394r.gif', 'dK9394r', '© Gym visual — https://gymvisual.com/'),
('0870', 'butt-ups', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Coloca las manos a los lados, con las palmas hacia abajo. Activando el abdomen, levanta las piernas del suelo, llevando las rodillas hacia el pecho. En la parte más alta del movimiento, contrae el abdomen y haz un', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"hip flexors","lower back"}', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Coloca las manos a los lados, con las palmas hacia abajo. Activando el abdomen, levanta las piernas del suelo, llevando las rodillas hacia el pecho. En la parte más alta del movimiento, contrae el abdomen y haz una pausa breve. Baja lentamente las piernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on your back with your knees bent and feet flat on the ground. Place your hands by your sides, palms facing down. Engaging your abs, lift your legs off the ground, bringing your knees towards your chest. At the top of the movement, squeeze your abs and pause for a moment. Slowly lower your legs back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0870-qcNN2FN.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0870-qcNN2FN.gif', 'qcNN2FN', '© Gym visual — https://gymvisual.com/'),
('1494', 'butterfly yoga pose', 'Siéntate en el suelo con las piernas extendidas frente a ti. Flexiona las rodillas y junta las plantas de los pies, dejando que las rodillas caigan hacia los lados. Sujétate los tobillos o los pies con las manos. Siéntate erguido y alarga la columna. Presiona suavemente las rodillas hacia el suelo, ', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'adductors', '{"hamstrings","groin"}', 'Siéntate en el suelo con las piernas extendidas frente a ti. Flexiona las rodillas y junta las plantas de los pies, dejando que las rodillas caigan hacia los lados. Sujétate los tobillos o los pies con las manos. Siéntate erguido y alarga la columna. Presiona suavemente las rodillas hacia el suelo, sintiendo un estiramiento en la parte interna de los muslos. Mantén esta posición durante unas cuantas respiraciones. Para liberar, lleva lentamente las rodillas hacia arriba de nuevo y extiende las piernas.', 'Sit on the floor with your legs extended in front of you. Bend your knees and bring the soles of your feet together, allowing your knees to fall out to the sides. Hold onto your ankles or feet with your hands. Sit up tall and lengthen your spine. Gently press your knees down towards the floor, feeling a stretch in your inner thighs. Hold this position for a few breaths. To release, slowly bring your knees back up and extend your legs.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1494-bWlZvXh.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1494-bWlZvXh.gif', 'bWlZvXh', '© Gym visual — https://gymvisual.com/'),
('0148', 'cable alternate shoulder press', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta las agarraderas de la máquina de cable con agarre prono. Coloca las manos a la altura de los hombros, con las palmas mirando hacia adelante. Mantén el core activado y la espalda recta. Empuja una agarradera hacia arriba y hacia ', 'shoulders', 'cable', 'shoulders', 'shoulders', 'delts', '{"triceps","upper back"}', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta las agarraderas de la máquina de cable con agarre prono. Coloca las manos a la altura de los hombros, con las palmas mirando hacia adelante. Mantén el core activado y la espalda recta. Empuja una agarradera hacia arriba y hacia adelante hasta que el brazo quede completamente extendido. Haz una pausa breve en la parte más alta, luego baja lentamente la agarradera de vuelta a la posición inicial. Repite con el otro brazo. Alterna entre los brazos el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and grasp the handles of the cable machine with an overhand grip. Position your hands at shoulder height, with your palms facing forward. Keep your core engaged and your back straight. Press one handle up and forward until your arm is fully extended. Pause for a moment at the top, then slowly lower the handle back to the starting position. Repeat with the other arm. Alternate between arms for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0148-KHPZL0b.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0148-KHPZL0b.gif', 'KHPZL0b', '© Gym visual — https://gymvisual.com/'),
('0149', 'cable alternate triceps extension', 'Ponte de pie frente a la máquina de cable con los pies separados a la altura de los hombros. Sujeta la agarradera del cable con la mano derecha y levanta el brazo de modo que el brazo superior quede paralelo al suelo y el codo flexionado en un ángulo de 90 grados. Mantén el brazo superior quieto y e', 'upper arms', 'cable', 'upper arms', 'upper arms', 'triceps', '{"shoulders"}', 'Ponte de pie frente a la máquina de cable con los pies separados a la altura de los hombros. Sujeta la agarradera del cable con la mano derecha y levanta el brazo de modo que el brazo superior quede paralelo al suelo y el codo flexionado en un ángulo de 90 grados. Mantén el brazo superior quieto y extiende el antebrazo hacia atrás, estirando completamente el brazo. Haz una pausa por un momento, luego regresa lentamente a la posición inicial. Repite con el brazo izquierdo. Continúa alternando los brazos durante el número de repeticiones deseado.', 'Stand facing the cable machine with your feet shoulder-width apart. Hold the cable handle with your right hand and bring your arm up so that your upper arm is parallel to the ground and your elbow is bent at a 90-degree angle. Keep your upper arm stationary and extend your forearm backward, fully straightening your arm. Pause for a moment, then slowly return to the starting position. Repeat with your left arm. Continue alternating arms for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0149-Gchi5Tr.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0149-Gchi5Tr.gif', 'Gchi5Tr', '© Gym visual — https://gymvisual.com/'),
('3235', 'cable assisted inverse leg curl', 'Ajusta la máquina de cable de modo que el accesorio para el tobillo quede en la posición más baja. Túmbate boca abajo en el banco con las piernas rectas y el accesorio para el tobillo sujeto a los tobillos. Sujétate de las agarraderas del banco para mantener la estabilidad. Manteniendo quieta la par', 'upper legs', 'cable', 'upper legs', 'upper legs', 'hamstrings', '{"glutes","calves"}', 'Ajusta la máquina de cable de modo que el accesorio para el tobillo quede en la posición más baja. Túmbate boca abajo en el banco con las piernas rectas y el accesorio para el tobillo sujeto a los tobillos. Sujétate de las agarraderas del banco para mantener la estabilidad. Manteniendo quieta la parte superior del cuerpo, exhala y flexiona las piernas hacia los glúteos doblando las rodillas. Haz una pausa breve en la parte más alta del movimiento, contrayendo los isquiotibiales. Inhala y baja lentamente las piernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the cable machine so that the ankle attachment is at the lowest setting. Lie face down on the bench with your legs straight and the ankle attachment secured to your ankles. Hold onto the handles of the bench for stability. Keeping your upper body stationary, exhale and curl your legs up towards your glutes by flexing your knees. Pause for a moment at the top of the movement, squeezing your hamstrings. Inhale and slowly lower your legs back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3235-zHEpuuc.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3235-zHEpuuc.gif', 'zHEpuuc', '© Gym visual — https://gymvisual.com/'),
('0150', 'cable bar lateral pulldown', 'Ajusta la polea del cable a una posición alta y coloca una barra recta. Siéntate frente a la máquina de cable con los pies planos en el suelo y las rodillas ligeramente flexionadas. Sujeta la barra con agarre prono, un poco más separado que el ancho de los hombros. Inclínate ligeramente hacia atrás ', 'back', 'cable', 'back', 'back', 'lats', '{"biceps","rhomboids","rear deltoids"}', 'Ajusta la polea del cable a una posición alta y coloca una barra recta. Siéntate frente a la máquina de cable con los pies planos en el suelo y las rodillas ligeramente flexionadas. Sujeta la barra con agarre prono, un poco más separado que el ancho de los hombros. Inclínate ligeramente hacia atrás y mantén el pecho elevado, conservando un ligero arco en la zona lumbar. Tira de la barra hacia el pecho, guiando el movimiento con los codos y juntando los omóplatos. Haz una pausa breve en la parte más baja del movimiento, luego vuelve lentamente la barra a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the cable pulley to a high position and attach a straight bar. Sit facing the cable machine with your feet flat on the ground and your knees slightly bent. Grasp the bar with an overhand grip, slightly wider than shoulder-width apart. Lean back slightly and keep your chest up, maintaining a slight arch in your lower back. Pull the bar down towards your chest, leading with your elbows and squeezing your shoulder blades together. Pause for a moment at the bottom of the movement, then slowly return the bar to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0150-eYnzaCm.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0150-eYnzaCm.gif', 'eYnzaCm', '© Gym visual — https://gymvisual.com/'),
('0151', 'cable bench press', 'Ajusta la máquina de cable a la altura del pecho y coloca las agarraderas. Ponte de pie de espaldas a la máquina con los pies separados a la altura de los hombros. Sujeta las agarraderas con agarre prono y da un paso hacia adelante para crear tensión en los cables. Coloca los pies firmemente en el s', 'chest', 'cable', 'chest', 'chest', 'pectorals', '{"triceps","shoulders"}', 'Ajusta la máquina de cable a la altura del pecho y coloca las agarraderas. Ponte de pie de espaldas a la máquina con los pies separados a la altura de los hombros. Sujeta las agarraderas con agarre prono y da un paso hacia adelante para crear tensión en los cables. Coloca los pies firmemente en el suelo y activa el core. Flexiona los codos y lleva las manos a la altura de los hombros, manteniendo los codos en un ángulo de 90 grados. Empuja las agarraderas hacia adelante, extendiendo completamente los brazos frente a ti. Haz una pausa breve, luego invierte lentamente el movimiento, llevando las manos de vuelta a la altura de los hombros. Repite el número de repeticiones deseado.', 'Adjust the cable machine to chest height and attach the handles. Stand facing away from the machine with your feet shoulder-width apart. Grasp the handles with an overhand grip and step forward to create tension in the cables. Position your feet firmly on the ground and engage your core. Bend your elbows and bring your hands to shoulder level, keeping your elbows at a 90-degree angle. Push the handles forward, extending your arms fully in front of you. Pause for a moment, then slowly reverse the movement, bringing your hands back to shoulder level. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0151-7xI5MXA.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0151-7xI5MXA.gif', '7xI5MXA', '© Gym visual — https://gymvisual.com/'),
('1630', 'cable close grip curl', 'Coloca una barra recta en una máquina de cable con polea baja. Ponte de pie frente a la máquina con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Sujeta la barra con agarre supino, manos separadas a la altura de los hombros. Mantén los codos cerca de los costa', 'upper arms', 'cable', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Coloca una barra recta en una máquina de cable con polea baja. Ponte de pie frente a la máquina con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Sujeta la barra con agarre supino, manos separadas a la altura de los hombros. Mantén los codos cerca de los costados y los brazos superiores quietos durante todo el ejercicio. Exhala y flexiona la barra hacia los hombros, contrayendo los bíceps. Haz una pausa breve en la parte más alta del movimiento, contrayendo los bíceps. Inhala y baja lentamente la barra de vuelta a la posición inicial, extendiendo completamente los brazos. Repite el número de repeticiones deseado.', 'Attach a straight bar to a low pulley cable machine. Stand facing the machine with your feet shoulder-width apart and your knees slightly bent. Grasp the bar with an underhand grip, hands shoulder-width apart. Keep your elbows close to your sides and your upper arms stationary throughout the exercise. Exhale and curl the bar up towards your shoulders, contracting your biceps. Pause for a moment at the top of the movement, squeezing your biceps. Inhale and slowly lower the bar back to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1630-BCGQ6J5.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1630-BCGQ6J5.gif', 'BCGQ6J5', '© Gym visual — https://gymvisual.com/'),
('1631', 'cable concentration curl', 'Siéntate en un banco o silla con los pies planos en el suelo y las rodillas ligeramente flexionadas. Sujeta la agarradera del cable con agarre supino y apoya el codo en la parte interna del muslo. Manteniendo el brazo superior quieto, exhala y flexiona la agarradera del cable hacia el hombro contray', 'upper arms', 'cable', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Siéntate en un banco o silla con los pies planos en el suelo y las rodillas ligeramente flexionadas. Sujeta la agarradera del cable con agarre supino y apoya el codo en la parte interna del muslo. Manteniendo el brazo superior quieto, exhala y flexiona la agarradera del cable hacia el hombro contrayendo el bíceps. Haz una pausa breve en la parte más alta del movimiento, luego inhala y baja lentamente la agarradera del cable de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia de brazo.', 'Sit on a bench or chair with your feet flat on the floor and your knees slightly bent. Hold the cable handle with an underhand grip and rest your elbow against the inside of your thigh. Keeping your upper arm stationary, exhale and curl the cable handle towards your shoulder while contracting your biceps. Pause for a moment at the top of the movement, then inhale and slowly lower the cable handle back to the starting position. Repeat for the desired number of repetitions, then switch arms.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1631-NvfE43H.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1631-NvfE43H.gif', 'NvfE43H', '© Gym visual — https://gymvisual.com/'),
('0152', 'cable concentration extension (on knee)', 'Siéntate en un banco o silla con las rodillas flexionadas y los pies planos en el suelo. Sujeta la agarradera del cable con la mano derecha y coloca el codo en la parte interna de la rodilla derecha. Extiende completamente el brazo, manteniendo el codo quieto y cerca de la rodilla. Haz una pausa bre', 'upper arms', 'cable', 'upper arms', 'upper arms', 'triceps', '{"forearms"}', 'Siéntate en un banco o silla con las rodillas flexionadas y los pies planos en el suelo. Sujeta la agarradera del cable con la mano derecha y coloca el codo en la parte interna de la rodilla derecha. Extiende completamente el brazo, manteniendo el codo quieto y cerca de la rodilla. Haz una pausa breve en la parte más alta, luego baja lentamente el brazo de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia de lado.', 'Sit on a bench or chair with your knees bent and feet flat on the ground. Hold the cable handle with your right hand and place your elbow on the inside of your right knee. Extend your arm fully, keeping your elbow stationary and close to your knee. Pause for a moment at the top, then slowly lower your arm back to the starting position. Repeat for the desired number of repetitions, then switch sides.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0152-Db7eEgw.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0152-Db7eEgw.gif', 'Db7eEgw', '© Gym visual — https://gymvisual.com/'),
('0153', 'cable cross-over lateral pulldown', 'Coloca una agarradera de cable en cada lado de una máquina de cable a la altura de los hombros. Ponte de pie en el centro de la máquina con los pies separados a la altura de los hombros. Sujeta las agarraderas con agarre prono y da un paso hacia atrás para crear tensión en los cables. Inclínate lige', 'back', 'cable', 'back', 'back', 'lats', '{"biceps","rhomboids","rear deltoids"}', 'Coloca una agarradera de cable en cada lado de una máquina de cable a la altura de los hombros. Ponte de pie en el centro de la máquina con los pies separados a la altura de los hombros. Sujeta las agarraderas con agarre prono y da un paso hacia atrás para crear tensión en los cables. Inclínate ligeramente hacia adelante desde las caderas, manteniendo la espalda recta y el pecho elevado. Tira de las agarraderas hacia abajo y a través del cuerpo, juntando los omóplatos. Haz una pausa breve en la parte más baja del movimiento, luego vuelve lentamente a la posición inicial. Repite el número de repeticiones deseado.', 'Attach a cable handle to each side of a cable machine at shoulder height. Stand in the middle of the machine with your feet shoulder-width apart. Grasp the handles with an overhand grip and step back to create tension in the cables. Lean forward slightly from the hips, keeping your back straight and your chest up. Pull the handles down and across your body, squeezing your shoulder blades together. Pause for a moment at the bottom of the movement, then slowly return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0153-OQ1otBN.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0153-OQ1otBN.gif', 'OQ1otBN', '© Gym visual — https://gymvisual.com/'),
('0154', 'cable cross-over revers fly', 'Coloca una agarradera en D en cada cable de polea baja y ponte de pie en el centro de la máquina de cable cruzado. Sujeta las agarraderas con agarre prono (palmas hacia abajo) y da un paso hacia adelante, colocando los pies separados a la altura de los hombros. Flexiona ligeramente las rodillas e in', 'shoulders', 'cable', 'shoulders', 'shoulders', 'delts', '{"rhomboids","trapezius"}', 'Coloca una agarradera en D en cada cable de polea baja y ponte de pie en el centro de la máquina de cable cruzado. Sujeta las agarraderas con agarre prono (palmas hacia abajo) y da un paso hacia adelante, colocando los pies separados a la altura de los hombros. Flexiona ligeramente las rodillas e inclínate hacia adelante desde la cintura, manteniendo la espalda recta y el abdomen activado. Con los brazos extendidos hacia los lados y ligeramente flexionados en los codos, exhala y junta los omóplatos mientras tiras de los cables hacia atrás y hacia arriba en un movimiento de apertura inversa. Haz una pausa breve en el punto máximo de contracción, luego inhala y vuelve lentamente a la posición inicial. Repite el número de repeticiones deseado.', 'Attach a D-handle to each low pulley cable and stand in the middle of the cable crossover machine. Grasp the handles with a pronated grip (palms facing down) and take a step forward, positioning your feet shoulder-width apart. Bend your knees slightly and lean forward at the waist, keeping your back straight and your abs engaged. With your arms extended out to the sides and slightly bent at the elbows, exhale and squeeze your shoulder blades together as you pull the cables back and upward in a reverse fly motion. Pause for a moment at the peak contraction, then inhale and slowly return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0154-aqvSOQE.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0154-aqvSOQE.gif', 'aqvSOQE', '© Gym visual — https://gymvisual.com/'),
('0155', 'cable cross-over variation', 'Ajusta las poleas del cable a la altura del pecho. Ponte de pie en el centro de la máquina de cable con un pie delante del otro. Sujeta las agarraderas con las palmas hacia abajo y los brazos extendidos hacia los lados. Da un paso hacia adelante, manteniendo los brazos ligeramente flexionados. Con u', 'chest', 'cable', 'chest', 'chest', 'pectorals', '{"deltoids","triceps"}', 'Ajusta las poleas del cable a la altura del pecho. Ponte de pie en el centro de la máquina de cable con un pie delante del otro. Sujeta las agarraderas con las palmas hacia abajo y los brazos extendidos hacia los lados. Da un paso hacia adelante, manteniendo los brazos ligeramente flexionados. Con una ligera flexión en los codos, junta las manos frente al pecho. Haz una pausa breve, luego vuelve lentamente los brazos a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the cable pulleys to chest height. Stand in the center of the cable machine with one foot in front of the other. Grasp the handles with your palms facing down and your arms extended out to the sides. Take a step forward, keeping your arms slightly bent. With a slight bend in your elbows, bring your hands together in front of your chest. Pause for a moment, then slowly return your arms back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0155-0CXGHya.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0155-0CXGHya.gif', '0CXGHya', '© Gym visual — https://gymvisual.com/'),
('0868', 'cable curl', 'Ponte de pie frente a la máquina de cable con los pies separados a la altura de los hombros. Sujeta el accesorio del cable con agarre supino, palmas hacia arriba. Mantén los codos cerca de los costados y los brazos superiores quietos. Exhala y flexiona el accesorio del cable hacia los hombros, contr', 'upper arms', 'cable', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ponte de pie frente a la máquina de cable con los pies separados a la altura de los hombros. Sujeta el accesorio del cable con agarre supino, palmas hacia arriba. Mantén los codos cerca de los costados y los brazos superiores quietos. Exhala y flexiona el accesorio del cable hacia los hombros, contrayendo los bíceps. Haz una pausa breve en la parte más alta del movimiento, contrayendo los bíceps. Inhala y baja lentamente el accesorio del cable de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand facing the cable machine with your feet shoulder-width apart. Grasp the cable attachment with an underhand grip, palms facing up. Keep your elbows close to your sides and your upper arms stationary. Exhale and curl the cable attachment towards your shoulders, contracting your biceps. Pause for a moment at the top of the movement, squeezing your biceps. Inhale and slowly lower the cable attachment back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0868-G08RZcQ.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0868-G08RZcQ.gif', 'G08RZcQ', '© Gym visual — https://gymvisual.com/'),
('0157', 'cable deadlift', 'Ponte de pie frente a la máquina de cable con los pies separados a la altura de los hombros. Flexiona las caderas y las rodillas, bajando el torso hasta que la espalda quede paralela al suelo. Sujeta las agarraderas del cable con agarre prono, manteniendo los brazos rectos y los hombros hacia atrás.', 'upper legs', 'cable', 'upper legs', 'upper legs', 'glutes', '{"hamstrings","quadriceps","lower back"}', 'Ponte de pie frente a la máquina de cable con los pies separados a la altura de los hombros. Flexiona las caderas y las rodillas, bajando el torso hasta que la espalda quede paralela al suelo. Sujeta las agarraderas del cable con agarre prono, manteniendo los brazos rectos y los hombros hacia atrás. Activa los glúteos y los isquiotibiales para levantar las agarraderas del cable, extendiendo las caderas y poniéndote de pie. Haz una pausa breve en la parte más alta, luego baja lentamente las agarraderas del cable de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand facing the cable machine with your feet shoulder-width apart. Bend at the hips and knees, lowering your torso until your back is parallel to the ground. Grasp the cable handles with an overhand grip, keeping your arms straight and your shoulders back. Engage your glutes and hamstrings to lift the cable handles, extending your hips and standing up straight. Pause for a moment at the top, then slowly lower the cable handles back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0157-eGDudUV.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0157-eGDudUV.gif', 'eGDudUV', '© Gym visual — https://gymvisual.com/'),
('0158', 'cable decline fly', 'Ajusta la máquina de cable a una posición declinada. Ponte de pie de espaldas a la máquina con los pies separados a la altura de los hombros. Sujeta las agarraderas con las palmas hacia adelante y los brazos extendidos rectos frente a ti. Manteniendo una ligera flexión en los codos, abre los brazos ', 'chest', 'cable', 'chest', 'chest', 'pectorals', '{"shoulders","triceps"}', 'Ajusta la máquina de cable a una posición declinada. Ponte de pie de espaldas a la máquina con los pies separados a la altura de los hombros. Sujeta las agarraderas con las palmas hacia adelante y los brazos extendidos rectos frente a ti. Manteniendo una ligera flexión en los codos, abre los brazos hacia los lados con un movimiento controlado. Haz una pausa breve en la posición completamente extendida, luego vuelve lentamente a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the cable machine to a decline position. Stand facing away from the machine with your feet shoulder-width apart. Hold the handles with your palms facing forward and your arms extended straight out in front of you. Keeping a slight bend in your elbows, open your arms out to the sides in a controlled motion. Pause for a moment at the fully extended position, then slowly return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0158-7saC5zz.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0158-7saC5zz.gif', '7saC5zz', '© Gym visual — https://gymvisual.com/'),
('1260', 'cable decline one arm press', 'Ajusta la máquina de cable a una posición declinada. Ponte de pie de espaldas a la máquina y sujeta la agarradera con una mano. Colócate con la espalda contra el banco declinado y el brazo extendido recto frente a ti. Flexiona el codo y baja la agarradera hacia el pecho, manteniendo el brazo superio', 'chest', 'cable', 'chest', 'chest', 'pectorals', '{"triceps","shoulders"}', 'Ajusta la máquina de cable a una posición declinada. Ponte de pie de espaldas a la máquina y sujeta la agarradera con una mano. Colócate con la espalda contra el banco declinado y el brazo extendido recto frente a ti. Flexiona el codo y baja la agarradera hacia el pecho, manteniendo el brazo superior quieto. Haz una pausa breve en la parte más baja, luego empuja la agarradera de vuelta hacia la posición inicial. Repite el número de repeticiones deseado, luego cambia de brazo.', 'Adjust the cable machine to a decline position. Stand facing away from the machine and grab the handle with one hand. Position yourself with your back against the decline bench and your arm extended straight in front of you. Bend your elbow and lower the handle towards your chest while keeping your upper arm stationary. Pause for a moment at the bottom, then push the handle back up to the starting position. Repeat for the desired number of repetitions, then switch arms.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1260-KHGNa16.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1260-KHGNa16.gif', 'KHGNa16', '© Gym visual — https://gymvisual.com/'),
('1261', 'cable decline press', 'Ajusta la máquina de cable a una posición declinada. Siéntate en el banco declinado frente a la máquina de cable. Sujeta las agarraderas con agarre prono y colócalas a la altura del pecho. Mantén los pies planos en el suelo y la espalda firmemente apoyada en el banco. Exhala y empuja las agarraderas', 'chest', 'cable', 'chest', 'chest', 'pectorals', '{"triceps","shoulders"}', 'Ajusta la máquina de cable a una posición declinada. Siéntate en el banco declinado frente a la máquina de cable. Sujeta las agarraderas con agarre prono y colócalas a la altura del pecho. Mantén los pies planos en el suelo y la espalda firmemente apoyada en el banco. Exhala y empuja las agarraderas alejándolas del cuerpo, extendiendo completamente los brazos. Haz una pausa breve al final del movimiento, contrayendo los músculos del pecho. Inhala y vuelve lentamente las agarraderas a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the cable machine to a decline position. Sit on the decline bench facing the cable machine. Grasp the handles with an overhand grip and position them at chest level. Keep your feet flat on the ground and your back firmly against the bench. Exhale and push the handles away from your body, extending your arms fully. Pause for a moment at the end of the movement, squeezing your chest muscles. Inhale and slowly return the handles back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1261-2Pya1cP.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1261-2Pya1cP.gif', '2Pya1cP', '© Gym visual — https://gymvisual.com/'),
('0159', 'cable decline seated wide-grip row', 'Siéntate en el banco declinado frente a la máquina de cable con los pies firmemente colocados en los reposapiés. Sujeta el accesorio del cable con un agarre prono amplio, palmas hacia abajo. Inclínate ligeramente hacia atrás, manteniendo la espalda recta y el core activado. Tira del cable hacia la p', 'back', 'cable', 'back', 'back', 'upper back', '{"biceps","forearms"}', 'Siéntate en el banco declinado frente a la máquina de cable con los pies firmemente colocados en los reposapiés. Sujeta el accesorio del cable con un agarre prono amplio, palmas hacia abajo. Inclínate ligeramente hacia atrás, manteniendo la espalda recta y el core activado. Tira del cable hacia la parte inferior del pecho, juntando los omóplatos. Haz una pausa breve en el punto máximo de la contracción, luego suelta lentamente el cable de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on the decline bench facing the cable machine with your feet securely placed on the footrests. Grasp the cable attachment with a wide overhand grip, palms facing down. Lean back slightly, keeping your back straight and your core engaged. Pull the cable towards your lower chest, squeezing your shoulder blades together. Pause for a moment at the peak of the contraction, then slowly release the cable back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0159-kesXOpB.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0159-kesXOpB.gif', 'kesXOpB', '© Gym visual — https://gymvisual.com/'),
('1632', 'cable drag curl', 'Ponte de pie frente a una máquina de cable con los pies separados a la altura de los hombros. Sujeta el accesorio del cable con agarre supino, palmas hacia arriba, y los brazos completamente extendidos. Manteniendo los brazos superiores quietos, exhala y flexiona el accesorio del cable hacia los hom', 'upper arms', 'cable', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ponte de pie frente a una máquina de cable con los pies separados a la altura de los hombros. Sujeta el accesorio del cable con agarre supino, palmas hacia arriba, y los brazos completamente extendidos. Manteniendo los brazos superiores quietos, exhala y flexiona el accesorio del cable hacia los hombros contrayendo los bíceps. Haz una pausa breve en la parte más alta del movimiento, contrayendo los bíceps. Inhala y baja lentamente el accesorio del cable de vuelta a la posición inicial, extendiendo completamente los brazos. Repite el número de repeticiones deseado.', 'Stand facing a cable machine with your feet shoulder-width apart. Grasp the cable attachment with an underhand grip, palms facing up, and arms fully extended. Keeping your upper arms stationary, exhale and curl the cable attachment towards your shoulders by contracting your biceps. Pause for a moment at the top of the movement, squeezing your biceps. Inhale and slowly lower the cable attachment back to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1632-dXz8zjF.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1632-dXz8zjF.gif', 'dXz8zjF', '© Gym visual — https://gymvisual.com/'),
('0160', 'cable floor seated wide-grip row', 'Siéntate en el suelo con las piernas extendidas y la espalda recta. Coloca una agarradera de cable en una polea baja y ubica la máquina de cable detrás de ti. Sujeta la agarradera con un agarre prono amplio, palmas hacia abajo. Inclínate ligeramente hacia atrás, manteniendo la espalda recta y el pec', 'back', 'cable', 'back', 'back', 'upper back', '{"biceps","forearms"}', 'Siéntate en el suelo con las piernas extendidas y la espalda recta. Coloca una agarradera de cable en una polea baja y ubica la máquina de cable detrás de ti. Sujeta la agarradera con un agarre prono amplio, palmas hacia abajo. Inclínate ligeramente hacia atrás, manteniendo la espalda recta y el pecho elevado. Tira de la agarradera hacia la cintura, juntando los omóplatos. Haz una pausa breve en la parte más alta del movimiento, luego suelta lentamente la agarradera de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on the floor with your legs extended and your back straight. Attach a cable handle to a low pulley and position the cable machine behind you. Grasp the handle with a wide overhand grip, palms facing down. Lean back slightly, keeping your back straight and your chest lifted. Pull the handle towards your waist, squeezing your shoulder blades together. Pause for a moment at the top of the movement, then slowly release the handle back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0160-veXwo0D.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0160-veXwo0D.gif', 'veXwo0D', '© Gym visual — https://gymvisual.com/'),
('0161', 'cable forward raise', 'Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Sujeta la agarradera del cable con agarre prono, palmas hacia abajo, y los brazos completamente extendidos frente a ti. Manteniendo los brazos rectos, levanta la agarradera del cable hasta la altur', 'shoulders', 'cable', 'shoulders', 'shoulders', 'delts', '{"triceps","forearms"}', 'Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Sujeta la agarradera del cable con agarre prono, palmas hacia abajo, y los brazos completamente extendidos frente a ti. Manteniendo los brazos rectos, levanta la agarradera del cable hasta la altura de los hombros. Haz una pausa breve en la parte más alta, luego baja lentamente la agarradera del cable de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and your knees slightly bent. Hold the cable handle with an overhand grip, palms facing down, and your arms fully extended in front of you. Keeping your arms straight, raise the cable handle up to shoulder level. Pause for a moment at the top, then slowly lower the cable handle back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0161-hvHhCv8.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0161-hvHhCv8.gif', 'hvHhCv8', '© Gym visual — https://gymvisual.com/'),
('0162', 'cable front raise', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta la agarradera del cable con agarre prono. Mantén la espalda recta y el core activado. Levanta la agarradera del cable frente a ti, manteniendo los brazos rectos y las palmas hacia abajo. Continúa levantando hasta que los brazos ', 'shoulders', 'cable', 'shoulders', 'shoulders', 'delts', '{"triceps","forearms"}', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta la agarradera del cable con agarre prono. Mantén la espalda recta y el core activado. Levanta la agarradera del cable frente a ti, manteniendo los brazos rectos y las palmas hacia abajo. Continúa levantando hasta que los brazos queden paralelos al suelo. Haz una pausa breve en la parte más alta, luego baja lentamente la agarradera del cable de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and grasp the cable handle with an overhand grip. Keep your back straight and your core engaged. Raise the cable handle in front of you, keeping your arms straight and your palms facing down. Continue lifting until your arms are parallel to the floor. Pause for a moment at the top, then slowly lower the cable handle back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0162-u2X71Np.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0162-u2X71Np.gif', 'u2X71Np', '© Gym visual — https://gymvisual.com/'),
('0164', 'cable front shoulder raise', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta la agarradera del cable con agarre prono. Mantén la espalda recta y el core activado. Levanta la agarradera del cable frente a ti, manteniendo los brazos rectos y las palmas hacia abajo. Continúa levantando hasta que los brazos ', 'shoulders', 'cable', 'shoulders', 'shoulders', 'delts', '{"trapezius","biceps"}', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta la agarradera del cable con agarre prono. Mantén la espalda recta y el core activado. Levanta la agarradera del cable frente a ti, manteniendo los brazos rectos y las palmas hacia abajo. Continúa levantando hasta que los brazos queden paralelos al suelo. Haz una pausa breve en la parte más alta, luego baja lentamente la agarradera del cable de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and grasp the cable handle with an overhand grip. Keep your back straight and your core engaged. Raise the cable handle in front of you, keeping your arms straight and your palms facing down. Continue lifting until your arms are parallel to the floor. Pause for a moment at the top, then slowly lower the cable handle back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0164-mTT3KLn.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0164-mTT3KLn.gif', 'mTT3KLn', '© Gym visual — https://gymvisual.com/'),
('0165', 'cable hammer curl (with rope)', 'Ponte de pie con los pies separados a la altura de los hombros y una ligera flexión en las rodillas. Sujeta el accesorio de cuerda del cable con agarre supino, palmas mirándose entre sí, y los brazos completamente extendidos. Manteniendo los brazos superiores fijos, exhala y levanta el peso mientras', 'upper arms', 'cable', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ponte de pie con los pies separados a la altura de los hombros y una ligera flexión en las rodillas. Sujeta el accesorio de cuerda del cable con agarre supino, palmas mirándose entre sí, y los brazos completamente extendidos. Manteniendo los brazos superiores fijos, exhala y levanta el peso mientras contraes los bíceps. Continúa levantando el accesorio de cuerda del cable hasta que los bíceps estén completamente contraídos y la cuerda esté a la altura de los hombros. Mantén la posición contraída durante una breve pausa mientras aprietas los bíceps. Inhala y comienza a bajar lentamente el accesorio de cuerda del cable de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand upright with your feet shoulder-width apart and a slight bend in your knees. Hold the cable rope attachment with an underhand grip, palms facing each other, and your arms fully extended. Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Continue to raise the cable rope attachment until your biceps are fully contracted and the rope is at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly begin to lower the cable rope attachment back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0165-HPlPoQA.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0165-HPlPoQA.gif', 'HPlPoQA', '© Gym visual — https://gymvisual.com/'),
('1722', 'cable high pulley overhead tricep extension', 'Coloca una cuerda en una polea alta y ponte de pie de espaldas a la máquina. Sujeta la cuerda con ambas manos y extiende los brazos por encima de la cabeza. Mantén los codos cerca de la cabeza y la parte superior de los brazos inmóvil. Baja lentamente la cuerda detrás de la cabeza flexionando los co', 'upper arms', 'cable', 'upper arms', 'upper arms', 'triceps', '{"shoulders"}', 'Coloca una cuerda en una polea alta y ponte de pie de espaldas a la máquina. Sujeta la cuerda con ambas manos y extiende los brazos por encima de la cabeza. Mantén los codos cerca de la cabeza y la parte superior de los brazos inmóvil. Baja lentamente la cuerda detrás de la cabeza flexionando los codos. Haz una pausa por un momento y luego extiende los brazos de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Attach a rope to a high pulley and stand facing away from the machine. Grasp the rope with both hands and extend your arms overhead. Keep your elbows close to your head and your upper arms stationary. Slowly lower the rope behind your head by bending your elbows. Pause for a moment, then extend your arms back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1722-1xHyxys.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1722-1xHyxys.gif', '1xHyxys', '© Gym visual — https://gymvisual.com/'),
('0167', 'cable high row (kneeling)', 'Sujeta una barra recta a una máquina de cable a la altura del pecho. Ponte de rodillas frente a la máquina de cable y agarra la barra con un agarre prono, con las manos separadas a la altura de los hombros. Siéntate sobre los talones, manteniendo la espalda recta y el core activado. Jala la barra ha', 'back', 'cable', 'back', 'back', 'upper back', '{"biceps","shoulders"}', 'Sujeta una barra recta a una máquina de cable a la altura del pecho. Ponte de rodillas frente a la máquina de cable y agarra la barra con un agarre prono, con las manos separadas a la altura de los hombros. Siéntate sobre los talones, manteniendo la espalda recta y el core activado. Jala la barra hacia la parte superior del abdomen, apretando los omóplatos entre sí. Haz una pausa por un momento en la parte más alta del movimiento y luego suelta lentamente la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Attach a straight bar to a cable machine at chest height. Kneel down in front of the cable machine and grab the bar with an overhand grip, hands shoulder-width apart. Sit back on your heels, keeping your back straight and your core engaged. Pull the bar towards your upper abdomen, squeezing your shoulder blades together. Pause for a moment at the top of the movement, then slowly release the bar back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0167-ZSJNetl.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0167-ZSJNetl.gif', 'ZSJNetl', '© Gym visual — https://gymvisual.com/'),
('0168', 'cable hip adduction', 'Sujeta el manguito de tobillo a tu tobillo y ponte de pie frente a la máquina de cable. Colócate lo suficientemente alejado de la máquina para que haya tensión en el cable. Coloca las manos sobre la máquina para apoyarte. Manteniendo la pierna recta, mueve lentamente la pierna por delante del cuerpo', 'upper legs', 'cable', 'upper legs', 'upper legs', 'adductors', '{"glutes","quadriceps"}', 'Sujeta el manguito de tobillo a tu tobillo y ponte de pie frente a la máquina de cable. Colócate lo suficientemente alejado de la máquina para que haya tensión en el cable. Coloca las manos sobre la máquina para apoyarte. Manteniendo la pierna recta, mueve lentamente la pierna por delante del cuerpo hacia la línea media. Haz una pausa por un momento al final del movimiento, luego regresa lentamente a la posición inicial. Repite el número de repeticiones deseado.', 'Attach the ankle cuff to your ankle and stand facing the cable machine. Position yourself far enough away from the machine so that there is tension on the cable. Place your hands on the machine for support. Keeping your leg straight, slowly move your leg across your body towards the midline. Pause for a moment at the end of the movement, then slowly return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0168-hBGWILP.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0168-hBGWILP.gif', 'hBGWILP', '© Gym visual — https://gymvisual.com/'),
('0169', 'cable incline bench press', 'Ajusta el banco a una inclinación de 45 grados. Sujeta las agarraderas del cable a las poleas altas. Siéntate en el banco frente a la máquina de cable con los pies apoyados planos en el suelo. Sujeta las agarraderas con un agarre prono y llévalas a la altura de los hombros. Empuja las agarraderas ha', 'chest', 'cable', 'chest', 'chest', 'pectorals', '{"deltoids","triceps"}', 'Ajusta el banco a una inclinación de 45 grados. Sujeta las agarraderas del cable a las poleas altas. Siéntate en el banco frente a la máquina de cable con los pies apoyados planos en el suelo. Sujeta las agarraderas con un agarre prono y llévalas a la altura de los hombros. Empuja las agarraderas hacia adelante y hacia arriba hasta que los brazos queden completamente extendidos. Haz una pausa por un momento y luego baja lentamente las agarraderas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the bench to a 45-degree incline. Attach the cable handles to the high pulleys. Sit on the bench facing the cable machine with your feet flat on the ground. Grasp the handles with an overhand grip and bring them to shoulder height. Push the handles forward and upward until your arms are fully extended. Pause for a moment, then slowly lower the handles back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0169-Vh0GsK4.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0169-Vh0GsK4.gif', 'Vh0GsK4', '© Gym visual — https://gymvisual.com/'),
('1318', 'cable incline bench row', 'Coloca un banco inclinado a un ángulo de 45 grados y sujeta una agarradera de cable a la polea baja. Siéntate en el banco frente a la máquina de cable con los pies apoyados planos en el suelo y las rodillas ligeramente flexionadas. Sujeta la agarradera del cable con un agarre prono y extiende los br', 'back', 'cable', 'back', 'back', 'upper back', '{"biceps","rear deltoids"}', 'Coloca un banco inclinado a un ángulo de 45 grados y sujeta una agarradera de cable a la polea baja. Siéntate en el banco frente a la máquina de cable con los pies apoyados planos en el suelo y las rodillas ligeramente flexionadas. Sujeta la agarradera del cable con un agarre prono y extiende los brazos completamente frente a ti. Inclínate hacia adelante desde las caderas manteniendo la espalda recta y el core activado. Jala la agarradera del cable hacia el pecho retrayendo los omóplatos y flexionando los codos. Aprieta los músculos de la espalda en la parte más alta del movimiento y luego extiende lentamente los brazos de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Set up an incline bench at a 45-degree angle and attach a cable handle to the low pulley. Sit on the bench facing the cable machine with your feet flat on the floor and your knees slightly bent. Grasp the cable handle with an overhand grip and extend your arms fully in front of you. Lean forward from your hips while keeping your back straight and your core engaged. Pull the cable handle towards your chest by retracting your shoulder blades and bending your elbows. Squeeze your back muscles at the top of the movement, then slowly extend your arms back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1318-yaMIo4D.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1318-yaMIo4D.gif', 'yaMIo4D', '© Gym visual — https://gymvisual.com/'),
('0171', 'cable incline fly', 'Ajusta la máquina de cable a una posición baja y sujeta las agarraderas. Siéntate en un banco inclinado con la espalda apoyada en el respaldo y los pies planos en el suelo. Sujeta las agarraderas con un agarre prono y extiende los brazos rectos frente a ti. Manteniendo una ligera flexión en los codo', 'chest', 'cable', 'chest', 'chest', 'pectorals', '{"deltoids","triceps"}', 'Ajusta la máquina de cable a una posición baja y sujeta las agarraderas. Siéntate en un banco inclinado con la espalda apoyada en el respaldo y los pies planos en el suelo. Sujeta las agarraderas con un agarre prono y extiende los brazos rectos frente a ti. Manteniendo una ligera flexión en los codos, abre los brazos hacia los lados con un movimiento controlado. Haz una pausa breve en la posición completamente extendida, luego vuelve lentamente a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the cable machine to a low position and attach the handles. Sit on an incline bench with your back against the pad and feet flat on the floor. Grasp the handles with an overhand grip and extend your arms straight out in front of you. Keeping a slight bend in your elbows, open your arms out to the sides in a controlled motion. Pause for a moment at the fully extended position, then slowly return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0171-tBWXbIT.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0171-tBWXbIT.gif', 'tBWXbIT', '© Gym visual — https://gymvisual.com/'),
('0170', 'cable incline fly (on stability ball)', 'Coloca un balón de estabilidad en un ángulo inclinado. Sujeta las agarraderas del cable a las poleas altas de una máquina de cable. Siéntate sobre el balón de estabilidad de espaldas a la máquina, con los pies firmemente apoyados en el suelo. Sujeta las agarraderas del cable con un agarre prono, con', 'chest', 'cable', 'chest', 'chest', 'pectorals', '{"deltoids","triceps"}', 'Coloca un balón de estabilidad en un ángulo inclinado. Sujeta las agarraderas del cable a las poleas altas de una máquina de cable. Siéntate sobre el balón de estabilidad de espaldas a la máquina, con los pies firmemente apoyados en el suelo. Sujeta las agarraderas del cable con un agarre prono, con las palmas hacia adelante. Inclínate ligeramente hacia adelante, manteniendo la espalda recta y el core activado. Con un movimiento controlado, lleva los brazos hacia los lados, manteniendo una ligera flexión en los codos. Continúa el movimiento hasta que los brazos queden paralelos al suelo. Haz una pausa por un momento, luego regresa lentamente a la posición inicial. Repite el número de repeticiones deseado.', 'Set up a stability ball at an incline angle. Attach the cable handles to the high pulleys of a cable machine. Sit on the stability ball facing away from the machine, with your feet firmly planted on the ground. Grasp the cable handles with an overhand grip, palms facing forward. Lean forward slightly, keeping your back straight and core engaged. With a controlled motion, bring your arms out to the sides, keeping a slight bend in your elbows. Continue the motion until your arms are parallel to the ground. Pause for a moment, then slowly return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0170-27NNGFr.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0170-27NNGFr.gif', '27NNGFr', '© Gym visual — https://gymvisual.com/'),
('0172', 'cable incline pushdown', 'Sujeta una barra recta a una máquina de cable con polea alta. Ponte de pie de espaldas a la máquina con los pies separados a la altura de los hombros. Sujeta la barra con un agarre prono, con las manos un poco más separadas que el ancho de los hombros. Inclínate ligeramente hacia adelante y mantén l', 'back', 'cable', 'back', 'back', 'lats', '{"triceps","shoulders"}', 'Sujeta una barra recta a una máquina de cable con polea alta. Ponte de pie de espaldas a la máquina con los pies separados a la altura de los hombros. Sujeta la barra con un agarre prono, con las manos un poco más separadas que el ancho de los hombros. Inclínate ligeramente hacia adelante y mantén la espalda recta. Jala la barra hacia abajo en dirección a tus muslos extendiendo los codos. Haz una pausa por un momento en la parte baja y luego regresa lentamente la barra a la posición inicial. Repite el número de repeticiones deseado.', 'Attach a straight bar to a high pulley cable machine. Stand facing away from the machine with your feet shoulder-width apart. Grasp the bar with an overhand grip, hands slightly wider than shoulder-width apart. Lean forward slightly and keep your back straight. Pull the bar down towards your thighs by extending your elbows. Pause for a moment at the bottom, then slowly return the bar to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0172-1PK5Uo3.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0172-1PK5Uo3.gif', '1PK5Uo3', '© Gym visual — https://gymvisual.com/'),
('0173', 'cable incline triceps extension', 'Ajusta la máquina de cable a una posición de polea baja. Sujeta una barra recta al cable. Ponte de pie de espaldas a la máquina con los pies separados a la altura de los hombros. Sujeta la barra con un agarre prono y extiende los brazos rectos por encima de la cabeza. Inclínate ligeramente hacia ade', 'upper arms', 'cable', 'upper arms', 'upper arms', 'triceps', '{"shoulders"}', 'Ajusta la máquina de cable a una posición de polea baja. Sujeta una barra recta al cable. Ponte de pie de espaldas a la máquina con los pies separados a la altura de los hombros. Sujeta la barra con un agarre prono y extiende los brazos rectos por encima de la cabeza. Inclínate ligeramente hacia adelante, manteniendo la espalda recta y el core activado. Flexiona los codos y baja la barra detrás de la cabeza, manteniendo la parte superior de los brazos cerca de las orejas. Haz una pausa por un momento y luego extiende los brazos de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the cable machine to a low pulley position. Attach a straight bar to the cable. Stand facing away from the machine with your feet shoulder-width apart. Grasp the bar with an overhand grip and extend your arms straight overhead. Lean forward slightly, keeping your back straight and core engaged. Bend your elbows and lower the bar behind your head, keeping your upper arms close to your ears. Pause for a moment, then extend your arms back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0173-Hx1WC8I.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0173-Hx1WC8I.gif', 'Hx1WC8I', '© Gym visual — https://gymvisual.com/'),
('0174', 'cable judo flip', 'Ponte de pie frente a la máquina de cable con los pies separados a la altura de los hombros. Sujeta la agarradera del cable con ambas manos a la altura del pecho, con las palmas hacia abajo. Activa el core y rota el torso hacia la derecha, jalando el cable a través del cuerpo. Mientras rotas, gira e', 'waist', 'cable', 'waist', 'waist', 'abs', '{"obliques","shoulders"}', 'Ponte de pie frente a la máquina de cable con los pies separados a la altura de los hombros. Sujeta la agarradera del cable con ambas manos a la altura del pecho, con las palmas hacia abajo. Activa el core y rota el torso hacia la derecha, jalando el cable a través del cuerpo. Mientras rotas, gira el pie de atrás y permite que las caderas roten de forma natural. Extiende los brazos completamente y termina el movimiento llevando la agarradera del cable por encima del hombro. Vuelve a la posición inicial revirtiendo el movimiento, rotando el torso de regreso al centro. Repite el movimiento en el lado opuesto. Continúa alternando lados durante el número de repeticiones deseado.', 'Stand facing the cable machine with your feet shoulder-width apart. Hold the cable handle with both hands at chest level, palms facing down. Engage your core and rotate your torso to the right, pulling the cable across your body. As you rotate, pivot your back foot and allow your hips to rotate naturally. Extend your arms fully and finish the movement by flipping the cable handle over your shoulder. Return to the starting position by reversing the movement, rotating your torso back to the center. Repeat the movement on the opposite side. Continue alternating sides for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0174-MvQPqVW.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0174-MvQPqVW.gif', 'MvQPqVW', '© Gym visual — https://gymvisual.com/'),
('0860', 'cable kickback', 'Ponte de pie frente a una máquina de cable con los pies separados a la altura de los hombros. Sujeta la agarradera del cable con la mano derecha y retrocede un paso para crear tensión en el cable. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda ', 'upper arms', 'cable', 'upper arms', 'upper arms', 'triceps', '{"shoulders"}', 'Ponte de pie frente a una máquina de cable con los pies separados a la altura de los hombros. Sujeta la agarradera del cable con la mano derecha y retrocede un paso para crear tensión en el cable. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta. Mantén la parte superior del brazo cerca del cuerpo y el codo flexionado en un ángulo de 90 grados. Extiende el antebrazo hacia atrás, enderezando el brazo por completo. Haz una pausa por un momento, luego regresa lentamente a la posición inicial. Repite el número de repeticiones deseado, luego cambia de lado.', 'Stand facing a cable machine with your feet shoulder-width apart. Hold the cable handle with your right hand and step back to create tension in the cable. Bend your knees slightly and hinge forward at the hips, keeping your back straight. Keep your upper arm close to your body and your elbow bent at a 90-degree angle. Extend your forearm backward, straightening your arm fully. Pause for a moment, then slowly return to the starting position. Repeat for the desired number of repetitions, then switch sides.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0860-HEJ6DIX.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0860-HEJ6DIX.gif', 'HEJ6DIX', '© Gym visual — https://gymvisual.com/'),
('0175', 'cable kneeling crunch', 'Sujeta una agarradera de cuerda a una polea alta y ponte de rodillas de espaldas a la máquina. Sujeta la agarradera de cuerda con ambas manos y colócala detrás de la cabeza, manteniendo los codos hacia afuera a los lados. Manteniendo las caderas inmóviles, flexiona la cintura y encoge el torso hacia', 'waist', 'cable', 'waist', 'waist', 'abs', '{"obliques"}', 'Sujeta una agarradera de cuerda a una polea alta y ponte de rodillas de espaldas a la máquina. Sujeta la agarradera de cuerda con ambas manos y colócala detrás de la cabeza, manteniendo los codos hacia afuera a los lados. Manteniendo las caderas inmóviles, flexiona la cintura y encoge el torso hacia los muslos. Haz una pausa por un momento en la parte inferior, luego regresa lentamente a la posición inicial. Repite el número de repeticiones deseado.', 'Attach a rope handle to a high pulley and kneel down facing away from the machine. Hold the rope handle with both hands and place it behind your head, keeping your elbows out to the sides. Keeping your hips stationary, flex your waist and crunch your torso down towards your thighs. Pause for a moment at the bottom, then slowly return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0175-WW95auq.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0175-WW95auq.gif', 'WW95auq', '© Gym visual — https://gymvisual.com/'),
('3697', 'cable kneeling rear delt row (with rope) (male)', 'Sujeta una agarradera de cuerda a una polea baja y ponte de rodillas frente a la máquina. Sujeta la cuerda con un agarre neutro (las palmas una frente a la otra) y extiende los brazos completamente frente a ti. Manteniendo la espalda recta y el core activado, jala la cuerda hacia el cuerpo retrayend', 'shoulders', 'cable', 'shoulders', 'shoulders', 'delts', '{"trapezius","rhomboids","biceps"}', 'Sujeta una agarradera de cuerda a una polea baja y ponte de rodillas frente a la máquina. Sujeta la cuerda con un agarre neutro (las palmas una frente a la otra) y extiende los brazos completamente frente a ti. Manteniendo la espalda recta y el core activado, jala la cuerda hacia el cuerpo retrayendo los omóplatos. Aprieta los omóplatos al final del movimiento y mantén la posición por una breve pausa. Libera lentamente la tensión y vuelve a la posición inicial. Repite el número de repeticiones deseado.', 'Attach a rope handle to a low cable pulley and kneel down facing the machine. Grasp the rope with a neutral grip (palms facing each other) and extend your arms fully in front of you. Keeping your back straight and core engaged, pull the rope towards your body by retracting your shoulder blades. Squeeze your shoulder blades together at the end of the movement and hold for a brief pause. Slowly release the tension and return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3697-G61cXLk.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3697-G61cXLk.gif', 'G61cXLk', '© Gym visual — https://gymvisual.com/'),
('0176', 'cable kneeling triceps extension', 'Sujeta una agarradera de cuerda a una polea alta y ponte de rodillas frente a la máquina de cable. Sujeta la cuerda con un agarre neutro (las palmas una frente a la otra) y lleva las manos a los lados de la cabeza. Mantén los codos cerca de la cabeza y la parte superior de los brazos inmóvil durante', 'upper arms', 'cable', 'upper arms', 'upper arms', 'triceps', '{"shoulders"}', 'Sujeta una agarradera de cuerda a una polea alta y ponte de rodillas frente a la máquina de cable. Sujeta la cuerda con un agarre neutro (las palmas una frente a la otra) y lleva las manos a los lados de la cabeza. Mantén los codos cerca de la cabeza y la parte superior de los brazos inmóvil durante todo el ejercicio. Extiende los antebrazos contrayendo los tríceps hasta que los brazos queden completamente extendidos. Haz una pausa por un momento y luego vuelve lentamente a la posición inicial flexionando los codos. Repite el número de repeticiones deseado.', 'Attach a rope handle to a high pulley and kneel down facing the cable machine. Grasp the rope with a neutral grip (palms facing each other) and bring your hands to the sides of your head. Keep your elbows close to your head and your upper arms stationary throughout the exercise. Extend your forearms by contracting your triceps until your arms are fully extended. Pause for a moment, then slowly return to the starting position by bending your elbows. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0176-KWdF2JI.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0176-KWdF2JI.gif', 'KWdF2JI', '© Gym visual — https://gymvisual.com/'),
('2330', 'cable lat pulldown full range of motion', 'Siéntate en la máquina de jalón al pecho con las rodillas colocadas debajo de las almohadillas. Sujeta la barra del cable con un agarre prono, un poco más separado que el ancho de los hombros. Inclínate ligeramente hacia atrás y mantén el pecho elevado, conservando un ligero arco en la zona lumbar. ', 'back', 'cable', 'back', 'back', 'lats', '{"biceps","rhomboids","rear deltoids"}', 'Siéntate en la máquina de jalón al pecho con las rodillas colocadas debajo de las almohadillas. Sujeta la barra del cable con un agarre prono, un poco más separado que el ancho de los hombros. Inclínate ligeramente hacia atrás y mantén el pecho elevado, conservando un ligero arco en la zona lumbar. Jala la barra hacia la parte superior del pecho, apretando los omóplatos entre sí. Haz una pausa por un momento en la parte baja del movimiento y luego suelta lentamente la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on the lat pulldown machine with your knees positioned under the pads. Grasp the cable bar with an overhand grip, slightly wider than shoulder-width apart. Lean back slightly and keep your chest up, maintaining a slight arch in your lower back. Pull the bar down towards your upper chest, squeezing your shoulder blades together. Pause for a moment at the bottom of the movement, then slowly release the bar back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2330-LEprlgG.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2330-LEprlgG.gif', 'LEprlgG', '© Gym visual — https://gymvisual.com/'),
('0177', 'cable lateral pulldown (with rope attachment)', 'Sujeta un accesorio de cuerda a la máquina de cable en una posición alta. Ponte de pie frente a la máquina con los pies separados a la altura de los hombros. Sujeta la cuerda con un agarre prono, con las palmas una frente a la otra. Mantén la espalda recta e inclínate ligeramente hacia atrás. Jala l', 'back', 'cable', 'back', 'back', 'lats', '{"biceps","forearms"}', 'Sujeta un accesorio de cuerda a la máquina de cable en una posición alta. Ponte de pie frente a la máquina con los pies separados a la altura de los hombros. Sujeta la cuerda con un agarre prono, con las palmas una frente a la otra. Mantén la espalda recta e inclínate ligeramente hacia atrás. Jala la cuerda hacia los costados, apretando los omóplatos entre sí. Haz una pausa por un momento en la parte baja del movimiento. Libera lentamente la tensión y permite que la cuerda vuelva a la posición inicial. Repite el número de repeticiones deseado.', 'Attach a rope attachment to the cable machine at a high position. Stand facing the machine with your feet shoulder-width apart. Grasp the rope with an overhand grip, palms facing each other. Keep your back straight and lean slightly back. Pull the rope down towards your sides, squeezing your shoulder blades together. Pause for a moment at the bottom of the movement. Slowly release the tension and allow the rope to return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0177-CuaWCmC.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0177-CuaWCmC.gif', 'CuaWCmC', '© Gym visual — https://gymvisual.com/'),
('2616', 'cable lateral pulldown with v-bar', 'Siéntate en la máquina de jalón de cable y agarra el accesorio en V con un agarre prono. Ajusta la almohadilla de rodillas para que tus muslos queden asegurados debajo de ella. Mantén la espalda recta e inclínate ligeramente hacia atrás. Jala el accesorio en V hacia la parte superior del pecho mante', 'back', 'cable', 'back', 'back', 'lats', '{"biceps","forearms"}', 'Siéntate en la máquina de jalón de cable y agarra el accesorio en V con un agarre prono. Ajusta la almohadilla de rodillas para que tus muslos queden asegurados debajo de ella. Mantén la espalda recta e inclínate ligeramente hacia atrás. Jala el accesorio en V hacia la parte superior del pecho manteniendo los codos cerca del cuerpo. Aprieta los músculos de la espalda en la parte baja del movimiento. Regresa lentamente el accesorio en V a la posición inicial y repite el número de repeticiones deseado.', 'Sit down on the cable pulldown machine and grab the v-bar attachment with an overhand grip. Adjust the knee pad so that your thighs are secured under it. Keep your back straight and lean back slightly. Pull the v-bar down towards your upper chest while keeping your elbows close to your body. Squeeze your back muscles at the bottom of the movement. Slowly return the v-bar to the starting position and repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2616-4c9BhzB.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2616-4c9BhzB.gif', '4c9BhzB', '© Gym visual — https://gymvisual.com/'),
('0178', 'cable lateral raise', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta las agarraderas del cable con un agarre prono. Mantén los brazos rectos y el core activado. Levanta los brazos hacia los lados hasta que queden paralelos al suelo. Haz una pausa por un momento en la parte superior, luego baja le', 'shoulders', 'cable', 'shoulders', 'shoulders', 'delts', '{"traps","triceps"}', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta las agarraderas del cable con un agarre prono. Mantén los brazos rectos y el core activado. Levanta los brazos hacia los lados hasta que queden paralelos al suelo. Haz una pausa por un momento en la parte superior, luego baja lentamente los brazos de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and grasp the cable handles with an overhand grip. Keep your arms straight and your core engaged. Raise your arms out to the sides until they are parallel to the floor. Pause for a moment at the top, then slowly lower your arms back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0178-goJ6ezq.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0178-goJ6ezq.gif', 'goJ6ezq', '© Gym visual — https://gymvisual.com/'),
('0179', 'cable low fly', 'Sujeta las agarraderas a las poleas bajas de una máquina de cable y selecciona un peso adecuado. Ponte de pie en el centro de la máquina con los pies separados a la altura de los hombros y una ligera flexión en las rodillas. Sujeta las agarraderas con un agarre prono y extiende los brazos hacia los ', 'chest', 'cable', 'chest', 'chest', 'pectorals', '{"deltoids","triceps"}', 'Sujeta las agarraderas a las poleas bajas de una máquina de cable y selecciona un peso adecuado. Ponte de pie en el centro de la máquina con los pies separados a la altura de los hombros y una ligera flexión en las rodillas. Sujeta las agarraderas con un agarre prono y extiende los brazos hacia los lados, manteniendo una ligera flexión en los codos. Manteniendo el control, lleva lentamente los brazos hacia adelante con un movimiento amplio, cruzándolos frente al cuerpo. Haz una pausa por un momento en el punto más alto del movimiento, sintiendo el estiramiento en los músculos del pecho. Invierte el movimiento y regresa lentamente los brazos a la posición inicial, manteniendo la tensión en los músculos del pecho durante todo el recorrido. Repite el número de repeticiones deseado.', 'Attach the handles to the low pulleys of a cable machine and select an appropriate weight. Stand in the middle of the machine with your feet shoulder-width apart and a slight bend in your knees. Grasp the handles with an overhand grip and extend your arms out to the sides, keeping a slight bend in your elbows. Maintaining control, slowly bring your arms forward in a sweeping motion, crossing them in front of your body. Pause for a moment at the peak of the movement, feeling the stretch in your chest muscles. Reverse the motion and slowly return your arms to the starting position, keeping tension on your chest muscles throughout. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0179-FVmZVhk.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0179-FVmZVhk.gif', 'FVmZVhk', '© Gym visual — https://gymvisual.com/'),
('0180', 'cable low seated row', 'Siéntate en la máquina con los pies planos sobre los apoyapiés y las rodillas ligeramente flexionadas. Sujeta las agarraderas con un agarre prono, con las palmas hacia abajo. Mantén la espalda recta e inclínate ligeramente hacia adelante, manteniendo una ligera flexión en los codos. Jala las agarrad', 'back', 'cable', 'back', 'back', 'upper back', '{"biceps","forearms"}', 'Siéntate en la máquina con los pies planos sobre los apoyapiés y las rodillas ligeramente flexionadas. Sujeta las agarraderas con un agarre prono, con las palmas hacia abajo. Mantén la espalda recta e inclínate ligeramente hacia adelante, manteniendo una ligera flexión en los codos. Jala las agarraderas hacia el cuerpo, apretando los omóplatos entre sí. Haz una pausa por un momento en el punto máximo del movimiento, luego suelta lentamente las agarraderas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on the machine with your feet flat on the footrests and your knees slightly bent. Grasp the handles with an overhand grip, palms facing down. Keep your back straight and lean slightly forward, maintaining a slight bend in your elbows. Pull the handles towards your body, squeezing your shoulder blades together. Pause for a moment at the peak of the movement, then slowly release the handles back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0180-hvV79Si.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0180-hvV79Si.gif', 'hvV79Si', '© Gym visual — https://gymvisual.com/'),
('1634', 'cable lying bicep curl', 'Coloca una barra recta en una máquina de cable con polea baja. Túmbate boca arriba en un banco plano con los pies apoyados planos en el suelo. Sujeta la barra con agarre supino, manos separadas a la altura de los hombros. Extiende los brazos por completo, manteniendo los codos cerca de los costados.', 'upper arms', 'cable', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Coloca una barra recta en una máquina de cable con polea baja. Túmbate boca arriba en un banco plano con los pies apoyados planos en el suelo. Sujeta la barra con agarre supino, manos separadas a la altura de los hombros. Extiende los brazos por completo, manteniendo los codos cerca de los costados. Manteniendo la parte superior de los brazos inmóvil, exhala y curva la barra hacia los hombros. Haz una pausa breve en la parte alta, apretando los bíceps. Inhala y baja lentamente la barra de vuelta a la posición inicial, extendiendo completamente los brazos. Repite el número de repeticiones deseado.', 'Attach a straight bar to a low pulley cable machine. Lie face up on a flat bench with your feet flat on the ground. Grasp the bar with an underhand grip, hands shoulder-width apart. Extend your arms fully, keeping your elbows close to your sides. Keeping your upper arms stationary, exhale and curl the bar up towards your shoulders. Pause for a moment at the top, squeezing your biceps. Inhale and slowly lower the bar back to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1634-otqIxU4.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1634-otqIxU4.gif', 'otqIxU4', '© Gym visual — https://gymvisual.com/'),
('0182', 'cable lying close-grip curl', 'Coloca una barra recta en una máquina de cable con polea baja. Túmbate boca arriba en un banco plano con los pies apoyados planos en el suelo. Sujeta la barra con agarre supino, manos separadas a la altura de los hombros. Extiende los brazos por completo, manteniendo los codos cerca de los costados.', 'upper arms', 'cable', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Coloca una barra recta en una máquina de cable con polea baja. Túmbate boca arriba en un banco plano con los pies apoyados planos en el suelo. Sujeta la barra con agarre supino, manos separadas a la altura de los hombros. Extiende los brazos por completo, manteniendo los codos cerca de los costados. Manteniendo la parte superior de los brazos inmóvil, curva la barra hacia el pecho contrayendo los bíceps. Haz una pausa breve en la parte alta, apretando los bíceps. Baja lentamente la barra de vuelta a la posición inicial, extendiendo los brazos por completo. Repite el número de repeticiones deseado.', 'Attach a straight bar to a low pulley cable machine. Lie face up on a flat bench with your feet flat on the ground. Grasp the bar with an underhand grip, hands shoulder-width apart. Extend your arms fully, keeping your elbows close to your sides. Keeping your upper arms stationary, curl the bar towards your chest by contracting your biceps. Pause for a moment at the top, squeezing your biceps. Slowly lower the bar back to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0182-61GrD55.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0182-61GrD55.gif', '61GrD55', '© Gym visual — https://gymvisual.com/'),
('0184', 'cable lying extension pullover (with rope attachment)', 'Sujeta una cuerda a una máquina de cable y coloca la polea en la posición más alta. Túmbate en un banco con la cabeza orientada hacia la máquina de cable. Sujeta la cuerda con ambas manos y extiende los brazos rectos por encima del pecho. Manteniendo los brazos rectos, baja lentamente la cuerda detr', 'back', 'cable', 'back', 'back', 'lats', '{"triceps","shoulders"}', 'Sujeta una cuerda a una máquina de cable y coloca la polea en la posición más alta. Túmbate en un banco con la cabeza orientada hacia la máquina de cable. Sujeta la cuerda con ambas manos y extiende los brazos rectos por encima del pecho. Manteniendo los brazos rectos, baja lentamente la cuerda detrás de la cabeza manteniendo el control. Haz una pausa por un momento en la parte baja y luego sube lentamente la cuerda de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Attach a rope to a cable machine and set the pulley at the highest position. Lie down on a bench with your head towards the cable machine. Hold the rope with both hands and extend your arms straight up above your chest. Keeping your arms straight, slowly lower the rope behind your head while maintaining control. Pause for a moment at the bottom, then slowly raise the rope back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0184-Q2Eu1Ax.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0184-Q2Eu1Ax.gif', 'Q2Eu1Ax', '© Gym visual — https://gymvisual.com/'),
('0185', 'cable lying fly', 'Sujeta las agarraderas a los cables y túmbate boca arriba en un banco con los pies apoyados planos en el suelo. Sujeta las agarraderas con las palmas una frente a la otra y los brazos extendidos rectos por encima del pecho. Manteniendo una ligera flexión en los codos, baja los brazos hacia los lados', 'chest', 'cable', 'chest', 'chest', 'pectorals', '{"deltoids","triceps"}', 'Sujeta las agarraderas a los cables y túmbate boca arriba en un banco con los pies apoyados planos en el suelo. Sujeta las agarraderas con las palmas una frente a la otra y los brazos extendidos rectos por encima del pecho. Manteniendo una ligera flexión en los codos, baja los brazos hacia los lados en un amplio arco hasta sentir un estiramiento en el pecho. Haz una pausa por un momento y luego aprieta los músculos del pecho para regresar los brazos a la posición inicial. Repite el número de repeticiones deseado.', 'Attach the handles to the cables and lie flat on a bench with your feet flat on the ground. Hold the handles with your palms facing each other and your arms extended straight above your chest. Keeping a slight bend in your elbows, lower your arms out to the sides in a wide arc until you feel a stretch in your chest. Pause for a moment, then squeeze your chest muscles to bring your arms back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0185-lJJ7Yq8.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0185-lJJ7Yq8.gif', 'lJJ7Yq8', '© Gym visual — https://gymvisual.com/'),
('0186', 'cable lying triceps extension v. 2', 'Sujeta una agarradera de cuerda a una máquina de cable con polea baja. Túmbate boca arriba en un banco plano con la cabeza orientada hacia la máquina de cable. Sujeta la agarradera de cuerda con ambas manos, con las palmas una frente a la otra, y extiende los brazos rectos por encima del pecho. Mant', 'upper arms', 'cable', 'upper arms', 'upper arms', 'triceps', '{"shoulders"}', 'Sujeta una agarradera de cuerda a una máquina de cable con polea baja. Túmbate boca arriba en un banco plano con la cabeza orientada hacia la máquina de cable. Sujeta la agarradera de cuerda con ambas manos, con las palmas una frente a la otra, y extiende los brazos rectos por encima del pecho. Manteniendo la parte superior de los brazos inmóvil, baja lentamente la agarradera de cuerda hacia la frente flexionando los codos. Haz una pausa breve en la parte baja y luego extiende los brazos de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Attach a rope handle to a low pulley cable machine. Lie down on a flat bench facing up, with your head towards the cable machine. Grasp the rope handle with both hands, palms facing each other, and extend your arms straight up over your chest. Keeping your upper arms stationary, slowly lower the rope handle towards your forehead by bending your elbows. Pause for a moment at the bottom, then extend your arms back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0186-uxJcFUU.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0186-uxJcFUU.gif', 'uxJcFUU', '© Gym visual — https://gymvisual.com/'),
('0188', 'cable middle fly', 'Sujeta los cables a ambos lados de una máquina de cable a la altura del pecho. Ponte de pie en el centro de la máquina con un pie ligeramente delante del otro. Sujeta las agarraderas con un agarre prono y extiende los brazos hacia los lados. Mantén una ligera flexión en los codos y conserva una leve', 'chest', 'cable', 'chest', 'chest', 'pectorals', '{"deltoids","triceps"}', 'Sujeta los cables a ambos lados de una máquina de cable a la altura del pecho. Ponte de pie en el centro de la máquina con un pie ligeramente delante del otro. Sujeta las agarraderas con un agarre prono y extiende los brazos hacia los lados. Mantén una ligera flexión en los codos y conserva una leve inclinación hacia adelante. Activa los músculos del pecho y lleva los brazos hacia adelante con un movimiento amplio. Haz una pausa por un momento en el centro y luego regresa lentamente los brazos a la posición inicial. Repite el número de repeticiones deseado.', 'Attach cables to both sides of a cable machine at chest height. Stand in the center of the machine with one foot slightly in front of the other. Grasp the handles with an overhand grip and extend your arms out to the sides. Keep a slight bend in your elbows and maintain a slight forward lean. Engage your chest muscles and bring your arms forward in a sweeping motion. Pause for a moment at the center, then slowly return your arms back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0188-xLYSdtg.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0188-xLYSdtg.gif', 'xLYSdtg', '© Gym visual — https://gymvisual.com/'),
('0189', 'cable one arm bent over row', 'Ponte de pie frente a una máquina de cable con los pies separados a la altura de los hombros. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta. Sujeta la agarradera del cable con una mano, con la palma hacia adentro, y extiende el brazo por', 'back', 'cable', 'back', 'back', 'upper back', '{"biceps","forearms"}', 'Ponte de pie frente a una máquina de cable con los pies separados a la altura de los hombros. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta. Sujeta la agarradera del cable con una mano, con la palma hacia adentro, y extiende el brazo por completo. Jala la agarradera del cable hacia el cuerpo, manteniendo el codo cerca del costado, hasta que la mano llegue a la parte baja del pecho. Haz una pausa por un momento y luego extiende lentamente el brazo de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia de lado.', 'Stand facing a cable machine with your feet shoulder-width apart. Bend your knees slightly and hinge forward at the hips, keeping your back straight. Grasp the cable handle with one hand, palm facing inward, and extend your arm fully. Pull the cable handle towards your body, keeping your elbow close to your side, until your hand reaches your lower chest. Pause for a moment, then slowly extend your arm back to the starting position. Repeat for the desired number of repetitions, then switch sides.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0189-EIsE3u8.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0189-EIsE3u8.gif', 'EIsE3u8', '© Gym visual — https://gymvisual.com/'),
('0190', 'cable one arm curl', 'Ponte de pie frente a la máquina de cable con los pies separados a la altura de los hombros. Sujeta la agarradera del cable con un agarre supino, con la palma hacia arriba. Mantén el codo cerca del costado y curva lentamente el antebrazo hacia el hombro. Haz una pausa por un momento en la parte supe', 'upper arms', 'cable', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ponte de pie frente a la máquina de cable con los pies separados a la altura de los hombros. Sujeta la agarradera del cable con un agarre supino, con la palma hacia arriba. Mantén el codo cerca del costado y curva lentamente el antebrazo hacia el hombro. Haz una pausa por un momento en la parte superior, luego baja lentamente el antebrazo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand facing the cable machine with your feet shoulder-width apart. Grasp the cable handle with an underhand grip, palm facing up. Keep your elbow close to your side and slowly curl your forearm up towards your shoulder. Pause for a moment at the top, then slowly lower your forearm back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0190-YTur5nR.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0190-YTur5nR.gif', 'YTur5nR', '© Gym visual — https://gymvisual.com/'),
('1262', 'cable one arm decline chest fly', 'Sujeta una agarradera en D a una máquina de cable con polea baja y coloca el banco en un ángulo declinado. Túmbate en el banco con la cabeza orientada hacia la máquina y agarra la agarradera con la mano derecha. Extiende el brazo recto por encima del pecho, manteniendo una ligera flexión en el codo.', 'chest', 'cable', 'chest', 'chest', 'pectorals', '{"shoulders","triceps"}', 'Sujeta una agarradera en D a una máquina de cable con polea baja y coloca el banco en un ángulo declinado. Túmbate en el banco con la cabeza orientada hacia la máquina y agarra la agarradera con la mano derecha. Extiende el brazo recto por encima del pecho, manteniendo una ligera flexión en el codo. Con un movimiento controlado, baja el brazo hacia el lado hasta que la mano quede alineada con el hombro. Haz una pausa por un momento y luego invierte el movimiento para regresar el brazo a la posición inicial. Repite el número de repeticiones deseado y luego cambia al brazo izquierdo y repite el ejercicio.', 'Attach a D-handle to a low pulley cable machine and set the bench to a decline angle. Lie down on the bench with your head towards the machine and grab the handle with your right hand. Extend your arm straight up above your chest, keeping a slight bend in your elbow. With a controlled motion, lower your arm out to the side until your hand is in line with your shoulder. Pause for a moment, then reverse the motion and bring your arm back to the starting position. Repeat for the desired number of repetitions, then switch to your left arm and repeat the exercise.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1262-w4dLzSx.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1262-w4dLzSx.gif', 'w4dLzSx', '© Gym visual — https://gymvisual.com/'),
('1263', 'cable one arm fly on exercise ball', 'Siéntate sobre un balón de ejercicio con los pies apoyados planos en el suelo y la espalda recta. Sujeta una agarradera del cable con una mano y extiende el brazo hacia el lado, paralelo al suelo. Mantén el codo ligeramente flexionado y la palma hacia adelante. Lleva lentamente el brazo a través del', 'chest', 'cable', 'chest', 'chest', 'pectorals', '{"deltoids","triceps"}', 'Siéntate sobre un balón de ejercicio con los pies apoyados planos en el suelo y la espalda recta. Sujeta una agarradera del cable con una mano y extiende el brazo hacia el lado, paralelo al suelo. Mantén el codo ligeramente flexionado y la palma hacia adelante. Lleva lentamente el brazo a través del cuerpo, apretando los músculos del pecho. Haz una pausa por un momento al final del movimiento, luego regresa lentamente a la posición inicial. Repite el número de repeticiones deseado, luego cambia de lado.', 'Sit on an exercise ball with your feet flat on the ground and your back straight. Hold a cable handle in one hand and extend your arm out to the side, parallel to the ground. Keep your elbow slightly bent and your palm facing forward. Slowly bring your arm across your body, squeezing your chest muscles. Pause for a moment at the end of the movement, then slowly return to the starting position. Repeat for the desired number of repetitions, then switch sides.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1263-hHy8tQG.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1263-hHy8tQG.gif', 'hHy8tQG', '© Gym visual — https://gymvisual.com/'),
('1264', 'cable one arm incline fly on exercise ball', 'Siéntate sobre un balón de ejercicio con los pies apoyados planos en el suelo y la espalda contra un banco inclinado. Sujeta una agarradera del cable con una mano, con el brazo extendido y la palma hacia adentro. Manteniendo una ligera flexión en el codo, baja lentamente el brazo hacia el lado hasta', 'chest', 'cable', 'chest', 'chest', 'pectorals', '{"deltoids","triceps"}', 'Siéntate sobre un balón de ejercicio con los pies apoyados planos en el suelo y la espalda contra un banco inclinado. Sujeta una agarradera del cable con una mano, con el brazo extendido y la palma hacia adentro. Manteniendo una ligera flexión en el codo, baja lentamente el brazo hacia el lado hasta que la mano quede alineada con el hombro. Haz una pausa por un momento y luego aprieta los músculos del pecho para regresar el brazo a la posición inicial. Repite el número de repeticiones deseado, luego cambia de brazo.', 'Sit on an exercise ball with your feet flat on the ground and your back against an incline bench. Hold a cable handle in one hand with your arm extended and palm facing inward. Keeping a slight bend in your elbow, slowly lower your arm out to the side until your hand is in line with your shoulder. Pause for a moment, then squeeze your chest muscles to bring your arm back to the starting position. Repeat for the desired number of repetitions, then switch arms.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1264-P14Dz9D.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1264-P14Dz9D.gif', 'P14Dz9D', '© Gym visual — https://gymvisual.com/'),
('1265', 'cable one arm incline press', 'Ajusta la máquina de cable a una posición de polea baja. Siéntate en un banco inclinado de espaldas a la máquina de cable. Sujeta la agarradera con una mano y llévala hasta la altura del hombro. Coloca los pies firmemente en el suelo y mantén una posición estable. Empuja la agarradera hacia adelante', 'chest', 'cable', 'chest', 'chest', 'pectorals', '{"deltoids","triceps"}', 'Ajusta la máquina de cable a una posición de polea baja. Siéntate en un banco inclinado de espaldas a la máquina de cable. Sujeta la agarradera con una mano y llévala hasta la altura del hombro. Coloca los pies firmemente en el suelo y mantén una posición estable. Empuja la agarradera hacia adelante y hacia arriba, extendiendo el brazo por completo. Haz una pausa breve en la parte más alta, luego baja lentamente la agarradera de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia de lado.', 'Adjust the cable machine to a low pulley position. Sit on an incline bench facing away from the cable machine. Grasp the handle with one hand and bring it up to shoulder height. Position your feet firmly on the ground and maintain a stable position. Press the handle forward and upward, extending your arm fully. Pause for a moment at the top, then slowly lower the handle back to the starting position. Repeat for the desired number of repetitions, then switch sides.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1265-GKEH6jj.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1265-GKEH6jj.gif', 'GKEH6jj', '© Gym visual — https://gymvisual.com/'),
('1266', 'cable one arm incline press on exercise ball', 'Siéntate sobre un balón de ejercicio con los pies apoyados planos en el suelo y la espalda contra un banco inclinado. Sujeta una agarradera del cable con una mano y coloca el brazo en un ángulo de 90 grados con el codo flexionado. Empuja la agarradera del cable hacia adelante y hacia arriba, extendi', 'chest', 'cable', 'chest', 'chest', 'pectorals', '{"shoulders","triceps"}', 'Siéntate sobre un balón de ejercicio con los pies apoyados planos en el suelo y la espalda contra un banco inclinado. Sujeta una agarradera del cable con una mano y coloca el brazo en un ángulo de 90 grados con el codo flexionado. Empuja la agarradera del cable hacia adelante y hacia arriba, extendiendo el brazo por completo. Haz una pausa breve en la parte más alta, luego baja lentamente la agarradera del cable de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia al otro brazo.', 'Sit on an exercise ball with your feet flat on the ground and your back resting against an incline bench. Hold a cable handle in one hand and position your arm at a 90-degree angle with your elbow bent. Press the cable handle forward and upward, extending your arm fully. Pause for a moment at the top, then slowly lower the cable handle back to the starting position. Repeat for the desired number of repetitions, then switch to the other arm.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1266-6t00BsF.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1266-6t00BsF.gif', '6t00BsF', '© Gym visual — https://gymvisual.com/'),
('0191', 'cable one arm lateral bent-over', 'Ponte de pie con los pies separados a la altura de los hombros, frente a una máquina de cable. Sujeta la agarradera con una mano y retrocede un paso para crear tensión en el cable. Inclínate hacia adelante desde la cintura, manteniendo la espalda recta y el core activado. Extiende el brazo hacia el ', 'chest', 'cable', 'chest', 'chest', 'pectorals', '{"deltoids","trapezius"}', 'Ponte de pie con los pies separados a la altura de los hombros, frente a una máquina de cable. Sujeta la agarradera con una mano y retrocede un paso para crear tensión en el cable. Inclínate hacia adelante desde la cintura, manteniendo la espalda recta y el core activado. Extiende el brazo hacia el lado, paralelo al suelo, con una ligera flexión en el codo. Regresa lentamente el brazo a la posición inicial, manteniendo el control durante todo el movimiento. Repite el número de repeticiones deseado, luego cambia de lado.', 'Stand with your feet shoulder-width apart, facing a cable machine. Grasp the handle with one hand and step back to create tension on the cable. Bend forward at the waist, keeping your back straight and your core engaged. Extend your arm out to the side, parallel to the ground, with a slight bend in your elbow. Slowly bring your arm back to the starting position, maintaining control throughout the movement. Repeat for the desired number of repetitions, then switch sides.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0191-dB07vDu.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0191-dB07vDu.gif', 'dB07vDu', '© Gym visual — https://gymvisual.com/'),
('0192', 'cable one arm lateral raise', 'Ponte de pie con los pies separados a la altura de los hombros, frente a la máquina de cable. Sujeta la agarradera del cable con una mano, con la palma hacia abajo, y colócate lo suficientemente alejado de la máquina para que haya tensión en el cable. Mantén el brazo recto y levántalo lentamente hac', 'shoulders', 'cable', 'shoulders', 'shoulders', 'delts', '{"traps","triceps"}', 'Ponte de pie con los pies separados a la altura de los hombros, frente a la máquina de cable. Sujeta la agarradera del cable con una mano, con la palma hacia abajo, y colócate lo suficientemente alejado de la máquina para que haya tensión en el cable. Mantén el brazo recto y levántalo lentamente hacia el lado hasta que quede paralelo al suelo. Haz una pausa breve en la parte más alta, luego baja lentamente el brazo de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia de lado.', 'Stand with your feet shoulder-width apart, facing the cable machine. Hold the cable handle with one hand, palm facing down, and stand far enough away from the machine so that there is tension on the cable. Keep your arm straight and slowly raise it out to the side until it is parallel to the ground. Pause for a moment at the top, then slowly lower your arm back down to the starting position. Repeat for the desired number of repetitions, then switch sides.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0192-wEulIzp.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0192-wEulIzp.gif', 'wEulIzp', '© Gym visual — https://gymvisual.com/'),
('1633', 'cable one arm preacher curl', 'Ajusta la máquina de cable de modo que la almohadilla para curl en banco scott quede a la altura del pecho. Ponte de pie frente a la máquina de cable con los pies separados a la altura de los hombros. Sujeta la agarradera del cable con un agarre supino y coloca la parte superior del brazo contra la ', 'upper arms', 'cable', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ajusta la máquina de cable de modo que la almohadilla para curl en banco scott quede a la altura del pecho. Ponte de pie frente a la máquina de cable con los pies separados a la altura de los hombros. Sujeta la agarradera del cable con un agarre supino y coloca la parte superior del brazo contra la almohadilla del banco scott. Mantén la espalda recta y el core activado. Curva lentamente la agarradera del cable hacia el hombro, manteniendo la parte superior del brazo contra la almohadilla. Haz una pausa breve en la parte más alta del movimiento, contrayendo los bíceps. Baja lentamente la agarradera del cable de vuelta a la posición inicial. Repite el número de repeticiones deseado. Cambia de brazo y repite el ejercicio.', 'Adjust the cable machine so that the preacher curl pad is at chest height. Stand facing the cable machine with your feet shoulder-width apart. Grasp the cable handle with an underhand grip and position your upper arm against the preacher curl pad. Keep your back straight and your core engaged. Slowly curl the cable handle towards your shoulder, keeping your upper arm against the pad. Pause for a moment at the top of the movement, squeezing your biceps. Slowly lower the cable handle back to the starting position. Repeat for the desired number of repetitions. Switch arms and repeat the exercise.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1633-eHBlPsa.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1633-eHBlPsa.gif', 'eHBlPsa', '© Gym visual — https://gymvisual.com/'),
('1267', 'cable one arm press on exercise ball', 'Siéntate sobre un balón de ejercicio con los pies apoyados planos en el suelo y la espalda recta. Sujeta una agarradera del cable con una mano y coloca el brazo a la altura del pecho, con el codo flexionado. Coloca la otra mano en la cadera para mantener el equilibrio. Empuja la agarradera del cable', 'chest', 'cable', 'chest', 'chest', 'pectorals', '{"shoulders","triceps"}', 'Siéntate sobre un balón de ejercicio con los pies apoyados planos en el suelo y la espalda recta. Sujeta una agarradera del cable con una mano y coloca el brazo a la altura del pecho, con el codo flexionado. Coloca la otra mano en la cadera para mantener el equilibrio. Empuja la agarradera del cable hacia adelante, extendiendo el brazo por completo. Haz una pausa por un momento, luego regresa lentamente a la posición inicial. Repite el número de repeticiones deseado, luego cambia de brazo.', 'Sit on an exercise ball with your feet flat on the ground and your back straight. Hold a cable handle in one hand and position your arm at chest height, elbow bent. Place your other hand on your hip for stability. Press the cable handle forward, extending your arm fully. Pause for a moment, then slowly return to the starting position. Repeat for the desired number of repetitions, then switch arms.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1267-MKIelrR.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1267-MKIelrR.gif', 'MKIelrR', '© Gym visual — https://gymvisual.com/'),
('3563', 'cable one arm pulldown', 'Sujeta una agarradera individual a una máquina de cable con polea alta. Ponte de pie frente a la máquina con los pies separados a la altura de los hombros. Sujeta la agarradera con un agarre prono y extiende el brazo por completo. Mantén la espalda recta y el core activado. Jala la agarradera hacia ', 'back', 'cable', 'back', 'back', 'lats', '{"biceps","forearms"}', 'Sujeta una agarradera individual a una máquina de cable con polea alta. Ponte de pie frente a la máquina con los pies separados a la altura de los hombros. Sujeta la agarradera con un agarre prono y extiende el brazo por completo. Mantén la espalda recta y el core activado. Jala la agarradera hacia abajo en dirección al costado, manteniendo el codo cerca del cuerpo. Haz una pausa por un momento en la parte baja del movimiento, apretando el dorsal. Suelta lentamente la agarradera de vuelta a la posición inicial. Repite el número de repeticiones deseado. Cambia de lado y repite el ejercicio con el otro brazo.', 'Attach a single handle to a high pulley cable machine. Stand facing the machine with your feet shoulder-width apart. Grasp the handle with an overhand grip and extend your arm fully. Keep your back straight and your core engaged. Pull the handle down towards your side while keeping your elbow close to your body. Pause for a moment at the bottom of the movement, squeezing your lat muscle. Slowly release the handle back to the starting position. Repeat for the desired number of repetitions. Switch sides and repeat the exercise with the other arm.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3563-U5INZY6.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3563-U5INZY6.gif', 'U5INZY6', '© Gym visual — https://gymvisual.com/'),
('1635', 'cable one arm reverse preacher curl', 'Ajusta la máquina de cable de modo que la polea quede en la posición más baja. Ponte de pie frente a la máquina de cable con los pies separados a la altura de los hombros. Sujeta la agarradera del cable con un agarre supino y coloca la parte superior del brazo contra la almohadilla del banco scott. ', 'upper arms', 'cable', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ajusta la máquina de cable de modo que la polea quede en la posición más baja. Ponte de pie frente a la máquina de cable con los pies separados a la altura de los hombros. Sujeta la agarradera del cable con un agarre supino y coloca la parte superior del brazo contra la almohadilla del banco scott. Mantén la espalda recta y el core activado durante todo el ejercicio. Curva lentamente el antebrazo hacia el bíceps, manteniendo la parte superior del brazo inmóvil contra la almohadilla. Haz una pausa por un momento en la parte más alta del movimiento, apretando el bíceps. Baja lentamente la agarradera del cable de vuelta a la posición inicial. Repite el número de repeticiones deseado. Cambia de brazo y repite el ejercicio.', 'Adjust the cable machine so that the pulley is at the lowest position. Stand facing the cable machine with your feet shoulder-width apart. Grasp the cable handle with an underhand grip and position your upper arm against the preacher bench pad. Keep your back straight and your core engaged throughout the exercise. Slowly curl your forearm towards your bicep, keeping your upper arm stationary against the pad. Pause for a moment at the top of the movement, squeezing your bicep. Slowly lower the cable handle back to the starting position. Repeat for the desired number of repetitions. Switch arms and repeat the exercise.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1635-ZXnjcOQ.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1635-ZXnjcOQ.gif', 'ZXnjcOQ', '© Gym visual — https://gymvisual.com/'),
('0193', 'cable one arm straight back high row (kneeling)', 'Sujeta una agarradera a una máquina de cable a la altura de la cintura. Ponte de rodillas frente a la máquina de cable y agarra la agarradera con una mano. Mantén la espalda recta y el core activado. Jala la agarradera hacia el pecho, apretando los omóplatos entre sí. Haz una pausa breve en la parte', 'back', 'cable', 'back', 'back', 'upper back', '{"biceps","shoulders"}', 'Sujeta una agarradera a una máquina de cable a la altura de la cintura. Ponte de rodillas frente a la máquina de cable y agarra la agarradera con una mano. Mantén la espalda recta y el core activado. Jala la agarradera hacia el pecho, apretando los omóplatos entre sí. Haz una pausa breve en la parte alta del movimiento. Suelta lentamente la agarradera de vuelta a la posición inicial. Repite el número de repeticiones deseado. Cambia de lado y repite el ejercicio con el otro brazo.', 'Attach a handle to a cable machine at waist height. Kneel down facing the cable machine and grab the handle with one hand. Keep your back straight and your core engaged. Pull the handle towards your chest, squeezing your shoulder blades together. Pause for a moment at the top of the movement. Slowly release the handle back to the starting position. Repeat for the desired number of repetitions. Switch sides and repeat the exercise with the other arm.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0193-WrYPP2g.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0193-WrYPP2g.gif', 'WrYPP2g', '© Gym visual — https://gymvisual.com/'),
('1723', 'cable one arm tricep pushdown', 'Ponte de pie frente a una máquina de cable con un accesorio de barra recta a la altura del pecho. Sujeta la barra con un agarre prono y retrocede un paso para crear tensión en el cable. Coloca los pies separados a la altura de los hombros y flexiona ligeramente las rodillas. Mantén la espalda recta ', 'upper arms', 'cable', 'upper arms', 'upper arms', 'triceps', '{"forearms"}', 'Ponte de pie frente a una máquina de cable con un accesorio de barra recta a la altura del pecho. Sujeta la barra con un agarre prono y retrocede un paso para crear tensión en el cable. Coloca los pies separados a la altura de los hombros y flexiona ligeramente las rodillas. Mantén la espalda recta y el core activado durante todo el ejercicio. Comienza con el brazo completamente extendido y perpendicular al suelo. Manteniendo la parte superior del brazo inmóvil, exhala y empuja la barra hacia abajo hasta que el brazo quede completamente extendido. Haz una pausa por un momento, luego inhala y regresa lentamente a la posición inicial. Repite el número de repeticiones deseado, luego cambia de brazo.', 'Stand facing a cable machine with a straight bar attachment at chest height. Grasp the bar with an overhand grip and step back to create tension in the cable. Position your feet shoulder-width apart and slightly bend your knees. Keep your back straight and core engaged throughout the exercise. Start with your arm fully extended and perpendicular to the floor. Keeping your upper arm stationary, exhale and push the bar down until your arm is fully extended. Pause for a moment, then inhale and slowly return to the starting position. Repeat for the desired number of repetitions, then switch arms.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1723-qRZ5S1N.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1723-qRZ5S1N.gif', 'qRZ5S1N', '© Gym visual — https://gymvisual.com/'),
('1636', 'cable overhead curl', 'Sujeta una barra recta a una máquina de cable con polea alta. Ponte de pie frente a la máquina con los pies separados a la altura de los hombros. Sujeta la barra con agarre supino, manos separadas a la altura de los hombros. Mantén los codos cerca de los costados y los brazos superiores quietos. Exh', 'upper arms', 'cable', 'upper arms', 'upper arms', 'biceps', '{"forearms","shoulders"}', 'Sujeta una barra recta a una máquina de cable con polea alta. Ponte de pie frente a la máquina con los pies separados a la altura de los hombros. Sujeta la barra con agarre supino, manos separadas a la altura de los hombros. Mantén los codos cerca de los costados y los brazos superiores quietos. Exhala y curva la barra hacia la frente, manteniendo la parte superior de los brazos inmóvil. Haz una pausa por un momento en la parte baja del movimiento, apretando los bíceps. Inhala y regresa lentamente la barra a la posición inicial, extendiendo los brazos por completo. Repite el número de repeticiones deseado.', 'Attach a straight bar to a high pulley cable machine. Stand facing the machine with your feet shoulder-width apart. Grasp the bar with an underhand grip, hands shoulder-width apart. Keep your elbows close to your sides and your upper arms stationary. Exhale and curl the bar down towards your forehead, keeping your upper arms stationary. Pause for a moment at the bottom of the movement, squeezing your biceps. Inhale and slowly return the bar to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1636-wDUqY2u.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1636-wDUqY2u.gif', 'wDUqY2u', '© Gym visual — https://gymvisual.com/'),
('1637', 'cable overhead curl on exercise ball', 'Siéntate sobre un balón de ejercicio y sujeta la agarradera del cable con un agarre supino. Extiende los brazos completamente por encima de la cabeza, manteniendo los codos cerca de las orejas. Curva lentamente el cable hacia la frente, manteniendo la parte superior de los brazos inmóvil. Haz una pa', 'upper arms', 'cable', 'upper arms', 'upper arms', 'biceps', '{"forearms","shoulders"}', 'Siéntate sobre un balón de ejercicio y sujeta la agarradera del cable con un agarre supino. Extiende los brazos completamente por encima de la cabeza, manteniendo los codos cerca de las orejas. Curva lentamente el cable hacia la frente, manteniendo la parte superior de los brazos inmóvil. Haz una pausa breve en la parte más baja del movimiento, luego vuelve lentamente a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on an exercise ball and hold the cable handle with an underhand grip. Extend your arms fully overhead, keeping your elbows close to your ears. Slowly curl the cable down towards your forehead, keeping your upper arms stationary. Pause for a moment at the bottom of the movement, then slowly return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1637-ioTf098.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1637-ioTf098.gif', 'ioTf098', '© Gym visual — https://gymvisual.com/'),
('0194', 'cable overhead triceps extension (rope attachment)', 'Sujeta una cuerda a una máquina de cable en una posición alta. Ponte de pie de espaldas a la máquina con los pies separados a la altura de los hombros. Sujeta la cuerda con ambas manos, con las palmas una frente a la otra, y lleva las manos por encima de la cabeza. Mantén la parte superior de los br', 'upper arms', 'cable', 'upper arms', 'upper arms', 'triceps', '{"shoulders"}', 'Sujeta una cuerda a una máquina de cable en una posición alta. Ponte de pie de espaldas a la máquina con los pies separados a la altura de los hombros. Sujeta la cuerda con ambas manos, con las palmas una frente a la otra, y lleva las manos por encima de la cabeza. Mantén la parte superior de los brazos cerca de la cabeza y los codos apuntando hacia adelante. Baja lentamente la cuerda detrás de la cabeza flexionando los codos. Haz una pausa breve y luego extiende los brazos de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Attach a rope to a cable machine at a high position. Stand facing away from the machine with your feet shoulder-width apart. Grasp the rope with both hands, palms facing each other, and bring your hands above your head. Keep your upper arms close to your head and your elbows pointing forward. Slowly lower the rope behind your head by bending your elbows. Pause for a moment, then extend your arms back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0194-2IxROQ1.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0194-2IxROQ1.gif', '2IxROQ1', '© Gym visual — https://gymvisual.com/'),
('1319', 'cable palm rotational row', 'Sujeta una agarradera a una máquina de cable a la altura de la cintura. Ponte de pie frente a la máquina con los pies separados a la altura de los hombros. Sujeta la agarradera con un agarre prono, con las palmas hacia abajo. Retrocede un paso para crear tensión en el cable, manteniendo la espalda r', 'back', 'cable', 'back', 'back', 'upper back', '{"biceps","forearms"}', 'Sujeta una agarradera a una máquina de cable a la altura de la cintura. Ponte de pie frente a la máquina con los pies separados a la altura de los hombros. Sujeta la agarradera con un agarre prono, con las palmas hacia abajo. Retrocede un paso para crear tensión en el cable, manteniendo la espalda recta y las rodillas ligeramente flexionadas. Jala la agarradera hacia el cuerpo, rotando las palmas hacia arriba mientras lo haces. Aprieta los omóplatos al final del movimiento. Suelta lentamente la agarradera de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Attach a handle to a cable machine at waist height. Stand facing the machine with your feet shoulder-width apart. Grasp the handle with an overhand grip, palms facing down. Step back to create tension on the cable, keeping your back straight and knees slightly bent. Pull the handle towards your body, rotating your palms to face upwards as you do so. Squeeze your shoulder blades together at the end of the movement. Slowly release the handle back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1319-OmQ8w0p.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1319-OmQ8w0p.gif', 'OmQ8w0p', '© Gym visual — https://gymvisual.com/'),
('0195', 'cable preacher curl', 'Ajusta la máquina de cable de modo que la almohadilla para curl en banco scott quede a la altura del pecho. Siéntate en el banco scott y coloca la parte superior de los brazos sobre la almohadilla, agarrando el accesorio del cable con un agarre supino. Mantén la espalda recta y los codos pegados a l', 'upper arms', 'cable', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ajusta la máquina de cable de modo que la almohadilla para curl en banco scott quede a la altura del pecho. Siéntate en el banco scott y coloca la parte superior de los brazos sobre la almohadilla, agarrando el accesorio del cable con un agarre supino. Mantén la espalda recta y los codos pegados a los costados. Curva lentamente el accesorio del cable hacia los hombros, apretando los bíceps en la parte más alta del movimiento. Haz una pausa por un momento y luego baja lentamente el accesorio del cable de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the cable machine so that the preacher curl pad is at chest height. Sit on the preacher curl bench and place your upper arms on the pad, gripping the cable attachment with an underhand grip. Keep your back straight and your elbows tucked in at your sides. Slowly curl the cable attachment up towards your shoulders, squeezing your biceps at the top of the movement. Pause for a moment, then slowly lower the cable attachment back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0195-P2lNrGL.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0195-P2lNrGL.gif', 'P2lNrGL', '© Gym visual — https://gymvisual.com/'),
('1268', 'cable press on exercise ball', 'Siéntate sobre un balón de ejercicio con los pies apoyados planos en el suelo y las rodillas en un ángulo de 90 grados. Sujeta las agarraderas del cable a la altura del pecho con las palmas hacia abajo y los codos flexionados. Activa el core y empuja las agarraderas del cable hacia adelante hasta qu', 'chest', 'cable', 'chest', 'chest', 'pectorals', '{"shoulders","triceps"}', 'Siéntate sobre un balón de ejercicio con los pies apoyados planos en el suelo y las rodillas en un ángulo de 90 grados. Sujeta las agarraderas del cable a la altura del pecho con las palmas hacia abajo y los codos flexionados. Activa el core y empuja las agarraderas del cable hacia adelante hasta que los brazos queden completamente extendidos. Haz una pausa por un momento y luego libera lentamente la tensión, regresando las agarraderas del cable a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on an exercise ball with your feet flat on the ground and your knees at a 90-degree angle. Hold the cable handles at chest height with your palms facing down and your elbows bent. Engage your core and press the cable handles forward until your arms are fully extended. Pause for a moment, then slowly release the tension and bring the cable handles back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1268-vAwm6rK.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1268-vAwm6rK.gif', 'vAwm6rK', '© Gym visual — https://gymvisual.com/'),
('0196', 'cable pull through (with rope)', 'Ponte de pie de espaldas a la máquina de cable con los pies separados a la altura de los hombros. Agarra el accesorio de cuerda con ambas manos y da un paso hacia adelante, creando tensión en el cable. Flexiona las caderas y baja la parte superior del cuerpo hasta que quede paralela al suelo, manten', 'upper legs', 'cable', 'upper legs', 'upper legs', 'glutes', '{"hamstrings","lower back"}', 'Ponte de pie de espaldas a la máquina de cable con los pies separados a la altura de los hombros. Agarra el accesorio de cuerda con ambas manos y da un paso hacia adelante, creando tensión en el cable. Flexiona las caderas y baja la parte superior del cuerpo hasta que quede paralela al suelo, manteniendo la espalda recta. Activa los glúteos y los isquiotibiales para llevar el cuerpo de vuelta hacia arriba, a la posición inicial. Repite el número de repeticiones deseado.', 'Stand facing away from the cable machine with your feet shoulder-width apart. Grab the rope attachment with both hands and step forward, creating tension in the cable. Bend at the hips and lower your upper body until it is parallel to the ground, keeping your back straight. Engage your glutes and hamstrings to pull your body back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0196-OM46QHm.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0196-OM46QHm.gif', 'OM46QHm', '© Gym visual — https://gymvisual.com/'),
('0198', 'cable pulldown', 'Ajusta la máquina de jalón de cable de modo que el asiento quede a una altura cómoda y la almohadilla de rodillas esté asegurada. Siéntate con la espalda recta y los pies apoyados planos en el suelo. Sujeta la barra del cable con un agarre prono, un poco más separado que el ancho de los hombros. Inc', 'back', 'cable', 'back', 'back', 'lats', '{"biceps","forearms"}', 'Ajusta la máquina de jalón de cable de modo que el asiento quede a una altura cómoda y la almohadilla de rodillas esté asegurada. Siéntate con la espalda recta y los pies apoyados planos en el suelo. Sujeta la barra del cable con un agarre prono, un poco más separado que el ancho de los hombros. Inclínate ligeramente hacia atrás y activa el core. Jala la barra del cable hacia el pecho, apretando los omóplatos entre sí. Haz una pausa por un momento en la parte baja del movimiento y luego suelta lentamente la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the cable pulldown machine so that the seat is at a comfortable height and the knee pad is secured. Sit on the seat with your back straight and your feet flat on the ground. Grasp the cable bar with an overhand grip, slightly wider than shoulder-width apart. Lean back slightly and engage your core. Pull the cable bar down towards your chest, squeezing your shoulder blades together. Pause for a moment at the bottom of the movement, then slowly release the bar back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0198-RVwzP10.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0198-RVwzP10.gif', 'RVwzP10', '© Gym visual — https://gymvisual.com/'),
('0197', 'cable pulldown (pro lat bar)', 'Ajusta la altura del asiento para que tus muslos queden paralelos al suelo y tus pies queden apoyados planos en el suelo. Sujeta la barra de jalón con un agarre prono, un poco más separado que el ancho de los hombros. Siéntate e inclínate ligeramente hacia atrás, manteniendo el pecho elevado y la es', 'back', 'cable', 'back', 'back', 'lats', '{"biceps","forearms"}', 'Ajusta la altura del asiento para que tus muslos queden paralelos al suelo y tus pies queden apoyados planos en el suelo. Sujeta la barra de jalón con un agarre prono, un poco más separado que el ancho de los hombros. Siéntate e inclínate ligeramente hacia atrás, manteniendo el pecho elevado y la espalda recta. Jala la barra hacia el pecho, apretando los omóplatos entre sí. Haz una pausa por un momento en la parte baja del movimiento y luego suelta lentamente la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the seat height so that your thighs are parallel to the ground and your feet are flat on the floor. Grasp the lat bar with an overhand grip, slightly wider than shoulder-width apart. Sit down and lean back slightly, keeping your chest up and your back straight. Pull the bar down towards your chest, squeezing your shoulder blades together. Pause for a moment at the bottom of the movement, then slowly release the bar back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0197-qdRxqCj.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0197-qdRxqCj.gif', 'qdRxqCj', '© Gym visual — https://gymvisual.com/'),
('1638', 'cable pulldown bicep curl', 'Sujeta una barra recta a la máquina de cable en el ajuste más alto. Ponte de pie frente a la máquina con los pies separados a la altura de los hombros. Sujeta la barra con agarre supino, manos separadas a la altura de los hombros. Mantén los codos cerca de los costados y los brazos superiores quieto', 'upper arms', 'cable', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Sujeta una barra recta a la máquina de cable en el ajuste más alto. Ponte de pie frente a la máquina con los pies separados a la altura de los hombros. Sujeta la barra con agarre supino, manos separadas a la altura de los hombros. Mantén los codos cerca de los costados y los brazos superiores quietos. Exhala y curva lentamente la barra hacia los muslos, manteniendo las muñecas rectas. Haz una pausa por un momento en la parte baja del movimiento, apretando los bíceps. Inhala y regresa lentamente la barra a la posición inicial, extendiendo los brazos por completo. Repite el número de repeticiones deseado.', 'Attach a straight bar to the cable machine at the highest setting. Stand facing the machine with your feet shoulder-width apart. Grasp the bar with an underhand grip, hands shoulder-width apart. Keep your elbows close to your sides and your upper arms stationary. Exhale and slowly curl the bar down towards your thighs, keeping your wrists straight. Pause for a moment at the bottom of the movement, squeezing your biceps. Inhale and slowly return the bar to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1638-QTXKWPh.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1638-QTXKWPh.gif', 'QTXKWPh', '© Gym visual — https://gymvisual.com/'),
('0201', 'cable pushdown', 'Sujeta una barra recta a una máquina de cable con polea alta. Ponte de pie frente a la máquina con los pies separados a la altura de los hombros y una ligera flexión en las rodillas. Sujeta la barra con un agarre prono, con las manos separadas a la altura de los hombros. Mantén los codos cerca de lo', 'upper arms', 'cable', 'upper arms', 'upper arms', 'triceps', '{"forearms"}', 'Sujeta una barra recta a una máquina de cable con polea alta. Ponte de pie frente a la máquina con los pies separados a la altura de los hombros y una ligera flexión en las rodillas. Sujeta la barra con un agarre prono, con las manos separadas a la altura de los hombros. Mantén los codos cerca de los costados y los brazos superiores quietos. Exhala y empuja la barra hacia abajo hasta que los codos queden completamente extendidos. Haz una pausa por un momento, luego inhala y regresa lentamente la barra a la posición inicial. Repite el número de repeticiones deseado.', 'Attach a straight bar to a high pulley cable machine. Stand facing the machine with your feet shoulder-width apart and a slight bend in your knees. Grasp the bar with an overhand grip, hands shoulder-width apart. Keep your elbows close to your sides and your upper arms stationary. Exhale and push the bar down until your elbows are fully extended. Pause for a moment, then inhale and slowly return the bar to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0201-3ZflifB.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0201-3ZflifB.gif', '3ZflifB', '© Gym visual — https://gymvisual.com/'),
('0199', 'cable pushdown (straight arm) v. 2', 'Sujeta una barra recta a una máquina de cable con polea alta. Ponte de pie frente a la máquina con los pies separados a la altura de los hombros y una ligera flexión en las rodillas. Sujeta la barra con un agarre prono, manteniendo los brazos rectos y las palmas hacia abajo. Activa el core y mantén ', 'back', 'cable', 'back', 'back', 'lats', '{"triceps","shoulders"}', 'Sujeta una barra recta a una máquina de cable con polea alta. Ponte de pie frente a la máquina con los pies separados a la altura de los hombros y una ligera flexión en las rodillas. Sujeta la barra con un agarre prono, manteniendo los brazos rectos y las palmas hacia abajo. Activa el core y mantén la espalda recta mientras exhalas y empujas la barra hacia abajo en dirección a los muslos. Haz una pausa por un momento en la parte baja y luego regresa lentamente la barra a la posición inicial mientras inhalas. Repite el número de repeticiones deseado.', 'Attach a straight bar to a high pulley cable machine. Stand facing the machine with your feet shoulder-width apart and a slight bend in your knees. Grasp the bar with an overhand grip, keeping your arms straight and your palms facing down. Engage your core and keep your back straight as you exhale and push the bar down towards your thighs. Pause for a moment at the bottom, then slowly return the bar to the starting position while inhaling. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0199-PskORrA.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0199-PskORrA.gif', 'PskORrA', '© Gym visual — https://gymvisual.com/'),
('0200', 'cable pushdown (with rope attachment)', 'Sujeta un accesorio de cuerda a una polea alta en una máquina de cable. Ponte de pie frente a la máquina con los pies separados a la altura de los hombros y una ligera flexión en las rodillas. Sujeta la cuerda con un agarre prono, con las palmas una frente a la otra. Mantén los codos cerca de los co', 'upper arms', 'cable', 'upper arms', 'upper arms', 'triceps', '{"forearms"}', 'Sujeta un accesorio de cuerda a una polea alta en una máquina de cable. Ponte de pie frente a la máquina con los pies separados a la altura de los hombros y una ligera flexión en las rodillas. Sujeta la cuerda con un agarre prono, con las palmas una frente a la otra. Mantén los codos cerca de los costados y los brazos superiores quietos durante todo el ejercicio. Exhala y empuja la cuerda hacia abajo extendiendo los codos hasta que los brazos queden completamente extendidos. Haz una pausa por un momento, luego inhala y regresa lentamente a la posición inicial permitiendo que los codos se flexionen. Repite el número de repeticiones deseado.', 'Attach a rope attachment to a high pulley on a cable machine. Stand facing the machine with your feet shoulder-width apart and a slight bend in your knees. Grasp the rope with an overhand grip, palms facing each other. Keep your elbows close to your sides and your upper arms stationary throughout the exercise. Exhale and push the rope downward by extending your elbows until your arms are fully extended. Pause for a moment, then inhale and slowly return to the starting position by allowing your elbows to flex. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0200-dU605di.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0200-dU605di.gif', 'dU605di', '© Gym visual — https://gymvisual.com/'),
('0202', 'cable rear delt row (stirrups)', 'Sujeta un asa de estribo a una polea de cable baja y ponte de pie frente a la máquina. Sujeta el asa con la mano izquierda y retrocede un paso con el pie derecho, colocando el cuerpo en un ligero ángulo. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la e', 'shoulders', 'cable', 'shoulders', 'shoulders', 'delts', '{"trapezius","rhomboids","biceps"}', 'Sujeta un asa de estribo a una polea de cable baja y ponte de pie frente a la máquina. Sujeta el asa con la mano izquierda y retrocede un paso con el pie derecho, colocando el cuerpo en un ligero ángulo. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta y el core activado. Con el brazo izquierdo extendido y la palma hacia abajo, jala el asa hacia el pecho retrayendo el omóplato. Haz una pausa por un momento en la parte más alta del movimiento, apretando el omóplato. Suelta lentamente el asa de vuelta a la posición inicial y repite el número de repeticiones deseado. Cambia de lado y repite el ejercicio con el brazo derecho.', 'Attach a stirrup handle to a low cable pulley and stand facing the machine. Grasp the handle with your left hand and take a step back with your right foot, positioning your body at a slight angle. Bend your knees slightly and hinge forward at the hips, keeping your back straight and your core engaged. With your left arm extended and your palm facing down, pull the handle towards your chest by retracting your shoulder blade. Pause for a moment at the top of the movement, squeezing your shoulder blade. Slowly release the handle back to the starting position and repeat for the desired number of repetitions. Switch sides and repeat the exercise with your right arm.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0202-yUdIGNs.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0202-yUdIGNs.gif', 'yUdIGNs', '© Gym visual — https://gymvisual.com/'),
('0203', 'cable rear delt row (with rope)', 'Sujeta una agarradera de cuerda a una máquina de cable con polea baja. Ponte de pie frente a la máquina con los pies separados a la altura de los hombros. Sujeta la agarradera de cuerda con un agarre prono, con las palmas una frente a la otra. Flexiona ligeramente las rodillas e inclínate hacia adel', 'shoulders', 'cable', 'shoulders', 'shoulders', 'delts', '{"trapezius","rhomboids","biceps"}', 'Sujeta una agarradera de cuerda a una máquina de cable con polea baja. Ponte de pie frente a la máquina con los pies separados a la altura de los hombros. Sujeta la agarradera de cuerda con un agarre prono, con las palmas una frente a la otra. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta. Mantén los codos ligeramente flexionados y jala la cuerda hacia el pecho, apretando los omóplatos entre sí. Haz una pausa por un momento en la parte más alta del movimiento y luego libera lentamente la tensión, regresando a la posición inicial. Repite el número de repeticiones deseado.', 'Attach a rope handle to a low pulley cable machine. Stand facing the machine with your feet shoulder-width apart. Grasp the rope handle with an overhand grip, palms facing each other. Bend your knees slightly and hinge forward at the hips, keeping your back straight. Keep your elbows slightly bent and pull the rope towards your chest, squeezing your shoulder blades together. Pause for a moment at the top of the movement, then slowly release the tension and return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0203-wqNPGCg.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0203-wqNPGCg.gif', 'wqNPGCg', '© Gym visual — https://gymvisual.com/'),
('0204', 'cable rear drive', 'Sujeta una agarradera a una máquina de cable con polea baja y ponte de pie de espaldas a la máquina. Sujeta la agarradera con un agarre prono y extiende los brazos rectos frente a ti. Manteniendo los codos inmóviles, jala la agarradera de vuelta hacia el cuerpo, apretando los tríceps al final del mo', 'upper arms', 'cable', 'upper arms', 'upper arms', 'triceps', '{"shoulders","back"}', 'Sujeta una agarradera a una máquina de cable con polea baja y ponte de pie de espaldas a la máquina. Sujeta la agarradera con un agarre prono y extiende los brazos rectos frente a ti. Manteniendo los codos inmóviles, jala la agarradera de vuelta hacia el cuerpo, apretando los tríceps al final del movimiento. Regresa lentamente la agarradera a la posición inicial y repite el número de repeticiones deseado.', 'Attach a handle to a low pulley cable machine and stand facing away from the machine. Grasp the handle with an overhand grip and extend your arms straight out in front of you. Keeping your elbows stationary, pull the handle back towards your body, squeezing your triceps at the end of the movement. Slowly return the handle to the starting position and repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0204-c3QQLPi.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0204-c3QQLPi.gif', 'c3QQLPi', '© Gym visual — https://gymvisual.com/'),
('0205', 'cable rear pulldown', 'Ajusta la máquina de cable de modo que la polea quede en la posición más alta. Siéntate frente a la máquina con los pies apoyados planos en el suelo y las rodillas ligeramente flexionadas. Sujeta el accesorio del cable con un agarre prono, con las manos un poco más separadas que el ancho de los homb', 'back', 'cable', 'back', 'back', 'lats', '{"biceps","rhomboids","rear deltoids"}', 'Ajusta la máquina de cable de modo que la polea quede en la posición más alta. Siéntate frente a la máquina con los pies apoyados planos en el suelo y las rodillas ligeramente flexionadas. Sujeta el accesorio del cable con un agarre prono, con las manos un poco más separadas que el ancho de los hombros. Inclínate ligeramente hacia atrás, manteniendo la espalda recta y el pecho elevado. Jala el accesorio del cable hacia el pecho, apretando los omóplatos entre sí. Haz una pausa por un momento en la parte baja del movimiento y luego suelta lentamente el cable de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the cable machine so that the pulley is at the highest position. Sit facing the machine with your feet flat on the ground and your knees slightly bent. Grasp the cable attachment with an overhand grip, hands slightly wider than shoulder-width apart. Lean back slightly, keeping your back straight and your chest up. Pull the cable attachment down towards your chest, squeezing your shoulder blades together. Pause for a moment at the bottom of the movement, then slowly release the cable back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0205-SpsOSXk.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0205-SpsOSXk.gif', 'SpsOSXk', '© Gym visual — https://gymvisual.com/'),
('0873', 'cable reverse crunch', 'Sujeta un cable a una polea baja y túmbate boca arriba sobre un tapete. Sujeta el cable con ambas manos y extiende los brazos rectos hacia el techo. Flexiona las rodillas y levanta las piernas, llevando los muslos hacia el pecho. Mientras mantienes la parte superior del cuerpo estable, curva la pelv', 'waist', 'cable', 'waist', 'waist', 'abs', '{"hip flexors"}', 'Sujeta un cable a una polea baja y túmbate boca arriba sobre un tapete. Sujeta el cable con ambas manos y extiende los brazos rectos hacia el techo. Flexiona las rodillas y levanta las piernas, llevando los muslos hacia el pecho. Mientras mantienes la parte superior del cuerpo estable, curva la pelvis hacia el pecho, levantando las caderas del tapete. Haz una pausa por un momento en la parte superior, luego baja lentamente las caderas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Attach a cable to a low pulley and lie down facing up on a mat. Hold the cable with both hands and extend your arms straight up towards the ceiling. Bend your knees and lift your legs up, bringing your thighs towards your chest. While keeping your upper body stable, curl your pelvis up towards your chest, lifting your hips off the mat. Pause for a moment at the top, then slowly lower your hips back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0873-RqOtqD7.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0873-RqOtqD7.gif', 'RqOtqD7', '© Gym visual — https://gymvisual.com/'),
('0206', 'cable reverse curl', 'Coloca una barra recta en una máquina de cable con polea baja. Ponte de pie frente a la máquina con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Sujeta la barra con agarre supino, manos separadas a la altura de los hombros. Mantén los codos cerca de los costa', 'upper arms', 'cable', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Coloca una barra recta en una máquina de cable con polea baja. Ponte de pie frente a la máquina con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Sujeta la barra con agarre supino, manos separadas a la altura de los hombros. Mantén los codos cerca de los costados y los brazos superiores quietos durante todo el ejercicio. Exhala y flexiona la barra hacia los hombros, contrayendo los bíceps. Haz una pausa breve en la parte alta, apretando los bíceps. Inhala y baja lentamente la barra de vuelta a la posición inicial, extendiendo completamente los brazos. Repite el número de repeticiones deseado.', 'Attach a straight bar to a low pulley cable machine. Stand facing the machine with your feet shoulder-width apart and your knees slightly bent. Grasp the bar with an underhand grip, hands shoulder-width apart. Keep your elbows close to your sides and your upper arms stationary throughout the exercise. Exhale and curl the bar up towards your shoulders, contracting your biceps. Pause for a moment at the top, squeezing your biceps. Inhale and slowly lower the bar back to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0206-eOG0r6v.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0206-eOG0r6v.gif', 'eOG0r6v', '© Gym visual — https://gymvisual.com/'),
('2406', 'cable reverse grip triceps pushdown (sz-bar) (with arm blaster)', 'Sujeta una barra recta a la máquina de cable en el ajuste más alto. Ponte de pie frente a la máquina de cable con los pies separados a la altura de los hombros. Sujeta la barra con un agarre supino, con las palmas hacia arriba y las manos separadas a la altura de los hombros. Mantén los codos cerca ', 'upper arms', 'cable', 'upper arms', 'upper arms', 'triceps', '{"forearms"}', 'Sujeta una barra recta a la máquina de cable en el ajuste más alto. Ponte de pie frente a la máquina de cable con los pies separados a la altura de los hombros. Sujeta la barra con un agarre supino, con las palmas hacia arriba y las manos separadas a la altura de los hombros. Mantén los codos cerca de los costados y los brazos superiores quietos durante todo el ejercicio. Activa los tríceps y empuja lentamente la barra hacia abajo hasta que los brazos queden completamente extendidos. Haz una pausa por un momento en la parte baja y luego regresa lentamente la barra a la posición inicial. Repite el número de repeticiones deseado.', 'Attach a straight bar to the cable machine at the highest setting. Stand facing the cable machine with your feet shoulder-width apart. Grasp the bar with an underhand grip, palms facing up, and your hands shoulder-width apart. Keep your elbows close to your sides and your upper arms stationary throughout the exercise. Engage your triceps and slowly push the bar down until your arms are fully extended. Pause for a moment at the bottom, then slowly return the bar to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2406-ThKP69G.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2406-ThKP69G.gif', 'ThKP69G', '© Gym visual — https://gymvisual.com/'),
('1413', 'cable reverse one arm curl', 'Ponte de pie frente a una máquina de cable con los pies separados a la altura de los hombros. Sujeta la agarradera del cable con un agarre supino, con la palma hacia abajo. Mantén el codo cerca del costado y curva lentamente el antebrazo hacia el hombro. Haz una pausa por un momento en la parte supe', 'upper arms', 'cable', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ponte de pie frente a una máquina de cable con los pies separados a la altura de los hombros. Sujeta la agarradera del cable con un agarre supino, con la palma hacia abajo. Mantén el codo cerca del costado y curva lentamente el antebrazo hacia el hombro. Haz una pausa por un momento en la parte superior, luego baja lentamente el antebrazo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand facing a cable machine with your feet shoulder-width apart. Grasp the cable handle with an underhand grip, palm facing down. Keep your elbow close to your side and slowly curl your forearm up towards your shoulder. Pause for a moment at the top, then slowly lower your forearm back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1413-gVlnLIJ.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1413-gVlnLIJ.gif', 'gVlnLIJ', '© Gym visual — https://gymvisual.com/'),
('0209', 'cable reverse preacher curl', 'Ajusta la máquina de cable de modo que la almohadilla para curl en banco scott quede a la altura del pecho. Siéntate en el banco scott y coloca la parte superior de los brazos sobre la almohadilla, con las palmas hacia abajo y los codos completamente extendidos. Agarra las agarraderas del cable con ', 'upper arms', 'cable', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ajusta la máquina de cable de modo que la almohadilla para curl en banco scott quede a la altura del pecho. Siéntate en el banco scott y coloca la parte superior de los brazos sobre la almohadilla, con las palmas hacia abajo y los codos completamente extendidos. Agarra las agarraderas del cable con un agarre supino, separadas a la altura de los hombros. Manteniendo la parte superior de los brazos inmóvil, exhala y curva las agarraderas hacia los hombros, contrayendo los bíceps. Haz una pausa breve en la parte más alta del movimiento, contrayendo los bíceps. Inhala y baja lentamente las agarraderas de vuelta a la posición inicial, extendiendo los codos por completo. Repite el número de repeticiones deseado.', 'Adjust the cable machine so that the preacher curl pad is at chest height. Sit on the preacher curl bench and place your upper arms on the pad, with your palms facing down and your elbows fully extended. Grab the cable handles with an underhand grip, shoulder-width apart. Keeping your upper arms stationary, exhale and curl the handles towards your shoulders, contracting your biceps. Pause for a moment at the top of the movement, squeezing your biceps. Inhale and slowly lower the handles back to the starting position, fully extending your elbows. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0209-IwX5NqK.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0209-IwX5NqK.gif', 'IwX5NqK', '© Gym visual — https://gymvisual.com/'),
('0210', 'cable reverse wrist curl', 'Sujeta un cable a una polea baja y siéntate en un banco frente a la máquina de cable. Sujeta la agarradera del cable con un agarre prono, con las palmas hacia abajo. Apoya los antebrazos sobre los muslos, con las muñecas colgando del borde. Manteniendo los antebrazos fijos, exhala y flexiona las muñ', 'lower arms', 'cable', 'lower arms', 'lower arms', 'forearms', '{"forearms","wrists"}', 'Sujeta un cable a una polea baja y siéntate en un banco frente a la máquina de cable. Sujeta la agarradera del cable con un agarre prono, con las palmas hacia abajo. Apoya los antebrazos sobre los muslos, con las muñecas colgando del borde. Manteniendo los antebrazos fijos, exhala y flexiona las muñecas hacia arriba tanto como sea posible. Haz una pausa por un momento en la parte alta, luego inhala y baja lentamente las muñecas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Attach a cable to a low pulley and sit on a bench facing the cable machine. Grasp the cable handle with an overhand grip, palms facing down. Rest your forearms on your thighs, with your wrists hanging off the edge. Keeping your forearms stationary, exhale and curl your wrists upward as far as possible. Pause for a moment at the top, then inhale and slowly lower your wrists back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0210-eYmsEPR.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0210-eYmsEPR.gif', 'eYmsEPR', '© Gym visual — https://gymvisual.com/'),
('0207', 'cable reverse-grip pushdown', 'Sujeta una barra recta a una máquina de cable con polea alta. Ponte de pie frente a la máquina con los pies separados a la altura de los hombros. Sujeta la barra con un agarre supino, con las palmas hacia arriba y las manos separadas a la altura de los hombros. Mantén los codos cerca de los costados', 'upper arms', 'cable', 'upper arms', 'upper arms', 'triceps', '{"forearms"}', 'Sujeta una barra recta a una máquina de cable con polea alta. Ponte de pie frente a la máquina con los pies separados a la altura de los hombros. Sujeta la barra con un agarre supino, con las palmas hacia arriba y las manos separadas a la altura de los hombros. Mantén los codos cerca de los costados y los brazos superiores quietos durante todo el ejercicio. Usando los tríceps, empuja la barra hacia abajo hasta que los brazos queden completamente extendidos y los tríceps contraídos. Haz una pausa por un momento y luego regresa lentamente la barra a la posición inicial. Repite el número de repeticiones deseado.', 'Attach a straight bar to a high pulley cable machine. Stand facing the machine with your feet shoulder-width apart. Grasp the bar with an underhand grip, palms facing up, and your hands shoulder-width apart. Keep your elbows close to your sides and your upper arms stationary throughout the exercise. Using your triceps, push the bar down until your arms are fully extended and your triceps are contracted. Pause for a moment, then slowly return the bar to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0207-VjYliFZ.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0207-VjYliFZ.gif', 'VjYliFZ', '© Gym visual — https://gymvisual.com/'),
('0208', 'cable reverse-grip straight back seated high row', 'Siéntate frente a la máquina de cable con los pies apoyados planos en el suelo. Sujeta el accesorio del cable con un agarre supino, con las palmas hacia arriba y las manos separadas a la altura de los hombros. Mantén la espalda recta e inclínate ligeramente hacia adelante desde las caderas. Jala el ', 'back', 'cable', 'back', 'back', 'upper back', '{"biceps","forearms"}', 'Siéntate frente a la máquina de cable con los pies apoyados planos en el suelo. Sujeta el accesorio del cable con un agarre supino, con las palmas hacia arriba y las manos separadas a la altura de los hombros. Mantén la espalda recta e inclínate ligeramente hacia adelante desde las caderas. Jala el cable hacia el torso retrayendo los omóplatos y apretando los músculos de la espalda. Haz una pausa breve en el punto máximo de la contracción, luego suelta lentamente el cable de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on the seat facing the cable machine with your feet flat on the floor. Grasp the cable attachment with an underhand grip, palms facing up, and your hands shoulder-width apart. Keep your back straight and lean slightly forward from your hips. Pull the cable towards your torso by retracting your shoulder blades and squeezing your back muscles. Pause for a moment at the peak of the contraction, then slowly release the cable back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0208-PNtsX17.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0208-PNtsX17.gif', 'PNtsX17', '© Gym visual — https://gymvisual.com/'),
('1320', 'cable rope crossover seated row', 'Siéntate en la máquina de remo con los pies planos sobre los apoyapiés y las rodillas ligeramente flexionadas. Sujeta las cuerdas del cable con un agarre prono, con las palmas una frente a la otra. Inclínate ligeramente hacia atrás, manteniendo la espalda recta y el core activado. Jala las cuerdas d', 'back', 'cable', 'back', 'back', 'upper back', '{"biceps","forearms"}', 'Siéntate en la máquina de remo con los pies planos sobre los apoyapiés y las rodillas ligeramente flexionadas. Sujeta las cuerdas del cable con un agarre prono, con las palmas una frente a la otra. Inclínate ligeramente hacia atrás, manteniendo la espalda recta y el core activado. Jala las cuerdas del cable hacia el pecho, apretando los omóplatos entre sí. Haz una pausa por un momento en el punto más alto del movimiento, luego libera lentamente la tensión y regresa a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on the rowing machine with your feet flat on the footrests and your knees slightly bent. Grasp the cable ropes with an overhand grip, palms facing each other. Lean back slightly, keeping your back straight and your core engaged. Pull the cable ropes towards your chest, squeezing your shoulder blades together. Pause for a moment at the peak of the movement, then slowly release the tension and return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1320-UFGF6gk.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1320-UFGF6gk.gif', 'UFGF6gk', '© Gym visual — https://gymvisual.com/'),
('1321', 'cable rope elevated seated row', 'Siéntate en el asiento elevado frente a la máquina de cable. Agarra las agarraderas de cuerda con un agarre prono, con las palmas una frente a la otra. Mantén la espalda recta e inclínate ligeramente hacia atrás, conservando una ligera flexión en las rodillas. Jala el cable hacia el cuerpo retrayend', 'back', 'cable', 'back', 'back', 'upper back', '{"biceps","forearms"}', 'Siéntate en el asiento elevado frente a la máquina de cable. Agarra las agarraderas de cuerda con un agarre prono, con las palmas una frente a la otra. Mantén la espalda recta e inclínate ligeramente hacia atrás, conservando una ligera flexión en las rodillas. Jala el cable hacia el cuerpo retrayendo los omóplatos y apretando los músculos de la espalda. Haz una pausa por un momento en la posición de contracción completa. Libera lentamente la tensión y extiende los brazos de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on the elevated seat facing the cable machine. Grab the cable rope handles with an overhand grip, palms facing each other. Keep your back straight and lean slightly back, maintaining a slight bend in your knees. Pull the cable towards your body by retracting your shoulder blades and squeezing your back muscles. Pause for a moment at the fully contracted position. Slowly release the tension and extend your arms back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1321-c8oybX6.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1321-c8oybX6.gif', 'c8oybX6', '© Gym visual — https://gymvisual.com/'),
('1322', 'cable rope extension incline bench row', 'Coloca un banco inclinado a un ángulo de 45 grados y sujeta una máquina de cable a la polea baja. Sujeta una agarradera de cuerda a la máquina de cable y siéntate en el banco inclinado frente a la máquina. Agarra la agarradera de cuerda con un agarre prono e inclínate hacia adelante, manteniendo la ', 'back', 'cable', 'back', 'back', 'upper back', '{"biceps","shoulders"}', 'Coloca un banco inclinado a un ángulo de 45 grados y sujeta una máquina de cable a la polea baja. Sujeta una agarradera de cuerda a la máquina de cable y siéntate en el banco inclinado frente a la máquina. Agarra la agarradera de cuerda con un agarre prono e inclínate hacia adelante, manteniendo la espalda recta. Extiende los brazos por completo, jalando la cuerda hacia la parte superior del pecho mientras mantienes los codos cerca del cuerpo. Aprieta los omóplatos al final del movimiento. Libera lentamente la tensión y vuelve a la posición inicial. Repite el número de repeticiones deseado.', 'Set up an incline bench at a 45-degree angle and attach a cable machine to the low pulley. Attach a rope handle to the cable machine and sit on the incline bench facing the machine. Grab the rope handle with an overhand grip and lean forward, keeping your back straight. Extend your arms fully, pulling the rope towards your upper chest while keeping your elbows close to your body. Squeeze your shoulder blades together at the end of the movement. Slowly release the tension and return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1322-MgKwAAo.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1322-MgKwAAo.gif', 'MgKwAAo', '© Gym visual — https://gymvisual.com/'),
('1639', 'cable rope hammer preacher curl', 'Sujeta un accesorio de cuerda a una máquina de cable con polea baja. Ponte de pie frente a la máquina con los pies separados a la altura de los hombros. Sujeta la cuerda con un agarre neutro (las palmas una frente a la otra). Coloca la parte superior de los brazos contra la almohadilla del banco sco', 'upper arms', 'cable', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Sujeta un accesorio de cuerda a una máquina de cable con polea baja. Ponte de pie frente a la máquina con los pies separados a la altura de los hombros. Sujeta la cuerda con un agarre neutro (las palmas una frente a la otra). Coloca la parte superior de los brazos contra la almohadilla del banco scott, manteniendo los codos ligeramente flexionados. Manteniendo la parte superior de los brazos inmóvil, exhala y curva la cuerda hacia los hombros contrayendo los bíceps. Mantén la posición contraída durante una breve pausa mientras aprietas los bíceps. Inhala y baja lentamente la cuerda de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Attach a rope attachment to a low pulley cable machine. Stand facing the machine with your feet shoulder-width apart. Grasp the rope with a neutral grip (palms facing each other). Position your upper arms against the preacher bench pad, keeping your elbows slightly bent. Keeping your upper arms stationary, exhale and curl the rope towards your shoulders by contracting your biceps. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly lower the rope back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1639-PcPe0P5.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1639-PcPe0P5.gif', 'PcPe0P5', '© Gym visual — https://gymvisual.com/'),
('1724', 'cable rope high pulley overhead tricep extension', 'Sujeta una cuerda a una polea alta y ajusta el peso según corresponda. Ponte de pie de espaldas a la máquina de poleas con los pies separados a la altura de los hombros. Sujeta la cuerda con ambas manos, con las palmas hacia abajo, y lleva las manos por encima de la cabeza. Mantén la parte superior ', 'upper arms', 'cable', 'upper arms', 'upper arms', 'triceps', '{"shoulders"}', 'Sujeta una cuerda a una polea alta y ajusta el peso según corresponda. Ponte de pie de espaldas a la máquina de poleas con los pies separados a la altura de los hombros. Sujeta la cuerda con ambas manos, con las palmas hacia abajo, y lleva las manos por encima de la cabeza. Mantén la parte superior de los brazos cerca de la cabeza y perpendicular al suelo. Baja lentamente la cuerda detrás de la cabeza flexionando los codos. Haz una pausa por un momento y luego extiende los brazos de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Attach a rope to a high pulley and adjust the weight accordingly. Stand facing away from the pulley machine with your feet shoulder-width apart. Grasp the rope with both hands, palms facing down, and bring your hands above your head. Keep your upper arms close to your head and perpendicular to the floor. Slowly lower the rope behind your head by bending your elbows. Pause for a moment, then extend your arms back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1724-NN8nSNT.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1724-NN8nSNT.gif', 'NN8nSNT', '© Gym visual — https://gymvisual.com/'),
('1725', 'cable rope incline tricep extension', 'Sujeta una cuerda a una polea alta y ajusta el banco inclinado a un ángulo cómodo. Ponte de pie de espaldas a la polea con los pies separados a la altura de los hombros. Sujeta la cuerda con un agarre prono y extiende los brazos rectos por encima de la cabeza. Mantén los codos cerca de la cabeza y l', 'upper arms', 'cable', 'upper arms', 'upper arms', 'triceps', '{"shoulders"}', 'Sujeta una cuerda a una polea alta y ajusta el banco inclinado a un ángulo cómodo. Ponte de pie de espaldas a la polea con los pies separados a la altura de los hombros. Sujeta la cuerda con un agarre prono y extiende los brazos rectos por encima de la cabeza. Mantén los codos cerca de la cabeza y la parte superior de los brazos inmóvil durante todo el ejercicio. Baja la cuerda detrás de la cabeza flexionando los codos hasta que los antebrazos toquen los bíceps. Haz una pausa por un momento y luego extiende los brazos de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Attach a rope to a high pulley and adjust the incline bench to a comfortable angle. Stand facing away from the pulley with your feet shoulder-width apart. Grasp the rope with an overhand grip and extend your arms straight overhead. Keep your elbows close to your head and your upper arms stationary throughout the exercise. Lower the rope behind your head by bending your elbows until your forearms touch your biceps. Pause for a moment, then extend your arms back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1725-ZujAdR9.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1725-ZujAdR9.gif', 'ZujAdR9', '© Gym visual — https://gymvisual.com/'),
('1726', 'cable rope lying on floor tricep extension', 'Sujeta una cuerda a una máquina de cable y colócala en la posición más baja. Túmbate en el suelo boca arriba, con la cabeza orientada hacia la máquina de cable. Sujeta la cuerda con ambas manos, con las palmas una frente a la otra, y extiende los brazos rectos hacia el techo. Mantén la parte superio', 'upper arms', 'cable', 'upper arms', 'upper arms', 'triceps', '{"shoulders"}', 'Sujeta una cuerda a una máquina de cable y colócala en la posición más baja. Túmbate en el suelo boca arriba, con la cabeza orientada hacia la máquina de cable. Sujeta la cuerda con ambas manos, con las palmas una frente a la otra, y extiende los brazos rectos hacia el techo. Mantén la parte superior de los brazos inmóvil y baja lentamente la cuerda hacia la frente, flexionando los codos. Haz una pausa breve y luego extiende los brazos de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Attach a rope to a cable machine and set it to the lowest position. Lie on the floor facing up, with your head towards the cable machine. Hold the rope with both hands, palms facing each other, and extend your arms straight up towards the ceiling. Keep your upper arms stationary and slowly lower the rope towards your forehead, bending your elbows. Pause for a moment, then extend your arms back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1726-U3ffHlY.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1726-U3ffHlY.gif', 'U3ffHlY', '© Gym visual — https://gymvisual.com/'),
('1640', 'cable rope one arm hammer preacher curl', 'Sujeta una agarradera de cuerda a una máquina de cable con polea baja. Ponte de pie frente a la máquina con los pies separados a la altura de los hombros. Sujeta la agarradera de cuerda con un agarre supino, con las palmas hacia arriba. Coloca la parte superior del brazo contra la almohadilla del ba', 'upper arms', 'cable', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Sujeta una agarradera de cuerda a una máquina de cable con polea baja. Ponte de pie frente a la máquina con los pies separados a la altura de los hombros. Sujeta la agarradera de cuerda con un agarre supino, con las palmas hacia arriba. Coloca la parte superior del brazo contra la almohadilla del banco scott, manteniendo el codo ligeramente flexionado. Mantén la espalda recta y el core activado durante todo el ejercicio. Curva lentamente la agarradera de cuerda hacia el hombro, manteniendo la parte superior del brazo inmóvil. Aprieta el bíceps en la parte más alta del movimiento y luego baja lentamente la agarradera de cuerda de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia de brazo.', 'Attach a rope handle to a low pulley cable machine. Stand facing the machine with your feet shoulder-width apart. Grasp the rope handle with an underhand grip, palms facing up. Position your upper arm against the preacher bench pad, keeping your elbow slightly bent. Keep your back straight and your core engaged throughout the exercise. Slowly curl the rope handle towards your shoulder, keeping your upper arm stationary. Squeeze your biceps at the top of the movement, then slowly lower the rope handle back to the starting position. Repeat for the desired number of repetitions, then switch arms.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1640-4hATdoB.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1640-4hATdoB.gif', '4hATdoB', '© Gym visual — https://gymvisual.com/'),
('1323', 'cable rope seated row', 'Siéntate en la máquina de remo con los pies planos sobre los apoyapiés y las rodillas ligeramente flexionadas. Sujeta las cuerdas del cable con un agarre prono, con las palmas una frente a la otra. Mantén la espalda recta e inclínate ligeramente hacia adelante, manteniendo una ligera flexión en los ', 'back', 'cable', 'back', 'back', 'upper back', '{"biceps","forearms"}', 'Siéntate en la máquina de remo con los pies planos sobre los apoyapiés y las rodillas ligeramente flexionadas. Sujeta las cuerdas del cable con un agarre prono, con las palmas una frente a la otra. Mantén la espalda recta e inclínate ligeramente hacia adelante, manteniendo una ligera flexión en los codos. Jala las cuerdas del cable hacia el cuerpo, apretando los omóplatos entre sí. Haz una pausa por un momento en el punto más alto del movimiento, luego libera lentamente la tensión y regresa a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on the rowing machine with your feet flat on the footrests and knees slightly bent. Grasp the cable ropes with an overhand grip, palms facing each other. Keep your back straight and lean slightly forward, maintaining a slight bend in your elbows. Pull the cable ropes towards your body, squeezing your shoulder blades together. Pause for a moment at the peak of the movement, then slowly release the tension and return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1323-SJqRxOt.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1323-SJqRxOt.gif', 'SJqRxOt', '© Gym visual — https://gymvisual.com/'),
('0211', 'cable russian twists (on stability ball)', 'Siéntate sobre un balón de estabilidad con los pies apoyados planos en el suelo y las rodillas flexionadas en un ángulo de 90 grados. Sujeta la agarradera del cable con ambas manos y extiende los brazos rectos frente a ti. Inclínate ligeramente hacia atrás manteniendo la espalda recta y el core acti', 'waist', 'cable', 'waist', 'waist', 'abs', '{"obliques","lower back"}', 'Siéntate sobre un balón de estabilidad con los pies apoyados planos en el suelo y las rodillas flexionadas en un ángulo de 90 grados. Sujeta la agarradera del cable con ambas manos y extiende los brazos rectos frente a ti. Inclínate ligeramente hacia atrás manteniendo la espalda recta y el core activado. Gira el torso hacia la derecha, llevando la agarradera del cable hacia la cadera derecha. Haz una pausa por un momento y luego gira el torso hacia la izquierda, llevando la agarradera del cable hacia la cadera izquierda. Continúa alternando los giros el número de repeticiones deseado.', 'Sit on a stability ball with your feet flat on the ground and your knees bent at a 90-degree angle. Hold the cable handle with both hands and extend your arms straight out in front of you. Lean back slightly while keeping your back straight and your core engaged. Twist your torso to the right, bringing the cable handle towards your right hip. Pause for a moment, then twist your torso to the left, bringing the cable handle towards your left hip. Continue alternating twists for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0211-d9Xaxq6.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0211-d9Xaxq6.gif', 'd9Xaxq6', '© Gym visual — https://gymvisual.com/'),
('2144', 'cable seated chest press', 'Ajusta la altura del asiento y las agarraderas del cable a una posición cómoda. Siéntate en el banco con la espalda recta y los pies apoyados planos en el suelo. Sujeta las agarraderas del cable con un agarre prono a la altura del hombro. Empuja las agarraderas hacia adelante y alejándolas del cuerp', 'chest', 'cable', 'chest', 'chest', 'pectorals', '{"shoulders","triceps"}', 'Ajusta la altura del asiento y las agarraderas del cable a una posición cómoda. Siéntate en el banco con la espalda recta y los pies apoyados planos en el suelo. Sujeta las agarraderas del cable con un agarre prono a la altura del hombro. Empuja las agarraderas hacia adelante y alejándolas del cuerpo, extendiendo los brazos por completo. Haz una pausa por un momento y luego regresa lentamente las agarraderas a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the seat height and cable handles to a comfortable position. Sit on the bench with your back straight and feet flat on the floor. Grasp the cable handles with an overhand grip at shoulder height. Push the handles forward and away from your body, extending your arms fully. Pause for a moment, then slowly bring the handles back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2144-nIR4Rwl.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2144-nIR4Rwl.gif', 'nIR4Rwl', '© Gym visual — https://gymvisual.com/'),
('0212', 'cable seated crunch', 'Siéntate en una máquina de cable con los pies apoyados planos en el suelo y las rodillas flexionadas. Sujeta la agarradera del cable con ambas manos y colócala detrás de la cabeza. Activa el abdomen y curva lentamente la parte superior del cuerpo hacia adelante, llevando el pecho hacia las rodillas.', 'waist', 'cable', 'waist', 'waist', 'abs', '{"obliques"}', 'Siéntate en una máquina de cable con los pies apoyados planos en el suelo y las rodillas flexionadas. Sujeta la agarradera del cable con ambas manos y colócala detrás de la cabeza. Activa el abdomen y curva lentamente la parte superior del cuerpo hacia adelante, llevando el pecho hacia las rodillas. Haz una pausa por un momento en la parte alta y luego regresa lentamente a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a cable machine with your feet flat on the ground and your knees bent. Hold the cable handle with both hands and position it behind your head. Engage your abs and slowly curl your upper body forward, bringing your chest towards your knees. Pause for a moment at the top, then slowly return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0212-8xUv4J7.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0212-8xUv4J7.gif', '8xUv4J7', '© Gym visual — https://gymvisual.com/'),
('1641', 'cable seated curl', 'Siéntate en una máquina de cable con los pies apoyados planos en el suelo y la espalda recta. Sujeta el accesorio del cable con un agarre supino, con las palmas hacia arriba y los brazos completamente extendidos. Manteniendo la parte superior de los brazos inmóvil, exhala y curva el accesorio del ca', 'upper arms', 'cable', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Siéntate en una máquina de cable con los pies apoyados planos en el suelo y la espalda recta. Sujeta el accesorio del cable con un agarre supino, con las palmas hacia arriba y los brazos completamente extendidos. Manteniendo la parte superior de los brazos inmóvil, exhala y curva el accesorio del cable hacia los hombros, contrayendo los bíceps. Haz una pausa breve en la parte más alta del movimiento, contrayendo los bíceps. Inhala y baja lentamente el accesorio del cable de vuelta a la posición inicial, extendiendo completamente los brazos. Repite el número de repeticiones deseado.', 'Sit on a cable machine with your feet flat on the ground and your back straight. Grasp the cable attachment with an underhand grip, palms facing up, and your arms fully extended. Keeping your upper arms stationary, exhale and curl the cable attachment towards your shoulders, contracting your biceps. Pause for a moment at the top of the movement, squeezing your biceps. Inhale and slowly lower the cable attachment back to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1641-8oYqOt9.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1641-8oYqOt9.gif', '8oYqOt9', '© Gym visual — https://gymvisual.com/'),
('0213', 'cable seated high row (v-bar)', 'Siéntate en la máquina de cable con los pies apoyados planos en el suelo y las rodillas ligeramente flexionadas. Sujeta el accesorio en V con un agarre prono, con las palmas una frente a la otra y las manos separadas a la altura de los hombros. Mantén la espalda recta e inclínate ligeramente hacia a', 'back', 'cable', 'back', 'back', 'lats', '{"biceps","rhomboids","rear deltoids"}', 'Siéntate en la máquina de cable con los pies apoyados planos en el suelo y las rodillas ligeramente flexionadas. Sujeta el accesorio en V con un agarre prono, con las palmas una frente a la otra y las manos separadas a la altura de los hombros. Mantén la espalda recta e inclínate ligeramente hacia adelante desde las caderas. Jala el accesorio en V hacia el torso retrayendo los omóplatos y apretando los músculos de la espalda. Haz una pausa por un momento en el punto más alto de la contracción, luego libera lentamente la tensión y regresa a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on the cable machine with your feet flat on the floor and your knees slightly bent. Grasp the v-bar attachment with an overhand grip, palms facing each other, and your hands shoulder-width apart. Keep your back straight and lean slightly forward from the hips. Pull the v-bar towards your torso by retracting your shoulder blades and squeezing your back muscles. Pause for a moment at the peak of the contraction, then slowly release the tension and return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0213-pwt0pnM.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0213-pwt0pnM.gif', 'pwt0pnM', '© Gym visual — https://gymvisual.com/'),
('0214', 'cable seated one arm alternate row', 'Siéntate en un banco frente a una máquina de cable con los pies apoyados planos en el suelo y las rodillas ligeramente flexionadas. Sujeta la agarradera con una mano y mantén el brazo completamente extendido frente a ti. Jala la agarradera hacia el cuerpo, retrayendo el omóplato y manteniendo el cod', 'back', 'cable', 'back', 'back', 'upper back', '{"biceps","forearms"}', 'Siéntate en un banco frente a una máquina de cable con los pies apoyados planos en el suelo y las rodillas ligeramente flexionadas. Sujeta la agarradera con una mano y mantén el brazo completamente extendido frente a ti. Jala la agarradera hacia el cuerpo, retrayendo el omóplato y manteniendo el codo cerca del costado. Haz una pausa por un momento en la parte más alta del movimiento, apretando los músculos de la espalda. Suelta lentamente la agarradera de vuelta a la posición inicial. Repite con el otro brazo. Alterna entre los brazos el número de repeticiones deseado.', 'Sit on a bench facing a cable machine with your feet flat on the ground and knees slightly bent. Grasp the handle with one hand and keep your arm fully extended in front of you. Pull the handle towards your body, retracting your shoulder blade and keeping your elbow close to your side. Pause for a moment at the top of the movement, squeezing your back muscles. Slowly release the handle back to the starting position. Repeat with the other arm. Alternate between arms for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0214-vpp9Ku2.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0214-vpp9Ku2.gif', 'vpp9Ku2', '© Gym visual — https://gymvisual.com/'),
('1642', 'cable seated one arm concentration curl', 'Siéntate en un banco con los pies apoyados planos en el suelo y la espalda recta. Sujeta una agarradera del cable con una mano y coloca el codo en la parte interna del muslo, justo arriba de la rodilla. Mantén la parte superior del brazo inmóvil y curva la agarradera del cable hacia el hombro mientr', 'upper arms', 'cable', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Siéntate en un banco con los pies apoyados planos en el suelo y la espalda recta. Sujeta una agarradera del cable con una mano y coloca el codo en la parte interna del muslo, justo arriba de la rodilla. Mantén la parte superior del brazo inmóvil y curva la agarradera del cable hacia el hombro mientras exhalas. Haz una pausa breve en la parte más alta del movimiento, contrayendo los bíceps. Baja lentamente la agarradera del cable de vuelta a la posición inicial mientras inhalas. Repite el número de repeticiones deseado, luego cambia de brazo.', 'Sit on a bench with your feet flat on the floor and your back straight. Hold a cable handle with one hand and place your elbow on the inside of your thigh, just above the knee. Keep your upper arm stationary and curl the cable handle towards your shoulder while exhaling. Pause for a moment at the top of the movement, squeezing your biceps. Slowly lower the cable handle back to the starting position while inhaling. Repeat for the desired number of repetitions, then switch arms.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1642-rZ80Gbp.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1642-rZ80Gbp.gif', 'rZ80Gbp', '© Gym visual — https://gymvisual.com/'),
('1643', 'cable seated overhead curl', 'Siéntate en un banco frente a la máquina de cable con los pies apoyados planos en el suelo. Sujeta el accesorio del cable con un agarre supino, con las palmas hacia arriba y las manos separadas a la altura de los hombros. Mantén la parte superior de los brazos inmóvil y los codos cerca de los costad', 'upper arms', 'cable', 'upper arms', 'upper arms', 'biceps', '{"forearms","shoulders"}', 'Siéntate en un banco frente a la máquina de cable con los pies apoyados planos en el suelo. Sujeta el accesorio del cable con un agarre supino, con las palmas hacia arriba y las manos separadas a la altura de los hombros. Mantén la parte superior de los brazos inmóvil y los codos cerca de los costados. Exhala y flexiona el accesorio del cable hacia los hombros, contrayendo los bíceps. Haz una pausa breve en la parte más alta del movimiento, contrayendo los bíceps. Inhala y baja lentamente el accesorio del cable de vuelta a la posición inicial, extendiendo completamente los brazos. Repite el número de repeticiones deseado.', 'Sit on a bench facing the cable machine with your feet flat on the ground. Grasp the cable attachment with an underhand grip, palms facing up, and your hands shoulder-width apart. Keep your upper arms stationary and your elbows close to your sides. Exhale and curl the cable attachment towards your shoulders, contracting your biceps. Pause for a moment at the top of the movement, squeezing your biceps. Inhale and slowly lower the cable attachment back to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1643-DpWMFP5.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1643-DpWMFP5.gif', 'DpWMFP5', '© Gym visual — https://gymvisual.com/'),
('0215', 'cable seated rear lateral raise', 'Siéntate en un banco frente a la máquina de cable con los pies apoyados planos en el suelo. Sujeta las agarraderas del cable con un agarre prono y extiende los brazos rectos frente a ti. Manteniendo los brazos rectos, levántalos lentamente hacia los lados hasta que queden paralelos al suelo. Haz una', 'shoulders', 'cable', 'shoulders', 'shoulders', 'delts', '{"traps","rhomboids"}', 'Siéntate en un banco frente a la máquina de cable con los pies apoyados planos en el suelo. Sujeta las agarraderas del cable con un agarre prono y extiende los brazos rectos frente a ti. Manteniendo los brazos rectos, levántalos lentamente hacia los lados hasta que queden paralelos al suelo. Haz una pausa por un momento en la parte superior, luego baja lentamente los brazos de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a bench facing the cable machine with your feet flat on the ground. Grasp the cable handles with an overhand grip and extend your arms straight in front of you. Keeping your arms straight, slowly raise them out to the sides until they are parallel to the floor. Pause for a moment at the top, then slowly lower your arms back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0215-x825CZm.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0215-x825CZm.gif', 'x825CZm', '© Gym visual — https://gymvisual.com/'),
('0861', 'cable seated row', 'Siéntate en la máquina de remo con cable con los pies planos sobre los apoyapiés y las rodillas ligeramente flexionadas. Sujeta las agarraderas con un agarre prono, manteniendo la espalda recta y los hombros relajados. Jala las agarraderas hacia el cuerpo, apretando los omóplatos entre sí. Haz una p', 'back', 'cable', 'back', 'back', 'upper back', '{"biceps","forearms"}', 'Siéntate en la máquina de remo con cable con los pies planos sobre los apoyapiés y las rodillas ligeramente flexionadas. Sujeta las agarraderas con un agarre prono, manteniendo la espalda recta y los hombros relajados. Jala las agarraderas hacia el cuerpo, apretando los omóplatos entre sí. Haz una pausa por un momento en el punto máximo del movimiento, luego suelta lentamente las agarraderas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on the cable row machine with your feet flat on the footrests and your knees slightly bent. Grasp the handles with an overhand grip, keeping your back straight and your shoulders relaxed. Pull the handles towards your body, squeezing your shoulder blades together. Pause for a moment at the peak of the movement, then slowly release the handles back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0861-fUBheHs.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0861-fUBheHs.gif', 'fUBheHs', '© Gym visual — https://gymvisual.com/'),
('0216', 'cable seated shoulder internal rotation', 'Siéntate en un banco o silla frente a la máquina de cable con los pies apoyados planos en el suelo. Sujeta la agarradera del cable con el brazo extendido recto frente a ti, paralelo al suelo. Mantén el codo ligeramente flexionado y los omóplatos retraídos hacia atrás y hacia abajo. Rota lentamente e', 'shoulders', 'cable', 'shoulders', 'shoulders', 'delts', '{"rotator cuff","triceps"}', 'Siéntate en un banco o silla frente a la máquina de cable con los pies apoyados planos en el suelo. Sujeta la agarradera del cable con el brazo extendido recto frente a ti, paralelo al suelo. Mantén el codo ligeramente flexionado y los omóplatos retraídos hacia atrás y hacia abajo. Rota lentamente el brazo hacia adentro, llevando la agarradera del cable hacia el centro del cuerpo. Haz una pausa por un momento al final del movimiento, luego regresa lentamente a la posición inicial. Repite el número de repeticiones deseado, luego cambia de brazo.', 'Sit on a bench or chair facing the cable machine with your feet flat on the ground. Hold the cable handle with your arm extended straight out in front of you, parallel to the ground. Keep your elbow slightly bent and your shoulder blades pulled back and down. Slowly rotate your arm inward, bringing the cable handle towards the center of your body. Pause for a moment at the end of the movement, then slowly return to the starting position. Repeat for the desired number of repetitions, then switch arms.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0216-YPoVrBi.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0216-YPoVrBi.gif', 'YPoVrBi', '© Gym visual — https://gymvisual.com/'),
('2399', 'cable seated twist', 'Siéntate en una máquina de cable con los pies apoyados planos en el suelo y las rodillas ligeramente flexionadas. Sujeta la agarradera del cable con ambas manos y extiende los brazos rectos frente a ti. Manteniendo el core activado, rota lentamente el torso hacia un lado, jalando el cable a través d', 'waist', 'cable', 'waist', 'waist', 'abs', '{"obliques"}', 'Siéntate en una máquina de cable con los pies apoyados planos en el suelo y las rodillas ligeramente flexionadas. Sujeta la agarradera del cable con ambas manos y extiende los brazos rectos frente a ti. Manteniendo el core activado, rota lentamente el torso hacia un lado, jalando el cable a través del cuerpo. Haz una pausa por un momento al final del rango de movimiento y luego rota lentamente de vuelta a la posición inicial. Repite del otro lado. Continúa alternando lados durante el número de repeticiones deseado.', 'Sit on a cable machine with your feet flat on the ground and your knees slightly bent. Hold the cable handle with both hands and extend your arms straight in front of you. Keeping your core engaged, slowly rotate your torso to one side, pulling the cable across your body. Pause for a moment at the end of the range of motion, then slowly rotate back to the starting position. Repeat on the other side. Continue alternating sides for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2399-UEjSrKI.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2399-UEjSrKI.gif', 'UEjSrKI', '© Gym visual — https://gymvisual.com/'),
('0218', 'cable seated wide-grip row', 'Siéntate en la máquina de remo con cable con los pies planos sobre los apoyapiés y las rodillas ligeramente flexionadas. Sujeta la agarradera con un agarre prono amplio, palmas hacia abajo. Mantén la espalda recta e inclínate ligeramente hacia adelante desde las caderas. Jala la agarradera hacia la ', 'back', 'cable', 'back', 'back', 'upper back', '{"biceps","forearms"}', 'Siéntate en la máquina de remo con cable con los pies planos sobre los apoyapiés y las rodillas ligeramente flexionadas. Sujeta la agarradera con un agarre prono amplio, palmas hacia abajo. Mantén la espalda recta e inclínate ligeramente hacia adelante desde las caderas. Jala la agarradera hacia la parte baja del pecho, apretando los omóplatos entre sí. Haz una pausa por un momento en el punto más alto de la contracción. Suelta lentamente la agarradera de vuelta a la posición inicial, extendiendo los brazos por completo. Repite el número de repeticiones deseado.', 'Sit on the cable row machine with your feet flat on the footrests and your knees slightly bent. Grasp the handle with a wide overhand grip, palms facing down. Keep your back straight and lean slightly forward from the hips. Pull the handle towards your lower chest, squeezing your shoulder blades together. Pause for a moment at the peak of the contraction. Slowly release the handle back to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0218-qcY50ZD.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0218-qcY50ZD.gif', 'qcY50ZD', '© Gym visual — https://gymvisual.com/'),
('0219', 'cable shoulder press', 'Ajusta la máquina de cable de modo que las agarraderas queden a la altura del hombro. Ponte de pie de espaldas a la máquina con los pies separados a la altura de los hombros. Sujeta las agarraderas con un agarre prono y llévalas hasta la altura del hombro, con los codos flexionados y apuntando hacia', 'shoulders', 'cable', 'shoulders', 'shoulders', 'delts', '{"triceps","upper back"}', 'Ajusta la máquina de cable de modo que las agarraderas queden a la altura del hombro. Ponte de pie de espaldas a la máquina con los pies separados a la altura de los hombros. Sujeta las agarraderas con un agarre prono y llévalas hasta la altura del hombro, con los codos flexionados y apuntando hacia afuera. Empuja las agarraderas hacia arriba hasta que los brazos queden completamente extendidos por encima de la cabeza. Haz una pausa por un momento en la parte alta y luego baja lentamente las agarraderas de vuelta a la altura del hombro. Repite el número de repeticiones deseado.', 'Adjust the cable machine so that the handles are at shoulder height. Stand facing away from the machine with your feet shoulder-width apart. Grasp the handles with an overhand grip and bring them up to shoulder level, with your elbows bent and pointing outwards. Press the handles upwards until your arms are fully extended overhead. Pause for a moment at the top, then slowly lower the handles back down to shoulder level. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0219-PzQanLE.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0219-PzQanLE.gif', 'PzQanLE', '© Gym visual — https://gymvisual.com/'),
('0220', 'cable shrug', 'Ponte de pie frente a la máquina de cable con los pies separados a la altura de los hombros. Sujeta las agarraderas del cable con un agarre prono y deja que los brazos cuelguen frente a ti. Manteniendo los brazos rectos, encoge los hombros hacia las orejas. Mantén la contracción por un momento, lueg', 'back', 'cable', 'back', 'back', 'traps', '{"shoulders"}', 'Ponte de pie frente a la máquina de cable con los pies separados a la altura de los hombros. Sujeta las agarraderas del cable con un agarre prono y deja que los brazos cuelguen frente a ti. Manteniendo los brazos rectos, encoge los hombros hacia las orejas. Mantén la contracción por un momento, luego baja lentamente los hombros de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand facing the cable machine with your feet shoulder-width apart. Grasp the cable handles with an overhand grip and let your arms hang down in front of you. Keeping your arms straight, shrug your shoulders up towards your ears. Hold the contraction for a moment, then slowly lower your shoulders back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0220-Eg98Ft9.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0220-Eg98Ft9.gif', 'Eg98Ft9', '© Gym visual — https://gymvisual.com/'),
('0222', 'cable side bend', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta la agarradera del cable con una mano. Mantén la espalda recta y el core activado. Flexiona lentamente la cintura hacia un lado, bajando la agarradera del cable hacia la rodilla. Haz una pausa breve y luego vuelve a la posición i', 'waist', 'cable', 'waist', 'waist', 'abs', '{"obliques"}', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta la agarradera del cable con una mano. Mantén la espalda recta y el core activado. Flexiona lentamente la cintura hacia un lado, bajando la agarradera del cable hacia la rodilla. Haz una pausa breve y luego vuelve a la posición inicial. Repite del otro lado. Alterna los lados durante el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and grasp the cable handle with one hand. Keep your back straight and your core engaged. Slowly bend sideways at the waist, lowering the cable handle towards your knee. Pause for a moment, then return to the starting position. Repeat on the other side. Alternate sides for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0222-wPypxFY.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0222-wPypxFY.gif', 'wPypxFY', '© Gym visual — https://gymvisual.com/'),
('0221', 'cable side bend crunch (bosu ball)', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando la agarradera del cable con una mano. Coloca la otra mano en la cadera. Activa el core y flexiona lentamente la cintura hacia el lado en que sujetas el cable, manteniendo la espalda recta. Haz una pausa breve en la parte más b', 'waist', 'cable', 'waist', 'waist', 'abs', '{"obliques"}', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando la agarradera del cable con una mano. Coloca la otra mano en la cadera. Activa el core y flexiona lentamente la cintura hacia el lado en que sujetas el cable, manteniendo la espalda recta. Haz una pausa breve en la parte más baja del movimiento, luego vuelve lentamente a la posición inicial. Repite el número de repeticiones deseado, luego cambia de lado.', 'Stand with your feet shoulder-width apart, holding a cable handle in one hand. Place the other hand on your hip. Engage your core and slowly bend sideways towards the hand holding the cable, keeping your back straight. Pause for a moment at the bottom of the movement, then slowly return to the starting position. Repeat for the desired number of repetitions, then switch sides.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0221-qatbkEd.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0221-qatbkEd.gif', 'qatbkEd', '© Gym visual — https://gymvisual.com/'),
('0223', 'cable side crunch', 'Coloca un mango de cable en una polea baja y ponte de pie de lado a la máquina. Agarra el mango con la mano más alejada de la máquina y coloca la otra mano en tu cadera. Coloca los pies separados a la altura de los hombros y flexiona ligeramente las rodillas. Con el abdomen activado, flexiona la cin', 'waist', 'cable', 'waist', 'waist', 'abs', '{"obliques"}', 'Coloca un mango de cable en una polea baja y ponte de pie de lado a la máquina. Agarra el mango con la mano más alejada de la máquina y coloca la otra mano en tu cadera. Coloca los pies separados a la altura de los hombros y flexiona ligeramente las rodillas. Con el abdomen activado, flexiona la cintura hacia el lado, bajando el codo hacia la cadera. Haz una pausa por un momento en la parte inferior, luego regresa lentamente a la posición inicial. Repite el número de repeticiones deseado, luego cambia de lado.', 'Attach a cable handle to a low pulley and stand sideways to the machine. Grasp the handle with the hand furthest from the machine and place your other hand on your hip. Keep your feet shoulder-width apart and your knees slightly bent. With your abs engaged, bend sideways at the waist, bringing your elbow down towards your hip. Pause for a moment at the bottom, then slowly return to the starting position. Repeat for the desired number of repetitions, then switch sides.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0223-q2ADGqV.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0223-q2ADGqV.gif', 'q2ADGqV', '© Gym visual — https://gymvisual.com/'),
('1717', 'cable squat row (with rope attachment)', 'Sujeta una cuerda a una máquina de cable a la altura de la cintura. Ponte de pie frente a la máquina de cable con los pies separados a la altura de los hombros. Flexiona las rodillas y baja el cuerpo hacia una posición de sentadilla, manteniendo la espalda recta y el pecho elevado. Agarra la cuerda ', 'back', 'cable', 'back', 'back', 'lats', '{"biceps","rhomboids","rear deltoids"}', 'Sujeta una cuerda a una máquina de cable a la altura de la cintura. Ponte de pie frente a la máquina de cable con los pies separados a la altura de los hombros. Flexiona las rodillas y baja el cuerpo hacia una posición de sentadilla, manteniendo la espalda recta y el pecho elevado. Agarra la cuerda con un agarre prono, con las manos separadas a la altura de los hombros. Activa el core y tira de la cuerda hacia tu cuerpo, apretando los omóplatos entre sí. Mantén los codos cerca del cuerpo y continúa tirando hasta que las manos lleguen a tu pecho. Haz una pausa breve en la parte alta del movimiento, luego suelta lentamente la cuerda y extiende los brazos de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Attach a rope to a cable machine at waist height. Stand facing the cable machine with your feet shoulder-width apart. Bend your knees and lower your body into a squat position, keeping your back straight and chest up. Grasp the rope with an overhand grip, with your hands shoulder-width apart. Engage your core and pull the rope towards your body, squeezing your shoulder blades together. Keep your elbows close to your body and continue pulling until your hands reach your chest. Pause for a moment at the top of the movement, then slowly release the rope and extend your arms back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1717-f7fnAIB.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1717-f7fnAIB.gif', 'f7fnAIB', '© Gym visual — https://gymvisual.com/'),
('1644', 'cable squatting curl', 'Coloca un mango de cable en el ajuste más bajo de una máquina de cable. Ponte de pie frente a la máquina con los pies separados a la altura de los hombros. Sujeta el mango del cable con un agarre supino, con las palmas hacia arriba y los brazos completamente extendidos. Baja el cuerpo hacia una posi', 'upper arms', 'cable', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Coloca un mango de cable en el ajuste más bajo de una máquina de cable. Ponte de pie frente a la máquina con los pies separados a la altura de los hombros. Sujeta el mango del cable con un agarre supino, con las palmas hacia arriba y los brazos completamente extendidos. Baja el cuerpo hacia una posición de sentadilla, manteniendo la espalda recta y las rodillas detrás de las puntas de los pies. Mientras te agachas, flexiona el mango del cable hacia los hombros, manteniendo los codos cerca de los costados. Haz una pausa breve en la parte alta del movimiento, apretando los bíceps. Baja lentamente el mango del cable de vuelta a la posición inicial, extendiendo completamente los brazos. Repite el número de repeticiones deseado.', 'Attach a cable handle to the lowest setting on a cable machine. Stand facing the machine with your feet shoulder-width apart. Hold the cable handle with an underhand grip, palms facing up, and arms fully extended. Lower your body into a squat position, keeping your back straight and knees behind your toes. As you squat down, curl the cable handle towards your shoulders, keeping your elbows close to your sides. Pause for a moment at the top of the curl, squeezing your biceps. Slowly lower the cable handle back to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1644-3XFdb1Z.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1644-3XFdb1Z.gif', '3XFdb1Z', '© Gym visual — https://gymvisual.com/'),
('0224', 'cable standing back wrist curl', 'Ponte de pie frente a una máquina de cable con los pies separados a la altura de los hombros. Sujeta el mango del cable con un agarre prono, con las palmas hacia abajo. Mantén los brazos rectos y los codos cerca de los costados. Flexiona lentamente las muñecas hacia arriba, llevando el mango del cab', 'lower arms', 'cable', 'lower arms', 'lower arms', 'forearms', '{"biceps","brachialis"}', 'Ponte de pie frente a una máquina de cable con los pies separados a la altura de los hombros. Sujeta el mango del cable con un agarre prono, con las palmas hacia abajo. Mantén los brazos rectos y los codos cerca de los costados. Flexiona lentamente las muñecas hacia arriba, llevando el mango del cable hacia tu cuerpo. Haz una pausa breve en la parte más alta, luego baja lentamente la agarradera del cable de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand facing a cable machine with your feet shoulder-width apart. Hold the cable handle with an overhand grip, palms facing down. Keep your arms straight and your elbows close to your sides. Slowly curl your wrists upward, bringing the cable handle towards your body. Pause for a moment at the top, then slowly lower the cable handle back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0224-VhX2JdE.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0224-VhX2JdE.gif', 'VhX2JdE', '© Gym visual — https://gymvisual.com/'),
('1375', 'cable standing calf raise', 'Ponte de pie frente a una máquina de cable con los pies separados a la altura de los hombros. Sujétate de los mangos de la máquina de cable o coloca una correa de tobillo de cable en tus tobillos. Levanta los talones del suelo extendiendo los tobillos lo más alto posible. Haz una pausa breve en la p', 'lower legs', 'cable', 'lower legs', 'lower legs', 'calves', '{"hamstrings","glutes"}', 'Ponte de pie frente a una máquina de cable con los pies separados a la altura de los hombros. Sujétate de los mangos de la máquina de cable o coloca una correa de tobillo de cable en tus tobillos. Levanta los talones del suelo extendiendo los tobillos lo más alto posible. Haz una pausa breve en la parte alta y luego baja lentamente los talones de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand facing a cable machine with your feet shoulder-width apart. Hold onto the cable machine handles or attach a cable ankle strap to your ankles. Raise your heels off the ground by extending your ankles as high as possible. Pause for a moment at the top, then slowly lower your heels back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1375-yl2IYyy.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1375-yl2IYyy.gif', 'yl2IYyy', '© Gym visual — https://gymvisual.com/'),
('0225', 'cable standing cross-over high reverse fly', 'Coloca un mango en D en cada lado de una máquina de cable a la altura de los hombros. Ponte de pie en el medio de la máquina de cable con los pies separados a la altura de los hombros. Agarra los mangos con un agarre prono y extiende los brazos hacia los lados, con las palmas hacia adelante. Mantén ', 'shoulders', 'cable', 'shoulders', 'shoulders', 'delts', '{"trapezius","rhomboids","rear deltoids"}', 'Coloca un mango en D en cada lado de una máquina de cable a la altura de los hombros. Ponte de pie en el medio de la máquina de cable con los pies separados a la altura de los hombros. Agarra los mangos con un agarre prono y extiende los brazos hacia los lados, con las palmas hacia adelante. Mantén una ligera flexión en los codos y conserva la espalda recta durante todo el ejercicio. Activa los músculos de los hombros y aprieta los omóplatos entre sí mientras tiras de los mangos hacia la parte delantera de tu cuerpo. Haz una pausa breve en el punto máximo del movimiento, luego regresa lentamente a la posición inicial. Repite el número de repeticiones deseado.', 'Attach a D-handle to each side of a cable machine at shoulder height. Stand in the middle of the cable machine with your feet shoulder-width apart. Grasp the handles with an overhand grip and extend your arms out to the sides, palms facing forward. Keep a slight bend in your elbows and maintain a straight back throughout the exercise. Engage your shoulder muscles and squeeze your shoulder blades together as you pull the handles towards the front of your body. Pause for a moment at the peak of the movement, then slowly return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0225-P5p0j8B.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0225-P5p0j8B.gif', 'P5p0j8B', '© Gym visual — https://gymvisual.com/'),
('0226', 'cable standing crunch', 'Coloca un mango de cable en una polea alta y ponte de pie de espaldas a la máquina. Sujeta el mango con ambas manos y colócalo detrás de la cabeza, manteniendo los codos flexionados. Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Con el abdomen', 'waist', 'cable', 'waist', 'waist', 'abs', '{"obliques"}', 'Coloca un mango de cable en una polea alta y ponte de pie de espaldas a la máquina. Sujeta el mango con ambas manos y colócalo detrás de la cabeza, manteniendo los codos flexionados. Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Con el abdomen activado, exhala y flexiona el torso hacia las rodillas, llevando los codos hacia los muslos. Haz una pausa breve en la parte más baja del movimiento, luego vuelve lentamente a la posición inicial. Repite el número de repeticiones deseado.', 'Attach a cable handle to a high pulley and stand facing away from the machine. Hold the handle with both hands and place it behind your head, keeping your elbows bent. Stand with your feet shoulder-width apart and your knees slightly bent. Keeping your abs engaged, exhale and crunch your torso down towards your knees, bringing your elbows towards your thighs. Pause for a moment at the bottom of the movement, then slowly return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0226-jpgqxiS.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0226-jpgqxiS.gif', 'jpgqxiS', '© Gym visual — https://gymvisual.com/'),
('0874', 'cable standing crunch (with rope attachment)', 'Sujeta una cuerda a una máquina de cable a la altura del pecho. Ponte de pie de espaldas a la máquina con los pies separados a la altura de los hombros. Sujeta la cuerda con ambas manos y llévala detrás de la cabeza, manteniendo los codos flexionados. Activa el abdomen y flexiona lentamente el torso', 'waist', 'cable', 'waist', 'waist', 'abs', '{"obliques"}', 'Sujeta una cuerda a una máquina de cable a la altura del pecho. Ponte de pie de espaldas a la máquina con los pies separados a la altura de los hombros. Sujeta la cuerda con ambas manos y llévala detrás de la cabeza, manteniendo los codos flexionados. Activa el abdomen y flexiona lentamente el torso hacia adelante, llevando los codos hacia las rodillas. Haz una pausa por un momento en la parte más alta del movimiento, luego regresa lentamente a la posición inicial. Repite el número de repeticiones deseado.', 'Attach a rope to a cable machine at chest height. Stand facing away from the machine with your feet shoulder-width apart. Hold the rope with both hands and bring it behind your head, keeping your elbows bent. Engage your abs and slowly crunch your torso forward, bringing your elbows towards your knees. Pause for a moment at the top of the crunch, then slowly return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0874-XU3ePuv.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0874-XU3ePuv.gif', 'XU3ePuv', '© Gym visual — https://gymvisual.com/'),
('0227', 'cable standing fly', 'Coloca los mangos en los cables a la altura del pecho. Ponte de pie con los pies separados a la altura de los hombros, de espaldas a la máquina de cable. Agarra los mangos con un agarre prono, con las palmas hacia adelante. Da un paso adelante para crear tensión en los cables. Mantén el core activad', 'chest', 'cable', 'chest', 'chest', 'pectorals', '{"deltoids","triceps"}', 'Coloca los mangos en los cables a la altura del pecho. Ponte de pie con los pies separados a la altura de los hombros, de espaldas a la máquina de cable. Agarra los mangos con un agarre prono, con las palmas hacia adelante. Da un paso adelante para crear tensión en los cables. Mantén el core activado y la espalda recta durante todo el ejercicio. Con una ligera flexión en los codos, lleva lentamente los brazos hacia adelante y júntalos frente al pecho. Aprieta los músculos del pecho en el punto máximo del movimiento. Invierte lentamente el movimiento, regresando los brazos a la posición inicial. Repite el número de repeticiones deseado.', 'Attach the handles to the cables at chest height. Stand with your feet shoulder-width apart, facing away from the cable machine. Grasp the handles with an overhand grip, palms facing forward. Step forward slightly to create tension in the cables. Keep your core engaged and your back straight throughout the exercise. With a slight bend in your elbows, slowly bring your arms forward and together in front of your chest. Squeeze your chest muscles at the peak of the movement. Slowly reverse the movement, returning your arms to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0227-Pr9Rhf4.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0227-Pr9Rhf4.gif', 'Pr9Rhf4', '© Gym visual — https://gymvisual.com/'),
('0228', 'cable standing hip extension', 'Sujeta un cable a una polea baja y ponte de pie de espaldas a la máquina. Coloca el cable alrededor de tu tobillo y ponte de pie con los pies separados a la altura de los hombros. Mantén el core activado y la espalda recta durante todo el ejercicio. Extiende lentamente la pierna hacia atrás, apretan', 'upper legs', 'cable', 'upper legs', 'upper legs', 'glutes', '{"hamstrings","quadriceps"}', 'Sujeta un cable a una polea baja y ponte de pie de espaldas a la máquina. Coloca el cable alrededor de tu tobillo y ponte de pie con los pies separados a la altura de los hombros. Mantén el core activado y la espalda recta durante todo el ejercicio. Extiende lentamente la pierna hacia atrás, apretando los glúteos en la parte alta del movimiento. Haz una pausa breve y luego vuelve a la posición inicial. Repite el número de repeticiones deseado. Cambia de lado y repite con la otra pierna.', 'Attach a cable to a low pulley and stand facing away from the machine. Place the cable around your ankle and stand with your feet shoulder-width apart. Keep your core engaged and your back straight throughout the exercise. Slowly extend your leg straight back, squeezing your glutes at the top of the movement. Pause for a moment, then return to the starting position. Repeat for the desired number of repetitions. Switch sides and repeat with the other leg.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0228-Kpajagk.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0228-Kpajagk.gif', 'Kpajagk', '© Gym visual — https://gymvisual.com/'),
('0229', 'cable standing inner curl', 'Ponte de pie frente a una máquina de cable con los pies separados a la altura de los hombros. Agarra el mango del cable con un agarre supino, con las palmas hacia arriba. Mantén los codos cerca de los costados y los brazos superiores quietos. Exhala y flexiona el mango del cable hacia los hombros, c', 'upper arms', 'cable', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ponte de pie frente a una máquina de cable con los pies separados a la altura de los hombros. Agarra el mango del cable con un agarre supino, con las palmas hacia arriba. Mantén los codos cerca de los costados y los brazos superiores quietos. Exhala y flexiona el mango del cable hacia los hombros, contrayendo los bíceps. Haz una pausa breve en la parte más alta del movimiento, contrayendo los bíceps. Inhala y baja lentamente el mango del cable de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand facing a cable machine with your feet shoulder-width apart. Grasp the cable handle with an underhand grip, palms facing up. Keep your elbows close to your sides and your upper arms stationary. Exhale and curl the cable handle towards your shoulders, contracting your biceps. Pause for a moment at the top of the movement, squeezing your biceps. Inhale and slowly lower the cable handle back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0229-YwnI4ja.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0229-YwnI4ja.gif', 'YwnI4ja', '© Gym visual — https://gymvisual.com/'),
('0230', 'cable standing lift', 'Ponte de pie frente a la máquina de cable con los pies separados a la altura de los hombros. Sujeta el mango del cable con ambas manos y colócalo a la altura de la cintura. Activa el core y mantén la espalda recta durante todo el ejercicio. Manteniendo los brazos rectos, exhala y eleva el mango del ', 'waist', 'cable', 'waist', 'waist', 'abs', '{"obliques","lower back"}', 'Ponte de pie frente a la máquina de cable con los pies separados a la altura de los hombros. Sujeta el mango del cable con ambas manos y colócalo a la altura de la cintura. Activa el core y mantén la espalda recta durante todo el ejercicio. Manteniendo los brazos rectos, exhala y eleva el mango del cable hacia el hombro opuesto, rotando el torso. Haz una pausa breve en la parte alta, luego inhala y baja lentamente el mango del cable de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia de lado.', 'Stand facing the cable machine with your feet shoulder-width apart. Hold the cable handle with both hands and position it at waist height. Engage your core and maintain a straight back throughout the exercise. Keeping your arms straight, exhale and lift the cable handle up towards your opposite shoulder, rotating your torso. Pause for a moment at the top, then inhale and slowly lower the cable handle back to the starting position. Repeat for the desired number of repetitions, then switch sides.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0230-qFpAkpP.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0230-qFpAkpP.gif', 'qFpAkpP', '© Gym visual — https://gymvisual.com/'),
('0231', 'cable standing one arm triceps extension', 'Ponte de pie con los pies separados a la altura de los hombros, frente a la máquina de cable. Sujeta el mango del cable con la mano derecha, con la palma hacia abajo, y coloca el brazo completamente extendido y paralelo al suelo. Mantén el codo quieto y cerca del cuerpo. Flexiona lentamente el codo,', 'upper arms', 'cable', 'upper arms', 'upper arms', 'triceps', '{"shoulders"}', 'Ponte de pie con los pies separados a la altura de los hombros, frente a la máquina de cable. Sujeta el mango del cable con la mano derecha, con la palma hacia abajo, y coloca el brazo completamente extendido y paralelo al suelo. Mantén el codo quieto y cerca del cuerpo. Flexiona lentamente el codo, bajando el mango del cable hacia la parte de atrás de la cabeza. Haz una pausa breve en la parte baja del movimiento, luego extiende el brazo de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia de lado y realiza el ejercicio con el brazo izquierdo.', 'Stand with your feet shoulder-width apart, facing the cable machine. Hold the cable handle with your right hand, palm facing down, and position your arm so that it is fully extended and parallel to the ground. Keep your elbow stationary and close to your body. Slowly bend your elbow, lowering the cable handle towards the back of your head. Pause for a moment at the bottom of the movement, then extend your arm back to the starting position. Repeat for the desired number of repetitions, then switch sides and perform the exercise with your left arm.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0231-sYCcnon.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0231-sYCcnon.gif', 'sYCcnon', '© Gym visual — https://gymvisual.com/'),
('1376', 'cable standing one leg calf raise', 'Ponte de pie frente a una máquina de cable con los pies separados a la altura de los hombros. Sujétate de la máquina de cable para apoyarte. Levanta una pierna del suelo y equilíbrate sobre la otra pierna. Levanta lentamente el talón del suelo, elevando el cuerpo sobre las puntas de los pies. Haz un', 'lower legs', 'cable', 'lower legs', 'lower legs', 'calves', '{"ankles","feet"}', 'Ponte de pie frente a una máquina de cable con los pies separados a la altura de los hombros. Sujétate de la máquina de cable para apoyarte. Levanta una pierna del suelo y equilíbrate sobre la otra pierna. Levanta lentamente el talón del suelo, elevando el cuerpo sobre las puntas de los pies. Haz una pausa por un momento en la parte superior, luego baja lentamente el talón de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia de pierna.', 'Stand facing a cable machine with your feet shoulder-width apart. Hold onto the cable machine for support. Lift one leg off the ground and balance on the other leg. Slowly raise your heel off the ground, lifting your body up onto your toes. Pause for a moment at the top, then slowly lower your heel back down to the starting position. Repeat for the desired number of repetitions, then switch legs.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1376-fgc9Xdl.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1376-fgc9Xdl.gif', 'fgc9Xdl', '© Gym visual — https://gymvisual.com/'),
('0232', 'cable standing pulldown (with rope)', 'Sujeta una cuerda a la máquina de cable en el ajuste más alto. Ponte de pie frente a la máquina con los pies separados a la altura de los hombros. Agarra la cuerda con un agarre prono, con las palmas hacia abajo. Mantén la espalda recta y el core activado durante todo el ejercicio. Tira de la cuerda', 'upper arms', 'cable', 'upper arms', 'upper arms', 'biceps', '{"forearms","shoulders"}', 'Sujeta una cuerda a la máquina de cable en el ajuste más alto. Ponte de pie frente a la máquina con los pies separados a la altura de los hombros. Agarra la cuerda con un agarre prono, con las palmas hacia abajo. Mantén la espalda recta y el core activado durante todo el ejercicio. Tira de la cuerda hacia abajo, hacia los muslos, apretando los bíceps. Haz una pausa breve en la parte baja, luego suelta lentamente la cuerda hacia arriba. Repite el número de repeticiones deseado.', 'Attach a rope to the cable machine at the highest setting. Stand facing the machine with your feet shoulder-width apart. Grasp the rope with an overhand grip, palms facing down. Keep your back straight and core engaged throughout the exercise. Pull the rope down towards your thighs, squeezing your biceps. Pause for a moment at the bottom, then slowly release the rope back up. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0232-CvPn9WV.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0232-CvPn9WV.gif', 'CvPn9WV', '© Gym visual — https://gymvisual.com/'),
('0233', 'cable standing rear delt row (with rope)', 'Ponte de pie frente a una máquina de cable con los pies separados a la altura de los hombros. Sujeta el accesorio del cable con ambas manos, con las palmas una frente a la otra, y retrocede un paso para crear tensión en el cable. Mantén la espalda recta y el core activado. Tira del cable hacia tu cu', 'shoulders', 'cable', 'shoulders', 'shoulders', 'delts', '{"trapezius","rhomboids","biceps"}', 'Ponte de pie frente a una máquina de cable con los pies separados a la altura de los hombros. Sujeta el accesorio del cable con ambas manos, con las palmas una frente a la otra, y retrocede un paso para crear tensión en el cable. Mantén la espalda recta y el core activado. Tira del cable hacia tu cuerpo, apretando los omóplatos entre sí. Haz una pausa breve en el punto máximo del movimiento, luego suelta lentamente el cable de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand facing a cable machine with your feet shoulder-width apart. Hold the cable attachment with both hands, palms facing each other, and step back to create tension in the cable. Keep your back straight and your core engaged. Pull the cable towards your body, squeezing your shoulder blades together. Pause for a moment at the peak of the movement, then slowly release the cable back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0233-ZfyAGhK.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0233-ZfyAGhK.gif', 'ZfyAGhK', '© Gym visual — https://gymvisual.com/'),
('1727', 'cable standing reverse grip one arm overhead tricep extension', 'Ponte de pie de espaldas a la máquina de cable con los pies separados a la altura de los hombros. Sujeta el mango del cable con un agarre supino y extiende el brazo por encima de la cabeza, manteniendo el codo cerca de la cabeza. Mantén el brazo superior quieto y baja lentamente el mango del cable d', 'upper arms', 'cable', 'upper arms', 'upper arms', 'triceps', '{"shoulders"}', 'Ponte de pie de espaldas a la máquina de cable con los pies separados a la altura de los hombros. Sujeta el mango del cable con un agarre supino y extiende el brazo por encima de la cabeza, manteniendo el codo cerca de la cabeza. Mantén el brazo superior quieto y baja lentamente el mango del cable detrás de la cabeza flexionando el codo. Haz una pausa breve en la parte baja, luego extiende el brazo de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia de brazo.', 'Stand facing away from the cable machine with your feet shoulder-width apart. Hold the cable handle with an underhand grip and extend your arm overhead, keeping your elbow close to your head. Keep your upper arm stationary and slowly lower the cable handle behind your head by bending your elbow. Pause for a moment at the bottom, then extend your arm back to the starting position. Repeat for the desired number of repetitions, then switch arms.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1727-i11JWU7.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1727-i11JWU7.gif', 'i11JWU7', '© Gym visual — https://gymvisual.com/'),
('0234', 'cable standing row (v-bar)', 'Ponte de pie frente a la máquina de cable con los pies separados a la altura de los hombros. Agarra el accesorio en V con un agarre prono, con las palmas hacia abajo. Mantén la espalda recta y el core activado. Tira del accesorio en V hacia tu cuerpo, apretando los omóplatos entre sí. Haz una pausa ', 'back', 'cable', 'back', 'back', 'upper back', '{"biceps","shoulders"}', 'Ponte de pie frente a la máquina de cable con los pies separados a la altura de los hombros. Agarra el accesorio en V con un agarre prono, con las palmas hacia abajo. Mantén la espalda recta y el core activado. Tira del accesorio en V hacia tu cuerpo, apretando los omóplatos entre sí. Haz una pausa por un momento en el punto más alto del movimiento, luego libera lentamente la tensión y regresa a la posición inicial. Repite el número de repeticiones deseado.', 'Stand facing the cable machine with your feet shoulder-width apart. Grasp the v-bar attachment with an overhand grip, palms facing down. Keep your back straight and your core engaged. Pull the v-bar towards your body, squeezing your shoulder blades together. Pause for a moment at the peak of the movement, then slowly release the tension and return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0234-4f8RXP8.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0234-4f8RXP8.gif', '4f8RXP8', '© Gym visual — https://gymvisual.com/'),
('0235', 'cable standing shoulder external rotation', 'Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Sujeta el mango del cable con el brazo extendido frente a ti, paralelo al suelo. Mantén el codo ligeramente flexionado y los omóplatos retraídos hacia atrás. Rota lentamente el brazo hacia afuera, ', 'shoulders', 'cable', 'shoulders', 'shoulders', 'delts', '{"rotator cuff","trapezius"}', 'Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Sujeta el mango del cable con el brazo extendido frente a ti, paralelo al suelo. Mantén el codo ligeramente flexionado y los omóplatos retraídos hacia atrás. Rota lentamente el brazo hacia afuera, alejándolo de tu cuerpo, manteniendo el codo en la misma posición. Haz una pausa por un momento al final del movimiento, luego regresa lentamente a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and your knees slightly bent. Hold the cable handle with your arm extended in front of you, parallel to the ground. Keep your elbow slightly bent and your shoulder blades pulled back. Slowly rotate your arm outward, away from your body, while keeping your elbow in the same position. Pause for a moment at the end of the movement, then slowly return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0235-FWdVhcW.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0235-FWdVhcW.gif', 'FWdVhcW', '© Gym visual — https://gymvisual.com/'),
('0236', 'cable standing twist row (v-bar)', 'Coloca un accesorio en V en una máquina de cable a la altura del pecho. Ponte de pie frente a la máquina de cable con los pies separados a la altura de los hombros. Agarra el accesorio en V con un agarre prono, con las palmas hacia abajo. Da un paso atrás para crear tensión en el cable. Mantén la es', 'back', 'cable', 'back', 'back', 'upper back', '{"biceps","shoulders"}', 'Coloca un accesorio en V en una máquina de cable a la altura del pecho. Ponte de pie frente a la máquina de cable con los pies separados a la altura de los hombros. Agarra el accesorio en V con un agarre prono, con las palmas hacia abajo. Da un paso atrás para crear tensión en el cable. Mantén la espalda recta y el core activado durante todo el ejercicio. Tira del accesorio en V hacia tu torso retrayendo los omóplatos y flexionando los codos. Mientras tiras, gira el torso hacia un lado, apretando los omóplatos entre sí. Haz una pausa breve en la parte alta del movimiento, sintiendo la contracción en la parte alta de la espalda. Suelta lentamente la tensión y regresa a la posición inicial, deshaciendo el giro del torso. Repite el movimiento el número de repeticiones deseado, alternando la dirección del giro en cada repetición.', 'Attach a v-bar attachment to a cable machine at chest height. Stand facing the cable machine with your feet shoulder-width apart. Grasp the v-bar with an overhand grip, palms facing down. Take a step back to create tension in the cable. Keep your back straight and core engaged throughout the exercise. Pull the v-bar towards your torso by retracting your shoulder blades and bending your elbows. As you pull, twist your torso to one side, squeezing your shoulder blades together. Pause for a moment at the top of the movement, feeling the contraction in your upper back. Slowly release the tension and return to the starting position, untwisting your torso. Repeat the movement for the desired number of repetitions, alternating the twisting direction with each rep.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0236-JOZhu2h.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0236-JOZhu2h.gif', 'JOZhu2h', '© Gym visual — https://gymvisual.com/'),
('1269', 'cable standing up straight crossovers', 'Ponte de pie en el medio de una máquina de cable con los pies separados a la altura de los hombros. Sujeta los mangos de los cables con las palmas hacia abajo y los brazos extendidos hacia los lados. Manteniendo los brazos rectos, junta las manos frente a tu cuerpo, cruzándolas una sobre la otra. Ha', 'chest', 'cable', 'chest', 'chest', 'pectorals', '{"deltoids","triceps"}', 'Ponte de pie en el medio de una máquina de cable con los pies separados a la altura de los hombros. Sujeta los mangos de los cables con las palmas hacia abajo y los brazos extendidos hacia los lados. Manteniendo los brazos rectos, junta las manos frente a tu cuerpo, cruzándolas una sobre la otra. Haz una pausa breve, luego regresa lentamente a la posición inicial, manteniendo los brazos extendidos. Repite el número de repeticiones deseado.', 'Stand in the middle of a cable machine with your feet shoulder-width apart. Hold the handles of the cables with your palms facing down and your arms extended straight out to the sides. Keeping your arms straight, bring your hands together in front of your body, crossing them over each other. Pause for a moment, then slowly return to the starting position, keeping your arms extended. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1269-UKWTJWR.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1269-UKWTJWR.gif', 'UKWTJWR', '© Gym visual — https://gymvisual.com/'),
('0238', 'cable straight arm pulldown', 'Coloca una barra recta en la polea alta de una máquina de cable. Ponte de pie frente a la máquina con los pies separados a la altura de los hombros. Sujeta la barra con un agarre prono, manteniendo los brazos rectos y las palmas hacia abajo. Activa los dorsales y tira de la barra hacia abajo, hacia ', 'back', 'cable', 'back', 'back', 'lats', '{"shoulders","biceps"}', 'Coloca una barra recta en la polea alta de una máquina de cable. Ponte de pie frente a la máquina con los pies separados a la altura de los hombros. Sujeta la barra con un agarre prono, manteniendo los brazos rectos y las palmas hacia abajo. Activa los dorsales y tira de la barra hacia abajo, hacia los muslos, manteniendo los brazos rectos durante todo el movimiento. Haz una pausa por un momento en la parte baja y luego regresa lentamente la barra a la posición inicial. Repite el número de repeticiones deseado.', 'Attach a straight bar to the high pulley of a cable machine. Stand facing the machine with your feet shoulder-width apart. Grasp the bar with an overhand grip, keeping your arms straight and your palms facing down. Engage your lats and pull the bar down towards your thighs, keeping your arms straight throughout the movement. Pause for a moment at the bottom, then slowly return the bar to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0238-x69MAlq.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0238-x69MAlq.gif', 'x69MAlq', '© Gym visual — https://gymvisual.com/'),
('0237', 'cable straight arm pulldown (with rope)', 'Sujeta una cuerda a la máquina de cable en el ajuste más alto. Ponte de pie frente a la máquina con los pies separados a la altura de los hombros. Agarra la cuerda con ambas manos, con las palmas hacia abajo. Extiende completamente los brazos frente a ti, manteniendo los codos ligeramente flexionado', 'back', 'cable', 'back', 'back', 'lats', '{"biceps","forearms"}', 'Sujeta una cuerda a la máquina de cable en el ajuste más alto. Ponte de pie frente a la máquina con los pies separados a la altura de los hombros. Agarra la cuerda con ambas manos, con las palmas hacia abajo. Extiende completamente los brazos frente a ti, manteniendo los codos ligeramente flexionados. Activa los dorsales y tira lentamente de la cuerda hacia abajo, hacia los muslos, manteniendo los brazos rectos. Haz una pausa por un momento en la parte inferior, luego suelta lentamente la tensión y regresa a la posición inicial. Repite el número de repeticiones deseado.', 'Attach a rope to the cable machine at the highest setting. Stand facing the machine with your feet shoulder-width apart. Grasp the rope with both hands, palms facing down. Extend your arms fully in front of you, keeping your elbows slightly bent. Engage your lats and slowly pull the rope down towards your thighs, keeping your arms straight. Pause for a moment at the bottom, then slowly release the tension and return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0237-DT14T9T.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0237-DT14T9T.gif', 'DT14T9T', '© Gym visual — https://gymvisual.com/'),
('0239', 'cable straight back seated row', 'Siéntate en la máquina de remo con cable con los pies planos sobre los apoyapiés y las rodillas ligeramente flexionadas. Agarra los mangos del cable con un agarre prono, con las palmas hacia abajo. Mantén la espalda recta e inclínate ligeramente hacia adelante desde las caderas. Tira de los mangos d', 'back', 'cable', 'back', 'back', 'upper back', '{"biceps","forearms","shoulders"}', 'Siéntate en la máquina de remo con cable con los pies planos sobre los apoyapiés y las rodillas ligeramente flexionadas. Agarra los mangos del cable con un agarre prono, con las palmas hacia abajo. Mantén la espalda recta e inclínate ligeramente hacia adelante desde las caderas. Tira de los mangos del cable hacia tu cuerpo, apretando los omóplatos entre sí. Haz una pausa por un momento en el punto máximo del movimiento, luego suelta lentamente las agarraderas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on the cable row machine with your feet flat on the footrests and your knees slightly bent. Grasp the cable handles with an overhand grip, palms facing down. Keep your back straight and lean slightly forward from the hips. Pull the cable handles towards your body, squeezing your shoulder blades together. Pause for a moment at the peak of the movement, then slowly release the handles back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0239-Tq6gbK6.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0239-Tq6gbK6.gif', 'Tq6gbK6', '© Gym visual — https://gymvisual.com/'),
('0240', 'cable supine reverse fly', 'Coloca un mango en D en una máquina de cable con polea baja y túmbate boca abajo en un banco plano. Agarra el mango en D con cada mano, con las palmas hacia abajo, y extiende los brazos frente a ti. Manteniendo los brazos rectos, levántalos hacia los lados hasta que estén paralelos al suelo. Haz una', 'shoulders', 'cable', 'shoulders', 'shoulders', 'delts', '{"trapezius","rhomboids"}', 'Coloca un mango en D en una máquina de cable con polea baja y túmbate boca abajo en un banco plano. Agarra el mango en D con cada mano, con las palmas hacia abajo, y extiende los brazos frente a ti. Manteniendo los brazos rectos, levántalos hacia los lados hasta que estén paralelos al suelo. Haz una pausa por un momento en la parte superior, luego baja lentamente los brazos de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Attach a D-handle to a low pulley cable machine and lie face down on a flat bench. Grasp the D-handle with each hand, palms facing down, and extend your arms straight out in front of you. Keeping your arms straight, raise them out to the sides until they are parallel to the floor. Pause for a moment at the top, then slowly lower your arms back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0240-PQcUlDi.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0240-PQcUlDi.gif', 'PQcUlDi', '© Gym visual — https://gymvisual.com/'),
('2464', 'cable thibaudeau kayak row', 'Coloca un mango de cable en una polea baja y siéntate frente a la máquina con los pies planos en el suelo. Agarra el mango con la mano derecha y extiende completamente el brazo, manteniendo una ligera flexión en el codo. Inclínate hacia adelante desde las caderas, manteniendo la espalda recta y el a', 'back', 'cable', 'back', 'back', 'lats', '{"biceps","rhomboids","rear deltoids"}', 'Coloca un mango de cable en una polea baja y siéntate frente a la máquina con los pies planos en el suelo. Agarra el mango con la mano derecha y extiende completamente el brazo, manteniendo una ligera flexión en el codo. Inclínate hacia adelante desde las caderas, manteniendo la espalda recta y el abdomen activado. Tira del mango hacia tu torso retrayendo el omóplato y flexionando el codo, manteniendo el brazo cerca del cuerpo. Aprieta los músculos de la espalda en la parte alta del movimiento, luego regresa lentamente a la posición inicial. Repite el número de repeticiones deseado, luego cambia de lado y realiza el ejercicio con el brazo izquierdo.', 'Attach a cable handle to a low pulley and sit facing the machine with your feet flat on the floor. Grasp the handle with your right hand and extend your arm fully, keeping a slight bend in your elbow. Lean forward from your hips, keeping your back straight and your abs engaged. Pull the handle towards your torso by retracting your shoulder blade and bending your elbow, keeping your arm close to your body. Squeeze your back muscles at the top of the movement, then slowly return to the starting position. Repeat for the desired number of repetitions, then switch sides and perform with your left arm.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2464-ZgwWBoC.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2464-ZgwWBoC.gif', 'ZgwWBoC', '© Gym visual — https://gymvisual.com/'),
('0241', 'cable triceps pushdown (v-bar)', 'Coloca un accesorio en V en la máquina de cable en el ajuste más alto. Ponte de pie frente a la máquina de cable con los pies separados a la altura de los hombros. Agarra el accesorio en V con un agarre prono, con las palmas hacia abajo y las manos separadas a la altura de los hombros. Mantén los co', 'upper arms', 'cable', 'upper arms', 'upper arms', 'triceps', '{"forearms"}', 'Coloca un accesorio en V en la máquina de cable en el ajuste más alto. Ponte de pie frente a la máquina de cable con los pies separados a la altura de los hombros. Agarra el accesorio en V con un agarre prono, con las palmas hacia abajo y las manos separadas a la altura de los hombros. Mantén los codos cerca de los costados y los brazos superiores quietos durante todo el ejercicio. Activa los tríceps y exhala mientras empujas el accesorio en V hacia abajo hasta que los brazos estén completamente extendidos. Haz una pausa breve en la parte baja del movimiento, apretando los tríceps. Inhala mientras regresas lentamente el accesorio en V a la posición inicial, manteniendo el control. Repite el número de repeticiones deseado.', 'Attach a v-bar attachment to the cable machine at the highest setting. Stand facing the cable machine with your feet shoulder-width apart. Grasp the v-bar with an overhand grip, palms facing down, and your hands shoulder-width apart. Keep your elbows close to your sides and your upper arms stationary throughout the exercise. Engage your triceps and exhale as you push the v-bar down until your arms are fully extended. Pause for a moment at the bottom of the movement, squeezing your triceps. Inhale as you slowly return the v-bar to the starting position, maintaining control. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0241-gAwDzB3.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0241-gAwDzB3.gif', 'gAwDzB3', '© Gym visual — https://gymvisual.com/'),
('2405', 'cable triceps pushdown (v-bar) (with arm blaster)', 'Coloca un accesorio en V en la máquina de cable en el ajuste más alto. Ponte de pie frente a la máquina de cable con los pies separados a la altura de los hombros. Agarra el accesorio en V con un agarre prono, con las palmas hacia abajo y las manos separadas a la altura de los hombros. Mantén los co', 'upper arms', 'cable', 'upper arms', 'upper arms', 'triceps', '{"forearms"}', 'Coloca un accesorio en V en la máquina de cable en el ajuste más alto. Ponte de pie frente a la máquina de cable con los pies separados a la altura de los hombros. Agarra el accesorio en V con un agarre prono, con las palmas hacia abajo y las manos separadas a la altura de los hombros. Mantén los codos cerca de los costados y los brazos superiores quietos durante todo el ejercicio. Activa los tríceps y exhala mientras empujas el accesorio en V hacia abajo hasta que los brazos estén completamente extendidos. Haz una pausa breve en la parte baja del movimiento, apretando los tríceps. Inhala mientras regresas lentamente el accesorio en V a la posición inicial, manteniendo el control. Repite el número de repeticiones deseado.', 'Attach a v-bar attachment to the cable machine at the highest setting. Stand facing the cable machine with your feet shoulder-width apart. Grasp the v-bar with an overhand grip, palms facing down, and your hands shoulder-width apart. Keep your elbows close to your sides and your upper arms stationary throughout the exercise. Engage your triceps and exhale as you push the v-bar down until your arms are fully extended. Pause for a moment at the bottom of the movement, squeezing your triceps. Inhale as you slowly return the v-bar to the starting position, maintaining control. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2405-OxJk1fg.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2405-OxJk1fg.gif', 'OxJk1fg', '© Gym visual — https://gymvisual.com/'),
('0242', 'cable tuck reverse crunch', 'Sujeta un cable a una polea baja y túmbate boca arriba sobre una esterilla. Sujeta el cable con ambas manos y extiende los brazos rectos por encima del pecho. Flexiona las rodillas y levanta las piernas, llevando las rodillas hacia el pecho. Al mismo tiempo, eleva la pelvis hacia el pecho, levantand', 'waist', 'cable', 'waist', 'waist', 'abs', '{"hip flexors"}', 'Sujeta un cable a una polea baja y túmbate boca arriba sobre una esterilla. Sujeta el cable con ambas manos y extiende los brazos rectos por encima del pecho. Flexiona las rodillas y levanta las piernas, llevando las rodillas hacia el pecho. Al mismo tiempo, eleva la pelvis hacia el pecho, levantando las caderas del suelo. Haz una pausa breve en la parte alta, luego baja lentamente las piernas y las caderas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Attach a cable to a low pulley and lie down on a mat facing up. Hold the cable with both hands and extend your arms straight up above your chest. Bend your knees and lift your legs up, bringing your knees towards your chest. At the same time, curl your pelvis up towards your chest, lifting your hips off the ground. Pause for a moment at the top, then slowly lower your legs and hips back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0242-TXtXc84.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0242-TXtXc84.gif', 'TXtXc84', '© Gym visual — https://gymvisual.com/'),
('0243', 'cable twist', 'Ponte de pie con los pies separados a la altura de los hombros, frente a la máquina de cable. Sujeta el mango del cable con ambas manos frente al pecho, manteniendo los brazos ligeramente flexionados. Activa el core y gira el torso hacia la derecha, tirando del cable a través de tu cuerpo. Haz una p', 'waist', 'cable', 'waist', 'waist', 'abs', '{"obliques"}', 'Ponte de pie con los pies separados a la altura de los hombros, frente a la máquina de cable. Sujeta el mango del cable con ambas manos frente al pecho, manteniendo los brazos ligeramente flexionados. Activa el core y gira el torso hacia la derecha, tirando del cable a través de tu cuerpo. Haz una pausa breve al final del movimiento, sintiendo la contracción en el abdomen y los oblicuos. Regresa lentamente a la posición inicial, resistiendo la tracción del cable. Repite el movimiento hacia el lado izquierdo. Continúa alternando lados durante el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, facing the cable machine. Hold the cable handle with both hands in front of your chest, keeping your arms slightly bent. Engage your core and twist your torso to the right, pulling the cable across your body. Pause for a moment at the end of the movement, feeling the contraction in your abs and obliques. Slowly return to the starting position, resisting the cable''s pull. Repeat the movement to the left side. Continue alternating sides for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0243-aVs3BR3.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0243-aVs3BR3.gif', 'aVs3BR3', '© Gym visual — https://gymvisual.com/'),
('0862', 'cable twist (up-down)', 'Ponte de pie con los pies separados a la altura de los hombros, frente a la máquina de cable. Sujeta el mango del cable con ambas manos frente al pecho, manteniendo los brazos ligeramente flexionados. Activa el core y gira lentamente el torso hacia un lado, manteniendo las caderas y las piernas esta', 'waist', 'cable', 'waist', 'waist', 'abs', '{"obliques","lower back"}', 'Ponte de pie con los pies separados a la altura de los hombros, frente a la máquina de cable. Sujeta el mango del cable con ambas manos frente al pecho, manteniendo los brazos ligeramente flexionados. Activa el core y gira lentamente el torso hacia un lado, manteniendo las caderas y las piernas estables. Haz una pausa por un momento al final de la rotación, luego regresa lentamente a la posición inicial. Repite el giro hacia el lado opuesto. Continúa alternando lados durante el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, facing the cable machine. Hold the cable handle with both hands in front of your chest, keeping your arms slightly bent. Engage your core and slowly rotate your torso to one side, keeping your hips and legs stable. Pause for a moment at the end of the rotation, then slowly return to the starting position. Repeat the rotation to the opposite side. Continue alternating sides for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0862-fhZQPlV.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0862-fhZQPlV.gif', 'fhZQPlV', '© Gym visual — https://gymvisual.com/'),
('0244', 'cable twisting pull', 'Coloca un mango de cable en una polea baja y ponte de pie frente a la máquina. Agarra el mango con la mano izquierda y aléjate de la máquina, extendiendo completamente el brazo. Coloca los pies separados a la altura de los hombros, con las rodillas ligeramente flexionadas. Mantén la espalda recta y ', 'back', 'cable', 'back', 'back', 'lats', '{"shoulders","biceps"}', 'Coloca un mango de cable en una polea baja y ponte de pie frente a la máquina. Agarra el mango con la mano izquierda y aléjate de la máquina, extendiendo completamente el brazo. Coloca los pies separados a la altura de los hombros, con las rodillas ligeramente flexionadas. Mantén la espalda recta y el core activado durante todo el ejercicio. Tira del mango hacia tu cuerpo, rotando el torso hacia la derecha al hacerlo. Aprieta los músculos de la espalda al final del movimiento. Regresa lentamente a la posición inicial, manteniendo la tensión en el cable. Repite el número de repeticiones deseado, luego cambia de lado y realiza el ejercicio con la mano derecha.', 'Attach a cable handle to a low pulley and stand facing the machine. Grasp the handle with your left hand and step away from the machine, extending your arm fully. Position your feet shoulder-width apart, with your knees slightly bent. Keep your back straight and your core engaged throughout the exercise. Pull the handle towards your body, rotating your torso to the right as you do so. Squeeze your back muscles at the end of the movement. Slowly return to the starting position, keeping tension on the cable. Repeat for the desired number of repetitions, then switch sides and perform with your right hand.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0244-zCgxPbV.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0244-zCgxPbV.gif', 'zCgxPbV', '© Gym visual — https://gymvisual.com/'),
('1645', 'cable two arm curl on incline bench', 'Siéntate en un banco inclinado con la espalda apoyada en el respaldo y los pies planos en el suelo. Agarra los mangos del cable con un agarre supino, con las palmas hacia arriba y los brazos completamente extendidos. Manteniendo los brazos superiores quietos, exhala y flexiona los mangos hacia los h', 'upper arms', 'cable', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Siéntate en un banco inclinado con la espalda apoyada en el respaldo y los pies planos en el suelo. Agarra los mangos del cable con un agarre supino, con las palmas hacia arriba y los brazos completamente extendidos. Manteniendo los brazos superiores quietos, exhala y flexiona los mangos hacia los hombros mientras contraes los bíceps. Haz una pausa breve en la parte más alta del movimiento, contrayendo los bíceps. Inhala y baja lentamente los mangos de vuelta a la posición inicial, extendiendo completamente los brazos. Repite el número de repeticiones deseado.', 'Sit on an incline bench with your back against the pad and your feet flat on the ground. Grasp the cable handles with an underhand grip, palms facing up, and your arms fully extended. Keeping your upper arms stationary, exhale and curl the handles towards your shoulders while contracting your biceps. Pause for a moment at the top of the movement, squeezing your biceps. Inhale and slowly lower the handles back to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1645-H9y3Dkr.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1645-H9y3Dkr.gif', 'H9y3Dkr', '© Gym visual — https://gymvisual.com/'),
('1728', 'cable two arm tricep kickback', 'Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Sujeta el mango del cable en cada mano con las palmas hacia adentro y los brazos flexionados en un ángulo de 90 grados. Manteniendo los brazos superiores quietos, extiende los antebrazos hacia atrá', 'upper arms', 'cable', 'upper arms', 'upper arms', 'triceps', '{"shoulders"}', 'Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Sujeta el mango del cable en cada mano con las palmas hacia adentro y los brazos flexionados en un ángulo de 90 grados. Manteniendo los brazos superiores quietos, extiende los antebrazos hacia atrás hasta que los brazos estén completamente extendidos. Haz una pausa por un momento, luego regresa lentamente a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and knees slightly bent. Hold the cable handle in each hand with your palms facing inwards and your arms bent at a 90-degree angle. Keeping your upper arms stationary, extend your forearms backwards until your arms are fully extended. Pause for a moment, then slowly return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1728-vvNjDJS.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1728-vvNjDJS.gif', 'vvNjDJS', '© Gym visual — https://gymvisual.com/'),
('0245', 'cable underhand pulldown', 'Ajusta la máquina de cable de modo que la barra de jalón quede a una altura por encima de tu cabeza. Siéntate y agarra la barra de jalón con un agarre supino, con las manos un poco más separadas que el ancho de los hombros. Mantén la espalda recta e inclínate ligeramente hacia atrás. Jala la barra h', 'back', 'cable', 'back', 'back', 'lats', '{"biceps","forearms"}', 'Ajusta la máquina de cable de modo que la barra de jalón quede a una altura por encima de tu cabeza. Siéntate y agarra la barra de jalón con un agarre supino, con las manos un poco más separadas que el ancho de los hombros. Mantén la espalda recta e inclínate ligeramente hacia atrás. Jala la barra hacia el pecho, apretando los omóplatos entre sí. Haz una pausa por un momento en la parte baja del movimiento y luego suelta lentamente la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the cable machine so that the pulldown bar is at a height above your head. Sit down on the seat and grab the pulldown bar with an underhand grip, hands slightly wider than shoulder-width apart. Keep your back straight and lean back slightly. Pull the bar down towards your chest, squeezing your shoulder blades together. Pause for a moment at the bottom of the movement, then slowly release the bar back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0245-xBYcQHj.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0245-xBYcQHj.gif', 'xBYcQHj', '© Gym visual — https://gymvisual.com/'),
('1270', 'cable upper chest crossovers', 'Coloca los mangos en los cables a la altura del pecho. Ponte de pie en el centro de la máquina de cable con un pie ligeramente delante del otro. Sujeta las agarraderas con las palmas hacia abajo y los brazos extendidos hacia los lados. Mantén una ligera flexión en los codos y activa el core. Tira de', 'chest', 'cable', 'chest', 'chest', 'pectorals', '{"deltoids","triceps"}', 'Coloca los mangos en los cables a la altura del pecho. Ponte de pie en el centro de la máquina de cable con un pie ligeramente delante del otro. Sujeta las agarraderas con las palmas hacia abajo y los brazos extendidos hacia los lados. Mantén una ligera flexión en los codos y activa el core. Tira de los cables juntos frente al pecho, cruzándolos uno sobre el otro. Aprieta los músculos del pecho en el punto máximo del movimiento. Suelta lentamente los cables de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Attach the handles to the cables at chest height. Stand in the center of the cable machine with one foot slightly in front of the other. Grasp the handles with your palms facing down and your arms extended out to the sides. Keep a slight bend in your elbows and engage your core. Pull the cables together in front of your chest, crossing them over each other. Squeeze your chest muscles at the peak of the movement. Slowly release the cables back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1270-j7XMAyn.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1270-j7XMAyn.gif', 'j7XMAyn', '© Gym visual — https://gymvisual.com/'),
('1324', 'cable upper row', 'Sujeta una barra recta a una máquina de cable a la altura del pecho. Ponte de pie frente a la máquina con los pies separados a la altura de los hombros. Sujeta la barra con un agarre prono, con las manos un poco más separadas que el ancho de los hombros. Mantén la espalda recta y el core activado. J', 'back', 'cable', 'back', 'back', 'upper back', '{"biceps","shoulders"}', 'Sujeta una barra recta a una máquina de cable a la altura del pecho. Ponte de pie frente a la máquina con los pies separados a la altura de los hombros. Sujeta la barra con un agarre prono, con las manos un poco más separadas que el ancho de los hombros. Mantén la espalda recta y el core activado. Jala la barra hacia la parte superior del pecho, apretando los omóplatos entre sí. Haz una pausa breve en la parte alta del movimiento. Suelta lentamente la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Attach a straight bar to a cable machine at chest height. Stand facing the machine with your feet shoulder-width apart. Grasp the bar with an overhand grip, hands slightly wider than shoulder-width apart. Keep your back straight and your core engaged. Pull the bar towards your upper chest, squeezing your shoulder blades together. Pause for a moment at the top of the movement. Slowly release the bar back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1324-PQStVXH.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1324-PQStVXH.gif', 'PQStVXH', '© Gym visual — https://gymvisual.com/'),
('0246', 'cable upright row', 'Ponte de pie con los pies separados a la altura de los hombros, las rodillas ligeramente flexionadas, y sujeta el accesorio del cable con un agarre prono. Mantén la espalda recta y el core activado durante todo el ejercicio. Tira del accesorio del cable directamente hacia arriba, hacia tu barbilla, ', 'shoulders', 'cable', 'shoulders', 'shoulders', 'delts', '{"traps","biceps"}', 'Ponte de pie con los pies separados a la altura de los hombros, las rodillas ligeramente flexionadas, y sujeta el accesorio del cable con un agarre prono. Mantén la espalda recta y el core activado durante todo el ejercicio. Tira del accesorio del cable directamente hacia arriba, hacia tu barbilla, guiando con los codos. Haz una pausa breve en la parte alta, apretando los omóplatos entre sí. Baja lentamente el accesorio del cable de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, knees slightly bent, and hold the cable attachment with an overhand grip. Keep your back straight and your core engaged throughout the exercise. Pull the cable attachment straight up towards your chin, leading with your elbows. Pause for a moment at the top, squeezing your shoulder blades together. Slowly lower the cable attachment back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0246-cALKspW.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0246-cALKspW.gif', 'cALKspW', '© Gym visual — https://gymvisual.com/'),
('1325', 'cable wide grip rear pulldown behind neck', 'Ajusta la máquina de cable de modo que la barra de jalón quede a una altura por encima de tu cabeza. Siéntate y agarra la barra de jalón con un agarre prono amplio. Mantén la espalda recta y el pecho elevado mientras te reclinas ligeramente hacia atrás. Jala la barra hacia la parte superior del pech', 'back', 'cable', 'back', 'back', 'lats', '{"biceps","rhomboids","rear deltoids"}', 'Ajusta la máquina de cable de modo que la barra de jalón quede a una altura por encima de tu cabeza. Siéntate y agarra la barra de jalón con un agarre prono amplio. Mantén la espalda recta y el pecho elevado mientras te reclinas ligeramente hacia atrás. Jala la barra hacia la parte superior del pecho, apretando los omóplatos entre sí. Haz una pausa por un momento en la parte baja del movimiento y luego suelta lentamente la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the cable machine so that the pulldown bar is at a height above your head. Sit down on the seat and grab the pulldown bar with a wide overhand grip. Keep your back straight and your chest up as you lean back slightly. Pull the bar down towards your upper chest, squeezing your shoulder blades together. Pause for a moment at the bottom of the movement, then slowly release the bar back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1325-CmEr4pM.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1325-CmEr4pM.gif', 'CmEr4pM', '© Gym visual — https://gymvisual.com/'),
('0247', 'cable wrist curl', 'Coloca una barra recta en una máquina de cable con polea baja. Ponte de pie frente a la máquina con los pies separados a la altura de los hombros. Sujeta la barra con un agarre supino, con las palmas hacia arriba y las manos separadas a la altura de los hombros. Apoya los antebrazos en un banco o al', 'lower arms', 'cable', 'lower arms', 'lower arms', 'forearms', '{"biceps","brachialis"}', 'Coloca una barra recta en una máquina de cable con polea baja. Ponte de pie frente a la máquina con los pies separados a la altura de los hombros. Sujeta la barra con un agarre supino, con las palmas hacia arriba y las manos separadas a la altura de los hombros. Apoya los antebrazos en un banco o almohadilla, con las muñecas colgando del borde. Manteniendo los antebrazos fijos, exhala y flexiona las muñecas hacia arriba tanto como sea posible. Haz una pausa breve en la parte alta, luego inhala y baja lentamente la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Attach a straight bar to a low pulley cable machine. Stand facing the machine with your feet shoulder-width apart. Grasp the bar with an underhand grip, palms facing up, and your hands shoulder-width apart. Rest your forearms on a bench or pad, with your wrists hanging off the edge. Keeping your forearms stationary, exhale and curl your wrists upward as far as possible. Pause for a moment at the top, then inhale and slowly lower the bar back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0247-LrV4s90.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0247-LrV4s90.gif', 'LrV4s90', '© Gym visual — https://gymvisual.com/'),
('1407', 'calf push stretch with hands against wall', 'Ponte de pie frente a una pared con los pies separados a la altura de las caderas. Coloca las manos contra la pared a la altura de los hombros. Da un paso atrás con un pie, manteniendo el talón en el suelo y la pierna recta. Flexiona ligeramente la rodilla delantera e inclínate hacia adelante, sinti', 'lower legs', 'body weight', 'lower legs', 'lower legs', 'calves', '{"hamstrings"}', 'Ponte de pie frente a una pared con los pies separados a la altura de las caderas. Coloca las manos contra la pared a la altura de los hombros. Da un paso atrás con un pie, manteniendo el talón en el suelo y la pierna recta. Flexiona ligeramente la rodilla delantera e inclínate hacia adelante, sintiendo un estiramiento en la pantorrilla. Mantén el estiramiento durante 20-30 segundos. Cambia de pierna y repite el estiramiento.', 'Stand facing a wall with your feet hip-width apart. Place your hands against the wall at shoulder height. Step back with one foot, keeping your heel on the ground and your leg straight. Bend your front knee slightly and lean forward, feeling a stretch in your calf. Hold the stretch for 20-30 seconds. Switch legs and repeat the stretch.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1407-PzNxakt.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1407-PzNxakt.gif', 'PzNxakt', '© Gym visual — https://gymvisual.com/'),
('1377', 'calf stretch with hands against wall', 'Ponte de pie frente a una pared con los pies separados a la altura de las caderas. Coloca las manos contra la pared a la altura de los hombros. Da un paso atrás con el pie derecho, manteniendo el talón en el suelo y la pierna recta. Flexiona la rodilla izquierda e inclínate hacia adelante, mantenien', 'lower legs', 'body weight', 'lower legs', 'lower legs', 'calves', '{"hamstrings"}', 'Ponte de pie frente a una pared con los pies separados a la altura de las caderas. Coloca las manos contra la pared a la altura de los hombros. Da un paso atrás con el pie derecho, manteniendo el talón en el suelo y la pierna recta. Flexiona la rodilla izquierda e inclínate hacia adelante, manteniendo la pierna de atrás recta y el talón en el suelo. Mantén el estiramiento durante 20-30 segundos. Cambia de pierna y repite el estiramiento.', 'Stand facing a wall with your feet hip-width apart. Place your hands against the wall at shoulder height. Step your right foot back, keeping your heel on the ground and your leg straight. Bend your left knee and lean forward, keeping your back leg straight and your heel on the ground. Hold the stretch for 20-30 seconds. Switch legs and repeat the stretch.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1377-m0tCHqc.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1377-m0tCHqc.gif', 'm0tCHqc', '© Gym visual — https://gymvisual.com/'),
('1378', 'calf stretch with rope', 'Ponte de pie frente a una pared u objeto firme con los pies separados a la altura de las caderas. Sujeta los extremos de la cuerda con cada mano y coloca el centro de la cuerda alrededor de la planta del pie derecho. Da un paso atrás con el pie izquierdo, manteniendo el talón en el suelo y la pierna', 'lower legs', 'rope', 'lower legs', 'lower legs', 'calves', '{"hamstrings"}', 'Ponte de pie frente a una pared u objeto firme con los pies separados a la altura de las caderas. Sujeta los extremos de la cuerda con cada mano y coloca el centro de la cuerda alrededor de la planta del pie derecho. Da un paso atrás con el pie izquierdo, manteniendo el talón en el suelo y la pierna recta. Inclínate hacia adelante, manteniendo la espalda recta, y tira suavemente de la cuerda para estirar la pantorrilla. Mantén el estiramiento durante 20-30 segundos, luego suelta. Repite con la otra pierna.', 'Stand facing a wall or sturdy object with your feet hip-width apart. Hold the ends of the rope in each hand and place the middle of the rope around the ball of your right foot. Step back with your left foot, keeping your heel on the ground and your leg straight. Lean forward, keeping your back straight, and gently pull on the rope to stretch your calf. Hold the stretch for 20-30 seconds, then release. Repeat on the other leg.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1378-1LVFcEn.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1378-1LVFcEn.gif', '1LVFcEn', '© Gym visual — https://gymvisual.com/'),
('0248', 'cambered bar lying row', 'Coloca una barra en el suelo y túmbate boca abajo en un banco con el pecho justo en el borde. Estírate hacia abajo y agarra la barra con un agarre prono, un poco más ancho que el ancho de los hombros. Con las piernas rectas y los pies en el suelo, levanta la barra del suelo extendiendo los brazos. T', 'back', 'barbell', 'back', 'back', 'upper back', '{"biceps","forearms"}', 'Coloca una barra en el suelo y túmbate boca abajo en un banco con el pecho justo en el borde. Estírate hacia abajo y agarra la barra con un agarre prono, un poco más ancho que el ancho de los hombros. Con las piernas rectas y los pies en el suelo, levanta la barra del suelo extendiendo los brazos. Tira de la barra hacia el pecho, juntando los omóplatos. Baja la barra de vuelta a la posición inicial y repite el número de repeticiones deseado.', 'Set up a barbell on the floor and lie face down on a bench with your chest just off the edge. Reach down and grab the barbell with an overhand grip, slightly wider than shoulder-width apart. With your legs straight and feet on the ground, lift the barbell off the floor by extending your arms. Pull the barbell towards your chest, squeezing your shoulder blades together. Lower the barbell back down to the starting position and repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0248-R5swFnc.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0248-R5swFnc.gif', 'R5swFnc', '© Gym visual — https://gymvisual.com/'),
('2963', 'captains chair straight leg raise', 'Siéntate en la silla romana con la espalda apoyada en el respaldo y los antebrazos apoyados en las almohadillas. Mantén la parte superior del cuerpo estable y la espalda recta. Activa el abdomen y levanta las piernas frente a ti, manteniéndolas rectas. Continúa levantando hasta que las piernas estén', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"hip flexors"}', 'Siéntate en la silla romana con la espalda apoyada en el respaldo y los antebrazos apoyados en las almohadillas. Mantén la parte superior del cuerpo estable y la espalda recta. Activa el abdomen y levanta las piernas frente a ti, manteniéndolas rectas. Continúa levantando hasta que las piernas estén paralelas al suelo o tan alto como puedas llegar cómodamente. Haz una pausa por un momento en la parte superior, luego baja lentamente las piernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on the captain''s chair with your back against the backrest and your forearms resting on the arm pads. Keep your upper body stable and your back straight. Engage your abs and lift your legs up in front of you, keeping them straight. Continue lifting until your legs are parallel to the ground or as high as you can comfortably go. Pause for a moment at the top, then slowly lower your legs back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2963-weoDEpH.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2963-weoDEpH.gif', 'weoDEpH', '© Gym visual — https://gymvisual.com/'),
('1548', 'chair leg extended stretch', 'Siéntate al borde de una silla con la espalda recta y los pies planos en el suelo. Extiende una pierna recta frente a ti, manteniendo el talón en el suelo. Inclínate ligeramente hacia adelante, sintiendo un estiramiento en los cuádriceps. Mantén esta posición durante 20-30 segundos. Cambia de pierna', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'quads', '{"hamstrings","calves"}', 'Siéntate al borde de una silla con la espalda recta y los pies planos en el suelo. Extiende una pierna recta frente a ti, manteniendo el talón en el suelo. Inclínate ligeramente hacia adelante, sintiendo un estiramiento en los cuádriceps. Mantén esta posición durante 20-30 segundos. Cambia de pierna y repite el estiramiento.', 'Sit on the edge of a chair with your back straight and feet flat on the ground. Extend one leg straight out in front of you, keeping your heel on the ground. Lean forward slightly, feeling a stretch in your quadriceps. Hold this position for 20-30 seconds. Switch legs and repeat the stretch.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1548-xGgAGPm.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1548-xGgAGPm.gif', 'xGgAGPm', '© Gym visual — https://gymvisual.com/'),
('1271', 'chest and front of shoulder stretch', 'Ponte de pie con la espalda recta y los pies separados a la altura de los hombros. Extiende los brazos rectos frente a ti a la altura de los hombros. Cruza los brazos frente a tu cuerpo, con el brazo derecho sobre el brazo izquierdo. Entrelaza los dedos y presiona las palmas entre sí. Aprieta suavem', 'chest', 'body weight', 'chest', 'chest', 'pectorals', '{"deltoids"}', 'Ponte de pie con la espalda recta y los pies separados a la altura de los hombros. Extiende los brazos rectos frente a ti a la altura de los hombros. Cruza los brazos frente a tu cuerpo, con el brazo derecho sobre el brazo izquierdo. Entrelaza los dedos y presiona las palmas entre sí. Aprieta suavemente los omóplatos entre sí y empuja las manos hacia adelante, sintiendo un estiramiento en el pecho y la parte delantera de los hombros. Mantén el estiramiento durante 20-30 segundos, luego suelta. Repite el número de repeticiones deseado.', 'Stand tall with your feet shoulder-width apart. Extend your arms straight out in front of you at shoulder height. Cross your arms in front of your body, with your right arm on top of your left arm. Interlace your fingers and press your palms together. Gently squeeze your shoulder blades together and push your hands forward, feeling a stretch in your chest and front of your shoulders. Hold the stretch for 20-30 seconds, then release. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1271-Uto7l43.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1271-Uto7l43.gif', 'Uto7l43', '© Gym visual — https://gymvisual.com/'),
('0251', 'chest dip', 'Colócate en las barras paralelas con los brazos completamente extendidos y el cuerpo recto. Baja el cuerpo flexionando los codos hasta que los hombros queden por debajo de los codos. Empújate de vuelta hacia arriba a la posición inicial extendiendo los brazos. Repite el número de repeticiones desead', 'chest', 'body weight', 'chest', 'chest', 'pectorals', '{"triceps","shoulders"}', 'Colócate en las barras paralelas con los brazos completamente extendidos y el cuerpo recto. Baja el cuerpo flexionando los codos hasta que los hombros queden por debajo de los codos. Empújate de vuelta hacia arriba a la posición inicial extendiendo los brazos. Repite el número de repeticiones deseado.', 'Position yourself on parallel bars with your arms fully extended and your body straight. Lower your body by bending your elbows until your shoulders are below your elbows. Push yourself back up to the starting position by straightening your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0251-9WTm7dq.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0251-9WTm7dq.gif', '9WTm7dq', '© Gym visual — https://gymvisual.com/'),
('1430', 'chest dip (on dip-pull-up cage)', 'Ajusta las barras de fondos a una altura que te permita agarrarlas cómodamente. Ponte de pie entre las barras y coloca las manos en cada barra, un poco más separadas que el ancho de los hombros. Salta y estira los brazos, sosteniendo el peso de tu cuerpo sobre las barras. Flexiona las rodillas y cru', 'chest', 'body weight', 'chest', 'chest', 'pectorals', '{"triceps","shoulders"}', 'Ajusta las barras de fondos a una altura que te permita agarrarlas cómodamente. Ponte de pie entre las barras y coloca las manos en cada barra, un poco más separadas que el ancho de los hombros. Salta y estira los brazos, sosteniendo el peso de tu cuerpo sobre las barras. Flexiona las rodillas y cruza los tobillos detrás de ti. Baja el cuerpo flexionando los codos, manteniendo el pecho elevado y los hombros bajos. Continúa bajando hasta que los hombros queden por debajo de los codos o hasta que sientas un estiramiento en el pecho. Empuja con las palmas y extiende los codos para subir el cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the dip bars to a height that allows you to comfortably grip them. Stand between the bars and place your hands on each bar, slightly wider than shoulder-width apart. Jump up and straighten your arms, supporting your body weight on the bars. Bend your knees and cross your ankles behind you. Lower your body by bending your elbows, keeping your chest up and your shoulders down. Continue lowering until your shoulders are below your elbows or until you feel a stretch in your chest. Push through your palms and extend your elbows to raise your body back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1430-XgWyAiA.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1430-XgWyAiA.gif', 'XgWyAiA', '© Gym visual — https://gymvisual.com/'),
('2462', 'chest dip on straight bar', 'Agarra las barras paralelas con las palmas hacia abajo y los brazos completamente extendidos. Flexiona las rodillas y cruza los tobillos. Baja el cuerpo flexionando los brazos hasta que los hombros queden por debajo de los codos. Empújate de vuelta hacia arriba a la posición inicial extendiendo los ', 'chest', 'body weight', 'chest', 'chest', 'pectorals', '{"triceps","shoulders"}', 'Agarra las barras paralelas con las palmas hacia abajo y los brazos completamente extendidos. Flexiona las rodillas y cruza los tobillos. Baja el cuerpo flexionando los brazos hasta que los hombros queden por debajo de los codos. Empújate de vuelta hacia arriba a la posición inicial extendiendo los brazos. Repite el número de repeticiones deseado.', 'Grab the parallel bars with your palms facing down and your arms fully extended. Bend your knees and cross your ankles. Lower your body by bending your arms until your shoulders are below your elbows. Push yourself back up to the starting position by straightening your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2462-LQFOrMn.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2462-LQFOrMn.gif', 'LQFOrMn', '© Gym visual — https://gymvisual.com/'),
('1272', 'chest stretch with exercise ball', 'Siéntate en el balón de estabilidad con los pies planos en el suelo y la espalda recta. Sujeta el balón de ejercicio con ambas manos y extiende los brazos rectos frente a ti. Lleva lentamente el balón de ejercicio hacia tu pecho, sintiendo un estiramiento en los músculos del pecho. Mantén el estiram', 'chest', 'stability ball', 'chest', 'chest', 'pectorals', '{"shoulders","triceps"}', 'Siéntate en el balón de estabilidad con los pies planos en el suelo y la espalda recta. Sujeta el balón de ejercicio con ambas manos y extiende los brazos rectos frente a ti. Lleva lentamente el balón de ejercicio hacia tu pecho, sintiendo un estiramiento en los músculos del pecho. Mantén el estiramiento durante unos segundos, luego regresa lentamente a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on the stability ball with your feet flat on the ground and your back straight. Hold the exercise ball with both hands and extend your arms straight out in front of you. Slowly bring the exercise ball towards your chest, feeling a stretch in your chest muscles. Hold the stretch for a few seconds, then slowly return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1272-ykA5tU7.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1272-ykA5tU7.gif', 'ykA5tU7', '© Gym visual — https://gymvisual.com/'),
('3216', 'chest tap push-up (male)', 'Comienza en posición de plancha alta con las manos un poco más separadas que el ancho de los hombros y el cuerpo en línea recta. Baja el cuerpo hacia el suelo flexionando los codos, manteniéndolos cerca de los costados. Mientras te bajas, toca tu pecho con la mano derecha. Empújate de vuelta hacia a', 'chest', 'body weight', 'chest', 'chest', 'pectorals', '{"triceps","shoulders"}', 'Comienza en posición de plancha alta con las manos un poco más separadas que el ancho de los hombros y el cuerpo en línea recta. Baja el cuerpo hacia el suelo flexionando los codos, manteniéndolos cerca de los costados. Mientras te bajas, toca tu pecho con la mano derecha. Empújate de vuelta hacia arriba hasta la posición inicial. Repite el movimiento, esta vez tocando tu pecho con la mano izquierda. Continúa alternando lados durante el número de repeticiones deseado.', 'Start in a high plank position with your hands slightly wider than shoulder-width apart and your body in a straight line. Lower your body towards the ground by bending your elbows, keeping them close to your sides. As you lower yourself, tap your chest with your right hand. Push yourself back up to the starting position. Repeat the movement, this time tapping your chest with your left hand. Continue alternating sides for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3216-7E06s6d.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3216-7E06s6d.gif', '7E06s6d', '© Gym visual — https://gymvisual.com/'),
('1326', 'chin-up', 'Cuélgate de una barra de dominadas con las palmas mirando hacia ti y las manos separadas a la altura de los hombros. Activa el core y tira de tu cuerpo hacia arriba, hacia la barra, guiando con el pecho. Continúa subiendo hasta que la barbilla quede por encima de la barra. Haz una pausa por un momen', 'back', 'body weight', 'back', 'back', 'lats', '{"biceps","forearms"}', 'Cuélgate de una barra de dominadas con las palmas mirando hacia ti y las manos separadas a la altura de los hombros. Activa el core y tira de tu cuerpo hacia arriba, hacia la barra, guiando con el pecho. Continúa subiendo hasta que la barbilla quede por encima de la barra. Haz una pausa por un momento en la parte superior, luego baja lentamente el cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Hang from a pull-up bar with your palms facing towards you and your hands shoulder-width apart. Engage your core and pull your body up towards the bar, leading with your chest. Continue pulling until your chin is above the bar. Pause for a moment at the top, then slowly lower your body back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1326-T2mxWqc.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1326-T2mxWqc.gif', 'T2mxWqc', '© Gym visual — https://gymvisual.com/'),
('0253', 'chin-ups (narrow parallel grip)', 'Cuélgate de una barra de dominadas con un agarre paralelo estrecho, con las palmas hacia ti. Activa los músculos de la espalda y tira de tu cuerpo hacia arriba, hacia la barra, manteniendo los codos cerca del cuerpo. Continúa subiendo hasta que la barbilla quede por encima de la barra. Haz una pausa', 'back', 'body weight', 'back', 'back', 'upper back', '{"biceps","forearms"}', 'Cuélgate de una barra de dominadas con un agarre paralelo estrecho, con las palmas hacia ti. Activa los músculos de la espalda y tira de tu cuerpo hacia arriba, hacia la barra, manteniendo los codos cerca del cuerpo. Continúa subiendo hasta que la barbilla quede por encima de la barra. Haz una pausa por un momento en la parte superior, luego baja lentamente el cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Hang from a pull-up bar with a narrow parallel grip, palms facing towards you. Engage your back muscles and pull your body up towards the bar, keeping your elbows close to your body. Continue pulling until your chin is above the bar. Pause for a moment at the top, then slowly lower your body back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0253-G70mEAJ.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0253-G70mEAJ.gif', 'G70mEAJ', '© Gym visual — https://gymvisual.com/'),
('0257', 'circles knee stretch', 'Ponte de pie con los pies separados a la altura de los hombros y las manos en las caderas. Flexiona ligeramente las rodillas y levanta los talones del suelo, equilibrándote sobre las puntas de los pies. Manteniendo las rodillas flexionadas, gira las rodillas en un movimiento circular, primero en el ', 'lower legs', 'body weight', 'lower legs', 'lower legs', 'calves', '{"hamstrings","quadriceps"}', 'Ponte de pie con los pies separados a la altura de los hombros y las manos en las caderas. Flexiona ligeramente las rodillas y levanta los talones del suelo, equilibrándote sobre las puntas de los pies. Manteniendo las rodillas flexionadas, gira las rodillas en un movimiento circular, primero en el sentido de las agujas del reloj y luego en sentido contrario. Realiza el movimiento el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and your hands on your hips. Bend your knees slightly and lift your heels off the ground, balancing on the balls of your feet. Keeping your knees bent, rotate your knees in a circular motion, first clockwise and then counterclockwise. Perform the movement for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0257-X7jbxra.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0257-X7jbxra.gif', 'X7jbxra', '© Gym visual — https://gymvisual.com/'),
('1273', 'clap push up', 'Comienza en posición de plancha alta con las manos un poco más separadas que el ancho de los hombros. Baja el cuerpo hacia el suelo flexionando los codos, manteniendo el core activado. Empuja con las palmas de forma explosiva para impulsar tu cuerpo fuera del suelo. Mientras estás en el aire, junta ', 'chest', 'body weight', 'chest', 'chest', 'pectorals', '{"triceps","shoulders"}', 'Comienza en posición de plancha alta con las manos un poco más separadas que el ancho de los hombros. Baja el cuerpo hacia el suelo flexionando los codos, manteniendo el core activado. Empuja con las palmas de forma explosiva para impulsar tu cuerpo fuera del suelo. Mientras estás en el aire, junta las manos en un aplauso antes de aterrizar de vuelta en la posición inicial. Repite el número de repeticiones deseado.', 'Start in a high plank position with your hands slightly wider than shoulder-width apart. Lower your body towards the ground by bending your elbows, keeping your core engaged. Push through your palms explosively to propel your body off the ground. While in mid-air, clap your hands together before landing back in the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1273-wigSg76.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1273-wigSg76.gif', 'wigSg76', '© Gym visual — https://gymvisual.com/'),
('0258', 'clock push-up', 'Comienza en una posición de plancha alta con las manos justo debajo de los hombros y el cuerpo en línea recta. Baja el cuerpo hacia el suelo flexionando los codos, manteniéndolos cerca de los costados. Mientras bajas, gira el cuerpo hacia la izquierda, extendiendo el brazo izquierdo recto hacia el l', 'chest', 'body weight', 'chest', 'chest', 'pectorals', '{"triceps","shoulders","core"}', 'Comienza en una posición de plancha alta con las manos justo debajo de los hombros y el cuerpo en línea recta. Baja el cuerpo hacia el suelo flexionando los codos, manteniéndolos cerca de los costados. Mientras bajas, gira el cuerpo hacia la izquierda, extendiendo el brazo izquierdo recto hacia el lado. Empuja de vuelta hacia arriba hasta la posición inicial, mientras giras el cuerpo hacia el centro. Repite la flexión de brazos, esta vez girando el cuerpo hacia la derecha y extendiendo el brazo derecho hacia el lado. Continúa alternando lados en cada repetición.', 'Start in a high plank position with your hands directly under your shoulders and your body in a straight line. Lower your body towards the ground by bending your elbows, keeping them close to your sides. As you lower, rotate your body to the left, extending your left arm straight out to the side. Push back up to the starting position, while rotating your body to the center. Repeat the push-up, this time rotating your body to the right and extending your right arm out to the side. Continue alternating sides with each repetition.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0258-CMAxnsG.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0258-CMAxnsG.gif', 'CMAxnsG', '© Gym visual — https://gymvisual.com/'),
('1327', 'close grip chin-up', 'Agarra la barra de dominadas con las palmas hacia ti y las manos separadas a la altura de los hombros. Cuélgate de la barra con los brazos completamente extendidos y los pies fuera del suelo. Activa los músculos de la espalda y tira de tu cuerpo hacia arriba, hacia la barra, manteniendo los codos ce', 'back', 'body weight', 'back', 'back', 'lats', '{"biceps","forearms"}', 'Agarra la barra de dominadas con las palmas hacia ti y las manos separadas a la altura de los hombros. Cuélgate de la barra con los brazos completamente extendidos y los pies fuera del suelo. Activa los músculos de la espalda y tira de tu cuerpo hacia arriba, hacia la barra, manteniendo los codos cerca del cuerpo. Continúa subiendo hasta que la barbilla quede por encima de la barra. Haz una pausa por un momento en la parte superior, luego baja lentamente el cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Grab the pull-up bar with your palms facing towards you and your hands shoulder-width apart. Hang from the bar with your arms fully extended and your feet off the ground. Engage your back muscles and pull your body up towards the bar, keeping your elbows close to your body. Continue pulling until your chin is above the bar. Pause for a moment at the top, then slowly lower your body back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1327-VnfUNW7.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1327-VnfUNW7.gif', 'VnfUNW7', '© Gym visual — https://gymvisual.com/'),
('0259', 'close-grip push-up', 'Comienza en posición de plancha alta con las manos juntas, directamente debajo de los hombros. Activa el core y baja el cuerpo hacia el suelo, manteniendo los codos cerca de los costados. Empuja con las palmas para extender los brazos y regresar a la posición inicial. Repite el número de repeticione', 'upper arms', 'body weight', 'upper arms', 'upper arms', 'triceps', '{"chest","shoulders"}', 'Comienza en posición de plancha alta con las manos juntas, directamente debajo de los hombros. Activa el core y baja el cuerpo hacia el suelo, manteniendo los codos cerca de los costados. Empuja con las palmas para extender los brazos y regresar a la posición inicial. Repite el número de repeticiones deseado.', 'Start in a high plank position with your hands placed close together, directly under your shoulders. Engage your core and lower your body towards the ground, keeping your elbows close to your sides. Push through your palms to extend your arms and return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0259-x6KpKpq.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0259-x6KpKpq.gif', 'x6KpKpq', '© Gym visual — https://gymvisual.com/'),
('2398', 'close-grip push-up (on knees)', 'Comienza apoyándote sobre las manos y las rodillas, con las manos separadas a la altura de los hombros y las rodillas separadas a la altura de las caderas. Baja la parte superior del cuerpo hacia el suelo flexionando los codos, manteniéndolos cerca de los costados. Haz una pausa breve cuando tu pech', 'upper arms', 'body weight', 'upper arms', 'upper arms', 'triceps', '{"chest","shoulders"}', 'Comienza apoyándote sobre las manos y las rodillas, con las manos separadas a la altura de los hombros y las rodillas separadas a la altura de las caderas. Baja la parte superior del cuerpo hacia el suelo flexionando los codos, manteniéndolos cerca de los costados. Haz una pausa breve cuando tu pecho esté justo por encima del suelo. Empuja con las palmas para estirar los brazos y regresar a la posición inicial. Repite el número de repeticiones deseado.', 'Start by getting on your hands and knees, with your hands shoulder-width apart and your knees hip-width apart. Lower your upper body towards the ground by bending your elbows, keeping them close to your sides. Pause for a moment when your chest is just above the ground. Push through your palms to straighten your arms and return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2398-v3vLFW0.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2398-v3vLFW0.gif', 'v3vLFW0', '© Gym visual — https://gymvisual.com/'),
('0260', 'cocoons', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Coloca las manos detrás de la cabeza con los codos apuntando hacia afuera. Activando el abdomen, levanta lentamente la parte superior del cuerpo del suelo, curvándote hacia adelante hasta que tu torso forme un áng', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"hip flexors","lower back"}', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Coloca las manos detrás de la cabeza con los codos apuntando hacia afuera. Activando el abdomen, levanta lentamente la parte superior del cuerpo del suelo, curvándote hacia adelante hasta que tu torso forme un ángulo de 45 grados. Haz una pausa por un momento en la parte superior, luego baja lentamente la parte superior del cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on your back with your knees bent and feet flat on the ground. Place your hands behind your head with your elbows pointing outwards. Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle. Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0260-SLKj2pX.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0260-SLKj2pX.gif', 'SLKj2pX', '© Gym visual — https://gymvisual.com/'),
('1468', 'crab twist toe touch', 'Comienza sentado en el suelo con las rodillas flexionadas y los pies planos en el suelo. Coloca las manos detrás de ti, con los dedos apuntando hacia los pies, y levanta las caderas del suelo. Extiende una pierna recta frente a ti mientras al mismo tiempo llevas la mano contraria hacia los dedos del', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"obliques","hip flexors"}', 'Comienza sentado en el suelo con las rodillas flexionadas y los pies planos en el suelo. Coloca las manos detrás de ti, con los dedos apuntando hacia los pies, y levanta las caderas del suelo. Extiende una pierna recta frente a ti mientras al mismo tiempo llevas la mano contraria hacia los dedos del pie. Regresa a la posición inicial y repite del otro lado. Continúa alternando lados durante el número de repeticiones deseado.', 'Start by sitting on the ground with your knees bent and feet flat on the floor. Place your hands behind you, fingers pointing towards your feet, and lift your hips off the ground. Extend one leg straight out in front of you while simultaneously reaching your opposite hand towards your toes. Return to the starting position and repeat on the other side. Continue alternating sides for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1468-xgsGFVM.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1468-xgsGFVM.gif', 'xgsGFVM', '© Gym visual — https://gymvisual.com/'),
('0262', 'cross body crunch', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Coloca las manos detrás de la cabeza con los codos apuntando hacia afuera. Activando el abdomen, levanta la parte superior del cuerpo del suelo y gira para llevar el codo derecho hacia la rodilla izquierda. Haz un', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"obliques"}', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Coloca las manos detrás de la cabeza con los codos apuntando hacia afuera. Activando el abdomen, levanta la parte superior del cuerpo del suelo y gira para llevar el codo derecho hacia la rodilla izquierda. Haz una pausa por un momento en la parte superior, luego baja lentamente la parte superior del cuerpo de vuelta a la posición inicial. Repite en el otro lado, llevando el codo izquierdo hacia la rodilla derecha. Repite el número de repeticiones deseado.', 'Lie flat on your back with your knees bent and feet flat on the ground. Place your hands behind your head with your elbows pointing outwards. Engaging your abs, lift your upper body off the ground and twist to bring your right elbow towards your left knee. Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Repeat on the other side, bringing your left elbow towards your right knee. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0262-rbu5UUb.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0262-rbu5UUb.gif', 'rbu5UUb', '© Gym visual — https://gymvisual.com/'),
('0267', 'crunch (hands overhead)', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Extiende los brazos rectos por encima de la cabeza. Activando el abdomen, levanta la parte superior del cuerpo del suelo, flexionándote hacia adelante en dirección a las rodillas. Haz una pausa por un momento en l', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"hip flexors"}', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Extiende los brazos rectos por encima de la cabeza. Activando el abdomen, levanta la parte superior del cuerpo del suelo, flexionándote hacia adelante en dirección a las rodillas. Haz una pausa por un momento en la parte superior, luego baja lentamente la parte superior del cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on your back with your knees bent and feet flat on the ground. Extend your arms straight above your head. Engaging your abs, lift your upper body off the ground, curling forward towards your knees. Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0267-kjJ3VoQ.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0267-kjJ3VoQ.gif', 'kjJ3VoQ', '© Gym visual — https://gymvisual.com/'),
('0271', 'crunch (on stability ball)', 'Siéntate en el balón de estabilidad con los pies planos en el suelo y las rodillas flexionadas en un ángulo de 90 grados. Reclínate sobre el balón hasta que la zona lumbar esté apoyada y la parte superior del cuerpo quede paralela al suelo. Coloca las manos detrás de la cabeza o cruzadas sobre el pe', 'waist', 'stability ball', 'waist', 'waist', 'abs', '{"hip flexors"}', 'Siéntate en el balón de estabilidad con los pies planos en el suelo y las rodillas flexionadas en un ángulo de 90 grados. Reclínate sobre el balón hasta que la zona lumbar esté apoyada y la parte superior del cuerpo quede paralela al suelo. Coloca las manos detrás de la cabeza o cruzadas sobre el pecho. Activa el abdomen y levanta la parte superior del cuerpo hacia las rodillas, flexionando el torso hacia adelante. Haz una pausa breve en la parte alta del movimiento, luego baja lentamente la parte superior del cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on the stability ball with your feet flat on the ground and your knees bent at a 90-degree angle. Lie back on the ball until your lower back is supported and your upper body is parallel to the floor. Place your hands behind your head or across your chest. Engage your abs and lift your upper body towards your knees, curling your torso forward. Pause for a moment at the top of the movement, then slowly lower your upper body back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0271-MCUhf1F.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0271-MCUhf1F.gif', 'MCUhf1F', '© Gym visual — https://gymvisual.com/'),
('0272', 'crunch (on stability ball, arms straight)', 'Siéntate en el balón de estabilidad con los pies planos en el suelo y las rodillas flexionadas en un ángulo de 90 grados. Reclínate sobre el balón hasta que la zona lumbar esté apoyada y la parte superior del cuerpo quede paralela al suelo. Coloca las manos detrás de la cabeza o crúzalas sobre el pe', 'waist', 'stability ball', 'waist', 'waist', 'abs', '{"hip flexors"}', 'Siéntate en el balón de estabilidad con los pies planos en el suelo y las rodillas flexionadas en un ángulo de 90 grados. Reclínate sobre el balón hasta que la zona lumbar esté apoyada y la parte superior del cuerpo quede paralela al suelo. Coloca las manos detrás de la cabeza o crúzalas sobre el pecho. Activa el abdomen y levanta la parte superior del cuerpo del balón, flexionando los hombros hacia las caderas. Haz una pausa por un momento en la parte superior, luego baja lentamente la parte superior del cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on the stability ball with your feet flat on the ground and your knees bent at a 90-degree angle. Lie back on the ball until your lower back is supported and your upper body is parallel to the floor. Place your hands behind your head or cross them over your chest. Engage your abs and lift your upper body off the ball, curling your shoulders towards your hips. Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0272-Sn8wxAI.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0272-Sn8wxAI.gif', 'Sn8wxAI', '© Gym visual — https://gymvisual.com/'),
('0274', 'crunch floor', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Coloca las manos detrás de la cabeza con los codos apuntando hacia afuera. Activa el abdomen y levanta los hombros del suelo, flexionándote hacia adelante en dirección a las rodillas. Haz una pausa breve en la par', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"hip flexors"}', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Coloca las manos detrás de la cabeza con los codos apuntando hacia afuera. Activa el abdomen y levanta los hombros del suelo, flexionándote hacia adelante en dirección a las rodillas. Haz una pausa breve en la parte alta, luego baja lentamente los hombros de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on your back with your knees bent and feet flat on the ground. Place your hands behind your head with your elbows pointing outwards. Engage your abs and lift your shoulders off the ground, curling forward towards your knees. Pause for a moment at the top, then slowly lower your shoulders back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0274-TFqbd8t.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0274-TFqbd8t.gif', 'TFqbd8t', '© Gym visual — https://gymvisual.com/'),
('3016', 'curl-up', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Coloca las manos detrás de la cabeza con los codos apuntando hacia afuera. Activando el abdomen, levanta lentamente la parte superior del cuerpo del suelo, curvándote hacia adelante hasta que tu torso forme un áng', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"hip flexors"}', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Coloca las manos detrás de la cabeza con los codos apuntando hacia afuera. Activando el abdomen, levanta lentamente la parte superior del cuerpo del suelo, curvándote hacia adelante hasta que tu torso forme un ángulo de 45 grados. Haz una pausa por un momento en la parte superior, luego baja lentamente la parte superior del cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on your back with your knees bent and feet flat on the ground. Place your hands behind your head with your elbows pointing outwards. Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle. Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3016-g2oKspu.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3016-g2oKspu.gif', 'g2oKspu', '© Gym visual — https://gymvisual.com/'),
('3769', 'curtsey squat', 'Ponte de pie con los pies separados a la altura de los hombros. Da un paso en diagonal hacia atrás y a través de tu cuerpo con el pie derecho, cruzándolo detrás de la pierna izquierda. Flexiona ambas rodillas como si hicieras una reverencia, bajando el cuerpo hacia el suelo. Mantén el torso erguido ', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves"}', 'Ponte de pie con los pies separados a la altura de los hombros. Da un paso en diagonal hacia atrás y a través de tu cuerpo con el pie derecho, cruzándolo detrás de la pierna izquierda. Flexiona ambas rodillas como si hicieras una reverencia, bajando el cuerpo hacia el suelo. Mantén el torso erguido y el peso sobre el pie delantero. Empuja con el pie delantero para regresar a la posición inicial. Repite en el otro lado, dando un paso en diagonal hacia atrás y a través de tu cuerpo con el pie izquierdo.', 'Stand with your feet shoulder-width apart. Take a step diagonally behind and across your body with your right foot, crossing it behind your left leg. Bend both knees as if you were curtsying, lowering your body towards the ground. Keep your torso upright and your weight on your front foot. Push through your front foot to return to the starting position. Repeat on the other side, stepping diagonally behind and across your body with your left foot.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3769-gUjqdei.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3769-gUjqdei.gif', 'gUjqdei', '© Gym visual — https://gymvisual.com/'),
('2331', 'cycle cross trainer', 'Ajusta la altura del asiento y colócate en la bicicleta elíptica. Coloca los pies en los pedales y sujeta el manillar. Comienza a pedalear con un movimiento suave y controlado. Mantén un ritmo constante y aumenta la resistencia si lo deseas. Continúa pedaleando durante la duración deseada de tu entr', 'cardio', 'leverage machine', 'cardio', 'cardio', 'cardiovascular system', '{"quadriceps","hamstrings","glutes"}', 'Ajusta la altura del asiento y colócate en la bicicleta elíptica. Coloca los pies en los pedales y sujeta el manillar. Comienza a pedalear con un movimiento suave y controlado. Mantén un ritmo constante y aumenta la resistencia si lo deseas. Continúa pedaleando durante la duración deseada de tu entrenamiento cardiovascular.', 'Adjust the seat height and position yourself on the cycle cross trainer. Place your feet on the pedals and grip the handlebars. Start pedaling in a smooth and controlled motion. Maintain a steady pace and increase the resistance if desired. Continue pedaling for the desired duration of your cardio workout.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2331-XSCHmiI.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2331-XSCHmiI.gif', 'XSCHmiI', '© Gym visual — https://gymvisual.com/'),
('0276', 'dead bug', 'Túmbate boca arriba con los brazos extendidos hacia el techo. Flexiona las rodillas y levanta las piernas del suelo, formando un ángulo de 90 grados en las caderas y las rodillas. Activa el core y la zona lumbar para presionar la zona lumbar contra el suelo. Baja lentamente el brazo derecho y la pie', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"hip flexors","lower back"}', 'Túmbate boca arriba con los brazos extendidos hacia el techo. Flexiona las rodillas y levanta las piernas del suelo, formando un ángulo de 90 grados en las caderas y las rodillas. Activa el core y la zona lumbar para presionar la zona lumbar contra el suelo. Baja lentamente el brazo derecho y la pierna izquierda hacia el suelo, manteniéndolos rectos y justo por encima del suelo. Haz una pausa breve y luego vuelve a la posición inicial. Repite el movimiento con el brazo izquierdo y la pierna derecha. Continúa alternando lados durante el número de repeticiones deseado.', 'Lie flat on your back with your arms extended towards the ceiling. Bend your knees and lift your legs off the ground, creating a 90-degree angle at your hips and knees. Engage your core and lower back to press your lower back into the ground. Slowly lower your right arm and left leg towards the ground, keeping them straight and hovering just above the floor. Pause for a moment, then return to the starting position. Repeat the movement with your left arm and right leg. Continue alternating sides for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0276-iny3m5y.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0276-iny3m5y.gif', 'iny3m5y', '© Gym visual — https://gymvisual.com/'),
('0277', 'decline crunch', 'Túmbate en un banco declinado con los pies sujetos y las rodillas flexionadas en un ángulo de 90 grados. Coloca las manos detrás de la cabeza o cruzadas sobre el pecho. Activa el abdomen y levanta la parte superior del cuerpo hacia las rodillas, flexionando el torso. Haz una pausa por un momento en ', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"hip flexors"}', 'Túmbate en un banco declinado con los pies sujetos y las rodillas flexionadas en un ángulo de 90 grados. Coloca las manos detrás de la cabeza o cruzadas sobre el pecho. Activa el abdomen y levanta la parte superior del cuerpo hacia las rodillas, flexionando el torso. Haz una pausa por un momento en la parte superior, luego baja lentamente la parte superior del cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie on a decline bench with your feet secured and your knees bent at a 90-degree angle. Place your hands behind your head or across your chest. Engage your abs and lift your upper body towards your knees, curling your torso. Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0277-9Ap7miY.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0277-9Ap7miY.gif', '9Ap7miY', '© Gym visual — https://gymvisual.com/'),
('0279', 'decline push-up', 'Coloca las manos en el suelo un poco más separadas que el ancho de los hombros, con los pies elevados sobre una superficie estable. Mantén el cuerpo en línea recta de la cabeza a los pies, activando los músculos del core. Baja el pecho hacia el suelo flexionando los codos, manteniéndolos cerca del c', 'chest', 'body weight', 'chest', 'chest', 'pectorals', '{"triceps","shoulders"}', 'Coloca las manos en el suelo un poco más separadas que el ancho de los hombros, con los pies elevados sobre una superficie estable. Mantén el cuerpo en línea recta de la cabeza a los pies, activando los músculos del core. Baja el pecho hacia el suelo flexionando los codos, manteniéndolos cerca del cuerpo. Empuja con las palmas para extender los brazos y regresar a la posición inicial. Repite el número de repeticiones deseado.', 'Place your hands on the ground slightly wider than shoulder-width apart, with your feet elevated on a stable surface. Keep your body in a straight line from head to toe, engaging your core muscles. Lower your chest towards the ground by bending your elbows, keeping them close to your body. Push through your palms to extend your arms and return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0279-i5cEhka.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0279-i5cEhka.gif', 'i5cEhka', '© Gym visual — https://gymvisual.com/'),
('0282', 'decline sit-up', 'Túmbate en un banco declinado con los pies sujetos y las rodillas flexionadas. Coloca las manos detrás de la cabeza o cruzadas sobre el pecho. Activa el abdomen y levanta la parte superior del cuerpo del banco, flexionándote hacia adelante en dirección a las rodillas. Haz una pausa por un momento en', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"hip flexors","lower back"}', 'Túmbate en un banco declinado con los pies sujetos y las rodillas flexionadas. Coloca las manos detrás de la cabeza o cruzadas sobre el pecho. Activa el abdomen y levanta la parte superior del cuerpo del banco, flexionándote hacia adelante en dirección a las rodillas. Haz una pausa por un momento en la parte superior, luego baja lentamente la parte superior del cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie on a decline bench with your feet secured and your knees bent. Place your hands behind your head or across your chest. Engage your abs and lift your upper body off the bench, curling forward towards your knees. Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0282-QLL2gdc.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0282-QLL2gdc.gif', 'QLL2gdc', '© Gym visual — https://gymvisual.com/'),
('1274', 'deep push up', 'Comienza en posición de plancha alta con las manos un poco más separadas que el ancho de los hombros y el cuerpo en línea recta. Baja el pecho hacia el suelo flexionando los codos, manteniéndolos cerca del cuerpo. Empuja con las palmas para extender los brazos y regresar a la posición inicial. Repit', 'chest', 'dumbbell', 'chest', 'chest', 'pectorals', '{"triceps","shoulders"}', 'Comienza en posición de plancha alta con las manos un poco más separadas que el ancho de los hombros y el cuerpo en línea recta. Baja el pecho hacia el suelo flexionando los codos, manteniéndolos cerca del cuerpo. Empuja con las palmas para extender los brazos y regresar a la posición inicial. Repite el número de repeticiones deseado.', 'Start in a high plank position with your hands slightly wider than shoulder-width apart and your body in a straight line. Lower your chest towards the ground by bending your elbows, keeping them close to your body. Push through your palms to extend your arms and return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1274-vptOQ4N.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1274-vptOQ4N.gif', 'vptOQ4N', '© Gym visual — https://gymvisual.com/'),
('0283', 'diamond push-up', 'Comienza en posición de plancha alta con las manos juntas, formando una figura de diamante con los pulgares y los índices. Mantén el cuerpo en línea recta de la cabeza a los pies, activando el core y los glúteos. Baja el pecho hacia la figura de diamante formada por tus manos, manteniendo los codos ', 'upper arms', 'body weight', 'upper arms', 'upper arms', 'triceps', '{"chest","shoulders"}', 'Comienza en posición de plancha alta con las manos juntas, formando una figura de diamante con los pulgares y los índices. Mantén el cuerpo en línea recta de la cabeza a los pies, activando el core y los glúteos. Baja el pecho hacia la figura de diamante formada por tus manos, manteniendo los codos cerca del cuerpo. Haz una pausa por un momento en la parte inferior, luego empuja tu cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Start in a high plank position with your hands close together, forming a diamond shape with your thumbs and index fingers. Keep your body in a straight line from head to toe, engaging your core and glutes. Lower your chest towards the diamond shape formed by your hands, keeping your elbows close to your body. Pause for a moment at the bottom, then push yourself back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0283-soIB2rj.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0283-soIB2rj.gif', 'soIB2rj', '© Gym visual — https://gymvisual.com/'),
('0284', 'donkey calf raise', 'Ponte de pie con las puntas de los pies sobre una superficie elevada, como un escalón o un bloque. Coloca las manos en un soporte estable, como una pared o un pasamanos, para mantener el equilibrio. Levanta los talones lo más alto posible, elevando el peso de tu cuerpo sobre las puntas de los pies. ', 'lower legs', 'body weight', 'lower legs', 'lower legs', 'calves', '{"hamstrings","glutes"}', 'Ponte de pie con las puntas de los pies sobre una superficie elevada, como un escalón o un bloque. Coloca las manos en un soporte estable, como una pared o un pasamanos, para mantener el equilibrio. Levanta los talones lo más alto posible, elevando el peso de tu cuerpo sobre las puntas de los pies. Haz una pausa breve en la parte alta y luego baja lentamente los talones de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your toes on an elevated surface, such as a step or block. Place your hands on a stable support, such as a wall or railing, for balance. Raise your heels as high as possible, lifting your body weight onto the balls of your feet. Pause for a moment at the top, then slowly lower your heels back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0284-u5ESqzH.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0284-u5ESqzH.gif', 'u5ESqzH', '© Gym visual — https://gymvisual.com/'),
('1275', 'drop push up', 'Comienza en posición de plancha alta con las manos un poco más separadas que el ancho de los hombros. Baja el pecho hacia el suelo, manteniendo los codos cerca del cuerpo. Una vez que tu pecho esté justo por encima del suelo, baja rápidamente las rodillas al suelo. Empuja tu cuerpo de vuelta a la po', 'chest', 'body weight', 'chest', 'chest', 'pectorals', '{"triceps","shoulders"}', 'Comienza en posición de plancha alta con las manos un poco más separadas que el ancho de los hombros. Baja el pecho hacia el suelo, manteniendo los codos cerca del cuerpo. Una vez que tu pecho esté justo por encima del suelo, baja rápidamente las rodillas al suelo. Empuja tu cuerpo de vuelta a la posición inicial extendiendo los brazos. Repite el número de repeticiones deseado.', 'Start in a high plank position with your hands slightly wider than shoulder-width apart. Lower your chest towards the ground, keeping your elbows close to your body. Once your chest is just above the ground, quickly drop your knees to the ground. Push yourself back up to the starting position by extending your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1275-Q497lAE.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1275-Q497lAE.gif', 'Q497lAE', '© Gym visual — https://gymvisual.com/'),
('0285', 'dumbbell alternate biceps curl', 'Ponte de pie con una mancuerna en cada mano, con las palmas hacia adelante y los brazos completamente extendidos. Manteniendo los brazos superiores fijos, exhala y levanta el peso mientras contraes los bíceps. Continúa levantando las mancuernas hasta que los bíceps estén completamente contraídos y l', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ponte de pie con una mancuerna en cada mano, con las palmas hacia adelante y los brazos completamente extendidos. Manteniendo los brazos superiores fijos, exhala y levanta el peso mientras contraes los bíceps. Continúa levantando las mancuernas hasta que los bíceps estén completamente contraídos y las mancuernas estén a la altura de los hombros. Mantén la posición contraída durante una breve pausa mientras aprietas los bíceps. Inhala y comienza a bajar lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado, alternando los brazos.', 'Stand up straight with a dumbbell in each hand, palms facing forward and arms fully extended. Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly begin to lower the dumbbells back to the starting position. Repeat for the desired number of repetitions, alternating arms.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0285-BU15nH4.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0285-BU15nH4.gif', 'BU15nH4', '© Gym visual — https://gymvisual.com/'),
('2403', 'dumbbell alternate biceps curl (with arm blaster)', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una mancuerna en cada mano, con las palmas hacia adelante. Coloca el soporte para brazos en la parte superior de tus brazos, asegurándote de que quede bien ajustado. Manteniendo los brazos superiores quietos, exhala y flexiona u', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una mancuerna en cada mano, con las palmas hacia adelante. Coloca el soporte para brazos en la parte superior de tus brazos, asegurándote de que quede bien ajustado. Manteniendo los brazos superiores quietos, exhala y flexiona una mancuerna hacia el hombro mientras contraes el bíceps. Continúa levantando la mancuerna hasta que el bíceps esté completamente contraído y la mancuerna esté a la altura del hombro. Mantén la posición contraída durante una breve pausa mientras aprietas los bíceps. Inhala y baja lentamente la mancuerna de vuelta a la posición inicial. Repite el movimiento con el brazo contrario. Continúa alternando los brazos durante el número de repeticiones deseado.', 'Stand up straight with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing forward. Place the arm blaster on your upper arms, ensuring a secure fit. Keeping your upper arms stationary, exhale and curl one dumbbell up towards your shoulder while contracting your biceps. Continue to raise the dumbbell until your biceps are fully contracted and the dumbbell is at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly lower the dumbbell back to the starting position. Repeat the movement with the opposite arm. Continue alternating arms for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2403-CfKsRbG.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2403-CfKsRbG.gif', 'CfKsRbG', '© Gym visual — https://gymvisual.com/'),
('1646', 'dumbbell alternate hammer preacher curl', 'Siéntate en un banco scott con una mancuerna en cada mano, con las palmas hacia tu torso y los brazos completamente extendidos. Mantén los brazos superiores fijos y exhala mientras levantas el peso contrayendo los bíceps. Continúa levantando las mancuernas hasta que los bíceps estén completamente co', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Siéntate en un banco scott con una mancuerna en cada mano, con las palmas hacia tu torso y los brazos completamente extendidos. Mantén los brazos superiores fijos y exhala mientras levantas el peso contrayendo los bíceps. Continúa levantando las mancuernas hasta que los bíceps estén completamente contraídos y las mancuernas estén a la altura de los hombros. Mantén la posición contraída durante una breve pausa mientras aprietas los bíceps. Inhala y comienza a bajar lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones recomendado.', 'Sit on a preacher bench with a dumbbell in each hand, palms facing your torso and arms fully extended. Keep your upper arms stationary and exhale as you curl the weights while contracting your biceps. Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly begin to lower the dumbbells back to the starting position. Repeat for the recommended amount of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1646-fy7Tgy4.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1646-fy7Tgy4.gif', 'fy7Tgy4', '© Gym visual — https://gymvisual.com/'),
('1647', 'dumbbell alternate preacher curl', 'Siéntate en un banco scott con una mancuerna en cada mano, con las palmas hacia arriba. Apoya la parte superior de los brazos en la almohadilla del banco scott, permitiendo que los brazos se extiendan completamente. Manteniendo los brazos superiores quietos, exhala y flexiona la mancuerna en tu mano', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Siéntate en un banco scott con una mancuerna en cada mano, con las palmas hacia arriba. Apoya la parte superior de los brazos en la almohadilla del banco scott, permitiendo que los brazos se extiendan completamente. Manteniendo los brazos superiores quietos, exhala y flexiona la mancuerna en tu mano derecha mientras contraes el bíceps. Continúa flexionando la mancuerna hasta que el bíceps esté completamente contraído y la mancuerna esté a la altura del hombro. Haz una pausa breve, luego inhala y baja lentamente la mancuerna de vuelta a la posición inicial. Repite el movimiento con el brazo izquierdo. Continúa alternando los brazos durante el número de repeticiones deseado.', 'Sit on a preacher bench with a dumbbell in each hand, palms facing up. Rest your upper arms on the pad of the preacher bench, allowing your arms to fully extend. Keeping your upper arms stationary, exhale and curl the dumbbell in your right hand as you contract your biceps. Continue to curl the dumbbell until your biceps are fully contracted and the dumbbell is at shoulder level. Pause for a moment, then inhale and slowly lower the dumbbell back to the starting position. Repeat the movement with your left arm. Continue alternating arms for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1647-NlfIbzq.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1647-NlfIbzq.gif', 'NlfIbzq', '© Gym visual — https://gymvisual.com/'),
('1648', 'dumbbell alternate seated hammer curl', 'Siéntate en un banco con una mancuerna en cada mano, con las palmas hacia tu torso y los brazos extendidos hacia abajo. Mantén la espalda recta y los codos cerca del torso. Exhala y flexiona la mancuerna de tu mano derecha hacia el hombro, manteniendo el brazo superior quieto. Continúa levantando la', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Siéntate en un banco con una mancuerna en cada mano, con las palmas hacia tu torso y los brazos extendidos hacia abajo. Mantén la espalda recta y los codos cerca del torso. Exhala y flexiona la mancuerna de tu mano derecha hacia el hombro, manteniendo el brazo superior quieto. Continúa levantando la mancuerna hasta que el bíceps esté completamente contraído y la mancuerna esté a la altura del hombro. Haz una pausa breve, luego inhala y baja lentamente la mancuerna de vuelta a la posición inicial. Repite el movimiento con el brazo izquierdo. Continúa alternando los brazos durante el número de repeticiones deseado.', 'Sit on a bench with a dumbbell in each hand, palms facing your torso and arms extended down. Keep your back straight and your elbows close to your torso. Exhale and curl the dumbbell in your right hand towards your shoulder, keeping your upper arm stationary. Continue to raise the dumbbell until your biceps are fully contracted and the dumbbell is at shoulder level. Pause for a brief moment, then inhale and slowly lower the dumbbell back to the starting position. Repeat the movement with your left arm. Continue alternating arms for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1648-6em2Dxj.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1648-6em2Dxj.gif', '6em2Dxj', '© Gym visual — https://gymvisual.com/'),
('0286', 'dumbbell alternate side press', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una mancuerna en cada mano a la altura de los hombros. Empuja una mancuerna por encima de la cabeza mientras mantienes la otra mancuerna a la altura del hombro. Baja la mancuerna empujada de vuelta a la altura del hombro mient', 'shoulders', 'dumbbell', 'shoulders', 'shoulders', 'delts', '{"triceps","core"}', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una mancuerna en cada mano a la altura de los hombros. Empuja una mancuerna por encima de la cabeza mientras mantienes la otra mancuerna a la altura del hombro. Baja la mancuerna empujada de vuelta a la altura del hombro mientras empujas la otra mancuerna por encima de la cabeza. Continúa alternando lados durante el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, holding a dumbbell in each hand at shoulder height. Press one dumbbell overhead while keeping the other dumbbell at shoulder height. Lower the pressed dumbbell back to shoulder height while pressing the other dumbbell overhead. Continue alternating sides for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0286-izMnLqz.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0286-izMnLqz.gif', 'izMnLqz', '© Gym visual — https://gymvisual.com/'),
('1649', 'dumbbell alternating bicep curl with leg raised on exercise ball', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una mancuerna en cada mano, con las palmas hacia adelante. Coloca un balón de ejercicio detrás de ti y apoya un pie sobre él, manteniendo el equilibrio. Con los brazos completamente extendidos y los codos cerca de los costados, ', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms","shoulders"}', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una mancuerna en cada mano, con las palmas hacia adelante. Coloca un balón de ejercicio detrás de ti y apoya un pie sobre él, manteniendo el equilibrio. Con los brazos completamente extendidos y los codos cerca de los costados, flexiona una mancuerna hacia el hombro mientras mantienes el brazo superior quieto. Baja la mancuerna de vuelta a la posición inicial y repite con el otro brazo. Continúa alternando los brazos durante el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing forward. Place an exercise ball behind you and position one foot on top of it, keeping your balance. With your arms fully extended and elbows close to your sides, curl one dumbbell towards your shoulder while keeping your upper arm stationary. Lower the dumbbell back down to the starting position and repeat with the other arm. Continue alternating arms for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1649-Zwiw7XR.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1649-Zwiw7XR.gif', 'Zwiw7XR', '© Gym visual — https://gymvisual.com/'),
('1650', 'dumbbell alternating seated bicep curl on exercise ball', 'Siéntate sobre un balón de ejercicio con los pies apoyados planos en el suelo y la espalda recta. Sujeta una mancuerna en cada mano con las palmas hacia adelante y los brazos completamente extendidos. Manteniendo los brazos superiores quietos, exhala y flexiona una mancuerna mientras rotas el antebr', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Siéntate sobre un balón de ejercicio con los pies apoyados planos en el suelo y la espalda recta. Sujeta una mancuerna en cada mano con las palmas hacia adelante y los brazos completamente extendidos. Manteniendo los brazos superiores quietos, exhala y flexiona una mancuerna mientras rotas el antebrazo hasta que la palma quede frente al hombro. Inhala y baja lentamente la mancuerna de vuelta a la posición inicial. Repite la flexión con el otro brazo. Continúa alternando flexiones el número de repeticiones deseado.', 'Sit on an exercise ball with your feet flat on the ground and your back straight. Hold a dumbbell in each hand with your palms facing forward and your arms fully extended. Keeping your upper arms stationary, exhale and curl one dumbbell while rotating your forearm until your palm is facing your shoulder. Inhale and slowly lower the dumbbell back to the starting position. Repeat the curl with the other arm. Continue alternating curls for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1650-J74XlNf.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1650-J74XlNf.gif', 'J74XlNf', '© Gym visual — https://gymvisual.com/'),
('2137', 'dumbbell arnold press', 'Siéntate en un banco con respaldo y sujeta una mancuerna en cada mano a la altura del hombro, con las palmas hacia tu cuerpo y los codos flexionados. Empuja las mancuernas hacia arriba hasta que los brazos estén completamente extendidos y las palmas miren hacia adelante. Rota las muñecas mientras le', 'shoulders', 'dumbbell', 'shoulders', 'shoulders', 'delts', '{"triceps","upper chest"}', 'Siéntate en un banco con respaldo y sujeta una mancuerna en cada mano a la altura del hombro, con las palmas hacia tu cuerpo y los codos flexionados. Empuja las mancuernas hacia arriba hasta que los brazos estén completamente extendidos y las palmas miren hacia adelante. Rota las muñecas mientras levantas, de modo que las palmas miren hacia adelante en la parte alta del movimiento. Haz una pausa breve en la parte alta, luego baja lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a bench with back support and hold a dumbbell in each hand at shoulder level, palms facing your body and elbows bent. Press the dumbbells upward until your arms are fully extended and your palms are facing forward. Rotate your wrists as you lift, so that your palms are facing forward at the top of the movement. Pause for a moment at the top, then slowly lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2137-Xy4jlWA.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2137-Xy4jlWA.gif', 'Xy4jlWA', '© Gym visual — https://gymvisual.com/'),
('0287', 'dumbbell arnold press v. 2', 'Siéntate en un banco con respaldo y sujeta una mancuerna en cada mano a la altura del hombro, con las palmas hacia tu cuerpo y los codos flexionados. Empuja las mancuernas hacia arriba hasta que los brazos estén completamente extendidos y las palmas miren hacia adelante. Rota las muñecas mientras le', 'shoulders', 'dumbbell', 'shoulders', 'shoulders', 'delts', '{"triceps","upper chest"}', 'Siéntate en un banco con respaldo y sujeta una mancuerna en cada mano a la altura del hombro, con las palmas hacia tu cuerpo y los codos flexionados. Empuja las mancuernas hacia arriba hasta que los brazos estén completamente extendidos y las palmas miren hacia adelante. Rota las muñecas mientras levantas, de modo que las palmas terminen mirando hacia adelante en la parte alta del movimiento. Haz una pausa breve en la parte alta, luego baja lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a bench with back support and hold a dumbbell in each hand at shoulder level, palms facing your body and elbows bent. Press the dumbbells upward until your arms are fully extended and your palms are facing forward. Rotate your wrists as you lift, so that your palms end up facing forward at the top of the movement. Pause for a moment at the top, then slowly lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0287-eOrFCnx.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0287-eOrFCnx.gif', 'eOrFCnx', '© Gym visual — https://gymvisual.com/'),
('0288', 'dumbbell around pullover', 'Túmbate en un banco con la cabeza en un extremo y los pies firmemente apoyados en el suelo. Sujeta una mancuerna con ambas manos y extiende los brazos rectos por encima del pecho. Manteniendo los brazos rectos, baja lentamente la mancuerna detrás de la cabeza en un movimiento de arco. Haz una pausa ', 'chest', 'dumbbell', 'chest', 'chest', 'pectorals', '{"triceps","latissimus dorsi"}', 'Túmbate en un banco con la cabeza en un extremo y los pies firmemente apoyados en el suelo. Sujeta una mancuerna con ambas manos y extiende los brazos rectos por encima del pecho. Manteniendo los brazos rectos, baja lentamente la mancuerna detrás de la cabeza en un movimiento de arco. Haz una pausa breve en la parte baja, luego levanta la mancuerna de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on a bench with your head at one end and your feet firmly on the ground. Hold a dumbbell with both hands and extend your arms straight above your chest. Keeping your arms straight, slowly lower the dumbbell behind your head in an arc motion. Pause for a moment at the bottom, then raise the dumbbell back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0288-vi8EhoE.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0288-vi8EhoE.gif', 'vi8EhoE', '© Gym visual — https://gymvisual.com/'),
('0289', 'dumbbell bench press', 'Túmbate sobre un banco con los pies apoyados en el suelo y la espalda presionada contra el banco. Sujeta una mancuerna en cada mano, con las palmas hacia adelante y los brazos extendidos por encima del pecho. Baja lentamente las mancuernas hacia los lados del pecho, manteniendo los codos en un ángul', 'chest', 'dumbbell', 'chest', 'chest', 'pectorals', '{"triceps","shoulders"}', 'Túmbate sobre un banco con los pies apoyados en el suelo y la espalda presionada contra el banco. Sujeta una mancuerna en cada mano, con las palmas hacia adelante y los brazos extendidos por encima del pecho. Baja lentamente las mancuernas hacia los lados del pecho, manteniendo los codos en un ángulo de 90 grados. Haz una pausa breve, luego empuja las mancuernas de vuelta hacia arriba hasta la posición inicial, extendiendo completamente los brazos. Repite el número de repeticiones deseado.', 'Lie flat on a bench with your feet flat on the ground and your back pressed against the bench. Hold a dumbbell in each hand, with your palms facing forward and your arms extended above your chest. Lower the dumbbells slowly to the sides of your chest, keeping your elbows at a 90-degree angle. Pause for a moment, then push the dumbbells back up to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0289-SpYC0Kp.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0289-SpYC0Kp.gif', 'SpYC0Kp', '© Gym visual — https://gymvisual.com/'),
('0290', 'dumbbell bench seated press', 'Siéntate en un banco con una mancuerna en cada mano, apoyadas en los muslos. Reclínate hacia atrás y coloca las mancuernas a los lados del pecho, con las palmas hacia adelante. Empuja las mancuernas hacia arriba hasta que los brazos estén completamente extendidos. Haz una pausa breve en la parte alt', 'shoulders', 'dumbbell', 'shoulders', 'shoulders', 'delts', '{"triceps","chest"}', 'Siéntate en un banco con una mancuerna en cada mano, apoyadas en los muslos. Reclínate hacia atrás y coloca las mancuernas a los lados del pecho, con las palmas hacia adelante. Empuja las mancuernas hacia arriba hasta que los brazos estén completamente extendidos. Haz una pausa breve en la parte alta, luego baja lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a bench with a dumbbell in each hand, resting on your thighs. Lean back and position the dumbbells to the sides of your chest, palms facing forward. Press the dumbbells upward until your arms are fully extended. Pause for a moment at the top, then slowly lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0290-3d7wHyd.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0290-3d7wHyd.gif', '3d7wHyd', '© Gym visual — https://gymvisual.com/'),
('0291', 'dumbbell bench squat', 'Coloca una mancuerna en el suelo frente a un banco. Ponte de pie de espaldas al banco con los pies separados a la altura de los hombros. Flexiona las rodillas y las caderas para bajar hacia el banco, manteniendo el pecho elevado y la espalda recta. Una vez que los glúteos toquen el banco, empuja con', 'upper legs', 'dumbbell', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves"}', 'Coloca una mancuerna en el suelo frente a un banco. Ponte de pie de espaldas al banco con los pies separados a la altura de los hombros. Flexiona las rodillas y las caderas para bajar hacia el banco, manteniendo el pecho elevado y la espalda recta. Una vez que los glúteos toquen el banco, empuja con los talones para volver a ponerte de pie en la posición inicial. Repite el número de repeticiones deseado.', 'Place a dumbbell on the ground in front of a bench. Stand facing away from the bench with your feet shoulder-width apart. Bend at the knees and hips to lower yourself down towards the bench, keeping your chest up and back straight. Once your glutes touch the bench, push through your heels to stand back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0291-mnzcrIB.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0291-mnzcrIB.gif', 'mnzcrIB', '© Gym visual — https://gymvisual.com/'),
('0293', 'dumbbell bent over row', 'Ponte de pie con los pies separados a la altura de los hombros, las rodillas ligeramente flexionadas, y sujeta una mancuerna en cada mano con las palmas hacia tu cuerpo. Inclínate hacia adelante desde las caderas, manteniendo la espalda recta y el core activado. Deja que los brazos cuelguen rectos h', 'back', 'dumbbell', 'back', 'back', 'upper back', '{"biceps","forearms"}', 'Ponte de pie con los pies separados a la altura de los hombros, las rodillas ligeramente flexionadas, y sujeta una mancuerna en cada mano con las palmas hacia tu cuerpo. Inclínate hacia adelante desde las caderas, manteniendo la espalda recta y el core activado. Deja que los brazos cuelguen rectos hacia el suelo, con los codos ligeramente flexionados. Tira de las mancuernas hacia arriba, hacia el pecho, apretando los omóplatos entre sí. Haz una pausa breve en la parte alta, luego baja lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, knees slightly bent, and hold a dumbbell in each hand with your palms facing your body. Bend forward at the hips, keeping your back straight and your core engaged. Let your arms hang straight down towards the floor, with your elbows slightly bent. Pull the dumbbells up towards your chest, squeezing your shoulder blades together. Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0293-BJ0Hz5L.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0293-BJ0Hz5L.gif', 'BJ0Hz5L', '© Gym visual — https://gymvisual.com/'),
('1651', 'dumbbell bicep curl lunge with bowling motion', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una mancuerna en cada mano con las palmas hacia adelante. Da un paso adelante con el pie derecho, flexionando la rodilla derecha y bajando el cuerpo a una posición de zancada. Mientras avanzas en la zancada, flexiona las mancu', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms","shoulders"}', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una mancuerna en cada mano con las palmas hacia adelante. Da un paso adelante con el pie derecho, flexionando la rodilla derecha y bajando el cuerpo a una posición de zancada. Mientras avanzas en la zancada, flexiona las mancuernas hacia los hombros, manteniendo los codos cerca del cuerpo. En la parte baja de la zancada, gira el torso hacia la derecha, como si estuvieras lanzando una bola de boliche. Invierte el movimiento, retrocediendo con el pie derecho y regresando a la posición inicial mientras bajas las mancuernas de nuevo. Repite el movimiento de zancada y flexión, esta vez girando el torso hacia la izquierda. Continúa alternando lados durante el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing forward. Take a step forward with your right foot, bending your right knee and lowering your body into a lunge position. As you lunge forward, curl the dumbbells up towards your shoulders, keeping your elbows close to your body. At the bottom of the lunge, rotate your torso to the right, as if you were bowling a ball. Reverse the motion, stepping back with your right foot and returning to the starting position while lowering the dumbbells back down. Repeat the lunge and curl motion, this time rotating your torso to the left. Continue alternating sides for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1651-1VpF8db.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1651-1VpF8db.gif', '1VpF8db', '© Gym visual — https://gymvisual.com/'),
('1652', 'dumbbell bicep curl on exercise ball with leg raised', 'Siéntate sobre un balón de ejercicio con los pies apoyados planos en el suelo y la espalda recta. Sujeta una mancuerna en cada mano con las palmas hacia adelante y los brazos completamente extendidos. Flexiona lentamente las mancuernas hacia los hombros, manteniendo los codos cerca de los costados. ', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms","shoulders"}', 'Siéntate sobre un balón de ejercicio con los pies apoyados planos en el suelo y la espalda recta. Sujeta una mancuerna en cada mano con las palmas hacia adelante y los brazos completamente extendidos. Flexiona lentamente las mancuernas hacia los hombros, manteniendo los codos cerca de los costados. Haz una pausa breve en la parte alta del movimiento, luego baja lentamente las mancuernas de vuelta a la posición inicial. Mientras realizas el curl de bíceps, levanta una pierna del suelo y mantenla en el aire durante todo el ejercicio. Repite el número de repeticiones deseado y luego cambia de pierna y repite.', 'Sit on an exercise ball with your feet flat on the ground and your back straight. Hold a dumbbell in each hand with your palms facing forward and your arms fully extended. Slowly curl the dumbbells towards your shoulders, keeping your elbows close to your sides. Pause for a moment at the top of the movement, then slowly lower the dumbbells back to the starting position. While performing the bicep curl, raise one leg off the ground and hold it in the air for the duration of the exercise. Repeat for the desired number of repetitions, then switch legs and repeat.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1652-2NImIAG.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1652-2NImIAG.gif', '2NImIAG', '© Gym visual — https://gymvisual.com/'),
('1653', 'dumbbell bicep curl with stork stance', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una mancuerna en cada mano, con las palmas hacia adelante. Extiende una pierna hacia atrás, equilibrándote sobre los dedos de ese pie. Manteniendo los brazos superiores fijos, exhala y levanta el peso mientras contraes los bícep', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una mancuerna en cada mano, con las palmas hacia adelante. Extiende una pierna hacia atrás, equilibrándote sobre los dedos de ese pie. Manteniendo los brazos superiores fijos, exhala y levanta el peso mientras contraes los bíceps. Continúa levantando las pesas hasta que los bíceps estén completamente contraídos y las mancuernas estén a la altura de los hombros. Mantén la posición contraída durante una breve pausa mientras aprietas los bíceps. Inhala y comienza a bajar lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado y luego cambia de pierna y repite.', 'Stand with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing forward. Extend one leg behind you, balancing on the toes of that foot. Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly begin to lower the dumbbells back to the starting position. Repeat for the desired number of repetitions, then switch legs and repeat.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1653-uSkDMYl.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1653-uSkDMYl.gif', 'uSkDMYl', '© Gym visual — https://gymvisual.com/'),
('0294', 'dumbbell biceps curl', 'Ponte de pie con una mancuerna en cada mano, con las palmas hacia adelante y los brazos completamente extendidos. Manteniendo los brazos superiores fijos, exhala y levanta el peso mientras contraes los bíceps. Continúa levantando las pesas hasta que los bíceps estén completamente contraídos y las ma', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ponte de pie con una mancuerna en cada mano, con las palmas hacia adelante y los brazos completamente extendidos. Manteniendo los brazos superiores fijos, exhala y levanta el peso mientras contraes los bíceps. Continúa levantando las pesas hasta que los bíceps estén completamente contraídos y las mancuernas estén a la altura de los hombros. Mantén la posición contraída durante una breve pausa mientras aprietas los bíceps. Inhala y comienza a bajar lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand up straight with a dumbbell in each hand, palms facing forward and arms fully extended. Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly begin to lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0294-NbVPDMW.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0294-NbVPDMW.gif', 'NbVPDMW', '© Gym visual — https://gymvisual.com/'),
('2401', 'dumbbell biceps curl (with arm blaster)', 'Ponte de pie con una mancuerna en cada mano, con las palmas hacia adelante. Mantén los codos cerca del torso y los brazos superiores quietos. Exhala y flexiona las pesas mientras contraes los bíceps. Continúa levantando las pesas hasta que los bíceps estén completamente contraídos y las mancuernas e', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ponte de pie con una mancuerna en cada mano, con las palmas hacia adelante. Mantén los codos cerca del torso y los brazos superiores quietos. Exhala y flexiona las pesas mientras contraes los bíceps. Continúa levantando las pesas hasta que los bíceps estén completamente contraídos y las mancuernas estén a la altura de los hombros. Mantén la posición contraída durante una breve pausa mientras aprietas los bíceps. Inhala y comienza a bajar lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand up straight with a dumbbell in each hand, palms facing forward. Keep your elbows close to your torso and your upper arms stationary. Exhale and curl the weights while contracting your biceps. Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly begin to lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2401-nlJsbkW.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2401-nlJsbkW.gif', 'nlJsbkW', '© Gym visual — https://gymvisual.com/'),
('1654', 'dumbbell biceps curl reverse', 'Ponte de pie con una mancuerna en cada mano, con las palmas hacia abajo y los brazos completamente extendidos. Manteniendo los brazos superiores fijos, exhala y levanta el peso mientras contraes los bíceps. Continúa levantando las mancuernas hasta que los bíceps estén completamente contraídos y las ', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ponte de pie con una mancuerna en cada mano, con las palmas hacia abajo y los brazos completamente extendidos. Manteniendo los brazos superiores fijos, exhala y levanta el peso mientras contraes los bíceps. Continúa levantando las mancuernas hasta que los bíceps estén completamente contraídos y las mancuernas estén a la altura de los hombros. Mantén la posición contraída durante una breve pausa mientras aprietas los bíceps. Inhala y comienza a bajar lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand up straight with a dumbbell in each hand, palms facing down and arms fully extended. Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly begin to lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1654-nFc4FyV.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1654-nFc4FyV.gif', 'nFc4FyV', '© Gym visual — https://gymvisual.com/'),
('1655', 'dumbbell biceps curl squat', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una mancuerna en cada mano con las palmas hacia adelante. Manteniendo la espalda recta y los codos cerca de los costados, exhala y flexiona las mancuernas hacia los hombros. Haz una pausa breve en la parte alta, apretando los ', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una mancuerna en cada mano con las palmas hacia adelante. Manteniendo la espalda recta y los codos cerca de los costados, exhala y flexiona las mancuernas hacia los hombros. Haz una pausa breve en la parte alta, apretando los bíceps. Inhala y baja lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing forward. Keeping your back straight and your elbows close to your sides, exhale and curl the dumbbells up towards your shoulders. Pause for a moment at the top, squeezing your biceps. Inhale and slowly lower the dumbbells back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1655-niXESDw.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1655-niXESDw.gif', 'niXESDw', '© Gym visual — https://gymvisual.com/'),
('1656', 'dumbbell biceps curl v sit on bosu ball', 'Siéntate en un bosu con los pies planos en el suelo y las rodillas flexionadas en un ángulo de 90 grados. Sujeta una mancuerna en cada mano con las palmas hacia adelante y los brazos completamente extendidos hacia abajo a los lados. Manteniendo los brazos superiores fijos, exhala y levanta el peso m', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms","shoulders"}', 'Siéntate en un bosu con los pies planos en el suelo y las rodillas flexionadas en un ángulo de 90 grados. Sujeta una mancuerna en cada mano con las palmas hacia adelante y los brazos completamente extendidos hacia abajo a los lados. Manteniendo los brazos superiores fijos, exhala y levanta el peso mientras contraes los bíceps. Continúa levantando las mancuernas hasta que los bíceps estén completamente contraídos y las mancuernas estén a la altura de los hombros. Mantén la posición contraída durante una breve pausa mientras aprietas los bíceps. Inhala y comienza a bajar lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a bosu ball with your feet flat on the ground and your knees bent at a 90-degree angle. Hold a dumbbell in each hand with your palms facing forward and your arms fully extended down by your sides. Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly begin to lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1656-H1XAdpk.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1656-H1XAdpk.gif', 'H1XAdpk', '© Gym visual — https://gymvisual.com/'),
('1201', 'dumbbell burpee', 'Comienza de pie con los pies separados a la altura de los hombros y una mancuerna en cada mano. Baja el cuerpo a una posición de sentadilla, colocando las mancuernas en el suelo frente a ti. Lleva los pies hacia atrás a una posición de flexión de brazos, manteniendo el cuerpo en línea recta. Realiza', 'cardio', 'dumbbell', 'cardio', 'cardio', 'cardiovascular system', '{"quadriceps","hamstrings","calves","shoulders","triceps","core"}', 'Comienza de pie con los pies separados a la altura de los hombros y una mancuerna en cada mano. Baja el cuerpo a una posición de sentadilla, colocando las mancuernas en el suelo frente a ti. Lleva los pies hacia atrás a una posición de flexión de brazos, manteniendo el cuerpo en línea recta. Realiza una flexión de brazos, flexionando los codos y bajando el pecho hacia el suelo. Salta con los pies hacia tus manos, aterrizando en una posición de sentadilla. Ponte de pie de forma explosiva, levantando las mancuernas del suelo y llevándolas a los hombros. Empuja las mancuernas por encima de la cabeza, extendiendo completamente los brazos. Baja las mancuernas de vuelta a los hombros y repite toda la secuencia el número de repeticiones deseado.', 'Start in a standing position with your feet shoulder-width apart and a dumbbell in each hand. Lower your body into a squat position, placing the dumbbells on the ground in front of you. Kick your feet back into a push-up position, keeping your body in a straight line. Perform a push-up, bending your elbows and lowering your chest towards the ground. Jump your feet back towards your hands, landing in a squat position. Stand up explosively, lifting the dumbbells off the ground and bringing them to your shoulders. Press the dumbbells overhead, fully extending your arms. Lower the dumbbells back to your shoulders and repeat the entire sequence for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1201-0JtKWum.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1201-0JtKWum.gif', '0JtKWum', '© Gym visual — https://gymvisual.com/'),
('0295', 'dumbbell clean', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una mancuerna en cada mano con un agarre prono. Flexiona las rodillas y baja las caderas hacia una posición de sentadilla, manteniendo la espalda recta y el pecho elevado. Extiende las caderas y las rodillas de forma explosiva', 'upper legs', 'dumbbell', 'upper legs', 'upper legs', 'glutes', '{"hamstrings","quadriceps","calves"}', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una mancuerna en cada mano con un agarre prono. Flexiona las rodillas y baja las caderas hacia una posición de sentadilla, manteniendo la espalda recta y el pecho elevado. Extiende las caderas y las rodillas de forma explosiva, empujando con los talones para saltar del suelo. Mientras saltas, encoge los hombros y tira de las mancuernas hacia arriba, hacia los hombros, manteniéndolas cerca del cuerpo. Atrapa las mancuernas a la altura de los hombros, con los codos apuntando hacia adelante y las palmas hacia arriba. Baja las mancuernas de vuelta a la posición inicial invirtiendo el movimiento. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, holding a dumbbell in each hand with an overhand grip. Bend your knees and lower your hips into a squat position, keeping your back straight and chest up. Explosively extend your hips and knees, driving through your heels to jump off the ground. As you jump, shrug your shoulders and pull the dumbbells up towards your shoulders, keeping them close to your body. Catch the dumbbells at shoulder height, with your elbows pointing forward and your palms facing up. Lower the dumbbells back down to the starting position by reversing the movement. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0295-7Hg55JG.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0295-7Hg55JG.gif', '7Hg55JG', '© Gym visual — https://gymvisual.com/'),
('1731', 'dumbbell close grip press', 'Siéntate en un banco plano con una mancuerna en cada mano, apoyadas en los muslos. Usando los muslos para ayudar a levantar las mancuernas, levanta las mancuernas una a la vez para poder sostenerlas frente a ti a la altura de los hombros. Una vez a la altura de los hombros, rota las muñecas hacia ad', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'triceps', '{"chest","shoulders"}', 'Siéntate en un banco plano con una mancuerna en cada mano, apoyadas en los muslos. Usando los muslos para ayudar a levantar las mancuernas, levanta las mancuernas una a la vez para poder sostenerlas frente a ti a la altura de los hombros. Una vez a la altura de los hombros, rota las muñecas hacia adelante de modo que las palmas de las manos miren hacia afuera de ti. Esta será tu posición inicial. Mientras inhalas, baja lentamente las mancuernas hacia tu lado hasta que queden aproximadamente a la altura del pecho. Mientras exhalas, usa los tríceps para levantar las mancuernas de vuelta a la posición inicial. Asegúrate de usar solo los tríceps y no usar los antebrazos ni los bíceps para ayudar a levantar las mancuernas. Después de una pausa de un segundo en la posición contraída, repite el movimiento el número de repeticiones prescrito.', 'Sit on a flat bench with a dumbbell in each hand, resting on your thighs. Using your thighs to help raise the dumbbells, lift the dumbbells one at a time so that you can hold them in front of you at shoulder width. Once at shoulder width, rotate your wrists forward so that the palms of your hands are facing away from you. This will be your starting position. As you breathe in, slowly lower the dumbbells to your side until they are about level with your chest. As you exhale, use your triceps to lift the dumbbells back to the starting position. Make sure to use only your triceps and do not use your forearms or biceps to help lift the dumbbells. After a second pause at the contracted position, repeat the movement for the prescribed amount of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1731-7jGOBF3.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1731-7jGOBF3.gif', '7jGOBF3', '© Gym visual — https://gymvisual.com/'),
('0296', 'dumbbell close-grip press', 'Siéntate en un banco plano con una mancuerna en cada mano, apoyadas en los muslos. Usando los muslos para ayudar a levantar las mancuernas, levanta las mancuernas una a la vez para poder sostenerlas frente a ti a la altura de los hombros. Una vez a la altura de los hombros, rota las muñecas hacia ad', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'triceps', '{"chest","shoulders"}', 'Siéntate en un banco plano con una mancuerna en cada mano, apoyadas en los muslos. Usando los muslos para ayudar a levantar las mancuernas, levanta las mancuernas una a la vez para poder sostenerlas frente a ti a la altura de los hombros. Una vez a la altura de los hombros, rota las muñecas hacia adelante de modo que las palmas de las manos miren hacia afuera de ti. Esta será tu posición inicial. Mientras inhalas, baja lentamente las mancuernas hacia tu lado hasta que queden aproximadamente a la altura del pecho. Mientras exhalas, usa los tríceps para levantar las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a flat bench with a dumbbell in each hand, resting on your thighs. Using your thighs to help raise the dumbbells, lift the dumbbells one at a time so that you can hold them in front of you at shoulder width. Once at shoulder width, rotate your wrists forward so that the palms of your hands are facing away from you. This will be your starting position. As you breathe in, slowly lower the dumbbells to your side until they are about level with your chest. As you exhale, use your triceps to lift the dumbbells back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0296-RxayqAZ.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0296-RxayqAZ.gif', 'RxayqAZ', '© Gym visual — https://gymvisual.com/'),
('0297', 'dumbbell concentration curl', 'Siéntate en un banco con las piernas separadas y una mancuerna en una mano, apoyando el codo en la parte interna del muslo. Extiende completamente el brazo y sujeta la mancuerna con un agarre supino. Manteniendo el brazo superior quieto, exhala y flexiona el peso hacia el hombro mientras contraes el', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Siéntate en un banco con las piernas separadas y una mancuerna en una mano, apoyando el codo en la parte interna del muslo. Extiende completamente el brazo y sujeta la mancuerna con un agarre supino. Manteniendo el brazo superior quieto, exhala y flexiona el peso hacia el hombro mientras contraes el bíceps. Continúa levantando la mancuerna hasta que el bíceps esté completamente contraído y la mancuerna esté a la altura del hombro. Mantén la posición contraída durante una breve pausa mientras aprietas los bíceps. Inhala y baja lentamente la mancuerna de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia de brazo.', 'Sit on a bench with your legs spread apart and a dumbbell in one hand, resting your elbow on the inside of your thigh. Fully extend your arm and hold the dumbbell with an underhand grip. Keeping your upper arm stationary, exhale and curl the weight up towards your shoulder while contracting your biceps. Continue to raise the dumbbell until your biceps are fully contracted and the dumbbell is at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly lower the dumbbell back to the starting position. Repeat for the desired number of repetitions, then switch arms.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0297-gvsWLQw.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0297-gvsWLQw.gif', 'gvsWLQw', '© Gym visual — https://gymvisual.com/'),
('3635', 'dumbbell contralateral forward lunge', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una mancuerna en cada mano. Da un paso adelante con el pie derecho, manteniendo la espalda recta y el core activado. Baja el cuerpo flexionando ambas rodillas hasta que el muslo derecho quede paralelo al suelo. Empuja con el t', 'upper legs', 'dumbbell', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves"}', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una mancuerna en cada mano. Da un paso adelante con el pie derecho, manteniendo la espalda recta y el core activado. Baja el cuerpo flexionando ambas rodillas hasta que el muslo derecho quede paralelo al suelo. Empuja con el talón derecho para regresar a la posición inicial. Repite con la pierna izquierda. Alterna las piernas el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, holding a dumbbell in each hand. Take a step forward with your right foot, keeping your back straight and core engaged. Lower your body by bending both knees until your right thigh is parallel to the ground. Push through your right heel to return to the starting position. Repeat with your left leg. Alternate legs for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3635-ecl28tP.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3635-ecl28tP.gif', 'ecl28tP', '© Gym visual — https://gymvisual.com/'),
('0298', 'dumbbell cross body hammer curl', 'Ponte de pie con una mancuerna en cada mano, con las palmas hacia tu cuerpo. Mantén los codos cerca del torso y los brazos superiores quietos. Exhala y flexiona los brazos contrayendo los bíceps, llevando las mancuernas a través del cuerpo hacia el hombro opuesto. Continúa levantando las mancuernas ', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ponte de pie con una mancuerna en cada mano, con las palmas hacia tu cuerpo. Mantén los codos cerca del torso y los brazos superiores quietos. Exhala y flexiona los brazos contrayendo los bíceps, llevando las mancuernas a través del cuerpo hacia el hombro opuesto. Continúa levantando las mancuernas hasta que los bíceps estén completamente contraídos y las mancuernas estén a la altura de los hombros. Mantén la posición contraída durante una breve pausa mientras aprietas los bíceps. Inhala y comienza a bajar lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand up straight with a dumbbell in each hand, palms facing your body. Keep your elbows close to your torso and your upper arms stationary. Exhale and curl the weights while contracting your biceps, bringing the dumbbells across your body towards your opposite shoulder. Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly begin to lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0298-Qyk5J3p.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0298-Qyk5J3p.gif', 'Qyk5J3p', '© Gym visual — https://gymvisual.com/'),
('1657', 'dumbbell cross body hammer curl v. 2', 'Ponte de pie con una mancuerna en cada mano, con las palmas hacia tu cuerpo. Mantén los codos cerca del torso y los brazos superiores quietos. Exhala y flexiona los brazos contrayendo los bíceps, acercando las mancuernas lo más posible al hombro opuesto. Mantén la posición contraída durante una brev', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ponte de pie con una mancuerna en cada mano, con las palmas hacia tu cuerpo. Mantén los codos cerca del torso y los brazos superiores quietos. Exhala y flexiona los brazos contrayendo los bíceps, acercando las mancuernas lo más posible al hombro opuesto. Mantén la posición contraída durante una breve pausa mientras aprietas los bíceps. Inhala y comienza a bajar lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand up straight with a dumbbell in each hand, palms facing your body. Keep your elbows close to your torso and your upper arms stationary. Exhale and curl the weights while contracting your biceps, bringing the dumbbells as close to your opposite shoulder as possible. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly begin to lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1657-HDYiZcY.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1657-HDYiZcY.gif', 'HDYiZcY', '© Gym visual — https://gymvisual.com/'),
('0299', 'dumbbell cuban press', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo una mancuerna en cada mano a la altura de los hombros con las palmas hacia abajo. Manteniendo el core activado y los codos ligeramente flexionados, empuja las mancuernas hacia arriba por encima de la cabeza hasta que los bra', 'shoulders', 'dumbbell', 'shoulders', 'shoulders', 'delts', '{"triceps","upper back"}', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo una mancuerna en cada mano a la altura de los hombros con las palmas hacia abajo. Manteniendo el core activado y los codos ligeramente flexionados, empuja las mancuernas hacia arriba por encima de la cabeza hasta que los brazos queden completamente extendidos. Gira las muñecas de modo que las palmas queden mirando hacia adelante. Baja lentamente las mancuernas a la posición inicial, girando las muñecas de vuelta a la posición inicial mientras lo haces. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, holding a dumbbell in each hand at shoulder height with your palms facing down. Keeping your core engaged and your elbows slightly bent, press the dumbbells up and overhead until your arms are fully extended. Rotate your wrists so that your palms are facing forward. Slowly lower the dumbbells back to the starting position, rotating your wrists back to the starting position as you do so. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0299-QfAKy1G.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0299-QfAKy1G.gif', 'QfAKy1G', '© Gym visual — https://gymvisual.com/'),
('2136', 'dumbbell cuban press v. 2', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo una mancuerna en cada mano a la altura de los hombros con las palmas hacia abajo. Manteniendo el core activado y la espalda recta, empuja las mancuernas directamente hacia arriba por encima de la cabeza hasta que los brazos ', 'shoulders', 'dumbbell', 'shoulders', 'shoulders', 'delts', '{"triceps","upper back"}', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo una mancuerna en cada mano a la altura de los hombros con las palmas hacia abajo. Manteniendo el core activado y la espalda recta, empuja las mancuernas directamente hacia arriba por encima de la cabeza hasta que los brazos queden completamente extendidos. Gira las muñecas de modo que las palmas queden mirando hacia adelante. Baja las mancuernas de nuevo hasta la altura de los hombros, girando las muñecas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, holding a dumbbell in each hand at shoulder height with your palms facing down. Keeping your core engaged and your back straight, press the dumbbells straight up overhead until your arms are fully extended. Rotate your wrists so that your palms are facing forward. Lower the dumbbells back down to shoulder height, rotating your wrists back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2136-BqgCRif.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2136-BqgCRif.gif', 'BqgCRif', '© Gym visual — https://gymvisual.com/'),
('0300', 'dumbbell deadlift', 'Ponte de pie con los pies separados a la altura de los hombros, con las puntas de los pies apuntando hacia adelante. Sostén una mancuerna en cada mano, con las palmas hacia el cuerpo y los brazos extendidos hacia abajo. Flexiona las caderas y las rodillas, bajando las mancuernas hacia el suelo mient', 'upper legs', 'dumbbell', 'upper legs', 'upper legs', 'glutes', '{"hamstrings","lower back"}', 'Ponte de pie con los pies separados a la altura de los hombros, con las puntas de los pies apuntando hacia adelante. Sostén una mancuerna en cada mano, con las palmas hacia el cuerpo y los brazos extendidos hacia abajo. Flexiona las caderas y las rodillas, bajando las mancuernas hacia el suelo mientras mantienes la espalda recta. Empuja con los talones y extiende las caderas y las rodillas, levantando las mancuernas de nuevo a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, toes pointing forward. Hold a dumbbell in each hand, palms facing your body, arms extended downwards. Bend at your hips and knees, lowering the dumbbells towards the ground while keeping your back straight. Push through your heels and extend your hips and knees, lifting the dumbbells back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0300-nUwVh7b.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0300-nUwVh7b.gif', 'nUwVh7b', '© Gym visual — https://gymvisual.com/'),
('0301', 'dumbbell decline bench press', 'Túmbate en un banco declinado con los pies sujetos y la cabeza más baja que las caderas. Sostén una mancuerna en cada mano y extiende los brazos rectos hacia arriba por encima del pecho, con las palmas hacia adelante. Baja lentamente las mancuernas hacia los lados del pecho, manteniendo los codos en', 'chest', 'dumbbell', 'chest', 'chest', 'pectorals', '{"triceps","shoulders"}', 'Túmbate en un banco declinado con los pies sujetos y la cabeza más baja que las caderas. Sostén una mancuerna en cada mano y extiende los brazos rectos hacia arriba por encima del pecho, con las palmas hacia adelante. Baja lentamente las mancuernas hacia los lados del pecho, manteniendo los codos en un ángulo de 90 grados. Empuja las mancuernas de nuevo hacia arriba hasta la posición inicial, extendiendo completamente los brazos. Repite el número de repeticiones deseado.', 'Lie down on a decline bench with your feet secured and your head lower than your hips. Hold a dumbbell in each hand and extend your arms straight up above your chest, palms facing forward. Lower the dumbbells slowly to the sides of your chest, keeping your elbows at a 90-degree angle. Push the dumbbells back up to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0301-DwhEmmE.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0301-DwhEmmE.gif', 'DwhEmmE', '© Gym visual — https://gymvisual.com/'),
('0302', 'dumbbell decline fly', 'Túmbate en un banco declinado con los pies sujetos y la cabeza más baja que las caderas. Sostén una mancuerna en cada mano con las palmas enfrentadas entre sí y los brazos extendidos por encima del pecho. Baja las mancuernas hacia los lados describiendo un amplio arco hasta sentir un estiramiento en', 'chest', 'dumbbell', 'chest', 'chest', 'pectorals', '{"shoulders"}', 'Túmbate en un banco declinado con los pies sujetos y la cabeza más baja que las caderas. Sostén una mancuerna en cada mano con las palmas enfrentadas entre sí y los brazos extendidos por encima del pecho. Baja las mancuernas hacia los lados describiendo un amplio arco hasta sentir un estiramiento en el pecho. Haz una pausa por un momento, luego contrae los músculos del pecho para llevar las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie on a decline bench with your feet secured and your head lower than your hips. Hold a dumbbell in each hand with your palms facing each other and your arms extended above your chest. Lower the dumbbells out to the sides in a wide arc until you feel a stretch in your chest. Pause for a moment, then squeeze your chest muscles to bring the dumbbells back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0302-xXm4nYq.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0302-xXm4nYq.gif', 'xXm4nYq', '© Gym visual — https://gymvisual.com/'),
('0303', 'dumbbell decline hammer press', 'Túmbate en un banco declinado con los pies sujetos y la cabeza más baja que las caderas. Sostén una mancuerna en cada mano con las palmas enfrentadas entre sí y los brazos extendidos por encima del pecho. Baja las mancuernas a los lados del pecho, manteniendo los codos ligeramente flexionados. Empuj', 'chest', 'dumbbell', 'chest', 'chest', 'pectorals', '{"triceps","shoulders"}', 'Túmbate en un banco declinado con los pies sujetos y la cabeza más baja que las caderas. Sostén una mancuerna en cada mano con las palmas enfrentadas entre sí y los brazos extendidos por encima del pecho. Baja las mancuernas a los lados del pecho, manteniendo los codos ligeramente flexionados. Empuja las mancuernas de nuevo hacia arriba hasta la posición inicial, extendiendo completamente los brazos. Repite el número de repeticiones deseado.', 'Lie on a decline bench with your feet secured and your head lower than your hips. Hold a dumbbell in each hand with your palms facing each other and your arms extended above your chest. Lower the dumbbells to the sides of your chest, keeping your elbows slightly bent. Press the dumbbells back up to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0303-1qrWgZ2.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0303-1qrWgZ2.gif', '1qrWgZ2', '© Gym visual — https://gymvisual.com/'),
('1276', 'dumbbell decline one arm fly', 'Túmbate en un banco declinado con una mancuerna en una mano, apoyándola sobre el muslo. Usando el muslo para ayudar a levantar la mancuerna, álzala hasta la altura de los hombros con la palma mirando hacia el torso. Gira la muñeca de modo que la palma de la mano quede mirando hacia adelante. Mientra', 'chest', 'dumbbell', 'chest', 'chest', 'pectorals', '{"shoulders"}', 'Túmbate en un banco declinado con una mancuerna en una mano, apoyándola sobre el muslo. Usando el muslo para ayudar a levantar la mancuerna, álzala hasta la altura de los hombros con la palma mirando hacia el torso. Gira la muñeca de modo que la palma de la mano quede mirando hacia adelante. Mientras inhalas, baja la mancuerna lentamente hacia el lado hasta sentir un estiramiento en el pecho. Exhala y usa los músculos del pecho para llevar la mancuerna de nuevo hacia arriba hasta la posición inicial. Repite el número de repeticiones deseado, luego cambia de brazo.', 'Lie down on a decline bench with a dumbbell in one hand, resting it on your thigh. Using your thigh to help raise the dumbbell, lift it up to shoulder width with your palm facing your torso. Rotate your wrist so that the palm of your hand is facing forward. As you breathe in, lower the dumbbell slowly to the side until you feel a stretch in your chest. Exhale and use your chest muscles to bring the dumbbell back up to the starting position. Repeat for the desired number of repetitions, then switch arms.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1276-NL6YBwN.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1276-NL6YBwN.gif', 'NL6YBwN', '© Gym visual — https://gymvisual.com/'),
('1617', 'dumbbell decline one arm hammer press', 'Túmbate en un banco declinado con una mancuerna en una mano, apoyada sobre el pecho. Extiende el brazo recto hacia arriba, manteniendo el codo ligeramente flexionado. Baja la mancuerna hacia el hombro, manteniendo el codo cerca del cuerpo. Empuja la mancuerna de nuevo hacia arriba hasta la posición ', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'triceps', '{"chest","shoulders"}', 'Túmbate en un banco declinado con una mancuerna en una mano, apoyada sobre el pecho. Extiende el brazo recto hacia arriba, manteniendo el codo ligeramente flexionado. Baja la mancuerna hacia el hombro, manteniendo el codo cerca del cuerpo. Empuja la mancuerna de nuevo hacia arriba hasta la posición inicial. Repite el número de repeticiones deseado, luego cambia de brazo.', 'Lie on a decline bench with a dumbbell in one hand, resting on your chest. Extend your arm straight up, keeping your elbow slightly bent. Lower the dumbbell down towards your shoulder, keeping your elbow close to your body. Press the dumbbell back up to the starting position. Repeat for the desired number of repetitions, then switch arms.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1617-SHUMp5H.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1617-SHUMp5H.gif', 'SHUMp5H', '© Gym visual — https://gymvisual.com/'),
('0305', 'dumbbell decline shrug', 'Ajusta un banco declinado a un ángulo de 45 grados. Túmbate boca abajo en el banco con el pecho y el abdomen apoyados contra él. Sostén una mancuerna en cada mano con los brazos completamente extendidos hacia el suelo. Manteniendo los brazos rectos, levanta los hombros hacia las orejas lo más alto p', 'back', 'dumbbell', 'back', 'back', 'traps', '{"shoulders","rhomboids"}', 'Ajusta un banco declinado a un ángulo de 45 grados. Túmbate boca abajo en el banco con el pecho y el abdomen apoyados contra él. Sostén una mancuerna en cada mano con los brazos completamente extendidos hacia el suelo. Manteniendo los brazos rectos, levanta los hombros hacia las orejas lo más alto posible. Mantén la contracción por un momento, luego baja lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Set up a decline bench at a 45-degree angle. Lie face down on the bench with your chest and stomach resting against it. Hold a dumbbell in each hand with your arms fully extended towards the floor. Keeping your arms straight, raise your shoulders towards your ears as high as possible. Hold the contraction for a moment, then slowly lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0305-cwsAI4G.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0305-cwsAI4G.gif', 'cwsAI4G', '© Gym visual — https://gymvisual.com/'),
('0304', 'dumbbell decline shrug v. 2', 'Ajusta un banco declinado a un ángulo de 45 grados. Túmbate boca abajo en el banco con el pecho y el abdomen apoyados sobre él. Sostén una mancuerna en cada mano con las palmas enfrentadas entre sí y los brazos completamente extendidos. Manteniendo los brazos rectos, levanta los hombros lo más alto ', 'back', 'dumbbell', 'back', 'back', 'traps', '{"shoulders","rhomboids"}', 'Ajusta un banco declinado a un ángulo de 45 grados. Túmbate boca abajo en el banco con el pecho y el abdomen apoyados sobre él. Sostén una mancuerna en cada mano con las palmas enfrentadas entre sí y los brazos completamente extendidos. Manteniendo los brazos rectos, levanta los hombros lo más alto posible mientras juntas los omóplatos. Mantén la contracción durante una breve pausa, luego baja las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Set up a decline bench at a 45-degree angle. Lie face down on the bench with your chest and stomach resting on it. Hold a dumbbell in each hand with your palms facing each other and your arms fully extended. Keeping your arms straight, raise your shoulders as high as possible while squeezing your shoulder blades together. Hold the contraction for a brief pause, then lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0304-bRlbdjK.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0304-bRlbdjK.gif', 'bRlbdjK', '© Gym visual — https://gymvisual.com/'),
('0306', 'dumbbell decline triceps extension', 'Túmbate en un banco declinado con la cabeza más baja que los pies y sostén una mancuerna en cada mano, con las palmas enfrentadas entre sí. Extiende completamente los brazos, manteniendo los codos cerca de la cabeza. Baja lentamente las mancuernas detrás de la cabeza, flexionando los codos. Haz una ', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'triceps', '{"shoulders"}', 'Túmbate en un banco declinado con la cabeza más baja que los pies y sostén una mancuerna en cada mano, con las palmas enfrentadas entre sí. Extiende completamente los brazos, manteniendo los codos cerca de la cabeza. Baja lentamente las mancuernas detrás de la cabeza, flexionando los codos. Haz una pausa por un momento, luego levanta las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie on a decline bench with your head lower than your feet and hold a dumbbell in each hand, palms facing each other. Extend your arms fully, keeping your elbows close to your head. Lower the dumbbells slowly behind your head, bending your elbows. Pause for a moment, then raise the dumbbells back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0306-OTgkHwR.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0306-OTgkHwR.gif', 'OTgkHwR', '© Gym visual — https://gymvisual.com/'),
('0307', 'dumbbell decline twist fly', 'Túmbate en un banco declinado con la cabeza más baja que las caderas. Sostén una mancuerna en cada mano con las palmas enfrentadas entre sí y los brazos extendidos rectos hacia arriba sobre el pecho. Baja las mancuernas hacia los lados describiendo un amplio arco hasta sentir un estiramiento en el p', 'chest', 'dumbbell', 'chest', 'chest', 'pectorals', '{"shoulders","triceps"}', 'Túmbate en un banco declinado con la cabeza más baja que las caderas. Sostén una mancuerna en cada mano con las palmas enfrentadas entre sí y los brazos extendidos rectos hacia arriba sobre el pecho. Baja las mancuernas hacia los lados describiendo un amplio arco hasta sentir un estiramiento en el pecho. Mientras bajas las mancuernas, gira las muñecas de modo que las palmas queden mirando hacia adelante en la parte inferior del movimiento. Invierte el movimiento y lleva las mancuernas de nuevo hacia arriba hasta la posición inicial, contrayendo los músculos del pecho en la parte superior. Repite el número de repeticiones deseado.', 'Lie down on a decline bench with your head lower than your hips. Hold a dumbbell in each hand with your palms facing each other and your arms extended straight up over your chest. Lower the dumbbells out to the sides in a wide arc until you feel a stretch in your chest. As you lower the dumbbells, twist your wrists so that your palms face forward at the bottom of the movement. Reverse the motion and bring the dumbbells back up to the starting position, squeezing your chest muscles at the top. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0307-reFHapa.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0307-reFHapa.gif', 'reFHapa', '© Gym visual — https://gymvisual.com/'),
('1437', 'dumbbell finger curls', 'Siéntate en un banco o silla con los pies apoyados en el suelo y la espalda recta. Sostén una mancuerna en una mano con agarre supino, apoyando el antebrazo sobre el muslo, con la palma hacia arriba. Deja que la mancuerna ruede hacia las puntas de los dedos, luego flexiona los dedos para volver a en', 'lower arms', 'dumbbell', 'lower arms', 'lower arms', 'forearms', '{"wrist flexors","wrist extensors"}', 'Siéntate en un banco o silla con los pies apoyados en el suelo y la espalda recta. Sostén una mancuerna en una mano con agarre supino, apoyando el antebrazo sobre el muslo, con la palma hacia arriba. Deja que la mancuerna ruede hacia las puntas de los dedos, luego flexiona los dedos para volver a enrollarla hacia arriba. Repite el número de repeticiones deseado, luego cambia a la otra mano.', 'Sit on a bench or chair with your feet flat on the ground and your back straight. Hold a dumbbell in one hand with an underhand grip, resting your forearm on your thigh, palm facing up. Allow the dumbbell to roll down to your fingertips, then curl it back up by flexing your fingers. Repeat for the desired number of repetitions, then switch to the other hand.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1437-mtXengz.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1437-mtXengz.gif', 'mtXengz', '© Gym visual — https://gymvisual.com/'),
('0308', 'dumbbell fly', 'Túmbate boca arriba en un banco con una mancuerna en cada mano, con las palmas enfrentadas entre sí. Extiende los brazos rectos hacia arriba sobre el pecho, con una ligera flexión en los codos. Manteniendo una ligera flexión en los codos, baja los brazos hacia los lados en un amplio arco hasta senti', 'chest', 'dumbbell', 'chest', 'chest', 'pectorals', '{"shoulders"}', 'Túmbate boca arriba en un banco con una mancuerna en cada mano, con las palmas enfrentadas entre sí. Extiende los brazos rectos hacia arriba sobre el pecho, con una ligera flexión en los codos. Manteniendo una ligera flexión en los codos, baja los brazos hacia los lados en un amplio arco hasta sentir un estiramiento en el pecho. Haz una pausa por un momento, luego invierte el movimiento y lleva las mancuernas de nuevo hacia arriba hasta la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on a bench with a dumbbell in each hand, palms facing each other. Extend your arms straight up over your chest, with a slight bend in your elbows. Keeping a slight bend in your elbows, lower your arms out to the sides in a wide arc until you feel a stretch in your chest. Pause for a moment, then reverse the movement and bring the dumbbells back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0308-yz9nUhF.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0308-yz9nUhF.gif', 'yz9nUhF', '© Gym visual — https://gymvisual.com/'),
('1277', 'dumbbell fly on exercise ball', 'Siéntate sobre un balón de estabilidad y sostén una mancuerna en cada mano. Camina con los pies hacia adelante y baja el cuerpo rodando hasta que la cabeza, el cuello y la parte superior de la espalda queden apoyados sobre el balón. Extiende los brazos rectos por encima del pecho, con las palmas enf', 'chest', 'dumbbell', 'chest', 'chest', 'pectorals', '{"shoulders","triceps"}', 'Siéntate sobre un balón de estabilidad y sostén una mancuerna en cada mano. Camina con los pies hacia adelante y baja el cuerpo rodando hasta que la cabeza, el cuello y la parte superior de la espalda queden apoyados sobre el balón. Extiende los brazos rectos por encima del pecho, con las palmas enfrentadas entre sí. Flexiona ligeramente los codos y baja los brazos hacia los lados describiendo un amplio arco hasta sentir un estiramiento en el pecho. Haz una pausa por un momento, luego invierte el movimiento y contrae los músculos del pecho mientras llevas las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on an exercise ball and hold a dumbbell in each hand. Walk your feet forward and roll your body down until your head, neck, and upper back are supported by the ball. Extend your arms straight up above your chest, palms facing each other. Bend your elbows slightly and lower your arms out to the sides in a wide arc until you feel a stretch in your chest. Pause for a moment, then reverse the movement and squeeze your chest muscles as you bring the dumbbells back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1277-Lt3iWnf.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1277-Lt3iWnf.gif', 'Lt3iWnf', '© Gym visual — https://gymvisual.com/'),
('1732', 'dumbbell forward lunge triceps extension', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una mancuerna en cada mano. Da un paso adelante con el pie derecho, bajando el cuerpo hasta una posición de zancada. Mantén la espalda recta y el pecho elevado. Extiende los brazos rectos por encima de la cabeza, manteniendo l', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'triceps', '{"shoulders","core"}', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una mancuerna en cada mano. Da un paso adelante con el pie derecho, bajando el cuerpo hasta una posición de zancada. Mantén la espalda recta y el pecho elevado. Extiende los brazos rectos por encima de la cabeza, manteniendo los codos cerca de las orejas. Baja las mancuernas detrás de la cabeza flexionando los codos. Haz una pausa por un momento, luego estira los brazos para volver a la posición inicial. Repite el movimiento el número de repeticiones deseado, luego cambia de pierna y repite.', 'Stand with your feet shoulder-width apart, holding a dumbbell in each hand. Take a step forward with your right foot, lowering your body into a lunge position. Keep your back straight and your chest up. Extend your arms straight overhead, keeping your elbows close to your ears. Lower the dumbbells behind your head by bending your elbows. Pause for a moment, then straighten your arms to return to the starting position. Repeat the movement for the desired number of repetitions, then switch legs and repeat.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1732-XalXcvM.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1732-XalXcvM.gif', 'XalXcvM', '© Gym visual — https://gymvisual.com/'),
('0310', 'dumbbell front raise', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo una mancuerna en cada mano con las palmas hacia los muslos. Manteniendo los brazos rectos, exhala y levanta las mancuernas frente a ti hasta que queden a la altura de los hombros. Haz una pausa por un momento en la parte sup', 'shoulders', 'dumbbell', 'shoulders', 'shoulders', 'delts', '{"biceps","trapezius"}', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo una mancuerna en cada mano con las palmas hacia los muslos. Manteniendo los brazos rectos, exhala y levanta las mancuernas frente a ti hasta que queden a la altura de los hombros. Haz una pausa por un momento en la parte superior, luego inhala y baja lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing your thighs. Keeping your arms straight, exhale and lift the dumbbells in front of you until they are at shoulder level. Pause for a moment at the top, then inhale and slowly lower the dumbbells back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0310-3eGE2JC.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0310-3eGE2JC.gif', '3eGE2JC', '© Gym visual — https://gymvisual.com/'),
('0309', 'dumbbell front raise v. 2', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo una mancuerna en cada mano con las palmas hacia los muslos. Mantén la espalda recta y activa el core. Levanta lentamente las mancuernas frente a ti, con los brazos rectos, hasta que queden a la altura de los hombros. Haz una', 'shoulders', 'dumbbell', 'shoulders', 'shoulders', 'delts', '{"trapezius","biceps"}', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo una mancuerna en cada mano con las palmas hacia los muslos. Mantén la espalda recta y activa el core. Levanta lentamente las mancuernas frente a ti, con los brazos rectos, hasta que queden a la altura de los hombros. Haz una pausa breve en la parte alta, luego baja lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing your thighs. Keep your back straight and engage your core. Slowly lift the dumbbells in front of you, with your arms straight, until they are at shoulder level. Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0309-Rr7S3yg.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0309-Rr7S3yg.gif', 'Rr7S3yg', '© Gym visual — https://gymvisual.com/'),
('0311', 'dumbbell full can lateral raise', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo una mancuerna en cada mano con las palmas hacia el cuerpo. Mantén la espalda recta y activa el core. Levanta los brazos hacia los lados, manteniendo una ligera flexión en los codos, hasta que queden paralelos al suelo. Haz u', 'shoulders', 'dumbbell', 'shoulders', 'shoulders', 'delts', '{"traps","rotator cuff"}', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo una mancuerna en cada mano con las palmas hacia el cuerpo. Mantén la espalda recta y activa el core. Levanta los brazos hacia los lados, manteniendo una ligera flexión en los codos, hasta que queden paralelos al suelo. Haz una pausa por un momento en la parte superior, luego baja lentamente los brazos de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing your body. Keep your back straight and engage your core. Raise your arms out to the sides, keeping a slight bend in your elbows, until they are parallel to the ground. Pause for a moment at the top, then slowly lower your arms back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0311-AQ0mC4Y.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0311-AQ0mC4Y.gif', 'AQ0mC4Y', '© Gym visual — https://gymvisual.com/'),
('1760', 'dumbbell goblet squat', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo una mancuerna verticalmente contra el pecho con ambas manos. Manteniendo el pecho erguido y el core activado, baja el cuerpo a una posición de sentadilla empujando las caderas hacia atrás y flexionando las rodillas. Continúa', 'upper legs', 'dumbbell', 'upper legs', 'upper legs', 'quads', '{"glutes","hamstrings","calves"}', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo una mancuerna verticalmente contra el pecho con ambas manos. Manteniendo el pecho erguido y el core activado, baja el cuerpo a una posición de sentadilla empujando las caderas hacia atrás y flexionando las rodillas. Continúa bajando hasta que los muslos queden paralelos al suelo, o tan abajo como puedas hacerlo cómodamente. Haz una pausa por un momento en la parte inferior, luego empuja con los talones para regresar a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, holding a dumbbell vertically against your chest with both hands. Keeping your chest up and core engaged, lower your body down into a squat position by pushing your hips back and bending your knees. Continue lowering until your thighs are parallel to the ground, or as low as you can comfortably go. Pause for a moment at the bottom, then push through your heels to return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1760-yn8yg1r.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1760-yn8yg1r.gif', 'yn8yg1r', '© Gym visual — https://gymvisual.com/'),
('0313', 'dumbbell hammer curl', 'Ponte de pie con una mancuerna en cada mano, con las palmas mirando hacia el torso. Mantén los codos cerca del torso y gira las palmas de las manos hasta que queden mirando hacia adelante. Esta será tu posición inicial. Ahora, manteniendo los brazos superiores quietos, exhala y flexiona los brazos c', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ponte de pie con una mancuerna en cada mano, con las palmas mirando hacia el torso. Mantén los codos cerca del torso y gira las palmas de las manos hasta que queden mirando hacia adelante. Esta será tu posición inicial. Ahora, manteniendo los brazos superiores quietos, exhala y flexiona los brazos contrayendo los bíceps. Continúa levantando las pesas hasta que los bíceps estén completamente contraídos y las mancuernas estén a la altura de los hombros. Mantén la posición contraída durante una breve pausa mientras aprietas los bíceps. Luego, inhala y comienza a bajar lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones recomendado.', 'Stand up straight with a dumbbell in each hand, palms facing your torso. Keep your elbows close to your torso and rotate the palms of your hands until they are facing forward. This will be your starting position. Now, keeping the upper arms stationary, exhale and curl the weights while contracting your biceps. Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Then, inhale and slowly begin to lower the dumbbells back to the starting position. Repeat for the recommended amount of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0313-slDvUAU.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0313-slDvUAU.gif', 'slDvUAU', '© Gym visual — https://gymvisual.com/'),
('1659', 'dumbbell hammer curl on exercise ball', 'Siéntate sobre un balón de ejercicio con los pies apoyados planos en el suelo y la espalda recta. Sostén una mancuerna en cada mano con las palmas hacia el cuerpo y los brazos completamente extendidos. Manteniendo los brazos superiores quietos, exhala y flexiona las mancuernas contrayendo los bíceps', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Siéntate sobre un balón de ejercicio con los pies apoyados planos en el suelo y la espalda recta. Sostén una mancuerna en cada mano con las palmas hacia el cuerpo y los brazos completamente extendidos. Manteniendo los brazos superiores quietos, exhala y flexiona las mancuernas contrayendo los bíceps. Continúa levantando las mancuernas hasta que los bíceps estén completamente contraídos y las mancuernas estén a la altura de los hombros. Mantén la posición contraída durante una breve pausa mientras aprietas los bíceps. Inhala y comienza a bajar lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on an exercise ball with your feet flat on the ground and your back straight. Hold a dumbbell in each hand with your palms facing your body and your arms fully extended. Keeping your upper arms stationary, exhale and curl the dumbbells while contracting your biceps. Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly begin to lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1659-fY68AyX.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1659-fY68AyX.gif', 'fY68AyX', '© Gym visual — https://gymvisual.com/'),
('0312', 'dumbbell hammer curl v. 2', 'Ponte de pie con una mancuerna en cada mano, con las palmas mirando hacia el torso. Mantén los codos cerca del torso y gira las palmas de las manos hasta que queden mirando hacia adelante. Esta será tu posición inicial. Ahora, manteniendo los brazos superiores quietos, exhala y flexiona los brazos c', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ponte de pie con una mancuerna en cada mano, con las palmas mirando hacia el torso. Mantén los codos cerca del torso y gira las palmas de las manos hasta que queden mirando hacia adelante. Esta será tu posición inicial. Ahora, manteniendo los brazos superiores quietos, exhala y flexiona los brazos contrayendo los bíceps. Continúa levantando las pesas hasta que los bíceps estén completamente contraídos y las mancuernas estén a la altura de los hombros. Mantén la posición contraída durante una breve pausa mientras aprietas los bíceps. Luego, inhala y comienza a bajar lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones recomendado.', 'Stand up straight with a dumbbell in each hand, palms facing your torso. Keep your elbows close to your torso and rotate the palms of your hands until they are facing forward. This will be your starting position. Now, keeping the upper arms stationary, exhale and curl the weights while contracting your biceps. Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Then, inhale and slowly begin to lower the dumbbells back to the starting position. Repeat for the recommended amount of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0312-2NpxjC1.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0312-2NpxjC1.gif', '2NpxjC1', '© Gym visual — https://gymvisual.com/'),
('2402', 'dumbbell hammer curls (with arm blaster)', 'Ponte de pie con una mancuerna en cada mano, con las palmas mirando hacia el torso. Mantén los codos cerca del torso y gira las palmas de las manos hasta que queden mirando hacia adelante. Esta será tu posición inicial. Ahora, manteniendo el brazo superior quieto, exhala y flexiona los brazos contra', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ponte de pie con una mancuerna en cada mano, con las palmas mirando hacia el torso. Mantén los codos cerca del torso y gira las palmas de las manos hasta que queden mirando hacia adelante. Esta será tu posición inicial. Ahora, manteniendo el brazo superior quieto, exhala y flexiona los brazos contrayendo los bíceps. Continúa levantando las pesas hasta que los bíceps estén completamente contraídos y las mancuernas estén a la altura de los hombros. Mantén la posición contraída durante una breve pausa mientras aprietas los bíceps. Luego, inhala y comienza a bajar lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones recomendado.', 'Stand up straight with a dumbbell in each hand, palms facing your torso. Keep your elbows close to your torso and rotate the palms of your hands until they are facing forward. This will be your starting position. Now, while holding your upper arm stationary, exhale and curl the weights while contracting your biceps. Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Then, inhale and slowly begin to lower the dumbbells back to the starting position. Repeat for the recommended amount of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2402-GNhAeJ0.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2402-GNhAeJ0.gif', 'GNhAeJ0', '© Gym visual — https://gymvisual.com/'),
('1664', 'dumbbell high curl', 'Ponte de pie con una mancuerna en cada mano, con las palmas hacia adelante. Mantén los brazos superiores quietos y flexiona las mancuernas lo más alto posible contrayendo los bíceps. Haz una pausa breve en la parte alta, luego baja lentamente las mancuernas de vuelta a la posición inicial. Repite el', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ponte de pie con una mancuerna en cada mano, con las palmas hacia adelante. Mantén los brazos superiores quietos y flexiona las mancuernas lo más alto posible contrayendo los bíceps. Haz una pausa breve en la parte alta, luego baja lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand up straight with a dumbbell in each hand, palms facing forward. Keep your upper arms stationary and curl the dumbbells as high as possible while contracting your biceps. Pause for a moment at the top, then slowly lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1664-qAmNMJY.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1664-qAmNMJY.gif', 'qAmNMJY', '© Gym visual — https://gymvisual.com/'),
('3545', 'dumbbell incline alternate press', 'Siéntate en un banco inclinado con una mancuerna en cada mano, apoyadas sobre los muslos. Recuéstate en el banco y usa los muslos para ayudar a levantar las mancuernas hasta la altura de los hombros, con las palmas hacia adelante. Una vez a la altura de los hombros, gira las muñecas de modo que las ', 'chest', 'dumbbell', 'chest', 'chest', 'pectorals', '{"shoulders","triceps"}', 'Siéntate en un banco inclinado con una mancuerna en cada mano, apoyadas sobre los muslos. Recuéstate en el banco y usa los muslos para ayudar a levantar las mancuernas hasta la altura de los hombros, con las palmas hacia adelante. Una vez a la altura de los hombros, gira las muñecas de modo que las palmas de las manos queden mirando hacia adelante. Empuja las mancuernas hacia arriba con el pecho y los hombros, extendiendo completamente los brazos. Baja las mancuernas de nuevo hasta la posición inicial, manteniendo los codos ligeramente flexionados. Repite el número de repeticiones deseado, alternando los brazos.', 'Sit on an incline bench with a dumbbell in each hand, resting on your thighs. Lean back on the bench and use your thighs to help raise the dumbbells to shoulder height, palms facing forward. Once at shoulder height, rotate your wrists so that the palms of your hands are facing forward. Push the dumbbells up with your chest and shoulders, extending your arms fully. Lower the dumbbells back down to the starting position, keeping your elbows slightly bent. Repeat for the desired number of repetitions, alternating arms.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3545-TVdivgY.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3545-TVdivgY.gif', 'TVdivgY', '© Gym visual — https://gymvisual.com/'),
('0314', 'dumbbell incline bench press', 'Coloca un banco inclinado a un ángulo de 45 grados. Siéntate en el banco con los pies apoyados en el suelo y la espalda firmemente apoyada contra el banco. Sostén una mancuerna en cada mano, con las palmas hacia adelante, y levántalas hasta la altura de los hombros. Baja lentamente las mancuernas ha', 'chest', 'dumbbell', 'chest', 'chest', 'pectorals', '{"shoulders","triceps"}', 'Coloca un banco inclinado a un ángulo de 45 grados. Siéntate en el banco con los pies apoyados en el suelo y la espalda firmemente apoyada contra el banco. Sostén una mancuerna en cada mano, con las palmas hacia adelante, y levántalas hasta la altura de los hombros. Baja lentamente las mancuernas hacia los lados del pecho, manteniendo los codos en un ángulo de 90 grados. Empuja las mancuernas de nuevo hacia arriba hasta la posición inicial, extendiendo completamente los brazos. Repite el número de repeticiones deseado.', 'Set up an incline bench at a 45-degree angle. Sit on the bench with your feet flat on the ground and your back pressed firmly against the bench. Hold a dumbbell in each hand, palms facing forward, and lift them to shoulder height. Slowly lower the dumbbells to the sides of your chest, keeping your elbows at a 90-degree angle. Push the dumbbells back up to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0314-ns0SIbU.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0314-ns0SIbU.gif', 'ns0SIbU', '© Gym visual — https://gymvisual.com/'),
('0315', 'dumbbell incline biceps curl', 'Siéntate en un banco inclinado con una mancuerna en cada mano, con las palmas hacia adelante y los brazos completamente extendidos. Manteniendo los brazos superiores fijos, exhala y levanta el peso mientras contraes los bíceps. Continúa levantando las mancuernas hasta que los bíceps estén completame', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Siéntate en un banco inclinado con una mancuerna en cada mano, con las palmas hacia adelante y los brazos completamente extendidos. Manteniendo los brazos superiores fijos, exhala y levanta el peso mientras contraes los bíceps. Continúa levantando las mancuernas hasta que los bíceps estén completamente contraídos y las mancuernas estén a la altura de los hombros. Mantén la posición contraída durante una breve pausa mientras aprietas los bíceps. Inhala y comienza a bajar lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on an incline bench with a dumbbell in each hand, palms facing forward, and arms fully extended. Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly begin to lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0315-F3xgbjF.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0315-F3xgbjF.gif', 'F3xgbjF', '© Gym visual — https://gymvisual.com/'),
('0316', 'dumbbell incline breeding', 'Coloca un banco inclinado a un ángulo de 45 grados. Siéntate en el banco con la espalda apoyada en el respaldo y los pies planos sobre el suelo. Sostén una mancuerna en cada mano con agarre prono, con las palmas hacia adelante. Comienza con los brazos completamente extendidos, perpendiculares al sue', 'chest', 'dumbbell', 'chest', 'chest', 'pectorals', '{"shoulders","triceps"}', 'Coloca un banco inclinado a un ángulo de 45 grados. Siéntate en el banco con la espalda apoyada en el respaldo y los pies planos sobre el suelo. Sostén una mancuerna en cada mano con agarre prono, con las palmas hacia adelante. Comienza con los brazos completamente extendidos, perpendiculares al suelo. Baja lentamente las mancuernas hacia los lados del pecho, manteniendo los codos en un ángulo de 90 grados. Haz una pausa por un momento en la parte inferior, luego empuja las mancuernas de nuevo hacia arriba hasta la posición inicial. Repite el número de repeticiones deseado.', 'Set up an incline bench at a 45-degree angle. Sit on the bench with your back against the pad and feet flat on the ground. Hold a dumbbell in each hand with an overhand grip, palms facing forward. Start with your arms fully extended, perpendicular to the ground. Lower the dumbbells slowly to the sides of your chest, keeping your elbows at a 90-degree angle. Pause for a moment at the bottom, then push the dumbbells back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0316-B3Rxp6L.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0316-B3Rxp6L.gif', 'B3Rxp6L', '© Gym visual — https://gymvisual.com/'),
('0318', 'dumbbell incline curl', 'Ajusta un banco inclinado a un ángulo de 45 grados y siéntate en él con una mancuerna en cada mano, con las palmas hacia adelante. Apoya los brazos superiores en el banco inclinado y deja que los codos cuelguen hacia abajo, extendiendo completamente los brazos. Manteniendo los brazos superiores fijo', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ajusta un banco inclinado a un ángulo de 45 grados y siéntate en él con una mancuerna en cada mano, con las palmas hacia adelante. Apoya los brazos superiores en el banco inclinado y deja que los codos cuelguen hacia abajo, extendiendo completamente los brazos. Manteniendo los brazos superiores fijos, exhala y levanta el peso mientras contraes los bíceps. Continúa levantando las mancuernas hasta que los bíceps estén completamente contraídos y las mancuernas estén a la altura de los hombros. Mantén la posición contraída durante una breve pausa mientras aprietas los bíceps. Inhala y comienza a bajar lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Set an incline bench to a 45-degree angle and sit on it with a dumbbell in each hand, palms facing forward. Rest your upper arms on the incline bench and let your elbows hang down, fully extending your arms. Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly begin to lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0318-ae9UoXQ.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0318-ae9UoXQ.gif', 'ae9UoXQ', '© Gym visual — https://gymvisual.com/'),
('0317', 'dumbbell incline curl v. 2', 'Siéntate en un banco inclinado con una mancuerna en cada mano, con las palmas hacia adelante y los brazos completamente extendidos. Manteniendo los brazos superiores fijos, exhala y levanta el peso mientras contraes los bíceps. Continúa levantando las mancuernas hasta que los bíceps estén completame', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Siéntate en un banco inclinado con una mancuerna en cada mano, con las palmas hacia adelante y los brazos completamente extendidos. Manteniendo los brazos superiores fijos, exhala y levanta el peso mientras contraes los bíceps. Continúa levantando las mancuernas hasta que los bíceps estén completamente contraídos y las mancuernas estén a la altura de los hombros. Mantén la posición contraída durante una breve pausa mientras aprietas los bíceps. Inhala y comienza a bajar lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on an incline bench with a dumbbell in each hand, palms facing forward and arms fully extended. Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly begin to lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0317-RaflbWD.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0317-RaflbWD.gif', 'RaflbWD', '© Gym visual — https://gymvisual.com/'),
('0319', 'dumbbell incline fly', 'Ajusta un banco inclinado a un ángulo de 45 grados. Siéntate en el banco con una mancuerna en cada mano, con las palmas enfrentadas entre sí. Recuéstate en el banco y empuja las mancuernas hacia arriba hasta la posición inicial, directamente por encima del pecho. Baja las mancuernas hacia los lados ', 'chest', 'dumbbell', 'chest', 'chest', 'pectorals', '{"shoulders"}', 'Ajusta un banco inclinado a un ángulo de 45 grados. Siéntate en el banco con una mancuerna en cada mano, con las palmas enfrentadas entre sí. Recuéstate en el banco y empuja las mancuernas hacia arriba hasta la posición inicial, directamente por encima del pecho. Baja las mancuernas hacia los lados describiendo un amplio arco hasta sentir un estiramiento en el pecho. Haz una pausa por un momento, luego contrae los músculos del pecho para llevar las mancuernas de nuevo hacia arriba hasta la posición inicial. Repite el número de repeticiones deseado.', 'Set an incline bench to a 45-degree angle. Sit on the bench with a dumbbell in each hand, palms facing each other. Lie back on the bench and press the dumbbells up to the starting position, directly above your chest. Lower the dumbbells out to the sides in a wide arc until you feel a stretch in your chest. Pause for a moment, then squeeze your chest muscles to bring the dumbbells back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0319-ESOd5Pl.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0319-ESOd5Pl.gif', 'ESOd5Pl', '© Gym visual — https://gymvisual.com/'),
('1278', 'dumbbell incline fly on exercise ball', 'Coloca un banco inclinado a un ángulo de 45 grados. Siéntate sobre un balón de estabilidad y rueda hacia adelante hasta que la parte superior de la espalda quede apoyada en el banco inclinado. Sostén una mancuerna en cada mano con las palmas enfrentadas entre sí y los brazos extendidos por encima de', 'chest', 'dumbbell', 'chest', 'chest', 'pectorals', '{"shoulders"}', 'Coloca un banco inclinado a un ángulo de 45 grados. Siéntate sobre un balón de estabilidad y rueda hacia adelante hasta que la parte superior de la espalda quede apoyada en el banco inclinado. Sostén una mancuerna en cada mano con las palmas enfrentadas entre sí y los brazos extendidos por encima del pecho. Baja las mancuernas hacia los lados describiendo un amplio arco hasta sentir un estiramiento en el pecho. Haz una pausa por un momento, luego contrae los músculos del pecho para llevar las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Set up an incline bench at a 45-degree angle. Sit on an exercise ball and roll forward until your upper back is resting on the incline bench. Hold a dumbbell in each hand with your palms facing each other and your arms extended above your chest. Lower the dumbbells out to the sides in a wide arc until you feel a stretch in your chest. Pause for a moment, then squeeze your chest muscles to bring the dumbbells back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1278-HYe1ZqR.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1278-HYe1ZqR.gif', 'HYe1ZqR', '© Gym visual — https://gymvisual.com/'),
('0320', 'dumbbell incline hammer curl', 'Siéntate en un banco inclinado con una mancuerna en cada mano, con las palmas hacia el torso y los brazos completamente extendidos. Mantén la espalda contra el banco y los pies apoyados en el suelo. Manteniendo los brazos superiores quietos, exhala y flexiona los brazos contrayendo los bíceps. Conti', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Siéntate en un banco inclinado con una mancuerna en cada mano, con las palmas hacia el torso y los brazos completamente extendidos. Mantén la espalda contra el banco y los pies apoyados en el suelo. Manteniendo los brazos superiores quietos, exhala y flexiona los brazos contrayendo los bíceps. Continúa levantando las pesas hasta que los bíceps estén completamente contraídos y las mancuernas estén a la altura de los hombros. Mantén la posición contraída durante una breve pausa mientras aprietas los bíceps. Inhala y comienza a bajar lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on an incline bench with a dumbbell in each hand, palms facing your torso and arms fully extended. Keep your back against the bench and your feet flat on the floor. While keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly begin to lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0320-ByX0WxV.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0320-ByX0WxV.gif', 'ByX0WxV', '© Gym visual — https://gymvisual.com/'),
('0321', 'dumbbell incline hammer press', 'Ajusta un banco inclinado a un ángulo de 45 grados y siéntate en él con una mancuerna en cada mano, apoyadas sobre los muslos. Recuéstate en el banco y coloca las mancuernas a la altura de los hombros con las palmas enfrentadas entre sí. Empuja las mancuernas hacia arriba y alejándolas del cuerpo ha', 'chest', 'dumbbell', 'chest', 'chest', 'pectorals', '{"shoulders","triceps"}', 'Ajusta un banco inclinado a un ángulo de 45 grados y siéntate en él con una mancuerna en cada mano, apoyadas sobre los muslos. Recuéstate en el banco y coloca las mancuernas a la altura de los hombros con las palmas enfrentadas entre sí. Empuja las mancuernas hacia arriba y alejándolas del cuerpo hasta que los brazos queden completamente extendidos. Haz una pausa breve en la parte alta, luego baja lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Set an incline bench to a 45-degree angle and sit on it with a dumbbell in each hand, resting on your thighs. Lie back on the bench and position the dumbbells at shoulder level with your palms facing each other. Press the dumbbells up and away from your body until your arms are fully extended. Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0321-PG1kcIb.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0321-PG1kcIb.gif', 'PG1kcIb', '© Gym visual — https://gymvisual.com/'),
('1618', 'dumbbell incline hammer press on exercise ball', 'Siéntate sobre un balón de estabilidad con una mancuerna en cada mano, con las palmas enfrentadas entre sí. Camina con los pies hacia adelante y baja el cuerpo rodando sobre el balón hasta que la cabeza, el cuello y la parte superior de la espalda queden apoyados sobre el balón. Sostén las mancuerna', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'triceps', '{"chest","shoulders"}', 'Siéntate sobre un balón de estabilidad con una mancuerna en cada mano, con las palmas enfrentadas entre sí. Camina con los pies hacia adelante y baja el cuerpo rodando sobre el balón hasta que la cabeza, el cuello y la parte superior de la espalda queden apoyados sobre el balón. Sostén las mancuernas a la altura de los hombros, con los codos flexionados y apuntando hacia los lados. Empuja las mancuernas hacia arriba y ligeramente hacia adentro, manteniendo las palmas enfrentadas entre sí. Extiende completamente los brazos, contrayendo los tríceps en la parte superior del movimiento. Baja lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on an exercise ball with a dumbbell in each hand, palms facing each other. Walk your feet forward and roll your body down the ball until your head, neck, and upper back are supported on the ball. Hold the dumbbells at shoulder level, elbows bent and pointing out to the sides. Press the dumbbells up and slightly inward, keeping your palms facing each other. Extend your arms fully, squeezing your triceps at the top of the movement. Slowly lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1618-wkgnGfb.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1618-wkgnGfb.gif', 'wkgnGfb', '© Gym visual — https://gymvisual.com/'),
('0322', 'dumbbell incline inner biceps curl', 'Siéntate en un banco inclinado con una mancuerna en cada mano, con las palmas enfrentadas entre sí. Apoya los brazos superiores en el banco, permitiendo que los codos cuelguen hacia abajo y las palmas miren hacia adelante. Manteniendo los brazos superiores fijos, exhala y levanta el peso mientras co', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Siéntate en un banco inclinado con una mancuerna en cada mano, con las palmas enfrentadas entre sí. Apoya los brazos superiores en el banco, permitiendo que los codos cuelguen hacia abajo y las palmas miren hacia adelante. Manteniendo los brazos superiores fijos, exhala y levanta el peso mientras contraes los bíceps. Continúa levantando las mancuernas hasta que los bíceps estén completamente contraídos y las mancuernas estén a la altura de los hombros. Mantén la posición contraída durante una breve pausa mientras aprietas los bíceps. Inhala y comienza a bajar lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on an incline bench with a dumbbell in each hand, palms facing each other. Rest your upper arms on the bench, allowing your elbows to hang down and your palms to face forward. Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly begin to lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0322-LCtQPn8.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0322-LCtQPn8.gif', 'LCtQPn8', '© Gym visual — https://gymvisual.com/'),
('1279', 'dumbbell incline one arm fly', 'Ajusta el banco inclinado a un ángulo de 30-45 grados. Siéntate en el banco con una mancuerna en una mano, apoyándola sobre el muslo. Recuéstate en el banco, manteniendo los pies apoyados en el suelo. Sostén la mancuerna con el brazo extendido recto hacia arriba sobre el pecho. Baja la mancuerna hac', 'chest', 'dumbbell', 'chest', 'chest', 'pectorals', '{"deltoids","triceps"}', 'Ajusta el banco inclinado a un ángulo de 30-45 grados. Siéntate en el banco con una mancuerna en una mano, apoyándola sobre el muslo. Recuéstate en el banco, manteniendo los pies apoyados en el suelo. Sostén la mancuerna con el brazo extendido recto hacia arriba sobre el pecho. Baja la mancuerna hacia el lado describiendo un amplio arco, manteniendo una ligera flexión en el codo. Haz una pausa cuando el brazo esté paralelo al suelo, luego invierte el movimiento para llevar la mancuerna de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia de brazo.', 'Adjust the incline bench to a 30-45 degree angle. Sit on the bench with a dumbbell in one hand, resting it on your thigh. Lie back on the bench, keeping your feet flat on the ground. Hold the dumbbell with your arm extended straight up over your chest. Lower the dumbbell out to the side in a wide arc, keeping a slight bend in your elbow. Pause when your arm is parallel to the ground, then reverse the motion to bring the dumbbell back to the starting position. Repeat for the desired number of repetitions, then switch arms.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1279-Gw2HFvW.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1279-Gw2HFvW.gif', 'Gw2HFvW', '© Gym visual — https://gymvisual.com/'),
('1280', 'dumbbell incline one arm fly on exercise ball', 'Siéntate sobre un balón de estabilidad con una mancuerna en una mano. Camina con los pies hacia adelante y baja el cuerpo rodando hasta que la cabeza, el cuello y la parte superior de la espalda queden apoyados sobre el balón. Sostén la mancuerna con el brazo extendido recto hacia arriba sobre el pe', 'chest', 'dumbbell', 'chest', 'chest', 'pectorals', '{"shoulders"}', 'Siéntate sobre un balón de estabilidad con una mancuerna en una mano. Camina con los pies hacia adelante y baja el cuerpo rodando hasta que la cabeza, el cuello y la parte superior de la espalda queden apoyados sobre el balón. Sostén la mancuerna con el brazo extendido recto hacia arriba sobre el pecho, con la palma hacia adentro. Baja lentamente la mancuerna hacia el lado, manteniendo una ligera flexión en el codo. Haz una pausa por un momento cuando el brazo esté paralelo al suelo. Activa los músculos del pecho para llevar la mancuerna de nuevo hacia arriba hasta la posición inicial. Repite el número de repeticiones deseado, luego cambia de brazo.', 'Sit on an exercise ball with a dumbbell in one hand. Walk your feet forward and roll your body down until your head, neck, and upper back are supported on the ball. Hold the dumbbell with your arm extended straight up over your chest, palm facing inwards. Slowly lower the dumbbell out to the side, keeping a slight bend in your elbow. Pause for a moment when your arm is parallel to the ground. Engage your chest muscles to bring the dumbbell back up to the starting position. Repeat for the desired number of repetitions, then switch arms.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1280-LLNh6q5.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1280-LLNh6q5.gif', 'LLNh6q5', '© Gym visual — https://gymvisual.com/'),
('1619', 'dumbbell incline one arm hammer press', 'Siéntate en un banco inclinado con una mancuerna en una mano, apoyada sobre el muslo. Recuéstate en el banco y usa el muslo para ayudar a levantar la mancuerna hasta la altura de los hombros. Gira la muñeca de modo que la palma quede mirando hacia adentro, hacia el cuerpo. Empuja la mancuerna hacia ', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'triceps', '{"shoulders","chest"}', 'Siéntate en un banco inclinado con una mancuerna en una mano, apoyada sobre el muslo. Recuéstate en el banco y usa el muslo para ayudar a levantar la mancuerna hasta la altura de los hombros. Gira la muñeca de modo que la palma quede mirando hacia adentro, hacia el cuerpo. Empuja la mancuerna hacia arriba y alejándola del cuerpo, extendiendo completamente el brazo. Haz una pausa breve en la parte más alta, luego baja lentamente la mancuerna de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia de brazo.', 'Sit on an incline bench with a dumbbell in one hand, resting on your thigh. Lean back on the bench and use your thigh to help raise the dumbbell to shoulder height. Rotate your wrist so that your palm is facing inward, towards your body. Press the dumbbell up and away from your body, extending your arm fully. Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position. Repeat for the desired number of repetitions, then switch arms.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1619-LL1UiTX.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1619-LL1UiTX.gif', 'LL1UiTX', '© Gym visual — https://gymvisual.com/'),
('1620', 'dumbbell incline one arm hammer press on exercise ball', 'Siéntate sobre un balón de estabilidad con una mancuerna en una mano. Camina con los pies hacia adelante y baja el cuerpo rodando hasta que la cabeza, el cuello y la parte superior de la espalda queden apoyados sobre el balón. Sostén la mancuerna con la palma hacia adentro y el codo flexionado en un', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'triceps', '{"shoulders","chest"}', 'Siéntate sobre un balón de estabilidad con una mancuerna en una mano. Camina con los pies hacia adelante y baja el cuerpo rodando hasta que la cabeza, el cuello y la parte superior de la espalda queden apoyados sobre el balón. Sostén la mancuerna con la palma hacia adentro y el codo flexionado en un ángulo de 90 grados. Empuja la mancuerna hacia el techo, estirando el brazo. Baja la mancuerna de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia de brazo.', 'Sit on an exercise ball with a dumbbell in one hand. Walk your feet forward and roll your body down until your head, neck, and upper back are supported on the ball. Hold the dumbbell with your palm facing inward and your elbow bent at a 90-degree angle. Press the dumbbell up towards the ceiling, straightening your arm. Lower the dumbbell back down to the starting position. Repeat for the desired number of repetitions, then switch arms.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1620-jDnrkar.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1620-jDnrkar.gif', 'jDnrkar', '© Gym visual — https://gymvisual.com/'),
('0323', 'dumbbell incline one arm lateral raise', 'Siéntate en un banco inclinado con una mancuerna en una mano, apoyándola sobre el muslo. Inclínate hacia adelante y coloca el brazo superior contra la parte interna del muslo. Levanta la mancuerna hacia el lado, manteniendo el brazo ligeramente flexionado y la palma hacia abajo. Continúa levantando ', 'shoulders', 'dumbbell', 'shoulders', 'shoulders', 'delts', '{"trapezius","triceps"}', 'Siéntate en un banco inclinado con una mancuerna en una mano, apoyándola sobre el muslo. Inclínate hacia adelante y coloca el brazo superior contra la parte interna del muslo. Levanta la mancuerna hacia el lado, manteniendo el brazo ligeramente flexionado y la palma hacia abajo. Continúa levantando hasta que el brazo quede paralelo al suelo. Haz una pausa breve en la parte más alta, luego baja lentamente la mancuerna de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia al otro brazo.', 'Sit on an incline bench with a dumbbell in one hand, resting it on your thigh. Lean forward and position your upper arm against the inside of your thigh. Raise the dumbbell to the side, keeping your arm slightly bent and your palm facing down. Continue lifting until your arm is parallel to the floor. Pause for a moment at the top, then slowly lower the dumbbell back to the starting position. Repeat for the desired number of repetitions, then switch to the other arm.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0323-aTNKZiC.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0323-aTNKZiC.gif', 'aTNKZiC', '© Gym visual — https://gymvisual.com/'),
('1281', 'dumbbell incline one arm press', 'Siéntate en un banco inclinado con una mancuerna en una mano, apoyada sobre el muslo. Recuéstate en el banco y coloca la mancuerna a la altura del hombro, con la palma hacia adelante. Empuja la mancuerna hacia arriba y ligeramente hacia adentro, extendiendo completamente el brazo. Haz una pausa brev', 'chest', 'dumbbell', 'chest', 'chest', 'pectorals', '{"shoulders","triceps"}', 'Siéntate en un banco inclinado con una mancuerna en una mano, apoyada sobre el muslo. Recuéstate en el banco y coloca la mancuerna a la altura del hombro, con la palma hacia adelante. Empuja la mancuerna hacia arriba y ligeramente hacia adentro, extendiendo completamente el brazo. Haz una pausa breve en la parte más alta, luego baja lentamente la mancuerna de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia al otro brazo.', 'Sit on an incline bench with a dumbbell in one hand, resting on your thigh. Lie back on the bench and position the dumbbell at shoulder level, palm facing forward. Press the dumbbell upward and slightly inward, extending your arm fully. Pause for a moment at the top, then slowly lower the dumbbell back to the starting position. Repeat for the desired number of repetitions, then switch to the other arm.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1281-rDAiRf9.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1281-rDAiRf9.gif', 'rDAiRf9', '© Gym visual — https://gymvisual.com/'),
('1282', 'dumbbell incline one arm press on exercise ball', 'Siéntate sobre un balón de estabilidad con una mancuerna en una mano, con los pies apoyados en el suelo. Camina lentamente con los pies hacia adelante, haciendo rodar el balón hasta que la cabeza, el cuello y la parte superior de la espalda queden apoyados sobre el balón. Sostén la mancuerna a la al', 'chest', 'dumbbell', 'chest', 'chest', 'pectorals', '{"shoulders","triceps"}', 'Siéntate sobre un balón de estabilidad con una mancuerna en una mano, con los pies apoyados en el suelo. Camina lentamente con los pies hacia adelante, haciendo rodar el balón hasta que la cabeza, el cuello y la parte superior de la espalda queden apoyados sobre el balón. Sostén la mancuerna a la altura del hombro con la palma hacia adelante. Empuja la mancuerna hacia arriba hasta que el brazo quede completamente extendido. Haz una pausa breve en la parte más alta, luego baja lentamente la mancuerna de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia al otro brazo.', 'Sit on an exercise ball with a dumbbell in one hand, feet flat on the ground. Slowly walk your feet forward, rolling the ball until your head, neck, and upper back are supported on the ball. Hold the dumbbell at shoulder height with your palm facing forward. Press the dumbbell upward until your arm is fully extended. Pause for a moment at the top, then slowly lower the dumbbell back to the starting position. Repeat for the desired number of repetitions, then switch to the other arm.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1282-Bg5JKSH.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1282-Bg5JKSH.gif', 'Bg5JKSH', '© Gym visual — https://gymvisual.com/'),
('0324', 'dumbbell incline palm-in press', 'Coloca un banco inclinado a un ángulo de 45 grados. Siéntate en el banco con una mancuerna en cada mano, con las palmas enfrentadas entre sí. Planta los pies firmemente en el suelo y mantén la espalda recta contra el banco. Comienza con las mancuernas a la altura de los hombros, con los codos flexio', 'chest', 'dumbbell', 'chest', 'chest', 'pectorals', '{"shoulders","triceps"}', 'Coloca un banco inclinado a un ángulo de 45 grados. Siéntate en el banco con una mancuerna en cada mano, con las palmas enfrentadas entre sí. Planta los pies firmemente en el suelo y mantén la espalda recta contra el banco. Comienza con las mancuernas a la altura de los hombros, con los codos flexionados y las palmas enfrentadas entre sí. Empuja las mancuernas hacia arriba y alejándolas del cuerpo, extendiendo completamente los brazos. Haz una pausa breve en la parte alta, luego baja lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Set up an incline bench at a 45-degree angle. Sit on the bench with a dumbbell in each hand, palms facing each other. Plant your feet firmly on the ground and keep your back straight against the bench. Start with the dumbbells at shoulder level, elbows bent and palms facing each other. Press the dumbbells up and away from your body, extending your arms fully. Pause for a moment at the top, then slowly lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0324-OVLmUuL.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0324-OVLmUuL.gif', 'OVLmUuL', '© Gym visual — https://gymvisual.com/'),
('1283', 'dumbbell incline press on exercise ball', 'Siéntate sobre un balón de estabilidad con una mancuerna en cada mano, con las palmas hacia adelante. Camina lentamente con los pies hacia adelante, bajando el cuerpo rodando sobre el balón hasta que la cabeza, el cuello y la parte superior de la espalda queden apoyados sobre el balón. Sostén las ma', 'chest', 'dumbbell', 'chest', 'chest', 'pectorals', '{"shoulders","triceps"}', 'Siéntate sobre un balón de estabilidad con una mancuerna en cada mano, con las palmas hacia adelante. Camina lentamente con los pies hacia adelante, bajando el cuerpo rodando sobre el balón hasta que la cabeza, el cuello y la parte superior de la espalda queden apoyados sobre el balón. Sostén las mancuernas a la altura de los hombros, con los codos flexionados y apuntando hacia los lados. Empuja las mancuernas hacia arriba, extendiendo completamente los brazos. Haz una pausa breve en la parte alta, luego baja lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on an exercise ball with a dumbbell in each hand, palms facing forward. Slowly walk your feet forward, rolling your body down the ball until your head, neck, and upper back are supported on the ball. Hold the dumbbells at shoulder level, elbows bent and pointing out to the sides. Press the dumbbells upward, extending your arms fully. Pause for a moment at the top, then slowly lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1283-bfiHMpI.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1283-bfiHMpI.gif', 'bfiHMpI', '© Gym visual — https://gymvisual.com/'),
('0325', 'dumbbell incline raise', 'Siéntate en un banco inclinado con una mancuerna en cada mano, apoyadas sobre los muslos. Recuéstate en el banco y levanta las mancuernas hasta la altura de los hombros, con las palmas hacia adelante. Manteniendo la espalda contra el banco, exhala y levanta las mancuernas por encima de la cabeza, ex', 'shoulders', 'dumbbell', 'shoulders', 'shoulders', 'delts', '{"trapezius","triceps"}', 'Siéntate en un banco inclinado con una mancuerna en cada mano, apoyadas sobre los muslos. Recuéstate en el banco y levanta las mancuernas hasta la altura de los hombros, con las palmas hacia adelante. Manteniendo la espalda contra el banco, exhala y levanta las mancuernas por encima de la cabeza, extendiendo completamente los brazos. Haz una pausa por un momento en la parte superior, luego inhala y baja lentamente las mancuernas de vuelta a la altura de los hombros. Repite el número de repeticiones deseado.', 'Sit on an incline bench with a dumbbell in each hand, resting on your thighs. Lean back on the bench and raise the dumbbells to shoulder height, palms facing forward. Keeping your back against the bench, exhale and raise the dumbbells above your head, fully extending your arms. Pause for a moment at the top, then inhale and slowly lower the dumbbells back to shoulder height. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0325-nxW6BkN.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0325-nxW6BkN.gif', 'nxW6BkN', '© Gym visual — https://gymvisual.com/'),
('0326', 'dumbbell incline rear lateral raise', 'Coloca un banco inclinado a un ángulo de 45 grados. Siéntate en el banco con el pecho contra el respaldo y sostén una mancuerna en cada mano. Extiende los brazos rectos hacia abajo con las palmas enfrentadas entre sí. Manteniendo una ligera flexión en los codos, levanta los brazos hacia los lados ha', 'shoulders', 'dumbbell', 'shoulders', 'shoulders', 'delts', '{"traps","rhomboids"}', 'Coloca un banco inclinado a un ángulo de 45 grados. Siéntate en el banco con el pecho contra el respaldo y sostén una mancuerna en cada mano. Extiende los brazos rectos hacia abajo con las palmas enfrentadas entre sí. Manteniendo una ligera flexión en los codos, levanta los brazos hacia los lados hasta que queden paralelos al suelo. Haz una pausa por un momento en la parte superior, luego baja lentamente los brazos de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Set up an incline bench at a 45-degree angle. Sit on the bench with your chest against the backrest and hold a dumbbell in each hand. Extend your arms straight down with your palms facing each other. Keeping a slight bend in your elbows, raise your arms out to the sides until they are parallel to the ground. Pause for a moment at the top, then slowly lower your arms back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0326-vYk8lqw.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0326-vYk8lqw.gif', 'vYk8lqw', '© Gym visual — https://gymvisual.com/'),
('0327', 'dumbbell incline row', 'Coloca un banco inclinado a un ángulo de 45 grados. Toma una mancuerna en cada mano y siéntate en el banco con el pecho apoyado contra la inclinación. Extiende completamente los brazos, dejando que las mancuernas cuelguen rectas hacia abajo desde los hombros. Tira de las mancuernas hacia arriba, hac', 'back', 'dumbbell', 'back', 'back', 'upper back', '{"biceps","shoulders"}', 'Coloca un banco inclinado a un ángulo de 45 grados. Toma una mancuerna en cada mano y siéntate en el banco con el pecho apoyado contra la inclinación. Extiende completamente los brazos, dejando que las mancuernas cuelguen rectas hacia abajo desde los hombros. Tira de las mancuernas hacia arriba, hacia el pecho, apretando los omóplatos entre sí. Haz una pausa breve en la parte alta, luego baja lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Set up an incline bench at a 45-degree angle. Grab a dumbbell in each hand and sit on the bench with your chest against the incline. Extend your arms fully, allowing the dumbbells to hang straight down from your shoulders. Pull the dumbbells up towards your chest, squeezing your shoulder blades together. Pause for a moment at the top, then slowly lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0327-7vG5o25.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0327-7vG5o25.gif', '7vG5o25', '© Gym visual — https://gymvisual.com/'),
('0328', 'dumbbell incline shoulder raise', 'Ajusta un banco inclinado a un ángulo de 45 grados y siéntate en él con una mancuerna en cada mano, con las palmas hacia abajo. Apoya las mancuernas sobre los muslos y recuéstate en el banco. Usa los muslos para ayudar a levantar las mancuernas hasta la altura de los hombros, luego gira las muñecas ', 'chest', 'dumbbell', 'chest', 'chest', 'serratus anterior', '{"deltoids","trapezius"}', 'Ajusta un banco inclinado a un ángulo de 45 grados y siéntate en él con una mancuerna en cada mano, con las palmas hacia abajo. Apoya las mancuernas sobre los muslos y recuéstate en el banco. Usa los muslos para ayudar a levantar las mancuernas hasta la altura de los hombros, luego gira las muñecas de modo que las palmas queden mirando hacia adelante. Exhala y levanta lentamente las mancuernas por encima de la cabeza, manteniendo una ligera flexión en los codos. Haz una pausa por un momento en la parte superior, luego inhala y baja lentamente las mancuernas de vuelta a la altura de los hombros. Repite el número de repeticiones deseado.', 'Set an incline bench to a 45-degree angle and sit on it with a dumbbell in each hand, palms facing down. Rest the dumbbells on your thighs and lean back onto the bench. Use your thighs to help raise the dumbbells to shoulder height, then rotate your wrists so that your palms are facing forward. Exhale and slowly raise the dumbbells above your head, keeping a slight bend in your elbows. Pause for a moment at the top, then inhale and slowly lower the dumbbells back to shoulder height. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0328-6e2DcYX.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0328-6e2DcYX.gif', '6e2DcYX', '© Gym visual — https://gymvisual.com/'),
('0329', 'dumbbell incline shrug', 'Ajusta un banco inclinado a un ángulo de 45 grados y siéntate en él con una mancuerna en cada mano. Coloca los pies planos sobre el suelo y deja que los brazos cuelguen rectos hacia abajo con las palmas hacia el cuerpo. Manteniendo los brazos rectos, encoge los hombros hacia las orejas lo más alto p', 'back', 'dumbbell', 'back', 'back', 'traps', '{"shoulders"}', 'Ajusta un banco inclinado a un ángulo de 45 grados y siéntate en él con una mancuerna en cada mano. Coloca los pies planos sobre el suelo y deja que los brazos cuelguen rectos hacia abajo con las palmas hacia el cuerpo. Manteniendo los brazos rectos, encoge los hombros hacia las orejas lo más alto posible. Mantén la contracción por un momento, luego baja lentamente los hombros de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Set an incline bench to a 45-degree angle and sit on it with a dumbbell in each hand. Place your feet flat on the ground and let your arms hang straight down with your palms facing your body. Keeping your arms straight, shrug your shoulders up towards your ears as high as possible. Hold the contraction for a moment, then slowly lower your shoulders back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0329-JymLInS.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0329-JymLInS.gif', 'JymLInS', '© Gym visual — https://gymvisual.com/'),
('3542', 'dumbbell incline t-raise', 'Ajusta un banco inclinado a un ángulo de 45 grados y siéntate en él con una mancuerna en cada mano, con las palmas hacia adentro. Inclínate hacia adelante y deja que los brazos cuelguen rectos hacia abajo, perpendiculares al suelo. Manteniendo los brazos rectos, levántalos hacia los lados hasta que ', 'shoulders', 'dumbbell', 'shoulders', 'shoulders', 'delts', '{"traps","rhomboids"}', 'Ajusta un banco inclinado a un ángulo de 45 grados y siéntate en él con una mancuerna en cada mano, con las palmas hacia adentro. Inclínate hacia adelante y deja que los brazos cuelguen rectos hacia abajo, perpendiculares al suelo. Manteniendo los brazos rectos, levántalos hacia los lados hasta que queden paralelos al suelo, formando una ''T'' con el cuerpo. Haz una pausa por un momento en la parte superior, luego baja lentamente los brazos de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Set an incline bench to a 45-degree angle and sit on it with a dumbbell in each hand, palms facing inwards. Lean forward and let your arms hang straight down, perpendicular to the floor. Keeping your arms straight, raise them out to the sides until they are parallel to the floor, forming a ''T'' shape with your body. Pause for a moment at the top, then slowly lower your arms back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3542-jgbvVJ0.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3542-jgbvVJ0.gif', 'jgbvVJ0', '© Gym visual — https://gymvisual.com/'),
('0330', 'dumbbell incline triceps extension', 'Siéntate en un banco inclinado con una mancuerna en cada mano, con las palmas hacia adentro. Extiende completamente los brazos por encima de la cabeza, manteniendo los codos cerca de la cabeza. Baja las mancuernas detrás de la cabeza flexionando los codos, manteniendo los brazos superiores quietos. ', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'triceps', '{"shoulders"}', 'Siéntate en un banco inclinado con una mancuerna en cada mano, con las palmas hacia adentro. Extiende completamente los brazos por encima de la cabeza, manteniendo los codos cerca de la cabeza. Baja las mancuernas detrás de la cabeza flexionando los codos, manteniendo los brazos superiores quietos. Haz una pausa por un momento, luego levanta las mancuernas de vuelta a la posición inicial extendiendo los brazos. Repite el número de repeticiones deseado.', 'Sit on an incline bench with a dumbbell in each hand, palms facing inwards. Extend your arms fully overhead, keeping your elbows close to your head. Lower the dumbbells behind your head by bending your elbows, keeping your upper arms stationary. Pause for a moment, then raise the dumbbells back to the starting position by extending your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0330-OVIKwsd.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0330-OVIKwsd.gif', 'OVIKwsd', '© Gym visual — https://gymvisual.com/'),
('0331', 'dumbbell incline twisted flyes', 'Ajusta un banco inclinado a un ángulo de 45 grados y siéntate en él con una mancuerna en cada mano, con las palmas enfrentadas entre sí. Recuéstate en el banco y empuja las mancuernas hacia arriba hasta la posición inicial, directamente por encima del pecho, con los brazos extendidos. Baja las mancu', 'chest', 'dumbbell', 'chest', 'chest', 'pectorals', '{"shoulders","triceps"}', 'Ajusta un banco inclinado a un ángulo de 45 grados y siéntate en él con una mancuerna en cada mano, con las palmas enfrentadas entre sí. Recuéstate en el banco y empuja las mancuernas hacia arriba hasta la posición inicial, directamente por encima del pecho, con los brazos extendidos. Baja las mancuernas hacia los lados describiendo un amplio arco hasta sentir un estiramiento en el pecho. Mientras bajas las mancuernas, gira las muñecas de modo que las palmas queden mirando hacia adelante en la parte inferior del movimiento. Invierte el movimiento y lleva las mancuernas de nuevo hacia arriba hasta la posición inicial, contrayendo los músculos del pecho en la parte superior. Repite el número de repeticiones deseado.', 'Set an incline bench to a 45-degree angle and sit on it with a dumbbell in each hand, palms facing each other. Lie back on the bench and press the dumbbells up to the starting position, directly above your chest, with your arms extended. Lower the dumbbells out to the sides in a wide arc until you feel a stretch in your chest. As you lower the dumbbells, rotate your wrists so that your palms face forward at the bottom of the movement. Reverse the motion and bring the dumbbells back up to the starting position, squeezing your chest muscles together at the top. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0331-1PLE8e9.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0331-1PLE8e9.gif', '1PLE8e9', '© Gym visual — https://gymvisual.com/'),
('1733', 'dumbbell incline two arm extension', 'Siéntate en un banco inclinado con una mancuerna en cada mano, apoyadas sobre los muslos. Recuéstate lentamente en el banco, manteniendo las mancuernas cerca del pecho. Una vez completamente recostado, extiende los brazos rectos hacia el techo, manteniendo los codos ligeramente flexionados. Haz una ', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'triceps', '{"shoulders"}', 'Siéntate en un banco inclinado con una mancuerna en cada mano, apoyadas sobre los muslos. Recuéstate lentamente en el banco, manteniendo las mancuernas cerca del pecho. Una vez completamente recostado, extiende los brazos rectos hacia el techo, manteniendo los codos ligeramente flexionados. Haz una pausa breve en la parte alta, luego baja lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on an incline bench with a dumbbell in each hand, resting on your thighs. Slowly lie back on the bench, keeping the dumbbells close to your chest. Once you are fully lying down, extend your arms straight up towards the ceiling, keeping your elbows slightly bent. Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1733-U7D9Fx3.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1733-U7D9Fx3.gif', 'U7D9Fx3', '© Gym visual — https://gymvisual.com/'),
('3541', 'dumbbell incline y-raise', 'Ajusta un banco inclinado a un ángulo de 45 grados y siéntate en él con una mancuerna en cada mano, con las palmas hacia adentro. Inclínate ligeramente hacia adelante y deja que los brazos cuelguen rectos hacia abajo, manteniendo una ligera flexión en los codos. Levanta los brazos hacia los lados y ', 'back', 'dumbbell', 'back', 'back', 'upper back', '{"shoulders","rear deltoids"}', 'Ajusta un banco inclinado a un ángulo de 45 grados y siéntate en él con una mancuerna en cada mano, con las palmas hacia adentro. Inclínate ligeramente hacia adelante y deja que los brazos cuelguen rectos hacia abajo, manteniendo una ligera flexión en los codos. Levanta los brazos hacia los lados y hacia arriba formando una Y hasta que queden paralelos al suelo. Haz una pausa por un momento en la parte superior, luego baja lentamente los brazos de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Set an incline bench to a 45-degree angle and sit on it with a dumbbell in each hand, palms facing inwards. Lean forward slightly and let your arms hang straight down, keeping a slight bend in your elbows. Raise your arms out to the sides and up in a Y shape until they are parallel to the ground. Pause for a moment at the top, then slowly lower your arms back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3541-PbzNu7c.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3541-PbzNu7c.gif', 'PbzNu7c', '© Gym visual — https://gymvisual.com/'),
('0332', 'dumbbell iron cross', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo una mancuerna en cada mano a los costados. Levanta los brazos hacia los lados hasta que queden paralelos al suelo, formando una T con el cuerpo. Haz una pausa por un momento, luego baja lentamente los brazos de vuelta a la p', 'shoulders', 'dumbbell', 'shoulders', 'shoulders', 'delts', '{"triceps","chest"}', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo una mancuerna en cada mano a los costados. Levanta los brazos hacia los lados hasta que queden paralelos al suelo, formando una T con el cuerpo. Haz una pausa por un momento, luego baja lentamente los brazos de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, holding a dumbbell in each hand at your sides. Raise your arms out to the sides until they are parallel to the ground, forming a T shape with your body. Pause for a moment, then slowly lower your arms back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0332-cALkHHX.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0332-cALkHHX.gif', 'cALkHHX', '© Gym visual — https://gymvisual.com/'),
('0333', 'dumbbell kickback', 'Ponte de pie con los pies separados a la altura de los hombros y sostén una mancuerna en cada mano. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta. Acerca los brazos superiores a los costados, con los codos flexionados en un ángulo de 90 ', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'triceps', '{"shoulders"}', 'Ponte de pie con los pies separados a la altura de los hombros y sostén una mancuerna en cada mano. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta. Acerca los brazos superiores a los costados, con los codos flexionados en un ángulo de 90 grados. Extiende los brazos rectos hacia atrás, contrayendo los tríceps en la parte superior del movimiento. Haz una pausa por un momento, luego baja lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and hold a dumbbell in each hand. Bend your knees slightly and hinge forward at the hips, keeping your back straight. Bring your upper arms close to your sides, with your elbows bent at a 90-degree angle. Extend your arms straight back, squeezing your triceps at the top of the movement. Pause for a moment, then slowly lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0333-W6PxUkg.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0333-W6PxUkg.gif', 'W6PxUkg', '© Gym visual — https://gymvisual.com/'),
('1734', 'dumbbell kickbacks on exercise ball', 'Siéntate sobre un balón de ejercicio con los pies apoyados planos en el suelo y la espalda recta. Sostén una mancuerna en cada mano con las palmas hacia adentro y los brazos flexionados en un ángulo de 90 grados. Extiende los brazos rectos hacia atrás, contrayendo los tríceps en la parte superior de', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'triceps', '{"shoulders","back"}', 'Siéntate sobre un balón de ejercicio con los pies apoyados planos en el suelo y la espalda recta. Sostén una mancuerna en cada mano con las palmas hacia adentro y los brazos flexionados en un ángulo de 90 grados. Extiende los brazos rectos hacia atrás, contrayendo los tríceps en la parte superior del movimiento. Haz una pausa por un momento, luego baja lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on an exercise ball with your feet flat on the ground and your back straight. Hold a dumbbell in each hand with your palms facing inwards and your arms bent at a 90-degree angle. Extend your arms straight back, squeezing your triceps at the top of the movement. Pause for a moment, then slowly lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1734-cAvTaSg.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1734-cAvTaSg.gif', 'cAvTaSg', '© Gym visual — https://gymvisual.com/'),
('1660', 'dumbbell kneeling bicep curl exercise ball', 'Arrodíllate en el suelo con un balón de estabilidad frente a ti. Coloca los codos sobre el balón de estabilidad, sosteniendo una mancuerna en cada mano con las palmas hacia arriba. Manteniendo los brazos superiores quietos, exhala y flexiona las mancuernas contrayendo los bíceps. Continúa levantando', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Arrodíllate en el suelo con un balón de estabilidad frente a ti. Coloca los codos sobre el balón de estabilidad, sosteniendo una mancuerna en cada mano con las palmas hacia arriba. Manteniendo los brazos superiores quietos, exhala y flexiona las mancuernas contrayendo los bíceps. Continúa levantando las mancuernas hasta que los bíceps estén completamente contraídos y las mancuernas estén a la altura de los hombros. Mantén la posición contraída durante una breve pausa mientras aprietas los bíceps. Inhala y comienza a bajar lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Kneel on the floor with an exercise ball in front of you. Place your elbows on top of the exercise ball, holding a dumbbell in each hand with your palms facing up. Keeping your upper arms stationary, exhale and curl the dumbbells while contracting your biceps. Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly begin to lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1660-2JCuFTU.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1660-2JCuFTU.gif', '2JCuFTU', '© Gym visual — https://gymvisual.com/'),
('0334', 'dumbbell lateral raise', 'Ponte de pie con los pies separados a la altura de los hombros y sostén una mancuerna en cada mano, con las palmas hacia el cuerpo. Mantén la espalda recta y activa el core. Levanta los brazos hacia los lados hasta que queden paralelos al suelo, manteniendo una ligera flexión en los codos. Haz una p', 'shoulders', 'dumbbell', 'shoulders', 'shoulders', 'delts', '{"traps"}', 'Ponte de pie con los pies separados a la altura de los hombros y sostén una mancuerna en cada mano, con las palmas hacia el cuerpo. Mantén la espalda recta y activa el core. Levanta los brazos hacia los lados hasta que queden paralelos al suelo, manteniendo una ligera flexión en los codos. Haz una pausa por un momento en la parte superior, luego baja lentamente los brazos de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing your body. Keep your back straight and engage your core. Raise your arms out to the sides until they are parallel to the floor, keeping a slight bend in your elbows. Pause for a moment at the top, then slowly lower your arms back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0334-DsgkuIt.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0334-DsgkuIt.gif', 'DsgkuIt', '© Gym visual — https://gymvisual.com/'),
('0335', 'dumbbell lateral to front raise', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo una mancuerna en cada mano con las palmas hacia el cuerpo. Mantén la espalda recta y activa el core. Levanta los brazos hacia los lados hasta que queden paralelos al suelo, manteniendo una ligera flexión en los codos. Haz un', 'shoulders', 'dumbbell', 'shoulders', 'shoulders', 'delts', '{"trapezius","biceps"}', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo una mancuerna en cada mano con las palmas hacia el cuerpo. Mantén la espalda recta y activa el core. Levanta los brazos hacia los lados hasta que queden paralelos al suelo, manteniendo una ligera flexión en los codos. Haz una pausa por un momento en la parte superior, luego baja lentamente los brazos de vuelta a la posición inicial. Luego, levanta los brazos frente a ti hasta que queden paralelos al suelo, manteniendo nuevamente una ligera flexión en los codos. Haz una pausa por un momento en la parte superior, luego baja lentamente los brazos de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing your body. Keep your back straight and engage your core. Raise your arms out to the sides until they are parallel to the ground, keeping a slight bend in your elbows. Pause for a moment at the top, then slowly lower your arms back down to the starting position. Next, raise your arms in front of you until they are parallel to the ground, again keeping a slight bend in your elbows. Pause for a moment at the top, then slowly lower your arms back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0335-xMjBKwn.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0335-xMjBKwn.gif', 'xMjBKwn', '© Gym visual — https://gymvisual.com/'),
('0336', 'dumbbell lunge', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una mancuerna en cada mano. Da un paso adelante con el pie derecho, bajando el cuerpo hasta una posición de zancada. Mantén la espalda recta y el pecho erguido mientras bajas el cuerpo. Empuja con el talón derecho para regresa', 'upper legs', 'dumbbell', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves"}', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una mancuerna en cada mano. Da un paso adelante con el pie derecho, bajando el cuerpo hasta una posición de zancada. Mantén la espalda recta y el pecho erguido mientras bajas el cuerpo. Empuja con el talón derecho para regresar a la posición inicial. Repite con la pierna izquierda. Alterna las piernas el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, holding a dumbbell in each hand. Take a step forward with your right foot, lowering your body into a lunge position. Keep your back straight and your chest up as you lower your body. Push through your right heel to return to the starting position. Repeat with your left leg. Alternate legs for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0336-RRWFUcw.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0336-RRWFUcw.gif', 'RRWFUcw', '© Gym visual — https://gymvisual.com/'),
('1658', 'dumbbell lunge with bicep curl', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una mancuerna en cada mano con las palmas hacia adelante. Da un paso adelante con el pie derecho, bajando el cuerpo hasta una posición de zancada. La rodilla derecha debe quedar flexionada en un ángulo de 90 grados y la rodill', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"quadriceps","hamstrings"}', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una mancuerna en cada mano con las palmas hacia adelante. Da un paso adelante con el pie derecho, bajando el cuerpo hasta una posición de zancada. La rodilla derecha debe quedar flexionada en un ángulo de 90 grados y la rodilla izquierda debe quedar justo por encima del suelo. Mientras avanzas en la zancada, flexiona simultáneamente las mancuernas hacia los hombros, manteniendo los codos cerca del cuerpo. Haz una pausa por un momento en la parte baja de la zancada, luego empuja con el talón derecho para volver a la posición inicial, bajando las mancuernas de nuevo a los costados. Repite la zancada y el curl de bíceps en el lado opuesto, dando un paso adelante con el pie izquierdo. Continúa alternando lados durante el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing forward. Take a step forward with your right foot, lowering your body into a lunge position. Your right knee should be bent at a 90-degree angle and your left knee should be hovering just above the ground. As you lunge forward, simultaneously curl the dumbbells towards your shoulders, keeping your elbows close to your body. Pause for a moment at the bottom of the lunge, then push through your right heel to return to the starting position, lowering the dumbbells back down to your sides. Repeat the lunge and bicep curl on the opposite side, stepping forward with your left foot. Continue alternating sides for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1658-Mz6lLcW.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1658-Mz6lLcW.gif', 'Mz6lLcW', '© Gym visual — https://gymvisual.com/'),
('0337', 'dumbbell lying extension (across face)', 'Túmbate boca arriba en un banco con los pies planos sobre el suelo y la cabeza en el extremo del banco. Sostén una mancuerna con ambas manos y extiende los brazos rectos hacia arriba sobre el pecho, con las palmas enfrentadas entre sí. Manteniendo los brazos superiores quietos, baja lentamente la ma', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'triceps', '{"shoulders"}', 'Túmbate boca arriba en un banco con los pies planos sobre el suelo y la cabeza en el extremo del banco. Sostén una mancuerna con ambas manos y extiende los brazos rectos hacia arriba sobre el pecho, con las palmas enfrentadas entre sí. Manteniendo los brazos superiores quietos, baja lentamente la mancuerna describiendo un arco detrás de la cabeza hasta que los antebrazos queden paralelos al suelo. Haz una pausa por un momento, luego contrae los tríceps para llevar la mancuerna de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on a bench with your feet flat on the ground and your head at the end of the bench. Hold a dumbbell with both hands and extend your arms straight up above your chest, palms facing each other. Keeping your upper arms stationary, slowly lower the dumbbell in an arc behind your head until your forearms are parallel to the ground. Pause for a moment, then contract your triceps to bring the dumbbell back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0337-L2V5Nan.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0337-L2V5Nan.gif', 'L2V5Nan', '© Gym visual — https://gymvisual.com/'),
('1729', 'dumbbell lying alternate extension', 'Túmbate boca arriba en un banco con una mancuerna en cada mano, con las palmas enfrentadas entre sí. Extiende los brazos rectos hacia arriba sobre el pecho, con una ligera flexión en los codos. Baja una mancuerna hacia la cabeza, flexionando el codo, mientras mantienes el otro brazo extendido. Haz u', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'triceps', '{"shoulders"}', 'Túmbate boca arriba en un banco con una mancuerna en cada mano, con las palmas enfrentadas entre sí. Extiende los brazos rectos hacia arriba sobre el pecho, con una ligera flexión en los codos. Baja una mancuerna hacia la cabeza, flexionando el codo, mientras mantienes el otro brazo extendido. Haz una pausa breve en la parte baja, luego levanta la mancuerna de vuelta a la posición inicial. Repite con el otro brazo, alternando lados el número de repeticiones deseado.', 'Lie flat on a bench with a dumbbell in each hand, palms facing each other. Extend your arms straight up over your chest, keeping a slight bend in your elbows. Lower one dumbbell down towards your head, bending at the elbow, while keeping the other arm extended. Pause for a moment at the bottom, then raise the dumbbell back up to the starting position. Repeat with the other arm, alternating sides for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1729-NfP83rA.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1729-NfP83rA.gif', 'NfP83rA', '© Gym visual — https://gymvisual.com/'),
('0338', 'dumbbell lying elbow press', 'Túmbate boca arriba en un banco con una mancuerna en cada mano, con las palmas enfrentadas entre sí y los brazos extendidos rectos hacia arriba sobre el pecho. Baja las mancuernas hacia los hombros flexionando los codos, manteniendo los brazos superiores quietos. Haz una pausa por un momento en la p', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'triceps', '{"chest","shoulders"}', 'Túmbate boca arriba en un banco con una mancuerna en cada mano, con las palmas enfrentadas entre sí y los brazos extendidos rectos hacia arriba sobre el pecho. Baja las mancuernas hacia los hombros flexionando los codos, manteniendo los brazos superiores quietos. Haz una pausa por un momento en la parte inferior, luego empuja las mancuernas de nuevo hacia arriba hasta la posición inicial extendiendo los codos. Repite el número de repeticiones deseado.', 'Lie flat on a bench with a dumbbell in each hand, palms facing each other and arms extended straight up over your chest. Lower the dumbbells towards your shoulders by bending your elbows, keeping your upper arms stationary. Pause for a moment at the bottom, then press the dumbbells back up to the starting position by extending your elbows. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0338-eOCOwIR.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0338-eOCOwIR.gif', 'eOCOwIR', '© Gym visual — https://gymvisual.com/'),
('0863', 'dumbbell lying external shoulder rotation', 'Túmbate de lado en un banco plano con el brazo superior contra el costado y el codo flexionado a 90 grados. Sostén una mancuerna en la mano con la palma hacia abajo. Manteniendo el brazo superior contra el costado, gira lentamente el antebrazo hacia arriba lo más posible. Haz una pausa por un moment', 'shoulders', 'dumbbell', 'shoulders', 'shoulders', 'delts', '{"rotator cuff","triceps"}', 'Túmbate de lado en un banco plano con el brazo superior contra el costado y el codo flexionado a 90 grados. Sostén una mancuerna en la mano con la palma hacia abajo. Manteniendo el brazo superior contra el costado, gira lentamente el antebrazo hacia arriba lo más posible. Haz una pausa por un momento en la parte superior, luego baja lentamente el antebrazo de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia de lado.', 'Lie on your side on a flat bench with your upper arm against your side and your elbow bent 90 degrees. Hold a dumbbell in your hand with your palm facing down. Keeping your upper arm against your side, slowly rotate your forearm upward as far as possible. Pause for a moment at the top, then slowly lower your forearm back down to the starting position. Repeat for the desired number of repetitions, then switch sides.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0863-bmBf7LN.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0863-bmBf7LN.gif', 'bmBf7LN', '© Gym visual — https://gymvisual.com/'),
('0339', 'dumbbell lying femoral', 'Túmbate boca arriba con las piernas extendidas y una mancuerna apoyada sobre el abdomen bajo. Flexiona las rodillas y lleva la mancuerna hacia los glúteos, manteniendo los pies apoyados en el suelo. Haz una pausa breve en la parte más alta, luego baja lentamente la mancuerna de vuelta a la posición ', 'upper legs', 'dumbbell', 'upper legs', 'upper legs', 'hamstrings', '{"glutes"}', 'Túmbate boca arriba con las piernas extendidas y una mancuerna apoyada sobre el abdomen bajo. Flexiona las rodillas y lleva la mancuerna hacia los glúteos, manteniendo los pies apoyados en el suelo. Haz una pausa breve en la parte más alta, luego baja lentamente la mancuerna de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on your back with your legs extended and a dumbbell resting on your lower abdomen. Bend your knees and bring the dumbbell towards your glutes, keeping your feet flat on the ground. Pause for a moment at the top, then slowly lower the dumbbell back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0339-FkBIE6a.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0339-FkBIE6a.gif', 'FkBIE6a', '© Gym visual — https://gymvisual.com/'),
('0340', 'dumbbell lying hammer press', 'Túmbate boca arriba en un banco con una mancuerna en cada mano, con las palmas enfrentadas entre sí y los brazos extendidos rectos hacia arriba. Baja las mancuernas a los lados del pecho, manteniendo los codos en un ángulo de 90 grados. Empuja las mancuernas de nuevo hacia arriba hasta la posición i', 'chest', 'dumbbell', 'chest', 'chest', 'pectorals', '{"triceps","shoulders"}', 'Túmbate boca arriba en un banco con una mancuerna en cada mano, con las palmas enfrentadas entre sí y los brazos extendidos rectos hacia arriba. Baja las mancuernas a los lados del pecho, manteniendo los codos en un ángulo de 90 grados. Empuja las mancuernas de nuevo hacia arriba hasta la posición inicial, extendiendo completamente los brazos. Repite el número de repeticiones deseado.', 'Lie flat on a bench with a dumbbell in each hand, palms facing each other and arms extended straight up. Lower the dumbbells to the sides of your chest, keeping your elbows at a 90-degree angle. Press the dumbbells back up to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0340-7gdLIXa.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0340-7gdLIXa.gif', '7gdLIXa', '© Gym visual — https://gymvisual.com/'),
('2470', 'dumbbell lying on floor rear delt raise', 'Túmbate boca abajo en el suelo con una mancuerna en cada mano, con las palmas enfrentadas entre sí. Extiende los brazos rectos frente a ti, manteniendo una ligera flexión en los codos. Activando los músculos de los hombros, levanta los brazos hacia arriba y hacia los lados, juntando los omóplatos. H', 'shoulders', 'dumbbell', 'shoulders', 'shoulders', 'delts', '{"trapezius","rhomboids"}', 'Túmbate boca abajo en el suelo con una mancuerna en cada mano, con las palmas enfrentadas entre sí. Extiende los brazos rectos frente a ti, manteniendo una ligera flexión en los codos. Activando los músculos de los hombros, levanta los brazos hacia arriba y hacia los lados, juntando los omóplatos. Haz una pausa por un momento en la parte superior, luego baja lentamente los brazos de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie face down on the floor with a dumbbell in each hand, palms facing each other. Extend your arms straight out in front of you, keeping a slight bend in your elbows. Engaging your shoulder muscles, lift your arms up and out to the sides, squeezing your shoulder blades together. Pause for a moment at the top, then slowly lower your arms back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2470-Ion0XWz.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2470-Ion0XWz.gif', 'Ion0XWz', '© Gym visual — https://gymvisual.com/'),
('0341', 'dumbbell lying one arm deltoid rear', 'Túmbate boca abajo en un banco plano con una mancuerna en una mano, con la palma hacia adentro. Extiende el brazo recto hacia el suelo, manteniéndolo cerca del cuerpo. Levanta el brazo hacia arriba y hacia atrás, acercando el omóplato hacia la columna. Haz una pausa breve en la parte más alta, luego', 'shoulders', 'dumbbell', 'shoulders', 'shoulders', 'delts', '{"trapezius","rhomboids"}', 'Túmbate boca abajo en un banco plano con una mancuerna en una mano, con la palma hacia adentro. Extiende el brazo recto hacia el suelo, manteniéndolo cerca del cuerpo. Levanta el brazo hacia arriba y hacia atrás, acercando el omóplato hacia la columna. Haz una pausa breve en la parte más alta, luego baja lentamente el brazo de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia de brazo.', 'Lie face down on a flat bench with a dumbbell in one hand, palm facing inwards. Extend your arm straight down towards the floor, keeping it close to your body. Raise your arm up and back, squeezing your shoulder blade towards your spine. Pause for a moment at the top, then slowly lower your arm back down to the starting position. Repeat for the desired number of repetitions, then switch arms.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0341-gSw59a4.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0341-gSw59a4.gif', 'gSw59a4', '© Gym visual — https://gymvisual.com/'),
('0343', 'dumbbell lying one arm press', 'Túmbate boca arriba en un banco con una mancuerna en una mano y los pies apoyados en el suelo. Sostén la mancuerna a la altura del hombro con la palma hacia adelante. Empuja la mancuerna hacia arriba hasta que el brazo quede completamente extendido. Haz una pausa breve en la parte más alta, luego ba', 'chest', 'dumbbell', 'chest', 'chest', 'pectorals', '{"triceps","shoulders"}', 'Túmbate boca arriba en un banco con una mancuerna en una mano y los pies apoyados en el suelo. Sostén la mancuerna a la altura del hombro con la palma hacia adelante. Empuja la mancuerna hacia arriba hasta que el brazo quede completamente extendido. Haz una pausa breve en la parte más alta, luego baja lentamente la mancuerna de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia al otro brazo.', 'Lie flat on a bench with a dumbbell in one hand and your feet flat on the ground. Hold the dumbbell at shoulder level with your palm facing forward. Press the dumbbell upward until your arm is fully extended. Pause for a moment at the top, then slowly lower the dumbbell back to the starting position. Repeat for the desired number of repetitions, then switch to the other arm.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0343-zGSIWQi.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0343-zGSIWQi.gif', 'zGSIWQi', '© Gym visual — https://gymvisual.com/'),
('0342', 'dumbbell lying one arm press v. 2', 'Túmbate boca arriba en un banco con la espalda apoyada y los pies planos sobre el suelo. Sostén una mancuerna en una mano con la palma hacia los pies. Extiende el brazo recto hacia el techo, manteniendo el codo ligeramente flexionado. Baja lentamente la mancuerna hacia el pecho, manteniendo el codo ', 'chest', 'dumbbell', 'chest', 'chest', 'pectorals', '{"triceps","shoulders"}', 'Túmbate boca arriba en un banco con la espalda apoyada y los pies planos sobre el suelo. Sostén una mancuerna en una mano con la palma hacia los pies. Extiende el brazo recto hacia el techo, manteniendo el codo ligeramente flexionado. Baja lentamente la mancuerna hacia el pecho, manteniendo el codo cerca del cuerpo. Haz una pausa por un momento en la parte inferior, luego empuja la mancuerna de nuevo hacia arriba hasta la posición inicial. Repite el número de repeticiones deseado, luego cambia al otro brazo.', 'Lie flat on a bench with your back supported and feet flat on the ground. Hold a dumbbell in one hand with your palm facing towards your feet. Extend your arm straight up towards the ceiling, keeping your elbow slightly bent. Slowly lower the dumbbell down towards your chest, keeping your elbow close to your body. Pause for a moment at the bottom, then push the dumbbell back up to the starting position. Repeat for the desired number of repetitions, then switch to the other arm.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0342-K3dIO25.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0342-K3dIO25.gif', 'K3dIO25', '© Gym visual — https://gymvisual.com/'),
('0344', 'dumbbell lying one arm pronated triceps extension', 'Túmbate boca arriba en un banco con la espalda y la cabeza apoyadas, y los pies planos sobre el suelo. Sostén una mancuerna en una mano con la palma hacia abajo, y extiende el brazo recto por encima del hombro. Manteniendo el brazo superior quieto, baja lentamente la mancuerna detrás de la cabeza fl', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'triceps', '{"shoulders"}', 'Túmbate boca arriba en un banco con la espalda y la cabeza apoyadas, y los pies planos sobre el suelo. Sostén una mancuerna en una mano con la palma hacia abajo, y extiende el brazo recto por encima del hombro. Manteniendo el brazo superior quieto, baja lentamente la mancuerna detrás de la cabeza flexionando el codo. Haz una pausa por un momento en la parte inferior, luego extiende el brazo de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia de brazo.', 'Lie flat on a bench with your back and head supported, and your feet flat on the ground. Hold a dumbbell in one hand with your palm facing down, and extend your arm straight up above your shoulder. Keeping your upper arm stationary, slowly lower the dumbbell behind your head by bending your elbow. Pause for a moment at the bottom, then extend your arm back up to the starting position. Repeat for the desired number of repetitions, then switch arms.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0344-wyaqzOS.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0344-wyaqzOS.gif', 'wyaqzOS', '© Gym visual — https://gymvisual.com/'),
('0345', 'dumbbell lying one arm rear lateral raise', 'Túmbate boca abajo en un banco plano con una mancuerna en una mano, colgando hacia el suelo. Mantén el brazo recto y levanta la mancuerna hacia el lado, alejándola del cuerpo. Haz una pausa breve en la parte más alta, luego baja lentamente la mancuerna de vuelta a la posición inicial. Repite el núme', 'shoulders', 'dumbbell', 'shoulders', 'shoulders', 'delts', '{"traps","rhomboids"}', 'Túmbate boca abajo en un banco plano con una mancuerna en una mano, colgando hacia el suelo. Mantén el brazo recto y levanta la mancuerna hacia el lado, alejándola del cuerpo. Haz una pausa breve en la parte más alta, luego baja lentamente la mancuerna de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia al otro brazo.', 'Lie face down on a flat bench with a dumbbell in one hand, hanging towards the floor. Keep your arm straight and lift the dumbbell out to the side, away from your body. Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position. Repeat for the desired number of repetitions, then switch to the other arm.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0345-KwFGiEP.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0345-KwFGiEP.gif', 'KwFGiEP', '© Gym visual — https://gymvisual.com/'),
('0346', 'dumbbell lying one arm supinated triceps extension', 'Túmbate boca arriba en un banco con la espalda y la cabeza apoyadas, y los pies planos sobre el suelo. Sostén una mancuerna en una mano con agarre supino, y extiende el brazo recto por encima del hombro. Manteniendo el brazo superior quieto, baja lentamente la mancuerna detrás de la cabeza flexionan', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'triceps', '{"forearms"}', 'Túmbate boca arriba en un banco con la espalda y la cabeza apoyadas, y los pies planos sobre el suelo. Sostén una mancuerna en una mano con agarre supino, y extiende el brazo recto por encima del hombro. Manteniendo el brazo superior quieto, baja lentamente la mancuerna detrás de la cabeza flexionando el codo. Haz una pausa por un momento en la parte inferior, luego extiende el brazo de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia de brazo.', 'Lie flat on a bench with your back and head supported, and your feet flat on the ground. Hold a dumbbell in one hand with an underhand grip, and extend your arm straight up above your shoulder. Keeping your upper arm stationary, slowly lower the dumbbell behind your head by bending your elbow. Pause for a moment at the bottom, then extend your arm back up to the starting position. Repeat for the desired number of repetitions, then switch arms.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0346-zZlORz6.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0346-zZlORz6.gif', 'zZlORz6', '© Gym visual — https://gymvisual.com/'),
('0347', 'dumbbell lying pronation', 'Túmbate boca abajo en un banco con el pecho hacia abajo y los brazos extendidos rectos hacia abajo, sosteniendo una mancuerna en cada mano. Gira las palmas de modo que queden mirando hacia arriba. Manteniendo los brazos superiores quietos, exhala y flexiona las mancuernas mientras giras las palmas h', 'lower arms', 'dumbbell', 'lower arms', 'lower arms', 'forearms', '{"biceps","shoulders"}', 'Túmbate boca abajo en un banco con el pecho hacia abajo y los brazos extendidos rectos hacia abajo, sosteniendo una mancuerna en cada mano. Gira las palmas de modo que queden mirando hacia arriba. Manteniendo los brazos superiores quietos, exhala y flexiona las mancuernas mientras giras las palmas hacia abajo. Inhala y baja lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on a bench with your chest facing down and your arms extended straight down, holding a dumbbell in each hand. Rotate your palms so they are facing up. Keeping your upper arms stationary, exhale and curl the dumbbells as you rotate your palms to face down. Inhale and slowly lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0347-mym4hJo.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0347-mym4hJo.gif', 'mym4hJo', '© Gym visual — https://gymvisual.com/'),
('2705', 'dumbbell lying pronation on floor', 'Túmbate boca abajo en el suelo con los brazos extendidos rectos frente a ti, sosteniendo una mancuerna en cada mano. Gira las palmas de modo que queden mirando hacia el suelo. Manteniendo los brazos rectos, levanta las mancuernas del suelo contrayendo los antebrazos. Continúa levantando hasta que lo', 'lower arms', 'dumbbell', 'lower arms', 'lower arms', 'forearms', '{"biceps","triceps"}', 'Túmbate boca abajo en el suelo con los brazos extendidos rectos frente a ti, sosteniendo una mancuerna en cada mano. Gira las palmas de modo que queden mirando hacia el suelo. Manteniendo los brazos rectos, levanta las mancuernas del suelo contrayendo los antebrazos. Continúa levantando hasta que los antebrazos estén completamente contraídos y las mancuernas queden a la altura de los hombros. Mantén la posición por un momento, luego baja lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on the floor with your face down and your arms extended straight out in front of you, holding a dumbbell in each hand. Rotate your palms so they are facing down towards the floor. Keeping your arms straight, lift the dumbbells off the floor by contracting your forearms. Continue lifting until your forearms are fully contracted and the dumbbells are at shoulder level. Hold for a moment, then slowly lower the dumbbells back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2705-7RWNjiB.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2705-7RWNjiB.gif', '7RWNjiB', '© Gym visual — https://gymvisual.com/'),
('1284', 'dumbbell lying pullover on exercise ball', 'Siéntate sobre un balón de estabilidad y rueda hacia adelante hasta que la parte superior de la espalda quede apoyada en el balón. Sostén una mancuerna con ambas manos y extiende los brazos rectos hacia arriba sobre el pecho. Baja lentamente la mancuerna detrás de la cabeza manteniendo los brazos re', 'chest', 'dumbbell', 'chest', 'chest', 'pectorals', '{"triceps","shoulders","back"}', 'Siéntate sobre un balón de estabilidad y rueda hacia adelante hasta que la parte superior de la espalda quede apoyada en el balón. Sostén una mancuerna con ambas manos y extiende los brazos rectos hacia arriba sobre el pecho. Baja lentamente la mancuerna detrás de la cabeza manteniendo los brazos rectos. Haz una pausa por un momento, luego levanta la mancuerna de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on an exercise ball and roll forward until your upper back is resting on the ball. Hold a dumbbell with both hands and extend your arms straight up over your chest. Slowly lower the dumbbell behind your head while keeping your arms straight. Pause for a moment, then raise the dumbbell back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1284-iK59oEA.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1284-iK59oEA.gif', 'iK59oEA', '© Gym visual — https://gymvisual.com/'),
('1328', 'dumbbell lying rear delt row', 'Túmbate boca abajo en un banco plano con una mancuerna en cada mano, con las palmas hacia adentro. Extiende los brazos rectos hacia el suelo, manteniendo una ligera flexión en los codos. Activando los músculos de la espalda, levanta las mancuernas hacia el pecho, juntando los omóplatos. Haz una paus', 'back', 'dumbbell', 'back', 'back', 'upper back', '{"shoulders","biceps"}', 'Túmbate boca abajo en un banco plano con una mancuerna en cada mano, con las palmas hacia adentro. Extiende los brazos rectos hacia el suelo, manteniendo una ligera flexión en los codos. Activando los músculos de la espalda, levanta las mancuernas hacia el pecho, juntando los omóplatos. Haz una pausa breve en la parte alta, luego baja lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie face down on a flat bench with a dumbbell in each hand, palms facing inwards. Extend your arms straight down towards the floor, keeping a slight bend in your elbows. Engaging your back muscles, lift the dumbbells up towards your chest, squeezing your shoulder blades together. Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1328-XUUD0Fs.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1328-XUUD0Fs.gif', 'XUUD0Fs', '© Gym visual — https://gymvisual.com/'),
('0348', 'dumbbell lying rear lateral raise', 'Túmbate boca abajo en un banco plano con una mancuerna en cada mano, con las palmas enfrentadas entre sí. Extiende los brazos rectos hacia el suelo, manteniendo una ligera flexión en los codos. Activando los músculos de los hombros, levanta los brazos hacia los lados hasta que queden paralelos al su', 'shoulders', 'dumbbell', 'shoulders', 'shoulders', 'delts', '{"traps","rhomboids"}', 'Túmbate boca abajo en un banco plano con una mancuerna en cada mano, con las palmas enfrentadas entre sí. Extiende los brazos rectos hacia el suelo, manteniendo una ligera flexión en los codos. Activando los músculos de los hombros, levanta los brazos hacia los lados hasta que queden paralelos al suelo. Haz una pausa por un momento en la parte superior, luego baja lentamente los brazos de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie face down on a flat bench with a dumbbell in each hand, palms facing each other. Extend your arms straight down towards the floor, keeping a slight bend in your elbows. Engaging your shoulder muscles, lift your arms out to the sides until they are parallel to the floor. Pause for a moment at the top, then slowly lower your arms back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0348-53Ttlck.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0348-53Ttlck.gif', '53Ttlck', '© Gym visual — https://gymvisual.com/'),
('1735', 'dumbbell lying single extension', 'Túmbate boca arriba en un banco con una mancuerna en una mano y el brazo completamente extendido por encima del pecho. Baja la mancuerna de manera controlada hacia la frente, manteniendo el brazo superior quieto. Haz una breve pausa en la parte inferior del movimiento, luego extiende el brazo de vue', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'triceps', '{"shoulders"}', 'Túmbate boca arriba en un banco con una mancuerna en una mano y el brazo completamente extendido por encima del pecho. Baja la mancuerna de manera controlada hacia la frente, manteniendo el brazo superior quieto. Haz una breve pausa en la parte inferior del movimiento, luego extiende el brazo de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia de brazo.', 'Lie flat on a bench with a dumbbell in one hand and your arm fully extended above your chest. Lower the dumbbell in a controlled manner towards your forehead, keeping your upper arm stationary. Pause briefly at the bottom of the movement, then extend your arm back to the starting position. Repeat for the desired number of repetitions, then switch arms.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1735-6MfS53i.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1735-6MfS53i.gif', '6MfS53i', '© Gym visual — https://gymvisual.com/'),
('0349', 'dumbbell lying supination', 'Túmbate boca arriba en un banco con los pies planos sobre el suelo. Sostén una mancuerna en cada mano con las palmas hacia arriba y los brazos completamente extendidos. Manteniendo los brazos superiores quietos, flexiona las mancuernas hacia los hombros contrayendo los antebrazos. Haz una pausa brev', 'lower arms', 'dumbbell', 'lower arms', 'lower arms', 'forearms', '{"biceps","shoulders"}', 'Túmbate boca arriba en un banco con los pies planos sobre el suelo. Sostén una mancuerna en cada mano con las palmas hacia arriba y los brazos completamente extendidos. Manteniendo los brazos superiores quietos, flexiona las mancuernas hacia los hombros contrayendo los antebrazos. Haz una pausa breve en la parte alta, luego baja lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on a bench with your feet flat on the ground. Hold a dumbbell in each hand with your palms facing up and your arms fully extended. Keeping your upper arms stationary, curl the dumbbells towards your shoulders by contracting your forearms. Pause for a moment at the top, then slowly lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0349-M2Pm3zj.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0349-M2Pm3zj.gif', 'M2Pm3zj', '© Gym visual — https://gymvisual.com/'),
('2706', 'dumbbell lying supination on floor', 'Túmbate boca arriba en el suelo con las piernas extendidas y los brazos a los costados, sosteniendo una mancuerna en cada mano. Gira las palmas hacia arriba, manteniendo los codos cerca de los costados. Flexiona lentamente las mancuernas hacia los hombros, contrayendo los antebrazos. Haz una pausa b', 'lower arms', 'dumbbell', 'lower arms', 'lower arms', 'forearms', '{"biceps","shoulders"}', 'Túmbate boca arriba en el suelo con las piernas extendidas y los brazos a los costados, sosteniendo una mancuerna en cada mano. Gira las palmas hacia arriba, manteniendo los codos cerca de los costados. Flexiona lentamente las mancuernas hacia los hombros, contrayendo los antebrazos. Haz una pausa breve en la parte alta, luego baja lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on your back on the floor with your legs extended and your arms by your sides, holding a dumbbell in each hand. Rotate your palms to face up, keeping your elbows close to your sides. Slowly curl the dumbbells towards your shoulders, squeezing your forearms. Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2706-rEhi2o5.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2706-rEhi2o5.gif', 'rEhi2o5', '© Gym visual — https://gymvisual.com/'),
('1661', 'dumbbell lying supine biceps curl', 'Túmbate boca arriba en un banco con la espalda y la cabeza apoyadas, y los pies planos sobre el suelo. Sostén una mancuerna en cada mano con las palmas hacia arriba y los brazos completamente extendidos. Manteniendo los brazos superiores fijos, exhala y levanta el peso mientras contraes los bíceps. ', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Túmbate boca arriba en un banco con la espalda y la cabeza apoyadas, y los pies planos sobre el suelo. Sostén una mancuerna en cada mano con las palmas hacia arriba y los brazos completamente extendidos. Manteniendo los brazos superiores fijos, exhala y levanta el peso mientras contraes los bíceps. Continúa levantando las pesas hasta que los bíceps estén completamente contraídos y las mancuernas estén a la altura de los hombros. Mantén la posición contraída durante una breve pausa mientras aprietas los bíceps. Inhala y comienza a bajar lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on a bench with your back and head supported, and your feet flat on the ground. Hold a dumbbell in each hand with your palms facing up and your arms fully extended. Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly begin to lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1661-XVzF3iZ.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1661-XVzF3iZ.gif', 'XVzF3iZ', '© Gym visual — https://gymvisual.com/'),
('0350', 'dumbbell lying supine curl', 'Túmbate boca arriba en un banco con una mancuerna en cada mano, con las palmas hacia arriba y los brazos completamente extendidos. Manteniendo los brazos superiores fijos, exhala y levanta el peso mientras contraes los bíceps. Continúa levantando las mancuernas hasta que los bíceps estén completamen', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Túmbate boca arriba en un banco con una mancuerna en cada mano, con las palmas hacia arriba y los brazos completamente extendidos. Manteniendo los brazos superiores fijos, exhala y levanta el peso mientras contraes los bíceps. Continúa levantando las mancuernas hasta que los bíceps estén completamente contraídos y las mancuernas estén a la altura de los hombros. Mantén la posición contraída durante una breve pausa mientras aprietas los bíceps. Inhala y comienza a bajar lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on a bench with a dumbbell in each hand, palms facing up and arms fully extended. Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly begin to lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0350-KUaZst7.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0350-KUaZst7.gif', 'KUaZst7', '© Gym visual — https://gymvisual.com/'),
('0351', 'dumbbell lying triceps extension', 'Túmbate boca arriba en un banco con una mancuerna en cada mano, con las palmas enfrentadas entre sí. Extiende los brazos rectos hacia arriba sobre el pecho, manteniendo los codos cerca del cuerpo. Baja las mancuernas hacia la frente, flexionando los codos. Haz una pausa breve y luego extiende los br', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'triceps', '{"shoulders"}', 'Túmbate boca arriba en un banco con una mancuerna en cada mano, con las palmas enfrentadas entre sí. Extiende los brazos rectos hacia arriba sobre el pecho, manteniendo los codos cerca del cuerpo. Baja las mancuernas hacia la frente, flexionando los codos. Haz una pausa breve y luego extiende los brazos de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on a bench with a dumbbell in each hand, palms facing each other. Extend your arms straight up over your chest, keeping your elbows close to your body. Lower the dumbbells down towards your forehead, bending your elbows. Pause for a moment, then extend your arms back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0351-mpKZGWz.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0351-mpKZGWz.gif', 'mpKZGWz', '© Gym visual — https://gymvisual.com/'),
('1662', 'dumbbell lying wide curl', 'Túmbate boca arriba en un banco con una mancuerna en cada mano, con las palmas hacia arriba y los brazos completamente extendidos. Manteniendo los brazos superiores fijos, exhala y levanta el peso mientras contraes los bíceps. Continúa levantando las pesas hasta que los bíceps estén completamente co', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Túmbate boca arriba en un banco con una mancuerna en cada mano, con las palmas hacia arriba y los brazos completamente extendidos. Manteniendo los brazos superiores fijos, exhala y levanta el peso mientras contraes los bíceps. Continúa levantando las pesas hasta que los bíceps estén completamente contraídos y las mancuernas estén a la altura de los hombros. Mantén la posición contraída durante una breve pausa mientras aprietas los bíceps. Inhala y comienza a bajar lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on a bench with a dumbbell in each hand, palms facing up and arms fully extended. Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly begin to lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1662-qm9veZw.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1662-qm9veZw.gif', 'qm9veZw', '© Gym visual — https://gymvisual.com/'),
('0352', 'dumbbell neutral grip bench press', 'Túmbate sobre un banco con los pies apoyados en el suelo y la espalda presionada contra el banco. Sostén una mancuerna en cada mano con agarre neutro (palmas enfrentadas entre sí) y los brazos extendidos rectos hacia arriba sobre el pecho. Baja lentamente las mancuernas hacia el pecho, manteniendo l', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'triceps', '{"chest","shoulders"}', 'Túmbate sobre un banco con los pies apoyados en el suelo y la espalda presionada contra el banco. Sostén una mancuerna en cada mano con agarre neutro (palmas enfrentadas entre sí) y los brazos extendidos rectos hacia arriba sobre el pecho. Baja lentamente las mancuernas hacia el pecho, manteniendo los codos cerca del cuerpo. Haz una pausa por un momento en la parte inferior, luego empuja las mancuernas de nuevo hacia arriba hasta la posición inicial, extendiendo completamente los brazos. Repite el número de repeticiones deseado.', 'Lie flat on a bench with your feet flat on the ground and your back pressed against the bench. Hold a dumbbell in each hand with a neutral grip (palms facing each other) and your arms extended straight up over your chest. Slowly lower the dumbbells down towards your chest, keeping your elbows close to your body. Pause for a moment at the bottom, then push the dumbbells back up to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0352-pP8wP2P.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0352-pP8wP2P.gif', 'pP8wP2P', '© Gym visual — https://gymvisual.com/'),
('1285', 'dumbbell one arm bench fly', 'Siéntate en un banco plano con una mancuerna en una mano, apoyándola sobre el muslo. Recuéstate en el banco, manteniendo la mancuerna presionada contra el muslo. Usando la mano libre, ayuda a levantar la mancuerna hasta la posición inicial. Sostén la mancuerna directamente sobre el hombro con el bra', 'chest', 'dumbbell', 'chest', 'chest', 'pectorals', '{"shoulders"}', 'Siéntate en un banco plano con una mancuerna en una mano, apoyándola sobre el muslo. Recuéstate en el banco, manteniendo la mancuerna presionada contra el muslo. Usando la mano libre, ayuda a levantar la mancuerna hasta la posición inicial. Sostén la mancuerna directamente sobre el hombro con el brazo extendido y la palma hacia adentro. Baja la mancuerna hacia el lado describiendo un amplio arco, manteniendo una ligera flexión en el codo. Haz una pausa cuando el brazo esté paralelo al suelo, luego invierte el movimiento y lleva la mancuerna de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia de brazo y repite.', 'Sit on a flat bench with a dumbbell in one hand, resting it on top of your thigh. Lie back on the bench, keeping the dumbbell pressed against your thigh. Using your free hand, help lift the dumbbell up to the starting position. Hold the dumbbell directly above your shoulder with your arm extended and palm facing inward. Lower the dumbbell out to the side in a wide arc, keeping a slight bend in your elbow. Pause when your arm is parallel to the ground, then reverse the movement and bring the dumbbell back to the starting position. Repeat for the desired number of repetitions, then switch arms and repeat.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1285-o5Jsk92.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1285-o5Jsk92.gif', 'o5Jsk92', '© Gym visual — https://gymvisual.com/'),
('0292', 'dumbbell one arm bent-over row', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo una mancuerna en una mano con la palma hacia el cuerpo. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta y el core activado. Deja que la mancuerna cuelgue recta hac', 'back', 'dumbbell', 'back', 'back', 'upper back', '{"biceps","forearms"}', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo una mancuerna en una mano con la palma hacia el cuerpo. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta y el core activado. Deja que la mancuerna cuelgue recta hacia el suelo, con el brazo completamente extendido. Tira de la mancuerna hacia el pecho, manteniendo el codo cerca del cuerpo y juntando los omóplatos. Haz una pausa breve en la parte más alta, luego baja lentamente la mancuerna de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia de lado.', 'Stand with your feet shoulder-width apart, holding a dumbbell in one hand with your palm facing your body. Bend your knees slightly and hinge forward at the hips, keeping your back straight and your core engaged. Let the dumbbell hang straight down towards the floor, with your arm fully extended. Pull the dumbbell up towards your chest, keeping your elbow close to your body and squeezing your shoulder blades together. Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position. Repeat for the desired number of repetitions, then switch sides.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0292-C0MA9bC.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0292-C0MA9bC.gif', 'C0MA9bC', '© Gym visual — https://gymvisual.com/'),
('1286', 'dumbbell one arm chest fly on exercise ball', 'Siéntate sobre un balón de estabilidad con una mancuerna en una mano y los pies apoyados en el suelo. Camina con los pies hacia adelante, haciendo rodar el balón hasta que la parte superior de la espalda quede apoyada en el balón y la cabeza, el cuello y los hombros queden fuera de él. Extiende el b', 'chest', 'dumbbell', 'chest', 'chest', 'pectorals', '{"shoulders","triceps"}', 'Siéntate sobre un balón de estabilidad con una mancuerna en una mano y los pies apoyados en el suelo. Camina con los pies hacia adelante, haciendo rodar el balón hasta que la parte superior de la espalda quede apoyada en el balón y la cabeza, el cuello y los hombros queden fuera de él. Extiende el brazo con la mancuerna recto hacia arriba sobre el pecho, con la palma hacia adentro. Baja lentamente la mancuerna hacia el lado, manteniendo una ligera flexión en el codo. Haz una pausa por un momento cuando el brazo esté paralelo al suelo. Activa los músculos del pecho para llevar la mancuerna de nuevo hacia arriba hasta la posición inicial. Repite el número de repeticiones deseado, luego cambia de brazo.', 'Sit on an exercise ball with a dumbbell in one hand and your feet flat on the ground. Walk your feet forward, rolling the ball until your upper back is supported on the ball and your head, neck, and shoulders are off the ball. Extend your arm with the dumbbell straight up above your chest, palm facing inward. Slowly lower the dumbbell out to the side, keeping a slight bend in your elbow. Pause for a moment when your arm is parallel to the ground. Engage your chest muscles to bring the dumbbell back up to the starting position. Repeat for the desired number of repetitions, then switch arms.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1286-Bpkf41o.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1286-Bpkf41o.gif', 'Bpkf41o', '© Gym visual — https://gymvisual.com/'),
('0353', 'dumbbell one arm concentration curl (on stability ball)', 'Siéntate sobre un balón de estabilidad con los pies apoyados planos en el suelo y las rodillas flexionadas en un ángulo de 90 grados. Sostén una mancuerna en una mano con la palma hacia arriba y el brazo extendido hacia el suelo. Apoya el codo en la parte interna del muslo, justo por encima de la ro', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Siéntate sobre un balón de estabilidad con los pies apoyados planos en el suelo y las rodillas flexionadas en un ángulo de 90 grados. Sostén una mancuerna en una mano con la palma hacia arriba y el brazo extendido hacia el suelo. Apoya el codo en la parte interna del muslo, justo por encima de la rodilla. Manteniendo el brazo superior quieto, exhala y flexiona la mancuerna hacia el hombro contrayendo el bíceps. Haz una pausa por un momento en la parte superior del movimiento, luego inhala y baja lentamente la mancuerna de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia de brazo y repite.', 'Sit on a stability ball with your feet flat on the ground and your knees bent at a 90-degree angle. Hold a dumbbell in one hand with your palm facing up and your arm extended down towards the floor. Rest your elbow on the inside of your thigh, just above the knee. Keeping your upper arm stationary, exhale and curl the dumbbell up towards your shoulder while contracting your biceps. Pause for a moment at the top of the movement, then inhale and slowly lower the dumbbell back down to the starting position. Repeat for the desired number of repetitions, then switch arms and repeat.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0353-k5IpyHg.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0353-k5IpyHg.gif', 'k5IpyHg', '© Gym visual — https://gymvisual.com/'),
('1287', 'dumbbell one arm decline chest press', 'Túmbate en un banco declinado con una mancuerna en una mano, apoyada sobre el pecho. Coloca los pies planos sobre el suelo y mantén la espalda presionada contra el banco. Extiende el brazo y empuja la mancuerna hacia el techo, extendiendo completamente el codo. Haz una pausa breve en la parte más al', 'chest', 'dumbbell', 'chest', 'chest', 'pectorals', '{"triceps","shoulders"}', 'Túmbate en un banco declinado con una mancuerna en una mano, apoyada sobre el pecho. Coloca los pies planos sobre el suelo y mantén la espalda presionada contra el banco. Extiende el brazo y empuja la mancuerna hacia el techo, extendiendo completamente el codo. Haz una pausa breve en la parte más alta, luego baja lentamente la mancuerna de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia al otro brazo.', 'Lie on a decline bench with a dumbbell in one hand, resting on your chest. Place your feet flat on the ground and keep your back pressed against the bench. Extend your arm and push the dumbbell up towards the ceiling, fully extending your elbow. Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position. Repeat for the desired number of repetitions, then switch to the other arm.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1287-REGM1dE.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1287-REGM1dE.gif', 'REGM1dE', '© Gym visual — https://gymvisual.com/'),
('1288', 'dumbbell one arm fly on exercise ball', 'Siéntate sobre un balón de estabilidad con una mancuerna en una mano y los pies apoyados en el suelo. Camina con los pies hacia adelante y baja el cuerpo rodando hasta que la parte superior de la espalda quede apoyada sobre el balón de estabilidad. Extiende el brazo con la mancuerna recto hacia arri', 'chest', 'dumbbell', 'chest', 'chest', 'pectorals', '{"shoulders","triceps"}', 'Siéntate sobre un balón de estabilidad con una mancuerna en una mano y los pies apoyados en el suelo. Camina con los pies hacia adelante y baja el cuerpo rodando hasta que la parte superior de la espalda quede apoyada sobre el balón de estabilidad. Extiende el brazo con la mancuerna recto hacia arriba sobre el pecho, con la palma hacia adentro. Baja lentamente la mancuerna hacia el lado, manteniendo una ligera flexión en el codo. Haz una pausa por un momento, luego contrae los músculos del pecho para llevar la mancuerna de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia de brazo.', 'Sit on an exercise ball with a dumbbell in one hand and your feet flat on the ground. Walk your feet forward and roll your body down until your upper back is resting on the exercise ball. Extend your arm with the dumbbell straight up above your chest, palm facing inwards. Slowly lower the dumbbell out to the side, keeping a slight bend in your elbow. Pause for a moment, then squeeze your chest muscles to bring the dumbbell back to the starting position. Repeat for the desired number of repetitions, then switch arms.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1288-Am02iPd.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1288-Am02iPd.gif', 'Am02iPd', '© Gym visual — https://gymvisual.com/'),
('1736', 'dumbbell one arm french press on exercise ball', 'Siéntate sobre un balón de ejercicio con los pies apoyados planos en el suelo y la espalda recta. Sostén una mancuerna en una mano con la palma hacia arriba y el codo flexionado en un ángulo de 90 grados. Extiende el brazo recto hacia el techo, manteniendo el codo quieto. Baja lentamente la mancuern', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'triceps', '{"shoulders"}', 'Siéntate sobre un balón de ejercicio con los pies apoyados planos en el suelo y la espalda recta. Sostén una mancuerna en una mano con la palma hacia arriba y el codo flexionado en un ángulo de 90 grados. Extiende el brazo recto hacia el techo, manteniendo el codo quieto. Baja lentamente la mancuerna de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia de brazo.', 'Sit on an exercise ball with your feet flat on the ground and your back straight. Hold a dumbbell in one hand with your palm facing up and your elbow bent at a 90-degree angle. Extend your arm straight up towards the ceiling, keeping your elbow stationary. Slowly lower the dumbbell back down to the starting position. Repeat for the desired number of repetitions, then switch arms.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1736-ziFKQXP.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1736-ziFKQXP.gif', 'ziFKQXP', '© Gym visual — https://gymvisual.com/'),
('1663', 'dumbbell one arm hammer preacher curl', 'Siéntate en un banco scott con una mancuerna en una mano y el brazo superior apoyado sobre la almohadilla. Sostén la mancuerna con agarre neutro (palmas hacia el cuerpo). Manteniendo el brazo superior quieto, exhala y flexiona la mancuerna hacia el hombro. Haz una pausa breve en la parte alta, apret', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Siéntate en un banco scott con una mancuerna en una mano y el brazo superior apoyado sobre la almohadilla. Sostén la mancuerna con agarre neutro (palmas hacia el cuerpo). Manteniendo el brazo superior quieto, exhala y flexiona la mancuerna hacia el hombro. Haz una pausa breve en la parte alta, apretando los bíceps. Inhala y baja lentamente la mancuerna de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia de brazo.', 'Sit on a preacher bench with a dumbbell in one hand and your upper arm resting on the pad. Hold the dumbbell with a neutral grip (palms facing your body). Keeping your upper arm stationary, exhale and curl the dumbbell up towards your shoulder. Pause for a moment at the top, squeezing your biceps. Inhale and slowly lower the dumbbell back to the starting position. Repeat for the desired number of repetitions, then switch arms.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1663-4dF3maG.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1663-4dF3maG.gif', '4dF3maG', '© Gym visual — https://gymvisual.com/'),
('1621', 'dumbbell one arm hammer press on exercise ball', 'Siéntate sobre un balón de ejercicio con los pies apoyados planos en el suelo y la espalda recta. Sostén una mancuerna en una mano con la palma hacia adentro y el codo flexionado en un ángulo de 90 grados. Coloca la otra mano en la cadera para mantener el equilibrio. Empuja la mancuerna hacia arriba', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'triceps', '{"shoulders","chest"}', 'Siéntate sobre un balón de ejercicio con los pies apoyados planos en el suelo y la espalda recta. Sostén una mancuerna en una mano con la palma hacia adentro y el codo flexionado en un ángulo de 90 grados. Coloca la otra mano en la cadera para mantener el equilibrio. Empuja la mancuerna hacia arriba, extendiendo completamente el brazo. Haz una pausa breve en la parte más alta, luego baja lentamente la mancuerna de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia de brazo.', 'Sit on an exercise ball with your feet flat on the ground and your back straight. Hold a dumbbell in one hand with your palm facing inwards and your elbow bent at a 90-degree angle. Place your other hand on your hip for stability. Press the dumbbell upwards, extending your arm fully. Pause for a moment at the top, then slowly lower the dumbbell back to the starting position. Repeat for the desired number of repetitions, then switch arms.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1621-VYmYxK5.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1621-VYmYxK5.gif', 'VYmYxK5', '© Gym visual — https://gymvisual.com/'),
('1289', 'dumbbell one arm incline chest press', 'Ajusta el banco inclinado a un ángulo de 45 grados. Siéntate en el banco con la espalda apoyada en el respaldo y los pies planos sobre el suelo. Sostén una mancuerna en una mano con agarre prono, apoyándola sobre el hombro. Empuja la mancuerna hacia arriba y alejándola del cuerpo, extendiendo comple', 'chest', 'dumbbell', 'chest', 'chest', 'pectorals', '{"shoulders","triceps"}', 'Ajusta el banco inclinado a un ángulo de 45 grados. Siéntate en el banco con la espalda apoyada en el respaldo y los pies planos sobre el suelo. Sostén una mancuerna en una mano con agarre prono, apoyándola sobre el hombro. Empuja la mancuerna hacia arriba y alejándola del cuerpo, extendiendo completamente el brazo. Haz una pausa breve en la parte más alta, luego baja lentamente la mancuerna de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia al otro brazo.', 'Adjust the incline bench to a 45-degree angle. Sit on the bench with your back against the pad and feet flat on the ground. Hold a dumbbell in one hand with an overhand grip, resting it on your shoulder. Push the dumbbell up and away from your body, extending your arm fully. Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position. Repeat for the desired number of repetitions, then switch to the other arm.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1289-PDaMuyV.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1289-PDaMuyV.gif', 'PDaMuyV', '© Gym visual — https://gymvisual.com/'),
('0354', 'dumbbell one arm kickback', 'Ponte de pie con los pies separados a la altura de los hombros y sostén una mancuerna en la mano derecha. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta. Lleva el codo derecho hacia el costado, manteniéndolo flexionado en un ángulo de 90 ', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'triceps', '{"shoulders"}', 'Ponte de pie con los pies separados a la altura de los hombros y sostén una mancuerna en la mano derecha. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta. Lleva el codo derecho hacia el costado, manteniéndolo flexionado en un ángulo de 90 grados. Extiende el brazo derecho recto hacia atrás, contrayendo el tríceps en la parte superior del movimiento. Baja lentamente la mancuerna de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia de lado.', 'Stand with your feet shoulder-width apart and hold a dumbbell in your right hand. Bend your knees slightly and hinge forward at the hips, keeping your back straight. Bring your right elbow up to your side, keeping it bent at a 90-degree angle. Extend your right arm straight back, squeezing your triceps at the top of the movement. Slowly lower the dumbbell back to the starting position. Repeat for the desired number of repetitions, then switch sides.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0354-bQy2Eni.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0354-bQy2Eni.gif', 'bQy2Eni', '© Gym visual — https://gymvisual.com/'),
('0355', 'dumbbell one arm lateral raise', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo una mancuerna en una mano con la palma hacia el cuerpo. Mantén la espalda recta y el core activado durante todo el ejercicio. Levanta la mancuerna hacia el lado, manteniendo el brazo recto y la palma hacia abajo. Continúa le', 'shoulders', 'dumbbell', 'shoulders', 'shoulders', 'delts', '{"trapezius","triceps"}', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo una mancuerna en una mano con la palma hacia el cuerpo. Mantén la espalda recta y el core activado durante todo el ejercicio. Levanta la mancuerna hacia el lado, manteniendo el brazo recto y la palma hacia abajo. Continúa levantando hasta que el brazo quede paralelo al suelo. Haz una pausa breve en la parte más alta, luego baja lentamente la mancuerna de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia al otro brazo.', 'Stand with your feet shoulder-width apart, holding a dumbbell in one hand with your palm facing your body. Keep your back straight and your core engaged throughout the exercise. Raise the dumbbell to the side, keeping your arm straight and your palm facing down. Continue lifting until your arm is parallel to the ground. Pause for a moment at the top, then slowly lower the dumbbell back to the starting position. Repeat for the desired number of repetitions, then switch to the other arm.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0355-n5cWCsI.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0355-n5cWCsI.gif', 'n5cWCsI', '© Gym visual — https://gymvisual.com/'),
('0356', 'dumbbell one arm lateral raise with support', 'Ponte de pie con los pies separados a la altura de los hombros y sostén una mancuerna en una mano, con la palma hacia el cuerpo. Coloca la otra mano sobre una superficie estable, como un banco o una pared, para apoyarte. Mantén la espalda recta y activa el core. Levanta la mancuerna hacia el lado, m', 'shoulders', 'dumbbell', 'shoulders', 'shoulders', 'delts', '{"trapezius","rotator cuff"}', 'Ponte de pie con los pies separados a la altura de los hombros y sostén una mancuerna en una mano, con la palma hacia el cuerpo. Coloca la otra mano sobre una superficie estable, como un banco o una pared, para apoyarte. Mantén la espalda recta y activa el core. Levanta la mancuerna hacia el lado, manteniendo el brazo recto y la palma hacia abajo. Continúa levantando hasta que el brazo quede paralelo al suelo. Haz una pausa breve en la parte más alta, luego baja lentamente la mancuerna de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia de lado.', 'Stand with your feet shoulder-width apart and hold a dumbbell in one hand, with your palm facing your body. Place your other hand on a stable surface, such as a bench or wall, for support. Keep your back straight and engage your core. Raise the dumbbell out to the side, keeping your arm straight and your palm facing down. Continue lifting until your arm is parallel to the ground. Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position. Repeat for the desired number of repetitions, then switch sides.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0356-Yg7MJAT.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0356-Yg7MJAT.gif', 'Yg7MJAT', '© Gym visual — https://gymvisual.com/'),
('1290', 'dumbbell one arm press on exercise ball', 'Siéntate sobre un balón de estabilidad con los pies apoyados en el suelo y las rodillas flexionadas en un ángulo de 90 grados. Sostén una mancuerna en una mano y colócala a la altura del hombro, con el codo flexionado y la palma hacia adelante. Empuja lentamente la mancuerna hacia arriba hasta que e', 'chest', 'dumbbell', 'chest', 'chest', 'pectorals', '{"shoulders","triceps","core"}', 'Siéntate sobre un balón de estabilidad con los pies apoyados en el suelo y las rodillas flexionadas en un ángulo de 90 grados. Sostén una mancuerna en una mano y colócala a la altura del hombro, con el codo flexionado y la palma hacia adelante. Empuja lentamente la mancuerna hacia arriba hasta que el brazo quede completamente extendido, manteniendo el core activado y el equilibrio sobre el balón de estabilidad. Haz una pausa breve en la parte más alta, luego baja lentamente la mancuerna de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia al otro brazo.', 'Sit on an exercise ball with your feet flat on the ground and your knees bent at a 90-degree angle. Hold a dumbbell in one hand and position it at shoulder height, with your elbow bent and palm facing forward. Slowly press the dumbbell upward until your arm is fully extended, while keeping your core engaged and maintaining balance on the exercise ball. Pause for a moment at the top, then slowly lower the dumbbell back to the starting position. Repeat for the desired number of repetitions, then switch to the other arm.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1290-QZFv5ui.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1290-QZFv5ui.gif', 'QZFv5ui', '© Gym visual — https://gymvisual.com/'),
('1665', 'dumbbell one arm prone curl', 'Túmbate boca abajo en un banco plano con una mancuerna en una mano, con la palma hacia abajo. Extiende completamente el brazo, dejando que cuelgue recto hacia el suelo. Manteniendo el brazo superior quieto, flexiona la mancuerna hacia el hombro contrayendo el bíceps. Haz una pausa breve en la parte ', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Túmbate boca abajo en un banco plano con una mancuerna en una mano, con la palma hacia abajo. Extiende completamente el brazo, dejando que cuelgue recto hacia el suelo. Manteniendo el brazo superior quieto, flexiona la mancuerna hacia el hombro contrayendo el bíceps. Haz una pausa breve en la parte más alta, luego baja lentamente la mancuerna de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia de brazo.', 'Lie face down on a flat bench with a dumbbell in one hand, palm facing down. Extend your arm fully, letting it hang straight down towards the floor. Keeping your upper arm stationary, curl the dumbbell up towards your shoulder by contracting your biceps. Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position. Repeat for the desired number of repetitions, then switch arms.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1665-JWjujiY.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1665-JWjujiY.gif', 'JWjujiY', '© Gym visual — https://gymvisual.com/'),
('1666', 'dumbbell one arm prone hammer curl', 'Túmbate boca abajo en un banco plano con una mancuerna en una mano, con la palma hacia el cuerpo y el brazo completamente extendido. Mantén el brazo superior quieto y flexiona la mancuerna hacia el hombro, contrayendo el bíceps. Haz una pausa breve en la parte más alta, luego baja lentamente la manc', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Túmbate boca abajo en un banco plano con una mancuerna en una mano, con la palma hacia el cuerpo y el brazo completamente extendido. Mantén el brazo superior quieto y flexiona la mancuerna hacia el hombro, contrayendo el bíceps. Haz una pausa breve en la parte más alta, luego baja lentamente la mancuerna de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia de brazo.', 'Lie face down on a flat bench with a dumbbell in one hand, palm facing your body and arm fully extended. Keep your upper arm stationary and curl the dumbbell towards your shoulder, contracting your biceps. Pause for a moment at the top, then slowly lower the dumbbell back to the starting position. Repeat for the desired number of repetitions, then switch arms.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1666-LIGZSTA.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1666-LIGZSTA.gif', 'LIGZSTA', '© Gym visual — https://gymvisual.com/'),
('1291', 'dumbbell one arm pullover on exercise ball', 'Siéntate sobre un balón de estabilidad con los pies apoyados en el suelo y las rodillas flexionadas en un ángulo de 90 grados. Sostén una mancuerna con una mano y extiende el brazo recto hacia arriba sobre el pecho. Baja lentamente la mancuerna detrás de la cabeza manteniendo el brazo recto. Haz una', 'chest', 'dumbbell', 'chest', 'chest', 'pectorals', '{"triceps","latissimus dorsi","rhomboids"}', 'Siéntate sobre un balón de estabilidad con los pies apoyados en el suelo y las rodillas flexionadas en un ángulo de 90 grados. Sostén una mancuerna con una mano y extiende el brazo recto hacia arriba sobre el pecho. Baja lentamente la mancuerna detrás de la cabeza manteniendo el brazo recto. Haz una pausa por un momento, luego levanta la mancuerna de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia de brazo.', 'Sit on an exercise ball with your feet flat on the ground and your knees bent at a 90-degree angle. Hold a dumbbell with one hand and extend your arm straight up above your chest. Slowly lower the dumbbell behind your head while keeping your arm straight. Pause for a moment, then raise the dumbbell back to the starting position. Repeat for the desired number of repetitions, then switch arms.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1291-bQHPBU3.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1291-bQHPBU3.gif', 'bQHPBU3', '© Gym visual — https://gymvisual.com/'),
('0358', 'dumbbell one arm reverse wrist curl', 'Siéntate en un banco o silla con los pies apoyados en el suelo. Sostén una mancuerna en una mano con agarre prono, con la palma hacia abajo. Apoya el antebrazo sobre el muslo, con la muñeca colgando fuera del borde. Baja lentamente la mancuerna hacia el suelo flexionando la muñeca. Haz una pausa por', 'lower arms', 'dumbbell', 'lower arms', 'lower arms', 'forearms', '{"wrist extensors"}', 'Siéntate en un banco o silla con los pies apoyados en el suelo. Sostén una mancuerna en una mano con agarre prono, con la palma hacia abajo. Apoya el antebrazo sobre el muslo, con la muñeca colgando fuera del borde. Baja lentamente la mancuerna hacia el suelo flexionando la muñeca. Haz una pausa por un momento en la parte inferior, luego flexiona lentamente la muñeca de vuelta hacia el cuerpo. Repite el número de repeticiones deseado, luego cambia al otro brazo.', 'Sit on a bench or chair with your feet flat on the ground. Hold a dumbbell in one hand with an overhand grip, palm facing down. Rest your forearm on your thigh, with your wrist hanging off the edge. Slowly lower the dumbbell towards the ground by flexing your wrist. Pause for a moment at the bottom, then slowly curl your wrist back up towards your body. Repeat for the desired number of repetitions, then switch to the other arm.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0358-BwSNDGt.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0358-BwSNDGt.gif', 'BwSNDGt', '© Gym visual — https://gymvisual.com/'),
('0359', 'dumbbell one arm reverse fly (with support)', 'Siéntate en un banco con los pies apoyados planos en el suelo y la espalda recta. Sostén una mancuerna en una mano con la palma hacia adentro. Inclínate hacia adelante y coloca la mano libre sobre el banco para apoyarte. Mantén el brazo ligeramente flexionado y levántalo hacia el lado hasta que qued', 'shoulders', 'dumbbell', 'shoulders', 'shoulders', 'delts', '{"trapezius","rhomboids"}', 'Siéntate en un banco con los pies apoyados planos en el suelo y la espalda recta. Sostén una mancuerna en una mano con la palma hacia adentro. Inclínate hacia adelante y coloca la mano libre sobre el banco para apoyarte. Mantén el brazo ligeramente flexionado y levántalo hacia el lado hasta que quede paralelo al suelo. Haz una pausa breve en la parte más alta, luego baja lentamente el brazo de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia de brazo.', 'Sit on a bench with your feet flat on the ground and your back straight. Hold a dumbbell in one hand with your palm facing inwards. Lean forward and place your free hand on the bench for support. Keep your arm slightly bent and raise it out to the side until it is parallel to the ground. Pause for a moment at the top, then slowly lower your arm back down to the starting position. Repeat for the desired number of repetitions, then switch arms.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0359-e25F58f.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0359-e25F58f.gif', 'e25F58f', '© Gym visual — https://gymvisual.com/'),
('1622', 'dumbbell one arm reverse grip press', 'Siéntate en un banco plano con una mancuerna en una mano, con la palma hacia el cuerpo. Coloca los pies planos sobre el suelo y mantén la espalda recta. Levanta la mancuerna hasta la altura del hombro, manteniendo el codo cerca del cuerpo. Empuja la mancuerna hacia arriba hasta que el brazo quede co', 'chest', 'dumbbell', 'chest', 'chest', 'pectorals', '{"triceps","shoulders"}', 'Siéntate en un banco plano con una mancuerna en una mano, con la palma hacia el cuerpo. Coloca los pies planos sobre el suelo y mantén la espalda recta. Levanta la mancuerna hasta la altura del hombro, manteniendo el codo cerca del cuerpo. Empuja la mancuerna hacia arriba hasta que el brazo quede completamente extendido. Haz una pausa breve en la parte más alta, luego baja lentamente la mancuerna de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia al otro brazo.', 'Sit on a flat bench with a dumbbell in one hand, palm facing towards your body. Place your feet flat on the ground and keep your back straight. Raise the dumbbell to shoulder height, keeping your elbow close to your body. Press the dumbbell upwards until your arm is fully extended. Pause for a moment at the top, then slowly lower the dumbbell back to the starting position. Repeat for the desired number of repetitions, then switch to the other arm.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1622-Ze7MoIb.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1622-Ze7MoIb.gif', 'Ze7MoIb', '© Gym visual — https://gymvisual.com/'),
('1414', 'dumbbell one arm reverse preacher curl', 'Siéntate en un banco scott con el pecho contra la almohadilla y el brazo extendido sobre el borde del banco, sosteniendo una mancuerna con agarre supino. Baja lentamente la mancuerna hasta que el brazo quede completamente extendido. Flexiona la mancuerna de nuevo hacia el hombro, manteniendo el braz', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Siéntate en un banco scott con el pecho contra la almohadilla y el brazo extendido sobre el borde del banco, sosteniendo una mancuerna con agarre supino. Baja lentamente la mancuerna hasta que el brazo quede completamente extendido. Flexiona la mancuerna de nuevo hacia el hombro, manteniendo el brazo superior quieto. Contrae el bíceps en la parte más alta del movimiento, luego baja lentamente la mancuerna de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia de brazo.', 'Sit on a preacher bench with your chest against the pad and your arm extended over the edge of the bench, holding a dumbbell with an underhand grip. Lower the dumbbell slowly until your arm is fully extended. Curl the dumbbell back up towards your shoulder, keeping your upper arm stationary. Squeeze your biceps at the top of the movement, then slowly lower the dumbbell back down to the starting position. Repeat for the desired number of repetitions, then switch arms.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1414-bWxq4op.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1414-bWxq4op.gif', 'bWxq4op', '© Gym visual — https://gymvisual.com/'),
('1667', 'dumbbell one arm reverse spider curl', 'Ponte de pie con una mancuerna en una mano, con la palma hacia abajo y el brazo completamente extendido. Manteniendo el brazo superior quieto, flexiona la mancuerna hacia el hombro flexionando el codo. Haz una pausa breve en la parte más alta, luego baja lentamente la mancuerna de vuelta a la posici', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ponte de pie con una mancuerna en una mano, con la palma hacia abajo y el brazo completamente extendido. Manteniendo el brazo superior quieto, flexiona la mancuerna hacia el hombro flexionando el codo. Haz una pausa breve en la parte más alta, luego baja lentamente la mancuerna de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia de brazo.', 'Stand up straight with a dumbbell in one hand, palm facing down and arm fully extended. Keeping your upper arm stationary, curl the dumbbell towards your shoulder by flexing your elbow. Pause for a moment at the top, then slowly lower the dumbbell back to the starting position. Repeat for the desired number of repetitions, then switch arms.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1667-VdLZ3nB.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1667-VdLZ3nB.gif', 'VdLZ3nB', '© Gym visual — https://gymvisual.com/'),
('1668', 'dumbbell one arm seated bicep curl on exercise ball', 'Siéntate sobre un balón de ejercicio con los pies apoyados planos en el suelo y la espalda recta. Sostén una mancuerna en una mano con la palma hacia arriba y el brazo completamente extendido. Manteniendo el brazo superior quieto, flexiona la mancuerna hacia el hombro contrayendo el bíceps. Haz una ', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Siéntate sobre un balón de ejercicio con los pies apoyados planos en el suelo y la espalda recta. Sostén una mancuerna en una mano con la palma hacia arriba y el brazo completamente extendido. Manteniendo el brazo superior quieto, flexiona la mancuerna hacia el hombro contrayendo el bíceps. Haz una pausa breve en la parte más alta, luego baja lentamente la mancuerna de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia de brazo.', 'Sit on an exercise ball with your feet flat on the ground and your back straight. Hold a dumbbell in one hand with your palm facing up and your arm fully extended. Keeping your upper arm stationary, curl the dumbbell towards your shoulder by contracting your biceps. Pause for a moment at the top, then slowly lower the dumbbell back to the starting position. Repeat for the desired number of repetitions, then switch arms.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1668-s999Hdo.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1668-s999Hdo.gif', 's999Hdo', '© Gym visual — https://gymvisual.com/'),
('1669', 'dumbbell one arm seated hammer curl', 'Siéntate en un banco con la espalda recta y los pies planos sobre el suelo. Sostén una mancuerna en una mano con agarre neutro (palmas enfrentadas entre sí). Apoya el codo en la parte interna del muslo, justo por encima de la rodilla. Manteniendo el brazo superior quieto, exhala y flexiona la mancue', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Siéntate en un banco con la espalda recta y los pies planos sobre el suelo. Sostén una mancuerna en una mano con agarre neutro (palmas enfrentadas entre sí). Apoya el codo en la parte interna del muslo, justo por encima de la rodilla. Manteniendo el brazo superior quieto, exhala y flexiona la mancuerna hacia el hombro. Haz una pausa breve en la parte alta, apretando los bíceps. Inhala y baja lentamente la mancuerna de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia de brazo.', 'Sit on a bench with your back straight and feet flat on the ground. Hold a dumbbell in one hand with a neutral grip (palms facing each other). Rest your elbow on the inside of your thigh, just above the knee. Keeping your upper arm stationary, exhale and curl the dumbbell up towards your shoulder. Pause for a moment at the top, squeezing your biceps. Inhale and slowly lower the dumbbell back to the starting position. Repeat for the desired number of repetitions, then switch arms.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1669-jK2hZ6n.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1669-jK2hZ6n.gif', 'jK2hZ6n', '© Gym visual — https://gymvisual.com/'),
('1415', 'dumbbell one arm seated neutral wrist curl', 'Siéntate en un banco con los pies apoyados en el suelo y sostén una mancuerna en una mano, con la palma hacia arriba. Apoya el antebrazo sobre el muslo, dejando que la muñeca cuelgue fuera del borde. Manteniendo el antebrazo quieto, flexiona la muñeca hacia arriba lo más posible. Haz una pausa por u', 'lower arms', 'dumbbell', 'lower arms', 'lower arms', 'forearms', '{"biceps","brachialis"}', 'Siéntate en un banco con los pies apoyados en el suelo y sostén una mancuerna en una mano, con la palma hacia arriba. Apoya el antebrazo sobre el muslo, dejando que la muñeca cuelgue fuera del borde. Manteniendo el antebrazo quieto, flexiona la muñeca hacia arriba lo más posible. Haz una pausa por un momento en la parte superior, luego baja lentamente la muñeca de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia a la otra mano.', 'Sit on a bench with your feet flat on the ground and hold a dumbbell in one hand, palm facing up. Rest your forearm on your thigh, allowing your wrist to hang off the edge. Keeping your forearm stationary, curl your wrist upward as far as possible. Pause for a moment at the top, then slowly lower your wrist back down to the starting position. Repeat for the desired number of repetitions, then switch to the other hand.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1415-YtaCTYl.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1415-YtaCTYl.gif', 'YtaCTYl', '© Gym visual — https://gymvisual.com/'),
('0361', 'dumbbell one arm shoulder press', 'Ponte de pie con los pies separados a la altura de los hombros y sostén una mancuerna en una mano a la altura del hombro, con la palma hacia adelante. Empuja la mancuerna hacia arriba hasta que el brazo quede completamente extendido por encima de la cabeza. Haz una pausa breve en la parte más alta, ', 'shoulders', 'dumbbell', 'shoulders', 'shoulders', 'delts', '{"triceps","upper back"}', 'Ponte de pie con los pies separados a la altura de los hombros y sostén una mancuerna en una mano a la altura del hombro, con la palma hacia adelante. Empuja la mancuerna hacia arriba hasta que el brazo quede completamente extendido por encima de la cabeza. Haz una pausa breve en la parte más alta, luego baja lentamente la mancuerna de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia al otro brazo.', 'Stand with your feet shoulder-width apart and hold a dumbbell in one hand at shoulder level, palm facing forward. Press the dumbbell upward until your arm is fully extended overhead. Pause for a moment at the top, then slowly lower the dumbbell back to the starting position. Repeat for the desired number of repetitions, then switch to the other arm.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0361-84RyJf8.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0361-84RyJf8.gif', '84RyJf8', '© Gym visual — https://gymvisual.com/'),
('0360', 'dumbbell one arm shoulder press v. 2', 'Ponte de pie con los pies separados a la altura de los hombros y sostén una mancuerna en una mano a la altura del hombro, con la palma hacia adelante. Activa el core y empuja la mancuerna directamente hacia arriba por encima de la cabeza, extendiendo completamente el brazo. Haz una pausa por un mome', 'shoulders', 'dumbbell', 'shoulders', 'shoulders', 'delts', '{"triceps","upper back"}', 'Ponte de pie con los pies separados a la altura de los hombros y sostén una mancuerna en una mano a la altura del hombro, con la palma hacia adelante. Activa el core y empuja la mancuerna directamente hacia arriba por encima de la cabeza, extendiendo completamente el brazo. Haz una pausa por un momento en la parte superior, luego baja lentamente la mancuerna de vuelta a la altura del hombro. Repite el número de repeticiones deseado, luego cambia al otro brazo.', 'Stand with your feet shoulder-width apart and hold a dumbbell in one hand at shoulder level, palm facing forward. Engage your core and press the dumbbell straight up overhead, fully extending your arm. Pause for a moment at the top, then slowly lower the dumbbell back to shoulder level. Repeat for the desired number of repetitions, then switch to the other arm.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0360-1TkiAFK.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0360-1TkiAFK.gif', '1TkiAFK', '© Gym visual — https://gymvisual.com/'),
('3888', 'dumbbell one arm snatch', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo una mancuerna en una mano con agarre prono. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta y el pecho elevado. Baja la mancuerna hacia el suelo, manteniéndola cer', 'upper legs', 'dumbbell', 'upper legs', 'upper legs', 'glutes', '{"hamstrings","quadriceps","core"}', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo una mancuerna en una mano con agarre prono. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta y el pecho elevado. Baja la mancuerna hacia el suelo, manteniéndola cerca del cuerpo. Extiende explosivamente las caderas, las rodillas y los tobillos, impulsando la mancuerna hacia arriba en línea recta. Cuando la mancuerna alcance la altura del hombro, gira rápidamente la mano y empújala por encima de la cabeza, extendiendo completamente el brazo. Recibe la mancuerna por encima de la cabeza con una ligera flexión en las rodillas y las caderas. Baja la mancuerna de nuevo a la posición inicial de manera controlada. Repite el número de repeticiones deseado, luego cambia al otro brazo.', 'Stand with your feet shoulder-width apart, holding a dumbbell in one hand with an overhand grip. Bend your knees slightly and hinge forward at the hips, keeping your back straight and chest up. Lower the dumbbell towards the ground, keeping it close to your body. Explosively extend your hips, knees, and ankles, driving the dumbbell upwards in a straight line. As the dumbbell reaches shoulder height, quickly rotate your hand and punch it overhead, fully extending your arm. Catch the dumbbell overhead with a slight bend in your knees and hips. Lower the dumbbell back down to the starting position in a controlled manner. Repeat for the desired number of repetitions, then switch to the other arm.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3888-6pTkI99.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3888-6pTkI99.gif', '6pTkI99', '© Gym visual — https://gymvisual.com/'),
('1670', 'dumbbell one arm standing curl', 'Ponte de pie con una mancuerna en una mano, con la palma hacia adelante y el brazo completamente extendido. Manteniendo el brazo superior quieto, exhala y flexiona el peso hacia arriba contrayendo el bíceps. Continúa levantando la mancuerna hasta que el bíceps esté completamente contraído y la mancu', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ponte de pie con una mancuerna en una mano, con la palma hacia adelante y el brazo completamente extendido. Manteniendo el brazo superior quieto, exhala y flexiona el peso hacia arriba contrayendo el bíceps. Continúa levantando la mancuerna hasta que el bíceps esté completamente contraído y la mancuerna esté a la altura del hombro. Mantén la posición contraída durante una breve pausa mientras aprietas los bíceps. Inhala y baja lentamente la mancuerna de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia de brazo.', 'Stand up straight with a dumbbell in one hand, palm facing forward and arm fully extended. Keeping your upper arm stationary, exhale and curl the weight upward while contracting your biceps. Continue to raise the dumbbell until your biceps are fully contracted and the dumbbell is at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly lower the dumbbell back to the starting position. Repeat for the desired number of repetitions, then switch arms.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1670-ffQsyBj.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1670-ffQsyBj.gif', 'ffQsyBj', '© Gym visual — https://gymvisual.com/'),
('1671', 'dumbbell one arm standing hammer curl', 'Ponte de pie con una mancuerna en cada mano, con las palmas mirando hacia el torso. Mantén los codos cerca del torso y los brazos superiores quietos. Exhala y flexiona las pesas mientras contraes los bíceps. Continúa levantando las pesas hasta que los bíceps estén completamente contraídos y las manc', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ponte de pie con una mancuerna en cada mano, con las palmas mirando hacia el torso. Mantén los codos cerca del torso y los brazos superiores quietos. Exhala y flexiona las pesas mientras contraes los bíceps. Continúa levantando las pesas hasta que los bíceps estén completamente contraídos y las mancuernas estén a la altura de los hombros. Mantén la posición contraída durante una breve pausa mientras aprietas los bíceps. Inhala y comienza a bajar lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand up straight with a dumbbell in each hand, palms facing your torso. Keep your elbows close to your torso and your upper arms stationary. Exhale and curl the weights while contracting your biceps. Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly begin to lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1671-2sQGZ5b.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1671-2sQGZ5b.gif', '2sQGZ5b', '© Gym visual — https://gymvisual.com/'),
('0362', 'dumbbell one arm triceps extension (on bench)', 'Siéntate en un banco con la espalda recta y los pies planos sobre el suelo. Sostén una mancuerna en una mano y coloca la otra mano sobre el banco para apoyarte. Levanta la mancuerna por encima de la cabeza, manteniendo el brazo superior cerca de la cabeza y el codo apuntando hacia adelante. Baja la ', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'triceps', '{"shoulders"}', 'Siéntate en un banco con la espalda recta y los pies planos sobre el suelo. Sostén una mancuerna en una mano y coloca la otra mano sobre el banco para apoyarte. Levanta la mancuerna por encima de la cabeza, manteniendo el brazo superior cerca de la cabeza y el codo apuntando hacia adelante. Baja la mancuerna detrás de la cabeza flexionando el codo, manteniendo el brazo superior quieto. Extiende el brazo de vuelta a la posición inicial, estirando completamente el codo. Repite el número de repeticiones deseado, luego cambia de brazo.', 'Sit on a bench with your back straight and feet flat on the ground. Hold a dumbbell in one hand and place your other hand on the bench for support. Raise the dumbbell overhead, keeping your upper arm close to your head and your elbow pointing forward. Lower the dumbbell behind your head by bending your elbow, keeping your upper arm stationary. Extend your arm back up to the starting position, fully straightening your elbow. Repeat for the desired number of repetitions, then switch arms.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0362-nAuHPcD.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0362-nAuHPcD.gif', 'nAuHPcD', '© Gym visual — https://gymvisual.com/'),
('0363', 'dumbbell one arm upright row', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo una mancuerna en una mano con agarre prono. Deja que la mancuerna cuelgue a la distancia de un brazo frente a los muslos, con la palma hacia el cuerpo. Manteniendo la espalda recta y el core activado, exhala y levanta la man', 'shoulders', 'dumbbell', 'shoulders', 'shoulders', 'delts', '{"traps","biceps"}', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo una mancuerna en una mano con agarre prono. Deja que la mancuerna cuelgue a la distancia de un brazo frente a los muslos, con la palma hacia el cuerpo. Manteniendo la espalda recta y el core activado, exhala y levanta la mancuerna recta hacia la barbilla, guiando con el codo. Haz una pausa por un momento en la parte superior, luego inhala y baja lentamente la mancuerna de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia al otro brazo.', 'Stand with your feet shoulder-width apart, holding a dumbbell in one hand with an overhand grip. Let the dumbbell hang at arm''s length in front of your thighs, with your palm facing your body. Keeping your back straight and your core engaged, exhale and lift the dumbbell straight up towards your chin, leading with your elbow. Pause for a moment at the top, then inhale and slowly lower the dumbbell back down to the starting position. Repeat for the desired number of repetitions, then switch to the other arm.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0363-6cKQC5E.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0363-6cKQC5E.gif', '6cKQC5E', '© Gym visual — https://gymvisual.com/'),
('0364', 'dumbbell one arm wrist curl', 'Siéntate en un banco o silla con los pies apoyados en el suelo. Sostén una mancuerna en una mano con agarre supino, apoyando el antebrazo sobre el muslo. Permite que la muñeca se extienda, dejando que la mancuerna ruede hacia los dedos. Flexiona lentamente la muñeca hacia arriba, acercando la mancue', 'lower arms', 'dumbbell', 'lower arms', 'lower arms', 'forearms', '{"biceps","brachialis"}', 'Siéntate en un banco o silla con los pies apoyados en el suelo. Sostén una mancuerna en una mano con agarre supino, apoyando el antebrazo sobre el muslo. Permite que la muñeca se extienda, dejando que la mancuerna ruede hacia los dedos. Flexiona lentamente la muñeca hacia arriba, acercando la mancuerna hacia el antebrazo. Repite el número de repeticiones deseado, luego cambia a la otra mano.', 'Sit on a bench or chair with your feet flat on the ground. Hold a dumbbell in one hand with an underhand grip, resting your forearm on your thigh. Allow your wrist to extend, letting the dumbbell roll down towards your fingers. Slowly curl your wrist back up, bringing the dumbbell towards your forearm. Repeat for the desired number of repetitions, then switch to the other hand.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0364-q8aHNoF.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0364-q8aHNoF.gif', 'q8aHNoF', '© Gym visual — https://gymvisual.com/'),
('1672', 'dumbbell one arm zottman preacher curl', 'Siéntate en un banco scott y sostén una mancuerna en una mano con agarre supino. Apoya el brazo superior sobre la almohadilla del banco scott, permitiendo que el brazo se extienda completamente. Flexiona la mancuerna de nuevo hacia el hombro, manteniendo el brazo superior quieto. En la parte superio', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Siéntate en un banco scott y sostén una mancuerna en una mano con agarre supino. Apoya el brazo superior sobre la almohadilla del banco scott, permitiendo que el brazo se extienda completamente. Flexiona la mancuerna de nuevo hacia el hombro, manteniendo el brazo superior quieto. En la parte superior del curl, gira la muñeca de modo que la palma quede hacia arriba. Baja lentamente la mancuerna de vuelta a la posición inicial, girando la muñeca de regreso a la posición inicial. Repite el número de repeticiones deseado, luego cambia de brazo.', 'Sit on a preacher curl bench and hold a dumbbell in one hand with an underhand grip. Rest your upper arm on the preacher bench pad, allowing your arm to fully extend. Curl the dumbbell up towards your shoulder, keeping your upper arm stationary. At the top of the curl, rotate your wrist so that your palm faces up. Slowly lower the dumbbell back down to the starting position, rotating your wrist back to the starting position. Repeat for the desired number of repetitions, then switch arms.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1672-sxY5Biu.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1672-sxY5Biu.gif', 'sxY5Biu', '© Gym visual — https://gymvisual.com/'),
('1292', 'dumbbell one leg fly on exercise ball', 'Siéntate sobre un balón de estabilidad con una mancuerna en cada mano, con las palmas enfrentadas entre sí. Coloca un pie en el suelo y extiende la otra pierna recta hacia adelante. Inclínate ligeramente hacia adelante y lleva los brazos hacia los lados, manteniendo una ligera flexión en los codos. ', 'chest', 'dumbbell', 'chest', 'chest', 'pectorals', '{"shoulders","triceps"}', 'Siéntate sobre un balón de estabilidad con una mancuerna en cada mano, con las palmas enfrentadas entre sí. Coloca un pie en el suelo y extiende la otra pierna recta hacia adelante. Inclínate ligeramente hacia adelante y lleva los brazos hacia los lados, manteniendo una ligera flexión en los codos. Baja lentamente las mancuernas hacia abajo y hacia los lados, sintiendo un estiramiento en el pecho. Haz una pausa por un momento en la parte inferior, luego contrae los músculos del pecho para llevar las mancuernas de nuevo hacia arriba hasta la posición inicial. Repite el número de repeticiones deseado y luego cambia de pierna y repite.', 'Sit on an exercise ball with a dumbbell in each hand, palms facing each other. Place one foot on the ground and extend the other leg straight out in front of you. Lean forward slightly and bring your arms out to the sides, keeping a slight bend in your elbows. Slowly lower the dumbbells down and out to the sides, feeling a stretch in your chest. Pause for a moment at the bottom, then squeeze your chest muscles to bring the dumbbells back up to the starting position. Repeat for the desired number of repetitions, then switch legs and repeat.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1292-pH2x2jj.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1292-pH2x2jj.gif', 'pH2x2jj', '© Gym visual — https://gymvisual.com/'),
('0365', 'dumbbell over bench neutral wrist curl', 'Siéntate en un banco con los pies apoyados en el suelo y sostén una mancuerna en cada mano, con las palmas hacia arriba. Apoya los antebrazos sobre el banco, dejando que las muñecas cuelguen del borde. Manteniendo los brazos superiores quietos, exhala y flexiona las mancuernas hacia los hombros. Haz', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Siéntate en un banco con los pies apoyados en el suelo y sostén una mancuerna en cada mano, con las palmas hacia arriba. Apoya los antebrazos sobre el banco, dejando que las muñecas cuelguen del borde. Manteniendo los brazos superiores quietos, exhala y flexiona las mancuernas hacia los hombros. Haz una pausa por un momento en la parte superior, luego inhala y baja lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a bench with your feet flat on the ground and hold a dumbbell in each hand, palms facing up. Rest your forearms on the bench, allowing your wrists to hang off the edge. Keeping your upper arms stationary, exhale and curl the dumbbells up towards your shoulders. Pause for a moment at the top, then inhale and slowly lower the dumbbells back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0365-BKa8dmT.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0365-BKa8dmT.gif', 'BKa8dmT', '© Gym visual — https://gymvisual.com/'),
('0366', 'dumbbell over bench one arm neutral wrist curl', 'Siéntate en un banco con una mancuerna en una mano y el brazo extendido sobre el banco, con la palma hacia arriba. Mantén el brazo superior quieto y flexiona la mancuerna hacia el hombro, manteniendo la muñeca en posición neutra. Haz una pausa breve en la parte más alta, luego baja lentamente la man', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Siéntate en un banco con una mancuerna en una mano y el brazo extendido sobre el banco, con la palma hacia arriba. Mantén el brazo superior quieto y flexiona la mancuerna hacia el hombro, manteniendo la muñeca en posición neutra. Haz una pausa breve en la parte más alta, luego baja lentamente la mancuerna de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia de brazo.', 'Sit on a bench with a dumbbell in one hand and your arm extended over the bench, palm facing up. Keep your upper arm stationary and curl the dumbbell towards your shoulder, keeping your wrist in a neutral position. Pause for a moment at the top, then slowly lower the dumbbell back to the starting position. Repeat for the desired number of repetitions, then switch arms.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0366-IvV6C9M.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0366-IvV6C9M.gif', 'IvV6C9M', '© Gym visual — https://gymvisual.com/'),
('1441', 'dumbbell over bench one arm reverse wrist curl', 'Siéntate en un banco con los pies apoyados en el suelo y sujeta una mancuerna con una mano, con la palma hacia abajo. Apoya el antebrazo en el banco con la muñeca colgando del borde. Flexiona lentamente la muñeca hacia arriba, acercando la mancuerna hacia el antebrazo. Haz una pausa breve en la part', 'lower arms', 'dumbbell', 'lower arms', 'lower arms', 'forearms', '{"biceps","brachialis"}', 'Siéntate en un banco con los pies apoyados en el suelo y sujeta una mancuerna con una mano, con la palma hacia abajo. Apoya el antebrazo en el banco con la muñeca colgando del borde. Flexiona lentamente la muñeca hacia arriba, acercando la mancuerna hacia el antebrazo. Haz una pausa breve en la parte más alta, luego baja lentamente la mancuerna de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia al otro brazo.', 'Sit on a bench with your feet flat on the ground and hold a dumbbell in one hand, palm facing down. Rest your forearm on the bench with your wrist hanging off the edge. Slowly curl your wrist upwards, bringing the dumbbell towards your forearm. Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position. Repeat for the desired number of repetitions, then switch to the other arm.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1441-4Jc36XM.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1441-4Jc36XM.gif', '4Jc36XM', '© Gym visual — https://gymvisual.com/'),
('0367', 'dumbbell over bench one arm wrist curl', 'Siéntate en un banco con los pies apoyados en el suelo y sujeta una mancuerna con una mano, con la palma hacia abajo. Apoya el antebrazo en el banco con la muñeca colgando del borde. Flexiona lentamente la muñeca hacia arriba, acercando la mancuerna hacia el antebrazo. Haz una pausa breve en la part', 'lower arms', 'dumbbell', 'lower arms', 'lower arms', 'forearms', '{"biceps","shoulders"}', 'Siéntate en un banco con los pies apoyados en el suelo y sujeta una mancuerna con una mano, con la palma hacia abajo. Apoya el antebrazo en el banco con la muñeca colgando del borde. Flexiona lentamente la muñeca hacia arriba, acercando la mancuerna hacia el antebrazo. Haz una pausa breve en la parte más alta, luego baja lentamente la mancuerna de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia al otro brazo.', 'Sit on a bench with your feet flat on the ground and hold a dumbbell in one hand, palm facing down. Rest your forearm on the bench with your wrist hanging off the edge. Slowly curl your wrist upwards, bringing the dumbbell towards your forearm. Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position. Repeat for the desired number of repetitions, then switch to the other arm.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0367-KI1DjNN.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0367-KI1DjNN.gif', 'KI1DjNN', '© Gym visual — https://gymvisual.com/'),
('0368', 'dumbbell over bench revers wrist curl', 'Siéntate en un banco con los pies apoyados en el suelo y sujeta una mancuerna en cada mano, con las palmas hacia abajo. Apoya los antebrazos sobre el banco, dejando que las muñecas cuelguen del borde. Flexiona lentamente las muñecas hacia arriba, acercando las mancuernas hacia tu cuerpo. Haz una pau', 'lower arms', 'dumbbell', 'lower arms', 'lower arms', 'forearms', '{"biceps","brachialis"}', 'Siéntate en un banco con los pies apoyados en el suelo y sujeta una mancuerna en cada mano, con las palmas hacia abajo. Apoya los antebrazos sobre el banco, dejando que las muñecas cuelguen del borde. Flexiona lentamente las muñecas hacia arriba, acercando las mancuernas hacia tu cuerpo. Haz una pausa breve en la parte alta, luego baja lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a bench with your feet flat on the ground and hold a dumbbell in each hand, palms facing down. Rest your forearms on the bench, allowing your wrists to hang off the edge. Slowly curl your wrists upward, bringing the dumbbells towards your body. Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0368-3tAXPQ6.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0368-3tAXPQ6.gif', '3tAXPQ6', '© Gym visual — https://gymvisual.com/'),
('0369', 'dumbbell over bench wrist curl', 'Siéntate en un banco con los antebrazos apoyados en él y las palmas hacia arriba, sujetando una mancuerna en cada mano. Deja que tus muñecas cuelguen del borde del banco. Flexiona lentamente las muñecas hacia arriba, apretando los antebrazos en la parte superior del movimiento. Haz una pausa por un ', 'lower arms', 'dumbbell', 'lower arms', 'lower arms', 'forearms', '{"biceps","brachialis"}', 'Siéntate en un banco con los antebrazos apoyados en él y las palmas hacia arriba, sujetando una mancuerna en cada mano. Deja que tus muñecas cuelguen del borde del banco. Flexiona lentamente las muñecas hacia arriba, apretando los antebrazos en la parte superior del movimiento. Haz una pausa por un momento y luego baja lentamente las muñecas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a bench with your forearms resting on the bench and your palms facing up, holding a dumbbell in each hand. Allow your wrists to hang over the edge of the bench. Slowly curl your wrists upward, squeezing your forearms at the top of the movement. Pause for a moment, then slowly lower your wrists back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0369-D1xYJAU.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0369-D1xYJAU.gif', 'D1xYJAU', '© Gym visual — https://gymvisual.com/'),
('1329', 'dumbbell palm rotational bent over row', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una mancuerna en cada mano con un agarre prono. Inclínate hacia adelante desde las caderas, manteniendo la espalda recta y las rodillas ligeramente flexionadas. Deja que los brazos cuelguen rectos hacia abajo, con las palmas h', 'back', 'dumbbell', 'back', 'back', 'upper back', '{"biceps","forearms"}', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una mancuerna en cada mano con un agarre prono. Inclínate hacia adelante desde las caderas, manteniendo la espalda recta y las rodillas ligeramente flexionadas. Deja que los brazos cuelguen rectos hacia abajo, con las palmas hacia tu cuerpo. Activa el core y tira de las mancuernas hacia tu pecho, manteniendo los codos cerca del cuerpo. Mientras subes las mancuernas, gira las palmas para que queden mirando hacia afuera, alejadas de tu cuerpo. Junta los omóplatos en la parte superior del movimiento. Baja lentamente las mancuernas hasta la posición inicial, girando las palmas de vuelta a su posición original. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, holding a dumbbell in each hand with an overhand grip. Bend forward at the hips, keeping your back straight and your knees slightly bent. Let your arms hang straight down, palms facing your body. Engage your core and pull the dumbbells up towards your chest, keeping your elbows close to your body. As you pull the dumbbells up, rotate your palms so they face away from your body. Squeeze your shoulder blades together at the top of the movement. Slowly lower the dumbbells back down to the starting position, rotating your palms back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1329-wt6rwjk.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1329-wt6rwjk.gif', 'wt6rwjk', '© Gym visual — https://gymvisual.com/'),
('1623', 'dumbbell palms in incline bench press', 'Coloca un banco inclinado a un ángulo de 45 grados. Siéntate en el banco con la espalda apoyada en el respaldo y los pies planos en el suelo. Sujeta una mancuerna en cada mano con agarre prono, con las palmas hacia adentro. Extiende los brazos rectos hacia arriba, por encima del pecho, manteniendo u', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'triceps', '{"chest","shoulders"}', 'Coloca un banco inclinado a un ángulo de 45 grados. Siéntate en el banco con la espalda apoyada en el respaldo y los pies planos en el suelo. Sujeta una mancuerna en cada mano con agarre prono, con las palmas hacia adentro. Extiende los brazos rectos hacia arriba, por encima del pecho, manteniendo una ligera flexión en los codos. Baja las mancuernas lentamente hacia los hombros, manteniendo los codos cerca del cuerpo. Haz una pausa por un momento en la posición más baja y luego presiona las mancuernas de vuelta hacia arriba, hasta la posición inicial. Repite el número de repeticiones deseado.', 'Set up an incline bench at a 45-degree angle. Sit on the bench with your back against the backrest and feet flat on the ground. Hold a dumbbell in each hand with an overhand grip, palms facing inwards. Extend your arms straight up above your chest, keeping a slight bend in your elbows. Lower the dumbbells slowly towards your shoulders, keeping your elbows close to your body. Pause for a moment at the bottom, then press the dumbbells back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1623-8eqjhOl.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1623-8eqjhOl.gif', '8eqjhOl', '© Gym visual — https://gymvisual.com/'),
('0370', 'dumbbell peacher hammer curl', 'Ponte de pie con una mancuerna en cada mano, con las palmas mirando hacia el torso. Mantén los codos cerca del torso y gira las palmas de las manos hasta que queden mirando hacia adelante. Esta será tu posición inicial. Ahora, manteniendo los brazos superiores quietos, exhala y flexiona los brazos c', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ponte de pie con una mancuerna en cada mano, con las palmas mirando hacia el torso. Mantén los codos cerca del torso y gira las palmas de las manos hasta que queden mirando hacia adelante. Esta será tu posición inicial. Ahora, manteniendo los brazos superiores quietos, exhala y flexiona los brazos contrayendo los bíceps. Continúa levantando las pesas hasta que los bíceps estén completamente contraídos y las mancuernas estén a la altura de los hombros. Mantén la posición contraída durante una breve pausa mientras aprietas los bíceps. Luego, inhala y comienza a bajar lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones recomendado.', 'Stand up straight with a dumbbell in each hand, palms facing your torso. Keep your elbows close to your torso and rotate the palms of your hands until they are facing forward. This will be your starting position. Now, keeping the upper arms stationary, exhale and curl the weights while contracting your biceps. Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Then, inhale and slowly begin to lower the dumbbells back to the starting position. Repeat for the recommended amount of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0370-F1KxjBa.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0370-F1KxjBa.gif', 'F1KxjBa', '© Gym visual — https://gymvisual.com/'),
('0371', 'dumbbell plyo squat', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo una mancuerna en cada mano a los costados. Baja el cuerpo hacia una posición de sentadilla flexionando las rodillas y empujando las caderas hacia atrás. Cuando llegues al punto más bajo de la sentadilla, impúlsate explosivam', 'upper legs', 'dumbbell', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves"}', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo una mancuerna en cada mano a los costados. Baja el cuerpo hacia una posición de sentadilla flexionando las rodillas y empujando las caderas hacia atrás. Cuando llegues al punto más bajo de la sentadilla, impúlsate explosivamente hacia arriba, saltando del suelo. Mientras estás en el aire, cambia rápidamente la posición de los pies, aterrizando con el pie opuesto adelante. Baja inmediatamente el cuerpo de vuelta a la posición de sentadilla y repite el salto, cambiando de nuevo los pies. Continúa alternando la posición de los pies en cada salto durante el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, holding a dumbbell in each hand at your sides. Lower your body into a squat position by bending your knees and pushing your hips back. As you reach the bottom of the squat, explode upward, jumping off the ground. While in the air, quickly switch the position of your feet, landing with your opposite foot forward. Immediately lower your body back into a squat position and repeat the jump, switching your feet again. Continue alternating the position of your feet with each jump for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0371-S4pwGlc.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0371-S4pwGlc.gif', 'S4pwGlc', '© Gym visual — https://gymvisual.com/'),
('0372', 'dumbbell preacher curl', 'Siéntate en un banco scott con la parte superior de los brazos apoyada en la almohadilla y el pecho contra ella. Sostén una mancuerna en cada mano con las palmas hacia arriba y los brazos completamente extendidos. Manteniendo los brazos superiores fijos, exhala y levanta el peso mientras contraes lo', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Siéntate en un banco scott con la parte superior de los brazos apoyada en la almohadilla y el pecho contra ella. Sostén una mancuerna en cada mano con las palmas hacia arriba y los brazos completamente extendidos. Manteniendo los brazos superiores fijos, exhala y levanta el peso mientras contraes los bíceps. Continúa levantando las mancuernas hasta que los bíceps estén completamente contraídos y las mancuernas estén a la altura de los hombros. Mantén la posición contraída durante una breve pausa mientras aprietas los bíceps. Inhala y comienza a bajar lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a preacher curl bench with your upper arms resting on the pad and your chest against it. Hold a dumbbell in each hand with your palms facing up and your arms fully extended. Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly begin to lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0372-jivWf8n.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0372-jivWf8n.gif', 'jivWf8n', '© Gym visual — https://gymvisual.com/'),
('1673', 'dumbbell preacher curl over exercise ball', 'Siéntate sobre un balón de ejercicio con los pies apoyados planos en el suelo y la espalda recta. Sujeta una mancuerna con una mano con agarre supino, apoyando el codo sobre el balón de estabilidad. Manteniendo el brazo superior quieto, exhala y flexiona la mancuerna hacia el hombro. Haz una pausa p', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Siéntate sobre un balón de ejercicio con los pies apoyados planos en el suelo y la espalda recta. Sujeta una mancuerna con una mano con agarre supino, apoyando el codo sobre el balón de estabilidad. Manteniendo el brazo superior quieto, exhala y flexiona la mancuerna hacia el hombro. Haz una pausa por un momento arriba, luego inhala y baja lentamente la mancuerna a la posición inicial. Repite el número de repeticiones deseado, luego cambia de brazo.', 'Sit on an exercise ball with your feet flat on the ground and your back straight. Hold a dumbbell in one hand with an underhand grip, resting your elbow on the exercise ball. Keeping your upper arm stationary, exhale and curl the dumbbell up towards your shoulder. Pause for a moment at the top, then inhale and slowly lower the dumbbell back to the starting position. Repeat for the desired number of repetitions, then switch arms.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1673-hwygydB.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1673-hwygydB.gif', 'hwygydB', '© Gym visual — https://gymvisual.com/'),
('1293', 'dumbbell press on exercise ball', 'Siéntate sobre un balón de estabilidad con los pies planos en el suelo y una mancuerna en cada mano, apoyadas sobre los muslos. Camina lentamente hacia adelante con los pies, haciendo rodar el balón de estabilidad hasta que tu zona lumbar quede apoyada sobre el balón y tus rodillas formen un ángulo ', 'chest', 'dumbbell', 'chest', 'chest', 'pectorals', '{"shoulders","triceps"}', 'Siéntate sobre un balón de estabilidad con los pies planos en el suelo y una mancuerna en cada mano, apoyadas sobre los muslos. Camina lentamente hacia adelante con los pies, haciendo rodar el balón de estabilidad hasta que tu zona lumbar quede apoyada sobre el balón y tus rodillas formen un ángulo de 90 grados. Sube las mancuernas hasta la altura de los hombros, con las palmas hacia adelante. Empuja las mancuernas hacia arriba hasta que los brazos estén completamente extendidos. Haz una pausa breve en la parte alta, luego baja lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on an exercise ball with your feet flat on the ground and dumbbells in each hand, resting on your thighs. Slowly walk your feet forward, rolling the exercise ball until your lower back is supported on the ball and your knees are at a 90-degree angle. Raise the dumbbells to shoulder height, palms facing forward. Press the dumbbells upward until your arms are fully extended. Pause for a moment at the top, then slowly lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1293-O8o7q4d.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1293-O8o7q4d.gif', 'O8o7q4d', '© Gym visual — https://gymvisual.com/'),
('0373', 'dumbbell pronate-grip triceps extension', 'Siéntate en un banco o silla con la espalda recta y los pies apoyados en el suelo. Sujeta una mancuerna con ambas manos, con las palmas hacia abajo, y extiende los brazos rectos por encima de la cabeza. Manteniendo la parte superior de los brazos cerca de la cabeza y los codos apuntando hacia adelan', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'triceps', '{"forearms"}', 'Siéntate en un banco o silla con la espalda recta y los pies apoyados en el suelo. Sujeta una mancuerna con ambas manos, con las palmas hacia abajo, y extiende los brazos rectos por encima de la cabeza. Manteniendo la parte superior de los brazos cerca de la cabeza y los codos apuntando hacia adelante, baja lentamente la mancuerna detrás de la cabeza flexionando los codos. Haz una pausa breve y luego extiende los brazos de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a bench or chair with your back straight and feet flat on the ground. Hold a dumbbell with both hands, palms facing down, and extend your arms straight up overhead. Keeping your upper arms close to your head and elbows pointing forward, slowly lower the dumbbell behind your head by bending your elbows. Pause for a moment, then extend your arms back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0373-bpJL2Qs.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0373-bpJL2Qs.gif', 'bpJL2Qs', '© Gym visual — https://gymvisual.com/'),
('0374', 'dumbbell prone incline curl', 'Ajusta el banco a una inclinación de 45 grados. Túmbate boca abajo en el banco con el pecho y el abdomen apoyados contra él. Sujeta una mancuerna en cada mano con las palmas hacia abajo y los brazos completamente extendidos. Manteniendo los brazos superiores fijos, exhala y levanta el peso mientras ', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ajusta el banco a una inclinación de 45 grados. Túmbate boca abajo en el banco con el pecho y el abdomen apoyados contra él. Sujeta una mancuerna en cada mano con las palmas hacia abajo y los brazos completamente extendidos. Manteniendo los brazos superiores fijos, exhala y levanta el peso mientras contraes los bíceps. Continúa levantando las pesas hasta que los bíceps estén completamente contraídos y las mancuernas estén a la altura de los hombros. Mantén la posición contraída durante una breve pausa mientras aprietas los bíceps. Inhala y comienza a bajar lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the bench to a 45-degree incline. Lie face down on the bench with your chest and stomach resting against it. Hold a dumbbell in each hand with your palms facing down and your arms fully extended. Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly begin to lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0374-mwpPcr1.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0374-mwpPcr1.gif', 'mwpPcr1', '© Gym visual — https://gymvisual.com/'),
('1674', 'dumbbell prone incline hammer curl', 'Ajusta el banco a una inclinación de 45 grados. Túmbate boca abajo en el banco con una mancuerna en cada mano, con las palmas mirándose entre sí. Deja que los brazos cuelguen rectos hacia el suelo, manteniendo los codos ligeramente flexionados. Manteniendo los brazos superiores fijos, exhala y levan', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ajusta el banco a una inclinación de 45 grados. Túmbate boca abajo en el banco con una mancuerna en cada mano, con las palmas mirándose entre sí. Deja que los brazos cuelguen rectos hacia el suelo, manteniendo los codos ligeramente flexionados. Manteniendo los brazos superiores fijos, exhala y levanta el peso mientras contraes los bíceps. Continúa levantando las mancuernas hasta que los bíceps estén completamente contraídos y las mancuernas estén a la altura de los hombros. Mantén la posición contraída durante una breve pausa mientras aprietas los bíceps. Inhala y comienza a bajar lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the bench to a 45-degree incline. Lie face down on the bench with a dumbbell in each hand, palms facing each other. Allow your arms to hang straight down towards the floor, keeping your elbows slightly bent. Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly begin to lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1674-cWemPG8.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1674-cWemPG8.gif', 'cWemPG8', '© Gym visual — https://gymvisual.com/'),
('0375', 'dumbbell pullover', 'Túmbate boca arriba en un banco con la cabeza en un extremo y los pies en el suelo. Sujeta una mancuerna con ambas manos y extiende los brazos rectos por encima del pecho. Manteniendo una ligera flexión en los codos, baja lentamente la mancuerna detrás de la cabeza hasta sentir un estiramiento en el', 'chest', 'dumbbell', 'chest', 'chest', 'pectorals', '{"latissimus dorsi","triceps"}', 'Túmbate boca arriba en un banco con la cabeza en un extremo y los pies en el suelo. Sujeta una mancuerna con ambas manos y extiende los brazos rectos por encima del pecho. Manteniendo una ligera flexión en los codos, baja lentamente la mancuerna detrás de la cabeza hasta sentir un estiramiento en el pecho y los hombros. Haz una pausa por un momento, luego levanta la mancuerna de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on a bench with your head at one end and your feet on the floor. Hold a dumbbell with both hands and extend your arms straight above your chest. Keeping a slight bend in your elbows, slowly lower the dumbbell behind your head until you feel a stretch in your chest and shoulders. Pause for a moment, then raise the dumbbell back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0375-9XjtHvS.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0375-9XjtHvS.gif', '9XjtHvS', '© Gym visual — https://gymvisual.com/'),
('1294', 'dumbbell pullover hip extension on exercise ball', 'Siéntate sobre un balón de estabilidad con los pies planos en el suelo y la mancuerna apoyada sobre los muslos. Camina lentamente hacia adelante con los pies, haciendo rodar el balón de estabilidad por tu espalda hasta que la cabeza, el cuello y la parte superior de la espalda queden apoyados sobre ', 'chest', 'dumbbell', 'chest', 'chest', 'pectorals', '{"triceps","shoulders","core"}', 'Siéntate sobre un balón de estabilidad con los pies planos en el suelo y la mancuerna apoyada sobre los muslos. Camina lentamente hacia adelante con los pies, haciendo rodar el balón de estabilidad por tu espalda hasta que la cabeza, el cuello y la parte superior de la espalda queden apoyados sobre el balón. Sujeta la mancuerna con ambas manos y extiende los brazos rectos por encima del pecho, manteniendo una ligera flexión en los codos. Baja la mancuerna detrás de la cabeza, manteniendo los brazos rectos y con control total. Haz una pausa por un momento, luego levanta la mancuerna de vuelta a la posición inicial. Manteniendo los brazos extendidos, levanta las caderas del suelo, apretando los glúteos y activando el core. Baja las caderas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on an exercise ball with your feet flat on the ground and the dumbbell resting on your thighs. Slowly walk your feet forward, rolling the exercise ball down your back until your head, neck, and upper back are supported on the ball. Hold the dumbbell with both hands and extend your arms straight up over your chest, keeping a slight bend in your elbows. Lower the dumbbell behind your head, keeping your arms straight and maintaining control. Pause for a moment, then raise the dumbbell back to the starting position. While keeping your arms extended, lift your hips off the ground, squeezing your glutes and engaging your core. Lower your hips back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1294-lI7easp.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1294-lI7easp.gif', 'lI7easp', '© Gym visual — https://gymvisual.com/'),
('1295', 'dumbbell pullover on exercise ball', 'Siéntate sobre un balón de estabilidad y sujeta una mancuerna con ambas manos por encima del pecho, con los brazos extendidos. Baja lentamente la mancuerna detrás de la cabeza manteniendo los brazos rectos. Haz una pausa por un momento, luego levanta la mancuerna de vuelta a la posición inicial. Rep', 'chest', 'dumbbell', 'chest', 'chest', 'pectorals', '{"triceps","latissimus dorsi"}', 'Siéntate sobre un balón de estabilidad y sujeta una mancuerna con ambas manos por encima del pecho, con los brazos extendidos. Baja lentamente la mancuerna detrás de la cabeza manteniendo los brazos rectos. Haz una pausa por un momento, luego levanta la mancuerna de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on an exercise ball and hold a dumbbell with both hands above your chest, arms extended. Slowly lower the dumbbell behind your head while keeping your arms straight. Pause for a moment, then raise the dumbbell back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1295-FSD6PGL.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1295-FSD6PGL.gif', 'FSD6PGL', '© Gym visual — https://gymvisual.com/'),
('1700', 'dumbbell push press', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una mancuerna en cada mano a la altura de los hombros. Flexiona ligeramente las rodillas y baja el cuerpo, luego extiende las piernas de forma explosiva y presiona las mancuernas por encima de la cabeza. Bloquea los brazos en ', 'shoulders', 'dumbbell', 'shoulders', 'shoulders', 'delts', '{"triceps","core"}', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una mancuerna en cada mano a la altura de los hombros. Flexiona ligeramente las rodillas y baja el cuerpo, luego extiende las piernas de forma explosiva y presiona las mancuernas por encima de la cabeza. Bloquea los brazos en la parte superior del movimiento, luego baja las mancuernas de vuelta a la altura de los hombros. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, holding a dumbbell in each hand at shoulder level. Bend your knees slightly and dip your body down, then explosively extend your legs and press the dumbbells overhead. Lock out your arms at the top of the movement, then lower the dumbbells back to shoulder level. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1700-FS63wTN.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1700-FS63wTN.gif', 'FS63wTN', '© Gym visual — https://gymvisual.com/'),
('0376', 'dumbbell raise', 'Ponte de pie con los pies separados a la altura de los hombros y sostén una mancuerna en cada mano, con las palmas hacia el cuerpo. Mantén la espalda recta y activa el core. Levanta los brazos hacia los lados hasta que queden paralelos al suelo, manteniendo una ligera flexión en los codos. Haz una p', 'shoulders', 'dumbbell', 'shoulders', 'shoulders', 'delts', '{"traps","rhomboids"}', 'Ponte de pie con los pies separados a la altura de los hombros y sostén una mancuerna en cada mano, con las palmas hacia el cuerpo. Mantén la espalda recta y activa el core. Levanta los brazos hacia los lados hasta que queden paralelos al suelo, manteniendo una ligera flexión en los codos. Haz una pausa por un momento en la parte superior, luego baja lentamente los brazos de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing your body. Keep your back straight and engage your core. Raise your arms out to the sides until they are parallel to the floor, keeping a slight bend in your elbows. Pause for a moment at the top, then slowly lower your arms back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0376-c9MnDRp.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0376-c9MnDRp.gif', 'c9MnDRp', '© Gym visual — https://gymvisual.com/'),
('2292', 'dumbbell rear delt raise', 'Ponte de pie con los pies separados a la altura de los hombros y sostén una mancuerna en cada mano, con las palmas hacia el cuerpo. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta. Levanta los brazos hacia los lados, manteniendo una ligera', 'shoulders', 'dumbbell', 'shoulders', 'shoulders', 'delts', '{"trapezius","rhomboids"}', 'Ponte de pie con los pies separados a la altura de los hombros y sostén una mancuerna en cada mano, con las palmas hacia el cuerpo. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta. Levanta los brazos hacia los lados, manteniendo una ligera flexión en los codos, hasta que queden paralelos al suelo. Haz una pausa por un momento en la parte superior, luego baja lentamente los brazos de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing your body. Bend your knees slightly and hinge forward at the hips, keeping your back straight. Raise your arms out to the sides, keeping a slight bend in your elbows, until they are parallel to the floor. Pause for a moment at the top, then slowly lower your arms back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2292-mu5Guxt.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2292-mu5Guxt.gif', 'mu5Guxt', '© Gym visual — https://gymvisual.com/'),
('0377', 'dumbbell rear delt row_shoulder', 'Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Sujeta una mancuerna en cada mano con las palmas hacia tu cuerpo. Inclínate hacia adelante desde la cintura, manteniendo la espalda recta y el core activado. Extiende los brazos rectos hacia el sue', 'shoulders', 'dumbbell', 'shoulders', 'shoulders', 'delts', '{"trapezius","rhomboids"}', 'Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Sujeta una mancuerna en cada mano con las palmas hacia tu cuerpo. Inclínate hacia adelante desde la cintura, manteniendo la espalda recta y el core activado. Extiende los brazos rectos hacia el suelo, con una ligera flexión en los codos. Levanta las mancuernas hacia los lados, apretando los omóplatos entre sí. Haz una pausa breve en la parte alta, luego baja lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and knees slightly bent. Hold a dumbbell in each hand with your palms facing your body. Bend forward at the waist, keeping your back straight and your core engaged. Extend your arms straight down towards the floor, with a slight bend in your elbows. Raise the dumbbells out to the sides, squeezing your shoulder blades together. Pause for a moment at the top, then slowly lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0377-EKXOMEh.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0377-EKXOMEh.gif', 'EKXOMEh', '© Gym visual — https://gymvisual.com/'),
('0378', 'dumbbell rear fly', 'Ponte de pie con los pies separados a la altura de los hombros y sostén una mancuerna en cada mano. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta. Extiende los brazos rectos hacia el suelo, con las palmas mirándose entre sí. Manteniendo ', 'shoulders', 'dumbbell', 'shoulders', 'shoulders', 'delts', '{"trapezius","rhomboids"}', 'Ponte de pie con los pies separados a la altura de los hombros y sostén una mancuerna en cada mano. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta. Extiende los brazos rectos hacia el suelo, con las palmas mirándose entre sí. Manteniendo una ligera flexión en los codos, levanta los brazos hacia los lados y aprieta los omóplatos entre sí. Haz una pausa por un momento en la parte superior, luego baja lentamente los brazos de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and hold a dumbbell in each hand. Bend your knees slightly and hinge forward at the hips, keeping your back straight. Extend your arms straight down towards the ground, palms facing each other. Keeping a slight bend in your elbows, lift your arms out to the sides and squeeze your shoulder blades together. Pause for a moment at the top, then slowly lower your arms back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0378-8DiFDVA.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0378-8DiFDVA.gif', '8DiFDVA', '© Gym visual — https://gymvisual.com/'),
('0380', 'dumbbell rear lateral raise', 'Ponte de pie con los pies separados a la altura de los hombros y sostén una mancuerna en cada mano, con las palmas hacia el cuerpo. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta y el core activado. Levanta los brazos hacia los lados, man', 'shoulders', 'dumbbell', 'shoulders', 'shoulders', 'delts', '{"traps","rhomboids"}', 'Ponte de pie con los pies separados a la altura de los hombros y sostén una mancuerna en cada mano, con las palmas hacia el cuerpo. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta y el core activado. Levanta los brazos hacia los lados, manteniendo una ligera flexión en los codos, hasta que queden paralelos al suelo. Haz una pausa por un momento en la parte superior, luego baja lentamente los brazos de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing your body. Bend your knees slightly and hinge forward at the hips, keeping your back straight and core engaged. Raise your arms out to the sides, keeping a slight bend in your elbows, until they are parallel to the floor. Pause for a moment at the top, then slowly lower your arms back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0380-v1qBec9.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0380-v1qBec9.gif', 'v1qBec9', '© Gym visual — https://gymvisual.com/'),
('0379', 'dumbbell rear lateral raise (support head)', 'Ponte de pie con los pies separados a la altura de los hombros y sostén una mancuerna en cada mano. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta. Levanta los brazos hacia los lados, manteniendo una ligera flexión en los codos, hasta que', 'shoulders', 'dumbbell', 'shoulders', 'shoulders', 'delts', '{"traps","rhomboids"}', 'Ponte de pie con los pies separados a la altura de los hombros y sostén una mancuerna en cada mano. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta. Levanta los brazos hacia los lados, manteniendo una ligera flexión en los codos, hasta que queden paralelos al suelo. Haz una pausa por un momento en la parte superior, luego baja lentamente los brazos de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and hold a dumbbell in each hand. Bend your knees slightly and hinge forward at the hips, keeping your back straight. Raise your arms out to the sides, keeping a slight bend in your elbows, until they are parallel to the ground. Pause for a moment at the top, then slowly lower your arms back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0379-UzkLrem.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0379-UzkLrem.gif', 'UzkLrem', '© Gym visual — https://gymvisual.com/'),
('0381', 'dumbbell rear lunge', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una mancuerna en cada mano. Da un paso hacia atrás con el pie derecho, bajando el cuerpo a una posición de zancada. Flexiona la rodilla izquierda y baja el cuerpo hasta que el muslo izquierdo quede paralelo al suelo. Haz una p', 'upper legs', 'dumbbell', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves"}', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una mancuerna en cada mano. Da un paso hacia atrás con el pie derecho, bajando el cuerpo a una posición de zancada. Flexiona la rodilla izquierda y baja el cuerpo hasta que el muslo izquierdo quede paralelo al suelo. Haz una pausa por un momento, luego empuja con el talón izquierdo para volver a la posición inicial. Repite del otro lado, dando un paso hacia atrás con el pie izquierdo.', 'Stand with your feet shoulder-width apart, holding a dumbbell in each hand. Take a step backward with your right foot, lowering your body into a lunge position. Bend your left knee and lower your body until your left thigh is parallel to the ground. Pause for a moment, then push through your left heel to return to the starting position. Repeat on the other side, stepping back with your left foot.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0381-SSsBDwB.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0381-SSsBDwB.gif', 'SSsBDwB', '© Gym visual — https://gymvisual.com/'),
('0382', 'dumbbell revers grip biceps curl', 'Ponte de pie con una mancuerna en cada mano, con las palmas hacia abajo y los brazos completamente extendidos. Manteniendo los brazos superiores fijos, exhala y levanta el peso mientras contraes los bíceps. Continúa levantando las pesas hasta que los bíceps estén completamente contraídos y las mancu', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ponte de pie con una mancuerna en cada mano, con las palmas hacia abajo y los brazos completamente extendidos. Manteniendo los brazos superiores fijos, exhala y levanta el peso mientras contraes los bíceps. Continúa levantando las pesas hasta que los bíceps estén completamente contraídos y las mancuernas estén a la altura de los hombros. Mantén la posición contraída durante una breve pausa mientras aprietas los bíceps. Inhala y comienza a bajar lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand up straight with a dumbbell in each hand, palms facing down and arms fully extended. Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly begin to lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0382-e4ojVhP.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0382-e4ojVhP.gif', 'e4ojVhP', '© Gym visual — https://gymvisual.com/'),
('1624', 'dumbbell reverse bench press', 'Túmbate boca arriba en un banco con los pies apoyados en el suelo y las rodillas flexionadas. Sujeta una mancuerna en cada mano con agarre prono, con las palmas hacia tus pies. Extiende los brazos rectos hacia el techo, manteniendo una ligera flexión en los codos. Baja lentamente las mancuernas haci', 'chest', 'dumbbell', 'chest', 'chest', 'pectorals', '{"triceps","shoulders"}', 'Túmbate boca arriba en un banco con los pies apoyados en el suelo y las rodillas flexionadas. Sujeta una mancuerna en cada mano con agarre prono, con las palmas hacia tus pies. Extiende los brazos rectos hacia el techo, manteniendo una ligera flexión en los codos. Baja lentamente las mancuernas hacia el pecho, permitiendo que los codos se abran hacia los lados. Haz una pausa por un momento en la parte inferior, luego empuja las mancuernas de nuevo hacia arriba hasta la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on a bench with your feet flat on the ground and your knees bent. Hold a dumbbell in each hand with an overhand grip, palms facing towards your feet. Extend your arms straight up towards the ceiling, keeping a slight bend in your elbows. Slowly lower the dumbbells towards your chest, allowing your elbows to flare out to the sides. Pause for a moment at the bottom, then push the dumbbells back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1624-UIbGx6H.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1624-UIbGx6H.gif', 'UIbGx6H', '© Gym visual — https://gymvisual.com/'),
('0383', 'dumbbell reverse fly', 'Ponte de pie con los pies separados a la altura de los hombros y sostén una mancuerna en cada mano. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta. Extiende los brazos rectos hacia adelante, con las palmas mirándose entre sí. Manteniendo ', 'shoulders', 'dumbbell', 'shoulders', 'shoulders', 'delts', '{"trapezius","rhomboids"}', 'Ponte de pie con los pies separados a la altura de los hombros y sostén una mancuerna en cada mano. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta. Extiende los brazos rectos hacia adelante, con las palmas mirándose entre sí. Manteniendo una ligera flexión en los codos, levanta los brazos hacia los lados hasta que queden paralelos al suelo. Haz una pausa por un momento en la parte superior, luego baja lentamente los brazos de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and hold a dumbbell in each hand. Bend your knees slightly and hinge forward at the hips, keeping your back straight. Extend your arms straight down in front of you, palms facing each other. Keeping a slight bend in your elbows, raise your arms out to the sides until they are parallel to the ground. Pause for a moment at the top, then slowly lower your arms back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0383-EAs3xL9.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0383-EAs3xL9.gif', 'EAs3xL9', '© Gym visual — https://gymvisual.com/'),
('1330', 'dumbbell reverse grip incline bench one arm row', 'Coloca un banco inclinado a un ángulo de 45 grados. Coloca una mancuerna en el suelo junto al banco. Ponte de pie frente al banco con los pies separados a la altura de los hombros. Inclínate desde la cintura y coloca la rodilla izquierda y la mano izquierda sobre el banco para apoyarte. Toma la manc', 'back', 'dumbbell', 'back', 'back', 'upper back', '{"biceps","shoulders"}', 'Coloca un banco inclinado a un ángulo de 45 grados. Coloca una mancuerna en el suelo junto al banco. Ponte de pie frente al banco con los pies separados a la altura de los hombros. Inclínate desde la cintura y coloca la rodilla izquierda y la mano izquierda sobre el banco para apoyarte. Toma la mancuerna con la mano derecha usando un agarre inverso (con la palma hacia abajo). Mantén la espalda recta y el core activado. Tira de la mancuerna hacia el pecho, manteniendo el codo cerca del cuerpo. Aprieta los músculos de la espalda en la parte superior del movimiento. Baja la mancuerna de nuevo a la posición inicial de manera controlada. Repite el número de repeticiones deseado. Cambia de lado y repite el ejercicio con el brazo izquierdo.', 'Set up an incline bench at a 45-degree angle. Place a dumbbell on the floor next to the bench. Stand facing the bench with your feet shoulder-width apart. Bend at the waist and place your left knee and left hand on the bench for support. Pick up the dumbbell with your right hand using a reverse grip (palm facing down). Keep your back straight and your core engaged. Pull the dumbbell up towards your chest, keeping your elbow close to your body. Squeeze your back muscles at the top of the movement. Lower the dumbbell back down to the starting position in a controlled manner. Repeat for the desired number of repetitions. Switch sides and repeat the exercise with your left arm.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1330-ZIViNh1.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1330-ZIViNh1.gif', 'ZIViNh1', '© Gym visual — https://gymvisual.com/'),
('1331', 'dumbbell reverse grip incline bench two arm row', 'Coloca un banco inclinado a un ángulo de 45 grados. Siéntate en el banco con el pecho apoyado en el respaldo y los pies planos en el suelo. Sujeta una mancuerna en cada mano con agarre supino. Inclínate hacia adelante y deja que tus brazos cuelguen rectos hacia abajo, completamente extendidos. Tira ', 'back', 'dumbbell', 'back', 'back', 'upper back', '{"biceps","forearms"}', 'Coloca un banco inclinado a un ángulo de 45 grados. Siéntate en el banco con el pecho apoyado en el respaldo y los pies planos en el suelo. Sujeta una mancuerna en cada mano con agarre supino. Inclínate hacia adelante y deja que tus brazos cuelguen rectos hacia abajo, completamente extendidos. Tira de las mancuernas hacia arriba, hacia el pecho, apretando los omóplatos entre sí. Haz una pausa breve en la parte alta, luego baja lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Set up an incline bench at a 45-degree angle. Sit on the bench with your chest against the backrest and your feet flat on the ground. Hold a dumbbell in each hand with an underhand grip. Lean forward and let your arms hang straight down, fully extended. Pull the dumbbells up towards your chest, squeezing your shoulder blades together. Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1331-9pQSkH8.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1331-9pQSkH8.gif', '9pQSkH8', '© Gym visual — https://gymvisual.com/'),
('2327', 'dumbbell reverse grip row (female)', 'Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Sujeta una mancuerna en cada mano con agarre prono, con las palmas hacia tu cuerpo. Inclínate hacia adelante desde la cintura, manteniendo la espalda recta y el core activado. Deja que tus brazos c', 'back', 'dumbbell', 'back', 'back', 'upper back', '{"biceps","forearms"}', 'Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Sujeta una mancuerna en cada mano con agarre prono, con las palmas hacia tu cuerpo. Inclínate hacia adelante desde la cintura, manteniendo la espalda recta y el core activado. Deja que tus brazos cuelguen rectos hacia abajo, completamente extendidos, con una ligera flexión en los codos. Tira de las mancuernas hacia arriba, hacia el pecho, apretando los omóplatos entre sí. Haz una pausa breve en la parte alta, luego baja lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and knees slightly bent. Hold a dumbbell in each hand with an overhand grip, palms facing your body. Bend forward at the waist, keeping your back straight and your core engaged. Let your arms hang straight down, fully extended, with a slight bend in your elbows. Pull the dumbbells up towards your chest, squeezing your shoulder blades together. Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2327-Nh3mvOO.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2327-Nh3mvOO.gif', 'Nh3mvOO', '© Gym visual — https://gymvisual.com/'),
('0384', 'dumbbell reverse preacher curl', 'Siéntate en un banco predicador con los brazos superiores apoyados en el cojín y el pecho contra el soporte. Sujeta una mancuerna en cada mano con agarre supino, con las palmas hacia arriba. Manteniendo la parte superior de los brazos fija, exhala y flexiona las mancuernas mientras contraes los bíce', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Siéntate en un banco predicador con los brazos superiores apoyados en el cojín y el pecho contra el soporte. Sujeta una mancuerna en cada mano con agarre supino, con las palmas hacia arriba. Manteniendo la parte superior de los brazos fija, exhala y flexiona las mancuernas mientras contraes los bíceps. Continúa flexionando las mancuernas hasta que los bíceps estén completamente contraídos y las mancuernas estén a la altura de los hombros. Mantén la posición contraída durante una breve pausa mientras aprietas los bíceps. Inhala y baja lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a preacher bench with your upper arms resting on the pad and your chest against the support. Hold a dumbbell in each hand with an underhand grip, palms facing up. Keeping your upper arms stationary, exhale and curl the dumbbells as you contract your biceps. Continue to curl the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0384-O8Aq69u.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0384-O8Aq69u.gif', 'O8Aq69u', '© Gym visual — https://gymvisual.com/'),
('1675', 'dumbbell reverse spider curl', 'Ponte de pie con la espalda recta, con una mancuerna en cada mano, las palmas hacia tu cuerpo y los brazos completamente extendidos. Manteniendo los brazos superiores fijos, exhala y levanta el peso mientras contraes los bíceps. Continúa levantando las mancuernas hasta que los bíceps estén completam', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ponte de pie con la espalda recta, con una mancuerna en cada mano, las palmas hacia tu cuerpo y los brazos completamente extendidos. Manteniendo los brazos superiores fijos, exhala y levanta el peso mientras contraes los bíceps. Continúa levantando las mancuernas hasta que los bíceps estén completamente contraídos y las mancuernas estén a la altura de los hombros. Mantén la posición contraída durante una breve pausa mientras aprietas los bíceps. Inhala y comienza a bajar lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand up straight with a dumbbell in each hand, palms facing your body and arms fully extended. Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly begin to lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1675-6sMAmNv.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1675-6sMAmNv.gif', '6sMAmNv', '© Gym visual — https://gymvisual.com/'),
('0385', 'dumbbell reverse wrist curl', 'Siéntate en un banco o silla con los pies apoyados en el suelo. Sujeta una mancuerna en cada mano con agarre prono, con las palmas hacia abajo. Apoya los antebrazos sobre los muslos, dejando que las muñecas cuelguen del borde. Flexiona lentamente las muñecas hacia arriba, acercando las mancuernas ha', 'lower arms', 'dumbbell', 'lower arms', 'lower arms', 'forearms', '{"biceps","brachialis"}', 'Siéntate en un banco o silla con los pies apoyados en el suelo. Sujeta una mancuerna en cada mano con agarre prono, con las palmas hacia abajo. Apoya los antebrazos sobre los muslos, dejando que las muñecas cuelguen del borde. Flexiona lentamente las muñecas hacia arriba, acercando las mancuernas hacia tu cuerpo. Haz una pausa breve en la parte alta, luego baja lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a bench or chair with your feet flat on the ground. Hold a dumbbell in each hand with an overhand grip, palms facing down. Rest your forearms on your thighs, allowing your wrists to hang off the edge. Slowly curl your wrists upward, bringing the dumbbells towards your body. Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0385-BLCvwr2.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0385-BLCvwr2.gif', 'BLCvwr2', '© Gym visual — https://gymvisual.com/'),
('1459', 'dumbbell romanian deadlift', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una mancuerna en cada mano con un agarre prono. Manteniendo la espalda recta y el core activado, inclínate desde las caderas y baja las mancuernas hacia el suelo, permitiendo que las rodillas se flexionen ligeramente. Baja las', 'upper legs', 'dumbbell', 'upper legs', 'upper legs', 'glutes', '{"hamstrings","lower back"}', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una mancuerna en cada mano con un agarre prono. Manteniendo la espalda recta y el core activado, inclínate desde las caderas y baja las mancuernas hacia el suelo, permitiendo que las rodillas se flexionen ligeramente. Baja las mancuernas hasta sentir un estiramiento en los isquiotibiales, luego empuja con los talones y activa los glúteos para volver a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, holding a dumbbell in each hand with an overhand grip. Keeping your back straight and your core engaged, hinge at the hips and lower the dumbbells towards the ground, allowing your knees to bend slightly. Lower the dumbbells until you feel a stretch in your hamstrings, then push through your heels and engage your glutes to return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1459-rR0LJzx.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1459-rR0LJzx.gif', 'rR0LJzx', '© Gym visual — https://gymvisual.com/'),
('0386', 'dumbbell rotation reverse fly', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una mancuerna en cada mano, con las palmas hacia adentro. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta y el pecho elevado. Levanta los brazos hacia los lados, mante', 'shoulders', 'dumbbell', 'shoulders', 'shoulders', 'delts', '{"trapezius","rhomboids"}', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una mancuerna en cada mano, con las palmas hacia adentro. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta y el pecho elevado. Levanta los brazos hacia los lados, manteniendo una ligera flexión en los codos, hasta que queden paralelos al suelo. Gira los brazos de modo que las palmas queden mirando hacia abajo. Baja lentamente los brazos de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing inwards. Bend your knees slightly and hinge forward at the hips, keeping your back straight and chest up. Raise your arms out to the sides, keeping a slight bend in your elbows, until they are parallel to the floor. Rotate your arms so that your palms are facing downwards. Slowly lower your arms back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0386-prbWx1D.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0386-prbWx1D.gif', 'prbWx1D', '© Gym visual — https://gymvisual.com/'),
('2397', 'dumbbell scott press', 'Siéntate en un banco con una mancuerna en cada mano, con las palmas hacia adelante. Sube las mancuernas hasta la altura de los hombros, con los codos flexionados y las palmas hacia adelante. Empuja las mancuernas hacia arriba hasta que los brazos estén completamente extendidos. Haz una pausa breve e', 'shoulders', 'dumbbell', 'shoulders', 'shoulders', 'delts', '{"triceps","chest"}', 'Siéntate en un banco con una mancuerna en cada mano, con las palmas hacia adelante. Sube las mancuernas hasta la altura de los hombros, con los codos flexionados y las palmas hacia adelante. Empuja las mancuernas hacia arriba hasta que los brazos estén completamente extendidos. Haz una pausa breve en la parte alta, luego baja lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a bench with a dumbbell in each hand, palms facing forward. Raise the dumbbells to shoulder height, with your elbows bent and palms facing forward. Press the dumbbells upward until your arms are fully extended. Pause for a moment at the top, then slowly lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2397-5vfAI0I.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2397-5vfAI0I.gif', '5vfAI0I', '© Gym visual — https://gymvisual.com/'),
('0387', 'dumbbell seated alternate front raise', 'Siéntate en un banco con la espalda recta y los pies planos sobre el suelo. Sujeta una mancuerna en cada mano con las palmas hacia tu cuerpo y los brazos extendidos hacia abajo a los lados. Manteniendo los brazos rectos, levanta una mancuerna frente a ti hasta que quede paralela al suelo. Haz una pa', 'shoulders', 'dumbbell', 'shoulders', 'shoulders', 'delts', '{"trapezius","biceps"}', 'Siéntate en un banco con la espalda recta y los pies planos sobre el suelo. Sujeta una mancuerna en cada mano con las palmas hacia tu cuerpo y los brazos extendidos hacia abajo a los lados. Manteniendo los brazos rectos, levanta una mancuerna frente a ti hasta que quede paralela al suelo. Haz una pausa breve en la parte más alta, luego baja lentamente la mancuerna de vuelta a la posición inicial. Repite con el otro brazo. Alterna entre los brazos el número de repeticiones deseado.', 'Sit on a bench with your back straight and feet flat on the ground. Hold a dumbbell in each hand with your palms facing your body and arms extended down by your sides. Keeping your arms straight, raise one dumbbell in front of you until it is parallel to the ground. Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position. Repeat with the other arm. Alternate between arms for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0387-gH5fRsC.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0387-gH5fRsC.gif', 'gH5fRsC', '© Gym visual — https://gymvisual.com/'),
('1676', 'dumbbell seated alternate hammer curl on exercise ball', 'Siéntate sobre un balón de ejercicio con los pies apoyados planos en el suelo y la espalda recta. Sostén una mancuerna en cada mano con las palmas hacia el cuerpo y los brazos completamente extendidos. Manteniendo la parte superior de los brazos fija, exhala y flexiona una mancuerna hacia el hombro ', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Siéntate sobre un balón de ejercicio con los pies apoyados planos en el suelo y la espalda recta. Sostén una mancuerna en cada mano con las palmas hacia el cuerpo y los brazos completamente extendidos. Manteniendo la parte superior de los brazos fija, exhala y flexiona una mancuerna hacia el hombro mientras mantienes la palma hacia tu cuerpo. Continúa levantando la mancuerna hasta que el bíceps esté completamente contraído y la mancuerna esté a la altura del hombro. Mantén la posición contraída durante una breve pausa mientras aprietas los bíceps. Inhala y baja lentamente la mancuerna de vuelta a la posición inicial. Repite el movimiento con el brazo contrario. Continúa alternando los brazos durante el número de repeticiones deseado.', 'Sit on an exercise ball with your feet flat on the ground and your back straight. Hold a dumbbell in each hand with your palms facing your body and your arms fully extended. Keeping your upper arms stationary, exhale and curl one dumbbell up towards your shoulder while keeping your palm facing your body. Continue to raise the dumbbell until your biceps are fully contracted and the dumbbell is at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly lower the dumbbell back to the starting position. Repeat the movement with the opposite arm. Continue alternating arms for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1676-QLRmNeT.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1676-QLRmNeT.gif', 'QLRmNeT', '© Gym visual — https://gymvisual.com/'),
('0388', 'dumbbell seated alternate press', 'Siéntate en un banco con una mancuerna en cada mano, con las palmas hacia adelante. Sube las mancuernas hasta la altura de los hombros, con los codos flexionados y las palmas hacia adelante. Presiona una mancuerna hacia arriba, por encima de la cabeza, extendiendo completamente el brazo. Baja la man', 'shoulders', 'dumbbell', 'shoulders', 'shoulders', 'delts', '{"triceps","chest"}', 'Siéntate en un banco con una mancuerna en cada mano, con las palmas hacia adelante. Sube las mancuernas hasta la altura de los hombros, con los codos flexionados y las palmas hacia adelante. Presiona una mancuerna hacia arriba, por encima de la cabeza, extendiendo completamente el brazo. Baja la mancuerna de vuelta a la altura de los hombros. Repite con el otro brazo. Continúa alternando los brazos durante el número de repeticiones deseado.', 'Sit on a bench with a dumbbell in each hand, palms facing forward. Raise the dumbbells to shoulder height, with your elbows bent and palms facing forward. Press one dumbbell up overhead, fully extending your arm. Lower the dumbbell back down to shoulder height. Repeat with the other arm. Continue alternating arms for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0388-QT5Q0nK.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0388-QT5Q0nK.gif', 'QT5Q0nK', '© Gym visual — https://gymvisual.com/'),
('3546', 'dumbbell seated alternate shoulder', 'Siéntate en un banco con la espalda recta y los pies planos sobre el suelo. Sujeta una mancuerna en cada mano, con las palmas hacia adentro, y levántalas a la altura de los hombros. Presiona una mancuerna hacia arriba, por encima de la cabeza, mientras mantienes la otra mancuerna a la altura de los ', 'shoulders', 'dumbbell', 'shoulders', 'shoulders', 'delts', '{"triceps","upper back"}', 'Siéntate en un banco con la espalda recta y los pies planos sobre el suelo. Sujeta una mancuerna en cada mano, con las palmas hacia adentro, y levántalas a la altura de los hombros. Presiona una mancuerna hacia arriba, por encima de la cabeza, mientras mantienes la otra mancuerna a la altura de los hombros. Baja la mancuerna levantada de vuelta a la altura de los hombros mientras presionas simultáneamente la otra mancuerna por encima de la cabeza. Continúa alternando entre los brazos durante el número de repeticiones deseado.', 'Sit on a bench with your back straight and feet flat on the ground. Hold a dumbbell in each hand, palms facing inwards, and raise them to shoulder height. Press one dumbbell up overhead while keeping the other dumbbell at shoulder height. Lower the raised dumbbell back to shoulder height while simultaneously pressing the other dumbbell up overhead. Continue alternating between arms for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3546-q7qkONO.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3546-q7qkONO.gif', 'q7qkONO', '© Gym visual — https://gymvisual.com/'),
('0389', 'dumbbell seated bench extension', 'Siéntate en un banco con la espalda recta y los pies planos sobre el suelo. Sujeta una mancuerna con ambas manos y extiende los brazos rectos por encima de la cabeza. Baja lentamente la mancuerna detrás de la cabeza, manteniendo los codos cerca de las orejas. Haz una pausa por un momento, luego sube', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'triceps', '{"shoulders"}', 'Siéntate en un banco con la espalda recta y los pies planos sobre el suelo. Sujeta una mancuerna con ambas manos y extiende los brazos rectos por encima de la cabeza. Baja lentamente la mancuerna detrás de la cabeza, manteniendo los codos cerca de las orejas. Haz una pausa por un momento, luego sube la mancuerna de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a bench with your back straight and feet flat on the ground. Hold a dumbbell with both hands and extend your arms straight up above your head. Slowly lower the dumbbell behind your head, keeping your elbows close to your ears. Pause for a moment, then raise the dumbbell back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0389-JhYSVwT.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0389-JhYSVwT.gif', 'JhYSVwT', '© Gym visual — https://gymvisual.com/'),
('2317', 'dumbbell seated bent arm lateral raise', 'Siéntate en un banco con la espalda recta y los pies planos sobre el suelo. Sujeta una mancuerna en cada mano con las palmas hacia tu cuerpo y los brazos flexionados en un ángulo de 90 grados. Manteniendo los codos flexionados, levanta los brazos hacia los lados hasta que queden paralelos al suelo. ', 'shoulders', 'dumbbell', 'shoulders', 'shoulders', 'delts', '{"trapezius","rhomboids"}', 'Siéntate en un banco con la espalda recta y los pies planos sobre el suelo. Sujeta una mancuerna en cada mano con las palmas hacia tu cuerpo y los brazos flexionados en un ángulo de 90 grados. Manteniendo los codos flexionados, levanta los brazos hacia los lados hasta que queden paralelos al suelo. Haz una pausa por un momento en la parte superior, luego baja lentamente los brazos de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a bench with your back straight and feet flat on the ground. Hold a dumbbell in each hand with your palms facing your body and your arms bent at a 90-degree angle. Keeping your elbows bent, raise your arms out to the sides until they are parallel to the ground. Pause for a moment at the top, then slowly lower your arms back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2317-JzQbv7J.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2317-JzQbv7J.gif', 'JzQbv7J', '© Gym visual — https://gymvisual.com/'),
('1730', 'dumbbell seated bent over alternate kickback', 'Siéntate en un banco con una mancuerna en cada mano, con las palmas hacia adentro. Inclínate hacia adelante desde la cintura, manteniendo la espalda recta y paralela al suelo. Extiende un brazo recto hacia atrás, manteniéndolo cerca de tu cuerpo, hasta que el brazo esté completamente extendido. Haz ', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'triceps', '{"shoulders","back"}', 'Siéntate en un banco con una mancuerna en cada mano, con las palmas hacia adentro. Inclínate hacia adelante desde la cintura, manteniendo la espalda recta y paralela al suelo. Extiende un brazo recto hacia atrás, manteniéndolo cerca de tu cuerpo, hasta que el brazo esté completamente extendido. Haz una pausa por un momento, luego baja lentamente la mancuerna de vuelta a la posición inicial. Repite con el otro brazo. Continúa alternando los brazos durante el número de repeticiones deseado.', 'Sit on a bench with a dumbbell in each hand, palms facing inwards. Bend forward at the waist, keeping your back straight and parallel to the ground. Extend one arm straight back, keeping it close to your body, until your arm is fully extended. Pause for a moment, then slowly lower the dumbbell back to the starting position. Repeat with the other arm. Continue alternating arms for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1730-x0lwvfq.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1730-x0lwvfq.gif', 'x0lwvfq', '© Gym visual — https://gymvisual.com/'),
('1737', 'dumbbell seated bent over triceps extension', 'Siéntate en un banco con los pies apoyados en el suelo y sujeta una mancuerna en cada mano. Inclínate hacia adelante desde la cintura, manteniendo la espalda recta y la cabeza erguida. Extiende los brazos rectos hacia atrás, manteniendo los codos cerca de la cabeza. Haz una pausa por un momento, lue', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'triceps', '{"shoulders","back"}', 'Siéntate en un banco con los pies apoyados en el suelo y sujeta una mancuerna en cada mano. Inclínate hacia adelante desde la cintura, manteniendo la espalda recta y la cabeza erguida. Extiende los brazos rectos hacia atrás, manteniendo los codos cerca de la cabeza. Haz una pausa por un momento, luego baja lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a bench with your feet flat on the ground and hold a dumbbell in each hand. Bend forward at the waist, keeping your back straight and your head up. Extend your arms straight back, keeping your elbows close to your head. Pause for a moment, then slowly lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1737-4ievMJ9.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1737-4ievMJ9.gif', '4ievMJ9', '© Gym visual — https://gymvisual.com/'),
('1677', 'dumbbell seated bicep curl', 'Siéntate en un banco con los pies apoyados en el suelo y sostén una mancuerna en cada mano, con las palmas hacia arriba. Mantén la espalda recta y los codos cerca del torso. Exhala y flexiona las mancuernas hacia los hombros, contrayendo los bíceps. Haz una pausa por un momento en la parte superior,', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Siéntate en un banco con los pies apoyados en el suelo y sostén una mancuerna en cada mano, con las palmas hacia arriba. Mantén la espalda recta y los codos cerca del torso. Exhala y flexiona las mancuernas hacia los hombros, contrayendo los bíceps. Haz una pausa por un momento en la parte superior, luego inhala y baja lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a bench with your feet flat on the ground and hold a dumbbell in each hand, palms facing up. Keep your back straight and your elbows close to your torso. Exhale and curl the dumbbells up towards your shoulders, contracting your biceps. Pause for a moment at the top, then inhale and slowly lower the dumbbells back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1677-xiA6lRr.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1677-xiA6lRr.gif', 'xiA6lRr', '© Gym visual — https://gymvisual.com/'),
('0390', 'dumbbell seated biceps curl (on stability ball)', 'Siéntate sobre un balón de estabilidad con los pies apoyados en el suelo y la espalda recta. Sujeta una mancuerna en cada mano con las palmas hacia adelante y los brazos completamente extendidos. Manteniendo los brazos superiores quietos, exhala y flexiona las mancuernas contrayendo los bíceps. Cont', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Siéntate sobre un balón de estabilidad con los pies apoyados en el suelo y la espalda recta. Sujeta una mancuerna en cada mano con las palmas hacia adelante y los brazos completamente extendidos. Manteniendo los brazos superiores quietos, exhala y flexiona las mancuernas contrayendo los bíceps. Continúa levantando las mancuernas hasta que los bíceps estén completamente contraídos y las mancuernas estén a la altura de los hombros. Mantén la posición contraída durante una breve pausa mientras aprietas los bíceps. Inhala y comienza a bajar lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a stability ball with your feet flat on the ground and your back straight. Hold a dumbbell in each hand with your palms facing forward and your arms fully extended. Keeping your upper arms stationary, exhale and curl the dumbbells while contracting your biceps. Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly begin to lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0390-WgJnBH5.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0390-WgJnBH5.gif', 'WgJnBH5', '© Gym visual — https://gymvisual.com/'),
('3547', 'dumbbell seated biceps curl to shoulder press', 'Siéntate en un banco con la espalda recta y los pies planos sobre el suelo. Sujeta una mancuerna en cada mano con las palmas hacia adelante y los brazos completamente extendidos. Manteniendo los codos cerca de tus costados, flexiona las mancuernas hacia los hombros. Una vez que tus antebrazos estén ', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"shoulders"}', 'Siéntate en un banco con la espalda recta y los pies planos sobre el suelo. Sujeta una mancuerna en cada mano con las palmas hacia adelante y los brazos completamente extendidos. Manteniendo los codos cerca de tus costados, flexiona las mancuernas hacia los hombros. Una vez que tus antebrazos estén verticales, gira las muñecas de modo que las palmas queden hacia adelante. Presiona las mancuernas por encima de la cabeza hasta que los brazos estén completamente extendidos. Baja las mancuernas de vuelta a la posición inicial invirtiendo el movimiento. Repite el número de repeticiones deseado.', 'Sit on a bench with your back straight and feet flat on the ground. Hold a dumbbell in each hand with your palms facing forward and arms fully extended. Keeping your elbows close to your sides, curl the dumbbells up towards your shoulders. Once your forearms are vertical, rotate your wrists so that your palms are facing forward. Press the dumbbells overhead until your arms are fully extended. Lower the dumbbells back down to the starting position by reversing the movement. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3547-OeL23VY.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3547-OeL23VY.gif', 'OeL23VY', '© Gym visual — https://gymvisual.com/'),
('1379', 'dumbbell seated calf raise', 'Siéntate en un banco o silla con los pies apoyados en el suelo y una mancuerna apoyada sobre los muslos. Coloca la punta de los pies sobre una superficie elevada, como un escalón o un bloque, con los talones colgando del borde. Sujétate de la mancuerna para mantener la estabilidad. Levanta los talon', 'lower legs', 'dumbbell', 'lower legs', 'lower legs', 'calves', '{"hamstrings"}', 'Siéntate en un banco o silla con los pies apoyados en el suelo y una mancuerna apoyada sobre los muslos. Coloca la punta de los pies sobre una superficie elevada, como un escalón o un bloque, con los talones colgando del borde. Sujétate de la mancuerna para mantener la estabilidad. Levanta los talones lo más alto posible, elevando el peso de tu cuerpo sobre las puntas de los pies. Haz una pausa breve en la parte alta y luego baja lentamente los talones de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a bench or chair with your feet flat on the ground and a dumbbell resting on your thighs. Place the balls of your feet on a raised surface such as a step or block, with your heels hanging off the edge. Hold onto the dumbbell for stability. Raise your heels as high as possible, lifting your body weight onto the balls of your feet. Pause for a moment at the top, then slowly lower your heels back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1379-r29jP7S.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1379-r29jP7S.gif', 'r29jP7S', '© Gym visual — https://gymvisual.com/'),
('0391', 'dumbbell seated curl', 'Siéntate en un banco con los pies apoyados en el suelo y una mancuerna en cada mano, con las palmas hacia adelante. Mantén la espalda recta y los codos cerca del torso. Exhala y flexiona las mancuernas hacia los hombros, contrayendo los bíceps. Haz una pausa por un momento en la parte superior, lueg', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Siéntate en un banco con los pies apoyados en el suelo y una mancuerna en cada mano, con las palmas hacia adelante. Mantén la espalda recta y los codos cerca del torso. Exhala y flexiona las mancuernas hacia los hombros, contrayendo los bíceps. Haz una pausa por un momento en la parte superior, luego inhala y baja lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a bench with your feet flat on the ground and a dumbbell in each hand, palms facing forward. Keep your back straight and your elbows close to your torso. Exhale and curl the dumbbells up towards your shoulders, contracting your biceps. Pause for a moment at the top, then inhale and slowly lower the dumbbells back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0391-TiaZTxx.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0391-TiaZTxx.gif', 'TiaZTxx', '© Gym visual — https://gymvisual.com/'),
('0392', 'dumbbell seated front raise', 'Siéntate en un banco con los pies apoyados en el suelo y una mancuerna en cada mano, apoyadas sobre los muslos. Mantén la espalda recta y el core activado. Levanta las mancuernas frente a ti, con las palmas hacia abajo, hasta que queden a la altura de los hombros. Haz una pausa breve en la parte alt', 'shoulders', 'dumbbell', 'shoulders', 'shoulders', 'delts', '{"trapezius","biceps"}', 'Siéntate en un banco con los pies apoyados en el suelo y una mancuerna en cada mano, apoyadas sobre los muslos. Mantén la espalda recta y el core activado. Levanta las mancuernas frente a ti, con las palmas hacia abajo, hasta que queden a la altura de los hombros. Haz una pausa breve en la parte alta, luego baja lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a bench with your feet flat on the ground and a dumbbell in each hand, resting on your thighs. Keep your back straight and core engaged. Raise the dumbbells in front of you, with your palms facing down, until they are at shoulder level. Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0392-Ys97II0.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0392-Ys97II0.gif', 'Ys97II0', '© Gym visual — https://gymvisual.com/'),
('1678', 'dumbbell seated hammer curl', 'Siéntate en un banco con una mancuerna en cada mano, con las palmas hacia tu torso y los brazos extendidos rectos hacia abajo. Manteniendo los brazos superiores fijos, exhala y levanta el peso mientras contraes los bíceps. Continúa levantando las mancuernas hasta que los bíceps estén completamente c', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Siéntate en un banco con una mancuerna en cada mano, con las palmas hacia tu torso y los brazos extendidos rectos hacia abajo. Manteniendo los brazos superiores fijos, exhala y levanta el peso mientras contraes los bíceps. Continúa levantando las mancuernas hasta que los bíceps estén completamente contraídos y las mancuernas estén a la altura de los hombros. Mantén la posición contraída durante una breve pausa mientras aprietas los bíceps. Inhala y comienza a bajar lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a bench with a dumbbell in each hand, palms facing your torso and arms extended straight down. Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly begin to lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1678-IGtBdNT.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1678-IGtBdNT.gif', 'IGtBdNT', '© Gym visual — https://gymvisual.com/'),
('0393', 'dumbbell seated inner biceps curl', 'Siéntate en un banco con los pies apoyados en el suelo y sostén una mancuerna en cada mano, con las palmas hacia arriba. Apoya la parte superior de los brazos sobre los muslos, dejando que las mancuernas cuelguen hacia abajo. Manteniendo la parte superior de los brazos fija, flexiona las mancuernas ', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Siéntate en un banco con los pies apoyados en el suelo y sostén una mancuerna en cada mano, con las palmas hacia arriba. Apoya la parte superior de los brazos sobre los muslos, dejando que las mancuernas cuelguen hacia abajo. Manteniendo la parte superior de los brazos fija, flexiona las mancuernas hacia los hombros contrayendo los bíceps. Haz una pausa breve en la parte alta, luego baja lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a bench with your feet flat on the ground and hold a dumbbell in each hand, palms facing up. Rest your upper arms on your thighs, allowing the dumbbells to hang down. Keeping your upper arms stationary, curl the dumbbells up towards your shoulders by contracting your biceps. Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0393-KXyoEtA.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0393-KXyoEtA.gif', 'KXyoEtA', '© Gym visual — https://gymvisual.com/'),
('0394', 'dumbbell seated kickback', 'Siéntate en un banco con los pies apoyados en el suelo y sujeta una mancuerna en cada mano. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta. Acerca la parte superior de los brazos a tus costados y mantén los codos flexionados en un ángulo ', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'triceps', '{"shoulders"}', 'Siéntate en un banco con los pies apoyados en el suelo y sujeta una mancuerna en cada mano. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta. Acerca la parte superior de los brazos a tus costados y mantén los codos flexionados en un ángulo de 90 grados. Extiende los brazos rectos hacia atrás, contrayendo los tríceps en la parte superior del movimiento. Haz una pausa por un momento, luego baja lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a bench with your feet flat on the ground and hold a dumbbell in each hand. Bend your knees slightly and lean forward from your hips, keeping your back straight. Bring your upper arms close to your sides and keep your elbows bent at a 90-degree angle. Extend your arms straight back, squeezing your triceps at the top of the movement. Pause for a moment, then slowly lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0394-en550rk.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0394-en550rk.gif', 'en550rk', '© Gym visual — https://gymvisual.com/'),
('0396', 'dumbbell seated lateral raise', 'Siéntate en un banco con los pies apoyados en el suelo y una mancuerna en cada mano, apoyadas sobre los muslos. Mantén la espalda recta y el core activado. Levanta las mancuernas hacia los lados con una ligera flexión en los codos, hasta que tus brazos queden paralelos al suelo. Haz una pausa breve ', 'shoulders', 'dumbbell', 'shoulders', 'shoulders', 'delts', '{"traps","upper back"}', 'Siéntate en un banco con los pies apoyados en el suelo y una mancuerna en cada mano, apoyadas sobre los muslos. Mantén la espalda recta y el core activado. Levanta las mancuernas hacia los lados con una ligera flexión en los codos, hasta que tus brazos queden paralelos al suelo. Haz una pausa breve en la parte alta, luego baja lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a bench with your feet flat on the ground and a dumbbell in each hand, resting on your thighs. Keep your back straight and core engaged. Raise the dumbbells to your sides with a slight bend in your elbows, until your arms are parallel to the ground. Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0396-hxyTtWj.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0396-hxyTtWj.gif', 'hxyTtWj', '© Gym visual — https://gymvisual.com/'),
('0395', 'dumbbell seated lateral raise v. 2', 'Siéntate en un banco con los pies apoyados en el suelo y una mancuerna en cada mano, apoyadas sobre los muslos. Mantén la espalda recta y el core activado. Levanta las mancuernas hacia los lados con una ligera flexión en los codos, hasta que tus brazos queden paralelos al suelo. Haz una pausa breve ', 'shoulders', 'dumbbell', 'shoulders', 'shoulders', 'delts', '{"traps","triceps"}', 'Siéntate en un banco con los pies apoyados en el suelo y una mancuerna en cada mano, apoyadas sobre los muslos. Mantén la espalda recta y el core activado. Levanta las mancuernas hacia los lados con una ligera flexión en los codos, hasta que tus brazos queden paralelos al suelo. Haz una pausa breve en la parte alta, luego baja lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a bench with your feet flat on the ground and a dumbbell in each hand, resting on your thighs. Keep your back straight and core engaged. Raise the dumbbells to your sides with a slight bend in your elbows, until your arms are parallel to the ground. Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0395-hrrS0Ed.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0395-hrrS0Ed.gif', 'hrrS0Ed', '© Gym visual — https://gymvisual.com/'),
('0397', 'dumbbell seated neutral wrist curl', 'Siéntate en un banco con los pies apoyados en el suelo y sujeta una mancuerna en cada mano, con las palmas mirándose entre sí. Apoya los antebrazos sobre los muslos, dejando que las mancuernas cuelguen hacia abajo. Manteniendo las muñecas en posición neutra, flexiona las mancuernas hacia los hombros', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Siéntate en un banco con los pies apoyados en el suelo y sujeta una mancuerna en cada mano, con las palmas mirándose entre sí. Apoya los antebrazos sobre los muslos, dejando que las mancuernas cuelguen hacia abajo. Manteniendo las muñecas en posición neutra, flexiona las mancuernas hacia los hombros. Haz una pausa breve en la parte alta, luego baja lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a bench with your feet flat on the ground and hold a dumbbell in each hand, palms facing each other. Rest your forearms on your thighs, allowing the dumbbells to hang down. Keeping your wrists in a neutral position, curl the dumbbells up towards your shoulders. Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0397-uJmK7Z1.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0397-uJmK7Z1.gif', 'uJmK7Z1', '© Gym visual — https://gymvisual.com/'),
('1679', 'dumbbell seated one arm bicep curl on exercise ball with leg raised', 'Siéntate sobre un balón de ejercicio con los pies apoyados planos en el suelo y la espalda recta. Sostén una mancuerna en una mano con la palma hacia arriba y el brazo completamente extendido. Coloca la otra mano en la cadera para mantener el equilibrio. Flexiona lentamente la mancuerna hacia tu hom', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms","shoulders"}', 'Siéntate sobre un balón de ejercicio con los pies apoyados planos en el suelo y la espalda recta. Sostén una mancuerna en una mano con la palma hacia arriba y el brazo completamente extendido. Coloca la otra mano en la cadera para mantener el equilibrio. Flexiona lentamente la mancuerna hacia tu hombro, manteniendo fija la parte superior del brazo. Haz una pausa por un momento en la parte más alta del movimiento, apretando el bíceps. Baja lentamente la mancuerna de vuelta a la posición inicial. Repite el número de repeticiones deseado. Cambia de brazo y repite el ejercicio.', 'Sit on an exercise ball with your feet flat on the ground and your back straight. Hold a dumbbell in one hand with your palm facing up and your arm fully extended. Place your other hand on your hip for stability. Slowly curl the dumbbell towards your shoulder, keeping your upper arm stationary. Pause for a moment at the top of the movement, squeezing your bicep. Slowly lower the dumbbell back to the starting position. Repeat for the desired number of repetitions. Switch arms and repeat the exercise.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1679-84sESNy.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1679-84sESNy.gif', '84sESNy', '© Gym visual — https://gymvisual.com/'),
('0398', 'dumbbell seated one arm kickback', 'Siéntate en un banco con los pies apoyados en el suelo y sujeta una mancuerna con una mano. Inclina el torso hacia adelante desde la cintura, manteniendo la espalda recta y paralela al suelo. Extiende el brazo recto hacia atrás, manteniendo el codo cerca de tu cuerpo. Haz una pausa breve en la parte', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'triceps', '{"shoulders"}', 'Siéntate en un banco con los pies apoyados en el suelo y sujeta una mancuerna con una mano. Inclina el torso hacia adelante desde la cintura, manteniendo la espalda recta y paralela al suelo. Extiende el brazo recto hacia atrás, manteniendo el codo cerca de tu cuerpo. Haz una pausa breve en la parte más alta, luego baja lentamente la mancuerna de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia de brazo.', 'Sit on a bench with your feet flat on the ground and hold a dumbbell in one hand. Bend your torso forward at the waist, keeping your back straight and parallel to the ground. Extend your arm straight back, keeping your elbow close to your body. Pause for a moment at the top, then slowly lower the dumbbell back to the starting position. Repeat for the desired number of repetitions, then switch arms.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0398-VQ3sNCn.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0398-VQ3sNCn.gif', 'VQ3sNCn', '© Gym visual — https://gymvisual.com/'),
('0399', 'dumbbell seated one arm rotate', 'Siéntate en un banco con la espalda recta y sujeta una mancuerna con una mano, apoyándola sobre el muslo. Sube la mancuerna hasta la altura del hombro, manteniendo el codo cerca de tu cuerpo. Gira el antebrazo hacia afuera, alejándolo de tu cuerpo, mientras mantienes fija la parte superior del brazo', 'lower arms', 'dumbbell', 'lower arms', 'lower arms', 'forearms', '{"shoulders","biceps"}', 'Siéntate en un banco con la espalda recta y sujeta una mancuerna con una mano, apoyándola sobre el muslo. Sube la mancuerna hasta la altura del hombro, manteniendo el codo cerca de tu cuerpo. Gira el antebrazo hacia afuera, alejándolo de tu cuerpo, mientras mantienes fija la parte superior del brazo. Haz una pausa por un momento en la parte superior, luego gira lentamente el antebrazo de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia al otro brazo.', 'Sit on a bench with your back straight and hold a dumbbell in one hand, resting it on your thigh. Raise the dumbbell up to shoulder height, keeping your elbow close to your body. Rotate your forearm outward, away from your body, while keeping your upper arm stationary. Pause for a moment at the top, then slowly rotate your forearm back to the starting position. Repeat for the desired number of repetitions, then switch to the other arm.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0399-7f2jsqP.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0399-7f2jsqP.gif', '7f2jsqP', '© Gym visual — https://gymvisual.com/'),
('0400', 'dumbbell seated one leg calf raise', 'Siéntate en un banco o silla con los pies apoyados en el suelo y una mancuerna apoyada sobre el muslo derecho. Extiende la pierna izquierda recta hacia adelante, manteniendo el pie flexionado. Coloca la punta del pie derecho sobre una superficie elevada, como un escalón o un disco de peso. Usando lo', 'lower legs', 'dumbbell', 'lower legs', 'lower legs', 'calves', '{"hamstrings","glutes"}', 'Siéntate en un banco o silla con los pies apoyados en el suelo y una mancuerna apoyada sobre el muslo derecho. Extiende la pierna izquierda recta hacia adelante, manteniendo el pie flexionado. Coloca la punta del pie derecho sobre una superficie elevada, como un escalón o un disco de peso. Usando los músculos de la pantorrilla, eleva el talón derecho lo más alto posible. Haz una pausa por un momento en la parte superior, luego baja lentamente el talón de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia de pierna.', 'Sit on a bench or chair with your feet flat on the ground and a dumbbell resting on your right thigh. Extend your left leg straight out in front of you, keeping your foot flexed. Place the ball of your right foot on an elevated surface, such as a step or weight plate. Using your calf muscles, raise your right heel as high as possible. Pause for a moment at the top, then slowly lower your heel back down to the starting position. Repeat for the desired number of repetitions, then switch legs.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0400-Ia7tumC.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0400-Ia7tumC.gif', 'Ia7tumC', '© Gym visual — https://gymvisual.com/'),
('1380', 'dumbbell seated one leg calf raise - hammer grip', 'Siéntate en un banco o silla con los pies apoyados en el suelo y una mancuerna apoyada sobre los muslos. Coloca un pie sobre una superficie elevada, como un escalón o un bloque, con el talón colgando del borde. Sujeta la mancuerna con agarre neutro, es decir, con las palmas mirándose entre sí y los ', 'lower legs', 'dumbbell', 'lower legs', 'lower legs', 'calves', '{"hamstrings","glutes"}', 'Siéntate en un banco o silla con los pies apoyados en el suelo y una mancuerna apoyada sobre los muslos. Coloca un pie sobre una superficie elevada, como un escalón o un bloque, con el talón colgando del borde. Sujeta la mancuerna con agarre neutro, es decir, con las palmas mirándose entre sí y los dedos envolviendo la barra. Manteniendo el core activado y la espalda recta, eleva lentamente el talón lo más alto posible empujando con la punta del pie. Haz una pausa por un momento en la parte superior, luego baja lentamente el talón de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia a la otra pierna.', 'Sit on a bench or chair with your feet flat on the ground and a dumbbell resting on your thighs. Place one foot on a raised surface, such as a step or block, with your heel hanging off the edge. Hold the dumbbell with a hammer grip, meaning your palms are facing each other and your fingers are wrapped around the handle. Keeping your core engaged and your back straight, slowly raise your heel as high as possible by pushing through the ball of your foot. Pause for a moment at the top, then slowly lower your heel back down to the starting position. Repeat for the desired number of repetitions, then switch to the other leg.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1380-FxhcxUW.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1380-FxhcxUW.gif', 'FxhcxUW', '© Gym visual — https://gymvisual.com/'),
('1381', 'dumbbell seated one leg calf raise - palm up', 'Siéntate en un banco o silla con la espalda recta y los pies apoyados en el suelo. Sujeta una mancuerna con una mano y colócala sobre el muslo, con la palma hacia arriba. Levanta una pierna del suelo y extiéndela frente a ti, manteniendo la rodilla ligeramente flexionada. Eleva el talón lo más alto ', 'lower legs', 'dumbbell', 'lower legs', 'lower legs', 'calves', '{"hamstrings","glutes"}', 'Siéntate en un banco o silla con la espalda recta y los pies apoyados en el suelo. Sujeta una mancuerna con una mano y colócala sobre el muslo, con la palma hacia arriba. Levanta una pierna del suelo y extiéndela frente a ti, manteniendo la rodilla ligeramente flexionada. Eleva el talón lo más alto posible empujando con la punta del pie. Haz una pausa por un momento en la parte superior, luego baja lentamente el talón de vuelta hacia abajo. Repite el número de repeticiones deseado y luego cambia de pierna y repite.', 'Sit on a bench or chair with your back straight and your feet flat on the ground. Hold a dumbbell in one hand and place it on top of your thigh, palm facing up. Lift one leg off the ground and extend it in front of you, keeping your knee slightly bent. Raise your heel as high as possible by pushing through the ball of your foot. Pause for a moment at the top, then slowly lower your heel back down. Repeat for the desired number of repetitions, then switch legs and repeat.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1381-VW88JNd.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1381-VW88JNd.gif', 'VW88JNd', '© Gym visual — https://gymvisual.com/'),
('0401', 'dumbbell seated palms up wrist curl', 'Siéntate en un banco con los pies apoyados en el suelo y sostén una mancuerna en cada mano, con las palmas hacia arriba. Apoya los antebrazos sobre los muslos, dejando que las muñecas cuelguen del borde. Flexiona lentamente las muñecas hacia arriba, apretando los antebrazos en la parte superior del ', 'lower arms', 'dumbbell', 'lower arms', 'lower arms', 'forearms', '{"biceps","shoulders"}', 'Siéntate en un banco con los pies apoyados en el suelo y sostén una mancuerna en cada mano, con las palmas hacia arriba. Apoya los antebrazos sobre los muslos, dejando que las muñecas cuelguen del borde. Flexiona lentamente las muñecas hacia arriba, apretando los antebrazos en la parte superior del movimiento. Haz una pausa por un momento y luego baja las muñecas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a bench with your feet flat on the ground and hold a dumbbell in each hand, palms facing up. Rest your forearms on your thighs, allowing your wrists to hang off the edge. Slowly curl your wrists upward, squeezing your forearms at the top of the movement. Pause for a moment, then lower your wrists back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0401-2dImyQ8.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0401-2dImyQ8.gif', '2dImyQ8', '© Gym visual — https://gymvisual.com/'),
('0402', 'dumbbell seated preacher curl', 'Siéntate en un banco scott con los pies apoyados en el suelo. Sujeta una mancuerna con una mano con agarre supino, apoyando la parte superior del brazo en la almohadilla del banco scott. Manteniendo el brazo superior quieto, exhala y flexiona la mancuerna hacia el hombro. Haz una pausa por un moment', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Siéntate en un banco scott con los pies apoyados en el suelo. Sujeta una mancuerna con una mano con agarre supino, apoyando la parte superior del brazo en la almohadilla del banco scott. Manteniendo el brazo superior quieto, exhala y flexiona la mancuerna hacia el hombro. Haz una pausa por un momento en la parte superior, luego inhala y baja lentamente la mancuerna de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia de brazo.', 'Sit on a preacher curl bench with your feet flat on the floor. Hold a dumbbell in one hand with an underhand grip, resting your upper arm against the preacher pad. Keeping your upper arm stationary, exhale and curl the dumbbell up towards your shoulder. Pause for a moment at the top, then inhale and slowly lower the dumbbell back down to the starting position. Repeat for the desired number of repetitions, then switch arms.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0402-7D5bgLT.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0402-7D5bgLT.gif', '7D5bgLT', '© Gym visual — https://gymvisual.com/'),
('0403', 'dumbbell seated revers grip concentration curl', 'Siéntate en un banco con los pies apoyados en el suelo y sostén una mancuerna en una mano, con la palma hacia arriba. Apoya el codo en la parte interna del muslo, justo por encima de la rodilla. Manteniendo el brazo superior quieto, exhala y flexiona la mancuerna hacia el hombro. Haz una pausa breve', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Siéntate en un banco con los pies apoyados en el suelo y sostén una mancuerna en una mano, con la palma hacia arriba. Apoya el codo en la parte interna del muslo, justo por encima de la rodilla. Manteniendo el brazo superior quieto, exhala y flexiona la mancuerna hacia el hombro. Haz una pausa breve en la parte alta, apretando los bíceps. Inhala y baja lentamente la mancuerna de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia de brazo.', 'Sit on a bench with your feet flat on the ground and hold a dumbbell in one hand, palm facing up. Rest your elbow on the inside of your thigh, just above the knee. Keeping your upper arm stationary, exhale and curl the dumbbell towards your shoulder. Pause for a moment at the top, squeezing your biceps. Inhale and slowly lower the dumbbell back to the starting position. Repeat for the desired number of repetitions, then switch arms.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0403-lyKCLmK.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0403-lyKCLmK.gif', 'lyKCLmK', '© Gym visual — https://gymvisual.com/'),
('1738', 'dumbbell seated reverse grip one arm overhead tricep extension', 'Siéntate en un banco con la espalda recta y los pies planos sobre el suelo. Sujeta una mancuerna con agarre supino y extiende el brazo recto por encima de la cabeza. Baja la mancuerna detrás de la cabeza flexionando el codo, manteniendo el brazo superior quieto. Haz una pausa por un momento, luego e', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'triceps', '{"shoulders"}', 'Siéntate en un banco con la espalda recta y los pies planos sobre el suelo. Sujeta una mancuerna con agarre supino y extiende el brazo recto por encima de la cabeza. Baja la mancuerna detrás de la cabeza flexionando el codo, manteniendo el brazo superior quieto. Haz una pausa por un momento, luego extiende el brazo de vuelta hacia arriba, hasta la posición inicial. Repite el número de repeticiones deseado, luego cambia de brazo.', 'Sit on a bench with your back straight and feet flat on the ground. Hold a dumbbell with an underhand grip and extend your arm straight up overhead. Lower the dumbbell behind your head by bending your elbow, keeping your upper arm stationary. Pause for a moment, then extend your arm back up to the starting position. Repeat for the desired number of repetitions, then switch arms.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1738-5fKX7wi.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1738-5fKX7wi.gif', '5fKX7wi', '© Gym visual — https://gymvisual.com/'),
('0405', 'dumbbell seated shoulder press', 'Siéntate en un banco con una mancuerna en cada mano, apoyadas en los muslos. Sube las mancuernas hasta la altura de los hombros, con las palmas hacia adelante. Presiona las mancuernas hacia arriba hasta que los brazos queden completamente extendidos por encima de la cabeza. Haz una pausa por un mome', 'shoulders', 'dumbbell', 'shoulders', 'shoulders', 'delts', '{"triceps","upper back"}', 'Siéntate en un banco con una mancuerna en cada mano, apoyadas en los muslos. Sube las mancuernas hasta la altura de los hombros, con las palmas hacia adelante. Presiona las mancuernas hacia arriba hasta que los brazos queden completamente extendidos por encima de la cabeza. Haz una pausa por un momento en la parte superior, luego baja lentamente las mancuernas de vuelta a la altura de los hombros. Repite el número de repeticiones deseado.', 'Sit on a bench with a dumbbell in each hand, resting on your thighs. Raise the dumbbells to shoulder height, palms facing forward. Press the dumbbells upward until your arms are fully extended overhead. Pause for a moment at the top, then slowly lower the dumbbells back to shoulder height. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0405-znQUdHY.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0405-znQUdHY.gif', 'znQUdHY', '© Gym visual — https://gymvisual.com/'),
('0404', 'dumbbell seated shoulder press (parallel grip)', 'Siéntate en un banco con una mancuerna en cada mano, con las palmas hacia adentro. Sube las mancuernas hasta la altura de los hombros, con los codos flexionados y las palmas hacia adelante. Presiona las mancuernas hacia arriba hasta que los brazos queden completamente extendidos por encima de la cab', 'shoulders', 'dumbbell', 'shoulders', 'shoulders', 'delts', '{"triceps","upper back"}', 'Siéntate en un banco con una mancuerna en cada mano, con las palmas hacia adentro. Sube las mancuernas hasta la altura de los hombros, con los codos flexionados y las palmas hacia adelante. Presiona las mancuernas hacia arriba hasta que los brazos queden completamente extendidos por encima de la cabeza. Haz una pausa por un momento en la parte superior, luego baja lentamente las mancuernas de vuelta a la altura de los hombros. Repite el número de repeticiones deseado.', 'Sit on a bench with a dumbbell in each hand, palms facing inward. Raise the dumbbells to shoulder height, elbows bent and palms facing forward. Press the dumbbells upward until your arms are fully extended overhead. Pause for a moment at the top, then slowly lower the dumbbells back to shoulder height. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0404-f1jf47L.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0404-f1jf47L.gif', 'f1jf47L', '© Gym visual — https://gymvisual.com/'),
('2188', 'dumbbell seated triceps extension', 'Siéntate en un banco con la espalda recta y los pies planos sobre el suelo. Sujeta una mancuerna con ambas manos y extiende los brazos rectos por encima de la cabeza. Flexiona los codos y baja la mancuerna detrás de la cabeza, manteniendo la parte superior de los brazos cerca de las orejas. Haz una ', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'triceps', '{"shoulders"}', 'Siéntate en un banco con la espalda recta y los pies planos sobre el suelo. Sujeta una mancuerna con ambas manos y extiende los brazos rectos por encima de la cabeza. Flexiona los codos y baja la mancuerna detrás de la cabeza, manteniendo la parte superior de los brazos cerca de las orejas. Haz una pausa por un momento, luego endereza los brazos y vuelve a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a bench with your back straight and feet flat on the ground. Hold a dumbbell with both hands and extend your arms straight up overhead. Bend your elbows and lower the dumbbell behind your head, keeping your upper arms close to your ears. Pause for a moment, then straighten your arms and return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2188-kont8Ut.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2188-kont8Ut.gif', 'kont8Ut', '© Gym visual — https://gymvisual.com/'),
('0406', 'dumbbell shrug', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una mancuerna en cada mano con las palmas hacia tu cuerpo. Mantén los brazos rectos y deja que las mancuernas cuelguen a tus costados. Eleva los hombros lo más alto posible, como si intentaras tocarte las orejas con ellos. Manté', 'back', 'dumbbell', 'back', 'back', 'traps', '{"shoulders"}', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una mancuerna en cada mano con las palmas hacia tu cuerpo. Mantén los brazos rectos y deja que las mancuernas cuelguen a tus costados. Eleva los hombros lo más alto posible, como si intentaras tocarte las orejas con ellos. Mantén la contracción durante un segundo, luego baja lentamente los hombros de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and hold a dumbbell in each hand with your palms facing your body. Keep your arms straight and let the dumbbells hang by your sides. Raise your shoulders as high as possible, as if you are trying to touch your ears with your shoulders. Hold the contraction for a second, then slowly lower your shoulders back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0406-NJzBsGJ.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0406-NJzBsGJ.gif', 'NJzBsGJ', '© Gym visual — https://gymvisual.com/'),
('0407', 'dumbbell side bend', 'Ponte de pie con la espalda recta y los pies separados a la altura de los hombros, sujetando una mancuerna con una mano y dejando que cuelgue a tu costado. Manteniendo la espalda recta y el core activado, inclínate lentamente hacia el lado opuesto de la mancuerna, bajando el peso tanto como te sea p', 'waist', 'dumbbell', 'waist', 'waist', 'abs', '{"obliques"}', 'Ponte de pie con la espalda recta y los pies separados a la altura de los hombros, sujetando una mancuerna con una mano y dejando que cuelgue a tu costado. Manteniendo la espalda recta y el core activado, inclínate lentamente hacia el lado opuesto de la mancuerna, bajando el peso tanto como te sea posible con comodidad. Haz una pausa por un momento, luego regresa lentamente a la posición inicial. Repite el número de repeticiones deseado, luego cambia de lado y repite.', 'Stand up straight with your feet shoulder-width apart and hold a dumbbell in one hand, letting it hang down by your side. Keeping your back straight and your core engaged, slowly bend sideways at the waist towards the opposite side of the dumbbell, lowering the weight as far as you comfortably can. Pause for a moment, then slowly return to the starting position. Repeat for the desired number of repetitions, then switch sides and repeat.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0407-IpONWYv.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0407-IpONWYv.gif', 'IpONWYv', '© Gym visual — https://gymvisual.com/'),
('0408', 'dumbbell side lying one hand raise', 'Túmbate de lado con las piernas extendidas y la cabeza apoyada sobre el brazo. Sujeta una mancuerna con la mano de arriba, con la palma hacia abajo. Manteniendo el brazo recto, sube la mancuerna hasta la altura del hombro. Haz una pausa breve en la parte más alta, luego baja lentamente la mancuerna ', 'shoulders', 'dumbbell', 'shoulders', 'shoulders', 'delts', '{"trapezius","rhomboids"}', 'Túmbate de lado con las piernas extendidas y la cabeza apoyada sobre el brazo. Sujeta una mancuerna con la mano de arriba, con la palma hacia abajo. Manteniendo el brazo recto, sube la mancuerna hasta la altura del hombro. Haz una pausa breve en la parte más alta, luego baja lentamente la mancuerna de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia de lado.', 'Lie on your side with your legs extended and your head supported by your arm. Hold a dumbbell in your top hand with your palm facing down. Keeping your arm straight, raise the dumbbell up to shoulder height. Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position. Repeat for the desired number of repetitions, then switch sides.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0408-fTlkJop.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0408-fTlkJop.gif', 'fTlkJop', '© Gym visual — https://gymvisual.com/'),
('3664', 'dumbbell side plank with rear fly', 'Comienza tumbado de lado con las piernas extendidas y apiladas una sobre la otra. Coloca el antebrazo en el suelo, justo debajo del hombro, manteniendo el codo flexionado en un ángulo de 90 grados. Sujeta una mancuerna con la mano de arriba, con el brazo extendido recto hacia el suelo. Activa el cor', 'back', 'dumbbell', 'back', 'back', 'upper back', '{"shoulders","core"}', 'Comienza tumbado de lado con las piernas extendidas y apiladas una sobre la otra. Coloca el antebrazo en el suelo, justo debajo del hombro, manteniendo el codo flexionado en un ángulo de 90 grados. Sujeta una mancuerna con la mano de arriba, con el brazo extendido recto hacia el suelo. Activa el core y levanta las caderas del suelo, formando una línea recta desde la cabeza hasta los talones. Manteniendo la posición de plancha lateral, levanta la mancuerna hacia el techo, apretando los omóplatos entre sí. Baja la mancuerna de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia de lado.', 'Start by lying on your side with your legs extended and stacked on top of each other. Place your forearm on the ground directly below your shoulder, keeping your elbow bent at a 90-degree angle. Hold a dumbbell in your top hand, with your arm extended straight down towards the ground. Engage your core and lift your hips off the ground, creating a straight line from your head to your heels. While maintaining the side plank position, lift the dumbbell up towards the ceiling, squeezing your shoulder blades together. Lower the dumbbell back down to the starting position. Repeat for the desired number of repetitions, then switch sides.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3664-X6ytgYZ.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3664-X6ytgYZ.gif', 'X6ytgYZ', '© Gym visual — https://gymvisual.com/'),
('3548', 'dumbbell single arm overhead carry', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una mancuerna con una mano. Levanta la mancuerna por encima de la cabeza, extendiendo completamente el brazo. Activa el core y mantén la espalda recta mientras caminas hacia adelante, sosteniendo la mancuerna por encima de la ', 'shoulders', 'dumbbell', 'shoulders', 'shoulders', 'delts', '{"traps","core"}', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una mancuerna con una mano. Levanta la mancuerna por encima de la cabeza, extendiendo completamente el brazo. Activa el core y mantén la espalda recta mientras caminas hacia adelante, sosteniendo la mancuerna por encima de la cabeza. Continúa caminando durante la distancia o el tiempo deseado. Cambia de mano y repite el ejercicio.', 'Stand tall with your feet shoulder-width apart, holding a dumbbell in one hand. Raise the dumbbell overhead, fully extending your arm. Engage your core and keep your back straight as you walk forward, maintaining the dumbbell overhead. Continue walking for the desired distance or time. Switch hands and repeat the exercise.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3548-mWBtgmb.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3548-mWBtgmb.gif', 'mWBtgmb', '© Gym visual — https://gymvisual.com/'),
('0409', 'dumbbell single leg calf raise', 'Ponte de pie en el borde de un escalón o plataforma, con los talones colgando y la punta de los pies sobre el escalón. Sujeta una mancuerna con una mano y coloca la otra mano sobre una pared o barandilla para apoyarte. Eleva el talón lo más alto posible, levantando el cuerpo sobre la punta de los pi', 'lower legs', 'dumbbell', 'lower legs', 'lower legs', 'calves', '{"ankles"}', 'Ponte de pie en el borde de un escalón o plataforma, con los talones colgando y la punta de los pies sobre el escalón. Sujeta una mancuerna con una mano y coloca la otra mano sobre una pared o barandilla para apoyarte. Eleva el talón lo más alto posible, levantando el cuerpo sobre la punta de los pies. Haz una pausa por un momento en la parte superior, luego baja lentamente el talón por debajo del nivel del escalón. Repite el número de repeticiones deseado, luego cambia a la otra pierna.', 'Stand on the edge of a step or platform with your heels hanging off and your toes on the step. Hold a dumbbell in one hand and place your other hand on a wall or railing for support. Raise your heel as high as possible, lifting your body up onto your toes. Pause for a moment at the top, then slowly lower your heel back down below the step. Repeat for the desired number of repetitions, then switch to the other leg.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0409-1kB3Wmk.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0409-1kB3Wmk.gif', '1kB3Wmk', '© Gym visual — https://gymvisual.com/'),
('1757', 'dumbbell single leg deadlift', 'Ponte de pie con los pies separados a la altura de las caderas, sujetando una mancuerna con la mano derecha. Traslada tu peso a la pierna izquierda y levanta el pie derecho ligeramente del suelo. Manteniendo la espalda recta, inclínate hacia adelante desde las caderas y baja la mancuerna hacia el su', 'upper legs', 'dumbbell', 'upper legs', 'upper legs', 'glutes', '{"hamstrings","lower back"}', 'Ponte de pie con los pies separados a la altura de las caderas, sujetando una mancuerna con la mano derecha. Traslada tu peso a la pierna izquierda y levanta el pie derecho ligeramente del suelo. Manteniendo la espalda recta, inclínate hacia adelante desde las caderas y baja la mancuerna hacia el suelo. Al mismo tiempo, extiende la pierna derecha recta hacia atrás, manteniendo una ligera flexión en la rodilla izquierda. Baja la mancuerna hasta que tu torso y tu pierna derecha queden paralelos al suelo. Haz una pausa por un momento, luego activa los glúteos y los isquiotibiales para volver a la posición inicial. Repite el número de repeticiones deseado, luego cambia de lado.', 'Stand with your feet hip-width apart, holding a dumbbell in your right hand. Shift your weight onto your left leg and lift your right foot slightly off the ground. Keeping your back straight, hinge forward at the hips and lower the dumbbell towards the ground. At the same time, extend your right leg straight behind you, maintaining a slight bend in your left knee. Lower the dumbbell until your torso and right leg are parallel to the ground. Pause for a moment, then engage your glutes and hamstrings to return to the starting position. Repeat for the desired number of repetitions, then switch sides.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1757-gKozT8X.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1757-gKozT8X.gif', 'gKozT8X', '© Gym visual — https://gymvisual.com/'),
('2805', 'dumbbell single leg deadlift with stepbox support', 'Ponte de pie con los pies separados a la altura de las caderas, sujetando una mancuerna con la mano derecha. Coloca el pie izquierdo sobre un cajón de step o una superficie elevada detrás de ti. Manteniendo la espalda recta y el core activado, inclínate hacia adelante desde las caderas, bajando la m', 'upper legs', 'dumbbell', 'upper legs', 'upper legs', 'glutes', '{"hamstrings","lower back"}', 'Ponte de pie con los pies separados a la altura de las caderas, sujetando una mancuerna con la mano derecha. Coloca el pie izquierdo sobre un cajón de step o una superficie elevada detrás de ti. Manteniendo la espalda recta y el core activado, inclínate hacia adelante desde las caderas, bajando la mancuerna hacia el suelo. Mientras bajas la mancuerna, levanta al mismo tiempo la pierna izquierda detrás de ti, manteniendo una línea recta desde la cabeza hasta el talón. Baja la mancuerna hasta sentir un estiramiento en el isquiotibial derecho, luego vuelve a la posición inicial. Repite el número de repeticiones deseado, luego cambia de lado.', 'Stand with your feet hip-width apart, holding a dumbbell in your right hand. Place your left foot on a stepbox or elevated surface behind you. Keeping your back straight and core engaged, hinge forward at the hips, lowering the dumbbell towards the ground. As you lower the dumbbell, simultaneously lift your left leg behind you, maintaining a straight line from head to heel. Lower the dumbbell until you feel a stretch in your right hamstring, then return to the starting position. Repeat for the desired number of repetitions, then switch sides.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2805-daBmy1Y.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2805-daBmy1Y.gif', 'daBmy1Y', '© Gym visual — https://gymvisual.com/'),
('0410', 'dumbbell single leg split squat', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una mancuerna en cada mano. Da un paso hacia adelante con un pie y coloca los pies de modo que el pie delantero quede plano en el suelo y el pie trasero quede elevado sobre un banco o escalón. Baja el cuerpo flexionando la rod', 'upper legs', 'dumbbell', 'upper legs', 'upper legs', 'quads', '{"glutes","hamstrings","calves"}', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una mancuerna en cada mano. Da un paso hacia adelante con un pie y coloca los pies de modo que el pie delantero quede plano en el suelo y el pie trasero quede elevado sobre un banco o escalón. Baja el cuerpo flexionando la rodilla y la cadera delanteras, manteniendo la rodilla trasera ligeramente flexionada y el talón trasero levantado del suelo. Continúa bajando hasta que el muslo delantero quede paralelo al suelo, luego empuja con el talón delantero para volver a la posición inicial. Repite el número de repeticiones deseado y luego cambia de pierna y repite.', 'Stand with your feet shoulder-width apart, holding a dumbbell in each hand. Take a step forward with one foot and position your feet so that your front foot is flat on the ground and your back foot is elevated on a bench or step. Lower your body by bending your front knee and hip, keeping your back knee slightly bent and your back heel off the ground. Continue lowering until your front thigh is parallel to the ground, then push through your front heel to return to the starting position. Repeat for the desired number of repetitions, then switch legs and repeat.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0410-qx4fgX7.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0410-qx4fgX7.gif', 'qx4fgX7', '© Gym visual — https://gymvisual.com/'),
('0411', 'dumbbell single leg squat', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una mancuerna en cada mano. Extiende una pierna hacia adelante y mantenla levantada del suelo durante todo el ejercicio. Flexiona la pierna de apoyo y baja el cuerpo como si te sentaras en una silla. Mantén el pecho arriba y l', 'upper legs', 'dumbbell', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves"}', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una mancuerna en cada mano. Extiende una pierna hacia adelante y mantenla levantada del suelo durante todo el ejercicio. Flexiona la pierna de apoyo y baja el cuerpo como si te sentaras en una silla. Mantén el pecho arriba y la espalda recta. Haz una pausa por un momento en la posición más baja, luego empuja con el talón para volver a la posición inicial. Repite el número de repeticiones deseado, luego cambia de pierna.', 'Stand with your feet shoulder-width apart, holding a dumbbell in each hand. Extend one leg forward and keep it off the ground throughout the exercise. Bend your standing leg and lower your body down as if sitting back into a chair. Keep your chest up and your back straight. Pause for a moment at the bottom, then push through your heel to return to the starting position. Repeat for the desired number of repetitions, then switch legs.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0411-H6ybluc.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0411-H6ybluc.gif', 'H6ybluc', '© Gym visual — https://gymvisual.com/'),
('0413', 'dumbbell squat', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo una mancuerna en cada mano a los costados. Manteniendo el pecho arriba y el core activado, baja el cuerpo flexionando las rodillas y las caderas, como si te sentaras en una silla. Continúa bajando hasta que los muslos queden', 'upper legs', 'dumbbell', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves"}', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo una mancuerna en cada mano a los costados. Manteniendo el pecho arriba y el core activado, baja el cuerpo flexionando las rodillas y las caderas, como si te sentaras en una silla. Continúa bajando hasta que los muslos queden paralelos al suelo, o tan abajo como puedas hacerlo cómodamente. Haz una pausa por un momento en la parte inferior, luego empuja con los talones para regresar a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, holding a dumbbell in each hand at your sides. Keeping your chest up and core engaged, lower your body down by bending at the knees and hips, as if sitting back into a chair. Continue lowering until your thighs are parallel to the ground, or as low as you can comfortably go. Pause for a moment at the bottom, then push through your heels to return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0413-HsvHqgf.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0413-HsvHqgf.gif', 'HsvHqgf', '© Gym visual — https://gymvisual.com/'),
('3560', 'dumbbell standing alternate hammer curl and press', 'Ponte de pie con una mancuerna en cada mano, con las palmas hacia tu cuerpo. Mantén los codos cerca del torso y la espalda recta. Exhala y flexiona la mancuerna de tu mano derecha hacia el hombro, manteniendo el brazo superior quieto. Continúa levantando la mancuerna hasta que el bíceps esté complet', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms","shoulders"}', 'Ponte de pie con una mancuerna en cada mano, con las palmas hacia tu cuerpo. Mantén los codos cerca del torso y la espalda recta. Exhala y flexiona la mancuerna de tu mano derecha hacia el hombro, manteniendo el brazo superior quieto. Continúa levantando la mancuerna hasta que el bíceps esté completamente contraído y la mancuerna esté a la altura del hombro. Inhala y baja lentamente la mancuerna de vuelta a la posición inicial. Repite el curl con la mano izquierda. Después de completar el curl con la mano izquierda, exhala y presiona la mancuerna de la mano derecha por encima de la cabeza. Extiende completamente el brazo y mantén la posición por un momento en la parte superior. Inhala y baja lentamente la mancuerna de vuelta a la posición inicial. Repite el press con la mano izquierda. Continúa alternando entre curls y press durante el número de repeticiones deseado.', 'Stand up straight with a dumbbell in each hand, palms facing your body. Keep your elbows close to your torso and your back straight. Exhale and curl the dumbbell in your right hand towards your shoulder, keeping your upper arm stationary. Continue to raise the dumbbell until your biceps are fully contracted and the dumbbell is at shoulder level. Inhale and slowly lower the dumbbell back to the starting position. Repeat the curl with your left hand. After completing the curl with your left hand, exhale and press the dumbbell in your right hand overhead. Extend your arm fully and hold for a moment at the top. Inhale and slowly lower the dumbbell back to the starting position. Repeat the press with your left hand. Continue alternating between curls and presses for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3560-LeaZOIz.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3560-LeaZOIz.gif', 'LeaZOIz', '© Gym visual — https://gymvisual.com/'),
('0414', 'dumbbell standing alternate overhead press', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una mancuerna en cada mano a la altura de los hombros, con las palmas hacia adelante. Presiona una mancuerna por encima de la cabeza, extendiendo completamente el brazo. Baja la mancuerna de vuelta a la altura de los hombros. ', 'shoulders', 'dumbbell', 'shoulders', 'shoulders', 'delts', '{"triceps","core"}', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una mancuerna en cada mano a la altura de los hombros, con las palmas hacia adelante. Presiona una mancuerna por encima de la cabeza, extendiendo completamente el brazo. Baja la mancuerna de vuelta a la altura de los hombros. Repite con el otro brazo. Continúa alternando los brazos durante el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, holding a dumbbell in each hand at shoulder level with your palms facing forward. Press one dumbbell overhead, fully extending your arm. Lower the dumbbell back to shoulder level. Repeat with the other arm. Continue alternating arms for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0414-bBi35y3.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0414-bBi35y3.gif', 'bBi35y3', '© Gym visual — https://gymvisual.com/'),
('0415', 'dumbbell standing alternate raise', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo una mancuerna en cada mano con las palmas hacia el cuerpo. Mantén la espalda recta y el core activado. Levanta una mancuerna hacia el lado, manteniendo el brazo recto y la palma hacia abajo. Continúa levantando hasta que el ', 'shoulders', 'dumbbell', 'shoulders', 'shoulders', 'delts', '{"traps","forearms"}', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo una mancuerna en cada mano con las palmas hacia el cuerpo. Mantén la espalda recta y el core activado. Levanta una mancuerna hacia el lado, manteniendo el brazo recto y la palma hacia abajo. Continúa levantando hasta que el brazo quede paralelo al suelo. Haz una pausa breve en la parte más alta, luego baja lentamente la mancuerna de vuelta a la posición inicial. Repite con el otro brazo. Alterna entre los brazos el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing your body. Keep your back straight and your core engaged. Raise one dumbbell to the side, keeping your arm straight and your palm facing down. Continue lifting until your arm is parallel to the ground. Pause for a moment at the top, then slowly lower the dumbbell back to the starting position. Repeat with the other arm. Alternate between arms for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0415-SxHteRW.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0415-SxHteRW.gif', 'SxHteRW', '© Gym visual — https://gymvisual.com/'),
('1739', 'dumbbell standing alternating tricep kickback', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una mancuerna en cada mano. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta. Extiende los brazos rectos hacia atrás, manteniendo los codos cerca del cuerpo. Haz una ', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'triceps', '{"shoulders"}', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una mancuerna en cada mano. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta. Extiende los brazos rectos hacia atrás, manteniendo los codos cerca del cuerpo. Haz una pausa breve en la parte alta, luego baja lentamente las mancuernas de vuelta a la posición inicial. Repite con el otro brazo, alternando lados en cada repetición.', 'Stand with your feet shoulder-width apart, holding a dumbbell in each hand. Bend your knees slightly and hinge forward at the hips, keeping your back straight. Extend your arms straight back, keeping your elbows close to your body. Pause for a moment at the top, then slowly lower the dumbbells back to the starting position. Repeat with the other arm, alternating sides with each repetition.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1739-Gi2BXfK.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1739-Gi2BXfK.gif', 'Gi2BXfK', '© Gym visual — https://gymvisual.com/'),
('2143', 'dumbbell standing around world', 'Ponte de pie con los pies separados a la altura de los hombros y sostén una mancuerna en cada mano. Extiende los brazos rectos hacia los lados a la altura de los hombros, con las palmas hacia abajo. Manteniendo los brazos rectos, gira lentamente los brazos en un movimiento circular, llevando las man', 'shoulders', 'dumbbell', 'shoulders', 'shoulders', 'delts', '{"triceps","forearms"}', 'Ponte de pie con los pies separados a la altura de los hombros y sostén una mancuerna en cada mano. Extiende los brazos rectos hacia los lados a la altura de los hombros, con las palmas hacia abajo. Manteniendo los brazos rectos, gira lentamente los brazos en un movimiento circular, llevando las mancuernas frente al cuerpo y luego por encima de la cabeza. Continúa el movimiento circular, bajando las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and hold a dumbbell in each hand. Extend your arms straight out to the sides at shoulder height, palms facing down. Keeping your arms straight, slowly rotate your arms in a circular motion, bringing the dumbbells in front of your body and then overhead. Continue the circular motion, bringing the dumbbells back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2143-RSOsp5d.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2143-RSOsp5d.gif', 'RSOsp5d', '© Gym visual — https://gymvisual.com/'),
('1740', 'dumbbell standing bent over one arm triceps extension', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una mancuerna con una mano. Inclínate hacia adelante desde la cintura, manteniendo la espalda recta y paralela al suelo. Extiende el brazo recto hacia atrás, manteniendo el codo cerca de tu cuerpo. Baja lentamente la mancuerna d', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'triceps', '{"shoulders","back"}', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una mancuerna con una mano. Inclínate hacia adelante desde la cintura, manteniendo la espalda recta y paralela al suelo. Extiende el brazo recto hacia atrás, manteniendo el codo cerca de tu cuerpo. Baja lentamente la mancuerna de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia de brazo.', 'Stand with your feet shoulder-width apart and hold a dumbbell in one hand. Bend forward at the waist, keeping your back straight and parallel to the ground. Extend your arm straight back, keeping your elbow close to your body. Slowly lower the dumbbell back to the starting position. Repeat for the desired number of repetitions, then switch arms.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1740-CJwa0vD.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1740-CJwa0vD.gif', 'CJwa0vD', '© Gym visual — https://gymvisual.com/'),
('1741', 'dumbbell standing bent over two arm triceps extension', 'Ponte de pie con los pies separados a la altura de los hombros y sostén una mancuerna en cada mano. Inclínate hacia adelante desde la cintura, manteniendo la espalda recta y las rodillas ligeramente flexionadas. Extiende los brazos rectos hacia atrás, manteniendo los codos cerca del cuerpo. Baja len', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'triceps', '{"shoulders","back"}', 'Ponte de pie con los pies separados a la altura de los hombros y sostén una mancuerna en cada mano. Inclínate hacia adelante desde la cintura, manteniendo la espalda recta y las rodillas ligeramente flexionadas. Extiende los brazos rectos hacia atrás, manteniendo los codos cerca del cuerpo. Baja lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and hold a dumbbell in each hand. Bend forward at the waist, keeping your back straight and your knees slightly bent. Extend your arms straight back, keeping your elbows close to your body. Slowly lower the dumbbells back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1741-3T12T87.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1741-3T12T87.gif', '3T12T87', '© Gym visual — https://gymvisual.com/'),
('0416', 'dumbbell standing biceps curl', 'Ponte de pie con una mancuerna en cada mano, con las palmas hacia adelante y los brazos completamente extendidos. Manteniendo los brazos superiores fijos, exhala y levanta el peso mientras contraes los bíceps. Continúa levantando las mancuernas hasta que los bíceps estén completamente contraídos y l', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ponte de pie con una mancuerna en cada mano, con las palmas hacia adelante y los brazos completamente extendidos. Manteniendo los brazos superiores fijos, exhala y levanta el peso mientras contraes los bíceps. Continúa levantando las mancuernas hasta que los bíceps estén completamente contraídos y las mancuernas estén a la altura de los hombros. Mantén la posición contraída durante una breve pausa mientras aprietas los bíceps. Inhala y comienza a bajar lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand up straight with a dumbbell in each hand, palms facing forward and arms fully extended. Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly begin to lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0416-3s4NnTh.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0416-3s4NnTh.gif', '3s4NnTh', '© Gym visual — https://gymvisual.com/'),
('0417', 'dumbbell standing calf raise', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una mancuerna en cada mano. Levanta los talones del suelo lo más alto posible, usando las pantorrillas. Haz una pausa breve en la parte alta y luego baja lentamente los talones de vuelta a la posición inicial. Repite el número', 'lower legs', 'dumbbell', 'lower legs', 'lower legs', 'calves', '{"ankles"}', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una mancuerna en cada mano. Levanta los talones del suelo lo más alto posible, usando las pantorrillas. Haz una pausa breve en la parte alta y luego baja lentamente los talones de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, holding a dumbbell in each hand. Raise your heels off the ground as high as possible, using your calves. Pause for a moment at the top, then slowly lower your heels back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0417-dPmaUaU.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0417-dPmaUaU.gif', 'dPmaUaU', '© Gym visual — https://gymvisual.com/'),
('0418', 'dumbbell standing concentration curl', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una mancuerna con una mano, con el brazo completamente extendido y la palma hacia adentro. Apoya la otra mano sobre el muslo para mayor estabilidad. Manteniendo fija la parte superior del brazo, exhala y flexiona la mancuerna ha', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una mancuerna con una mano, con el brazo completamente extendido y la palma hacia adentro. Apoya la otra mano sobre el muslo para mayor estabilidad. Manteniendo fija la parte superior del brazo, exhala y flexiona la mancuerna hacia el hombro contrayendo el bíceps. Continúa levantando la mancuerna hasta que el bíceps esté completamente contraído y la mancuerna esté a la altura del hombro. Mantén la posición contraída durante una breve pausa mientras aprietas los bíceps. Inhala y baja lentamente la mancuerna de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia de brazo.', 'Stand with your feet shoulder-width apart and hold a dumbbell in one hand, with your arm fully extended and palm facing inwards. Place your opposite hand on your thigh for support. Keeping your upper arm stationary, exhale and curl the dumbbell towards your shoulder by contracting your biceps. Continue to raise the dumbbell until your biceps are fully contracted and the dumbbell is at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly lower the dumbbell back to the starting position. Repeat for the desired number of repetitions, then switch arms.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0418-7inpWch.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0418-7inpWch.gif', '7inpWch', '© Gym visual — https://gymvisual.com/'),
('0419', 'dumbbell standing front raise above head', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una mancuerna en cada mano con un agarre prono. Mantén los brazos rectos y levanta las mancuernas frente a ti, elevándolas por encima de la cabeza. Haz una pausa breve en la parte alta, luego baja lentamente las mancuernas de ', 'shoulders', 'dumbbell', 'shoulders', 'shoulders', 'delts', '{"trapezius","biceps"}', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una mancuerna en cada mano con un agarre prono. Mantén los brazos rectos y levanta las mancuernas frente a ti, elevándolas por encima de la cabeza. Haz una pausa breve en la parte alta, luego baja lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, holding a dumbbell in each hand with an overhand grip. Keep your arms straight and lift the dumbbells in front of you, raising them above your head. Pause for a moment at the top, then slowly lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0419-laVRfDf.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0419-laVRfDf.gif', 'laVRfDf', '© Gym visual — https://gymvisual.com/'),
('2321', 'dumbbell standing inner biceps curl v. 2', 'Ponte de pie con una mancuerna en cada mano, con las palmas mirando hacia el torso. Mantén los codos cerca del torso y gira las palmas de las manos hasta que queden mirando hacia adelante. Manteniendo fija la parte superior de los brazos, flexiona los pesos mientras contraes los bíceps. Continúa lev', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ponte de pie con una mancuerna en cada mano, con las palmas mirando hacia el torso. Mantén los codos cerca del torso y gira las palmas de las manos hasta que queden mirando hacia adelante. Manteniendo fija la parte superior de los brazos, flexiona los pesos mientras contraes los bíceps. Continúa levantando las pesas hasta que los bíceps estén completamente contraídos y las mancuernas estén a la altura de los hombros. Mantén la posición contraída durante una breve pausa mientras aprietas los bíceps. Comienza a llevar lentamente las mancuernas de vuelta a la posición inicial mientras inhalas. Repite el número de repeticiones recomendado.', 'Stand up straight with a dumbbell in each hand, palms facing your torso. Keep your elbows close to your torso and rotate the palms of your hands until they are facing forward. While holding your upper arms stationary, curl the weights while contracting your biceps. Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Slowly begin to bring the dumbbells back to the starting position as your breathe in. Repeat for the recommended amount of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2321-vKilzz3.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2321-vKilzz3.gif', 'vKilzz3', '© Gym visual — https://gymvisual.com/'),
('0420', 'dumbbell standing kickback', 'Ponte de pie con los pies separados a la altura de los hombros y sostén una mancuerna en cada mano. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta. Extiende los brazos rectos hacia atrás, contrayendo los tríceps en la parte superior del m', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'triceps', '{"shoulders"}', 'Ponte de pie con los pies separados a la altura de los hombros y sostén una mancuerna en cada mano. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta. Extiende los brazos rectos hacia atrás, contrayendo los tríceps en la parte superior del movimiento. Haz una pausa por un momento, luego baja lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and hold a dumbbell in each hand. Bend your knees slightly and hinge forward at the hips, keeping your back straight. Extend your arms straight back, squeezing your triceps at the top of the movement. Pause for a moment, then slowly lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0420-UmpPAAe.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0420-UmpPAAe.gif', 'UmpPAAe', '© Gym visual — https://gymvisual.com/'),
('0421', 'dumbbell standing one arm concentration curl', 'Ponte de pie con la espalda recta y los pies separados a la altura de los hombros, sujetando una mancuerna con una mano, con la palma hacia arriba. Coloca la mano libre sobre el muslo para apoyarte. Manteniendo fija la parte superior del brazo, exhala y flexiona la mancuerna hacia el hombro contraye', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ponte de pie con la espalda recta y los pies separados a la altura de los hombros, sujetando una mancuerna con una mano, con la palma hacia arriba. Coloca la mano libre sobre el muslo para apoyarte. Manteniendo fija la parte superior del brazo, exhala y flexiona la mancuerna hacia el hombro contrayendo el bíceps. Continúa levantando la mancuerna hasta que el bíceps esté completamente contraído y la mancuerna esté a la altura del hombro. Mantén la posición contraída durante una breve pausa mientras aprietas los bíceps. Inhala y baja lentamente la mancuerna de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia de brazo.', 'Stand up straight with your feet shoulder-width apart and hold a dumbbell in one hand, palm facing up. Place your free hand on your thigh for support. Keeping your upper arm stationary, exhale and curl the dumbbell towards your shoulder by contracting your biceps. Continue to raise the dumbbell until your biceps are fully contracted and the dumbbell is at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly lower the dumbbell back to the starting position. Repeat for the desired number of repetitions, then switch arms.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0421-8fgqP5a.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0421-8fgqP5a.gif', '8fgqP5a', '© Gym visual — https://gymvisual.com/'),
('0422', 'dumbbell standing one arm curl (over incline bench)', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una mancuerna con una mano, con la palma hacia adelante. Coloca la otra mano sobre un banco inclinado para apoyarte. Manteniendo fija la parte superior del brazo, exhala y flexiona la mancuerna hacia el hombro contrayendo el b', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una mancuerna con una mano, con la palma hacia adelante. Coloca la otra mano sobre un banco inclinado para apoyarte. Manteniendo fija la parte superior del brazo, exhala y flexiona la mancuerna hacia el hombro contrayendo el bíceps. Haz una pausa por un momento arriba, luego inhala y baja lentamente la mancuerna a la posición inicial. Repite el número de repeticiones deseado, luego cambia de brazo.', 'Stand with your feet shoulder-width apart, holding a dumbbell in one hand with your palm facing forward. Place your other hand on an incline bench for support. Keeping your upper arm stationary, exhale and curl the dumbbell towards your shoulder by contracting your biceps. Pause for a moment at the top, then inhale and slowly lower the dumbbell back to the starting position. Repeat for the desired number of repetitions, then switch arms.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0422-BIb1tGo.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0422-BIb1tGo.gif', 'BIb1tGo', '© Gym visual — https://gymvisual.com/'),
('1680', 'dumbbell standing one arm curl over incline bench', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una mancuerna con una mano. Coloca la otra mano sobre un banco inclinado para apoyarte. Manteniendo el brazo superior quieto, flexiona la mancuerna hacia el hombro contrayendo el bíceps. Haz una pausa breve en la parte más alt', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una mancuerna con una mano. Coloca la otra mano sobre un banco inclinado para apoyarte. Manteniendo el brazo superior quieto, flexiona la mancuerna hacia el hombro contrayendo el bíceps. Haz una pausa breve en la parte más alta, luego baja lentamente la mancuerna de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia de brazo.', 'Stand with your feet shoulder-width apart, holding a dumbbell in one hand. Place your other hand on an incline bench for support. Keeping your upper arm stationary, curl the dumbbell towards your shoulder by contracting your biceps. Pause for a moment at the top, then slowly lower the dumbbell back to the starting position. Repeat for the desired number of repetitions, then switch arms.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1680-EmlJR2y.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1680-EmlJR2y.gif', 'EmlJR2y', '© Gym visual — https://gymvisual.com/'),
('0423', 'dumbbell standing one arm extension', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una mancuerna con una mano. Levanta la mancuerna por encima de la cabeza, extendiendo completamente el brazo. Mantén la parte superior del brazo cerca de la cabeza y perpendicular al suelo. Baja lentamente la mancuerna detrás ', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'triceps', '{"shoulders"}', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una mancuerna con una mano. Levanta la mancuerna por encima de la cabeza, extendiendo completamente el brazo. Mantén la parte superior del brazo cerca de la cabeza y perpendicular al suelo. Baja lentamente la mancuerna detrás de la cabeza, flexionando el codo. Haz una pausa por un momento, luego levanta la mancuerna de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, holding a dumbbell in one hand. Raise the dumbbell overhead, fully extending your arm. Keep your upper arm close to your head and perpendicular to the ground. Slowly lower the dumbbell behind your head, bending your elbow. Pause for a moment, then raise the dumbbell back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0423-BCUR88E.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0423-BCUR88E.gif', 'BCUR88E', '© Gym visual — https://gymvisual.com/'),
('0424', 'dumbbell standing one arm palm in press', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una mancuerna con una mano a la altura del hombro, con la palma hacia adentro. Activa el core y mantén la espalda recta. Empuja la mancuerna hacia arriba hasta que el brazo quede completamente extendido. Haz una pausa breve en', 'shoulders', 'dumbbell', 'shoulders', 'shoulders', 'delts', '{"triceps","core"}', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una mancuerna con una mano a la altura del hombro, con la palma hacia adentro. Activa el core y mantén la espalda recta. Empuja la mancuerna hacia arriba hasta que el brazo quede completamente extendido. Haz una pausa breve en la parte más alta, luego baja lentamente la mancuerna de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia al otro brazo.', 'Stand with your feet shoulder-width apart, holding a dumbbell in one hand at shoulder height with your palm facing inwards. Engage your core and keep your back straight. Press the dumbbell upwards until your arm is fully extended. Pause for a moment at the top, then slowly lower the dumbbell back to the starting position. Repeat for the desired number of repetitions, then switch to the other arm.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0424-ocYc6Db.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0424-ocYc6Db.gif', 'ocYc6Db', '© Gym visual — https://gymvisual.com/'),
('0425', 'dumbbell standing one arm reverse curl', 'Ponte de pie con la espalda recta y los pies separados a la altura de los hombros, sujetando una mancuerna con una mano con agarre prono. Mantén el brazo completamente extendido y cerca del cuerpo, con la palma hacia abajo. Flexiona lentamente la mancuerna hacia tu hombro, manteniendo fija la parte ', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ponte de pie con la espalda recta y los pies separados a la altura de los hombros, sujetando una mancuerna con una mano con agarre prono. Mantén el brazo completamente extendido y cerca del cuerpo, con la palma hacia abajo. Flexiona lentamente la mancuerna hacia tu hombro, manteniendo fija la parte superior del brazo. Haz una pausa breve en la parte más alta, luego baja lentamente la mancuerna de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia al otro brazo.', 'Stand up straight with your feet shoulder-width apart and hold a dumbbell in one hand with an overhand grip. Keep your arm fully extended and close to your body, with your palm facing down. Slowly curl the dumbbell up towards your shoulder, keeping your upper arm stationary. Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position. Repeat for the desired number of repetitions, then switch to the other arm.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0425-DU5Kkj2.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0425-DU5Kkj2.gif', 'DU5Kkj2', '© Gym visual — https://gymvisual.com/'),
('0426', 'dumbbell standing overhead press', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una mancuerna en cada mano a la altura de los hombros, con las palmas hacia adelante. Presiona las mancuernas hacia arriba hasta que los brazos queden completamente extendidos por encima de la cabeza. Haz una pausa por un mome', 'shoulders', 'dumbbell', 'shoulders', 'shoulders', 'delts', '{"triceps","upper back"}', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una mancuerna en cada mano a la altura de los hombros, con las palmas hacia adelante. Presiona las mancuernas hacia arriba hasta que los brazos queden completamente extendidos por encima de la cabeza. Haz una pausa por un momento en la parte superior, luego baja lentamente las mancuernas de vuelta a la altura de los hombros. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, holding a dumbbell in each hand at shoulder level with your palms facing forward. Press the dumbbells upward until your arms are fully extended overhead. Pause for a moment at the top, then slowly lower the dumbbells back down to shoulder level. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0426-A6wtbuL.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0426-A6wtbuL.gif', 'A6wtbuL', '© Gym visual — https://gymvisual.com/'),
('0427', 'dumbbell standing palms in press', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una mancuerna en cada mano a la altura de los hombros, con las palmas hacia adentro. Manteniendo el core activado y la espalda recta, presiona las mancuernas hacia arriba hasta que los brazos queden completamente extendidos po', 'shoulders', 'dumbbell', 'shoulders', 'shoulders', 'delts', '{"triceps","chest"}', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una mancuerna en cada mano a la altura de los hombros, con las palmas hacia adentro. Manteniendo el core activado y la espalda recta, presiona las mancuernas hacia arriba hasta que los brazos queden completamente extendidos por encima de la cabeza. Haz una pausa breve en la parte alta, luego baja lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, holding a dumbbell in each hand at shoulder level with your palms facing inwards. Keeping your core engaged and your back straight, press the dumbbells upwards until your arms are fully extended overhead. Pause for a moment at the top, then slowly lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0427-UilDHSs.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0427-UilDHSs.gif', 'UilDHSs', '© Gym visual — https://gymvisual.com/'),
('0428', 'dumbbell standing preacher curl', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una mancuerna en cada mano, con las palmas hacia adelante. Apoya la parte posterior de la parte superior de los brazos contra el banco scott o un banco inclinado, con los codos ligeramente flexionados. Manteniendo los brazos sup', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una mancuerna en cada mano, con las palmas hacia adelante. Apoya la parte posterior de la parte superior de los brazos contra el banco scott o un banco inclinado, con los codos ligeramente flexionados. Manteniendo los brazos superiores fijos, exhala y levanta el peso mientras contraes los bíceps. Continúa levantando las mancuernas hasta que los bíceps estén completamente contraídos y las mancuernas estén a la altura de los hombros. Mantén la posición contraída durante una breve pausa mientras aprietas los bíceps. Inhala y comienza a bajar lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand upright with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing forward. Rest the back of your upper arms against the preacher bench or an incline bench, with your elbows slightly bent. Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly begin to lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0428-hq2hyDH.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0428-hq2hyDH.gif', 'hq2hyDH', '© Gym visual — https://gymvisual.com/'),
('0429', 'dumbbell standing reverse curl', 'Ponte de pie con la espalda recta y los pies separados a la altura de los hombros, sujetando una mancuerna en cada mano, con las palmas hacia tu cuerpo. Manteniendo fija la parte superior de los brazos, exhala y flexiona los pesos mientras contraes los bíceps. Continúa subiendo los pesos hasta que l', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ponte de pie con la espalda recta y los pies separados a la altura de los hombros, sujetando una mancuerna en cada mano, con las palmas hacia tu cuerpo. Manteniendo fija la parte superior de los brazos, exhala y flexiona los pesos mientras contraes los bíceps. Continúa subiendo los pesos hasta que los bíceps estén completamente contraídos y las mancuernas estén a la altura de los hombros. Mantén la posición contraída durante una breve pausa mientras aprietas los bíceps. Inhala y comienza a bajar lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand up straight with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing your body. Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly begin to lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0429-0IgNjSM.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0429-0IgNjSM.gif', '0IgNjSM', '© Gym visual — https://gymvisual.com/'),
('0430', 'dumbbell standing triceps extension', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una mancuerna con una mano. Levanta la mancuerna por encima de la cabeza, manteniendo el brazo recto. Flexiona el codo y baja la mancuerna detrás de la cabeza, manteniendo fija la parte superior del brazo. Extiende el brazo de v', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'triceps', '{"shoulders"}', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una mancuerna con una mano. Levanta la mancuerna por encima de la cabeza, manteniendo el brazo recto. Flexiona el codo y baja la mancuerna detrás de la cabeza, manteniendo fija la parte superior del brazo. Extiende el brazo de vuelta hacia arriba, hasta la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and hold a dumbbell in one hand. Raise the dumbbell overhead, keeping your arm straight. Bend your elbow and lower the dumbbell behind your head, keeping your upper arm stationary. Extend your arm back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0430-PdmaD0N.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0430-PdmaD0N.gif', 'PdmaD0N', '© Gym visual — https://gymvisual.com/'),
('2293', 'dumbbell standing zottman preacher curl', 'Ponte de pie con una mancuerna en cada mano, con las palmas hacia adelante. Apoya la parte superior de los brazos contra el banco scott y mantén los codos ligeramente flexionados. Flexiona las mancuernas hacia los hombros mientras mantienes fija la parte superior de los brazos. En la parte superior ', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ponte de pie con una mancuerna en cada mano, con las palmas hacia adelante. Apoya la parte superior de los brazos contra el banco scott y mantén los codos ligeramente flexionados. Flexiona las mancuernas hacia los hombros mientras mantienes fija la parte superior de los brazos. En la parte superior del movimiento, gira las muñecas de modo que las palmas queden hacia abajo. Baja lentamente las mancuernas de vuelta a la posición inicial, girando también las muñecas a su posición original. Repite el número de repeticiones deseado.', 'Stand up straight with a dumbbell in each hand, palms facing forward. Place your upper arms against the preacher bench and keep your elbows slightly bent. Curl the dumbbells up towards your shoulders while keeping your upper arms stationary. At the top of the movement, rotate your wrists so that your palms are facing downward. Slowly lower the dumbbells back to the starting position, rotating your wrists back to the starting position as well. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2293-P2nRiUa.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2293-P2nRiUa.gif', 'P2nRiUa', '© Gym visual — https://gymvisual.com/'),
('1684', 'dumbbell step up single leg balance with bicep curl', 'Ponte de pie frente a un escalón o plataforma con una mancuerna en cada mano, con las palmas hacia tu cuerpo. Coloca el pie derecho sobre el escalón, asegurándote de que todo el pie esté en contacto con la superficie. Activa el core y empuja con el talón derecho para subir el cuerpo sobre el escalón', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"quadriceps","glutes","hamstrings"}', 'Ponte de pie frente a un escalón o plataforma con una mancuerna en cada mano, con las palmas hacia tu cuerpo. Coloca el pie derecho sobre el escalón, asegurándote de que todo el pie esté en contacto con la superficie. Activa el core y empuja con el talón derecho para subir el cuerpo sobre el escalón, llevando la rodilla izquierda hacia el pecho. En la parte superior del movimiento, realiza un curl de bíceps flexionando los codos y llevando las mancuernas hacia los hombros. Baja las mancuernas y, al mismo tiempo, baja el pie izquierdo de vuelta al suelo. Repite el movimiento del lado contrario, subiendo con el pie izquierdo y flexionando las mancuernas. Continúa alternando lados durante el número de repeticiones deseado.', 'Stand in front of a step or platform with a dumbbell in each hand, palms facing your body. Place your right foot on the step, ensuring your entire foot is in contact with the surface. Engage your core and push through your right heel to lift your body up onto the step, bringing your left knee up towards your chest. At the top of the movement, perform a bicep curl by bending your elbows and bringing the dumbbells towards your shoulders. Lower the dumbbells back down and simultaneously lower your left foot back to the ground. Repeat the movement on the opposite side, stepping up with your left foot and curling the dumbbells. Continue alternating sides for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1684-76vfTdU.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1684-76vfTdU.gif', '76vfTdU', '© Gym visual — https://gymvisual.com/'),
('0431', 'dumbbell step-up', 'Ponte de pie frente a un banco o escalón con una mancuerna en cada mano, con las palmas hacia tu cuerpo. Coloca el pie derecho sobre el banco o escalón, asegurándote de que todo el pie esté en contacto con la superficie. Empuja con el talón derecho y sube el cuerpo sobre el banco o escalón, endereza', 'upper legs', 'dumbbell', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves"}', 'Ponte de pie frente a un banco o escalón con una mancuerna en cada mano, con las palmas hacia tu cuerpo. Coloca el pie derecho sobre el banco o escalón, asegurándote de que todo el pie esté en contacto con la superficie. Empuja con el talón derecho y sube el cuerpo sobre el banco o escalón, enderezando la pierna derecha. Sube el pie izquierdo hasta el banco o escalón, quedando completamente erguido. Baja con el pie izquierdo, seguido del pie derecho, volviendo a la posición inicial. Repite el número de repeticiones deseado, luego cambia de pierna.', 'Stand in front of a bench or step with a dumbbell in each hand, palms facing your body. Place your right foot on the bench or step, ensuring your entire foot is in contact with the surface. Push through your right heel and lift your body up onto the bench or step, straightening your right leg. Bring your left foot up onto the bench or step, standing fully upright. Step back down with your left foot, followed by your right foot, returning to the starting position. Repeat for the desired number of repetitions, then switch legs.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0431-aXtJhlg.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0431-aXtJhlg.gif', 'aXtJhlg', '© Gym visual — https://gymvisual.com/'),
('2796', 'dumbbell step-up lunge', 'Ponte de pie frente a un escalón o plataforma con una mancuerna en cada mano, con las palmas hacia tus costados. Coloca el pie derecho sobre el escalón, asegurándote de que todo el pie esté sobre la superficie. Empuja con el talón derecho y sube el cuerpo sobre el escalón, llevando también el pie iz', 'upper legs', 'dumbbell', 'upper legs', 'upper legs', 'quads', '{"glutes","hamstrings","calves"}', 'Ponte de pie frente a un escalón o plataforma con una mancuerna en cada mano, con las palmas hacia tus costados. Coloca el pie derecho sobre el escalón, asegurándote de que todo el pie esté sobre la superficie. Empuja con el talón derecho y sube el cuerpo sobre el escalón, llevando también el pie izquierdo hacia arriba. Una vez que ambos pies estén sobre el escalón, baja el pie izquierdo de vuelta a la posición inicial, manteniendo el pie derecho sobre el escalón. Repite el movimiento, alternando el pie con el que subes cada vez. Continúa durante el número de repeticiones deseado.', 'Stand in front of a step or platform with a dumbbell in each hand, palms facing your sides. Place your right foot on the step, ensuring your entire foot is on the surface. Push through your right heel and lift your body up onto the step, bringing your left foot up as well. Once both feet are on the step, lower your left foot back down to the starting position, keeping your right foot on the step. Repeat the movement, alternating which foot you step up with each time. Continue for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2796-gFyFj9z.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2796-gFyFj9z.gif', 'gFyFj9z', '© Gym visual — https://gymvisual.com/'),
('2812', 'dumbbell step-up split squat', 'Ponte de pie frente a un banco o escalón con una mancuerna en cada mano, con las palmas hacia tu cuerpo. Coloca el pie derecho sobre el banco o escalón, asegurándote de que todo el pie esté en contacto con la superficie. Sube al banco o escalón con el pie derecho, empujando con el talón para levanta', 'upper legs', 'dumbbell', 'upper legs', 'upper legs', 'quads', '{"glutes","hamstrings","calves"}', 'Ponte de pie frente a un banco o escalón con una mancuerna en cada mano, con las palmas hacia tu cuerpo. Coloca el pie derecho sobre el banco o escalón, asegurándote de que todo el pie esté en contacto con la superficie. Sube al banco o escalón con el pie derecho, empujando con el talón para levantar el cuerpo. Mientras subes, levanta al mismo tiempo la rodilla izquierda hacia el pecho. Haz una pausa en la parte superior del movimiento, luego baja lentamente el pie izquierdo de vuelta al suelo mientras mantienes el pie derecho sobre el banco o escalón. Repite el movimiento con el pie izquierdo sobre el banco o escalón. Continúa alternando entre el pie derecho y el izquierdo durante el número de repeticiones deseado.', 'Stand in front of a bench or step with a dumbbell in each hand, palms facing your body. Place your right foot on the bench or step, ensuring your entire foot is in contact with the surface. Step up onto the bench or step with your right foot, pushing through your heel to lift your body up. As you step up, simultaneously lift your left knee towards your chest. Pause at the top of the movement, then slowly lower your left foot back to the ground while keeping your right foot on the bench or step. Repeat the movement with your left foot on the bench or step. Continue alternating between your right and left foot for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2812-QjE2DcA.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2812-QjE2DcA.gif', 'QjE2DcA', '© Gym visual — https://gymvisual.com/'),
('0432', 'dumbbell stiff leg deadlift', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una mancuerna en cada mano con un agarre prono. Manteniendo la espalda recta y el core activado, inclínate desde las caderas y baja las mancuernas hacia el suelo, permitiendo una ligera flexión en las rodillas. Baja las mancue', 'upper legs', 'dumbbell', 'upper legs', 'upper legs', 'glutes', '{"hamstrings","lower back"}', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una mancuerna en cada mano con un agarre prono. Manteniendo la espalda recta y el core activado, inclínate desde las caderas y baja las mancuernas hacia el suelo, permitiendo una ligera flexión en las rodillas. Baja las mancuernas hasta sentir un estiramiento en los isquiotibiales, luego aprieta los glúteos y empuja con los talones para volver a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, holding a dumbbell in each hand with an overhand grip. Keeping your back straight and your core engaged, hinge at the hips and lower the dumbbells towards the ground, allowing a slight bend in your knees. Lower the dumbbells until you feel a stretch in your hamstrings, then squeeze your glutes and push through your heels to return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0432-5eLRITT.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0432-5eLRITT.gif', '5eLRITT', '© Gym visual — https://gymvisual.com/'),
('0433', 'dumbbell straight arm pullover', 'Túmbate en un banco con la cabeza en un extremo y los pies firmemente apoyados en el suelo. Sujeta una mancuerna con ambas manos y extiende los brazos rectos por encima del pecho. Manteniendo los brazos rectos, baja lentamente la mancuerna detrás de la cabeza con un movimiento en forma de arco. Haz ', 'chest', 'dumbbell', 'chest', 'chest', 'pectorals', '{"latissimus dorsi","triceps"}', 'Túmbate en un banco con la cabeza en un extremo y los pies firmemente apoyados en el suelo. Sujeta una mancuerna con ambas manos y extiende los brazos rectos por encima del pecho. Manteniendo los brazos rectos, baja lentamente la mancuerna detrás de la cabeza con un movimiento en forma de arco. Haz una pausa por un momento, luego levanta la mancuerna de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on a bench with your head at one end and your feet planted firmly on the ground. Hold a dumbbell with both hands and extend your arms straight above your chest. Keeping your arms straight, slowly lower the dumbbell behind your head in an arc-like motion. Pause for a moment, then raise the dumbbell back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0433-i8BdLTK.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0433-i8BdLTK.gif', 'i8BdLTK', '© Gym visual — https://gymvisual.com/'),
('0434', 'dumbbell straight leg deadlift', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una mancuerna en cada mano con un agarre prono. Manteniendo la espalda recta y el core activado, inclínate desde las caderas y baja las mancuernas hacia el suelo, permitiendo que el torso se incline hacia adelante. Continúa ba', 'upper legs', 'dumbbell', 'upper legs', 'upper legs', 'glutes', '{"hamstrings","lower back"}', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una mancuerna en cada mano con un agarre prono. Manteniendo la espalda recta y el core activado, inclínate desde las caderas y baja las mancuernas hacia el suelo, permitiendo que el torso se incline hacia adelante. Continúa bajando las mancuernas hasta sentir un estiramiento en los isquiotibiales, manteniendo las rodillas ligeramente flexionadas. Haz una pausa breve en la posición más baja, luego activa los glúteos y los isquiotibiales para levantar el torso de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, holding a dumbbell in each hand with an overhand grip. Keeping your back straight and your core engaged, hinge at the hips and lower the dumbbells towards the ground, allowing your torso to lean forward. Continue lowering the dumbbells until you feel a stretch in your hamstrings, keeping your knees slightly bent. Pause for a moment at the bottom, then engage your glutes and hamstrings to lift your torso back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0434-oom75KC.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0434-oom75KC.gif', 'oom75KC', '© Gym visual — https://gymvisual.com/'),
('2808', 'dumbbell sumo pull through', 'Ponte de pie con los pies más separados que la altura de los hombros, con las puntas de los pies hacia afuera. Sujeta una mancuerna con ambas manos frente a tu cuerpo, con los brazos extendidos. Flexiona las rodillas y baja las caderas hasta una posición de sentadilla, manteniendo la espalda recta. ', 'upper legs', 'dumbbell', 'upper legs', 'upper legs', 'glutes', '{"hamstrings","quadriceps","core"}', 'Ponte de pie con los pies más separados que la altura de los hombros, con las puntas de los pies hacia afuera. Sujeta una mancuerna con ambas manos frente a tu cuerpo, con los brazos extendidos. Flexiona las rodillas y baja las caderas hasta una posición de sentadilla, manteniendo la espalda recta. Baja la mancuerna entre las piernas, manteniendo los brazos rectos. Empuja con los talones y extiende las caderas hacia adelante, llevando la mancuerna hacia arriba y frente a tu cuerpo. Aprieta los glúteos en la parte superior del movimiento, luego baja la mancuerna de vuelta entre las piernas. Repite el número de repeticiones deseado.', 'Stand with your feet wider than shoulder-width apart, toes pointed outwards. Hold a dumbbell with both hands in front of your body, arms extended. Bend your knees and lower your hips down into a squat position, keeping your back straight. Lower the dumbbell down between your legs, keeping your arms straight. Drive through your heels and extend your hips forward, pulling the dumbbell up and in front of your body. Squeeze your glutes at the top of the movement, then lower the dumbbell back down between your legs. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2808-BmrwWzo.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2808-BmrwWzo.gif', 'BmrwWzo', '© Gym visual — https://gymvisual.com/'),
('2803', 'dumbbell supported squat', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo una mancuerna en cada mano a los costados. Manteniendo el pecho arriba y el core activado, baja lentamente el cuerpo flexionando las rodillas y empujando las caderas hacia atrás. Continúa bajando hasta que los muslos queden ', 'upper legs', 'dumbbell', 'upper legs', 'upper legs', 'quads', '{"glutes","hamstrings","calves"}', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo una mancuerna en cada mano a los costados. Manteniendo el pecho arriba y el core activado, baja lentamente el cuerpo flexionando las rodillas y empujando las caderas hacia atrás. Continúa bajando hasta que los muslos queden paralelos al suelo, o tan abajo como puedas hacerlo cómodamente. Haz una pausa por un momento en la parte inferior, luego empuja con los talones para regresar a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, holding a dumbbell in each hand at your sides. Keeping your chest up and core engaged, slowly lower your body down by bending your knees and pushing your hips back. Continue lowering until your thighs are parallel to the ground, or as low as you can comfortably go. Pause for a moment at the bottom, then push through your heels to return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2803-r5DgrW9.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2803-r5DgrW9.gif', 'r5DgrW9', '© Gym visual — https://gymvisual.com/'),
('0436', 'dumbbell tate press', 'Siéntate en un banco plano con una mancuerna en cada mano, con las palmas mirándose entre sí. Sube las mancuernas hasta la altura de los hombros, luego gira las muñecas de modo que las palmas queden mirando hacia afuera. Presiona las mancuernas hacia arriba hasta que los brazos queden completamente ', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'triceps', '{"shoulders"}', 'Siéntate en un banco plano con una mancuerna en cada mano, con las palmas mirándose entre sí. Sube las mancuernas hasta la altura de los hombros, luego gira las muñecas de modo que las palmas queden mirando hacia afuera. Presiona las mancuernas hacia arriba hasta que los brazos queden completamente extendidos, luego bájalas de vuelta a la altura de los hombros. Gira las muñecas de vuelta a la posición inicial y repite el número de repeticiones deseado.', 'Sit on a flat bench with a dumbbell in each hand, palms facing each other. Raise the dumbbells to shoulder height, then rotate your wrists so that your palms are facing away from you. Press the dumbbells up until your arms are fully extended, then lower them back down to shoulder height. Rotate your wrists back to the starting position and repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0436-s5PdDyY.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0436-s5PdDyY.gif', 's5PdDyY', '© Gym visual — https://gymvisual.com/'),
('1742', 'dumbbell tricep kickback with stork stance', 'Ponte de pie con los pies separados a la altura de los hombros y sostén una mancuerna en la mano derecha. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta. Lleva el codo derecho hacia el costado, manteniéndolo flexionado en un ángulo de 90 ', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'triceps', '{"shoulders"}', 'Ponte de pie con los pies separados a la altura de los hombros y sostén una mancuerna en la mano derecha. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta. Lleva el codo derecho hacia el costado, manteniéndolo flexionado en un ángulo de 90 grados. Extiende el brazo derecho recto hacia atrás, apretando el tríceps. Haz una pausa por un momento, luego baja lentamente la mancuerna de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia de lado.', 'Stand with your feet shoulder-width apart and hold a dumbbell in your right hand. Bend your knees slightly and hinge forward at the hips, keeping your back straight. Bring your right elbow up to your side, keeping it bent at a 90-degree angle. Extend your right arm straight back, squeezing your triceps. Pause for a moment, then slowly lower the dumbbell back to the starting position. Repeat for the desired number of repetitions, then switch sides.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1742-wOLmCXc.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1742-wOLmCXc.gif', 'wOLmCXc', '© Gym visual — https://gymvisual.com/'),
('1743', 'dumbbell twisting bench press', 'Túmbate sobre un banco con los pies apoyados en el suelo y la espalda presionada contra el banco. Sujeta una mancuerna en cada mano con agarre prono, con las palmas alejadas de ti. Extiende los brazos rectos hacia arriba sobre el pecho, con una ligera flexión en los codos. Baja las mancuernas hacia ', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'triceps', '{"chest","shoulders"}', 'Túmbate sobre un banco con los pies apoyados en el suelo y la espalda presionada contra el banco. Sujeta una mancuerna en cada mano con agarre prono, con las palmas alejadas de ti. Extiende los brazos rectos hacia arriba sobre el pecho, con una ligera flexión en los codos. Baja las mancuernas hacia el pecho, manteniendo los codos cerca del cuerpo. Mientras bajas las mancuernas, gira las muñecas de modo que las palmas queden hacia ti en la parte más baja del movimiento. Haz una pausa por un momento en la parte más baja, luego invierte el movimiento presionando las mancuernas de vuelta hacia arriba, hasta la posición inicial. Mientras presionas las mancuernas hacia arriba, gira las muñecas de vuelta a la posición inicial con las palmas alejadas de ti. Repite el número de repeticiones deseado.', 'Lie flat on a bench with your feet flat on the ground and your back pressed against the bench. Hold a dumbbell in each hand with an overhand grip, palms facing away from you. Extend your arms straight up over your chest, keeping a slight bend in your elbows. Lower the dumbbells down towards your chest, keeping your elbows close to your body. As you lower the dumbbells, twist your wrists so that your palms face towards you at the bottom of the movement. Pause for a moment at the bottom, then reverse the movement by pressing the dumbbells back up to the starting position. As you press the dumbbells up, twist your wrists back to the starting position with palms facing away from you. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1743-z6TAHoT.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1743-z6TAHoT.gif', 'z6TAHoT', '© Gym visual — https://gymvisual.com/'),
('0437', 'dumbbell upright row', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una mancuerna en cada mano con un agarre prono. Deja que las mancuernas cuelguen frente a tus muslos, con los brazos completamente extendidos. Manteniendo la espalda recta y el core activado, exhala y levanta las mancuernas re', 'shoulders', 'dumbbell', 'shoulders', 'shoulders', 'delts', '{"traps","biceps"}', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una mancuerna en cada mano con un agarre prono. Deja que las mancuernas cuelguen frente a tus muslos, con los brazos completamente extendidos. Manteniendo la espalda recta y el core activado, exhala y levanta las mancuernas rectas hacia tu barbilla, guiando el movimiento con los codos. Haz una pausa por un momento en la parte superior, luego inhala y baja lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, holding a dumbbell in each hand with an overhand grip. Let the dumbbells hang in front of your thighs, with your arms fully extended. Keeping your back straight and your core engaged, exhale and lift the dumbbells straight up towards your chin, leading with your elbows. Pause for a moment at the top, then inhale and slowly lower the dumbbells back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0437-ainizkb.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0437-ainizkb.gif', 'ainizkb', '© Gym visual — https://gymvisual.com/'),
('1765', 'dumbbell upright row (back pov)', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una mancuerna en cada mano con un agarre prono. Deja que las mancuernas cuelguen frente a tus muslos, con los brazos completamente extendidos y las palmas hacia tu cuerpo. Manteniendo la espalda recta y el core activado, exhal', 'shoulders', 'dumbbell', 'shoulders', 'shoulders', 'delts', '{"traps","biceps"}', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una mancuerna en cada mano con un agarre prono. Deja que las mancuernas cuelguen frente a tus muslos, con los brazos completamente extendidos y las palmas hacia tu cuerpo. Manteniendo la espalda recta y el core activado, exhala y levanta las mancuernas rectas hacia tu barbilla, guiando el movimiento con los codos. Continúa subiendo hasta que las mancuernas estén a la altura de los hombros, con los codos apuntando hacia los lados. Haz una pausa por un momento en la parte superior, luego inhala y baja lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, holding a dumbbell in each hand with an overhand grip. Let the dumbbells hang in front of your thighs, with your arms fully extended and your palms facing your body. Keeping your back straight and your core engaged, exhale and lift the dumbbells straight up towards your chin, leading with your elbows. Continue lifting until the dumbbells are at shoulder height, with your elbows pointing out to the sides. Pause for a moment at the top, then inhale and slowly lower the dumbbells back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1765-Iptlv6x.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1765-Iptlv6x.gif', 'Iptlv6x', '© Gym visual — https://gymvisual.com/'),
('0864', 'dumbbell upright shoulder external rotation', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una mancuerna en cada mano con las palmas hacia tu cuerpo. Levanta los brazos hacia los lados hasta que queden paralelos al suelo, manteniendo los codos ligeramente flexionados. Gira los brazos hacia afuera, llevando las mancuer', 'shoulders', 'dumbbell', 'shoulders', 'shoulders', 'delts', '{"rotator cuff","trapezius"}', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una mancuerna en cada mano con las palmas hacia tu cuerpo. Levanta los brazos hacia los lados hasta que queden paralelos al suelo, manteniendo los codos ligeramente flexionados. Gira los brazos hacia afuera, llevando las mancuernas hacia la cabeza mientras mantienes los codos en la misma posición. Haz una pausa breve en la parte alta, luego baja lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and hold a dumbbell in each hand with your palms facing your body. Raise your arms out to the sides until they are parallel to the ground, keeping your elbows slightly bent. Rotate your arms externally, bringing the dumbbells up towards your head while keeping your elbows in the same position. Pause for a moment at the top, then slowly lower the dumbbells back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0864-x306lCW.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0864-x306lCW.gif', 'x306lCW', '© Gym visual — https://gymvisual.com/'),
('5201', 'dumbbell waiter biceps curl', 'Ponte de pie con una mancuerna en cada mano, con las palmas hacia adelante. Mantén la parte superior de los brazos cerca del cuerpo y los codos pegados. Flexiona lentamente las mancuernas hacia los hombros, manteniendo las muñecas rectas. Haz una pausa breve en la parte alta, luego baja lentamente l', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms","shoulders"}', 'Ponte de pie con una mancuerna en cada mano, con las palmas hacia adelante. Mantén la parte superior de los brazos cerca del cuerpo y los codos pegados. Flexiona lentamente las mancuernas hacia los hombros, manteniendo las muñecas rectas. Haz una pausa breve en la parte alta, luego baja lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand up straight with a dumbbell in each hand, palms facing forward. Keep your upper arms close to your body and your elbows tucked in. Slowly curl the dumbbells up towards your shoulders, keeping your wrists straight. Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/5201-KOpzGBL.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/5201-KOpzGBL.gif', 'KOpzGBL', '© Gym visual — https://gymvisual.com/'),
('0438', 'dumbbell w-press', 'Siéntate en un banco con una mancuerna en cada mano, con las palmas hacia adelante. Sube las mancuernas hasta la altura de los hombros, con los codos flexionados y las palmas hacia adelante. Presiona las mancuernas hacia arriba hasta que los brazos queden completamente extendidos por encima de la ca', 'shoulders', 'dumbbell', 'shoulders', 'shoulders', 'delts', '{"triceps","chest"}', 'Siéntate en un banco con una mancuerna en cada mano, con las palmas hacia adelante. Sube las mancuernas hasta la altura de los hombros, con los codos flexionados y las palmas hacia adelante. Presiona las mancuernas hacia arriba hasta que los brazos queden completamente extendidos por encima de la cabeza. Baja las mancuernas de vuelta a la altura de los hombros. Repite el número de repeticiones deseado.', 'Sit on a bench with a dumbbell in each hand, palms facing forward. Raise the dumbbells to shoulder height, elbows bent and palms facing forward. Press the dumbbells upward until your arms are fully extended overhead. Lower the dumbbells back to shoulder height. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0438-vmwLyCg.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0438-vmwLyCg.gif', 'vmwLyCg', '© Gym visual — https://gymvisual.com/'),
('0439', 'dumbbell zottman curl', 'Ponte de pie con una mancuerna en cada mano, con las palmas hacia tu cuerpo. Mantén los codos cerca del torso y gira las palmas para que queden hacia adelante. Flexiona las mancuernas hacia los hombros mientras mantienes fija la parte superior de los brazos. En la parte superior del movimiento, gira', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ponte de pie con una mancuerna en cada mano, con las palmas hacia tu cuerpo. Mantén los codos cerca del torso y gira las palmas para que queden hacia adelante. Flexiona las mancuernas hacia los hombros mientras mantienes fija la parte superior de los brazos. En la parte superior del movimiento, gira las muñecas de modo que las palmas queden alejadas de tu cuerpo. Baja lentamente las mancuernas de vuelta a la posición inicial, girando las palmas de nuevo hacia tu cuerpo. Repite el número de repeticiones deseado.', 'Stand up straight with a dumbbell in each hand, palms facing your body. Keep your elbows close to your torso and rotate your palms to face forward. Curl the dumbbells up to your shoulders while keeping your upper arms stationary. At the top of the movement, rotate your wrists so that your palms are facing away from your body. Slowly lower the dumbbells back to the starting position, rotating your palms back to facing your body. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0439-kXaIn5A.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0439-kXaIn5A.gif', 'kXaIn5A', '© Gym visual — https://gymvisual.com/'),
('2294', 'dumbbell zottman preacher curl', 'Siéntate en un banco scott con una mancuerna en cada mano, con las palmas hacia arriba y los codos apoyados en la almohadilla. Flexiona las mancuernas hacia los hombros, manteniendo fija la parte superior de los brazos y las palmas hacia arriba. En la parte superior del curl, gira las muñecas de mod', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Siéntate en un banco scott con una mancuerna en cada mano, con las palmas hacia arriba y los codos apoyados en la almohadilla. Flexiona las mancuernas hacia los hombros, manteniendo fija la parte superior de los brazos y las palmas hacia arriba. En la parte superior del curl, gira las muñecas de modo que las palmas queden hacia abajo. Baja lentamente las mancuernas de vuelta a la posición inicial, girando también las muñecas a su posición original mientras lo haces. Repite el número de repeticiones deseado.', 'Sit on a preacher bench with a dumbbell in each hand, palms facing up and elbows resting on the pad. Curl the dumbbells up towards your shoulders, keeping your upper arms stationary and your palms facing up. At the top of the curl, rotate your wrists so that your palms are facing down. Slowly lower the dumbbells back down to the starting position, rotating your wrists back to the starting position as you do so. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2294-y5U5B9Y.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2294-y5U5B9Y.gif', 'y5U5B9Y', '© Gym visual — https://gymvisual.com/'),
('2189', 'dumbbells seated triceps extension', 'Siéntate en un banco con la espalda recta y los pies planos sobre el suelo. Sujeta una mancuerna con ambas manos con agarre prono y levántala por encima de la cabeza. Flexiona los codos y baja la mancuerna detrás de la cabeza, manteniendo la parte superior de los brazos cerca de las orejas. Extiende', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'triceps', '{"shoulders"}', 'Siéntate en un banco con la espalda recta y los pies planos sobre el suelo. Sujeta una mancuerna con ambas manos con agarre prono y levántala por encima de la cabeza. Flexiona los codos y baja la mancuerna detrás de la cabeza, manteniendo la parte superior de los brazos cerca de las orejas. Extiende los brazos y sube la mancuerna de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a bench with your back straight and feet flat on the ground. Hold a dumbbell in both hands with an overhand grip, and raise it above your head. Bend your elbows and lower the dumbbell behind your head, keeping your upper arms close to your ears. Extend your arms and raise the dumbbell back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2189-FQXdXzY.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2189-FQXdXzY.gif', 'FQXdXzY', '© Gym visual — https://gymvisual.com/'),
('1167', 'dynamic chest stretch (male)', 'Ponte de pie con la espalda recta y los pies separados a la altura de los hombros. Extiende los brazos hacia los lados, paralelos al suelo. Lleva lentamente los brazos hacia adelante, cruzándolos frente al cuerpo. Siente el estiramiento en los músculos del pecho. Mantén el estiramiento durante 10-30', 'chest', 'body weight', 'chest', 'chest', 'pectorals', '{"shoulders","triceps"}', 'Ponte de pie con la espalda recta y los pies separados a la altura de los hombros. Extiende los brazos hacia los lados, paralelos al suelo. Lleva lentamente los brazos hacia adelante, cruzándolos frente al cuerpo. Siente el estiramiento en los músculos del pecho. Mantén el estiramiento durante 10-30 segundos. Vuelve a la posición inicial y repite el número de repeticiones deseado.', 'Stand tall with your feet shoulder-width apart. Extend your arms straight out to the sides, parallel to the ground. Slowly bring your arms forward, crossing them in front of your body. Feel the stretch in your chest muscles. Hold the stretch for 10-30 seconds. Return to the starting position and repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1167-3uj0Ozg.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1167-3uj0Ozg.gif', '3uj0Ozg', '© Gym visual — https://gymvisual.com/'),
('3287', 'elbow dips', 'Siéntate en el borde de un banco o silla con las manos sujetando el borde junto a las caderas. Desliza las caderas hacia adelante, fuera del banco, y estira las piernas, manteniendo los talones en el suelo. Flexiona los codos y baja el cuerpo hacia el suelo, manteniendo la espalda cerca del banco. H', 'upper arms', 'body weight', 'upper arms', 'upper arms', 'triceps', '{"chest","shoulders"}', 'Siéntate en el borde de un banco o silla con las manos sujetando el borde junto a las caderas. Desliza las caderas hacia adelante, fuera del banco, y estira las piernas, manteniendo los talones en el suelo. Flexiona los codos y baja el cuerpo hacia el suelo, manteniendo la espalda cerca del banco. Haz una pausa por un momento en la posición más baja, luego empuja con las manos para enderezar los brazos y levantar el cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on the edge of a bench or chair with your hands gripping the edge next to your hips. Slide your hips forward off the bench and straighten your legs, keeping your heels on the ground. Bend your elbows and lower your body towards the ground, keeping your back close to the bench. Pause for a moment at the bottom, then push through your hands to straighten your arms and lift your body back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3287-LkoAWAE.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3287-LkoAWAE.gif', 'LkoAWAE', '© Gym visual — https://gymvisual.com/'),
('1772', 'elbow lift - reverse push-up', 'Comienza tumbado boca abajo en el suelo con las piernas extendidas y las manos colocadas justo debajo de los hombros. Activa el core y presiona con las palmas para levantar la parte superior del cuerpo del suelo, manteniendo los codos cerca de los costados. Haz una pausa por un momento en la parte s', 'back', 'body weight', 'back', 'back', 'upper back', '{"triceps","shoulders"}', 'Comienza tumbado boca abajo en el suelo con las piernas extendidas y las manos colocadas justo debajo de los hombros. Activa el core y presiona con las palmas para levantar la parte superior del cuerpo del suelo, manteniendo los codos cerca de los costados. Haz una pausa por un momento en la parte superior, apretando los músculos de la espalda alta. Baja lentamente el cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Start by lying face down on the ground with your legs extended and your hands placed directly under your shoulders. Engage your core and press through your palms to lift your upper body off the ground, keeping your elbows close to your sides. Pause at the top for a moment, squeezing your upper back muscles. Slowly lower your body back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1772-wbUYILZ.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1772-wbUYILZ.gif', 'wbUYILZ', '© Gym visual — https://gymvisual.com/'),
('0443', 'elbow-to-knee', 'Comienza tumbado boca arriba con las rodillas flexionadas y los pies apoyados en el suelo. Coloca las manos detrás de la cabeza con los codos apuntando hacia afuera. Activa el abdomen y levanta la parte superior del cuerpo del suelo, llevando el codo derecho hacia la rodilla izquierda. Al mismo tiem', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"obliques"}', 'Comienza tumbado boca arriba con las rodillas flexionadas y los pies apoyados en el suelo. Coloca las manos detrás de la cabeza con los codos apuntando hacia afuera. Activa el abdomen y levanta la parte superior del cuerpo del suelo, llevando el codo derecho hacia la rodilla izquierda. Al mismo tiempo, lleva la rodilla izquierda hacia el codo derecho, creando un movimiento de torsión. Haz una pausa por un momento en la parte superior, luego baja lentamente la parte superior del cuerpo y extiende las piernas de vuelta a la posición inicial. Repite el movimiento, esta vez llevando el codo izquierdo hacia la rodilla derecha y la rodilla derecha hacia el codo izquierdo. Continúa alternando lados durante el número de repeticiones deseado.', 'Start by lying flat on your back with your knees bent and feet flat on the ground. Place your hands behind your head with your elbows pointing outwards. Engage your abs and lift your upper body off the ground, bringing your right elbow towards your left knee. At the same time, bring your left knee towards your right elbow, creating a twisting motion. Pause for a moment at the top, then slowly lower your upper body and extend your legs back to the starting position. Repeat the movement, this time bringing your left elbow towards your right knee and your right knee towards your left elbow. Continue alternating sides for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0443-jvp6DiD.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0443-jvp6DiD.gif', 'jvp6DiD', '© Gym visual — https://gymvisual.com/'),
('3292', 'elevator', 'Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Coloca las manos sobre las caderas o crúzalas frente al pecho. Manteniendo la espalda recta, inclínate lentamente hacia adelante desde la cintura, bajando la parte superior del cuerpo hacia el suel', 'back', 'body weight', 'back', 'back', 'upper back', '{"shoulders","trapezius"}', 'Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Coloca las manos sobre las caderas o crúzalas frente al pecho. Manteniendo la espalda recta, inclínate lentamente hacia adelante desde la cintura, bajando la parte superior del cuerpo hacia el suelo. Haz una pausa por un momento en la posición más baja, luego sube lentamente la parte superior del cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and your knees slightly bent. Place your hands on your hips or cross them in front of your chest. Keeping your back straight, slowly bend forward at the waist, lowering your upper body towards the ground. Pause for a moment at the bottom, then slowly raise your upper body back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3292-zYmNaoY.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3292-zYmNaoY.gif', 'zYmNaoY', '© Gym visual — https://gymvisual.com/'),
('1332', 'exercise ball alternating arm ups', 'Siéntate en el balón de estabilidad con los pies planos en el suelo y la espalda recta. Sujeta una mancuerna en cada mano con las palmas hacia adentro y los brazos extendidos hacia abajo a los lados. Activa el core y levanta lentamente un brazo hacia el hombro, manteniendo el codo ligeramente flexio', 'back', 'stability ball', 'back', 'back', 'lats', '{"shoulders","core"}', 'Siéntate en el balón de estabilidad con los pies planos en el suelo y la espalda recta. Sujeta una mancuerna en cada mano con las palmas hacia adentro y los brazos extendidos hacia abajo a los lados. Activa el core y levanta lentamente un brazo hacia el hombro, manteniendo el codo ligeramente flexionado. Haz una pausa breve en la parte más alta, luego baja lentamente el brazo de vuelta a la posición inicial. Repite el movimiento con el otro brazo. Continúa alternando los brazos durante el número de repeticiones deseado.', 'Sit on the stability ball with your feet flat on the ground and your back straight. Hold a dumbbell in each hand with your palms facing inwards and your arms extended down by your sides. Engage your core and slowly lift one arm up towards your shoulder, keeping your elbow slightly bent. Pause for a moment at the top, then slowly lower your arm back down to the starting position. Repeat the movement with the other arm. Continue alternating arms for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1332-EyLrNC2.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1332-EyLrNC2.gif', 'EyLrNC2', '© Gym visual — https://gymvisual.com/'),
('1333', 'exercise ball back extension with arms extended', 'Coloca el balón de estabilidad en el suelo y túmbate boca abajo sobre él, con las caderas apoyadas en el balón y los pies contra una pared para mayor estabilidad. Extiende los brazos rectos hacia adelante, con las palmas hacia abajo. Activa el core y levanta lentamente la parte superior del cuerpo d', 'back', 'stability ball', 'back', 'back', 'spine', '{"glutes","hamstrings"}', 'Coloca el balón de estabilidad en el suelo y túmbate boca abajo sobre él, con las caderas apoyadas en el balón y los pies contra una pared para mayor estabilidad. Extiende los brazos rectos hacia adelante, con las palmas hacia abajo. Activa el core y levanta lentamente la parte superior del cuerpo del balón, manteniendo la espalda recta y el cuello alineado con la columna. Haz una pausa por un momento en la parte superior, luego baja lentamente la parte superior del cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Place the stability ball on the ground and lie face down on top of it, with your hips resting on the ball and your feet against a wall for stability. Extend your arms straight out in front of you, with your palms facing down. Engage your core and slowly lift your upper body off the ball, keeping your back straight and your neck in line with your spine. Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1333-PERjVm8.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1333-PERjVm8.gif', 'PERjVm8', '© Gym visual — https://gymvisual.com/'),
('1334', 'exercise ball back extension with hands behind head', 'Coloca el balón de estabilidad en el suelo y túmbate boca abajo sobre él con las caderas apoyadas en el balón. Coloca los pies contra una pared u otra superficie estable para apoyarte. Cruza los brazos detrás de la cabeza, con las manos tocando la parte de atrás de la cabeza. Activa el core y levant', 'back', 'stability ball', 'back', 'back', 'spine', '{"glutes","hamstrings"}', 'Coloca el balón de estabilidad en el suelo y túmbate boca abajo sobre él con las caderas apoyadas en el balón. Coloca los pies contra una pared u otra superficie estable para apoyarte. Cruza los brazos detrás de la cabeza, con las manos tocando la parte de atrás de la cabeza. Activa el core y levanta lentamente la parte superior del cuerpo del balón, extendiendo la espalda hasta que tu cuerpo forme una línea recta desde la cabeza hasta las caderas. Haz una pausa breve en la parte alta del movimiento, luego baja lentamente la parte superior del cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Place the stability ball on the ground and lie face down on top of it with your hips resting on the ball. Position your feet against a wall or other stable surface for support. Cross your arms behind your head, with your hands touching the back of your head. Engage your core and slowly lift your upper body off the ball, extending your back until your body forms a straight line from your head to your hips. Pause for a moment at the top of the movement, then slowly lower your upper body back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1334-o1HGDSq.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1334-o1HGDSq.gif', 'o1HGDSq', '© Gym visual — https://gymvisual.com/'),
('1335', 'exercise ball back extension with knees off ground', 'Coloca el balón de estabilidad en el suelo y túmbate boca abajo sobre él, con las caderas apoyadas en el balón y los pies contra una pared para mayor estabilidad. Coloca las manos detrás de la cabeza o cruzadas sobre el pecho. Activa el core y levanta lentamente la parte superior del cuerpo del baló', 'back', 'stability ball', 'back', 'back', 'spine', '{"glutes","hamstrings"}', 'Coloca el balón de estabilidad en el suelo y túmbate boca abajo sobre él, con las caderas apoyadas en el balón y los pies contra una pared para mayor estabilidad. Coloca las manos detrás de la cabeza o cruzadas sobre el pecho. Activa el core y levanta lentamente la parte superior del cuerpo del balón, extendiendo la espalda hasta que tu cuerpo forme una línea recta desde la cabeza hasta los talones. Haz una pausa por un momento en la parte superior, luego baja lentamente la parte superior del cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Place the stability ball on the ground and lie face down on top of it, with your hips resting on the ball and your feet against a wall for stability. Position your hands behind your head or crossed over your chest. Engage your core and slowly lift your upper body off the ball, extending your back until your body forms a straight line from your head to your heels. Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1335-WME869U.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1335-WME869U.gif', 'WME869U', '© Gym visual — https://gymvisual.com/'),
('1336', 'exercise ball back extension with rotation', 'Comienza tumbado boca abajo sobre el balón de estabilidad, con las caderas apoyadas en el balón y los pies firmemente apoyados en el suelo. Coloca las manos detrás de la cabeza o crúzalas sobre el pecho. Activa el core y levanta lentamente la parte superior del cuerpo del balón, extendiendo la espal', 'back', 'stability ball', 'back', 'back', 'spine', '{"glutes","hamstrings"}', 'Comienza tumbado boca abajo sobre el balón de estabilidad, con las caderas apoyadas en el balón y los pies firmemente apoyados en el suelo. Coloca las manos detrás de la cabeza o crúzalas sobre el pecho. Activa el core y levanta lentamente la parte superior del cuerpo del balón, extendiendo la espalda hasta que tu cuerpo forme una línea recta desde la cabeza hasta los talones. Haz una pausa por un momento en la parte superior, luego gira lentamente el torso hacia un lado, manteniendo las caderas y las piernas estables. Vuelve al centro y repite el giro hacia el otro lado. Baja la parte superior del cuerpo de vuelta a la posición inicial y repite el número de repeticiones deseado.', 'Start by lying face down on the stability ball with your hips resting on the ball and your feet firmly planted on the ground. Place your hands behind your head or cross them over your chest. Engage your core and slowly lift your upper body off the ball, extending your back until your body forms a straight line from your head to your heels. Pause for a moment at the top, then slowly rotate your torso to one side, keeping your hips and legs stable. Return to the center and repeat the rotation to the other side. Lower your upper body back down to the starting position and repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1336-WVD66ff.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1336-WVD66ff.gif', 'WVD66ff', '© Gym visual — https://gymvisual.com/'),
('1744', 'exercise ball dip', 'Siéntate en el balón de estabilidad con los pies planos en el suelo y las rodillas flexionadas en un ángulo de 90 grados. Coloca las manos sobre el balón junto a las caderas, con los dedos apuntando hacia adelante. Activa el tríceps y empuja con las manos para levantar el cuerpo del balón, enderezan', 'upper arms', 'stability ball', 'upper arms', 'upper arms', 'triceps', '{"chest","shoulders"}', 'Siéntate en el balón de estabilidad con los pies planos en el suelo y las rodillas flexionadas en un ángulo de 90 grados. Coloca las manos sobre el balón junto a las caderas, con los dedos apuntando hacia adelante. Activa el tríceps y empuja con las manos para levantar el cuerpo del balón, enderezando los brazos. Baja el cuerpo flexionando los codos, manteniéndolos cerca de los costados. Repite el número de repeticiones deseado.', 'Sit on the stability ball with your feet flat on the ground and your knees bent at a 90-degree angle. Place your hands on the ball beside your hips, fingers pointing forward. Engage your triceps and push through your hands to lift your body off the ball, straightening your arms. Lower your body back down by bending your elbows, keeping them close to your sides. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1744-kprile3.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1744-kprile3.gif', 'kprile3', '© Gym visual — https://gymvisual.com/'),
('1559', 'exercise ball hip flexor stretch', 'Coloca el balón de estabilidad en el suelo y arrodíllate frente a él. Coloca el pie derecho sobre el balón de estabilidad, con la rodilla flexionada en un ángulo de 90 grados. Extiende la pierna izquierda hacia atrás, manteniéndola recta. Inclínate hacia adelante, empujando las caderas hacia el baló', 'upper legs', 'stability ball', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings"}', 'Coloca el balón de estabilidad en el suelo y arrodíllate frente a él. Coloca el pie derecho sobre el balón de estabilidad, con la rodilla flexionada en un ángulo de 90 grados. Extiende la pierna izquierda hacia atrás, manteniéndola recta. Inclínate hacia adelante, empujando las caderas hacia el balón de estabilidad, hasta sentir un estiramiento en el flexor de la cadera derecha. Mantén el estiramiento durante 20-30 segundos, luego cambia de lado y repite.', 'Place the stability ball on the ground and kneel in front of it. Place your right foot on top of the stability ball, with your knee bent at a 90-degree angle. Extend your left leg behind you, keeping it straight. Lean forward, pushing your hips towards the stability ball, until you feel a stretch in your right hip flexor. Hold the stretch for 20-30 seconds, then switch sides and repeat.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1559-2LQkNPW.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1559-2LQkNPW.gif', '2LQkNPW', '© Gym visual — https://gymvisual.com/'),
('1338', 'exercise ball hug', 'Siéntate en el balón de estabilidad con los pies planos en el suelo y la espalda recta. Sujeta el balón de estabilidad con ambas manos, abrazándolo cerca del pecho. Activa los músculos del core y reclínate lentamente hacia atrás, manteniendo la espalda recta y los pies apoyados en el suelo. Continúa', 'back', 'stability ball', 'back', 'back', 'spine', '{"shoulders","chest"}', 'Siéntate en el balón de estabilidad con los pies planos en el suelo y la espalda recta. Sujeta el balón de estabilidad con ambas manos, abrazándolo cerca del pecho. Activa los músculos del core y reclínate lentamente hacia atrás, manteniendo la espalda recta y los pies apoyados en el suelo. Continúa reclinándote hacia atrás hasta sentir un estiramiento en los músculos de la espalda. Mantén la posición durante unos segundos, luego vuelve lentamente a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on the stability ball with your feet flat on the ground and your back straight. Hold the stability ball with both hands, hugging it close to your chest. Engage your core muscles and slowly lean back, keeping your back straight and your feet planted on the ground. Continue leaning back until you feel a stretch in your back muscles. Hold the position for a few seconds, then slowly return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1338-d7z1Y7V.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1338-d7z1Y7V.gif', 'd7z1Y7V', '© Gym visual — https://gymvisual.com/'),
('1339', 'exercise ball lat stretch', 'Siéntate sobre un balón de estabilidad con los pies apoyados en el suelo y la espalda recta. Sujeta una mancuerna con una mano y extiende el brazo recto por encima de la cabeza. Inclínate lentamente hacia el lado opuesto, sintiendo un estiramiento en el músculo dorsal. Mantén el estiramiento durante', 'back', 'stability ball', 'back', 'back', 'lats', '{"shoulders","triceps"}', 'Siéntate sobre un balón de estabilidad con los pies apoyados en el suelo y la espalda recta. Sujeta una mancuerna con una mano y extiende el brazo recto por encima de la cabeza. Inclínate lentamente hacia el lado opuesto, sintiendo un estiramiento en el músculo dorsal. Mantén el estiramiento durante 20-30 segundos, luego vuelve a la posición inicial. Repite del otro lado.', 'Sit on a stability ball with your feet flat on the ground and your back straight. Hold a dumbbell in one hand and extend your arm straight up overhead. Slowly lean to the opposite side, feeling a stretch in your lat muscle. Hold the stretch for 20-30 seconds, then return to the starting position. Repeat on the other side.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1339-sM84pE4.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1339-sM84pE4.gif', 'sM84pE4', '© Gym visual — https://gymvisual.com/'),
('1341', 'exercise ball lower back stretch (pyramid)', 'Siéntate en el balón de estabilidad con los pies planos en el suelo y las rodillas flexionadas en un ángulo de 90 grados. Camina lentamente hacia adelante con los pies, haciendo rodar el balón por tu espalda hasta que tu zona lumbar quede apoyada sobre el balón. Coloca las manos detrás de la cabeza ', 'back', 'stability ball', 'back', 'back', 'lats', '{"glutes","hamstrings"}', 'Siéntate en el balón de estabilidad con los pies planos en el suelo y las rodillas flexionadas en un ángulo de 90 grados. Camina lentamente hacia adelante con los pies, haciendo rodar el balón por tu espalda hasta que tu zona lumbar quede apoyada sobre el balón. Coloca las manos detrás de la cabeza o crúzalas sobre el pecho. Activa el core y baja lentamente la parte superior del cuerpo hacia el suelo, permitiendo que tu zona lumbar se estire sobre el balón. Mantén el estiramiento durante unos segundos, luego regresa lentamente a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on the stability ball with your feet flat on the ground and your knees bent at a 90-degree angle. Slowly walk your feet forward, rolling the ball down your back until your lower back is resting on the ball. Place your hands behind your head or cross them over your chest. Engage your core and slowly lower your upper body towards the ground, allowing your lower back to stretch over the ball. Hold the stretch for a few seconds, then slowly return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1341-yU7w7CA.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1341-yU7w7CA.gif', 'yU7w7CA', '© Gym visual — https://gymvisual.com/'),
('1342', 'exercise ball lying side lat stretch', 'Túmbate de lado con las piernas extendidas y la cabeza apoyada sobre el balón de estabilidad. Coloca el brazo de arriba sobre el balón para mantener la estabilidad. Extiende el brazo de arriba por encima de la cabeza y permite que tu torso gire ligeramente. Siente el estiramiento en los músculos dor', 'back', 'stability ball', 'back', 'back', 'lats', '{"shoulders","triceps"}', 'Túmbate de lado con las piernas extendidas y la cabeza apoyada sobre el balón de estabilidad. Coloca el brazo de arriba sobre el balón para mantener la estabilidad. Extiende el brazo de arriba por encima de la cabeza y permite que tu torso gire ligeramente. Siente el estiramiento en los músculos dorsales del costado de tu cuerpo. Mantén el estiramiento durante 20-30 segundos, luego cambia de lado y repite.', 'Lie on your side with your legs extended and your head supported by the stability ball. Place your top arm on the ball for stability. Reach your top arm overhead and allow your torso to rotate slightly. Feel the stretch in your lat muscles on the side of your body. Hold the stretch for 20-30 seconds, then switch sides and repeat.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1342-rTbyBYV.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1342-rTbyBYV.gif', 'rTbyBYV', '© Gym visual — https://gymvisual.com/'),
('1382', 'exercise ball on the wall calf raise', 'Ponte de pie con la espalda contra una pared y coloca un balón de ejercicio entre tu zona lumbar y la pared. Coloca los pies separados a la altura de los hombros, con la punta de los pies hacia adelante. Sujeta una mancuerna en cada mano, con los brazos extendidos a los lados. Levanta los talones de', 'lower legs', 'dumbbell', 'lower legs', 'lower legs', 'calves', '{"hamstrings","quadriceps"}', 'Ponte de pie con la espalda contra una pared y coloca un balón de ejercicio entre tu zona lumbar y la pared. Coloca los pies separados a la altura de los hombros, con la punta de los pies hacia adelante. Sujeta una mancuerna en cada mano, con los brazos extendidos a los lados. Levanta los talones del suelo, llevando el peso de tu cuerpo hacia la punta de los pies. Haz una pausa breve en la parte alta y luego baja lentamente los talones de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your back against a wall and place an exercise ball between your lower back and the wall. Position your feet shoulder-width apart, with your toes pointing forward. Hold a dumbbell in each hand, with your arms extended by your sides. Raise your heels off the ground, lifting your body weight onto the balls of your feet. Pause for a moment at the top, then slowly lower your heels back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1382-xo6sENf.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1382-xo6sENf.gif', 'xo6sENf', '© Gym visual — https://gymvisual.com/'),
('3241', 'exercise ball on the wall calf raise (tennis ball between ankles)', 'Ponte de pie frente a una pared con los pies separados a la altura de los hombros. Coloca un balón de ejercicio entre la pared y tu zona lumbar. Sujeta una mancuerna en cada mano, con los brazos extendidos a los lados. Coloca una pelota de tenis entre los tobillos. Levanta los talones del suelo, ele', 'lower legs', 'dumbbell', 'lower legs', 'lower legs', 'calves', '{"hamstrings","quadriceps"}', 'Ponte de pie frente a una pared con los pies separados a la altura de los hombros. Coloca un balón de ejercicio entre la pared y tu zona lumbar. Sujeta una mancuerna en cada mano, con los brazos extendidos a los lados. Coloca una pelota de tenis entre los tobillos. Levanta los talones del suelo, elevando el cuerpo sobre la punta de los pies. Haz una pausa breve en la parte alta y luego baja lentamente los talones de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand facing a wall with your feet shoulder-width apart. Place an exercise ball between the wall and your lower back. Hold a dumbbell in each hand, with your arms extended by your sides. Place a tennis ball between your ankles. Raise your heels off the ground, lifting your body up onto your toes. Pause for a moment at the top, then slowly lower your heels back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3241-FY3UdNT.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3241-FY3UdNT.gif', 'FY3UdNT', '© Gym visual — https://gymvisual.com/'),
('3240', 'exercise ball on the wall calf raise (tennis ball between knees)', 'Ponte de pie con la espalda contra una pared y coloca un balón de ejercicio entre tu zona lumbar y la pared. Coloca los pies separados a la altura de los hombros y ligeramente por delante de ti. Sujeta una mancuerna en cada mano, con los brazos extendidos a los lados. Coloca una pelota de tenis entr', 'lower legs', 'dumbbell', 'lower legs', 'lower legs', 'calves', '{"quadriceps","hamstrings"}', 'Ponte de pie con la espalda contra una pared y coloca un balón de ejercicio entre tu zona lumbar y la pared. Coloca los pies separados a la altura de los hombros y ligeramente por delante de ti. Sujeta una mancuerna en cada mano, con los brazos extendidos a los lados. Coloca una pelota de tenis entre las rodillas. Levanta los talones del suelo, elevando el cuerpo sobre la punta de los pies. Haz una pausa breve en la parte alta y luego baja lentamente los talones de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your back against a wall and place an exercise ball between your lower back and the wall. Position your feet shoulder-width apart and slightly in front of you. Hold a dumbbell in each hand, with your arms extended by your sides. Place a tennis ball between your knees. Raise your heels off the ground, lifting your body up onto your toes. Pause for a moment at the top, then slowly lower your heels back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3240-j74M6Zn.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3240-j74M6Zn.gif', 'j74M6Zn', '© Gym visual — https://gymvisual.com/'),
('1416', 'exercise ball one leg prone lower body rotation', 'Túmbate boca abajo sobre el balón de estabilidad con las caderas apoyadas en el balón y las piernas extendidas rectas detrás de ti. Coloca las manos en el suelo frente a ti para mayor apoyo. Activa los glúteos y el abdomen para estabilizar el cuerpo. Levanta lentamente una pierna del suelo, mantenié', 'upper legs', 'stability ball', 'upper legs', 'upper legs', 'glutes', '{"hamstrings","quadriceps","core"}', 'Túmbate boca abajo sobre el balón de estabilidad con las caderas apoyadas en el balón y las piernas extendidas rectas detrás de ti. Coloca las manos en el suelo frente a ti para mayor apoyo. Activa los glúteos y el abdomen para estabilizar el cuerpo. Levanta lentamente una pierna del suelo, manteniéndola recta y paralela al piso. Gira la pierna hacia afuera, alejándola del cuerpo, mientras mantienes las caderas y la parte superior del cuerpo estables. Haz una pausa al final de la rotación, luego regresa lentamente la pierna a la posición inicial. Repite la rotación con la otra pierna. Continúa alternando las piernas durante el número de repeticiones deseado.', 'Lie face down on the stability ball with your hips resting on the ball and your legs extended straight behind you. Place your hands on the ground in front of you for support. Engage your glutes and core muscles to stabilize your body. Slowly lift one leg off the ground, keeping it straight and parallel to the floor. Rotate your leg outward, away from your body, while keeping your hips and upper body stable. Pause for a moment at the end of the rotation, then slowly return your leg to the starting position. Repeat the rotation with the other leg. Continue alternating legs for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1416-M72BExt.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1416-M72BExt.gif', 'M72BExt', '© Gym visual — https://gymvisual.com/'),
('1417', 'exercise ball one legged diagonal kick hamstring curl', 'Comienza acostado sobre la espalda con las piernas extendidas y los talones apoyados sobre el balón de estabilidad. Coloca los brazos a los lados del cuerpo para mantener el equilibrio. Activa los glúteos y el abdomen para levantar las caderas del suelo, formando una línea recta desde los hombros ha', 'upper legs', 'stability ball', 'upper legs', 'upper legs', 'glutes', '{"hamstrings","calves"}', 'Comienza acostado sobre la espalda con las piernas extendidas y los talones apoyados sobre el balón de estabilidad. Coloca los brazos a los lados del cuerpo para mantener el equilibrio. Activa los glúteos y el abdomen para levantar las caderas del suelo, formando una línea recta desde los hombros hasta los talones. Dobla la rodilla derecha y llévala hacia el pecho, manteniendo la pierna izquierda extendida y el pie en flexión. Lleva la pierna derecha en diagonal a través del cuerpo, extendiéndola por completo y activando los isquiotibiales. Regresa lentamente la pierna derecha a la posición inicial, manteniendo el control y el equilibrio. Repite el movimiento con la pierna izquierda, alternando los lados durante el número de repeticiones deseado.', 'Start by lying on your back with your legs extended and your heels resting on top of the stability ball. Place your arms by your sides for stability. Engage your glutes and core muscles to lift your hips off the ground, creating a straight line from your shoulders to your heels. Bend your right knee and bring it towards your chest, keeping your left leg extended and your foot flexed. Kick your right leg diagonally across your body, extending it fully and engaging your hamstrings. Slowly return your right leg to the starting position, maintaining control and stability. Repeat the movement with your left leg, alternating sides for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1417-GOJKFfO.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1417-GOJKFfO.gif', 'GOJKFfO', '© Gym visual — https://gymvisual.com/'),
('1296', 'exercise ball pike push up', 'Comienza en posición de flexión de brazos con las manos en el suelo y las espinillas apoyadas sobre el balón de estabilidad. Activa el core y levanta las caderas hacia el techo, haciendo rodar el balón hacia las manos. Mantén las piernas rectas y el cuerpo en posición de pica, formando una V inverti', 'chest', 'stability ball', 'chest', 'chest', 'pectorals', '{"shoulders","triceps","core"}', 'Comienza en posición de flexión de brazos con las manos en el suelo y las espinillas apoyadas sobre el balón de estabilidad. Activa el core y levanta las caderas hacia el techo, haciendo rodar el balón hacia las manos. Mantén las piernas rectas y el cuerpo en posición de pica, formando una V invertida. Dobla los codos y baja la parte superior del cuerpo hacia el suelo, manteniendo la cabeza alineada con las manos. Empuja con las manos y extiende los brazos para volver a la posición inicial. Repite el número de repeticiones deseado.', 'Start in a push-up position with your hands on the floor and your shins resting on the stability ball. Engage your core and lift your hips up towards the ceiling, rolling the ball towards your hands. Keep your legs straight and your body in a pike position, forming an inverted V shape. Bend your elbows and lower your upper body towards the floor, keeping your head in line with your hands. Push through your hands and extend your arms to return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1296-sVvXT5J.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1296-sVvXT5J.gif', 'sVvXT5J', '© Gym visual — https://gymvisual.com/'),
('1343', 'exercise ball prone leg raise', 'Túmbate boca abajo sobre una esterilla con las piernas extendidas y los dedos de los pies apoyados sobre el balón de estabilidad. Coloca las manos en el suelo, separadas a la altura de los hombros, y activa el abdomen. Manteniendo las piernas rectas, levántalas lentamente del suelo, usando la zona l', 'back', 'stability ball', 'back', 'back', 'spine', '{"abdominals","glutes"}', 'Túmbate boca abajo sobre una esterilla con las piernas extendidas y los dedos de los pies apoyados sobre el balón de estabilidad. Coloca las manos en el suelo, separadas a la altura de los hombros, y activa el abdomen. Manteniendo las piernas rectas, levántalas lentamente del suelo, usando la zona lumbar y los glúteos para elevarlas tan alto como sea posible. Haz una pausa por un momento en la parte superior, luego baja lentamente las piernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie face down on a mat with your legs extended and your toes resting on top of the stability ball. Place your hands on the ground, shoulder-width apart, and engage your core muscles. Keeping your legs straight, slowly lift them off the ground, using your lower back and glutes to raise them as high as possible. Pause for a moment at the top, then slowly lower your legs back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1343-lCKm4Rs.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1343-lCKm4Rs.gif', 'lCKm4Rs', '© Gym visual — https://gymvisual.com/'),
('1560', 'exercise ball seated hamstring stretch', 'Siéntate en el balón de estabilidad con los pies planos en el suelo y las rodillas flexionadas en un ángulo de 90 grados. Haz rodar el balón lentamente hacia adelante, caminando con los pies hacia afuera hasta que la parte superior de la espalda quede apoyada sobre el balón y las piernas queden exte', 'upper legs', 'stability ball', 'upper legs', 'upper legs', 'hamstrings', '{"glutes","lower back"}', 'Siéntate en el balón de estabilidad con los pies planos en el suelo y las rodillas flexionadas en un ángulo de 90 grados. Haz rodar el balón lentamente hacia adelante, caminando con los pies hacia afuera hasta que la parte superior de la espalda quede apoyada sobre el balón y las piernas queden extendidas rectas frente a ti. Coloca las manos en las caderas para mayor apoyo. Activa el core y baja lentamente la parte superior del cuerpo hacia el suelo, manteniendo la espalda recta y el pecho elevado. Detente cuando sientas un estiramiento en los isquiotibiales y mantén la posición durante 20-30 segundos. Regresa lentamente a la posición inicial empujando con los talones y usando los isquiotibiales para volver a subir. Repite el número de repeticiones deseado.', 'Sit on the stability ball with your feet flat on the ground and your knees bent at a 90-degree angle. Slowly roll the ball forward, walking your feet out until your upper back is resting on the ball and your legs are extended straight in front of you. Place your hands on your hips for support. Engage your core and slowly lower your upper body towards the ground, keeping your back straight and your chest lifted. Stop when you feel a stretch in your hamstrings, and hold the position for 20-30 seconds. Slowly return to the starting position by pushing through your heels and using your hamstrings to pull yourself back up. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1560-yRYyfdA.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1560-yRYyfdA.gif', 'yRYyfdA', '© Gym visual — https://gymvisual.com/'),
('1745', 'exercise ball seated triceps stretch', 'Siéntate sobre un balón de estabilidad con los pies apoyados en el suelo y la espalda recta. Sostén una mancuerna con una mano y extiende el brazo recto por encima de la cabeza. Dobla el codo y baja la mancuerna detrás de la cabeza, manteniendo el brazo cerca de la oreja. Mantén el estiramiento dura', 'upper arms', 'stability ball', 'upper arms', 'upper arms', 'triceps', '{"shoulders"}', 'Siéntate sobre un balón de estabilidad con los pies apoyados en el suelo y la espalda recta. Sostén una mancuerna con una mano y extiende el brazo recto por encima de la cabeza. Dobla el codo y baja la mancuerna detrás de la cabeza, manteniendo el brazo cerca de la oreja. Mantén el estiramiento durante unos segundos, luego regresa a la posición inicial. Repite con el otro brazo.', 'Sit on a stability ball with your feet flat on the ground and your back straight. Hold a dumbbell in one hand and extend your arm straight up above your head. Bend your elbow and lower the dumbbell behind your head, keeping your upper arm close to your ear. Hold the stretch for a few seconds, then return to the starting position. Repeat with the other arm.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1745-7ePTw4B.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1745-7ePTw4B.gif', '7ePTw4B', '© Gym visual — https://gymvisual.com/'),
('1746', 'exercise ball supine triceps extension', 'Siéntate sobre un balón de estabilidad con los pies apoyados en el suelo y las rodillas flexionadas en un ángulo de 90 grados. Sostén una mancuerna con ambas manos y extiende los brazos rectos hacia el techo. Baja lentamente la mancuerna detrás de la cabeza, manteniendo los codos cerca de las orejas', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'triceps', '{"shoulders"}', 'Siéntate sobre un balón de estabilidad con los pies apoyados en el suelo y las rodillas flexionadas en un ángulo de 90 grados. Sostén una mancuerna con ambas manos y extiende los brazos rectos hacia el techo. Baja lentamente la mancuerna detrás de la cabeza, manteniendo los codos cerca de las orejas. Haz una pausa por un momento, luego sube la mancuerna de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on an exercise ball with your feet flat on the ground and your knees bent at a 90-degree angle. Hold a dumbbell with both hands and extend your arms straight up towards the ceiling. Slowly lower the dumbbell behind your head, keeping your elbows close to your ears. Pause for a moment, then raise the dumbbell back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1746-Gm2Uv1z.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1746-Gm2Uv1z.gif', 'Gm2Uv1z', '© Gym visual — https://gymvisual.com/'),
('1747', 'ez bar french press on exercise ball', 'Siéntate sobre un balón de ejercicio y sostén una barra EZ con agarre prono. Extiende los brazos rectos hacia arriba, manteniendo los codos cerca de la cabeza. Baja lentamente la barra detrás de la cabeza doblando los codos. Haz una pausa breve y luego extiende los brazos de vuelta a la posición ini', 'upper arms', 'ez barbell', 'upper arms', 'upper arms', 'triceps', '{"shoulders"}', 'Siéntate sobre un balón de ejercicio y sostén una barra EZ con agarre prono. Extiende los brazos rectos hacia arriba, manteniendo los codos cerca de la cabeza. Baja lentamente la barra detrás de la cabeza doblando los codos. Haz una pausa breve y luego extiende los brazos de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on an exercise ball and hold an EZ barbell with an overhand grip. Extend your arms straight up, keeping your elbows close to your head. Slowly lower the barbell behind your head by bending your elbows. Pause for a moment, then extend your arms back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1747-CFN9P8G.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1747-CFN9P8G.gif', 'CFN9P8G', '© Gym visual — https://gymvisual.com/'),
('3010', 'ez bar lying bent arms pullover', 'Túmbate boca arriba en un banco con la cabeza en un extremo y los pies en el suelo. Sostén la barra EZ con agarre prono (palmas hacia afuera) y las manos separadas a la altura de los hombros. Extiende los brazos rectos por encima del pecho, manteniendo una ligera flexión en los codos. Baja la barra ', 'back', 'ez barbell', 'back', 'back', 'lats', '{"triceps","chest"}', 'Túmbate boca arriba en un banco con la cabeza en un extremo y los pies en el suelo. Sostén la barra EZ con agarre prono (palmas hacia afuera) y las manos separadas a la altura de los hombros. Extiende los brazos rectos por encima del pecho, manteniendo una ligera flexión en los codos. Baja la barra describiendo un arco detrás de la cabeza, manteniendo la ligera flexión en los codos. Haz una pausa breve, luego regresa la barra a la posición inicial invirtiendo el movimiento del arco. Repite el número de repeticiones deseado.', 'Lie flat on a bench with your head at one end and your feet on the floor. Hold the EZ barbell with a pronated grip (palms facing away from you) and your hands shoulder-width apart. Extend your arms straight above your chest, keeping a slight bend in your elbows. Lower the barbell in an arc motion behind your head, maintaining the slight bend in your elbows. Pause for a moment, then return the barbell to the starting position by reversing the arc motion. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3010-nDK1HJ0.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3010-nDK1HJ0.gif', 'nDK1HJ0', '© Gym visual — https://gymvisual.com/'),
('1748', 'ez bar lying close grip triceps extension behind head', 'Túmbate boca arriba en un banco con los pies planos sobre el suelo y la cabeza en el extremo del banco. Sostén la barra EZ con agarre cerrado, palmas hacia arriba, y extiende los brazos rectos por encima del pecho. Manteniendo los brazos superiores fijos, baja lentamente la barra detrás de la cabeza', 'upper arms', 'ez barbell', 'upper arms', 'upper arms', 'triceps', '{"shoulders"}', 'Túmbate boca arriba en un banco con los pies planos sobre el suelo y la cabeza en el extremo del banco. Sostén la barra EZ con agarre cerrado, palmas hacia arriba, y extiende los brazos rectos por encima del pecho. Manteniendo los brazos superiores fijos, baja lentamente la barra detrás de la cabeza flexionando los codos. Haz una pausa breve y luego extiende los brazos de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on a bench with your feet flat on the ground and your head at the end of the bench. Hold the ez barbell with a close grip, palms facing up, and extend your arms straight up over your chest. Keeping your upper arms stationary, slowly lower the barbell behind your head by bending your elbows. Pause for a moment, then extend your arms back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1748-6CKUx7o.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1748-6CKUx7o.gif', '6CKUx7o', '© Gym visual — https://gymvisual.com/'),
('1344', 'ez bar reverse grip bent over row', 'Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Sostén la barra EZ con agarre supino, palmas hacia arriba, y las manos separadas a la altura de los hombros. Inclínate hacia delante desde las caderas, manteniendo la espalda recta y el pecho eleva', 'back', 'ez barbell', 'back', 'back', 'upper back', '{"biceps","forearms"}', 'Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Sostén la barra EZ con agarre supino, palmas hacia arriba, y las manos separadas a la altura de los hombros. Inclínate hacia delante desde las caderas, manteniendo la espalda recta y el pecho elevado, hasta que el torso quede casi paralelo al suelo. Tira de la barra EZ hacia la parte baja del pecho, apretando los omóplatos entre sí. Haz una pausa breve en la parte superior, luego baja lentamente la barra EZ a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and knees slightly bent. Hold the ez barbell with an underhand grip, palms facing up, and hands shoulder-width apart. Bend forward at the hips, keeping your back straight and chest up, until your torso is almost parallel to the floor. Pull the ez barbell towards your lower chest, squeezing your shoulder blades together. Pause for a moment at the top, then slowly lower the ez barbell back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1344-G8dXpNG.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1344-G8dXpNG.gif', 'G8dXpNG', '© Gym visual — https://gymvisual.com/'),
('1682', 'ez bar seated close grip concentration curl', 'Siéntate en un banco con los pies apoyados en el suelo y sostén una barra EZ con agarre supino. Apoya el codo en la parte interna del muslo, justo por encima de la rodilla. Sube la barra curvando el brazo hacia el hombro mientras mantienes el brazo superior inmóvil. Contrae los bíceps en la parte su', 'upper arms', 'ez barbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Siéntate en un banco con los pies apoyados en el suelo y sostén una barra EZ con agarre supino. Apoya el codo en la parte interna del muslo, justo por encima de la rodilla. Sube la barra curvando el brazo hacia el hombro mientras mantienes el brazo superior inmóvil. Contrae los bíceps en la parte superior del movimiento, luego baja lentamente la barra a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a bench with your feet flat on the ground and hold an EZ barbell with an underhand grip. Rest your elbow on the inside of your thigh, just above the knee. Curl the barbell up towards your shoulder while keeping your upper arm stationary. Squeeze your biceps at the top of the movement, then slowly lower the barbell back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1682-Dsfz0Id.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1682-Dsfz0Id.gif', 'Dsfz0Id', '© Gym visual — https://gymvisual.com/'),
('1749', 'ez bar standing french press', 'Ponte de pie con los pies separados a la altura de los hombros y sostén la barra EZ con agarre prono. Levanta la barra por encima de la cabeza, extendiendo completamente los brazos. Manteniendo los brazos superiores cerca de la cabeza, baja lentamente la barra detrás de la cabeza flexionando los cod', 'upper arms', 'ez barbell', 'upper arms', 'upper arms', 'triceps', '{"shoulders"}', 'Ponte de pie con los pies separados a la altura de los hombros y sostén la barra EZ con agarre prono. Levanta la barra por encima de la cabeza, extendiendo completamente los brazos. Manteniendo los brazos superiores cerca de la cabeza, baja lentamente la barra detrás de la cabeza flexionando los codos. Haz una pausa por un momento y luego extiende los brazos de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and hold the ez barbell with an overhand grip. Raise the barbell above your head, fully extending your arms. Keeping your upper arms close to your head, slowly lower the barbell behind your head by bending your elbows. Pause for a moment, then extend your arms back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1749-1cTf2Ux.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1749-1cTf2Ux.gif', '1cTf2Ux', '© Gym visual — https://gymvisual.com/'),
('0445', 'ez barbell anti gravity press', 'Comienza de pie con los pies separados a la altura de los hombros y sosteniendo la barra EZ con agarre prono. Eleva la barra hasta la altura de los hombros, manteniendo los codos ligeramente flexionados y las palmas hacia adelante. Empuja la barra por encima de la cabeza, extendiendo completamente l', 'shoulders', 'ez barbell', 'shoulders', 'shoulders', 'delts', '{"triceps","chest"}', 'Comienza de pie con los pies separados a la altura de los hombros y sosteniendo la barra EZ con agarre prono. Eleva la barra hasta la altura de los hombros, manteniendo los codos ligeramente flexionados y las palmas hacia adelante. Empuja la barra por encima de la cabeza, extendiendo completamente los brazos. Baja la barra de vuelta a la altura de los hombros y repite el número de repeticiones deseado.', 'Start by standing with your feet shoulder-width apart and holding the ez barbell with an overhand grip. Raise the barbell to shoulder height, keeping your elbows slightly bent and your palms facing forward. Press the barbell overhead, extending your arms fully. Lower the barbell back to shoulder height and repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0445-fprd84i.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0445-fprd84i.gif', 'fprd84i', '© Gym visual — https://gymvisual.com/'),
('1627', 'ez barbell close grip preacher curl', 'Siéntate en un banco scott y coloca los brazos superiores sobre la almohadilla, sujetando la barra EZ con agarre supino. Apoya los tríceps sobre la almohadilla y extiende los brazos por completo, manteniendo la espalda recta. Sube lentamente la barra hacia los hombros, contrayendo los bíceps. Haz un', 'upper arms', 'ez barbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Siéntate en un banco scott y coloca los brazos superiores sobre la almohadilla, sujetando la barra EZ con agarre supino. Apoya los tríceps sobre la almohadilla y extiende los brazos por completo, manteniendo la espalda recta. Sube lentamente la barra hacia los hombros, contrayendo los bíceps. Haz una pausa breve en la parte alta, apretando los bíceps. Baja la barra a la posición inicial, extendiendo los brazos por completo. Repite el número de repeticiones deseado.', 'Sit on a preacher curl bench and place your upper arms on the pad, gripping the ez barbell with an underhand grip. Rest your triceps on the pad and fully extend your arms, keeping your back straight. Slowly curl the barbell towards your shoulders, contracting your biceps. Pause for a moment at the top, squeezing your biceps. Lower the barbell back to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1627-hacCyUv.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1627-hacCyUv.gif', 'hacCyUv', '© Gym visual — https://gymvisual.com/'),
('0446', 'ez barbell close-grip curl', 'Ponte de pie con los pies separados a la altura de los hombros y sostén la barra EZ con agarre supino, manos separadas a la altura de los hombros. Mantén los codos cerca del torso y los brazos superiores quietos durante todo el movimiento. Sube la barra hacia los hombros, contrayendo los bíceps. Haz', 'upper arms', 'ez barbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ponte de pie con los pies separados a la altura de los hombros y sostén la barra EZ con agarre supino, manos separadas a la altura de los hombros. Mantén los codos cerca del torso y los brazos superiores quietos durante todo el movimiento. Sube la barra hacia los hombros, contrayendo los bíceps. Haz una pausa breve en la parte alta y luego baja lentamente la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand up straight with your feet shoulder-width apart and hold the ez barbell with an underhand grip, hands shoulder-width apart. Keep your elbows close to your torso and your upper arms stationary throughout the movement. Curl the barbell up towards your shoulders, contracting your biceps. Pause for a moment at the top, then slowly lower the barbell back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0446-V4ryaZa.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0446-V4ryaZa.gif', 'V4ryaZa', '© Gym visual — https://gymvisual.com/'),
('0447', 'ez barbell curl', 'Ponte de pie con los pies separados a la altura de los hombros y sostén la barra EZ con agarre supino, palmas hacia arriba. Mantén los codos cerca del torso y los brazos superiores quietos durante todo el movimiento. Exhala mientras subes la barra hacia los hombros, contrayendo los bíceps. Haz una p', 'upper arms', 'ez barbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ponte de pie con los pies separados a la altura de los hombros y sostén la barra EZ con agarre supino, palmas hacia arriba. Mantén los codos cerca del torso y los brazos superiores quietos durante todo el movimiento. Exhala mientras subes la barra hacia los hombros, contrayendo los bíceps. Haz una pausa breve en la parte más alta, luego inhala mientras bajas lentamente la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand up straight with your feet shoulder-width apart and hold the ez barbell with an underhand grip, palms facing up. Keep your elbows close to your torso and your upper arms stationary throughout the movement. Exhale as you curl the barbell up towards your shoulders, contracting your biceps. Pause for a moment at the top, then inhale as you slowly lower the barbell back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0447-6TG6x2w.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0447-6TG6x2w.gif', '6TG6x2w', '© Gym visual — https://gymvisual.com/'),
('0448', 'ez barbell decline close grip face press', 'Túmbate en un banco declinado con la cabeza más baja que los pies. Sujeta la barra EZ con agarre cerrado, palmas una frente a la otra. Extiende los brazos rectos por encima del pecho, manteniendo los codos cerca del cuerpo. Baja la barra hacia la frente doblando los codos. Haz una pausa breve, luego', 'upper arms', 'ez barbell', 'upper arms', 'upper arms', 'triceps', '{"chest","shoulders"}', 'Túmbate en un banco declinado con la cabeza más baja que los pies. Sujeta la barra EZ con agarre cerrado, palmas una frente a la otra. Extiende los brazos rectos por encima del pecho, manteniendo los codos cerca del cuerpo. Baja la barra hacia la frente doblando los codos. Haz una pausa breve, luego empuja la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie on a decline bench with your head lower than your feet. Grasp the ez barbell with a close grip, palms facing each other. Extend your arms straight up above your chest, keeping your elbows close to your body. Lower the barbell towards your forehead by bending your elbows. Pause for a moment, then press the barbell back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0448-DgZQ11d.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0448-DgZQ11d.gif', 'DgZQ11d', '© Gym visual — https://gymvisual.com/'),
('2186', 'ez barbell decline triceps extension', 'Túmbate en un banco declinado con la cabeza más baja que los pies y los pies asegurados. Sostén la barra EZ con agarre prono, manos separadas a la altura de los hombros. Extiende completamente los brazos, manteniendo los codos cerca de la cabeza. Baja la barra lentamente hacia la frente, doblando lo', 'upper arms', 'ez barbell', 'upper arms', 'upper arms', 'triceps', '{"shoulders"}', 'Túmbate en un banco declinado con la cabeza más baja que los pies y los pies asegurados. Sostén la barra EZ con agarre prono, manos separadas a la altura de los hombros. Extiende completamente los brazos, manteniendo los codos cerca de la cabeza. Baja la barra lentamente hacia la frente, doblando los codos. Haz una pausa por un momento y luego extiende los brazos de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie on a decline bench with your head lower than your feet and your feet secured. Hold the ez barbell with an overhand grip, hands shoulder-width apart. Extend your arms fully, keeping your elbows close to your head. Lower the barbell slowly towards your forehead, bending your elbows. Pause for a moment, then extend your arms back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2186-CQHoDm0.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2186-CQHoDm0.gif', 'CQHoDm0', '© Gym visual — https://gymvisual.com/'),
('0449', 'ez barbell incline triceps extension', 'Coloca un banco inclinado a un ángulo de 45 grados. Siéntate en el banco con la espalda apoyada en el respaldo y sostén la barra EZ con agarre prono. Extiende completamente los brazos por encima de la cabeza, manteniendo los codos cerca de la cabeza. Baja la barra detrás de la cabeza doblando los co', 'upper arms', 'ez barbell', 'upper arms', 'upper arms', 'triceps', '{"shoulders"}', 'Coloca un banco inclinado a un ángulo de 45 grados. Siéntate en el banco con la espalda apoyada en el respaldo y sostén la barra EZ con agarre prono. Extiende completamente los brazos por encima de la cabeza, manteniendo los codos cerca de la cabeza. Baja la barra detrás de la cabeza doblando los codos, manteniendo los brazos superiores inmóviles. Haz una pausa por un momento y luego extiende los brazos de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Set up an incline bench at a 45-degree angle. Sit on the bench with your back against the pad and hold the ez barbell with an overhand grip. Extend your arms fully overhead, keeping your elbows close to your head. Lower the barbell behind your head by bending your elbows, keeping your upper arms stationary. Pause for a moment, then extend your arms back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0449-KyLtiLT.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0449-KyLtiLT.gif', 'KyLtiLT', '© Gym visual — https://gymvisual.com/'),
('0450', 'ez barbell jm bench press', 'Túmbate sobre un banco con los pies apoyados en el suelo y la espalda presionada contra el banco. Sujeta la barra EZ con agarre prono, ligeramente más ancho que la altura de los hombros. Baja la barra hacia el pecho, manteniendo los codos pegados cerca del cuerpo. Empuja la barra de vuelta a la posi', 'upper arms', 'ez barbell', 'upper arms', 'upper arms', 'triceps', '{"chest","shoulders"}', 'Túmbate sobre un banco con los pies apoyados en el suelo y la espalda presionada contra el banco. Sujeta la barra EZ con agarre prono, ligeramente más ancho que la altura de los hombros. Baja la barra hacia el pecho, manteniendo los codos pegados cerca del cuerpo. Empuja la barra de vuelta a la posición inicial, extendiendo completamente los brazos. Repite el número de repeticiones deseado.', 'Lie flat on a bench with your feet flat on the ground and your back pressed against the bench. Grasp the ez barbell with an overhand grip, slightly wider than shoulder-width apart. Lower the barbell to your chest, keeping your elbows tucked in close to your body. Push the barbell back up to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0450-hnOYgH3.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0450-hnOYgH3.gif', 'hnOYgH3', '© Gym visual — https://gymvisual.com/'),
('0451', 'ez barbell reverse grip curl', 'Ponte de pie con los pies separados a la altura de los hombros y sostén la barra EZ con agarre supino. Mantén los codos cerca del torso y los brazos superiores inmóviles durante todo el ejercicio. Sube la barra contrayendo los bíceps, mientras exhalas. Continúa levantando la barra hasta que los bíce', 'upper arms', 'ez barbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ponte de pie con los pies separados a la altura de los hombros y sostén la barra EZ con agarre supino. Mantén los codos cerca del torso y los brazos superiores inmóviles durante todo el ejercicio. Sube la barra contrayendo los bíceps, mientras exhalas. Continúa levantando la barra hasta que los bíceps estén completamente contraídos y la barra esté a la altura de los hombros. Mantén la posición contraída durante una breve pausa mientras aprietas los bíceps. Comienza a regresar la barra lentamente a la posición inicial mientras inhalas. Repite el número de repeticiones deseado.', 'Stand up straight with your feet shoulder-width apart and hold the ez barbell with an underhand grip. Keep your elbows close to your torso and your upper arms stationary throughout the exercise. Curl the barbell upwards by contracting your biceps, while exhaling. Continue to raise the barbell until your biceps are fully contracted and the barbell is at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Slowly begin to bring the barbell back to the starting position as you inhale. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0451-Y5X65IB.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0451-Y5X65IB.gif', 'Y5X65IB', '© Gym visual — https://gymvisual.com/'),
('0452', 'ez barbell reverse grip preacher curl', 'Siéntate en un banco scott con el pecho apoyado en la almohadilla y los pies planos sobre el suelo. Sujeta la barra EZ con agarre supino, manos separadas a la altura de los hombros. Apoya los brazos superiores en la almohadilla, dejando que los antebrazos cuelguen hacia abajo. Manteniendo los brazos', 'upper arms', 'ez barbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Siéntate en un banco scott con el pecho apoyado en la almohadilla y los pies planos sobre el suelo. Sujeta la barra EZ con agarre supino, manos separadas a la altura de los hombros. Apoya los brazos superiores en la almohadilla, dejando que los antebrazos cuelguen hacia abajo. Manteniendo los brazos superiores fijos, exhala y levanta la barra hacia los hombros. Haz una pausa breve en la parte más alta, luego inhala y baja lentamente la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a preacher bench with your chest against the pad and your feet flat on the floor. Grasp the ez barbell with an underhand grip, hands shoulder-width apart. Rest your upper arms on the pad, allowing your forearms to hang down. Keeping your upper arms stationary, exhale and curl the barbell up towards your shoulders. Pause for a moment at the top, then inhale and slowly lower the barbell back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0452-vBNyir7.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0452-vBNyir7.gif', 'vBNyir7', '© Gym visual — https://gymvisual.com/'),
('1458', 'ez barbell seated curls', 'Siéntate en un banco con los pies apoyados planos en el suelo y la espalda recta. Sostén la barra EZ con agarre supino, palmas hacia arriba, y las manos separadas a la altura de los hombros. Apoya los brazos superiores en los muslos, dejando que la barra EZ cuelgue frente a ti. Manteniendo los brazo', 'upper arms', 'ez barbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Siéntate en un banco con los pies apoyados planos en el suelo y la espalda recta. Sostén la barra EZ con agarre supino, palmas hacia arriba, y las manos separadas a la altura de los hombros. Apoya los brazos superiores en los muslos, dejando que la barra EZ cuelgue frente a ti. Manteniendo los brazos superiores inmóviles, exhala y sube la barra EZ hacia los hombros. Haz una pausa breve en la parte alta, apretando los bíceps. Inhala y baja lentamente la barra EZ a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a bench with your feet flat on the ground and your back straight. Hold the ez barbell with an underhand grip, palms facing up, and your hands shoulder-width apart. Rest your upper arms on your thighs, allowing the ez barbell to hang down in front of you. Keeping your upper arms stationary, exhale and curl the ez barbell upwards towards your shoulders. Pause for a moment at the top, squeezing your biceps. Inhale and slowly lower the ez barbell back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1458-jtFKbt5.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1458-jtFKbt5.gif', 'jtFKbt5', '© Gym visual — https://gymvisual.com/'),
('0453', 'ez barbell seated triceps extension', 'Siéntate en un banco con la espalda recta y los pies planos sobre el suelo. Sostén la barra EZ con agarre prono, manos separadas a la altura de los hombros. Levanta la barra por encima de la cabeza, extendiendo completamente los brazos. Manteniendo los brazos superiores inmóviles, baja la barra detr', 'upper arms', 'ez barbell', 'upper arms', 'upper arms', 'triceps', '{"shoulders"}', 'Siéntate en un banco con la espalda recta y los pies planos sobre el suelo. Sostén la barra EZ con agarre prono, manos separadas a la altura de los hombros. Levanta la barra por encima de la cabeza, extendiendo completamente los brazos. Manteniendo los brazos superiores inmóviles, baja la barra detrás de la cabeza doblando los codos. Haz una pausa breve, luego levanta la barra de vuelta a la posición inicial extendiendo los brazos. Repite el número de repeticiones deseado.', 'Sit on a bench with your back straight and feet flat on the ground. Hold the ez barbell with an overhand grip, hands shoulder-width apart. Raise the barbell overhead, fully extending your arms. Keeping your upper arms stationary, lower the barbell behind your head by bending your elbows. Pause for a moment, then raise the barbell back to the starting position by extending your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0453-iaapw0g.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0453-iaapw0g.gif', 'iaapw0g', '© Gym visual — https://gymvisual.com/'),
('0454', 'ez barbell spider curl', 'Ponte de pie con los pies separados a la altura de los hombros y sostén la barra EZ con agarre supino, palmas hacia arriba. Apoya los brazos superiores en un banco scott o en un balón de estabilidad, dejando que los codos cuelguen hacia abajo. Manteniendo los brazos superiores fijos, exhala y levant', 'upper arms', 'ez barbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ponte de pie con los pies separados a la altura de los hombros y sostén la barra EZ con agarre supino, palmas hacia arriba. Apoya los brazos superiores en un banco scott o en un balón de estabilidad, dejando que los codos cuelguen hacia abajo. Manteniendo los brazos superiores fijos, exhala y levanta la barra hacia los hombros. Haz una pausa breve en la parte alta, apretando los bíceps. Inhala y baja lentamente la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and hold the ez barbell with an underhand grip, palms facing up. Rest your upper arms on a preacher bench or stability ball, allowing your elbows to hang down. Keeping your upper arms stationary, exhale and curl the barbell up towards your shoulders. Pause for a moment at the top, squeezing your biceps. Inhale and slowly lower the barbell back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0454-Ye5Qxb0.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0454-Ye5Qxb0.gif', 'Ye5Qxb0', '© Gym visual — https://gymvisual.com/'),
('1628', 'ez barbell spider curl', 'Ponte de pie con los pies separados a la altura de los hombros y sostén la barra EZ con agarre supino, palmas hacia arriba. Apoya los brazos superiores en un banco scott o en un balón de estabilidad, dejando que los codos cuelguen hacia abajo. Manteniendo los brazos superiores fijos, exhala y levant', 'upper arms', 'ez barbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ponte de pie con los pies separados a la altura de los hombros y sostén la barra EZ con agarre supino, palmas hacia arriba. Apoya los brazos superiores en un banco scott o en un balón de estabilidad, dejando que los codos cuelguen hacia abajo. Manteniendo los brazos superiores fijos, exhala y levanta la barra hacia los hombros. Haz una pausa breve en la parte alta, apretando los bíceps. Inhala y baja lentamente la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and hold the ez barbell with an underhand grip, palms facing up. Rest your upper arms on a preacher bench or stability ball, allowing your elbows to hang down. Keeping your upper arms stationary, exhale and curl the barbell up towards your shoulders. Pause for a moment at the top, squeezing your biceps. Inhale and slowly lower the barbell back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1628-2kattbR.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1628-2kattbR.gif', '2kattbR', '© Gym visual — https://gymvisual.com/'),
('2404', 'ez-bar biceps curl (with arm blaster)', 'Ponte de pie con los pies separados a la altura de los hombros y sostén la barra EZ con agarre supino, palmas hacia arriba. Coloca los brazos superiores contra el soporte de aislamiento de brazos, manteniéndolos inmóviles durante todo el ejercicio. Manteniendo los codos cerca del cuerpo, exhala y su', 'upper arms', 'ez barbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ponte de pie con los pies separados a la altura de los hombros y sostén la barra EZ con agarre supino, palmas hacia arriba. Coloca los brazos superiores contra el soporte de aislamiento de brazos, manteniéndolos inmóviles durante todo el ejercicio. Manteniendo los codos cerca del cuerpo, exhala y sube la barra hacia los hombros. Haz una pausa breve en la parte alta, apretando los bíceps. Inhala y baja lentamente la barra de vuelta a la posición inicial, extendiendo completamente los brazos. Repite el número de repeticiones deseado.', 'Stand up straight with your feet shoulder-width apart and hold the ez barbell with an underhand grip, palms facing up. Place your upper arms against the arm blaster, keeping them stationary throughout the exercise. Keeping your elbows close to your body, exhale and curl the barbell up towards your shoulders. Pause for a moment at the top, squeezing your biceps. Inhale and slowly lower the barbell back to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2404-tJ5nYqo.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2404-tJ5nYqo.gif', 'tJ5nYqo', '© Gym visual — https://gymvisual.com/'),
('2432', 'ez-bar close-grip bench press', 'Túmbate sobre un banco con los pies apoyados en el suelo y la espalda presionada contra el banco. Sujeta la barra EZ con agarre cerrado, manos separadas a la altura de los hombros, palmas hacia adelante. Levanta la barra del soporte y sostenla directamente sobre el pecho con los brazos completamente', 'upper arms', 'ez barbell', 'upper arms', 'upper arms', 'triceps', '{"chest","shoulders"}', 'Túmbate sobre un banco con los pies apoyados en el suelo y la espalda presionada contra el banco. Sujeta la barra EZ con agarre cerrado, manos separadas a la altura de los hombros, palmas hacia adelante. Levanta la barra del soporte y sostenla directamente sobre el pecho con los brazos completamente extendidos. Baja la barra lentamente hacia el pecho, manteniendo los codos cerca del cuerpo. Haz una pausa breve cuando la barra toque el pecho. Empuja la barra de vuelta a la posición inicial, extendiendo completamente los brazos. Repite el número de repeticiones deseado.', 'Lie flat on a bench with your feet flat on the ground and your back pressed against the bench. Grasp the ez barbell with a close grip, hands shoulder-width apart, palms facing forward. Lift the barbell off the rack and hold it directly above your chest with your arms fully extended. Slowly lower the barbell towards your chest, keeping your elbows close to your body. Pause for a moment when the barbell touches your chest. Push the barbell back up to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2432-da4cXST.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2432-da4cXST.gif', 'da4cXST', '© Gym visual — https://gymvisual.com/'),
('2741', 'ez-barbell standing wide grip biceps curl', 'Ponte de pie con los pies separados a la altura de los hombros y sostén la barra EZ con agarre supino, manos más separadas que la altura de los hombros. Mantén los codos cerca del torso y los brazos superiores quietos durante todo el movimiento. Sube la barra hacia los hombros contrayendo los bíceps', 'upper arms', 'ez barbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ponte de pie con los pies separados a la altura de los hombros y sostén la barra EZ con agarre supino, manos más separadas que la altura de los hombros. Mantén los codos cerca del torso y los brazos superiores quietos durante todo el movimiento. Sube la barra hacia los hombros contrayendo los bíceps. Haz una pausa breve en la parte alta y luego baja lentamente la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand up straight with your feet shoulder-width apart and hold the ez barbell with an underhand grip, hands wider than shoulder-width apart. Keep your elbows close to your torso and your upper arms stationary throughout the movement. Curl the barbell up towards your shoulders by contracting your biceps. Pause for a moment at the top, then slowly lower the barbell back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2741-OVTZ65k.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2741-OVTZ65k.gif', 'OVTZ65k', '© Gym visual — https://gymvisual.com/'),
('2133', 'farmers walk', 'Ponte de pie con una mancuerna en cada mano, palmas hacia los costados. Mantén la espalda recta y los hombros hacia atrás. Da pasos pequeños y controlados hacia adelante, manteniendo una postura erguida. Continúa caminando durante la distancia o el tiempo deseado. Para terminar, deja de caminar y ba', 'upper legs', 'dumbbell', 'upper legs', 'upper legs', 'quads', '{"calves","forearms","core"}', 'Ponte de pie con una mancuerna en cada mano, palmas hacia los costados. Mantén la espalda recta y los hombros hacia atrás. Da pasos pequeños y controlados hacia adelante, manteniendo una postura erguida. Continúa caminando durante la distancia o el tiempo deseado. Para terminar, deja de caminar y baja con cuidado las mancuernas a los costados.', 'Stand up straight with a dumbbell in each hand, palms facing your sides. Keep your back straight and your shoulders back. Take small, controlled steps forward, maintaining an upright posture. Continue walking for the desired distance or time. To finish, stop walking and carefully lower the dumbbells to your sides.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2133-qPEzJjA.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2133-qPEzJjA.gif', 'qPEzJjA', '© Gym visual — https://gymvisual.com/'),
('0455', 'finger curls', 'Siéntate en un banco con los pies planos sobre el suelo y sujeta una barra con un agarre supino, con las palmas hacia arriba. Apoya los antebrazos sobre los muslos, dejando que las muñecas cuelguen del borde. Curva lentamente los dedos hacia las palmas, apretando la barra con fuerza. Mantén la contr', 'lower arms', 'barbell', 'lower arms', 'lower arms', 'forearms', '{"wrist flexors","grip muscles"}', 'Siéntate en un banco con los pies planos sobre el suelo y sujeta una barra con un agarre supino, con las palmas hacia arriba. Apoya los antebrazos sobre los muslos, dejando que las muñecas cuelguen del borde. Curva lentamente los dedos hacia las palmas, apretando la barra con fuerza. Mantén la contracción por un momento, luego suelta lentamente los dedos hasta la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a bench with your feet flat on the ground and hold a barbell with an underhand grip, palms facing up. Rest your forearms on your thighs, allowing your wrists to hang off the edge. Slowly curl your fingers towards your palms, squeezing the barbell tightly. Hold the contraction for a moment, then slowly release your fingers back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0455-awG04cF.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0455-awG04cF.gif', 'awG04cF', '© Gym visual — https://gymvisual.com/'),
('3303', 'flag', 'Comienza sujetando un poste vertical con ambas manos, palmas una frente a la otra, y los brazos completamente extendidos. Activa el core y levanta las piernas del suelo, manteniéndolas rectas. Usando la fuerza del core y de la parte superior del cuerpo, levanta las piernas hasta que queden paralelas', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"obliques","shoulders"}', 'Comienza sujetando un poste vertical con ambas manos, palmas una frente a la otra, y los brazos completamente extendidos. Activa el core y levanta las piernas del suelo, manteniéndolas rectas. Usando la fuerza del core y de la parte superior del cuerpo, levanta las piernas hasta que queden paralelas al suelo. Mantén esta posición todo el tiempo que puedas, conservando una línea corporal recta. Baja lentamente las piernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Start by gripping a vertical pole with both hands, palms facing each other, and arms fully extended. Engage your core and lift your legs off the ground, keeping them straight. Using your core and upper body strength, raise your legs until they are parallel to the ground. Hold this position for as long as you can, maintaining a straight body line. Slowly lower your legs back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3303-pQ0Mx1Z.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3303-pQ0Mx1Z.gif', 'pQ0Mx1Z', '© Gym visual — https://gymvisual.com/'),
('0456', 'flexion leg sit up (bent knee)', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Coloca las manos detrás de la cabeza con los codos apuntando hacia afuera. Activando el abdomen, levanta lentamente la parte superior del cuerpo del suelo, curvándote hacia adelante hasta que tu torso forme un áng', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"hip flexors"}', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Coloca las manos detrás de la cabeza con los codos apuntando hacia afuera. Activando el abdomen, levanta lentamente la parte superior del cuerpo del suelo, curvándote hacia adelante hasta que tu torso forme un ángulo de 45 grados. Al mismo tiempo, levanta las piernas del suelo, doblando las rodillas y llevándolas hacia el pecho. Haz una pausa breve en la parte superior, luego baja lentamente la parte superior del cuerpo y las piernas a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on your back with your knees bent and feet flat on the ground. Place your hands behind your head with your elbows pointing outwards. Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle. At the same time, lift your legs off the ground, bending your knees and bringing them towards your chest. Pause for a moment at the top, then slowly lower your upper body and legs back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0456-AR0ig3o.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0456-AR0ig3o.gif', 'AR0ig3o', '© Gym visual — https://gymvisual.com/'),
('0457', 'flexion leg sit up (straight arm)', 'Túmbate boca arriba con las piernas extendidas y los brazos rectos por encima de la cabeza. Activando el abdomen, levanta la parte superior del cuerpo del suelo mientras al mismo tiempo levantas las piernas hacia el pecho. Extiende las manos hacia los dedos de los pies mientras levantas la parte sup', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"hip flexors","quadriceps"}', 'Túmbate boca arriba con las piernas extendidas y los brazos rectos por encima de la cabeza. Activando el abdomen, levanta la parte superior del cuerpo del suelo mientras al mismo tiempo levantas las piernas hacia el pecho. Extiende las manos hacia los dedos de los pies mientras levantas la parte superior del cuerpo y las piernas. Haz una pausa breve en la parte superior, luego baja lentamente la parte superior del cuerpo y las piernas a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on your back with your legs extended and arms straight above your head. Engaging your abs, lift your upper body off the ground while simultaneously lifting your legs towards your chest. Reach your hands towards your toes as you lift your upper body and legs. Pause for a moment at the top, then slowly lower your upper body and legs back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0457-KZn52RC.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0457-KZn52RC.gif', 'KZn52RC', '© Gym visual — https://gymvisual.com/'),
('0458', 'floor fly (with barbell)', 'Túmbate boca arriba en el suelo con las rodillas flexionadas y los pies planos sobre el suelo. Sostén una barra con agarre prono, brazos extendidos rectos por encima del pecho. Baja lentamente la barra hacia los lados, manteniendo una ligera flexión en los codos. Baja la barra hasta que los brazos q', 'chest', 'barbell', 'chest', 'chest', 'pectorals', '{"deltoids","triceps"}', 'Túmbate boca arriba en el suelo con las rodillas flexionadas y los pies planos sobre el suelo. Sostén una barra con agarre prono, brazos extendidos rectos por encima del pecho. Baja lentamente la barra hacia los lados, manteniendo una ligera flexión en los codos. Baja la barra hasta que los brazos queden paralelos al suelo, sintiendo un estiramiento en el pecho. Haz una pausa breve, luego contrae los músculos del pecho para llevar la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on your back on the floor with your knees bent and feet flat on the ground. Hold a barbell with an overhand grip, arms extended straight up over your chest. Slowly lower the barbell out to the sides, keeping a slight bend in your elbows. Lower the barbell until your arms are parallel to the floor, feeling a stretch in your chest. Pause for a moment, then squeeze your chest muscles to bring the barbell back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0458-neonEDL.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0458-neonEDL.gif', 'neonEDL', '© Gym visual — https://gymvisual.com/'),
('0459', 'flutter kicks', 'Túmbate boca arriba con las piernas extendidas y las manos a los costados. Activa el core y levanta las piernas del suelo unos 15 centímetros. Manteniendo las piernas rectas, alterna levantando una pierna ligeramente más alto que la otra. Continúa este movimiento de aleteo durante el número de repet', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'glutes', '{"hip flexors","lower abs"}', 'Túmbate boca arriba con las piernas extendidas y las manos a los costados. Activa el core y levanta las piernas del suelo unos 15 centímetros. Manteniendo las piernas rectas, alterna levantando una pierna ligeramente más alto que la otra. Continúa este movimiento de aleteo durante el número de repeticiones deseado.', 'Lie flat on your back with your legs extended and your hands by your sides. Engage your core and lift your legs off the ground about 6 inches. Keeping your legs straight, alternate lifting one leg slightly higher than the other. Continue this fluttering motion for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0459-UVo2Qs2.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0459-UVo2Qs2.gif', 'UVo2Qs2', '© Gym visual — https://gymvisual.com/'),
('1472', 'forward jump', 'Ponte de pie con los pies separados a la altura de los hombros. Flexiona las rodillas y baja el cuerpo hacia una posición de sentadilla. Balancea los brazos hacia atrás para generar impulso. Salta hacia adelante de forma explosiva, extendiendo las caderas, las rodillas y los tobillos. Aterriza suave', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'quads', '{"calves","hamstrings","glutes"}', 'Ponte de pie con los pies separados a la altura de los hombros. Flexiona las rodillas y baja el cuerpo hacia una posición de sentadilla. Balancea los brazos hacia atrás para generar impulso. Salta hacia adelante de forma explosiva, extendiendo las caderas, las rodillas y los tobillos. Aterriza suavemente sobre la punta de los pies y pasa de inmediato al siguiente salto. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart. Bend your knees and lower your body into a squat position. Swing your arms back for momentum. Jump forward explosively, extending your hips, knees, and ankles. Land softly on the balls of your feet and immediately go into the next jump. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1472-uZKq7lo.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1472-uZKq7lo.gif', 'uZKq7lo', '© Gym visual — https://gymvisual.com/'),
('3470', 'forward lunge (male)', 'Ponte de pie con los pies separados a la altura de las caderas y las manos en las caderas. Da un paso grande hacia adelante con el pie derecho, bajando el cuerpo hasta una posición de zancada. Dobla la rodilla derecha hasta unos 90 grados, manteniendo la rodilla alineada con el tobillo. Empuja con e', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves"}', 'Ponte de pie con los pies separados a la altura de las caderas y las manos en las caderas. Da un paso grande hacia adelante con el pie derecho, bajando el cuerpo hasta una posición de zancada. Dobla la rodilla derecha hasta unos 90 grados, manteniendo la rodilla alineada con el tobillo. Empuja con el pie derecho y vuelve a la posición inicial. Repite con la pierna izquierda, alternando los lados durante el número de repeticiones deseado.', 'Stand with your feet hip-width apart and hands on your hips. Take a big step forward with your right foot, lowering your body into a lunge position. Bend your right knee to about 90 degrees, keeping your knee aligned with your ankle. Push off with your right foot and return to the starting position. Repeat with your left leg, alternating sides for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3470-kMzUs9Y.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3470-kMzUs9Y.gif', 'kMzUs9Y', '© Gym visual — https://gymvisual.com/'),
('3194', 'frankenstein squat', 'Ponte de pie con los pies separados a la altura de los hombros y sostén la barra frente al cuerpo con los brazos rectos. Manteniendo la espalda recta, baja el cuerpo flexionando las rodillas y las caderas, como si fueras a sentarte en una silla. Continúa bajando hasta que los muslos queden paralelos', 'upper legs', 'barbell', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves"}', 'Ponte de pie con los pies separados a la altura de los hombros y sostén la barra frente al cuerpo con los brazos rectos. Manteniendo la espalda recta, baja el cuerpo flexionando las rodillas y las caderas, como si fueras a sentarte en una silla. Continúa bajando hasta que los muslos queden paralelos al suelo, o tan abajo como puedas hacerlo cómodamente. Haz una pausa breve y luego empuja con los talones para volver a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and hold the barbell in front of your body with straight arms. Keeping your back straight, lower your body by bending at the knees and hips, as if sitting back into a chair. Continue lowering until your thighs are parallel to the ground, or as low as you can comfortably go. Pause for a moment, then push through your heels to return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3194-bdWcbaU.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3194-bdWcbaU.gif', 'bdWcbaU', '© Gym visual — https://gymvisual.com/'),
('2429', 'frog crunch', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Coloca las manos detrás de la cabeza con los codos apuntando hacia afuera. Activando el abdomen, levanta la parte superior del cuerpo del suelo, curvándote hacia adelante hasta que el torso forme un ángulo de 45 g', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"hip flexors"}', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Coloca las manos detrás de la cabeza con los codos apuntando hacia afuera. Activando el abdomen, levanta la parte superior del cuerpo del suelo, curvándote hacia adelante hasta que el torso forme un ángulo de 45 grados. Haz una pausa por un momento en la parte superior, luego baja lentamente la parte superior del cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on your back with your knees bent and feet flat on the ground. Place your hands behind your head with your elbows pointing outwards. Engaging your abs, lift your upper body off the ground, curling forward until your torso is at a 45-degree angle. Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2429-FFRP97T.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2429-FFRP97T.gif', 'FFRP97T', '© Gym visual — https://gymvisual.com/'),
('3301', 'frog planche', 'Comienza en posición de flexión de brazos con las manos separadas a la altura de los hombros y los pies juntos. Dobla los codos y baja el cuerpo hacia el suelo, manteniendo la espalda recta. Mientras bajas el cuerpo, levanta los pies del suelo y lleva las rodillas hacia el pecho. Mantén esta posició', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"shoulders","chest","triceps"}', 'Comienza en posición de flexión de brazos con las manos separadas a la altura de los hombros y los pies juntos. Dobla los codos y baja el cuerpo hacia el suelo, manteniendo la espalda recta. Mientras bajas el cuerpo, levanta los pies del suelo y lleva las rodillas hacia el pecho. Mantén esta posición durante unos segundos, luego extiende las piernas de nuevo y empújate hacia arriba a la posición inicial. Repite el número de repeticiones deseado.', 'Start in a push-up position with your hands shoulder-width apart and your feet together. Bend your elbows and lower your body towards the ground, keeping your back straight. As you lower your body, lift your feet off the ground and bring your knees towards your chest. Hold this position for a few seconds, then extend your legs back out and push yourself back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3301-rQhGcin.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3301-rQhGcin.gif', 'rQhGcin', '© Gym visual — https://gymvisual.com/'),
('3296', 'front lever', 'Comienza colgado de una barra de dominadas con agarre prono, manos separadas a la altura de los hombros. Activa el core y lleva los omóplatos hacia abajo y atrás. Flexiona las rodillas y llévalas hacia el pecho. Al mismo tiempo, levanta las piernas y extiéndelas rectas frente a ti, manteniendo el cu', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"lats","shoulders","forearms"}', 'Comienza colgado de una barra de dominadas con agarre prono, manos separadas a la altura de los hombros. Activa el core y lleva los omóplatos hacia abajo y atrás. Flexiona las rodillas y llévalas hacia el pecho. Al mismo tiempo, levanta las piernas y extiéndelas rectas frente a ti, manteniendo el cuerpo paralelo al suelo. Mantén esta posición todo el tiempo que puedas, intentando lograr una posición completa de palanca frontal. Para soltar, baja lentamente las piernas y regresa a la posición inicial. Repite el número de repeticiones deseado.', 'Start by hanging from a pull-up bar with an overhand grip, hands shoulder-width apart. Engage your core and pull your shoulder blades down and back. Bend your knees and tuck them towards your chest. Simultaneously, lift your legs up and extend them straight out in front of you, keeping your body parallel to the ground. Hold this position for as long as you can, aiming for a full front lever position. To release, slowly lower your legs back down and return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3296-PkCN2lv.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3296-PkCN2lv.gif', 'PkCN2lv', '© Gym visual — https://gymvisual.com/'),
('3295', 'front lever reps', 'Cuélgate de una barra de dominadas con agarre prono, palmas hacia afuera. Activa el core y lleva los omóplatos hacia abajo y atrás. Manteniendo el cuerpo recto, levanta las piernas hasta que queden paralelas al suelo. Mantén esta posición todo el tiempo que puedas, intentando llegar a 10-20 segundos', 'back', 'body weight', 'back', 'back', 'upper back', '{"core","shoulders"}', 'Cuélgate de una barra de dominadas con agarre prono, palmas hacia afuera. Activa el core y lleva los omóplatos hacia abajo y atrás. Manteniendo el cuerpo recto, levanta las piernas hasta que queden paralelas al suelo. Mantén esta posición todo el tiempo que puedas, intentando llegar a 10-20 segundos. Baja lentamente las piernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Hang from a pull-up bar with an overhand grip, palms facing away from you. Engage your core and pull your shoulder blades down and back. Keeping your body straight, lift your legs up until they are parallel to the ground. Hold this position for as long as you can, aiming for 10-20 seconds. Slowly lower your legs back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3295-hbY9wqG.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3295-hbY9wqG.gif', 'hbY9wqG', '© Gym visual — https://gymvisual.com/'),
('0464', 'front plank with twist', 'Comienza en posición de plancha alta con las manos directamente debajo de los hombros y el cuerpo en línea recta de la cabeza a los pies. Activa el core y los glúteos para mantener una posición estable. Gira el torso hacia la derecha, levantando el brazo derecho y extendiéndolo hacia el techo. Manté', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"obliques","shoulders"}', 'Comienza en posición de plancha alta con las manos directamente debajo de los hombros y el cuerpo en línea recta de la cabeza a los pies. Activa el core y los glúteos para mantener una posición estable. Gira el torso hacia la derecha, levantando el brazo derecho y extendiéndolo hacia el techo. Mantén las caderas y las piernas estables mientras giras. Mantén la posición por un momento, luego regresa a la posición inicial. Repite el giro hacia el lado izquierdo. Continúa alternando lados durante el número de repeticiones deseado.', 'Start in a high plank position with your hands directly under your shoulders and your body in a straight line from head to toe. Engage your core and glutes to maintain a stable position. Rotate your torso to the right, lifting your right arm and extending it towards the ceiling. Keep your hips and legs stable as you twist. Hold for a moment, then return to the starting position. Repeat the twist on the left side. Continue alternating sides for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0464-CosupLu.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0464-CosupLu.gif', 'CosupLu', '© Gym visual — https://gymvisual.com/'),
('3315', 'full maltese', 'Comienza de pie con los pies separados a la altura de los hombros y los brazos extendidos rectos hacia los lados. Inclínate lentamente hacia adelante, manteniendo los brazos rectos, hasta que la parte superior del cuerpo quede paralela al suelo. Activa el core y mantén esta posición durante unos seg', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"shoulders","chest"}', 'Comienza de pie con los pies separados a la altura de los hombros y los brazos extendidos rectos hacia los lados. Inclínate lentamente hacia adelante, manteniendo los brazos rectos, hasta que la parte superior del cuerpo quede paralela al suelo. Activa el core y mantén esta posición durante unos segundos. Regresa a la posición inicial empujando con los pies y volviendo a ponerte de pie. Repite el número de repeticiones deseado.', 'Start by standing with your feet shoulder-width apart and your arms extended straight out to the sides. Slowly lean forward, keeping your arms straight, until your upper body is parallel to the ground. Engage your core and hold this position for a few seconds. Return to the starting position by pushing through your feet and standing back up. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3315-YRaCa5Y.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3315-YRaCa5Y.gif', 'YRaCa5Y', '© Gym visual — https://gymvisual.com/'),
('3299', 'full planche', 'Comienza en posición de flexión de brazos con las manos separadas a la altura de los hombros y los dedos apuntando hacia adelante. Activa el core y desplaza lentamente el peso hacia adelante, levantando los pies del suelo. Continúa desplazando el peso hacia adelante hasta que el cuerpo quede paralel', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"shoulders","chest","triceps"}', 'Comienza en posición de flexión de brazos con las manos separadas a la altura de los hombros y los dedos apuntando hacia adelante. Activa el core y desplaza lentamente el peso hacia adelante, levantando los pies del suelo. Continúa desplazando el peso hacia adelante hasta que el cuerpo quede paralelo al suelo, equilibrándote sobre las manos. Mantén esta posición todo el tiempo que puedas, conservando una línea corporal recta. Baja lentamente los pies de nuevo al suelo y regresa a la posición inicial. Repite el número de repeticiones deseado.', 'Start in a push-up position with your hands shoulder-width apart and your fingers pointing forward. Engage your core and slowly shift your weight forward, lifting your feet off the ground. Continue shifting your weight forward until your body is parallel to the ground, balancing on your hands. Hold this position for as long as you can, maintaining a straight body line. Slowly lower your feet back to the ground and return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3299-YZ4961r.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3299-YZ4961r.gif', 'YZ4961r', '© Gym visual — https://gymvisual.com/'),
('3327', 'full planche push-up', 'Comienza en posición de flexión de brazos con las manos un poco más separadas que el ancho de los hombros. Activa el core y baja el cuerpo hacia el suelo, manteniendo los codos cerca de los costados. Mientras te bajas, inclina el cuerpo hacia adelante y levanta los pies del suelo, equilibrándote sob', 'chest', 'body weight', 'chest', 'chest', 'pectorals', '{"shoulders","triceps","core"}', 'Comienza en posición de flexión de brazos con las manos un poco más separadas que el ancho de los hombros. Activa el core y baja el cuerpo hacia el suelo, manteniendo los codos cerca de los costados. Mientras te bajas, inclina el cuerpo hacia adelante y levanta los pies del suelo, equilibrándote sobre las manos. Continúa bajando el cuerpo hasta que el pecho quede justo por encima del suelo. Empuja con las manos y extiende los brazos para volver a subir el cuerpo a la posición inicial. Mantén una línea recta desde la cabeza hasta los talones durante todo el movimiento. Repite el número de repeticiones deseado.', 'Start in a push-up position with your hands placed slightly wider than shoulder-width apart. Engage your core and lower your body down towards the ground, keeping your elbows close to your sides. As you lower yourself, lean your body forward and lift your feet off the ground, balancing on your hands. Continue to lower your body until your chest is just above the ground. Push through your hands and extend your arms to lift your body back up to the starting position. Maintain a straight line from your head to your heels throughout the movement. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3327-gw9PqGk.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3327-gw9PqGk.gif', 'gw9PqGk', '© Gym visual — https://gymvisual.com/'),
('0466', 'gironda sternum chin', 'Ponte de pie frente a una barra alta con los pies separados a la altura de los hombros. Estira los brazos hacia arriba y agarra la barra con agarre prono, ligeramente más ancho que la altura de los hombros. Cuélgate de la barra con los brazos completamente extendidos y el cuerpo recto. Activa los do', 'back', 'body weight', 'back', 'back', 'lats', '{"biceps","rhomboids","rear deltoids"}', 'Ponte de pie frente a una barra alta con los pies separados a la altura de los hombros. Estira los brazos hacia arriba y agarra la barra con agarre prono, ligeramente más ancho que la altura de los hombros. Cuélgate de la barra con los brazos completamente extendidos y el cuerpo recto. Activa los dorsales y los bíceps para llevar el pecho hacia la barra, guiando con el esternón. Haz una pausa breve en la parte más alta, luego baja lentamente de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand facing a high bar with your feet shoulder-width apart. Reach up and grab the bar with an overhand grip, slightly wider than shoulder-width apart. Hang from the bar with your arms fully extended and your body straight. Engage your lats and biceps to pull your chest up towards the bar, leading with your sternum. Pause for a moment at the top, then slowly lower yourself back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0466-IL0JUxR.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0466-IL0JUxR.gif', 'IL0JUxR', '© Gym visual — https://gymvisual.com/'),
('3561', 'glute bridge march', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Activa los glúteos y levanta las caderas del suelo, formando una línea recta desde las rodillas hasta los hombros. Manteniendo las caderas elevadas, levanta un pie del suelo y lleva la rodilla hacia el pecho. Baja', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'glutes', '{"hamstrings","quadriceps"}', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Activa los glúteos y levanta las caderas del suelo, formando una línea recta desde las rodillas hasta los hombros. Manteniendo las caderas elevadas, levanta un pie del suelo y lleva la rodilla hacia el pecho. Baja el pie de nuevo al suelo y repite el movimiento con la otra pierna. Continúa alternando las piernas con un movimiento de marcha mientras mantienes la posición de puente. Repite el número de repeticiones deseado.', 'Lie flat on your back with your knees bent and feet flat on the ground. Engage your glutes and lift your hips off the ground, forming a straight line from your knees to your shoulders. While keeping your hips lifted, lift one foot off the ground and bring your knee towards your chest. Lower your foot back to the ground and repeat the movement with the other leg. Continue alternating legs in a marching motion while maintaining the bridge position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3561-GibBPPg.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3561-GibBPPg.gif', 'GibBPPg', '© Gym visual — https://gymvisual.com/'),
('3523', 'glute bridge two legs on bench (male)', 'Siéntate en el borde de un banco con la espalda apoyada en él y los pies planos sobre el suelo. Coloca las manos en el banco junto a las caderas para mayor apoyo. Activa los glúteos y los isquiotibiales, luego levanta las caderas del banco hasta que el cuerpo forme una línea recta desde las rodillas', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'glutes', '{"hamstrings","core"}', 'Siéntate en el borde de un banco con la espalda apoyada en él y los pies planos sobre el suelo. Coloca las manos en el banco junto a las caderas para mayor apoyo. Activa los glúteos y los isquiotibiales, luego levanta las caderas del banco hasta que el cuerpo forme una línea recta desde las rodillas hasta los hombros. Haz una pausa por un momento en la parte superior, luego baja lentamente las caderas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on the edge of a bench with your back against it and your feet flat on the ground. Place your hands on the bench beside your hips for support. Engage your glutes and hamstrings, then lift your hips off the bench until your body forms a straight line from your knees to your shoulders. Pause for a moment at the top, then slowly lower your hips back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3523-aWedzZX.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3523-aWedzZX.gif', 'aWedzZX', '© Gym visual — https://gymvisual.com/'),
('3193', 'glute-ham raise', 'Ajusta la máquina de extensión de glúteos e isquiotibiales para que se adapte a tu cuerpo. Colócate boca abajo en la máquina con los tobillos asegurados. Coloca las manos sobre el pecho o crúzalas sobre el pecho. Activa los isquiotibiales y los glúteos para levantar la parte superior del cuerpo haci', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'hamstrings', '{"glutes","lower back"}', 'Ajusta la máquina de extensión de glúteos e isquiotibiales para que se adapte a tu cuerpo. Colócate boca abajo en la máquina con los tobillos asegurados. Coloca las manos sobre el pecho o crúzalas sobre el pecho. Activa los isquiotibiales y los glúteos para levantar la parte superior del cuerpo hacia el techo. Continúa levantando hasta que el cuerpo forme una línea recta desde la cabeza hasta los talones. Haz una pausa por un momento en la parte superior, luego baja lentamente el cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the glute-ham raise machine to fit your body. Position yourself face down on the machine with your ankles secured. Place your hands on your chest or cross them over your chest. Engage your hamstrings and glutes to lift your upper body up towards the ceiling. Continue lifting until your body is in a straight line from your head to your heels. Pause for a moment at the top, then slowly lower your body back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3193-Vvwjz6N.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3193-Vvwjz6N.gif', 'Vvwjz6N', '© Gym visual — https://gymvisual.com/'),
('0467', 'gorilla chin', 'Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Sujeta una barra de dominadas con agarre prono, ligeramente más ancho que la altura de los hombros. Cuélgate de la barra con los brazos completamente extendidos y las palmas hacia afuera. Activa el', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"forearms","biceps"}', 'Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Sujeta una barra de dominadas con agarre prono, ligeramente más ancho que la altura de los hombros. Cuélgate de la barra con los brazos completamente extendidos y las palmas hacia afuera. Activa el core y tira del cuerpo hacia la barra, llevando la barbilla por encima de la barra. Haz una pausa por un momento en la parte superior, luego baja lentamente el cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and your knees slightly bent. Grasp a pull-up bar with an overhand grip, slightly wider than shoulder-width apart. Hang from the bar with your arms fully extended and your palms facing away from you. Engage your core and pull your body up towards the bar, bringing your chin above the bar. Pause for a moment at the top, then slowly lower your body back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0467-bmwlYvD.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0467-bmwlYvD.gif', 'bmwlYvD', '© Gym visual — https://gymvisual.com/'),
('0469', 'groin crunch', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Coloca las manos detrás de la cabeza con los codos apuntando hacia afuera. Activando el abdomen, levanta las piernas del suelo, llevando las rodillas hacia el pecho. Haz una pausa por un momento en la parte superi', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"hip flexors","inner thighs"}', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Coloca las manos detrás de la cabeza con los codos apuntando hacia afuera. Activando el abdomen, levanta las piernas del suelo, llevando las rodillas hacia el pecho. Haz una pausa por un momento en la parte superior, luego baja lentamente las piernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on your back with your knees bent and feet flat on the ground. Place your hands behind your head with your elbows pointing outwards. Engaging your abs, lift your legs off the ground, bringing your knees towards your chest. Pause for a moment at the top, then slowly lower your legs back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0469-mWppALS.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0469-mWppALS.gif', 'mWppALS', '© Gym visual — https://gymvisual.com/'),
('1383', 'hack calf raise', 'Ajusta la máquina de trineo a un peso adecuado. Ponte de pie sobre la máquina de trineo con la punta de los pies en la plataforma y los talones colgando. Sujétate de las asas para mantener el equilibrio. Levanta los talones lo más alto posible empujando con la punta de los pies. Haz una pausa breve ', 'lower legs', 'sled machine', 'lower legs', 'lower legs', 'calves', '{"hamstrings","glutes"}', 'Ajusta la máquina de trineo a un peso adecuado. Ponte de pie sobre la máquina de trineo con la punta de los pies en la plataforma y los talones colgando. Sujétate de las asas para mantener el equilibrio. Levanta los talones lo más alto posible empujando con la punta de los pies. Haz una pausa breve en la parte alta y luego baja lentamente los talones de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the sled machine to a comfortable weight. Stand on the sled machine with your toes on the platform and your heels hanging off. Hold onto the handles for stability. Raise your heels as high as possible by pushing through the balls of your feet. Pause for a moment at the top, then slowly lower your heels back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1383-2ORFMoR.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1383-2ORFMoR.gif', '2ORFMoR', '© Gym visual — https://gymvisual.com/'),
('1384', 'hack one leg calf raise', 'Ajusta la máquina de trineo a un peso adecuado. Ponte de pie sobre la máquina de trineo con un pie, manteniendo el otro pie levantado del suelo. Sujétate de las asas para mantener el equilibrio. Levanta el talón lo más alto posible, elevando el cuerpo sobre la punta del pie. Haz una pausa por un mom', 'lower legs', 'sled machine', 'lower legs', 'lower legs', 'calves', '{"hamstrings","glutes"}', 'Ajusta la máquina de trineo a un peso adecuado. Ponte de pie sobre la máquina de trineo con un pie, manteniendo el otro pie levantado del suelo. Sujétate de las asas para mantener el equilibrio. Levanta el talón lo más alto posible, elevando el cuerpo sobre la punta del pie. Haz una pausa por un momento en la parte superior, luego baja lentamente el talón de vuelta a la posición inicial. Repite el número de repeticiones deseado. Cambia de pierna y repite el ejercicio.', 'Adjust the sled machine to an appropriate weight. Stand on the sled machine with one foot, keeping the other foot off the ground. Hold onto the handles for stability. Raise your heel as high as possible, lifting your body up on the ball of your foot. Pause for a moment at the top, then slowly lower your heel back down to the starting position. Repeat for the desired number of repetitions. Switch legs and repeat the exercise.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1384-AxFoqAD.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1384-AxFoqAD.gif', 'AxFoqAD', '© Gym visual — https://gymvisual.com/'),
('3221', 'half knee bends (male)', 'Ponte de pie con los pies separados a la altura de los hombros. Dobla las rodillas y baja el cuerpo como si te fueras a sentar en una silla. Mantén el pecho elevado y el peso en los talones. Haz una pausa por un momento en la parte inferior, luego empuja con los talones para regresar a la posición i', 'cardio', 'body weight', 'cardio', 'cardio', 'cardiovascular system', '{"quadriceps","hamstrings","glutes"}', 'Ponte de pie con los pies separados a la altura de los hombros. Dobla las rodillas y baja el cuerpo como si te fueras a sentar en una silla. Mantén el pecho elevado y el peso en los talones. Haz una pausa por un momento en la parte inferior, luego empuja con los talones para regresar a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart. Bend your knees and lower your body down as if you were sitting back into a chair. Keep your chest up and your weight in your heels. Pause for a moment at the bottom, then push through your heels to return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3221-ia6kIIl.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3221-ia6kIIl.gif', 'ia6kIIl', '© Gym visual — https://gymvisual.com/'),
('3202', 'half sit-up (male)', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Coloca las manos detrás de la cabeza con los codos apuntando hacia afuera. Activando el abdomen, levanta lentamente la parte superior del cuerpo del suelo, curvándote hacia adelante hasta que tu torso forme un áng', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"hip flexors"}', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Coloca las manos detrás de la cabeza con los codos apuntando hacia afuera. Activando el abdomen, levanta lentamente la parte superior del cuerpo del suelo, curvándote hacia adelante hasta que tu torso forme un ángulo de 45 grados. Haz una pausa por un momento en la parte superior, luego baja lentamente la parte superior del cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on your back with your knees bent and feet flat on the ground. Place your hands behind your head with your elbows pointing outwards. Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle. Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3202-iQ241UP.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3202-iQ241UP.gif', 'iQ241UP', '© Gym visual — https://gymvisual.com/'),
('1511', 'hamstring stretch', 'Ponte de pie con los pies separados a la altura de los hombros. Da un paso adelante con el pie derecho y traslada el peso hacia la pierna derecha. Manteniendo la espalda recta, inclínate lentamente hacia adelante desde las caderas, alcanzando el pie derecho con ambas manos. Mantén el estiramiento du', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'hamstrings', '{"glutes"}', 'Ponte de pie con los pies separados a la altura de los hombros. Da un paso adelante con el pie derecho y traslada el peso hacia la pierna derecha. Manteniendo la espalda recta, inclínate lentamente hacia adelante desde las caderas, alcanzando el pie derecho con ambas manos. Mantén el estiramiento durante 20-30 segundos, luego vuelve a la posición inicial. Repite del otro lado.', 'Stand with your feet shoulder-width apart. Step forward with your right foot and shift your weight onto your right leg. Keeping your back straight, slowly bend forward at the hips, reaching towards your right foot with both hands. Hold the stretch for 20-30 seconds, then return to the starting position. Repeat on the other side.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1511-99rWm7w.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1511-99rWm7w.gif', '99rWm7w', '© Gym visual — https://gymvisual.com/'),
('2139', 'hands bike', 'Ajusta la altura del asiento y la posición del manillar a un nivel cómodo. Siéntate en el ergómetro con la espalda recta y los pies sobre los pedales. Sujeta las asas con las manos y coloca los brazos en un ángulo de 90 grados. Comienza a pedalear con las manos, empujando y tirando de las asas con u', 'chest', 'upper body ergometer', 'chest', 'chest', 'pectorals', '{"triceps","shoulders"}', 'Ajusta la altura del asiento y la posición del manillar a un nivel cómodo. Siéntate en el ergómetro con la espalda recta y los pies sobre los pedales. Sujeta las asas con las manos y coloca los brazos en un ángulo de 90 grados. Comienza a pedalear con las manos, empujando y tirando de las asas con un movimiento controlado. Continúa pedaleando durante el tiempo o el número de repeticiones deseado.', 'Adjust the seat height and handlebar position to a comfortable level. Sit on the ergometer with your back straight and feet on the pedals. Grasp the handles with your hands and position your arms at a 90-degree angle. Start pedaling with your hands, pushing and pulling the handles in a controlled motion. Continue pedaling for the desired duration or number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2139-pAIWRGu.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2139-pAIWRGu.gif', 'pAIWRGu', '© Gym visual — https://gymvisual.com/'),
('3218', 'hands clasped circular toe touch (male)', 'Ponte de pie con los pies separados a la altura de los hombros y las manos entrelazadas frente al pecho. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta. Baja las manos hacia los dedos de los pies con un movimiento circular, llegando tan l', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'glutes', '{"hamstrings","quadriceps","calves"}', 'Ponte de pie con los pies separados a la altura de los hombros y las manos entrelazadas frente al pecho. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta. Baja las manos hacia los dedos de los pies con un movimiento circular, llegando tan lejos como puedas sin forzar. Haz una pausa por un momento en la parte inferior, luego regresa lentamente a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and your hands clasped together in front of your chest. Bend your knees slightly and hinge forward at the hips, keeping your back straight. Lower your hands towards your toes in a circular motion, reaching as far as you can without straining. Pause for a moment at the bottom, then slowly return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3218-B5xca8s.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3218-B5xca8s.gif', 'B5xca8s', '© Gym visual — https://gymvisual.com/'),
('3215', 'hands reversed clasped circular toe touch (male)', 'Ponte de pie con los pies separados a la altura de los hombros y los brazos extendidos hacia los lados. Inclínate hacia adelante desde la cintura, manteniendo la espalda recta y las rodillas ligeramente flexionadas. Extiende las manos hacia abajo y entrelázalas detrás de las piernas. Sube lentamente', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'glutes', '{"hamstrings","quadriceps","calves"}', 'Ponte de pie con los pies separados a la altura de los hombros y los brazos extendidos hacia los lados. Inclínate hacia adelante desde la cintura, manteniendo la espalda recta y las rodillas ligeramente flexionadas. Extiende las manos hacia abajo y entrelázalas detrás de las piernas. Sube lentamente las manos en un movimiento circular por encima de la cabeza, manteniendo las piernas rectas. Continúa el movimiento circular hasta que las manos toquen los dedos de los pies. Invierte el movimiento y regresa las manos a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and your arms extended to the sides. Bend forward at the waist, keeping your back straight and your knees slightly bent. Reach down with your hands and clasp them together behind your legs. Slowly raise your hands up and over your head in a circular motion, keeping your legs straight. Continue the circular motion until your hands touch your toes. Reverse the motion and bring your hands back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3215-yq3GAJX.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3215-yq3GAJX.gif', 'yq3GAJX', '© Gym visual — https://gymvisual.com/'),
('3302', 'handstand', 'Busca un espacio abierto con suficiente espacio para hacer un pino. Coloca las manos en el suelo separadas a la altura de los hombros, con los dedos apuntando hacia adelante. Lanza las piernas hacia la pared, usando el core y los hombros para mantener el equilibrio. Una vez en posición de pino, acti', 'upper arms', 'body weight', 'upper arms', 'upper arms', 'triceps', '{"shoulders","core"}', 'Busca un espacio abierto con suficiente espacio para hacer un pino. Coloca las manos en el suelo separadas a la altura de los hombros, con los dedos apuntando hacia adelante. Lanza las piernas hacia la pared, usando el core y los hombros para mantener el equilibrio. Una vez en posición de pino, activa los tríceps para sostener el peso corporal. Mantén el pino el mayor tiempo posible mientras conserves el equilibrio. Para bajar, lleva lentamente las piernas de vuelta al suelo. Repite el número de repeticiones deseado.', 'Find an open space with enough room to perform a handstand. Place your hands on the ground shoulder-width apart, fingers pointing forward. Kick your legs up towards the wall, using your core and shoulders to maintain balance. Once in a handstand position, engage your triceps to support your body weight. Hold the handstand for as long as you can maintain balance. To come down, slowly lower your legs back to the ground. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3302-XooAdhl.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3302-XooAdhl.gif', 'XooAdhl', '© Gym visual — https://gymvisual.com/'),
('0471', 'handstand push-up', 'Busca una pared y colócate de espaldas a ella, de pie a unos pasos de distancia. Coloca las manos en el suelo separadas a la altura de los hombros y lanza los pies hacia la pared, llegando a una posición de pino. Dobla los codos y baja la cabeza hacia el suelo, manteniendo el cuerpo en línea recta. ', 'upper arms', 'body weight', 'upper arms', 'upper arms', 'triceps', '{"shoulders","chest","core"}', 'Busca una pared y colócate de espaldas a ella, de pie a unos pasos de distancia. Coloca las manos en el suelo separadas a la altura de los hombros y lanza los pies hacia la pared, llegando a una posición de pino. Dobla los codos y baja la cabeza hacia el suelo, manteniendo el cuerpo en línea recta. Empuja con las manos y extiende los brazos para volver a la posición inicial. Repite el número de repeticiones deseado.', 'Find a wall and face away from it, standing a few feet away. Place your hands on the ground shoulder-width apart and kick your feet up against the wall, coming into a handstand position. Bend your elbows and lower your head towards the ground, keeping your body in a straight line. Push through your hands and extend your arms to return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0471-rQxwMxO.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0471-rQxwMxO.gif', 'rQxwMxO', '© Gym visual — https://gymvisual.com/'),
('1764', 'hanging leg hip raise', 'Cuélgate de una barra de dominadas con los brazos completamente extendidos y las palmas mirando hacia afuera. Activa el core y levanta las piernas flexionando las caderas y las rodillas hasta que los muslos queden paralelos al suelo. Haz una pausa por un momento en la parte superior, luego baja lent', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"hip flexors","lower back"}', 'Cuélgate de una barra de dominadas con los brazos completamente extendidos y las palmas mirando hacia afuera. Activa el core y levanta las piernas flexionando las caderas y las rodillas hasta que los muslos queden paralelos al suelo. Haz una pausa por un momento en la parte superior, luego baja lentamente las piernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Hang from a pull-up bar with your arms fully extended and your palms facing away from you. Engage your core and lift your legs up by flexing your hips and knees until your thighs are parallel to the ground. Pause for a moment at the top, then slowly lower your legs back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1764-VEcJRo2.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1764-VEcJRo2.gif', 'VEcJRo2', '© Gym visual — https://gymvisual.com/'),
('0472', 'hanging leg raise', 'Cuélgate de una barra de dominadas con los brazos completamente extendidos y las palmas mirando hacia afuera. Activa el core y levanta las piernas frente a ti, manteniéndolas rectas. Continúa levantando hasta que las piernas estén paralelas al suelo o tan alto como puedas llegar cómodamente. Haz una', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"hip flexors"}', 'Cuélgate de una barra de dominadas con los brazos completamente extendidos y las palmas mirando hacia afuera. Activa el core y levanta las piernas frente a ti, manteniéndolas rectas. Continúa levantando hasta que las piernas estén paralelas al suelo o tan alto como puedas llegar cómodamente. Haz una pausa por un momento en la parte superior, luego baja lentamente las piernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Hang from a pull-up bar with your arms fully extended and your palms facing away from you. Engage your core and lift your legs up in front of you, keeping them straight. Continue lifting until your legs are parallel to the ground or as high as you can comfortably go. Pause for a moment at the top, then slowly lower your legs back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0472-I3tsCnC.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0472-I3tsCnC.gif', 'I3tsCnC', '© Gym visual — https://gymvisual.com/'),
('1761', 'hanging oblique knee raise', 'Cuélgate de una barra de dominadas con los brazos completamente extendidos y las palmas mirando hacia afuera. Activa el core y levanta las rodillas hacia el pecho, girando el torso hacia un lado mientras lo haces. Haz una pausa por un momento en la parte superior, luego baja lentamente las piernas d', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"obliques"}', 'Cuélgate de una barra de dominadas con los brazos completamente extendidos y las palmas mirando hacia afuera. Activa el core y levanta las rodillas hacia el pecho, girando el torso hacia un lado mientras lo haces. Haz una pausa por un momento en la parte superior, luego baja lentamente las piernas de vuelta a la posición inicial. Repite hacia el otro lado, girando el torso en la dirección opuesta. Continúa alternando lados durante el número de repeticiones deseado.', 'Hang from a pull-up bar with your arms fully extended and your palms facing away from you. Engage your core and lift your knees towards your chest, twisting your torso to the side as you do so. Pause for a moment at the top, then slowly lower your legs back down to the starting position. Repeat on the other side, twisting your torso in the opposite direction. Continue alternating sides for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1761-BaE7O6U.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1761-BaE7O6U.gif', 'BaE7O6U', '© Gym visual — https://gymvisual.com/'),
('0473', 'hanging pike', 'Cuélgate de una barra de dominadas con los brazos completamente extendidos y las palmas mirando hacia afuera. Activa el core y levanta las piernas hacia la barra, manteniéndolas rectas. Continúa levantando hasta que el cuerpo forme una ''V'', con las piernas paralelas al suelo. Mantén la posición por ', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"hip flexors","shoulders"}', 'Cuélgate de una barra de dominadas con los brazos completamente extendidos y las palmas mirando hacia afuera. Activa el core y levanta las piernas hacia la barra, manteniéndolas rectas. Continúa levantando hasta que el cuerpo forme una ''V'', con las piernas paralelas al suelo. Mantén la posición por un momento, luego baja lentamente las piernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Hang from a pull-up bar with your arms fully extended and your palms facing away from you. Engage your core and lift your legs up towards the bar, keeping them straight. Continue lifting until your body forms a ''V'' shape, with your legs parallel to the ground. Hold the position for a moment, then slowly lower your legs back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0473-nuBF9MO.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0473-nuBF9MO.gif', 'nuBF9MO', '© Gym visual — https://gymvisual.com/'),
('0474', 'hanging straight leg hip raise', 'Cuélgate de una barra de dominadas con los brazos completamente extendidos y las palmas mirando hacia afuera. Activa el core y levanta las piernas hacia adelante hasta que queden paralelas al suelo. Haz una pausa por un momento en la parte superior, luego baja lentamente las piernas de vuelta a la p', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"hip flexors"}', 'Cuélgate de una barra de dominadas con los brazos completamente extendidos y las palmas mirando hacia afuera. Activa el core y levanta las piernas hacia adelante hasta que queden paralelas al suelo. Haz una pausa por un momento en la parte superior, luego baja lentamente las piernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Hang from a pull-up bar with your arms fully extended and your palms facing away from you. Engage your core and lift your legs up in front of you until they are parallel to the ground. Pause for a moment at the top, then slowly lower your legs back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0474-pj0X0tF.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0474-pj0X0tF.gif', 'pj0X0tF', '© Gym visual — https://gymvisual.com/'),
('0475', 'hanging straight leg raise', 'Cuélgate de una barra de dominadas con los brazos completamente extendidos y las palmas mirando hacia afuera. Activa el core y levanta las piernas frente a ti, manteniéndolas rectas. Continúa levantando hasta que las piernas estén paralelas al suelo o tan alto como puedas llegar cómodamente. Haz una', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"hip flexors"}', 'Cuélgate de una barra de dominadas con los brazos completamente extendidos y las palmas mirando hacia afuera. Activa el core y levanta las piernas frente a ti, manteniéndolas rectas. Continúa levantando hasta que las piernas estén paralelas al suelo o tan alto como puedas llegar cómodamente. Haz una pausa por un momento en la parte superior, luego baja lentamente las piernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Hang from a pull-up bar with your arms fully extended and your palms facing away from you. Engage your core and lift your legs up in front of you, keeping them straight. Continue lifting until your legs are parallel to the ground or as high as you can comfortably go. Pause for a moment at the top, then slowly lower your legs back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0475-4Ml7QFO.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0475-4Ml7QFO.gif', '4Ml7QFO', '© Gym visual — https://gymvisual.com/'),
('0476', 'hanging straight twisting leg hip raise', 'Cuélgate de una barra de dominadas con los brazos completamente extendidos y las piernas rectas. Activa el core y levanta las piernas hacia el pecho, manteniéndolas rectas. Cuando las piernas queden paralelas al suelo, gira las caderas hacia un lado, llevando las piernas hacia ese lado. Haz una paus', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"obliques","hip flexors"}', 'Cuélgate de una barra de dominadas con los brazos completamente extendidos y las piernas rectas. Activa el core y levanta las piernas hacia el pecho, manteniéndolas rectas. Cuando las piernas queden paralelas al suelo, gira las caderas hacia un lado, llevando las piernas hacia ese lado. Haz una pausa breve y luego vuelve a la posición inicial. Repite el movimiento, pero esta vez gira las caderas hacia el lado opuesto. Continúa alternando lados durante el número de repeticiones deseado.', 'Hang from a pull-up bar with your arms fully extended and your legs straight. Engage your core and lift your legs up towards your chest, keeping them straight. Once your legs are parallel to the ground, twist your hips to one side, bringing your legs towards that side. Pause for a moment, then return to the starting position. Repeat the movement, but this time twist your hips to the opposite side. Continue alternating sides for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0476-Q6bvyen.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0476-Q6bvyen.gif', 'Q6bvyen', '© Gym visual — https://gymvisual.com/'),
('3636', 'high knee against wall', 'Ponte de pie frente a una pared con los pies separados a la altura de las caderas. Coloca las manos en la pared para mayor apoyo. Activa el core y levanta la rodilla derecha hacia el pecho, mientras mantienes el pie izquierdo en el suelo. Cambia rápidamente de pierna, llevando la rodilla izquierda h', 'cardio', 'body weight', 'cardio', 'cardio', 'cardiovascular system', '{"quadriceps","hamstrings","glutes","calves"}', 'Ponte de pie frente a una pared con los pies separados a la altura de las caderas. Coloca las manos en la pared para mayor apoyo. Activa el core y levanta la rodilla derecha hacia el pecho, mientras mantienes el pie izquierdo en el suelo. Cambia rápidamente de pierna, llevando la rodilla izquierda hacia el pecho y bajando el pie derecho de nuevo. Continúa alternando las piernas con un movimiento de carrera, llevando las rodillas lo más alto posible. Mantén un ritmo rápido y la parte superior del cuerpo estable durante todo el ejercicio. Repite durante la duración o el número de repeticiones deseado.', 'Stand facing a wall with your feet hip-width apart. Place your hands on the wall for support. Engage your core and lift your right knee up towards your chest, while keeping your left foot on the ground. Quickly switch legs, bringing your left knee up towards your chest and lowering your right foot back down. Continue alternating legs in a running motion, bringing your knees up as high as possible. Maintain a fast pace and keep your upper body stable throughout the exercise. Repeat for the desired duration or number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3636-ealLwvX.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3636-ealLwvX.gif', 'ealLwvX', '© Gym visual — https://gymvisual.com/'),
('0484', 'hip raise (bent knee)', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Coloca las manos a los lados, con las palmas hacia abajo. Activa el core y los glúteos, luego levanta las caderas del suelo hasta que el cuerpo forme una línea recta desde las rodillas hasta los hombros. Haz una p', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"glutes","hamstrings"}', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Coloca las manos a los lados, con las palmas hacia abajo. Activa el core y los glúteos, luego levanta las caderas del suelo hasta que el cuerpo forme una línea recta desde las rodillas hasta los hombros. Haz una pausa por un momento en la parte superior, luego baja lentamente las caderas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on your back with your knees bent and feet flat on the ground. Place your hands by your sides, palms facing down. Engage your core and glutes, then lift your hips off the ground until your body forms a straight line from your knees to your shoulders. Pause for a moment at the top, then slowly lower your hips back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0484-196HJGw.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0484-196HJGw.gif', '196HJGw', '© Gym visual — https://gymvisual.com/'),
('1418', 'hug keens to chest', 'Comienza de pie con los pies separados a la altura de los hombros. Flexiona las rodillas y baja el cuerpo hacia una posición de sentadilla. Al ponerte en cuclillas, lleva las rodillas hacia el pecho y abrázalas con los brazos. Mantén esta posición por un momento, luego regresa lentamente a la posici', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'glutes', '{"hamstrings","quadriceps"}', 'Comienza de pie con los pies separados a la altura de los hombros. Flexiona las rodillas y baja el cuerpo hacia una posición de sentadilla. Al ponerte en cuclillas, lleva las rodillas hacia el pecho y abrázalas con los brazos. Mantén esta posición por un momento, luego regresa lentamente a la posición inicial. Repite el número de repeticiones deseado.', 'Start by standing with your feet shoulder-width apart. Bend your knees and lower your body down into a squat position. As you squat down, bring your knees up towards your chest and hug them with your arms. Hold this position for a moment, then slowly return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1418-znP9SIh.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1418-znP9SIh.gif', 'znP9SIh', '© Gym visual — https://gymvisual.com/'),
('3234', 'hyght dumbbell fly', 'Túmbate boca arriba en un banco con una mancuerna en cada mano, con las palmas enfrentadas entre sí. Extiende los brazos rectos hacia arriba sobre el pecho, con una ligera flexión en los codos. Manteniendo una ligera flexión en los codos, baja las mancuernas hacia los lados describiendo un amplio ar', 'chest', 'dumbbell', 'chest', 'chest', 'pectorals', '{"shoulders"}', 'Túmbate boca arriba en un banco con una mancuerna en cada mano, con las palmas enfrentadas entre sí. Extiende los brazos rectos hacia arriba sobre el pecho, con una ligera flexión en los codos. Manteniendo una ligera flexión en los codos, baja las mancuernas hacia los lados describiendo un amplio arco hasta sentir un estiramiento en el pecho. Haz una pausa por un momento, luego invierte el movimiento y lleva las mancuernas de nuevo hacia arriba hasta la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on a bench with a dumbbell in each hand, palms facing each other. Extend your arms straight up over your chest, with a slight bend in your elbows. Keeping a slight bend in your elbows, lower the dumbbells out to the sides in a wide arc until you feel a stretch in your chest. Pause for a moment, then reverse the movement and bring the dumbbells back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3234-P9ZRyLT.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3234-P9ZRyLT.gif', 'P9ZRyLT', '© Gym visual — https://gymvisual.com/'),
('0489', 'hyperextension', 'Ajusta el banco de hiperextensiones para que la parte superior de los muslos quede apoyada en la almohadilla y los pies queden asegurados. Cruza los brazos sobre el pecho o coloca las manos detrás de la cabeza. Baja la parte superior del cuerpo hacia el suelo manteniendo la espalda recta. Haz una pa', 'back', 'body weight', 'back', 'back', 'spine', '{"glutes","hamstrings"}', 'Ajusta el banco de hiperextensiones para que la parte superior de los muslos quede apoyada en la almohadilla y los pies queden asegurados. Cruza los brazos sobre el pecho o coloca las manos detrás de la cabeza. Baja la parte superior del cuerpo hacia el suelo manteniendo la espalda recta. Haz una pausa breve en la parte baja, luego eleva la parte superior del cuerpo hasta que quede alineada con las piernas. Repite el número de repeticiones deseado.', 'Adjust the hyperextension bench so that your upper thighs are resting on the pad and your feet are secured. Cross your arms over your chest or place your hands behind your head. Lower your upper body towards the ground while keeping your back straight. Pause for a moment at the bottom, then raise your upper body back up until it is in line with your legs. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0489-zhMwOwE.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0489-zhMwOwE.gif', 'zhMwOwE', '© Gym visual — https://gymvisual.com/'),
('0488', 'hyperextension (on bench)', 'Ajusta el banco de hiperextensiones para que las caderas queden apoyadas cómodamente en la almohadilla y los pies queden asegurados. Cruza los brazos sobre el pecho o coloca las manos detrás de la cabeza. Baja lentamente la parte superior del cuerpo hacia el suelo manteniendo la espalda recta. Haz u', 'back', 'body weight', 'back', 'back', 'spine', '{"glutes","hamstrings"}', 'Ajusta el banco de hiperextensiones para que las caderas queden apoyadas cómodamente en la almohadilla y los pies queden asegurados. Cruza los brazos sobre el pecho o coloca las manos detrás de la cabeza. Baja lentamente la parte superior del cuerpo hacia el suelo manteniendo la espalda recta. Haz una pausa breve en la parte baja, luego eleva la parte superior del cuerpo hasta que quede alineada con las piernas. Repite el número de repeticiones deseado.', 'Adjust the hyperextension bench so that your hips are resting comfortably on the pad and your feet are secured. Cross your arms over your chest or place your hands behind your head. Slowly lower your upper body towards the ground while keeping your back straight. Pause for a moment at the bottom, then raise your upper body back up until it is in line with your legs. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0488-zkgRrbK.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0488-zkgRrbK.gif', 'zkgRrbK', '© Gym visual — https://gymvisual.com/'),
('3289', 'impossible dips', 'Colócate entre dos barras paralelas con los brazos completamente extendidos y el cuerpo suspendido en el aire. Flexiona las rodillas y cruza los tobillos. Baja el cuerpo flexionando los codos hasta que los brazos queden paralelos al suelo. Haz una pausa breve, luego empújate de nuevo hacia arriba a ', 'upper arms', 'body weight', 'upper arms', 'upper arms', 'triceps', '{"chest","shoulders"}', 'Colócate entre dos barras paralelas con los brazos completamente extendidos y el cuerpo suspendido en el aire. Flexiona las rodillas y cruza los tobillos. Baja el cuerpo flexionando los codos hasta que los brazos queden paralelos al suelo. Haz una pausa breve, luego empújate de nuevo hacia arriba a la posición inicial estirando los brazos. Repite el número de repeticiones deseado.', 'Position yourself between two parallel bars with your arms fully extended and your body suspended in the air. Bend your knees and cross your ankles. Lower your body by bending your elbows until your upper arms are parallel to the ground. Pause for a moment, then push yourself back up to the starting position by straightening your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3289-05Cf2v8.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3289-05Cf2v8.gif', '05Cf2v8', '© Gym visual — https://gymvisual.com/'),
('1471', 'inchworm', 'Comienza de pie con los pies separados a la altura de las caderas. Inclínate hacia adelante desde la cintura y coloca las manos en el suelo frente a ti. Camina con las manos hacia adelante hasta quedar en posición de plancha alta, con el cuerpo en línea recta de la cabeza a los pies. Haz una pausa b', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"shoulders","hamstrings"}', 'Comienza de pie con los pies separados a la altura de las caderas. Inclínate hacia adelante desde la cintura y coloca las manos en el suelo frente a ti. Camina con las manos hacia adelante hasta quedar en posición de plancha alta, con el cuerpo en línea recta de la cabeza a los pies. Haz una pausa breve, luego camina con las manos de vuelta hacia los pies, manteniendo las piernas lo más rectas posible. Cuando las manos lleguen a los pies, ponte de pie de nuevo en la posición inicial. Repite el número de repeticiones deseado.', 'Start in a standing position with your feet hip-width apart. Bend forward at the waist and place your hands on the ground in front of you. Walk your hands forward until you are in a high plank position, with your body in a straight line from head to toe. Pause for a moment, then walk your hands back towards your feet, keeping your legs as straight as possible. Once your hands reach your feet, stand back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1471-ZgsNQ6d.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1471-ZgsNQ6d.gif', 'ZgsNQ6d', '© Gym visual — https://gymvisual.com/'),
('3698', 'inchworm v. 2', 'Comienza de pie con los pies separados a la altura de las caderas. Inclínate hacia adelante desde la cintura y coloca las manos en el suelo frente a ti. Camina con las manos hacia adelante hasta quedar en posición de plancha alta, con el cuerpo en línea recta de la cabeza a los pies. Manteniendo las', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"shoulders","hamstrings"}', 'Comienza de pie con los pies separados a la altura de las caderas. Inclínate hacia adelante desde la cintura y coloca las manos en el suelo frente a ti. Camina con las manos hacia adelante hasta quedar en posición de plancha alta, con el cuerpo en línea recta de la cabeza a los pies. Manteniendo las piernas rectas, camina con los pies hacia las manos, llevando las caderas hacia el techo. Continúa caminando con las manos hacia adelante, repitiendo el movimiento durante el número de repeticiones deseado.', 'Start in a standing position with your feet hip-width apart. Bend forward at the waist and place your hands on the ground in front of you. Walk your hands forward until you are in a high plank position, with your body in a straight line from head to toe. Keeping your legs straight, walk your feet towards your hands, bringing your hips up towards the ceiling. Continue walking your hands forward, repeating the movement for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3698-TV87DNB.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3698-TV87DNB.gif', 'TV87DNB', '© Gym visual — https://gymvisual.com/'),
('0490', 'incline close-grip push-up', 'Coloca las manos sobre una superficie elevada, como un banco o un escalón, ligeramente más separadas que la altura de los hombros. Extiende las piernas detrás de ti, apoyándote en la punta de los pies, con el cuerpo formando una línea recta desde la cabeza hasta los talones. Baja el pecho hacia la s', 'upper arms', 'body weight', 'upper arms', 'upper arms', 'triceps', '{"chest","shoulders"}', 'Coloca las manos sobre una superficie elevada, como un banco o un escalón, ligeramente más separadas que la altura de los hombros. Extiende las piernas detrás de ti, apoyándote en la punta de los pies, con el cuerpo formando una línea recta desde la cabeza hasta los talones. Baja el pecho hacia la superficie elevada doblando los codos, manteniéndolos cerca de los costados. Haz una pausa breve en la parte baja, luego empújate de nuevo hacia arriba a la posición inicial estirando los brazos. Repite el número de repeticiones deseado.', 'Place your hands on an elevated surface, such as a bench or step, slightly wider than shoulder-width apart. Extend your legs behind you, resting on the balls of your feet, with your body forming a straight line from head to heels. Lower your chest towards the elevated surface by bending your elbows, keeping them close to your sides. Pause for a moment at the bottom, then push yourself back up to the starting position by straightening your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0490-1YB40kg.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0490-1YB40kg.gif', '1YB40kg', '© Gym visual — https://gymvisual.com/'),
('0491', 'incline leg hip raise (leg straight)', 'Túmbate en un banco inclinado con la espalda apoyada plana en el banco y las piernas extendidas rectas frente a ti. Coloca las manos a los lados del banco para apoyarte. Activando el abdomen, levanta las piernas del banco, elevándolas tan alto como puedas mientras las mantienes rectas. Haz una pausa', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"hip flexors"}', 'Túmbate en un banco inclinado con la espalda apoyada plana en el banco y las piernas extendidas rectas frente a ti. Coloca las manos a los lados del banco para apoyarte. Activando el abdomen, levanta las piernas del banco, elevándolas tan alto como puedas mientras las mantienes rectas. Haz una pausa por un momento en la parte superior, luego baja lentamente las piernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie on an incline bench with your back flat against the bench and your legs extended straight out in front of you. Place your hands on the sides of the bench for support. Engaging your abs, lift your legs off the bench, raising them as high as you can while keeping them straight. Pause for a moment at the top, then slowly lower your legs back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0491-eVxAzgz.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0491-eVxAzgz.gif', 'eVxAzgz', '© Gym visual — https://gymvisual.com/'),
('0492', 'incline push up depth jump', 'Busca una superficie elevada, como un banco o un escalón, y coloca las manos separadas a la altura de los hombros en el borde. Da un paso hacia atrás con los pies, manteniendo el cuerpo en línea recta desde la cabeza hasta los talones. Baja el pecho hacia el borde de la superficie, doblando los codo', 'chest', 'body weight', 'chest', 'chest', 'pectorals', '{"triceps","shoulders","core"}', 'Busca una superficie elevada, como un banco o un escalón, y coloca las manos separadas a la altura de los hombros en el borde. Da un paso hacia atrás con los pies, manteniendo el cuerpo en línea recta desde la cabeza hasta los talones. Baja el pecho hacia el borde de la superficie, doblando los codos y manteniendo el cuerpo alineado. Empuja con las palmas para extender los brazos y regresar a la posición inicial. Salta desde el borde de la superficie, aterrizando suavemente con las rodillas ligeramente flexionadas. Repite la flexión de brazos y el salto en profundidad durante el número de repeticiones deseado.', 'Find an elevated surface, such as a bench or step, and place your hands shoulder-width apart on the edge. Step your feet back, keeping your body in a straight line from head to heels. Lower your chest towards the edge of the surface, bending your elbows and keeping your body aligned. Push through your palms to extend your arms and return to the starting position. Jump off the edge of the surface, landing softly with your knees slightly bent. Repeat the push-up and depth jump for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0492-CB8WET1.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0492-CB8WET1.gif', 'CB8WET1', '© Gym visual — https://gymvisual.com/'),
('0493', 'incline push-up', 'Coloca las manos sobre una superficie elevada, como un banco o un escalón, ligeramente más separadas que la altura de los hombros. Extiende las piernas detrás de ti, apoyándote en la punta de los pies, formando una línea recta desde la cabeza hasta los talones. Baja el pecho hacia la superficie elev', 'chest', 'body weight', 'chest', 'chest', 'pectorals', '{"triceps","shoulders"}', 'Coloca las manos sobre una superficie elevada, como un banco o un escalón, ligeramente más separadas que la altura de los hombros. Extiende las piernas detrás de ti, apoyándote en la punta de los pies, formando una línea recta desde la cabeza hasta los talones. Baja el pecho hacia la superficie elevada doblando los codos, manteniendo el cuerpo en línea recta. Haz una pausa breve en la parte baja, luego empújate de nuevo hacia arriba a la posición inicial estirando los brazos. Repite el número de repeticiones deseado.', 'Place your hands on an elevated surface, such as a bench or step, slightly wider than shoulder-width apart. Extend your legs behind you, resting on the balls of your feet, creating a straight line from your head to your heels. Lower your chest towards the elevated surface by bending your elbows, keeping your body in a straight line. Pause for a moment at the bottom, then push yourself back up to the starting position by straightening your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0493-B1EVP9F.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0493-B1EVP9F.gif', 'B1EVP9F', '© Gym visual — https://gymvisual.com/'),
('3785', 'incline push-up (on box)', 'Coloca las manos en el borde de una caja o una superficie elevada, ligeramente más separadas que la altura de los hombros. Extiende las piernas detrás de ti, apoyándote en la punta de los pies, formando una línea recta desde la cabeza hasta los talones. Baja el pecho hacia la caja doblando los codos', 'chest', 'body weight', 'chest', 'chest', 'pectorals', '{"triceps","shoulders"}', 'Coloca las manos en el borde de una caja o una superficie elevada, ligeramente más separadas que la altura de los hombros. Extiende las piernas detrás de ti, apoyándote en la punta de los pies, formando una línea recta desde la cabeza hasta los talones. Baja el pecho hacia la caja doblando los codos, manteniendo el cuerpo en línea recta. Haz una pausa breve en la parte baja, luego empújate de nuevo hacia arriba a la posición inicial estirando los brazos. Repite el número de repeticiones deseado.', 'Place your hands on the edge of a box or elevated surface, slightly wider than shoulder-width apart. Extend your legs behind you, resting on the balls of your feet, creating a straight line from your head to your heels. Lower your chest towards the box by bending your elbows, keeping your body in a straight line. Pause for a moment at the bottom, then push yourself back up to the starting position by straightening your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3785-F7vjXqT.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3785-F7vjXqT.gif', 'F7vjXqT', '© Gym visual — https://gymvisual.com/'),
('0494', 'incline reverse grip push-up', 'Coloca las manos en el borde de un banco o una superficie elevada, ligeramente más separadas que la altura de los hombros. Extiende las piernas detrás de ti, apoyándote en la punta de los pies, formando una línea recta desde la cabeza hasta los talones. Baja el pecho hacia el banco doblando los codo', 'chest', 'body weight', 'chest', 'chest', 'pectorals', '{"triceps","shoulders"}', 'Coloca las manos en el borde de un banco o una superficie elevada, ligeramente más separadas que la altura de los hombros. Extiende las piernas detrás de ti, apoyándote en la punta de los pies, formando una línea recta desde la cabeza hasta los talones. Baja el pecho hacia el banco doblando los codos, manteniéndolos cerca de los costados. Haz una pausa breve en la parte baja, luego empújate de nuevo hacia arriba a la posición inicial extendiendo los brazos. Repite el número de repeticiones deseado.', 'Place your hands on the edge of a bench or elevated surface, slightly wider than shoulder-width apart. Extend your legs behind you, resting on the balls of your feet, creating a straight line from your head to your heels. Lower your chest towards the bench by bending your elbows, keeping them close to your sides. Pause for a moment at the bottom, then push yourself back up to the starting position by extending your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0494-XaaRnRn.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0494-XaaRnRn.gif', 'XaaRnRn', '© Gym visual — https://gymvisual.com/'),
('3011', 'incline scapula push up', 'Coloca un banco inclinado a un ángulo de 45 grados. Coloca las manos en el banco, ligeramente más separadas que la altura de los hombros. Coloca los pies en el suelo, separados a la altura de las caderas. Baja el pecho hacia el banco, manteniendo los codos pegados al cuerpo. Mientras bajas, retrae l', 'chest', 'body weight', 'chest', 'chest', 'serratus anterior', '{"triceps","shoulders"}', 'Coloca un banco inclinado a un ángulo de 45 grados. Coloca las manos en el banco, ligeramente más separadas que la altura de los hombros. Coloca los pies en el suelo, separados a la altura de las caderas. Baja el pecho hacia el banco, manteniendo los codos pegados al cuerpo. Mientras bajas, retrae los omóplatos, apretándolos entre sí. Empuja con las palmas para extender los brazos y regresar a la posición inicial. Repite el número de repeticiones deseado.', 'Set up an incline bench at a 45-degree angle. Place your hands on the bench slightly wider than shoulder-width apart. Position your feet on the ground, hip-width apart. Lower your chest towards the bench, keeping your elbows tucked in. As you lower, retract your shoulder blades, squeezing your scapulae together. Push through your palms to extend your arms and return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3011-GdMa1ET.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3011-GdMa1ET.gif', 'GdMa1ET', '© Gym visual — https://gymvisual.com/'),
('0495', 'incline twisting sit-up', 'Coloca un banco inclinado a un ángulo de 45 grados. Túmbate en el banco con los pies asegurados bajo las almohadillas para los pies. Coloca las manos detrás de la cabeza o cruzadas sobre el pecho. Activa el abdomen y levanta la parte superior del cuerpo del banco, curvándote hacia adelante. Mientras', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"obliques"}', 'Coloca un banco inclinado a un ángulo de 45 grados. Túmbate en el banco con los pies asegurados bajo las almohadillas para los pies. Coloca las manos detrás de la cabeza o cruzadas sobre el pecho. Activa el abdomen y levanta la parte superior del cuerpo del banco, curvándote hacia adelante. Mientras te incorporas, gira el torso hacia un lado, llevando el codo hacia la rodilla opuesta. Haz una pausa por un momento en la parte superior, luego baja lentamente la parte superior del cuerpo de vuelta a la posición inicial. Repite el movimiento, esta vez girando el torso hacia el otro lado. Continúa alternando lados durante el número de repeticiones deseado.', 'Set up an incline bench at a 45-degree angle. Lie down on the bench with your feet secured under the foot pads. Place your hands behind your head or across your chest. Engage your abs and lift your upper body off the bench, curling forward. As you curl up, twist your torso to one side, bringing your elbow towards the opposite knee. Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Repeat the movement, this time twisting your torso to the other side. Continue alternating sides for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0495-9ZGZuOD.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0495-9ZGZuOD.gif', '9ZGZuOD', '© Gym visual — https://gymvisual.com/'),
('1564', 'intermediate hip flexor and quad stretch', 'Ponte de pie con la espalda recta y los pies separados a la altura de los hombros. Sujétate de un objeto estable para mayor apoyo. Dobla la rodilla derecha y lleva el pie derecho hacia los glúteos, sujetando la cuerda con la mano derecha. Tira lentamente del pie derecho hacia los glúteos, sintiendo ', 'upper legs', 'rope', 'upper legs', 'upper legs', 'quads', '{"hamstrings","glutes"}', 'Ponte de pie con la espalda recta y los pies separados a la altura de los hombros. Sujétate de un objeto estable para mayor apoyo. Dobla la rodilla derecha y lleva el pie derecho hacia los glúteos, sujetando la cuerda con la mano derecha. Tira lentamente del pie derecho hacia los glúteos, sintiendo un estiramiento en el cuádriceps derecho. Mantén el estiramiento durante 20-30 segundos. Suelta el estiramiento y repite en el lado izquierdo.', 'Stand upright with your feet shoulder-width apart. Hold onto a stable object for support. Bend your right knee and bring your right foot towards your glutes, grabbing the rope with your right hand. Slowly pull your right foot towards your glutes, feeling a stretch in your right quad. Hold the stretch for 20-30 seconds. Release the stretch and repeat on the left side.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1564-tFGKm99.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1564-tFGKm99.gif', 'tFGKm99', '© Gym visual — https://gymvisual.com/'),
('0496', 'inverse leg curl (bench support)', 'Túmbate boca abajo en un banco con las caderas en el borde y las piernas extendidas rectas detrás de ti. Sujétate del banco para mayor apoyo. Manteniendo la parte superior del cuerpo quieta, dobla las rodillas y curva las piernas hacia los glúteos. Haz una pausa breve en la parte superior, luego ext', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'hamstrings', '{"glutes","calves"}', 'Túmbate boca abajo en un banco con las caderas en el borde y las piernas extendidas rectas detrás de ti. Sujétate del banco para mayor apoyo. Manteniendo la parte superior del cuerpo quieta, dobla las rodillas y curva las piernas hacia los glúteos. Haz una pausa breve en la parte superior, luego extiende lentamente las piernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie face down on a bench with your hips at the edge and your legs extended straight behind you. Hold onto the bench for support. Keeping your upper body still, bend your knees and curl your legs towards your glutes. Pause for a moment at the top, then slowly extend your legs back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0496-ms7tjSG.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0496-ms7tjSG.gif', 'ms7tjSG', '© Gym visual — https://gymvisual.com/'),
('2400', 'inverse leg curl (on pull-up cable machine)', 'Ajusta la máquina de cable para que las correas de tobillo estén en el ajuste más bajo. Túmbate boca abajo en el banco con las piernas extendidas y las correas de tobillo sujetas a los pies. Sujétate de las agarraderas del banco para mantener la estabilidad. Dobla las rodillas y curva las piernas ha', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'hamstrings', '{"glutes","calves"}', 'Ajusta la máquina de cable para que las correas de tobillo estén en el ajuste más bajo. Túmbate boca abajo en el banco con las piernas extendidas y las correas de tobillo sujetas a los pies. Sujétate de las agarraderas del banco para mantener la estabilidad. Dobla las rodillas y curva las piernas hacia los glúteos, contrayendo los isquiotibiales. Haz una pausa breve en la parte superior del movimiento, luego baja lentamente las piernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the cable machine so that the ankle straps are at the lowest setting. Lie face down on the bench with your legs extended and the ankle straps attached to your feet. Hold onto the handles of the bench for stability. Bend your knees and curl your legs towards your glutes, squeezing your hamstrings. Pause for a moment at the top of the movement, then slowly lower your legs back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2400-0rHfvy9.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2400-0rHfvy9.gif', '0rHfvy9', '© Gym visual — https://gymvisual.com/'),
('0499', 'inverted row', 'Coloca una barra a la altura de la cintura o usa un entrenador de suspensión. Ponte de pie frente a la barra o al entrenador de suspensión, con los pies separados a la altura de los hombros. Agarra la barra o las asas con agarre prono, ligeramente más ancho que la altura de los hombros. Inclínate ha', 'back', 'body weight', 'back', 'back', 'upper back', '{"biceps","forearms"}', 'Coloca una barra a la altura de la cintura o usa un entrenador de suspensión. Ponte de pie frente a la barra o al entrenador de suspensión, con los pies separados a la altura de los hombros. Agarra la barra o las asas con agarre prono, ligeramente más ancho que la altura de los hombros. Inclínate hacia atrás, manteniendo el cuerpo recto y los talones en el suelo. Tira del pecho hacia la barra o las asas, apretando los omóplatos entre sí. Haz una pausa breve en la parte más alta, luego baja lentamente de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Set up a bar at waist height or use a suspension trainer. Stand facing the bar or suspension trainer, with your feet shoulder-width apart. Grab the bar or handles with an overhand grip, slightly wider than shoulder-width apart. Lean back, keeping your body straight and your heels on the ground. Pull your chest towards the bar or handles, squeezing your shoulder blades together. Pause for a moment at the top, then slowly lower yourself back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0499-bZGHsAZ.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0499-bZGHsAZ.gif', 'bZGHsAZ', '© Gym visual — https://gymvisual.com/'),
('2300', 'inverted row bent knees', 'Coloca una barra a la altura de la cintura y túmbate debajo de ella. Agarra la barra con agarre prono, ligeramente más ancho que la altura de los hombros. Coloca el cuerpo de manera que los talones queden en el suelo y el cuerpo esté recto. Tira del pecho hacia arriba en dirección a la barra apretan', 'back', 'body weight', 'back', 'back', 'upper back', '{"biceps","forearms"}', 'Coloca una barra a la altura de la cintura y túmbate debajo de ella. Agarra la barra con agarre prono, ligeramente más ancho que la altura de los hombros. Coloca el cuerpo de manera que los talones queden en el suelo y el cuerpo esté recto. Tira del pecho hacia arriba en dirección a la barra apretando los omóplatos entre sí. Haz una pausa por un momento en la parte superior, luego baja lentamente el cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Set up a bar at waist height and lie underneath it. Grab the bar with an overhand grip, slightly wider than shoulder-width apart. Position your body so that your heels are on the ground and your body is straight. Pull your chest up towards the bar by squeezing your shoulder blades together. Pause for a moment at the top, then slowly lower your body back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2300-VPPtusI.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2300-VPPtusI.gif', 'VPPtusI', '© Gym visual — https://gymvisual.com/'),
('2298', 'inverted row on bench', 'Coloca un banco a una altura que permita que el cuerpo cuelgue libremente debajo de él. Túmbate boca arriba en el suelo con la cabeza hacia el banco. Estira los brazos hacia arriba y agarra el banco con agarre prono, ligeramente más ancho que la altura de los hombros. Coloca el cuerpo de manera que ', 'back', 'body weight', 'back', 'back', 'upper back', '{"biceps","forearms"}', 'Coloca un banco a una altura que permita que el cuerpo cuelgue libremente debajo de él. Túmbate boca arriba en el suelo con la cabeza hacia el banco. Estira los brazos hacia arriba y agarra el banco con agarre prono, ligeramente más ancho que la altura de los hombros. Coloca el cuerpo de manera que los talones queden en el suelo y los brazos completamente extendidos. Activa el core y aprieta los omóplatos entre sí mientras tiras del pecho hacia el banco. Haz una pausa breve en la parte superior del movimiento, luego baja lentamente el cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Set up a bench at a height that allows your body to hang freely underneath it. Lie face up on the ground with your head towards the bench. Reach up and grab the bench with an overhand grip, slightly wider than shoulder-width apart. Position your body so that your heels are on the ground and your arms are fully extended. Engage your core and squeeze your shoulder blades together as you pull your chest up towards the bench. Pause for a moment at the top of the movement, then slowly lower your body back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2298-Mxa7Cr8.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2298-Mxa7Cr8.gif', 'Mxa7Cr8', '© Gym visual — https://gymvisual.com/'),
('0497', 'inverted row v. 2', 'Coloca una barra a la altura de la cintura en una máquina Smith o usa un entrenador de suspensión. Ponte de pie frente a la barra o al entrenador de suspensión y agárrala con agarre prono, manos separadas a la altura de los hombros. Camina con los pies hacia adelante, inclinándote hacia atrás hasta ', 'back', 'body weight', 'back', 'back', 'upper back', '{"biceps","forearms"}', 'Coloca una barra a la altura de la cintura en una máquina Smith o usa un entrenador de suspensión. Ponte de pie frente a la barra o al entrenador de suspensión y agárrala con agarre prono, manos separadas a la altura de los hombros. Camina con los pies hacia adelante, inclinándote hacia atrás hasta que el cuerpo quede en un ligero ángulo. Mantén el cuerpo recto y tira del pecho hacia la barra o las asas, apretando los omóplatos entre sí. Haz una pausa breve en la parte más alta, luego baja lentamente de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Set up a bar at waist height on a Smith machine or use a suspension trainer. Stand facing the bar or suspension trainer and grab it with an overhand grip, hands shoulder-width apart. Walk your feet forward, leaning back until your body is at a slight angle. Keep your body straight and pull your chest up towards the bar or handles, squeezing your shoulder blades together. Pause for a moment at the top, then slowly lower yourself back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0497-uX3sUBz.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0497-uX3sUBz.gif', 'uX3sUBz', '© Gym visual — https://gymvisual.com/'),
('0498', 'inverted row with straps', 'Coloca un entrenador de suspensión o correas a la altura del pecho. Ponte de pie frente al punto de anclaje y agarra las asas con agarre prono. Camina con los pies hacia adelante, inclinándote hacia atrás hasta que el cuerpo quede en ángulo. Mantén el cuerpo recto y activa el core. Tira del pecho ha', 'back', 'body weight', 'back', 'back', 'upper back', '{"biceps","forearms"}', 'Coloca un entrenador de suspensión o correas a la altura del pecho. Ponte de pie frente al punto de anclaje y agarra las asas con agarre prono. Camina con los pies hacia adelante, inclinándote hacia atrás hasta que el cuerpo quede en ángulo. Mantén el cuerpo recto y activa el core. Tira del pecho hacia las asas, apretando los omóplatos entre sí. Haz una pausa breve en la parte más alta, luego baja lentamente de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Set up a suspension trainer or straps at chest height. Stand facing the anchor point and grab the handles with an overhand grip. Walk your feet forward, leaning back until your body is at an angle. Keep your body straight and engage your core. Pull your chest towards the handles, squeezing your shoulder blades together. Pause for a moment at the top, then slowly lower yourself back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0498-jdiExfW.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0498-jdiExfW.gif', 'jdiExfW', '© Gym visual — https://gymvisual.com/'),
('1419', 'iron cross stretch', 'Túmbate boca arriba con los brazos extendidos hacia los lados. Levanta las piernas hacia el techo, manteniéndolas rectas. Baja lentamente las piernas hacia un lado, intentando tocar el suelo con los pies. Mantén el estiramiento durante unos segundos, luego regresa las piernas a la posición inicial. ', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'glutes', '{"hamstrings","quadriceps"}', 'Túmbate boca arriba con los brazos extendidos hacia los lados. Levanta las piernas hacia el techo, manteniéndolas rectas. Baja lentamente las piernas hacia un lado, intentando tocar el suelo con los pies. Mantén el estiramiento durante unos segundos, luego regresa las piernas a la posición inicial. Repite el estiramiento en el otro lado. Continúa alternando lados durante el número de repeticiones deseado.', 'Lie flat on your back with your arms extended out to the sides. Raise your legs up towards the ceiling, keeping them straight. Slowly lower your legs to one side, aiming to touch the floor with your feet. Hold the stretch for a few seconds, then return your legs to the starting position. Repeat the stretch on the other side. Continue alternating sides for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1419-pZwUsKB.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1419-pZwUsKB.gif', 'pZwUsKB', '© Gym visual — https://gymvisual.com/'),
('1297', 'isometric chest squeeze', 'Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Extiende los brazos rectos frente a ti, paralelos al suelo, con las palmas una frente a la otra. Aprieta los músculos del pecho con la mayor fuerza posible, manteniendo los brazos rectos. Mantén es', 'chest', 'body weight', 'chest', 'chest', 'pectorals', '{"triceps","shoulders"}', 'Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Extiende los brazos rectos frente a ti, paralelos al suelo, con las palmas una frente a la otra. Aprieta los músculos del pecho con la mayor fuerza posible, manteniendo los brazos rectos. Mantén esta posición durante unos segundos, concentrándote en contraer los músculos del pecho. Suelta la contracción y relaja los músculos del pecho. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and your knees slightly bent. Extend your arms straight out in front of you, parallel to the ground, with your palms facing each other. Squeeze your chest muscles together as hard as you can, while keeping your arms straight. Hold this position for a few seconds, focusing on contracting your chest muscles. Release the squeeze and relax your chest muscles. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1297-HbSG1Pw.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1297-HbSG1Pw.gif', 'HbSG1Pw', '© Gym visual — https://gymvisual.com/'),
('0500', 'isometric wipers', 'Comienza acostado boca arriba en una esterilla o un banco. Extiende los brazos hacia los lados, perpendiculares al cuerpo. Activa el core y levanta ambas piernas del suelo, manteniéndolas juntas y rectas. Baja lentamente las piernas hacia un lado, intentando tocar el suelo con los pies mientras mant', 'chest', 'body weight', 'chest', 'chest', 'pectorals', '{"shoulders","triceps","core"}', 'Comienza acostado boca arriba en una esterilla o un banco. Extiende los brazos hacia los lados, perpendiculares al cuerpo. Activa el core y levanta ambas piernas del suelo, manteniéndolas juntas y rectas. Baja lentamente las piernas hacia un lado, intentando tocar el suelo con los pies mientras mantienes el control. Haz una pausa breve, luego usa el core para llevar las piernas de vuelta a la posición inicial. Repite el movimiento, esta vez bajando las piernas hacia el lado opuesto. Continúa alternando lados durante el número de repeticiones deseado.', 'Start by lying flat on your back on a mat or bench. Extend your arms straight out to the sides, perpendicular to your body. Engage your core and lift both legs off the ground, keeping them together and straight. Slowly lower your legs to one side, aiming to touch the ground with your feet while maintaining control. Pause for a moment, then use your core to lift your legs back to the starting position. Repeat the movement, this time lowering your legs to the opposite side. Continue alternating sides for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0500-11wrviz.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0500-11wrviz.gif', '11wrviz', '© Gym visual — https://gymvisual.com/'),
('0501', 'jack burpee', 'Comienza de pie con los pies separados a la altura de los hombros. Baja el cuerpo a una posición de sentadilla, colocando las manos en el suelo frente a ti. Lanza los pies hacia atrás, aterrizando en posición de flexión de brazos. Realiza una flexión de brazos, bajando el pecho hacia el suelo y lueg', 'cardio', 'body weight', 'cardio', 'cardio', 'cardiovascular system', '{"quadriceps","hamstrings","calves","shoulders","triceps","core"}', 'Comienza de pie con los pies separados a la altura de los hombros. Baja el cuerpo a una posición de sentadilla, colocando las manos en el suelo frente a ti. Lanza los pies hacia atrás, aterrizando en posición de flexión de brazos. Realiza una flexión de brazos, bajando el pecho hacia el suelo y luego empujando de nuevo hacia arriba. Salta con los pies hacia adelante, aterrizando en posición de sentadilla. Salta hacia arriba explosivamente, llevando los brazos por encima de la cabeza. Aterriza suavemente y baja de inmediato a una posición de sentadilla para comenzar la siguiente repetición.', 'Start in a standing position with your feet shoulder-width apart. Lower your body into a squat position, placing your hands on the ground in front of you. Kick your feet back, landing in a push-up position. Perform a push-up, lowering your chest to the ground and then pushing back up. Jump your feet forward, landing in a squat position. Jump up explosively, reaching your arms overhead. Land softly and immediately lower back into the squat position to begin the next repetition.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0501-mr7pkqP.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0501-mr7pkqP.gif', 'mr7pkqP', '© Gym visual — https://gymvisual.com/'),
('3224', 'jack jump (male)', 'Ponte de pie con los pies juntos y los brazos a los costados. Salta, separando los pies y levantando los brazos por encima de la cabeza. Al aterrizar, salta rápidamente de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'cardio', 'body weight', 'cardio', 'cardio', 'cardiovascular system', '{"quadriceps","calves"}', 'Ponte de pie con los pies juntos y los brazos a los costados. Salta, separando los pies y levantando los brazos por encima de la cabeza. Al aterrizar, salta rápidamente de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet together and your arms by your sides. Jump up, spreading your feet apart and raising your arms above your head. As you land, quickly jump back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3224-1g5bPpA.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3224-1g5bPpA.gif', '1g5bPpA', '© Gym visual — https://gymvisual.com/'),
('0507', 'jackknife sit-up', 'Túmbate boca arriba con las piernas extendidas y los brazos por encima de la cabeza. Activa el core y levanta las piernas y la parte superior del cuerpo al mismo tiempo, llevando las manos hacia los dedos de los pies. Haz una pausa por un momento en la parte superior, luego baja lentamente las piern', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"hip flexors"}', 'Túmbate boca arriba con las piernas extendidas y los brazos por encima de la cabeza. Activa el core y levanta las piernas y la parte superior del cuerpo al mismo tiempo, llevando las manos hacia los dedos de los pies. Haz una pausa por un momento en la parte superior, luego baja lentamente las piernas y la parte superior del cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on your back with your legs extended and your arms overhead. Engage your core and lift your legs and upper body simultaneously, reaching your hands towards your toes. Pause for a moment at the top, then slowly lower your legs and upper body back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0507-mbkgB44.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0507-mbkgB44.gif', 'mbkgB44', '© Gym visual — https://gymvisual.com/'),
('0508', 'janda sit-up', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Coloca las manos detrás de la cabeza con los codos apuntando hacia afuera. Activando el abdomen, levanta lentamente la parte superior del cuerpo del suelo, curvándote hacia adelante hasta que tu torso forme un áng', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"hip flexors","lower back"}', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Coloca las manos detrás de la cabeza con los codos apuntando hacia afuera. Activando el abdomen, levanta lentamente la parte superior del cuerpo del suelo, curvándote hacia adelante hasta que tu torso forme un ángulo de 45 grados. Haz una pausa por un momento en la parte superior, luego baja lentamente la parte superior del cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on your back with your knees bent and feet flat on the ground. Place your hands behind your head with your elbows pointing outwards. Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle. Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0508-1GPHRyK.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0508-1GPHRyK.gif', '1GPHRyK', '© Gym visual — https://gymvisual.com/'),
('2612', 'jump rope', 'Sujeta las asas de la cuerda de saltar con las manos, palmas hacia adentro. Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Balancea la cuerda por encima de la cabeza y salta sobre ella cuando se acerque a los pies. Aterriza suavemente sobre la ', 'cardio', 'rope', 'cardio', 'cardio', 'cardiovascular system', '{"calves","quadriceps","hamstrings","glutes"}', 'Sujeta las asas de la cuerda de saltar con las manos, palmas hacia adentro. Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Balancea la cuerda por encima de la cabeza y salta sobre ella cuando se acerque a los pies. Aterriza suavemente sobre la punta de los pies y repite el salto cuando la cuerda vuelva a pasar. Continúa saltando durante el tiempo o el número de repeticiones deseado.', 'Hold the handles of the jump rope with your hands, palms facing inward. Stand with your feet shoulder-width apart and knees slightly bent. Swing the rope over your head and jump over it as it comes towards your feet. Land softly on the balls of your feet and repeat the jump as the rope comes around again. Continue jumping for the desired duration or number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2612-e1e76I2.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2612-e1e76I2.gif', 'e1e76I2', '© Gym visual — https://gymvisual.com/'),
('0514', 'jump squat', 'Ponte de pie con los pies separados a la altura de los hombros. Baja el cuerpo hacia una posición de sentadilla flexionando las rodillas y empujando las caderas hacia atrás. Salta de forma explosiva desde el suelo, extendiendo las caderas, las rodillas y los tobillos. Mientras estás en el aire, llev', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves"}', 'Ponte de pie con los pies separados a la altura de los hombros. Baja el cuerpo hacia una posición de sentadilla flexionando las rodillas y empujando las caderas hacia atrás. Salta de forma explosiva desde el suelo, extendiendo las caderas, las rodillas y los tobillos. Mientras estás en el aire, lleva rápidamente los brazos hacia adelante para mantener el equilibrio. Aterriza suavemente sobre la punta de los pies y pasa de inmediato a la siguiente repetición. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart. Lower your body into a squat position by bending your knees and pushing your hips back. Jump explosively off the ground, extending your hips, knees, and ankles. While in mid-air, quickly bring your arms forward for balance. Land softly on the balls of your feet and immediately go into the next repetition. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0514-LIlE5Tn.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0514-LIlE5Tn.gif', 'LIlE5Tn', '© Gym visual — https://gymvisual.com/'),
('0513', 'jump squat v. 2', 'Ponte de pie con los pies separados a la altura de los hombros. Baja el cuerpo hacia una posición de sentadilla flexionando las rodillas y empujando las caderas hacia atrás. Salta de forma explosiva, extendiendo por completo las caderas y las rodillas. Aterriza suavemente sobre la punta de los pies ', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves"}', 'Ponte de pie con los pies separados a la altura de los hombros. Baja el cuerpo hacia una posición de sentadilla flexionando las rodillas y empujando las caderas hacia atrás. Salta de forma explosiva, extendiendo por completo las caderas y las rodillas. Aterriza suavemente sobre la punta de los pies y de inmediato baja el cuerpo de nuevo a una posición de sentadilla. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart. Lower your body into a squat position by bending your knees and pushing your hips back. Jump explosively, extending your hips and knees fully. Land softly on the balls of your feet and immediately lower your body back into a squat position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0513-TDYiji6.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0513-TDYiji6.gif', 'TDYiji6', '© Gym visual — https://gymvisual.com/'),
('0517', 'kettlebell advanced windmill', 'Ponte de pie con los pies más separados que el ancho de los hombros, con las puntas de los pies ligeramente hacia afuera. Sostén una pesa rusa en la mano derecha, con el brazo extendido por encima de la cabeza y la palma hacia adelante. Gira el pie izquierdo ligeramente hacia la derecha y traslada e', 'waist', 'kettlebell', 'waist', 'waist', 'abs', '{"obliques","shoulders"}', 'Ponte de pie con los pies más separados que el ancho de los hombros, con las puntas de los pies ligeramente hacia afuera. Sostén una pesa rusa en la mano derecha, con el brazo extendido por encima de la cabeza y la palma hacia adelante. Gira el pie izquierdo ligeramente hacia la derecha y traslada el peso hacia la pierna izquierda. Dobla la rodilla izquierda y flexiona la cadera, bajando el torso hacia el lado izquierdo. Mantén el brazo derecho extendido por encima de la cabeza y la mirada en la pesa rusa. Mientras bajas el torso, permite que la pierna derecha se enderece y que el pie derecho gire ligeramente. Baja el torso hasta sentir un estiramiento en el isquiotibial izquierdo y que el brazo derecho apunte hacia el suelo. Haz una pausa breve, luego activa el core y empuja con el talón izquierdo para regresar a la posición inicial. Repite el número de repeticiones deseado, luego cambia de lado.', 'Stand with your feet wider than shoulder-width apart, toes pointing slightly outward. Hold a kettlebell in your right hand, with your arm extended overhead and your palm facing forward. Rotate your left foot slightly to the right, and shift your weight onto your left leg. Bend your left knee and hinge at the hip, lowering your torso towards the left side. Keep your right arm extended overhead and your eyes on the kettlebell. As you lower your torso, allow your right leg to straighten and your right foot to pivot slightly. Lower your torso until you feel a stretch in your left hamstring and your right arm is pointing towards the ground. Pause for a moment, then engage your core and push through your left heel to return to the starting position. Repeat for the desired number of repetitions, then switch sides.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0517-Kal9cQQ.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0517-Kal9cQQ.gif', 'Kal9cQQ', '© Gym visual — https://gymvisual.com/'),
('0518', 'kettlebell alternating hang clean', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo una pesa rusa en cada mano con agarre prono. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta y el pecho elevado. Deja que las pesas rusas cuelguen frente al cuerpo', 'lower arms', 'kettlebell', 'lower arms', 'lower arms', 'forearms', '{"shoulders","traps","core"}', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo una pesa rusa en cada mano con agarre prono. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta y el pecho elevado. Deja que las pesas rusas cuelguen frente al cuerpo con los brazos completamente extendidos. En un solo movimiento fluido, extiende las caderas de forma explosiva, encoge los hombros y tira de las pesas rusas hacia los hombros. Cuando las pesas rusas alcancen la altura de los hombros, gira las muñecas y atrápalas en posición de descanso, con las palmas hacia adentro y las pesas rusas apoyadas en la parte externa de los antebrazos. Baja las pesas rusas de nuevo a la posición inicial y repite el movimiento con el brazo opuesto. Continúa alternando los brazos durante el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, holding a kettlebell in each hand with an overhand grip. Bend your knees slightly and hinge forward at the hips, keeping your back straight and chest up. Allow the kettlebells to hang in front of your body with your arms fully extended. In one fluid motion, explosively extend your hips, shrug your shoulders, and pull the kettlebells up towards your shoulders. As the kettlebells reach shoulder height, rotate your wrists and catch the kettlebells in the rack position, with your palms facing inward and the kettlebells resting on the outside of your forearms. Lower the kettlebells back down to the starting position and repeat the movement with the opposite arm. Continue alternating arms for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0518-I4tibZG.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0518-I4tibZG.gif', 'I4tibZG', '© Gym visual — https://gymvisual.com/'),
('0520', 'kettlebell alternating press', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo una pesa rusa en cada mano a la altura de los hombros. Empuja una pesa rusa por encima de la cabeza, extendiendo el brazo por completo. Baja la pesa rusa de nuevo a la altura de los hombros. Repite con el otro brazo. Continú', 'shoulders', 'kettlebell', 'shoulders', 'shoulders', 'delts', '{"triceps","core"}', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo una pesa rusa en cada mano a la altura de los hombros. Empuja una pesa rusa por encima de la cabeza, extendiendo el brazo por completo. Baja la pesa rusa de nuevo a la altura de los hombros. Repite con el otro brazo. Continúa alternando los brazos durante el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, holding a kettlebell in each hand at shoulder height. Press one kettlebell overhead, fully extending your arm. Lower the kettlebell back to shoulder height. Repeat with the other arm. Continue alternating arms for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0520-5KLbZWx.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0520-5KLbZWx.gif', '5KLbZWx', '© Gym visual — https://gymvisual.com/'),
('0519', 'kettlebell alternating press on floor', 'Comienza acostado boca arriba en el suelo con las rodillas dobladas y los pies planos sobre el suelo. Sostén una pesa rusa en cada mano, con las palmas hacia los pies y los brazos extendidos rectos hacia el techo. Baja una pesa rusa hacia el hombro mientras mantienes la otra pesa rusa extendida rect', 'chest', 'kettlebell', 'chest', 'chest', 'pectorals', '{"shoulders","triceps"}', 'Comienza acostado boca arriba en el suelo con las rodillas dobladas y los pies planos sobre el suelo. Sostén una pesa rusa en cada mano, con las palmas hacia los pies y los brazos extendidos rectos hacia el techo. Baja una pesa rusa hacia el hombro mientras mantienes la otra pesa rusa extendida recta hacia arriba. Empuja la pesa rusa bajada de vuelta hacia la posición inicial mientras al mismo tiempo bajas la otra pesa rusa hacia el hombro. Continúa alternando el movimiento de empuje con cada pesa rusa durante el número de repeticiones deseado.', 'Start by lying on your back on the floor with your knees bent and feet flat on the ground. Hold a kettlebell in each hand, with your palms facing towards your feet and your arms extended straight up towards the ceiling. Lower one kettlebell down towards your shoulder while keeping the other kettlebell extended straight up. Press the lowered kettlebell back up to the starting position while simultaneously lowering the other kettlebell down towards your shoulder. Continue alternating the press motion with each kettlebell for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0519-7w6i0vE.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0519-7w6i0vE.gif', '7w6i0vE', '© Gym visual — https://gymvisual.com/'),
('0521', 'kettlebell alternating renegade row', 'Comienza en posición de plancha alta con las manos sujetando las pesas rusas y los pies separados a la altura de las caderas. Activa el core y mantén el cuerpo en línea recta desde la cabeza hasta los talones. Tira de una pesa rusa hacia el pecho, manteniendo el codo cerca del cuerpo. Baja la pesa r', 'back', 'kettlebell', 'back', 'back', 'upper back', '{"core","shoulders"}', 'Comienza en posición de plancha alta con las manos sujetando las pesas rusas y los pies separados a la altura de las caderas. Activa el core y mantén el cuerpo en línea recta desde la cabeza hasta los talones. Tira de una pesa rusa hacia el pecho, manteniendo el codo cerca del cuerpo. Baja la pesa rusa de nuevo a la posición inicial y repite con el otro brazo. Continúa alternando los brazos durante el número de repeticiones deseado.', 'Start in a high plank position with your hands gripping the kettlebells and your feet hip-width apart. Engage your core and keep your body in a straight line from head to heels. Pull one kettlebell up towards your chest, keeping your elbow close to your body. Lower the kettlebell back down to the starting position and repeat with the other arm. Continue alternating arms for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0521-b9kqlBy.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0521-b9kqlBy.gif', 'b9kqlBy', '© Gym visual — https://gymvisual.com/'),
('0522', 'kettlebell alternating row', 'Ponte de pie con los pies separados a la altura de los hombros, las rodillas ligeramente flexionadas, y sostén una pesa rusa en cada mano con las palmas hacia el cuerpo. Inclínate hacia adelante desde las caderas, manteniendo la espalda recta y el core activado. Tira de una pesa rusa hacia el pecho,', 'back', 'kettlebell', 'back', 'back', 'upper back', '{"biceps","forearms"}', 'Ponte de pie con los pies separados a la altura de los hombros, las rodillas ligeramente flexionadas, y sostén una pesa rusa en cada mano con las palmas hacia el cuerpo. Inclínate hacia adelante desde las caderas, manteniendo la espalda recta y el core activado. Tira de una pesa rusa hacia el pecho, manteniendo el codo cerca del cuerpo y apretando los omóplatos entre sí. Baja la pesa rusa de nuevo a la posición inicial y repite con el otro brazo. Continúa alternando los brazos durante el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, knees slightly bent, and hold a kettlebell in each hand with your palms facing your body. Bend forward at the hips, keeping your back straight and your core engaged. Pull one kettlebell up towards your chest, keeping your elbow close to your body and squeezing your shoulder blades together. Lower the kettlebell back down to the starting position and repeat with the other arm. Continue alternating arms for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0522-Ca76jUE.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0522-Ca76jUE.gif', 'Ca76jUE', '© Gym visual — https://gymvisual.com/'),
('0523', 'kettlebell arnold press', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo una pesa rusa en cada mano a la altura de los hombros con las palmas hacia ti. Activa el core y empuja las pesas rusas por encima de la cabeza, girando las palmas hacia adelante mientras extiendes los brazos. Haz una pausa e', 'shoulders', 'kettlebell', 'shoulders', 'shoulders', 'delts', '{"triceps","upper back"}', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo una pesa rusa en cada mano a la altura de los hombros con las palmas hacia ti. Activa el core y empuja las pesas rusas por encima de la cabeza, girando las palmas hacia adelante mientras extiendes los brazos. Haz una pausa en la parte superior del movimiento, luego baja lentamente las pesas rusas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, holding a kettlebell in each hand at shoulder height with your palms facing towards you. Engage your core and press the kettlebells overhead, rotating your palms to face forward as you extend your arms. Pause at the top of the movement, then slowly lower the kettlebells back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0523-UM8mgyG.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0523-UM8mgyG.gif', 'UM8mgyG', '© Gym visual — https://gymvisual.com/'),
('0524', 'kettlebell bent press', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo una pesa rusa en la mano derecha. Dobla ligeramente las rodillas y empuja la pesa rusa por encima de la cabeza con el brazo derecho, manteniendo el codo bloqueado. Rota el torso hacia la izquierda, trasladando tu peso al pie', 'waist', 'kettlebell', 'waist', 'waist', 'abs', '{"shoulders","triceps","obliques"}', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo una pesa rusa en la mano derecha. Dobla ligeramente las rodillas y empuja la pesa rusa por encima de la cabeza con el brazo derecho, manteniendo el codo bloqueado. Rota el torso hacia la izquierda, trasladando tu peso al pie izquierdo. Flexiona la rodilla izquierda y baja el torso hacia el suelo, manteniendo el brazo derecho extendido por encima de la cabeza. Mientras bajas, mantén la mirada en la pesa rusa y el pecho elevado. Cuando tu mano izquierda toque el suelo, empuja con el pie izquierdo y estira la pierna izquierda, llevando las caderas hacia adelante. Mientras llevas las caderas hacia adelante, usa el core y el brazo derecho para empujar la pesa rusa de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia de lado.', 'Stand with your feet shoulder-width apart, holding a kettlebell in your right hand. Bend your knees slightly and press the kettlebell overhead with your right arm, keeping your elbow locked. Rotate your torso to the left, shifting your weight onto your left foot. Bend your left knee and lower your torso towards the ground, keeping your right arm extended overhead. As you lower, keep your eyes on the kettlebell and your chest lifted. Once your left hand touches the ground, push through your left foot and straighten your left leg, driving your hips forward. As you drive your hips forward, use your core and right arm to press the kettlebell back up to the starting position. Repeat for the desired number of repetitions, then switch sides.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0524-kjE55n5.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0524-kjE55n5.gif', 'kjE55n5', '© Gym visual — https://gymvisual.com/'),
('0525', 'kettlebell bottoms up clean from the hang position', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una pesa rusa con una mano en agarre prono. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta y el pecho elevado. Deja que la pesa rusa cuelgue entre tus piernas, con ', 'upper arms', 'kettlebell', 'upper arms', 'upper arms', 'biceps', '{"forearms","shoulders"}', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una pesa rusa con una mano en agarre prono. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta y el pecho elevado. Deja que la pesa rusa cuelgue entre tus piernas, con el brazo completamente extendido. En un solo movimiento fluido, extiende explosivamente las caderas y las rodillas mientras tiras de la pesa rusa hacia el hombro. Cuando la pesa rusa llegue a la altura del hombro, rota la muñeca de modo que la base de la pesa rusa quede hacia arriba. Atrapa la pesa rusa a la altura del hombro con el codo flexionado y la palma hacia arriba. Baja la pesa rusa de vuelta a la posición inicial invirtiendo el movimiento. Repite el número de repeticiones deseado, luego cambia de lado.', 'Stand with your feet shoulder-width apart, holding a kettlebell in one hand with an overhand grip. Bend your knees slightly and hinge forward at the hips, keeping your back straight and chest up. Allow the kettlebell to hang down between your legs, with your arm fully extended. In one fluid motion, explosively extend your hips and knees while pulling the kettlebell up towards your shoulder. As the kettlebell reaches shoulder height, rotate your wrist so that the bottom of the kettlebell is facing up. Catch the kettlebell at shoulder height with your elbow bent and your palm facing up. Lower the kettlebell back down to the starting position by reversing the movement. Repeat for the desired number of repetitions, then switch sides.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0525-4KJEpzb.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0525-4KJEpzb.gif', '4KJEpzb', '© Gym visual — https://gymvisual.com/'),
('0526', 'kettlebell double alternating hang clean', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo una pesa rusa en cada mano con agarre prono. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta y el pecho elevado. Deja que las pesas rusas cuelguen rectas frente a ', 'upper arms', 'kettlebell', 'upper arms', 'upper arms', 'biceps', '{"forearms","shoulders"}', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo una pesa rusa en cada mano con agarre prono. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta y el pecho elevado. Deja que las pesas rusas cuelguen rectas frente a tu cuerpo. En un solo movimiento fluido, extiende explosivamente las caderas y las rodillas mientras encoges los hombros. Mientras las pesas rusas suben, tira de ellas hacia los hombros, manteniendo los codos altos y hacia los lados. Atrapa las pesas rusas a la altura del hombro, con las palmas hacia adentro y los codos apuntando hacia adelante. Baja las pesas rusas de vuelta a la posición inicial y repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, holding a kettlebell in each hand with an overhand grip. Bend your knees slightly and hinge forward at the hips, keeping your back straight and chest up. Allow the kettlebells to hang straight down in front of your body. In one fluid motion, explosively extend your hips and knees while shrugging your shoulders. As the kettlebells rise, pull them up towards your shoulders, keeping your elbows high and out to the sides. Catch the kettlebells at shoulder height, with your palms facing inward and your elbows pointing forward. Lower the kettlebells back down to the starting position and repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0526-a4F9Oyc.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0526-a4F9Oyc.gif', 'a4F9Oyc', '© Gym visual — https://gymvisual.com/'),
('0527', 'kettlebell double jerk', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo una pesa rusa en cada mano a la altura de los hombros. Flexiona ligeramente las rodillas y activa el core. Presiona las pesas rusas por encima de la cabeza, extendiendo los brazos por completo. Flexiona las rodillas y baja r', 'shoulders', 'kettlebell', 'shoulders', 'shoulders', 'delts', '{"triceps","core"}', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo una pesa rusa en cada mano a la altura de los hombros. Flexiona ligeramente las rodillas y activa el core. Presiona las pesas rusas por encima de la cabeza, extendiendo los brazos por completo. Flexiona las rodillas y baja rápidamente a una sentadilla parcial. Extiende explosivamente las caderas y las rodillas, impulsando las pesas rusas hacia arriba. Bloquea los brazos y atrapa las pesas rusas por encima de la cabeza con las rodillas ligeramente flexionadas. Ponte de pie recto y vuelve a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, holding a kettlebell in each hand at shoulder height. Bend your knees slightly and engage your core. Press the kettlebells overhead, fully extending your arms. Bend your knees and quickly drop into a partial squat. Explosively extend your hips and knees, driving the kettlebells overhead. Lock out your arms and catch the kettlebells overhead with your knees slightly bent. Stand up straight and return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0527-tznL2Ad.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0527-tznL2Ad.gif', 'tznL2Ad', '© Gym visual — https://gymvisual.com/'),
('0528', 'kettlebell double push press', 'Comienza de pie con los pies separados a la altura de los hombros, sujetando una pesa rusa en cada mano a la altura del hombro. Flexiona ligeramente las rodillas y activa el core. Inicia el movimiento extendiendo explosivamente las caderas, las rodillas y los tobillos, impulsando las pesas rusas por', 'shoulders', 'kettlebell', 'shoulders', 'shoulders', 'delts', '{"triceps","core"}', 'Comienza de pie con los pies separados a la altura de los hombros, sujetando una pesa rusa en cada mano a la altura del hombro. Flexiona ligeramente las rodillas y activa el core. Inicia el movimiento extendiendo explosivamente las caderas, las rodillas y los tobillos, impulsando las pesas rusas por encima de la cabeza. Cuando las pesas rusas lleguen arriba, presiónalas completamente por encima de la cabeza, bloqueando los brazos. Baja las pesas rusas a la posición inicial flexionando los codos y llevándolas de vuelta a la altura del hombro. Repite el número de repeticiones deseado.', 'Start by standing with your feet shoulder-width apart, holding a kettlebell in each hand at shoulder height. Bend your knees slightly and engage your core. Initiate the movement by explosively extending your hips, knees, and ankles, driving the kettlebells overhead. As the kettlebells reach the top, press them fully overhead, locking out your arms. Lower the kettlebells back to the starting position by bending your elbows and bringing them back down to shoulder height. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0528-I4KkPdl.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0528-I4KkPdl.gif', 'I4KkPdl', '© Gym visual — https://gymvisual.com/'),
('0529', 'kettlebell double snatch', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una pesa rusa en cada mano con el brazo extendido frente a los muslos. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta y el pecho elevado. En un solo movimiento expl', 'shoulders', 'kettlebell', 'shoulders', 'shoulders', 'delts', '{"trapezius","forearms","core"}', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una pesa rusa en cada mano con el brazo extendido frente a los muslos. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta y el pecho elevado. En un solo movimiento explosivo, extiende las caderas, las rodillas y los tobillos, y al mismo tiempo tira de las pesas rusas hacia los hombros. Cuando las pesas rusas lleguen a la altura del hombro, rota las muñecas y lanza las pesas rusas por encima de la cabeza, extendiendo los brazos por completo. Baja las pesas rusas de vuelta a la posición inicial y repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, holding a kettlebell in each hand at arm''s length in front of your thighs. Bend your knees slightly and hinge forward at the hips, keeping your back flat and chest up. In one explosive motion, extend your hips, knees, and ankles, and simultaneously pull the kettlebells up towards your shoulders. As the kettlebells reach shoulder level, rotate your wrists and punch the kettlebells overhead, fully extending your arms. Lower the kettlebells back down to the starting position and repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0529-M74kdvm.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0529-M74kdvm.gif', 'M74kdvm', '© Gym visual — https://gymvisual.com/'),
('0530', 'kettlebell double windmill', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo una pesa rusa en la mano derecha. Extiende el brazo derecho por encima de la cabeza, manteniendo la mirada en la pesa rusa. Rota el pie izquierdo 45 grados hacia la izquierda y el pie derecho 90 grados hacia la derecha. Flex', 'waist', 'kettlebell', 'waist', 'waist', 'abs', '{"shoulders","hamstrings"}', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo una pesa rusa en la mano derecha. Extiende el brazo derecho por encima de la cabeza, manteniendo la mirada en la pesa rusa. Rota el pie izquierdo 45 grados hacia la izquierda y el pie derecho 90 grados hacia la derecha. Flexiona la cintura hacia la izquierda, manteniendo el brazo derecho extendido por encima de la cabeza. Baja la pesa rusa hacia el suelo, extendiéndote hacia el pie izquierdo. Haz una pausa breve, luego activa el core y empuja con el pie derecho para volver a la posición inicial. Repite el número de repeticiones deseado, luego cambia de lado.', 'Stand with your feet shoulder-width apart, holding a kettlebell in your right hand. Extend your right arm overhead, keeping your eyes on the kettlebell. Rotate your left foot 45 degrees to the left and your right foot 90 degrees to the right. Bend at the waist to the left, keeping your right arm extended overhead. Lower the kettlebell towards the ground, reaching towards your left foot. Pause for a moment, then engage your core and push through your right foot to return to the starting position. Repeat for the desired number of repetitions, then switch sides.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0530-OaE7CpD.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0530-OaE7CpD.gif', 'OaE7CpD', '© Gym visual — https://gymvisual.com/'),
('0531', 'kettlebell extended range one arm press on floor', 'Comienza acostado boca arriba en el suelo con las rodillas dobladas y los pies planos sobre el suelo. Sujeta una pesa rusa con una mano, con la palma hacia los pies. Extiende el brazo recto hacia el techo, manteniendo el codo bloqueado y la muñeca recta. Baja lentamente la pesa rusa de vuelta a la p', 'chest', 'kettlebell', 'chest', 'chest', 'pectorals', '{"triceps","shoulders"}', 'Comienza acostado boca arriba en el suelo con las rodillas dobladas y los pies planos sobre el suelo. Sujeta una pesa rusa con una mano, con la palma hacia los pies. Extiende el brazo recto hacia el techo, manteniendo el codo bloqueado y la muñeca recta. Baja lentamente la pesa rusa de vuelta a la posición inicial, manteniendo el control durante todo el movimiento. Repite el número de repeticiones deseado, luego cambia al otro brazo.', 'Start by lying on your back on the floor with your knees bent and feet flat on the ground. Hold a kettlebell in one hand, with your palm facing towards your feet. Extend your arm straight up towards the ceiling, keeping your elbow locked and your wrist straight. Slowly lower the kettlebell back down to the starting position, maintaining control throughout the movement. Repeat for the desired number of repetitions, then switch to the other arm.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0531-rseLfH3.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0531-rseLfH3.gif', 'rseLfH3', '© Gym visual — https://gymvisual.com/'),
('0532', 'kettlebell figure 8', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una pesa rusa con una mano. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta. Pasa la pesa rusa entre las piernas, cambiándola de mano cuando llegue detrás de las pie', 'waist', 'kettlebell', 'waist', 'waist', 'abs', '{"shoulders","forearms"}', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una pesa rusa con una mano. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta. Pasa la pesa rusa entre las piernas, cambiándola de mano cuando llegue detrás de las piernas. Cuando la pesa rusa vuelva hacia adelante, pásala a la otra mano entre las piernas. Continúa pasando la pesa rusa entre las piernas con un movimiento en forma de ocho. Mantén un ritmo constante y activa el core durante todo el ejercicio. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, holding a kettlebell in one hand. Bend your knees slightly and hinge forward at the hips, keeping your back straight. Pass the kettlebell between your legs, switching hands as it reaches the back of your legs. As the kettlebell comes forward, pass it to the other hand between your legs. Continue passing the kettlebell between your legs in a figure 8 motion. Maintain a steady pace and engage your core throughout the exercise. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0532-L4ay0PW.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0532-L4ay0PW.gif', 'L4ay0PW', '© Gym visual — https://gymvisual.com/'),
('0533', 'kettlebell front squat', 'Ponte de pie con los pies separados a la altura de los hombros, con los dedos de los pies ligeramente hacia afuera. Sujeta la pesa rusa con ambas manos frente al pecho, cerca del cuerpo. Activa el core y mantén el pecho elevado mientras bajas las caderas hacia abajo y hacia atrás, como si te sentara', 'upper legs', 'kettlebell', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves"}', 'Ponte de pie con los pies separados a la altura de los hombros, con los dedos de los pies ligeramente hacia afuera. Sujeta la pesa rusa con ambas manos frente al pecho, cerca del cuerpo. Activa el core y mantén el pecho elevado mientras bajas las caderas hacia abajo y hacia atrás, como si te sentaras en una silla. Baja hasta que los muslos queden paralelos al suelo, o tan abajo como puedas hacerlo cómodamente. Empuja con los talones para volver a ponerte de pie, contrayendo los glúteos en la parte más alta. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, toes slightly turned out. Hold the kettlebell with both hands in front of your chest, close to your body. Engage your core and keep your chest up as you lower your hips down and back, as if sitting into a chair. Lower until your thighs are parallel to the ground, or as low as you can comfortably go. Drive through your heels to stand back up, squeezing your glutes at the top. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0533-DB0n8AG.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0533-DB0n8AG.gif', 'DB0n8AG', '© Gym visual — https://gymvisual.com/'),
('0534', 'kettlebell goblet squat', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una pesa rusa cerca del pecho con ambas manos. Manteniendo el pecho elevado y el core activado, baja el cuerpo a una posición de sentadilla flexionando las rodillas y las caderas. Continúa bajando hasta que los muslos queden p', 'upper legs', 'kettlebell', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves"}', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una pesa rusa cerca del pecho con ambas manos. Manteniendo el pecho elevado y el core activado, baja el cuerpo a una posición de sentadilla flexionando las rodillas y las caderas. Continúa bajando hasta que los muslos queden paralelos al suelo, o tan abajo como puedas hacerlo cómodamente. Haz una pausa por un momento en la parte inferior, luego empuja con los talones para regresar a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, holding a kettlebell close to your chest with both hands. Keeping your chest up and core engaged, lower your body down into a squat position by bending at the knees and hips. Continue lowering until your thighs are parallel to the ground, or as low as you can comfortably go. Pause for a moment at the bottom, then push through your heels to return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0534-ZA8b5hc.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0534-ZA8b5hc.gif', 'ZA8b5hc', '© Gym visual — https://gymvisual.com/'),
('0535', 'kettlebell hang clean', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una pesa rusa frente a los muslos. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta. Baja la pesa rusa hacia el suelo, dejando que se balancee entre las piernas. Exti', 'upper legs', 'kettlebell', 'upper legs', 'upper legs', 'hamstrings', '{"glutes","quadriceps","calves"}', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una pesa rusa frente a los muslos. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta. Baja la pesa rusa hacia el suelo, dejando que se balancee entre las piernas. Extiende rápidamente las caderas y las rodillas, usando el impulso para hacer que la pesa rusa suba hasta la altura del hombro. Cuando la pesa rusa llegue a la altura del hombro, rota las muñecas y atrápala en posición de descanso, con el codo pegado al cuerpo y la pesa rusa apoyada en el antebrazo. Baja la pesa rusa de vuelta a la posición inicial entre las piernas y repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, holding a kettlebell in front of your thighs. Bend your knees slightly and hinge forward at the hips, keeping your back straight. Lower the kettlebell towards the ground, allowing it to swing between your legs. Quickly extend your hips and knees, using the momentum to swing the kettlebell up to shoulder height. As the kettlebell reaches shoulder height, rotate your wrists and catch the kettlebell in the rack position, with your elbow tucked in and the kettlebell resting on your forearm. Lower the kettlebell back down to the starting position between your legs, and repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0535-LHWF7us.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0535-LHWF7us.gif', 'LHWF7us', '© Gym visual — https://gymvisual.com/'),
('0536', 'kettlebell lunge pass through', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una pesa rusa frente al pecho con ambas manos. Da un paso adelante con el pie derecho, bajando el cuerpo hasta una posición de zancada. Mientras avanzas en la zancada, pasa la pesa rusa por debajo del muslo derecho y trasládal', 'upper legs', 'kettlebell', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves"}', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una pesa rusa frente al pecho con ambas manos. Da un paso adelante con el pie derecho, bajando el cuerpo hasta una posición de zancada. Mientras avanzas en la zancada, pasa la pesa rusa por debajo del muslo derecho y trasládala a la mano izquierda. Empuja con el pie derecho para volver a la posición inicial, mientras pasas la pesa rusa de vuelta a la mano derecha al mismo tiempo. Repite la zancada en el lado opuesto, pasando la pesa rusa por debajo del muslo izquierdo. Continúa alternando zancadas y pasando la pesa rusa entre las manos durante el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, holding a kettlebell in front of your chest with both hands. Take a step forward with your right foot, lowering your body into a lunge position. As you lunge forward, pass the kettlebell under your right thigh and transfer it to your left hand. Push off with your right foot to return to the starting position, while simultaneously passing the kettlebell back to your right hand. Repeat the lunge on the opposite side, passing the kettlebell under your left thigh. Continue alternating lunges and passing the kettlebell between hands for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0536-WKMQzCD.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0536-WKMQzCD.gif', 'WKMQzCD', '© Gym visual — https://gymvisual.com/'),
('0537', 'kettlebell one arm clean and jerk', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una pesa rusa con una mano en agarre prono. Flexiona ligeramente las rodillas y inclínate desde las caderas, bajando la pesa rusa entre las piernas. Extiende explosivamente las caderas, las rodillas y los tobillos, usando el i', 'shoulders', 'kettlebell', 'shoulders', 'shoulders', 'delts', '{"triceps","core"}', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una pesa rusa con una mano en agarre prono. Flexiona ligeramente las rodillas y inclínate desde las caderas, bajando la pesa rusa entre las piernas. Extiende explosivamente las caderas, las rodillas y los tobillos, usando el impulso para hacer que la pesa rusa suba hasta la altura del hombro. Cuando la pesa rusa llegue a la altura del hombro, rota la muñeca y lanza la mano recta hacia arriba, bloqueando el brazo por encima de la cabeza. Baja la pesa rusa de vuelta a la posición inicial y repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, holding a kettlebell in one hand with an overhand grip. Bend your knees slightly and hinge at the hips, lowering the kettlebell between your legs. Explosively extend your hips, knees, and ankles, using the momentum to swing the kettlebell up to shoulder height. As the kettlebell reaches shoulder height, rotate your wrist and punch your hand straight up, locking out your arm overhead. Lower the kettlebell back down to the starting position and repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0537-vzAxBtt.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0537-vzAxBtt.gif', 'vzAxBtt', '© Gym visual — https://gymvisual.com/'),
('1298', 'kettlebell one arm floor press', 'Túmbate boca arriba en el suelo con las rodillas flexionadas y los pies planos sobre el suelo. Sujeta la pesa rusa con una mano con la palma hacia los pies y el brazo extendido recto hacia el techo. Baja lentamente la pesa rusa hacia el pecho flexionando el codo, manteniendo el brazo superior cerca ', 'chest', 'kettlebell', 'chest', 'chest', 'pectorals', '{"triceps","shoulders"}', 'Túmbate boca arriba en el suelo con las rodillas flexionadas y los pies planos sobre el suelo. Sujeta la pesa rusa con una mano con la palma hacia los pies y el brazo extendido recto hacia el techo. Baja lentamente la pesa rusa hacia el pecho flexionando el codo, manteniendo el brazo superior cerca del cuerpo. Haz una pausa cuando la pesa rusa esté justo encima del pecho, luego empújala de vuelta hacia arriba a la posición inicial extendiendo el codo. Repite el número de repeticiones deseado, luego cambia al otro brazo.', 'Lie flat on your back on the floor with your knees bent and feet flat on the ground. Hold the kettlebell in one hand with your palm facing towards your feet and your arm extended straight up towards the ceiling. Slowly lower the kettlebell towards your chest by bending your elbow, keeping your upper arm close to your body. Pause for a moment when the kettlebell is just above your chest, then push it back up to the starting position by extending your elbow. Repeat for the desired number of repetitions, then switch to the other arm.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1298-rg59QCH.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1298-rg59QCH.gif', 'rg59QCH', '© Gym visual — https://gymvisual.com/'),
('0538', 'kettlebell one arm jerk', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una pesa rusa con una mano a la altura del hombro. Flexiona ligeramente las rodillas y activa el core. Presiona la pesa rusa por encima de la cabeza en línea recta, extendiendo el brazo por completo. Mientras presionas la pesa', 'shoulders', 'kettlebell', 'shoulders', 'shoulders', 'delts', '{"triceps","core"}', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una pesa rusa con una mano a la altura del hombro. Flexiona ligeramente las rodillas y activa el core. Presiona la pesa rusa por encima de la cabeza en línea recta, extendiendo el brazo por completo. Mientras presionas la pesa rusa por encima de la cabeza, flexiona las rodillas simultáneamente y estíralas rápidamente para generar impulso. Cuando la pesa rusa llegue a su punto más alto, baja rápidamente por debajo de ella flexionando las rodillas y las caderas. Atrapa la pesa rusa con una ligera flexión de rodillas y caderas, y el brazo completamente extendido por encima de la cabeza. Ponte de pie recto, extendiendo por completo las rodillas y las caderas, y estabiliza la pesa rusa por encima de la cabeza. Baja la pesa rusa de vuelta a la posición inicial flexionando las rodillas y las caderas, y repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, holding a kettlebell in one hand at shoulder height. Bend your knees slightly and engage your core. Press the kettlebell overhead in a straight line, fully extending your arm. As you press the kettlebell overhead, simultaneously dip your knees and quickly straighten them to generate momentum. As the kettlebell reaches its highest point, quickly drop underneath it by bending your knees and hips. Catch the kettlebell with a slight bend in your knees and hips, and your arm fully extended overhead. Stand up straight, fully extending your knees and hips, and stabilize the kettlebell overhead. Lower the kettlebell back to the starting position by bending your knees and hips, and repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0538-S37C94C.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0538-S37C94C.gif', 'S37C94C', '© Gym visual — https://gymvisual.com/'),
('0539', 'kettlebell one arm military press to the side', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una pesa rusa con una mano a la altura del hombro. Activa el core y mantén la espalda recta. Presiona la pesa rusa por encima de la cabeza, extendiendo el brazo por completo. Haz una pausa breve en lo alto, luego baja lentamen', 'shoulders', 'kettlebell', 'shoulders', 'shoulders', 'delts', '{"triceps","core"}', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una pesa rusa con una mano a la altura del hombro. Activa el core y mantén la espalda recta. Presiona la pesa rusa por encima de la cabeza, extendiendo el brazo por completo. Haz una pausa breve en lo alto, luego baja lentamente la pesa rusa de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia de lado.', 'Stand with your feet shoulder-width apart, holding a kettlebell in one hand at shoulder height. Engage your core and keep your back straight. Press the kettlebell overhead, extending your arm fully. Pause for a moment at the top, then slowly lower the kettlebell back to the starting position. Repeat for the desired number of repetitions, then switch sides.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0539-yCvYdi7.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0539-yCvYdi7.gif', 'yCvYdi7', '© Gym visual — https://gymvisual.com/'),
('0540', 'kettlebell one arm push press', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una pesa rusa con una mano a la altura del hombro. Flexiona ligeramente las rodillas y activa el core. Presiona la pesa rusa por encima de la cabeza extendiendo el brazo y estirando por completo las piernas. Baja la pesa rusa ', 'shoulders', 'kettlebell', 'shoulders', 'shoulders', 'delts', '{"triceps","core"}', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una pesa rusa con una mano a la altura del hombro. Flexiona ligeramente las rodillas y activa el core. Presiona la pesa rusa por encima de la cabeza extendiendo el brazo y estirando por completo las piernas. Baja la pesa rusa de vuelta a la posición inicial flexionando las rodillas y devolviendo la pesa rusa al hombro. Repite el número de repeticiones deseado, luego cambia de lado.', 'Stand with your feet shoulder-width apart, holding a kettlebell in one hand at shoulder level. Bend your knees slightly and engage your core. Press the kettlebell overhead by extending your arm and fully extending your legs. Lower the kettlebell back to the starting position by bending your knees and bringing the kettlebell back to your shoulder. Repeat for the desired number of repetitions, then switch sides.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0540-osdXT3K.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0540-osdXT3K.gif', 'osdXT3K', '© Gym visual — https://gymvisual.com/'),
('0541', 'kettlebell one arm row', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una pesa rusa con una mano en agarre prono. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta y el core activado. Tira de la pesa rusa hacia el pecho, manteniendo el c', 'back', 'kettlebell', 'back', 'back', 'upper back', '{"biceps","forearms"}', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una pesa rusa con una mano en agarre prono. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta y el core activado. Tira de la pesa rusa hacia el pecho, manteniendo el codo cerca del cuerpo y juntando los omóplatos. Haz una pausa breve en lo alto, luego baja lentamente la pesa rusa de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia de lado y repite con el otro brazo.', 'Stand with your feet shoulder-width apart, holding a kettlebell in one hand with an overhand grip. Bend your knees slightly and hinge forward at the hips, keeping your back straight and your core engaged. Pull the kettlebell up towards your chest, keeping your elbow close to your body and squeezing your shoulder blades together. Pause for a moment at the top, then slowly lower the kettlebell back down to the starting position. Repeat for the desired number of repetitions, then switch sides and repeat with the other arm.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0541-g9AsZ8P.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0541-g9AsZ8P.gif', 'g9AsZ8P', '© Gym visual — https://gymvisual.com/'),
('0542', 'kettlebell one arm snatch', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una pesa rusa con una mano entre las piernas. Flexiona ligeramente las rodillas e inclínate desde las caderas, bajando la pesa rusa hacia el suelo. Extiende explosivamente las caderas y las rodillas, usando el impulso para hac', 'shoulders', 'kettlebell', 'shoulders', 'shoulders', 'delts', '{"trapezius","forearms","core"}', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una pesa rusa con una mano entre las piernas. Flexiona ligeramente las rodillas e inclínate desde las caderas, bajando la pesa rusa hacia el suelo. Extiende explosivamente las caderas y las rodillas, usando el impulso para hacer que la pesa rusa suba hacia el hombro. Cuando la pesa rusa llegue a la altura del hombro, rota la mano y lánzala recta hacia arriba por encima de la cabeza, extendiendo el brazo por completo. Baja la pesa rusa de vuelta entre las piernas y repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, holding a kettlebell in one hand between your legs. Bend your knees slightly and hinge at the hips, lowering the kettlebell towards the ground. Explosively extend your hips and knees, using the momentum to swing the kettlebell up towards your shoulder. As the kettlebell reaches shoulder height, rotate your hand and punch it straight up overhead, fully extending your arm. Lower the kettlebell back down between your legs and repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0542-aXcUyKb.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0542-aXcUyKb.gif', 'aXcUyKb', '© Gym visual — https://gymvisual.com/'),
('0543', 'kettlebell pirate supper legs', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una pesa rusa con una mano. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta. Levanta la pesa rusa hasta la altura del hombro, manteniendo el codo cerca del cuerpo. E', 'shoulders', 'kettlebell', 'shoulders', 'shoulders', 'delts', '{"triceps","forearms"}', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una pesa rusa con una mano. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta. Levanta la pesa rusa hasta la altura del hombro, manteniendo el codo cerca del cuerpo. Extiende el brazo por completo por encima de la cabeza, enderezando el codo. Baja la pesa rusa de vuelta a la altura del hombro, luego vuelve a la posición inicial. Repite el número de repeticiones deseado, luego cambia de lado.', 'Stand with your feet shoulder-width apart, holding a kettlebell in one hand. Bend your knees slightly and hinge forward at the hips, keeping your back straight. Raise the kettlebell up to shoulder height, keeping your elbow close to your body. Extend your arm fully overhead, straightening your elbow. Lower the kettlebell back down to shoulder height, then return to the starting position. Repeat for the desired number of repetitions, then switch sides.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0543-kuXhl0o.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0543-kuXhl0o.gif', 'kuXhl0o', '© Gym visual — https://gymvisual.com/'),
('0544', 'kettlebell pistol squat', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una pesa rusa frente al pecho con ambas manos. Levanta el pie izquierdo del suelo y extiéndelo hacia adelante, manteniéndolo paralelo al suelo. Baja lentamente el cuerpo a una posición de sentadilla, manteniendo el pie derecho', 'upper legs', 'kettlebell', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves"}', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una pesa rusa frente al pecho con ambas manos. Levanta el pie izquierdo del suelo y extiéndelo hacia adelante, manteniéndolo paralelo al suelo. Baja lentamente el cuerpo a una posición de sentadilla, manteniendo el pie derecho plano en el suelo y la pierna izquierda extendida. Haz una pausa breve en la parte baja de la sentadilla, luego empuja con el talón derecho para volver a la posición inicial. Repite el número de repeticiones deseado, luego cambia de pierna.', 'Stand with your feet shoulder-width apart, holding a kettlebell in front of your chest with both hands. Lift your left foot off the ground and extend it forward, keeping it parallel to the ground. Slowly lower your body down into a squat position, keeping your right foot flat on the ground and your left leg extended. Pause for a moment at the bottom of the squat, then push through your right heel to return to the starting position. Repeat for the desired number of repetitions, then switch legs.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0544-5bpPTHv.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0544-5bpPTHv.gif', '5bpPTHv', '© Gym visual — https://gymvisual.com/'),
('0545', 'kettlebell plyo push-up', 'Comienza en una posición de plancha alta con las manos sobre las pesas rusas, separadas a la altura de los hombros. Baja el pecho hacia el suelo, manteniendo los codos cerca del cuerpo. Empuja con las manos de forma explosiva, levantándolas de las pesas rusas y extendiendo los brazos por completo. A', 'chest', 'kettlebell', 'chest', 'chest', 'pectorals', '{"triceps","shoulders","core"}', 'Comienza en una posición de plancha alta con las manos sobre las pesas rusas, separadas a la altura de los hombros. Baja el pecho hacia el suelo, manteniendo los codos cerca del cuerpo. Empuja con las manos de forma explosiva, levantándolas de las pesas rusas y extendiendo los brazos por completo. Aterriza suavemente sobre las pesas rusas y baja el pecho de inmediato para la siguiente repetición. Repite el número de repeticiones deseado.', 'Start in a high plank position with your hands on the kettlebells, shoulder-width apart. Lower your chest towards the ground, keeping your elbows close to your body. Push through your hands explosively, lifting your hands off the kettlebells and extending your arms fully. Land softly back on the kettlebells and immediately lower your chest back down for the next repetition. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0545-ktf3nvW.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0545-ktf3nvW.gif', 'ktf3nvW', '© Gym visual — https://gymvisual.com/'),
('0546', 'kettlebell seated press', 'Siéntate en un banco con la espalda recta y los pies planos sobre el suelo. Sujeta una pesa rusa en cada mano a la altura del hombro, con las palmas hacia adelante. Presiona las pesas rusas por encima de la cabeza, extendiendo los brazos por completo. Baja las pesas rusas de vuelta a la altura del h', 'shoulders', 'kettlebell', 'shoulders', 'shoulders', 'delts', '{"triceps","core"}', 'Siéntate en un banco con la espalda recta y los pies planos sobre el suelo. Sujeta una pesa rusa en cada mano a la altura del hombro, con las palmas hacia adelante. Presiona las pesas rusas por encima de la cabeza, extendiendo los brazos por completo. Baja las pesas rusas de vuelta a la altura del hombro. Repite el número de repeticiones deseado.', 'Sit on a bench with your back straight and feet flat on the ground. Hold a kettlebell in each hand at shoulder height, palms facing forward. Press the kettlebells overhead, fully extending your arms. Lower the kettlebells back to shoulder height. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0546-BkxB8LW.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0546-BkxB8LW.gif', 'BkxB8LW', '© Gym visual — https://gymvisual.com/'),
('1438', 'kettlebell seated two arm military press', 'Siéntate en un banco con la espalda recta y los pies planos sobre el suelo. Sujeta una pesa rusa en cada mano a la altura del hombro con las palmas hacia adelante. Presiona las pesas rusas por encima de la cabeza extendiendo los brazos por completo. Haz una pausa breve en lo alto, luego baja lentame', 'shoulders', 'kettlebell', 'shoulders', 'shoulders', 'delts', '{"triceps","upper back"}', 'Siéntate en un banco con la espalda recta y los pies planos sobre el suelo. Sujeta una pesa rusa en cada mano a la altura del hombro con las palmas hacia adelante. Presiona las pesas rusas por encima de la cabeza extendiendo los brazos por completo. Haz una pausa breve en lo alto, luego baja lentamente las pesas rusas de vuelta a la altura del hombro. Repite el número de repeticiones deseado.', 'Sit on a bench with your back straight and feet flat on the ground. Hold a kettlebell in each hand at shoulder level with your palms facing forward. Press the kettlebells overhead by extending your arms fully. Pause for a moment at the top, then slowly lower the kettlebells back to shoulder level. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1438-ZEkjZDi.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1438-ZEkjZDi.gif', 'ZEkjZDi', '© Gym visual — https://gymvisual.com/'),
('0547', 'kettlebell seesaw press', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo una pesa rusa en cada mano a la altura de los hombros. Presiona una pesa rusa por encima de la cabeza mientras mantienes la otra pesa rusa a la altura del hombro. Baja la pesa rusa presionada de vuelta a la altura del hombro', 'shoulders', 'kettlebell', 'shoulders', 'shoulders', 'delts', '{"triceps","core"}', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo una pesa rusa en cada mano a la altura de los hombros. Presiona una pesa rusa por encima de la cabeza mientras mantienes la otra pesa rusa a la altura del hombro. Baja la pesa rusa presionada de vuelta a la altura del hombro mientras presionas simultáneamente la otra pesa rusa por encima de la cabeza. Continúa alternando el movimiento de presión, creando un movimiento similar a un balancín. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, holding a kettlebell in each hand at shoulder height. Press one kettlebell overhead while keeping the other kettlebell at shoulder height. Lower the pressed kettlebell back to shoulder height while simultaneously pressing the other kettlebell overhead. Continue alternating the pressing motion, creating a seesaw-like movement. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0547-UDm6cGl.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0547-UDm6cGl.gif', 'UDm6cGl', '© Gym visual — https://gymvisual.com/'),
('0548', 'kettlebell sumo high pull', 'Ponte de pie con los pies más separados que el ancho de los hombros, con las puntas de los pies hacia afuera. Sujeta una pesa rusa con ambas manos frente al cuerpo, con los brazos extendidos hacia abajo. Flexiona las rodillas y baja las caderas hasta una posición de sentadilla, manteniendo la espald', 'back', 'kettlebell', 'back', 'back', 'traps', '{"shoulders","glutes","hamstrings"}', 'Ponte de pie con los pies más separados que el ancho de los hombros, con las puntas de los pies hacia afuera. Sujeta una pesa rusa con ambas manos frente al cuerpo, con los brazos extendidos hacia abajo. Flexiona las rodillas y baja las caderas hasta una posición de sentadilla, manteniendo la espalda recta. Empuja con los talones y extiende explosivamente las caderas y las rodillas, tirando de la pesa rusa hacia la barbilla. Mientras tiras de la pesa rusa hacia arriba, mantén los codos altos y abiertos, y junta los omóplatos. Baja la pesa rusa de vuelta a la posición inicial y repite el número de repeticiones deseado.', 'Stand with your feet wider than shoulder-width apart, toes pointing outwards. Hold a kettlebell with both hands in front of your body, arms extended downwards. Bend your knees and lower your hips into a squat position, keeping your back straight. Drive through your heels and explosively extend your hips and knees, pulling the kettlebell up towards your chin. As you pull the kettlebell up, keep your elbows high and wide, and squeeze your shoulder blades together. Lower the kettlebell back down to the starting position and repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0548-8ARQ9Hw.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0548-8ARQ9Hw.gif', '8ARQ9Hw', '© Gym visual — https://gymvisual.com/'),
('0549', 'kettlebell swing', 'Ponte de pie con los pies separados a la altura de los hombros, con los dedos de los pies ligeramente hacia afuera. Sujeta la pesa rusa con ambas manos frente al cuerpo, con los brazos extendidos. Flexiona ligeramente las rodillas e inclínate desde las caderas, empujando los glúteos hacia atrás. Lle', 'upper legs', 'kettlebell', 'upper legs', 'upper legs', 'glutes', '{"hamstrings","core"}', 'Ponte de pie con los pies separados a la altura de los hombros, con los dedos de los pies ligeramente hacia afuera. Sujeta la pesa rusa con ambas manos frente al cuerpo, con los brazos extendidos. Flexiona ligeramente las rodillas e inclínate desde las caderas, empujando los glúteos hacia atrás. Lleva la pesa rusa hacia atrás entre las piernas, manteniendo los brazos rectos y la espalda plana. Lleva las caderas hacia adelante y haz que la pesa rusa suba hasta la altura del hombro, usando el impulso generado por las caderas. Deja que la pesa rusa se balancee de vuelta hacia abajo entre las piernas y repite el movimiento el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, toes pointed slightly outward. Hold the kettlebell with both hands in front of your body, arms extended. Bend your knees slightly and hinge at the hips, pushing your butt back. Swing the kettlebell back between your legs, keeping your arms straight and maintaining a flat back. Drive your hips forward and swing the kettlebell up to shoulder height, using the momentum generated by your hips. Allow the kettlebell to swing back down between your legs and repeat the movement for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0549-UHJlbu3.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0549-UHJlbu3.gif', 'UHJlbu3', '© Gym visual — https://gymvisual.com/'),
('0550', 'kettlebell thruster', 'Comienza de pie con los pies separados a la altura de los hombros, sujetando una pesa rusa frente al pecho con ambas manos, con las palmas una frente a la otra. Baja a una posición de sentadilla flexionando las rodillas y empujando las caderas hacia atrás, manteniendo el pecho elevado y la espalda r', 'shoulders', 'kettlebell', 'shoulders', 'shoulders', 'delts', '{"quadriceps","glutes","core"}', 'Comienza de pie con los pies separados a la altura de los hombros, sujetando una pesa rusa frente al pecho con ambas manos, con las palmas una frente a la otra. Baja a una posición de sentadilla flexionando las rodillas y empujando las caderas hacia atrás, manteniendo el pecho elevado y la espalda recta. Al llegar a la parte baja de la sentadilla, empuja explosivamente con los talones para ponerte de pie, presionando al mismo tiempo la pesa rusa por encima de la cabeza. Bloquea los brazos en la parte alta del movimiento, extendiendo los codos por completo. Baja la pesa rusa de vuelta a la posición inicial invirtiendo el movimiento, flexionando los codos y bajando el peso de vuelta al pecho. Repite el número de repeticiones deseado.', 'Start by standing with your feet shoulder-width apart, holding a kettlebell in front of your chest with both hands, palms facing each other. Lower into a squat position by bending your knees and pushing your hips back, keeping your chest up and your back straight. As you reach the bottom of the squat, explosively drive through your heels to stand up, simultaneously pressing the kettlebell overhead. Lock out your arms at the top of the movement, fully extending your elbows. Lower the kettlebell back to the starting position by reversing the movement, bending your elbows and lowering the weight back to your chest. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0550-yWxMvB5.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0550-yWxMvB5.gif', 'yWxMvB5', '© Gym visual — https://gymvisual.com/'),
('0551', 'kettlebell turkish get up (squat style)', 'Comienza tumbado boca arriba con las piernas extendidas y la pesa rusa sostenida en la mano derecha, con el brazo completamente extendido por encima del hombro. Flexiona la rodilla derecha y coloca el pie derecho plano en el suelo, manteniendo la pierna izquierda extendida. Presionando con el pie de', 'upper legs', 'kettlebell', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","core"}', 'Comienza tumbado boca arriba con las piernas extendidas y la pesa rusa sostenida en la mano derecha, con el brazo completamente extendido por encima del hombro. Flexiona la rodilla derecha y coloca el pie derecho plano en el suelo, manteniendo la pierna izquierda extendida. Presionando con el pie derecho, levanta las caderas del suelo, llegando a una posición de puente. Desliza la pierna izquierda por debajo del cuerpo, flexionando la rodilla izquierda y colocando el pie izquierdo plano en el suelo. Rota el torso hacia la izquierda, llevando la mano izquierda al suelo como apoyo. Presionando con el pie derecho y la mano izquierda, levanta el torso del suelo, llegando a una posición de rodillas. Desde la posición de rodillas, ponte de pie, manteniendo la pesa rusa extendida por encima de la cabeza. Invierte el movimiento para volver a la posición inicial. Repite el ejercicio en el otro lado, comenzando con la pesa rusa en la mano izquierda.', 'Start by lying on your back with your legs extended and the kettlebell held in your right hand, arm fully extended above your shoulder. Bend your right knee and place your right foot flat on the ground, keeping your left leg extended. Pressing through your right foot, lift your hips off the ground, coming into a bridge position. Slide your left leg underneath your body, bending your left knee and placing your left foot flat on the ground. Rotate your torso to the left, bringing your left hand to the ground for support. Pressing through your right foot and left hand, lift your torso off the ground, coming into a kneeling position. From the kneeling position, stand up, keeping the kettlebell extended overhead. Reverse the movement to return to the starting position. Repeat the exercise on the other side, starting with the kettlebell in your left hand.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0551-Ha7SZ3y.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0551-Ha7SZ3y.gif', 'Ha7SZ3y', '© Gym visual — https://gymvisual.com/'),
('0552', 'kettlebell two arm clean', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una pesa rusa frente a los muslos con ambas manos, con las palmas hacia ti. Flexiona ligeramente las rodillas e inclínate desde las caderas, bajando la pesa rusa hacia el suelo. Extiende explosivamente las caderas y las rodill', 'shoulders', 'kettlebell', 'shoulders', 'shoulders', 'delts', '{"traps","forearms"}', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una pesa rusa frente a los muslos con ambas manos, con las palmas hacia ti. Flexiona ligeramente las rodillas e inclínate desde las caderas, bajando la pesa rusa hacia el suelo. Extiende explosivamente las caderas y las rodillas, usando el impulso para tirar de la pesa rusa hacia los hombros. Cuando la pesa rusa llegue a la altura del hombro, rota las muñecas y atrápala en posición de descanso, con los codos pegados al cuerpo y la pesa rusa apoyada en la parte posterior del antebrazo. Baja la pesa rusa de vuelta a la posición inicial y repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, holding a kettlebell in front of your thighs with both hands, palms facing towards you. Bend your knees slightly and hinge at the hips, lowering the kettlebell towards the ground. Explosively extend your hips and knees, using the momentum to pull the kettlebell up towards your shoulders. As the kettlebell reaches shoulder height, rotate your wrists and catch the kettlebell in the rack position, with your elbows tucked in and the kettlebell resting on the back of your forearm. Lower the kettlebell back down to the starting position and repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0552-7Ba7bQ2.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0552-7Ba7bQ2.gif', '7Ba7bQ2', '© Gym visual — https://gymvisual.com/'),
('0553', 'kettlebell two arm military press', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una pesa rusa en cada mano a la altura del hombro con las palmas hacia adelante. Activa el core y presiona las pesas rusas por encima de la cabeza, extendiendo los brazos por completo. Haz una pausa breve en lo alto, luego baj', 'shoulders', 'kettlebell', 'shoulders', 'shoulders', 'delts', '{"triceps","upper back"}', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una pesa rusa en cada mano a la altura del hombro con las palmas hacia adelante. Activa el core y presiona las pesas rusas por encima de la cabeza, extendiendo los brazos por completo. Haz una pausa breve en lo alto, luego baja lentamente las pesas rusas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, holding a kettlebell in each hand at shoulder level with your palms facing forward. Engage your core and press the kettlebells overhead, fully extending your arms. Pause for a moment at the top, then slowly lower the kettlebells back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0553-blBXysN.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0553-blBXysN.gif', 'blBXysN', '© Gym visual — https://gymvisual.com/'),
('1345', 'kettlebell two arm row', 'Ponte de pie con los pies separados a la altura de los hombros, las rodillas ligeramente flexionadas, y sostén una pesa rusa en cada mano con las palmas hacia el cuerpo. Inclínate hacia adelante desde las caderas, manteniendo la espalda recta y el core activado. Tira de las pesas rusas hacia el pech', 'back', 'kettlebell', 'back', 'back', 'upper back', '{"biceps","forearms"}', 'Ponte de pie con los pies separados a la altura de los hombros, las rodillas ligeramente flexionadas, y sostén una pesa rusa en cada mano con las palmas hacia el cuerpo. Inclínate hacia adelante desde las caderas, manteniendo la espalda recta y el core activado. Tira de las pesas rusas hacia el pecho, juntando los omóplatos. Haz una pausa breve en lo alto, luego baja lentamente las pesas rusas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, knees slightly bent, and hold a kettlebell in each hand with your palms facing your body. Bend forward at the hips, keeping your back straight and your core engaged. Pull the kettlebells up towards your chest, squeezing your shoulder blades together. Pause for a moment at the top, then slowly lower the kettlebells back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1345-wf24o8S.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1345-wf24o8S.gif', 'wf24o8S', '© Gym visual — https://gymvisual.com/'),
('0554', 'kettlebell windmill', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una pesa rusa en la mano derecha por encima de la cabeza. Rota el pie izquierdo hacia afuera unos 45 grados y mantén el pie derecho apuntando hacia adelante. Inclina el torso hacia el lado izquierdo, manteniendo el brazo derec', 'waist', 'kettlebell', 'waist', 'waist', 'abs', '{"obliques","shoulders"}', 'Ponte de pie con los pies separados a la altura de los hombros, sujetando una pesa rusa en la mano derecha por encima de la cabeza. Rota el pie izquierdo hacia afuera unos 45 grados y mantén el pie derecho apuntando hacia adelante. Inclina el torso hacia el lado izquierdo, manteniendo el brazo derecho extendido por encima de la cabeza y la mirada en la pesa rusa. Baja el torso tanto como puedas mientras mantienes el brazo derecho recto y el brazo izquierdo extendido hacia el lado. Haz una pausa breve, luego vuelve a la posición inicial empujando con el pie derecho y activando los oblicuos. Repite el número de repeticiones deseado, luego cambia de lado.', 'Stand with your feet shoulder-width apart, holding a kettlebell in your right hand overhead. Rotate your left foot outwards about 45 degrees and keep your right foot pointing forward. Bend your torso to the left side, keeping your right arm extended overhead and your eyes on the kettlebell. Lower your torso as far as you can while keeping your right arm straight and your left arm extended to the side. Pause for a moment, then return to the starting position by pushing through your right foot and engaging your obliques. Repeat for the desired number of repetitions, then switch sides.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0554-9Tkqa9O.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0554-9Tkqa9O.gif', '9Tkqa9O', '© Gym visual — https://gymvisual.com/'),
('0555', 'kick out sit', 'Siéntate en el borde de un banco o una silla con los pies planos en el suelo y las rodillas flexionadas en un ángulo de 90 grados. Inclínate ligeramente hacia atrás y coloca las manos en el borde del banco o la silla como apoyo. Activando los isquiotibiales, levanta los pies del suelo y extiende las', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'hamstrings', '{"quadriceps","glutes"}', 'Siéntate en el borde de un banco o una silla con los pies planos en el suelo y las rodillas flexionadas en un ángulo de 90 grados. Inclínate ligeramente hacia atrás y coloca las manos en el borde del banco o la silla como apoyo. Activando los isquiotibiales, levanta los pies del suelo y extiende las piernas rectas hacia adelante. Haz una pausa breve en lo alto, luego flexiona lentamente las rodillas y lleva los pies de vuelta hacia el cuerpo. Repite el número de repeticiones deseado.', 'Sit on the edge of a bench or chair with your feet flat on the ground and your knees bent at a 90-degree angle. Lean back slightly and place your hands on the edge of the bench or chair for support. Engaging your hamstrings, lift your feet off the ground and extend your legs straight out in front of you. Pause for a moment at the top, then slowly bend your knees and bring your feet back towards your body. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0555-v7p5bYl.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0555-v7p5bYl.gif', 'v7p5bYl', '© Gym visual — https://gymvisual.com/'),
('0558', 'kipping muscle up', 'Comienza colgándote de una barra de dominadas con un agarre prono, con las manos un poco más separadas que el ancho de los hombros. Activa el core y usa un movimiento de balanceo para generar impulso. Mientras te balanceas hacia adelante, tira del pecho hacia la barra, usando los dorsales y los bíce', 'back', 'body weight', 'back', 'back', 'lats', '{"biceps","triceps","shoulders","core"}', 'Comienza colgándote de una barra de dominadas con un agarre prono, con las manos un poco más separadas que el ancho de los hombros. Activa el core y usa un movimiento de balanceo para generar impulso. Mientras te balanceas hacia adelante, tira del pecho hacia la barra, usando los dorsales y los bíceps para iniciar el movimiento. Continúa el movimiento ascendente hasta que el pecho llegue a la barra, luego pasa a una posición de fondos empujando hacia abajo en la barra y extendiendo los brazos. Bájate de vuelta a la posición inicial flexionando los brazos y controlando el descenso. Repite el número de repeticiones deseado.', 'Start by hanging from a pull-up bar with an overhand grip, hands slightly wider than shoulder-width apart. Engage your core and use a swinging motion to generate momentum. As you swing forward, pull your chest towards the bar, using your lats and biceps to initiate the movement. Continue the upward motion until your chest reaches the bar, then transition into a dip position by pushing down on the bar and extending your arms. Lower yourself back down to the starting position by bending your arms and controlling the descent. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0558-pM07UxU.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0558-pM07UxU.gif', 'pM07UxU', '© Gym visual — https://gymvisual.com/'),
('3640', 'knee touch crunch', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Coloca las manos detrás de la cabeza con los codos apuntando hacia afuera. Activando el abdomen, levanta los omóplatos del suelo y extiende la mano derecha hacia la rodilla izquierda. Vuelve a la posición inicial ', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"hip flexors"}', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Coloca las manos detrás de la cabeza con los codos apuntando hacia afuera. Activando el abdomen, levanta los omóplatos del suelo y extiende la mano derecha hacia la rodilla izquierda. Vuelve a la posición inicial y repite, esta vez extendiendo la mano izquierda hacia la rodilla derecha. Continúa alternando lados durante el número de repeticiones deseado.', 'Lie flat on your back with your knees bent and feet flat on the ground. Place your hands behind your head with your elbows pointing outwards. Engaging your abs, lift your shoulder blades off the ground and reach your right hand towards your left knee. Return to the starting position and repeat, this time reaching your left hand towards your right knee. Continue alternating sides for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3640-dTg95eZ.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3640-dTg95eZ.gif', 'dTg95eZ', '© Gym visual — https://gymvisual.com/'),
('1420', 'kneeling jump squat', 'Comienza arrodillado en el suelo con los pies separados a la altura de las caderas y los dedos de los pies apuntando hacia adelante. Sujeta una barra sobre la parte superior de la espalda, apoyándola en los hombros. Activa el core y los glúteos, luego salta explosivamente hacia arriba, extendiendo l', 'upper legs', 'barbell', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves"}', 'Comienza arrodillado en el suelo con los pies separados a la altura de las caderas y los dedos de los pies apuntando hacia adelante. Sujeta una barra sobre la parte superior de la espalda, apoyándola en los hombros. Activa el core y los glúteos, luego salta explosivamente hacia arriba, extendiendo las caderas y las rodillas. Mientras saltas, empuja con los dedos de los pies y extiende por completo los tobillos, las rodillas y las caderas. Aterriza suavemente de vuelta en el suelo, flexionando las rodillas para absorber el impacto. Pasa de inmediato a la siguiente repetición, repitiendo el movimiento de sentadilla con salto.', 'Start by kneeling on the ground with your feet hip-width apart and your toes pointing forward. Hold a barbell across your upper back, resting it on your shoulders. Engage your core and glutes, then explosively jump up into the air, extending your hips and knees. As you jump, push through your toes and fully extend your ankles, knees, and hips. Land softly back on the ground, bending your knees to absorb the impact. Immediately go into the next repetition, repeating the jump squat motion.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1420-UgDm3oy.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1420-UgDm3oy.gif', 'UgDm3oy', '© Gym visual — https://gymvisual.com/'),
('1346', 'kneeling lat stretch', 'Arrodíllate en el suelo con las rodillas separadas a la altura de las caderas y los dedos de los pies apuntando hacia atrás. Extiende los brazos por encima de la cabeza y entrelaza los dedos. Manteniendo la espalda recta, inclínate lentamente hacia el lado derecho, sintiendo un estiramiento en el do', 'back', 'body weight', 'back', 'back', 'lats', '{"shoulders","triceps"}', 'Arrodíllate en el suelo con las rodillas separadas a la altura de las caderas y los dedos de los pies apuntando hacia atrás. Extiende los brazos por encima de la cabeza y entrelaza los dedos. Manteniendo la espalda recta, inclínate lentamente hacia el lado derecho, sintiendo un estiramiento en el dorsal izquierdo. Mantén el estiramiento durante 20-30 segundos, luego vuelve a la posición inicial. Repite el estiramiento en el lado izquierdo, inclinándote hacia la izquierda y sintiendo un estiramiento en el dorsal derecho. Continúa alternando lados durante el número de repeticiones deseado.', 'Kneel on the ground with your knees hip-width apart and your toes pointing back. Extend your arms overhead and interlace your fingers. Keeping your back straight, slowly lean to the right side, feeling a stretch in your left lat muscle. Hold the stretch for 20-30 seconds, then return to the starting position. Repeat the stretch on the left side, leaning to the left and feeling a stretch in your right lat muscle. Continue alternating sides for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1346-f38OEuO.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1346-f38OEuO.gif', 'f38OEuO', '© Gym visual — https://gymvisual.com/'),
('3239', 'kneeling plank tap shoulder (male)', 'Comienza en posición de rodillas con las manos en el suelo, separadas a la altura de los hombros. Extiende las piernas hacia atrás, apoyándote en los dedos de los pies, y levanta el cuerpo a una posición de plancha. Manteniendo el core activado y las caderas estables, levanta una mano del suelo y to', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"shoulders","triceps"}', 'Comienza en posición de rodillas con las manos en el suelo, separadas a la altura de los hombros. Extiende las piernas hacia atrás, apoyándote en los dedos de los pies, y levanta el cuerpo a una posición de plancha. Manteniendo el core activado y las caderas estables, levanta una mano del suelo y toca el hombro opuesto. Devuelve la mano al suelo y repite con la otra mano. Continúa alternando lados durante el número de repeticiones deseado.', 'Start in a kneeling position with your hands on the ground, shoulder-width apart. Extend your legs behind you, resting on your toes, and lift your body into a plank position. Keeping your core engaged and your hips stable, lift one hand off the ground and tap the opposite shoulder. Return the hand to the ground and repeat with the other hand. Continue alternating sides for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3239-h1ezqSu.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3239-h1ezqSu.gif', 'h1ezqSu', '© Gym visual — https://gymvisual.com/'),
('3211', 'kneeling push-up (male)', 'Comienza arrodillado en el suelo con las manos separadas a la altura de los hombros, los dedos apuntando hacia adelante. Extiende las piernas hacia atrás, apoyándote en la punta de los pies, de modo que tu cuerpo forme una línea recta desde la cabeza hasta los talones. Activa el core y baja el cuerp', 'chest', 'body weight', 'chest', 'chest', 'pectorals', '{"triceps","shoulders"}', 'Comienza arrodillado en el suelo con las manos separadas a la altura de los hombros, los dedos apuntando hacia adelante. Extiende las piernas hacia atrás, apoyándote en la punta de los pies, de modo que tu cuerpo forme una línea recta desde la cabeza hasta los talones. Activa el core y baja el cuerpo hacia el suelo flexionando los codos, manteniéndolos cerca de los costados. Continúa bajando hasta que el pecho esté justo encima del suelo, luego empuja hacia arriba a la posición inicial enderezando los brazos. Repite el número de repeticiones deseado.', 'Start by kneeling on the ground with your hands shoulder-width apart, fingers pointing forward. Extend your legs behind you, resting on the balls of your feet, so that your body forms a straight line from head to heels. Engage your core and lower your body towards the ground by bending your elbows, keeping them close to your sides. Continue lowering until your chest is just above the ground, then push back up to the starting position by straightening your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3211-ZOuKWir.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3211-ZOuKWir.gif', 'ZOuKWir', '© Gym visual — https://gymvisual.com/'),
('3288', 'korean dips', 'Colócate entre dos barras paralelas con los brazos extendidos sosteniendo el peso de tu cuerpo. Baja el cuerpo flexionando los codos hasta que los brazos queden paralelos al suelo. Haz una pausa breve, luego empújate de nuevo hacia arriba a la posición inicial estirando los brazos. Repite el número ', 'chest', 'body weight', 'chest', 'chest', 'pectorals', '{"triceps","shoulders"}', 'Colócate entre dos barras paralelas con los brazos extendidos sosteniendo el peso de tu cuerpo. Baja el cuerpo flexionando los codos hasta que los brazos queden paralelos al suelo. Haz una pausa breve, luego empújate de nuevo hacia arriba a la posición inicial estirando los brazos. Repite el número de repeticiones deseado.', 'Position yourself between two parallel bars with your arms extended and supporting your body weight. Lower your body by bending your elbows until your upper arms are parallel to the ground. Pause for a moment, then push yourself back up to the starting position by straightening your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3288-rWoBmi5.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3288-rWoBmi5.gif', 'rWoBmi5', '© Gym visual — https://gymvisual.com/'),
('3418', 'l-pull-up', 'Sujeta la barra de dominadas con un agarre prono, un poco más ancho que la altura de los hombros. Cuélgate con los brazos completamente extendidos y el cuerpo recto. Activa los dorsales y los bíceps para llevar el cuerpo hacia arriba en dirección a la barra, manteniendo los codos cerca del cuerpo. C', 'back', 'body weight', 'back', 'back', 'lats', '{"biceps","forearms"}', 'Sujeta la barra de dominadas con un agarre prono, un poco más ancho que la altura de los hombros. Cuélgate con los brazos completamente extendidos y el cuerpo recto. Activa los dorsales y los bíceps para llevar el cuerpo hacia arriba en dirección a la barra, manteniendo los codos cerca del cuerpo. Continúa subiendo hasta que la barbilla quede por encima de la barra. Haz una pausa por un momento en la parte superior, luego baja lentamente el cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Grab the pull-up bar with an overhand grip, slightly wider than shoulder-width apart. Hang with your arms fully extended and your body straight. Engage your lats and biceps to pull your body up towards the bar, keeping your elbows close to your body. Continue pulling until your chin is above the bar. Pause for a moment at the top, then slowly lower your body back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3418-d1GgzTU.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3418-d1GgzTU.gif', 'd1GgzTU', '© Gym visual — https://gymvisual.com/'),
('3419', 'l-sit on floor', 'Siéntate en el suelo con las piernas extendidas frente a ti. Coloca las manos en el suelo junto a las caderas, con los dedos apuntando hacia adelante. Activa el core y levanta las piernas del suelo, manteniéndolas rectas. Intenta llevar las piernas paralelas al suelo, formando una ''L'' con el cuerpo.', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"hip flexors"}', 'Siéntate en el suelo con las piernas extendidas frente a ti. Coloca las manos en el suelo junto a las caderas, con los dedos apuntando hacia adelante. Activa el core y levanta las piernas del suelo, manteniéndolas rectas. Intenta llevar las piernas paralelas al suelo, formando una ''L'' con el cuerpo. Mantén esta posición durante el mayor tiempo posible. Baja lentamente las piernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on the floor with your legs extended in front of you. Place your hands on the floor beside your hips, fingers pointing forward. Engage your core and lift your legs off the ground, keeping them straight. Try to bring your legs parallel to the floor, forming an ''L'' shape with your body. Hold this position for as long as you can. Slowly lower your legs back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3419-UpWmA5E.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3419-UpWmA5E.gif', 'UpWmA5E', '© Gym visual — https://gymvisual.com/'),
('0562', 'landmine 180', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta la barra con ambas manos frente al pecho. Flexiona ligeramente las rodillas y rota el torso hacia la derecha, llevando la barra hacia la cadera derecha. Cuando llegues a la parte baja del movimiento, invierte rápidamente el movi', 'waist', 'barbell', 'waist', 'waist', 'abs', '{"obliques","quadriceps"}', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta la barra con ambas manos frente al pecho. Flexiona ligeramente las rodillas y rota el torso hacia la derecha, llevando la barra hacia la cadera derecha. Cuando llegues a la parte baja del movimiento, invierte rápidamente el movimiento y rota el torso hacia la izquierda, llevando la barra hacia arriba y a través del cuerpo en dirección al hombro izquierdo. Continúa este movimiento de giro, alternando lados, durante el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and hold the barbell with both hands in front of your chest. Bend your knees slightly and rotate your torso to the right, swinging the barbell down towards your right hip. As you reach the bottom of the movement, quickly reverse the motion and rotate your torso to the left, swinging the barbell up and across your body towards your left shoulder. Continue this twisting motion, alternating sides, for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0562-QYysSLV.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0562-QYysSLV.gif', 'QYysSLV', '© Gym visual — https://gymvisual.com/'),
('3237', 'landmine lateral raise', 'Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Sujeta la barra con un agarre prono, apoyándola en la parte delantera de los hombros. Manteniendo el core activado y la espalda recta, levanta la barra alejándola del cuerpo, elevándola hasta la al', 'shoulders', 'barbell', 'shoulders', 'shoulders', 'delts', '{"traps","upper back"}', 'Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Sujeta la barra con un agarre prono, apoyándola en la parte delantera de los hombros. Manteniendo el core activado y la espalda recta, levanta la barra alejándola del cuerpo, elevándola hasta la altura del hombro. Haz una pausa breve en la parte alta y luego baja lentamente la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and knees slightly bent. Hold the barbell with an overhand grip, resting it on the front of your shoulders. Keeping your core engaged and back straight, lift the barbell up and away from your body, raising it to shoulder height. Pause for a moment at the top, then slowly lower the barbell back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3237-eXMFHww.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3237-eXMFHww.gif', 'eXMFHww', '© Gym visual — https://gymvisual.com/'),
('3300', 'lean planche', 'Comienza en una posición de flexión con las manos separadas a la altura de los hombros y el cuerpo recto. Activa el core y traslada lentamente el peso hacia adelante, llevando los hombros más allá de las manos. Mantén los codos ligeramente flexionados y el cuerpo recto mientras te inclinas hacia ade', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"shoulders","chest","triceps"}', 'Comienza en una posición de flexión con las manos separadas a la altura de los hombros y el cuerpo recto. Activa el core y traslada lentamente el peso hacia adelante, llevando los hombros más allá de las manos. Mantén los codos ligeramente flexionados y el cuerpo recto mientras te inclinas hacia adelante. Mantén esta posición durante unos segundos, luego vuelve lentamente a la posición inicial. Repite el número de repeticiones deseado.', 'Start in a push-up position with your hands shoulder-width apart and your body straight. Engage your core and slowly shift your weight forward, bringing your shoulders past your hands. Keep your elbows slightly bent and your body straight as you lean forward. Hold this position for a few seconds, then slowly return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3300-LYJodFS.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3300-LYJodFS.gif', 'LYJodFS', '© Gym visual — https://gymvisual.com/'),
('2271', 'left hook. boxing', 'Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Mantén la mano izquierda arriba para proteger el rostro y la mano derecha junto a la barbilla. Rota las caderas y pívota sobre el pie izquierdo mientras extiendes el brazo izquierdo hacia adelante ', 'shoulders', 'body weight', 'shoulders', 'shoulders', 'delts', '{"biceps","triceps","forearms"}', 'Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Mantén la mano izquierda arriba para proteger el rostro y la mano derecha junto a la barbilla. Rota las caderas y pívota sobre el pie izquierdo mientras extiendes el brazo izquierdo hacia adelante con un movimiento de golpe. Gira el torso y activa los músculos del core para generar potencia en el golpe. Lleva el brazo rápidamente de vuelta a la posición inicial y repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and your knees slightly bent. Keep your left hand up to protect your face and your right hand by your chin. Rotate your hips and pivot on your left foot as you extend your left arm forward in a punching motion. Twist your torso and engage your core muscles to generate power in the punch. Snap your arm back to the starting position and repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2271-hoXt6wv.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2271-hoXt6wv.gif', 'hoXt6wv', '© Gym visual — https://gymvisual.com/'),
('0570', 'leg pull in flat bench', 'Siéntate en un banco plano con las piernas extendidas rectas hacia adelante. Coloca las manos en el banco junto a las caderas para mayor apoyo. Activa el abdomen y levanta las piernas del suelo, llevando las rodillas hacia el pecho. Haz una pausa por un momento en la parte superior, luego baja lenta', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"hip flexors","lower back"}', 'Siéntate en un banco plano con las piernas extendidas rectas hacia adelante. Coloca las manos en el banco junto a las caderas para mayor apoyo. Activa el abdomen y levanta las piernas del suelo, llevando las rodillas hacia el pecho. Haz una pausa por un momento en la parte superior, luego baja lentamente las piernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a flat bench with your legs extended straight out in front of you. Place your hands on the bench beside your hips for support. Engage your abs and lift your legs off the ground, bringing your knees towards your chest. Pause for a moment at the top, then slowly lower your legs back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0570-OyoZ3Pu.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0570-OyoZ3Pu.gif', 'OyoZ3Pu', '© Gym visual — https://gymvisual.com/'),
('1576', 'leg up hamstring stretch', 'Túmbate boca arriba con las piernas extendidas. Flexiona una rodilla y llévala hacia el pecho, sujetándote del muslo o la espinilla. Endereza la pierna tanto como sea posible mientras la mantienes elevada. Mantén el estiramiento durante 20-30 segundos. Repite con la otra pierna.', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'hamstrings', '{"glutes"}', 'Túmbate boca arriba con las piernas extendidas. Flexiona una rodilla y llévala hacia el pecho, sujetándote del muslo o la espinilla. Endereza la pierna tanto como sea posible mientras la mantienes elevada. Mantén el estiramiento durante 20-30 segundos. Repite con la otra pierna.', 'Lie flat on your back with your legs extended. Bend one knee and bring it towards your chest, holding onto your thigh or shin. Straighten your leg as much as possible while keeping it elevated. Hold the stretch for 20-30 seconds. Repeat with the other leg.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1576-sU5BrfP.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1576-sU5BrfP.gif', 'sU5BrfP', '© Gym visual — https://gymvisual.com/'),
('2287', 'lever alternate leg press', 'Ajusta el asiento y la plataforma para los pies de la máquina de palanca a la posición deseada. Siéntate en la máquina con la espalda apoyada en el respaldo y los pies sobre la plataforma para los pies. Coloca las manos en las asas o en los lados de la máquina para mayor estabilidad. Empuja un pie c', 'upper legs', 'leverage machine', 'upper legs', 'upper legs', 'quads', '{"hamstrings","glutes"}', 'Ajusta el asiento y la plataforma para los pies de la máquina de palanca a la posición deseada. Siéntate en la máquina con la espalda apoyada en el respaldo y los pies sobre la plataforma para los pies. Coloca las manos en las asas o en los lados de la máquina para mayor estabilidad. Empuja un pie contra la plataforma para los pies, extendiendo la pierna hasta que esté casi completamente recta. Haz una pausa breve, luego flexiona lentamente la pierna y vuelve a la posición inicial. Repite con la otra pierna. Continúa alternando las piernas durante el número de repeticiones deseado.', 'Adjust the seat and foot platform of the leverage machine to your desired position. Sit on the machine with your back against the backrest and your feet on the foot platform. Place your hands on the handles or sides of the machine for stability. Push one foot against the foot platform, extending your leg until it is almost fully straight. Pause for a moment, then slowly bend your leg and return to the starting position. Repeat with the other leg. Continue alternating legs for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2287-V07qpXy.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2287-V07qpXy.gif', 'V07qpXy', '© Gym visual — https://gymvisual.com/'),
('0571', 'lever alternating narrow grip seated row', 'Ajusta la altura del asiento y la posición de la placa para los pies para asegurar una alineación correcta. Siéntate en la máquina con la espalda recta y los pies planos sobre la placa para los pies. Sujeta las asas con un agarre estrecho, con las palmas una frente a la otra. Mantén el pecho elevado', 'back', 'leverage machine', 'back', 'back', 'upper back', '{"biceps","forearms"}', 'Ajusta la altura del asiento y la posición de la placa para los pies para asegurar una alineación correcta. Siéntate en la máquina con la espalda recta y los pies planos sobre la placa para los pies. Sujeta las asas con un agarre estrecho, con las palmas una frente a la otra. Mantén el pecho elevado y los hombros hacia atrás durante todo el ejercicio. Tira de una asa hacia el torso mientras mantienes la otra asa inmóvil. Aprieta los omóplatos al final del movimiento. Devuelve lentamente el asa a la posición inicial y repite con el otro lado. Continúa alternando lados durante el número de repeticiones deseado.', 'Adjust the seat height and footplate position to ensure proper alignment. Sit on the machine with your back straight and feet flat on the footplate. Grasp the handles with a narrow grip, palms facing each other. Keep your chest up and shoulders back throughout the exercise. Pull one handle towards your torso while keeping the other handle stationary. Squeeze your shoulder blades together at the end of the movement. Slowly return the handle to the starting position and repeat with the other side. Continue alternating sides for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0571-w2oRpuH.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0571-w2oRpuH.gif', 'w2oRpuH', '© Gym visual — https://gymvisual.com/'),
('0572', 'lever assisted chin-up', 'Ajusta la máquina de palanca al nivel de resistencia deseado. Sube a la plataforma para los pies y agarra las agarraderas con un agarre prono, un poco más separadas que el ancho de los hombros. Cuélgate con los brazos completamente extendidos, manteniendo el cuerpo recto. Activa los músculos de la e', 'back', 'leverage machine', 'back', 'back', 'lats', '{"biceps","forearms"}', 'Ajusta la máquina de palanca al nivel de resistencia deseado. Sube a la plataforma para los pies y agarra las agarraderas con un agarre prono, un poco más separadas que el ancho de los hombros. Cuélgate con los brazos completamente extendidos, manteniendo el cuerpo recto. Activa los músculos de la espalda y tira del cuerpo hacia arriba en dirección a las asas, liderando con el pecho. Continúa subiendo hasta que la barbilla quede por encima de las agarraderas. Haz una pausa por un momento en la parte superior, luego baja lentamente el cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the leverage machine to your desired resistance level. Stand on the foot platform and grip the handles with an overhand grip, slightly wider than shoulder-width apart. Hang with your arms fully extended, keeping your body straight. Engage your back muscles and pull your body up towards the handles, leading with your chest. Continue pulling until your chin is above the handles. Pause for a moment at the top, then slowly lower your body back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0572-MaMuGH6.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0572-MaMuGH6.gif', 'MaMuGH6', '© Gym visual — https://gymvisual.com/'),
('0573', 'lever back extension', 'Ajusta la máquina según el tamaño de tu cuerpo y tu rango de movimiento. Siéntate en la máquina con la espalda apoyada en la almohadilla y los pies asegurados. Coloca las manos en las asas o en las barras de agarre. Activa el core e inclínate lentamente hacia adelante, permitiendo que la espalda se ', 'back', 'leverage machine', 'back', 'back', 'spine', '{"glutes","hamstrings"}', 'Ajusta la máquina según el tamaño de tu cuerpo y tu rango de movimiento. Siéntate en la máquina con la espalda apoyada en la almohadilla y los pies asegurados. Coloca las manos en las asas o en las barras de agarre. Activa el core e inclínate lentamente hacia adelante, permitiendo que la espalda se redondee ligeramente. Haz una pausa breve en la posición baja, sintiendo un estiramiento en la zona lumbar. Usando los músculos de la espalda, levanta lentamente el torso de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the machine to fit your body size and range of motion. Sit on the machine with your back against the pad and your feet secured. Place your hands on the handles or grip bars. Engage your core and slowly lean forward, allowing your back to round slightly. Pause for a moment at the bottom position, feeling a stretch in your lower back. Using your back muscles, slowly raise your torso back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0573-rUXfn3R.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0573-rUXfn3R.gif', 'rUXfn3R', '© Gym visual — https://gymvisual.com/'),
('0574', 'lever bent over row', 'Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Sujeta la barra con un agarre pronado, manos un poco más separadas que el ancho de los hombros. Inclínate hacia delante desde las caderas, manteniendo la espalda recta y el pecho elevado. Tira de l', 'back', 'barbell', 'back', 'back', 'upper back', '{"biceps","forearms"}', 'Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Sujeta la barra con un agarre pronado, manos un poco más separadas que el ancho de los hombros. Inclínate hacia delante desde las caderas, manteniendo la espalda recta y el pecho elevado. Tira de la barra hacia la parte inferior del pecho, juntando los omóplatos. Haz una pausa breve en la parte alta y luego baja lentamente la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and knees slightly bent. Hold the barbell with an overhand grip, hands slightly wider than shoulder-width apart. Bend forward at the hips, keeping your back straight and chest up. Pull the barbell towards your lower chest, squeezing your shoulder blades together. Pause for a moment at the top, then slowly lower the barbell back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0574-X3cqyXz.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0574-X3cqyXz.gif', 'X3cqyXz', '© Gym visual — https://gymvisual.com/'),
('3200', 'lever bent-over row with v-bar', 'Ajusta la altura del asiento y colócate frente a la máquina. Sujeta la barra en V con un agarre prono, manteniendo la espalda recta y las rodillas ligeramente flexionadas. Tira de la barra en V hacia el abdomen, juntando los omóplatos. Haz una pausa breve en la parte alta del movimiento, luego suelt', 'back', 'leverage machine', 'back', 'back', 'upper back', '{"biceps","forearms"}', 'Ajusta la altura del asiento y colócate frente a la máquina. Sujeta la barra en V con un agarre prono, manteniendo la espalda recta y las rodillas ligeramente flexionadas. Tira de la barra en V hacia el abdomen, juntando los omóplatos. Haz una pausa breve en la parte alta del movimiento, luego suelta lentamente el peso de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the seat height and position yourself facing the machine. Grasp the v-bar with an overhand grip, keeping your back straight and your knees slightly bent. Pull the v-bar towards your abdomen, squeezing your shoulder blades together. Pause for a moment at the top of the movement, then slowly release the weight back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3200-LuBEORI.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3200-LuBEORI.gif', 'LuBEORI', '© Gym visual — https://gymvisual.com/'),
('0575', 'lever bicep curl', 'Ajusta la altura del asiento y colócate en la máquina con la espalda apoyada en la almohadilla. Sujeta las asas con un agarre supino, con las palmas hacia arriba, y mantén los codos cerca de los costados. Exhala y flexiona las asas hacia arriba, contrayendo los bíceps. Haz una pausa breve en la part', 'upper arms', 'leverage machine', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ajusta la altura del asiento y colócate en la máquina con la espalda apoyada en la almohadilla. Sujeta las asas con un agarre supino, con las palmas hacia arriba, y mantén los codos cerca de los costados. Exhala y flexiona las asas hacia arriba, contrayendo los bíceps. Haz una pausa breve en la parte más alta del movimiento, contrayendo los bíceps. Inhala y baja lentamente los mangos de vuelta a la posición inicial, extendiendo completamente los brazos. Repite el número de repeticiones deseado.', 'Adjust the seat height and position yourself on the machine with your back against the pad. Grasp the handles with an underhand grip, palms facing up, and keep your elbows close to your sides. Exhale and curl the handles upward, contracting your biceps. Pause for a moment at the top of the movement, squeezing your biceps. Inhale and slowly lower the handles back to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0575-q6y3OhV.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0575-q6y3OhV.gif', 'q6y3OhV', '© Gym visual — https://gymvisual.com/'),
('2289', 'lever calf press', 'Ajusta el asiento de la máquina de palanca de modo que los hombros queden alineados con la almohadilla de la palanca. Coloca los dedos de los pies sobre la almohadilla de la palanca, con los talones colgando fuera del borde. Sujeta las asas o los soportes laterales para mayor estabilidad. Empuja la ', 'lower legs', 'leverage machine', 'lower legs', 'lower legs', 'calves', '{"hamstrings"}', 'Ajusta el asiento de la máquina de palanca de modo que los hombros queden alineados con la almohadilla de la palanca. Coloca los dedos de los pies sobre la almohadilla de la palanca, con los talones colgando fuera del borde. Sujeta las asas o los soportes laterales para mayor estabilidad. Empuja la almohadilla de la palanca hacia abajo extendiendo los tobillos, contrayendo los músculos de las pantorrillas. Haz una pausa por un momento en la parte baja del movimiento. Vuelve lentamente a la posición inicial dejando que los talones se eleven de nuevo. Repite el número de repeticiones deseado.', 'Adjust the seat of the leverage machine so that your shoulders are aligned with the lever pad. Place your toes on the lever pad, with your heels hanging off the edge. Grasp the handles or side supports for stability. Push the lever pad down by extending your ankles, contracting your calf muscles. Pause for a moment at the bottom of the movement. Slowly return to the starting position by allowing your heels to rise back up. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2289-7B4F5nZ.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2289-7B4F5nZ.gif', '7B4F5nZ', '© Gym visual — https://gymvisual.com/'),
('0577', 'lever chest press', 'Ajusta la altura del asiento y colócate en la máquina con la espalda totalmente apoyada en la almohadilla. Sujeta las asas con un agarre prono y coloca los codos en un ángulo de 90 grados. Empuja las asas hacia adelante hasta que los brazos queden completamente extendidos, exhalando durante el movim', 'chest', 'leverage machine', 'chest', 'chest', 'pectorals', '{"triceps","shoulders"}', 'Ajusta la altura del asiento y colócate en la máquina con la espalda totalmente apoyada en la almohadilla. Sujeta las asas con un agarre prono y coloca los codos en un ángulo de 90 grados. Empuja las asas hacia adelante hasta que los brazos queden completamente extendidos, exhalando durante el movimiento. Haz una pausa breve al final del movimiento, luego vuelve lentamente a la posición inicial, inhalando mientras lo haces. Repite el número de repeticiones deseado.', 'Adjust the seat height and position yourself on the machine with your back flat against the pad. Grasp the handles with an overhand grip and position your elbows at a 90-degree angle. Push the handles forward until your arms are fully extended, exhaling during the movement. Pause briefly at the end of the movement, then slowly return to the starting position, inhaling as you do so. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0577-T0yTjgW.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0577-T0yTjgW.gif', 'T0yTjgW', '© Gym visual — https://gymvisual.com/'),
('0576', 'lever chest press', 'Ajusta la altura del asiento y colócate en la máquina con la espalda totalmente apoyada en la almohadilla. Sujeta las asas con un agarre prono y coloca los codos en un ángulo de 90 grados. Empuja las asas hacia adelante hasta que los brazos queden completamente extendidos, exhalando durante el movim', 'chest', 'leverage machine', 'chest', 'chest', 'pectorals', '{"triceps","shoulders"}', 'Ajusta la altura del asiento y colócate en la máquina con la espalda totalmente apoyada en la almohadilla. Sujeta las asas con un agarre prono y coloca los codos en un ángulo de 90 grados. Empuja las asas hacia adelante hasta que los brazos queden completamente extendidos, exhalando durante el movimiento. Haz una pausa breve al final del movimiento, luego vuelve lentamente a la posición inicial, inhalando mientras lo haces. Repite el número de repeticiones deseado.', 'Adjust the seat height and position yourself on the machine with your back flat against the pad. Grasp the handles with an overhand grip and position your elbows at a 90-degree angle. Push the handles forward until your arms are fully extended, exhaling during the movement. Pause briefly at the end of the movement, then slowly return to the starting position, inhaling as you do so. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0576-DOoWcnA.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0576-DOoWcnA.gif', 'DOoWcnA', '© Gym visual — https://gymvisual.com/'),
('0578', 'lever deadlift', 'Ajusta la altura del asiento y la plataforma para los pies a la posición deseada. Siéntate en la máquina con la espalda apoyada en la almohadilla y los pies planos sobre la plataforma para los pies. Sujeta las asas o los lados del asiento para mayor estabilidad. Activa los glúteos y los isquiotibial', 'upper legs', 'leverage machine', 'upper legs', 'upper legs', 'glutes', '{"hamstrings","quadriceps"}', 'Ajusta la altura del asiento y la plataforma para los pies a la posición deseada. Siéntate en la máquina con la espalda apoyada en la almohadilla y los pies planos sobre la plataforma para los pies. Sujeta las asas o los lados del asiento para mayor estabilidad. Activa los glúteos y los isquiotibiales, y empuja con los talones para levantar el peso. Mantén la espalda recta y evita redondear los hombros. Extiende por completo las caderas en la parte alta del movimiento, apretando los glúteos. Baja el peso de manera controlada, manteniendo la tensión en los glúteos y los isquiotibiales. Repite el número de repeticiones deseado.', 'Adjust the seat height and foot platform to your desired position. Sit on the machine with your back against the pad and your feet flat on the foot platform. Grasp the handles or the sides of the seat for stability. Engage your glutes and hamstrings, and push through your heels to lift the weight up. Keep your back straight and avoid rounding your shoulders. Extend your hips fully at the top of the movement, squeezing your glutes. Lower the weight back down in a controlled manner, keeping tension on your glutes and hamstrings. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0578-GUT8I22.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0578-GUT8I22.gif', 'GUT8I22', '© Gym visual — https://gymvisual.com/'),
('1300', 'lever decline chest press', 'Ajusta la altura del asiento y el respaldo de la máquina de palanca a una posición cómoda. Siéntate en la máquina con la espalda apoyada en el respaldo y los pies planos en el suelo. Sujeta las asas con un agarre prono y coloca las manos un poco más separadas que la altura de los hombros. Empuja las', 'chest', 'leverage machine', 'chest', 'chest', 'pectorals', '{"triceps","shoulders"}', 'Ajusta la altura del asiento y el respaldo de la máquina de palanca a una posición cómoda. Siéntate en la máquina con la espalda apoyada en el respaldo y los pies planos en el suelo. Sujeta las asas con un agarre prono y coloca las manos un poco más separadas que la altura de los hombros. Empuja las asas hacia adelante y alejándolas del cuerpo hasta que los brazos queden completamente extendidos. Baja lentamente las asas de vuelta hacia el pecho, manteniendo los codos ligeramente flexionados. Haz una pausa breve en la parte baja, luego empuja las asas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the seat height and backrest of the leverage machine to a comfortable position. Sit on the machine with your back against the backrest and your feet flat on the floor. Grasp the handles with an overhand grip and position your hands slightly wider than shoulder-width apart. Push the handles forward and away from your body until your arms are fully extended. Slowly lower the handles back towards your chest, keeping your elbows slightly bent. Pause for a moment at the bottom, then push the handles back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1300-vsVoPHt.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1300-vsVoPHt.gif', 'vsVoPHt', '© Gym visual — https://gymvisual.com/'),
('1253', 'lever donkey calf raise', 'Ajusta la máquina de palanca a la altura adecuada para tu cuerpo. Colócate de frente a la máquina, con los dedos de los pies en la plataforma y los talones colgando fuera del borde. Coloca las manos en las asas o en las barras de soporte para mayor estabilidad. Activa las pantorrillas y levanta los ', 'lower legs', 'leverage machine', 'lower legs', 'lower legs', 'calves', '{"hamstrings","glutes"}', 'Ajusta la máquina de palanca a la altura adecuada para tu cuerpo. Colócate de frente a la máquina, con los dedos de los pies en la plataforma y los talones colgando fuera del borde. Coloca las manos en las asas o en las barras de soporte para mayor estabilidad. Activa las pantorrillas y levanta los talones tan alto como sea posible, usando la parte delantera de los pies. Haz una pausa breve en la parte alta y luego baja lentamente los talones de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the leverage machine to the appropriate height for your body. Position yourself facing the machine, with your toes on the foot platform and your heels hanging off the edge. Place your hands on the handles or the support bars for stability. Engage your calves and lift your heels as high as possible, using the balls of your feet. Pause for a moment at the top, then slowly lower your heels back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1253-C9LuR4A.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1253-C9LuR4A.gif', 'C9LuR4A', '© Gym visual — https://gymvisual.com/'),
('0579', 'lever front pulldown', 'Ajusta la altura del asiento y colócate en la máquina con las rodillas debajo de las almohadillas y los pies planos en el suelo. Agarra las agarraderas con un agarre prono, un poco más separadas que el ancho de los hombros. Siéntate erguido con el pecho elevado y los hombros hacia atrás, manteniendo', 'back', 'leverage machine', 'back', 'back', 'lats', '{"biceps","rhomboids","rear deltoids"}', 'Ajusta la altura del asiento y colócate en la máquina con las rodillas debajo de las almohadillas y los pies planos en el suelo. Agarra las agarraderas con un agarre prono, un poco más separadas que el ancho de los hombros. Siéntate erguido con el pecho elevado y los hombros hacia atrás, manteniendo un ligero arco en la zona lumbar. Activa los dorsales y tira de las asas hacia el pecho, juntando los omóplatos. Haz una pausa breve en la parte baja del movimiento, luego suelta lentamente las asas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the seat height and position yourself on the machine with your knees under the pads and your feet flat on the ground. Grasp the handles with an overhand grip, slightly wider than shoulder-width apart. Sit upright with your chest lifted and your shoulders back, maintaining a slight arch in your lower back. Engage your lats and pull the handles down towards your chest, squeezing your shoulder blades together. Pause for a moment at the bottom of the movement, then slowly release the handles back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0579-7F1DVzn.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0579-7F1DVzn.gif', '7F1DVzn', '© Gym visual — https://gymvisual.com/'),
('0580', 'lever gripless shrug', 'Ajusta la altura del asiento y colócate en la máquina de palanca. Sujeta las asas con las palmas hacia adentro y los brazos completamente extendidos. Manteniendo la espalda recta, exhala y eleva los hombros tan alto como sea posible. Mantén la contracción por un momento breve, luego inhala y baja le', 'back', 'leverage machine', 'back', 'back', 'traps', '{"shoulders","forearms"}', 'Ajusta la altura del asiento y colócate en la máquina de palanca. Sujeta las asas con las palmas hacia adentro y los brazos completamente extendidos. Manteniendo la espalda recta, exhala y eleva los hombros tan alto como sea posible. Mantén la contracción por un momento breve, luego inhala y baja lentamente los hombros de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the seat height and position yourself on the leverage machine. Grasp the handles with your palms facing inwards and your arms fully extended. Keeping your back straight, exhale and elevate your shoulders as high as possible. Hold the contraction for a brief moment, then inhale and slowly lower your shoulders back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0580-f91FwXG.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0580-f91FwXG.gif', 'f91FwXG', '© Gym visual — https://gymvisual.com/'),
('1439', 'lever gripless shrug v. 2', 'Ajusta la altura del asiento y colócate en la máquina con la espalda apoyada en la almohadilla. Sujeta las asas o barras con un agarre prono, manteniendo los brazos rectos. Manteniendo la espalda recta, eleva los hombros hacia las orejas tan alto como sea posible. Mantén la contracción por un moment', 'back', 'leverage machine', 'back', 'back', 'traps', '{"shoulders","forearms"}', 'Ajusta la altura del asiento y colócate en la máquina con la espalda apoyada en la almohadilla. Sujeta las asas o barras con un agarre prono, manteniendo los brazos rectos. Manteniendo la espalda recta, eleva los hombros hacia las orejas tan alto como sea posible. Mantén la contracción por un momento, luego baja lentamente los hombros de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the seat height and position yourself on the machine with your back against the pad. Grasp the handles or bars with an overhand grip, keeping your arms straight. Keeping your back straight, lift your shoulders up towards your ears as high as possible. Hold the contraction for a moment, then slowly lower your shoulders back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1439-cbuFJrn.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1439-cbuFJrn.gif', 'cbuFJrn', '© Gym visual — https://gymvisual.com/'),
('2288', 'lever gripper hands', 'Ajusta la altura del asiento y sujeta las asas de la máquina de palanca. Mantén la espalda recta y los pies planos en el suelo. Exhala y aprieta las asas, contrayendo los antebrazos. Mantén la contracción durante un segundo, luego suelta lentamente y vuelve a la posición inicial. Repite el número de', 'lower arms', 'leverage machine', 'lower arms', 'lower arms', 'forearms', '{"biceps","triceps"}', 'Ajusta la altura del asiento y sujeta las asas de la máquina de palanca. Mantén la espalda recta y los pies planos en el suelo. Exhala y aprieta las asas, contrayendo los antebrazos. Mantén la contracción durante un segundo, luego suelta lentamente y vuelve a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the seat height and grip the handles of the leverage machine. Keep your back straight and your feet flat on the ground. Exhale and squeeze the handles, contracting your forearms. Hold the contraction for a second, then slowly release and return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2288-mKwcrHn.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2288-mKwcrHn.gif', 'mKwcrHn', '© Gym visual — https://gymvisual.com/'),
('1615', 'lever hammer grip preacher curl', 'Ajusta la altura del asiento y colócate en la máquina de palanca. Coloca los brazos superiores sobre la almohadilla de predicador, asegurándote de que el pecho quede apoyado contra ella. Sujeta las asas con agarre neutro (palmas una frente a la otra). Manteniendo los brazos superiores inmóviles, exh', 'upper arms', 'leverage machine', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ajusta la altura del asiento y colócate en la máquina de palanca. Coloca los brazos superiores sobre la almohadilla de predicador, asegurándote de que el pecho quede apoyado contra ella. Sujeta las asas con agarre neutro (palmas una frente a la otra). Manteniendo los brazos superiores inmóviles, exhala y flexiona las asas hacia los hombros. Haz una pausa breve en la parte alta, apretando los bíceps. Inhala y baja lentamente las asas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the seat height and position yourself on the leverage machine. Place your upper arms on the preacher pad, ensuring your chest is pressed against it. Grasp the handles with a hammer grip (palms facing each other). Keeping your upper arms stationary, exhale and curl the handles towards your shoulders. Pause for a moment at the top, squeezing your biceps. Inhale and slowly lower the handles back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1615-OAguZoG.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1615-OAguZoG.gif', 'OAguZoG', '© Gym visual — https://gymvisual.com/'),
('0581', 'lever high row', 'Ajusta la altura del asiento y la plataforma para los pies a una posición cómoda. Siéntate en la máquina con el pecho contra la almohadilla y los pies planos sobre la plataforma para los pies. Agarra las agarraderas con un agarre prono, un poco más separadas que el ancho de los hombros. Mantén la es', 'back', 'leverage machine', 'back', 'back', 'upper back', '{"biceps","rear deltoids"}', 'Ajusta la altura del asiento y la plataforma para los pies a una posición cómoda. Siéntate en la máquina con el pecho contra la almohadilla y los pies planos sobre la plataforma para los pies. Agarra las agarraderas con un agarre prono, un poco más separadas que el ancho de los hombros. Mantén la espalda recta y activa el core. Jala las agarraderas hacia el cuerpo, apretando los omóplatos entre sí. Haz una pausa por un momento en el punto máximo del movimiento, luego suelta lentamente las agarraderas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the seat height and foot platform to a comfortable position. Sit on the machine with your chest against the pad and your feet flat on the foot platform. Grasp the handles with an overhand grip, slightly wider than shoulder-width apart. Keep your back straight and engage your core. Pull the handles towards your body, squeezing your shoulder blades together. Pause for a moment at the peak of the movement, then slowly release the handles back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0581-nZZZy9m.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0581-nZZZy9m.gif', 'nZZZy9m', '© Gym visual — https://gymvisual.com/'),
('2286', 'lever hip extension v. 2', 'Ajusta la máquina a tu cuerpo y siéntate en ella con la espalda apoyada en el respaldo. Coloca los pies en los apoyapiés y sujeta las asas para mayor estabilidad. Activa los glúteos y los isquiotibiales, luego empuja contra los apoyapiés para extender las caderas y levantar las piernas hacia atrás. ', 'upper legs', 'leverage machine', 'upper legs', 'upper legs', 'glutes', '{"hamstrings"}', 'Ajusta la máquina a tu cuerpo y siéntate en ella con la espalda apoyada en el respaldo. Coloca los pies en los apoyapiés y sujeta las asas para mayor estabilidad. Activa los glúteos y los isquiotibiales, luego empuja contra los apoyapiés para extender las caderas y levantar las piernas hacia atrás. Haz una pausa por un momento en la parte superior, luego baja lentamente las piernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the machine to fit your body and sit on it with your back against the backrest. Place your feet on the footrests and grip the handles for stability. Engage your glutes and hamstrings, then push against the footrests to extend your hips and raise your legs backward. Pause for a moment at the top, then slowly lower your legs back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2286-OPqShYN.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2286-OPqShYN.gif', 'OPqShYN', '© Gym visual — https://gymvisual.com/'),
('2611', 'lever horizontal one leg press', 'Ajusta el asiento de la máquina de modo que las rodillas queden en un ángulo de 90 grados cuando los pies estén sobre la placa para los pies. Siéntate en la máquina con la espalda apoyada en el respaldo y los pies separados a la altura de los hombros sobre la placa para los pies. Coloca las manos en', 'upper legs', 'leverage machine', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves"}', 'Ajusta el asiento de la máquina de modo que las rodillas queden en un ángulo de 90 grados cuando los pies estén sobre la placa para los pies. Siéntate en la máquina con la espalda apoyada en el respaldo y los pies separados a la altura de los hombros sobre la placa para los pies. Coloca las manos en las asas o en los lados de la máquina para mayor estabilidad. Empuja la placa para los pies alejándola del cuerpo extendiendo la pierna, manteniendo la espalda apoyada en el respaldo. Haz una pausa breve en la posición completamente extendida, luego flexiona lentamente la pierna para volver a la posición inicial. Repite el número de repeticiones deseado, luego cambia de pierna.', 'Adjust the seat of the machine so that your knees are at a 90-degree angle when your feet are on the footplate. Sit on the machine with your back against the backrest and your feet shoulder-width apart on the footplate. Place your hands on the handles or sides of the machine for stability. Push the footplate away from your body by extending your leg, keeping your back against the backrest. Pause for a moment at the fully extended position, then slowly bend your leg to return to the starting position. Repeat for the desired number of repetitions, then switch legs.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2611-9KU9TYF.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2611-9KU9TYF.gif', '9KU9TYF', '© Gym visual — https://gymvisual.com/'),
('1299', 'lever incline chest press', 'Ajusta el asiento y el respaldo de la máquina de palanca a una posición cómoda. Siéntate en la máquina con la espalda apoyada en el respaldo y los pies planos en el suelo. Sujeta las asas con un agarre prono y coloca las manos un poco más separadas que la altura de los hombros. Empuja las asas hacia', 'chest', 'leverage machine', 'chest', 'chest', 'pectorals', '{"shoulders","triceps"}', 'Ajusta el asiento y el respaldo de la máquina de palanca a una posición cómoda. Siéntate en la máquina con la espalda apoyada en el respaldo y los pies planos en el suelo. Sujeta las asas con un agarre prono y coloca las manos un poco más separadas que la altura de los hombros. Empuja las asas hacia adelante y alejándolas del cuerpo hasta que los brazos queden completamente extendidos. Haz una pausa breve, luego flexiona lentamente los codos y baja las asas de vuelta hacia el pecho. Repite el número de repeticiones deseado.', 'Adjust the seat and backrest of the leverage machine to a comfortable position. Sit on the machine with your back against the backrest and your feet flat on the floor. Grasp the handles with an overhand grip and position your hands slightly wider than shoulder-width apart. Push the handles forward and away from your body until your arms are fully extended. Pause for a moment, then slowly bend your elbows and lower the handles back towards your chest. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1299-jHAnWmT.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1299-jHAnWmT.gif', 'jHAnWmT', '© Gym visual — https://gymvisual.com/'),
('1479', 'lever incline chest press v. 2', 'Ajusta la altura del asiento y el ángulo del respaldo de la máquina de palanca a una posición cómoda. Siéntate en la máquina con la espalda apoyada en el respaldo y los pies planos en el suelo. Sujeta las asas con un agarre prono y coloca las manos un poco más separadas que la altura de los hombros.', 'chest', 'leverage machine', 'chest', 'chest', 'pectorals', '{"triceps","shoulders"}', 'Ajusta la altura del asiento y el ángulo del respaldo de la máquina de palanca a una posición cómoda. Siéntate en la máquina con la espalda apoyada en el respaldo y los pies planos en el suelo. Sujeta las asas con un agarre prono y coloca las manos un poco más separadas que la altura de los hombros. Empuja las asas hacia adelante y alejándolas del cuerpo hasta que los brazos queden completamente extendidos, pero sin bloquear los codos. Haz una pausa breve en la posición completamente extendida, luego flexiona lentamente los codos y baja las asas de vuelta hacia el pecho. Repite el número de repeticiones deseado.', 'Adjust the seat height and backrest angle on the leverage machine to a comfortable position. Sit on the machine with your back against the backrest and your feet flat on the floor. Grasp the handles with an overhand grip and position your hands slightly wider than shoulder-width apart. Push the handles forward and away from your body until your arms are fully extended, but without locking your elbows. Pause for a moment at the fully extended position, then slowly bend your elbows and lower the handles back towards your chest. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1479-o17Jfkt.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1479-o17Jfkt.gif', 'o17Jfkt', '© Gym visual — https://gymvisual.com/'),
('0582', 'lever kneeling leg curl', 'Ajusta la máquina a tu cuerpo y selecciona el peso deseado. Arrodíllate en la máquina mirando hacia abajo, con las rodillas apoyadas en la almohadilla y los pies asegurados bajo las almohadillas para los pies. Sujeta las asas o los lados de la máquina para mayor estabilidad. Manteniendo quieta la pa', 'upper legs', 'leverage machine', 'upper legs', 'upper legs', 'hamstrings', '{"glutes"}', 'Ajusta la máquina a tu cuerpo y selecciona el peso deseado. Arrodíllate en la máquina mirando hacia abajo, con las rodillas apoyadas en la almohadilla y los pies asegurados bajo las almohadillas para los pies. Sujeta las asas o los lados de la máquina para mayor estabilidad. Manteniendo quieta la parte superior del cuerpo, exhala y flexiona las piernas hacia los glúteos doblando las rodillas. Haz una pausa breve en la parte más alta del movimiento, contrayendo los isquiotibiales. Inhala y baja lentamente las piernas de vuelta a la posición inicial, extendiendo por completo las rodillas. Repite el número de repeticiones deseado.', 'Adjust the machine to fit your body and select the desired weight. Kneel on the machine facing downwards, with your knees resting on the pad and your feet secured under the footpads. Grasp the handles or the sides of the machine for stability. Keeping your upper body stationary, exhale and curl your legs up towards your glutes by flexing your knees. Pause for a moment at the top of the movement, squeezing your hamstrings. Inhale and slowly lower your legs back to the starting position, fully extending your knees. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0582-nnmCTLN.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0582-nnmCTLN.gif', 'nnmCTLN', '© Gym visual — https://gymvisual.com/'),
('0583', 'lever kneeling twist', 'Ajusta la altura del asiento y colócate en la máquina con las rodillas apoyadas en las almohadillas y la parte superior del cuerpo mirando hacia adelante. Sujeta las asas o los lados de la máquina para mayor estabilidad. Manteniendo el core activado, gira el torso hacia un lado tanto como sea cómoda', 'waist', 'leverage machine', 'waist', 'waist', 'abs', '{"obliques","lower back"}', 'Ajusta la altura del asiento y colócate en la máquina con las rodillas apoyadas en las almohadillas y la parte superior del cuerpo mirando hacia adelante. Sujeta las asas o los lados de la máquina para mayor estabilidad. Manteniendo el core activado, gira el torso hacia un lado tanto como sea cómodamente posible. Haz una pausa por un momento, luego regresa lentamente a la posición inicial. Repite el giro hacia el lado opuesto. Continúa alternando lados durante el número de repeticiones deseado.', 'Adjust the seat height and position yourself on the machine with your knees resting on the pads and your upper body facing forward. Grasp the handles or the sides of the machine for stability. Keeping your core engaged, twist your torso to one side as far as comfortably possible. Pause for a moment, then slowly return to the starting position. Repeat the twist to the opposite side. Continue alternating sides for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0583-sZOR9EV.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0583-sZOR9EV.gif', 'sZOR9EV', '© Gym visual — https://gymvisual.com/'),
('0584', 'lever lateral raise', 'Ajusta la altura del asiento y colócate en la máquina con la espalda apoyada en la almohadilla. Sujeta las asas con un agarre prono y mantén los brazos rectos. Exhala y levanta los brazos hacia los lados hasta que queden paralelos al suelo. Haz una pausa breve en lo alto, luego inhala y baja lentame', 'shoulders', 'leverage machine', 'shoulders', 'shoulders', 'delts', '{"traps","upper back"}', 'Ajusta la altura del asiento y colócate en la máquina con la espalda apoyada en la almohadilla. Sujeta las asas con un agarre prono y mantén los brazos rectos. Exhala y levanta los brazos hacia los lados hasta que queden paralelos al suelo. Haz una pausa breve en lo alto, luego inhala y baja lentamente los brazos de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the seat height and position yourself on the machine with your back against the pad. Grasp the handles with an overhand grip and keep your arms straight. Exhale and raise your arms out to the sides until they are parallel to the floor. Pause for a moment at the top, then inhale and slowly lower your arms back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0584-dRTfGZT.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0584-dRTfGZT.gif', 'dRTfGZT', '© Gym visual — https://gymvisual.com/'),
('0585', 'lever leg extension', 'Ajusta la altura del asiento y el respaldo de la máquina a tu cuerpo. Siéntate en la máquina con la espalda apoyada en el respaldo y los pies sobre la almohadilla para los pies. Sujeta las asas o las barras laterales para mayor estabilidad. Extiende las piernas hacia adelante enderezando las rodilla', 'upper legs', 'leverage machine', 'upper legs', 'upper legs', 'quads', '{"hamstrings"}', 'Ajusta la altura del asiento y el respaldo de la máquina a tu cuerpo. Siéntate en la máquina con la espalda apoyada en el respaldo y los pies sobre la almohadilla para los pies. Sujeta las asas o las barras laterales para mayor estabilidad. Extiende las piernas hacia adelante enderezando las rodillas, levantando el peso. Haz una pausa breve en lo alto, luego baja lentamente el peso de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the seat height and backrest of the machine to fit your body. Sit on the machine with your back against the backrest and your feet on the footpad. Grasp the handles or sidebars for stability. Extend your legs forward by straightening your knees, lifting the weight. Pause for a moment at the top, then slowly lower the weight back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0585-my33uHU.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0585-my33uHU.gif', 'my33uHU', '© Gym visual — https://gymvisual.com/'),
('0586', 'lever lying leg curl', 'Ajusta la máquina a tu cuerpo y selecciona el peso deseado. Túmbate boca abajo en la máquina con las piernas rectas y los talones contra la palanca acolchada. Sujeta las asas o los lados de la máquina para mayor estabilidad. Manteniendo la parte superior del cuerpo inmóvil, exhala y flexiona las pie', 'upper legs', 'leverage machine', 'upper legs', 'upper legs', 'hamstrings', '{"calves"}', 'Ajusta la máquina a tu cuerpo y selecciona el peso deseado. Túmbate boca abajo en la máquina con las piernas rectas y los talones contra la palanca acolchada. Sujeta las asas o los lados de la máquina para mayor estabilidad. Manteniendo la parte superior del cuerpo inmóvil, exhala y flexiona las piernas hacia arriba tanto como sea posible sin levantar las caderas de la almohadilla. Mantén la posición contraída durante una pausa breve mientras aprietas los isquiotibiales. Inhala y baja lentamente la palanca de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the machine to fit your body and select the desired weight. Lie face down on the machine with your legs straight and your heels against the padded lever. Grasp the handles or the sides of the machine for stability. Keeping your upper body stationary, exhale and curl your legs up as far as possible without lifting your hips off the pad. Hold the contracted position for a brief pause as you squeeze your hamstrings. Inhale and slowly lower the lever back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0586-17lJ1kr.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0586-17lJ1kr.gif', '17lJ1kr', '© Gym visual — https://gymvisual.com/'),
('3195', 'lever lying two-one leg curl', 'Ajusta la máquina a tu cuerpo y siéntate en ella con la espalda apoyada en el respaldo. Coloca las piernas sobre la almohadilla de la palanca, justo encima de los tobillos. Sujeta las asas a los lados de la máquina para mayor apoyo. Manteniendo la parte superior del cuerpo inmóvil, exhala y flexiona', 'upper legs', 'leverage machine', 'upper legs', 'upper legs', 'hamstrings', '{"glutes"}', 'Ajusta la máquina a tu cuerpo y siéntate en ella con la espalda apoyada en el respaldo. Coloca las piernas sobre la almohadilla de la palanca, justo encima de los tobillos. Sujeta las asas a los lados de la máquina para mayor apoyo. Manteniendo la parte superior del cuerpo inmóvil, exhala y flexiona las piernas hacia los glúteos. Haz una pausa breve en lo alto, luego inhala y baja lentamente las piernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the machine to fit your body and sit on it with your back against the backrest. Place your legs on the lever pad, just above your ankles. Grasp the handles on the sides of the machine for support. Keeping your upper body still, exhale and curl your legs up towards your glutes. Pause for a moment at the top, then inhale and slowly lower your legs back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3195-UXpKJoq.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3195-UXpKJoq.gif', 'UXpKJoq', '© Gym visual — https://gymvisual.com/'),
('0587', 'lever military press', 'Ajusta la altura del asiento y colócate en la máquina con la espalda apoyada en el respaldo. Sujeta las asas con un agarre prono y coloca las manos un poco más separadas que la altura de los hombros. Empuja las asas hacia arriba hasta que los brazos queden completamente extendidos, pero sin bloquear', 'shoulders', 'leverage machine', 'shoulders', 'shoulders', 'delts', '{"triceps","upper chest"}', 'Ajusta la altura del asiento y colócate en la máquina con la espalda apoyada en el respaldo. Sujeta las asas con un agarre prono y coloca las manos un poco más separadas que la altura de los hombros. Empuja las asas hacia arriba hasta que los brazos queden completamente extendidos, pero sin bloquear los codos. Haz una pausa breve en lo alto, luego baja lentamente las asas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the seat height and position yourself on the machine with your back against the backrest. Grasp the handles with an overhand grip and position your hands slightly wider than shoulder-width apart. Push the handles upward until your arms are fully extended, but do not lock your elbows. Pause for a moment at the top, then slowly lower the handles back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0587-CggQhII.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0587-CggQhII.gif', 'CggQhII', '© Gym visual — https://gymvisual.com/'),
('0588', 'lever narrow grip seated row', 'Ajusta la altura del asiento y los apoyapiés para asegurar una postura correcta. Siéntate en la máquina con los pies planos sobre los apoyapiés y las rodillas ligeramente flexionadas. Sujeta las asas con un agarre estrecho, con las palmas una frente a la otra. Mantén la espalda recta e inclínate lig', 'back', 'leverage machine', 'back', 'back', 'upper back', '{"biceps","forearms"}', 'Ajusta la altura del asiento y los apoyapiés para asegurar una postura correcta. Siéntate en la máquina con los pies planos sobre los apoyapiés y las rodillas ligeramente flexionadas. Sujeta las asas con un agarre estrecho, con las palmas una frente a la otra. Mantén la espalda recta e inclínate ligeramente hacia adelante. Tira de las asas hacia el torso, juntando los omóplatos. Haz una pausa breve en la parte alta del movimiento. Suelta lentamente las asas y vuelve a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the seat height and footrests to ensure proper form. Sit on the machine with your feet flat on the footrests and your knees slightly bent. Grasp the handles with a narrow grip, palms facing each other. Keep your back straight and lean slightly forward. Pull the handles towards your torso, squeezing your shoulder blades together. Pause for a moment at the peak of the movement. Slowly release the handles and return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0588-IGjKj1v.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0588-IGjKj1v.gif', 'IGjKj1v', '© Gym visual — https://gymvisual.com/'),
('0589', 'lever one arm bent over row', 'Ponte de pie con los pies separados a la altura de los hombros, las rodillas ligeramente flexionadas, y sujeta una barra con agarre prono. Inclínate hacia adelante desde las caderas, manteniendo la espalda recta y la cabeza erguida. Deja que la barra cuelgue frente a ti con los brazos completamente ', 'back', 'barbell', 'back', 'back', 'upper back', '{"biceps","forearms"}', 'Ponte de pie con los pies separados a la altura de los hombros, las rodillas ligeramente flexionadas, y sujeta una barra con agarre prono. Inclínate hacia adelante desde las caderas, manteniendo la espalda recta y la cabeza erguida. Deja que la barra cuelgue frente a ti con los brazos completamente extendidos. Tira de la barra hacia el pecho, manteniendo los codos cerca del cuerpo. Junta los omóplatos en la parte superior del movimiento. Baja la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, knees slightly bent, and hold a barbell with an overhand grip. Bend forward at the hips, keeping your back straight and your head up. Let the barbell hang in front of you with your arms fully extended. Pull the barbell up towards your chest, keeping your elbows close to your body. Squeeze your shoulder blades together at the top of the movement. Lower the barbell back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0589-Fhdtwf3.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0589-Fhdtwf3.gif', 'Fhdtwf3', '© Gym visual — https://gymvisual.com/'),
('1356', 'lever one arm lateral high row', 'Ajusta la altura del asiento y colócate frente a la máquina. Sujeta el asa con una mano y mantén la espalda recta. Tira del asa hacia el cuerpo, manteniendo el codo cerca del costado. Aprieta los músculos de la espalda en la parte superior del movimiento. Suelta lentamente la agarradera de vuelta a ', 'back', 'leverage machine', 'back', 'back', 'upper back', '{"biceps","shoulders"}', 'Ajusta la altura del asiento y colócate frente a la máquina. Sujeta el asa con una mano y mantén la espalda recta. Tira del asa hacia el cuerpo, manteniendo el codo cerca del costado. Aprieta los músculos de la espalda en la parte superior del movimiento. Suelta lentamente la agarradera de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the seat height and position yourself facing the machine. Grasp the handle with one hand and keep your back straight. Pull the handle towards your body, keeping your elbow close to your side. Squeeze your back muscles at the top of the movement. Slowly release the handle back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1356-OIFMAp1.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1356-OIFMAp1.gif', 'OIFMAp1', '© Gym visual — https://gymvisual.com/'),
('1347', 'lever one arm lateral wide pulldown', 'Ajusta la altura del asiento y colócate en la máquina con el pecho contra la almohadilla y los pies planos en el suelo. Sujeta el asa con un agarre prono y extiende el brazo por completo, manteniendo una ligera flexión en el codo. Tira del asa hacia abajo y a través del cuerpo en dirección a la cade', 'back', 'leverage machine', 'back', 'back', 'lats', '{"biceps","rhomboids","rear deltoids"}', 'Ajusta la altura del asiento y colócate en la máquina con el pecho contra la almohadilla y los pies planos en el suelo. Sujeta el asa con un agarre prono y extiende el brazo por completo, manteniendo una ligera flexión en el codo. Tira del asa hacia abajo y a través del cuerpo en dirección a la cadera opuesta, apretando el dorsal en la parte baja del movimiento. Devuelve lentamente el asa a la posición inicial, extendiendo el brazo por completo. Repite el número de repeticiones deseado, luego cambia de lado.', 'Adjust the seat height and position yourself on the machine with your chest against the pad and your feet flat on the floor. Grasp the handle with an overhand grip and fully extend your arm, keeping a slight bend in your elbow. Pull the handle down and across your body towards your opposite hip, squeezing your lat muscle at the bottom of the movement. Slowly return the handle to the starting position, fully extending your arm. Repeat for the desired number of repetitions, then switch sides.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1347-tTuZSDT.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1347-tTuZSDT.gif', 'tTuZSDT', '© Gym visual — https://gymvisual.com/'),
('0590', 'lever one arm shoulder press', 'Ajusta la altura del asiento y colócate en la máquina con la espalda apoyada en la almohadilla. Sujeta el asa de la palanca con una mano y coloca el codo en un ángulo de 90 grados. Presiona la palanca hacia arriba hasta que el brazo quede completamente extendido por encima de la cabeza. Haz una paus', 'shoulders', 'leverage machine', 'shoulders', 'shoulders', 'delts', '{"triceps","upper back"}', 'Ajusta la altura del asiento y colócate en la máquina con la espalda apoyada en la almohadilla. Sujeta el asa de la palanca con una mano y coloca el codo en un ángulo de 90 grados. Presiona la palanca hacia arriba hasta que el brazo quede completamente extendido por encima de la cabeza. Haz una pausa breve en la parte más alta, luego baja lentamente la agarradera de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia al otro brazo.', 'Adjust the seat height and position yourself on the machine with your back against the pad. Grasp the lever handle with one hand and position your elbow at a 90-degree angle. Press the lever upward until your arm is fully extended overhead. Pause for a moment at the top, then slowly lower the lever back down to the starting position. Repeat for the desired number of repetitions, then switch to the other arm.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0590-2KGnL6M.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0590-2KGnL6M.gif', '2KGnL6M', '© Gym visual — https://gymvisual.com/'),
('0591', 'lever overhand triceps dip', 'Ajusta la máquina a la altura adecuada y asegura tu cuerpo en posición. Sujeta las asas con un agarre prono y coloca el cuerpo de modo que los brazos queden completamente extendidos. Baja el cuerpo flexionando los codos, manteniendo los brazos superiores cerca de los costados. Continúa bajando hasta', 'upper arms', 'leverage machine', 'upper arms', 'upper arms', 'triceps', '{"chest","shoulders"}', 'Ajusta la máquina a la altura adecuada y asegura tu cuerpo en posición. Sujeta las asas con un agarre prono y coloca el cuerpo de modo que los brazos queden completamente extendidos. Baja el cuerpo flexionando los codos, manteniendo los brazos superiores cerca de los costados. Continúa bajando hasta que los brazos superiores queden paralelos al suelo. Haz una pausa breve, luego empújate de vuelta hacia arriba a la posición inicial extendiendo los codos. Repite el número de repeticiones deseado.', 'Adjust the machine to the appropriate height and secure your body in position. Grasp the handles with an overhand grip and position your body so that your arms are fully extended. Lower your body by bending your elbows, keeping your upper arms close to your sides. Continue lowering until your upper arms are parallel to the floor. Pause for a moment, then push yourself back up to the starting position by extending your elbows. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0591-D5yqP2p.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0591-D5yqP2p.gif', 'D5yqP2p', '© Gym visual — https://gymvisual.com/'),
('0592', 'lever preacher curl', 'Ajusta la altura del asiento y colócate en la máquina de palanca. Coloca los brazos superiores en la almohadilla y sujeta las asas con un agarre supino. Mantén la espalda recta y los codos colocados sobre la almohadilla. Exhala y flexiona los antebrazos hacia los brazos superiores, contrayendo los b', 'upper arms', 'leverage machine', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ajusta la altura del asiento y colócate en la máquina de palanca. Coloca los brazos superiores en la almohadilla y sujeta las asas con un agarre supino. Mantén la espalda recta y los codos colocados sobre la almohadilla. Exhala y flexiona los antebrazos hacia los brazos superiores, contrayendo los bíceps. Haz una pausa breve en la parte más alta del movimiento, contrayendo los bíceps. Inhala y baja lentamente las asas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the seat height and position yourself on the leverage machine. Place your upper arms on the pad and grip the handles with an underhand grip. Keep your back straight and your elbows positioned on the pad. Exhale and curl your forearms towards your upper arms, contracting your biceps. Pause for a moment at the top of the movement, squeezing your biceps. Inhale and slowly lower the handles back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0592-b6hQYMb.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0592-b6hQYMb.gif', 'b6hQYMb', '© Gym visual — https://gymvisual.com/'),
('1614', 'lever preacher curl v. 2', 'Ajusta la altura del asiento y colócate en la máquina con los brazos superiores apoyados en la almohadilla y el pecho contra el soporte. Sujeta las asas con un agarre supino, un poco más separadas que la altura de los hombros. Mantén los brazos superiores inmóviles y exhala mientras flexionas las as', 'upper arms', 'leverage machine', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ajusta la altura del asiento y colócate en la máquina con los brazos superiores apoyados en la almohadilla y el pecho contra el soporte. Sujeta las asas con un agarre supino, un poco más separadas que la altura de los hombros. Mantén los brazos superiores inmóviles y exhala mientras flexionas las asas hacia los hombros, contrayendo los bíceps. Haz una pausa breve en la parte más alta del movimiento, contrayendo los bíceps. Inhala mientras bajas lentamente las asas de vuelta a la posición inicial, extendiendo los brazos por completo. Repite el número de repeticiones deseado.', 'Adjust the seat height and position yourself on the machine with your upper arms resting on the pad and your chest against the support. Grasp the handles with an underhand grip, slightly wider than shoulder-width apart. Keep your upper arms stationary and exhale as you curl the handles towards your shoulders, contracting your biceps. Pause for a moment at the top of the movement, squeezing your biceps. Inhale as you slowly lower the handles back to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1614-ye84CTU.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1614-ye84CTU.gif', 'ye84CTU', '© Gym visual — https://gymvisual.com/'),
('2285', 'lever pullover', 'Ajusta el asiento y las asas de la máquina de palanca a una posición cómoda. Siéntate en la máquina con la espalda apoyada en la almohadilla y sujeta las asas con un agarre prono. Mantén los brazos ligeramente flexionados y el core activado. Tira lentamente de las asas hacia el pecho, apretando los ', 'back', 'leverage machine', 'back', 'back', 'lats', '{"triceps","shoulders"}', 'Ajusta el asiento y las asas de la máquina de palanca a una posición cómoda. Siéntate en la máquina con la espalda apoyada en la almohadilla y sujeta las asas con un agarre prono. Mantén los brazos ligeramente flexionados y el core activado. Tira lentamente de las asas hacia el pecho, apretando los dorsales. Haz una pausa breve en el punto máximo de contracción, luego vuelve lentamente a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the seat and handles of the leverage machine to a comfortable position. Sit on the machine with your back against the pad and grasp the handles with an overhand grip. Keep your arms slightly bent and your core engaged. Slowly pull the handles towards your chest, squeezing your lats. Pause for a moment at the peak contraction, then slowly return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2285-4U7iLb5.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2285-4U7iLb5.gif', '4U7iLb5', '© Gym visual — https://gymvisual.com/'),
('2736', 'lever reverse grip lateral pulldown', 'Ajusta la altura del asiento y colócate en la máquina con las rodillas debajo de las almohadillas y los pies planos en el suelo. Agarra las agarraderas con un agarre prono, un poco más separadas que el ancho de los hombros. Siéntate erguido con el pecho hacia afuera y los hombros hacia atrás, manten', 'back', 'leverage machine', 'back', 'back', 'lats', '{"biceps","rhomboids","rear deltoids"}', 'Ajusta la altura del asiento y colócate en la máquina con las rodillas debajo de las almohadillas y los pies planos en el suelo. Agarra las agarraderas con un agarre prono, un poco más separadas que el ancho de los hombros. Siéntate erguido con el pecho hacia afuera y los hombros hacia atrás, manteniendo un ligero arco en la zona lumbar. Tira de las asas hacia el pecho, liderando con los codos y juntando los omóplatos. Haz una pausa breve en la parte baja del movimiento, luego suelta lentamente las asas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the seat height and position yourself on the machine with your knees under the pads and your feet flat on the ground. Grasp the handles with an overhand grip, slightly wider than shoulder-width apart. Sit upright with your chest out and shoulders back, maintaining a slight arch in your lower back. Pull the handles down towards your chest, leading with your elbows and squeezing your shoulder blades together. Pause for a moment at the bottom of the movement, then slowly release the handles back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2736-ky8FLU8.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2736-ky8FLU8.gif', 'ky8FLU8', '© Gym visual — https://gymvisual.com/'),
('1616', 'lever reverse grip preacher curl', 'Ajusta la altura del asiento y colócate en la máquina de palanca. Sujeta las asas con un agarre supino, con las palmas hacia arriba. Apoya los brazos superiores sobre la almohadilla de predicador, asegurándote de que los codos queden completamente extendidos. Manteniendo los brazos superiores inmóvi', 'upper arms', 'leverage machine', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ajusta la altura del asiento y colócate en la máquina de palanca. Sujeta las asas con un agarre supino, con las palmas hacia arriba. Apoya los brazos superiores sobre la almohadilla de predicador, asegurándote de que los codos queden completamente extendidos. Manteniendo los brazos superiores inmóviles, exhala y flexiona las asas hacia los hombros. Haz una pausa breve en la parte más alta del movimiento, contrayendo los bíceps. Inhala y baja lentamente las agarraderas de vuelta a la posición inicial, extendiendo los codos por completo. Repite el número de repeticiones deseado.', 'Adjust the seat height and position yourself on the leverage machine. Grasp the handles with an underhand grip, palms facing up. Rest your upper arms on the preacher pad, ensuring your elbows are fully extended. Keeping your upper arms stationary, exhale and curl the handles towards your shoulders. Pause for a moment at the top of the movement, squeezing your biceps. Inhale and slowly lower the handles back to the starting position, fully extending your elbows. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1616-kj3hy6W.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1616-kj3hy6W.gif', 'kj3hy6W', '© Gym visual — https://gymvisual.com/'),
('1348', 'lever reverse grip vertical row', 'Ajusta la altura del asiento y la posición de la placa para los pies para asegurar una alineación correcta. Siéntate en la máquina con el pecho contra la almohadilla y los pies planos sobre la placa para los pies. Sujeta las asas con un agarre supino, con las palmas hacia arriba. Mantén la espalda r', 'back', 'leverage machine', 'back', 'back', 'upper back', '{"biceps","forearms"}', 'Ajusta la altura del asiento y la posición de la placa para los pies para asegurar una alineación correcta. Siéntate en la máquina con el pecho contra la almohadilla y los pies planos sobre la placa para los pies. Sujeta las asas con un agarre supino, con las palmas hacia arriba. Mantén la espalda recta y activa el core. Tira de las asas hacia el pecho, juntando los omóplatos. Haz una pausa breve en la parte alta del movimiento, luego suelta lentamente y extiende los brazos de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the seat height and footplate position to ensure proper alignment. Sit on the machine with your chest against the pad and your feet flat on the footplate. Grasp the handles with an underhand grip, palms facing up. Keep your back straight and engage your core. Pull the handles towards your chest, squeezing your shoulder blades together. Pause for a moment at the top of the movement, then slowly release and extend your arms back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1348-ZqNOWQ6.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1348-ZqNOWQ6.gif', 'ZqNOWQ6', '© Gym visual — https://gymvisual.com/'),
('0593', 'lever reverse hyperextension', 'Ajusta la máquina de palanca a tu cuerpo y asegura los pies en las almohadillas para los pies. Túmbate boca abajo en la máquina con la parte superior del cuerpo colgando fuera del borde y las caderas apoyadas en la almohadilla. Cruza los brazos sobre el pecho o colócalos detrás de la cabeza. Activa ', 'upper legs', 'leverage machine', 'upper legs', 'upper legs', 'glutes', '{"hamstrings","lower back"}', 'Ajusta la máquina de palanca a tu cuerpo y asegura los pies en las almohadillas para los pies. Túmbate boca abajo en la máquina con la parte superior del cuerpo colgando fuera del borde y las caderas apoyadas en la almohadilla. Cruza los brazos sobre el pecho o colócalos detrás de la cabeza. Activa los glúteos y los isquiotibiales para levantar las piernas hacia arriba hasta que queden paralelas al suelo. Haz una pausa por un momento en la parte superior, luego baja lentamente las piernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the leverage machine to fit your body and secure your feet in the foot pads. Lie face down on the machine with your upper body hanging off the edge and your hips resting on the pad. Cross your arms over your chest or place them behind your head. Engage your glutes and hamstrings to lift your legs upward until they are parallel to the ground. Pause for a moment at the top, then slowly lower your legs back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0593-Krmb3cB.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0593-Krmb3cB.gif', 'Krmb3cB', '© Gym visual — https://gymvisual.com/'),
('1349', 'lever reverse t-bar row', 'Ajusta la altura del asiento y la posición de la placa para los pies en la máquina de palanca. Siéntate en la máquina con el pecho contra la almohadilla y los pies planos sobre la placa para los pies. Agarra las agarraderas con un agarre prono, un poco más separadas que el ancho de los hombros. Mant', 'back', 'leverage machine', 'back', 'back', 'upper back', '{"biceps","forearms"}', 'Ajusta la altura del asiento y la posición de la placa para los pies en la máquina de palanca. Siéntate en la máquina con el pecho contra la almohadilla y los pies planos sobre la placa para los pies. Agarra las agarraderas con un agarre prono, un poco más separadas que el ancho de los hombros. Mantén la espalda recta y activa el core. Tira de las asas hacia el pecho, juntando los omóplatos. Haz una pausa breve en la parte alta del movimiento, luego suelta lentamente y extiende los brazos de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the seat height and footplate position on the leverage machine. Sit on the machine with your chest against the pad and your feet flat on the footplate. Grasp the handles with an overhand grip, slightly wider than shoulder-width apart. Keep your back straight and engage your core. Pull the handles towards your chest, squeezing your shoulder blades together. Pause for a moment at the top of the movement, then slowly release and extend your arms back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1349-BgljGjd.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1349-BgljGjd.gif', 'BgljGjd', '© Gym visual — https://gymvisual.com/'),
('2315', 'lever rotary calf', 'Ajusta la altura del asiento de modo que las rodillas queden ligeramente flexionadas y los pies queden planos sobre la placa para los pies. Coloca los dedos de los pies sobre la placa para los pies, con los talones colgando fuera del borde. Sujeta las asas o los lados de la máquina para mayor estabi', 'lower legs', 'leverage machine', 'lower legs', 'lower legs', 'calves', '{"soleus","ankle stabilizers"}', 'Ajusta la altura del asiento de modo que las rodillas queden ligeramente flexionadas y los pies queden planos sobre la placa para los pies. Coloca los dedos de los pies sobre la placa para los pies, con los talones colgando fuera del borde. Sujeta las asas o los lados de la máquina para mayor estabilidad. Empuja con la parte delantera de los pies, elevando los talones tan alto como sea posible. Haz una pausa breve en la parte alta y luego baja lentamente los talones de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the seat height so that your knees are slightly bent and your feet are flat on the footplate. Place your toes on the footplate, with your heels hanging off the edge. Grasp the handles or the sides of the machine for stability. Push through the balls of your feet, raising your heels as high as possible. Pause for a moment at the top, then slowly lower your heels back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2315-MrgP9L6.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2315-MrgP9L6.gif', 'MrgP9L6', '© Gym visual — https://gymvisual.com/'),
('2335', 'lever seated calf press', 'Ajusta el asiento de la máquina de modo que los hombros queden alineados con la almohadilla de la palanca. Coloca los dedos de los pies en la parte inferior de la plataforma y posiciona las rodillas debajo de la almohadilla de la palanca. Sujeta las asas a los lados del asiento para mayor estabilida', 'lower legs', 'leverage machine', 'lower legs', 'lower legs', 'calves', '{"soleus","hamstrings"}', 'Ajusta el asiento de la máquina de modo que los hombros queden alineados con la almohadilla de la palanca. Coloca los dedos de los pies en la parte inferior de la plataforma y posiciona las rodillas debajo de la almohadilla de la palanca. Sujeta las asas a los lados del asiento para mayor estabilidad. Presiona la almohadilla de la palanca hacia abajo extendiendo los tobillos, elevando los talones tan alto como sea posible. Haz una pausa breve en la parte alta del movimiento, luego baja lentamente los talones de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the seat of the machine so that your shoulders are aligned with the lever pad. Place your toes on the lower portion of the platform and position your knees under the lever pad. Grasp the handles on the sides of the seat for stability. Press the lever pad down by extending your ankles, lifting your heels as high as possible. Pause for a moment at the top of the movement, then slowly lower your heels back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2335-Ie9UGty.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2335-Ie9UGty.gif', 'Ie9UGty', '© Gym visual — https://gymvisual.com/'),
('0594', 'lever seated calf raise', 'Ajusta la altura del asiento de modo que las rodillas queden ligeramente flexionadas y los pies queden planos sobre la placa para los pies. Coloca los dedos de los pies sobre la placa para los pies, con los talones colgando fuera del borde. Sujeta las asas o los lados del asiento para mayor estabili', 'lower legs', 'leverage machine', 'lower legs', 'lower legs', 'calves', '{"soleus","ankle stabilizers"}', 'Ajusta la altura del asiento de modo que las rodillas queden ligeramente flexionadas y los pies queden planos sobre la placa para los pies. Coloca los dedos de los pies sobre la placa para los pies, con los talones colgando fuera del borde. Sujeta las asas o los lados del asiento para mayor estabilidad. Empuja con la parte delantera de los pies para elevar los talones tan alto como sea posible. Haz una pausa breve en la parte alta y luego baja lentamente los talones de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the seat height so that your knees are slightly bent and your feet are flat on the footplate. Place your toes on the footplate with your heels hanging off the edge. Grasp the handles or the sides of the seat for stability. Push through the balls of your feet to raise your heels as high as possible. Pause for a moment at the top, then slowly lower your heels back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0594-bOOdeyc.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0594-bOOdeyc.gif', 'bOOdeyc', '© Gym visual — https://gymvisual.com/'),
('1452', 'lever seated crunch', 'Siéntate en la máquina de palanca con la espalda apoyada en la almohadilla y los pies planos en el suelo. Sujeta las asas o coloca las manos sobre las almohadillas laterales para mayor apoyo. Activa el abdomen e inclínate lentamente hacia atrás, dejando que la almohadilla se mueva contigo. Cuando la', 'waist', 'leverage machine', 'waist', 'waist', 'abs', '{"obliques"}', 'Siéntate en la máquina de palanca con la espalda apoyada en la almohadilla y los pies planos en el suelo. Sujeta las asas o coloca las manos sobre las almohadillas laterales para mayor apoyo. Activa el abdomen e inclínate lentamente hacia atrás, dejando que la almohadilla se mueva contigo. Cuando la parte superior del cuerpo esté en un ángulo de 45 grados, contrae el abdomen y haz un crunch hacia adelante, llevando el pecho hacia las rodillas. Haz una pausa breve en lo alto, luego suelta lentamente y vuelve a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on the leverage machine with your back against the pad and your feet flat on the floor. Grasp the handles or place your hands on the side pads for support. Engage your abs and slowly lean back, allowing the pad to move with you. Once your upper body is at a 45-degree angle, contract your abs and crunch forward, bringing your chest towards your knees. Pause for a moment at the top, then slowly release and return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1452-Wgaz7pm.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1452-Wgaz7pm.gif', 'Wgaz7pm', '© Gym visual — https://gymvisual.com/'),
('0595', 'lever seated crunch (chest pad)', 'Ajusta la altura del asiento y la posición de la almohadilla para el pecho según tu comodidad. Siéntate en la máquina con la espalda apoyada en la almohadilla para el pecho y los pies planos en el suelo. Sujeta las asas o las barras laterales para mayor estabilidad. Activa el abdomen y reclínate len', 'waist', 'leverage machine', 'waist', 'waist', 'abs', '{"obliques"}', 'Ajusta la altura del asiento y la posición de la almohadilla para el pecho según tu comodidad. Siéntate en la máquina con la espalda apoyada en la almohadilla para el pecho y los pies planos en el suelo. Sujeta las asas o las barras laterales para mayor estabilidad. Activa el abdomen y reclínate lentamente hacia atrás, permitiendo que el respaldo se mueva contigo. Haz una pausa en la contracción máxima, sintiendo la tensión en el abdomen. Vuelve lentamente a la posición inicial contrayendo el abdomen y tirando de tu cuerpo hacia arriba. Repite el número de repeticiones deseado.', 'Adjust the seat height and chest pad position according to your comfort. Sit on the machine with your back against the chest pad and your feet flat on the floor. Grasp the handles or side bars for stability. Engage your abs and slowly lean back, allowing the chest pad to move with you. Pause for a moment at the maximum contraction, feeling the tension in your abs. Slowly return to the starting position by contracting your abs and pulling yourself back up. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0595-ZnJHhMk.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0595-ZnJHhMk.gif', 'ZnJHhMk', '© Gym visual — https://gymvisual.com/'),
('3760', 'lever seated crunch v. 2', 'Siéntate en la máquina de palanca con la espalda apoyada en el respaldo y los pies sujetos bajo las almohadillas. Coloca las manos en las asas o en los lados del asiento para mayor apoyo. Activa el abdomen y flexiona lentamente el torso hacia adelante, llevando el pecho hacia las rodillas. Haz una p', 'waist', 'leverage machine', 'waist', 'waist', 'abs', '{"obliques","hip flexors"}', 'Siéntate en la máquina de palanca con la espalda apoyada en el respaldo y los pies sujetos bajo las almohadillas. Coloca las manos en las asas o en los lados del asiento para mayor apoyo. Activa el abdomen y flexiona lentamente el torso hacia adelante, llevando el pecho hacia las rodillas. Haz una pausa por un momento en la parte superior del movimiento, apretando el abdomen. Vuelve lentamente a la posición inicial, dejando que tu espalda se redondee ligeramente. Repite el número de repeticiones deseado.', 'Sit on the leverage machine with your back against the pad and your feet secured under the footpads. Place your hands on the handles or the sides of the seat for support. Engage your abs and slowly crunch forward, bringing your chest towards your knees. Pause for a moment at the top of the movement, squeezing your abs. Slowly return to the starting position, allowing your back to round slightly. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3760-eXFXCY0.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3760-eXFXCY0.gif', 'eXFXCY0', '© Gym visual — https://gymvisual.com/'),
('1451', 'lever seated dip', 'Ajusta la altura del asiento de modo que tus pies queden planos en el suelo y tus rodillas formen un ángulo de 90 grados. Agarra las asas de la máquina de palanca con las palmas hacia abajo y los brazos completamente extendidos. Baja lentamente el cuerpo flexionando los codos hasta que tus brazos qu', 'upper arms', 'leverage machine', 'upper arms', 'upper arms', 'triceps', '{"chest","shoulders"}', 'Ajusta la altura del asiento de modo que tus pies queden planos en el suelo y tus rodillas formen un ángulo de 90 grados. Agarra las asas de la máquina de palanca con las palmas hacia abajo y los brazos completamente extendidos. Baja lentamente el cuerpo flexionando los codos hasta que tus brazos queden paralelos al suelo. Haz una pausa breve, luego empújate de nuevo hacia arriba a la posición inicial estirando los brazos. Repite el número de repeticiones deseado.', 'Adjust the seat height so that your feet are flat on the ground and your knees are at a 90-degree angle. Grasp the handles of the leverage machine with your palms facing down and your arms fully extended. Slowly lower your body by bending your elbows until your upper arms are parallel to the ground. Pause for a moment, then push yourself back up to the starting position by straightening your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1451-BRImeP8.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1451-BRImeP8.gif', 'BRImeP8', '© Gym visual — https://gymvisual.com/'),
('0596', 'lever seated fly', 'Ajusta la altura del asiento y colócate en la máquina con la espalda apoyada en la almohadilla. Agarra las asas con un agarre pronado y mantén los codos ligeramente flexionados. Exhala y empuja las asas hacia adelante, juntándolas frente a tu pecho. Haz una pausa por un momento, contrayendo los músc', 'chest', 'leverage machine', 'chest', 'chest', 'pectorals', '{"deltoids","trapezius"}', 'Ajusta la altura del asiento y colócate en la máquina con la espalda apoyada en la almohadilla. Agarra las asas con un agarre pronado y mantén los codos ligeramente flexionados. Exhala y empuja las asas hacia adelante, juntándolas frente a tu pecho. Haz una pausa por un momento, contrayendo los músculos del pecho. Inhala y vuelve lentamente a la posición inicial, permitiendo que los músculos del pecho se estiren. Repite el número de repeticiones deseado.', 'Adjust the seat height and position yourself on the machine with your back against the pad. Grasp the handles with a pronated grip and keep your elbows slightly bent. Exhale and push the handles forward, bringing them together in front of your chest. Pause for a moment, squeezing your chest muscles. Inhale and slowly return to the starting position, allowing your chest muscles to stretch. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0596-v3xmPAR.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0596-v3xmPAR.gif', 'v3xmPAR', '© Gym visual — https://gymvisual.com/'),
('3759', 'lever seated good morning', 'Ajusta la altura del asiento de modo que tus caderas queden un poco más altas que tus rodillas. Siéntate en la máquina con la espalda apoyada en el respaldo y los pies planos sobre los apoyapiés. Sujeta las asas o los lados del asiento para mayor estabilidad. Manteniendo la espalda recta, inclínate ', 'upper legs', 'leverage machine', 'upper legs', 'upper legs', 'glutes', '{"hamstrings","lower back"}', 'Ajusta la altura del asiento de modo que tus caderas queden un poco más altas que tus rodillas. Siéntate en la máquina con la espalda apoyada en el respaldo y los pies planos sobre los apoyapiés. Sujeta las asas o los lados del asiento para mayor estabilidad. Manteniendo la espalda recta, inclínate lentamente hacia adelante desde las caderas hasta que la parte superior de tu cuerpo quede paralela al suelo. Haz una pausa por un momento y luego vuelve lentamente a la posición inicial empujando con los glúteos y los isquiotibiales. Repite el número de repeticiones deseado.', 'Adjust the seat height so that your hips are slightly higher than your knees. Sit on the machine with your back against the pad and your feet flat on the footrests. Grasp the handles or the sides of the seat for stability. Keeping your back straight, slowly lean forward from your hips until your upper body is parallel to the ground. Pause for a moment, then slowly return to the starting position by pushing through your glutes and hamstrings. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3759-XsCcxCC.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3759-XsCcxCC.gif', 'XsCcxCC', '© Gym visual — https://gymvisual.com/'),
('0597', 'lever seated hip abduction', 'Ajusta la altura del asiento de modo que tus rodillas formen un ángulo de 90 grados. Siéntate en la máquina con la espalda apoyada en el respaldo y los pies sobre los apoyapiés. Coloca las manos en las asas laterales para mayor estabilidad. Activa los abductores y empuja lentamente las piernas hacia', 'upper legs', 'leverage machine', 'upper legs', 'upper legs', 'abductors', '{"glutes","hamstrings"}', 'Ajusta la altura del asiento de modo que tus rodillas formen un ángulo de 90 grados. Siéntate en la máquina con la espalda apoyada en el respaldo y los pies sobre los apoyapiés. Coloca las manos en las asas laterales para mayor estabilidad. Activa los abductores y empuja lentamente las piernas hacia afuera, alejándolas de la línea media del cuerpo. Haz una pausa al final del movimiento y luego junta lentamente las piernas de nuevo hasta la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the seat height so that your knees are at a 90-degree angle. Sit on the machine with your back against the backrest and your feet on the footrests. Place your hands on the side handles for stability. Engage your abductors and slowly push your legs apart, away from the midline of your body. Pause for a moment at the end of the movement, then slowly bring your legs back together to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0597-CHpahtl.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0597-CHpahtl.gif', 'CHpahtl', '© Gym visual — https://gymvisual.com/'),
('0598', 'lever seated hip adduction', 'Ajusta la altura del asiento y colócate en la máquina con la espalda apoyada en el respaldo. Coloca los pies sobre los apoyapiés y agarra las asas para mayor estabilidad. Activa los aductores y junta lentamente las piernas, apretando la parte interna de los muslos. Haz una pausa breve en el punto má', 'upper legs', 'leverage machine', 'upper legs', 'upper legs', 'adductors', '{"hamstrings","glutes"}', 'Ajusta la altura del asiento y colócate en la máquina con la espalda apoyada en el respaldo. Coloca los pies sobre los apoyapiés y agarra las asas para mayor estabilidad. Activa los aductores y junta lentamente las piernas, apretando la parte interna de los muslos. Haz una pausa breve en el punto máximo de contracción, luego vuelve lentamente a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the seat height and position yourself on the machine with your back against the backrest. Place your feet on the footrests and grasp the handles for stability. Engage your adductor muscles and slowly bring your legs together, squeezing your inner thighs. Pause for a moment at the peak contraction, then slowly return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0598-oHsrypV.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0598-oHsrypV.gif', 'oHsrypV', '© Gym visual — https://gymvisual.com/'),
('0599', 'lever seated leg curl', 'Ajusta la máquina a tu cuerpo y siéntate en ella con la espalda apoyada en el respaldo. Coloca la parte baja de las piernas debajo de la palanca acolchada, justo por encima de los tobillos. Sujeta las asas a los lados de la máquina para mayor apoyo. Manteniendo la parte superior de las piernas inmóv', 'upper legs', 'leverage machine', 'upper legs', 'upper legs', 'hamstrings', '{"calves"}', 'Ajusta la máquina a tu cuerpo y siéntate en ella con la espalda apoyada en el respaldo. Coloca la parte baja de las piernas debajo de la palanca acolchada, justo por encima de los tobillos. Sujeta las asas a los lados de la máquina para mayor apoyo. Manteniendo la parte superior de las piernas inmóvil, exhala y flexiona las piernas hacia arriba todo lo que puedas. Mantén la posición contraída durante una pausa breve mientras aprietas los isquiotibiales. Inhala y baja lentamente la palanca de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the machine to fit your body and sit on it with your back against the backrest. Place your lower legs under the padded lever, just above your ankles. Grasp the handles on the sides of the machine for support. Keeping your upper legs stationary, exhale and curl your legs up as far as possible. Hold the contracted position for a brief pause as you squeeze your hamstrings. Inhale and slowly lower the lever back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0599-Zg3XY7P.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0599-Zg3XY7P.gif', 'Zg3XY7P', '© Gym visual — https://gymvisual.com/'),
('0600', 'lever seated leg raise crunch', 'Siéntate en la máquina de palanca con la espalda apoyada en el respaldo y los pies sobre los apoyapiés. Sujeta las asas o las barras laterales para mayor estabilidad. Activa el abdomen y eleva lentamente las piernas hacia el pecho, mientras curvas el torso hacia adelante al mismo tiempo. Haz una pau', 'waist', 'leverage machine', 'waist', 'waist', 'abs', '{"hip flexors"}', 'Siéntate en la máquina de palanca con la espalda apoyada en el respaldo y los pies sobre los apoyapiés. Sujeta las asas o las barras laterales para mayor estabilidad. Activa el abdomen y eleva lentamente las piernas hacia el pecho, mientras curvas el torso hacia adelante al mismo tiempo. Haz una pausa por un momento en la parte alta y luego baja lentamente las piernas y el torso a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on the leverage machine with your back against the backrest and your feet on the footrests. Grasp the handles or sidebars for stability. Engage your abs and slowly raise your legs up towards your chest, curling your torso forward at the same time. Pause for a moment at the top, then slowly lower your legs and torso back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0600-PQ2AtC3.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0600-PQ2AtC3.gif', 'PQ2AtC3', '© Gym visual — https://gymvisual.com/'),
('0602', 'lever seated reverse fly', 'Ajusta la altura del asiento y colócate en la máquina con el pecho contra la almohadilla y los pies planos en el suelo. Agarra las asas con un agarre prono y mantén los brazos ligeramente flexionados. Exhala y junta las escápulas mientras llevas las asas hacia atrás y hacia afuera, alejándolas de tu', 'shoulders', 'leverage machine', 'shoulders', 'shoulders', 'delts', '{"trapezius","rhomboids"}', 'Ajusta la altura del asiento y colócate en la máquina con el pecho contra la almohadilla y los pies planos en el suelo. Agarra las asas con un agarre prono y mantén los brazos ligeramente flexionados. Exhala y junta las escápulas mientras llevas las asas hacia atrás y hacia afuera, alejándolas de tu cuerpo. Haz una pausa breve en el punto máximo de contracción, luego inhala y vuelve lentamente a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the seat height and position yourself on the machine with your chest against the pad and your feet flat on the floor. Grasp the handles with an overhand grip and keep your arms slightly bent. Exhale and squeeze your shoulder blades together as you pull the handles back and outward, away from your body. Pause for a moment at the peak contraction, then inhale and slowly return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0602-myfUsKf.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0602-myfUsKf.gif', 'myfUsKf', '© Gym visual — https://gymvisual.com/'),
('0601', 'lever seated reverse fly (parallel grip)', 'Ajusta la altura del asiento y colócate en la máquina con el pecho contra la almohadilla y los pies planos en el suelo. Agarra las asas con un agarre paralelo, con las palmas enfrentadas, y mantén los brazos ligeramente flexionados. Exhala y junta las escápulas mientras llevas las asas hacia atrás y', 'shoulders', 'leverage machine', 'shoulders', 'shoulders', 'delts', '{"trapezius","rhomboids"}', 'Ajusta la altura del asiento y colócate en la máquina con el pecho contra la almohadilla y los pies planos en el suelo. Agarra las asas con un agarre paralelo, con las palmas enfrentadas, y mantén los brazos ligeramente flexionados. Exhala y junta las escápulas mientras llevas las asas hacia atrás y hacia afuera, alejándolas de tu cuerpo. Haz una pausa breve en el punto máximo de contracción, luego inhala y vuelve lentamente a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the seat height and position yourself on the machine with your chest against the pad and your feet flat on the floor. Grasp the handles with a parallel grip, palms facing each other, and keep your arms slightly bent. Exhale and squeeze your shoulder blades together as you pull the handles back and outward, away from your body. Pause for a moment at the peak contraction, then inhale and slowly return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0601-xiHiJcA.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0601-xiHiJcA.gif', 'xiHiJcA', '© Gym visual — https://gymvisual.com/'),
('1350', 'lever seated row', 'Ajusta la altura del asiento y los apoyapiés a una posición cómoda. Siéntate en la máquina con el pecho apoyado en la almohadilla y los pies sobre los apoyapiés. Agarra las asas con un agarre prono, con las manos separadas a la altura de los hombros. Mantén la espalda recta y el core activado. Jala ', 'back', 'leverage machine', 'back', 'back', 'upper back', '{"biceps","forearms"}', 'Ajusta la altura del asiento y los apoyapiés a una posición cómoda. Siéntate en la máquina con el pecho apoyado en la almohadilla y los pies sobre los apoyapiés. Agarra las asas con un agarre prono, con las manos separadas a la altura de los hombros. Mantén la espalda recta y el core activado. Jala las agarraderas hacia el cuerpo, apretando los omóplatos entre sí. Haz una pausa breve en la parte alta del movimiento. Suelta lentamente las asas y vuelve a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the seat height and footrests to a comfortable position. Sit on the machine with your chest against the pad and your feet on the footrests. Grasp the handles with an overhand grip, shoulder-width apart. Keep your back straight and your core engaged. Pull the handles towards your body, squeezing your shoulder blades together. Pause for a moment at the peak of the movement. Slowly release the handles and return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1350-7I6LNUG.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1350-7I6LNUG.gif', '7I6LNUG', '© Gym visual — https://gymvisual.com/'),
('1385', 'lever seated squat calf raise on leg press machine', 'Ajusta el asiento de la máquina de prensa de piernas de modo que tus rodillas queden ligeramente flexionadas cuando los pies estén sobre la plataforma. Siéntate en la máquina con la espalda apoyada en el respaldo y los pies planos sobre la plataforma, separados a la altura de los hombros. Coloca los', 'lower legs', 'leverage machine', 'lower legs', 'lower legs', 'calves', '{"quadriceps","hamstrings","glutes"}', 'Ajusta el asiento de la máquina de prensa de piernas de modo que tus rodillas queden ligeramente flexionadas cuando los pies estén sobre la plataforma. Siéntate en la máquina con la espalda apoyada en el respaldo y los pies planos sobre la plataforma, separados a la altura de los hombros. Coloca los dedos y la planta de los pies sobre la plataforma, manteniendo los talones alejados del borde. Suelta las palancas de seguridad y empuja la plataforma alejándola de ti extendiendo las rodillas. Una vez que tus rodillas estén completamente extendidas, baja lentamente los talones flexionando las pantorrillas. Haz una pausa por un momento en la parte baja y luego empuja la plataforma de nuevo hacia arriba extendiendo las pantorrillas. Repite el número de repeticiones deseado.', 'Adjust the seat of the leg press machine so that your knees are slightly bent when your feet are on the footplate. Sit on the machine with your back against the backrest and your feet flat on the footplate, shoulder-width apart. Place your toes and the balls of your feet on the footplate, keeping your heels off the edge. Release the safety handles and push the footplate away from you by extending your knees. Once your knees are fully extended, slowly lower your heels by flexing your calves. Pause for a moment at the bottom, then push the footplate back up by extending your calves. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1385-IeDEXTe.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1385-IeDEXTe.gif', 'IeDEXTe', '© Gym visual — https://gymvisual.com/'),
('0603', 'lever shoulder press', 'Ajusta la altura del asiento y colócate en la máquina con la espalda apoyada en el respaldo. Agarra las asas con un agarre prono y coloca las manos a la altura de los hombros. Empuja las asas hacia arriba hasta que los brazos queden completamente extendidos, pero sin bloquear los codos. Haz una paus', 'shoulders', 'leverage machine', 'shoulders', 'shoulders', 'delts', '{"triceps","chest"}', 'Ajusta la altura del asiento y colócate en la máquina con la espalda apoyada en el respaldo. Agarra las asas con un agarre prono y coloca las manos a la altura de los hombros. Empuja las asas hacia arriba hasta que los brazos queden completamente extendidos, pero sin bloquear los codos. Haz una pausa breve en lo alto, luego baja lentamente las asas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the seat height and position yourself on the machine with your back against the backrest. Grasp the handles with an overhand grip and position your hands at shoulder level. Push the handles upward until your arms are fully extended, but do not lock your elbows. Pause for a moment at the top, then slowly lower the handles back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0603-67n3r98.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0603-67n3r98.gif', '67n3r98', '© Gym visual — https://gymvisual.com/'),
('0869', 'lever shoulder press v. 2', 'Ajusta la altura del asiento y el respaldo de la máquina de palanca a una posición cómoda. Siéntate en la máquina con la espalda apoyada en el respaldo y los pies planos en el suelo. Agarra las asas de la máquina con un agarre prono, un poco más separadas que la anchura de los hombros. Empuja las as', 'shoulders', 'leverage machine', 'shoulders', 'shoulders', 'delts', '{"triceps","chest"}', 'Ajusta la altura del asiento y el respaldo de la máquina de palanca a una posición cómoda. Siéntate en la máquina con la espalda apoyada en el respaldo y los pies planos en el suelo. Agarra las asas de la máquina con un agarre prono, un poco más separadas que la anchura de los hombros. Empuja las asas hacia arriba y hacia adelante hasta que los brazos queden completamente extendidos, pero sin bloquear los codos. Haz una pausa breve en lo alto, luego baja lentamente las asas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the seat height and backrest of the leverage machine to a comfortable position. Sit on the machine with your back against the backrest and your feet flat on the floor. Grasp the handles of the machine with an overhand grip, slightly wider than shoulder-width apart. Push the handles upward and forward until your arms are fully extended, but not locked. Pause for a moment at the top, then slowly lower the handles back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0869-vqsbmL0.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0869-vqsbmL0.gif', 'vqsbmL0', '© Gym visual — https://gymvisual.com/'),
('2318', 'lever shoulder press v. 3', 'Ajusta la altura del asiento y el respaldo de la máquina de palanca a una posición cómoda. Siéntate en la máquina con la espalda apoyada en el respaldo y los pies planos en el suelo. Agarra las asas de la máquina con un agarre prono, un poco más separadas que la anchura de los hombros. Empuja las as', 'shoulders', 'leverage machine', 'shoulders', 'shoulders', 'delts', '{"triceps","chest"}', 'Ajusta la altura del asiento y el respaldo de la máquina de palanca a una posición cómoda. Siéntate en la máquina con la espalda apoyada en el respaldo y los pies planos en el suelo. Agarra las asas de la máquina con un agarre prono, un poco más separadas que la anchura de los hombros. Empuja las asas hacia arriba y hacia adelante hasta que los brazos queden completamente extendidos, pero sin bloquear los codos. Haz una pausa breve en lo alto, luego baja lentamente las asas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the seat height and backrest of the leverage machine to a comfortable position. Sit on the machine with your back against the backrest and your feet flat on the floor. Grasp the handles of the machine with an overhand grip, slightly wider than shoulder-width apart. Push the handles upward and forward until your arms are fully extended, but not locked. Pause for a moment at the top, then slowly lower the handles back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2318-dNFYIU1.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2318-dNFYIU1.gif', 'dNFYIU1', '© Gym visual — https://gymvisual.com/'),
('0604', 'lever shrug', 'Ajusta la altura del asiento y colócate en la máquina de palanca con la espalda apoyada en la almohadilla. Sujeta las asas con un agarre prono y mantén los brazos rectos. Manteniendo la espalda recta, eleva los hombros hacia las orejas tan alto como sea posible. Mantén la contracción por un momento,', 'back', 'leverage machine', 'back', 'back', 'traps', '{"shoulders"}', 'Ajusta la altura del asiento y colócate en la máquina de palanca con la espalda apoyada en la almohadilla. Sujeta las asas con un agarre prono y mantén los brazos rectos. Manteniendo la espalda recta, eleva los hombros hacia las orejas tan alto como sea posible. Mantén la contracción por un momento, luego baja lentamente los hombros de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the seat height and position yourself on the leverage machine with your back against the pad. Grasp the handles with an overhand grip and keep your arms straight. Keeping your back straight, lift your shoulders up towards your ears as high as possible. Hold the contraction for a moment, then slowly lower your shoulders back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0604-ZZKbeMw.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0604-ZZKbeMw.gif', 'ZZKbeMw', '© Gym visual — https://gymvisual.com/'),
('0605', 'lever standing calf raise', 'Ajusta la máquina a tu altura y ponte de pie con los pies separados a la altura de los hombros. Coloca los hombros debajo de las almohadillas y sujétate de las asas para mayor estabilidad. Eleva los talones tan alto como puedas extendiendo los tobillos. Haz una pausa breve en la parte alta y luego b', 'lower legs', 'leverage machine', 'lower legs', 'lower legs', 'calves', '{"soleus","ankle stabilizers"}', 'Ajusta la máquina a tu altura y ponte de pie con los pies separados a la altura de los hombros. Coloca los hombros debajo de las almohadillas y sujétate de las asas para mayor estabilidad. Eleva los talones tan alto como puedas extendiendo los tobillos. Haz una pausa breve en la parte alta y luego baja lentamente los talones de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the machine to your height and stand with your feet shoulder-width apart. Place your shoulders under the pads and hold onto the handles for stability. Raise your heels as high as possible by extending your ankles. Pause for a moment at the top, then slowly lower your heels back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0605-ykUOVze.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0605-ykUOVze.gif', 'ykUOVze', '© Gym visual — https://gymvisual.com/'),
('3758', 'lever standing chest press', 'Ajusta la altura del asiento y colócate en la máquina con los pies planos en el suelo. Agarra las asas con un agarre prono y coloca las manos a la altura del pecho. Empuja las asas hacia adelante hasta que los brazos queden completamente extendidos, manteniendo los codos ligeramente flexionados. Haz', 'chest', 'leverage machine', 'chest', 'chest', 'pectorals', '{"shoulders","triceps"}', 'Ajusta la altura del asiento y colócate en la máquina con los pies planos en el suelo. Agarra las asas con un agarre prono y coloca las manos a la altura del pecho. Empuja las asas hacia adelante hasta que los brazos queden completamente extendidos, manteniendo los codos ligeramente flexionados. Haz una pausa por un momento y luego lleva lentamente las asas de vuelta hacia el pecho, manteniendo el control durante todo el movimiento. Repite el número de repeticiones deseado.', 'Adjust the seat height and position yourself on the machine with your feet flat on the ground. Grasp the handles with an overhand grip and position your hands at chest level. Push the handles forward until your arms are fully extended, keeping your elbows slightly bent. Pause for a moment, then slowly bring the handles back towards your chest, maintaining control throughout the movement. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3758-WbNq5Xu.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3758-WbNq5Xu.gif', 'WbNq5Xu', '© Gym visual — https://gymvisual.com/'),
('0606', 'lever t bar row', 'Ajusta la altura del asiento y la posición de la placa para los pies para asegurar una alineación correcta. Siéntate en la máquina con el pecho contra la almohadilla y los pies planos sobre la placa para los pies. Agarra las agarraderas con un agarre prono, un poco más separadas que el ancho de los ', 'back', 'leverage machine', 'back', 'back', 'upper back', '{"biceps","forearms"}', 'Ajusta la altura del asiento y la posición de la placa para los pies para asegurar una alineación correcta. Siéntate en la máquina con el pecho contra la almohadilla y los pies planos sobre la placa para los pies. Agarra las agarraderas con un agarre prono, un poco más separadas que el ancho de los hombros. Mantén la espalda recta y activa el core. Tira de las asas hacia el torso, juntando los omóplatos. Haz una pausa en el punto de máxima contracción y luego suelta lentamente las asas hasta la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the seat height and footplate position to ensure proper alignment. Sit on the machine with your chest against the pad and your feet flat on the footplate. Grasp the handles with an overhand grip, slightly wider than shoulder-width apart. Keep your back straight and engage your core. Pull the handles towards your torso, squeezing your shoulder blades together. Pause for a moment at the peak contraction, then slowly release the handles back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0606-aaXr7ld.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0606-aaXr7ld.gif', 'aaXr7ld', '© Gym visual — https://gymvisual.com/'),
('1351', 'lever t-bar reverse grip row', 'Ajusta la altura del asiento y colócate en la máquina con el pecho contra la almohadilla y los pies planos en el suelo. Agarra las agarraderas con un agarre prono, un poco más separadas que el ancho de los hombros. Mantén la espalda recta y activa el core. Tira de las asas hacia el pecho, juntando l', 'back', 'leverage machine', 'back', 'back', 'upper back', '{"biceps","forearms"}', 'Ajusta la altura del asiento y colócate en la máquina con el pecho contra la almohadilla y los pies planos en el suelo. Agarra las agarraderas con un agarre prono, un poco más separadas que el ancho de los hombros. Mantén la espalda recta y activa el core. Tira de las asas hacia el pecho, juntando los omóplatos. Haz una pausa breve en la parte alta del movimiento, luego suelta lentamente y extiende los brazos de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the seat height and position yourself on the machine with your chest against the pad and your feet flat on the floor. Grasp the handles with an overhand grip, slightly wider than shoulder-width apart. Keep your back straight and engage your core. Pull the handles towards your chest, squeezing your shoulder blades together. Pause for a moment at the top of the movement, then slowly release and extend your arms back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1351-FVM1AUZ.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1351-FVM1AUZ.gif', 'FVM1AUZ', '© Gym visual — https://gymvisual.com/'),
('0607', 'lever triceps extension', 'Ajusta la altura del asiento y colócate en la máquina con la espalda apoyada en la almohadilla. Agarra las asas con un agarre prono y extiende completamente los brazos frente a ti. Manteniendo la parte superior de los brazos inmóvil, baja lentamente las asas hacia tu frente flexionando los codos. Ha', 'upper arms', 'leverage machine', 'upper arms', 'upper arms', 'triceps', '{"shoulders"}', 'Ajusta la altura del asiento y colócate en la máquina con la espalda apoyada en la almohadilla. Agarra las asas con un agarre prono y extiende completamente los brazos frente a ti. Manteniendo la parte superior de los brazos inmóvil, baja lentamente las asas hacia tu frente flexionando los codos. Haz una pausa por un momento en la parte baja y luego empuja las asas de vuelta hacia arriba hasta la posición inicial extendiendo los brazos. Repite el número de repeticiones deseado.', 'Adjust the seat height and position yourself on the machine with your back against the pad. Grasp the handles with an overhand grip and fully extend your arms in front of you. Keeping your upper arms stationary, slowly lower the handles towards your forehead by bending your elbows. Pause for a moment at the bottom, then push the handles back up to the starting position by extending your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0607-Ser9eQp.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0607-Ser9eQp.gif', 'Ser9eQp', '© Gym visual — https://gymvisual.com/'),
('1313', 'lever unilateral row', 'Ajusta la altura del asiento y colócate frente a la máquina. Agarra las asas con un agarre prono y mantén la espalda recta. Jala las agarraderas hacia el cuerpo, apretando los omóplatos entre sí. Haz una pausa en el punto máximo del movimiento y luego suelta lentamente, extendiendo los brazos de vue', 'back', 'leverage machine', 'back', 'back', 'upper back', '{"biceps","forearms"}', 'Ajusta la altura del asiento y colócate frente a la máquina. Agarra las asas con un agarre prono y mantén la espalda recta. Jala las agarraderas hacia el cuerpo, apretando los omóplatos entre sí. Haz una pausa en el punto máximo del movimiento y luego suelta lentamente, extendiendo los brazos de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the seat height and position yourself facing the machine. Grasp the handles with an overhand grip and keep your back straight. Pull the handles towards your body, squeezing your shoulder blades together. Pause for a moment at the peak of the movement, then slowly release and extend your arms back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1313-oROuvrX.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1313-oROuvrX.gif', 'oROuvrX', '© Gym visual — https://gymvisual.com/'),
('0609', 'london bridge', 'Sujeta la cuerda a un punto de anclaje alto. Ponte de pie de espaldas al punto de anclaje con los pies separados a la altura de los hombros. Agarra la cuerda con un agarre prono, con las palmas hacia abajo. Inclínate ligeramente hacia adelante, manteniendo la espalda recta y el core activado. Tira d', 'back', 'rope', 'back', 'back', 'upper back', '{"shoulders","biceps","forearms"}', 'Sujeta la cuerda a un punto de anclaje alto. Ponte de pie de espaldas al punto de anclaje con los pies separados a la altura de los hombros. Agarra la cuerda con un agarre prono, con las palmas hacia abajo. Inclínate ligeramente hacia adelante, manteniendo la espalda recta y el core activado. Tira de la cuerda hacia tu cuerpo, juntando las escápulas. Haz una pausa por un momento en el punto más alto del movimiento, luego libera lentamente la tensión y regresa a la posición inicial. Repite el número de repeticiones deseado.', 'Attach the rope to a high anchor point. Stand facing away from the anchor point with your feet shoulder-width apart. Grasp the rope with an overhand grip, palms facing down. Lean forward slightly, keeping your back straight and core engaged. Pull the rope towards your body, squeezing your shoulder blades together. Pause for a moment at the peak of the movement, then slowly release the tension and return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0609-bLyQokI.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0609-bLyQokI.gif', 'bLyQokI', '© Gym visual — https://gymvisual.com/'),
('3013', 'low glute bridge on floor', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Coloca los brazos a los lados del cuerpo, con las palmas hacia abajo. Activa los glúteos y el core, y luego eleva las caderas del suelo hasta que tu cuerpo forme una línea recta desde las rodillas hasta los hombro', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'glutes', '{"hamstrings","core"}', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Coloca los brazos a los lados del cuerpo, con las palmas hacia abajo. Activa los glúteos y el core, y luego eleva las caderas del suelo hasta que tu cuerpo forme una línea recta desde las rodillas hasta los hombros. Haz una pausa breve en la parte alta, apretando los glúteos. Baja lentamente las caderas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on your back with your knees bent and feet flat on the ground. Place your arms by your sides, palms facing down. Engage your glutes and core, then lift your hips off the ground until your body forms a straight line from your knees to your shoulders. Pause for a moment at the top, squeezing your glutes. Slowly lower your hips back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3013-u0cNiij.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3013-u0cNiij.gif', 'u0cNiij', '© Gym visual — https://gymvisual.com/'),
('1352', 'lower back curl', 'Túmbate boca abajo con las piernas extendidas y los brazos a los lados del cuerpo. Activa los glúteos y los isquiotibiales, y eleva lentamente la parte superior del cuerpo del suelo, curvando la espalda hacia arriba. Haz una pausa por un momento en la parte superior, luego baja lentamente la parte s', 'back', 'body weight', 'back', 'back', 'spine', '{"glutes","hamstrings"}', 'Túmbate boca abajo con las piernas extendidas y los brazos a los lados del cuerpo. Activa los glúteos y los isquiotibiales, y eleva lentamente la parte superior del cuerpo del suelo, curvando la espalda hacia arriba. Haz una pausa por un momento en la parte superior, luego baja lentamente la parte superior del cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on your stomach with your legs extended and your arms by your sides. Engage your glutes and hamstrings, and slowly lift your upper body off the ground, curling your back upwards. Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1352-ANbbry2.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1352-ANbbry2.gif', 'ANbbry2', '© Gym visual — https://gymvisual.com/'),
('3582', 'lunge with jump', 'Comienza de pie con los pies separados a la altura de los hombros. Da un paso adelante con el pie derecho, bajando el cuerpo hasta una posición de zancada. Empújate con el pie derecho y salta al aire, cambiando la posición de los pies en pleno vuelo. Aterriza suavemente con el pie izquierdo hacia ad', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves"}', 'Comienza de pie con los pies separados a la altura de los hombros. Da un paso adelante con el pie derecho, bajando el cuerpo hasta una posición de zancada. Empújate con el pie derecho y salta al aire, cambiando la posición de los pies en pleno vuelo. Aterriza suavemente con el pie izquierdo hacia adelante y baja inmediatamente el cuerpo a una posición de zancada. Continúa alternando entre zancadas y saltos el número de repeticiones deseado.', 'Start by standing with your feet shoulder-width apart. Take a step forward with your right foot, lowering your body into a lunge position. Push off with your right foot and jump into the air, switching the position of your feet mid-air. Land softly with your left foot forward and immediately lower your body into a lunge position. Continue alternating between lunges and jumps for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3582-PM1PZjg.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3582-PM1PZjg.gif', 'PM1PZjg', '© Gym visual — https://gymvisual.com/'),
('1688', 'lunge with twist', 'Comienza de pie con los pies separados a la altura de los hombros. Da un paso adelante con el pie derecho, bajando el cuerpo hasta una posición de zancada. Al hacer la zancada, gira el torso hacia la derecha, llevando el codo izquierdo hacia la rodilla derecha. Haz una pausa breve y luego vuelve a l', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"quadriceps","glutes","hamstrings"}', 'Comienza de pie con los pies separados a la altura de los hombros. Da un paso adelante con el pie derecho, bajando el cuerpo hasta una posición de zancada. Al hacer la zancada, gira el torso hacia la derecha, llevando el codo izquierdo hacia la rodilla derecha. Haz una pausa breve y luego vuelve a la posición inicial. Repite hacia el otro lado, dando un paso adelante con el pie izquierdo y girando el torso hacia la izquierda. Continúa alternando lados durante el número de repeticiones deseado.', 'Start by standing with your feet shoulder-width apart. Take a step forward with your right foot, lowering your body into a lunge position. As you lunge, twist your torso to the right, bringing your left elbow towards your right knee. Pause for a moment, then return to the starting position. Repeat on the other side, stepping forward with your left foot and twisting your torso to the left. Continue alternating sides for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1688-K9VL0Jq.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1688-K9VL0Jq.gif', 'K9VL0Jq', '© Gym visual — https://gymvisual.com/'),
('0613', 'lying (side) quads stretch', 'Túmbate de lado con las piernas rectas. Flexiona la pierna de arriba y agarra tu tobillo o pie con la mano. Tira suavemente del tobillo o del pie hacia los glúteos hasta sentir un estiramiento en los cuádriceps. Mantén el estiramiento durante 20-30 segundos. Suelta el estiramiento y repite del otro ', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'quads', '{"hamstrings"}', 'Túmbate de lado con las piernas rectas. Flexiona la pierna de arriba y agarra tu tobillo o pie con la mano. Tira suavemente del tobillo o del pie hacia los glúteos hasta sentir un estiramiento en los cuádriceps. Mantén el estiramiento durante 20-30 segundos. Suelta el estiramiento y repite del otro lado.', 'Lie on your side with your legs straight. Bend your top leg and grab your ankle or foot with your hand. Gently pull your ankle or foot towards your glutes until you feel a stretch in your quads. Hold the stretch for 20-30 seconds. Release the stretch and repeat on the other side.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0613-BWnJR72.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0613-BWnJR72.gif', 'BWnJR72', '© Gym visual — https://gymvisual.com/'),
('2312', 'lying elbow to knee', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Coloca las manos detrás de la cabeza con los codos apuntando hacia afuera. Activa el abdomen y levanta la parte superior del cuerpo del suelo, llevando el codo derecho hacia la rodilla izquierda. Al mismo tiempo, ', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"hip flexors","lower back"}', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Coloca las manos detrás de la cabeza con los codos apuntando hacia afuera. Activa el abdomen y levanta la parte superior del cuerpo del suelo, llevando el codo derecho hacia la rodilla izquierda. Al mismo tiempo, extiende la pierna derecha en línea recta y levántala del suelo. Haz una pausa breve y luego vuelve a la posición inicial. Repite el movimiento, esta vez llevando el codo izquierdo hacia la rodilla derecha y extendiendo la pierna izquierda. Continúa alternando lados durante el número de repeticiones deseado.', 'Lie flat on your back with your knees bent and feet flat on the ground. Place your hands behind your head with your elbows pointing outwards. Engage your abs and lift your upper body off the ground, bringing your right elbow towards your left knee. At the same time, extend your right leg straight out and lift it off the ground. Pause for a moment, then return to the starting position. Repeat the movement, this time bringing your left elbow towards your right knee and extending your left leg. Continue alternating sides for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2312-AQIhRjM.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2312-AQIhRjM.gif', 'AQIhRjM', '© Gym visual — https://gymvisual.com/'),
('0620', 'lying leg raise flat bench', 'Túmbate en un banco plano con la espalda presionada contra él. Coloca las manos debajo de los glúteos como apoyo. Mantén las piernas rectas y juntas, y elévalas hacia el techo. Haz una pausa por un momento en la parte superior, luego baja lentamente las piernas de vuelta a la posición inicial. Repit', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"hip flexors"}', 'Túmbate en un banco plano con la espalda presionada contra él. Coloca las manos debajo de los glúteos como apoyo. Mantén las piernas rectas y juntas, y elévalas hacia el techo. Haz una pausa por un momento en la parte superior, luego baja lentamente las piernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on a flat bench with your back pressed against it. Place your hands under your glutes for support. Keep your legs straight and together, and lift them up towards the ceiling. Pause for a moment at the top, then slowly lower your legs back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0620-WhuFnR7.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0620-WhuFnR7.gif', 'WhuFnR7', '© Gym visual — https://gymvisual.com/'),
('0865', 'lying leg-hip raise', 'Túmbate sobre tu espalda con las piernas extendidas y los brazos a los lados. Coloca las manos debajo de los glúteos como apoyo. Activa el core y levanta las piernas del suelo, elevándolas hacia el techo. Haz una pausa por un momento en la parte superior, luego baja lentamente las piernas de vuelta ', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"hip flexors"}', 'Túmbate sobre tu espalda con las piernas extendidas y los brazos a los lados. Coloca las manos debajo de los glúteos como apoyo. Activa el core y levanta las piernas del suelo, elevándolas hacia el techo. Haz una pausa por un momento en la parte superior, luego baja lentamente las piernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on your back with your legs extended and your arms by your sides. Place your hands under your glutes for support. Engage your core and lift your legs off the ground, raising them towards the ceiling. Pause for a moment at the top, then slowly lower your legs back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0865-9IxJdtC.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0865-9IxJdtC.gif', '9IxJdtC', '© Gym visual — https://gymvisual.com/'),
('1301', 'machine inner chest press', 'Ajusta la altura del asiento y colócate en la máquina con la espalda totalmente apoyada en la almohadilla. Sujeta las asas con un agarre prono y coloca los codos en un ángulo de 90 grados. Empuja las asas hacia adelante hasta que los brazos queden completamente extendidos, exhalando durante el movim', 'chest', 'leverage machine', 'chest', 'chest', 'pectorals', '{"triceps","shoulders"}', 'Ajusta la altura del asiento y colócate en la máquina con la espalda totalmente apoyada en la almohadilla. Sujeta las asas con un agarre prono y coloca los codos en un ángulo de 90 grados. Empuja las asas hacia adelante hasta que los brazos queden completamente extendidos, exhalando durante el movimiento. Haz una pausa al final del movimiento y luego vuelve lentamente a la posición inicial, inhalando mientras lo haces. Repite el número de repeticiones deseado.', 'Adjust the seat height and position yourself on the machine with your back flat against the pad. Grasp the handles with an overhand grip and position your elbows at a 90-degree angle. Push the handles forward until your arms are fully extended, exhaling during the movement. Pause for a moment at the end of the movement, then slowly return to the starting position, inhaling as you do so. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1301-wDN97Ca.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1301-wDN97Ca.gif', 'wDN97Ca', '© Gym visual — https://gymvisual.com/'),
('0624', 'march sit (wall)', 'Ponte de pie con la espalda contra una pared y los pies separados a la altura de las caderas. Desliza lentamente la espalda hacia abajo por la pared hasta que las rodillas formen un ángulo de 90 grados. Levanta el pie derecho del suelo y lleva la rodilla hacia el pecho. Baja el pie derecho de nuevo ', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves"}', 'Ponte de pie con la espalda contra una pared y los pies separados a la altura de las caderas. Desliza lentamente la espalda hacia abajo por la pared hasta que las rodillas formen un ángulo de 90 grados. Levanta el pie derecho del suelo y lleva la rodilla hacia el pecho. Baja el pie derecho de nuevo y levanta el pie izquierdo del suelo, llevando la rodilla hacia el pecho. Continúa alternando entre levantar el pie derecho y el izquierdo el número de repeticiones deseado.', 'Stand with your back against a wall and your feet hip-width apart. Slowly slide your back down the wall until your knees are bent at a 90-degree angle. Lift your right foot off the ground and bring your knee towards your chest. Lower your right foot back down and lift your left foot off the ground, bringing your knee towards your chest. Continue alternating between lifting your right and left foot for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0624-sVQCCeG.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0624-sVQCCeG.gif', 'sVQCCeG', '© Gym visual — https://gymvisual.com/'),
('1353', 'medicine ball catch and overhead throw', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo un balón medicinal con ambas manos a la altura del pecho. Flexiona ligeramente las rodillas y activa el core. Baja el cuerpo a una posición de sentadilla, manteniendo la espalda recta y el pecho hacia arriba. Extiende explos', 'back', 'medicine ball', 'back', 'back', 'lats', '{"shoulders","core"}', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo un balón medicinal con ambas manos a la altura del pecho. Flexiona ligeramente las rodillas y activa el core. Baja el cuerpo a una posición de sentadilla, manteniendo la espalda recta y el pecho hacia arriba. Extiende explosivamente las caderas y las piernas, mientras lanzas simultáneamente el balón medicinal por encima de la cabeza. Suelta el balón en la parte más alta del movimiento y atrápalo cuando vaya bajando. Baja de nuevo el cuerpo a la posición de sentadilla y repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, holding a medicine ball in both hands at chest level. Bend your knees slightly and engage your core. Lower your body into a squat position, keeping your back straight and chest up. Explosively extend your hips and legs, while simultaneously throwing the medicine ball overhead. Release the ball at the top of the movement and catch it on the way down. Lower your body back into the squat position and repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1353-PsVS1QP.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1353-PsVS1QP.gif', 'PsVS1QP', '© Gym visual — https://gymvisual.com/'),
('1302', 'medicine ball chest pass', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo el balón medicinal a la altura del pecho. Extiende los brazos hacia adelante, empujando el balón medicinal con fuerza para alejarlo del pecho. Al soltar el balón, continúa el movimiento con los brazos y el torso, transfirien', 'chest', 'medicine ball', 'chest', 'chest', 'pectorals', '{"shoulders","triceps"}', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo el balón medicinal a la altura del pecho. Extiende los brazos hacia adelante, empujando el balón medicinal con fuerza para alejarlo del pecho. Al soltar el balón, continúa el movimiento con los brazos y el torso, transfiriendo el peso del pie de atrás al pie de adelante. Atrapa el balón cuando rebote en la pared o en tu compañero, y repite el movimiento de inmediato. Continúa durante el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, holding the medicine ball at chest level. Extend your arms forward, pushing the medicine ball away from your chest with force. As you release the ball, follow through with your arms and torso, transferring your weight from your back foot to your front foot. Catch the ball as it rebounds off the wall or partner, and immediately repeat the movement. Continue for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1302-aDoFKrE.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1302-aDoFKrE.gif', 'aDoFKrE', '© Gym visual — https://gymvisual.com/'),
('1303', 'medicine ball chest push from 3 point stance', 'Comienza en una posición de apoyo de 3 puntos con una mano sobre el balón medicinal y la otra en el suelo. Extiende las piernas y coloca tu cuerpo en línea recta. Baja el pecho hacia el suelo manteniendo la espalda recta. Empuja el balón medicinal alejándolo de tu cuerpo, extendiendo completamente e', 'chest', 'medicine ball', 'chest', 'chest', 'pectorals', '{"shoulders","triceps"}', 'Comienza en una posición de apoyo de 3 puntos con una mano sobre el balón medicinal y la otra en el suelo. Extiende las piernas y coloca tu cuerpo en línea recta. Baja el pecho hacia el suelo manteniendo la espalda recta. Empuja el balón medicinal alejándolo de tu cuerpo, extendiendo completamente el brazo. Vuelve a la posición inicial y repite el número de repeticiones deseado.', 'Start in a 3 point stance with one hand on the medicine ball and the other hand on the ground. Extend your legs and position your body in a straight line. Lower your chest towards the ground while keeping your back straight. Push the medicine ball away from your body, extending your arm fully. Return to the starting position and repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1303-dCJnuVq.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1303-dCJnuVq.gif', 'dCJnuVq', '© Gym visual — https://gymvisual.com/'),
('1304', 'medicine ball chest push multiple response', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo un balón medicinal a la altura del pecho. Extiende los brazos hacia adelante, alejando el balón medicinal de tu pecho. Haz una pausa por un momento y luego lleva lentamente el balón medicinal de vuelta al pecho. Repite el nú', 'chest', 'medicine ball', 'chest', 'chest', 'pectorals', '{"triceps","shoulders"}', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo un balón medicinal a la altura del pecho. Extiende los brazos hacia adelante, alejando el balón medicinal de tu pecho. Haz una pausa por un momento y luego lleva lentamente el balón medicinal de vuelta al pecho. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, holding a medicine ball at chest level. Extend your arms forward, pushing the medicine ball away from your chest. Pause for a moment, then slowly bring the medicine ball back to your chest. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1304-7aolH9D.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1304-7aolH9D.gif', '7aolH9D', '© Gym visual — https://gymvisual.com/'),
('1305', 'medicine ball chest push single response', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo el balón medicinal a la altura del pecho. Extiende los brazos hacia adelante, alejando el balón medicinal de tu pecho. Haz una pausa por un momento y luego lleva lentamente el balón medicinal de vuelta al pecho. Repite el nú', 'chest', 'medicine ball', 'chest', 'chest', 'pectorals', '{"triceps","shoulders"}', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo el balón medicinal a la altura del pecho. Extiende los brazos hacia adelante, alejando el balón medicinal de tu pecho. Haz una pausa por un momento y luego lleva lentamente el balón medicinal de vuelta al pecho. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, holding the medicine ball at chest level. Extend your arms forward, pushing the medicine ball away from your chest. Pause for a moment, then slowly bring the medicine ball back to your chest. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1305-jeHtrlO.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1305-jeHtrlO.gif', 'jeHtrlO', '© Gym visual — https://gymvisual.com/'),
('1312', 'medicine ball chest push with run release', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo un balón medicinal a la altura del pecho. Da un paso adelante con el pie derecho y, al mismo tiempo, empuja el balón medicinal hacia adelante, extendiendo completamente los brazos. Mientras empujas el balón hacia adelante, s', 'chest', 'medicine ball', 'chest', 'chest', 'pectorals', '{"triceps","shoulders","core"}', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo un balón medicinal a la altura del pecho. Da un paso adelante con el pie derecho y, al mismo tiempo, empuja el balón medicinal hacia adelante, extendiendo completamente los brazos. Mientras empujas el balón hacia adelante, suéltalo y déjalo rodar. Corre rápidamente hacia adelante y atrapa el balón antes de que toque el suelo. Una vez que atrapes el balón, llévalo de vuelta al pecho y repite el movimiento con el pie izquierdo adelante. Continúa alternando piernas y repitiendo el ejercicio el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, holding a medicine ball at chest level. Step forward with your right foot and simultaneously push the medicine ball forward, extending your arms fully. As you push the ball forward, release it and let it roll forward. Quickly run forward and catch the ball before it hits the ground. Once you catch the ball, bring it back to your chest and repeat the movement with your left foot forward. Continue alternating legs and repeating the exercise for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1312-pX9Elbe.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1312-pX9Elbe.gif', 'pX9Elbe', '© Gym visual — https://gymvisual.com/'),
('1701', 'medicine ball close grip push up', 'Comienza en una posición de plancha alta con las manos sobre el balón medicinal, separadas a la altura de los hombros. Baja el cuerpo hacia el suelo flexionando los codos, manteniéndolos cerca de los costados. Empuja de vuelta hasta la posición inicial, extendiendo completamente los brazos. Repite e', 'upper arms', 'medicine ball', 'upper arms', 'upper arms', 'triceps', '{"chest","shoulders"}', 'Comienza en una posición de plancha alta con las manos sobre el balón medicinal, separadas a la altura de los hombros. Baja el cuerpo hacia el suelo flexionando los codos, manteniéndolos cerca de los costados. Empuja de vuelta hasta la posición inicial, extendiendo completamente los brazos. Repite el número de repeticiones deseado.', 'Start in a high plank position with your hands on the medicine ball, shoulder-width apart. Lower your body towards the ground by bending your elbows, keeping them close to your sides. Push back up to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1701-8K7m2SS.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1701-8K7m2SS.gif', '8K7m2SS', '© Gym visual — https://gymvisual.com/'),
('1354', 'medicine ball overhead slam', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo un balón medicinal con ambas manos por encima de la cabeza. Activa el core y mantén la espalda recta. Flexiona ligeramente las rodillas y lanza con fuerza el balón medicinal contra el suelo frente a ti. Al lanzar el balón al', 'back', 'medicine ball', 'back', 'back', 'upper back', '{"shoulders","core"}', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo un balón medicinal con ambas manos por encima de la cabeza. Activa el core y mantén la espalda recta. Flexiona ligeramente las rodillas y lanza con fuerza el balón medicinal contra el suelo frente a ti. Al lanzar el balón al suelo, utiliza todo el cuerpo para generar potencia, incluidos los hombros y el core. Atrapa el balón al rebotar y repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, holding a medicine ball with both hands above your head. Engage your core and keep your back straight. Bend your knees slightly and forcefully slam the medicine ball down to the ground in front of you. As you slam the ball down, use your entire body to generate power, including your shoulders and core. Catch the ball on the bounce and repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1354-oHg8eop.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1354-oHg8eop.gif', 'oHg8eop', '© Gym visual — https://gymvisual.com/'),
('1750', 'medicine ball supine chest throw', 'Túmbate boca arriba en un banco con las rodillas flexionadas y los pies planos en el suelo. Sostén el balón medicinal con ambas manos, extendiendo los brazos rectos por encima del pecho. Baja el balón medicinal hacia el pecho, manteniendo los codos cerca del cuerpo. Empuja el balón medicinal explosi', 'upper arms', 'medicine ball', 'upper arms', 'upper arms', 'triceps', '{"chest","shoulders"}', 'Túmbate boca arriba en un banco con las rodillas flexionadas y los pies planos en el suelo. Sostén el balón medicinal con ambas manos, extendiendo los brazos rectos por encima del pecho. Baja el balón medicinal hacia el pecho, manteniendo los codos cerca del cuerpo. Empuja el balón medicinal explosivamente hacia arriba, extendiendo completamente los brazos y lanzando el balón lo más alto posible. Atrapa el balón medicinal y repite el número de repeticiones deseado.', 'Lie flat on your back on a bench with your knees bent and feet flat on the ground. Hold the medicine ball with both hands, extending your arms straight up above your chest. Lower the medicine ball towards your chest, keeping your elbows close to your body. Explosively push the medicine ball upwards, extending your arms fully and throwing the ball as high as possible. Catch the medicine ball and repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1750-Al3tP0D.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1750-Al3tP0D.gif', 'Al3tP0D', '© Gym visual — https://gymvisual.com/'),
('0627', 'mixed grip chin-up', 'Agarra la barra de dominadas con un agarre supino (las palmas hacia ti) y las manos un poco más separadas que la anchura de los hombros. Cuélgate de la barra con los brazos completamente extendidos y los pies fuera del suelo. Activa los músculos de la espalda y tira de tu cuerpo hacia la barra, llev', 'back', 'body weight', 'back', 'back', 'lats', '{"biceps","forearms"}', 'Agarra la barra de dominadas con un agarre supino (las palmas hacia ti) y las manos un poco más separadas que la anchura de los hombros. Cuélgate de la barra con los brazos completamente extendidos y los pies fuera del suelo. Activa los músculos de la espalda y tira de tu cuerpo hacia la barra, llevando el pecho por delante. Continúa subiendo hasta que la barbilla quede por encima de la barra. Haz una pausa por un momento en la parte alta y luego baja lentamente tu cuerpo, con control, hasta la posición inicial. Repite el número de repeticiones deseado.', 'Grab the pull-up bar with an underhand grip (palms facing towards you) and your hands slightly wider than shoulder-width apart. Hang from the bar with your arms fully extended and your feet off the ground. Engage your back muscles and pull your body up towards the bar, leading with your chest. Continue pulling until your chin is above the bar. Pause for a moment at the top, then slowly lower your body back down to the starting position with control. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0627-T8UpLkb.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0627-T8UpLkb.gif', 'T8UpLkb', '© Gym visual — https://gymvisual.com/'),
('3217', 'modified hindu push-up (male)', 'Comienza en posición de flexión con las manos un poco más separadas que la anchura de los hombros y los pies separados a la altura de las caderas. Baja el cuerpo hacia el suelo, flexionando los codos y manteniendo el core activado. Mientras bajas el cuerpo, desplaza el peso hacia atrás y eleva las c', 'chest', 'body weight', 'chest', 'chest', 'pectorals', '{"triceps","shoulders","core"}', 'Comienza en posición de flexión con las manos un poco más separadas que la anchura de los hombros y los pies separados a la altura de las caderas. Baja el cuerpo hacia el suelo, flexionando los codos y manteniendo el core activado. Mientras bajas el cuerpo, desplaza el peso hacia atrás y eleva las caderas hacia el techo, formando una V invertida con tu cuerpo. Sigue bajando el cuerpo hasta que el pecho quede justo por encima del suelo y luego invierte el movimiento, empujando las caderas hacia abajo y extendiendo los brazos para volver a la posición inicial. Repite el número de repeticiones deseado.', 'Start in a push-up position with your hands slightly wider than shoulder-width apart and your feet hip-width apart. Lower your body towards the ground, bending your elbows and keeping your core engaged. As you lower your body, shift your weight back and lift your hips up towards the ceiling, creating an inverted V shape with your body. Continue to lower your body until your chest is just above the ground, then reverse the movement, pushing your hips back down and extending your arms to return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3217-epOSYUZ.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3217-epOSYUZ.gif', 'epOSYUZ', '© Gym visual — https://gymvisual.com/'),
('1421', 'modified push up to lower arms', 'Comienza en posición de flexión con las manos directamente debajo de los hombros y el cuerpo en línea recta. Baja el cuerpo hacia el suelo flexionando los codos, manteniéndolos cerca de tu costado. Cuando los codos formen un ángulo de 90 grados, baja los antebrazos hasta el suelo, manteniendo los co', 'lower arms', 'body weight', 'lower arms', 'lower arms', 'forearms', '{"triceps","chest","shoulders"}', 'Comienza en posición de flexión con las manos directamente debajo de los hombros y el cuerpo en línea recta. Baja el cuerpo hacia el suelo flexionando los codos, manteniéndolos cerca de tu costado. Cuando los codos formen un ángulo de 90 grados, baja los antebrazos hasta el suelo, manteniendo los codos justo debajo de los hombros. Haz una pausa por un momento y luego empuja con las palmas para llevar los antebrazos de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Start in a push-up position with your hands directly under your shoulders and your body in a straight line. Lower your body down towards the ground by bending your elbows, keeping them close to your sides. Once your elbows are at a 90-degree angle, lower your forearms to the ground, keeping your elbows directly under your shoulders. Pause for a moment, then push through your palms to lift your forearms back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1421-arvaszz.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1421-arvaszz.gif', 'arvaszz', '© Gym visual — https://gymvisual.com/'),
('0628', 'monster walk', 'Coloca una banda elástica alrededor de los tobillos. Coloca los pies separados a la altura de los hombros y flexiona ligeramente las rodillas. Da un paso hacia el lado con el pie derecho, manteniendo la tensión en la banda elástica. Continúa con el pie izquierdo, dando un paso lateral para volver a ', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'glutes', '{"hamstrings","quadriceps"}', 'Coloca una banda elástica alrededor de los tobillos. Coloca los pies separados a la altura de los hombros y flexiona ligeramente las rodillas. Da un paso hacia el lado con el pie derecho, manteniendo la tensión en la banda elástica. Continúa con el pie izquierdo, dando un paso lateral para volver a la posición inicial. Repite el número de repeticiones deseado, luego cambia de lado.', 'Place a resistance band around your ankles. Stand with your feet shoulder-width apart and slightly bend your knees. Take a step to the side with your right foot, maintaining tension on the resistance band. Follow with your left foot, stepping to the side to return to the starting position. Repeat for the desired number of repetitions, then switch sides.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0628-O95afRA.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0628-O95afRA.gif', 'O95afRA', '© Gym visual — https://gymvisual.com/'),
('0630', 'mountain climber', 'Comienza en una posición de plancha alta con las manos justo debajo de los hombros y el cuerpo en línea recta. Activa el core y lleva la rodilla derecha hacia el pecho, luego cambia rápidamente y lleva la rodilla izquierda hacia el pecho. Continúa alternando las piernas con un movimiento de carrera,', 'cardio', 'body weight', 'cardio', 'cardio', 'cardiovascular system', '{"core","shoulders","triceps"}', 'Comienza en una posición de plancha alta con las manos justo debajo de los hombros y el cuerpo en línea recta. Activa el core y lleva la rodilla derecha hacia el pecho, luego cambia rápidamente y lleva la rodilla izquierda hacia el pecho. Continúa alternando las piernas con un movimiento de carrera, manteniendo las caderas bajas y el core activado. Mantén un ritmo constante y respira de forma regular durante todo el ejercicio. Repite el número de repeticiones deseado.', 'Start in a high plank position with your hands directly under your shoulders and your body in a straight line. Engage your core and bring your right knee towards your chest, then quickly switch and bring your left knee towards your chest. Continue alternating legs in a running motion, keeping your hips low and your core engaged. Maintain a steady pace and breathe evenly throughout the exercise. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0630-RJgzwny.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0630-RJgzwny.gif', 'RJgzwny', '© Gym visual — https://gymvisual.com/'),
('0631', 'muscle up', 'Comienza colgándote de una barra de dominadas con las palmas hacia afuera y los brazos completamente extendidos. Activa el core y tira de tu cuerpo hacia arriba, hacia la barra, guiando con el pecho. Al llegar a la parte alta del movimiento, cambia el agarre de modo que las palmas queden hacia ti. S', 'back', 'body weight', 'back', 'back', 'lats', '{"biceps","triceps","shoulders","chest"}', 'Comienza colgándote de una barra de dominadas con las palmas hacia afuera y los brazos completamente extendidos. Activa el core y tira de tu cuerpo hacia arriba, hacia la barra, guiando con el pecho. Al llegar a la parte alta del movimiento, cambia el agarre de modo que las palmas queden hacia ti. Sigue tirando hacia arriba hasta que el pecho quede por encima de la barra y los brazos estén completamente flexionados. Invierte el movimiento bajando lentamente de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Start by hanging from a pull-up bar with your palms facing away from you and your arms fully extended. Engage your core and pull your body up towards the bar, leading with your chest. As you reach the top of the movement, transition your grip so that your palms are facing towards you. Continue pulling yourself up until your chest is above the bar and your arms are fully flexed. Reverse the movement by slowly lowering yourself back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0631-yJUHKTn.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0631-yJUHKTn.gif', 'yJUHKTn', '© Gym visual — https://gymvisual.com/'),
('1401', 'muscle-up (on vertical bar)', 'Comienza colgándote de una barra vertical con las palmas hacia afuera y los brazos completamente extendidos. Activa el core y tira de tu cuerpo hacia arriba, hacia la barra, guiando con el pecho. Al subir tu cuerpo, inclínate ligeramente hacia atrás y lleva los codos hacia los costados. Sigue tirand', 'back', 'body weight', 'back', 'back', 'lats', '{"biceps","triceps","forearms"}', 'Comienza colgándote de una barra vertical con las palmas hacia afuera y los brazos completamente extendidos. Activa el core y tira de tu cuerpo hacia arriba, hacia la barra, guiando con el pecho. Al subir tu cuerpo, inclínate ligeramente hacia atrás y lleva los codos hacia los costados. Sigue tirando hasta que el pecho llegue a la barra y los codos estén completamente flexionados. Haz una pausa breve en la parte más alta, luego baja lentamente de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Start by hanging from a vertical bar with your palms facing away from you and your arms fully extended. Engage your core and pull your body up towards the bar, leading with your chest. As you pull yourself up, lean back slightly and bring your elbows towards your sides. Continue pulling until your chest reaches the bar and your elbows are fully bent. Pause for a moment at the top, then slowly lower yourself back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1401-Af0EW2I.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1401-Af0EW2I.gif', 'Af0EW2I', '© Gym visual — https://gymvisual.com/'),
('2328', 'narrow push-up on exercise ball', 'Coloca el balón de estabilidad en el suelo y ponte en posición de flexión con las manos sobre el balón, un poco más juntas que la anchura de los hombros. Activa el core y mantén el cuerpo en línea recta de la cabeza a los pies. Baja el pecho hacia el balón flexionando los codos, manteniéndolos cerca', 'upper arms', 'stability ball', 'upper arms', 'upper arms', 'triceps', '{"chest","shoulders"}', 'Coloca el balón de estabilidad en el suelo y ponte en posición de flexión con las manos sobre el balón, un poco más juntas que la anchura de los hombros. Activa el core y mantén el cuerpo en línea recta de la cabeza a los pies. Baja el pecho hacia el balón flexionando los codos, manteniéndolos cerca del cuerpo. Haz una pausa breve en la parte baja, luego empújate de nuevo hacia arriba a la posición inicial estirando los brazos. Repite el número de repeticiones deseado.', 'Place the stability ball on the ground and position yourself in a push-up position with your hands on the ball, slightly narrower than shoulder-width apart. Engage your core and keep your body in a straight line from head to toe. Lower your chest towards the ball by bending your elbows, keeping them close to your body. Pause for a moment at the bottom, then push yourself back up to the starting position by straightening your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2328-4cWjYEN.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2328-4cWjYEN.gif', '4cWjYEN', '© Gym visual — https://gymvisual.com/'),
('1403', 'neck side stretch', 'Ponte de pie o siéntate erguido con los hombros relajados. Inclina la cabeza hacia un lado, llevando la oreja hacia el hombro. Mantén el estiramiento durante 15-30 segundos. Repite del otro lado. Realiza de 2 a 4 series por cada lado.', 'neck', 'body weight', 'neck', 'neck', 'levator scapulae', '{"trapezius","sternocleidomastoid"}', 'Ponte de pie o siéntate erguido con los hombros relajados. Inclina la cabeza hacia un lado, llevando la oreja hacia el hombro. Mantén el estiramiento durante 15-30 segundos. Repite del otro lado. Realiza de 2 a 4 series por cada lado.', 'Stand or sit up straight with your shoulders relaxed. Tilt your head to one side, bringing your ear towards your shoulder. Hold the stretch for 15-30 seconds. Repeat on the other side. Perform 2-4 sets on each side.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1403-x2chWLO.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1403-x2chWLO.gif', 'x2chWLO', '© Gym visual — https://gymvisual.com/'),
('0634', 'negative crunch', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Coloca las manos detrás de la cabeza con los codos apuntando hacia afuera. Activando el abdomen, levanta lentamente la parte superior del cuerpo del suelo, curvándote hacia adelante hasta que tu torso forme un áng', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"hip flexors"}', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Coloca las manos detrás de la cabeza con los codos apuntando hacia afuera. Activando el abdomen, levanta lentamente la parte superior del cuerpo del suelo, curvándote hacia adelante hasta que tu torso forme un ángulo de 45 grados. Haz una pausa por un momento en la parte superior, luego baja lentamente la parte superior del cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on your back with your knees bent and feet flat on the ground. Place your hands behind your head with your elbows pointing outwards. Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle. Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0634-szIn2UK.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0634-szIn2UK.gif', 'szIn2UK', '© Gym visual — https://gymvisual.com/'),
('1495', 'oblique crunch v. 2', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Coloca las manos detrás de la cabeza o crúzalas sobre el pecho. Activa el abdomen y levanta las escápulas del suelo, rotando el torso hacia un lado. Haz una pausa por un momento y luego baja las escápulas de nuevo', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"obliques"}', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Coloca las manos detrás de la cabeza o crúzalas sobre el pecho. Activa el abdomen y levanta las escápulas del suelo, rotando el torso hacia un lado. Haz una pausa por un momento y luego baja las escápulas de nuevo a la posición inicial. Repite del otro lado. Continúa alternando lados durante el número de repeticiones deseado.', 'Lie on your back with your knees bent and feet flat on the ground. Place your hands behind your head or cross them over your chest. Engage your abs and lift your shoulder blades off the ground, rotating your torso to one side. Pause for a moment, then lower your shoulder blades back down to the starting position. Repeat on the other side. Continue alternating sides for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1495-cJgSTmh.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1495-cJgSTmh.gif', 'cJgSTmh', '© Gym visual — https://gymvisual.com/'),
('0635', 'oblique crunches floor', 'Túmbate boca arriba con las rodillas flexionadas y los pies planos en el suelo. Coloca las manos detrás de la cabeza o crúzalas sobre el pecho. Activa el abdomen y levanta las escápulas del suelo, rotando el torso hacia un lado. Haz una pausa por un momento y luego baja las escápulas de nuevo hasta ', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"obliques"}', 'Túmbate boca arriba con las rodillas flexionadas y los pies planos en el suelo. Coloca las manos detrás de la cabeza o crúzalas sobre el pecho. Activa el abdomen y levanta las escápulas del suelo, rotando el torso hacia un lado. Haz una pausa por un momento y luego baja las escápulas de nuevo hasta el suelo. Repite hacia el otro lado, alternando los lados en cada repetición.', 'Lie on your back with your knees bent and feet flat on the floor. Place your hands behind your head or cross them over your chest. Engage your abs and lift your shoulder blades off the floor, rotating your torso to one side. Pause for a moment, then lower your shoulder blades back down to the floor. Repeat on the other side, alternating sides with each repetition.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0635-QUDd8WS.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0635-QUDd8WS.gif', 'QUDd8WS', '© Gym visual — https://gymvisual.com/'),
('0636', 'olympic barbell hammer curl', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una barra olímpica con un agarre prono. Deja que la barra cuelgue a la altura de los brazos frente a tus muslos, con las palmas hacia tu cuerpo. Manteniendo los brazos superiores fijos, exhala y levanta el peso mientras contraes', 'upper arms', 'olympic barbell', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una barra olímpica con un agarre prono. Deja que la barra cuelgue a la altura de los brazos frente a tus muslos, con las palmas hacia tu cuerpo. Manteniendo los brazos superiores fijos, exhala y levanta el peso mientras contraes los bíceps. Continúa levantando la barra hasta que los bíceps estén completamente contraídos y la barra esté a la altura de los hombros. Mantén la posición contraída durante una breve pausa mientras aprietas los bíceps. Inhala y comienza a bajar lentamente la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand up straight with your feet shoulder-width apart and hold an Olympic barbell with an overhand grip. Let the barbell hang at arm''s length in front of your thighs, with your palms facing your body. Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Continue to raise the barbell until your biceps are fully contracted and the barbell is at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Inhale and slowly begin to lower the barbell back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0636-o1ntciW.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0636-o1ntciW.gif', 'o1ntciW', '© Gym visual — https://gymvisual.com/'),
('0637', 'olympic barbell triceps extension', 'Comienza de pie con los pies separados a la altura de los hombros y sosteniendo la barra con un agarre prono. Levanta la barra por encima de la cabeza, extendiendo completamente los brazos. Manteniendo los brazos superiores cerca de la cabeza, baja lentamente la barra detrás de la cabeza flexionando', 'upper arms', 'olympic barbell', 'upper arms', 'upper arms', 'triceps', '{"shoulders"}', 'Comienza de pie con los pies separados a la altura de los hombros y sosteniendo la barra con un agarre prono. Levanta la barra por encima de la cabeza, extendiendo completamente los brazos. Manteniendo los brazos superiores cerca de la cabeza, baja lentamente la barra detrás de la cabeza flexionando los codos. Haz una pausa por un momento y luego extiende los brazos de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Start by standing with your feet shoulder-width apart and holding the barbell with an overhand grip. Raise the barbell above your head, fully extending your arms. Keeping your upper arms close to your head, slowly lower the barbell behind your head by bending your elbows. Pause for a moment, then extend your arms back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0637-wu5LXwz.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0637-wu5LXwz.gif', 'wu5LXwz', '© Gym visual — https://gymvisual.com/'),
('1355', 'one arm against wall', 'Ponte de pie frente a una pared con los pies separados a la altura de los hombros. Extiende un brazo recto hacia adelante y coloca la palma contra la pared. Activa el core e inclina el cuerpo hacia adelante, manteniendo el brazo recto y la espalda plana. Empuja lentamente la pared con la palma, acti', 'back', 'body weight', 'back', 'back', 'lats', '{"shoulders","triceps"}', 'Ponte de pie frente a una pared con los pies separados a la altura de los hombros. Extiende un brazo recto hacia adelante y coloca la palma contra la pared. Activa el core e inclina el cuerpo hacia adelante, manteniendo el brazo recto y la espalda plana. Empuja lentamente la pared con la palma, activando los dorsales. Mantén la posición durante unos segundos, luego suelta y repite con el otro brazo.', 'Stand facing a wall with your feet shoulder-width apart. Extend one arm straight out in front of you and place your palm against the wall. Engage your core and lean your body forward, keeping your arm straight and your back flat. Slowly push against the wall with your palm, activating your lat muscles. Hold the position for a few seconds, then release and repeat with the other arm.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1355-ZZTGMKh.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1355-ZZTGMKh.gif', 'ZZTGMKh', '© Gym visual — https://gymvisual.com/'),
('0638', 'one arm chin-up', 'Ponte de pie frente a una barra de dominadas con los pies separados a la altura de los hombros. Estírate y agarra la barra con un agarre supino, con una mano sujetando la barra y la otra sosteniendo la muñeca como apoyo. Cuélgate de la barra con el brazo completamente extendido, manteniendo el cuerp', 'back', 'body weight', 'back', 'back', 'lats', '{"biceps","forearms"}', 'Ponte de pie frente a una barra de dominadas con los pies separados a la altura de los hombros. Estírate y agarra la barra con un agarre supino, con una mano sujetando la barra y la otra sosteniendo la muñeca como apoyo. Cuélgate de la barra con el brazo completamente extendido, manteniendo el cuerpo recto y el core activado. Tira de tu cuerpo hacia la barra flexionando el codo y contrayendo los músculos de la espalda. Continúa subiendo hasta que la barbilla quede por encima de la barra, luego bájate lentamente de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia de brazo y repite.', 'Stand facing a pull-up bar with your feet shoulder-width apart. Reach up and grab the bar with an underhand grip, with one hand gripping the bar and the other hand holding your wrist for support. Hang from the bar with your arm fully extended, keeping your body straight and your core engaged. Pull yourself up towards the bar by bending your elbow and squeezing your back muscles. Continue pulling until your chin is above the bar, then slowly lower yourself back down to the starting position. Repeat for the desired number of repetitions, then switch arms and repeat.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0638-HjdqmZa.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0638-HjdqmZa.gif', 'HjdqmZa', '© Gym visual — https://gymvisual.com/'),
('0639', 'one arm dip', 'Ponte de pie de espaldas a un banco o silla, con los pies separados a la altura de los hombros. Coloca una mano en el banco o silla detrás de ti, con los dedos apuntando hacia tu cuerpo. Extiende las piernas hacia adelante, manteniendo los talones en el suelo. Flexiona los codos y baja el cuerpo hac', 'upper arms', 'body weight', 'upper arms', 'upper arms', 'triceps', '{"chest","shoulders"}', 'Ponte de pie de espaldas a un banco o silla, con los pies separados a la altura de los hombros. Coloca una mano en el banco o silla detrás de ti, con los dedos apuntando hacia tu cuerpo. Extiende las piernas hacia adelante, manteniendo los talones en el suelo. Flexiona los codos y baja el cuerpo hacia el suelo, manteniendo la espalda cerca del banco o silla. Haz una pausa por un momento en la parte baja y luego empuja con las palmas para estirar los brazos y volver a la posición inicial. Repite el número de repeticiones deseado, luego cambia de lado y repite con el otro brazo.', 'Stand facing away from a bench or chair, with your feet shoulder-width apart. Place one hand on the bench or chair behind you, fingers pointing towards your body. Extend your legs out in front of you, keeping your heels on the ground. Bend your elbows and lower your body towards the ground, keeping your back close to the bench or chair. Pause for a moment at the bottom, then push through your palms to straighten your arms and return to the starting position. Repeat for the desired number of repetitions, then switch sides and repeat with the other arm.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0639-FAoIFMw.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0639-FAoIFMw.gif', 'FAoIFMw', '© Gym visual — https://gymvisual.com/'),
('0640', 'one arm slam (with medicine ball)', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo el balón medicinal con una mano frente a la cintura. Flexiona ligeramente las rodillas y activa el core. Eleva el balón medicinal por encima de la cabeza, extendiendo completamente el brazo. Lanza con fuerza el balón medicin', 'waist', 'medicine ball', 'waist', 'waist', 'abs', '{"shoulders","back"}', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo el balón medicinal con una mano frente a la cintura. Flexiona ligeramente las rodillas y activa el core. Eleva el balón medicinal por encima de la cabeza, extendiendo completamente el brazo. Lanza con fuerza el balón medicinal contra el suelo, usando el core y los hombros para generar potencia. Atrapa el balón medicinal al rebotar y repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, holding the medicine ball with one hand in front of your waist. Bend your knees slightly and engage your core. Raise the medicine ball above your head, fully extending your arm. Forcefully slam the medicine ball down to the ground, using your core and shoulders to generate power. Catch the medicine ball on the bounce and repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0640-jCrtE9b.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0640-jCrtE9b.gif', 'jCrtE9b', '© Gym visual — https://gymvisual.com/'),
('1773', 'one arm towel row', 'Ponte de pie con los pies separados a la altura de los hombros, las rodillas ligeramente flexionadas, y sujeta una toalla con una mano. Inclínate hacia adelante desde la cintura, manteniendo la espalda recta y el core activado. Extiende completamente el brazo, dejando que la toalla cuelgue frente a ', 'back', 'body weight', 'back', 'back', 'upper back', '{"biceps","forearms"}', 'Ponte de pie con los pies separados a la altura de los hombros, las rodillas ligeramente flexionadas, y sujeta una toalla con una mano. Inclínate hacia adelante desde la cintura, manteniendo la espalda recta y el core activado. Extiende completamente el brazo, dejando que la toalla cuelgue frente a ti. Tira de la toalla hacia el pecho, juntando los omóplatos. Haz una pausa breve en la parte más alta, luego baja lentamente la toalla de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia de brazo.', 'Stand with your feet shoulder-width apart, knees slightly bent, and hold a towel with one hand. Bend forward at the waist, keeping your back straight and your core engaged. Extend your arm fully, allowing the towel to hang in front of you. Pull the towel towards your chest, squeezing your shoulder blades together. Pause for a moment at the top, then slowly lower the towel back to the starting position. Repeat for the desired number of repetitions, then switch arms.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1773-bKWbrTA.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1773-bKWbrTA.gif', 'bKWbrTA', '© Gym visual — https://gymvisual.com/'),
('1386', 'one leg donkey calf raise', 'Ponte de pie con los pies separados a la altura de los hombros, con las puntas de los pies apuntando hacia adelante. Coloca las manos sobre una superficie estable para apoyarte, como una pared o una barra. Levanta una pierna del suelo, manteniendo la rodilla ligeramente flexionada. Eleva el talón lo', 'lower legs', 'body weight', 'lower legs', 'lower legs', 'calves', '{"hamstrings","glutes"}', 'Ponte de pie con los pies separados a la altura de los hombros, con las puntas de los pies apuntando hacia adelante. Coloca las manos sobre una superficie estable para apoyarte, como una pared o una barra. Levanta una pierna del suelo, manteniendo la rodilla ligeramente flexionada. Eleva el talón lo más alto posible, usando los músculos de la pantorrilla. Haz una pausa por un momento en la parte superior, luego baja lentamente el talón de vuelta hacia abajo. Repite el número de repeticiones deseado, luego cambia de pierna.', 'Stand with your feet shoulder-width apart, toes pointing forward. Place your hands on a stable surface for support, such as a wall or a bar. Lift one leg off the ground, keeping your knee slightly bent. Raise your heel as high as possible, using your calf muscles. Pause for a moment at the top, then slowly lower your heel back down. Repeat for the desired number of repetitions, then switch legs.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1386-A2upspL.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1386-A2upspL.gif', 'A2upspL', '© Gym visual — https://gymvisual.com/'),
('1387', 'one leg floor calf raise', 'Ponte de pie con los pies separados a la altura de las caderas y coloca las manos en una pared u objeto firme para mantener el equilibrio. Levanta un pie del suelo y mantén el equilibrio sobre el otro pie. Levanta lentamente el talón del suelo, elevando el cuerpo sobre las puntas de los pies. Haz un', 'lower legs', 'body weight', 'lower legs', 'lower legs', 'calves', '{"ankles","feet"}', 'Ponte de pie con los pies separados a la altura de las caderas y coloca las manos en una pared u objeto firme para mantener el equilibrio. Levanta un pie del suelo y mantén el equilibrio sobre el otro pie. Levanta lentamente el talón del suelo, elevando el cuerpo sobre las puntas de los pies. Haz una pausa por un momento en la parte superior, luego baja lentamente el talón de vuelta a la posición inicial. Repite el número de repeticiones deseado y luego cambia de pierna y repite.', 'Stand with your feet hip-width apart and place your hands on a wall or sturdy object for balance. Lift one foot off the ground and balance on the other foot. Slowly raise your heel off the ground, lifting your body up onto the ball of your foot. Pause for a moment at the top, then slowly lower your heel back down to the starting position. Repeat for the desired number of repetitions, then switch legs and repeat.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1387-0jp9Rlz.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1387-0jp9Rlz.gif', '0jp9Rlz', '© Gym visual — https://gymvisual.com/'),
('1476', 'one leg squat', 'Ponte de pie con los pies separados a la altura de los hombros. Extiende una pierna hacia adelante, manteniéndola elevada del suelo. Flexiona la pierna de apoyo y baja el cuerpo como si te sentaras en una silla. Mantén el pecho arriba y la espalda recta. Empuja con el talón para regresar a la posici', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves"}', 'Ponte de pie con los pies separados a la altura de los hombros. Extiende una pierna hacia adelante, manteniéndola elevada del suelo. Flexiona la pierna de apoyo y baja el cuerpo como si te sentaras en una silla. Mantén el pecho arriba y la espalda recta. Empuja con el talón para regresar a la posición inicial. Repite con la otra pierna.', 'Stand with your feet shoulder-width apart. Extend one leg forward, keeping it off the ground. Bend your standing leg and lower your body down as if sitting back into a chair. Keep your chest up and your back straight. Push through your heel to return to the starting position. Repeat with the other leg.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1476-C31LMnP.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1476-C31LMnP.gif', 'C31LMnP', '© Gym visual — https://gymvisual.com/'),
('0641', 'otis up', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Coloca las manos detrás de la cabeza con los codos apuntando hacia afuera. Activando el abdomen, levanta lentamente la parte superior del cuerpo del suelo, curvándote hacia adelante hasta que tu torso forme un áng', 'waist', 'weighted', 'waist', 'waist', 'abs', '{"hip flexors","lower back"}', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Coloca las manos detrás de la cabeza con los codos apuntando hacia afuera. Activando el abdomen, levanta lentamente la parte superior del cuerpo del suelo, curvándote hacia adelante hasta que tu torso forme un ángulo de 45 grados. Haz una pausa por un momento en la parte superior, luego baja lentamente la parte superior del cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on your back with your knees bent and feet flat on the ground. Place your hands behind your head with your elbows pointing outwards. Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle. Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0641-UVL20oz.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0641-UVL20oz.gif', 'UVL20oz', '© Gym visual — https://gymvisual.com/'),
('0642', 'outside leg kick push-up', 'Comienza en posición de flexión con las manos un poco más separadas que la anchura de los hombros y los pies juntos. Baja el cuerpo hacia el suelo flexionando los codos, manteniendo la espalda recta y el core activado. Al empujar de vuelta hacia arriba, lanza una pierna hacia el lado, extendiéndola ', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves"}', 'Comienza en posición de flexión con las manos un poco más separadas que la anchura de los hombros y los pies juntos. Baja el cuerpo hacia el suelo flexionando los codos, manteniendo la espalda recta y el core activado. Al empujar de vuelta hacia arriba, lanza una pierna hacia el lado, extendiéndola completamente y activando los glúteos. Vuelve a colocar la pierna en la posición inicial y repite la flexión, alternando las piernas en cada repetición. Continúa alternando las patadas de pierna y las flexiones el número de repeticiones deseado.', 'Start in a push-up position with your hands slightly wider than shoulder-width apart and your feet together. Lower your body towards the ground by bending your elbows, keeping your back straight and core engaged. As you push back up, kick one leg out to the side, extending it fully and engaging your glutes. Return your leg to the starting position and repeat the push-up, alternating legs with each repetition. Continue alternating leg kicks and push-ups for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0642-jNU1gFQ.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0642-jNU1gFQ.gif', 'jNU1gFQ', '© Gym visual — https://gymvisual.com/'),
('0643', 'overhead triceps stretch', 'Ponte de pie o siéntate erguido con los pies separados a la altura de los hombros. Extiende un brazo por encima de la cabeza, flexionando el codo de modo que la mano llegue hacia la escápula opuesta. Con la otra mano, tira suavemente del codo del brazo extendido hacia el lado opuesto de la cabeza, s', 'upper arms', 'body weight', 'upper arms', 'upper arms', 'triceps', '{"shoulders"}', 'Ponte de pie o siéntate erguido con los pies separados a la altura de los hombros. Extiende un brazo por encima de la cabeza, flexionando el codo de modo que la mano llegue hacia la escápula opuesta. Con la otra mano, tira suavemente del codo del brazo extendido hacia el lado opuesto de la cabeza, sintiendo un estiramiento en el tríceps. Mantén el estiramiento durante 15-30 segundos, luego suelta. Repite del otro lado.', 'Stand or sit upright with your feet shoulder-width apart. Extend one arm overhead, bending at the elbow so that your hand reaches towards the opposite shoulder blade. With your other hand, gently pull the elbow of the extended arm towards the opposite side of your head, feeling a stretch in your triceps. Hold the stretch for 15-30 seconds, then release. Repeat on the other side.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0643-Z5YStHW.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0643-Z5YStHW.gif', 'Z5YStHW', '© Gym visual — https://gymvisual.com/'),
('3147', 'pelvic tilt', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Coloca las manos a los lados del cuerpo. Activa el abdomen e inclina la pelvis hacia arriba, presionando la zona lumbar contra el suelo. Mantén esta posición durante unos segundos, concentrándote en contraer el ab', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"lower back"}', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Coloca las manos a los lados del cuerpo. Activa el abdomen e inclina la pelvis hacia arriba, presionando la zona lumbar contra el suelo. Mantén esta posición durante unos segundos, concentrándote en contraer el abdomen. Deshaz la inclinación y vuelve a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on your back with your knees bent and feet flat on the ground. Place your hands by your sides. Engage your abs and tilt your pelvis upward, pressing your lower back into the ground. Hold this position for a few seconds, focusing on contracting your abs. Release the tilt and return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3147-NKJ8o6x.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3147-NKJ8o6x.gif', 'NKJ8o6x', '© Gym visual — https://gymvisual.com/'),
('1422', 'pelvic tilt into bridge', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Coloca los brazos a los lados del cuerpo con las palmas hacia abajo. Activa los glúteos y los músculos del core. Inclina la pelvis hacia arriba, levantando las caderas del suelo. Mantén la posición de puente duran', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'glutes', '{"hamstrings","core"}', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Coloca los brazos a los lados del cuerpo con las palmas hacia abajo. Activa los glúteos y los músculos del core. Inclina la pelvis hacia arriba, levantando las caderas del suelo. Mantén la posición de puente durante unos segundos. Baja lentamente las caderas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie on your back with your knees bent and feet flat on the ground. Place your arms by your sides with your palms facing down. Engage your glutes and core muscles. Tilt your pelvis upward, lifting your hips off the ground. Hold the bridge position for a few seconds. Slowly lower your hips back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1422-D9qe7CM.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1422-D9qe7CM.gif', 'D9qe7CM', '© Gym visual — https://gymvisual.com/'),
('1388', 'peroneals stretch', 'Siéntate en el suelo con las piernas extendidas frente a ti. Enrolla la cuerda alrededor de la planta del pie y sujeta los extremos de la cuerda con las manos. Tira suavemente de la cuerda hacia ti, flexionando el pie y estirando los músculos de la pantorrilla. Mantén el estiramiento durante 15-30 s', 'lower legs', 'rope', 'lower legs', 'lower legs', 'calves', '{"ankles","feet"}', 'Siéntate en el suelo con las piernas extendidas frente a ti. Enrolla la cuerda alrededor de la planta del pie y sujeta los extremos de la cuerda con las manos. Tira suavemente de la cuerda hacia ti, flexionando el pie y estirando los músculos de la pantorrilla. Mantén el estiramiento durante 15-30 segundos. Suelta la tensión de la cuerda y repite el estiramiento en la otra pierna. Repite el número de repeticiones deseado.', 'Sit on the ground with your legs extended in front of you. Loop the rope around the ball of your foot and hold the ends of the rope with your hands. Gently pull the rope towards you, flexing your foot and stretching your calf muscles. Hold the stretch for 15-30 seconds. Release the tension on the rope and repeat the stretch on the other leg. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1388-XhfS1DZ.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1388-XhfS1DZ.gif', 'XhfS1DZ', '© Gym visual — https://gymvisual.com/'),
('3662', 'pike-to-cobra push-up', 'Comienza en posición de flexión con las manos un poco más separadas que la anchura de los hombros y los pies juntos. Activa el core y eleva las caderas hacia el techo, formando una V invertida con tu cuerpo. Baja la parte superior del cuerpo hacia el suelo flexionando los codos, manteniéndolos cerca', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'glutes', '{"core","shoulders","triceps"}', 'Comienza en posición de flexión con las manos un poco más separadas que la anchura de los hombros y los pies juntos. Activa el core y eleva las caderas hacia el techo, formando una V invertida con tu cuerpo. Baja la parte superior del cuerpo hacia el suelo flexionando los codos, manteniéndolos cerca del cuerpo. Al bajar, desplaza el peso hacia adelante y haz la transición a una postura de cobra estirando los brazos y elevando el pecho. Invierte el movimiento flexionando los codos y bajando el pecho de nuevo hacia el suelo. Empuja con las manos para volver a la posición de V invertida. Continúa el movimiento bajando las caderas de nuevo hacia el suelo, volviendo a la posición inicial de flexión. Repite el número de repeticiones deseado.', 'Start in a push-up position with your hands slightly wider than shoulder-width apart and your feet together. Engage your core and lift your hips up towards the ceiling, forming an inverted V shape with your body. Lower your upper body towards the ground by bending your elbows, keeping them close to your body. As you lower down, shift your weight forward and transition into a cobra pose by straightening your arms and lifting your chest up. Reverse the movement by bending your elbows and lowering your chest back down towards the ground. Push through your hands to return to the inverted V position. Continue the movement by lowering your hips back down towards the ground, returning to the starting push-up position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3662-XPUDTt7.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3662-XPUDTt7.gif', 'XPUDTt7', '© Gym visual — https://gymvisual.com/'),
('1306', 'plyo push up', 'Comienza en posición de plancha alta con las manos un poco más separadas que el ancho de los hombros. Baja el pecho hacia el suelo flexionando los codos, manteniendo el cuerpo en línea recta. Empuja explosivamente contra el suelo, usando los músculos del pecho para impulsar la parte superior del cue', 'chest', 'body weight', 'chest', 'chest', 'pectorals', '{"triceps","shoulders","core"}', 'Comienza en posición de plancha alta con las manos un poco más separadas que el ancho de los hombros. Baja el pecho hacia el suelo flexionando los codos, manteniendo el cuerpo en línea recta. Empuja explosivamente contra el suelo, usando los músculos del pecho para impulsar la parte superior del cuerpo fuera del suelo. Aterriza suavemente con las manos de vuelta en la posición inicial. Repite el número de repeticiones deseado.', 'Start in a high plank position with your hands slightly wider than shoulder-width apart. Lower your chest towards the ground by bending your elbows, keeping your body in a straight line. Push explosively off the ground, using your chest muscles to propel your upper body off the ground. Land softly with your hands back in the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1306-Snj1wSv.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1306-Snj1wSv.gif', 'Snj1wSv', '© Gym visual — https://gymvisual.com/'),
('1687', 'posterior step to overhead reach', 'Ponte de pie con los pies separados a la altura de las caderas y los brazos a los lados del cuerpo. Da un paso hacia atrás con el pie derecho, apoyándote en la punta del pie. Flexiona la rodilla izquierda y baja el cuerpo a una posición de zancada. Mientras bajas a la zancada, lleva simultáneamente ', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"glutes","hamstrings","quadriceps","shoulders"}', 'Ponte de pie con los pies separados a la altura de las caderas y los brazos a los lados del cuerpo. Da un paso hacia atrás con el pie derecho, apoyándote en la punta del pie. Flexiona la rodilla izquierda y baja el cuerpo a una posición de zancada. Mientras bajas a la zancada, lleva simultáneamente los brazos por encima de la cabeza. Haz una pausa por un momento en la parte baja de la zancada y luego vuelve a la posición inicial empujando con el talón izquierdo y llevando el pie derecho hacia adelante. Repite el movimiento hacia el otro lado, retrocediendo con el pie izquierdo y flexionando la rodilla derecha. Continúa alternando lados durante el número de repeticiones deseado.', 'Stand with your feet hip-width apart and your arms by your sides. Take a step back with your right foot, landing on the ball of your foot. Bend your left knee and lower your body into a lunge position. As you lower into the lunge, simultaneously reach your arms overhead. Pause for a moment at the bottom of the lunge, then return to the starting position by pushing through your left heel and bringing your right foot forward. Repeat the movement on the other side, stepping back with your left foot and bending your right knee. Continue alternating sides for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1687-ErqK3UL.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1687-ErqK3UL.gif', 'ErqK3UL', '© Gym visual — https://gymvisual.com/'),
('1389', 'posterior tibialis stretch', 'Siéntate en el suelo con las piernas extendidas frente a ti. Enrolla la cuerda alrededor de la planta del pie y sujeta los extremos de la cuerda con las manos. Tira suavemente de la cuerda hacia ti, flexionando el pie y estirando los músculos de la pantorrilla. Mantén el estiramiento durante 20-30 s', 'lower legs', 'rope', 'lower legs', 'lower legs', 'calves', '{"hamstrings","quadriceps"}', 'Siéntate en el suelo con las piernas extendidas frente a ti. Enrolla la cuerda alrededor de la planta del pie y sujeta los extremos de la cuerda con las manos. Tira suavemente de la cuerda hacia ti, flexionando el pie y estirando los músculos de la pantorrilla. Mantén el estiramiento durante 20-30 segundos. Suelta la tensión de la cuerda y relaja el pie. Repite el estiramiento en la otra pierna.', 'Sit on the ground with your legs extended in front of you. Loop the rope around the ball of your foot and hold the ends of the rope with your hands. Gently pull the rope towards you, flexing your foot and stretching your calf muscles. Hold the stretch for 20-30 seconds. Release the tension on the rope and relax your foot. Repeat the stretch on the other leg.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1389-DEEqoI2.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1389-DEEqoI2.gif', 'DEEqoI2', '© Gym visual — https://gymvisual.com/'),
('3119', 'potty squat', 'Ponte de pie con los pies separados a la altura de los hombros, los dedos de los pies ligeramente hacia afuera. Baja el cuerpo flexionando las rodillas y empujando las caderas hacia atrás como si te sentaras en una silla. Mantén el pecho hacia arriba y la espalda recta durante todo el movimiento. Ba', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"quadriceps","glutes"}', 'Ponte de pie con los pies separados a la altura de los hombros, los dedos de los pies ligeramente hacia afuera. Baja el cuerpo flexionando las rodillas y empujando las caderas hacia atrás como si te sentaras en una silla. Mantén el pecho hacia arriba y la espalda recta durante todo el movimiento. Baja hasta que los muslos queden paralelos al suelo o hasta donde puedas llegar cómodamente. Haz una pausa por un momento en la parte inferior, luego empuja con los talones para regresar a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, toes pointing slightly outward. Lower your body down by bending your knees and pushing your hips back as if you were sitting on a chair. Keep your chest up and your back straight throughout the movement. Lower yourself until your thighs are parallel to the ground or as low as you can comfortably go. Pause for a moment at the bottom, then push through your heels to return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3119-75Bgtjy.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3119-75Bgtjy.gif', '75Bgtjy', '© Gym visual — https://gymvisual.com/'),
('3132', 'potty squat with support', 'Ponte de pie con los pies separados a la altura de los hombros, los dedos de los pies ligeramente hacia afuera. Sujétate de un apoyo estable, como una silla o una pared, para mantener el equilibrio. Baja el cuerpo hacia una posición de sentadilla flexionando las rodillas y empujando las caderas haci', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves"}', 'Ponte de pie con los pies separados a la altura de los hombros, los dedos de los pies ligeramente hacia afuera. Sujétate de un apoyo estable, como una silla o una pared, para mantener el equilibrio. Baja el cuerpo hacia una posición de sentadilla flexionando las rodillas y empujando las caderas hacia atrás. Mantén el pecho hacia arriba y la espalda recta durante todo el movimiento. Haz una pausa por un momento en la parte inferior, luego empuja con los talones para regresar a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, toes pointing slightly outward. Hold onto a stable support, such as a chair or wall, for balance. Lower your body down into a squat position by bending your knees and pushing your hips back. Keep your chest up and your back straight throughout the movement. Pause for a moment at the bottom, then push through your heels to return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3132-b63ZzGe.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3132-b63ZzGe.gif', 'b63ZzGe', '© Gym visual — https://gymvisual.com/'),
('0648', 'power clean', 'Comienza con la barra en el suelo frente a ti, con los pies separados a la altura de los hombros. Agáchate y agarra la barra con un agarre prono, un poco más separado que la anchura de los hombros. Mantén la espalda recta y el pecho hacia arriba al levantar la barra del suelo, extendiendo las cadera', 'upper legs', 'barbell', 'upper legs', 'upper legs', 'hamstrings', '{"glutes","quadriceps","calves"}', 'Comienza con la barra en el suelo frente a ti, con los pies separados a la altura de los hombros. Agáchate y agarra la barra con un agarre prono, un poco más separado que la anchura de los hombros. Mantén la espalda recta y el pecho hacia arriba al levantar la barra del suelo, extendiendo las caderas y las rodillas. Cuando la barra llegue a la mitad del muslo, tira de ella explosivamente hacia arriba, encogiendo los hombros y llevando los codos hacia arriba y hacia los lados. Cuando la barra alcance su punto más alto, baja rápidamente debajo de ella, rotando los codos y atrapando la barra sobre los hombros en una posición de sentadilla frontal. Ponte de pie con la barra, extendiendo completamente las caderas y las rodillas. Baja la barra de nuevo a la posición inicial, manteniendo el control del peso durante todo el movimiento. Repite el número de repeticiones deseado.', 'Start with the barbell on the ground in front of you, with your feet shoulder-width apart. Bend down and grip the barbell with an overhand grip, slightly wider than shoulder-width apart. Keep your back straight and chest up as you lift the barbell off the ground, extending your hips and knees. As the barbell reaches your mid-thigh, explosively pull it upwards, shrugging your shoulders and pulling your elbows high and to the sides. As the barbell reaches its highest point, quickly drop underneath it, rotating your elbows around and catching the barbell on your shoulders in a front squat position. Stand up with the barbell, fully extending your hips and knees. Lower the barbell back down to the starting position, keeping control of the weight throughout the movement. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0648-SiWCcTN.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0648-SiWCcTN.gif', 'SiWCcTN', '© Gym visual — https://gymvisual.com/'),
('3665', 'power point plank', 'Comienza en posición de plancha alta con las manos directamente debajo de los hombros y el cuerpo en línea recta de la cabeza a los pies. Activa el core y aprieta los glúteos para mantener una posición estable. Baja el cuerpo hasta los antebrazos, un brazo a la vez, manteniendo una línea recta de la', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"shoulders","triceps","glutes"}', 'Comienza en posición de plancha alta con las manos directamente debajo de los hombros y el cuerpo en línea recta de la cabeza a los pies. Activa el core y aprieta los glúteos para mantener una posición estable. Baja el cuerpo hasta los antebrazos, un brazo a la vez, manteniendo una línea recta de la cabeza a los pies. Mantén esta posición durante el tiempo deseado, con el core y los glúteos activados. Para volver a la posición inicial, empuja con los antebrazos y eleva el cuerpo de nuevo a una posición de plancha alta. Repite el número de repeticiones deseado.', 'Start in a high plank position with your hands directly under your shoulders and your body in a straight line from head to toe. Engage your core and squeeze your glutes to maintain a stable position. Lower your body down onto your forearms, one arm at a time, maintaining a straight line from head to toe. Hold this position for the desired amount of time, keeping your core and glutes engaged. To return to the starting position, push through your forearms and lift your body back up into a high plank position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3665-hCjGsRQ.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3665-hCjGsRQ.gif', 'hCjGsRQ', '© Gym visual — https://gymvisual.com/'),
('3203', 'prisoner half sit-up (male)', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Coloca las manos detrás de la cabeza con los codos apuntando hacia afuera. Activando el abdomen, levanta lentamente la parte superior del cuerpo del suelo, curvándote hacia adelante hasta que tu torso forme un áng', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"hip flexors"}', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Coloca las manos detrás de la cabeza con los codos apuntando hacia afuera. Activando el abdomen, levanta lentamente la parte superior del cuerpo del suelo, curvándote hacia adelante hasta que tu torso forme un ángulo de 45 grados. Haz una pausa por un momento en la parte superior, luego baja lentamente la parte superior del cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on your back with your knees bent and feet flat on the ground. Place your hands behind your head with your elbows pointing outwards. Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle. Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3203-mgejmGP.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3203-mgejmGP.gif', 'mgejmGP', '© Gym visual — https://gymvisual.com/'),
('1707', 'prone twist on stability ball', 'Comienza tumbándote boca abajo sobre un balón de estabilidad con los pies separados a la altura de los hombros y los dedos de los pies tocando el suelo. Coloca las manos detrás de la cabeza o crúzalas sobre el pecho. Activa los músculos del core y eleva lentamente la parte superior del cuerpo del ba', 'waist', 'stability ball', 'waist', 'waist', 'abs', '{"obliques","lower back"}', 'Comienza tumbándote boca abajo sobre un balón de estabilidad con los pies separados a la altura de los hombros y los dedos de los pies tocando el suelo. Coloca las manos detrás de la cabeza o crúzalas sobre el pecho. Activa los músculos del core y eleva lentamente la parte superior del cuerpo del balón, manteniendo la espalda recta. Rota el torso hacia un lado, llevando el hombro hacia la cadera. Mantén las caderas y las piernas estables durante todo el movimiento. Haz una pausa breve y luego vuelve a la posición inicial. Repite la rotación hacia el otro lado. Continúa alternando lados durante el número de repeticiones deseado.', 'Start by lying face down on a stability ball with your feet shoulder-width apart and your toes touching the ground. Place your hands behind your head or cross them over your chest. Engage your core muscles and slowly lift your upper body off the ball, keeping your back straight. Rotate your torso to one side, bringing your shoulder towards your hip. Keep your hips and legs stable throughout the movement. Pause for a moment, then return to the starting position. Repeat the rotation to the other side. Continue alternating sides for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1707-1IG6gVF.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1707-1IG6gVF.gif', '1IG6gVF', '© Gym visual — https://gymvisual.com/'),
('0651', 'pull up (neutral grip)', 'Cuélgate de una barra de dominadas con un agarre neutro (las palmas enfrentadas) y los brazos completamente extendidos. Activa el core y junta los omóplatos. Tira de tu cuerpo hacia la barra flexionando los codos y llevándolos hacia las caderas. Continúa subiendo hasta que la barbilla quede por enci', 'back', 'body weight', 'back', 'back', 'lats', '{"biceps","forearms"}', 'Cuélgate de una barra de dominadas con un agarre neutro (las palmas enfrentadas) y los brazos completamente extendidos. Activa el core y junta los omóplatos. Tira de tu cuerpo hacia la barra flexionando los codos y llevándolos hacia las caderas. Continúa subiendo hasta que la barbilla quede por encima de la barra. Haz una pausa por un momento en la parte alta y luego baja lentamente tu cuerpo, con control, hasta la posición inicial. Repite el número de repeticiones deseado.', 'Hang from a pull-up bar with a neutral grip (palms facing each other) and your arms fully extended. Engage your core and squeeze your shoulder blades together. Pull your body up towards the bar by bending your elbows and driving your elbows down towards your hips. Continue pulling until your chin is above the bar. Pause for a moment at the top, then slowly lower your body back down to the starting position with control. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0651-0V2YQjW.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0651-0V2YQjW.gif', '0V2YQjW', '© Gym visual — https://gymvisual.com/'),
('0650', 'pull-in (on stability ball)', 'Comienza sentándote en el balón de estabilidad con los pies planos en el suelo y las rodillas flexionadas a un ángulo de 90 grados. Coloca las manos a los lados del balón de estabilidad para mayor apoyo. Activa el abdomen y rueda lentamente las caderas hacia adelante, llevando las rodillas hacia el ', 'waist', 'stability ball', 'waist', 'waist', 'abs', '{"hip flexors"}', 'Comienza sentándote en el balón de estabilidad con los pies planos en el suelo y las rodillas flexionadas a un ángulo de 90 grados. Coloca las manos a los lados del balón de estabilidad para mayor apoyo. Activa el abdomen y rueda lentamente las caderas hacia adelante, llevando las rodillas hacia el pecho. Haz una pausa por un momento en la parte alta del movimiento y luego extiende lentamente las piernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Start by sitting on the stability ball with your feet flat on the ground and your knees bent at a 90-degree angle. Place your hands on the sides of the stability ball for support. Engage your abs and slowly roll your hips forward, bringing your knees towards your chest. Pause for a moment at the top of the movement, then slowly extend your legs back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0650-UQr48Oi.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0650-UQr48Oi.gif', 'UQr48Oi', '© Gym visual — https://gymvisual.com/'),
('0652', 'pull-up', 'Cuélgate de una barra de dominadas con las palmas hacia afuera y los brazos completamente extendidos. Activa el core y junta los omóplatos. Tira de tu cuerpo hacia la barra flexionando los codos y llevando el pecho hacia la barra. Haz una pausa en la parte alta del movimiento y luego baja lentamente', 'back', 'body weight', 'back', 'back', 'lats', '{"biceps","forearms"}', 'Cuélgate de una barra de dominadas con las palmas hacia afuera y los brazos completamente extendidos. Activa el core y junta los omóplatos. Tira de tu cuerpo hacia la barra flexionando los codos y llevando el pecho hacia la barra. Haz una pausa en la parte alta del movimiento y luego baja lentamente el cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Hang from a pull-up bar with your palms facing away from you and your arms fully extended. Engage your core and squeeze your shoulder blades together. Pull your body up towards the bar by bending your elbows and bringing your chest towards the bar. Pause at the top of the movement, then slowly lower your body back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0652-lBDjFxJ.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0652-lBDjFxJ.gif', 'lBDjFxJ', '© Gym visual — https://gymvisual.com/'),
('1689', 'push and pull bodyweight', 'Comienza en posición de flexión con las manos un poco más separadas que la anchura de los hombros y el cuerpo en línea recta. Baja el pecho hacia el suelo flexionando los codos, manteniendo el cuerpo recto. Empuja con las palmas para extender los brazos y regresar a la posición inicial. Desde la pos', 'chest', 'body weight', 'chest', 'chest', 'pectorals', '{"triceps","deltoids"}', 'Comienza en posición de flexión con las manos un poco más separadas que la anchura de los hombros y el cuerpo en línea recta. Baja el pecho hacia el suelo flexionando los codos, manteniendo el cuerpo recto. Empuja con las palmas para extender los brazos y regresar a la posición inicial. Desde la posición de flexión, tira del pecho hacia el suelo flexionando los codos, manteniendo el cuerpo recto. Empuja con las palmas para extender los brazos y regresar a la posición inicial. Repite el número de repeticiones deseado.', 'Start in a push-up position with your hands slightly wider than shoulder-width apart and your body in a straight line. Lower your chest towards the ground by bending your elbows, keeping your body straight. Push through your palms to extend your arms and return to the starting position. From the push-up position, pull your chest towards the ground by bending your elbows, keeping your body straight. Push through your palms to extend your arms and return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1689-wXvUZC8.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1689-wXvUZC8.gif', 'wXvUZC8', '© Gym visual — https://gymvisual.com/'),
('3638', 'push to run', 'Comienza en posición de flexión con las manos separadas a la altura de los hombros y el cuerpo en línea recta. Baja el pecho hacia el suelo flexionando los codos, manteniendo el cuerpo recto. Empuja con las manos para extender los brazos y volver a la posición inicial. Lleva rápidamente una rodilla ', 'cardio', 'body weight', 'cardio', 'cardio', 'cardiovascular system', '{"quadriceps","hamstrings","calves"}', 'Comienza en posición de flexión con las manos separadas a la altura de los hombros y el cuerpo en línea recta. Baja el pecho hacia el suelo flexionando los codos, manteniendo el cuerpo recto. Empuja con las manos para extender los brazos y volver a la posición inicial. Lleva rápidamente una rodilla hacia el pecho, luego cambia rápidamente y lleva la otra rodilla hacia el pecho. Continúa alternando las rodillas tan rápido como puedas manteniendo una buena forma. Continúa durante el tiempo o el número de repeticiones deseado.', 'Start in a push-up position with your hands shoulder-width apart and your body in a straight line. Lower your chest towards the ground by bending your elbows, keeping your body straight. Push through your hands to extend your arms and return to the starting position. Quickly bring one knee towards your chest, then quickly switch and bring the other knee towards your chest. Continue alternating knees as fast as you can while maintaining good form. Continue for the desired duration or number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3638-PrQbjvB.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3638-PrQbjvB.gif', 'PrQbjvB', '© Gym visual — https://gymvisual.com/'),
('1307', 'push up on bosu ball', 'Coloca el bosu en el suelo con el lado plano hacia arriba. Colócate en posición de flexión con las manos en los bordes exteriores del bosu. Activa el core y baja el cuerpo hacia el bosu flexionando los codos. Empuja tu cuerpo de vuelta a la posición inicial extendiendo los brazos. Repite el número d', 'chest', 'bosu ball', 'chest', 'chest', 'pectorals', '{"triceps","shoulders","core"}', 'Coloca el bosu en el suelo con el lado plano hacia arriba. Colócate en posición de flexión con las manos en los bordes exteriores del bosu. Activa el core y baja el cuerpo hacia el bosu flexionando los codos. Empuja tu cuerpo de vuelta a la posición inicial extendiendo los brazos. Repite el número de repeticiones deseado.', 'Place the bosu ball on the ground with the flat side facing up. Position yourself in a push-up position with your hands on the outer edges of the bosu ball. Engage your core and lower your body down towards the bosu ball by bending your elbows. Push yourself back up to the starting position by extending your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1307-wVompEp.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1307-wVompEp.gif', 'wVompEp', '© Gym visual — https://gymvisual.com/'),
('0662', 'push-up', 'Comienza en una posición de plancha alta con las manos un poco más separadas que la anchura de los hombros y los pies juntos. Activa el core y baja el cuerpo hacia el suelo flexionando los codos, manteniendo el cuerpo en línea recta. Haz una pausa cuando el pecho esté justo por encima del suelo y lu', 'chest', 'body weight', 'chest', 'chest', 'pectorals', '{"triceps","deltoids","core"}', 'Comienza en una posición de plancha alta con las manos un poco más separadas que la anchura de los hombros y los pies juntos. Activa el core y baja el cuerpo hacia el suelo flexionando los codos, manteniendo el cuerpo en línea recta. Haz una pausa cuando el pecho esté justo por encima del suelo y luego empújate de vuelta a la posición inicial estirando los brazos. Repite el número de repeticiones deseado.', 'Start in a high plank position with your hands slightly wider than shoulder-width apart and your feet together. Engage your core and lower your body towards the ground by bending your elbows, keeping your body in a straight line. Pause for a moment when your chest is just above the ground, then push yourself back up to the starting position by straightening your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0662-I4hDWkc.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0662-I4hDWkc.gif', 'I4hDWkc', '© Gym visual — https://gymvisual.com/'),
('0653', 'push-up (bosu ball)', 'Coloca el bosu en el suelo con el lado plano hacia arriba. Colócate en posición de flexión con las manos en los bordes exteriores del bosu. Activa el core y baja el cuerpo hacia el bosu flexionando los codos. Empuja tu cuerpo de vuelta a la posición inicial extendiendo los brazos. Repite el número d', 'chest', 'bosu ball', 'chest', 'chest', 'pectorals', '{"triceps","shoulders","core"}', 'Coloca el bosu en el suelo con el lado plano hacia arriba. Colócate en posición de flexión con las manos en los bordes exteriores del bosu. Activa el core y baja el cuerpo hacia el bosu flexionando los codos. Empuja tu cuerpo de vuelta a la posición inicial extendiendo los brazos. Repite el número de repeticiones deseado.', 'Place the bosu ball on the ground with the flat side facing up. Position yourself in a push-up position with your hands on the outer edges of the bosu ball. Engage your core and lower your body down towards the bosu ball by bending your elbows. Push yourself back up to the starting position by extending your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0653-2kr2lWy.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0653-2kr2lWy.gif', '2kr2lWy', '© Gym visual — https://gymvisual.com/'),
('0655', 'push-up (on stability ball)', 'Coloca el balón de estabilidad en el suelo y ponte boca abajo con las manos sobre el balón, separadas a la altura de los hombros. Extiende las piernas rectas detrás de ti, equilibrándote sobre los dedos de los pies. Activa el core y baja el pecho hacia el balón flexionando los codos, manteniendo el ', 'chest', 'stability ball', 'chest', 'chest', 'pectorals', '{"triceps","shoulders","core"}', 'Coloca el balón de estabilidad en el suelo y ponte boca abajo con las manos sobre el balón, separadas a la altura de los hombros. Extiende las piernas rectas detrás de ti, equilibrándote sobre los dedos de los pies. Activa el core y baja el pecho hacia el balón flexionando los codos, manteniendo el cuerpo en línea recta. Haz una pausa breve en la parte baja, luego empújate de nuevo hacia arriba a la posición inicial estirando los brazos. Repite el número de repeticiones deseado.', 'Place the stability ball on the ground and position yourself facing down with your hands on the ball, shoulder-width apart. Extend your legs straight out behind you, balancing on your toes. Engage your core and lower your chest towards the ball by bending your elbows, keeping your body in a straight line. Pause for a moment at the bottom, then push yourself back up to the starting position by straightening your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0655-Y4BRNQF.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0655-Y4BRNQF.gif', 'Y4BRNQF', '© Gym visual — https://gymvisual.com/'),
('0656', 'push-up (on stability ball)', 'Coloca el balón de estabilidad en el suelo y ponte boca abajo con las manos sobre el balón, separadas a la altura de los hombros. Extiende las piernas rectas detrás de ti, equilibrándote sobre los dedos de los pies. Activa el core y baja el pecho hacia el balón flexionando los codos, manteniendo el ', 'chest', 'stability ball', 'chest', 'chest', 'pectorals', '{"triceps","shoulders","core"}', 'Coloca el balón de estabilidad en el suelo y ponte boca abajo con las manos sobre el balón, separadas a la altura de los hombros. Extiende las piernas rectas detrás de ti, equilibrándote sobre los dedos de los pies. Activa el core y baja el pecho hacia el balón flexionando los codos, manteniendo el cuerpo en línea recta. Haz una pausa breve en la parte baja, luego empújate de nuevo hacia arriba a la posición inicial estirando los brazos. Repite el número de repeticiones deseado.', 'Place the stability ball on the ground and position yourself facing down with your hands on the ball, shoulder-width apart. Extend your legs straight out behind you, balancing on your toes. Engage your core and lower your chest towards the ball by bending your elbows, keeping your body in a straight line. Pause for a moment at the bottom, then push yourself back up to the starting position by straightening your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0656-tgryw5Y.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0656-tgryw5Y.gif', 'tgryw5Y', '© Gym visual — https://gymvisual.com/'),
('0659', 'push-up (wall)', 'Ponte de pie frente a una pared, a una distancia aproximada de un brazo. Coloca las manos en la pared a la altura de los hombros, un poco más separadas que la anchura de los hombros. Da un paso atrás, manteniendo el cuerpo recto y los pies separados a la altura de las caderas. Flexiona los codos y b', 'chest', 'body weight', 'chest', 'chest', 'pectorals', '{"triceps","deltoids"}', 'Ponte de pie frente a una pared, a una distancia aproximada de un brazo. Coloca las manos en la pared a la altura de los hombros, un poco más separadas que la anchura de los hombros. Da un paso atrás, manteniendo el cuerpo recto y los pies separados a la altura de las caderas. Flexiona los codos y baja el pecho hacia la pared, manteniendo el cuerpo en línea recta. Empuja de vuelta a la posición inicial, estirando los brazos. Repite el número de repeticiones deseado.', 'Stand facing a wall, about arm''s length away. Place your hands on the wall at shoulder height, slightly wider than shoulder-width apart. Step back a few feet, keeping your body straight and your feet hip-width apart. Bend your elbows and lower your chest towards the wall, keeping your body in a straight line. Push back up to the starting position, straightening your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0659-LEH9jxP.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0659-LEH9jxP.gif', 'LEH9jxP', '© Gym visual — https://gymvisual.com/'),
('0658', 'push-up (wall) v. 2', 'Ponte de pie frente a una pared, a una distancia aproximada de un brazo. Coloca las manos en la pared a la altura de los hombros, un poco más separadas que la anchura de los hombros. Retrocede con los pies, manteniéndolos separados a la altura de las caderas. Activa el core y mantén el cuerpo en lín', 'chest', 'body weight', 'chest', 'chest', 'pectorals', '{"triceps","shoulders"}', 'Ponte de pie frente a una pared, a una distancia aproximada de un brazo. Coloca las manos en la pared a la altura de los hombros, un poco más separadas que la anchura de los hombros. Retrocede con los pies, manteniéndolos separados a la altura de las caderas. Activa el core y mantén el cuerpo en línea recta desde la cabeza hasta los talones. Flexiona los codos y baja el pecho hacia la pared, manteniendo el cuerpo recto. Haz una pausa por un momento y luego empújate de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand facing a wall, about arm''s length away. Place your hands on the wall at shoulder height, slightly wider than shoulder-width apart. Step back with your feet, keeping them hip-width apart. Engage your core and keep your body in a straight line from head to heels. Bend your elbows and lower your chest towards the wall, keeping your body straight. Pause for a moment, then push yourself back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0658-NCmbLCw.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0658-NCmbLCw.gif', 'NCmbLCw', '© Gym visual — https://gymvisual.com/'),
('0660', 'push-up close-grip off dumbbell', 'Comienza en posición de flexión con las manos juntas, directamente debajo de los hombros. Sostén una mancuerna en cada mano, apoyándolas en el suelo. Baja el cuerpo hacia el suelo flexionando los codos, manteniéndolos cerca de los costados. Empuja con las palmas para extender los brazos y regresar a', 'upper arms', 'dumbbell', 'upper arms', 'upper arms', 'triceps', '{"chest","shoulders"}', 'Comienza en posición de flexión con las manos juntas, directamente debajo de los hombros. Sostén una mancuerna en cada mano, apoyándolas en el suelo. Baja el cuerpo hacia el suelo flexionando los codos, manteniéndolos cerca de los costados. Empuja con las palmas para extender los brazos y regresar a la posición inicial. Repite el número de repeticiones deseado.', 'Start in a push-up position with your hands placed close together, directly under your shoulders. Hold a dumbbell in each hand, resting them on the ground. Lower your body towards the ground by bending your elbows, keeping them close to your sides. Push through your palms to extend your arms and return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0660-KZXAtKQ.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0660-KZXAtKQ.gif', 'KZXAtKQ', '© Gym visual — https://gymvisual.com/'),
('0661', 'push-up inside leg kick', 'Comienza en posición de flexión con las manos un poco más separadas que la anchura de los hombros y los pies juntos. Baja el cuerpo hacia el suelo flexionando los codos, manteniendo la espalda recta y el core activado. Al empujar de vuelta hacia arriba, levanta una pierna del suelo y lánzala hacia e', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves","core"}', 'Comienza en posición de flexión con las manos un poco más separadas que la anchura de los hombros y los pies juntos. Baja el cuerpo hacia el suelo flexionando los codos, manteniendo la espalda recta y el core activado. Al empujar de vuelta hacia arriba, levanta una pierna del suelo y lánzala hacia el lado, manteniéndola recta. Baja la pierna de nuevo y repite la flexión, luego cambia a la otra pierna. Continúa alternando las patadas de pierna en cada repetición de la flexión.', 'Start in a push-up position with your hands slightly wider than shoulder-width apart and your feet together. Lower your body towards the ground by bending your elbows, keeping your back straight and your core engaged. As you push back up, lift one leg off the ground and kick it out to the side, keeping it straight. Lower your leg back down and repeat the push-up, then switch to the other leg. Continue alternating leg kicks with each push-up repetition.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0661-0br45wL.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0661-0br45wL.gif', '0br45wL', '© Gym visual — https://gymvisual.com/'),
('0663', 'push-up medicine ball', 'Comienza en una posición de plancha alta con las manos sobre el balón medicinal, separadas a la altura de los hombros. Activa el core y baja el cuerpo hacia el suelo flexionando los codos, manteniendo la espalda recta. Empuja con las palmas para extender los brazos y regresar a la posición inicial. ', 'chest', 'medicine ball', 'chest', 'chest', 'pectorals', '{"triceps","shoulders","core"}', 'Comienza en una posición de plancha alta con las manos sobre el balón medicinal, separadas a la altura de los hombros. Activa el core y baja el cuerpo hacia el suelo flexionando los codos, manteniendo la espalda recta. Empuja con las palmas para extender los brazos y regresar a la posición inicial. Repite el número de repeticiones deseado.', 'Start in a high plank position with your hands on the medicine ball, shoulder-width apart. Engage your core and lower your body towards the ground by bending your elbows, keeping your back straight. Push through your palms to extend your arms and return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0663-W8KAlkI.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0663-W8KAlkI.gif', 'W8KAlkI', '© Gym visual — https://gymvisual.com/'),
('1467', 'push-up on lower arms', 'Comienza en posición de plancha con los antebrazos en el suelo y los codos directamente debajo de los hombros. Activa el core y mantén el cuerpo en línea recta de la cabeza a los pies. Baja el pecho hacia el suelo flexionando los codos, manteniéndolos cerca del cuerpo. Haz una pausa por un momento e', 'upper arms', 'body weight', 'upper arms', 'upper arms', 'triceps', '{"chest","shoulders"}', 'Comienza en posición de plancha con los antebrazos en el suelo y los codos directamente debajo de los hombros. Activa el core y mantén el cuerpo en línea recta de la cabeza a los pies. Baja el pecho hacia el suelo flexionando los codos, manteniéndolos cerca del cuerpo. Haz una pausa por un momento en la parte inferior, luego empuja tu cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Start in a plank position with your forearms on the ground and elbows directly below your shoulders. Engage your core and keep your body in a straight line from head to toe. Lower your chest towards the ground by bending your elbows, keeping them close to your body. Pause for a moment at the bottom, then push yourself back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1467-4Jt8QsQ.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1467-4Jt8QsQ.gif', '4Jt8QsQ', '© Gym visual — https://gymvisual.com/'),
('3145', 'push-up plus', 'Comienza en una posición de plancha alta con las manos un poco más separadas que la anchura de los hombros y el cuerpo en línea recta desde la cabeza hasta los talones. Baja el cuerpo hacia el suelo flexionando los codos, manteniéndolos cerca de los costados. Cuando el pecho esté justo por encima de', 'chest', 'body weight', 'chest', 'chest', 'pectorals', '{"triceps","shoulders"}', 'Comienza en una posición de plancha alta con las manos un poco más separadas que la anchura de los hombros y el cuerpo en línea recta desde la cabeza hasta los talones. Baja el cuerpo hacia el suelo flexionando los codos, manteniéndolos cerca de los costados. Cuando el pecho esté justo por encima del suelo, empuja con las manos para extender los brazos y levantar la parte superior del cuerpo. En la parte alta del movimiento, separa las escápulas empujando la parte superior de la espalda hacia el techo. Haz una pausa por un momento y luego invierte el movimiento juntando las escápulas y bajando el cuerpo de nuevo a la posición inicial. Repite el número de repeticiones deseado.', 'Start in a high plank position with your hands slightly wider than shoulder-width apart and your body in a straight line from head to heels. Lower your body towards the ground by bending your elbows, keeping them close to your sides. Once your chest is just above the ground, push through your hands to extend your arms and lift your upper body up. At the top of the movement, protract your shoulder blades by pushing your upper back towards the ceiling. Pause for a moment, then reverse the movement by retracting your shoulder blades and lowering your body back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3145-pvBMLHA.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3145-pvBMLHA.gif', 'pvBMLHA', '© Gym visual — https://gymvisual.com/'),
('0664', 'push-up to side plank', 'Comienza en posición de flexión con las manos separadas a la altura de los hombros y el cuerpo en línea recta. Baja el cuerpo hacia el suelo flexionando los codos, manteniendo el core activado. Empuja hacia arriba para volver a la posición inicial. Desplaza el peso hacia la mano izquierda y rota el ', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"shoulders","chest","triceps"}', 'Comienza en posición de flexión con las manos separadas a la altura de los hombros y el cuerpo en línea recta. Baja el cuerpo hacia el suelo flexionando los codos, manteniendo el core activado. Empuja hacia arriba para volver a la posición inicial. Desplaza el peso hacia la mano izquierda y rota el cuerpo hacia la derecha, elevando el brazo derecho hacia el techo. Mantén la posición de plancha lateral durante unos segundos y luego vuelve a la posición inicial. Repite la flexión y la plancha lateral en el lado opuesto. Continúa alternando lados durante el número de repeticiones deseado.', 'Start in a push-up position with your hands shoulder-width apart and your body in a straight line. Lower your body towards the ground by bending your elbows, keeping your core engaged. Push back up to the starting position. Shift your weight onto your left hand and rotate your body to the right, lifting your right arm towards the ceiling. Hold the side plank position for a few seconds, then return to the starting position. Repeat the push-up and side plank on the opposite side. Continue alternating sides for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0664-KhHJ338.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0664-KhHJ338.gif', 'KhHJ338', '© Gym visual — https://gymvisual.com/'),
('3533', 'quads', 'Ponte de pie con los pies separados a la altura de los hombros. Baja el cuerpo flexionando las rodillas y empujando las caderas hacia atrás como si te sentaras en una silla. Mantén el pecho arriba y la espalda recta. Baja hasta que los muslos queden paralelos al suelo. Empuja con los talones para vo', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'quads', '{"hamstrings","glutes"}', 'Ponte de pie con los pies separados a la altura de los hombros. Baja el cuerpo flexionando las rodillas y empujando las caderas hacia atrás como si te sentaras en una silla. Mantén el pecho arriba y la espalda recta. Baja hasta que los muslos queden paralelos al suelo. Empuja con los talones para volver a ponerte de pie en la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart. Lower your body by bending your knees and pushing your hips back as if sitting on a chair. Keep your chest up and your back straight. Lower yourself until your thighs are parallel to the ground. Push through your heels to return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3533-6YUfHPL.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3533-6YUfHPL.gif', '6YUfHPL', '© Gym visual — https://gymvisual.com/'),
('3201', 'quarter sit-up', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Coloca las manos detrás de la cabeza con los codos apuntando hacia afuera. Activando el abdomen, levanta lentamente la parte superior del cuerpo del suelo, curvándote hacia adelante hasta que tu torso forme un áng', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"hip flexors"}', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Coloca las manos detrás de la cabeza con los codos apuntando hacia afuera. Activando el abdomen, levanta lentamente la parte superior del cuerpo del suelo, curvándote hacia adelante hasta que tu torso forme un ángulo de 45 grados. Haz una pausa por un momento en la parte superior, luego baja lentamente la parte superior del cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on your back with your knees bent and feet flat on the ground. Place your hands behind your head with your elbows pointing outwards. Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle. Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3201-enxnJcM.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3201-enxnJcM.gif', 'enxnJcM', '© Gym visual — https://gymvisual.com/'),
('3552', 'quick feet v. 2', 'Ponte de pie con los pies separados a la altura de los hombros y los brazos a los costados. Comienza moviendo los pies rápidamente hacia arriba y hacia abajo, como si estuvieras corriendo en el sitio. Mantén los movimientos rápidos y ligeros, concentrándote en quedarte sobre la punta de los pies. Co', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'quads', '{"calves","hamstrings"}', 'Ponte de pie con los pies separados a la altura de los hombros y los brazos a los costados. Comienza moviendo los pies rápidamente hacia arriba y hacia abajo, como si estuvieras corriendo en el sitio. Mantén los movimientos rápidos y ligeros, concentrándote en quedarte sobre la punta de los pies. Continúa durante el tiempo o el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and your arms by your sides. Begin by rapidly moving your feet up and down, as if you were running in place. Keep your movements quick and light, focusing on staying on the balls of your feet. Continue for the desired duration or number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3552-mweqJin.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3552-mweqJin.gif', 'mweqJin', '© Gym visual — https://gymvisual.com/'),
('0666', 'raise single arm push-up', 'Comienza en posición de flexión con las manos un poco más separadas que la anchura de los hombros y los pies juntos. Extiende un brazo hacia el lado, paralelo al suelo. Baja el cuerpo hacia el suelo flexionando los codos, manteniendo la espalda recta y el core activado. Empuja de vuelta a la posició', 'chest', 'body weight', 'chest', 'chest', 'pectorals', '{"triceps","shoulders","core"}', 'Comienza en posición de flexión con las manos un poco más separadas que la anchura de los hombros y los pies juntos. Extiende un brazo hacia el lado, paralelo al suelo. Baja el cuerpo hacia el suelo flexionando los codos, manteniendo la espalda recta y el core activado. Empuja de vuelta a la posición inicial, usando los músculos del pecho para elevar el cuerpo. Repite con el otro brazo extendido.', 'Start in a push-up position with your hands slightly wider than shoulder-width apart and your feet together. Extend one arm straight out to the side, parallel to the ground. Lower your body towards the ground by bending your elbows, keeping your back straight and core engaged. Push back up to the starting position, using your chest muscles to lift your body. Repeat with the other arm extended.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0666-13TpY4H.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0666-13TpY4H.gif', '13TpY4H', '© Gym visual — https://gymvisual.com/'),
('0668', 'rear decline bridge', 'Túmbate boca arriba con los pies planos en el suelo y las rodillas flexionadas. Coloca los brazos a los lados del cuerpo con las palmas hacia abajo. Activa los glúteos y los isquiotibiales, y eleva las caderas del suelo hasta que tu cuerpo forme una línea recta desde las rodillas hasta los hombros. ', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'glutes', '{"hamstrings","lower back"}', 'Túmbate boca arriba con los pies planos en el suelo y las rodillas flexionadas. Coloca los brazos a los lados del cuerpo con las palmas hacia abajo. Activa los glúteos y los isquiotibiales, y eleva las caderas del suelo hasta que tu cuerpo forme una línea recta desde las rodillas hasta los hombros. Mantén esta posición durante unos segundos y luego baja lentamente las caderas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie on your back with your feet flat on the ground and your knees bent. Place your arms by your sides with your palms facing down. Engage your glutes and hamstrings, and lift your hips off the ground until your body forms a straight line from your knees to your shoulders. Hold this position for a few seconds, then slowly lower your hips back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0668-UpAlold.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0668-UpAlold.gif', 'UpAlold', '© Gym visual — https://gymvisual.com/'),
('0669', 'rear deltoid stretch', 'Ponte de pie con la espalda recta y los pies separados a la altura de los hombros. Extiende el brazo derecho a través del pecho, colocando la mano izquierda sobre el codo derecho. Tira suavemente del brazo derecho hacia el hombro izquierdo, sintiendo un estiramiento en el hombro derecho. Mantén el e', 'shoulders', 'body weight', 'shoulders', 'shoulders', 'delts', '{"trapezius","rhomboids"}', 'Ponte de pie con la espalda recta y los pies separados a la altura de los hombros. Extiende el brazo derecho a través del pecho, colocando la mano izquierda sobre el codo derecho. Tira suavemente del brazo derecho hacia el hombro izquierdo, sintiendo un estiramiento en el hombro derecho. Mantén el estiramiento durante 15-30 segundos, luego suelta. Repite del otro lado.', 'Stand tall with your feet shoulder-width apart. Extend your right arm across your chest, placing your left hand on your right elbow. Gently pull your right arm towards your left shoulder, feeling a stretch in your right shoulder. Hold the stretch for 15-30 seconds, then release. Repeat on the other side.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0669-xifhB5W.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0669-xifhB5W.gif', 'xifhB5W', '© Gym visual — https://gymvisual.com/'),
('0670', 'rear pull-up', 'Sujeta la barra de dominadas con un agarre prono, un poco más ancho que la altura de los hombros. Cuélgate de la barra con los brazos completamente extendidos y el cuerpo recto. Activa los músculos de la espalda y tira de tu cuerpo hacia arriba, hacia la barra, manteniendo los codos cerca del cuerpo', 'back', 'body weight', 'back', 'back', 'lats', '{"biceps","forearms"}', 'Sujeta la barra de dominadas con un agarre prono, un poco más ancho que la altura de los hombros. Cuélgate de la barra con los brazos completamente extendidos y el cuerpo recto. Activa los músculos de la espalda y tira de tu cuerpo hacia arriba, hacia la barra, manteniendo los codos cerca del cuerpo. Continúa subiendo hasta que la barbilla quede por encima de la barra. Haz una pausa por un momento en la parte superior, luego baja lentamente el cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Grab the pull-up bar with an overhand grip, slightly wider than shoulder-width apart. Hang from the bar with your arms fully extended and your body straight. Engage your back muscles and pull your body up towards the bar, keeping your elbows close to your body. Continue pulling until your chin is above the bar. Pause for a moment at the top, then slowly lower your body back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0670-CbFSYC1.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0670-CbFSYC1.gif', 'CbFSYC1', '© Gym visual — https://gymvisual.com/'),
('1582', 'reclining big toe pose with rope', 'Túmbate sobre tu espalda con las piernas extendidas y los brazos a los lados. Enrolla la cuerda alrededor de la planta del pie derecho y sujeta los extremos de la cuerda con las manos. Eleva lentamente la pierna derecha hacia el pecho, manteniendo la rodilla recta y el pie flexionado. Mantén el esti', 'upper legs', 'rope', 'upper legs', 'upper legs', 'hamstrings', '{"calves","glutes"}', 'Túmbate sobre tu espalda con las piernas extendidas y los brazos a los lados. Enrolla la cuerda alrededor de la planta del pie derecho y sujeta los extremos de la cuerda con las manos. Eleva lentamente la pierna derecha hacia el pecho, manteniendo la rodilla recta y el pie flexionado. Mantén el estiramiento durante unos segundos y luego baja lentamente la pierna de vuelta a la posición inicial. Repite con la pierna izquierda. Continúa alternando las piernas durante el número de repeticiones deseado.', 'Lie on your back with your legs extended and your arms by your sides. Loop the rope around the ball of your right foot and hold the ends of the rope with your hands. Slowly raise your right leg towards your chest, keeping your knee straight and your foot flexed. Hold the stretch for a few seconds, then slowly lower your leg back down to the starting position. Repeat with your left leg. Continue alternating legs for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1582-K5xgdvI.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1582-K5xgdvI.gif', 'K5xgdvI', '© Gym visual — https://gymvisual.com/'),
('3236', 'resistance band hip thrusts on knees (female)', 'Comienza arrodillándote en el suelo con las rodillas separadas a la altura de las caderas y los pies flexionados. Envuelve la banda elástica alrededor de los muslos, justo por encima de las rodillas. Coloca las manos en las caderas o extiéndelas frente a ti para mantener el equilibrio. Activa los gl', 'upper legs', 'resistance band', 'upper legs', 'upper legs', 'glutes', '{"hamstrings","quadriceps"}', 'Comienza arrodillándote en el suelo con las rodillas separadas a la altura de las caderas y los pies flexionados. Envuelve la banda elástica alrededor de los muslos, justo por encima de las rodillas. Coloca las manos en las caderas o extiéndelas frente a ti para mantener el equilibrio. Activa los glúteos y los músculos del core. Empuja las caderas hacia adelante y aprieta los glúteos mientras levantas las rodillas del suelo, extendiendo las caderas hasta que los muslos queden paralelos al suelo. Mantén la posición por un momento y luego baja lentamente las rodillas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Start by kneeling on the ground with your knees hip-width apart and your feet flexed. Wrap the resistance band around your thighs, just above your knees. Place your hands on your hips or extend them out in front of you for balance. Engage your glutes and core muscles. Push your hips forward and squeeze your glutes as you lift your knees off the ground, extending your hips until your thighs are parallel to the ground. Hold the position for a moment, then slowly lower your knees back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3236-Pjbc0Kt.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3236-Pjbc0Kt.gif', 'Pjbc0Kt', '© Gym visual — https://gymvisual.com/'),
('3007', 'resistance band leg extension', 'Sujeta la banda elástica a un punto de anclaje firme y asegúrala alrededor de tu tobillo. Ponte de pie frente al punto de anclaje con los pies separados a la altura de los hombros. Manteniendo el core activado y la parte superior del cuerpo estable, extiende la pierna recta frente a ti. Haz una paus', 'upper legs', 'resistance band', 'upper legs', 'upper legs', 'quads', '{"hamstrings"}', 'Sujeta la banda elástica a un punto de anclaje firme y asegúrala alrededor de tu tobillo. Ponte de pie frente al punto de anclaje con los pies separados a la altura de los hombros. Manteniendo el core activado y la parte superior del cuerpo estable, extiende la pierna recta frente a ti. Haz una pausa por un momento en la parte alta y luego vuelve lentamente la pierna a la posición inicial. Repite el número de repeticiones deseado, luego cambia de pierna.', 'Attach the resistance band to a sturdy anchor point and secure it around your ankle. Stand facing the anchor point with your feet shoulder-width apart. Keeping your core engaged and your upper body stable, extend your leg straight out in front of you. Pause for a moment at the top, then slowly return your leg to the starting position. Repeat for the desired number of repetitions, then switch legs.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3007-Y1MsI1l.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3007-Y1MsI1l.gif', 'Y1MsI1l', '© Gym visual — https://gymvisual.com/'),
('3123', 'resistance band seated biceps curl', 'Siéntate en una silla o banco con la espalda recta y los pies apoyados en el suelo. Sostén la banda elástica con un agarre supino, con las palmas hacia arriba y los brazos extendidos a los lados del cuerpo. Manteniendo la parte superior de los brazos inmóvil, exhala y flexiona la banda elástica haci', 'upper arms', 'resistance band', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Siéntate en una silla o banco con la espalda recta y los pies apoyados en el suelo. Sostén la banda elástica con un agarre supino, con las palmas hacia arriba y los brazos extendidos a los lados del cuerpo. Manteniendo la parte superior de los brazos inmóvil, exhala y flexiona la banda elástica hacia los hombros. Haz una pausa breve en la parte alta, apretando los bíceps. Inhala y baja lentamente la banda elástica de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a chair or bench with your back straight and feet flat on the ground. Hold the resistance band with an underhand grip, palms facing up, and arms extended down by your sides. Keeping your upper arms stationary, exhale and curl the resistance band up towards your shoulders. Pause for a moment at the top, squeezing your biceps. Inhale and slowly lower the resistance band back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3123-XFc3vpY.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3123-XFc3vpY.gif', 'XFc3vpY', '© Gym visual — https://gymvisual.com/'),
('3124', 'resistance band seated chest press', 'Siéntate en una silla o banco con la espalda recta y los pies apoyados en el suelo. Sostén las asas de la banda elástica en cada mano, con las palmas hacia abajo y los codos flexionados en un ángulo de 90 grados. Extiende los brazos hacia adelante, alejando la banda elástica de tu pecho. Haz una pau', 'chest', 'resistance band', 'chest', 'chest', 'pectorals', '{"shoulders","triceps"}', 'Siéntate en una silla o banco con la espalda recta y los pies apoyados en el suelo. Sostén las asas de la banda elástica en cada mano, con las palmas hacia abajo y los codos flexionados en un ángulo de 90 grados. Extiende los brazos hacia adelante, alejando la banda elástica de tu pecho. Haz una pausa por un momento al final del movimiento, luego regresa lentamente a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a chair or bench with your back straight and feet flat on the ground. Hold the resistance band handles in each hand, with your palms facing down and elbows bent at a 90-degree angle. Extend your arms forward, pushing the resistance band away from your chest. Pause for a moment at the end of the movement, then slowly return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3124-4x5Okof.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3124-4x5Okof.gif', '4x5Okof', '© Gym visual — https://gymvisual.com/'),
('3006', 'resistance band seated hip abduction', 'Siéntate en una silla o banco con la espalda recta y los pies apoyados en el suelo. Envuelve la banda elástica alrededor de los muslos, justo por encima de las rodillas. Coloca las manos en los lados de la silla o el banco para mayor apoyo. Activa los abductores (los músculos externos del muslo) y e', 'upper legs', 'resistance band', 'upper legs', 'upper legs', 'abductors', '{"glutes","hamstrings"}', 'Siéntate en una silla o banco con la espalda recta y los pies apoyados en el suelo. Envuelve la banda elástica alrededor de los muslos, justo por encima de las rodillas. Coloca las manos en los lados de la silla o el banco para mayor apoyo. Activa los abductores (los músculos externos del muslo) y empuja lentamente las rodillas hacia afuera, contra la resistencia de la banda. Haz una pausa al final del movimiento y luego junta lentamente las rodillas de nuevo. Repite el número de repeticiones deseado.', 'Sit on a chair or bench with your back straight and feet flat on the ground. Wrap the resistance band around your thighs, just above your knees. Place your hands on the sides of the chair or bench for support. Engage your abductors (outer thigh muscles) and slowly push your knees apart, against the resistance of the band. Pause for a moment at the end of the movement, then slowly bring your knees back together. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3006-0xDpB4L.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3006-0xDpB4L.gif', '0xDpB4L', '© Gym visual — https://gymvisual.com/'),
('3122', 'resistance band seated shoulder press', 'Siéntate en una silla o banco con la espalda recta y los pies apoyados en el suelo. Sostén la banda elástica con ambas manos, con las palmas hacia adelante, y elévala hasta la altura de los hombros. Empuja la banda por encima de la cabeza, extendiendo completamente los brazos. Haz una pausa por un m', 'shoulders', 'resistance band', 'shoulders', 'shoulders', 'delts', '{"triceps","upper back"}', 'Siéntate en una silla o banco con la espalda recta y los pies apoyados en el suelo. Sostén la banda elástica con ambas manos, con las palmas hacia adelante, y elévala hasta la altura de los hombros. Empuja la banda por encima de la cabeza, extendiendo completamente los brazos. Haz una pausa por un momento en la parte alta y luego baja lentamente la banda hasta la altura de los hombros. Repite el número de repeticiones deseado.', 'Sit on a chair or bench with your back straight and feet flat on the ground. Hold the resistance band with both hands, palms facing forward, and bring it up to shoulder level. Press the band overhead, extending your arms fully. Pause for a moment at the top, then slowly lower the band back down to shoulder level. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3122-S93zLTG.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3122-S93zLTG.gif', 'S93zLTG', '© Gym visual — https://gymvisual.com/'),
('3144', 'resistance band seated straight back row', 'Siéntate en el suelo con las piernas extendidas y enrolla la banda elástica alrededor de los pies. Sostén los extremos de la banda elástica con las manos, con las palmas enfrentadas. Mantén la espalda recta e inclínate ligeramente hacia atrás, activando el core. Tira de la banda elástica hacia el pe', 'back', 'resistance band', 'back', 'back', 'upper back', '{"biceps","shoulders"}', 'Siéntate en el suelo con las piernas extendidas y enrolla la banda elástica alrededor de los pies. Sostén los extremos de la banda elástica con las manos, con las palmas enfrentadas. Mantén la espalda recta e inclínate ligeramente hacia atrás, activando el core. Tira de la banda elástica hacia el pecho, juntando las escápulas. Haz una pausa por un momento en la parte superior, luego suelta lentamente la tensión y regresa a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on the floor with your legs extended and loop the resistance band around your feet. Hold the ends of the resistance band with your hands, palms facing each other. Keep your back straight and lean slightly back, engaging your core. Pull the resistance band towards your chest, squeezing your shoulder blades together. Pause for a moment at the top, then slowly release the tension and return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3144-Nu7jqFE.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3144-Nu7jqFE.gif', 'Nu7jqFE', '© Gym visual — https://gymvisual.com/'),
('0872', 'reverse crunch', 'Túmbate boca arriba con los brazos extendidos a los lados del cuerpo. Flexiona las rodillas y levanta los pies del suelo, llevando los muslos perpendiculares al suelo. Contrae el abdomen y eleva las caderas del suelo, llevando las rodillas hacia el pecho. Haz una pausa por un momento en la parte sup', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"hip flexors"}', 'Túmbate boca arriba con los brazos extendidos a los lados del cuerpo. Flexiona las rodillas y levanta los pies del suelo, llevando los muslos perpendiculares al suelo. Contrae el abdomen y eleva las caderas del suelo, llevando las rodillas hacia el pecho. Haz una pausa por un momento en la parte superior, luego baja lentamente las caderas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on your back with your arms extended along your sides. Bend your knees and lift your feet off the ground, bringing your thighs perpendicular to the floor. Contract your abs and curl your hips off the floor, bringing your knees towards your chest. Pause for a moment at the top, then slowly lower your hips back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0872-nCU1Ekp.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0872-nCU1Ekp.gif', 'nCU1Ekp', '© Gym visual — https://gymvisual.com/'),
('0672', 'reverse dip', 'Colócate entre dos barras paralelas con los brazos completamente extendidos y el cuerpo recto. Baja el cuerpo flexionando los codos hasta que los brazos queden paralelos al suelo. Haz una pausa breve, luego empújate de nuevo hacia arriba a la posición inicial estirando los brazos. Repite el número d', 'upper arms', 'body weight', 'upper arms', 'upper arms', 'triceps', '{"chest","shoulders"}', 'Colócate entre dos barras paralelas con los brazos completamente extendidos y el cuerpo recto. Baja el cuerpo flexionando los codos hasta que los brazos queden paralelos al suelo. Haz una pausa breve, luego empújate de nuevo hacia arriba a la posición inicial estirando los brazos. Repite el número de repeticiones deseado.', 'Position yourself between two parallel bars with your arms fully extended and your body straight. Lower your body by bending your elbows until your upper arms are parallel to the ground. Pause for a moment, then push yourself back up to the starting position by straightening your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0672-NZ5Qqkz.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0672-NZ5Qqkz.gif', 'NZ5Qqkz', '© Gym visual — https://gymvisual.com/'),
('0673', 'reverse grip machine lat pulldown', 'Ajusta la altura del asiento y colócate en la máquina con las rodillas debajo de las almohadillas y los pies planos en el suelo. Sujeta las asas con un agarre supino, un poco más separadas que la altura de los hombros. Siéntate erguido con el pecho hacia afuera y los hombros hacia atrás, manteniendo', 'back', 'leverage machine', 'back', 'back', 'lats', '{"biceps","forearms"}', 'Ajusta la altura del asiento y colócate en la máquina con las rodillas debajo de las almohadillas y los pies planos en el suelo. Sujeta las asas con un agarre supino, un poco más separadas que la altura de los hombros. Siéntate erguido con el pecho hacia afuera y los hombros hacia atrás, manteniendo un ligero arco en la zona lumbar. Tira de las asas hacia el pecho, juntando las escápulas. Haz una pausa breve en la parte baja del movimiento, luego suelta lentamente las asas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the seat height and position yourself on the machine with your knees under the pads and your feet flat on the ground. Grasp the handles with an underhand grip, slightly wider than shoulder-width apart. Sit upright with your chest out and shoulders back, maintaining a slight arch in your lower back. Pull the handles down towards your chest, squeezing your shoulder blades together. Pause for a moment at the bottom of the movement, then slowly release the handles back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0673-ecpY0rH.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0673-ecpY0rH.gif', 'ecpY0rH', '© Gym visual — https://gymvisual.com/'),
('0674', 'reverse grip pull-up', 'Agarra la barra de dominadas con un agarre supino, con las manos separadas a la altura de los hombros. Cuélgate de la barra con los brazos completamente extendidos y el cuerpo recto. Activa los músculos de la espalda y tira de tu cuerpo hacia la barra, llevando el pecho por delante. Continúa subiend', 'back', 'body weight', 'back', 'back', 'lats', '{"biceps","forearms"}', 'Agarra la barra de dominadas con un agarre supino, con las manos separadas a la altura de los hombros. Cuélgate de la barra con los brazos completamente extendidos y el cuerpo recto. Activa los músculos de la espalda y tira de tu cuerpo hacia la barra, llevando el pecho por delante. Continúa subiendo hasta que la barbilla quede por encima de la barra. Haz una pausa por un momento en la parte superior, luego baja lentamente el cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Grab the pull-up bar with an underhand grip, hands shoulder-width apart. Hang from the bar with your arms fully extended and your body straight. Engage your back muscles and pull your body up towards the bar, leading with your chest. Continue pulling until your chin is above the bar. Pause for a moment at the top, then slowly lower your body back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0674-YAk5dIw.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0674-YAk5dIw.gif', 'YAk5dIw', '© Gym visual — https://gymvisual.com/'),
('0675', 'reverse hyper extension (on stability ball)', 'Túmbate boca abajo sobre un balón de estabilidad con las caderas apoyadas en el balón y las piernas extendidas rectas detrás de ti. Coloca las manos en el suelo frente a ti para mayor estabilidad. Activando los glúteos y los isquiotibiales, eleva las piernas hacia el techo tan alto como puedas. Haz ', 'upper legs', 'stability ball', 'upper legs', 'upper legs', 'glutes', '{"hamstrings","lower back"}', 'Túmbate boca abajo sobre un balón de estabilidad con las caderas apoyadas en el balón y las piernas extendidas rectas detrás de ti. Coloca las manos en el suelo frente a ti para mayor estabilidad. Activando los glúteos y los isquiotibiales, eleva las piernas hacia el techo tan alto como puedas. Haz una pausa por un momento en la parte superior, luego baja lentamente las piernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie face down on a stability ball with your hips resting on the ball and your legs extended straight behind you. Place your hands on the ground in front of you for stability. Engaging your glutes and hamstrings, lift your legs up towards the ceiling as high as you can. Pause for a moment at the top, then slowly lower your legs back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0675-vM5YS2g.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0675-vM5YS2g.gif', 'vM5YS2g', '© Gym visual — https://gymvisual.com/'),
('1423', 'reverse hyper on flat bench', 'Túmbate boca abajo en un banco plano con las caderas en el borde y las piernas colgando del banco. Sujétate del banco para mantener la estabilidad. Manteniendo las piernas rectas, elévalas hacia el techo tan alto como puedas. Aprieta los glúteos en la parte alta del movimiento. Baja lentamente las p', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'glutes', '{"hamstrings","lower back"}', 'Túmbate boca abajo en un banco plano con las caderas en el borde y las piernas colgando del banco. Sujétate del banco para mantener la estabilidad. Manteniendo las piernas rectas, elévalas hacia el techo tan alto como puedas. Aprieta los glúteos en la parte alta del movimiento. Baja lentamente las piernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie face down on a flat bench with your hips at the edge and your legs hanging off the bench. Hold onto the bench for stability. Keeping your legs straight, raise them up towards the ceiling as high as you can. Squeeze your glutes at the top of the movement. Slowly lower your legs back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1423-OrETs32.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1423-OrETs32.gif', 'OrETs32', '© Gym visual — https://gymvisual.com/'),
('3663', 'reverse plank with leg lift', 'Siéntate en el suelo con las piernas extendidas frente a ti y las manos apoyadas en el suelo detrás de ti, con los dedos apuntando hacia los pies. Presiona con las manos y levanta las caderas del suelo, llegando a una posición de plancha inversa. Activa el core y levanta una pierna del suelo, extend', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"glutes","hamstrings","shoulders"}', 'Siéntate en el suelo con las piernas extendidas frente a ti y las manos apoyadas en el suelo detrás de ti, con los dedos apuntando hacia los pies. Presiona con las manos y levanta las caderas del suelo, llegando a una posición de plancha inversa. Activa el core y levanta una pierna del suelo, extendiéndola recta hacia el techo. Mantén la posición por un momento y luego baja la pierna de nuevo. Repite con la otra pierna. Continúa alternando las piernas durante el número de repeticiones deseado.', 'Sit on the ground with your legs extended in front of you and your hands resting on the ground behind you, fingers pointing towards your feet. Press through your hands and lift your hips off the ground, coming into a reverse plank position. Engage your core and lift one leg off the ground, extending it straight up towards the ceiling. Hold for a moment, then lower your leg back down. Repeat with the other leg. Continue alternating legs for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3663-tFToB7l.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3663-tFToB7l.gif', 'tFToB7l', '© Gym visual — https://gymvisual.com/'),
('0677', 'ring dips', 'Comienza colgándote de las anillas con los brazos completamente extendidos y el cuerpo recto. Baja el cuerpo flexionando los codos hasta que los hombros queden por debajo de los codos. Empújate de vuelta hacia arriba a la posición inicial extendiendo los brazos. Repite el número de repeticiones dese', 'upper arms', 'body weight', 'upper arms', 'upper arms', 'triceps', '{"chest","shoulders"}', 'Comienza colgándote de las anillas con los brazos completamente extendidos y el cuerpo recto. Baja el cuerpo flexionando los codos hasta que los hombros queden por debajo de los codos. Empújate de vuelta hacia arriba a la posición inicial extendiendo los brazos. Repite el número de repeticiones deseado.', 'Start by hanging from the rings with your arms fully extended and your body straight. Lower your body by bending your elbows until your shoulders are below your elbows. Push yourself back up to the starting position by straightening your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0677-ezTvXcr.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0677-ezTvXcr.gif', 'ezTvXcr', '© Gym visual — https://gymvisual.com/'),
('2571', 'rocking frog stretch', 'Comienza arrodillándote en el suelo con las rodillas separadas a la altura de las caderas. Coloca las manos en el suelo frente a ti para mayor apoyo. Inclínate lentamente hacia adelante, desplazando el peso hacia las manos y extendiendo las piernas detrás de ti. Mantén la espalda recta y activa los ', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'glutes', '{"hamstrings","quadriceps"}', 'Comienza arrodillándote en el suelo con las rodillas separadas a la altura de las caderas. Coloca las manos en el suelo frente a ti para mayor apoyo. Inclínate lentamente hacia adelante, desplazando el peso hacia las manos y extendiendo las piernas detrás de ti. Mantén la espalda recta y activa los glúteos mientras empujas las caderas hacia atrás y hacia arriba en dirección al techo. Mantén esta posición durante unos segundos, sintiendo un estiramiento en los glúteos. Vuelve lentamente a la posición inicial flexionando las rodillas y bajando las caderas de nuevo. Repite el número de repeticiones deseado.', 'Start by kneeling on the ground with your knees hip-width apart. Place your hands on the ground in front of you for support. Slowly lean forward, shifting your weight onto your hands and extending your legs behind you. Keep your back straight and engage your glutes as you push your hips back and up towards the ceiling. Hold this position for a few seconds, feeling a stretch in your glutes. Slowly return to the starting position by bending your knees and lowering your hips back down. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2571-2Dk4xQV.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2571-2Dk4xQV.gif', '2Dk4xQV', '© Gym visual — https://gymvisual.com/'),
('0678', 'rocky pull-up pulldown', 'Ponte de pie frente a una barra de dominadas con los pies separados a la altura de los hombros. Estira los brazos hacia arriba y agarra la barra con agarre prono, ligeramente más ancho que la altura de los hombros. Cuélgate de la barra con los brazos completamente extendidos y el cuerpo recto. Activ', 'back', 'body weight', 'back', 'back', 'lats', '{"biceps","forearms"}', 'Ponte de pie frente a una barra de dominadas con los pies separados a la altura de los hombros. Estira los brazos hacia arriba y agarra la barra con agarre prono, ligeramente más ancho que la altura de los hombros. Cuélgate de la barra con los brazos completamente extendidos y el cuerpo recto. Activa los músculos de la espalda y tira de tu cuerpo hacia la barra, llevando el pecho por delante. Haz una pausa por un momento en la parte superior, luego baja lentamente el cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand in front of a pull-up bar with your feet shoulder-width apart. Reach up and grab the bar with an overhand grip, slightly wider than shoulder-width apart. Hang from the bar with your arms fully extended and your body straight. Engage your back muscles and pull your body up towards the bar, leading with your chest. Pause for a moment at the top, then slowly lower your body back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0678-cQ19bBP.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0678-cQ19bBP.gif', 'cQ19bBP', '© Gym visual — https://gymvisual.com/'),
('2208', 'roller back stretch', 'Comienza sentándote en el suelo con las piernas extendidas frente a ti. Coloca el rodillo perpendicular a tu cuerpo, justo debajo de los glúteos. Rueda lentamente el cuerpo hacia atrás, dejando que el rodillo se desplace hacia arriba por tu espalda. Continúa rodando hasta que el rodillo llegue a la ', 'back', 'roller', 'back', 'back', 'spine', '{"hamstrings","glutes"}', 'Comienza sentándote en el suelo con las piernas extendidas frente a ti. Coloca el rodillo perpendicular a tu cuerpo, justo debajo de los glúteos. Rueda lentamente el cuerpo hacia atrás, dejando que el rodillo se desplace hacia arriba por tu espalda. Continúa rodando hasta que el rodillo llegue a la parte superior de tu espalda. Haz una pausa por un momento y luego rueda lentamente de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Start by sitting on the ground with your legs extended in front of you. Place the roller perpendicular to your body, just below your glutes. Slowly roll your body backwards, allowing the roller to move up your back. Continue rolling until the roller reaches your upper back. Pause for a moment, then slowly roll back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2208-isofgzg.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2208-isofgzg.gif', 'isofgzg', '© Gym visual — https://gymvisual.com/'),
('2204', 'roller body saw', 'Comienza en posición de plancha con los antebrazos sobre el rodillo y el cuerpo en línea recta. Activa el core y rueda lentamente el rodillo hacia adelante, extendiendo el cuerpo tanto como puedas mientras mantienes el control. Haz una pausa por un momento en el punto más lejano y luego rueda lentam', 'waist', 'roller', 'waist', 'waist', 'abs', '{"shoulders","triceps","core"}', 'Comienza en posición de plancha con los antebrazos sobre el rodillo y el cuerpo en línea recta. Activa el core y rueda lentamente el rodillo hacia adelante, extendiendo el cuerpo tanto como puedas mientras mantienes el control. Haz una pausa por un momento en el punto más lejano y luego rueda lentamente el rodillo de vuelta hacia tu posición inicial. Repite el número de repeticiones deseado.', 'Start in a plank position with your forearms on the roller and your body in a straight line. Engage your core and slowly roll the roller forward, extending your body as far as you can while maintaining control. Pause for a moment at the furthest point, then slowly roll the roller back towards your starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2204-XeMvLgE.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2204-XeMvLgE.gif', 'XeMvLgE', '© Gym visual — https://gymvisual.com/'),
('2205', 'roller hip lat stretch', 'Comienza arrodillándote en el suelo con el rodillo colocado debajo de las caderas. Coloca las manos sobre el rodillo para mayor apoyo. Rueda lentamente el rodillo hacia adelante, extendiendo las caderas y estirando los glúteos. Mantén el estiramiento durante unos segundos, luego regresa a la posició', 'upper legs', 'roller', 'upper legs', 'upper legs', 'glutes', '{"hamstrings","quadriceps"}', 'Comienza arrodillándote en el suelo con el rodillo colocado debajo de las caderas. Coloca las manos sobre el rodillo para mayor apoyo. Rueda lentamente el rodillo hacia adelante, extendiendo las caderas y estirando los glúteos. Mantén el estiramiento durante unos segundos, luego regresa a la posición inicial. Repite el número de repeticiones deseado.', 'Start by kneeling on the ground with the roller positioned under your hips. Place your hands on the roller for support. Slowly roll the roller forward, extending your hips and stretching your glutes. Hold the stretch for a few seconds, then roll back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2205-0L2KwtI.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2205-0L2KwtI.gif', '0L2KwtI', '© Gym visual — https://gymvisual.com/'),
('2202', 'roller hip stretch', 'Comienza sentándote en el suelo con las piernas extendidas frente a ti. Coloca el rodillo debajo de los glúteos, justo por encima de las rodillas. Inclínate hacia atrás y coloca las manos en el suelo detrás de ti para apoyarte. Activa los glúteos y rueda lentamente el rodillo hacia adelante, flexion', 'upper legs', 'roller', 'upper legs', 'upper legs', 'glutes', '{"hamstrings","quadriceps"}', 'Comienza sentándote en el suelo con las piernas extendidas frente a ti. Coloca el rodillo debajo de los glúteos, justo por encima de las rodillas. Inclínate hacia atrás y coloca las manos en el suelo detrás de ti para apoyarte. Activa los glúteos y rueda lentamente el rodillo hacia adelante, flexionando las rodillas y llevándolas hacia el pecho. Haz una pausa al final del movimiento, sintiendo un estiramiento en los glúteos. Rueda lentamente el rodillo de vuelta a la posición inicial, extendiendo las piernas. Repite el número de repeticiones deseado.', 'Start by sitting on the ground with your legs extended in front of you. Place the roller under your glutes, just above your knees. Lean back and place your hands on the ground behind you for support. Engage your glutes and slowly roll the roller forward, bending your knees and bringing them towards your chest. Pause for a moment at the end of the movement, feeling a stretch in your glutes. Slowly roll the roller back to the starting position, extending your legs. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2202-oMypNrz.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2202-oMypNrz.gif', 'oMypNrz', '© Gym visual — https://gymvisual.com/'),
('2206', 'roller reverse crunch', 'Túmbate boca arriba con los brazos extendidos rectos por encima de la cabeza y las piernas rectas frente a ti. Coloca el rodillo entre los pies y sujétalo con los dedos de los pies. Activando el abdomen, levanta las piernas del suelo y flexiona las rodillas hacia el pecho, rodando el rodillo hacia t', 'waist', 'roller', 'waist', 'waist', 'abs', '{"hip flexors"}', 'Túmbate boca arriba con los brazos extendidos rectos por encima de la cabeza y las piernas rectas frente a ti. Coloca el rodillo entre los pies y sujétalo con los dedos de los pies. Activando el abdomen, levanta las piernas del suelo y flexiona las rodillas hacia el pecho, rodando el rodillo hacia tu cuerpo. Haz una pausa por un momento en la parte alta y luego baja lentamente las piernas de vuelta a la posición inicial, rodando el rodillo alejándolo de tu cuerpo. Repite el número de repeticiones deseado.', 'Lie flat on your back with your arms extended straight above your head and your legs straight out in front of you. Place the roller between your feet and grip it with your toes. Engaging your abs, lift your legs off the ground and curl your knees towards your chest, rolling the roller towards your body. Pause for a moment at the top, then slowly lower your legs back down to the starting position, rolling the roller away from your body. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2206-SKXQAx3.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2206-SKXQAx3.gif', 'SKXQAx3', '© Gym visual — https://gymvisual.com/'),
('2203', 'roller seated shoulder flexor depresor retractor', 'Siéntate sobre una superficie plana con las piernas extendidas frente a ti. Sostén el rodillo con ambas manos, con las palmas hacia abajo, y colócalo sobre tus muslos. Inclínate ligeramente hacia delante y aleja el rodillo de tu cuerpo, extendiendo los brazos rectos frente a ti. Haz una pausa por un', 'chest', 'roller', 'chest', 'chest', 'pectorals', '{"deltoids","triceps"}', 'Siéntate sobre una superficie plana con las piernas extendidas frente a ti. Sostén el rodillo con ambas manos, con las palmas hacia abajo, y colócalo sobre tus muslos. Inclínate ligeramente hacia delante y aleja el rodillo de tu cuerpo, extendiendo los brazos rectos frente a ti. Haz una pausa por un momento, luego rueda el rodillo lentamente de vuelta hacia tu cuerpo, doblando los brazos y trayéndolo de nuevo hacia los muslos. Repite el número de repeticiones deseado.', 'Sit on a flat surface with your legs extended in front of you. Hold the roller with both hands, palms facing down, and place it on your thighs. Lean forward slightly and roll the roller away from your body, extending your arms straight in front of you. Pause for a moment, then slowly roll the roller back towards your body, bending your arms and bringing the roller back to your thighs. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2203-8coXSYU.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2203-8coXSYU.gif', '8coXSYU', '© Gym visual — https://gymvisual.com/'),
('2209', 'roller seated single leg shoulder flexor depresor retractor', 'Siéntate sobre una superficie plana con las piernas extendidas frente a ti. Sostén el rodillo con ambas manos, con las palmas hacia abajo, y colócalo sobre tus muslos. Inclínate ligeramente hacia atrás y contrae los músculos del core. Eleva el rodillo hasta la altura de los hombros, manteniendo los ', 'chest', 'roller', 'chest', 'chest', 'pectorals', '{"deltoids","triceps"}', 'Siéntate sobre una superficie plana con las piernas extendidas frente a ti. Sostén el rodillo con ambas manos, con las palmas hacia abajo, y colócalo sobre tus muslos. Inclínate ligeramente hacia atrás y contrae los músculos del core. Eleva el rodillo hasta la altura de los hombros, manteniendo los brazos rectos. Baja lentamente el rodillo de nuevo hacia los muslos. Repite el número de repeticiones deseado.', 'Sit on a flat surface with your legs extended in front of you. Hold the roller with both hands, palms facing down, and place it on your thighs. Lean back slightly and engage your core muscles. Raise the roller up to shoulder level, keeping your arms straight. Slowly lower the roller back down to your thighs. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2209-CjETvlw.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2209-CjETvlw.gif', 'CjETvlw', '© Gym visual — https://gymvisual.com/'),
('2207', 'roller side lat stretch', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta el rodillo con ambas manos frente al cuerpo. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta. Extiende los brazos hacia delante y rueda el rodillo hacia los pies, sint', 'back', 'roller', 'back', 'back', 'lats', '{"shoulders","triceps"}', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta el rodillo con ambas manos frente al cuerpo. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta. Extiende los brazos hacia delante y rueda el rodillo hacia los pies, sintiendo un estiramiento en los dorsales. Mantén el estiramiento durante unos segundos, luego rueda el rodillo lentamente de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and hold the roller with both hands in front of your body. Bend your knees slightly and hinge forward at the hips, keeping your back straight. Extend your arms forward and roll the roller down towards your feet, feeling a stretch in your lats. Hold the stretch for a few seconds, then slowly roll the roller back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2207-c3Pfhti.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2207-c3Pfhti.gif', 'c3Pfhti', '© Gym visual — https://gymvisual.com/'),
('0680', 'rope climb', 'Ponte de pie frente a la cuerda con los pies separados a la altura de los hombros. Sujeta la cuerda con ambas manos, con las palmas mirando hacia ti. Flexiona ligeramente las rodillas y activa el core. Comienza a subir por la cuerda alternando los movimientos de las manos. Usa las piernas para ayuda', 'back', 'rope', 'back', 'back', 'upper back', '{"forearms","biceps","shoulders"}', 'Ponte de pie frente a la cuerda con los pies separados a la altura de los hombros. Sujeta la cuerda con ambas manos, con las palmas mirando hacia ti. Flexiona ligeramente las rodillas y activa el core. Comienza a subir por la cuerda alternando los movimientos de las manos. Usa las piernas para ayudar en el movimiento ascendente. Continúa trepando hasta alcanzar la altura deseada o la parte superior de la cuerda. Para descender, invierte el movimiento alterno de las manos mientras controlas tu descenso. Repite el número de repeticiones deseado.', 'Stand facing the rope with your feet shoulder-width apart. Grab the rope with both hands, palms facing towards you. Bend your knees slightly and engage your core. Begin pulling yourself up the rope by alternating hand-over-hand movements. Use your legs to assist in the upward movement. Continue climbing until you reach the desired height or the top of the rope. To descend, reverse the hand-over-hand movement while controlling your descent. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0680-yaAxcQr.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0680-yaAxcQr.gif', 'yaAxcQr', '© Gym visual — https://gymvisual.com/'),
('0685', 'run', 'Comienza de pie con los pies separados a la altura de la cadera. Activa el core y mantén la parte superior del cuerpo relajada. Comienza a trotar en el lugar, levantando las rodillas hacia el pecho y aterrizando suavemente sobre la punta de los pies. Mantén un ritmo constante y continúa trotando dur', 'cardio', 'body weight', 'cardio', 'cardio', 'cardiovascular system', '{"quadriceps","hamstrings","calves"}', 'Comienza de pie con los pies separados a la altura de la cadera. Activa el core y mantén la parte superior del cuerpo relajada. Comienza a trotar en el lugar, levantando las rodillas hacia el pecho y aterrizando suavemente sobre la punta de los pies. Mantén un ritmo constante y continúa trotando durante la duración o distancia deseada. Recuerda respirar profundamente y mantener una buena postura durante todo el ejercicio.', 'Start by standing upright with your feet hip-width apart. Engage your core and keep your upper body relaxed. Begin jogging in place, lifting your knees up towards your chest and landing softly on the balls of your feet. Maintain a steady pace and continue jogging for the desired duration or distance. Remember to breathe deeply and maintain good posture throughout the exercise.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0685-oLrKqDH.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0685-oLrKqDH.gif', 'oLrKqDH', '© Gym visual — https://gymvisual.com/'),
('0684', 'run (equipment)', 'Comienza de pie con los pies separados a la altura de la cadera. Activa el core y mantén la parte superior del cuerpo relajada. Comienza a trotar en el lugar, levantando las rodillas hacia el pecho y aterrizando suavemente sobre la punta de los pies. Mantén un ritmo constante y continúa trotando dur', 'cardio', 'body weight', 'cardio', 'cardio', 'cardiovascular system', '{"quadriceps","hamstrings","calves"}', 'Comienza de pie con los pies separados a la altura de la cadera. Activa el core y mantén la parte superior del cuerpo relajada. Comienza a trotar en el lugar, levantando las rodillas hacia el pecho y aterrizando suavemente sobre la punta de los pies. Mantén un ritmo constante y continúa trotando durante la duración o distancia deseada. Recuerda respirar profundamente y mantener una buena postura durante todo el ejercicio.', 'Start by standing upright with your feet hip-width apart. Engage your core and keep your upper body relaxed. Begin jogging in place, lifting your knees up towards your chest and landing softly on the balls of your feet. Maintain a steady pace and continue jogging for the desired duration or distance. Remember to breathe deeply and maintain good posture throughout the exercise.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0684-y5p0H8a.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0684-y5p0H8a.gif', 'y5p0H8a', '© Gym visual — https://gymvisual.com/'),
('1585', 'runners stretch', 'Ponte de pie con los pies separados a la altura de la cadera. Da un paso hacia delante con el pie derecho, manteniendo el pie izquierdo firme en el suelo. Dobla la rodilla derecha y baja el cuerpo, manteniendo la pierna izquierda recta. Coloca las manos sobre el muslo derecho para apoyarte. Mantén e', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'hamstrings', '{"calves","quadriceps"}', 'Ponte de pie con los pies separados a la altura de la cadera. Da un paso hacia delante con el pie derecho, manteniendo el pie izquierdo firme en el suelo. Dobla la rodilla derecha y baja el cuerpo, manteniendo la pierna izquierda recta. Coloca las manos sobre el muslo derecho para apoyarte. Mantén el estiramiento durante 20-30 segundos, luego cambia de lado y repite.', 'Stand with your feet hip-width apart. Take a step forward with your right foot, keeping your left foot planted. Bend your right knee and lower your body down, keeping your left leg straight. Place your hands on your right thigh for support. Hold the stretch for 20-30 seconds, then switch sides and repeat.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1585-0mB6wHO.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1585-0mB6wHO.gif', '0mB6wHO', '© Gym visual — https://gymvisual.com/'),
('0687', 'russian twist', 'Siéntate en el suelo con las rodillas flexionadas y los pies apoyados en el suelo. Inclínate ligeramente hacia atrás manteniendo la espalda recta y el core activado. Junta las manos frente al pecho o sujeta una pesa si lo deseas. Levanta los pies del suelo, equilibrándote sobre los isquiones. Gira e', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"obliques"}', 'Siéntate en el suelo con las rodillas flexionadas y los pies apoyados en el suelo. Inclínate ligeramente hacia atrás manteniendo la espalda recta y el core activado. Junta las manos frente al pecho o sujeta una pesa si lo deseas. Levanta los pies del suelo, equilibrándote sobre los isquiones. Gira el torso hacia la derecha, llevando las manos o la pesa hacia el lado derecho del cuerpo. Haz una pausa por un momento, luego gira el torso hacia la izquierda, llevando las manos o la pesa hacia el lado izquierdo del cuerpo. Continúa alternando lados durante el número de repeticiones deseado.', 'Sit on the ground with your knees bent and feet flat on the floor. Lean back slightly while keeping your back straight and your core engaged. Hold your hands together in front of your chest or hold a weight if desired. Lift your feet off the ground, balancing on your sit bones. Twist your torso to the right, bringing your hands or weight towards the right side of your body. Pause for a moment, then twist your torso to the left, bringing your hands or weight towards the left side of your body. Continue alternating sides for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0687-XVDdcoj.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0687-XVDdcoj.gif', 'XVDdcoj', '© Gym visual — https://gymvisual.com/'),
('3012', 'scapula dips', 'Comienza de pie con los pies separados a la altura de los hombros y los brazos extendidos frente a ti. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta. Baja el cuerpo doblando los codos y retrayendo las escápulas, como si intentaras apreta', 'back', 'body weight', 'back', 'back', 'traps', '{"rhomboids","deltoids"}', 'Comienza de pie con los pies separados a la altura de los hombros y los brazos extendidos frente a ti. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta. Baja el cuerpo doblando los codos y retrayendo las escápulas, como si intentaras apretar un lápiz entre ellas. Haz una pausa por un momento en la posición baja, luego empuja con las manos para extender los codos y volver a la posición inicial. Repite el número de repeticiones deseado.', 'Start by standing with your feet shoulder-width apart and your arms extended in front of you. Bend your knees slightly and hinge forward at the hips, keeping your back straight. Lower your body by bending your elbows and retracting your shoulder blades, as if you are trying to squeeze a pencil between them. Pause for a moment at the bottom, then push through your hands to extend your elbows and return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3012-7xeukSt.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3012-7xeukSt.gif', '7xeukSt', '© Gym visual — https://gymvisual.com/'),
('3021', 'scapula push-up', 'Comienza en una posición de plancha alta con las manos justo debajo de los hombros y el cuerpo en línea recta. Baja el pecho hacia el suelo, manteniendo los codos cerca del cuerpo. A medida que bajas, junta las escápulas y empuja el pecho hacia delante. Haz una pausa por un momento en la posición ba', 'chest', 'body weight', 'chest', 'chest', 'serratus anterior', '{"triceps","shoulders"}', 'Comienza en una posición de plancha alta con las manos justo debajo de los hombros y el cuerpo en línea recta. Baja el pecho hacia el suelo, manteniendo los codos cerca del cuerpo. A medida que bajas, junta las escápulas y empuja el pecho hacia delante. Haz una pausa por un momento en la posición baja, luego empuja de nuevo hacia arriba hasta la posición inicial. Repite el número de repeticiones deseado.', 'Start in a high plank position with your hands directly under your shoulders and your body in a straight line. Lower your chest towards the ground, keeping your elbows close to your body. As you lower, squeeze your shoulder blades together and push your chest forward. Pause for a moment at the bottom, then push back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3021-jV65tKx.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3021-jV65tKx.gif', 'jV65tKx', '© Gym visual — https://gymvisual.com/'),
('0688', 'scapular pull-up', 'Comienza colgándote de una barra de dominadas con las palmas hacia afuera y los brazos completamente extendidos. Retrae las escápulas llevándolas hacia abajo y atrás. Activa los músculos de la espalda y tira de tu cuerpo hacia la barra, enfocándote en juntar las escápulas. Haz una pausa breve en la ', 'back', 'body weight', 'back', 'back', 'traps', '{"biceps","rhomboids","rear deltoids"}', 'Comienza colgándote de una barra de dominadas con las palmas hacia afuera y los brazos completamente extendidos. Retrae las escápulas llevándolas hacia abajo y atrás. Activa los músculos de la espalda y tira de tu cuerpo hacia la barra, enfocándote en juntar las escápulas. Haz una pausa breve en la parte superior del movimiento, luego baja lentamente el cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Start by hanging from a pull-up bar with your palms facing away from you and your arms fully extended. Retract your shoulder blades by pulling them down and back. Engage your back muscles and pull your body up towards the bar, focusing on squeezing your shoulder blades together. Pause for a moment at the top of the movement, then slowly lower your body back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0688-uTBt1HV.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0688-uTBt1HV.gif', 'uTBt1HV', '© Gym visual — https://gymvisual.com/'),
('3219', 'scissor jumps (male)', 'Ponte de pie con los pies separados a la altura de los hombros. Salta del suelo y al mismo tiempo cruza la pierna derecha por delante de la pierna izquierda. Al aterrizar, cambia rápidamente de pierna, cruzando la pierna izquierda por delante de la pierna derecha. Continúa alternando las piernas y s', 'cardio', 'body weight', 'cardio', 'cardio', 'cardiovascular system', '{"quadriceps","hamstrings","calves"}', 'Ponte de pie con los pies separados a la altura de los hombros. Salta del suelo y al mismo tiempo cruza la pierna derecha por delante de la pierna izquierda. Al aterrizar, cambia rápidamente de pierna, cruzando la pierna izquierda por delante de la pierna derecha. Continúa alternando las piernas y saltando lo más rápido posible. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart. Jump off the ground and simultaneously cross your right leg in front of your left leg. As you land, quickly switch legs, crossing your left leg in front of your right leg. Continue alternating legs and jumping as quickly as possible. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3219-Eh2v5Iu.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3219-Eh2v5Iu.gif', 'Eh2v5Iu', '© Gym visual — https://gymvisual.com/'),
('1390', 'seated calf stretch (male)', 'Siéntate en el borde de una silla o banco con los pies planos sobre el suelo. Extiende una pierna recta frente a ti, manteniendo el talón en el suelo. Inclínate ligeramente hacia delante, sintiendo un estiramiento en la pantorrilla. Mantén el estiramiento durante 20-30 segundos. Cambia de pierna y r', 'lower legs', 'body weight', 'lower legs', 'lower legs', 'calves', '{"hamstrings"}', 'Siéntate en el borde de una silla o banco con los pies planos sobre el suelo. Extiende una pierna recta frente a ti, manteniendo el talón en el suelo. Inclínate ligeramente hacia delante, sintiendo un estiramiento en la pantorrilla. Mantén el estiramiento durante 20-30 segundos. Cambia de pierna y repite el estiramiento.', 'Sit on the edge of a chair or bench with your feet flat on the ground. Extend one leg straight out in front of you, keeping your heel on the ground. Lean forward slightly, feeling a stretch in your calf muscle. Hold the stretch for 20-30 seconds. Switch legs and repeat the stretch.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1390-17bqEXD.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1390-17bqEXD.gif', '17bqEXD', '© Gym visual — https://gymvisual.com/'),
('1424', 'seated glute stretch', 'Siéntate en el suelo con las piernas extendidas frente a ti. Dobla la rodilla derecha y cruza el tobillo derecho sobre el muslo izquierdo. Coloca la mano derecha en el suelo detrás de ti para apoyarte. Con la mano izquierda, presiona suavemente la rodilla derecha para profundizar el estiramiento. Ma', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'glutes', '{"hamstrings"}', 'Siéntate en el suelo con las piernas extendidas frente a ti. Dobla la rodilla derecha y cruza el tobillo derecho sobre el muslo izquierdo. Coloca la mano derecha en el suelo detrás de ti para apoyarte. Con la mano izquierda, presiona suavemente la rodilla derecha para profundizar el estiramiento. Mantén el estiramiento durante 30 segundos a 1 minuto. Cambia de lado y repite.', 'Sit on the ground with your legs extended in front of you. Bend your right knee and cross your right ankle over your left thigh. Place your right hand on the ground behind you for support. With your left hand, gently press down on your right knee to deepen the stretch. Hold the stretch for 30 seconds to 1 minute. Switch sides and repeat.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1424-DeDThfG.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1424-DeDThfG.gif', 'DeDThfG', '© Gym visual — https://gymvisual.com/'),
('0689', 'seated leg raise', 'Siéntate en un banco plano con la espalda recta y los pies planos sobre el suelo. Coloca las manos a los lados del banco para apoyarte. Manteniendo las piernas rectas, levántalas lentamente frente a ti hasta que queden paralelas al suelo. Haz una pausa por un momento en la parte superior, luego baja', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"hip flexors"}', 'Siéntate en un banco plano con la espalda recta y los pies planos sobre el suelo. Coloca las manos a los lados del banco para apoyarte. Manteniendo las piernas rectas, levántalas lentamente frente a ti hasta que queden paralelas al suelo. Haz una pausa por un momento en la parte superior, luego baja lentamente las piernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a flat bench with your back straight and your feet flat on the ground. Place your hands on the sides of the bench for support. Keeping your legs straight, slowly raise them up in front of you until they are parallel to the ground. Pause for a moment at the top, then slowly lower your legs back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0689-Hgs6Nl1.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0689-Hgs6Nl1.gif', 'Hgs6Nl1', '© Gym visual — https://gymvisual.com/'),
('0690', 'seated lower back stretch', 'Siéntate en el borde de una silla con los pies planos sobre el suelo. Coloca las manos sobre los muslos o a los lados de la silla para apoyarte. Inclínate lentamente hacia delante desde la cadera, manteniendo la espalda recta. Siente el estiramiento en la zona lumbar y mantén la posición durante 20-', 'back', 'body weight', 'back', 'back', 'lats', '{"glutes","hamstrings"}', 'Siéntate en el borde de una silla con los pies planos sobre el suelo. Coloca las manos sobre los muslos o a los lados de la silla para apoyarte. Inclínate lentamente hacia delante desde la cadera, manteniendo la espalda recta. Siente el estiramiento en la zona lumbar y mantén la posición durante 20-30 segundos. Regresa lentamente a la posición inicial y repite el número de repeticiones deseado.', 'Sit on the edge of a chair with your feet flat on the ground. Place your hands on your thighs or on the sides of the chair for support. Slowly lean forward from your hips, keeping your back straight. Feel the stretch in your lower back and hold for 20-30 seconds. Slowly return to the starting position and repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0690-QFmz6ch.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0690-QFmz6ch.gif', 'QFmz6ch', '© Gym visual — https://gymvisual.com/'),
('2567', 'seated piriformis stretch', 'Siéntate en el suelo con las piernas extendidas frente a ti. Dobla la rodilla derecha y coloca el pie derecho en la parte exterior de la rodilla izquierda. Coloca el codo izquierdo en la parte exterior de la rodilla derecha y gira suavemente el torso hacia la derecha. Mantén el estiramiento durante ', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'glutes', '{"hamstrings"}', 'Siéntate en el suelo con las piernas extendidas frente a ti. Dobla la rodilla derecha y coloca el pie derecho en la parte exterior de la rodilla izquierda. Coloca el codo izquierdo en la parte exterior de la rodilla derecha y gira suavemente el torso hacia la derecha. Mantén el estiramiento durante 20-30 segundos, luego cambia de lado y repite.', 'Sit on the ground with your legs extended in front of you. Bend your right knee and place your right foot on the outside of your left knee. Place your left elbow on the outside of your right knee and gently twist your torso to the right. Hold the stretch for 20-30 seconds, then switch sides and repeat.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2567-QY39eBr.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2567-QY39eBr.gif', 'QY39eBr', '© Gym visual — https://gymvisual.com/'),
('0691', 'seated side crunch (wall)', 'Siéntate en el suelo con la espalda contra una pared y las piernas extendidas frente a ti. Dobla las rodillas y coloca los pies planos sobre el suelo, separados a la altura de la cadera. Coloca las manos detrás de la cabeza con los codos apuntando hacia afuera. Contrae el abdomen e inclínate hacia u', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"obliques"}', 'Siéntate en el suelo con la espalda contra una pared y las piernas extendidas frente a ti. Dobla las rodillas y coloca los pies planos sobre el suelo, separados a la altura de la cadera. Coloca las manos detrás de la cabeza con los codos apuntando hacia afuera. Contrae el abdomen e inclínate hacia un lado, llevando el codo hacia la cadera. Haz una pausa breve y luego vuelve a la posición inicial. Repite del otro lado. Continúa alternando lados durante el número de repeticiones deseado.', 'Sit on the floor with your back against a wall and your legs extended in front of you. Bend your knees and place your feet flat on the floor, hip-width apart. Place your hands behind your head with your elbows pointing outwards. Engage your abs and lean to one side, bringing your elbow towards your hip. Pause for a moment, then return to the starting position. Repeat on the other side. Continue alternating sides for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0691-Y9hNPcN.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0691-Y9hNPcN.gif', 'Y9hNPcN', '© Gym visual — https://gymvisual.com/'),
('1587', 'seated wide angle pose sequence', 'Siéntate en el suelo con las piernas extendidas formando un ángulo amplio. Flexiona los pies y contrae los cuádriceps. Coloca las manos en el suelo detrás de ti para apoyarte. Manteniendo la espalda recta, inclínate hacia delante desde la cadera. Continúa inclinándote hacia delante hasta sentir un e', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'hamstrings', '{"quadriceps","calves"}', 'Siéntate en el suelo con las piernas extendidas formando un ángulo amplio. Flexiona los pies y contrae los cuádriceps. Coloca las manos en el suelo detrás de ti para apoyarte. Manteniendo la espalda recta, inclínate hacia delante desde la cadera. Continúa inclinándote hacia delante hasta sentir un estiramiento en los isquiotibiales. Mantén esta posición durante unas cuantas respiraciones. Libera lentamente el estiramiento y vuelve a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on the ground with your legs extended in a wide angle. Flex your feet and engage your quadriceps. Place your hands on the ground behind you for support. Keeping your back straight, lean forward from your hips. Continue leaning forward until you feel a stretch in your hamstrings. Hold this position for a few breaths. Slowly release the stretch and return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1587-HIgYKAB.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1587-HIgYKAB.gif', 'HIgYKAB', '© Gym visual — https://gymvisual.com/'),
('0697', 'self assisted inverse leg curl', 'Túmbate boca arriba sobre una esterilla o banco con las piernas extendidas. Coloca las manos a los lados o debajo de los glúteos para apoyarte. Dobla las rodillas y levanta los pies del suelo, llevando los muslos hacia el pecho. Haz una pausa por un momento en la parte superior, luego baja lentament', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'hamstrings', '{"glutes","calves"}', 'Túmbate boca arriba sobre una esterilla o banco con las piernas extendidas. Coloca las manos a los lados o debajo de los glúteos para apoyarte. Dobla las rodillas y levanta los pies del suelo, llevando los muslos hacia el pecho. Haz una pausa por un momento en la parte superior, luego baja lentamente las piernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on your back on a mat or bench with your legs extended. Place your hands by your sides or under your glutes for support. Bend your knees and lift your feet off the ground, bringing your thighs towards your chest. Pause for a moment at the top, then slowly lower your legs back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0697-GwYwElT.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0697-GwYwElT.gif', 'GwYwElT', '© Gym visual — https://gymvisual.com/'),
('1766', 'self assisted inverse leg curl', 'Túmbate boca abajo en una máquina de curl femoral con las piernas extendidas y los tobillos enganchados bajo la palanca acolchada. Coloca las manos en las asas laterales de la máquina para apoyarte. Manteniendo la parte superior del cuerpo inmóvil, exhala y flexiona las piernas hacia arriba lo más p', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'hamstrings', '{"glutes","calves"}', 'Túmbate boca abajo en una máquina de curl femoral con las piernas extendidas y los tobillos enganchados bajo la palanca acolchada. Coloca las manos en las asas laterales de la máquina para apoyarte. Manteniendo la parte superior del cuerpo inmóvil, exhala y flexiona las piernas hacia arriba lo más posible. Mantén la posición contraída durante una pausa breve mientras aprietas los isquiotibiales. Baja lentamente las piernas de vuelta a la posición inicial mientras inhalas. Repite el número de repeticiones deseado.', 'Lie face down on a leg curl machine with your legs extended and your ankles hooked under the padded lever. Place your hands on the side handles of the machine for support. Keeping your upper body stationary, exhale and curl your legs upward as far as possible. Hold the contracted position for a brief pause as you squeeze your hamstrings. Slowly lower your legs back to the starting position while inhaling. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1766-ZSY3MsL.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1766-ZSY3MsL.gif', 'ZSY3MsL', '© Gym visual — https://gymvisual.com/'),
('0696', 'self assisted inverse leg curl (on floor)', 'Túmbate sobre tu espalda con las piernas extendidas y los brazos a los lados. Dobla las rodillas y coloca los pies planos sobre el suelo, separados a la altura de la cadera. Levanta las caderas del suelo, activando los glúteos y los isquiotibiales. Flexiona lentamente las piernas hacia los glúteos, ', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'hamstrings', '{"glutes","calves"}', 'Túmbate sobre tu espalda con las piernas extendidas y los brazos a los lados. Dobla las rodillas y coloca los pies planos sobre el suelo, separados a la altura de la cadera. Levanta las caderas del suelo, activando los glúteos y los isquiotibiales. Flexiona lentamente las piernas hacia los glúteos, manteniendo las caderas elevadas. Haz una pausa breve en la parte superior, luego extiende lentamente las piernas de vuelta a la posición inicial. Baja las caderas de nuevo hacia el suelo. Repite el número de repeticiones deseado.', 'Lie flat on your back with your legs extended and your arms by your sides. Bend your knees and place your feet flat on the ground, hip-width apart. Lift your hips off the ground, engaging your glutes and hamstrings. Slowly curl your legs towards your glutes, keeping your hips lifted. Pause for a moment at the top, then slowly extend your legs back to the starting position. Lower your hips back down to the ground. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0696-E4PwJqI.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0696-E4PwJqI.gif', 'E4PwJqI', '© Gym visual — https://gymvisual.com/'),
('3222', 'semi squat jump (male)', 'Ponte de pie con los pies separados a la altura de los hombros. Flexiona las rodillas y baja el cuerpo hacia una posición de sentadilla. Salta de forma explosiva, extendiendo las caderas y las rodillas mientras balanceas los brazos para generar impulso. Aterriza suavemente sobre la punta de los pies', 'cardio', 'body weight', 'cardio', 'cardio', 'cardiovascular system', '{"quadriceps","hamstrings","calves"}', 'Ponte de pie con los pies separados a la altura de los hombros. Flexiona las rodillas y baja el cuerpo hacia una posición de sentadilla. Salta de forma explosiva, extendiendo las caderas y las rodillas mientras balanceas los brazos para generar impulso. Aterriza suavemente sobre la punta de los pies y pasa de inmediato a la siguiente repetición. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart. Bend your knees and lower your body into a squat position. Jump explosively, extending your hips and knees while swinging your arms for momentum. Land softly on the balls of your feet and immediately go into the next repetition. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3222-6FMU51h.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3222-6FMU51h.gif', '6FMU51h', '© Gym visual — https://gymvisual.com/'),
('3656', 'short stride run', 'Busca un espacio abierto o una cinta de correr para realizar el ejercicio. Ponte de pie con los pies separados a la altura de la cadera. Comienza a trotar en el lugar, levantando las rodillas alto y moviendo los brazos. Después de unos segundos, comienza a dar pasos cortos hacia delante, manteniendo', 'cardio', 'body weight', 'cardio', 'cardio', 'cardiovascular system', '{"quadriceps","hamstrings","calves"}', 'Busca un espacio abierto o una cinta de correr para realizar el ejercicio. Ponte de pie con los pies separados a la altura de la cadera. Comienza a trotar en el lugar, levantando las rodillas alto y moviendo los brazos. Después de unos segundos, comienza a dar pasos cortos hacia delante, manteniendo un ritmo rápido. Continúa corriendo con pasos cortos durante la duración o distancia deseada.', 'Find an open space or a treadmill to perform the exercise. Stand tall with your feet hip-width apart. Start jogging in place, lifting your knees high and pumping your arms. After a few seconds, start taking short strides forward, maintaining a quick pace. Continue running with short strides for the desired duration or distance.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3656-CcWEoWV.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3656-CcWEoWV.gif', 'CcWEoWV', '© Gym visual — https://gymvisual.com/'),
('1763', 'shoulder grip pull-up', 'Sujeta la barra de dominadas con un agarre a la altura de los hombros, con las palmas mirando hacia fuera. Cuélgate libremente con los brazos completamente extendidos. Activa los músculos de la espalda y tira de tu cuerpo hacia la barra hasta que la barbilla quede por encima de ella. Haz una pausa p', 'back', 'body weight', 'back', 'back', 'lats', '{"biceps","forearms"}', 'Sujeta la barra de dominadas con un agarre a la altura de los hombros, con las palmas mirando hacia fuera. Cuélgate libremente con los brazos completamente extendidos. Activa los músculos de la espalda y tira de tu cuerpo hacia la barra hasta que la barbilla quede por encima de ella. Haz una pausa por un momento en la parte superior, luego baja lentamente el cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Grab the pull-up bar with a shoulder-width grip, palms facing away from you. Hang freely with your arms fully extended. Engage your back muscles and pull your body up towards the bar until your chin is above the bar. Pause for a moment at the top, then slowly lower your body back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1763-YtgD7Xq.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1763-YtgD7Xq.gif', 'YtgD7Xq', '© Gym visual — https://gymvisual.com/'),
('3699', 'shoulder tap', 'Comienza en una posición de plancha alta con las manos justo debajo de los hombros y el cuerpo en línea recta. Activa el core y levanta la mano derecha del suelo, extendiéndola para tocar el hombro izquierdo. Coloca la mano derecha de nuevo en el suelo y repite tocando el hombro derecho con la mano ', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"shoulders","triceps"}', 'Comienza en una posición de plancha alta con las manos justo debajo de los hombros y el cuerpo en línea recta. Activa el core y levanta la mano derecha del suelo, extendiéndola para tocar el hombro izquierdo. Coloca la mano derecha de nuevo en el suelo y repite tocando el hombro derecho con la mano izquierda. Continúa alternando los toques de hombro mientras mantienes las caderas y el torso estables. Repite el número de repeticiones deseado.', 'Start in a high plank position with your hands directly under your shoulders and your body in a straight line. Engage your core and lift your right hand off the ground, reaching across to tap your left shoulder. Place your right hand back on the ground and repeat with your left hand tapping your right shoulder. Continue alternating shoulder taps while keeping your hips and torso stable. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3699-yRpV5TC.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3699-yRpV5TC.gif', 'yRpV5TC', '© Gym visual — https://gymvisual.com/'),
('0699', 'shoulder tap push-up', 'Comienza en una posición de plancha alta con las manos un poco más separadas que la anchura de los hombros y el cuerpo en línea recta desde la cabeza hasta los talones. Baja el cuerpo hacia el suelo flexionando los codos, manteniéndolos cerca de los costados. Mientras empujas hacia arriba, levanta l', 'chest', 'body weight', 'chest', 'chest', 'pectorals', '{"triceps","core"}', 'Comienza en una posición de plancha alta con las manos un poco más separadas que la anchura de los hombros y el cuerpo en línea recta desde la cabeza hasta los talones. Baja el cuerpo hacia el suelo flexionando los codos, manteniéndolos cerca de los costados. Mientras empujas hacia arriba, levanta la mano derecha del suelo y toca el hombro izquierdo. Vuelve a colocar la mano derecha en el suelo y repite la flexión, esta vez levantando la mano izquierda y tocando el hombro derecho. Continúa alternando los toques de hombro en cada repetición de la flexión. Mantén el core estable y evita una rotación excesiva de la cadera durante todo el ejercicio. Repite el número de repeticiones deseado.', 'Start in a high plank position with your hands slightly wider than shoulder-width apart and your body in a straight line from head to heels. Lower your body towards the ground by bending your elbows, keeping them close to your sides. As you push back up, lift your right hand off the ground and tap your left shoulder. Return your right hand to the ground and repeat the push-up, this time lifting your left hand and tapping your right shoulder. Continue alternating shoulder taps with each push-up repetition. Maintain a stable core and avoid excessive hip rotation throughout the exercise. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0699-qEse6fe.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0699-qEse6fe.gif', 'qEse6fe', '© Gym visual — https://gymvisual.com/'),
('1774', 'side bridge hip abduction', 'Túmbate de lado con las piernas extendidas y una sobre la otra. Apóyate sobre el antebrazo, manteniendo el codo directamente debajo del hombro. Activa el core y levanta las caderas del suelo, formando una línea recta desde la cabeza hasta los pies. Manteniendo el core activado, levanta la pierna sup', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'abductors', '{"glutes","obliques"}', 'Túmbate de lado con las piernas extendidas y una sobre la otra. Apóyate sobre el antebrazo, manteniendo el codo directamente debajo del hombro. Activa el core y levanta las caderas del suelo, formando una línea recta desde la cabeza hasta los pies. Manteniendo el core activado, levanta la pierna superior lo más alto posible sin rotar las caderas. Haz una pausa por un momento en la posición alta, luego baja la pierna de nuevo. Repite el número de repeticiones deseado, luego cambia de lado.', 'Lie on your side with your legs extended and stacked on top of each other. Prop yourself up on your forearm, keeping your elbow directly below your shoulder. Engage your core and lift your hips off the ground, creating a straight line from your head to your feet. While keeping your core engaged, lift your top leg as high as possible without rotating your hips. Pause for a moment at the top, then lower your leg back down. Repeat for the desired number of repetitions, then switch sides.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1774-WL4EmxJ.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1774-WL4EmxJ.gif', 'WL4EmxJ', '© Gym visual — https://gymvisual.com/'),
('0705', 'side bridge v. 2', 'Túmbate de lado con las piernas extendidas y una sobre la otra. Coloca el antebrazo en el suelo justo debajo del hombro, con el codo flexionado en un ángulo de 90 grados. Activa el core y levanta las caderas del suelo, formando una línea recta desde la cabeza hasta los pies. Mantén esta posición dur', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"obliques","glutes"}', 'Túmbate de lado con las piernas extendidas y una sobre la otra. Coloca el antebrazo en el suelo justo debajo del hombro, con el codo flexionado en un ángulo de 90 grados. Activa el core y levanta las caderas del suelo, formando una línea recta desde la cabeza hasta los pies. Mantén esta posición durante el tiempo deseado. Baja las caderas de vuelta a la posición inicial. Repite del otro lado.', 'Lie on your side with your legs extended and stacked on top of each other. Place your forearm on the ground directly below your shoulder, with your elbow bent at a 90-degree angle. Engage your core and lift your hips off the ground, creating a straight line from your head to your feet. Hold this position for the desired amount of time. Lower your hips back down to the starting position. Repeat on the other side.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0705-RKjH6Lt.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0705-RKjH6Lt.gif', 'RKjH6Lt', '© Gym visual — https://gymvisual.com/'),
('0709', 'side hip (on parallel bars)', 'Ponte de pie entre dos barras paralelas con los pies separados a la altura de los hombros. Coloca las manos sobre las barras y levanta el cuerpo del suelo, apoyando tu peso en los brazos. Contrae el abdomen y levanta lentamente las piernas hacia el lado, manteniéndolas rectas. Haz una pausa por un m', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"obliques","hip flexors"}', 'Ponte de pie entre dos barras paralelas con los pies separados a la altura de los hombros. Coloca las manos sobre las barras y levanta el cuerpo del suelo, apoyando tu peso en los brazos. Contrae el abdomen y levanta lentamente las piernas hacia el lado, manteniéndolas rectas. Haz una pausa por un momento en la parte superior, luego baja lentamente las piernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand between two parallel bars with your feet shoulder-width apart. Place your hands on the bars and lift your body off the ground, supporting your weight on your arms. Engage your abs and slowly lift your legs to the side, keeping them straight. Pause for a moment at the top, then slowly lower your legs back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0709-jTkSc6o.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0709-jTkSc6o.gif', 'jTkSc6o', '© Gym visual — https://gymvisual.com/'),
('0710', 'side hip abduction', 'Ponte de pie con los pies separados a la altura de los hombros y las manos en las caderas. Traslada el peso a una pierna y levanta la pierna opuesta hacia el lado, manteniéndola recta. Haz una pausa por un momento en la posición alta, luego baja lentamente la pierna de nuevo a la posición inicial. R', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'abductors', '{"glutes","quadriceps"}', 'Ponte de pie con los pies separados a la altura de los hombros y las manos en las caderas. Traslada el peso a una pierna y levanta la pierna opuesta hacia el lado, manteniéndola recta. Haz una pausa por un momento en la posición alta, luego baja lentamente la pierna de nuevo a la posición inicial. Repite del otro lado. Continúa alternando lados durante el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and your hands on your hips. Shift your weight to one leg and lift the opposite leg out to the side, keeping it straight. Pause for a moment at the top, then slowly lower your leg back down to the starting position. Repeat on the other side. Continue alternating sides for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0710-7WaDzyL.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0710-7WaDzyL.gif', '7WaDzyL', '© Gym visual — https://gymvisual.com/'),
('1358', 'side lying floor stretch', 'Túmbate de lado con las piernas rectas y el brazo de abajo extendido recto por encima de la cabeza. Dobla la rodilla de arriba y coloca el pie en el suelo frente a la pierna de abajo. Extiende el brazo de arriba por encima de la cabeza y agárrate a algo estable, como una pared o un mueble. Levanta l', 'back', 'body weight', 'back', 'back', 'lats', '{"obliques","glutes"}', 'Túmbate de lado con las piernas rectas y el brazo de abajo extendido recto por encima de la cabeza. Dobla la rodilla de arriba y coloca el pie en el suelo frente a la pierna de abajo. Extiende el brazo de arriba por encima de la cabeza y agárrate a algo estable, como una pared o un mueble. Levanta lentamente la pierna de abajo del suelo, manteniéndola recta, hasta sentir un estiramiento en el costado. Mantén el estiramiento durante 20-30 segundos, luego baja lentamente la pierna de nuevo. Repite del otro lado.', 'Lie on your side with your legs straight and your bottom arm extended straight overhead. Bend your top knee and place your foot on the ground in front of your bottom leg. Reach your top arm over your head and grab onto something stable, like a wall or a piece of furniture. Slowly lift your bottom leg off the ground, keeping it straight, until you feel a stretch in your side. Hold the stretch for 20-30 seconds, then slowly lower your leg back down. Repeat on the other side.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1358-jDOKRM5.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1358-jDOKRM5.gif', 'jDOKRM5', '© Gym visual — https://gymvisual.com/'),
('3667', 'side lying hip adduction (male)', 'Túmbate de lado con las piernas rectas y apiladas una sobre la otra. Coloca el brazo de abajo bajo la cabeza para apoyarte. Activa los aductores y levanta la pierna de arriba lo más alto posible sin rotar las caderas ni inclinarte hacia atrás. Haz una pausa por un momento en la posición alta, luego ', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'adductors', '{"glutes","hamstrings"}', 'Túmbate de lado con las piernas rectas y apiladas una sobre la otra. Coloca el brazo de abajo bajo la cabeza para apoyarte. Activa los aductores y levanta la pierna de arriba lo más alto posible sin rotar las caderas ni inclinarte hacia atrás. Haz una pausa por un momento en la posición alta, luego baja lentamente la pierna de nuevo a la posición inicial. Repite el número de repeticiones deseado, luego cambia de lado.', 'Lie on your side with your legs straight and stacked on top of each other. Place your bottom arm under your head for support. Engage your adductors and lift your top leg as high as possible without rotating your hips or leaning backward. Pause for a moment at the top, then slowly lower your leg back down to the starting position. Repeat for the desired number of repetitions, then switch sides.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3667-c8f5cSY.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3667-c8f5cSY.gif', 'c8f5cSY', '© Gym visual — https://gymvisual.com/'),
('1775', 'side plank hip adduction', 'Comienza tumbado de lado con las piernas extendidas y apiladas una sobre la otra. Apóyate sobre el antebrazo, manteniendo el codo directamente debajo del hombro. Activa el core y levanta las caderas del suelo, formando una línea recta desde la cabeza hasta los pies. Manteniendo la posición de planch', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'adductors', '{"obliques","glutes"}', 'Comienza tumbado de lado con las piernas extendidas y apiladas una sobre la otra. Apóyate sobre el antebrazo, manteniendo el codo directamente debajo del hombro. Activa el core y levanta las caderas del suelo, formando una línea recta desde la cabeza hasta los pies. Manteniendo la posición de plancha lateral, levanta la pierna de arriba hacia el techo, manteniéndola recta. Baja lentamente la pierna de nuevo a la posición inicial. Repite el número de repeticiones deseado, luego cambia de lado.', 'Start by lying on your side with your legs extended and stacked on top of each other. Prop yourself up on your forearm, keeping your elbow directly below your shoulder. Engage your core and lift your hips off the ground, creating a straight line from your head to your feet. While maintaining the side plank position, lift your top leg towards the ceiling, keeping it straight. Slowly lower your leg back down to the starting position. Repeat for the desired number of repetitions, then switch sides.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1775-VO2qeJg.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1775-VO2qeJg.gif', 'VO2qeJg', '© Gym visual — https://gymvisual.com/'),
('0716', 'side push neck stretch', 'Ponte de pie o siéntate erguido con los hombros relajados. Inclina la cabeza hacia la derecha, llevando la oreja derecha hacia el hombro derecho. Coloca la mano derecha en el lado izquierdo de la cabeza y aplica una presión suave para aumentar el estiramiento. Mantén el estiramiento durante 15-30 se', 'neck', 'body weight', 'neck', 'neck', 'levator scapulae', '{"trapezius","sternocleidomastoid"}', 'Ponte de pie o siéntate erguido con los hombros relajados. Inclina la cabeza hacia la derecha, llevando la oreja derecha hacia el hombro derecho. Coloca la mano derecha en el lado izquierdo de la cabeza y aplica una presión suave para aumentar el estiramiento. Mantén el estiramiento durante 15-30 segundos. Repite hacia el otro lado, inclinando la cabeza hacia la izquierda y aplicando presión con la mano izquierda. Repite el estiramiento 2-3 veces en cada lado.', 'Stand or sit up straight with your shoulders relaxed. Tilt your head to the right, bringing your right ear towards your right shoulder. Place your right hand on the left side of your head and gently apply pressure to increase the stretch. Hold the stretch for 15-30 seconds. Repeat on the other side, tilting your head to the left and applying pressure with your left hand. Repeat the stretch 2-3 times on each side.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0716-oQRJYkC.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0716-oQRJYkC.gif', 'oQRJYkC', '© Gym visual — https://gymvisual.com/'),
('0717', 'side push-up', 'Comienza tumbado de lado con las piernas extendidas y apiladas una sobre la otra. Coloca la mano de abajo en el suelo directamente debajo del hombro, con los dedos apuntando hacia delante. Empuja con la mano de abajo para levantar el cuerpo del suelo, manteniendo las piernas rectas y el core activad', 'upper arms', 'body weight', 'upper arms', 'upper arms', 'triceps', '{"shoulders","chest","core"}', 'Comienza tumbado de lado con las piernas extendidas y apiladas una sobre la otra. Coloca la mano de abajo en el suelo directamente debajo del hombro, con los dedos apuntando hacia delante. Empuja con la mano de abajo para levantar el cuerpo del suelo, manteniendo las piernas rectas y el core activado. Extiende el brazo de arriba recto hacia el techo, formando una línea recta desde la cabeza hasta los talones. Baja el cuerpo de nuevo a la posición inicial con control. Repite el número de repeticiones deseado, luego cambia de lado.', 'Start by lying on your side with your legs extended and stacked on top of each other. Place your bottom hand on the ground directly under your shoulder, fingers pointing forward. Press through your bottom hand to lift your body off the ground, keeping your legs straight and your core engaged. Extend your top arm straight up towards the ceiling, creating a straight line from your head to your heels. Lower your body back down to the starting position with control. Repeat for the desired number of repetitions, then switch sides.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0717-wpbD28t.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0717-wpbD28t.gif', 'wpbD28t', '© Gym visual — https://gymvisual.com/'),
('0721', 'side wrist pull stretch', 'Ponte de pie con los pies separados a la altura de los hombros y los brazos extendidos frente a ti. Extiende el brazo derecho hacia el lado, paralelo al suelo, con la palma hacia abajo. Con la mano izquierda, sujeta la mano derecha y tira de ella suavemente hacia tu cuerpo, sintiendo un estiramiento', 'lower arms', 'body weight', 'lower arms', 'lower arms', 'forearms', '{"wrists","hands"}', 'Ponte de pie con los pies separados a la altura de los hombros y los brazos extendidos frente a ti. Extiende el brazo derecho hacia el lado, paralelo al suelo, con la palma hacia abajo. Con la mano izquierda, sujeta la mano derecha y tira de ella suavemente hacia tu cuerpo, sintiendo un estiramiento en el antebrazo derecho. Mantén el estiramiento durante 15-30 segundos, luego suelta. Repite del otro lado.', 'Stand with your feet shoulder-width apart and your arms extended in front of you. Extend your right arm out to the side, parallel to the ground, with your palm facing down. With your left hand, grab your right hand and gently pull it towards your body, feeling a stretch in your right forearm. Hold the stretch for 15-30 seconds, then release. Repeat on the other side.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0721-UtmIqcI.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0721-UtmIqcI.gif', 'UtmIqcI', '© Gym visual — https://gymvisual.com/'),
('0720', 'side-to-side chin', 'Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Sujeta una barra de dominadas con un agarre prono, con las manos un poco más separadas que el ancho de los hombros. Cuélgate de la barra con los brazos completamente extendidos y el cuerpo relajado', 'back', 'body weight', 'back', 'back', 'lats', '{"biceps","forearms"}', 'Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Sujeta una barra de dominadas con un agarre prono, con las manos un poco más separadas que el ancho de los hombros. Cuélgate de la barra con los brazos completamente extendidos y el cuerpo relajado. Levántate doblando los codos y llevando la barbilla hacia la barra, manteniendo el cuerpo recto. Una vez que la barbilla esté por encima de la barra, bájate de nuevo a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and your knees slightly bent. Grasp a pull-up bar with an overhand grip, hands slightly wider than shoulder-width apart. Hang from the bar with your arms fully extended and your body relaxed. Pull yourself up by bending your elbows and bringing your chin towards the bar, while keeping your body straight. Once your chin is above the bar, lower yourself back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0720-isAAZWA.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0720-isAAZWA.gif', 'isAAZWA', '© Gym visual — https://gymvisual.com/'),
('3213', 'side-to-side toe touch (male)', 'Ponte de pie con los pies separados a la altura de los hombros y los brazos extendidos hacia los lados. Dobla la cintura hacia la derecha, llevando la mano derecha hacia el pie derecho mientras mantienes la mano izquierda extendida hacia el lado. Vuelve a la posición inicial y luego dobla la cintura', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"obliques","hip flexors"}', 'Ponte de pie con los pies separados a la altura de los hombros y los brazos extendidos hacia los lados. Dobla la cintura hacia la derecha, llevando la mano derecha hacia el pie derecho mientras mantienes la mano izquierda extendida hacia el lado. Vuelve a la posición inicial y luego dobla la cintura hacia la izquierda, llevando la mano izquierda hacia el pie izquierdo mientras mantienes la mano derecha extendida hacia el lado. Repite el movimiento de flexión lateral el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and your arms extended to the sides. Bend at the waist to the right, reaching your right hand towards your right foot while keeping your left hand extended to the side. Return to the starting position and then bend at the waist to the left, reaching your left hand towards your left foot while keeping your right hand extended to the side. Repeat the side-to-side bending motion for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3213-WCAvOfC.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3213-WCAvOfC.gif', 'WCAvOfC', '© Gym visual — https://gymvisual.com/'),
('0725', 'single arm push-up', 'Comienza en posición de flexión con las manos separadas a la altura de los hombros y una mano colocada un poco más ancha que la otra. Activa el core y baja el cuerpo hacia el suelo flexionando los codos, manteniendo la espalda recta. Al bajar, traslada el peso hacia un lado y levanta el brazo opuest', 'chest', 'body weight', 'chest', 'chest', 'pectorals', '{"triceps","shoulders","core"}', 'Comienza en posición de flexión con las manos separadas a la altura de los hombros y una mano colocada un poco más ancha que la otra. Activa el core y baja el cuerpo hacia el suelo flexionando los codos, manteniendo la espalda recta. Al bajar, traslada el peso hacia un lado y levanta el brazo opuesto del suelo, extendiéndolo recto hacia el lado. Empuja con el pecho y los tríceps para subir el cuerpo de nuevo a la posición inicial, mientras bajas simultáneamente el brazo extendido de vuelta al suelo. Repite el movimiento, alternando el brazo que extiendes en cada repetición.', 'Start in a push-up position with your hands shoulder-width apart and one hand placed slightly wider than the other. Engage your core and lower your body towards the ground by bending your elbows, keeping your back straight. As you lower yourself, shift your weight to one side and lift the opposite arm off the ground, extending it straight out to the side. Push through your chest and triceps to raise your body back up to the starting position, while simultaneously lowering your extended arm back to the ground. Repeat the movement, alternating the arm you extend with each repetition.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0725-MUic5zN.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0725-MUic5zN.gif', 'MUic5zN', '© Gym visual — https://gymvisual.com/'),
('3645', 'single leg bridge with outstretched leg', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Extiende una pierna recta hacia delante. Activa los glúteos y levanta las caderas del suelo, formando una línea recta desde las rodillas hasta los hombros. Mantén la posición alta por un momento, luego baja lentam', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'glutes', '{"hamstrings","quadriceps"}', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Extiende una pierna recta hacia delante. Activa los glúteos y levanta las caderas del suelo, formando una línea recta desde las rodillas hasta los hombros. Mantén la posición alta por un momento, luego baja lentamente las caderas de nuevo a la posición inicial. Repite el número de repeticiones deseado, luego cambia de pierna.', 'Lie on your back with your knees bent and feet flat on the ground. Extend one leg straight out in front of you. Engage your glutes and lift your hips off the ground, forming a straight line from your knees to your shoulders. Hold for a moment at the top, then slowly lower your hips back down to the starting position. Repeat for the desired number of repetitions, then switch legs.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3645-rmEukuS.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3645-rmEukuS.gif', 'rmEukuS', '© Gym visual — https://gymvisual.com/'),
('0727', 'single leg calf raise (on a dumbbell)', 'Ponte de pie con los pies separados a la altura de la cadera y sujeta una mancuerna en una mano. Levanta un pie del suelo y mantén el equilibrio sobre el otro pie. Eleva lentamente el talón lo más alto posible, usando los músculos de la pantorrilla. Haz una pausa por un momento en la parte superior,', 'lower legs', 'dumbbell', 'lower legs', 'lower legs', 'calves', '{"ankles","feet"}', 'Ponte de pie con los pies separados a la altura de la cadera y sujeta una mancuerna en una mano. Levanta un pie del suelo y mantén el equilibrio sobre el otro pie. Eleva lentamente el talón lo más alto posible, usando los músculos de la pantorrilla. Haz una pausa por un momento en la parte superior, luego baja lentamente el talón de vuelta hacia abajo. Repite el número de repeticiones deseado, luego cambia a la otra pierna.', 'Stand with your feet hip-width apart and hold a dumbbell in one hand. Lift one foot off the ground and balance on the other foot. Slowly raise your heel as high as possible, using your calf muscles. Pause for a moment at the top, then slowly lower your heel back down. Repeat for the desired number of repetitions, then switch to the other leg.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0727-fKZgDEO.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0727-fKZgDEO.gif', 'fKZgDEO', '© Gym visual — https://gymvisual.com/'),
('0730', 'single leg platform slide', 'Comienza de pie con un pie sobre una plataforma o tabla deslizante. Dobla ligeramente la rodilla y desliza el pie sobre la plataforma hacia atrás, extendiendo la pierna. Mantén el core activado y conserva una postura recta durante todo el movimiento. Vuelve lentamente a la posición inicial deslizand', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'hamstrings', '{"glutes","quadriceps"}', 'Comienza de pie con un pie sobre una plataforma o tabla deslizante. Dobla ligeramente la rodilla y desliza el pie sobre la plataforma hacia atrás, extendiendo la pierna. Mantén el core activado y conserva una postura recta durante todo el movimiento. Vuelve lentamente a la posición inicial deslizando el pie de regreso a la posición inicial. Repite el movimiento el número de repeticiones deseado y luego cambia de pierna.', 'Start by standing with one foot on a platform or slide board. Bend your knee slightly and slide the foot on the platform backward, extending your leg. Keep your core engaged and maintain a straight posture throughout the movement. Slowly return to the starting position by sliding your foot back to the initial position. Repeat the movement for the desired number of repetitions, then switch legs.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0730-LNE3wfo.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0730-LNE3wfo.gif', 'LNE3wfo', '© Gym visual — https://gymvisual.com/'),
('1759', 'single leg squat (pistol) male', 'Ponte de pie con los pies separados a la altura de los hombros y los brazos extendidos frente a ti. Levanta el pie derecho del suelo y extiéndelo hacia delante. Baja lentamente el cuerpo doblando la rodilla izquierda y empujando las caderas hacia atrás. Mantén el pecho elevado y la espalda recta mie', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves"}', 'Ponte de pie con los pies separados a la altura de los hombros y los brazos extendidos frente a ti. Levanta el pie derecho del suelo y extiéndelo hacia delante. Baja lentamente el cuerpo doblando la rodilla izquierda y empujando las caderas hacia atrás. Mantén el pecho elevado y la espalda recta mientras bajas el cuerpo. Baja hasta que el muslo izquierdo quede paralelo al suelo, o lo más abajo que puedas llegar cómodamente. Haz una pausa por un momento en la posición baja, luego empuja con el talón izquierdo para volver a la posición inicial. Repite el número de repeticiones deseado, luego cambia de pierna.', 'Stand with your feet shoulder-width apart and arms extended in front of you. Lift your right foot off the ground and extend it forward. Slowly lower your body down by bending your left knee and pushing your hips back. Keep your chest up and your back straight as you lower yourself down. Lower until your left thigh is parallel to the ground, or as low as you can comfortably go. Pause for a moment at the bottom, then push through your left heel to return to the starting position. Repeat for the desired number of repetitions, then switch legs.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1759-nqs5HGV.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1759-nqs5HGV.gif', 'nqs5HGV', '© Gym visual — https://gymvisual.com/'),
('1489', 'sissy squat', 'Ponte de pie con los pies separados a la altura de los hombros y los dedos de los pies ligeramente hacia afuera. Sujétate de un objeto estable para mantener el equilibrio si es necesario. Baja lentamente el cuerpo doblando las rodillas e inclinándote hacia atrás, manteniendo el torso erguido. Contin', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'quads', '{"calves","glutes"}', 'Ponte de pie con los pies separados a la altura de los hombros y los dedos de los pies ligeramente hacia afuera. Sujétate de un objeto estable para mantener el equilibrio si es necesario. Baja lentamente el cuerpo doblando las rodillas e inclinándote hacia atrás, manteniendo el torso erguido. Continúa bajando hasta que los muslos queden paralelos al suelo o tan lejos como puedas llegar cómodamente. Haz una pausa breve y luego empuja con los talones para volver a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and your toes pointing slightly outward. Hold onto a stable object for balance if needed. Slowly lower your body by bending your knees and leaning back, keeping your torso upright. Continue lowering until your thighs are parallel to the ground or as far as you can comfortably go. Pause for a moment, then push through your heels to return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1489-xdYPUtE.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1489-xdYPUtE.gif', 'xdYPUtE', '© Gym visual — https://gymvisual.com/'),
('0735', 'sit-up v. 2', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Coloca las manos detrás de la cabeza con los codos apuntando hacia afuera. Activando el abdomen, levanta lentamente la parte superior del cuerpo del suelo, curvándote hacia adelante hasta que tu torso forme un áng', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"hip flexors"}', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Coloca las manos detrás de la cabeza con los codos apuntando hacia afuera. Activando el abdomen, levanta lentamente la parte superior del cuerpo del suelo, curvándote hacia adelante hasta que tu torso forme un ángulo de 45 grados. Haz una pausa por un momento en la parte superior, luego baja lentamente la parte superior del cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on your back with your knees bent and feet flat on the ground. Place your hands behind your head with your elbows pointing outwards. Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle. Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0735-Bn6TXyO.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0735-Bn6TXyO.gif', 'Bn6TXyO', '© Gym visual — https://gymvisual.com/'),
('3679', 'sit-up with arms on chest', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Cruza los brazos sobre el pecho. Contrayendo el abdomen, levanta la parte superior del cuerpo del suelo hacia las rodillas. Haz una pausa por un momento en la parte superior, luego baja lentamente la parte superio', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"hip flexors"}', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Cruza los brazos sobre el pecho. Contrayendo el abdomen, levanta la parte superior del cuerpo del suelo hacia las rodillas. Haz una pausa por un momento en la parte superior, luego baja lentamente la parte superior del cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on your back with your knees bent and feet flat on the ground. Cross your arms over your chest. Engaging your abs, lift your upper body off the ground towards your knees. Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3679-6ZCiYWQ.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3679-6ZCiYWQ.gif', '6ZCiYWQ', '© Gym visual — https://gymvisual.com/'),
('3361', 'skater hops', 'Ponte de pie con los pies separados a la altura de los hombros. Dobla ligeramente las rodillas y salta hacia la derecha, aterrizando sobre el pie derecho. Al aterrizar, balancea la pierna izquierda detrás de la pierna derecha y toca el suelo con los dedos del pie izquierdo. Salta inmediatamente haci', 'cardio', 'body weight', 'cardio', 'cardio', 'cardiovascular system', '{"quadriceps","hamstrings","glutes","calves"}', 'Ponte de pie con los pies separados a la altura de los hombros. Dobla ligeramente las rodillas y salta hacia la derecha, aterrizando sobre el pie derecho. Al aterrizar, balancea la pierna izquierda detrás de la pierna derecha y toca el suelo con los dedos del pie izquierdo. Salta inmediatamente hacia la izquierda, aterrizando sobre el pie izquierdo. Al aterrizar, balancea la pierna derecha detrás de la pierna izquierda y toca el suelo con los dedos del pie derecho. Continúa alternando los lados, saltando y tocando el suelo con cada pierna. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart. Bend your knees slightly and jump to the right, landing on your right foot. As you land, swing your left leg behind your right leg and tap the ground with your left toes. Immediately jump to the left, landing on your left foot. As you land, swing your right leg behind your left leg and tap the ground with your right toes. Continue alternating sides, jumping and tapping the ground with each leg. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3361-zfNHMN9.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3361-zfNHMN9.gif', 'zfNHMN9', '© Gym visual — https://gymvisual.com/'),
('2142', 'ski ergometer', 'Ajusta la altura del asiento y los apoyapiés a una posición cómoda. Sujeta las agarraderas con un agarre prono, con las palmas hacia abajo. Siéntate erguido con los pies planos sobre los apoyapiés. Extiende los brazos rectos frente a ti, manteniendo los codos ligeramente flexionados. Activa los tríc', 'upper arms', 'skierg machine', 'upper arms', 'upper arms', 'triceps', '{"shoulders","forearms"}', 'Ajusta la altura del asiento y los apoyapiés a una posición cómoda. Sujeta las agarraderas con un agarre prono, con las palmas hacia abajo. Siéntate erguido con los pies planos sobre los apoyapiés. Extiende los brazos rectos frente a ti, manteniendo los codos ligeramente flexionados. Activa los tríceps y empuja las asas hacia abajo, hacia los muslos. Haz una pausa por un momento en la parte inferior, luego regresa lentamente a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the seat height and footrests to a comfortable position. Grasp the handles with an overhand grip, palms facing down. Sit up straight with your feet flat on the footrests. Extend your arms straight out in front of you, keeping your elbows slightly bent. Engage your triceps and push the handles down towards your thighs. Pause for a moment at the bottom, then slowly return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2142-vpQaQkH.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2142-vpQaQkH.gif', 'vpQaQkH', '© Gym visual — https://gymvisual.com/'),
('3671', 'ski step', 'Ponte de pie con los pies separados a la altura de los hombros. Dobla ligeramente las rodillas y mantén la espalda recta. Salta hacia la derecha, aterrizando sobre el pie derecho mientras balanceas la pierna izquierda detrás de la pierna derecha. Salta inmediatamente hacia la izquierda, aterrizando ', 'cardio', 'body weight', 'cardio', 'cardio', 'cardiovascular system', '{"quadriceps","hamstrings","glutes","calves"}', 'Ponte de pie con los pies separados a la altura de los hombros. Dobla ligeramente las rodillas y mantén la espalda recta. Salta hacia la derecha, aterrizando sobre el pie derecho mientras balanceas la pierna izquierda detrás de la pierna derecha. Salta inmediatamente hacia la izquierda, aterrizando sobre el pie izquierdo mientras balanceas la pierna derecha detrás de la pierna izquierda. Continúa alternando los saltos de lado a lado, imitando un movimiento de esquí. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart. Bend your knees slightly and keep your back straight. Jump to the right, landing on your right foot while swinging your left leg behind your right leg. Immediately jump to the left, landing on your left foot while swinging your right leg behind your left leg. Continue alternating jumps from side to side, mimicking a skiing motion. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3671-5MRH8H2.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3671-5MRH8H2.gif', '5MRH8H2', '© Gym visual — https://gymvisual.com/'),
('3304', 'skin the cat', 'Comienza colgándote de una barra con los brazos completamente extendidos y el cuerpo relajado. Activa el core y levanta las piernas, llevando las rodillas hacia el pecho. Continúa levantando las piernas por encima de la cabeza, permitiendo que el cuerpo pase entre los brazos. Una vez que las piernas', 'back', 'body weight', 'back', 'back', 'upper back', '{"shoulders","core"}', 'Comienza colgándote de una barra con los brazos completamente extendidos y el cuerpo relajado. Activa el core y levanta las piernas, llevando las rodillas hacia el pecho. Continúa levantando las piernas por encima de la cabeza, permitiendo que el cuerpo pase entre los brazos. Una vez que las piernas estén completamente extendidas por encima de la cabeza, comienza a bajarlas de nuevo hacia la posición inicial. Mientras bajas las piernas, permite que el cuerpo pase de nuevo entre los brazos hasta quedar colgado con los brazos completamente extendidos otra vez. Repite el número de repeticiones deseado.', 'Start by hanging from a bar with your arms fully extended and your body relaxed. Engage your core and lift your legs up, bringing your knees towards your chest. Continue to lift your legs up and over your head, allowing your body to pass through the arms. Once your legs are fully extended over your head, begin to lower them back down towards the starting position. As you lower your legs, allow your body to pass back through the arms until you are hanging with your arms fully extended again. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3304-MSfvriJ.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3304-MSfvriJ.gif', 'MSfvriJ', '© Gym visual — https://gymvisual.com/'),
('1425', 'sled 45 degrees one leg press', 'Ajusta la máquina de trineo a un ángulo de 45 grados. Siéntate en la máquina de trineo con la espalda contra el respaldo y los pies sobre la placa. Coloca un pie sobre la placa y extiende la pierna, empujando el trineo alejándolo de ti. Dobla lentamente la rodilla y baja el trineo de vuelta a la pos', 'upper legs', 'sled machine', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves"}', 'Ajusta la máquina de trineo a un ángulo de 45 grados. Siéntate en la máquina de trineo con la espalda contra el respaldo y los pies sobre la placa. Coloca un pie sobre la placa y extiende la pierna, empujando el trineo alejándolo de ti. Dobla lentamente la rodilla y baja el trineo de vuelta a la posición inicial. Repite con la otra pierna. Continúa alternando las piernas durante el número de repeticiones deseado.', 'Adjust the sled machine to a 45-degree angle. Sit on the sled machine with your back against the pad and your feet on the footplate. Place one foot on the footplate and extend your leg, pushing the sled away from you. Slowly bend your knee and lower the sled back to the starting position. Repeat with the other leg. Continue alternating legs for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1425-WWD6FzI.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1425-WWD6FzI.gif', 'WWD6FzI', '© Gym visual — https://gymvisual.com/'),
('0738', 'sled 45в° calf press', 'Ajusta la máquina de trineo a un ángulo de 45 grados. Coloca los pies sobre la plataforma del trineo con los dedos de los pies apuntando hacia delante. Empuja la plataforma del trineo alejándola de ti extendiendo los tobillos y las pantorrillas. Haz una pausa por un momento en la posición alta, lueg', 'lower legs', 'sled machine', 'lower legs', 'lower legs', 'calves', '{"hamstrings"}', 'Ajusta la máquina de trineo a un ángulo de 45 grados. Coloca los pies sobre la plataforma del trineo con los dedos de los pies apuntando hacia delante. Empuja la plataforma del trineo alejándola de ti extendiendo los tobillos y las pantorrillas. Haz una pausa por un momento en la posición alta, luego baja lentamente la plataforma del trineo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the sled machine to a 45-degree angle. Place your feet on the sled platform with your toes pointing forward. Push the sled platform away from you by extending your ankles and calves. Pause for a moment at the top, then slowly lower the sled platform back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0738-qCNVnaU.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0738-qCNVnaU.gif', 'qCNVnaU', '© Gym visual — https://gymvisual.com/'),
('0739', 'sled 45в° leg press', 'Ajusta el asiento y la placa de la máquina de trineo a una posición cómoda. Siéntate en la máquina de trineo con la espalda contra el respaldo y los pies separados a la altura de los hombros sobre la placa. Sujeta las asas a los lados del asiento para mayor estabilidad. Empuja la placa alejándola de', 'upper legs', 'sled machine', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves"}', 'Ajusta el asiento y la placa de la máquina de trineo a una posición cómoda. Siéntate en la máquina de trineo con la espalda contra el respaldo y los pies separados a la altura de los hombros sobre la placa. Sujeta las asas a los lados del asiento para mayor estabilidad. Empuja la placa alejándola de tu cuerpo extendiendo las piernas, manteniendo los talones sobre la placa. Continúa empujando hasta que las piernas estén casi completamente extendidas, pero sin bloquear las rodillas. Haz una pausa por un momento en la parte alta del movimiento, luego baja lentamente la placa de vuelta hacia tu cuerpo doblando las rodillas. Repite el número de repeticiones deseado.', 'Adjust the seat and footplate of the sled machine to a comfortable position. Sit on the sled machine with your back against the backrest and your feet shoulder-width apart on the footplate. Grip the handles on the sides of the seat for stability. Push the footplate away from your body by extending your legs, keeping your heels on the footplate. Continue pushing until your legs are almost fully extended, but without locking your knees. Pause for a moment at the top of the movement, then slowly lower the footplate back towards your body by bending your knees. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0739-10Z2DXU.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0739-10Z2DXU.gif', '10Z2DXU', '© Gym visual — https://gymvisual.com/'),
('1464', 'sled 45в° leg press (back pov)', 'Ajusta el asiento de la máquina de trineo de modo que las rodillas queden en un ángulo de 45 grados. Siéntate en la máquina de trineo con la espalda contra el respaldo y los pies separados a la altura de los hombros sobre la placa. Sujeta las asas a los lados del asiento para mayor estabilidad. Empu', 'upper legs', 'sled machine', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves"}', 'Ajusta el asiento de la máquina de trineo de modo que las rodillas queden en un ángulo de 45 grados. Siéntate en la máquina de trineo con la espalda contra el respaldo y los pies separados a la altura de los hombros sobre la placa. Sujeta las asas a los lados del asiento para mayor estabilidad. Empuja la placa alejándola de tu cuerpo extendiendo las piernas, manteniendo los talones sobre la placa. Haz una pausa por un momento en la posición completamente extendida. Dobla lentamente las rodillas y baja la placa de vuelta hacia tu cuerpo, controlando el movimiento. Repite el número de repeticiones deseado.', 'Adjust the seat of the sled machine so that your knees are at a 45-degree angle. Sit on the sled machine with your back against the backrest and your feet shoulder-width apart on the footplate. Grip the handles on the sides of the seat for stability. Push the footplate away from your body by extending your legs, keeping your heels on the footplate. Pause for a moment at the fully extended position. Slowly bend your knees and lower the footplate back towards your body, controlling the movement. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1464-yn2lLSI.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1464-yn2lLSI.gif', 'yn2lLSI', '© Gym visual — https://gymvisual.com/'),
('1463', 'sled 45° leg press (side pov)', 'Ajusta el asiento de la máquina de trineo de modo que las rodillas queden en un ángulo de 90 grados cuando los pies estén sobre la placa. Siéntate en la máquina de trineo con la espalda plana contra el respaldo y los pies separados a la altura de los hombros sobre la placa. Sujeta las asas a los lad', 'upper legs', 'sled machine', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves"}', 'Ajusta el asiento de la máquina de trineo de modo que las rodillas queden en un ángulo de 90 grados cuando los pies estén sobre la placa. Siéntate en la máquina de trineo con la espalda plana contra el respaldo y los pies separados a la altura de los hombros sobre la placa. Sujeta las asas a los lados del asiento para mayor estabilidad. Empuja contra la placa para extender las piernas, estirándolas por completo. Haz una pausa por un momento en la posición alta, luego dobla lentamente las rodillas para bajar la placa de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the seat of the sled machine so that your knees are at a 90-degree angle when your feet are on the footplate. Sit on the sled machine with your back flat against the backrest and your feet shoulder-width apart on the footplate. Grip the handles on the sides of the seat for stability. Push against the footplate to extend your legs, straightening them completely. Pause for a moment at the top, then slowly bend your knees to lower the footplate back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1463-2Qh2J1e.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1463-2Qh2J1e.gif', '2Qh2J1e', '© Gym visual — https://gymvisual.com/'),
('0740', 'sled 45в° leg wide press', 'Ajusta la máquina de trineo a un ángulo de 45 grados. Siéntate en la máquina de trineo con la espalda contra el respaldo y los pies sobre la plataforma. Coloca los pies más separados que el ancho de los hombros. Empuja contra la plataforma para extender las piernas y enderezar las rodillas. Haz una ', 'upper legs', 'sled machine', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves"}', 'Ajusta la máquina de trineo a un ángulo de 45 grados. Siéntate en la máquina de trineo con la espalda contra el respaldo y los pies sobre la plataforma. Coloca los pies más separados que el ancho de los hombros. Empuja contra la plataforma para extender las piernas y enderezar las rodillas. Haz una pausa por un momento al final del movimiento, luego dobla lentamente las rodillas para volver a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the sled machine to a 45-degree angle. Sit on the sled machine with your back against the pad and your feet on the foot platform. Position your feet wider than shoulder-width apart. Push against the foot platform to extend your legs and straighten your knees. Pause for a moment at the end of the movement, then slowly bend your knees to return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0740-tj41Nu6.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0740-tj41Nu6.gif', 'tj41Nu6', '© Gym visual — https://gymvisual.com/'),
('1391', 'sled calf press on leg press', 'Ajusta el asiento de la máquina de prensa de piernas de modo que las rodillas queden ligeramente flexionadas cuando los pies estén sobre el trineo. Coloca los pies separados a la altura de los hombros sobre el trineo, con los dedos de los pies apuntando hacia delante. Suelta las asas de seguridad y ', 'lower legs', 'sled machine', 'lower legs', 'lower legs', 'calves', '{"hamstrings","quadriceps"}', 'Ajusta el asiento de la máquina de prensa de piernas de modo que las rodillas queden ligeramente flexionadas cuando los pies estén sobre el trineo. Coloca los pies separados a la altura de los hombros sobre el trineo, con los dedos de los pies apuntando hacia delante. Suelta las asas de seguridad y empuja el trineo alejándolo de ti extendiendo las rodillas y los tobillos. Haz una pausa por un momento en la parte alta del movimiento, luego baja lentamente el trineo doblando las rodillas y los tobillos. Repite el número de repeticiones deseado.', 'Adjust the seat of the leg press machine so that your knees are slightly bent when your feet are on the sled. Place your feet shoulder-width apart on the sled, with your toes pointing forward. Release the safety handles and push the sled away from you by extending your knees and ankles. Pause for a moment at the top of the movement, then slowly lower the sled back down by bending your knees and ankles. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1391-ykHcWme.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1391-ykHcWme.gif', 'ykHcWme', '© Gym visual — https://gymvisual.com/'),
('0741', 'sled closer hack squat', 'Ajusta la máquina de trineo a un peso cómodo y colócate con la espalda contra el respaldo. Coloca los pies separados a la altura de los hombros sobre la plataforma, con los dedos de los pies ligeramente apuntando hacia fuera. Sujeta las asas a los lados de la máquina para mayor estabilidad. Activa e', 'upper legs', 'sled machine', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves"}', 'Ajusta la máquina de trineo a un peso cómodo y colócate con la espalda contra el respaldo. Coloca los pies separados a la altura de los hombros sobre la plataforma, con los dedos de los pies ligeramente apuntando hacia fuera. Sujeta las asas a los lados de la máquina para mayor estabilidad. Activa el core y baja lentamente el cuerpo doblando las rodillas y las caderas, manteniendo la espalda recta. Continúa bajando hasta que los muslos queden paralelos al suelo o un poco por debajo. Haz una pausa por un momento en la posición baja, luego empuja con los talones para extender las piernas y volver a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the sled machine to a comfortable weight and position yourself with your back against the pad. Place your feet shoulder-width apart on the platform, toes slightly pointed outwards. Grip the handles on the sides of the machine for stability. Engage your core and slowly lower your body by bending your knees and hips, keeping your back straight. Continue lowering until your thighs are parallel to the ground or slightly below. Pause for a moment at the bottom, then push through your heels to extend your legs and return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0741-gf3ZjB9.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0741-gf3ZjB9.gif', 'gf3ZjB9', '© Gym visual — https://gymvisual.com/'),
('0742', 'sled forward angled calf raise', 'Ajusta la máquina de trineo a un peso cómodo y colócate en la máquina con la punta de los pies sobre la plataforma y los talones colgando. Coloca las manos en las asas o a los lados de la máquina para apoyarte. Activa las pantorrillas y eleva lentamente los talones lo más alto posible, empujando con', 'lower legs', 'sled machine', 'lower legs', 'lower legs', 'calves', '{"hamstrings","glutes"}', 'Ajusta la máquina de trineo a un peso cómodo y colócate en la máquina con la punta de los pies sobre la plataforma y los talones colgando. Coloca las manos en las asas o a los lados de la máquina para apoyarte. Activa las pantorrillas y eleva lentamente los talones lo más alto posible, empujando contra la resistencia del trineo. Haz una pausa breve en la parte alta del movimiento, luego baja lentamente los talones de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the sled machine to a comfortable weight and position yourself on the machine with your toes on the platform and your heels hanging off. Place your hands on the handles or the sides of the machine for support. Engage your calves and slowly raise your heels as high as possible, pushing against the resistance of the sled. Pause for a moment at the top of the movement, then slowly lower your heels back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0742-XDOiFns.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0742-XDOiFns.gif', 'XDOiFns', '© Gym visual — https://gymvisual.com/'),
('0743', 'sled hack squat', 'Ajusta la máquina de trineo a una posición cómoda según tu altura. Ponte de pie con los pies separados a la altura de los hombros sobre la plataforma, con los dedos de los pies ligeramente apuntando hacia fuera. Sujétate de las asas o barras para mayor estabilidad. Baja el cuerpo doblando las rodill', 'upper legs', 'sled machine', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves"}', 'Ajusta la máquina de trineo a una posición cómoda según tu altura. Ponte de pie con los pies separados a la altura de los hombros sobre la plataforma, con los dedos de los pies ligeramente apuntando hacia fuera. Sujétate de las asas o barras para mayor estabilidad. Baja el cuerpo doblando las rodillas y las caderas, manteniendo la espalda recta y el pecho elevado. Continúa bajando hasta que los muslos queden paralelos al suelo o un poco por debajo. Haz una pausa por un momento, luego empuja con los talones para subir el cuerpo de nuevo a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the sled machine to a comfortable position for your height. Stand with your feet shoulder-width apart on the platform, toes slightly pointed outwards. Hold onto the handles or bars for stability. Lower your body by bending your knees and hips, keeping your back straight and chest up. Continue lowering until your thighs are parallel to the ground or slightly below. Pause for a moment, then push through your heels to raise your body back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0743-Qa55kX1.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0743-Qa55kX1.gif', 'Qa55kX1', '© Gym visual — https://gymvisual.com/'),
('2334', 'sled lying calf press', 'Ajusta la máquina de trineo a un peso adecuado. Siéntate en la máquina de trineo con la espalda contra el respaldo y los pies sobre la plataforma. Coloca la punta y la almohadilla de los pies en el borde de la plataforma, con los talones colgando. Empuja la plataforma alejándola de ti extendiendo lo', 'lower legs', 'sled machine', 'lower legs', 'lower legs', 'calves', '{"hamstrings","glutes"}', 'Ajusta la máquina de trineo a un peso adecuado. Siéntate en la máquina de trineo con la espalda contra el respaldo y los pies sobre la plataforma. Coloca la punta y la almohadilla de los pies en el borde de la plataforma, con los talones colgando. Empuja la plataforma alejándola de ti extendiendo los tobillos, manteniendo las rodillas ligeramente flexionadas. Continúa empujando hasta que las pantorrillas estén completamente contraídas. Mantén la contracción por un momento, luego baja lentamente la plataforma de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the sled machine to a comfortable weight. Sit on the sled machine with your back against the pad and your feet on the platform. Place your toes and the balls of your feet on the edge of the platform, with your heels hanging off. Push the platform away from you by extending your ankles, keeping your knees slightly bent. Continue pushing until your calves are fully contracted. Hold the contraction for a moment, then slowly lower the platform back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2334-g376LuL.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2334-g376LuL.gif', 'g376LuL', '© Gym visual — https://gymvisual.com/'),
('0744', 'sled lying squat', 'Ajusta la máquina de trineo a un peso adecuado. Túmbate boca arriba en la máquina de trineo con los pies sobre la placa. Coloca los pies separados a la altura de los hombros y ligeramente angulados hacia fuera. Sujeta las asas de la máquina de trineo para mayor estabilidad. Activa los glúteos y los ', 'upper legs', 'sled machine', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves"}', 'Ajusta la máquina de trineo a un peso adecuado. Túmbate boca arriba en la máquina de trineo con los pies sobre la placa. Coloca los pies separados a la altura de los hombros y ligeramente angulados hacia fuera. Sujeta las asas de la máquina de trineo para mayor estabilidad. Activa los glúteos y los músculos del core. Empuja con los talones y extiende las piernas para levantar el trineo. Baja el trineo de nuevo doblando las rodillas y las caderas. Repite el número de repeticiones deseado.', 'Adjust the sled machine to a comfortable weight. Lie on your back on the sled machine with your feet on the footplate. Position your feet shoulder-width apart and slightly angled outwards. Grip the handles of the sled machine for stability. Engage your glutes and core muscles. Push through your heels and extend your legs to lift the sled. Lower the sled back down by bending your knees and hips. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0744-9n2149Z.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0744-9n2149Z.gif', '9n2149Z', '© Gym visual — https://gymvisual.com/'),
('1392', 'sled one leg calf press on leg press', 'Ajusta el asiento de la máquina de prensa de piernas de modo que las rodillas queden ligeramente flexionadas cuando los pies estén sobre el trineo. Siéntate en la máquina con la espalda contra el respaldo y los pies sobre el trineo, separados a la altura de los hombros. Coloca la punta y la almohadi', 'lower legs', 'sled machine', 'lower legs', 'lower legs', 'calves', '{"hamstrings","glutes"}', 'Ajusta el asiento de la máquina de prensa de piernas de modo que las rodillas queden ligeramente flexionadas cuando los pies estén sobre el trineo. Siéntate en la máquina con la espalda contra el respaldo y los pies sobre el trineo, separados a la altura de los hombros. Coloca la punta y la almohadilla de los pies sobre el trineo, manteniendo los talones levantados. Empuja el trineo hacia delante extendiendo los tobillos, manteniendo las rodillas ligeramente flexionadas. Haz una pausa por un momento en la posición alta, luego baja lentamente el trineo flexionando los tobillos. Repite el número de repeticiones deseado.', 'Adjust the seat of the leg press machine so that your knees are slightly bent when your feet are on the sled. Sit on the machine with your back against the backrest and your feet on the sled, shoulder-width apart. Place your toes and the balls of your feet on the sled, keeping your heels off. Push the sled forward by extending your ankles, keeping your knees slightly bent. Pause for a moment at the top, then slowly lower the sled back down by flexing your ankles. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1392-u0pLNgz.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1392-u0pLNgz.gif', 'u0pLNgz', '© Gym visual — https://gymvisual.com/'),
('1496', 'sledge hammer', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta el mazo con ambas manos. Activa el core y mantén la espalda recta. Balancea el mazo hacia el suelo, usando la fuerza del core y de la parte superior del cuerpo. Mientras balanceas hacia abajo, gira las caderas y transfiere la fu', 'waist', 'hammer', 'waist', 'waist', 'abs', '{"forearms","shoulders"}', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta el mazo con ambas manos. Activa el core y mantén la espalda recta. Balancea el mazo hacia el suelo, usando la fuerza del core y de la parte superior del cuerpo. Mientras balanceas hacia abajo, gira las caderas y transfiere la fuerza al mazo. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and hold the sledge hammer with both hands. Engage your core and keep your back straight. Swing the sledge hammer down towards the ground, using your core and upper body strength. As you swing down, pivot your hips and transfer the force to the hammer. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1496-REXmfVC.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1496-REXmfVC.gif', 'REXmfVC', '© Gym visual — https://gymvisual.com/'),
('0746', 'smith back shrug', 'Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Agarra la barra con un agarre pronado, con las manos un poco más separadas que el ancho de los hombros. Mantén los brazos rectos y deja que la barra cuelgue frente a los muslos. Levanta los hombros', 'back', 'smith machine', 'back', 'back', 'traps', '{"shoulders"}', 'Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Agarra la barra con un agarre pronado, con las manos un poco más separadas que el ancho de los hombros. Mantén los brazos rectos y deja que la barra cuelgue frente a los muslos. Levanta los hombros directamente hacia las orejas, contrayendo los trapecios en la parte alta. Mantén la posición por un momento, luego baja los hombros de nuevo a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and your knees slightly bent. Grasp the barbell with an overhand grip, hands slightly wider than shoulder-width apart. Keep your arms straight and allow the barbell to hang in front of your thighs. Lift your shoulders straight up towards your ears, squeezing your traps at the top. Hold for a moment, then lower your shoulders back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0746-MzNnwx9.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0746-MzNnwx9.gif', 'MzNnwx9', '© Gym visual — https://gymvisual.com/'),
('0747', 'smith behind neck press', 'Ajusta la altura del asiento de la máquina Smith de modo que la barra quede a la altura de los hombros. Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Sujeta la barra con agarre prono, un poco más separado que el ancho de los hombros. Levanta l', 'shoulders', 'smith machine', 'shoulders', 'shoulders', 'delts', '{"triceps","upper back"}', 'Ajusta la altura del asiento de la máquina Smith de modo que la barra quede a la altura de los hombros. Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Sujeta la barra con agarre prono, un poco más separado que el ancho de los hombros. Levanta la barra del soporte y da un paso atrás, manteniendo una postura estable. Baja la barra hacia la parte de atrás del cuello, manteniendo los codos apuntando hacia delante. Empuja la barra hacia arriba, por encima de la cabeza, hasta que los brazos queden completamente extendidos. Haz una pausa por un momento en la posición alta, luego baja lentamente la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the seat height of the smith machine so that the bar is at shoulder level. Stand with your feet shoulder-width apart and your knees slightly bent. Grasp the bar with an overhand grip, slightly wider than shoulder-width apart. Lift the bar off the rack and step back, maintaining a stable stance. Lower the bar down to the back of your neck, keeping your elbows pointing forward. Press the bar up overhead until your arms are fully extended. Pause for a moment at the top, then slowly lower the bar back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0747-Gpn4ADc.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0747-Gpn4ADc.gif', 'Gpn4ADc', '© Gym visual — https://gymvisual.com/'),
('0748', 'smith bench press', 'Ajusta la altura de la barra de la máquina Smith a la altura del pecho. Túmbate en el banco con los pies firmemente apoyados en el suelo. Sujeta la barra con agarre prono, un poco más separado que el ancho de los hombros. Suelta la barra del soporte y bájala hacia el pecho, manteniendo los codos peg', 'chest', 'smith machine', 'chest', 'chest', 'pectorals', '{"triceps","shoulders"}', 'Ajusta la altura de la barra de la máquina Smith a la altura del pecho. Túmbate en el banco con los pies firmemente apoyados en el suelo. Sujeta la barra con agarre prono, un poco más separado que el ancho de los hombros. Suelta la barra del soporte y bájala hacia el pecho, manteniendo los codos pegados al cuerpo. Haz una pausa por un momento cuando la barra toque el pecho. Empuja la barra de vuelta a la posición inicial, extendiendo los brazos por completo. Repite el número de repeticiones deseado.', 'Adjust the height of the smith machine bar to chest level. Lie flat on the bench with your feet firmly planted on the ground. Grip the bar with an overhand grip slightly wider than shoulder-width apart. Unrack the bar and lower it towards your chest, keeping your elbows tucked in. Pause for a moment when the bar touches your chest. Push the bar back up to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0748-trqKQv2.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0748-trqKQv2.gif', 'trqKQv2', '© Gym visual — https://gymvisual.com/'),
('0749', 'smith bent knee good morning', 'Comienza de pie con los pies separados a la altura de los hombros, con los dedos de los pies apuntando hacia delante. Coloca la barra sobre la parte superior de la espalda, apoyándola en los trapecios. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la esp', 'upper legs', 'smith machine', 'upper legs', 'upper legs', 'glutes', '{"hamstrings","lower back"}', 'Comienza de pie con los pies separados a la altura de los hombros, con los dedos de los pies apuntando hacia delante. Coloca la barra sobre la parte superior de la espalda, apoyándola en los trapecios. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta. Baja el torso hasta que quede paralelo al suelo, sintiendo un estiramiento en los isquiotibiales. Activa los glúteos y los isquiotibiales para levantar el torso de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Start by standing with your feet shoulder-width apart, toes pointing forward. Place the barbell across your upper back, resting it on your traps. Bend your knees slightly and hinge forward at the hips, keeping your back straight. Lower your torso until it is parallel to the ground, feeling a stretch in your hamstrings. Engage your glutes and hamstrings to raise your torso back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0749-1bQkKZK.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0749-1bQkKZK.gif', '1bQkKZK', '© Gym visual — https://gymvisual.com/'),
('1359', 'smith bent over row', 'Configura la máquina Smith con la barra a la altura de la cadera. Ponte de pie frente a la barra con los pies separados a la altura de los hombros. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta. Sujeta la barra con un agarre prono, con l', 'back', 'smith machine', 'back', 'back', 'upper back', '{"biceps","forearms"}', 'Configura la máquina Smith con la barra a la altura de la cadera. Ponte de pie frente a la barra con los pies separados a la altura de los hombros. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta. Sujeta la barra con un agarre prono, con las manos un poco más separadas que el ancho de los hombros. Tira de la barra hacia la parte baja del pecho, juntando las escápulas. Haz una pausa por un momento en la posición alta, luego baja lentamente la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Set up the smith machine with the bar at hip height. Stand facing the bar with your feet shoulder-width apart. Bend your knees slightly and hinge forward at the hips, keeping your back straight. Grasp the bar with an overhand grip, hands slightly wider than shoulder-width apart. Pull the bar towards your lower chest, squeezing your shoulder blades together. Pause for a moment at the top, then slowly lower the bar back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1359-ZX9UZmj.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1359-ZX9UZmj.gif', 'ZX9UZmj', '© Gym visual — https://gymvisual.com/'),
('0750', 'smith chair squat', 'Ajusta la altura de la barra de la máquina Smith a una posición cómoda. Ponte de pie con los pies separados a la altura de los hombros, con los dedos de los pies ligeramente hacia afuera. Coloca la barra sobre la parte superior de la espalda, apoyándola en los trapecios. Activa el core y mantén el p', 'upper legs', 'smith machine', 'upper legs', 'upper legs', 'quads', '{"glutes","hamstrings","calves"}', 'Ajusta la altura de la barra de la máquina Smith a una posición cómoda. Ponte de pie con los pies separados a la altura de los hombros, con los dedos de los pies ligeramente hacia afuera. Coloca la barra sobre la parte superior de la espalda, apoyándola en los trapecios. Activa el core y mantén el pecho elevado mientras bajas lentamente el cuerpo doblando las rodillas y las caderas. Continúa bajando hasta que los muslos queden paralelos al suelo, o tan abajo como puedas hacerlo cómodamente. Haz una pausa breve y luego empuja con los talones para volver a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the height of the smith machine bar to a comfortable position. Stand with your feet shoulder-width apart, toes slightly turned out. Place the barbell across your upper back, resting it on your traps. Engage your core and keep your chest up as you slowly lower your body by bending your knees and hips. Continue lowering until your thighs are parallel to the ground, or as low as you can comfortably go. Pause for a moment, then push through your heels to return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0750-Gu2rNJd.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0750-Gu2rNJd.gif', 'Gu2rNJd', '© Gym visual — https://gymvisual.com/'),
('0751', 'smith close-grip bench press', 'Ajusta la altura del asiento y colócate en el banco con los pies planos sobre el suelo. Agarra la barra con un agarre cerrado, un poco más estrecho que el ancho de los hombros. Baja la barra hacia el pecho, manteniendo los codos pegados cerca del cuerpo. Haz una pausa breve en la parte baja y luego ', 'upper arms', 'smith machine', 'upper arms', 'upper arms', 'triceps', '{"chest","shoulders"}', 'Ajusta la altura del asiento y colócate en el banco con los pies planos sobre el suelo. Agarra la barra con un agarre cerrado, un poco más estrecho que el ancho de los hombros. Baja la barra hacia el pecho, manteniendo los codos pegados cerca del cuerpo. Haz una pausa breve en la parte baja y luego empuja la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the seat height and position yourself on the bench with your feet flat on the ground. Grasp the barbell with a close grip, slightly narrower than shoulder-width apart. Lower the barbell towards your chest, keeping your elbows close to your body. Pause for a moment at the bottom, then push the barbell back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0751-WcHl7ru.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0751-WcHl7ru.gif', 'WcHl7ru', '© Gym visual — https://gymvisual.com/'),
('0752', 'smith deadlift', 'Configura la máquina Smith con la barra a la altura de la cadera. Ponte de pie con los pies separados a la altura de los hombros, los dedos de los pies ligeramente hacia afuera. Dobla las caderas y las rodillas, manteniendo la espalda recta y el pecho elevado, y sujeta la barra con un agarre prono u', 'upper legs', 'smith machine', 'upper legs', 'upper legs', 'glutes', '{"hamstrings","quadriceps","lower back"}', 'Configura la máquina Smith con la barra a la altura de la cadera. Ponte de pie con los pies separados a la altura de los hombros, los dedos de los pies ligeramente hacia afuera. Dobla las caderas y las rodillas, manteniendo la espalda recta y el pecho elevado, y sujeta la barra con un agarre prono un poco más ancho que los hombros. Activa el core y levanta la barra extendiendo las caderas y las rodillas, manteniendo la barra cerca del cuerpo. Ponte de pie erguido, extendiendo por completo las caderas y las rodillas. Baja la barra de nuevo doblando las caderas y las rodillas, manteniendo el control y la espalda recta. Repite el número de repeticiones deseado.', 'Set up the smith machine with the bar at hip height. Stand with your feet shoulder-width apart, toes pointing slightly outward. Bend at the hips and knees, keeping your back straight and chest up, and grip the bar with an overhand grip slightly wider than shoulder-width apart. Engage your core and lift the bar by extending your hips and knees, keeping the bar close to your body. Stand up straight, fully extending your hips and knees. Lower the bar back down by bending at the hips and knees, maintaining control and keeping your back straight. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0752-UfePqpx.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0752-UfePqpx.gif', 'UfePqpx', '© Gym visual — https://gymvisual.com/'),
('0753', 'smith decline bench press', 'Ajusta el banco declinado al ángulo deseado. Túmbate en el banco con los pies asegurados bajo las almohadillas para los pies. Agarra la barra con un agarre pronado un poco más ancho que la separación de los hombros. Saca la barra del soporte y bájala lentamente hacia el pecho, manteniendo los codos ', 'chest', 'smith machine', 'chest', 'chest', 'pectorals', '{"triceps","shoulders"}', 'Ajusta el banco declinado al ángulo deseado. Túmbate en el banco con los pies asegurados bajo las almohadillas para los pies. Agarra la barra con un agarre pronado un poco más ancho que la separación de los hombros. Saca la barra del soporte y bájala lentamente hacia el pecho, manteniendo los codos pegados al cuerpo. Haz una pausa breve en la parte baja y luego empuja la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the decline bench to the desired angle. Lie down on the bench with your feet secured under the foot pads. Grasp the barbell with an overhand grip slightly wider than shoulder-width apart. Unrack the barbell and lower it slowly towards your chest, keeping your elbows tucked in. Pause for a moment at the bottom, then push the barbell back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0753-ETZfAbZ.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0753-ETZfAbZ.gif', 'ETZfAbZ', '© Gym visual — https://gymvisual.com/'),
('0754', 'smith decline reverse-grip press', 'Ajusta la máquina Smith a una posición declinada. Túmbate en el banco con los pies asegurados bajo las almohadillas para los pies. Agarra la barra con un agarre invertido, manos un poco más separadas que el ancho de los hombros. Suelta la barra y bájala hacia el pecho, manteniendo los codos pegados ', 'chest', 'smith machine', 'chest', 'chest', 'pectorals', '{"triceps","shoulders"}', 'Ajusta la máquina Smith a una posición declinada. Túmbate en el banco con los pies asegurados bajo las almohadillas para los pies. Agarra la barra con un agarre invertido, manos un poco más separadas que el ancho de los hombros. Suelta la barra y bájala hacia el pecho, manteniendo los codos pegados al cuerpo. Haz una pausa breve en la parte baja y luego empuja la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the smith machine to a decline position. Lie down on the bench with your feet secured under the foot pads. Grasp the barbell with a reverse grip, hands slightly wider than shoulder-width apart. Unrack the barbell and lower it towards your chest, keeping your elbows tucked in. Pause for a moment at the bottom, then push the barbell back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0754-MY9P1WA.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0754-MY9P1WA.gif', 'MY9P1WA', '© Gym visual — https://gymvisual.com/'),
('1433', 'smith front squat (clean grip)', 'Configura la máquina Smith con la barra a la altura de los hombros. Ponte de pie frente a la barra con los pies separados a la altura de los hombros. Agarra la barra con un agarre pronado un poco más ancho que la separación de los hombros. Da un paso atrás y coloca la barra sobre los hombros delante', 'upper legs', 'smith machine', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves","core"}', 'Configura la máquina Smith con la barra a la altura de los hombros. Ponte de pie frente a la barra con los pies separados a la altura de los hombros. Agarra la barra con un agarre pronado un poco más ancho que la separación de los hombros. Da un paso atrás y coloca la barra sobre los hombros delanteros, apoyándola en la clavícula y los deltoides. Mantén el pecho elevado, la espalda recta y el core activado. Baja el cuerpo doblando las rodillas y las caderas, como si te sentaras en una silla. Continúa bajando hasta que los muslos queden paralelos al suelo o un poco por debajo. Haz una pausa breve y luego empuja con los talones para volver a la posición inicial. Repite el número de repeticiones deseado.', 'Set up the smith machine with the barbell at shoulder height. Stand facing the barbell with your feet shoulder-width apart. Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart. Step back and position the barbell on your front shoulders, resting it on your collarbone and deltoids. Keep your chest up, back straight, and core engaged. Lower your body by bending at the knees and hips, as if sitting back into a chair. Continue lowering until your thighs are parallel to the ground or slightly below. Pause for a moment, then push through your heels to return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1433-lFhb2Rw.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1433-lFhb2Rw.gif', 'lFhb2Rw', '© Gym visual — https://gymvisual.com/'),
('3281', 'smith full squat', 'Configura la máquina Smith con la barra a la altura de los hombros. Ponte de pie con los pies separados a la altura de los hombros, con los dedos de los pies ligeramente hacia afuera. Colócate debajo de la barra y posiciónala sobre la parte alta de la espalda, apoyándola en los trapecios. Sujeta la ', 'upper legs', 'smith machine', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves"}', 'Configura la máquina Smith con la barra a la altura de los hombros. Ponte de pie con los pies separados a la altura de los hombros, con los dedos de los pies ligeramente hacia afuera. Colócate debajo de la barra y posiciónala sobre la parte alta de la espalda, apoyándola en los trapecios. Sujeta la barra con las manos un poco más separadas que el ancho de los hombros. Suelta la barra del soporte y da un paso atrás, manteniendo una postura estable. Manteniendo el pecho elevado y el core activado, inicia la sentadilla empujando las caderas hacia atrás y doblando las rodillas. Baja el cuerpo hasta que los muslos queden paralelos al suelo, o tan abajo como tu flexibilidad lo permita. Haz una pausa por un momento en la posición baja, luego empuja con los talones para volver a la posición inicial. Repite el número de repeticiones deseado.', 'Set up the smith machine with the barbell at shoulder height. Stand with your feet shoulder-width apart, toes slightly turned out. Step under the bar and position it across your upper back, resting on your traps. Grip the bar with your hands slightly wider than shoulder-width apart. Unrack the bar and take a step back, maintaining a stable stance. Keeping your chest up and core engaged, initiate the squat by pushing your hips back and bending your knees. Lower your body until your thighs are parallel to the ground, or as low as your flexibility allows. Pause for a moment at the bottom, then drive through your heels to return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3281-NNoHCEA.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3281-NNoHCEA.gif', 'NNoHCEA', '© Gym visual — https://gymvisual.com/'),
('0755', 'smith hack squat', 'Ajusta la barra de la máquina Smith a una altura adecuada para tu cuerpo. Ponte de pie con los pies separados a la altura de los hombros, con los dedos de los pies ligeramente hacia afuera. Colócate debajo de la barra, apoyándola en la parte alta de los trapecios y los hombros. Agarra la barra con u', 'upper legs', 'smith machine', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves"}', 'Ajusta la barra de la máquina Smith a una altura adecuada para tu cuerpo. Ponte de pie con los pies separados a la altura de los hombros, con los dedos de los pies ligeramente hacia afuera. Colócate debajo de la barra, apoyándola en la parte alta de los trapecios y los hombros. Agarra la barra con un agarre pronado un poco más ancho que la separación de los hombros. Activa el core y mantén el pecho elevado mientras sueltas la barra del soporte. Da un paso atrás y coloca los pies un poco más separados que el ancho de los hombros. Dobla las rodillas y baja el cuerpo, manteniendo el pecho elevado y la espalda recta. Continúa descendiendo hasta que los muslos queden paralelos al suelo o un poco por debajo. Haz una pausa por un momento en la parte inferior, luego empuja con los talones para regresar a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the barbell on the smith machine to an appropriate height for your body. Stand with your feet shoulder-width apart, toes slightly pointed outwards. Position yourself under the barbell, resting it on your upper traps and shoulders. Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart. Engage your core and keep your chest up as you unrack the barbell. Take a step back and position your feet slightly wider than shoulder-width apart. Bend your knees and lower your body down, keeping your chest up and back straight. Continue descending until your thighs are parallel to the ground or slightly below. Pause for a moment at the bottom, then push through your heels to return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0755-ZuPXtCK.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0755-ZuPXtCK.gif', 'ZuPXtCK', '© Gym visual — https://gymvisual.com/'),
('0756', 'smith hip raise', 'Colócate en la máquina Smith con la espalda contra la almohadilla y los pies separados a la altura de los hombros. Coloca las manos en la barra, un poco más separadas que el ancho de los hombros. Activa el core y los glúteos, luego empuja con los talones para levantar las caderas del suelo. Continúa', 'waist', 'smith machine', 'waist', 'waist', 'abs', '{"glutes","hamstrings"}', 'Colócate en la máquina Smith con la espalda contra la almohadilla y los pies separados a la altura de los hombros. Coloca las manos en la barra, un poco más separadas que el ancho de los hombros. Activa el core y los glúteos, luego empuja con los talones para levantar las caderas del suelo. Continúa levantando hasta que el cuerpo forme una línea recta desde las rodillas hasta los hombros. Mantén la posición alta por un momento, luego baja lentamente las caderas de nuevo a la posición inicial. Repite el número de repeticiones deseado.', 'Position yourself on the smith machine with your back against the pad and your feet shoulder-width apart. Place your hands on the barbell, slightly wider than shoulder-width apart. Engage your core and glutes, then push through your heels to raise your hips off the ground. Continue lifting until your body forms a straight line from your knees to your shoulders. Hold for a moment at the top, then slowly lower your hips back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0756-CqhoytW.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0756-CqhoytW.gif', 'CqhoytW', '© Gym visual — https://gymvisual.com/'),
('0757', 'smith incline bench press', 'Ajusta el banco a una inclinación de 30-45 grados. Siéntate en el banco con la espalda plana contra la almohadilla y los pies firmemente apoyados en el suelo. Agarra la barra con un agarre pronado un poco más ancho que la separación de los hombros. Suelta la barra y bájala lentamente hacia la parte ', 'chest', 'smith machine', 'chest', 'chest', 'pectorals', '{"shoulders","triceps"}', 'Ajusta el banco a una inclinación de 30-45 grados. Siéntate en el banco con la espalda plana contra la almohadilla y los pies firmemente apoyados en el suelo. Agarra la barra con un agarre pronado un poco más ancho que la separación de los hombros. Suelta la barra y bájala lentamente hacia la parte alta del pecho, manteniendo los codos ligeramente pegados al cuerpo. Haz una pausa por un momento en la posición baja, luego empuja la barra de vuelta a la posición inicial, extendiendo los brazos por completo. Repite el número de repeticiones deseado.', 'Adjust the bench to a 30-45 degree incline. Sit on the bench with your back flat against the pad and feet firmly on the ground. Grasp the barbell with an overhand grip slightly wider than shoulder-width apart. Unrack the barbell and lower it slowly towards your upper chest, keeping your elbows slightly tucked in. Pause for a moment at the bottom, then push the barbell back up to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0757-5v7KYld.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0757-5v7KYld.gif', '5v7KYld', '© Gym visual — https://gymvisual.com/'),
('0758', 'smith incline reverse-grip press', 'Ajusta el asiento de la máquina Smith a un ángulo de inclinación cómodo. Siéntate en la máquina con la espalda contra la almohadilla y los pies planos sobre el suelo. Sujeta la barra con un agarre prono un poco más ancho que el ancho de los hombros. Suelta la barra y bájala lentamente hacia el pecho', 'chest', 'smith machine', 'chest', 'chest', 'pectorals', '{"triceps","shoulders"}', 'Ajusta el asiento de la máquina Smith a un ángulo de inclinación cómodo. Siéntate en la máquina con la espalda contra la almohadilla y los pies planos sobre el suelo. Sujeta la barra con un agarre prono un poco más ancho que el ancho de los hombros. Suelta la barra y bájala lentamente hacia el pecho, manteniendo los codos pegados al cuerpo. Haz una pausa por un momento cuando la barra esté justo por encima del pecho. Empuja la barra de vuelta a la posición inicial, extendiendo los brazos por completo. Repite el número de repeticiones deseado.', 'Adjust the seat of the smith machine to a comfortable incline angle. Sit on the machine with your back against the pad and your feet flat on the ground. Grasp the bar with an overhand grip that is slightly wider than shoulder-width apart. Unrack the bar and lower it slowly towards your chest, keeping your elbows tucked in. Pause for a moment when the bar is just above your chest. Push the bar back up to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0758-78VqWQK.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0758-78VqWQK.gif', '78VqWQK', '© Gym visual — https://gymvisual.com/'),
('0759', 'smith incline shoulder raises', 'Ajusta la máquina Smith a una posición inclinada. Ponte de pie frente a la máquina con los pies separados a la altura de los hombros. Sujeta la barra con agarre prono, un poco más separado que el ancho de los hombros. Mantén la espalda recta y el core activado. Eleva la barra hacia el techo, guiando', 'chest', 'smith machine', 'chest', 'chest', 'serratus anterior', '{"deltoids","trapezius"}', 'Ajusta la máquina Smith a una posición inclinada. Ponte de pie frente a la máquina con los pies separados a la altura de los hombros. Sujeta la barra con agarre prono, un poco más separado que el ancho de los hombros. Mantén la espalda recta y el core activado. Eleva la barra hacia el techo, guiando el movimiento con los codos. Haz una pausa breve en la parte alta y luego baja lentamente la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the smith machine to an incline position. Stand facing the machine with your feet shoulder-width apart. Grasp the bar with an overhand grip, slightly wider than shoulder-width apart. Keep your back straight and core engaged. Raise the barbell up towards the ceiling, leading with your elbows. Pause for a moment at the top, then slowly lower the barbell back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0759-ayAHcEm.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0759-ayAHcEm.gif', 'ayAHcEm', '© Gym visual — https://gymvisual.com/'),
('0760', 'smith leg press', 'Ajusta el asiento y la placa para los pies de la máquina Smith a una posición cómoda. Siéntate en la máquina con la espalda apoyada en el respaldo y los pies separados a la altura de los hombros sobre la placa para los pies. Sujeta las asas o los lados de la máquina para mayor estabilidad. Empuja la', 'upper legs', 'smith machine', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves"}', 'Ajusta el asiento y la placa para los pies de la máquina Smith a una posición cómoda. Siéntate en la máquina con la espalda apoyada en el respaldo y los pies separados a la altura de los hombros sobre la placa para los pies. Sujeta las asas o los lados de la máquina para mayor estabilidad. Empuja la placa alejándola de ti extendiendo las piernas, manteniendo la espalda contra el respaldo. Haz una pausa por un momento en la posición completamente extendida. Dobla lentamente las rodillas y baja la placa de vuelta hacia ti, regresando a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the seat and footplate of the smith machine to a comfortable position. Sit on the machine with your back against the backrest and your feet shoulder-width apart on the footplate. Grasp the handles or sides of the machine for stability. Push the footplate away from you by extending your legs, keeping your back against the backrest. Pause for a moment at the fully extended position. Slowly bend your knees and lower the footplate back towards you, returning to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0760-7zdxRTl.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0760-7zdxRTl.gif', '7zdxRTl', '© Gym visual — https://gymvisual.com/'),
('1434', 'smith low bar squat', 'Configura la máquina Smith con la barra a una altura que te permita apoyarla cómodamente en la parte alta de la espalda. Ponte de pie con los pies separados a la altura de los hombros, con los dedos de los pies ligeramente hacia afuera. Colócate debajo de la barra y posiciónala sobre la parte alta d', 'upper legs', 'smith machine', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves"}', 'Configura la máquina Smith con la barra a una altura que te permita apoyarla cómodamente en la parte alta de la espalda. Ponte de pie con los pies separados a la altura de los hombros, con los dedos de los pies ligeramente hacia afuera. Colócate debajo de la barra y posiciónala sobre la parte alta de la espalda, apoyándola en los trapecios. Sujeta la barra con las manos un poco más separadas que el ancho de los hombros. Suelta la barra del soporte estirando las piernas y dando un paso atrás para alejarte del soporte. Respira profundamente y tensa el core. Inicia la sentadilla empujando las caderas hacia atrás y doblando las rodillas. Baja el cuerpo hasta que los muslos queden paralelos al suelo o un poco por debajo. Mantén el pecho hacia arriba y la espalda recta durante todo el movimiento. Empuja con los talones para volver a ponerte de pie, extendiendo las caderas y las rodillas. Repite el número de repeticiones deseado.', 'Set up the smith machine with the barbell at a height that allows you to comfortably rest it on your upper back. Stand with your feet shoulder-width apart, toes slightly turned outwards. Step under the bar and position it across your upper back, resting it on your traps. Grip the bar with your hands slightly wider than shoulder-width apart. Unrack the bar by straightening your legs and stepping back from the rack. Take a deep breath and brace your core. Initiate the squat by pushing your hips back and bending your knees. Lower your body until your thighs are parallel to the ground or slightly below. Keep your chest up and your back straight throughout the movement. Drive through your heels to stand back up, extending your hips and knees. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1434-RGLscZM.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1434-RGLscZM.gif', 'RGLscZM', '© Gym visual — https://gymvisual.com/'),
('1683', 'smith machine bicep curl', 'Ajusta la altura de la barra de la máquina Smith a la altura de la cintura. Ponte de pie frente a la máquina Smith con los pies separados a la altura de los hombros. Sujeta la barra con un agarre supino, con las manos un poco más separadas que el ancho de los hombros. Mantén los codos cerca de los c', 'upper arms', 'smith machine', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ajusta la altura de la barra de la máquina Smith a la altura de la cintura. Ponte de pie frente a la máquina Smith con los pies separados a la altura de los hombros. Sujeta la barra con un agarre supino, con las manos un poco más separadas que el ancho de los hombros. Mantén los codos cerca de los costados y los brazos superiores quietos. Exhala y flexiona la barra hacia los hombros, contrayendo los bíceps. Haz una pausa breve en la parte más alta del movimiento, contrayendo los bíceps. Inhala y baja lentamente la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the height of the smith machine bar to be at waist level. Stand facing the smith machine with your feet shoulder-width apart. Grasp the bar with an underhand grip, hands slightly wider than shoulder-width apart. Keep your elbows close to your sides and your upper arms stationary. Exhale and curl the bar up towards your shoulders, contracting your biceps. Pause for a moment at the top of the movement, squeezing your biceps. Inhale and slowly lower the bar back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1683-zILLZ98.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1683-zILLZ98.gif', 'zILLZ98', '© Gym visual — https://gymvisual.com/'),
('1625', 'smith machine decline close grip bench press', 'Ajusta el banco de la máquina Smith a una posición declinada. Túmbate en el banco con los pies firmemente apoyados en el suelo. Agarra la barra con un agarre cerrado, un poco más estrecho que el ancho de los hombros. Saca la barra del soporte y bájala lentamente hacia el pecho, manteniendo los codos', 'upper arms', 'smith machine', 'upper arms', 'upper arms', 'triceps', '{"chest","shoulders"}', 'Ajusta el banco de la máquina Smith a una posición declinada. Túmbate en el banco con los pies firmemente apoyados en el suelo. Agarra la barra con un agarre cerrado, un poco más estrecho que el ancho de los hombros. Saca la barra del soporte y bájala lentamente hacia el pecho, manteniendo los codos cerca del cuerpo. Haz una pausa breve cuando la barra esté justo encima del pecho. Empuja la barra de vuelta a la posición inicial, extendiendo completamente los brazos. Repite el número de repeticiones deseado.', 'Adjust the bench on the smith machine to a decline position. Lie down on the bench with your feet firmly planted on the ground. Grasp the barbell with a close grip, slightly narrower than shoulder-width apart. Unrack the barbell and lower it slowly towards your chest, keeping your elbows close to your body. Pause for a moment when the barbell is just above your chest. Push the barbell back up to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1625-yB9SvIF.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1625-yB9SvIF.gif', 'yB9SvIF', '© Gym visual — https://gymvisual.com/'),
('1752', 'smith machine incline tricep extension', 'Ajusta el asiento de la máquina Smith de modo que la barra quede a la altura de los hombros. Siéntate en el banco con la espalda apoyada en el respaldo y los pies planos sobre el suelo. Sujeta la barra con agarre prono, un poco más separado que el ancho de los hombros. Extiende los brazos por comple', 'upper arms', 'smith machine', 'upper arms', 'upper arms', 'triceps', '{"shoulders"}', 'Ajusta el asiento de la máquina Smith de modo que la barra quede a la altura de los hombros. Siéntate en el banco con la espalda apoyada en el respaldo y los pies planos sobre el suelo. Sujeta la barra con agarre prono, un poco más separado que el ancho de los hombros. Extiende los brazos por completo, levantando la barra del soporte y sosteniéndola directamente sobre el pecho. Baja la barra lentamente hacia la frente, manteniendo los codos cerca de la cabeza. Haz una pausa por un momento en la posición baja, luego empuja la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the seat of the smith machine so that the bar is at shoulder height. Sit on the bench with your back against the pad and your feet flat on the ground. Grasp the bar with an overhand grip, slightly wider than shoulder-width apart. Extend your arms fully, lifting the bar off the rack and holding it directly above your chest. Lower the bar slowly towards your forehead, keeping your elbows close to your head. Pause for a moment at the bottom, then push the bar back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1752-o8aOcrz.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1752-o8aOcrz.gif', 'o8aOcrz', '© Gym visual — https://gymvisual.com/'),
('1626', 'smith machine reverse decline close grip bench press', 'Ajusta la máquina Smith a una posición declinada. Túmbate en el banco con los pies asegurados bajo las almohadillas para los pies. Agarra la barra con un agarre cerrado, un poco más estrecho que el ancho de los hombros. Saca la barra del soporte y bájala lentamente hacia el pecho, manteniendo los co', 'chest', 'smith machine', 'chest', 'chest', 'pectorals', '{"triceps","shoulders"}', 'Ajusta la máquina Smith a una posición declinada. Túmbate en el banco con los pies asegurados bajo las almohadillas para los pies. Agarra la barra con un agarre cerrado, un poco más estrecho que el ancho de los hombros. Saca la barra del soporte y bájala lentamente hacia el pecho, manteniendo los codos pegados al cuerpo. Haz una pausa breve en la parte baja y luego empuja la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the smith machine to a decline position. Lie down on the bench with your feet secured under the foot pads. Grasp the barbell with a close grip, slightly narrower than shoulder-width apart. Unrack the barbell and lower it slowly towards your chest, keeping your elbows tucked in. Pause for a moment at the bottom, then push the barbell back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1626-QyO6Uma.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1626-QyO6Uma.gif', 'QyO6Uma', '© Gym visual — https://gymvisual.com/'),
('0761', 'smith narrow row', 'Ajusta la altura del asiento y colócate en la máquina con los pies planos sobre el suelo. Sujeta las asas con un agarre prono, un poco más estrecho que el ancho de los hombros. Mantén la espalda recta y el pecho elevado mientras tiras de las asas hacia tu cuerpo, juntando las escápulas. Haz una paus', 'back', 'smith machine', 'back', 'back', 'upper back', '{"biceps","rear deltoids"}', 'Ajusta la altura del asiento y colócate en la máquina con los pies planos sobre el suelo. Sujeta las asas con un agarre prono, un poco más estrecho que el ancho de los hombros. Mantén la espalda recta y el pecho elevado mientras tiras de las asas hacia tu cuerpo, juntando las escápulas. Haz una pausa por un momento en el punto máximo del movimiento, luego suelta lentamente las agarraderas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the seat height and position yourself on the machine with your feet flat on the floor. Grasp the handles with an overhand grip, slightly narrower than shoulder-width apart. Keep your back straight and your chest up as you pull the handles towards your body, squeezing your shoulder blades together. Pause for a moment at the peak of the movement, then slowly release the handles back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0761-JGKowMS.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0761-JGKowMS.gif', 'JGKowMS', '© Gym visual — https://gymvisual.com/'),
('1360', 'smith one arm row', 'Ajusta la altura de la barra de la máquina Smith a la altura de la cintura. Ponte de pie frente a la máquina Smith con los pies separados a la altura de los hombros. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta. Sujeta la barra con una ', 'back', 'smith machine', 'back', 'back', 'upper back', '{"biceps","forearms"}', 'Ajusta la altura de la barra de la máquina Smith a la altura de la cintura. Ponte de pie frente a la máquina Smith con los pies separados a la altura de los hombros. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta. Sujeta la barra con una mano usando un agarre prono, con la palma hacia abajo. Mantén el codo cerca del cuerpo y tira de la barra hacia la cintura, juntando las escápulas. Haz una pausa por un momento en la parte alta del movimiento, luego baja lentamente la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado, luego cambia al otro brazo.', 'Adjust the height of the smith machine bar to waist level. Stand facing the smith machine with your feet shoulder-width apart. Bend your knees slightly and hinge forward at the hips, keeping your back straight. Grasp the bar with one hand using an overhand grip, with your palm facing down. Keep your elbow close to your body and pull the bar towards your waist, squeezing your shoulder blades together. Pause for a moment at the top of the movement, then slowly lower the bar back to the starting position. Repeat for the desired number of repetitions, then switch to the other arm.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1360-Q4DSJPC.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1360-Q4DSJPC.gif', 'Q4DSJPC', '© Gym visual — https://gymvisual.com/'),
('1393', 'smith one leg floor calf raise', 'Colócate en el suelo debajo de la barra de la máquina Smith, mirando en dirección contraria a la máquina. Coloca la punta de los pies sobre una superficie elevada, como un disco de peso o un bloque. Coloca la barra de la máquina Smith sobre la parte baja de las piernas, justo por encima de los tobil', 'lower legs', 'smith machine', 'lower legs', 'lower legs', 'calves', '{"hamstrings","glutes"}', 'Colócate en el suelo debajo de la barra de la máquina Smith, mirando en dirección contraria a la máquina. Coloca la punta de los pies sobre una superficie elevada, como un disco de peso o un bloque. Coloca la barra de la máquina Smith sobre la parte baja de las piernas, justo por encima de los tobillos. Sujeta la barra con las manos para mayor estabilidad. Levanta los talones del suelo extendiendo los tobillos, elevando el cuerpo hacia arriba. Haz una pausa en la parte alta del movimiento, luego baja lentamente los talones de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Position yourself on the floor under the smith machine bar, facing away from the machine. Place the balls of your feet on a raised surface, such as a weight plate or block. Position the smith machine bar across your lower legs, just above your ankles. Hold onto the bar with your hands for stability. Raise your heels off the ground by extending your ankles, lifting your body up. Pause at the top of the movement, then slowly lower your heels back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1393-9GXrTE6.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1393-9GXrTE6.gif', '9GXrTE6', '© Gym visual — https://gymvisual.com/'),
('0762', 'smith rear delt row', 'Ajusta la altura del asiento y colócate en la máquina con el pecho contra la almohadilla y los pies planos en el suelo. Agarra las agarraderas con un agarre prono, un poco más separadas que el ancho de los hombros. Mantén la espalda recta y el core activado mientras tiras de las asas hacia el pecho,', 'shoulders', 'smith machine', 'shoulders', 'shoulders', 'delts', '{"trapezius","rhomboids","biceps"}', 'Ajusta la altura del asiento y colócate en la máquina con el pecho contra la almohadilla y los pies planos en el suelo. Agarra las agarraderas con un agarre prono, un poco más separadas que el ancho de los hombros. Mantén la espalda recta y el core activado mientras tiras de las asas hacia el pecho, juntando las escápulas. Haz una pausa por un momento en la parte alta del movimiento, luego suelta lentamente las asas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the seat height and position yourself on the machine with your chest against the pad and your feet flat on the ground. Grasp the handles with an overhand grip, slightly wider than shoulder-width apart. Keep your back straight and your core engaged as you pull the handles towards your chest, squeezing your shoulder blades together. Pause for a moment at the top of the movement, then slowly release the handles back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0762-nFUwqG6.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0762-nFUwqG6.gif', 'nFUwqG6', '© Gym visual — https://gymvisual.com/'),
('0763', 'smith reverse calf raises', 'Ajusta la barra de la máquina Smith a una altura justo debajo de los hombros. Ponte de pie frente a la barra con los pies separados a la altura de la cadera y los dedos de los pies apuntando hacia delante. Coloca la punta de los pies en el borde de un escalón o plataforma, con los talones colgando. ', 'lower legs', 'smith machine', 'lower legs', 'lower legs', 'calves', '{"hamstrings"}', 'Ajusta la barra de la máquina Smith a una altura justo debajo de los hombros. Ponte de pie frente a la barra con los pies separados a la altura de la cadera y los dedos de los pies apuntando hacia delante. Coloca la punta de los pies en el borde de un escalón o plataforma, con los talones colgando. Sujétate de la barra para apoyarte, manteniendo la espalda recta y el core activado. Levanta los talones lo más alto posible, elevando el peso de tu cuerpo sobre las puntas de los pies. Haz una pausa breve en la parte alta y luego baja lentamente los talones de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the smith machine bar to a height just below your shoulders. Stand facing the bar with your feet hip-width apart and toes pointing forward. Place the balls of your feet on the edge of a step or platform, with your heels hanging off. Hold onto the bar for support, keeping your back straight and core engaged. Raise your heels as high as possible, lifting your body weight onto the balls of your feet. Pause for a moment at the top, then slowly lower your heels back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0763-ywaNfuh.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0763-ywaNfuh.gif', 'ywaNfuh', '© Gym visual — https://gymvisual.com/'),
('1394', 'smith reverse calf raises', 'Ajusta la barra de la máquina Smith a una altura justo debajo de los hombros. Ponte de pie frente a la barra con los pies separados a la altura de la cadera y los dedos de los pies apuntando hacia delante. Coloca la punta de los pies en el borde de un escalón o plataforma, con los talones colgando. ', 'lower legs', 'smith machine', 'lower legs', 'lower legs', 'calves', '{"hamstrings"}', 'Ajusta la barra de la máquina Smith a una altura justo debajo de los hombros. Ponte de pie frente a la barra con los pies separados a la altura de la cadera y los dedos de los pies apuntando hacia delante. Coloca la punta de los pies en el borde de un escalón o plataforma, con los talones colgando. Sujétate de la barra para apoyarte. Levanta los talones lo más alto posible, elevando el cuerpo sobre la punta de los pies. Haz una pausa breve en la parte alta y luego baja lentamente los talones de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the smith machine bar to a height just below your shoulders. Stand facing the bar with your feet hip-width apart and toes pointing forward. Place the balls of your feet on the edge of a step or platform, with your heels hanging off. Hold onto the bar for support. Raise your heels as high as possible, lifting your body up onto your toes. Pause for a moment at the top, then slowly lower your heels back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1394-Lsqrgh4.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1394-Lsqrgh4.gif', 'Lsqrgh4', '© Gym visual — https://gymvisual.com/'),
('1361', 'smith reverse grip bent over row', 'Configura la máquina Smith con la barra a la altura de la cadera. Ponte de pie frente a la barra con los pies separados a la altura de los hombros. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta. Sujeta la barra con agarre supino, manos s', 'back', 'smith machine', 'back', 'back', 'upper back', '{"biceps","forearms"}', 'Configura la máquina Smith con la barra a la altura de la cadera. Ponte de pie frente a la barra con los pies separados a la altura de los hombros. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta. Sujeta la barra con agarre supino, manos separadas a la altura de los hombros. Tira de la barra hacia la parte baja del pecho, juntando las escápulas. Haz una pausa por un momento en la posición alta, luego baja lentamente la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Set up the smith machine with the bar at hip height. Stand facing the bar with your feet shoulder-width apart. Bend your knees slightly and hinge forward at the hips, keeping your back straight. Grasp the bar with an underhand grip, hands shoulder-width apart. Pull the bar towards your lower chest, squeezing your shoulder blades together. Pause for a moment at the top, then slowly lower the bar back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1361-aaxA3cm.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1361-aaxA3cm.gif', 'aaxA3cm', '© Gym visual — https://gymvisual.com/'),
('0764', 'smith reverse-grip press', 'Ajusta la altura de la barra de la máquina Smith a la altura del pecho. Ponte de pie frente a la barra con los pies separados a la altura de los hombros. Sujeta la barra con un agarre prono, con las manos un poco más separadas que el ancho de los hombros. Da un paso atrás y colócate con una ligera f', 'chest', 'smith machine', 'chest', 'chest', 'pectorals', '{"triceps","shoulders"}', 'Ajusta la altura de la barra de la máquina Smith a la altura del pecho. Ponte de pie frente a la barra con los pies separados a la altura de los hombros. Sujeta la barra con un agarre prono, con las manos un poco más separadas que el ancho de los hombros. Da un paso atrás y colócate con una ligera flexión en las rodillas. Mantén el pecho elevado y el core activado durante todo el ejercicio. Baja la barra hacia el pecho, manteniendo los codos pegados al cuerpo. Haz una pausa por un momento en la posición baja, luego empuja la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the height of the smith machine bar to chest level. Stand facing the bar with your feet shoulder-width apart. Grasp the bar with an overhand grip, hands slightly wider than shoulder-width apart. Step back and position yourself with a slight bend in your knees. Keep your chest up and core engaged throughout the exercise. Lower the bar towards your chest, keeping your elbows tucked in. Pause for a moment at the bottom, then push the bar back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0764-zK8Fu1W.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0764-zK8Fu1W.gif', 'zK8Fu1W', '© Gym visual — https://gymvisual.com/'),
('1395', 'smith seated one leg calf raise', 'Siéntate en la máquina con la espalda contra la almohadilla y los pies sobre el apoyapiés. Coloca una pierna sobre el apoyapiés y mantén la otra pierna fuera de él. Eleva el talón lo más alto posible, usando los músculos de la pantorrilla. Haz una pausa por un momento en la parte superior, luego baj', 'lower legs', 'smith machine', 'lower legs', 'lower legs', 'calves', '{"hamstrings"}', 'Siéntate en la máquina con la espalda contra la almohadilla y los pies sobre el apoyapiés. Coloca una pierna sobre el apoyapiés y mantén la otra pierna fuera de él. Eleva el talón lo más alto posible, usando los músculos de la pantorrilla. Haz una pausa por un momento en la parte superior, luego baja lentamente el talón de vuelta a la posición inicial. Repite el número de repeticiones deseado y luego cambia de pierna y repite.', 'Sit on the machine with your back against the pad and your feet on the footrest. Place one leg on the footrest and keep the other leg off the footrest. Using your calf muscles, raise your heel as high as possible. Pause for a moment at the top, then slowly lower your heel back down to the starting position. Repeat for the desired number of repetitions, then switch legs and repeat.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1395-0S75mYG.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1395-0S75mYG.gif', '0S75mYG', '© Gym visual — https://gymvisual.com/'),
('0765', 'smith seated shoulder press', 'Ajusta la altura del asiento de modo que las asas queden a la altura de los hombros. Siéntate en la máquina con la espalda contra la almohadilla y los pies planos sobre el suelo. Sujeta las asas con un agarre prono y levántalas de los soportes, extendiendo los brazos por completo. Baja las asas hast', 'shoulders', 'smith machine', 'shoulders', 'shoulders', 'delts', '{"triceps","upper back"}', 'Ajusta la altura del asiento de modo que las asas queden a la altura de los hombros. Siéntate en la máquina con la espalda contra la almohadilla y los pies planos sobre el suelo. Sujeta las asas con un agarre prono y levántalas de los soportes, extendiendo los brazos por completo. Baja las asas hasta la altura de los hombros, manteniendo los codos ligeramente flexionados. Empuja las asas hacia arriba, por encima de la cabeza, hasta que los brazos queden completamente extendidos. Haz una pausa por un momento en la parte alta y luego baja lentamente las agarraderas de vuelta a la altura del hombro. Repite el número de repeticiones deseado.', 'Adjust the seat height so that the handles are at shoulder level. Sit on the machine with your back against the pad and your feet flat on the floor. Grasp the handles with an overhand grip and lift them off the supports, extending your arms fully. Lower the handles down to shoulder level, keeping your elbows slightly bent. Press the handles up overhead until your arms are fully extended. Pause for a moment at the top, then slowly lower the handles back down to shoulder level. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0765-xUwnBMT.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0765-xUwnBMT.gif', 'xUwnBMT', '© Gym visual — https://gymvisual.com/'),
('1426', 'smith seated wrist curl', 'Siéntate en un banco frente a una máquina Smith con los pies planos sobre el suelo. Sujeta la barra con un agarre supino, con las manos separadas a la altura de los hombros. Apoya los antebrazos sobre los muslos, permitiendo que las muñecas cuelguen. Flexiona lentamente las muñecas hacia arriba, lle', 'lower arms', 'smith machine', 'lower arms', 'lower arms', 'forearms', '{"biceps","brachialis"}', 'Siéntate en un banco frente a una máquina Smith con los pies planos sobre el suelo. Sujeta la barra con un agarre supino, con las manos separadas a la altura de los hombros. Apoya los antebrazos sobre los muslos, permitiendo que las muñecas cuelguen. Flexiona lentamente las muñecas hacia arriba, llevando la barra hacia los antebrazos. Haz una pausa breve en la parte alta y luego baja lentamente la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a bench in front of a Smith machine with your feet flat on the ground. Grasp the barbell with an underhand grip, hands shoulder-width apart. Rest your forearms on your thighs, allowing your wrists to hang off. Slowly curl your wrists upward, bringing the barbell towards your forearms. Pause for a moment at the top, then slowly lower the barbell back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1426-B6dAO1t.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1426-B6dAO1t.gif', 'B6dAO1t', '© Gym visual — https://gymvisual.com/'),
('0766', 'smith shoulder press', 'Ajusta la altura del asiento y colócate en la máquina Smith con los pies separados a la altura de los hombros. Sujeta la barra con agarre prono, un poco más separado que el ancho de los hombros. Levanta la barra del soporte y colócala a la altura de los hombros, con los codos flexionados y las palma', 'shoulders', 'smith machine', 'shoulders', 'shoulders', 'delts', '{"triceps","upper back"}', 'Ajusta la altura del asiento y colócate en la máquina Smith con los pies separados a la altura de los hombros. Sujeta la barra con agarre prono, un poco más separado que el ancho de los hombros. Levanta la barra del soporte y colócala a la altura de los hombros, con los codos flexionados y las palmas hacia delante. Empuja la barra hacia arriba hasta que los brazos queden completamente extendidos por encima de la cabeza. Haz una pausa por un momento en la posición alta, luego baja lentamente la barra de vuelta a la altura de los hombros. Repite el número de repeticiones deseado.', 'Adjust the seat height and position yourself on the smith machine with your feet shoulder-width apart. Grasp the bar with an overhand grip, slightly wider than shoulder-width apart. Lift the bar off the rack and position it at shoulder level, with your elbows bent and palms facing forward. Press the bar upward until your arms are fully extended overhead. Pause for a moment at the top, then slowly lower the bar back down to shoulder level. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0766-903mzG8.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0766-903mzG8.gif', '903mzG8', '© Gym visual — https://gymvisual.com/'),
('0767', 'smith shrug', 'Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Agarra la barra con un agarre pronado, con las manos un poco más separadas que el ancho de los hombros. Mantén los brazos rectos y los hombros relajados. Levanta los hombros hacia las orejas, contr', 'back', 'smith machine', 'back', 'back', 'traps', '{"shoulders"}', 'Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Agarra la barra con un agarre pronado, con las manos un poco más separadas que el ancho de los hombros. Mantén los brazos rectos y los hombros relajados. Levanta los hombros hacia las orejas, contrayendo los trapecios en la parte alta. Mantén la posición por un momento y luego baja lentamente los hombros de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and your knees slightly bent. Grasp the barbell with an overhand grip, hands slightly wider than shoulder-width apart. Keep your arms straight and your shoulders relaxed. Lift your shoulders up towards your ears, squeezing your traps at the top. Hold for a moment, then slowly lower your shoulders back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0767-OUQ0ZyW.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0767-OUQ0ZyW.gif', 'OUQ0ZyW', '© Gym visual — https://gymvisual.com/'),
('0768', 'smith single leg split squat', 'Ponte de pie frente a la máquina Smith con los pies separados a la altura de los hombros. Coloca un pie detrás de ti sobre un banco o escalón, con los dedos del pie apuntando hacia delante. Sujétate de la barra de la máquina Smith para mayor estabilidad. Dobla la rodilla delantera y baja el cuerpo h', 'upper legs', 'smith machine', 'upper legs', 'upper legs', 'quads', '{"glutes","hamstrings"}', 'Ponte de pie frente a la máquina Smith con los pies separados a la altura de los hombros. Coloca un pie detrás de ti sobre un banco o escalón, con los dedos del pie apuntando hacia delante. Sujétate de la barra de la máquina Smith para mayor estabilidad. Dobla la rodilla delantera y baja el cuerpo hacia una posición de zancada, manteniendo la espalda recta. Haz una pausa por un momento en la posición baja, luego empuja con el talón delantero para volver a la posición inicial. Repite el número de repeticiones deseado, luego cambia de pierna.', 'Stand in front of the smith machine with your feet shoulder-width apart. Place one foot behind you on a bench or step, with your toes pointing forward. Hold onto the smith machine bar for stability. Bend your front knee and lower your body down into a lunge position, keeping your back straight. Pause for a moment at the bottom, then push through your front heel to return to the starting position. Repeat for the desired number of repetitions, then switch legs.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0768-wWFspEi.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0768-wWFspEi.gif', 'wWFspEi', '© Gym visual — https://gymvisual.com/'),
('0769', 'smith sprint lunge', 'Configura la máquina Smith con la barra a la altura de la cadera. Ponte de pie de espaldas a la máquina con los pies separados a la altura de los hombros. Da un paso atrás con el pie derecho y colócalo sobre la barra, apoyando la parte superior del pie en ella. Dobla la rodilla izquierda y baja el c', 'upper legs', 'smith machine', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves"}', 'Configura la máquina Smith con la barra a la altura de la cadera. Ponte de pie de espaldas a la máquina con los pies separados a la altura de los hombros. Da un paso atrás con el pie derecho y colócalo sobre la barra, apoyando la parte superior del pie en ella. Dobla la rodilla izquierda y baja el cuerpo hacia una posición de zancada, manteniendo la espalda recta. Empuja con el talón izquierdo para volver a la posición inicial. Repite del otro lado, dando un paso hacia atrás con el pie izquierdo. Continúa alternando lados durante el número de repeticiones deseado.', 'Set up the smith machine with the barbell at hip height. Stand facing away from the machine with your feet shoulder-width apart. Step back with your right foot and place it on the barbell, resting the top of your foot on the bar. Bend your left knee and lower your body into a lunge position, keeping your back straight. Push through your left heel to return to the starting position. Repeat on the other side, stepping back with your left foot. Continue alternating sides for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0769-HsjbB1z.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0769-HsjbB1z.gif', 'HsjbB1z', '© Gym visual — https://gymvisual.com/'),
('0770', 'smith squat', 'Configura la máquina Smith con la barra a una altura adecuada para tu sentadilla. Ponte de pie con los pies separados a la altura de los hombros, con los dedos de los pies ligeramente hacia afuera. Colócate debajo de la barra, apoyándola en la parte alta de los trapecios y los hombros. Agarra la bar', 'upper legs', 'smith machine', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves"}', 'Configura la máquina Smith con la barra a una altura adecuada para tu sentadilla. Ponte de pie con los pies separados a la altura de los hombros, con los dedos de los pies ligeramente hacia afuera. Colócate debajo de la barra, apoyándola en la parte alta de los trapecios y los hombros. Agarra la barra con un agarre amplio, un poco más ancho que la separación de los hombros. Activa el core y suelta la barra del soporte, dando un paso atrás para alejarte del soporte. Manteniendo el pecho elevado y la espalda recta, inicia la sentadilla doblando las caderas y las rodillas. Baja el cuerpo hasta que los muslos queden paralelos al suelo o un poco por debajo. Haz una pausa por un momento en la posición baja, luego empuja con los talones para volver a la posición inicial. Repite el número de repeticiones deseado.', 'Set up the smith machine with the barbell at an appropriate height for your squat. Stand with your feet shoulder-width apart, toes slightly turned out. Position yourself under the barbell, resting it on your upper traps and shoulders. Grip the barbell with a wide grip, slightly wider than shoulder-width apart. Engage your core and unrack the barbell, stepping back to clear the rack. Keeping your chest up and back straight, initiate the squat by bending at the hips and knees. Lower your body until your thighs are parallel to the ground or slightly below. Pause for a moment at the bottom, then drive through your heels to return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0770-jFtipLl.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0770-jFtipLl.gif', 'jFtipLl', '© Gym visual — https://gymvisual.com/'),
('0771', 'smith standing back wrist curl', 'Ponte de pie frente a la máquina Smith con los pies separados a la altura de los hombros. Sujeta la barra con un agarre prono, con las manos separadas a la altura de los hombros. Mantén la espalda recta y los codos cerca del cuerpo. Flexiona lentamente las muñecas hacia arriba, llevando la barra hac', 'lower arms', 'smith machine', 'lower arms', 'lower arms', 'forearms', '{"biceps","triceps"}', 'Ponte de pie frente a la máquina Smith con los pies separados a la altura de los hombros. Sujeta la barra con un agarre prono, con las manos separadas a la altura de los hombros. Mantén la espalda recta y los codos cerca del cuerpo. Flexiona lentamente las muñecas hacia arriba, llevando la barra hacia el cuerpo. Haz una pausa breve en la parte alta y luego baja lentamente la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand facing the smith machine with your feet shoulder-width apart. Grasp the barbell with an overhand grip, hands shoulder-width apart. Keep your back straight and your elbows close to your body. Slowly curl your wrists upwards, bringing the barbell towards your body. Pause for a moment at the top, then slowly lower the barbell back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0771-hfmQ0Tz.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0771-hfmQ0Tz.gif', 'hfmQ0Tz', '© Gym visual — https://gymvisual.com/'),
('0772', 'smith standing behind head military press', 'Ajusta la altura del asiento de la máquina Smith de modo que la barra quede a la altura de los hombros. Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Sujeta la barra con agarre prono, un poco más separado que el ancho de los hombros. Levanta l', 'shoulders', 'smith machine', 'shoulders', 'shoulders', 'delts', '{"triceps","upper back"}', 'Ajusta la altura del asiento de la máquina Smith de modo que la barra quede a la altura de los hombros. Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Sujeta la barra con agarre prono, un poco más separado que el ancho de los hombros. Levanta la barra del soporte y da un paso atrás, manteniendo una postura estable. Coloca la barra detrás de la cabeza, apoyándola en la parte alta de los trapecios. Mantén el core activado y el pecho elevado durante todo el ejercicio. Empuja la barra por encima de la cabeza extendiendo los brazos, estirándolos por completo. Haz una breve pausa en la parte alta del movimiento, luego baja lentamente la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the seat height of the smith machine so that the bar is at shoulder level. Stand with your feet shoulder-width apart and your knees slightly bent. Grasp the bar with an overhand grip, slightly wider than shoulder-width apart. Lift the bar off the rack and step back, maintaining a stable stance. Position the bar behind your head, resting on your upper traps. Keep your core engaged and your chest lifted throughout the exercise. Press the bar overhead by extending your arms, fully straightening them. Pause briefly at the top of the movement, then slowly lower the bar back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0772-ht8xDrP.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0772-ht8xDrP.gif', 'ht8xDrP', '© Gym visual — https://gymvisual.com/'),
('0773', 'smith standing leg calf raise', 'Ajusta la barra de la máquina Smith a una altura que te permita estar de pie con los pies planos sobre el suelo y los hombros debajo de la barra. Colócate debajo de la barra con los pies separados a la altura de los hombros y los dedos de los pies apuntando hacia delante. Coloca las manos sobre la b', 'lower legs', 'smith machine', 'lower legs', 'lower legs', 'calves', '{"hamstrings","glutes"}', 'Ajusta la barra de la máquina Smith a una altura que te permita estar de pie con los pies planos sobre el suelo y los hombros debajo de la barra. Colócate debajo de la barra con los pies separados a la altura de los hombros y los dedos de los pies apuntando hacia delante. Coloca las manos sobre la barra para mayor estabilidad. Activa las pantorrillas y levanta lentamente los talones del suelo, elevando el cuerpo sobre la punta de los pies. Haz una pausa breve en la parte alta y luego baja lentamente los talones de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the smith machine bar to a height that allows you to stand with your feet flat on the ground and your shoulders under the bar. Position yourself under the bar with your feet shoulder-width apart and your toes pointing forward. Place your hands on the bar for stability. Engage your calves and slowly raise your heels off the ground, lifting your body up onto your toes. Pause for a moment at the top, then slowly lower your heels back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0773-6MaEjVA.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0773-6MaEjVA.gif', '6MaEjVA', '© Gym visual — https://gymvisual.com/'),
('0774', 'smith standing military press', 'Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Agarra la barra con un agarre pronado un poco más ancho que la separación de los hombros. Levanta la barra del soporte y bájala hasta la altura de los hombros, con las palmas hacia delante. Empuja ', 'shoulders', 'smith machine', 'shoulders', 'shoulders', 'delts', '{"triceps","upper back"}', 'Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Agarra la barra con un agarre pronado un poco más ancho que la separación de los hombros. Levanta la barra del soporte y bájala hasta la altura de los hombros, con las palmas hacia delante. Empuja la barra hacia arriba hasta que tus brazos queden completamente extendidos por encima de la cabeza. Haz una pausa de un momento en la parte superior y luego baja lentamente la barra de nuevo hasta la altura de los hombros. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and your knees slightly bent. Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart. Lift the barbell off the rack and bring it down to shoulder level, with your palms facing forward. Press the barbell upward until your arms are fully extended overhead. Pause for a moment at the top, then slowly lower the barbell back down to shoulder level. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0774-jjUPrze.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0774-jjUPrze.gif', 'jjUPrze', '© Gym visual — https://gymvisual.com/'),
('3142', 'smith sumo squat', 'Configura la máquina Smith con la barra a la altura de la cadera. Ponte de pie con los pies más separados que el ancho de los hombros, con las puntas de los pies hacia afuera. Colócate debajo de la barra, apoyándola sobre la parte superior de la espalda y los hombros. Activa el core y mantén el pech', 'upper legs', 'smith machine', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves"}', 'Configura la máquina Smith con la barra a la altura de la cadera. Ponte de pie con los pies más separados que el ancho de los hombros, con las puntas de los pies hacia afuera. Colócate debajo de la barra, apoyándola sobre la parte superior de la espalda y los hombros. Activa el core y mantén el pecho elevado mientras bajas el cuerpo hacia una posición de sentadilla, empujando las caderas hacia atrás y flexionando las rodillas. Baja hasta que los muslos queden paralelos al suelo, o tan abajo como puedas hacerlo cómodamente. Haz una pausa por un momento en la parte inferior, luego empuja con los talones para regresar a la posición inicial. Repite el número de repeticiones deseado.', 'Set up the smith machine with the barbell at hip height. Stand with your feet wider than shoulder-width apart, toes pointing outwards. Position yourself under the barbell, resting it on your upper back and shoulders. Engage your core and keep your chest up as you lower your body down into a squat position, pushing your hips back and bending your knees. Lower yourself until your thighs are parallel to the ground, or as low as you can comfortably go. Pause for a moment at the bottom, then push through your heels to return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3142-dzz6BiV.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3142-dzz6BiV.gif', 'dzz6BiV', '© Gym visual — https://gymvisual.com/'),
('1396', 'smith toe raise', 'Ajusta la barra de la máquina Smith a una altura que te permita pararte cómodamente con los pies planos sobre el suelo. Colócate debajo de la barra con los hombros justo debajo de ella y los pies separados a la altura de los hombros. Coloca la planta de los pies sobre una plataforma elevada o discos', 'lower legs', 'smith machine', 'lower legs', 'lower legs', 'calves', '{"ankles","shins"}', 'Ajusta la barra de la máquina Smith a una altura que te permita pararte cómodamente con los pies planos sobre el suelo. Colócate debajo de la barra con los hombros justo debajo de ella y los pies separados a la altura de los hombros. Coloca la planta de los pies sobre una plataforma elevada o discos de peso, dejando los talones colgando fuera del borde. Sujeta la barra con agarre prono, un poco más separado que el ancho de los hombros. Activa el core y mantén la espalda recta durante todo el ejercicio. Levanta lentamente los talones lo más alto posible, elevando el peso de tu cuerpo sobre la punta de los pies. Haz una pausa breve en la parte alta y luego baja lentamente los talones de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the smith machine bar to a height that allows you to comfortably stand with your feet flat on the ground. Position yourself under the bar with your shoulders directly below it and your feet shoulder-width apart. Place the balls of your feet on a raised platform or weight plates, with your heels hanging off the edge. Grasp the bar with an overhand grip, slightly wider than shoulder-width apart. Engage your core and keep your back straight throughout the exercise. Slowly raise your heels as high as possible, lifting your body weight onto the balls of your feet. Pause for a moment at the top, then slowly lower your heels back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1396-Y4QlY8z.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1396-Y4QlY8z.gif', 'Y4QlY8z', '© Gym visual — https://gymvisual.com/'),
('0775', 'smith upright row', 'Ponte de pie con los pies separados a la altura de los hombros, de frente a la máquina Smith. Agarra la barra con un agarre pronado, con las manos un poco más separadas que el ancho de los hombros. Mantén la espalda recta y el core activado. Tira de la barra hacia tu barbilla, guiando el movimiento ', 'shoulders', 'smith machine', 'shoulders', 'shoulders', 'delts', '{"traps","biceps"}', 'Ponte de pie con los pies separados a la altura de los hombros, de frente a la máquina Smith. Agarra la barra con un agarre pronado, con las manos un poco más separadas que el ancho de los hombros. Mantén la espalda recta y el core activado. Tira de la barra hacia tu barbilla, guiando el movimiento con los codos. Haz una pausa breve en la parte alta y luego baja lentamente la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, facing the smith machine. Grasp the barbell with an overhand grip, hands slightly wider than shoulder-width apart. Keep your back straight and your core engaged. Pull the barbell up towards your chin, leading with your elbows. Pause for a moment at the top, then slowly lower the barbell back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0775-1DN3iz4.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0775-1DN3iz4.gif', '1DN3iz4', '© Gym visual — https://gymvisual.com/'),
('1308', 'smith wide grip bench press', 'Ajusta el banco a una posición cómoda en la máquina Smith. Túmbate en el banco con los pies planos sobre el suelo. Agarra la barra con un agarre amplio, un poco más ancho que la separación de los hombros. Desengancha la barra y bájala lentamente hacia tu pecho, manteniendo los codos hacia afuera a l', 'chest', 'smith machine', 'chest', 'chest', 'pectorals', '{"triceps","shoulders"}', 'Ajusta el banco a una posición cómoda en la máquina Smith. Túmbate en el banco con los pies planos sobre el suelo. Agarra la barra con un agarre amplio, un poco más ancho que la separación de los hombros. Desengancha la barra y bájala lentamente hacia tu pecho, manteniendo los codos hacia afuera a los costados. Haz una pausa breve cuando la barra toque el pecho. Empuja la barra de vuelta a la posición inicial, extendiendo completamente los brazos. Repite el número de repeticiones deseado.', 'Adjust the bench to a comfortable position on the smith machine. Lie down on the bench with your feet flat on the ground. Grasp the barbell with a wide grip, slightly wider than shoulder-width apart. Unrack the barbell and lower it slowly towards your chest, keeping your elbows out to the sides. Pause for a moment when the barbell touches your chest. Push the barbell back up to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1308-zoOvPcx.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1308-zoOvPcx.gif', 'zoOvPcx', '© Gym visual — https://gymvisual.com/'),
('1309', 'smith wide grip decline bench press', 'Ajusta el banco declinado al ángulo deseado. Túmbate en el banco con los pies asegurados bajo las almohadillas para los pies. Agarra la barra con un agarre amplio, un poco más ancho que la separación de los hombros. Desengancha la barra y bájala lentamente hacia tu pecho, manteniendo los codos apunt', 'chest', 'smith machine', 'chest', 'chest', 'pectorals', '{"triceps","shoulders"}', 'Ajusta el banco declinado al ángulo deseado. Túmbate en el banco con los pies asegurados bajo las almohadillas para los pies. Agarra la barra con un agarre amplio, un poco más ancho que la separación de los hombros. Desengancha la barra y bájala lentamente hacia tu pecho, manteniendo los codos apuntando hacia afuera. Haz una pausa breve cuando la barra toque el pecho. Empuja la barra de vuelta a la posición inicial, extendiendo completamente los brazos. Repite el número de repeticiones deseado.', 'Adjust the decline bench to the desired angle. Lie down on the bench with your feet secured under the foot pads. Grasp the barbell with a wide grip, slightly wider than shoulder-width apart. Unrack the barbell and lower it slowly towards your chest, keeping your elbows pointed outwards. Pause for a moment when the barbell touches your chest. Push the barbell back up to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1309-wi2H9QX.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1309-wi2H9QX.gif', 'wi2H9QX', '© Gym visual — https://gymvisual.com/'),
('0776', 'snatch pull', 'Ponte de pie con los pies separados a la altura de los hombros y la barra en el suelo frente a ti. Flexiona las rodillas y dobla las caderas para bajar a una posición de sentadilla, agarrando la barra con un agarre prono. Mantén la espalda recta y el pecho elevado mientras empujas con los talones pa', 'upper legs', 'barbell', 'upper legs', 'upper legs', 'quads', '{"hamstrings","glutes","calves"}', 'Ponte de pie con los pies separados a la altura de los hombros y la barra en el suelo frente a ti. Flexiona las rodillas y dobla las caderas para bajar a una posición de sentadilla, agarrando la barra con un agarre prono. Mantén la espalda recta y el pecho elevado mientras empujas con los talones para levantar la barra del suelo, extendiendo las caderas y las rodillas. Cuando la barra llegue a la altura de la cadera, tira de ella hacia arriba de forma explosiva, encogiendo los hombros y llevando los codos altos y hacia los lados. Cuando la barra alcance su punto más alto, baja rápidamente debajo de ella, llevando tu cuerpo a una posición de sentadilla profunda. Recibe la barra por encima de la cabeza con los brazos completamente extendidos y las rodillas flexionadas. Ponte de pie extendiendo las caderas y las rodillas, manteniendo la barra por encima de la cabeza. Baja la barra de nuevo a la posición inicial invirtiendo el movimiento. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and the barbell on the ground in front of you. Bend your knees and hinge at the hips to lower into a squat position, gripping the barbell with an overhand grip. Keep your back straight and chest up as you drive through your heels to lift the barbell off the ground, extending your hips and knees. As the barbell reaches hip level, explosively pull it upwards, shrugging your shoulders and pulling your elbows high and to the sides. As the barbell reaches its highest point, quickly drop underneath it, pulling yourself into a deep squat position. Catch the barbell overhead with your arms fully extended and your knees bent. Stand up by extending your hips and knees, keeping the barbell overhead. Lower the barbell back down to the starting position by reversing the movement. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0776-dG5Smob.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0776-dG5Smob.gif', 'dG5Smob', '© Gym visual — https://gymvisual.com/'),
('0777', 'spell caster', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una mancuerna con una mano. Flexiona ligeramente las rodillas e inclínate hacia adelante desde la cintura, manteniendo la espalda recta. Extiende el brazo con la mancuerna hacia el pie opuesto, rotando el torso mientras lo haces', 'waist', 'dumbbell', 'waist', 'waist', 'abs', '{"obliques","lower back"}', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una mancuerna con una mano. Flexiona ligeramente las rodillas e inclínate hacia adelante desde la cintura, manteniendo la espalda recta. Extiende el brazo con la mancuerna hacia el pie opuesto, rotando el torso mientras lo haces. Regresa a la posición inicial y repite del otro lado. Continúa alternando lados durante el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and hold a dumbbell in one hand. Bend your knees slightly and hinge forward at the waist, keeping your back straight. Extend your arm with the dumbbell towards the opposite foot, rotating your torso as you do so. Return to the starting position and repeat on the other side. Continue alternating sides for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0777-p9cCe2r.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0777-p9cCe2r.gif', 'p9cCe2r', '© Gym visual — https://gymvisual.com/'),
('1362', 'sphinx', 'Túmbate boca abajo en el suelo con los antebrazos planos sobre el piso y los codos justo debajo de los hombros. Activa el core y levanta el pecho del suelo, manteniendo los antebrazos y los dedos de los pies en el piso. Mantén esta posición durante unos segundos, asegurándote de mantener el cuello e', 'back', 'body weight', 'back', 'back', 'spine', '{"glutes","hamstrings"}', 'Túmbate boca abajo en el suelo con los antebrazos planos sobre el piso y los codos justo debajo de los hombros. Activa el core y levanta el pecho del suelo, manteniendo los antebrazos y los dedos de los pies en el piso. Mantén esta posición durante unos segundos, asegurándote de mantener el cuello en una posición neutral. Baja lentamente el pecho de nuevo a la posición inicial. Repite el número de repeticiones deseado.', 'Lie face down on the ground with your forearms flat on the floor, elbows directly under your shoulders. Engage your core and lift your chest off the ground, keeping your forearms and toes on the floor. Hold this position for a few seconds, making sure to keep your neck in a neutral position. Slowly lower your chest back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1362-DIVyqrU.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1362-DIVyqrU.gif', 'DIVyqrU', '© Gym visual — https://gymvisual.com/'),
('0778', 'spider crawl push up', 'Comienza en posición de flexión con las manos un poco más separadas que la anchura de los hombros y los pies juntos. Lleva la rodilla derecha hacia el codo derecho, manteniéndola elevada del suelo. Mientras llevas la rodilla derecha hacia atrás, baja simultáneamente el cuerpo hacia el suelo flexiona', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'glutes', '{"core","chest","shoulders"}', 'Comienza en posición de flexión con las manos un poco más separadas que la anchura de los hombros y los pies juntos. Lleva la rodilla derecha hacia el codo derecho, manteniéndola elevada del suelo. Mientras llevas la rodilla derecha hacia atrás, baja simultáneamente el cuerpo hacia el suelo flexionando los codos. Empuja de nuevo hacia arriba a la posición inicial y repite llevando la rodilla izquierda hacia el codo izquierdo. Continúa alternando lados durante el número de repeticiones deseado.', 'Start in a push-up position with your hands slightly wider than shoulder-width apart and your feet together. Bring your right knee towards your right elbow, keeping it off the ground. As you bring your right knee back, simultaneously lower your body towards the ground by bending your elbows. Push back up to the starting position and repeat with your left knee towards your left elbow. Continue alternating sides for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0778-P9GFBME.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0778-P9GFBME.gif', 'P9GFBME', '© Gym visual — https://gymvisual.com/'),
('1363', 'spine stretch', 'Siéntate en el suelo con las piernas extendidas frente a ti. Coloca las manos en el suelo detrás de ti, con los dedos apuntando hacia tu cuerpo. Activa el core e inclínate lentamente hacia atrás, manteniendo la espalda recta. Sigue inclinándote hacia atrás hasta que sientas un estiramiento en la col', 'back', 'body weight', 'back', 'back', 'spine', '{"hamstrings","glutes"}', 'Siéntate en el suelo con las piernas extendidas frente a ti. Coloca las manos en el suelo detrás de ti, con los dedos apuntando hacia tu cuerpo. Activa el core e inclínate lentamente hacia atrás, manteniendo la espalda recta. Sigue inclinándote hacia atrás hasta que sientas un estiramiento en la columna. Mantén el estiramiento durante unos segundos, luego regresa lentamente a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on the ground with your legs extended in front of you. Place your hands on the ground behind you, fingers pointing towards your body. Engage your core and slowly lean back, keeping your back straight. Continue leaning back until you feel a stretch in your spine. Hold the stretch for a few seconds, then slowly return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1363-JbC2iaV.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1363-JbC2iaV.gif', 'JbC2iaV', '© Gym visual — https://gymvisual.com/'),
('2329', 'spine twist', 'Siéntate en el suelo con las piernas extendidas frente a ti. Dobla las rodillas y coloca los pies planos sobre el suelo, separados a la altura de la cadera. Coloca las manos detrás de la cabeza con los codos apuntando hacia afuera. Activa el abdomen y gira lentamente el torso hacia la derecha, lleva', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"obliques","lower back"}', 'Siéntate en el suelo con las piernas extendidas frente a ti. Dobla las rodillas y coloca los pies planos sobre el suelo, separados a la altura de la cadera. Coloca las manos detrás de la cabeza con los codos apuntando hacia afuera. Activa el abdomen y gira lentamente el torso hacia la derecha, llevando el codo derecho hacia la rodilla izquierda. Haz una pausa por un momento al final de la rotación, luego regresa lentamente a la posición inicial. Repite el giro hacia el lado izquierdo, llevando el codo izquierdo hacia la rodilla derecha. Continúa alternando lados durante el número de repeticiones deseado.', 'Sit on the ground with your legs extended in front of you. Bend your knees and place your feet flat on the ground, hip-width apart. Place your hands behind your head with your elbows pointing outwards. Engage your abs and slowly twist your torso to the right, bringing your right elbow towards your left knee. Pause for a moment at the end of the twist, then slowly return to the starting position. Repeat the twist to the left side, bringing your left elbow towards your right knee. Continue alternating sides for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2329-2jl9K55.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2329-2jl9K55.gif', '2jl9K55', '© Gym visual — https://gymvisual.com/'),
('2368', 'split squats', 'Ponte de pie con los pies separados a la altura de los hombros. Da un paso adelante con un pie y colócalo aproximadamente a dos pies de distancia por delante del otro pie. Baja el cuerpo flexionando las rodillas y las caderas, manteniendo la espalda recta. Sigue bajando hasta que el muslo delantero ', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'quads', '{"glutes","hamstrings","calves"}', 'Ponte de pie con los pies separados a la altura de los hombros. Da un paso adelante con un pie y colócalo aproximadamente a dos pies de distancia por delante del otro pie. Baja el cuerpo flexionando las rodillas y las caderas, manteniendo la espalda recta. Sigue bajando hasta que el muslo delantero quede paralelo al suelo y la rodilla trasera quede justo por encima del suelo. Haz una pausa breve, luego empuja con el talón delantero para volver a la posición inicial. Repite el número de repeticiones deseado y luego cambia de pierna y repite.', 'Stand with your feet shoulder-width apart. Take a step forward with one foot and place it about two feet in front of the other foot. Lower your body by bending your knees and hips, keeping your back straight. Continue lowering until your front thigh is parallel to the ground, and your back knee is hovering just above the ground. Pause for a moment, then push through your front heel to return to the starting position. Repeat for the desired number of repetitions, then switch legs and repeat.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2368-9E25EOx.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2368-9E25EOx.gif', '9E25EOx', '© Gym visual — https://gymvisual.com/'),
('0786', 'squat jerk', 'Comienza con la barra apoyada sobre los hombros y los pies separados a la altura de los hombros. Baja el cuerpo a una posición de sentadilla, manteniendo el pecho elevado y las rodillas alineadas con la punta de los pies. Al llegar al punto más bajo de la sentadilla, empuja con fuerza a través de la', 'upper legs', 'barbell', 'upper legs', 'upper legs', 'quads', '{"glutes","hamstrings","calves","core"}', 'Comienza con la barra apoyada sobre los hombros y los pies separados a la altura de los hombros. Baja el cuerpo a una posición de sentadilla, manteniendo el pecho elevado y las rodillas alineadas con la punta de los pies. Al llegar al punto más bajo de la sentadilla, empuja con fuerza a través de las piernas y eleva la barra por encima de la cabeza. Cuando la barra alcance su punto más alto, baja rápidamente a una posición de zancada dividida, con un pie adelante y otro atrás. Recibe la barra por encima de la cabeza con los brazos completamente extendidos y la rodilla trasera tocando ligeramente el suelo. Ponte de pie desde la posición dividida, juntando de nuevo los pies. Baja la barra de nuevo a los hombros y repite el número de repeticiones deseado.', 'Start with the barbell resting on your shoulders, with your feet shoulder-width apart. Lower your body into a squat position, keeping your chest up and your knees tracking over your toes. As you reach the bottom of the squat, explosively drive through your legs and push the barbell overhead. As the barbell reaches its peak, quickly drop into a split position, with one foot forward and one foot back. Catch the barbell overhead with your arms fully extended and your back knee slightly touching the ground. Stand up from the split position, bringing your feet back together. Lower the barbell back to your shoulders and repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0786-IMRsOCn.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0786-IMRsOCn.gif', 'IMRsOCn', '© Gym visual — https://gymvisual.com/'),
('1705', 'squat on bosu ball', 'Coloca el bosu en el suelo con el lado plano hacia arriba. Ponte de pie con los pies separados a la altura de los hombros y colócate encima del bosu. Baja el cuerpo flexionando las rodillas y las caderas, como si te sentaras en una silla. Mantén el pecho elevado y el peso en los talones. Baja hasta ', 'upper legs', 'bosu ball', 'upper legs', 'upper legs', 'quads', '{"glutes","hamstrings","calves"}', 'Coloca el bosu en el suelo con el lado plano hacia arriba. Ponte de pie con los pies separados a la altura de los hombros y colócate encima del bosu. Baja el cuerpo flexionando las rodillas y las caderas, como si te sentaras en una silla. Mantén el pecho elevado y el peso en los talones. Baja hasta que los muslos queden paralelos al suelo. Haz una pausa breve y luego empuja con los talones para volver a la posición inicial. Repite el número de repeticiones deseado.', 'Place the bosu ball on the ground with the flat side up. Stand with your feet shoulder-width apart and position yourself on top of the bosu ball. Lower your body down by bending your knees and hips, as if sitting back into a chair. Keep your chest up and your weight on your heels. Lower yourself until your thighs are parallel to the ground. Pause for a moment, then push through your heels to return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1705-T2fA5Ir.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1705-T2fA5Ir.gif', 'T2fA5Ir', '© Gym visual — https://gymvisual.com/'),
('1685', 'squat to overhead reach', 'Ponte de pie con los pies separados a la altura de los hombros y los dedos de los pies ligeramente hacia afuera. Baja el cuerpo hacia una posición de sentadilla flexionando las rodillas y empujando las caderas hacia atrás. Mientras te levantas de la sentadilla, extiende los brazos por encima de la c', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'quads', '{"glutes","hamstrings","core"}', 'Ponte de pie con los pies separados a la altura de los hombros y los dedos de los pies ligeramente hacia afuera. Baja el cuerpo hacia una posición de sentadilla flexionando las rodillas y empujando las caderas hacia atrás. Mientras te levantas de la sentadilla, extiende los brazos por encima de la cabeza, alcanzando hacia el techo. Vuelve a la posición inicial bajando los brazos y flexionando las rodillas para volver a hacer la sentadilla. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and toes slightly turned out. Lower your body down into a squat position by bending your knees and pushing your hips back. As you come up from the squat, extend your arms overhead, reaching towards the ceiling. Return to the starting position by lowering your arms and bending your knees to squat down again. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1685-QChZi3x.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1685-QChZi3x.gif', 'QChZi3x', '© Gym visual — https://gymvisual.com/'),
('1686', 'squat to overhead reach with twist', 'Ponte de pie con los pies separados a la altura de los hombros y los dedos de los pies ligeramente hacia afuera. Baja el cuerpo hacia una posición de sentadilla flexionando las rodillas y empujando las caderas hacia atrás. Mientras te levantas de la sentadilla, eleva los brazos por encima de la cabe', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'quads', '{"glutes","hamstrings","core"}', 'Ponte de pie con los pies separados a la altura de los hombros y los dedos de los pies ligeramente hacia afuera. Baja el cuerpo hacia una posición de sentadilla flexionando las rodillas y empujando las caderas hacia atrás. Mientras te levantas de la sentadilla, eleva los brazos por encima de la cabeza y gira el torso hacia un lado. Vuelve a la posición inicial y repite la sentadilla, esta vez girando el torso hacia el lado opuesto. Continúa alternando los lados en cada repetición de la sentadilla.', 'Stand with your feet shoulder-width apart and toes slightly turned out. Lower your body into a squat position by bending your knees and pushing your hips back. As you come up from the squat, raise your arms overhead and twist your torso to one side. Return to the starting position and repeat the squat, this time twisting your torso to the opposite side. Continue alternating sides with each squat repetition.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1686-5BZHW9s.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1686-5BZHW9s.gif', '5BZHW9s', '© Gym visual — https://gymvisual.com/'),
('2297', 'stability ball crunch (full range hands behind head)', 'Siéntate en el balón de estabilidad con los pies planos en el suelo y las rodillas flexionadas en un ángulo de 90 grados. Coloca las manos detrás de la cabeza con los codos apuntando hacia afuera. Activando el abdomen, curva lentamente la parte superior del cuerpo hacia adelante, llevando el pecho h', 'waist', 'stability ball', 'waist', 'waist', 'abs', '{"hip flexors"}', 'Siéntate en el balón de estabilidad con los pies planos en el suelo y las rodillas flexionadas en un ángulo de 90 grados. Coloca las manos detrás de la cabeza con los codos apuntando hacia afuera. Activando el abdomen, curva lentamente la parte superior del cuerpo hacia adelante, llevando el pecho hacia las rodillas. Haz una pausa por un momento en la parte superior, luego baja lentamente la parte superior del cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on the stability ball with your feet flat on the ground and your knees bent at a 90-degree angle. Place your hands behind your head with your elbows pointing outwards. Engaging your abs, slowly curl your upper body forward, bringing your chest towards your knees. Pause for a moment at the top, then slowly lower your upper body back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2297-Gn5FwYT.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2297-Gn5FwYT.gif', 'Gn5FwYT', '© Gym visual — https://gymvisual.com/'),
('3291', 'stalder press', 'Comienza de pie con los pies separados a la altura de los hombros y los brazos extendidos por encima de la cabeza. Flexiona ligeramente las rodillas y activa el core. Baja el cuerpo a una posición de sentadilla mientras mantienes los brazos extendidos por encima de la cabeza. Mientras bajas en la se', 'upper arms', 'body weight', 'upper arms', 'upper arms', 'triceps', '{"shoulders","core"}', 'Comienza de pie con los pies separados a la altura de los hombros y los brazos extendidos por encima de la cabeza. Flexiona ligeramente las rodillas y activa el core. Baja el cuerpo a una posición de sentadilla mientras mantienes los brazos extendidos por encima de la cabeza. Mientras bajas en la sentadilla, empuja los brazos hacia el suelo, activando los tríceps. Haz una pausa de un momento en la parte baja de la sentadilla, luego empuja con los talones para levantarte mientras al mismo tiempo elevas de nuevo los brazos por encima de la cabeza. Repite el número de repeticiones deseado.', 'Start by standing with your feet shoulder-width apart and your arms extended overhead. Bend your knees slightly and engage your core. Lower your body down into a squat position while keeping your arms extended overhead. As you squat down, press your arms down towards the ground, engaging your triceps. Pause for a moment at the bottom of the squat, then push through your heels to stand back up while simultaneously raising your arms back overhead. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3291-zd4P4B2.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3291-zd4P4B2.gif', 'zd4P4B2', '© Gym visual — https://gymvisual.com/'),
('3669', 'standing archer', 'Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Extiende los brazos rectos hacia adelante a la altura de los hombros, paralelos al suelo. Gira el torso hacia la derecha, manteniendo los brazos extendidos y la espalda recta. Mientras giras, extie', 'back', 'body weight', 'back', 'back', 'upper back', '{"shoulders","biceps","forearms"}', 'Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Extiende los brazos rectos hacia adelante a la altura de los hombros, paralelos al suelo. Gira el torso hacia la derecha, manteniendo los brazos extendidos y la espalda recta. Mientras giras, extiende el brazo derecho hacia adelante y el brazo izquierdo hacia atrás, imitando el movimiento de tensar un arco. Mantén la posición por un momento y luego vuelve a la posición inicial. Repite el movimiento, esta vez girando el torso hacia la izquierda y extendiendo el brazo izquierdo hacia adelante y el brazo derecho hacia atrás. Continúa alternando lados durante el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and your knees slightly bent. Extend your arms straight out in front of you at shoulder height, parallel to the ground. Rotate your torso to the right, keeping your arms extended and your back straight. As you rotate, extend your right arm forward and your left arm back, mimicking the motion of drawing a bowstring. Hold the position for a moment, then return to the starting position. Repeat the motion, this time rotating your torso to the left and extending your left arm forward and your right arm back. Continue alternating sides for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3669-JF8AkMX.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3669-JF8AkMX.gif', 'JF8AkMX', '© Gym visual — https://gymvisual.com/'),
('0788', 'standing behind neck press', 'Ponte de pie con los pies separados a la altura de los hombros y sostén la barra detrás del cuello con un agarre prono. Mantén la espalda recta y el core activado. Empuja la barra por encima de la cabeza extendiendo los brazos, estirando completamente los codos. Haz una pausa breve en la parte alta ', 'shoulders', 'barbell', 'shoulders', 'shoulders', 'delts', '{"triceps","upper back"}', 'Ponte de pie con los pies separados a la altura de los hombros y sostén la barra detrás del cuello con un agarre prono. Mantén la espalda recta y el core activado. Empuja la barra por encima de la cabeza extendiendo los brazos, estirando completamente los codos. Haz una pausa breve en la parte alta y luego baja lentamente la barra de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and hold the barbell behind your neck with an overhand grip. Keep your back straight and core engaged. Press the barbell overhead by extending your arms, fully extending your elbows. Pause for a moment at the top, then slowly lower the barbell back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0788-xDh0lJr.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0788-xDh0lJr.gif', 'xDh0lJr', '© Gym visual — https://gymvisual.com/'),
('1490', 'standing calf raise (on a staircase)', 'Ponte de pie en el borde de un escalón o una plataforma firme, con los talones colgando y la punta de los pies sobre el escalón. Sujétate de una baranda o pared para mantener el equilibrio si es necesario. Levanta lentamente los talones lo más alto posible, elevando el peso de tu cuerpo sobre la pun', 'lower legs', 'body weight', 'lower legs', 'lower legs', 'calves', '{"ankles","feet"}', 'Ponte de pie en el borde de un escalón o una plataforma firme, con los talones colgando y la punta de los pies sobre el escalón. Sujétate de una baranda o pared para mantener el equilibrio si es necesario. Levanta lentamente los talones lo más alto posible, elevando el peso de tu cuerpo sobre la punta de los pies. Haz una pausa breve en la parte alta y luego baja lentamente los talones de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand on the edge of a step or a sturdy platform with your heels hanging off and your toes on the step. Hold onto a railing or wall for balance if needed. Slowly raise your heels as high as possible, lifting your body weight onto the balls of your feet. Pause for a moment at the top, then slowly lower your heels back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1490-6HmFgmx.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1490-6HmFgmx.gif', '6HmFgmx', '© Gym visual — https://gymvisual.com/'),
('1397', 'standing calves', 'Ponte de pie con los pies separados a la altura de los hombros, con las puntas de los pies apuntando hacia adelante. Levanta los talones del suelo lo más alto posible, apoyándote sobre la punta de los pies. Mantén la posición por un momento y luego baja lentamente los talones de nuevo a la posición ', 'lower legs', 'body weight', 'lower legs', 'lower legs', 'calves', '{"hamstrings","glutes"}', 'Ponte de pie con los pies separados a la altura de los hombros, con las puntas de los pies apuntando hacia adelante. Levanta los talones del suelo lo más alto posible, apoyándote sobre la punta de los pies. Mantén la posición por un momento y luego baja lentamente los talones de nuevo a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, toes pointing forward. Raise your heels off the ground as high as possible, standing on your toes. Hold the position for a moment, then slowly lower your heels back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1397-XIHEoCG.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1397-XIHEoCG.gif', 'XIHEoCG', '© Gym visual — https://gymvisual.com/'),
('1398', 'standing calves calf stretch', 'Ponte de pie frente a una pared u objeto firme, a una distancia aproximada de un brazo. Coloca las manos sobre la pared o el objeto a la altura de los hombros. Da un paso hacia atrás con un pie, manteniendo el talón plano sobre el suelo. Flexiona ligeramente la rodilla delantera e inclínate hacia ad', 'lower legs', 'body weight', 'lower legs', 'lower legs', 'calves', '{"hamstrings","glutes"}', 'Ponte de pie frente a una pared u objeto firme, a una distancia aproximada de un brazo. Coloca las manos sobre la pared o el objeto a la altura de los hombros. Da un paso hacia atrás con un pie, manteniendo el talón plano sobre el suelo. Flexiona ligeramente la rodilla delantera e inclínate hacia adelante, manteniendo la pierna trasera recta. Deberías sentir un estiramiento en el músculo de la pantorrilla. Mantén el estiramiento durante 20-30 segundos. Repite con la otra pierna.', 'Stand facing a wall or sturdy object, about an arm''s length away. Place your hands on the wall or object at shoulder height. Step back with one foot, keeping your heel flat on the ground. Bend your front knee slightly and lean forward, keeping your back leg straight. You should feel a stretch in your calf muscle. Hold the stretch for 20-30 seconds. Repeat on the other leg.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1398-qOKcgVP.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1398-qOKcgVP.gif', 'qOKcgVP', '© Gym visual — https://gymvisual.com/'),
('1599', 'standing hamstring and calf stretch with strap', 'Ponte de pie con la espalda recta y los pies separados a la altura de los hombros. Sostén la correa con ambas manos y colócala alrededor de la parte anterior de la planta del pie. Mantén la pierna recta e inclínate lentamente hacia adelante desde las caderas, manteniendo la espalda recta. Siente el ', 'upper legs', 'rope', 'upper legs', 'upper legs', 'hamstrings', '{"calves"}', 'Ponte de pie con la espalda recta y los pies separados a la altura de los hombros. Sostén la correa con ambas manos y colócala alrededor de la parte anterior de la planta del pie. Mantén la pierna recta e inclínate lentamente hacia adelante desde las caderas, manteniendo la espalda recta. Siente el estiramiento en los isquiotibiales y en los músculos de la pantorrilla. Mantén el estiramiento durante 20-30 segundos. Suelta el estiramiento y repite con la otra pierna. Repite el número de repeticiones deseado.', 'Stand upright with your feet shoulder-width apart. Hold the strap with both hands and place it around the ball of your foot. Keep your leg straight and slowly lean forward from your hips, keeping your back straight. Feel the stretch in your hamstring and calf muscles. Hold the stretch for 20-30 seconds. Release the stretch and repeat with the other leg. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1599-xTjr103.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1599-xTjr103.gif', 'xTjr103', '© Gym visual — https://gymvisual.com/'),
('0794', 'standing lateral stretch', 'Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Extiende los brazos hacia los lados, paralelos al suelo. Inclina lentamente la parte superior del cuerpo hacia un lado, sintiendo un estiramiento en el costado y los dorsales. Mantén el estiramient', 'back', 'body weight', 'back', 'back', 'lats', '{"shoulders","obliques"}', 'Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Extiende los brazos hacia los lados, paralelos al suelo. Inclina lentamente la parte superior del cuerpo hacia un lado, sintiendo un estiramiento en el costado y los dorsales. Mantén el estiramiento durante 15-30 segundos. Regresa a la posición inicial y repite del otro lado. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and your knees slightly bent. Extend your arms straight out to the sides, parallel to the ground. Slowly lean your upper body to one side, feeling a stretch in your side and lats. Hold the stretch for 15-30 seconds. Return to the starting position and repeat on the other side. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0794-1jXLYEw.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0794-1jXLYEw.gif', '1jXLYEw', '© Gym visual — https://gymvisual.com/'),
('1364', 'standing pelvic tilt', 'Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Coloca las manos sobre las caderas o déjalas colgar a los lados. Activa los músculos del core e inclina la pelvis hacia adelante, empujando la zona lumbar hacia la pared detrás de ti. Mantén la pos', 'back', 'body weight', 'back', 'back', 'spine', '{"abdominals"}', 'Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Coloca las manos sobre las caderas o déjalas colgar a los lados. Activa los músculos del core e inclina la pelvis hacia adelante, empujando la zona lumbar hacia la pared detrás de ti. Mantén la posición durante unos segundos, luego suelta y vuelve a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and your knees slightly bent. Place your hands on your hips or let them hang by your sides. Engage your core muscles and tilt your pelvis forward, pushing your lower back towards the wall behind you. Hold the position for a few seconds, then release and return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1364-cuKYxhu.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1364-cuKYxhu.gif', 'cuKYxhu', '© Gym visual — https://gymvisual.com/'),
('0795', 'standing single leg curl', 'Ponte de pie con los pies separados a la altura de las caderas y las manos en las caderas. Traslada tu peso a la pierna izquierda y levanta el pie derecho del suelo, flexionando la rodilla. Curva lentamente el talón derecho hacia los glúteos, contrayendo el isquiotibial. Haz una pausa de un momento ', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'hamstrings', '{"glutes"}', 'Ponte de pie con los pies separados a la altura de las caderas y las manos en las caderas. Traslada tu peso a la pierna izquierda y levanta el pie derecho del suelo, flexionando la rodilla. Curva lentamente el talón derecho hacia los glúteos, contrayendo el isquiotibial. Haz una pausa de un momento en la parte superior y luego baja lentamente el pie derecho de nuevo a la posición inicial. Repite el número de repeticiones deseado, luego cambia de pierna.', 'Stand with your feet hip-width apart and your hands on your hips. Shift your weight onto your left leg and lift your right foot off the ground, bending your knee. Slowly curl your right heel towards your glutes, squeezing your hamstring. Pause for a moment at the top, then slowly lower your right foot back down to the starting position. Repeat for the desired number of repetitions, then switch legs.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0795-C5jncD2.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0795-C5jncD2.gif', 'C5jncD2', '© Gym visual — https://gymvisual.com/'),
('0796', 'standing wheel rollerout', 'Comienza de pie, erguido, con los pies separados a la altura de los hombros y el rodillo frente a ti. Dobla la cintura y haz rodar lentamente el rodillo hacia adelante, manteniendo la espalda recta y el core activado. Continúa rodando hacia adelante hasta sentir un estiramiento en el abdomen y que t', 'waist', 'wheel roller', 'waist', 'waist', 'abs', '{"lower back","shoulders"}', 'Comienza de pie, erguido, con los pies separados a la altura de los hombros y el rodillo frente a ti. Dobla la cintura y haz rodar lentamente el rodillo hacia adelante, manteniendo la espalda recta y el core activado. Continúa rodando hacia adelante hasta sentir un estiramiento en el abdomen y que tu cuerpo esté extendido lo máximo posible. Haz una pausa de un momento, luego haz rodar lentamente el rodillo de regreso hacia tu cuerpo, volviendo a la posición inicial. Repite el número de repeticiones deseado.', 'Start by standing tall with your feet shoulder-width apart and the wheel roller in front of you. Bend at your waist and slowly roll the wheel forward, keeping your back straight and your core engaged. Continue rolling forward until you feel a stretch in your abs and your body is extended as far as possible. Pause for a moment, then slowly roll the wheel back towards your body, returning to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0796-KtRomty.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0796-KtRomty.gif', 'KtRomty', '© Gym visual — https://gymvisual.com/'),
('3223', 'star jump (male)', 'Ponte de pie con los pies separados a la altura de los hombros y los brazos a los costados. Flexiona ligeramente las rodillas y salta hacia arriba de forma explosiva. Mientras saltas, separa las piernas y extiende los brazos hacia los lados, formando una figura de estrella con tu cuerpo. Aterriza su', 'cardio', 'body weight', 'cardio', 'cardio', 'cardiovascular system', '{"quadriceps","hamstrings","calves"}', 'Ponte de pie con los pies separados a la altura de los hombros y los brazos a los costados. Flexiona ligeramente las rodillas y salta hacia arriba de forma explosiva. Mientras saltas, separa las piernas y extiende los brazos hacia los lados, formando una figura de estrella con tu cuerpo. Aterriza suavemente sobre la punta de los pies con las rodillas ligeramente flexionadas. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and your arms by your sides. Bend your knees slightly and jump up explosively. As you jump, spread your legs and extend your arms out to the sides, forming a star shape with your body. Land softly on the balls of your feet with your knees slightly bent. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3223-HtfCpfi.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3223-HtfCpfi.gif', 'HtfCpfi', '© Gym visual — https://gymvisual.com/'),
('2138', 'stationary bike run v. 3', 'Ajusta la altura y la posición del asiento para asegurar una alineación correcta. Coloca los pies sobre los pedales y sujétalos con las correas si están disponibles. Comienza a pedalear a un ritmo cómodo. Mantén un ritmo constante y aumenta la resistencia según lo desees. Activa los músculos del cor', 'cardio', 'stationary bike', 'cardio', 'cardio', 'cardiovascular system', '{"quadriceps","hamstrings","calves"}', 'Ajusta la altura y la posición del asiento para asegurar una alineación correcta. Coloca los pies sobre los pedales y sujétalos con las correas si están disponibles. Comienza a pedalear a un ritmo cómodo. Mantén un ritmo constante y aumenta la resistencia según lo desees. Activa los músculos del core para mantener la estabilidad y una postura correcta. Continúa pedaleando durante la duración deseada de tu entrenamiento. Disminuye gradualmente la resistencia y reduce la velocidad antes de detenerte por completo. Estira las piernas y enfría después del entrenamiento.', 'Adjust the seat height and position to ensure proper alignment. Place your feet on the pedals and secure them with the straps if available. Start pedaling at a comfortable pace. Maintain a steady rhythm and increase the resistance as desired. Engage your core muscles to maintain stability and proper posture. Continue pedaling for the desired duration of your workout. Gradually decrease the resistance and slow down before coming to a complete stop. Stretch your legs and cool down after the workout.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2138-H1PESYI.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2138-H1PESYI.gif', 'H1PESYI', '© Gym visual — https://gymvisual.com/'),
('0798', 'stationary bike walk', 'Ajusta la altura y la posición del asiento en la bicicleta estática para asegurar una alineación correcta. Coloca los pies sobre los pedales y sujétalos con las correas si están disponibles. Comienza a pedalear a un ritmo cómodo, manteniendo la espalda recta y el core activado. Mantén un ritmo const', 'cardio', 'leverage machine', 'cardio', 'cardio', 'cardiovascular system', '{"quadriceps","hamstrings","calves"}', 'Ajusta la altura y la posición del asiento en la bicicleta estática para asegurar una alineación correcta. Coloca los pies sobre los pedales y sujétalos con las correas si están disponibles. Comienza a pedalear a un ritmo cómodo, manteniendo la espalda recta y el core activado. Mantén un ritmo constante y aumenta el nivel de resistencia si lo deseas. Continúa pedaleando durante la duración deseada de tu entrenamiento cardiovascular. Enfría reduciendo gradualmente tu ritmo y el nivel de resistencia. Estira los músculos de las piernas después del entrenamiento para prevenir la rigidez y favorecer la recuperación.', 'Adjust the seat height and position on the stationary bike to ensure proper alignment. Place your feet on the pedals and secure them with the straps if available. Start pedaling at a comfortable pace, keeping your back straight and core engaged. Maintain a steady rhythm and increase the resistance level if desired. Continue pedaling for the desired duration of your cardio workout. Cool down by gradually reducing your pace and resistance level. Stretch your leg muscles after the workout to prevent tightness and promote recovery.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0798-a8VDgLw.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0798-a8VDgLw.gif', 'a8VDgLw', '© Gym visual — https://gymvisual.com/'),
('3314', 'straddle maltese', 'Comienza colgándote de un par de anillas con los brazos completamente extendidos y el cuerpo en línea recta. Separa bien las piernas, formando una posición a horcajadas. Activa el core y baja lentamente el cuerpo hasta que los brazos queden paralelos al suelo. Mantén esta posición durante unos segun', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"shoulders","chest"}', 'Comienza colgándote de un par de anillas con los brazos completamente extendidos y el cuerpo en línea recta. Separa bien las piernas, formando una posición a horcajadas. Activa el core y baja lentamente el cuerpo hasta que los brazos queden paralelos al suelo. Mantén esta posición durante unos segundos, luego empújate de nuevo hacia arriba a la posición inicial. Repite el número de repeticiones deseado.', 'Start by hanging from a pair of rings with your arms fully extended and your body in a straight line. Spread your legs wide apart, forming a straddle position. Engage your core and slowly lower your body until your arms are parallel to the ground. Hold this position for a few seconds, then push yourself back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3314-HfqciZF.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3314-HfqciZF.gif', 'HfqciZF', '© Gym visual — https://gymvisual.com/'),
('3298', 'straddle planche', 'Comienza en posición de flexión con las manos separadas a la altura de los hombros y los pies bien separados. Activa el core y traslada lentamente tu peso hacia adelante, llevando los hombros por encima de las manos. Flexiona los codos y baja el cuerpo hacia el suelo, manteniendo los codos cerca de ', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"shoulders","triceps","chest"}', 'Comienza en posición de flexión con las manos separadas a la altura de los hombros y los pies bien separados. Activa el core y traslada lentamente tu peso hacia adelante, llevando los hombros por encima de las manos. Flexiona los codos y baja el cuerpo hacia el suelo, manteniendo los codos cerca de los costados. Haz una pausa por un momento en la posición más baja, luego empuja con las manos para enderezar los brazos y levantar el cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Start in a push-up position with your hands shoulder-width apart and your feet spread wide apart. Engage your core and slowly shift your weight forward, bringing your shoulders over your hands. Bend your elbows and lower your body towards the ground, keeping your elbows close to your sides. Pause for a moment at the bottom, then push through your hands to straighten your arms and lift your body back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3298-BL3GHeY.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3298-BL3GHeY.gif', 'BL3GHeY', '© Gym visual — https://gymvisual.com/'),
('1427', 'straight leg outer hip abductor', 'Túmbate de lado con las piernas rectas y apiladas una sobre la otra. Coloca el brazo de abajo bajo la cabeza para apoyarte. Activa el core y levanta la pierna superior lo más alto posible sin rotar las caderas ni inclinarte hacia atrás. Haz una pausa por un momento en la posición alta, luego baja le', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'abductors', '{"glutes","hamstrings"}', 'Túmbate de lado con las piernas rectas y apiladas una sobre la otra. Coloca el brazo de abajo bajo la cabeza para apoyarte. Activa el core y levanta la pierna superior lo más alto posible sin rotar las caderas ni inclinarte hacia atrás. Haz una pausa por un momento en la posición alta, luego baja lentamente la pierna de nuevo a la posición inicial. Repite el número de repeticiones deseado, luego cambia de lado.', 'Lie on your side with your legs straight and stacked on top of each other. Place your bottom arm under your head for support. Engage your core and lift your top leg as high as possible without rotating your hips or leaning backward. Pause for a moment at the top, then slowly lower your leg back down to the starting position. Repeat for the desired number of repetitions, then switch sides.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1427-mQ1tBXn.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1427-mQ1tBXn.gif', 'mQ1tBXn', '© Gym visual — https://gymvisual.com/'),
('0803', 'superman push-up', 'Comienza en una posición de plancha alta con las manos un poco más separadas que la anchura de los hombros y los pies juntos. Activa el core y baja el cuerpo hacia el suelo, manteniendo los codos cerca de los costados. Mientras bajas el cuerpo, levanta simultáneamente el brazo derecho y la pierna iz', 'chest', 'body weight', 'chest', 'chest', 'pectorals', '{"core","shoulders"}', 'Comienza en una posición de plancha alta con las manos un poco más separadas que la anchura de los hombros y los pies juntos. Activa el core y baja el cuerpo hacia el suelo, manteniendo los codos cerca de los costados. Mientras bajas el cuerpo, levanta simultáneamente el brazo derecho y la pierna izquierda del suelo, extendiéndolos completamente. Haz una pausa de un momento en la parte superior, luego baja el brazo y la pierna mientras te empujas de nuevo hacia arriba a la posición inicial. Repite el movimiento, esta vez levantando el brazo izquierdo y la pierna derecha. Continúa alternando lados durante el número de repeticiones deseado.', 'Start in a high plank position with your hands slightly wider than shoulder-width apart and your feet together. Engage your core and lower your body towards the ground, keeping your elbows close to your sides. As you lower your body, simultaneously lift your right arm and left leg off the ground, extending them straight out. Pause for a moment at the top, then lower your arm and leg back down while pushing yourself back up to the starting position. Repeat the movement, this time lifting your left arm and right leg. Continue alternating sides for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0803-4GqRrAk.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0803-4GqRrAk.gif', '4GqRrAk', '© Gym visual — https://gymvisual.com/'),
('0805', 'suspended abdominal fallout', 'Sujeta un entrenador de suspensión a un punto de anclaje alto y ajusta las correas a la altura de la cintura. Ponte de pie de espaldas al punto de anclaje y sostén las asas con los brazos extendidos frente a ti. Inclínate hacia adelante desde la cintura, manteniendo el cuerpo recto y el core activad', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"obliques","hip flexors"}', 'Sujeta un entrenador de suspensión a un punto de anclaje alto y ajusta las correas a la altura de la cintura. Ponte de pie de espaldas al punto de anclaje y sostén las asas con los brazos extendidos frente a ti. Inclínate hacia adelante desde la cintura, manteniendo el cuerpo recto y el core activado. Baja el cuerpo todo lo que puedas mientras mantienes el control y la tensión en el abdomen. Haz una pausa de un momento en la parte baja, luego eleva lentamente el cuerpo de nuevo a la posición inicial. Repite el número de repeticiones deseado.', 'Attach a suspension trainer to a high anchor point and adjust the straps to waist height. Stand facing away from the anchor point and hold the handles with your arms extended in front of you. Lean forward at the waist, keeping your body straight and your core engaged. Lower your body as far as you can while maintaining control and tension in your abs. Pause for a moment at the bottom, then slowly raise your body back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0805-X3TCNEU.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0805-X3TCNEU.gif', 'X3TCNEU', '© Gym visual — https://gymvisual.com/'),
('0806', 'suspended push-up', 'Busca un entrenador de suspensión y ajústalo a una altura adecuada. Ponte de pie de espaldas al punto de anclaje y sostén las asas con un agarre prono. Camina hacia adelante con los pies, inclinando el cuerpo hacia adelante hasta que tu peso quede sostenido por el entrenador de suspensión. Mantén el', 'chest', 'body weight', 'chest', 'chest', 'pectorals', '{"triceps","shoulders","core"}', 'Busca un entrenador de suspensión y ajústalo a una altura adecuada. Ponte de pie de espaldas al punto de anclaje y sostén las asas con un agarre prono. Camina hacia adelante con los pies, inclinando el cuerpo hacia adelante hasta que tu peso quede sostenido por el entrenador de suspensión. Mantén el cuerpo recto desde la cabeza hasta los talones, activa el core y baja el pecho hacia las asas. Empuja con el pecho y los brazos para volver a la posición inicial. Repite el número de repeticiones deseado.', 'Find a suspension trainer and adjust it to an appropriate height. Stand facing away from the anchor point and hold the handles with an overhand grip. Walk your feet forward, leaning your body forward until your weight is supported by the suspension trainer. Keep your body straight from head to heels, engage your core, and lower your chest towards the handles. Push through your chest and arms to return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0806-IaGQCrC.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0806-IaGQCrC.gif', 'IaGQCrC', '© Gym visual — https://gymvisual.com/'),
('0807', 'suspended reverse crunch', 'Cuélgate de una barra de dominadas con los brazos completamente extendidos y las palmas mirando hacia afuera. Activa el core y sube las rodillas hacia el pecho, curvando la pelvis hacia la caja torácica. Haz una pausa de un momento en la parte superior, luego baja lentamente las rodillas de nuevo a ', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"hip flexors"}', 'Cuélgate de una barra de dominadas con los brazos completamente extendidos y las palmas mirando hacia afuera. Activa el core y sube las rodillas hacia el pecho, curvando la pelvis hacia la caja torácica. Haz una pausa de un momento en la parte superior, luego baja lentamente las rodillas de nuevo a la posición inicial. Repite el número de repeticiones deseado.', 'Hang from a pull-up bar with your arms fully extended and your palms facing away from you. Engage your core and lift your knees up towards your chest, curling your pelvis towards your ribcage. Pause for a moment at the top, then slowly lower your knees back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0807-R1WYG5D.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0807-R1WYG5D.gif', 'R1WYG5D', '© Gym visual — https://gymvisual.com/'),
('0808', 'suspended row', 'Coloca un entrenador de suspensión a una altura adecuada. Ponte de pie frente al punto de anclaje con los pies separados a la altura de los hombros. Sostén las asas con un agarre prono, con las palmas mirándose entre sí. Inclínate hacia atrás, manteniendo el cuerpo recto y los talones en el suelo. T', 'back', 'body weight', 'back', 'back', 'upper back', '{"biceps","shoulders"}', 'Coloca un entrenador de suspensión a una altura adecuada. Ponte de pie frente al punto de anclaje con los pies separados a la altura de los hombros. Sostén las asas con un agarre prono, con las palmas mirándose entre sí. Inclínate hacia atrás, manteniendo el cuerpo recto y los talones en el suelo. Tira del pecho hacia las asas, apretando los omóplatos entre sí. Haz una pausa breve en la parte más alta, luego baja lentamente de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Set up a suspension trainer at an appropriate height. Stand facing the anchor point with your feet shoulder-width apart. Hold the handles with an overhand grip, palms facing each other. Lean back, keeping your body straight and your heels on the ground. Pull your chest towards the handles, squeezing your shoulder blades together. Pause for a moment at the top, then slowly lower yourself back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0808-4OaumBr.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0808-4OaumBr.gif', '4OaumBr', '© Gym visual — https://gymvisual.com/'),
('0809', 'suspended split squat', 'Ponte de pie de espaldas a un entrenador de suspensión con los pies separados a la altura de los hombros. Extiende una pierna hacia adelante y coloca el empeine del pie en el soporte para pie del entrenador de suspensión. Flexiona la pierna de apoyo y baja el cuerpo a una posición de zancada, manten', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'quads', '{"glutes","hamstrings","calves"}', 'Ponte de pie de espaldas a un entrenador de suspensión con los pies separados a la altura de los hombros. Extiende una pierna hacia adelante y coloca el empeine del pie en el soporte para pie del entrenador de suspensión. Flexiona la pierna de apoyo y baja el cuerpo a una posición de zancada, manteniendo el pecho elevado y la rodilla alineada con la punta del pie. Empuja con el talón para regresar a la posición inicial. Repite el número de repeticiones deseado, luego cambia de pierna.', 'Stand facing away from a suspension trainer with your feet shoulder-width apart. Extend one leg forward and place the top of your foot in the foot cradle of the suspension trainer. Bend your standing leg and lower your body down into a lunge position, keeping your chest up and your knee in line with your toes. Push through your heel to return to the starting position. Repeat for the desired number of repetitions, then switch legs.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0809-QpXqiq8.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0809-QpXqiq8.gif', 'QpXqiq8', '© Gym visual — https://gymvisual.com/'),
('3433', 'swimmer kicks v. 2 (male)', 'Túmbate boca abajo sobre una esterilla con los brazos extendidos por encima de la cabeza. Activa el core y levanta el pecho y las piernas del suelo al mismo tiempo. Mueve las piernas hacia arriba y hacia abajo con un movimiento de aleteo, como si estuvieras nadando. Continúa el movimiento de patada ', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'glutes', '{"hamstrings","quadriceps","calves"}', 'Túmbate boca abajo sobre una esterilla con los brazos extendidos por encima de la cabeza. Activa el core y levanta el pecho y las piernas del suelo al mismo tiempo. Mueve las piernas hacia arriba y hacia abajo con un movimiento de aleteo, como si estuvieras nadando. Continúa el movimiento de patada el número de repeticiones deseado. Baja el pecho y las piernas de nuevo a la posición inicial.', 'Lie face down on a mat with your arms extended overhead. Engage your core and lift your chest and legs off the ground simultaneously. Kick your legs up and down in a fluttering motion, as if you were swimming. Continue kicking for the desired number of repetitions. Lower your chest and legs back down to the starting position.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3433-SP3hUez.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3433-SP3hUez.gif', 'SP3hUez', '© Gym visual — https://gymvisual.com/'),
('3318', 'swing 360', 'Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Mantén los brazos extendidos rectos frente a ti, paralelos al suelo. Activa el core y mueve los brazos en un movimiento circular, rotando el torso mientras lo haces. Continúa el movimiento circular', 'cardio', 'body weight', 'cardio', 'cardio', 'cardiovascular system', '{"shoulders","core"}', 'Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Mantén los brazos extendidos rectos frente a ti, paralelos al suelo. Activa el core y mueve los brazos en un movimiento circular, rotando el torso mientras lo haces. Continúa el movimiento circular, moviendo los brazos y rotando el torso el número de repeticiones deseado. Recuerda respirar durante todo el ejercicio.', 'Stand with your feet shoulder-width apart and knees slightly bent. Hold your arms straight out in front of you, parallel to the ground. Engage your core and swing your arms in a circular motion, rotating your torso as you do so. Continue the circular motion, swinging your arms and rotating your torso for the desired number of repetitions. Remember to breathe throughout the exercise.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3318-tnaj0mT.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3318-tnaj0mT.gif', 'tnaj0mT', '© Gym visual — https://gymvisual.com/'),
('1753', 'three bench dip', 'Siéntate en un banco con las manos agarrando el borde, los dedos apuntando hacia adelante. Desliza los glúteos fuera del banco, sosteniendo tu peso con las manos. Flexiona los codos y baja el cuerpo hasta que la parte superior de los brazos quede paralela al suelo. Empújate de vuelta hacia arriba ha', 'upper arms', 'body weight', 'upper arms', 'upper arms', 'triceps', '{"chest","shoulders"}', 'Siéntate en un banco con las manos agarrando el borde, los dedos apuntando hacia adelante. Desliza los glúteos fuera del banco, sosteniendo tu peso con las manos. Flexiona los codos y baja el cuerpo hasta que la parte superior de los brazos quede paralela al suelo. Empújate de vuelta hacia arriba hasta la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a bench with your hands gripping the edge, fingers pointing forward. Slide your butt off the bench, supporting your weight with your hands. Bend your elbows and lower your body until your upper arms are parallel to the ground. Push yourself back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1753-DQ0cqkT.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1753-DQ0cqkT.gif', 'DQ0cqkT', '© Gym visual — https://gymvisual.com/'),
('2459', 'tire flip', 'Ponte de pie con los pies separados a la altura de los hombros, de frente al neumático. Flexiona las rodillas y dobla las caderas, bajando a una posición de sentadilla. Agáchate y agarra el borde inferior del neumático con ambas manos, con los dedos apuntando hacia ti. Activa los glúteos y los múscu', 'upper legs', 'tire', 'upper legs', 'upper legs', 'glutes', '{"hamstrings","quadriceps","core"}', 'Ponte de pie con los pies separados a la altura de los hombros, de frente al neumático. Flexiona las rodillas y dobla las caderas, bajando a una posición de sentadilla. Agáchate y agarra el borde inferior del neumático con ambas manos, con los dedos apuntando hacia ti. Activa los glúteos y los músculos de las piernas, y empuja con fuerza a través de las piernas para levantar el neumático del suelo. Mientras el neumático se voltea, usa la fuerza de la parte superior del cuerpo para guiarlo y mantener el control. Una vez que el neumático esté completamente volteado, retrocede rápidamente y reinicia tu postura. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, facing the tire. Bend your knees and hinge at the hips, lowering into a squat position. Reach down and grab the bottom edge of the tire with both hands, fingers facing towards you. Engage your glutes and leg muscles, and explosively drive through your legs to lift the tire off the ground. As the tire flips over, use your upper body strength to guide it and maintain control. Once the tire is fully flipped, quickly step back and reset your stance. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2459-oZjMu1t.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2459-oZjMu1t.gif', 'oZjMu1t', '© Gym visual — https://gymvisual.com/'),
('0811', 'trap bar deadlift', 'Ponte de pie con los pies separados a la altura de los hombros y la barra hexagonal en el suelo frente a ti. Flexiona las caderas y las rodillas para bajar y agarra las asas de la barra hexagonal con un agarre prono. Mantén la espalda recta y el pecho elevado mientras comienzas a levantar la barra h', 'upper legs', 'trap bar', 'upper legs', 'upper legs', 'glutes', '{"hamstrings","quadriceps","lower back"}', 'Ponte de pie con los pies separados a la altura de los hombros y la barra hexagonal en el suelo frente a ti. Flexiona las caderas y las rodillas para bajar y agarra las asas de la barra hexagonal con un agarre prono. Mantén la espalda recta y el pecho elevado mientras comienzas a levantar la barra hexagonal del suelo extendiendo las caderas y las rodillas. Al levantar, concéntrate en empujar con los talones y contraer los glúteos en la parte superior del movimiento. Baja la barra hexagonal de nuevo al suelo flexionando las caderas y las rodillas, manteniendo la espalda recta durante todo el movimiento. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and the trap bar on the ground in front of you. Bend at the hips and knees to lower yourself down and grip the handles of the trap bar with an overhand grip. Keep your back straight and chest up as you begin to lift the trap bar off the ground by extending your hips and knees. As you lift, focus on driving through your heels and squeezing your glutes at the top of the movement. Lower the trap bar back down to the ground by bending at the hips and knees, keeping your back straight throughout the movement. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0811-jQGwmxN.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0811-jQGwmxN.gif', 'jQGwmxN', '© Gym visual — https://gymvisual.com/'),
('0814', 'triceps dip', 'Siéntate en el borde de un banco o silla con las manos sujetando el borde, los dedos apuntando hacia adelante. Desliza los glúteos fuera del banco, sosteniendo tu peso con las manos. Flexiona los codos y baja el cuerpo hacia el suelo, manteniendo la espalda cerca del banco. Haz una pausa por un mome', 'upper arms', 'body weight', 'upper arms', 'upper arms', 'triceps', '{"chest","shoulders"}', 'Siéntate en el borde de un banco o silla con las manos sujetando el borde, los dedos apuntando hacia adelante. Desliza los glúteos fuera del banco, sosteniendo tu peso con las manos. Flexiona los codos y baja el cuerpo hacia el suelo, manteniendo la espalda cerca del banco. Haz una pausa por un momento en la parte inferior, luego empuja tu cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on the edge of a bench or chair with your hands gripping the edge, fingers pointing forward. Slide your butt off the bench, supporting your weight with your hands. Bend your elbows and lower your body towards the ground, keeping your back close to the bench. Pause for a moment at the bottom, then push yourself back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0814-X6C6i5Y.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0814-X6C6i5Y.gif', 'X6C6i5Y', '© Gym visual — https://gymvisual.com/'),
('0812', 'triceps dip (bench leg)', 'Siéntate en el borde de un banco con las manos agarrando el borde, los dedos apuntando hacia adelante. Camina con los pies hacia adelante, deslizando los glúteos fuera del banco, y estira los brazos. Flexiona los codos y baja el cuerpo hacia el suelo, manteniendo la espalda cerca del banco. Empuja c', 'upper arms', 'body weight', 'upper arms', 'upper arms', 'triceps', '{"chest","shoulders"}', 'Siéntate en el borde de un banco con las manos agarrando el borde, los dedos apuntando hacia adelante. Camina con los pies hacia adelante, deslizando los glúteos fuera del banco, y estira los brazos. Flexiona los codos y baja el cuerpo hacia el suelo, manteniendo la espalda cerca del banco. Empuja con las palmas para estirar los brazos y regresar a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on the edge of a bench with your hands gripping the edge, fingers pointing forward. Walk your feet forward, sliding your butt off the bench, and straighten your arms. Bend your elbows and lower your body towards the ground, keeping your back close to the bench. Push through your palms to straighten your arms and return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0812-VuoerH0.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0812-VuoerH0.gif', 'VuoerH0', '© Gym visual — https://gymvisual.com/'),
('0813', 'triceps dip (between benches)', 'Siéntate en un banco con las manos agarrando el borde del banco, los dedos apuntando hacia adelante. Desliza los glúteos fuera del banco, sosteniendo tu peso con las manos. Flexiona los codos y baja el cuerpo hacia el suelo, manteniendo la espalda cerca del banco. Haz una pausa por un momento en la ', 'upper arms', 'body weight', 'upper arms', 'upper arms', 'triceps', '{"chest","shoulders"}', 'Siéntate en un banco con las manos agarrando el borde del banco, los dedos apuntando hacia adelante. Desliza los glúteos fuera del banco, sosteniendo tu peso con las manos. Flexiona los codos y baja el cuerpo hacia el suelo, manteniendo la espalda cerca del banco. Haz una pausa por un momento en la parte inferior, luego empuja tu cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a bench with your hands gripping the edge of the bench, fingers pointing forward. Slide your butt off the bench, supporting your weight with your hands. Bend your elbows and lower your body towards the ground, keeping your back close to the bench. Pause for a moment at the bottom, then push yourself back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0813-Wgbn9qo.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0813-Wgbn9qo.gif', 'Wgbn9qo', '© Gym visual — https://gymvisual.com/'),
('0815', 'triceps dips floor', 'Siéntate en el borde de una silla o banco con las manos junto a las caderas, los dedos apuntando hacia adelante. Desliza los glúteos fuera del frente de la silla con las piernas extendidas frente a ti. Estira los brazos, manteniendo una ligera flexión en los codos para conservar la tensión en los tr', 'upper arms', 'body weight', 'upper arms', 'upper arms', 'triceps', '{"chest","shoulders"}', 'Siéntate en el borde de una silla o banco con las manos junto a las caderas, los dedos apuntando hacia adelante. Desliza los glúteos fuera del frente de la silla con las piernas extendidas frente a ti. Estira los brazos, manteniendo una ligera flexión en los codos para conservar la tensión en los tríceps y aliviarla en las articulaciones del codo. Flexiona lentamente los codos para bajar el cuerpo hacia el suelo hasta que los codos formen un ángulo de aproximadamente 90 grados. Cuando llegues al punto más bajo del movimiento, empuja hacia abajo contra la silla para estirar los codos, volviendo a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on the edge of a chair or bench with your hands next to your hips, fingers pointing forward. Slide your butt off the front of the chair with your legs extended in front of you. Straighten your arms, keeping a little bend in your elbows to keep tension on your triceps and off your elbow joints. Slowly bend your elbows to lower your body toward the floor until your elbows are at about a 90-degree angle. Once you reach the bottom of the movement, press down into the chair to straighten your elbows, returning to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0815-7aVz15j.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0815-7aVz15j.gif', '7aVz15j', '© Gym visual — https://gymvisual.com/'),
('0816', 'triceps press', 'Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Extiende los brazos rectos frente a ti, paralelos al suelo. Flexiona los codos y baja el cuerpo hacia el suelo, manteniendo la parte superior de los brazos cerca de los costados. Haz una pausa por ', 'upper arms', 'body weight', 'upper arms', 'upper arms', 'triceps', '{"shoulders"}', 'Ponte de pie con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas. Extiende los brazos rectos frente a ti, paralelos al suelo. Flexiona los codos y baja el cuerpo hacia el suelo, manteniendo la parte superior de los brazos cerca de los costados. Haz una pausa por un momento en la parte inferior, luego empuja tu cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and your knees slightly bent. Extend your arms straight out in front of you, parallel to the ground. Bend your elbows and lower your body towards the ground, keeping your upper arms close to your sides. Pause for a moment at the bottom, then push yourself back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0816-fSrPP6B.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0816-fSrPP6B.gif', 'fSrPP6B', '© Gym visual — https://gymvisual.com/'),
('0817', 'triceps stretch', 'Ponte de pie o siéntate erguido con la espalda recta. Extiende un brazo por encima de la cabeza, flexionándolo por el codo. Coloca la mano opuesta sobre el codo flexionado y tira de él suavemente hacia tu cabeza. Mantén el estiramiento de 15 a 30 segundos, sintiendo un estiramiento suave en el tríce', 'upper arms', 'body weight', 'upper arms', 'upper arms', 'triceps', '{"shoulders"}', 'Ponte de pie o siéntate erguido con la espalda recta. Extiende un brazo por encima de la cabeza, flexionándolo por el codo. Coloca la mano opuesta sobre el codo flexionado y tira de él suavemente hacia tu cabeza. Mantén el estiramiento de 15 a 30 segundos, sintiendo un estiramiento suave en el tríceps. Suelta el estiramiento y repite con el otro brazo.', 'Stand or sit upright with your back straight. Extend one arm overhead, bending it at the elbow. Place your opposite hand on the bent elbow and gently pull it towards your head. Hold the stretch for 15-30 seconds, feeling a gentle stretch in your triceps. Release the stretch and repeat on the other arm.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0817-uOV3Itw.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0817-uOV3Itw.gif', 'uOV3Itw', '© Gym visual — https://gymvisual.com/'),
('0871', 'tuck crunch', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Coloca las manos detrás de la cabeza con los codos apuntando hacia afuera. Activando el abdomen, levanta los omóplatos del suelo y lleva las rodillas hacia el pecho, curvando al mismo tiempo la parte superior del ', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"hip flexors"}', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Coloca las manos detrás de la cabeza con los codos apuntando hacia afuera. Activando el abdomen, levanta los omóplatos del suelo y lleva las rodillas hacia el pecho, curvando al mismo tiempo la parte superior del cuerpo hacia las rodillas. Haz una pausa de un momento en la parte superior, luego baja lentamente los omóplatos y extiende las piernas de nuevo a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on your back with your knees bent and feet flat on the ground. Place your hands behind your head with your elbows pointing outwards. Engaging your abs, lift your shoulder blades off the ground and bring your knees towards your chest, simultaneously curling your upper body towards your knees. Pause for a moment at the top, then slowly lower your shoulder blades and extend your legs back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0871-BMMolZ3.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0871-BMMolZ3.gif', 'BMMolZ3', '© Gym visual — https://gymvisual.com/'),
('0818', 'twin handle parallel grip lat pulldown', 'Ajusta la altura del asiento y colócate de frente a la máquina de cable. Agarra las asas con un agarre prono, con las manos separadas a la altura de los hombros. Siéntate y coloca los muslos debajo de las almohadillas para muslos, manteniendo los pies planos sobre el suelo. Inclínate ligeramente hac', 'back', 'cable', 'back', 'back', 'lats', '{"biceps","rhomboids","rear deltoids"}', 'Ajusta la altura del asiento y colócate de frente a la máquina de cable. Agarra las asas con un agarre prono, con las manos separadas a la altura de los hombros. Siéntate y coloca los muslos debajo de las almohadillas para muslos, manteniendo los pies planos sobre el suelo. Inclínate ligeramente hacia atrás y mantén el pecho elevado, conservando una columna neutral. Tira de las asas hacia la parte superior del pecho, apretando los omóplatos entre sí. Haz una pausa por un momento en la parte inferior del movimiento, sintiendo la contracción en los dorsales. Suelta lentamente las asas y vuelve a la posición inicial. Repite el número de repeticiones deseado.', 'Adjust the seat height and position yourself facing the cable machine. Grasp the handles with an overhand grip, hands shoulder-width apart. Sit down and position your thighs under the thigh pads, keeping your feet flat on the floor. Lean back slightly and keep your chest up, maintaining a neutral spine. Pull the handles down towards your upper chest, squeezing your shoulder blades together. Pause for a moment at the bottom of the movement, feeling the contraction in your lats. Slowly release the handles and return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0818-rkg41Fb.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0818-rkg41Fb.gif', 'rkg41Fb', '© Gym visual — https://gymvisual.com/'),
('1466', 'twist hip lift', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Coloca las manos a los lados para mayor apoyo. Activa los glúteos y levanta las caderas del suelo, formando una línea recta desde las rodillas hasta los hombros. Manteniendo las caderas elevadas, gira la parte inf', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'glutes', '{"obliques","hamstrings"}', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Coloca las manos a los lados para mayor apoyo. Activa los glúteos y levanta las caderas del suelo, formando una línea recta desde las rodillas hasta los hombros. Manteniendo las caderas elevadas, gira la parte inferior del cuerpo hacia el lado derecho, llevando las rodillas hacia el suelo. Vuelve a la posición inicial y repite el giro hacia el lado izquierdo. Continúa alternando los giros el número de repeticiones deseado.', 'Lie on your back with your knees bent and feet flat on the ground. Place your hands by your sides for support. Engage your glutes and lift your hips off the ground, forming a straight line from your knees to your shoulders. While keeping your hips lifted, twist your lower body to the right side, bringing your knees towards the ground. Return to the starting position and repeat the twist to the left side. Continue alternating twists for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1466-AX1kB0o.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1466-AX1kB0o.gif', 'AX1kB0o', '© Gym visual — https://gymvisual.com/'),
('2802', 'twisted leg raise', 'Túmbate sobre tu espalda con las piernas extendidas y los brazos a los lados. Coloca las manos debajo de los glúteos como apoyo. Activa el abdomen y levanta ambas piernas del suelo, manteniéndolas rectas. Mientras levantas las piernas, gira las caderas hacia un lado, llevando las piernas hacia el ho', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"obliques","hip flexors"}', 'Túmbate sobre tu espalda con las piernas extendidas y los brazos a los lados. Coloca las manos debajo de los glúteos como apoyo. Activa el abdomen y levanta ambas piernas del suelo, manteniéndolas rectas. Mientras levantas las piernas, gira las caderas hacia un lado, llevando las piernas hacia el hombro opuesto. Haz una pausa por un momento en la parte superior, luego baja lentamente las piernas de vuelta a la posición inicial. Repite el movimiento, esta vez girando las caderas hacia el otro lado. Continúa alternando lados durante el número de repeticiones deseado.', 'Lie flat on your back with your legs extended and your arms by your sides. Place your hands under your glutes for support. Engage your abs and lift both legs off the ground, keeping them straight. As you lift your legs, twist your hips to one side, bringing your legs towards your opposite shoulder. Pause for a moment at the top, then slowly lower your legs back down to the starting position. Repeat the movement, this time twisting your hips to the other side. Continue alternating sides for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2802-C0eCeEt.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2802-C0eCeEt.gif', 'C0eCeEt', '© Gym visual — https://gymvisual.com/'),
('2801', 'twisted leg raise (female)', 'Túmbate sobre tu espalda con las piernas extendidas y los brazos a los lados. Flexiona las rodillas y levanta las piernas del suelo, llevándolas hacia el pecho. Mientras levantas las piernas, gira las caderas hacia un lado, llevando las rodillas hacia el hombro opuesto. Haz una pausa por un momento ', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"obliques","hip flexors"}', 'Túmbate sobre tu espalda con las piernas extendidas y los brazos a los lados. Flexiona las rodillas y levanta las piernas del suelo, llevándolas hacia el pecho. Mientras levantas las piernas, gira las caderas hacia un lado, llevando las rodillas hacia el hombro opuesto. Haz una pausa por un momento en la parte superior, luego baja lentamente las piernas de vuelta a la posición inicial. Repite el movimiento, esta vez girando las caderas hacia el otro lado. Continúa alternando lados durante el número de repeticiones deseado.', 'Lie flat on your back with your legs extended and your arms by your sides. Bend your knees and lift your legs off the ground, bringing them towards your chest. As you lift your legs, twist your hips to one side, bringing your knees towards your opposite shoulder. Pause for a moment at the top, then slowly lower your legs back down to the starting position. Repeat the movement, this time twisting your hips to the other side. Continue alternating sides for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2801-yT9tk17.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2801-yT9tk17.gif', 'yT9tk17', '© Gym visual — https://gymvisual.com/'),
('3231', 'two toe touch (male)', 'Ponte de pie con los pies separados a la altura de los hombros y los brazos extendidos hacia los lados. Inclínate hacia adelante desde la cintura, manteniendo la espalda recta y las rodillas ligeramente flexionadas. Estira los brazos hacia la punta de los pies con ambas manos, manteniendo las pierna', 'back', 'body weight', 'back', 'back', 'spine', '{"hamstrings","glutes"}', 'Ponte de pie con los pies separados a la altura de los hombros y los brazos extendidos hacia los lados. Inclínate hacia adelante desde la cintura, manteniendo la espalda recta y las rodillas ligeramente flexionadas. Estira los brazos hacia la punta de los pies con ambas manos, manteniendo las piernas rectas. Haz una pausa por un momento en la parte inferior, luego regresa lentamente a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and your arms extended out to the sides. Bend forward at the waist, keeping your back straight and your knees slightly bent. Reach down towards your toes with both hands, keeping your legs straight. Pause for a moment at the bottom, then slowly return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3231-p195zsJ.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3231-p195zsJ.gif', 'p195zsJ', '© Gym visual — https://gymvisual.com/'),
('1365', 'upper back stretch', 'Ponte de pie con la espalda recta y los pies separados a la altura de los hombros. Extiende los brazos rectos frente a ti, paralelos al suelo. Entrelaza los dedos y gira las palmas alejándolas de tu cuerpo. Eleva lentamente los brazos por encima de la cabeza, manteniéndolos rectos y paralelos entre ', 'back', 'body weight', 'back', 'back', 'upper back', '{"shoulders"}', 'Ponte de pie con la espalda recta y los pies separados a la altura de los hombros. Extiende los brazos rectos frente a ti, paralelos al suelo. Entrelaza los dedos y gira las palmas alejándolas de tu cuerpo. Eleva lentamente los brazos por encima de la cabeza, manteniéndolos rectos y paralelos entre sí. Mientras elevas los brazos, aprieta los omóplatos entre sí. Mantén el estiramiento de 15 a 30 segundos, luego suelta y repite.', 'Stand up straight with your feet shoulder-width apart. Extend your arms straight in front of you, parallel to the ground. Interlace your fingers and rotate your palms away from your body. Slowly raise your arms overhead, keeping them straight and parallel to each other. As you raise your arms, squeeze your shoulder blades together. Hold the stretch for 15-30 seconds, then release and repeat.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1365-GSDioYu.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1365-GSDioYu.gif', 'GSDioYu', '© Gym visual — https://gymvisual.com/'),
('1366', 'upward facing dog', 'Túmbate boca abajo en el suelo con las piernas extendidas detrás de ti. Coloca las manos en el suelo junto a las costillas inferiores, con los dedos apuntando hacia adelante. Presiona las manos firmemente contra el suelo y estira los brazos, levantando el torso y los muslos del suelo. Lleva los homb', 'back', 'body weight', 'back', 'back', 'spine', '{"shoulders","chest"}', 'Túmbate boca abajo en el suelo con las piernas extendidas detrás de ti. Coloca las manos en el suelo junto a las costillas inferiores, con los dedos apuntando hacia adelante. Presiona las manos firmemente contra el suelo y estira los brazos, levantando el torso y los muslos del suelo. Lleva los hombros hacia atrás y hacia abajo, abriendo el pecho y elevando la mirada hacia el techo. Mantén esta posición durante unas cuantas respiraciones, luego baja lentamente el cuerpo de nuevo a la posición inicial. Repite el número de repeticiones deseado.', 'Lie face down on the floor with your legs extended behind you. Place your hands on the floor next to your lower ribs, fingers pointing forward. Press your hands firmly into the floor and straighten your arms, lifting your torso and thighs off the ground. Roll your shoulders back and down, opening your chest and lifting your gaze towards the ceiling. Hold this position for a few breaths, then slowly lower your body back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1366-01qpYSe.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1366-01qpYSe.gif', '01qpYSe', '© Gym visual — https://gymvisual.com/'),
('3420', 'v-sit on floor', 'Siéntate en el suelo con las piernas extendidas frente a ti. Inclínate ligeramente hacia atrás y levanta las piernas del suelo, manteniéndolas rectas. Al mismo tiempo, levanta la parte superior del cuerpo del suelo y extiende los brazos hacia las piernas. Mantén esta posición durante unos segundos, ', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"hip flexors"}', 'Siéntate en el suelo con las piernas extendidas frente a ti. Inclínate ligeramente hacia atrás y levanta las piernas del suelo, manteniéndolas rectas. Al mismo tiempo, levanta la parte superior del cuerpo del suelo y extiende los brazos hacia las piernas. Mantén esta posición durante unos segundos, luego baja lentamente la parte superior del cuerpo y las piernas de nuevo a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on the floor with your legs extended in front of you. Lean back slightly and lift your legs off the ground, keeping them straight. Simultaneously, lift your upper body off the ground and reach your arms towards your legs. Hold this position for a few seconds, then slowly lower your upper body and legs back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3420-ZuXu4Eq.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3420-ZuXu4Eq.gif', 'ZuXu4Eq', '© Gym visual — https://gymvisual.com/'),
('0826', 'vertical leg raise (on parallel bars)', 'Cuélgate de las barras paralelas con los brazos completamente extendidos y el cuerpo recto. Activa el core y levanta las piernas frente a ti, manteniéndolas rectas. Continúa levantando hasta que las piernas queden paralelas al suelo o un poco más arriba. Haz una pausa por un momento en la parte supe', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"hip flexors"}', 'Cuélgate de las barras paralelas con los brazos completamente extendidos y el cuerpo recto. Activa el core y levanta las piernas frente a ti, manteniéndolas rectas. Continúa levantando hasta que las piernas queden paralelas al suelo o un poco más arriba. Haz una pausa por un momento en la parte superior, luego baja lentamente las piernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Hang from the parallel bars with your arms fully extended and your body straight. Engage your core and lift your legs up in front of you, keeping them straight. Continue lifting until your legs are parallel to the ground or slightly higher. Pause for a moment at the top, then slowly lower your legs back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0826-ZNgOYQU.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0826-ZNgOYQU.gif', 'ZNgOYQU', '© Gym visual — https://gymvisual.com/'),
('2141', 'walk elliptical cross trainer', 'Ajusta el nivel de resistencia y la inclinación de la máquina elíptica a los valores deseados. Sube a los pedales de la máquina y agarra las asas con suavidad. Comienza empujando hacia abajo con los pies y tirando de las asas hacia tu cuerpo. Continúa con este movimiento, alternando entre empujar y ', 'cardio', 'elliptical machine', 'cardio', 'cardio', 'cardiovascular system', '{"quadriceps","hamstrings","glutes","calves"}', 'Ajusta el nivel de resistencia y la inclinación de la máquina elíptica a los valores deseados. Sube a los pedales de la máquina y agarra las asas con suavidad. Comienza empujando hacia abajo con los pies y tirando de las asas hacia tu cuerpo. Continúa con este movimiento, alternando entre empujar y tirar, para simular un movimiento de caminar o correr. Mantén un ritmo constante y conserva el core activado durante todo el ejercicio. Continúa durante la duración deseada de tu entrenamiento cardiovascular. Disminuye gradualmente la intensidad y la velocidad de la máquina antes de bajarte.', 'Adjust the resistance level and incline of the elliptical machine to your desired settings. Step onto the pedals of the machine and grip the handles lightly. Begin by pushing down with your feet and pulling the handles towards your body. Continue this motion, alternating between pushing and pulling, to simulate a walking or running motion. Maintain a steady pace and keep your core engaged throughout the exercise. Continue for the desired duration of your cardio workout. Gradually decrease the intensity and speed of the machine before stepping off.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2141-rjtuP6X.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2141-rjtuP6X.gif', 'rjtuP6X', '© Gym visual — https://gymvisual.com/'),
('3655', 'walking high knees lunge', 'Ponte de pie con los pies separados a la altura de la cadera. Levanta la rodilla derecha hacia el pecho lo más alto que puedas mientras mantienes el equilibrio sobre la pierna izquierda. Da un paso adelante con el pie derecho y baja el cuerpo a una posición de zancada, flexionando ambas rodillas a u', 'cardio', 'body weight', 'cardio', 'cardio', 'cardiovascular system', '{"quadriceps","hamstrings","glutes","calves"}', 'Ponte de pie con los pies separados a la altura de la cadera. Levanta la rodilla derecha hacia el pecho lo más alto que puedas mientras mantienes el equilibrio sobre la pierna izquierda. Da un paso adelante con el pie derecho y baja el cuerpo a una posición de zancada, flexionando ambas rodillas a un ángulo de 90 grados. Empújate con el pie derecho y lleva la rodilla izquierda hacia el pecho. Da un paso adelante con el pie izquierdo y baja el cuerpo a una posición de zancada. Continúa alternando las piernas y avanzando con zancadas, manteniendo el core activado y un ritmo constante. Repite el número de repeticiones deseado.', 'Stand with your feet hip-width apart. Lift your right knee up towards your chest as high as you can while balancing on your left leg. Step forward with your right foot and lower your body into a lunge position, bending both knees to a 90-degree angle. Push off with your right foot and bring your left knee up towards your chest. Step forward with your left foot and lower your body into a lunge position. Continue alternating legs and lunging forward, keeping your core engaged and maintaining a steady pace. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3655-J9zIWig.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3655-J9zIWig.gif', 'J9zIWig', '© Gym visual — https://gymvisual.com/'),
('1460', 'walking lunge', 'Ponte de pie con los pies separados a la altura de los hombros. Da un paso adelante con la pierna derecha, bajando el cuerpo a una posición de zancada. Mantén el torso erguido y la rodilla delantera alineada con el tobillo. Empújate con el pie derecho y lleva el pie izquierdo hacia adelante, entrand', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves"}', 'Ponte de pie con los pies separados a la altura de los hombros. Da un paso adelante con la pierna derecha, bajando el cuerpo a una posición de zancada. Mantén el torso erguido y la rodilla delantera alineada con el tobillo. Empújate con el pie derecho y lleva el pie izquierdo hacia adelante, entrando en una posición de zancada con la pierna izquierda. Continúa alternando las piernas y avanzando, manteniendo un ritmo controlado y constante. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart. Take a step forward with your right leg, lowering your body into a lunge position. Keep your torso upright and your front knee aligned with your ankle. Push off with your right foot and bring your left foot forward, stepping into a lunge position with your left leg. Continue alternating legs and walking forward, maintaining a controlled and steady pace. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1460-IZVHb27.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1460-IZVHb27.gif', 'IZVHb27', '© Gym visual — https://gymvisual.com/'),
('3666', 'walking on incline treadmill', 'Ajusta el nivel de inclinación de la cinta de correr a la intensidad deseada. Ponte de pie sobre la cinta de correr con los pies separados a la altura de los hombros. Comienza a caminar a un ritmo cómodo, asegurándote de mantener una forma correcta. Activa los músculos del core y mantén la espalda r', 'cardio', 'leverage machine', 'cardio', 'cardio', 'cardiovascular system', '{"quadriceps","hamstrings","calves"}', 'Ajusta el nivel de inclinación de la cinta de correr a la intensidad deseada. Ponte de pie sobre la cinta de correr con los pies separados a la altura de los hombros. Comienza a caminar a un ritmo cómodo, asegurándote de mantener una forma correcta. Activa los músculos del core y mantén la espalda recta durante todo el ejercicio. Continúa caminando en la cinta inclinada durante la duración deseada de tu entrenamiento cardiovascular. Disminuye gradualmente la inclinación y la velocidad de la cinta para enfriar antes de detenerte.', 'Adjust the incline level on the treadmill to your desired intensity. Stand on the treadmill with your feet shoulder-width apart. Start walking at a comfortable pace, ensuring that you maintain proper form. Engage your core muscles and keep your back straight throughout the exercise. Continue walking on the incline treadmill for the desired duration of your cardio workout. Gradually decrease the incline and speed of the treadmill to cool down before stopping.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3666-rjiM4L3.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3666-rjiM4L3.gif', 'rjiM4L3', '© Gym visual — https://gymvisual.com/'),
('2311', 'walking on stepmill', 'Ajusta la máquina de escalones a un nivel cómodo. Sube a la máquina y coloca las manos sobre los pasamanos para apoyarte. Comienza a caminar colocando un pie en un escalón y luego el otro, alternando entre las piernas. Mantén una postura erguida y activa los músculos del core. Continúa caminando dur', 'cardio', 'stepmill machine', 'cardio', 'cardio', 'cardiovascular system', '{"quadriceps","hamstrings","glutes","calves"}', 'Ajusta la máquina de escalones a un nivel cómodo. Sube a la máquina y coloca las manos sobre los pasamanos para apoyarte. Comienza a caminar colocando un pie en un escalón y luego el otro, alternando entre las piernas. Mantén una postura erguida y activa los músculos del core. Continúa caminando durante la duración o distancia deseada. Aumenta gradualmente la intensidad o la velocidad a medida que te sientas más cómodo con el ejercicio. Recuerda enfriar y estirar después de completar el ejercicio.', 'Adjust the stepmill machine to a comfortable level. Step onto the machine and place your hands on the handrails for support. Start walking by placing one foot on a step and then the other, alternating between legs. Maintain an upright posture and engage your core muscles. Continue walking for the desired duration or distance. Gradually increase the intensity or speed as you become more comfortable with the exercise. Remember to cool down and stretch after completing the exercise.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2311-j9Q5crt.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2311-j9Q5crt.gif', 'j9Q5crt', '© Gym visual — https://gymvisual.com/'),
('0830', 'weighted bench dip', 'Siéntate en un banco con las manos agarrando el borde, los dedos apuntando hacia adelante. Desliza los glúteos fuera del banco, sosteniendo tu peso con las manos. Baja el cuerpo flexionando los codos hasta que los brazos queden paralelos al suelo. Empújate de vuelta hacia arriba a la posición inicia', 'upper arms', 'weighted', 'upper arms', 'upper arms', 'triceps', '{"chest","shoulders"}', 'Siéntate en un banco con las manos agarrando el borde, los dedos apuntando hacia adelante. Desliza los glúteos fuera del banco, sosteniendo tu peso con las manos. Baja el cuerpo flexionando los codos hasta que los brazos queden paralelos al suelo. Empújate de vuelta hacia arriba a la posición inicial extendiendo los brazos. Repite el número de repeticiones deseado.', 'Sit on a bench with your hands gripping the edge, fingers pointing forward. Slide your butt off the bench, supporting your weight with your hands. Lower your body by bending your elbows until your upper arms are parallel to the floor. Push yourself back up to the starting position by straightening your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0830-MU9HnE7.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0830-MU9HnE7.gif', 'MU9HnE7', '© Gym visual — https://gymvisual.com/'),
('2987', 'weighted close grip chin-up on dip cage', 'Ponte de pie frente a la jaula de fondos y agarra las barras paralelas con un agarre supino, con las manos separadas a la altura de los hombros. Cuélgate de las barras con los brazos completamente extendidos, los pies levantados del suelo y el cuerpo recto. Activa los músculos de la espalda y tira d', 'back', 'weighted', 'back', 'back', 'lats', '{"biceps","forearms"}', 'Ponte de pie frente a la jaula de fondos y agarra las barras paralelas con un agarre supino, con las manos separadas a la altura de los hombros. Cuélgate de las barras con los brazos completamente extendidos, los pies levantados del suelo y el cuerpo recto. Activa los músculos de la espalda y tira de tu cuerpo hacia arriba en dirección a las barras, manteniendo los codos cerca de los costados. Continúa tirando hasta que tu barbilla quede por encima de las barras, luego haz una pausa de un momento. Baja lentamente el cuerpo de nuevo a la posición inicial, extendiendo completamente los brazos. Repite el número de repeticiones deseado.', 'Stand in front of the dip cage and grab the parallel bars with an underhand grip, hands shoulder-width apart. Hang from the bars with your arms fully extended, feet off the ground, and body straight. Engage your back muscles and pull your body up towards the bars, keeping your elbows close to your sides. Continue pulling until your chin is above the bars, then pause for a moment. Slowly lower your body back down to the starting position, fully extending your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2987-Gk1r408.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2987-Gk1r408.gif', 'Gk1r408', '© Gym visual — https://gymvisual.com/'),
('3643', 'weighted cossack squats (male)', 'Ponte de pie con los pies más separados que la anchura de los hombros y la punta de los pies apuntando ligeramente hacia afuera. Sostén un peso frente al pecho con ambas manos. Traslada tu peso hacia un lado y baja el cuerpo flexionando la rodilla del lado hacia el que te inclinaste, manteniendo la ', 'upper legs', 'weighted', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves"}', 'Ponte de pie con los pies más separados que la anchura de los hombros y la punta de los pies apuntando ligeramente hacia afuera. Sostén un peso frente al pecho con ambas manos. Traslada tu peso hacia un lado y baja el cuerpo flexionando la rodilla del lado hacia el que te inclinaste, manteniendo la otra pierna recta. Baja todo lo que puedas mientras mantienes el equilibrio y el pecho elevado. Empuja con el talón de la pierna flexionada para volver a la posición inicial. Repite con el otro lado, alternando entre las piernas.', 'Stand with your feet wider than shoulder-width apart and toes pointing slightly outward. Hold a weight in front of your chest with both hands. Shift your weight to one side and lower your body by bending the knee of the side you shifted towards, while keeping the other leg straight. Go as low as you can while maintaining balance and keeping your chest up. Push through the heel of the bent leg to return to the starting position. Repeat on the other side, alternating between legs.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3643-GWoKnIm.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3643-GWoKnIm.gif', 'GWoKnIm', '© Gym visual — https://gymvisual.com/'),
('0832', 'weighted crunch', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Sostén un disco de peso o una mancuerna sobre el pecho. Activa el abdomen y levanta la parte superior del cuerpo del suelo, curvándote hacia adelante hasta que los omóplatos se separen del suelo. Haz una pausa por', 'waist', 'weighted', 'waist', 'waist', 'abs', '{"obliques"}', 'Túmbate sobre tu espalda con las rodillas flexionadas y los pies apoyados en el suelo. Sostén un disco de peso o una mancuerna sobre el pecho. Activa el abdomen y levanta la parte superior del cuerpo del suelo, curvándote hacia adelante hasta que los omóplatos se separen del suelo. Haz una pausa por un momento en la parte superior, luego baja lentamente la parte superior del cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on your back with your knees bent and feet flat on the ground. Hold a weight plate or dumbbell on your chest. Engage your abs and lift your upper body off the ground, curling forward until your shoulder blades are off the ground. Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0832-s8nrDXF.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0832-s8nrDXF.gif', 's8nrDXF', '© Gym visual — https://gymvisual.com/'),
('3670', 'weighted decline sit-up', 'Túmbate boca arriba en un banco declinado con los pies sujetos debajo de las almohadillas para los pies. Coloca las manos detrás de la cabeza o cruzadas sobre el pecho. Activa el abdomen y levanta lentamente la parte superior del cuerpo del banco, curvándote hacia adelante hasta que el torso quede p', 'waist', 'weighted', 'waist', 'waist', 'abs', '{"hip flexors","lower back"}', 'Túmbate boca arriba en un banco declinado con los pies sujetos debajo de las almohadillas para los pies. Coloca las manos detrás de la cabeza o cruzadas sobre el pecho. Activa el abdomen y levanta lentamente la parte superior del cuerpo del banco, curvándote hacia adelante hasta que el torso quede perpendicular al suelo. Haz una pausa por un momento en la parte superior, luego baja lentamente la parte superior del cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Lie flat on a decline bench with your feet secured under the foot pads. Place your hands behind your head or across your chest. Engage your abs and slowly lift your upper body off the bench, curling forward until your torso is perpendicular to the ground. Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3670-EZeDVzO.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3670-EZeDVzO.gif', 'EZeDVzO', '© Gym visual — https://gymvisual.com/'),
('0833', 'weighted donkey calf raise', 'Ponte de pie sobre una plataforma elevada con la punta de los pies en el borde y los talones colgando. Sujétate de un objeto estable para mayor apoyo. Eleva los talones tan alto como puedas extendiendo los tobillos. Haz una pausa breve en la parte alta y luego baja lentamente los talones de vuelta a', 'lower legs', 'weighted', 'lower legs', 'lower legs', 'calves', '{"hamstrings","glutes"}', 'Ponte de pie sobre una plataforma elevada con la punta de los pies en el borde y los talones colgando. Sujétate de un objeto estable para mayor apoyo. Eleva los talones tan alto como puedas extendiendo los tobillos. Haz una pausa breve en la parte alta y luego baja lentamente los talones de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand on a raised platform with your toes on the edge and your heels hanging off. Hold onto a stable object for support. Raise your heels as high as possible by extending your ankles. Pause for a moment at the top, then slowly lower your heels back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0833-LmaFNZS.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0833-LmaFNZS.gif', 'LmaFNZS', '© Gym visual — https://gymvisual.com/'),
('1310', 'weighted drop push up', 'Comienza en una posición de plancha alta con las manos un poco más separadas que la anchura de los hombros y los pies juntos. Baja el pecho hacia el suelo, manteniendo los codos cerca del cuerpo. Cuando el pecho esté justo por encima del suelo, empújate hacia arriba de forma explosiva, levantando la', 'chest', 'weighted', 'chest', 'chest', 'pectorals', '{"triceps","shoulders"}', 'Comienza en una posición de plancha alta con las manos un poco más separadas que la anchura de los hombros y los pies juntos. Baja el pecho hacia el suelo, manteniendo los codos cerca del cuerpo. Cuando el pecho esté justo por encima del suelo, empújate hacia arriba de forma explosiva, levantando las manos del suelo. Mientras te empujas hacia arriba, mueve rápidamente las manos hacia los lados y un poco hacia adelante, permitiendo que tu cuerpo caiga hacia el suelo. Recíbete con las manos en la posición más ancha y baja de nuevo el pecho inmediatamente hacia el suelo. Repite el movimiento de flexión, bajando y recibiéndote con las manos en la posición más estrecha. Continúa alternando entre las posiciones de manos más ancha y más estrecha el número de repeticiones deseado.', 'Start in a high plank position with your hands slightly wider than shoulder-width apart and your feet together. Lower your chest towards the ground, keeping your elbows close to your body. Once your chest is just above the ground, explosively push yourself up, lifting your hands off the ground. As you push up, quickly move your hands out to the sides and slightly forward, allowing your body to drop down towards the ground. Catch yourself with your hands in the wider position and immediately lower your chest towards the ground again. Repeat the push-up motion, dropping down and catching yourself with your hands in the narrower position. Continue alternating between the wider and narrower hand positions for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1310-PSlvNMs.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1310-PSlvNMs.gif', 'PSlvNMs', '© Gym visual — https://gymvisual.com/'),
('2135', 'weighted front plank', 'Comienza tumbándote boca abajo en el suelo. Coloca los antebrazos en el suelo, con los codos justo debajo de los hombros. Extiende las piernas rectas hacia atrás, con la punta de los pies en el suelo. Activa el core y levanta el cuerpo del suelo, equilibrándote sobre los antebrazos y la punta de los', 'waist', 'weighted', 'waist', 'waist', 'abs', '{"shoulders","lower back"}', 'Comienza tumbándote boca abajo en el suelo. Coloca los antebrazos en el suelo, con los codos justo debajo de los hombros. Extiende las piernas rectas hacia atrás, con la punta de los pies en el suelo. Activa el core y levanta el cuerpo del suelo, equilibrándote sobre los antebrazos y la punta de los pies. Mantén el cuerpo en línea recta desde la cabeza hasta los talones. Mantén esta posición durante el tiempo deseado. Baja el cuerpo de nuevo a la posición inicial. Repite el número de repeticiones deseado.', 'Start by lying face down on the floor. Place your forearms on the ground, with your elbows directly under your shoulders. Extend your legs straight out behind you, with your toes on the ground. Engage your core and lift your body off the ground, balancing on your forearms and toes. Keep your body in a straight line from your head to your heels. Hold this position for the desired amount of time. Lower your body back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2135-VBAWRPG.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2135-VBAWRPG.gif', 'VBAWRPG', '© Gym visual — https://gymvisual.com/'),
('0834', 'weighted front raise', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo una mancuerna en cada mano con las palmas hacia los muslos. Manteniendo los brazos rectos, exhala y levanta las mancuernas frente a ti hasta que queden a la altura de los hombros. Haz una pausa por un momento en la parte sup', 'shoulders', 'weighted', 'shoulders', 'shoulders', 'delts', '{"biceps","forearms"}', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo una mancuerna en cada mano con las palmas hacia los muslos. Manteniendo los brazos rectos, exhala y levanta las mancuernas frente a ti hasta que queden a la altura de los hombros. Haz una pausa por un momento en la parte superior, luego inhala y baja lentamente las mancuernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing your thighs. Keeping your arms straight, exhale and lift the dumbbells in front of you until they are at shoulder level. Pause for a moment at the top, then inhale and slowly lower the dumbbells back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0834-e4aFmFY.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0834-e4aFmFY.gif', 'e4aFmFY', '© Gym visual — https://gymvisual.com/'),
('0866', 'weighted hanging leg-hip raise', 'Cuélgate de una barra de dominadas con los brazos completamente extendidos y las palmas mirando hacia afuera. Activa el core y levanta las piernas frente a ti, manteniéndolas rectas. Continúa levantando hasta que las piernas queden paralelas al suelo o un poco más arriba. Haz una pausa por un moment', 'waist', 'weighted', 'waist', 'waist', 'abs', '{"hip flexors","lower back"}', 'Cuélgate de una barra de dominadas con los brazos completamente extendidos y las palmas mirando hacia afuera. Activa el core y levanta las piernas frente a ti, manteniéndolas rectas. Continúa levantando hasta que las piernas queden paralelas al suelo o un poco más arriba. Haz una pausa por un momento en la parte superior, luego baja lentamente las piernas de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Hang from a pull-up bar with your arms fully extended and your palms facing away from you. Engage your core and lift your legs up in front of you, keeping them straight. Continue lifting until your legs are parallel to the ground or slightly higher. Pause for a moment at the top, then slowly lower your legs back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0866-QOA0FD0.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0866-QOA0FD0.gif', 'QOA0FD0', '© Gym visual — https://gymvisual.com/'),
('0835', 'weighted hyperextension (on stability ball)', 'Colócate boca abajo sobre un balón de estabilidad con las caderas apoyadas en el balón y los pies contra una pared para mayor estabilidad. Coloca las manos detrás de la cabeza o crúzalas sobre el pecho. Activa el core y levanta lentamente la parte superior del cuerpo del balón, extendiendo la espald', 'back', 'weighted', 'back', 'back', 'spine', '{"glutes","hamstrings"}', 'Colócate boca abajo sobre un balón de estabilidad con las caderas apoyadas en el balón y los pies contra una pared para mayor estabilidad. Coloca las manos detrás de la cabeza o crúzalas sobre el pecho. Activa el core y levanta lentamente la parte superior del cuerpo del balón, extendiendo la espalda hasta que tu cuerpo forme una línea recta. Haz una pausa por un momento en la parte superior, luego baja lentamente la parte superior del cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Position yourself face down on a stability ball with your hips resting on the ball and your feet against a wall for stability. Place your hands behind your head or cross them over your chest. Engage your core and slowly lift your upper body off the ball, extending your back until your body forms a straight line. Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0835-8urJS9b.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0835-8urJS9b.gif', '8urJS9b', '© Gym visual — https://gymvisual.com/'),
('3641', 'weighted kneeling step with swing', 'Comienza en posición de rodillas con las rodillas separadas a la altura de las caderas y la espalda recta. Sostén un peso en cada mano, con los brazos extendidos rectos hacia abajo frente a ti. Activa el core y balancea los pesos hacia arriba y por encima de la cabeza, manteniendo los brazos rectos.', 'shoulders', 'weighted', 'shoulders', 'shoulders', 'delts', '{"triceps","core"}', 'Comienza en posición de rodillas con las rodillas separadas a la altura de las caderas y la espalda recta. Sostén un peso en cada mano, con los brazos extendidos rectos hacia abajo frente a ti. Activa el core y balancea los pesos hacia arriba y por encima de la cabeza, manteniendo los brazos rectos. Baja los pesos de nuevo a la posición inicial y repite el número de repeticiones deseado.', 'Start in a kneeling position with your knees hip-width apart and your back straight. Hold a weight in each hand, with your arms extended straight down in front of you. Engage your core and swing the weights up and overhead, keeping your arms straight. Lower the weights back down to the starting position and repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3641-7uFJuXp.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3641-7uFJuXp.gif', '7uFJuXp', '© Gym visual — https://gymvisual.com/'),
('3644', 'weighted lunge with swing', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo un peso en cada mano. Da un paso adelante con el pie derecho, bajando el cuerpo hasta una posición de zancada. Mientras avanzas en la zancada, balancea los pesos hacia adelante y hacia arriba, manteniendo los brazos rectos. ', 'upper legs', 'weighted', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves"}', 'Ponte de pie con los pies separados a la altura de los hombros, sosteniendo un peso en cada mano. Da un paso adelante con el pie derecho, bajando el cuerpo hasta una posición de zancada. Mientras avanzas en la zancada, balancea los pesos hacia adelante y hacia arriba, manteniendo los brazos rectos. Empújate con el pie derecho y vuelve a la posición inicial, balanceando los pesos de nuevo hacia abajo. Repite con el pie izquierdo y continúa alternando las piernas el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, holding a weight in each hand. Take a step forward with your right foot, lowering your body into a lunge position. As you lunge forward, swing the weights forward and upward, keeping your arms straight. Push off with your right foot and return to the starting position, swinging the weights back down. Repeat with your left foot and continue alternating legs for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3644-5WiFcYk.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3644-5WiFcYk.gif', '5WiFcYk', '© Gym visual — https://gymvisual.com/'),
('3286', 'weighted muscle up', 'Comienza colgándote de una barra de dominadas con las palmas mirando hacia afuera y las manos un poco más separadas que la anchura de los hombros. Activa el core y tira de tu cuerpo hacia arriba, hacia la barra, guiando con el pecho. Al llegar a la parte alta del movimiento, cambia el agarre de modo', 'back', 'weighted', 'back', 'back', 'lats', '{"biceps","triceps","shoulders","chest"}', 'Comienza colgándote de una barra de dominadas con las palmas mirando hacia afuera y las manos un poco más separadas que la anchura de los hombros. Activa el core y tira de tu cuerpo hacia arriba, hacia la barra, guiando con el pecho. Al llegar a la parte alta del movimiento, cambia el agarre de modo que las palmas queden hacia ti. Continúa subiendo hasta que el pecho llegue a la barra, luego haz una pausa de un momento. Baja lentamente de nuevo a la posición inicial, manteniendo el control durante todo el movimiento. Repite el número de repeticiones deseado.', 'Start by hanging from a pull-up bar with your palms facing away from you and your hands slightly wider than shoulder-width apart. Engage your core and pull your body up towards the bar, leading with your chest. As you reach the top of the movement, transition your grip so that your palms are facing towards you. Continue pulling yourself up until your chest reaches the bar, then pause for a moment. Slowly lower yourself back down to the starting position, maintaining control throughout the movement. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3286-JsOV1SU.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3286-JsOV1SU.gif', 'JsOV1SU', '© Gym visual — https://gymvisual.com/'),
('3312', 'weighted muscle up (on bar)', 'Comienza colgándote de una barra de dominadas con las palmas mirando hacia afuera y las manos un poco más separadas que la anchura de los hombros. Activa el core y lleva los omóplatos hacia abajo y atrás. Flexiona los codos y tira del pecho hacia la barra, manteniendo el cuerpo recto. Cuando tu pech', 'back', 'weighted', 'back', 'back', 'lats', '{"biceps","triceps","shoulders","forearms"}', 'Comienza colgándote de una barra de dominadas con las palmas mirando hacia afuera y las manos un poco más separadas que la anchura de los hombros. Activa el core y lleva los omóplatos hacia abajo y atrás. Flexiona los codos y tira del pecho hacia la barra, manteniendo el cuerpo recto. Cuando tu pecho llegue a la barra, empuja hacia abajo con las manos y lleva los codos hacia atrás, elevando el cuerpo por encima de la barra. Haz una pausa en la parte más alta del movimiento, luego baja lentamente de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Start by hanging from a pull-up bar with your palms facing away from you and your hands slightly wider than shoulder-width apart. Engage your core and pull your shoulder blades down and back. Bend your elbows and pull your chest towards the bar, keeping your body straight. Once your chest reaches the bar, push down with your hands and drive your elbows back, lifting your body above the bar. Pause at the top of the movement, then slowly lower yourself back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3312-MCkqdKE.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3312-MCkqdKE.gif', 'MCkqdKE', '© Gym visual — https://gymvisual.com/'),
('3290', 'weighted one hand pull up', 'Sujeta la barra de dominadas con un agarre prono, un poco más ancho que la altura de los hombros. Cuélgate de la barra con un brazo completamente extendido y el cuerpo recto. Activa el core y tira de tu cuerpo hacia arriba en dirección a la barra flexionando el codo y contrayendo los músculos de la ', 'back', 'weighted', 'back', 'back', 'lats', '{"biceps","forearms"}', 'Sujeta la barra de dominadas con un agarre prono, un poco más ancho que la altura de los hombros. Cuélgate de la barra con un brazo completamente extendido y el cuerpo recto. Activa el core y tira de tu cuerpo hacia arriba en dirección a la barra flexionando el codo y contrayendo los músculos de la espalda. Continúa subiendo hasta que la barbilla quede por encima de la barra. Baja el cuerpo de nuevo a la posición inicial con control. Repite el número de repeticiones deseado.', 'Grab the pull-up bar with an overhand grip, slightly wider than shoulder-width apart. Hang from the bar with your arm fully extended and your body straight. Engage your core and pull your body up towards the bar by bending your elbow and squeezing your back muscles. Continue pulling until your chin is above the bar. Lower your body back down to the starting position with control. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3290-fXfqg1E.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3290-fXfqg1E.gif', 'fXfqg1E', '© Gym visual — https://gymvisual.com/'),
('0840', 'weighted overhead crunch (on stability ball)', 'Siéntate sobre un balón de estabilidad con los pies apoyados planos en el suelo y las rodillas flexionadas en un ángulo de 90 grados. Sostén un disco de peso o una mancuerna con ambas manos y extiende los brazos por encima de la cabeza. Activa el abdomen y curva lentamente el torso hacia adelante, l', 'waist', 'weighted', 'waist', 'waist', 'abs', '{"obliques","lower back"}', 'Siéntate sobre un balón de estabilidad con los pies apoyados planos en el suelo y las rodillas flexionadas en un ángulo de 90 grados. Sostén un disco de peso o una mancuerna con ambas manos y extiende los brazos por encima de la cabeza. Activa el abdomen y curva lentamente el torso hacia adelante, llevando el pecho hacia las rodillas. Haz una pausa de un momento en la parte superior, luego baja lentamente el torso de nuevo a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a stability ball with your feet flat on the ground and your knees bent at a 90-degree angle. Hold a weight plate or dumbbell with both hands and extend your arms overhead. Engage your abs and slowly curl your torso forward, bringing your chest towards your knees. Pause for a moment at the top, then slowly lower your torso back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0840-xmM75XG.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0840-xmM75XG.gif', 'xmM75XG', '© Gym visual — https://gymvisual.com/'),
('0841', 'weighted pull-up', 'Sujeta la barra de dominadas con un agarre prono, un poco más ancho que la altura de los hombros. Cuélgate de la barra con los brazos completamente extendidos y el cuerpo recto. Activa los músculos de la espalda y tira de tu cuerpo hacia arriba, hacia la barra, manteniendo los codos cerca del cuerpo', 'back', 'weighted', 'back', 'back', 'lats', '{"biceps","forearms"}', 'Sujeta la barra de dominadas con un agarre prono, un poco más ancho que la altura de los hombros. Cuélgate de la barra con los brazos completamente extendidos y el cuerpo recto. Activa los músculos de la espalda y tira de tu cuerpo hacia arriba, hacia la barra, manteniendo los codos cerca del cuerpo. Continúa subiendo hasta que la barbilla quede por encima de la barra. Haz una pausa por un momento en la parte superior, luego baja lentamente el cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Grab the pull-up bar with an overhand grip, slightly wider than shoulder-width apart. Hang from the bar with your arms fully extended and your body straight. Engage your back muscles and pull your body up towards the bar, keeping your elbows close to your body. Continue pulling until your chin is above the bar. Pause for a moment at the top, then slowly lower your body back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0841-HMzLjXx.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0841-HMzLjXx.gif', 'HMzLjXx', '© Gym visual — https://gymvisual.com/'),
('0844', 'weighted round arm', 'Ponte de pie con los pies separados a la altura de los hombros y sostén una mancuerna en cada mano. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta. Eleva los brazos hacia los lados, manteniendo una ligera flexión en los codos. Continúa el', 'shoulders', 'weighted', 'shoulders', 'shoulders', 'delts', '{"triceps","upper back"}', 'Ponte de pie con los pies separados a la altura de los hombros y sostén una mancuerna en cada mano. Flexiona ligeramente las rodillas e inclínate hacia adelante desde las caderas, manteniendo la espalda recta. Eleva los brazos hacia los lados, manteniendo una ligera flexión en los codos. Continúa elevando los brazos hasta que queden paralelos al suelo. Haz una pausa por un momento en la parte superior, luego baja lentamente los brazos de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and hold a dumbbell in each hand. Bend your knees slightly and hinge forward at the hips, keeping your back straight. Raise your arms out to the sides, keeping a slight bend in your elbows. Continue lifting your arms until they are parallel to the ground. Pause for a moment at the top, then slowly lower your arms back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0844-VLYXo8S.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0844-VLYXo8S.gif', 'VLYXo8S', '© Gym visual — https://gymvisual.com/'),
('0846', 'weighted russian twist', 'Siéntate en el suelo con las rodillas flexionadas y los pies apoyados en el suelo. Sostén un peso o un balón medicinal con ambas manos frente al pecho. Inclínate ligeramente hacia atrás, manteniendo la espalda recta y el core activado. Gira lentamente el torso hacia la derecha, llevando el peso o el', 'waist', 'weighted', 'waist', 'waist', 'abs', '{"obliques","lower back"}', 'Siéntate en el suelo con las rodillas flexionadas y los pies apoyados en el suelo. Sostén un peso o un balón medicinal con ambas manos frente al pecho. Inclínate ligeramente hacia atrás, manteniendo la espalda recta y el core activado. Gira lentamente el torso hacia la derecha, llevando el peso o el balón medicinal hacia el suelo a tu lado derecho. Haz una pausa de un momento, luego gira el torso hacia la izquierda, llevando el peso o el balón medicinal hacia el suelo a tu lado izquierdo. Continúa alternando lados durante el número de repeticiones deseado.', 'Sit on the ground with your knees bent and your feet flat on the floor. Hold a weight or medicine ball with both hands in front of your chest. Lean back slightly, keeping your back straight and your core engaged. Slowly twist your torso to the right, bringing the weight or medicine ball towards the floor on your right side. Pause for a moment, then twist your torso to the left, bringing the weight or medicine ball towards the floor on your left side. Continue alternating sides for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0846-fZFZ704.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0846-fZFZ704.gif', 'fZFZ704', '© Gym visual — https://gymvisual.com/'),
('0845', 'weighted russian twist (legs up)', 'Siéntate en el suelo con las rodillas flexionadas y los pies levantados del suelo, manteniendo las piernas juntas. Sostén el peso con ambas manos frente al pecho, manteniendo los codos ligeramente flexionados. Inclínate ligeramente hacia atrás para activar los músculos del core. Gira el torso hacia ', 'waist', 'weighted', 'waist', 'waist', 'abs', '{"obliques","hip flexors"}', 'Siéntate en el suelo con las rodillas flexionadas y los pies levantados del suelo, manteniendo las piernas juntas. Sostén el peso con ambas manos frente al pecho, manteniendo los codos ligeramente flexionados. Inclínate ligeramente hacia atrás para activar los músculos del core. Gira el torso hacia la derecha, llevando el peso hacia el suelo a tu lado derecho. Haz una pausa de un momento, luego gira el torso hacia la izquierda, llevando el peso hacia el suelo a tu lado izquierdo. Continúa alternando lados durante el número de repeticiones deseado.', 'Sit on the ground with your knees bent and feet lifted off the ground, keeping your legs together. Hold the weight with both hands in front of your chest, keeping your elbows slightly bent. Lean back slightly to engage your core muscles. Twist your torso to the right, bringing the weight towards the ground on your right side. Pause for a moment, then twist your torso to the left, bringing the weight towards the ground on your left side. Continue alternating sides for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0845-WU9BLIs.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0845-WU9BLIs.gif', 'WU9BLIs', '© Gym visual — https://gymvisual.com/'),
('2371', 'weighted russian twist v. 2', 'Siéntate en el suelo con las rodillas flexionadas y los pies apoyados en el suelo. Sostén el peso con ambas manos frente al pecho. Inclínate ligeramente hacia atrás para activar los músculos del core. Gira el torso hacia la derecha, llevando el peso hacia el lado derecho de tu cuerpo. Haz una pausa ', 'waist', 'weighted', 'waist', 'waist', 'abs', '{"obliques","lower back"}', 'Siéntate en el suelo con las rodillas flexionadas y los pies apoyados en el suelo. Sostén el peso con ambas manos frente al pecho. Inclínate ligeramente hacia atrás para activar los músculos del core. Gira el torso hacia la derecha, llevando el peso hacia el lado derecho de tu cuerpo. Haz una pausa de un momento, luego gira el torso hacia la izquierda, llevando el peso hacia el lado izquierdo de tu cuerpo. Continúa alternando lados durante el número de repeticiones deseado.', 'Sit on the ground with your knees bent and feet flat on the floor. Hold the weight with both hands in front of your chest. Lean back slightly to engage your core muscles. Twist your torso to the right, bringing the weight towards the right side of your body. Pause for a moment, then twist your torso to the left, bringing the weight towards the left side of your body. Continue alternating sides for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2371-YIUAtYf.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2371-YIUAtYf.gif', 'YIUAtYf', '© Gym visual — https://gymvisual.com/'),
('0847', 'weighted seated bicep curl (on stability ball)', 'Siéntate sobre un balón de estabilidad con los pies apoyados en el suelo y la espalda recta. Sostén un balón medicinal con un agarre supino, las palmas hacia arriba, y deja que los brazos cuelguen a los lados. Manteniendo la parte superior de los brazos quieta, exhala y curva el balón medicinal haci', 'upper arms', 'medicine ball', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Siéntate sobre un balón de estabilidad con los pies apoyados en el suelo y la espalda recta. Sostén un balón medicinal con un agarre supino, las palmas hacia arriba, y deja que los brazos cuelguen a los lados. Manteniendo la parte superior de los brazos quieta, exhala y curva el balón medicinal hacia los hombros. Haz una pausa breve en la parte alta, apretando los bíceps. Inhala y baja lentamente el balón medicinal de nuevo a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on a stability ball with your feet flat on the ground and your back straight. Hold a medicine ball with an underhand grip, palms facing up, and let your arms hang down by your sides. Keeping your upper arms stationary, exhale and curl the medicine ball up towards your shoulders. Pause for a moment at the top, squeezing your biceps. Inhale and slowly lower the medicine ball back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0847-b4b6afT.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0847-b4b6afT.gif', 'b4b6afT', '© Gym visual — https://gymvisual.com/'),
('0849', 'weighted seated twist (on stability ball)', 'Siéntate sobre un balón de estabilidad con los pies apoyados planos en el suelo y las rodillas flexionadas en un ángulo de 90 grados. Sostén un disco de peso o una mancuerna con ambas manos cerca del pecho. Activa el core y rota lentamente el torso hacia un lado, manteniendo las caderas estables. Ha', 'waist', 'weighted', 'waist', 'waist', 'abs', '{"obliques","lower back"}', 'Siéntate sobre un balón de estabilidad con los pies apoyados planos en el suelo y las rodillas flexionadas en un ángulo de 90 grados. Sostén un disco de peso o una mancuerna con ambas manos cerca del pecho. Activa el core y rota lentamente el torso hacia un lado, manteniendo las caderas estables. Haz una pausa por un momento al final de la rotación, luego regresa lentamente a la posición inicial. Repite la rotación hacia el otro lado. Continúa alternando lados durante el número de repeticiones deseado.', 'Sit on a stability ball with your feet flat on the ground and your knees bent at a 90-degree angle. Hold a weight plate or dumbbell with both hands close to your chest. Engage your core and slowly rotate your torso to one side, keeping your hips stable. Pause for a moment at the end of the rotation, then slowly return to the starting position. Repeat the rotation to the other side. Continue alternating sides for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0849-s34Y4LR.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0849-s34Y4LR.gif', 's34Y4LR', '© Gym visual — https://gymvisual.com/'),
('0850', 'weighted side bend (on stability ball)', 'Siéntate sobre un balón de estabilidad con los pies separados a la altura de los hombros y planos sobre el suelo. Sostén un peso en una mano y coloca la otra mano sobre la cadera. Activa el core e inclínate lentamente hacia el lado del peso, manteniendo la espalda recta. Haz una pausa por un momento', 'waist', 'weighted', 'waist', 'waist', 'abs', '{"obliques","lower back"}', 'Siéntate sobre un balón de estabilidad con los pies separados a la altura de los hombros y planos sobre el suelo. Sostén un peso en una mano y coloca la otra mano sobre la cadera. Activa el core e inclínate lentamente hacia el lado del peso, manteniendo la espalda recta. Haz una pausa por un momento en la parte inferior, luego regresa lentamente a la posición inicial. Repite el número de repeticiones deseado, luego cambia de lado.', 'Sit on a stability ball with your feet shoulder-width apart and flat on the ground. Hold a weight in one hand and place your other hand on your hip. Engage your core and slowly bend sideways towards the weighted side, keeping your back straight. Pause for a moment at the bottom, then slowly return to the starting position. Repeat for the desired number of repetitions, then switch sides.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0850-6bOA1Oi.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0850-6bOA1Oi.gif', '6bOA1Oi', '© Gym visual — https://gymvisual.com/'),
('0851', 'weighted sissy squat', 'Ponte de pie con los pies separados a la altura de los hombros y los dedos de los pies ligeramente hacia afuera. Sostén un peso frente al pecho con ambas manos, o coloca una barra sobre la parte superior de la espalda. Manteniendo el pecho elevado y el core activado, baja lentamente el cuerpo flexio', 'upper legs', 'weighted', 'upper legs', 'upper legs', 'quads', '{"glutes","hamstrings","calves"}', 'Ponte de pie con los pies separados a la altura de los hombros y los dedos de los pies ligeramente hacia afuera. Sostén un peso frente al pecho con ambas manos, o coloca una barra sobre la parte superior de la espalda. Manteniendo el pecho elevado y el core activado, baja lentamente el cuerpo flexionando las rodillas y las caderas. Continúa bajando hasta que los muslos queden paralelos al suelo, o tan abajo como puedas hacerlo cómodamente. Haz una pausa por un momento en la parte inferior, luego empuja con los talones para regresar a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and your toes pointing slightly outward. Hold a weight in front of your chest with both hands, or place a barbell across your upper back. Keeping your chest up and your core engaged, slowly lower your body down by bending at the knees and hips. Continue lowering until your thighs are parallel to the ground or as low as you can comfortably go. Pause for a moment at the bottom, then push through your heels to return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0851-0lQnxMZ.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0851-0lQnxMZ.gif', '0lQnxMZ', '© Gym visual — https://gymvisual.com/'),
('0852', 'weighted squat', 'Ponte de pie con los pies separados a la altura de los hombros, los dedos de los pies ligeramente hacia afuera. Sostén un peso frente al pecho o sobre los hombros. Activa el core y mantén el pecho elevado mientras bajas las caderas hacia abajo y hacia atrás, como si te sentaras en una silla. Baja ha', 'upper legs', 'weighted', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves"}', 'Ponte de pie con los pies separados a la altura de los hombros, los dedos de los pies ligeramente hacia afuera. Sostén un peso frente al pecho o sobre los hombros. Activa el core y mantén el pecho elevado mientras bajas las caderas hacia abajo y hacia atrás, como si te sentaras en una silla. Baja hasta que los muslos queden paralelos al suelo, o tan abajo como puedas hacerlo cómodamente. Empuja con los talones para volver a ponerte de pie, contrayendo los glúteos en la parte superior. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart, toes pointing slightly outward. Hold a weight in front of your chest or on your shoulders. Engage your core and keep your chest up as you lower your hips down and back, as if sitting into a chair. Lower until your thighs are parallel to the ground, or as low as you can comfortably go. Push through your heels to stand back up, squeezing your glutes at the top. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0852-JZuApnB.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0852-JZuApnB.gif', 'JZuApnB', '© Gym visual — https://gymvisual.com/'),
('0853', 'weighted standing curl', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una mancuerna en cada mano, con las palmas hacia adelante. Mantén los codos cerca del torso y exhala mientras curvas los pesos hasta la altura de los hombros. Haz una pausa de un momento en la parte superior, luego inhala mientr', 'upper arms', 'weighted', 'upper arms', 'upper arms', 'biceps', '{"forearms"}', 'Ponte de pie con los pies separados a la altura de los hombros y sujeta una mancuerna en cada mano, con las palmas hacia adelante. Mantén los codos cerca del torso y exhala mientras curvas los pesos hasta la altura de los hombros. Haz una pausa de un momento en la parte superior, luego inhala mientras bajas lentamente los pesos de nuevo a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing forward. Keep your elbows close to your torso and exhale as you curl the weights up to shoulder level. Pause for a moment at the top, then inhale as you slowly lower the weights back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0853-M5Y7GPg.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0853-M5Y7GPg.gif', 'M5Y7GPg', '© Gym visual — https://gymvisual.com/'),
('0854', 'weighted standing hand squeeze', 'Ponte de pie con los pies separados a la altura de los hombros y sostén un peso en cada mano. Extiende los brazos rectos hacia adelante, con las palmas mirándose entre sí. Aprieta las manos entre sí con la mayor fuerza posible, activando los antebrazos. Mantén la contracción durante unos segundos y ', 'lower arms', 'weighted', 'lower arms', 'lower arms', 'forearms', '{"biceps","triceps"}', 'Ponte de pie con los pies separados a la altura de los hombros y sostén un peso en cada mano. Extiende los brazos rectos hacia adelante, con las palmas mirándose entre sí. Aprieta las manos entre sí con la mayor fuerza posible, activando los antebrazos. Mantén la contracción durante unos segundos y luego suelta. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and hold a weight in each hand. Extend your arms straight in front of you, palms facing each other. Squeeze your hands together as hard as you can, engaging your forearms. Hold the squeeze for a few seconds, then release. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0854-bjqbauy.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0854-bjqbauy.gif', 'bjqbauy', '© Gym visual — https://gymvisual.com/'),
('3313', 'weighted straight bar dip', 'Colócate entre las barras paralelas con los brazos completamente extendidos y el cuerpo recto. Baja el cuerpo flexionando los codos hasta que los brazos queden paralelos al suelo. Haz una pausa breve, luego empújate de nuevo hacia arriba a la posición inicial estirando los brazos. Repite el número d', 'chest', 'weighted', 'chest', 'chest', 'pectorals', '{"triceps","shoulders"}', 'Colócate entre las barras paralelas con los brazos completamente extendidos y el cuerpo recto. Baja el cuerpo flexionando los codos hasta que los brazos queden paralelos al suelo. Haz una pausa breve, luego empújate de nuevo hacia arriba a la posición inicial estirando los brazos. Repite el número de repeticiones deseado.', 'Position yourself between parallel bars with your arms fully extended and your body straight. Lower your body by bending your elbows until your upper arms are parallel to the ground. Pause for a moment, then push yourself back up to the starting position by straightening your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3313-Ff18ItA.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3313-Ff18ItA.gif', 'Ff18ItA', '© Gym visual — https://gymvisual.com/'),
('3642', 'weighted stretch lunge', 'Ponte de pie con los pies separados a la altura de los hombros. Da un paso adelante con el pie derecho, manteniendo la espalda recta. Baja el cuerpo flexionando las rodillas hasta que el muslo derecho quede paralelo al suelo. Empuja con el talón derecho para regresar a la posición inicial. Repite co', 'upper legs', 'weighted', 'upper legs', 'upper legs', 'glutes', '{"quadriceps","hamstrings","calves"}', 'Ponte de pie con los pies separados a la altura de los hombros. Da un paso adelante con el pie derecho, manteniendo la espalda recta. Baja el cuerpo flexionando las rodillas hasta que el muslo derecho quede paralelo al suelo. Empuja con el talón derecho para regresar a la posición inicial. Repite con la pierna izquierda. Continúa alternando las piernas durante el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart. Take a step forward with your right foot, keeping your back straight. Lower your body by bending your knees until your right thigh is parallel to the ground. Push through your right heel to return to the starting position. Repeat with your left leg. Continue alternating legs for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3642-13VW2VO.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3642-13VW2VO.gif', '13VW2VO', '© Gym visual — https://gymvisual.com/'),
('0856', 'weighted svend press', 'Ponte de pie con los pies separados a la altura de los hombros y sostén un disco de peso frente al pecho con ambas manos. Mantén los codos ligeramente flexionados y las palmas mirándose entre sí. Empuja el disco de peso recto hacia adelante, extendiendo completamente los brazos. Haz una pausa de un ', 'chest', 'weighted', 'chest', 'chest', 'pectorals', '{"shoulders","triceps"}', 'Ponte de pie con los pies separados a la altura de los hombros y sostén un disco de peso frente al pecho con ambas manos. Mantén los codos ligeramente flexionados y las palmas mirándose entre sí. Empuja el disco de peso recto hacia adelante, extendiendo completamente los brazos. Haz una pausa de un momento al final del movimiento, luego lleva lentamente el disco de peso de nuevo a la posición inicial. Repite el número de repeticiones deseado.', 'Stand with your feet shoulder-width apart and hold a weight plate in front of your chest with both hands. Keep your elbows slightly bent and your palms facing each other. Press the weight plate straight out in front of you, fully extending your arms. Pause for a moment at the end of the movement, then slowly bring the weight plate back to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0856-I1OBLnn.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0856-I1OBLnn.gif', 'I1OBLnn', '© Gym visual — https://gymvisual.com/'),
('1754', 'weighted three bench dips', 'Siéntate en el borde de un banco con las manos agarrando el borde, los dedos apuntando hacia adelante. Camina con los pies hacia adelante, deslizando los glúteos fuera del banco y sosteniendo tu peso con los brazos. Baja el cuerpo flexionando los codos, manteniendo la espalda cerca del banco. Haz un', 'upper arms', 'weighted', 'upper arms', 'upper arms', 'triceps', '{"chest","shoulders"}', 'Siéntate en el borde de un banco con las manos agarrando el borde, los dedos apuntando hacia adelante. Camina con los pies hacia adelante, deslizando los glúteos fuera del banco y sosteniendo tu peso con los brazos. Baja el cuerpo flexionando los codos, manteniendo la espalda cerca del banco. Haz una pausa por un momento en la parte inferior, luego empuja tu cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Sit on the edge of a bench with your hands gripping the edge, fingers pointing forward. Walk your feet forward, sliding your butt off the bench and supporting your weight with your arms. Lower your body by bending your elbows, keeping your back close to the bench. Pause for a moment at the bottom, then push yourself back up to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1754-gtO1ErP.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1754-gtO1ErP.gif', 'gtO1ErP', '© Gym visual — https://gymvisual.com/'),
('1755', 'weighted tricep dips', 'Siéntate en el borde de un banco o silla con las manos sujetando el borde junto a las caderas. Desliza los glúteos fuera del frente del banco con las piernas extendidas frente a ti. Mantén la espalda cerca del banco y los codos ligeramente flexionados. Baja el cuerpo flexionando los codos hasta que ', 'upper arms', 'weighted', 'upper arms', 'upper arms', 'triceps', '{"chest","shoulders"}', 'Siéntate en el borde de un banco o silla con las manos sujetando el borde junto a las caderas. Desliza los glúteos fuera del frente del banco con las piernas extendidas frente a ti. Mantén la espalda cerca del banco y los codos ligeramente flexionados. Baja el cuerpo flexionando los codos hasta que los brazos queden paralelos al suelo. Empújate de vuelta hacia arriba a la posición inicial extendiendo los brazos. Repite el número de repeticiones deseado.', 'Sit on the edge of a bench or chair with your hands gripping the edge next to your hips. Slide your butt off the front of the bench with your legs extended in front of you. Keep your back close to the bench and your elbows slightly bent. Lower your body by bending your elbows until your upper arms are parallel to the floor. Push yourself back up to the starting position by straightening your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1755-bZq4bwK.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1755-bZq4bwK.gif', 'bZq4bwK', '© Gym visual — https://gymvisual.com/'),
('1767', 'weighted triceps dip on high parallel bars', 'Colócate entre dos barras paralelas con las manos agarrando las barras y los brazos completamente extendidos. Flexiona los codos y baja el cuerpo hasta que la parte superior de los brazos quede paralela al suelo. Haz una pausa de un momento, luego empuja con las palmas para estirar los brazos y volv', 'upper arms', 'weighted', 'upper arms', 'upper arms', 'triceps', '{"chest","shoulders"}', 'Colócate entre dos barras paralelas con las manos agarrando las barras y los brazos completamente extendidos. Flexiona los codos y baja el cuerpo hasta que la parte superior de los brazos quede paralela al suelo. Haz una pausa de un momento, luego empuja con las palmas para estirar los brazos y volver a la posición inicial. Repite el número de repeticiones deseado.', 'Position yourself between two parallel bars with your hands gripping the bars and your arms fully extended. Bend your elbows and lower your body until your upper arms are parallel to the ground. Pause for a moment, then push through your palms to straighten your arms and return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1767-K1vlode.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1767-K1vlode.gif', 'K1vlode', '© Gym visual — https://gymvisual.com/'),
('0857', 'wheel rollerout', 'Arrodíllate en el suelo y coloca el rodillo frente a ti. Coloca las manos en las asas del rodillo y extiende los brazos rectos hacia adelante. Activa los músculos del core y haz rodar lentamente el rodillo hacia adelante, manteniendo la espalda recta y el abdomen contraído. Continúa rodando hacia de', 'waist', 'wheel roller', 'waist', 'waist', 'abs', '{"lower back"}', 'Arrodíllate en el suelo y coloca el rodillo frente a ti. Coloca las manos en las asas del rodillo y extiende los brazos rectos hacia adelante. Activa los músculos del core y haz rodar lentamente el rodillo hacia adelante, manteniendo la espalda recta y el abdomen contraído. Continúa rodando hacia delante hasta que el cuerpo esté completamente extendido y los brazos por encima de la cabeza. Haz una pausa de un momento, luego haz rodar lentamente el rodillo de regreso hacia las rodillas, manteniendo el control y el abdomen activado. Repite el número de repeticiones deseado.', 'Kneel on the floor and place the wheel roller in front of you. Place your hands on the handles of the wheel roller and extend your arms straight out in front of you. Engage your core muscles and slowly roll the wheel forward, keeping your back straight and your abs tight. Continue rolling forward until your body is fully extended and your arms are overhead. Pause for a moment, then slowly roll the wheel back towards your knees, maintaining control and keeping your abs engaged. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0857-NAgVB3t.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0857-NAgVB3t.gif', 'NAgVB3t', '© Gym visual — https://gymvisual.com/'),
('3637', 'wheel run', 'Comienza en posición de plancha con las manos sobre el rodillo y el cuerpo recto. Activa el core y comienza a hacer rodar el rodillo hacia adelante extendiendo los brazos. Continúa rodando hasta que tu cuerpo quede completamente extendido y los brazos por encima de la cabeza. Invierte el movimiento ', 'cardio', 'body weight', 'cardio', 'cardio', 'cardiovascular system', '{"quadriceps","hamstrings","calves"}', 'Comienza en posición de plancha con las manos sobre el rodillo y el cuerpo recto. Activa el core y comienza a hacer rodar el rodillo hacia adelante extendiendo los brazos. Continúa rodando hasta que tu cuerpo quede completamente extendido y los brazos por encima de la cabeza. Invierte el movimiento tirando del rodillo de vuelta hacia tu cuerpo, usando el core y los brazos. Repite el número de repeticiones deseado.', 'Start in a plank position with your hands on the wheel and your body straight. Engage your core and start rolling the wheel forward by extending your arms. Continue rolling until your body is fully extended and your arms are overhead. Reverse the movement by pulling the wheel back towards your body, using your core and arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/3637-km2Ljzj.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/3637-km2Ljzj.gif', 'km2Ljzj', '© Gym visual — https://gymvisual.com/'),
('1429', 'wide grip pull-up', 'Cuélgate de una barra de dominadas con las palmas mirando hacia afuera y las manos más separadas que la anchura de los hombros. Activa el core y junta los omóplatos. Tira de tu cuerpo hacia arriba en dirección a la barra hasta que tu barbilla quede por encima de la barra. Baja el cuerpo de nuevo a l', 'back', 'body weight', 'back', 'back', 'lats', '{"biceps","forearms"}', 'Cuélgate de una barra de dominadas con las palmas mirando hacia afuera y las manos más separadas que la anchura de los hombros. Activa el core y junta los omóplatos. Tira de tu cuerpo hacia arriba en dirección a la barra hasta que tu barbilla quede por encima de la barra. Baja el cuerpo de nuevo a la posición inicial con control. Repite el número de repeticiones deseado.', 'Hang from a pull-up bar with your palms facing away from you and your hands wider than shoulder-width apart. Engage your core and squeeze your shoulder blades together. Pull your body up towards the bar until your chin is above the bar. Lower your body back down to the starting position with control. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1429-Qqi7bko.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1429-Qqi7bko.gif', 'Qqi7bko', '© Gym visual — https://gymvisual.com/'),
('1367', 'wide grip rear pull-up', 'Agarra la barra de dominadas con un agarre prono amplio, las manos un poco más separadas que la anchura de los hombros. Cuélgate de la barra con los brazos completamente extendidos y el cuerpo recto. Activa los músculos de la espalda y tira de tu cuerpo hacia la barra, llevando el pecho por delante.', 'back', 'body weight', 'back', 'back', 'lats', '{"biceps","forearms"}', 'Agarra la barra de dominadas con un agarre prono amplio, las manos un poco más separadas que la anchura de los hombros. Cuélgate de la barra con los brazos completamente extendidos y el cuerpo recto. Activa los músculos de la espalda y tira de tu cuerpo hacia la barra, llevando el pecho por delante. Continúa subiendo hasta que la barbilla quede por encima de la barra. Haz una pausa por un momento en la parte superior, luego baja lentamente el cuerpo de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Grab the pull-up bar with a wide overhand grip, hands slightly wider than shoulder-width apart. Hang from the bar with your arms fully extended and your body straight. Engage your back muscles and pull your body up towards the bar, leading with your chest. Continue pulling until your chin is above the bar. Pause for a moment at the top, then slowly lower your body back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1367-OYFhXVD.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1367-OYFhXVD.gif', 'OYFhXVD', '© Gym visual — https://gymvisual.com/'),
('1311', 'wide hand push up', 'Comienza en una posición de plancha alta con las manos más separadas que la anchura de los hombros. Mantén el cuerpo en línea recta de la cabeza a los pies. Baja el pecho hacia el suelo flexionando los codos, manteniéndolos cerca de los costados. Empuja con las palmas para extender los brazos y regr', 'chest', 'body weight', 'chest', 'chest', 'pectorals', '{"triceps","shoulders"}', 'Comienza en una posición de plancha alta con las manos más separadas que la anchura de los hombros. Mantén el cuerpo en línea recta de la cabeza a los pies. Baja el pecho hacia el suelo flexionando los codos, manteniéndolos cerca de los costados. Empuja con las palmas para extender los brazos y regresar a la posición inicial. Repite el número de repeticiones deseado.', 'Start in a high plank position with your hands wider than shoulder-width apart. Keep your body in a straight line from head to toe. Lower your chest towards the ground by bending your elbows, keeping them close to your sides. Push through your palms to extend your arms and return to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1311-JmMVpR3.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1311-JmMVpR3.gif', 'JmMVpR3', '© Gym visual — https://gymvisual.com/'),
('2363', 'wide-grip chest dip on high parallel bars', 'Colócate sobre las barras paralelas con los brazos completamente extendidos y el cuerpo suspendido en el aire. Inclínate ligeramente hacia adelante y baja el cuerpo flexionando los codos hasta que el pecho quede justo por encima de las barras. Haz una pausa breve, luego empújate de nuevo hacia arrib', 'chest', 'body weight', 'chest', 'chest', 'pectorals', '{"triceps","shoulders"}', 'Colócate sobre las barras paralelas con los brazos completamente extendidos y el cuerpo suspendido en el aire. Inclínate ligeramente hacia adelante y baja el cuerpo flexionando los codos hasta que el pecho quede justo por encima de las barras. Haz una pausa breve, luego empújate de nuevo hacia arriba a la posición inicial estirando los brazos. Repite el número de repeticiones deseado.', 'Position yourself on the parallel bars with your arms fully extended and your body suspended in the air. Lean forward slightly and lower your body by bending your elbows until your chest is just above the bars. Pause for a moment, then push yourself back up to the starting position by straightening your arms. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/2363-O2K9Vb5.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/2363-O2K9Vb5.gif', 'O2K9Vb5', '© Gym visual — https://gymvisual.com/'),
('0858', 'wind sprints', 'Busca un espacio abierto o una pista para realizar el ejercicio. Comienza de pie con los pies separados a la altura de los hombros. Comienza a correr lo más rápido que puedas, bombeando los brazos y elevando las rodillas. Continúa el sprint durante una distancia o periodo de tiempo específico. Desca', 'waist', 'body weight', 'waist', 'waist', 'abs', '{"quadriceps","hamstrings","calves"}', 'Busca un espacio abierto o una pista para realizar el ejercicio. Comienza de pie con los pies separados a la altura de los hombros. Comienza a correr lo más rápido que puedas, bombeando los brazos y elevando las rodillas. Continúa el sprint durante una distancia o periodo de tiempo específico. Descansa y repite el número de repeticiones deseado.', 'Find an open space or a track to perform the exercise. Start by standing with your feet shoulder-width apart. Begin running as fast as you can, pumping your arms and driving your knees up. Continue sprinting for a specific distance or time period. Rest and repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0858-Qoujh3Q.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0858-Qoujh3Q.gif', 'Qoujh3Q', '© Gym visual — https://gymvisual.com/'),
('1604', 'world greatest stretch', 'Comienza en posición de zancada con el pie derecho adelante y el pie izquierdo atrás. Coloca las manos en el suelo a ambos lados de tu pie derecho. Baja la rodilla izquierda hacia el suelo y extiende la pierna derecha, manteniendo el pie derecho plano sobre el suelo. Gira el torso hacia la derecha, ', 'upper legs', 'body weight', 'upper legs', 'upper legs', 'hamstrings', '{"glutes","quadriceps","calves"}', 'Comienza en posición de zancada con el pie derecho adelante y el pie izquierdo atrás. Coloca las manos en el suelo a ambos lados de tu pie derecho. Baja la rodilla izquierda hacia el suelo y extiende la pierna derecha, manteniendo el pie derecho plano sobre el suelo. Gira el torso hacia la derecha, extendiendo el brazo derecho hacia el techo. Mantén esta posición durante unos segundos, luego vuelve a la posición inicial. Cambia de lado y repite el estiramiento con el pie izquierdo adelante.', 'Start in a lunge position with your right foot forward and your left foot back. Place your hands on the ground on either side of your right foot. Lower your left knee to the ground and extend your right leg, keeping your right foot flat on the ground. Rotate your torso to the right, reaching your right arm up towards the ceiling. Hold this position for a few seconds, then return to the starting position. Switch sides and repeat the stretch with your left foot forward.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1604-DFGXwZr.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1604-DFGXwZr.gif', 'DFGXwZr', '© Gym visual — https://gymvisual.com/'),
('1428', 'wrist circles', 'Extiende los brazos rectos frente a ti. Cierra ambas manos en un puño. Gira las muñecas en un movimiento circular, manteniendo los brazos quietos. Continúa los círculos de muñeca el número de repeticiones deseado.', 'lower arms', 'body weight', 'lower arms', 'lower arms', 'forearms', '{"hands","wrists"}', 'Extiende los brazos rectos frente a ti. Cierra ambas manos en un puño. Gira las muñecas en un movimiento circular, manteniendo los brazos quietos. Continúa los círculos de muñeca el número de repeticiones deseado.', 'Extend your arms straight out in front of you. Make a fist with both hands. Rotate your wrists in a circular motion, keeping your arms still. Continue the wrist circles for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/1428-2zNKRUB.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/1428-2zNKRUB.gif', '2zNKRUB', '© Gym visual — https://gymvisual.com/'),
('0859', 'wrist rollerer', 'Sujeta un peso a un extremo de una cuerda o barra. Sostén el otro extremo de la cuerda o barra con ambas manos, con las palmas hacia abajo. Ponte de pie con los pies separados a la altura de los hombros y los brazos completamente extendidos frente a ti. Enrolla lentamente el peso hacia las manos fle', 'lower arms', 'weighted', 'lower arms', 'lower arms', 'forearms', '{"biceps","triceps"}', 'Sujeta un peso a un extremo de una cuerda o barra. Sostén el otro extremo de la cuerda o barra con ambas manos, con las palmas hacia abajo. Ponte de pie con los pies separados a la altura de los hombros y los brazos completamente extendidos frente a ti. Enrolla lentamente el peso hacia las manos flexionando las muñecas. Haz una pausa breve en lo alto, luego baja lentamente el peso de vuelta a la posición inicial. Repite el número de repeticiones deseado.', 'Attach a weight to one end of a rope or bar. Hold the other end of the rope or bar with both hands, palms facing down. Stand with your feet shoulder-width apart and your arms fully extended in front of you. Slowly roll the weight up towards your hands by flexing your wrists. Pause for a moment at the top, then slowly lower the weight back down to the starting position. Repeat for the desired number of repetitions.', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/images/0859-bd5b860.jpg', 'https://raw.githubusercontent.com/hasaneyldrm/exercises-dataset/main/videos/0859-bd5b860.gif', 'bd5b860', '© Gym visual — https://gymvisual.com/')
