-- =====================================================
-- MIGRACIÓN: Enriquecimiento de Biblioteca de Ejercicios
-- =====================================================
-- Descripción: Agrega nuevos campos a la tabla exercises
-- e importa 1,324 ejercicios del dataset exercises-dataset
-- =====================================================

-- 1. Agregar nuevas columnas a exercises
ALTER TABLE exercises ADD COLUMN IF NOT EXISTS external_id TEXT;
ALTER TABLE exercises ADD COLUMN IF NOT EXISTS category TEXT;
ALTER TABLE exercises ADD COLUMN IF NOT EXISTS body_part TEXT;
ALTER TABLE exercises ADD COLUMN IF NOT EXISTS target TEXT;
ALTER TABLE exercises ADD COLUMN IF NOT EXISTS secondary_muscles TEXT[] DEFAULT '{}';
ALTER TABLE exercises ADD COLUMN IF NOT EXISTS instructions_es TEXT;
ALTER TABLE exercises ADD COLUMN IF NOT EXISTS instructions_en TEXT;
ALTER TABLE exercises ADD COLUMN IF NOT EXISTS image_url TEXT;
ALTER TABLE exercises ADD COLUMN IF NOT EXISTS gif_url TEXT;
ALTER TABLE exercises ADD COLUMN IF NOT EXISTS media_id TEXT;
ALTER TABLE exercises ADD COLUMN IF NOT EXISTS attribution TEXT;

CREATE INDEX IF NOT EXISTS idx_exercises_external_id ON exercises(external_id);
CREATE INDEX IF NOT EXISTS idx_exercises_category ON exercises(category);
CREATE INDEX IF NOT EXISTS idx_exercises_target ON exercises(target);

-- 2. Actualizar los ejercicios existentes con datos enriquecidos si hay match
-- (los 25 ejercicios actuales están en español, el dataset en inglés,
--  así que no hay conflicto de nombres)

-- 3. Insertar 1,324 ejercicios del dataset
ON CONFLICT (name) DO UPDATE SET
  external_id = EXCLUDED.external_id,
  category = EXCLUDED.category,
  body_part = EXCLUDED.body_part,
  target = EXCLUDED.target,
  secondary_muscles = EXCLUDED.secondary_muscles,
  instructions_es = EXCLUDED.instructions_es,
  instructions_en = EXCLUDED.instructions_en,
  image_url = EXCLUDED.image_url,
  gif_url = EXCLUDED.gif_url,
  media_id = EXCLUDED.media_id,
  attribution = EXCLUDED.attribution,
  equipment = CASE WHEN exercises.equipment IS NULL THEN EXCLUDED.equipment ELSE exercises.equipment END,
  description = CASE WHEN exercises.description IS NULL THEN EXCLUDED.description ELSE exercises.description END;

-- 4. Vaciar ejercicios temporales si existen (de la migración 03/04)
-- Ya se insertaron con ON CONFLICT, no se necesita borrar nada

-- =====================================================
-- VERIFICACIÓN
-- =====================================================
SELECT COUNT(*) as total_exercises FROM exercises;
SELECT 'Migración completada: 1,324 ejercicios importados' as mensaje;